export interface Comentario {
  livro: string;
  capitulo: number;
  versiculo: number;
  autor: string;
  texto: string;
  tipo: 'historico' | 'teologico' | 'gramatical' | 'cultural' | 'aplicacao' | 'escatologico';
}

const comentarios: Record<string, Comentario[]> = {};

function chave(livro: string, capitulo: number, versiculo: number): string {
  return `${livro}:${capitulo}:${versiculo}`;
}

function add(livro: string, cap: number, v: number, autor: string, texto: string, tipo: Comentario['tipo']) {
  const k = chave(livro, cap, v);
  if (!comentarios[k]) comentarios[k] = [];
  comentarios[k].push({ livro, capitulo: cap, versiculo: v, autor, texto, tipo });
}

// GN (249 comentários)
add('gn', 1, 1, 'Tomás de Aquino', 'Deus criou os céus e a terra — A criação ex nihilo é ato da onipotência divina. O Filho é o Verbo pelo qual todas as coisas foram feitas.', 'teologico');
add('gn', 1, 3, 'Orígenes', 'Haja luz — A luz espiritual que Deus acende no alma é anterior e superior à luz material do cosmos.', 'teologico');
add('gn', 1, 26, 'João Crisóstomo', 'Façamos o homem — O plural revela consulta trinitária. A imagem divina no homem inclui livre-arbítrio e domínio sobre a criação.', 'teologico');
add('gn', 1, 27, 'Tomás de Aquino', 'Criou Deus o homem à sua imagem — A imagem de Deus se refere ao intelecto e à vontade livre, que aproximam o homem de Deus.', 'teologico');
add('gn', 3, 1, 'Orígenes', 'A serpente era astuta — O mal se apresenta como sabedoria. A astúcia da serpente é o oposto da prudência cristã.', 'teologico');
add('gn', 3, 5, 'Calvino', 'Sereis como Deus — A promessa mentirosa da serpente: o pecado oferece falsa divindade através da desobediência.', 'teologico');
add('gn', 3, 6, 'Wesley', 'Viu a mulher que a árvore era boa — A tentação segue o padrão: ver, desejar, tomar. A concupiscência precede o ato.', 'aplicacao');
add('gn', 3, 15, 'Calvino', 'Pôr inimizade — O Proto-evangelium: a primeira promessa de redenção. A semente da mulher esmagará a cabeça da serpente.', 'escatologico');
add('gn', 12, 1, 'N.T. Wright', 'Abraão é chamado para ser bênção — A eleição não é privilégio exclusivo, mas missão: ser bênção para todas as nações.', 'teologico');
add('gn', 12, 3, 'Adam Clarke', 'Serão abençoadas todas as famílias — A promessa é universal: não apenas Israel, mas todas as nações da terra.', 'escatologico');
add('gn', 15, 6, 'N.T. Wright', 'Crer no Senhor — A fé de Abraão é confiança na promessa de Deus, não apenas assentimento intelectual.', 'teologico');
add('gn', 22, 1, 'Kierkegaard', 'Deus tentou Abraão — O paradoxo da fé que obedece quando não compreende.', 'teologico');
add('gn', 22, 14, 'Tomás de Aquino', 'O Senhor proverá — O sacrifício de Isaque prefigura o sacrifício de Cristo: o Pai dá o Seu Filho unigênito.', 'teologico');
add('gn', 22, 2, 'John Stott', 'Toma o teu filho, o teu único — A exigência divina prepara Abraão para entender o custo do amor e da obediência.', 'aplicacao');
add('gn', 1, 2, 'Agostinho', 'O Espírito de Deus se movia — A presença do Espírito pairava sobre as águas, iniciando a obra da criação.', 'teologico');
add('gn', 2, 7, 'Calvino', 'Formou o homem do pó — A origem terrena do corpo e o sopro divino que concede a vida humana.', 'teologico');
add('gn', 2, 18, 'Matthew Henry', 'Não é bom que o homem esteja só — A instituição do casamento como resposta à solidão original.', 'aplicacao');
add('gn', 6, 8, 'Lutero', 'Noé achou graça — A graça precede o mérito: Noé foi justo porque Deus o agraciou, não por obras.', 'teologico');
add('gn', 9, 13, 'Spurgeon', 'Porei o meu arco nas nuvens — O arco-íris como sinal da aliança de Deus de não mais destruir a terra pelas águas.', 'teologico');
add('gn', 1, 6, 'Matthew Henry', 'We have here an account of the second day\'s work, the creation of the firmament, in which observe, 1. The command of God concerning it: Let there be a firmament, an expansion, so the Hebrew word signifies, like a sheet spread, or a curtain drawn out. This includes all that is visible above the earth, between it and the third heavens: the air, its higher, middle, and lower, regions - the celestial globe, and all the spheres and orbs of light above: it reaches as high as the place where the sta...', 'teologico');
add('gn', 1, 9, 'Matthew Henry', 'The third day\'s work is related in these verses - the forming of the sea and the dry land, and the making of the earth fruitful. Hitherto the power of the Creator had been exerted and employed about the upper part of the visible word; the light of heaven was kindled, and the firmament of heaven fixed: but now he descends to this lower world, the earth, which was designed for the children of men, designed both for their habitation and for their maintenance; and here we have an account of the f...', 'teologico');
add('gn', 1, 14, 'Matthew Henry', 'This is the history of the fourth day\'s work, the creating of the sun, moon, and stars, which are here accounted for, not as they are in themselves and in their own nature, to satisfy the curious, but as they are in relation to this earth, to which they serve as lights; and this is enough to furnish us with matter for praise and thanksgiving. Holy Job mentions this as an instance of the glorious power of God, that by the Spirit he hath garnished the heavens (Job 26:13); and here we have an ac...', 'teologico');
add('gn', 1, 20, 'Matthew Henry', 'Each day, hitherto, has produced very noble and excellent beings, which we can never sufficiently admire; but we do not read of the creation of any living creature till the fifth day, of which these verses give us an account. The work of creation not only proceeded gradually from one thing to another, but rose and advanced gradually from that which was less excellent to that which was more so, teaching us to press towards perfection and endeavour that our last works may be our best works. It ...', 'teologico');
add('gn', 1, 24, 'Matthew Henry', 'We have here the first part of the sixth day\'s work. The sea was, the day before, replenished with its fish, and the air with its fowl; and this day were made the beasts of the earth, the cattle, and the creeping things that pertain to the earth. Here, as before, 1. The Lord gave the word; he said, Let the earth bring forth, not as if the earth had any such prolific virtue as to produce these animals, or as if God resigned his creating power to it; but, "Let these creatures now come into bein...', 'teologico');
add('gn', 1, 29, 'Matthew Henry', 'We have here the third part of the sixth day\'s work, which was not any new creation, but a gracious provision of food for all flesh, Psa 136:25. He that made man and beast thus took care to preserve both, Psa 36:6. Here is,\nI. Food provided for man, Gen 1:29. Herbs and fruits must be his meat, including corn and all the products of the earth; these were allowed him, but (it should seem) not flesh, till after the flood, Gen 9:3. And before the earth was deluged, much more before it was cursed ...', 'teologico');
add('gn', 1, 31, 'Matthew Henry', 'We have here the approbation and conclusion of the whole work of creation. As for God, his work is perfect; and if he begin he will also make an end, in providence and grace, as well as here in creation. Observe,\nI. The review God took of his work: He saw every thing that he had made. So he does still; all the works of his hands are under his eye. He that made all sees all; he that made us sees us, Ps. 139:1-16. Omniscience cannot be separated from omnipotence. Known unto God are all his work...', 'teologico');
add('gn', 2, 1, 'Matthew Henry', 'We have here, I. The settlement of the kingdom of nature, in God\'s resting from the work of creation, Gen 2:1, Gen 2:2. Here observe, 1. The creatures made both in heaven and earth are the hosts or armies of them, which denotes them to be numerous, but marshalled, disciplined, and under command. How great is the sum of them! And yet every one knows and keeps his place. God uses them as his hosts for the defence of his people and the destruction of his enemies; for he is the Lord of hosts, of ...', 'teologico');
add('gn', 2, 4, 'Matthew Henry', 'In these verses, I. Here is a name given to the Creator which we have not yet met with, and that is Jehovah - the LORD, in capital letters, which are constantly used in our English translation to intimate that in the original it is Jehovah. All along, in the first chapter, he was called Elohim - a God of power; but now Jehovah Elohim - a God of power and perfection, a finishing God. As we find him known by his name Jehovah when he appeared to perform what he had promised (Exo 6:3), so now we ...', 'teologico');
add('gn', 2, 8, 'Matthew Henry', 'Man consisting of body and soul, a body made out of the earth and a rational immortal soul the breath of heaven, we have, in these verses, the provision that was made for the happiness of both; he that made him took care to make him happy, if he could but have kept himself so and known when he was well off. That part of man by which he is allied to the world of sense was made happy; for he was put in the paradise of God: that part by which he is allied to the world of spirits was well provide...', 'teologico');
add('gn', 2, 16, 'Matthew Henry', 'Observe here, I. God\'s authority over man, as a creature that had reason and freedom of will. The Lord God commanded the man, who stood now as a public person, the father and representative of all mankind, to receive law, as he had lately received a nature, for himself and all his. God commanded all the creatures, according to their capacity; the settled course of nature is a law, Psa 148:6; Psa 104:9. The brute-creatures have their respective instincts; but man was made capable of performing...', 'teologico');
add('gn', 2, 21, 'Matthew Henry', 'Here we have, I. The making of the woman, to be a help-meet for Adam. This was done upon the sixth day, as was also the placing of Adam in paradise, though it is here mentioned after an account of the seventh day\'s rest; but what was said in general (Gen 1:27), that God made man male and female, is more distinctly related here. Observe, 1. That Adam was first formed, then Eve (Ti1 2:13), and she was made of the man, and for the man (Co1 11:8, Co1 11:9), all which are urged there as reasons fo...', 'teologico');
add('gn', 3, 9, 'Matthew Henry', 'We have here the arraignment of these deserters before the righteous Judge of heaven and earth, who, though he is not tied to observe formalities, yet proceeds against them with all possible fairness, that he may be justified when he speaks. Observe here,\nI. The startling question with which God pursued Adam and arrested him: Where art thou? Not as if God did not know where he was; but thus he would enter the process against him. "Come, where is this foolish man?" Some make it a bemoaning que...', 'teologico');
add('gn', 3, 11, 'Matthew Henry', 'We have here the offenders found guilty by their own confession, and yet endeavouring to excuse and extenuate their fault. They could not confess and justify what they had done, but they confess and palliate it. Observe,\nI. How their confession was extorted from them. God put it to the man: Who told thee that thou wast naked? Gen 3:11. "How camest thou to be sensible of thy nakedness as thy shame?" Hast thou eaten of the forbidden tree? Note, Though God knows all our sins, yet he will know th...', 'teologico');
add('gn', 3, 14, 'Matthew Henry', 'The prisoners being found guilty by their own confession, besides the personal and infallible knowledge of the Judge, and nothing material being offered in arrest of judgment, God immediately proceeds to pass sentence; and, in these verses, he begins (where the sin began) with the serpent. God did not examine the serpent, nor ask him what he had done nor why he did it; but immediately sentenced him, 1. Because he was already convicted of rebellion against God, and his malice and wickedness we...', 'teologico');
add('gn', 3, 16, 'Matthew Henry', 'We have here the sentence passed upon the woman for her sin. Two things she is condemned to: a state of sorrow, and a state of subjection, proper punishments of a sin in which she had gratified her pleasure and her pride.\nI. She is here put into a state of sorrow, one particular of which only is specified, that in bringing forth children; but it includes all those impressions of grief and fear which the mind of that tender sex is most apt to receive, and all the common calamities which they a...', 'teologico');
add('gn', 3, 17, 'Matthew Henry', 'We have here the sentence passed upon Adam, which is prefaced with a recital of his crime: Because thou hast hearkened to the voice of thy wife, Gen 3:17. He excused the fault, by laying it on his wife: She gave it me. But God does not admit the excuse. She could but tempt him, she could not force him; though it was her fault to persuade him to eat, it was his fault to hearken to her. Thus men\'s frivolous pleas will, in the day of God\'s judgment, not only be overruled, but turned against them...', 'teologico');
add('gn', 3, 20, 'Matthew Henry', 'God having named the man, and called him Adam, which signifies red earth, Adam, in further token of dominion, named the woman, and called her Eve, that is, life. Adam bears the name of the dying body, Eve that of the living soul. The reason of the name is here given (some think, by Moses the historian, others, by Adam himself): Because she was (that is, was to be) the mother of all living. He had before called her Ishah - woman, as a wife; here he calls her Evah - life, as a mother. Now, 1. I...', 'teologico');
add('gn', 3, 21, 'Matthew Henry', 'We have here a further instance of God\'s care concerning our first parents, notwithstanding their sin. Though he corrects his disobedient children, and put them under the marks of his displeasure, yet he does not disinherit them, but, like a tender father, provides the herb of the field for their food and coats of skins for their clothing. Thus the father provided for the returning prodigal, Luk 15:22, Luk 15:23. If the Lord had been pleased to kill them, he would not have done this for them....', 'teologico');
add('gn', 3, 22, 'Matthew Henry', 'Sentence being passed upon the offenders, we have here execution, in part, done upon them immediately. Observe here,\nI. How they were justly disgraced and shamed before God and the holy angels, by the ironical upbraiding of them with the issue of their enterprise: "Behold, the man has become as one of us, to know good and evil! A goodly god he makes! Does he not? See what he has got, what preferments, what advantages, by eating forbidden fruit!" This was said to awaken and humble them, and to...', 'teologico');
add('gn', 4, 1, 'Matthew Henry', 'Adam and Eve had many sons and daughters, Gen 5:4. But Cain and Abel seem to have been the two eldest. Some think they were twins, and, as Esau and Jacob, the elder hated and the younger loved. Though God had cast our first parents out of paradise, he did not write them childless; but, to show that he had other blessings in store for them, he preserved to them the benefit of that first blessing of increase. Though they were sinners, nay, though they felt the humiliation and sorrow of penitent...', 'teologico');
add('gn', 4, 3, 'Matthew Henry', 'Here we have, I. The devotions of Cain and Abel. In process of time, when they had made some improvement in their respective callings (Heb. At the end of days, either at the end of the year, when they kept their feast of in-gathering or perhaps an annual fast in remembrance of the fall, or at the end of the days of the week, the seventh day, which was the sabbath) - at some set time, Cain and Abel brought to Adam, as the priest of the family, each of them an offering to the Lord, for the doin...', 'teologico');
add('gn', 4, 6, 'Matthew Henry', 'God is here reasoning with Cain, to convince him of the sin and folly of his anger and discontent, and to bring him into a good temper again, that further mischief might be prevented. It is an instance of God\'s patience and condescending goodness that he would deal thus tenderly with so bad a man, in so bad an affair. He is not willing that any should perish, but that all should come to repentance. Thus the father of the prodigal argued the case with the elder son (Luk 15:28, etc.), and God w...', 'teologico');
add('gn', 4, 8, 'Matthew Henry', 'We have here the progress of Cain\'s anger, and the issue of it in Abel\'s murder, which may be considered two ways: - \nI. As Cain\'s sin; and a scarlet, crimson, sin it was, a sin of the first magnitude, a sin against the light and law of nature, and which the consciences even of bad men have startled at. See in it, 1. The sad effects of sin\'s entrance into the world and into the hearts of men. See what a root of bitterness the corrupt nature is, which bears this gall and wormwood. Adam\'s eatin...', 'teologico');
add('gn', 4, 9, 'Matthew Henry', 'We have here a full account of the trial and condemnation of the first murderer. Civil courts of judicature not being yet erected for this purpose, as they were afterwards (Gen 9:6), God himself sits Judge; for he is the God to whom vengeance belongs, and who will be sure to make inquisition for blood, especially the blood of saints. Observe,\nI. The arraignment of Cain: The Lord said unto Cain, Where is Abel thy brother? Some think Cain was thus examined the next sabbath after the murder was ...', 'teologico');
add('gn', 4, 13, 'Matthew Henry', 'We have here a further account of the proceedings against Cain.\nI. Here is Cain\'s complaint of the sentence passed upon him, as hard and severe. Some make him to speak the language of despair, and read it, My iniquity is greater than that it may be forgiven; and so what he says is a reproach and affront to the mercy of God, which those only shall have the benefit of that hope in it. There is forgiveness with the God of pardons for the greatest sins and sinners; but those forfeit it who despai...', 'teologico');
add('gn', 4, 16, 'Matthew Henry', 'We have here a further account of Cain, and what became of him after he was rejected of God.\nI. He tamely submitted to that part of his sentence by which he was hidden from God\'s face; for (Gen 4:16) he went out from the presence of the Lord, that is, he willingly renounced God and religion, and was content to forego its privileges, so that he might not be under its precepts. He forsook Adam\'s family and altar, and cast off all pretensions to the fear of God, and never came among good people,...', 'teologico');
add('gn', 4, 19, 'Matthew Henry', 'We have here some particulars concerning Lamech, the seventh from Adam in the line of Cain. Observe,\nI. His marrying two wives. It was one of the degenerate race of Cain who first transgressed that original law of marriage that two only should be one flesh. Hitherto one man had but one wife at a time; but Lamech took two. From the beginning it was not so. Mal 2:15; Mat 19:5. See here, 1. Those who desert God\'s church and ordinances lay themselves open to all manner of temptation. 2. When a ba...', 'teologico');
add('gn', 4, 23, 'Matthew Henry', 'By this speech of Lamech, which is here recorded, and probably was much talked of in those times, he further appears to have been a wicked man, as Cain\'s accursed race generally were. Observe, 1. How haughtily and imperiously he speaks to his wives, as one that expected a mighty regard and observance: Hear my voice, you wives of Lamech. No marvel that he who had broken one law of marriage, by taking two wives, broke another, which obliged him to be kind and tender to those he had taken, and t...', 'teologico');
add('gn', 4, 25, 'Matthew Henry', 'This is the first mention of Adam in the story of this chapter. No question, the murder of Abel, and the impenitence and apostasy of Cain, were a very great grief to him and Eve, and the more because their own wickedness did now correct them and their backslidings did reprove them. Their folly had given sin and death entrance into the world; and now they smarted by it, being, by means thereof, deprived of both their sons in one day, Gen 27:45. When parents are grieved by their children\'s wick...', 'teologico');
add('gn', 5, 1, 'Matthew Henry', 'The first words of the chapter are the title or argument of the whole chapter: it is the book of the generations of Adam; it is the list or catalogue of the posterity of Adam, not of all, but only of the holy seed who were the substance thereof (Isa 6:13), and of whom, as concerning the flesh, Christ came (Rom 9:5), the names, ages, and deaths, of those that were the successors of the first Adam in the custody of the promise, and the ancestors of the second Adam. The genealogy begins with Ada...', 'teologico');
add('gn', 5, 6, 'Matthew Henry', 'We have here all that the Holy Ghost thought fit to leave upon record concerning five of the patriarchs before the flood, Seth, Enos, Cainan, Mahalaleel, and Jared. There is nothing observable concerning any of these particularly, though we have reason to think they were men of eminence, both for prudence and piety, in their day: but in general,\nI. Observe how largely and expressly their generations are recorded. This matter, one would think, might have been delivered in fewer words; but it i...', 'teologico');
add('gn', 5, 21, 'Matthew Henry', 'The accounts here run on for several generations without any thing remarkable, or any variation but of the names and numbers; but at length there comes in one that must not be passed over so, of whom special notice must be taken, and that is Enoch, the seventh from Adam: the rest, we may suppose, did virtuously, but he excelled them all, and was the brightest star of the patriarchal age. It is but little that is recorded concerning him; but this little is enough to make his name great, greate...', 'teologico');
add('gn', 5, 25, 'Matthew Henry', 'Concerning Methuselah observe, 1. The signification of his name, which some think was prophetical, his father Enoch being a prophet. Methuselah signifies, he dies, or there is a dart, or, a sending forth, namely, of the deluge, which came the very year that Methuselah died. If indeed his name was so intended and so explained, it was fair warning to a careless world, a long time before the judgment came. However, this is observable, that the longest liver that ever was carried death in his nam...', 'teologico');
add('gn', 5, 28, 'Matthew Henry', 'Here we have the first mention of Noah, of whom we shall read much in the following chapters. Observe,\nI. His name, with the reason of it: Noah signifies rest; his parents gave him that name, with a prospect of his being a more than ordinary blessing to his generation: This same shall comfort us concerning our work and toil of our hands, because of the ground which the Lord hath cursed. Here is, 1. Lamech\'s complaint of the calamitous state of human life. By the entrance of sin, and the entai...', 'teologico');
add('gn', 6, 1, 'Matthew Henry', 'For the glory of God\'s justice, and for warning to a wicked world, before the history of the ruin of the old world, we have a full account of its degeneracy, its apostasy from God and rebellion against him. The destroying of it was an act, not of an absolute sovereignty, but of necessary justice, for the maintaining of the honour of God\'s government. Now here we have an account of two things which occasioned the wickedness of the old world: - 1. The increase of mankind: Men began to multiply ...', 'teologico');
add('gn', 6, 3, 'Matthew Henry', 'This comes in here as a token of God\'s displeasure at those who married strange wives; he threatens to withdraw from them his Spirit, whom they had grieved by such marriages, contrary to their convictions: fleshly lusts are often punished with spiritual judgments, the sorest of all judgments. Or as another occasion of the great wickedness of the old world; the Spirit of the Lord, being provoked by their resistance of his motions, ceased to strive with them, and then all religion was soon lost...', 'teologico');
add('gn', 6, 4, 'Matthew Henry', 'We have here a further account of the corruption of the old world. When the sons of God had matched with the daughters of men, though it was very displeasing to God, yet he did not immediately cut them off, but waited to see what would be the issue of these marriages, and which side the children would take after; and it proved (as usually it does), that they took after the worst side. Here is,\nI. The temptation they were under to oppress and do violence. They were giants, and they were men of...', 'teologico');
add('gn', 6, 6, 'Matthew Henry', 'Here is, I. God\'s resentment of man\'s wickedness. He did not see it as an unconcerned spectator, but as one injured and affronted by it; he saw it as a tender father sees the folly and stubbornness of a rebellious and disobedient child, which not only angers him, but grieves him, and makes him wish he had been written childless. The expressions here used are very strange: It repented the Lord that he had made man upon the earth, that he had made a creature of such noble powers and faculties, ...', 'teologico');
add('gn', 6, 11, 'Matthew Henry', 'The wickedness of that generation is here again spoken of, either as a foil to Noah\'s piety - he was just and perfect, when all the earth was corrupt; or as a further justification of God\'s resolution to destroy the world, which he was now about to communicate to his servant Noah. 1. All kinds of sin was found among them, for it is said (Gen 6:11) that the earth was, (1.) Corrupt before God, that is, in the matters of God\'s worship; either they had other gods before him, or they worshipped hi...', 'teologico');
add('gn', 6, 13, 'Matthew Henry', 'Here it appears indeed that Noah found grace in the eyes of the Lord. God\'s favour to him was plainly intimated in what he said of him, Gen 6:8-10, where his name is mentioned five times in five lines, when once might have served to make the sense clear, as if the Holy Ghost took a pleasure in perpetuating his memory; but it appears much more in what he says to him in these verses - the informations and instructions here given him.\nI. God here makes Noah the man of his counsel, communicating ...', 'teologico');
add('gn', 6, 22, 'Matthew Henry', 'Noah\'s care and diligence in building the ark may be considered, 1. As an effect of his faith in the word of God. God had told him he would shortly drown the world; he believed it, feared the threatened deluge, and, in that fear, prepared the ark. Note, We ought to mix faith with the revelation God has made of his wrath against all ungodliness and unrighteousness of men; the threatenings of the word are not false alarms. Much might have been objected against the credibility of this warning gi...', 'teologico');
add('gn', 7, 1, 'Matthew Henry', 'Here is, I. A gracious invitation of Noah and his family into a place of safety, now that the flood of waters was coming, Gen 7:1.\n1. The call itself is very kind, like that of a tender father to his children, to come in doors, when he sees night or a storm coming: Come thou, and all thy house, that small family that thou hast, into the ark. Observe, (1.) Noah did not go into the ark till God bade him; though he knew it was designed for his place of refuge, yet he waited for a renewed command...', 'teologico');
add('gn', 7, 5, 'Matthew Henry', 'Here is Noah\'s ready obedience to the commands that God gave him. Observe, 1. He went into the ark, upon notice that the flood would come after seven days, though probably as yet there appeared no visible sign of its approach, no cloud arising that threatened it, nothing done towards it, but all continued serene and clear; for, as he prepared the ark by faith in the warning given that the flood would come, so he went into it by faith in this warning that it would come quickly, though he did n...', 'teologico');
add('gn', 7, 11, 'Matthew Henry', 'Here is, I. The date of this great event; this is carefully recorded, for the greater certainty of the story.\n1. It was in the 600th year of Noah\'s life, which, by computation, appears to be 1656 years from the creation. The years of the old world are reckoned, not by the reigns of the giants, but the lives of the patriarchs; saints are of more account with God than princes. The righteous shall be had in everlasting remembrance. Noah was now a very old man, even as men\'s years went then. Note...', 'teologico');
add('gn', 7, 13, 'Matthew Henry', 'Here is repeated what was related before of Noah\'s entrance into the ark, with his family and creatures that were marked for preservation. Now,\nI. It is thus repeated for the honour of Noah, whose faith and obedience herein shone so brightly, by which he obtained a good report, and who herein appeared so great a favourite of Heaven and so great a blessing to this earth.\nII. Notice is here taken of the beasts going in each after his kind, according to the phrase used in the history of the crea...', 'teologico');
add('gn', 7, 17, 'Matthew Henry', 'We are here told,\nI. How long the flood was increasing - forty days, Gen 7:17. The profane world, who believed not that it would come, probably when it came flattered themselves with hopes that it would soon abate and never come to extremity; but still it increased, it prevailed. Note, 1. When God judges he will overcome. If he begin, he will make an end; his way is perfect, both in judgment and mercy. 2. The gradual approaches and advances of God\'s judgments, which are designed to bring sinn...', 'teologico');
add('gn', 7, 21, 'Matthew Henry', 'Here is, I. The general destruction of all flesh by the waters of the flood. Come, and see the desolations which God makes in the earth (Psa 46:8), and how he lays heaps upon heaps. Never did death triumph, from its first entrance unto this day, as it did then. Come, and see Death upon his pale horse, and hell following with him, Rev 6:7, Rev 6:8.\n1. All the cattle, fowl, and creeping things, died, except the few that were in the ark. Observe how this is repeated: All flesh died, Gen 7:21. Al...', 'teologico');
add('gn', 8, 1, 'Matthew Henry', 'Here is, I. An act of God\'s grace: God remembered Noah and every living thing. This is an expression after the manner of men; for not any of his creatures (Luk 12:6), much less any of his people, are forgotten of God, Isa 49:15, Isa 49:16. but, 1. The whole race of mankind, except Noah and his family, was now extinguished, and driven into the land of forgetfulness, to be remembered no more; so that God\'s remembering Noah was the return of his mercy to mankind, of whom he would not make a full...', 'teologico');
add('gn', 8, 4, 'Matthew Henry', 'Here we have the effects and evidences of the ebbing of the waters. 1. The ark rested. This was some satisfaction to Noah, to feel the house he was in upon firm ground, and no longer movable. It rested upon a mountain, whither it was directed, not by Noah\'s prudence (he did not steer it), but by the wise and gracious providence of God, that it might rest the sooner. Note, God has times and places of rest for his people after their tossings; and many a time he provides for their seasonable and...', 'teologico');
add('gn', 8, 6, 'Matthew Henry', 'We have here an account of the spies which Noah sent forth to bring him intelligence from abroad, a raven and a dove. Observe here,\nI. That though God had told Noah particularly when the flood would come, even to a day (Gen 7:4), yet he did not give him a particular account by revelation at what times, and by what steps, it should go away, 1. Because the knowledge of the former was necessary to his preparing the ark, and settling himself in it; but the knowledge of the latter would serve only...', 'teologico');
add('gn', 8, 13, 'Matthew Henry', 'Here is, 1. The ground dry (Gen 8:13), that is, all the water carried off it, which, upon the first day of the first month (a joyful new-year\'s-day it was), Noah was himself an eye-witness of. He removed the covering of the ark, not the whole covering, but so much as would suffice to give him a prospect of the earth about it; and a most comfortable prospect he had. For behold, behold and wonder, the face of the ground was dry. Note, (1.) It is a great mercy to see ground about us. Noah was mo...', 'teologico');
add('gn', 8, 15, 'Matthew Henry', 'Here is, I. Noah\'s dismission out of the ark, Gen 8:15-17. Observe, 1. Noah did not stir till God bade him. As he had a command to go into the ark (Gen 7:1), so, how tedious soever his confinement there was, he would wait for a command to go out of it again. Note, We must in all our ways acknowledge God, and set him before us in all our removes. Those only go under God\'s protection that follow God\'s direction and submit to his government. Those that steadily adhere to God\'s word as their rule...', 'teologico');
add('gn', 8, 20, 'Matthew Henry', 'Here is, I. Noah\'s thankful acknowledgment of God\'s favour to him, in completing the mercy of his deliverance, Gen 8:20. 1. He built an altar. Hitherto he had done nothing without particular instructions and commands from God. He had a particular call into the ark, and another out of it; but, altars and sacrifices being already of divine institution for religious worship, he did not stay for a particular command thus to express his thankfulness. Those that have received mercy from God should ...', 'teologico');
add('gn', 9, 1, 'Matthew Henry', 'We read, in the close of the foregoing chapter, the very kind things which God said in his heart, concerning the remnant of mankind which was now left to be the seed of a new world. Now here we have these kind things spoken to them. In general, God blessed Noah and his sons (Gen 9:1), that is, he assured them of his good-will to them and his gracious intentions concerning them. This follows from what he said in his heart. Note, All God\'s promises of good flow from his purposes of love and the...', 'teologico');
add('gn', 9, 8, 'Matthew Henry', 'Here is, I. The general establishment of God\'s covenant with this new world, and the extent of that covenant, Gen 9:9, Gen 9:10. Here observe, 1. That God is graciously pleased to deal with man in the way of a covenant, wherein God greatly magnifies his condescending favour, and greatly encourages man\'s duty and obedience, as a reasonable and gainful service. 2. That all God\'s covenants with man are of his own making: I, behold, I. It is thus expressed both to raise our admiration - "Behold, ...', 'teologico');
add('gn', 9, 12, 'Matthew Henry', 'Articles of agreement among men are usually sealed, that the covenants may be the more solemn, and the performances of the covenants the more sure, to mutual satisfaction. God therefore, being willing more abundantly to show to the heirs of promise the immutability of his councils, has confirmed his covenant by a seal (Heb 6:17), which makes the foundations we build on stand sure, Ti2 2:19. The seal of this covenant of nature was natural enough; it was the rainbow, which, it is likely, was se...', 'teologico');
add('gn', 9, 18, 'Matthew Henry', 'Here is, I. Noah\'s family and employment. The names of his sons are again mentioned (Gen 9:18, Gen 9:19) as those from whom the whole earth was overspread, by which it appears that Noah, after the flood, had no more children: all the world came from these three. Note, God, when he pleases, can make a little one to become a thousand, and greatly increase the latter end of those whose beginning was small. Such are the power and efficacy of a divine blessing. The business Noah applied himself to...', 'teologico');
add('gn', 9, 24, 'Matthew Henry', 'Here, I. Noah comes to himself: He awoke from his wine. Sleep cured him, and, we may suppose, so cured him that he never relapsed into that sin afterwards. Those that sleep as Noah did should awake as he did, and not as that drunkard (Pro 23:35) who says when he awakes, I will seek it yet again.\nII. The spirit of prophecy comes upon him, and, like dying Jacob, he tells his sons what shall befal them, Gen 49:1.\n1. He pronounces a curse on Canaan the son of Ham (Gen 9:25), in whom Ham is himsel...', 'teologico');
add('gn', 9, 28, 'Matthew Henry', 'Here see, 1. How God prolonged the life of Noah; he lived 950 years, twenty more than Adam and but nineteen less than Methuselah: this long life was a further reward of his signal piety, and a great blessing to the world, to which no doubt he continued a preacher of righteousness, with this advantage, that now all he preached to were his own children. 2. How God put a period to his life at last. Though he lived long, yet he died, having probably first seen many that descended from him dead be...', 'teologico');
add('gn', 10, 1, 'Matthew Henry', 'Moses begins with Japheth\'s family, either because he was the eldest, or because his family lay remotest from Israel and had least concern with them at the time when Moses wrote, and therefore he mentions that race very briefly, hastening to give an account of the posterity of Ham, who were Israel\'s enemies and of Shem, who were Israel\'s ancestors; for it is the church that the scripture is designed to be the history of, and of the nations of the world only as they were some way or other rela...', 'teologico');
add('gn', 10, 6, 'Matthew Henry', 'That which is observable and improvable in these verses is the account here given of Nimrod, Gen 10:8-10. He is here represented as a great man in his day: He began to be a mighty one in the earth, that is, whereas those that went before him were content to stand upon the same level with their neighbours, and though every man bore rule in his own house yet no man pretended any further, Nimrod\'s aspiring mind could not rest here; he was resolved to tower above his neighbours, not only to be em...', 'teologico');
add('gn', 10, 15, 'Matthew Henry', 'Observe here, 1. The account of the posterity of Canaan, of the families and nations that descended from him, and of the land they possessed, is more particular than of any other in this chapter, because these were the nations that were to be subdued before Israel, and their land was in process of time to become the holy land, Immanuel\'s land; and this God had an eye to when, in the mean time, he cast the lot of that accursed devoted race in that spot of ground which he had selected for his o...', 'teologico');
add('gn', 10, 21, 'Matthew Henry', 'Two things especially are observable in this account of the posterity of Shem: - \nI. The description of Shem, Gen 10:21. We have not only his name, Shem, which signifies a name, but two titles to distinguish him by: - \n1. He was the father of all the children of Eber. Eber was his great grandson; but why should he be called the father of all his children, rather than of all Arphaxad\'s, or Salah\'s, etc.? Probably because Abraham and his seed, God\'s covenant-people, not only descended from Hebe...', 'teologico');
add('gn', 11, 1, 'Matthew Henry', 'The close of the foregoing chapter tells us that by the sons of Noah, or among the sons of Noah, the nations were divided in the earth after the flood, that is, were distinguished into several tribes or colonies; and, the places having grown too strait for them, it was either appointed by Noah, or agreed upon among his sons, which way each several tribe or colony should steer its course, beginning with the countries that were next them, and designing to proceed further and further, and to rem...', 'teologico');
add('gn', 11, 5, 'Matthew Henry', 'We have here the quashing of the project of the Babel-builders, and the turning of the counsel of those froward men headlong, that God\'s counsel might stand in spite of them. Here is,\nI. The cognizance God took of the design that was on foot: The Lord came down to see the city, Gen 11:5. It is an expression after the manner of men; he knew it as clearly and fully as men know that which they come to the place to view. Observe, 1. Before he gave judgment upon their cause, he enquired into it; f...', 'teologico');
add('gn', 11, 10, 'Matthew Henry', 'We have here a genealogy, not an endless genealogy, for here it ends in Abram, the friend of God, and leads further to Christ, the promised seed, who was the son of Abram, and from Abram the genealogy of Christ is reckoned (Mat 1:1, etc.); so that put ch. 5, ch. 11, and Mt. 1, together, and you have such an entire genealogy of Jesus Christ as cannot be produced, for aught I know, concerning any person in the world, out of his line, and at such a distance from the fountain-head. And, laying th...', 'teologico');
add('gn', 11, 27, 'Matthew Henry', 'Here begins the story of Abram, whose name is famous, henceforward, in both Testaments. We have here,\nI. His country: Ur of the Chaldees. This was the land of his nativity, an idolatrous country, where even the children of Eber themselves had degenerated. Note, Those who are, through grace, heirs of the land of promise, ought to remember what was the land of their nativity, what was their corrupt and sinful state by nature, the rock out of which they were hewn.\nII. His relations, mentioned fo...', 'teologico');
add('gn', 12, 4, 'Matthew Henry', 'Here is, I. Abraham\'s removal out of his country, out of Ur first and afterwards out of Haran, in compliance with the call of God: So Abram departed; he was not disobedient to the heavenly vision, but did as he was bidden, not conferring with flesh and blood, Gal 1:15, Gal 1:16. His obedience was speedy and without delay, submissive and without dispute; for he went out, not knowing whither he went (Heb 11:8), but knowing whom he followed and under whose direction he went. Thus God called him ...', 'teologico');
add('gn', 12, 6, 'Matthew Henry', 'One would have expected that Abram having had such an extraordinary call to Canaan some great event should have followed upon his arrival there, that he would have been introduced with all possible marks of honour and respect, and that the kings of Canaan should immediately have surrendered their crowns to him, and done him homage. But no; he comes not with observation, little notice is taken of him, for still God will have him to live by faith, and to look upon Canaan, even when he was in it...', 'teologico');
add('gn', 12, 10, 'Matthew Henry', 'Here is, I. A famine in the land of Canaan, a grievous famine. That fruitful land was turned into barrenness, not only to punish the iniquity of the Canaanites who dwelt therein, but to exercise the faith of Abram who sojourned therein; and a very sore trial it was; it tried what he would think, 1. Of God that brought him thither, whether he would not be ready to say with his murmuring seed that he was brought forth to be killed with hunger, Exo 16:3. Nothing short of a strong faith could kee...', 'teologico');
add('gn', 12, 14, 'Matthew Henry', 'Here is, I. The danger Sarai was in of having her chastity violated by the king of Egypt: and without doubt the peril of sin is the greatest peril we can be in. Pharaoh\'s princes (his pimps rather) saw her, and, observing what a comely woman she was, they commended her before Pharaoh, not for that which was really her praise - her virtue and modesty, her faith and piety (these were no excellencies in their eyes), but for her beauty, which they thought too good for the embraces of a subject. T...', 'teologico');
add('gn', 13, 1, 'Matthew Henry', 'I. Here is Abram\'s return out of Egypt, Gen 13:1. He came himself and brought all his with him back again to Canaan. Note, Though there may be occasion to go sometimes into places of temptation, yet we must hasten out of them as soon as possible. See Rut 1:6.\nII. His wealth: He was very rich, Rut 1:2. He was very heavy, so the Hebrew word signifies; for riches are a burden, and those that will be rich do but load themselves with thick clay, Hab 2:6. There is a burden of care in getting them, ...', 'teologico');
add('gn', 13, 5, 'Matthew Henry', 'We have here an unhappy falling out between Abram and Lot, who had hitherto been inseparable companions (see Gen 13:1, and Gen 12:4), but now parted.\nI. The occasion of their quarrel was their riches. We read (Gen 13:2) how rich Abram was; now here we are told (Gen 13:5) that Lot, who went with Abram, was rich too; and therefore God blessed him with riches because he went with Abram. Note, 1. It is good being in good company, and going with those with whom God is, Zac 8:23. 2. Those that are ...', 'teologico');
add('gn', 13, 10, 'Matthew Henry', 'We have here the choice that Lot made when he parted from Abram. Upon this occasion, one would have expected, 1. That he should have expressed an unwillingness to part from Abram, and that, at least, he should have done it with reluctancy. 2. That he should have been so civil as to have remitted the choice back again to Abram. But we find not any instance of deference or respect to his uncle in the whole management. Abram having offered him the choice, without compliment he accepted it, and m...', 'teologico');
add('gn', 13, 14, 'Matthew Henry', 'We have here an account of a gracious visit which God paid to Abram, to confirm the promise to him and his. Observe,\nI. When it was that God renewed and ratified the promise: After that Lot was separated from him, that is, 1. After the quarrel was over; for those are best prepared for the visits of divine grace whose spirits are calm and sedate, and not ruffled with any passion. 2. After Abram\'s humble self-denying condescensions to Lot for the preserving of peace. It was then that God came t...', 'teologico');
add('gn', 14, 1, 'Matthew Henry', 'We have here an account of the first war that ever we read of in scripture, which (though the wars of the nations make the greatest figure in history) we should not have had the history of if Abram and Lot had not been concerned in it. Now, concerning this war, we may observe,\nI. The parties engaged in it. The invaders were four kings, two of them no less than kings of Shinar and Elam (that is, Chaldea and Persia), yet probably not the sovereign princes of those great kingdoms in their own pe...', 'teologico');
add('gn', 14, 13, 'Matthew Henry', 'We have here an account of the only military action we ever find Abram engaged in, and this he was prompted to, not by his avarice or ambition, but purely by a principle of charity; it was not to enrich himself, but to help his friend. Never was any military expedition undertaken, prosecuted, and finished, more honourably than this of Abram\'s. Here we have,\nI. The tidings brought him of his kinsman\'s distress. Providence so ordered it that he now sojourned not far off, that he might be a very...', 'teologico');
add('gn', 14, 17, 'Matthew Henry', 'This paragraph begins with the mention of the respect which the king of Sodom paid to Abram at his return from the slaughter of the kings; but, before a particular account is given of this, the story of Melchizedek is briefly related, concerning whom observe,\nI. Who he was. He was king of Salem and priest of the most high God; and other glorious things are said of him, Heb 7:1, etc. 1. The rabbin, and most of our rabbinical writers, conclude that Melchizedek was Shem the son of Noah, who was ...', 'teologico');
add('gn', 14, 21, 'Matthew Henry', 'We have here an account of what passed between Abram and the king of Sodom, who succeeded him that fell in the battle (Gen 14:10), and thought himself obliged to do this honour to Abram, in return for the good services he had done him. Here is,\nI. The king of Sodom\'s grateful offer to Abram (Gen 14:21): Give me the soul, and take thou the substance; so the Hebrew reads it. Here he fairly begs the persons, but as freely bestows the goods on Abram. Note, 1. Where a right is dubious and divided,...', 'teologico');
add('gn', 15, 1, 'Matthew Henry', 'Observe here, I. The time when God made this treaty with Abram: After these things. 1. After that famous act of generous charity which Abram had done, in rescuing his friends and neighbours out of distress, and that, not for price nor reward. After this, God made him this gracious visit. Note, Those that show favour to men shall find favour with God. 2. After that victory which he had obtained over four kings. Lest Abram should be too much elevated and pleased with that, God comes to him, to ...', 'teologico');
add('gn', 15, 2, 'Matthew Henry', 'We have here the assurance given to Abram of a numerous offspring which should descend from him, in which observe,\nI. Abram\'s repeated complaint, Gen 15:2, Gen 15:3. This was that which gave occasion to this promise. The great affliction that sat heavy upon Abram was the want of a child; and the complaint of this he here pours out before the Lord, and shows before him his trouble, Psa 142:2. Note, Though we must never complain of God, yet we have leave to complain to him, and to be large and ...', 'teologico');
add('gn', 15, 7, 'Matthew Henry', 'We have here the assurance given to Abram of the land of Canaan for an inheritance.\nI. God declares his purpose concerning it, Gen 15:7. Observe here, Abram made no complaint in this matter, as he had done for the want of a child. Note, Those that are sure of an interest in the promised seed will see no reason to doubt of a title to the promised land. If Christ is ours, heaven is ours. Observe again, When he believed the former promise (Gen 15:6) then God explained and ratified this to him. N...', 'teologico');
add('gn', 15, 12, 'Matthew Henry', 'We have here a full and particular discovery made to Abram of God\'s purposes concerning his seed. Observe,\nI. The time when God came to him with this discovery: When the sun was going down, or declining, about the time of the evening oblation, Kg1 18:36; Dan 9:21. Early in the morning, before day, while the stars were yet to be seen, God had given him orders concerning the sacrifices (Gen 15:5), and we may suppose it was, at least, his morning\'s work to prepare them and set them in order; whe...', 'teologico');
add('gn', 15, 17, 'Matthew Henry', 'Here is, I. The covenant ratified (Gen 15:17); the sign which Abram desired was given, at length, when the sun had gone down, so that it was dark; for that was a dark dispensation.\n1. The smoking furnace signified the affliction of his seed in Egypt. They were there in the iron furnace (Deu 4:20), the furnace of affliction (Isa 48:10), labouring in the very fire. They were there in the smoke, their eyes darkened, that they could not see to the end of their troubles, and themselves at a loss t...', 'teologico');
add('gn', 16, 1, 'Matthew Henry', 'We have here the marriage of Abram to Hagar, who was his secondary wife. Herein, though some excuse may be made for him, he cannot be justified, for from the beginning it was not so; and, when it was so, it seems to have proceeded from an irregular desire to build up families for the speedier peopling of the world and the church. Certainly it must not be so now. Christ has reduced this matter to the first institution, and makes the marriage union to be between one man and one woman only. Now,...', 'teologico');
add('gn', 16, 4, 'Matthew Henry', 'We have here the immediate bad consequences of Abram\'s unhappy marriage to Hagar. A great deal of mischief it made quickly. When we do not well both sin and trouble lie at the door; and we may thank ourselves for the guilt and grief that follow us when we go out of the way of our duty. See it in this story.\nI. Sarai is despised, and thereby provoked and put into a passion, Gen 16:4. Hagar no sooner perceives herself with child by her master than she looks scornfully upon her mistress, upbraid...', 'teologico');
add('gn', 16, 7, 'Matthew Henry', 'Here is the first mention we have in scripture of an angel\'s appearance. Hagar was a type of the law, which was given by the disposition of angels; but the world to come is not put in subjection to them, Heb 2:5. Observe,\nI. How the angel arrested her in her flight, Heb 2:7. It should seem, she was making towards her own country; for she was in the way to Shur, which lay towards Egypt. It were well if our afflictions would make us think of our home, the better country. But Hagar was now out o...', 'teologico');
add('gn', 16, 10, 'Matthew Henry', 'We may suppose that the angel having given Hagar that good counsel (Gen 16:9) to return to her mistress she immediately promised to do so, and was setting her face homeward; and then the angel went on to encourage her with an assurance of the mercy God had in store for her and her seed: for God will meet those with mercy that are returning to their duty. I said, I will confess, and thou forgavest, Psa 32:5. Here is,\nI. A prediction concerning her posterity given her for her comfort in her pre...', 'teologico');
add('gn', 16, 15, 'Matthew Henry', 'It is here taken for granted, though not expressly recorded, that Hagar did as the angel commanded her, returning to here mistress and submitting herself; and then, in the fulness of time, she brought forth her son. Note, Those who obey divine precepts shall have the comfort of divine promises. This was the son of the bond-woman that was born after the flesh (Gal 4:23), representing the unbelieving Jews, v. 25. Note, 1. Many who can call Abraham father are yet born after the flesh, Mat 3:9. 2...', 'teologico');
add('gn', 17, 1, 'Matthew Henry', 'Here is, I. The time when God made Abram this gracious visit: When he was ninety-nine years old, full thirteen years after the birth of Ishmael. 1. So long, it should seem, God\'s extraordinary appearances to Abram were intermitted; and all the communion he had with God was only in the usual was of ordinances and providences. Note, There are some special comforts which are not the daily bread, no, not of the best saints, but they are favoured with them now and then. On this side heaven they ha...', 'teologico');
add('gn', 17, 4, 'Matthew Henry', 'The promise here is introduced with solemnity: "As for me," says the great God, "behold, behold and admire it, behold and be assured of it, my covenant is with thee;" as before (Gen 17:2), I will make my covenant. Note, The covenant of grace is a covenant of God\'s own making; this he glories in (as for me), and so may we. Now here,\nI. It is promised to Abraham that he should be a father of many nations; that is, 1. That his seed after the flesh should be very numerous, both in Isaac and Ishma...', 'teologico');
add('gn', 17, 7, 'Matthew Henry', 'Here is, I. The continuance of the covenant, intimated in three things: - 1. It is established; not to be altered nor revoked. It is fixed, it is ratified, it is made as firm as the divine power and truth can make it. 2. It is entailed; it is a covenant, not with Abraham only (then it would die with him), but with his seed after him, not only his seed after the flesh, but his spiritual seed. 3. It is everlasting in the evangelical sense and meaning of it. The covenant of grace is everlasting....', 'teologico');
add('gn', 17, 15, 'Matthew Henry', 'Here is, I. The promise made to Abraham of a son by Sarai, that son in whom the promise made to him should be fulfilled, that he should be the father of many nations; for she also shall be a mother of nations, and kings of people shall be of her, Gen 17:16. Note, 1. God reveals the purposes of his good-will to his people by degrees. God had told Abraham long before that he should have a son, but never till now that he should have a son by Sarai. 2. The blessing of the Lord makes fruitful, and...', 'teologico');
add('gn', 17, 23, 'Matthew Henry', 'We have here Abraham\'s obedience to the law of circumcision. He himself and all his family were circumcised, so receiving the token of the covenant and distinguishing themselves from other families, that had no part nor lot in the matter. 1. It was an implicit obedience: He did as God had said to him, and did not ask why or wherefore. God\'s will was not only a law to him, but a reason; he did it because God told him. 2. It was a speedy obedience: In the self-same day, Gen 17:23, Gen 17:26. Si...', 'teologico');
add('gn', 18, 1, 'Matthew Henry', 'The appearance of God to Abraham seems to have had in it more of freedom and familiarity, and less of grandeur and majesty, than those we have hitherto read of; and therefore more resembles that great visit which, in the fullness of time, the Son of God was to make to the world, when the Word would be flesh, and appear as one of us. Observe here,\nI. How Abraham expected strangers, and how richly his expectations were answered (Gen 18:1): He sat in the tent-door, in the heat of the day; not so...', 'teologico');
add('gn', 18, 9, 'Matthew Henry', 'These heavenly guests (being sent to confirm the promise lately made to Abraham, that he should have a son by Sarah), while they are receiving Abraham\'s kind entertainment, they return his kindness. He receives angels, and has angels\' rewards, a gracious message from heaven, Mat 10:41.\nI. Care is taken that Sarah should be within hearing. She must conceive by faith, and therefore the promise must be made to her, Heb 11:11. It was the modest usage of that time that the women did not sit at mea...', 'teologico');
add('gn', 18, 16, 'Matthew Henry', 'The messengers from heaven had now despatched one part of their business, which was an errand of grace to Abraham and Sarah, and which they delivered first; but now they have before them work of another nature. Sodom is to be destroyed, and they must do it, Gen 19:13. Note, As with the Lord there is mercy, so he is the God to whom vengeance belongs. Pursuant to their commission, we here find, 1. That they looked towards Sodom (Gen 18:16); they set their faces against it in wrath, as God is sa...', 'teologico');
add('gn', 18, 23, 'Matthew Henry', 'Communion with God is kept up by the word and by prayer. In the word God speaks to us; in prayer we speak to him. God had revealed to Abraham his purposes concerning Sodom; now from this Abraham takes occasion to speak to God on Sodom\'s behalf. Note, God\'s word then does us good when it furnishes us with matter for prayer and excites us to it. When God has spoken to us, we must consider what we have to say to him upon it. Observe,\nI. The solemnity of Abraham\'s address to God on this occasion:...', 'teologico');
add('gn', 19, 1, 'Matthew Henry', 'These angels, it is likely, were two of the three that had just before been with Abraham, the two created angels that were sent to execute God\'s purpose concerning Sodom. Observe here, 1. There was but one good man in Sodom, and these heavenly messengers soon found him out. Wherever we are, we should enquire out those of the place that live in the fear of God, and should choose to associate ourselves with them. Mat 10:11, Enquire who is worthy, and there abide. Those of the same country, when...', 'teologico');
add('gn', 19, 4, 'Matthew Henry', 'Now it appeared, beyond contradiction, that the cry of Sodom was no louder than there was cause for. This night\'s work was enough to fill the measure. For we find here,\nI. That they were all wicked, Gen 19:4. Wickedness had become universal, and they were unanimous in any vile design. Here were old and young, and all from every quarter, engaged in this riot; the old were not past it, and the young had soon come up to it. Either they had no magistrates to keep the peace, and protect the peacea...', 'teologico');
add('gn', 19, 12, 'Matthew Henry', 'We have here the preparation for Lot\'s deliverance.\nI. Notice is given him of the approach of Sodom\'s ruin: We will destroy this place, Gen 19:13. Note, The holy angels are ministers of God\'s wrath for the destruction of sinners, as well as of his mercy for the preservation and deliverance of his people. In this sense, the good angels become evil angels, Psa 78:49.\nII. He is directed to give notice to his friends and relations, that they, it they would, might be saved with him (Gen 19:12): "H...', 'teologico');
add('gn', 19, 15, 'Matthew Henry', 'Here is, I. The rescue of Lot out of Sodom. Thought there were not ten righteous men in Sodom, for whose sakes it might be spared, yet that one righteous man that was among them delivered his own soul, Eze 14:14. Early in the morning his own guests, in kindness to him, turned him out of doors, and his family with him, Gen 19:15. His daughters that were married perished with their unbelieving husbands; but those that continued with him were preserved with him. Observe,\n1. With what a gracious ...', 'teologico');
add('gn', 19, 24, 'Matthew Henry', 'Then, when Lot had got safely into Zoar, then this ruin came; for good men are taken away from the evil to come. Then, when the sun had risen bright and clear, promising a fair day, then this storm arose, to show that it was not from natural causes. Concerning this destruction observe, 1. God was the immediate author of it. It was destruction from the Almighty: The Lord rained - from the Lord (Gen 19:24), that is, God from himself, by his own immediate power, and not in the common course of n...', 'teologico');
add('gn', 19, 26, 'Matthew Henry', 'This also is written for our admonition. Our Saviour refers to it (Luk 17:32), Remember Lot\'s wife. As by the example of Sodom the wicked are warned to turn from their wickedness, so by the example of Lot\'s wife the righteous are warned not to turn from their righteousness. See Eze 3:18, Eze 3:20. We have here,\nI. The sin of Lot\'s wife: She looked back from behind him. This seemed a small thing, but we are sure, by the punishment of it, that it was a great sin, and exceedingly sinful. 1. She ...', 'teologico');
add('gn', 19, 27, 'Matthew Henry', 'Our communion with God consists in our gracious regard to him and his gracious regard to us; we have here therefore the communion that was between God and Abraham, in the event concerning Sodom, as before in the consultation concerning it, for communion with God is to be kept up in providences as well as in ordinances.\nI. Here is Abraham\'s pious regard to God in this event, in two things: - 1. A careful expectation of the event, Gen 19:27. He got up early to look towards Sodom; and, to intima...', 'teologico');
add('gn', 19, 30, 'Matthew Henry', 'Here is, I. The great trouble and distress that Lot was brought into after his deliverance, Gen 19:30. 1. He was frightened out of Zoar, durst not dwell there; probably because he was conscious to himself that it was a refuge of his own choosing and that herein he had foolishly prescribed to God, and therefore he could not but distrust his safety in it; or because he found it as wicked as Sodom, and therefore concluded it could not long survive it; or perhaps he observed the rise and increase...', 'teologico');
add('gn', 20, 1, 'Matthew Henry', 'Here is, 1. Abraham\'s removal from Mamre, where he had lived nearly twenty years, into the country of the Philistines: He sojourned in Gerar, Gen 20:1. We are not told upon what occasion he removed, whether terrified by the destruction of Sodom, or because the country round was for the present prejudiced by it, or, as some of the Jewish writers say, because he was grieved at Lot\'s incest with his daughters, and the reproach which the Canaanites cast upon him and his religion, for his kinsman\'...', 'teologico');
add('gn', 20, 3, 'Matthew Henry', 'It appears by this that God revealed himself by dreams (which evidenced themselves to be divine and supernatural) not only to his servants the prophets, but even to those who were out of the pale of the church and covenant; but then, usually, it was with some regard to God\'s own people as in Pharaoh\'s dream, to Joseph, in Nebuchadnezzar\'s, to Daniel, and here, in Abimelech\'s, to Abraham and Sarah, for he reproved this king for their sake, Psa 105:14, Psa 105:15.\nI. God gives him notice of his...', 'teologico');
add('gn', 20, 8, 'Matthew Henry', 'Abimelech, being thus warned of God in a dream, takes the warning, and, as one truly afraid of sin and its consequences, he rises early to obey the directions given him.\nI. He has a caution for his servants, Gen 20:8. Abraham himself could not be more careful than he was to command his household in this matter. Note, Those whom God has convinced of sin and danger ought to tell others what God has done for their souls, that they also may be awakened and brought to a like holy fear.\nII. He has ...', 'teologico');
add('gn', 20, 14, 'Matthew Henry', 'Here is, I. The kindness of a prince which Abimelech showed to Abraham. See how unjust Abraham\'s jealousies were. He fancied that if they knew that Sarah was his wife they would kill him; but, when they did know it, instead of killing him they were kind to him, frightened at least to be so by the divine rebukes they were under. 1. He gives him his royal licence to dwell where he pleased in his country, courting his stay because he gives him his royal gifts (Gen 20:14), sheep and oxen, and (Ge...', 'teologico');
add('gn', 21, 1, 'Matthew Henry', 'Long-looked-for comes at last. The vision concerning the promised seed is for an appointed time, and now, at the end, it speaks, and does not lie; few under the Old Testament were brought into the world with such expectation as Isaac was, not for the sake of any great person eminence at which he was to arrive, but because he was to be, in this very thin, a type of Christ, that seed which the holy God had so long promised and holy men so long expected. In this account of the first days of Isaa...', 'teologico');
add('gn', 21, 9, 'Matthew Henry', 'The casting out of Ishmael is here considered of, and resolved on.\nI. Ishmael himself gave the occasion by some affronts he gave to Isaac his little brother, some think on the day that Abraham made the feast for joy that Isaac was safely weaned, which the Jews say was not till he was three years old, others say five. Sarah herself was an eye-witness of the abuse: she saw the son of the Egyptian mocking (Gen 21:9), mocking Isaac, no doubt, for it is said, with reference to this (Gal 4:29), tha...', 'teologico');
add('gn', 21, 14, 'Matthew Henry', 'Here is, I. The casting out of the bond-woman, and her son from the family of Abraham, Gen 21:14. Abraham\'s obedience to the divine command in this matter was speedy - early in the morning, we may suppose immediately after he had, in the night\'s visions, received orders to do this. It was also submissive; it was contrary to his judgment, at least to his own inclination, to do it; yet as soon as he perceives that it is the mind of God he makes no objections, but silently does as he is bidden, ...', 'teologico');
add('gn', 21, 22, 'Matthew Henry', 'We have here an account of the treaty between Abimelech and Abraham, in which appears the accomplishment of that promise (Gen 12:2) that God would make his name great. His friendship is valued, is courted, though a stranger, though a tenant at will to the Canaanites and Perizzites.\nI. The league is proposed by Abimelech, and Phichol his prime-minister of state and general of his army.\n1. The inducement to it was God\'s favour to Abraham (Gen 21:22): "God is with thee in all that thou doest, an...', 'teologico');
add('gn', 21, 33, 'Matthew Henry', 'Observe, 1. Abraham, having got into a good neighbourhood, knew when he was well off, and continued a great while there. There he planted a grove for a shade to his tent, or perhaps an orchard of fruit-trees; and there, though we cannot say he settled, for God would have him, while he lived, to be a stranger and a pilgrim, yet he sojourned many days, as many as would consist with his character, as Abraham the Hebrew, or passenger. 2. There he made, not only a constant practice, but an open pr...', 'teologico');
add('gn', 22, 3, 'Matthew Henry', 'We have here Abraham\'s obedience to this severe command. Being tried, he offered up Isaac, Heb 11:17. Observe,\nI. The difficulties which he broke through in this act of obedience. Much might have been objected against it; as, 1. It seemed directly against an antecedent law of God, which forbids murder, under a severe penalty, Gen 9:5, Gen 9:6. Now can the unchangeable God contradict himself? He that hates robbery for burnt-offering (Isa 61:8) cannot delight in murder for it. 2. How would it c...', 'teologico');
add('gn', 22, 11, 'Matthew Henry', 'Hitherto this story has been very melancholy, and seemed to hasten towards a most tragical period; but here the sky suddenly clears up, the sun breaks out, and a bright and pleasant scene opens. The same hand that had wounded and cast down here heals and lifts up; for, though he cause grief, he will have compassion. The angel of the Lord, that is, God himself, the eternal Word, the angel of the covenant, who was to be the great Redeemer and comforter, he interposed, and gave a happy issue to ...', 'teologico');
add('gn', 22, 15, 'Matthew Henry', 'Abraham\'s obedience was graciously accepted; but this was not all: here we have it recompensed, abundantly recompensed, before he stirred from the place; probably while the ram he had sacrificed was yet burning God sent him this gracious message, renewed and ratified his covenant with him. All covenants were made by sacrifice, so was this by the typical sacrifices of Isaac and the ram. Very high expressions of God\'s favour to Abraham are employed in this confirmation of the covenant with him,...', 'teologico');
add('gn', 22, 20, 'Matthew Henry', 'This is recorded here, 1. To show that though Abraham saw his own family highly dignified with peculiar privileges, admitted into covenant, and blessed with the entail of the promise, yet he did not look with contempt and disdain upon his relations, but was glad to hear of the increase and prosperity of their families. 2. To make way for the following story of the marriage of Isaac to Rebekah, a daughter of this family.', 'teologico');
add('gn', 23, 1, 'Matthew Henry', 'We have here, 1. Sarah\'s age, Gen 23:1. Almost forty years before, she had called herself old, Gen 18:12. Old people will die never the sooner, but may die the better, for reckoning themselves old. 2. Her death, Gen 23:2. The longest liver must die at last. Abraham and Sarah had lived comfortably together many years; but death parts those whom nothing else could part. The special friends and favourites of Heaven are not exempted from the stroke of death. She died in the land of Canaan, where ...', 'teologico');
add('gn', 23, 3, 'Matthew Henry', 'Here is, I. The humble request which Abraham made to his neighbours, the Hittites, for a burying-place among them, Gen 23:3, Gen 23:4. It was strange he had this to do now; but we are to impute it rather to God\'s providence than to his improvidence, as appears Act 7:5, where it is said, God gave him no inheritance in Canaan. It were well if all those who take care to provide burying-places for their bodies after death were as careful to provide a resting-place for their souls. Observe here, 1...', 'teologico');
add('gn', 23, 16, 'Matthew Henry', 'We have here the conclusion of the treaty between Abraham and Ephron about the burying-place. The bargain was publicly made before all the neighbours, in the presence and audience of the sons of Heth, Gen 23:16, Gen 23:17. Note, Prudence, as well as justice, directs us to be fair, and open, and above-board, in our dealings. Fraudulent contracts hate the light, and choose to be clandestine; but those that design honestly in their bargains care not who are witnesses to them. Our law countenance...', 'teologico');
add('gn', 24, 1, 'Matthew Henry', 'Three things we may observe here concerning Abraham: - \nI. The care he took of a good son, to get him married, well married. It was high time to think of it now, for Isaac was about forty years old, and it had been customary with his ancestors to marry at thirty, or sooner, Gen 11:14, Gen 11:18, Gen 11:22, Gen 11:24. Abraham believed the promise of the building up of his family, and therefore did not make haste; not more haste than good speed. Two considerations moved him to think of it now (...', 'teologico');
add('gn', 24, 10, 'Matthew Henry', 'Abraham\'s servant now begins to make a figure in this story; and, though he is not named, yet much is here recorded to his honour, and for an example to all servants, who shall be honoured if, by faithfully serving God and their masters, they adorn the doctrine of Christ (compare Pro 27:18 with Tit 2:10); for there is no respect of persons with God, Col 3:24, Col 3:25. A good servant that makes conscience of the duty of his place, and does it in the fear of God, though he make not a figure in...', 'teologico');
add('gn', 24, 29, 'Matthew Henry', 'We have here the making up of the marriage between Isaac and Rebekah. It is related very largely and particularly, even to the minute circumstances, which, we should think, might have been spared, while other things of great moment and mystery (as the story of Melchizedek) are related in few words. Thus God conceals that which is curious from the wise and prudent, reveals to babes that which is common and level to their capacity (Mat 11:25), and rules and saves the world by the foolishness of...', 'teologico');
add('gn', 24, 54, 'Matthew Henry', 'Rebekah is here taking leave of her father\'s house; and 1. Abraham\'s servant presses for a dismission. Though he and his company were very welcome, and very cheerful there, yet he said, Send me away (Gen 24:54), and again, Gen 24:56. He knew his master would expect him home with some impatience; he had business to do at home which wanted him, and therefore, as one that preferred his work before his pleasure, he was for hastening home. Note, Lingering and loitering no way become a wise and goo...', 'teologico');
add('gn', 24, 62, 'Matthew Henry', 'Isaac and Rebekah are, at length, happily brought together. Observe,\nI. Isaac was well employed when he met Rebekah: He went out to meditate, or pray, in the field, at the even-tide, Gen 24:62, Gen 24:63. Some think he expected the return of his servants about this time, and went out on purpose to meet them. But, it should seem, he went out on another errand, to take the advantage of a silent evening and a solitary field for meditation and prayer, those divine exercises by which we converse w...', 'teologico');
add('gn', 25, 1, 'Matthew Henry', 'Abraham lived, after the marriage of Isaac, thirty-five years, and all that is recorded concerning him during the time lies here in a very few verses. We hear no more of God\'s extraordinary appearances to him or trials of him; for all the days, even of the best and greatest saints, are not eminent days, some slide on silently, and neither come nor go with observation; such were these last days of Abraham. We have here,\nI. An account of his children by Keturah, another wife whom he married aft...', 'teologico');
add('gn', 25, 11, 'Matthew Henry', 'Immediately after the account of Abraham\'s death, Moses begins the story of Isaac (Gen 25:11), and tells us where he dwelt and how remarkably God blessed him. Note, The blessing of Abraham did not die with him, but survived to all the children of the promise. But he presently digresses from the story of Isaac, to give a short account of Ishmael, forasmuch as he also was a son of Abraham, and God had made some promises concerning him, which it was requisite we should know the accomplishment of...', 'teologico');
add('gn', 25, 19, 'Matthew Henry', 'We have here an account of the birth of Jacob and Esau, the twin sons of Isaac and Rebekah: their entrance into the world was (which is not usual) one of the most considerable parts of their story; nor is much related concerning Isaac but what had reference to his father while he lived and to his sons afterwards. For Isaac seems not to have been a man of action, nor much tried, but to have spent his days in quietness and silence. Now concerning Jacob and Esau we are here told,\nI. That they we...', 'teologico');
add('gn', 25, 29, 'Matthew Henry', 'We have here a bargain made between Jacob and Esau about the birthright, which was Esau\'s by providence but Jacob\'s by promise. It was a spiritual privilege, including the excellency of dignity and the excellency of power, as well as the double portion, Gen 49:3. It seemed to be such a birthright as had then the blessing annexed to it, and the entail of the promise. Now see,\nI. Jacob\'s pious desire of the birthright, which yet he sought to obtain by indirect courses, not agreeable to his char...', 'teologico');
add('gn', 26, 1, 'Matthew Henry', 'Here, I. God tried Isaac by his providence. Isaac had been trained up in a believing dependence upon the divine grant of the land of Canaan to him and his heirs; yet now there is a famine in the land, Gen 26:1. What shall he think of the promise when the promised land will not find him bread? Is such a grant worth accepting, upon such terms, and after so long a time? Yes, Isaac will still cleave to the covenant; and the less valuable Canaan in itself seems to be the better he is taught to val...', 'teologico');
add('gn', 26, 6, 'Matthew Henry', 'Isaac had now laid aside all thoughts of going to Egypt, and, in obedience to the heavenly vision, sets up his staff in Gerar, the country in which he was born (Gen 26:6), yet there he enters into temptation, the same temptation that his good father had been once and again surprised and overcome by, namely, to deny his wife, and to give out that she was his sister. Observe,\nI. How he sinned, Gen 26:7. Because his wife was handsome, he fancied the Philistines would find some way or other to ta...', 'teologico');
add('gn', 26, 12, 'Matthew Henry', 'Here we have,\nI. The tokens of God\'s good-will to Isaac. He blessed him, and prospered him, and made all that he had to thrive under his hands. 1. His corn multiplied strangely, Gen 26:12. He had no land of his own, but took land of the Philistines, and sowed it; and (be it observed for the encouragement of poor tenants, that occupy other people\'s lands, and are honest and industrious) God blessed him with a great increase. He reaped a hundred fold; and there seems to be an emphasis laid upon...', 'teologico');
add('gn', 26, 26, 'Matthew Henry', 'We have here the contests that had been between Isaac and the Philistines issuing in a happy peace and reconciliation.\nI. Abimelech pays a friendly visit to Isaac, in token of the respect he had for him, Gen 26:26. Note, When a man\'s ways please the Lord he makes even his enemies to be at peace with him, Pro 16:7. King\'s hearts are in his hands, and when he pleases he can turn them to favour his people.\nII. Isaac prudently and cautiously questions his sincerity in this visit, Gen 26:27. Note,...', 'teologico');
add('gn', 26, 34, 'Matthew Henry', 'Here is, 1. Esau\'s foolish marriage - foolish, some think, in marrying two wives together, for which perhaps he is called a fornicator (Heb 12:16), or rather in marrying Canaanites, who were strangers to the blessing to Abraham, and subject to the curse of Noah, for which he is called profane; for hereby he intimated that he neither desired the blessing nor dreaded the curse of God. 2. The grief and trouble it created to his tender parents. (1.) It grieved them that he married without asking,...', 'teologico');
add('gn', 27, 1, 'Matthew Henry', 'Here is, I. Isaac\'s design to make his will, and to declare Esau his heir. The promise of the Messiah and the land of Canaan was a great trust, first committed to Abraham, inclusive and typical of spiritual and eternal blessings; this, by divine direction, he transmitted to Isaac. Isaac, being now old, and not knowing, or not understanding, or not duly considering, the divine oracle concerning his two sons, that the elder should serve the younger, resolves to entail all the honour and power t...', 'teologico');
add('gn', 27, 6, 'Matthew Henry', 'Rebekah is here contriving to procure for Jacob the blessing which was designed for Esau; and here,\nI. The end was good, for she was directed in this intention by the oracle of God, by which she had been governed in dispensing her affections. God had said it should be so, that the elder should serve the younger; and therefore Rebekah resolves it shall be so, and cannot bear to see her husband designing to thwart the oracle of God. But,\nII. The means were bad, and no way justifiable. If it was...', 'teologico');
add('gn', 27, 18, 'Matthew Henry', 'Observe here, I. The art and assurance with which Jacob managed this intrigue. Who would have thought that this plain man could have played his part so well in a design of this nature? His mother having put him in the way of it, and encouraged him in it, he dexterously applied himself to those methods which he had never accustomed himself to, but had always conceived an abhorrence of. Note, Lying is soon learnt. The psalmist speaks of those who, as soon as they are born, speak lies, Psa 58:3;...', 'teologico');
add('gn', 27, 30, 'Matthew Henry', 'Here is, I. The covenant-blessing denied to Esau. He that made so light of the birthright would now have inherited the blessing, but he was rejected, and found no place of repentance in his father, though he sought it carefully with tears, Heb 12:17. Observe, 1. How carefully he sought it. He prepared the savoury meat, as his father had directed him, and then begged the blessing which his father had encouraged him to expect, Gen 27:31. When he understood that Jacob had obtained it surreptitio...', 'teologico');
add('gn', 27, 41, 'Matthew Henry', 'Here is, I. The malice Esau bore to Jacob upon account of the blessing which he had obtained, Gen 27:41. Thus he went in the way of Cain, who slew his brother because he had gained that acceptance with God of which he had rendered himself unworthy. Esau\'s hatred of Jacob was, 1. A causeless hatred. He hated him for no other reason but because his father blessed him and God loved him. Note, The happiness of saints is the envy of sinners. Whom Heaven blesses, hell curses. 2. It was a cruel hatr...', 'teologico');
add('gn', 28, 1, 'Matthew Henry', 'Jacob had no sooner obtained the blessing than immediately he was forced to flee from his country; and, as it if were not enough that he was a stranger and sojourner there, he must go to be more so, and no better than an exile, in another country. Now Jacob fled into Syria, Hos 12:12. He was blessed with plenty of corn and wine, and yet he went away poor, was blessed with government, and yet went out to service, a hard service. This was, 1. Perhaps to correct him for his dealing fraudulently ...', 'teologico');
add('gn', 28, 6, 'Matthew Henry', 'This passage concerning Esau comes in in the midst of Jacob\'s story, either, 1. To show the influence of a good example. Esau, though the greater man, now begins to think Jacob the better man, and disdains not to take him for his pattern in this particular instance of marrying with a daughter of Abraham. The elder children should give to the younger an example of tractableness and obedience; it is bad if they do not: but it is some alleviation if they take the example of it from them, as Esau...', 'teologico');
add('gn', 28, 10, 'Matthew Henry', 'We have here Jacob upon his journey towards Syria, in a very desolate condition, like one that was sent to seek his fortune; but we find that, though he was alone, yet he was not alone, for the Father was with him, Joh 16:32. If what is here recorded happened (as it should seem it did) the first night, he had made a long day\'s journey from Beersheba to Bethel, above forty miles. Providence brought him to a convenient place, probably shaded with trees, to rest himself in that night; and there ...', 'teologico');
add('gn', 28, 16, 'Matthew Henry', 'God manifested himself and his favour to Jacob when he was asleep and purely passive; for the spirit, like the wind, blows when and where he listeth, and God\'s grace, like the dew, tarrieth not for the sons of men, Mic 5:7. But Jacob applied himself to the improvement of the visit God had made him when he was awake; and we may well think he awaked, as the prophet did (Jer 31:26), and behold his sleep was sweet to him. Here is much of Jacob\'s devotion on this occasion.\nI. He expressed a great ...', 'teologico');
add('gn', 29, 1, 'Matthew Henry', 'All the stages Israel\'s march to Canaan are distinctly noticed, but no particular journal is kept of Jacob\'s expedition further than Beth-el; no, he had no more such happy nights as he had at Beth-el, no more such visions of the Almighty. That was intended for a feast; he must not expect it to be his daily bread. But, 1. We are here told how cheerfully he proceeded in his journey after the sweet communion he had with God at Beth-el: Then Jacob lifted up his feet; so the margin reads it, Gen 2...', 'teologico');
add('gn', 29, 9, 'Matthew Henry', 'Here we see, 1. Rachel\'s humility and industry: She kept her father\'s sheep (Gen 29:9), that is, she took the care of them, having servants under her that were employed about them. Rachel\'s name signifies a sheep. Note, Honest useful labour is that which nobody needs be ashamed of, nor ought it to be a hindrance to any one\'s preferment. 2. Jacob\'s tenderness and affection. When he understood that this was his kinswoman (probably he had heard of her name before), knowing what his errand was in...', 'teologico');
add('gn', 29, 15, 'Matthew Henry', 'Here is, I. The fair contract made between Laban and Jacob, during the month that Jacob spent there as a guest, Gen 29:14. It seems he was not idle, nor did he spend his time in sport and pastime; but like a man of business, though he had no stock of his own, he applied himself to serve his uncle, as he had begun (Gen 29:10) when he watered his flock. Note, Wherever we are, it is good to be employing ourselves in some useful business, which will turn to a good account to ourselves or others. ...', 'teologico');
add('gn', 29, 31, 'Matthew Henry', 'We have here the birth of four of Jacob\'s sons, all by Leah. Observe, 1. That Leah, who was less beloved, was blessed with children, when Rachel was denied that blessing, Gen 29:31. See how Providence, in dispensing its gifts, observes a proportion, to keep the balance even, setting crosses and comforts one over-against another, that none may be either too much elevated or too much depressed. Rachel wants children, but she is blessed with her husband\'s love; Leah wants that, but she is fruitf...', 'teologico');
add('gn', 30, 1, 'Matthew Henry', 'We have here the bad consequences of that strange marriage which Jacob made with the two sisters. Here is,\nI. An unhappy disagreement between him and Rachel (Gen 30:1, Gen 30:2), occasioned, not so much by her own barrenness as by her sister\'s fruitfulness. Rebekah, the only wife of Isaac, was long childless, and yet we find no uneasiness between her and Isaac; but here, because Leah bears children, Rachel cannot live peaceably with Jacob.\n1. Rachel frets. She envied her sister, Gen 30:1. Env...', 'teologico');
add('gn', 30, 14, 'Matthew Henry', 'Here is, I. Leah fruitful again, after she had, for some time, left off bearing. Jacob, it should seem, associated more with Rachel than with Leah. The law of Moses supposes it a common case that, if a man had two wives, one would be beloved and the other hated, Deu 21:15. But at length Rachel\'s strong passions betrayed her into a bargain with Leah that Jacob should return to her apartment. Reuben, a little lad, five or six years old, playing in the field, found mandrakes, dudaim. It is uncer...', 'teologico');
add('gn', 30, 25, 'Matthew Henry', 'We have here,\nI. Jacob\'s thoughts of home. He faithfully served his time out with Laban, even his second apprenticeship, though he was an old man, had a large family to provide for, and it was high time for him to set up for himself. Though Laban\'s service was hard, and he had cheated him in the first bargain he had made, yet Jacob honestly performs his engagements. Note, A good man, though he swear to his own hurt, will not change. And though others have deceived us this will not justify us ...', 'teologico');
add('gn', 30, 37, 'Matthew Henry', 'Here is Jacob\'s honest policy to make his bargain more advantageous to himself than it was likely to be. If he had not taken some course to help himself, it would have been a bad bargain indeed, which he knew Laban would never consider, or rather would be well pleased to see him a loser by, so little did Laban consult any one\'s interest but his own. Now Jacob\'s contrivances were, 1. To set peeled sticks before the cattle where they were watered, that, looking much at those unusual party-colou...', 'teologico');
add('gn', 31, 1, 'Matthew Henry', 'Jacob is here taking up a resolution immediately to quit his uncle\'s service, to take what he had and go back to Canaan. This resolution he took up upon a just provocation, by divine direction, and with the advice and consent of his wives.\nI. Upon a just provocation; for Laban and his sons had become very cross and ill-natured towards him, so that he could not stay among them with safety or satisfaction.\n1. Laban\'s sons showed their ill-will in what they said, Gen 31:1. It should seem they sa...', 'teologico');
add('gn', 31, 17, 'Matthew Henry', 'Here is, I. Jacob\'s flight from Laban. We may suppose he had been long considering of it, and casting about in his mind respecting it; but when now, at last, God had given him positive orders to go, he made no delay, nor was he disobedient to the heavenly vision. The first opportunity that offered itself he laid hold of, when Laban was shearing his sheep (Gen 31:19), that part of his flock which was in the hands of his sons three days\' journey off. Now, 1. It is certain that it was lawful for...', 'teologico');
add('gn', 31, 25, 'Matthew Henry', 'We have here the reasoning, not to say the rallying, that took place between Laban and Jacob at their meeting, in that mountain which was afterwards called Gilead, Gen 31:25. Here is,\nI. The high charge which Laban exhibited against him. He accuses him,\n1. As a renegade that had unjustly deserted his service. To represent Jacob as a criminal, he will have it thought that he intended kindness to his daughters (Gen 31:27, Gen 31:28), that he would have dismissed them with all the marks of love ...', 'teologico');
add('gn', 31, 36, 'Matthew Henry', 'See in these verses,\nI. The power of provocation. Jacob\'s natural temper was mild and calm, and grace had improved it; he was a smooth man, and a plain man; and yet Laban\'s unreasonable carriage towards him put him into a heat that transported him into a heat that transported him into some vehemence, Gen 31:36, Gen 31:37. His chiding with Laban, though it may admit of some excuse, was not justifiable, nor is it written for our imitation. Grievous words stir up anger, and commonly do but make ...', 'teologico');
add('gn', 31, 43, 'Matthew Henry', 'We have here the compromising of the matter between Laban and Jacob. Laban had nothing to say in reply to Jacob\'s remonstrance: he could neither justify himself nor condemn Jacob, but was convicted by his own conscience of the wrong he had done him; and therefore desires to hear no more of the matter He is not willing to own himself in a fault, nor to ask Jacob\'s forgiveness, and make him satisfaction, as he ought to have done. But,\nI. He turns it off with a profession of kindness for Jacob\'s...', 'teologico');
add('gn', 32, 1, 'Matthew Henry', 'Jacob, having got clear of Laban, pursues his journey homewards towards Canaan: when God has helped us through difficulties we should go on our way heaven-ward with so much the more cheerfulness and resolution. Now, 1. Here is Jacob\'s convoy in his journey (Gen 32:1): The angels of God met him, in a visible appearance, whether in a vision by da or in a dream by night, as when he saw them upon the ladder (Gen 28:12), is uncertain. Note, Those that keep in a good way have always a good guard; a...', 'teologico');
add('gn', 32, 3, 'Matthew Henry', 'Now that Jacob was re-entering Canaan God, by the vision of angels, reminded him of the friends he had when he left it, and thence he takes occasion to remind himself of the enemies he had, particularly Esau. It is probable that Rebekah had sent him word of Esau\'s settlement in Seir, and of the continuance of his enmity to him. What shall poor Jacob do? He longs to see his father, and yet he dreads to see his brother. He rejoices to see Canaan again, and yet cannot but rejoice with trembling ...', 'teologico');
add('gn', 32, 9, 'Matthew Henry', 'Our rule is to call upon God in the time of trouble; we have here an example to this rule, and the success encourages us to follow this example. It was now a time of Jacob\'s trouble, but he shall be saved out of it; and here we have him praying for that salvation, Jer 30:7. In his distress he sought the Lord, and he heard him. Note, Times of fear should be times of prayer; whatever frightens us should drive us to our knees, to our God. Jacob had lately seen his guard of angels, but, in this d...', 'teologico');
add('gn', 32, 13, 'Matthew Henry', 'Jacob, having piously made God his friend by a prayer, is here prudently endeavouring to make Esau his friend by a present. He had prayed to God to deliver him from the had of Esau, for he feared him; but neither did his fear sink into such a despair as dispirits for the use of means, nor did his prayer make him presume upon God\'s mercy, without the use of means. Note, When we have prayed to God for any mercy, we must second our prayers with our endeavours; else, instead of trusting god, we t...', 'teologico');
add('gn', 32, 24, 'Matthew Henry', 'We have here the remarkable story of Jacob\'s wrestling with the angel and prevailing, which is referred to, Hos 12:4. Very early in the morning, a great while before day, Jacob had helped his wives and his children over the river, and he desired to be private, and was left alone, that he might again more fully spread his cares and fears before God in prayer. Note, We ought to continue instant in prayer, always to pray and not to faint: frequency and importunity in prayer prepare us for mercy....', 'teologico');
add('gn', 33, 1, 'Matthew Henry', 'Here, I. Jacob discovered Esau\'s approach, Gen 33:1. Some think that his lifting up his eyes denotes his cheerfulness and confidence, in opposition to a dejected countenance; having by prayer committed his case to God, he went on his way, and his countenance was no more sad, Sa1 1:18. Note, Those that have cast their care upon God may look before them with satisfaction and composure of mind, cheerfully expecting the issue, whatever it may be; come what will, nothing can come amiss to him whos...', 'teologico');
add('gn', 33, 5, 'Matthew Henry', 'We have here the discourse between the two brothers at their meeting, which is very free and friendly, without the least intimation of the old quarrel. It was the best way to say nothing of it. They converse,\nI. About Jacob\'s retinue, Gen 33:5-7. Eleven or twelve little ones, the eldest of them no fourteen years old, followed Jacob closely: Who are these? says Esau. Jacob had sent him an account of the increase of his estate (Gen 32:5), but made no mention of his children; perhaps because he ...', 'teologico');
add('gn', 33, 16, 'Matthew Henry', 'Here, 1. Jacob comes to Succoth. Having in a friendly manner parted with Esau, who had gone to his own country (Gen 33:16), he comes to a place where, it should seem, he rested for some time, set up booths for his cattle, and other conveniences for himself and family. The place was afterwards known by the name of Succoth, a city in the tribe of Gad, on the other side Jordan (it signifies booths), that when his posterity afterwards dwelt in houses of stone, they might remember that the Syrian ...', 'teologico');
add('gn', 34, 1, 'Matthew Henry', 'Dinah was, for aught that appears, Jacob\'s only daughter, and we may suppose her therefore the mother\'s fondling and the darling of the family, and yet she proves neither a joy nor a credit to them; for those children seldom prove either the best or the happiest that are most indulged. She is reckoned now but fifteen or sixteen years of age when she here occasioned so much mischief. Observe, 1. Her vain curiosity, which exposed her. She went out, perhaps unknown to her father, but by the conn...', 'teologico');
add('gn', 34, 6, 'Matthew Henry', 'Jacob\'s sons, when they heard of the injury done to Dinah, showed a very great resentment of it, influenced perhaps rather by jealousy for the honour of their family than by a sense of virtue. Many are concerned at the shamefulness of sin that never lay to heart the sinfulness of it. It is here called folly in Israel (Gen 34:7), according to the language of after-times; for Israel was not yet a people, but a family only. Note, 1. Uncleanness is folly; for it sacrifices the favour of God, peac...', 'teologico');
add('gn', 34, 18, 'Matthew Henry', 'Here, 1. Hamor and Shechem gave consent themselves to be circumcised, Gen 34:18, Gen 34:19. To this perhaps they were moved, not only by the strong desire they had to bring about this match, but by what they might have heard of the sacred and honourable intentions of this sign, in the family of Abraham, which, it is probable, they had some confused notions of, and of the promises confirmed by it, which made them the more desirous to incorporate with the family of Jacob, Zac 8:23. Note, Many w...', 'teologico');
add('gn', 34, 25, 'Matthew Henry', 'Here, we have Simeon and Levi, two of Jacob\'s sons, young men not much above twenty years old, cutting the throats of the Shechemites, and thereby breaking the heart of their good father.\nI. Here is the barbarous murder of the Shechemites. Jacob himself was used to the sheep-hook, but his sons had got swords by their sides, as if they had been the seed of Esau, who was to live by his sword; we have them here,\n1. Slaying the inhabitants of Shechem - all the males, Hamor and Shechem particularl...', 'teologico');
add('gn', 35, 1, 'Matthew Henry', 'Here, I. God reminds Jacob of his vow at Beth-el, and sends him thither to perform it, Gen 35:1. Jacob had said in the day of his distress, If I come again in peace, this stone shall be God\'s house, Gen 28:22. God had performed his part of the bargain, and had given Jacob more than bread to eat and raiment to put on - he had got an estate, and had become two bands; but, it should seem, he had forgotten his vow, or at least had too long deferred the performance of it. Seven or eight years it w...', 'teologico');
add('gn', 35, 6, 'Matthew Henry', 'Jacob and his retinue having safely arrived at Bethel, we are here told what passed there.\nI. There he built an altar (Gen 35:7), and no doubt offered sacrifice upon it, perhaps the tenth of his cattle, according to his vow, I will give the tenth unto thee. With these sacrifices he joined praises for former mercies, particularly that which the sight of the place brought afresh to his remembrance; and he added prayers for the continuance of God\'s favour to him and his family. And he called the...', 'teologico');
add('gn', 35, 16, 'Matthew Henry', 'We have here the story of the death of Rachel, the beloved wife of Jacob. 1. She fell in travail by the way, not able to reach to Bethlehem, the next town, though they were near it; so suddenly does pain sometimes come upon a woman in travail, which she cannot escape, or put off. We may suppose Jacob had soon a tent up, convenient enough for her reception. 2. Her pains were violent. She had hard labour, harder than usual: this was the effect of sin, Gen 3:16. Note, Human life begins with sorr...', 'teologico');
add('gn', 35, 21, 'Matthew Henry', 'Here is, 1. Jacob\'s removal, Gen 35:21. He also, as his fathers, sojourned in the land of promise as in a strange country, and was not long in a place. Immediately after the story of Rachel\'s death he is here called Israel (Gen 35:21, Gen 35:22), and not often so afterwards: the Jews say, "The historian does him this honour here because he bore that affliction with such admirable patience and submission to Providence." Note, Those are Israel\'s indeed, princes with God, that support the govern...', 'teologico');
add('gn', 36, 1, 'Matthew Henry', 'Observe here, 1. Concerning Esau himself, Gen 36:1. He is called Edom (and again, Gen 36:8), that name by which was perpetuated the remembrance of the foolish bargain he made, when he sold his birthright for that red, that red pottage. The very mention of that name is enough to intimate the reason why his family is turned off with such a short account. Note, If men do a wrong thing they must thank themselves, when it is, long afterwards, remembered against them to their reproach. 2. Concernin...', 'teologico');
add('gn', 36, 9, 'Matthew Henry', 'Observe here, 1. That only the names of Esau\'s sons and grandsons are recorded, only their names, not their history; for it is the church that Moses preserves the records of, not the record of those that are without. Those elders that lived by faith alone obtained a good report. It is Sion that produces men of renown, not Seir, Psa 87:5. Nor does the genealogy go any further than the third and fourth generation; the very names of all after are buried in oblivion. It is only the pedigree of th...', 'teologico');
add('gn', 36, 20, 'Matthew Henry', 'In the midst of this genealogy of the Edomites here is inserted the genealogy of the Horites, those Canaanites, or Hittites (compare Gen 26:34), that were the natives of Mount Seir. Mention is made of them, Gen 14:6, and of their interest in Mount Seir, before the Edomites took possession of it, Deu 2:12, Deu 2:22. This comes in here, not only to give light to the story, but to be a standing reflection upon the Edomites for intermarrying with them, by which, it is probable, they learned their...', 'teologico');
add('gn', 36, 31, 'Matthew Henry', 'By degrees, it seems, the Edomites wormed out the Horites, obtained full possession of the country, and had a government of their own. 1. They were ruled by kings, who governed the whole country, and seem to have come to the throne by election, and not by lineal descent; so bishop Patrick observes. These kings reigned in Edom before there reigned any king over the children of Israel, that is, before Moses\'s time, for he was king in Jeshurun, Gen 36:3. God had lately promised Jacob that kings ...', 'teologico');
add('gn', 37, 1, 'Matthew Henry', 'Moses has no more to say of the Edomites, unless as they happen to fall in Israel\'s way; but now applies himself closely to the story of Jacob\'s family: These are the generations of Jacob. His is not a bare barren genealogy as that of Esau (Gen 36:1), but a memorable useful history. Here is, 1. Jacob a sojourner with his father Isaac, who has yet living, Gen 37:1. We shall never be at home, till we come to heaven. 2. Joseph, a shepherd, feeding the flock with his brethren, Gen 37:2. Though he...', 'teologico');
add('gn', 37, 5, 'Matthew Henry', 'Here, I. Joseph relates the prophetical dreams he had, Gen 37:6, Gen 37:7, Gen 37:9, Gen 37:10. Though he was now very young (about seventeen years old), yet he was pious and devout, and well-inclined, and this fitted him for God\'s gracious discoveries of himself to him. Joseph had a great deal of trouble before him, and therefore God gave him betimes this prospect of his advancement, to support and comfort him under the long and grievous troubles with which he was to be exercised. Thus Chris...', 'teologico');
add('gn', 37, 12, 'Matthew Henry', 'Here is, I. The kind visit which Joseph, in obedience to his father\'s command, made to his brethren, who were feeding the flock at Shechem, many miles off. Some suggest that they went thither on purpose, expecting that Joseph would be sent to see them, and that then they should have an opportunity to do him a mischief. However, Joseph and his father had both of them more of the innocence of the dove than of the wisdom of the serpent, else he had never come thus into the hands of those that ha...', 'teologico');
add('gn', 37, 23, 'Matthew Henry', 'We have here the execution of their plot against Joseph. 1. They stripped him, each striving to seize the envied coat of many colours, Gen 37:23. Thus, in imagination, they degraded him from the birthright, of which perhaps this was the badge, grieving him, affronting their father, and making themselves sport, while they insulted over him. "Now, Joseph, where is the fine coat?" Thus our Lord Jesus was stripped of his seamless coat, and thus his suffering saints have first been industriously d...', 'teologico');
add('gn', 37, 31, 'Matthew Henry', 'I. Joseph would soon be missed, great enquiry would be made for him, and therefore his brethren have a further design, to make the world believe that Joseph was torn in pieces by a wild beast; and this they did, 1. To clear themselves, that they might not be suspected to have done him any mischief. Note, We have all learned of Adam to cover our transgression, Job 31:33. When the devil has taught men to commit one sin, he then teaches them to conceal it with another, theft and murder with lyin...', 'teologico');
add('gn', 38, 1, 'Matthew Henry', 'Here is, 1. Judah\'s foolish friendship with a Canaanite-man. He went down from his brethren, and withdrew for a time from their society and his father\'s family, and got to be intimately acquainted with one Hirah, an Adullamite, Gen 38:1. It is computed that he was now not much above fifteen or sixteen years of age, an easy prey to the tempter. Note, When young people that have been well educated begin to change their company, they will soon change their manners, and lose their good education....', 'teologico');
add('gn', 38, 12, 'Matthew Henry', 'It is a very ill-favoured story that is here told concerning Judah; one would not have expected such folly in Israel. Judah had buried his wife; and widowers have need to stand upon their guard with the utmost caution and resolution against all fleshly lusts. He was unjust to his daughter-in-law, either through negligence or design, in not giving her his surviving son, and this exposed her to temptation.\nI. Tamar wickedly prostituted herself as a harlot to Judah, that, if the son might not, t...', 'teologico');
add('gn', 38, 24, 'Matthew Henry', 'Here is, I. Judah\'s rigour against Tamar, when he heard she was an adulteress. She was, in the eye of the law, Shelah\'s wife, and therefore her being with child by another was looked upon as an injury and reproach to Judah\'s family: Bring her forth therefore, says Judah, the master of the family, and let her be burnt; not burnt to death, but burnt in the cheek or forehead, stigmatized for a harlot. This seems probable, Gen 38:24. Note, it is a common thing for men to be severe against those v...', 'teologico');
add('gn', 39, 1, 'Matthew Henry', 'Here is, I. Joseph bought (Gen 39:1), and he that bought him, whatever he gave for him, had a good bargain of him; it was better than the merchandise of silver. The Jews have a proverb, "If the world did not know the worth of good men, they would hedge them about with pearls." He was sold to an officer of Pharaoh, with whom he might get acquainted with public persons and public business, and so be fitted for the preferment for which he was designed. Note, 1. What God intends men for he will b...', 'teologico');
add('gn', 39, 7, 'Matthew Henry', 'Here is, I. A most shameful instance of impudence and immodesty in Joseph\'s mistress, the shame and scandal of her sex, perfectly lost to all virtue and honour, and not to be mentioned, nor thought of, without the utmost indignation. It was well that she was an Egyptian; for we must have shared in the confusion if such folly had been found in Israel. Observe,\nI. Her sin began in the eye: She cast her eyes upon Joseph (Gen 39:7), who was a goodly person, and well-favoured, Gen 39:6. Note, (1.)...', 'teologico');
add('gn', 39, 13, 'Matthew Henry', 'Joseph\'s mistress, having tried in vain to make him a criminal, now endeavours to represent him as one; so to be revenged on him for his virtue. Now was her love turned into the utmost rage and malice, and she pretends she cannot endure the sight of him whom awhile ago she could not endure out of her sight. Chaste and holy love will continue, though slighted; but sinful love, like Amnon\'s to Tamar, is easily changed into sinful hatred. 1. She accused him to his fellow servants (Gen 39:13-15) ...', 'teologico');
add('gn', 39, 19, 'Matthew Henry', 'Here is, 1. Joseph wronged by his master. He believed the accusation, and either Joseph durst not make his defence by telling the truth, as it would reflect too much upon his mistress, or his master would not hear it, or would not believe it, and there is no remedy, he is condemned to perpetual imprisonment, Gen 39:19, Gen 39:20. God restrained his wrath, else he had put him to death; and that wrath which imprisoned him God made to turn to his praise, in order to which Providence so disposed ...', 'teologico');
add('gn', 40, 1, 'Matthew Henry', 'We should not have had this story of Pharaoh\'s butler and baker recorded in scripture if it had not been serviceable to Joseph\'s preferment. The world stands for the sake of the church, and is governed for its good. Observe, 1. Two of the great officers of Pharaoh\'s court, having offended the king, are committed to prison. Note, High places are slippery places; nothing more uncertain than the favour of princes. Those that make God\'s favour their happiness, and his service their business, will...', 'teologico');
add('gn', 40, 5, 'Matthew Henry', 'Observe, I. The special providence of God, which filled the heads of these two prisoners with unusual dreams, such as made extraordinary impressions upon them, and carried with them evidences of a divine origin, both in one night. Note, God has immediate access to the spirits of men, which he can make serviceable to his own purposes whenever he pleases, quite beyond the intention of those concerned. To him all hearts are open, and anciently he spoke not only to his own people, but to others, ...', 'teologico');
add('gn', 40, 20, 'Matthew Henry', 'Here is, 1. The verifying of Joseph\'s interpretation of the dreams, on the very day prefixed. The chief butler and baker were both advanced, one to his office, the other to the gallows, and both at the three days\' end. Note, Very great changes, both for the better and for the worse, often happen in a very little time, so sudden are the revolutions of the wheel of nature. The occasion of giving judgement severally upon their case was the solemnizing of Pharaoh\'s birthday, on which, all his ser...', 'teologico');
add('gn', 41, 1, 'Matthew Henry', 'Observe, 1. The delay of Joseph\'s enlargement. It was not till the end of two full years (Gen 41:1); so long he waited after he had entrusted the chief butler with his case and began to have some prospect of relief. Note, We have need of patience, not only bearing, but waiting, patience. Joseph lay in prison until the time that his word came, Psa 105:19. There is a time set for the deliverance of God\'s people; that time will come, though it seem to tarry; and, when it comes, it will appear to...', 'teologico');
add('gn', 41, 9, 'Matthew Henry', 'Here is, 1. The recommending of Joseph to Pharaoh for an interpreter. The chief butler did it more in compliment to Pharaoh, to oblige him, than in gratitude to Joseph, or in compassion for his case. He makes a fair confession (Gen 41:9): "I remember my faults this day, in forgetting Joseph." Note, It is best to remember our duty, and to do it in its time; but, if we have neglected that, it is next best to remember our faults, and repent of them, and do our duty at last; better late than neve...', 'teologico');
add('gn', 41, 17, 'Matthew Henry', 'Here, I. Pharaoh relates his dream. He dreamt that he stood upon the bank of the river Nile, and saw the kine, both the fat ones and the lean ones, come out of the river. For the kingdom of Egypt had no rain, as appears, Zac 14:18, but the plenty of the year depended upon the overflowing of the river, and it was about one certain time of the year that it overflowed. If it rose to fifteen or sixteen cubits, there was plenty; if to twelve or thirteen only, or under, there was scarcity. See how ...', 'teologico');
add('gn', 41, 33, 'Matthew Henry', 'Here is, I. The good advice that Joseph gave to Pharaoh, which was, 1. That in the years of plenty he should lay up for the years of famine, buy up corn when it was cheap, that he might both enrich himself and supply the country when it would be dear and scarce. Note, Fair warning should always be followed with good counsel. Therefore the prudent man foresees the evil, that he may hide himself. God has in his word told us of a day of trial and exigence before us, when we shall need all the gr...', 'teologico');
add('gn', 41, 46, 'Matthew Henry', 'Observe here, I. The building of Joseph\'s family in the birth of two sons, Manasseh and Ephraim, Gen 41:50-52. In the names he gave them, he owned the divine Providence giving this happy turn to his affairs, 1. He was made to forget his misery, Job 11:16. We should bear our afflictions when they are present as those that know not but Providence may so outweigh them by after-comforts as that we may even forget them when they are past. But could he be so unnatural as to forget all his father\'s ...', 'teologico');
add('gn', 42, 1, 'Matthew Henry', 'Though Jacob\'s sons were all married, and had families of their own, yet, it should seem, they were still incorporated in one society, under the conduct and presidency of their father Jacob. We have here,\nI. The orders he gave them to go and buy corn in Egypt, Gen 42:1, Gen 42:2. Observe, 1. The famine was grievous in the land of Canaan. It is observable that all the three patriarches, to whom Canaan was the land of promise, met with famine in that land, which was not only to try their faith,...', 'teologico');
add('gn', 42, 7, 'Matthew Henry', 'We may well wonder that Joseph, during the twenty years that he had now been in Egypt, especially during the last seven years that he had been in power there, never sent to his father to acquaint him with his circumstances; nay, it is strange that he who so often went throughout all the land of Egypt (Gen 41:45, Gen 41:46) never made an excursion to Canaan, to visit his aged father, when he was in the borders of Egypt, that lay next to Canaan. Perhaps it would not have been above three or fou...', 'teologico');
add('gn', 42, 21, 'Matthew Henry', 'Here is, I. The penitent reflection Joseph\'s brethren made upon the wrong they had formerly done to him, Gen 42:21. They talked the matter over in the Hebrew tongue, not suspecting that Joseph, whom they took for a native of Egypt, understood them, much less that he was the person they spoke of.\n1. They remembered with regret the barbarous cruelty wherewith they persecuted him: We are verily guilty concerning our brother. We do not read that they said this during their three days\' imprisonmen...', 'teologico');
add('gn', 42, 29, 'Matthew Henry', 'Here is, 1. The report which Jacob\'s sons made to their father of the great distress they had been in in Egypt; how they had been suspected, and threatened, and obliged to leave Simeon a prisoner there, till they should bring Benjamin with them thither. Who would have thought of this when they left home? When we go abroad we should consider how many sad accidents, that we little think of, may befall us before we return home. We know not what a day may bring forth; we ought therefore to be alw...', 'teologico');
add('gn', 43, 1, 'Matthew Henry', 'Here, 1. Jacob urges his sons to go and buy more corn in Egypt, Gen 43:1, Gen 43:2. The famine continued; and the corn they had bought was all spent, for it is meat that perisheth. Jacob, as a good master of a family, is in care to provide for those of his own house food convenient; and shall not God provide for his children, for the household of faith? Jacob bids them go again and buy a little food; now, in time of scarcity, a little must suffice, for nature is content with a little. 2. Juda...', 'teologico');
add('gn', 43, 11, 'Matthew Henry', 'Observe here, I. Jacob\'s persuasibleness. He would be ruled by reason, though they were his inferiors that urged it. He saw the necessity of the case; and, since there was no remedy, he consented to yield to the necessity (Gen 43:11): "If it must be so now, take your brother. If no corn can be had but upon those terms, we may as well expose him to the perils of the journey as suffer ourselves and families, and Benjamin amongst the rest, to perish for want of bread." Skin for skin, and all tha...', 'teologico');
add('gn', 43, 15, 'Matthew Henry', 'Jacob\'s sons, having got leave to take Benjamin with them, were observant of the orders their father had given them, and went down the second time into Egypt to buy corn. If we should ever know what a famine of the word means, let us not think it much to travel as far for spiritual food as they did for corporal food. Now here we have an account of what passed between them and Joseph\'s steward, who, some conjecture, was in the secret, and knew them to be Joseph\'s brethren, and helped to humour...', 'teologico');
add('gn', 43, 26, 'Matthew Henry', 'Here is, I. The great respect that Joseph\'s brethren paid to him. When they brought him the present, they bowed themselves before him (Gen 43:26); and again, when they gave him an account of their father\'s health, they made obeisance, and called him, Thy servant our father, Gen 43:28. Thus were Joseph\'s dreams fulfilled more and more: and even the father, by the sons, bowed before him, according to the dream, Gen 37:10. Probably Jacob had directed them, if they had occasion to speak of him to...', 'teologico');
add('gn', 44, 1, 'Matthew Henry', 'Joseph heaps further kindnesses upon his brethren, fills their sacks, returns their money, and sends them away full of gladness; but he also exercises them with further trials. Our God thus humbles those whom he loves and loads with benefits. Joseph ordered his steward to put a fine silver cup which he had (and which, it is likely, was used at his table when they dined with him) into Benjamin\'s sack\'s mouth, that it might seem as if he had stolen it from the table, and put it here himself, af...', 'teologico');
add('gn', 44, 18, 'Matthew Henry', 'We have here a most ingenious and pathetic speech which Judah made to Joseph on Benjamin\'s behalf, to obtain his discharge from the sentence passed upon him. Perhaps Judah was a better friend to Benjamin than the rest were, and more solicitous to bring him off; or he thought himself under greater obligations to attempt it than the rest, because he had passed his word to his father for his safe return; or the rest chose him for their spokesman, because he was a man of better sense, and better ...', 'teologico');
add('gn', 45, 1, 'Matthew Henry', 'Judah and his brethren were waiting for an answer, and could not but be amazed to discover, instead of the gravity of a judge, the natural affection of a father or brother.\nI. Joseph ordered all his attendants to withdraw, Gen 45:1. The private conversations of friends are the most free. When Joseph would put on love he puts off state, and it was not fit his servants should be witnesses of this. Thus Christ graciously manifests himself and his loving-kindness to his people, out of the sight a...', 'teologico');
add('gn', 45, 16, 'Matthew Henry', 'Here is, 1. The kindness of Pharaoh to Joseph, and to his relations for his sake: he bade his brethren welcome (Gen 45:16), though it was a time of scarcity, and they were likely to be a charge to him. Nay, because it pleased Pharaoh, it pleased his servants too, at least they pretended to be pleased because Pharaoh was. He engaged Joseph to send for his father down to Egypt, and promised to furnish them with all conveniences both for his removal thither and his settlement there. If the good ...', 'teologico');
add('gn', 45, 25, 'Matthew Henry', 'We have here the good news brought to Jacob. 1. The relation of it, at first, sunk his spirits. When, without any preamble, his sons came in, crying, Joseph is yet alive, each striving which should first proclaim it, perhaps he thought they bantered him, and the affront grieved him; or the very mention of Joseph\'s name revived his sorrow, so that his heart fainted, Gen 45:26. It was a good while before he came to himself. He was in such care and fear about the rest of them that at this time i...', 'teologico');
add('gn', 46, 1, 'Matthew Henry', 'The divine precept is, In all thy ways acknowledge God; and the promise annexed to it is, He shall direct thy paths. Jacob has here a very great concern before him, not only a journey, but a removal, to settle in another country, a change which was very surprising to him (for he never had any other thoughts than to live and die in Canaan), and which would be of great consequence to his family for a long time to come. Now here we are told,\nI. How he acknowledged God in this way. He came to Bee...', 'teologico');
add('gn', 46, 5, 'Matthew Henry', 'Old Jacob is here flitting. Little did he think of ever leaving Canaan; he expected, no doubt, to die in his nest, and to leave his seed in actual possession of the promised land: but Providence orders it otherwise. Note, Those that think themselves well settled may yet be unsettled in a little time. Even old people, who think of no other removal than that to the grave (which Jacob had much upon his heart, Gen 37:35; Gen 42:38), sometimes live to see great changes in their family. It is good ...', 'teologico');
add('gn', 46, 28, 'Matthew Henry', 'We have here, I. The joyful meeting between Jacob and his son Joseph, in which observe,\n1. Jacob\'s prudence in sending Judah before him to Joseph, to give him notice of his arrival in Goshen. This was a piece of respect owing to the government, under the protection of which these strangers had come to put themselves, Gen 46:28. We should be very careful not to give offence to any, especially not to the higher powers.\n2. Joseph\'s filial respect to him. He went in his chariot to met him, and, i...', 'teologico');
add('gn', 47, 1, 'Matthew Henry', 'Here is, I. The respect which Joseph, as a subject, showed to his prince. Though he was his favourite, and prime-minister of state, and had had particular orders from him to send for his father down to Egypt, yet he would not suffer him to settle till he had given notice of it to Pharaoh, Gen 47:1. Christ, our Joseph, disposes of his followers in his kingdom as it is prepared of his Father, saying, It is not mine to give, Mat 20:23.\nII. The respect which Joseph, as a brother, showed to his br...', 'teologico');
add('gn', 47, 13, 'Matthew Henry', 'Care being taken of Jacob and his family, the preservation of which was especially designed by Providence in Joseph\'s advancement, an account is now given of the saving of the kingdom of Egypt too from ruin; for God is King of nations as well as King of saints, and provideth food for all flesh. Joseph now returns to the management of that great trust which Pharaoh had lodged in his hand. It would have been pleasing enough to him to have gone and lived with his father and brethren in Goshen; b...', 'teologico');
add('gn', 47, 27, 'Matthew Henry', 'Observe, 1. The comfort Jacob lived in (Gen 47:27, Gen 47:28); while the Egyptians were impoverished in their own land, Jacob was replenished in a strange land. He lived seventeen years after he came into Egypt, far beyond his own expectation. Seventeen years he had nourished Joseph (for so old he was when he was sold from him, Gen 37:2), and now, by way of requital, seventeen years Joseph nourished him. Observe how kindly Providence ordered Jacob\'s affairs, that when he was old, and least ab...', 'teologico');
add('gn', 48, 1, 'Matthew Henry', 'Here, I. Joseph, upon notice of his father\'s illness, goes to see him; though a man of honour and business, yet he will not fail to show this due respect to his aged father, Gen 48:1. Visiting the sick, to whom we lie under obligations, or may have opportunity of doing good, either for body or soul, is our duty. The sick bed is a proper place both for giving comfort and counsel to others and receiving instruction ourselves. Joseph took his two sons with him, that they might receive their dyin...', 'teologico');
add('gn', 48, 8, 'Matthew Henry', 'Here is, I. The blessing with which Jacob blessed the two sons of Joseph, which is the more remarkable because the apostle makes such particular mention of it (Heb 11:21), while he says nothing of the blessing which Jacob pronounced on the rest of his sons, though that also was done in faith. Observe here,\n1. Jacob was blind for age, Gen 48:10. It is one of the common infirmities of old age. Those that look out at the windows are darkened, Ecc 12:3. It is folly to walk in the sight of our eye...', 'teologico');
add('gn', 49, 1, 'Matthew Henry', 'Here is, I. The preface to the prophecy, in which, 1. The congregation is called together (Gen 49:2): Gather yourselves together; let them all be sent for from their several employments, to see their father die, and to hear his dying words. It was a comfort to Jacob, now that he was dying, to see all his children about him, and none missing, though he had sometimes thought himself bereaved. It was of use to them to attend him in his last moments, that they might learn of him how to die, as we...', 'teologico');
add('gn', 49, 5, 'Matthew Henry', 'These were next in age to Reuben, and they also had been a grief and shame to Jacob, when they treacherously and barbarously destroyed the Shechemites, which he here remembers against them. Children should be afraid of incurring their parents\' just displeasure, lest they fare the worse for it long afterwards, and, when they would inherit the blessing, be rejected. Observe, 1. The character of Simeon and Levi: they were brethren in disposition; but, unlike their father, they were passionate an...', 'teologico');
add('gn', 49, 8, 'Matthew Henry', 'Glorious things are here said of Judah. The mention of the crimes of the three elder of his sons had not so put the dying patriarch out of humour but that he had a blessing ready for Judah, to whom blessings belonged. Judah\'s name signifies praise, in allusion to which he says, Thou art he whom thy brethren shall praise, Gen 49:8. God was praised for him (Gen 29:35), praised by him, and praised in him; and therefore his brethren shall praise him. Note, Those that are to God for a praise shall...', 'teologico');
add('gn', 49, 13, 'Matthew Henry', 'Here we have Jacob\'s prophecy concerning six of his sons.\nI. Concerning Zebulun (Gen 49:13), that his posterity should have their lot upon the seacoast, and should be merchants, and mariners, and traders at sea. This was fulfilled when, two or three hundred years after, the land of Canaan was divided by lot, and the border of Zebulun went up towards the sea, Jos 19:11. Had they chosen their lot themselves, or Joshua appointed it, we might have supposed it done with design to make Jacob\'s word...', 'teologico');
add('gn', 49, 22, 'Matthew Henry', 'He closes with the blessings of his best beloved sons, Joseph and Benjamin; with these he will breathe his last.\nI. The blessing of Joseph, which is very large and full. He is compared (Gen 49:22) to a fruitful bouth, or young tree; for God had made him fruitful in the land of his affliction; he owned it. Gen 41:52. His two sons were as branches of a vine, or other spreading plant, running over the wall. Note, God can make those fruitful, great comforts to themselves and others, who have been...', 'teologico');
add('gn', 49, 28, 'Matthew Henry', 'Here is, I. The summing up of the blessings of Jacob\'s sons, Gen 49:28. Though Reuben, Simeon, and Levi were put under the marks of their father\'s displeasure, yet he is said to bless them every one according to his blessing; for none of them were rejected as Esau was. Note, Whatever rebukes of God\'s word or providence we are under at any time, yet, as long as we have an interest in God\'s covenant, a place and a name among his people, and good hopes of a share in the heavenly Canaan, we must ...', 'teologico');
add('gn', 50, 1, 'Matthew Henry', 'Joseph is here paying his last respects to his deceased father. 1. With tears and kisses, and all the tender expressions of a filial affection, he takes leave of the deserted body, Gen 50:1. Though Jacob was old and decrepit, and must needs die in the course of nature - though he was poor comparatively, and a constant charge to his son Joseph, yet such an affection he had for a loving father, and so sensible was he of the loss of a prudent, pious, praying father, that he could not part with h...', 'teologico');
add('gn', 50, 7, 'Matthew Henry', 'We have here an account of Jacob\'s funeral. Of the funerals of the kings of Judah, usually, no more is said than this, They were buried with their fathers in the city of David: but the funeral of the patriarch Jacob is more largely and fully described, to show how much better God was to him than he expected (he had spoken more than once of dying for grief, and going to the grave bereaved of his children, but, behold, he dies in honour, and is followed to the grave by all his children), and al...', 'teologico');
add('gn', 50, 15, 'Matthew Henry', 'We have here the settling of a good correspondence between Joseph and his brethren, now that their father was dead. Joseph was at court, in the royal city; his brethren were in Goshen, remote in the country; yet the keeping up of a good understanding, and a good affection, between them, would be both his honour and their interest. Note, When Providence has removed the parents by death, the best methods ought to be taken, not only for the preventing of quarrels among the children (which often ...', 'teologico');
add('gn', 50, 22, 'Matthew Henry', 'Here is, I. The prolonging of Joseph\'s life in Egypt: he lived to be a hundred and ten years old, Gen 50:22. Having honoured his father, his days were long in the land which, for the present, God had given him; and it was a great mercy to his relations that God continued him so long, a support and comfort to them.\nII. The building up of Joseph\'s family: he lived to see his great-grand-children by both his sons (Gen 50:23), and probably he saw his two sons solemnly owned as heads of distinct t...', 'teologico');

// EX (146 comentários)
add('ex', 3, 14, 'João Crisóstomo', 'Eu Sou — O nome revela que Deus não depende de nada para existir. Ele é a fonte de toda existência.', 'teologico');
add('ex', 12, 1, 'Calvino', 'O cordeiro da Páscoa — Tipologia cristológica: o cordeiro pascal prefigura Cristo, o Cordeiro de Deus que tira o pecado do mundo.', 'teologico');
add('ex', 12, 7, 'Matthew Henry', 'Marcar as ombreiras — A marca do sangue protege: tipologia do sangue de Cristo sobre os crentes.', 'cultural');
add('ex', 12, 13, 'Lutero', 'O sangue será por sinal — O sangue do cordeiro é sinal visível da graça invisível: fé que salva.', 'teologico');
add('ex', 14, 21, 'Spurgeon', 'O mar se abriu — O êxodo é o maior tipo de salvação no AT: libertação da escravidão pelo poder de Deus.', 'teologico');
add('ex', 14, 29, 'João Crisóstomo', 'O mar se fechou sobre os egípcios — A justiça divina se manifesta na destruição dos opressores.', 'teologico');
add('ex', 14, 13, 'Lloyd-Jones', 'Não temais — A vitória de Deus é certa. O crente deve permanecer em silêncio e ver a salvação do Senhor.', 'aplicacao');
add('ex', 20, 1, 'Calvino', 'Dez Mandamentos — A lei é revelação da vontade de Deus, não meio de salvação. Revela o pecado e aponta para Cristo.', 'teologico');
add('ex', 20, 3, 'Lutero', 'Não terás outros deuses — O primeiro mandamento é o fundamento: só Deus merece adoração e confiança absoluta.', 'teologico');
add('ex', 20, 12, 'Wesley', 'Honra pai e mãe — O primeiro mandamento com promessa: obediência filial traz bênção temporal.', 'aplicacao');
add('ex', 20, 17, 'Albert Barnes', 'Não cobiçarás — A cobiça é pecado do coração: revela a corrupção interna, não apenas o ato externo.', 'gramatical');
add('ex', 25, 17, 'Tomás de Aquino', 'O propiciatório — A capa de ouro puro sobre a arca simboliza Cristo, que cobre os pecados do povo.', 'teologico');
add('ex', 25, 22, 'Adam Clarke', 'Ali me encontrarei contigo — O propiciatório é o lugar da presença divina: tipo do que seria cumprido em Cristo.', 'teologico');
add('ex', 32, 14, 'Charles Ellicott', 'O Senhor se arrependeu — Linguagem antropomórfica: Deus não muda de decisão, mas a Escritura descreve Sua ação em termos humanos.', 'gramatical');
add('ex', 1, 1, 'Matthew Henry', 'In these verses we have, 1. A recital of the names of the twelve patriarchs, as they are called, Act 7:8. Their names are often repeated in scripture, that they may not sound uncouth to us, as other hard names, but that, by their occurring so frequently, they may become familiar to us; and to show how precious God\'s spiritual Israel are to him, and how much he delights in them. The account which was kept of the number of Jacob\'s family, when they went down into Egypt; they were in all seventy...', 'teologico');
add('ex', 1, 8, 'Matthew Henry', 'The land of Egypt here, at length, becomes to Israel a house of bondage, though hitherto it had been a happy shelter and settlement for them. Note, The place of our satisfaction may soon become the place of our affliction, and that may prove the greatest cross to us of which we said, This same shall comfort us. Those may prove our sworn enemies whose parents were our faithful friends; nay, the same persons that loved us may possibly turn to hate us: therefore cease from man, and say not conce...', 'teologico');
add('ex', 1, 15, 'Matthew Henry', 'The Egyptians\' indignation at Israel\'s increase, notwithstanding the many hardships they put upon them, drove them at length to the most barbarous and inhuman methods of suppressing them, by the murder of their children. It was strange that they did not rather pick quarrels with the grown men, against whom they might perhaps find some occasion: to be thus bloody towards the infants, whom all must own to be innocents, was a sin which they had to cloak for. Note, 1. There is more cruelty in the...', 'teologico');
add('ex', 2, 1, 'Matthew Henry', 'Moses was a Levite, both by father and mother. Jacob left Levi under marks of disgrace (Gen 49:5); and yet, soon after, Moses appears a descendant from him, that he might typify Christ, who came in the likeness of sinful flesh and was made a curse for us. This tribe began to be distinguished from the rest by the birth of Moses, as afterwards it became remarkable in many other instances. Observe, concerning this newborn infant,\nI. How he was hidden. It seems to have been just at the time of hi...', 'teologico');
add('ex', 2, 5, 'Matthew Henry', 'Here is, I. Moses saved from perishing. Come see the place where that great man lay when he was a little child; he lay in a bulrush-basket by the river\'s side. Had he been left to lie there, he must have perished in a little time with hunger, if he had not been sooner washed into the river or devoured by a crocodile. Had he fallen into any other hands than those he did fall into, either they would not, or durst not, have done otherwise than have thrown him straightway into the river; but Prov...', 'teologico');
add('ex', 2, 11, 'Matthew Henry', 'Moses had now passed the first forty years of his life in the court of Pharaoh, preparing himself for business; and now it was time for him to enter upon action, and,\nI. He boldly owns and espouses the cause of God\'s people: When Moses was grown he went out unto his brethren, and looked on their burdens, Exo 2:11. The best exposition of these words we have from an inspired pen, Heb 11:24-26, where we are told that by this he expressed, 1. His holy contempt of the honours and pleasures of the ...', 'teologico');
add('ex', 2, 16, 'Matthew Henry', 'Moses here gains a settlement in Midian, just as his father Jacob had gained one in Syria, Gen 29:2, etc. And both these instances should encourage us to trust Providence, and to follow it. Events that seem inconsiderable, and purely accidental, afterwards appear to have been designed by the wisdom of God for very good purposes, and of great consequence to his people. A casual transient occurrence has sometimes occasioned the greatest and happiest turns of a man\'s life. Observe,\nI. Concerning...', 'teologico');
add('ex', 2, 23, 'Matthew Henry', 'Here is, 1. The continuance of the Israelites\' bondage in Egypt, Exo 2:23. Probably the murdering of their infants did not continue; this part of their affliction attended only the period immediately connected with the birth of Moses, and served to signalize it. The Egyptians now were content with their increase, finding that Egypt was enriched by their labour; so that they might have them for slaves, they cared not how many they were. On this therefore they were intent, to keep them all at w...', 'teologico');
add('ex', 3, 1, 'Matthew Henry', 'The years of the life of Moses are remarkably divided into three forties: the first forty he spent as a prince in Pharaoh\'s court, the second a shepherd in Midian, the third a king in Jeshurun; so changeable is the life of men, especially the life of good men. He had now finished his second forty, when he received his commission to bring Israel out of Egypt. Note, Sometimes it is long before God calls his servants out of that work which of old he designed them for, and has been graciously pre...', 'teologico');
add('ex', 3, 7, 'Matthew Henry', 'Now that Moses had put off his shoes (for, no doubt, he observed the orders given him, Exo 3:5), and covered his face, God enters upon the particular business that was now to be concerted, which was the bringing of Israel out of Egypt. Now, after forty years of Israel\'s bondage and Moses\'s banishment, when we may suppose both he and they began to despair, they of being delivered and he of delivering them, at length, the time has come, even the year of the redeemed. Note, God often comes for t...', 'teologico');
add('ex', 3, 11, 'Matthew Henry', 'God, having spoken to Moses, allows him also a liberty of speech, which he here improves; and,\nI. He objects his own insufficiency for the service he was called to (Exo 3:11): Who am I? He thinks himself unworthy of the honour, and not par negotio - equal to the task. He thinks he wants courage, and therefore cannot go to Pharaoh, to make a demand which might cost the demandant his head: he thinks he wants skill, and therefore cannot bring forth the children of Israel out of Egypt; they are u...', 'teologico');
add('ex', 3, 16, 'Matthew Henry', 'Moses is here more particularly instructed in his work, and informed beforehand of his success. 1. He must deal with the elders of Israel, and raise their expectation of a speedy removal to Canaan, Exo 3:16, Exo 3:17. He must repeat to them what God had said to him, as a faithful ambassador. Note, That which ministers have received of the Lord they must deliver to his people, and keep back nothing that is profitable. Lay an emphasis on that, Exo 3:17 : "I have said, I will bring you up; that ...', 'teologico');
add('ex', 4, 1, 'Matthew Henry', 'It was a very great honour that Moses was called to when God commissioned him to bring Israel out of Egypt; yet he is with difficulty persuaded to accept the commission, and does it at last with great reluctance, which we should rather impute to a humble diffidence of himself and his own sufficiency than to any unbelieving distrust of God and his word and power. Note, Those whom God designs for preferment he clothes with humility; the most fit for service are the least forward.\nI. Moses objec...', 'teologico');
add('ex', 4, 10, 'Matthew Henry', 'Moses still continues backward to the service for which God had designed him, even to a fault; for now we can no longer impute it to his humility and modesty, but must own that here was too much of cowardice, slothfulness, and unbelief in it. Observe here,\nI. How Moses endeavours to excuse himself from the work.\n1. He pleads that he was no good spokesman: O my Lord! I am not eloquent, Exo 4:10. He was a great philosopher, statesman, and divine, and yet no orator; a man of a clear head, great ...', 'teologico');
add('ex', 4, 18, 'Matthew Henry', 'Here, I. Moses obtains leave of his father-in-law to return into Egypt, Exo 4:18. His father-in-law had been kind to him when he was a stranger, and therefore he would not be so uncivil as to leave his family, nor so unjust as to leave his service, without giving him notice. Note, The honour of being admitted into communion with God, and of being employed for him, does not exempt us from the duties of our relations and callings in this world. Moses said nothing to his father-in-law (for aught...', 'teologico');
add('ex', 4, 24, 'Matthew Henry', 'Moses is here going to Egypt, and we are told,\nI. How God met him in anger, Exo 4:24-26. This is a very difficult passage of story; much has been written, and excellently written, to make it intelligible; we will try to make it improving. Here is,\n1. The sin of Moses, which was neglecting to circumcise his son. This was probably the effect of his being unequally yoked with a Midianite, who was too indulgent of her child, while Moses was too indulgent of her. Note, (1.) We have need to watch c...', 'teologico');
add('ex', 5, 1, 'Matthew Henry', 'Moses and Aaron, having delivered their message to the elders of Israel, with whom they found good acceptance, are now to deal with Pharaoh, to whom they come in peril of their lives - Moses particularly, who perhaps was out-lawed for killing the Egyptian forty years before, so that if any of the old courtiers should happen to remember that against him now it might cost him his head. Their message itself was displeasing, and touch Pharaoh both in his honour and in his profit, two tender point...', 'teologico');
add('ex', 5, 3, 'Matthew Henry', 'Finding that Pharaoh had no veneration at all for God, Moses and Aaron next try whether he had any compassion for Israel, and become humble suitors to him for leave to go and sacrifice, but in vain.\nI. Their request is very humble and modest, Exo 5:3. They make no complaint of the rigour they were ruled with. They plead that the journey they designed was not a project formed among themselves, but that their God had met with them, and called them to it. They beg with all submission: We pray th...', 'teologico');
add('ex', 5, 10, 'Matthew Henry', 'Pharaoh\'s orders are here put in execution; straw is denied, and yet the work not diminished. 1. The Egyptian task-masters were very severe. Pharaoh having decreed unrighteous decrees, the task-masters were ready to write the grievousness that he had prescribed, Isa 10:1. Cruel princes will never want cruel instruments to be employed under them, who will justify them in that which is most unreasonable. These task-masters insisted upon the daily tasks, as when there was straw, Exo 5:13. See wh...', 'teologico');
add('ex', 5, 15, 'Matthew Henry', 'It was a great strait that the head-workmen were in, when they must either abuse those that were under them or be abused by those that were over them; yet, it should seem, rather than they would tyrannize, they would be tyrannized over; and they were so. In this evil case (Exo 5:19), observe,\nI. How justly they complained to Pharaoh: They came and cried unto Pharaoh, Exo 5:15. Whither should they go with a remonstrance of their grievances but to the supreme power, which is ordained for the pr...', 'teologico');
add('ex', 6, 1, 'Matthew Henry', 'Here, I. God silences Moses\'s complaints with the assurance of success in this negotiation, repeating the promise made him in Exo 3:20, After that, he will let you go. When Moses was at his wit\'s end, wishing he had staid in Midian, rather than have come to Egypt to make bad worse - when he was quite at a loss what to do - Then the Lord said unto Moses, for the quieting of his mind, "Now shalt thou see what I will do to Pharaoh (Exo 6:1); now that the affair has come to a crisis, things are a...', 'teologico');
add('ex', 6, 10, 'Matthew Henry', 'Here, I. God sends Moses the second time to Pharaoh (Exo 6:11) upon the same errand as before, to command him, at his peril, that he let the children of Israel go. Note, God repeats his precepts before he begins his punishments. Those that have often been called in vain to leave their sins must yet be called again and again, whether they will hear or whether they will forbear, Eze 3:11. God is said to hew sinners by his prophets (Hos 6:5), which denotes the repetition of the strokes. How ofte...', 'teologico');
add('ex', 6, 14, 'Matthew Henry', 'I. We have here a genealogy, not an endless one, such as the apostle condemns (Ti1 1:4), for it ends in those two great patriots Moses and Aaron, and comes in here to show that they were Israelites, bone of their bone and flesh of their flesh whom they were sent to deliver, raised up unto them of their brethren, as Christ also should be, who was to be the prophet and priest, the Redeemer and lawgiver, of the people of Israel, and whose genealogy also, like this, was to be carefully preserved....', 'teologico');
add('ex', 7, 1, 'Matthew Henry', 'Here, I. God encourages Moses to go to Pharaoh, and at last silences all his discouragements. 1. He clothes him with great power and authority (Exo 7:1): I have made thee a god to Pharaoh; that is, my representative in this affair, as magistrates are called gods, because they are God\'s viceregents. He was authorized to speak and act in God\'s name and stead, and, under the divine direction, was endued with a divine power to do that which is above the ordinary power of nature, and invested with...', 'teologico');
add('ex', 7, 8, 'Matthew Henry', 'The first time that Moses made his application to Pharaoh, he produced his instructions only; now he is directed to produce his credentials, and does accordingly. 1. It is taken for granted that Pharaoh would challenge these demandants to work a miracle, that, by a performance evidently above the power of nature, they might prove their commission from the God of nature. Pharaoh will say, Show a miracle; not with any desire to be convinced, but with the hope that none will be wrought, and then...', 'teologico');
add('ex', 7, 14, 'Matthew Henry', 'Here is the first of the ten plagues, the turning of the water into blood, which was, 1. A dreadful plague, and very grievous. The very sight of such vast rolling streams of blood, pure blood no doubt, florid and high-colored, could not but strike a horror upon people: much more afflictive were the consequences of it. Nothing more common than water: so wisely has Providence ordered it, and so kindly, that that which is so needful and serviceable to the comfort of human life should be cheap, a...', 'teologico');
add('ex', 8, 1, 'Matthew Henry', 'Pharaoh is here first threatened and then plagued with frogs, as afterwards, in this chapter, with lice and flies, little despicable inconsiderable animals, and yet by their vast numbers rendered sore plagues to the Egyptians. God could have plagued them with lions, or bears, or wolves, or with vultures or other birds of prey; but he chose to do it by these contemptible instruments. 1. That he might magnify his own power. He is Lord of the hosts of the whole creation, has them all at his beck...', 'teologico');
add('ex', 8, 16, 'Matthew Henry', 'Here is a short account of the plague of lice. It does not appear that any warning was given of it before. Pharaoh\'s abuse of the respite granted to him might have been a sufficient warning to him to expect another plague: for if the removal of an affliction harden us, and so we lose the benefit of it, we may conclude it goes away with a purpose to return or to make room for a worse. Observe,\nI. How this plague of lice was inflicted on the Egyptians, Exo 8:16, Exo 8:17. The frogs were produce...', 'teologico');
add('ex', 8, 20, 'Matthew Henry', 'Here is the story of the plague of flies, in which we are told,\nI. How it was threatened, like that of frogs, before it was inflicted. Moses is directed (Exo 8:20) to rise early in the morning, to meet Pharaoh when he came forth to the water, and there to repeat his demands. Note, 1. Those that would bring great things to pass for God and their generation must rise early, and redeem time in the morning. Pharaoh was early up at his superstitious devotions to the river; and shall we be for more...', 'teologico');
add('ex', 9, 1, 'Matthew Henry', 'Here is, I. Warning given of another plague, namely, the murrain of beasts. When Pharaoh\'s heart was hardened, after he had seemed to relent under the former plague, then Moses is sent to tell him there is another coming, to try what that would do towards reviving the impressions of the former plagues. Thus is the wrath of God revealed from heaven, both in his word and in his works, against all ungodliness and unrighteousness of men. 1. Moses puts Pharaoh in a very fair way to prevent it: Let...', 'teologico');
add('ex', 9, 8, 'Matthew Henry', 'Observe here, concerning the plague of boils and blains,\nI. When they were not wrought upon by the death of their cattle, God sent a plague that seized their own bodies, and touched them to the quick. If less judgments do not do their work, God will send greater. Let us therefore humble ourselves under the mighty hand of God, and go forth to meet him in the way of his judgments, that his anger may be turned away from us.\nII. The signal by which this plague was summoned was the sprinkling of w...', 'teologico');
add('ex', 9, 13, 'Matthew Henry', 'Here is, I. A general declaration of the wrath of God against Pharaoh for his obstinacy. Though God has hardened his heart (Exo 9:12), yet Moses must repeat his applications to him; God suspends his grace and yet demands obedience, to punish him for requiring bricks of the children of Israel when he denied them straw. God would likewise show forth a pattern of long-suffering, and how he waits to be gracious to a rebellious and gainsaying people Six times the demand had been made in vain, yet ...', 'teologico');
add('ex', 9, 22, 'Matthew Henry', 'The threatened plague of hail is here summoned by the powerful hand and rod of Moses (Exo 9:22, Exo 9:23), and it obeys the summons, or rather the divine command; for fire and hail fulfil God\'s word, Psa 148:8. And here we are told,\nI. What desolations it made upon the earth. The thunder, and fire from heaven (or lightning), made it both the more dreadful and the more destroying, Exo 9:23, Exo 9:24. Note, God makes the clouds, not only his store-houses whence he drops fatness on his people, b...', 'teologico');
add('ex', 10, 1, 'Matthew Henry', 'Here, I. Moses is instructed. We may well suppose that he, for his part, was much astonished both at Pharaoh\'s obstinacy and at God\'s severity, and could not but be compassionately concerned for the desolations of Egypt, and at a loss to conceive what this contest would come to at last. Now here God tells him what he designed, not only Israel\'s release, but the magnifying of his own name: That thou mayest tell in thy writings, which shall continue to the world\'s end, what I have wrought in Eg...', 'teologico');
add('ex', 10, 12, 'Matthew Henry', 'Here is, I. The invasion of the land by the locusts - God\'s great army, Joe 2:11. God bids Moses stretch out his hand (Exo 10:12), to beckon them, as it wee (for they came at a call), and he stretched forth his rod, Exo 10:13. Compare Exo 9:22 23. Moses ascribes it to the stretching out, not of his own hand, but the rod of God, the instituted sign of God\'s presence with him. The locusts obey the summons, and fly upon the wings of the wind, the east wind, and caterpillars without number, as we...', 'teologico');
add('ex', 10, 21, 'Matthew Henry', 'Here is, I. The plague of darkness brought upon Egypt, and a most dreadful plague it was, and therefore is put first of the ten in Psa 105:28, though it was one of the last; and in the destruction of the spiritual Egypt it is produced by the fifth vial, which is poured out upon the seat of the beast, Rev 16:10. His kingdom was full of darkness. Observe particularly concerning this plague, 1. That it was a total darkness. We have reason to think, not only that the lights of heaven were clouded...', 'teologico');
add('ex', 11, 1, 'Matthew Henry', 'Here is, I. The high favour Moses and Israel were in with God. 1. Moses was a favourite of Heaven, for God will not hide from him the thing he will do. God not only makes him his messenger to deliver his errands, but communicates to him his purpose (as the man of his counsel) that he would bring one plague more, and but one, upon Pharaoh, by which he would complete the deliverance of Israel, Exo 11:1. Moses longed to see an end of this dreadful work, to see Egypt no more plagued and Israel no...', 'teologico');
add('ex', 11, 4, 'Matthew Henry', 'Warning is here given to Pharaoh of the last and conquering plague which was now to be inflicted. This was the death of all the first-born in Egypt at once, which had been first threatened (Exo 4:23, I will slay thy son, thy first-born), but is last executed; less judgments were tried, which, if they had done the work would have prevented this. See how slow God is to wrath, and how willing to be met with in the way of his judgments, and to have his anger turned away, and particularly how prec...', 'teologico');
add('ex', 12, 21, 'Matthew Henry', 'I. Moses is here, as a faithful steward in God\'s house, teaching the children of Israel to observe all things which God had commanded him; and no doubt he gave the instructions as largely as he received them, though they are not so largely recorded. It is here added,\n1. That this night, when the first-born were to be destroyed, no Israelite must stir out of doors till morning, that is, till towards morning, when they would be called to march out of Egypt, Exo 12:22. Not but that the destroyin...', 'teologico');
add('ex', 12, 29, 'Matthew Henry', 'Here we have, I. The Egyptians\' sons, even their first-born, slain, Exo 12:29, Exo 12:30. If Pharaoh would have taken the warning which was given him of this plague, and would thereupon have released Israel, what a great many dear and valuable lives might have been preserved! But see what obstinate infidelity brings upon men. Observe, 1. The time when this blow was given: It was at midnight, which added to the terror of it. The three preceding nights were made dreadful by the additional plagu...', 'teologico');
add('ex', 12, 37, 'Matthew Henry', 'Here is the departure of the children of Israel out of Egypt; having obtained their dismission, they set forward without delay, and did not defer to a more convenient season. Pharaoh was now in a good mind; but they had reason to think he would not long continue so, and therefore it was no time to linger. We have here an account, 1. Of their number, about 600,000 men (Exo 12:37), besides women and children, which I think, we cannot suppose to make less than 1,200,000 more. What a vast increas...', 'teologico');
add('ex', 12, 43, 'Matthew Henry', 'Some further precepts are here given concerning the passover, as it should be observed in times to come.\nI. All the congregation of Israel must keep it, Exo 12:47. All that share in God\'s mercies should join in thankful praises for them. Though it was observed in families apart, yet it is looked upon as the act of the whole congregation; for the smaller communities constituted the greater. The New Testament passover, the Lord\'s supper, ought not to be neglected by any who are capable of celeb...', 'teologico');
add('ex', 13, 1, 'Matthew Henry', 'Care is here taken to perpetuate the remembrance,\nI. Of the preservation of Israel\'s firstborn, when the firstborn of the Egyptians were slain. In memory of that distinguishing favour, and in gratitude for it, the firstborn, in all ages, were to be consecrated to God, as his peculiars (Exo 13:2), and to be redeemed, Exo 13:13. God, who by the right of creation is proprietor and sovereign of all the creatures, here lays claim in particular to the firstborn of the Israelites, by right of protec...', 'teologico');
add('ex', 13, 11, 'Matthew Henry', 'Here we have,\nI. Further directions concerning the dedicating of their firstborn to God. 1. The firstlings of their cattle were to be dedicated to God, as part of their possessions. Those of clean beasts - calves, lambs, and kids - if males, were to be sacrificed, Exo 22:30; Num 18:17, Num 18:18. Those of unclean beasts, as colts, were to be redeemed with a lamb, or knocked on the head. For whatsoever is unclean (as we all are by nature), if it be not redeemed, will be destroyed, Exo 13:11, E...', 'teologico');
add('ex', 13, 17, 'Matthew Henry', 'Here is, I. The choice God made of their way, Exo 13:17, Exo 13:18. He was their guide. Moses gave them direction but as he received it from the Lord. Note, The way of man is not in himself, Jer 10:23. He may devise his way, and design it; but, after all, it is God that directs his steps, Pro 16:9. Man proposes, but God disposes, and in his disposal we must acquiesce, and set ourselves to follow providence. There were two ways from Egypt to Canaan. One was a short cut from the north of Egypt ...', 'teologico');
add('ex', 14, 1, 'Matthew Henry', 'We have here,\nI. Instructions given to Moses concerning Israel\'s motions and encampments, which were so very surprising that if Moses had not express orders about them before they would scarcely have been persuaded to follow the pillar of cloud and fire. That therefore there might be no scruple nor dissatisfaction about it, Moses is told before, 1. Whither they must go, Exo 14:1, Exo 14:2. They had got to the edge of the wilderness (Exo 13:20), and a stage or two more would have brought them ...', 'teologico');
add('ex', 14, 10, 'Matthew Henry', 'We have here, I. The fright that the children of Israel were in when they perceived that Pharaoh pursued them, Exo 14:10. They knew very well the strength and rage of the enemy, and their own weakness; numerous indeed they were, but all on foot, unarmed, undisciplined, disquieted by long servitude, and (which was worst of all) now penned up by the situation of their camp, so that they could not make their escape. On the one hand was Pi-hahiroth, a range of craggy rocks impassable; on the othe...', 'teologico');
add('ex', 14, 15, 'Matthew Henry', 'We have here,\nI. Direction given to Israel\'s leader.\n1. What he must do himself. He must, for the present, leave off praying, and apply himself to his business (Exo 14:15): Wherefore cryest thou unto me? Moses, though he was assured of a good issue to the present distress, yet did not neglect prayer. We read not of one word he said in prayer, but he lifted up to God his heart, the language of which God well understood and took notice of. Moses\'s silent prayers of faith prevailed more with God...', 'teologico');
add('ex', 15, 1, 'Matthew Henry', 'Having read how that complete victory of Israel over the Egyptians was obtained, here we are told how it was celebrated; those that were to hold their peace while the deliverance was in working (Exo 14:14) must not hold their peace now that it was wrought; the less they had to do then the more they had to do now. If God accomplishes deliverance by his own immediate power, it redounds so much the more to his glory. Moses, no doubt by divine inspiration, indited this song, and delivered it to t...', 'teologico');
add('ex', 15, 22, 'Matthew Henry', 'It should seem, it was with some difficulty that Moses prevailed with Israel to leave that triumphant shore on which they sang the foregoing song. They were so taken up with the sight, or with the song, or with the spoiling of the dead bodies, that they cared not to go forward, but Moses with much ado brought them from the Red Sea into a wilderness. The pleasures of our way to Canaan must not retard our progress, but quicken it, though we have a wilderness before us. Now here we are told,\nI. ...', 'teologico');
add('ex', 16, 1, 'Matthew Henry', 'The host of Israel, it seems, took along with them out of Egypt, when they came thence on the fifteenth day of the first month, a month\'s provisions, which, by the fifteenth day of the second month, was all spent; and here we have,\nI. Their discontent and murmuring upon that occasion, Exo 16:2, Exo 16:3. The whole congregation, the greatest part of them, joined in this mutiny; it was not immediately against God that they murmured, but (which was equivalent) against Moses and Aaron, God\'s vice...', 'teologico');
add('ex', 16, 13, 'Matthew Henry', 'Now they begin to be provided for by the immediate hand of God.\nI. He makes them a feast, at night, of delicate fowl, feathered fowl (Psa 78:27), therefore not locusts, as some think; quails, or pheasants, or some wild fowl, came up, and covered the camp, so tame that they might take up as many of them as they pleased. Note, God gives us of the good things of this life, not only for necessity, but for delight, that we may not only serve him, but serve him cheerfully.\nII. Next morning he raine...', 'teologico');
add('ex', 16, 22, 'Matthew Henry', 'We have here, 1. A plain intimation of the observing of a seventh day sabbath, not only before the giving of the law upon Mount Sinai, but before the bringing of Israel out of Egypt, and therefore, from the beginning, Gen 2:3. If the sabbath had now been first instituted, how could Moses have understood what God said to him (Exo 16:5), concerning a double portion to be gathered on the sixth day, without making any express mention of the sabbath? And how could the people so readily take the hi...', 'teologico');
add('ex', 16, 32, 'Matthew Henry', 'God having provided manna to be his people\'s food in the wilderness, and to be to them a continual feast, we are here told, 1. How the memory of it was preserved. An omer of this manna was laid up in a golden pot, as we are told (Heb 9:4), and kept before the testimony, or the ark, when it was afterwards made, Exo 16:32-34. The preservation of this manna from waste and corruption was a standing miracle, and therefore the more proper memorial of this miraculous food. "Posterity shall see the b...', 'teologico');
add('ex', 17, 1, 'Matthew Henry', 'Here is, I. The strait that the children of Israel were in for want of water; once before the were in the like distress, and now, a second time, Exo 17:1. They journeyed according to the commandment of the Lord, led by the pillar of cloud and fire, and yet they came to a place where there was no water for them to drink. Note, We may be in the way of our duty, and yet may meet with troubles, which Providence brings us into for the trial of our faith, and that God may be glorified in our relief...', 'teologico');
add('ex', 17, 8, 'Matthew Henry', 'We have here the story of the war with Amalek, which, we may suppose, was the first that was recorded in the book of the wars of the Lord, Num 21:14. Amalek was the first of the nations that Israel fought with, Num 24:20. Observe,\nI. Amalek\'s attempt: They came out, and fought with Israel, Exo 17:8. The Amalekites were the posterity of Esau, who hated Jacob because of the birthright and blessing, and this was an effort of the hereditary enmity, a malice that ran in the blood, and perhaps was ...', 'teologico');
add('ex', 18, 1, 'Matthew Henry', 'This incident may very well be allowed to have happened as it is placed here, before the giving of the law, and not, as some place it, in connection with what is recorded, Num 10:11, Num 10:29, etc. Sacrifices were offered before; in these mentioned here (Exo 18:12) it is observable that Jethro is said to take them, not Aaron. And as to Jethro\'s advising Moses to constitute judges under him, though it is intimate (Exo 18:13) that the occasion of his giving that advice was on the morrow, yet i...', 'teologico');
add('ex', 18, 7, 'Matthew Henry', 'Observe here, I. The kind greeting that took place between Moses and his father-in-law, Exo 18:7. Though Moses was a prophet of the Lord, a great prophet, and king in Jeshurun, yet he showed a very humble respect to his father-in-law. However God in his providence is pleased to advance us, we must make conscience of giving honour to whom honour is due, and never look with disdain upon our poor relations. Those that stand high in the favour of God are not thereby discharged from the duty they ...', 'teologico');
add('ex', 18, 13, 'Matthew Henry', 'Here is, I. The great zeal and industry of Moses as a magistrate.\n1. Having been employed to redeem Israel out of the house of bondage, herein he is a further type of Christ, that he is employed as a lawgiver and a judge among them. (1.) He was to answer enquiries, to acquaint them with the will of God in doubtful cases, and to explain the laws of God that were already given them, concerning the sabbath, the man, etc., beside the laws of nature, relating both to piety and equity, Exo 18:15. T...', 'teologico');
add('ex', 19, 1, 'Matthew Henry', 'Here is, I. The date of that great charter by which Israel was incorporated. 1. The time when it bears date (Exo 19:1) - in the third month after they came out of Egypt. It is computed that the law was given just fifty days after their coming out of Egypt, in remembrance of which the feast of Pentecost was observed the fiftieth day after the passover, and in compliance with which the Spirit was poured out upon the apostles at the feast of pentecost, fifty days after the death of Christ. In Eg...', 'teologico');
add('ex', 19, 9, 'Matthew Henry', 'Here, I. God intimates to Moses his purpose of coming down upon mount Sinai, in some visible appearance of his glory, in a thick cloud (Exo 19:9); for he said that he would dwell in the thick darkness (Ch2 6:1), and make this his pavilion (Psa 18:11), holding back the face of his throne when he set it upon mount Sinai, and spreading a cloud upon it, Job 26:9. This thick cloud was to prohibit curious enquiries into things secret, and to command an awful adoration of that which was revealed. Go...', 'teologico');
add('ex', 19, 16, 'Matthew Henry', 'Now, at length, comes that memorable day, that terrible day of the Lord, that day of judgment, in which Israel heard the voice of the Lord God speaking to them out of the midst of the fire, and lived, Deu 4:33. Never was there such a sermon preached, before nor since, as this which was here preached to the church in the wilderness. For,\nI. The preacher was God himself (Exo 19:18): The Lord descended in fire, and (Exo 19:20), The Lord came down upon mount Sinai. The shechinah, or glory of the ...', 'teologico');
add('ex', 20, 18, 'Matthew Henry', 'I. The extraordinary terror with which the law was given. Never was any thing delivered with such awful pomp; every word was accented, and every sentence paused, with thunder and lightning, much louder and brighter, no doubt, than ordinary. And why was the law given in this dreadful manner, and with all this tremendous ceremony? 1. It was designed (once for all) to give a sensible discovery of the glorious majesty of God, for the assistance of our faith concerning it, that, knowing the terror...', 'teologico');
add('ex', 20, 22, 'Matthew Henry', 'Moses having gone into the thick darkness, where God was, God there spoke in his hearing only, privately and without terror, all that follows hence to the end of ch. 23, which is mostly an exposition of the ten commandments; and he was to transmit it by word of mouth first, and afterwards in writing, to the people. The laws in these verses related to God\'s worship.\nI. They are here forbidden to make images for worship (Exo 20:22, Exo 20:23): You have seen that I have talked with you from heav...', 'teologico');
add('ex', 21, 1, 'Matthew Henry', 'The first verse is the general title of the laws contained in this and the two following chapters, some of them relating to the religious worship of God, but most of them relating to matters between man and man. Their government being purely a Theocracy, that which in other states is to be settled by human prudence was directed among them by a divine appointment, so that the constitution of their government was peculiarly adapted to make them happy. These laws are called judgments, because th...', 'teologico');
add('ex', 21, 12, 'Matthew Henry', 'Here is, I. A law concerning murder. He had lately said, Thou shalt not kill; here he provides, 1. For the punishing of wilful murder (Exo 21:12): He that smiteth a man, whether upon a sudden passion or in malice prepense, so that he die, the government must take care that the murderer be put to death, according to that ancient law (Gen 9:6), Whoso sheddeth man\'s blood, by man shall his blood be shed. God, who by his providence gives and maintains life, thus by his law protects it; so that me...', 'teologico');
add('ex', 21, 22, 'Matthew Henry', 'Observe here,\nI. The particular care which the law took of women with child, that no hurt should be done them which might occasion their mis-carrying. The law of nature obliges us to be very tender in that case, lest the tree and fruit be destroyed together, Exo 21:22, Exo 21:23. Women with child, who are thus taken under the special protection of the law of God, if they live in his fear, may still believe themselves under the special protection of the providence of God, and hope that they sh...', 'teologico');
add('ex', 22, 1, 'Matthew Henry', 'Here are the laws,\nI. Concerning theft, which are these: - 1. If a man steal any cattle (in which the wealth of those times chiefly consisted), and they be found in his custody, he must restore double, Exo 22:4. Thus he must both satisfy for the wrong and suffer for the crime. But it was afterwards provided that if the thief were touched in conscience, and voluntarily confessed it, before it was discovered or enquired into by any other, then he should only make restitution of what he had stol...', 'teologico');
add('ex', 22, 7, 'Matthew Henry', 'These laws are,\nI. Concerning trusts, Exo 22:7-13. If a man deliver goods, suppose to a carrier to be conveyed, or to a warehouse-keeper to be preserved, or cattle to a farmer to be fed, upon a valuable consideration, and if a special confidence be reposed in the person they are lodged with, in case these goods be stolen or lost, perish or be damaged, if it appear that it was not by any fault of the trustee, the owner must stand to the loss, otherwise he that has been false to this trust must...', 'teologico');
add('ex', 22, 16, 'Matthew Henry', 'Here is, I. A law that he who debauched a young woman should be obliged to marry her, Exo 22:16, Exo 22:17. If she was betrothed to another, it was death to debauch her (Deu 22:23, Deu 22:24); but the law here mentioned respects her as single. But, if the father refused her to him, he was to give satisfaction in money for the injury and disgrace he had done her. This law puts an honour upon marriage and shows likewise how improper a thing it is that children should marry without their parents...', 'teologico');
add('ex', 22, 25, 'Matthew Henry', 'Here is, I. A law against extortion in lending. 1. They must not receive use for money from any that borrowed for necessity (Exo 22:25), as in that case, Neh 5:5, Neh 5:7. And such provision the law made for the preservation of estates to their families by the year of jubilee that a people who had little concern in trade could not be supposed to borrow money but for necessity, and therefore it is generally forbidden among themselves; but to a stranger, whom yet they might not oppress, they we...', 'teologico');
add('ex', 23, 1, 'Matthew Henry', 'Here are, I. Cautions concerning judicial proceedings; it was not enough that they had good laws, better than ever any nation had, but care must be taken for the due administration of justice according to those laws.\n1. The witnesses are here cautioned that they neither occasion an innocent man to be indicted, by raising a false report of him and setting common fame against him, nor assist in the prosecution of an innocent man, or one whom they do not know to be guilty, by putting their hand ...', 'teologico');
add('ex', 23, 10, 'Matthew Henry', 'Here is, I. The institution of the sabbatical year, Exo 23:10, Exo 23:11. Every seventh year the land was to rest; they must not plough nor sow it at the beginning of the year, and then they could not expect any great harvest at the end of the year: but what the earth did produce of itself should be eaten from hand to mouth, and not laid up. Now this was designed, 1. To show what a plentiful land that was into which God was bringing them - that so numerous a people could have rich maintenance...', 'teologico');
add('ex', 23, 20, 'Matthew Henry', 'Three gracious promises are here made to Israel, to engage them to their duty and encourage them in it; and each of the promises has some needful precepts and cautions joined to it.\nI. It is here promised that they should be guided and kept in their way through the wilderness to the land of promise: Behold, I send an angel before thee (Exo 23:20), my angel (Exo 23:23), a created angel, say some, a minister of God\'s providence, employed in conducting and protecting the camp of Israel; that it ...', 'teologico');
add('ex', 24, 1, 'Matthew Henry', 'The first two verses record the appointment of a second session upon mount Sinai, for the making of laws, when an end was put to the first. When a communion is begun between God and us, it shall never fail on his side, if it do not first fail on ours. Moses is directed to bring Aaron and his sons, and the seventy elders of Israel, that they might be witnesses of the glory of God, and that communion with him to which Moses was admitted; and that their testimony might confirm the people\'s faith...', 'teologico');
add('ex', 24, 9, 'Matthew Henry', 'The people having, besides their submission to the ceremony of the sprinkling of blood, declared their well-pleasedness in their God and his law, again and again, God here gives to their representatives some special tokens of his favour to them (for God meets him that rejoices and works righteousness), and admits them nearer to him than they could have expected. Thus, in the New Testament church, we find the four living creatures, and the four and twenty elders, honoured with places round the...', 'teologico');
add('ex', 24, 12, 'Matthew Henry', 'The public ceremony of sealing the covenant being over, Moses is called up to receive further instructions, which we have in the following chapters.\nI. He is called up into the mount, and there he remains six days at some distance. Orders are given him (Exo 24:12): Come up to the mount, and be there, that is, "Expect to continue there for some considerable time." Those that would have communion with God must not only come to ordinances, but they must abide by them. Blessed are those that dwel...', 'teologico');
add('ex', 25, 1, 'Matthew Henry', 'We may suppose that when Moses went into the midst of the cloud, and abode there so long, where the holy angels attended the shechinah, or divine Majesty, he saw and heard very glorious things relating to the upper world, but they were things which it was not lawful nor possible to utter; and therefore, in the records he kept of the transactions there, he says nothing to satisfy the curiosity of those who would intrude into the things which they have not seen, but writes that only which he wa...', 'teologico');
add('ex', 25, 10, 'Matthew Henry', 'The first thing which is here ordered to be made is the ark with its appurtenances, the furniture of the most holy place, and the special token of God\'s presence, for which the tabernacle was erected to be the receptacle.\nI. The ark itself was a chest, or coffer, in which the two tables of the law, written with the finger of God, were to be honourably deposited, and carefully kept. The dimensions of it are exactly ordered; if the Jewish cubit was, as some learned men compute, three inches lon...', 'teologico');
add('ex', 25, 23, 'Matthew Henry', 'Here is, 1. A table ordered to be made of wood overlaid with gold, which was to stand, not in the holy of holies (nothing was in that but the ark with its appurtenances), but in the outer part of the tabernacle, called the sanctuary, or holy place, Heb 9:2, Heb 9:23, etc. There must also be the usual furniture of the sideboard, dishes and spoons, etc., and all of gold, Exo 25:29. 2. This table was to be always spread, and furnished with the show-bread (Exo 25:30), or bread of faces, twelve lo...', 'teologico');
add('ex', 25, 31, 'Matthew Henry', 'I. The next thing ordered to be made for the furnishing of God\'s palace was a rich stately candlestick, all of pure gold, not hollow, but solid. The particular directions here given concerning it show, 1. That it was very magnificent, and a great ornament to the place; it had many branches drawn from the main shaft, which had not only their bowls (to put the oil and the kindled wick in) for necessity, but knops and flowers for ornament. 2. That it was very convenient, and admirably contrived ...', 'teologico');
add('ex', 26, 1, 'Matthew Henry', 'I. The house must be a tabernacle or tent, such as soldiers now use in the camp, which was both a mean dwelling and a movable one; and yet the ark of God had not better, till Solomon built the temple 480 years after this, Kg1 6:1. God manifested his presence among them thus in a tabernacle, 1. In compliance with their present condition in the wilderness, that they might have him with them wherever they went. Note, God suits the tokens of his favour, and the gifts of his grace, to his people\'s...', 'teologico');
add('ex', 26, 7, 'Matthew Henry', 'Moses is here ordered to make a double covering for the tabernacle, that it might not rain in, and that the beauty of those fine curtains might not be damaged. 1. There was to be a covering of hair camlet curtains, which were somewhat larger every way than the inner curtains, because they were to enclose them, and probably were stretched out at some little distance from them, Exo 26:7, etc. These were coupled together with brass clasps. The stuff being less valuable, the tacks were so; but th...', 'teologico');
add('ex', 26, 15, 'Matthew Henry', 'Very particular directions are here given about the boards of the tabernacle, which were to bear up the curtains, as the stakes of a tent which had need to be strong, Isa 54:2. These boards had tenons which fell into the mortises that were made for them in silver bases. God took care to have every thing strong, as well as fine, in his tabernacle. Curtains without boards would have been shaken by every wind; but it is a good thing to have the heart established with grace, which is as the board...', 'teologico');
add('ex', 26, 31, 'Matthew Henry', 'Two veils are here ordered to be made, 1. One for a partition between the holy place and the most holy, which not only forbade any to enter, but forbade them so much as to look into the holiest of all, Exo 26:31, Exo 26:33. Under that dispensation, divine grace was veiled, but now we behold it with open face, Co2 3:18. The apostle tells us (Heb 9:8, Heb 9:9) what was the meaning of this veil; it intimated that the ceremonial law could not make the comers thereunto perfect, nor would the obser...', 'teologico');
add('ex', 27, 1, 'Matthew Henry', 'As God intended in the tabernacle to manifest his presence among his people, so there they were to pay their devotions to him, not in the tabernacle itself (into that only the priests entered as God\'s domestic servants), but in the court before the tabernacle, where, as common subjects, they attended. There an altar was ordered to be set up, to which they must bring their sacrifices, and on which their priests must offer them to God: and this altar was to sanctify their gifts. Here they were ...', 'teologico');
add('ex', 27, 9, 'Matthew Henry', 'Before the tabernacle there was to be a court or yard, enclosed with hangings of the finest linen that was used for tents. This court, according to the common computation of cubits, was fifty yards long, and twenty-five broad. Pillars were set up at convenient distances, in sockets of brass, the pillars filleted with silver, and silver tenter-hooks in them, on which the linen hangings were fastened: the hanging which served for the gate was finer than the rest, Exo 27:16. This court was a typ...', 'teologico');
add('ex', 27, 20, 'Matthew Henry', 'We read of the candlestick in the twenty-fifth chapter; here is an order given for the keeping of the lamps constantly burning in it, else it was useless; in every candlestick there should be a burning and shining light; candlesticks without candles are as wells without water or as clouds without rain. Now, 1. The people were to provide the oil; from them the Lord\'s ministers must have their maintenance. Or, rather, the pure oil signified the gifts and graces of the Spirit, which are communic...', 'teologico');
add('ex', 28, 1, 'Matthew Henry', 'We have here,\nI. The priests nominated: Aaron and his sons, Exo 28:1. Hitherto every master of a family was priest to his own family, and offered, as he saw cause, upon altars of earth; but now that the families of Israel began to be incorporated into a nation, and a tabernacle of the congregation was to be erected, as a visible centre of their unity, it was requisite there should be a public priesthood instituted. Moses, who had hitherto officiated, and is therefore reckoned among the priest...', 'teologico');
add('ex', 28, 6, 'Matthew Henry', 'Directions are here given concerning the ephod, which was the outmost garment of the high priest. Linen ephods were worn by the inferior priests, Sa1 22:18. Samuel wore one when he was a child (Sa1 2:18), and David when he danced before the ark (Sa2 6:14); but this which the high priest only wore was called a golden ephod, because there was a great deal of gold woven into it. It was a short coat without sleeves, buttoned closely to him, with a curious girdle of the same stuff (Exo 28:6-8); th...', 'teologico');
add('ex', 28, 15, 'Matthew Henry', 'The most considerable of the ornaments of the high priest was this breast-plate, a rich piece of cloth, curiously wrought with gold and purple, etc., two spans long and a span broad, so that, being doubled, it was a span square, Exo 28:16. This was fastened to the ephod with wreathen chains of gold (Exo 28:13, Exo 28:14, Exo 28:22, etc.) both at top and bottom, so that the breast-plate might not be loosed from the ephod, Exo 28:28. The ephod was the garment of service; the breast-plate of jud...', 'teologico');
add('ex', 28, 31, 'Matthew Henry', 'Here is, 1. Direction given concerning the robe of the ephod, Exo 28:31-35. This was next under the ephod, and reached down to the knees, was without sleeves, and was put on over their head, having holes on the sides to put the arms through, or, as Maimonides describes it, was not sewed together on the sides at all. The hole on the top, through which the head was put, was carefully bound about, that it might not tear in the putting on. In religious worship, care must be taken to prevent every...', 'teologico');
add('ex', 28, 40, 'Matthew Henry', 'We have here, 1. Particular orders about the vestments of the inferior priests. They were to have coats, and girdles, and bonnets, of the same materials with those of the high priest; but there was a difference in shape between their bonnets and his mitre. Theirs, as his, were to be for glory and beauty (Exo 28:40), that they might look great in their ministration: yet all this glory was nothing compared with the glory of grace, this beauty nothing to the beauty of holiness, of which these ho...', 'teologico');
add('ex', 29, 1, 'Matthew Henry', 'Here is, I. The law concerning the consecration of Aaron and his sons to the priest\'s office, which was to be done with a great deal of ceremony and solemnity, that they themselves might be duly affected with the greatness of the work to which they were called, and that the people also might learn to magnify the office and none might dare to invade it.\n1. The ceremonies wherewith it was to be done were very fully and particularly appointed, because nothing of this kind had been done before, a...', 'teologico');
add('ex', 29, 38, 'Matthew Henry', 'In this paragraph we have,\nI. The daily service appointed. A lamb was to be offered upon the altar every morning, and a lamb every evening, each with a meat-offering, both made by fire, as a continual burnt-offering throughout their generations, Exo 29:38-41. Whether there were any other sacrifices to be offered or not, these were sure to be offered, at the public charge, for the benefit and comfort of all Israel, to make atonement for their daily sins, and to be an acknowledgement to God of ...', 'teologico');
add('ex', 30, 1, 'Matthew Henry', 'I. The orders given concerning the altar of incense are, 1. That it was to be made of wood, and covered with gold, pure gold, about a yard high and half a yard square, with horns at the corners, a golden cornice round it, with rings and staves of gold, for the convenience of carrying it, Exo 30:1-5. It does not appear that there was any grate to this altar for the ashes to fall into, that they might be taken away; but, when they burnt incense, a golden censer was brought with coals in it, and...', 'teologico');
add('ex', 30, 11, 'Matthew Henry', 'Some observe that the repetition of those words, The Lord spoke unto Moses, here and afterwards (Exo 30:17, Exo 30:22, Exo 30:34), intimates that God did not deliver these precepts to Moses in the mount, in a continued discourse, but with many intermissions, giving him time either to write what was said to him or at least to charge his memory with it. Christ gave instructions to his disciples as they were able to hear them. Moses is here ordered to levy money upon the people by way of poll, s...', 'teologico');
add('ex', 30, 17, 'Matthew Henry', 'Orders are here given, 1. For the making of a laver, or font, of brass, a large vessel, that would contain a good quantity of water, which was to be set near the door of the tabernacle, Exo 30:18. The foot of brass, it is supposed, was so contrived as to receive the water, which was let into it out of the laver by spouts or cocks. They then had a laver for the priests only to wash in, but to us now there is a fountain open for Judah and Jerusalem to wash in (Zac 13:1), an inexhaustible founta...', 'teologico');
add('ex', 30, 22, 'Matthew Henry', 'Directions are here given for the composition of the holy anointing oil and the incense that were to be used in the service of the tabernacle; with these God was to be honoured, and therefore he would appoint the making of them; for nothing comes to God but what comes from him. 1. The holy anointing oil is here ordered to be made up the ingredients, and their quantities, are prescribed, Exo 30:23-25. Interpreters are not agreed concerning them; we are sure, in general, they were the best and ...', 'teologico');
add('ex', 31, 1, 'Matthew Henry', 'A great deal of fine work God had ordered to be done about the tabernacle; the materials the people were to provide, but who must put them into form? Moses himself was learned in all the learning of the Egyptians, nay, he was well acquainted with the words of God, and the visions of the Almighty; but he knew not how to engrave or embroider. We may suppose that there were some very ingenious men among the Israelites; but, having lived all their days in bondage in Egypt, we cannot think they we...', 'teologico');
add('ex', 31, 12, 'Matthew Henry', 'Here is, I. A strict command for the sanctification of the sabbath day, Exo 31:13-17. The law of the sabbath had been given them before any other law, by was of preparation (Exo 16:23); it had been inserted in the body of the moral law, in the fourth commandment; it had been annexed to the judicial law (Exo 23:12); and here it is added to the first part of the ceremonial law, because the observance of the sabbath is indeed the hem and hedge of the whole law; where no conscience is made of tha...', 'teologico');
add('ex', 32, 1, 'Matthew Henry', 'While Moses was in the mount, receiving the law from God, the people had time to meditate upon what had been delivered, and prepare themselves for what was further to be revealed, and forty days was little enough for that work; but, instead of that, there were those among them that were contriving how to break the laws they had already received, and to anticipate those which they were in expectation of. On the thirty-ninth day of the forty, the plot broke out of rebellion against the Lord. He...', 'teologico');
add('ex', 32, 7, 'Matthew Henry', 'Here, I. God acquaints Moses with what was doing in the camp while he was absent, Exo 32:7, Exo 32:8. He could have told him sooner, as soon as the first step was taken towards it, and have hastened him down to prevent it; but he suffered it to come to this height, for wise and holy ends, and then sent him down to punish it. Note, It is no reproach to the holiness of God that he suffers sin to be committed, since he knows, not only how to restrain it when he pleases, but how to make it servic...', 'teologico');
add('ex', 32, 15, 'Matthew Henry', 'Here is, I. The favour of God to Moses, in trusting him with the two tables of the testimony, which, though of common stone, were far more valuable than all the precious stones that adorned the breast-plate of Aaron. The topaz of Ethiopia could not equal them, Exo 32:15, Exo 32:16. God himself, without the ministry either of man or angel (for aught that appears), wrote the ten commandments on these tables, on both their sides, some on one table and some on the other, so that they were folded ...', 'teologico');
add('ex', 32, 21, 'Matthew Henry', 'Moses, having shown his just indignation against the sin of Israel by breaking the tables and burning the calf, now proceeds to reckon with the sinners and to call them to an account, herein acting as the representative of God, who is not only a holy God, and hates sin, but a just God, and is engaged in honour to punish it, Isa 59:18. Now,\nI. He begins with Aaron, as God began with Adam, because he was the principal person, though not first in the transgression, but drawn into it. Observe her...', 'teologico');
add('ex', 32, 30, 'Matthew Henry', 'Moses, having executed justice upon the principal offenders, is here dealing both with the people and with God.\nI. With the people, to bring them to repentance, Exo 32:30.\n1. When some were slain, lest the rest should imagine that, because they were exempt from the capital punishment, they were therefore looked upon as free from guilt, Moses here tells the survivors, You have sinned a great sin, and therefore, though you have escaped this time, except you repent, you shall all likewise perish...', 'teologico');
add('ex', 33, 1, 'Matthew Henry', 'Here is, I. The message which God sent by Moses to the children of Israel, signifying the continuance of the displeasure against them, and the bad terms they yet stood upon with God. This he must let them know for their further mortification. 1. He applies to them a mortifying name, by giving them their just character - a stiff-necked people, Exo 33:3, Exo 33:5. "Go," says God to Moses, "go and tell them that they are so." He that knows them better than they know themselves says so of them. G...', 'teologico');
add('ex', 33, 7, 'Matthew Henry', 'Here is, I. One mark of displeasure put upon them for their further humiliation: Moses took the tabernacle, not his own tent for his family, but the tent wherein he gave audience, heard causes, and enquired of God, the guild-hall (as it were) of their camp, and pitched it without, afar off from the camp (Exo 33:7), to signify to them that they had rendered themselves unworthy of it, and that, unless peace was made, it would return to them no more. God would thus let them know that he was at v...', 'teologico');
add('ex', 33, 12, 'Matthew Henry', 'Moses, having returned to the door of the tabernacle, becomes a humble and importunate supplicant there for two very great favours, and as a prince he has power with God, and prevails for both: herein he was a type of Christ the great intercessor, whom the Father heareth always.\nI. He is very earnest with God for a grant of his presence with Israel in the rest of their march to Canaan, notwithstanding their provocations. The people had by their sin deserved the wrath of God, and for the turni...', 'teologico');
add('ex', 34, 1, 'Matthew Henry', 'The treaty that was on foot between God and Israel being broken off abruptly, by their worshipping the golden calf, when peace was made all must be begun anew, not where they left off, but from the beginning. Thus backsliders must repent, and do their first works, Rev 2:5.\nI. Moses must prepare for the renewing of the tables, Exo 34:1. Before, God himself provided the tables, and wrote on them; now, Moses mus hew out the tables, and God would only write upon them. Thus, in the first writing o...', 'teologico');
add('ex', 34, 5, 'Matthew Henry', 'No sooner had Moses got to the top of the mount than God gave him the meeting (Exo 34:5): The Lord descended, by some sensible token of his presence, and manifestation of his glory. His descending bespeaks his condescension; he humbles himself to take cognizance of those that humble themselves to walk with him. Psa 113:6, Lord, what is man, that he should be thus visited? He descended in the cloud, probably that pillar of cloud which had hitherto gone before Israel, and had the day before met...', 'teologico');
add('ex', 34, 10, 'Matthew Henry', 'Reconciliation being made, a covenant of friendship is here settled between God and Israel. The traitors are not only pardoned, but preferred and made favourites again. Well may the assurances of this be ushered in with a behold, a word commanding attention and admiration: Behold, I make a covenant. When the covenant was broken, it was Israel that broke it; now that it comes to be renewed, it is God that makes it. If there be quarrels, we must bear all the blame; if there be peace, God must h...', 'teologico');
add('ex', 34, 18, 'Matthew Henry', 'Here is a repetition of several appointments made before, especially relating to their solemn feasts. When they had made the calf, they proclaimed a feast in honour of it; now, that they might never do so again, they are here charged with the observance of the feasts which God had instituted. Note, Men need not be drawn from their religion by the temptation of mirth, for we serve a Master that has abundantly provided for the joy of his servants: serious godliness is a continual feast, and joy...', 'teologico');
add('ex', 34, 28, 'Matthew Henry', 'Here is, I. The continuance of Moses in the mount, where he was miraculously sustained, Exo 34:28. He was there in very intimate communion with God, without interruption, forty days and forty nights, and did not think it long. When we are weary of an hour or two spent in attendance upon God and adoration of him, we should think how many days and nights Moses spent with him, and of the eternal day we hope to spend in praising him. During all this time Moses did neither eat nor drink. Though he...', 'teologico');
add('ex', 35, 1, 'Matthew Henry', 'It was said in general (Exo 34:32), Moses gave them in commandment all that the Lord has spoken with him. But, the erecting and furnishing of the tabernacle being the work to which they were now immediately to apply themselves, there is particular mention of the orders given concerning it.\nI. All the congregation is summoned to attend (Exo 35:1); that is, the heads and rulers of the congregation, the representatives of the several tribes, who must receive instructions from Moses as he had rec...', 'teologico');
add('ex', 35, 20, 'Matthew Henry', 'Moses having made known to them the will of God, they went home and immediately put in practice what they had heard, Exo 35:20. O that every congregation would thus depart from the hearing of the word of God, with a full resolution to be doers of the same! Observe here,\nI. The offerings that were brought for the service of the tabernacle (Exo 35:21, etc.), concerning which many things may be noted. 1. It is intimated that they brought their offerings immediately; they departed to their tents ...', 'teologico');
add('ex', 35, 30, 'Matthew Henry', 'Here is the divine appointment of the master-workmen, that there might be no strife for the office, and that all who were employed in the work might take direction from, and give account to, these general inspectors; for God is the God of order and not of confusion. Observe, 1. Those whom God called by name to this service he filled with the Spirit of God, to qualify them for it, Exo 35:30, Exo 35:31. Skill in secular employments is God\'s gift, and comes from above, Jam 1:17. From him the fac...', 'teologico');
add('ex', 36, 1, 'Matthew Henry', 'I. The workmen set in without delay. Then they wrought, Exo 36:1. When God had qualified them for the work, then they applied themselves to it. Note, The talents we are entrusted with must not be laid up, but laid out; not hid in a napkin, but traded with. What have we all our gifts for, but to do good with them? They began when Moses called them, Exo 36:2. Even those whom God has qualified for, and inclined to, the service of the tabernacle, yet must wait for a regular call to it, either ext...', 'teologico');
add('ex', 36, 8, 'Matthew Henry', 'The first work they set about was the framing of the house, which must be done before the furniture of it was prepared. This house was not made of timber or stone, but of curtains curiously embroidered and coupled together. This served to typify the state of the church in this world, the palace of God\'s kingdom among men. 1. Though it is upon the earth, yet its foundation is not in the earth, as that of a house is; no, Christ\'s kingdom is not of this world, nor founded in it. 2. It is mean an...', 'teologico');
add('ex', 36, 14, 'Matthew Henry', 'Here, 1. The shelter and special protection that the church is under are signified by the curtains of hair-cloth, which were spread over the tabernacle, and the covering of rams\' skins and badgers\' skins over them, Exo 36:14-19. God has provided for his people a shadow from the heat, and a covert from storm and rain, Isa 4:6. They are armed against all weathers; the sun and the moon shall not smite them: and they are protected from the storms of divine wrath, that hail which will sweep away t...', 'teologico');
add('ex', 36, 35, 'Matthew Henry', 'In the building of a house there is a great deal of work about the doors and partitions. In the tabernacle these were answerable to the rest of the fabric; there were curtains for doors, and veils for partitions. 1. There was a veil made for a partition between the holy place, and the most holy, Exo 36:35, Exo 36:36. This signified the darkness and distance of that dispensation, compared with the New Testament, which shows us the glory of God more clearly and invites us to draw near to it; an...', 'teologico');
add('ex', 37, 1, 'Matthew Henry', 'I. It may be thought strange that Moses, when he had recorded so fully the instructions given him upon the mount for the making of all these things, should here record as particularly the making of them, when it might have sufficed only to have said, in a few words, that each of these things was made exactly according to the directions before recited. We are sure that Moses, when he wrote by divine inspiration, used no vain repetitions; there are no idle words in scripture. Why then are so ma...', 'teologico');
add('ex', 37, 10, 'Matthew Henry', 'Here is, 1. The making of the table on which the show-bread was to be continually placed. God is a good householder, that always keeps a plentiful table. Is the world his tabernacle? His providence in it spreads a table for all the creatures: he provides food for all flesh. Is the church his tabernacle? His grace in it spreads a table for all believers, furnished with the bread of life. But observe how much the dispensation of the gospel exceeds that of the law. Though here was a table furnis...', 'teologico');
add('ex', 37, 25, 'Matthew Henry', 'Here is, 1. The making of the golden altar, on which incense was to be burnt daily, which signified both the prayers of saints and the intercession of Christ, to which are owing the acceptableness and success of those prayers. The rings and staves, and all the appurtenances of this altar, were overlaid with gold, as all the vessels of the table and candlestick were of gold, for these were used in the holy place. God is the best, and we must serve him with the best we have; but the best we can...', 'teologico');
add('ex', 38, 1, 'Matthew Henry', 'Bezaleel having finished the gold-work, which, though the richest, yet was ordered to lie most out of sight, in the tabernacle itself, here goes on to prepare the court, which lay open to the view of all. Two things the court was furnished with, and both made of brass: - \nI. An altar of burnt-offering, Exo 38:1-7. On this all their sacrifices were offered, and it was this which, being sanctified itself for this purpose by the divine appointment, sanctified the gift that was in faith offered o...', 'teologico');
add('ex', 38, 9, 'Matthew Henry', 'The walls of the court, or church-yard, were like the rest curtains or hangings, made according to the appointment, Exo 27:9, etc. This represented the state of the Old Testament church: it was a garden enclosed; the worshippers were then confined to a little compass. But the enclosure being of curtains only intimated that the confinement of the church in one particular nation was not to be perpetual. The dispensation itself was a tabernacle-dispensation, movable and mutable, and in due time ...', 'teologico');
add('ex', 38, 21, 'Matthew Henry', 'Here we have a breviat of the account which, by Moses\'s appointment, the Levites took and kept of the gold, silver, and brass, that was brought in for the tabernacle\'s use, and how it was employed. Ithamar the son of Aaron was appointed to draw up this account, and was thus by less services trained up and fitted for greater, Exo 38:21. Bezaleel and Aholiab must bring in the account (Exo 38:22, Exo 38:23), and Ithamar must audit it, and give it in to Moses. And it was thus: - 1. All the gold w...', 'teologico');
add('ex', 39, 1, 'Matthew Henry', 'In this account of the making of the priests\' garments, according to the instructions given (ch. 28), we may observe, 1. That the priests\' garments are called here clothes of service, Exo 39:1. Note, Those that wear robes of honour must look upon them as clothes of service; for from those upon whom honour is put service is expected. It is said of those that are arrayed in white robes that they are before the throne of God, and serve him day and night in his temple, Rev 7:13, Rev 7:15. Holy ga...', 'teologico');
add('ex', 39, 32, 'Matthew Henry', 'Observe here, I. The builders of the tabernacle made very good despatch. It was not much more than five months from the beginning to the finishing of it. Though there was a great deal of fine work about it, such as is usually the work of time, embroidering and engraving, not only in gold, but in precious stones, yet they went through with it in a little time. Church-work is usually slow work, but they made quick work of this, and yet did it with the greatest exactness imaginable. For, 1. Many...', 'teologico');
add('ex', 40, 1, 'Matthew Henry', 'The materials and furniture of the tabernacle had been viewed severally and approved, and now they must be put together. 1. God here directs Moses to set up the tabernacle and the utensils of it in their places. Though the work of the tabernacle was finished, and every thing ready for rearing, and the people, no doubt, were very desirous to see it up, yet Moses will not erect it till he has express orders for doing so. It is good to see God going before us in every step, Psa 37:23. The time f...', 'teologico');
add('ex', 40, 16, 'Matthew Henry', 'When the tabernacle and the furniture of it were prepared, they did not put off the rearing of it till they came to Canaan, though they now hoped to be there very shortly; but, in obedience to the will of God, they set it up in the midst of their camp, while they were in the wilderness. Those that are unsettled in the world must not think that this will excuse them in their continued irreligion; as if it were enough to begin to serve God when they begin to be settled in the world. No; a taber...', 'teologico');
add('ex', 40, 34, 'Matthew Henry', 'As when, in the creation, God had finished this earth, which he designed for man\'s habitation, he made man, and put him in possession of it, so when Moses had finished the tabernacle, which was designed for God\'s dwelling-place among men, God came and took possession of it. The shechinah, the divine eternal Word, though not yet made flesh, yet, as a prelude to that event, came and dwelt among them, Joh 1:14. This was henceforward the place of his throne, and the place of the soles of his feet...', 'teologico');

// LV (91 comentários)
add('lv', 19, 2, 'Calvino', 'Sede santos — A santidade é imitação de Deus. O povo de Deus é chamado a separação moral do mundo.', 'teologico');
add('lv', 17, 11, 'Agostinho', 'A vida está no sangue — O sangue expia porque representa a vida. Tipologia do sangue de Cristo que purifica.', 'teologico');
add('lv', 16, 30, 'Matthew Henry', 'Neste dia se fará expiação — O Dia da Expiação aponta para Cristo, nosso Sumo Sacerdote eterno.', 'escatologico');
add('lv', 1, 1, 'Matthew Henry', 'Observe here, 1. It is taken for granted that people would be inclined to bring offerings to the Lord. The very light of nature directs man, some way or other, to do honour to his Maker, and pay him homage as his Lord. Revealed religion supposes natural religion to be an ancient and early institution, since the fall had directed men to glorify God by sacrifice, which was an implicit acknowledgment of their having received all from God as creatures, and their having forfeited all to him as sin...', 'teologico');
add('lv', 1, 3, 'Matthew Henry', 'If a man were rich and could afford it, it is supposed that he would bring his burnt-sacrifice, with which he designed to honour God, out of his herd of larger cattle. He that considers that God is the best that is will resolve to give him the best he has, else he gives him not the glory due unto his name. Now if a man determined to kill a bullock, not for an entertainment for his family and friends, but for a sacrifice to his God, these rules must be religiously observed: - 1. The beast to b...', 'teologico');
add('lv', 1, 10, 'Matthew Henry', 'Here we have the laws concerning the burnt-offerings, which were of the flock or of the fowls. Those of the middle rank, that could not well afford to offer a bullock, would bring a sheep or a goat; and those that were not able to do that should be accepted of God if they brought a turtle-dove or a pigeon. For God, in his law and in his gospel, as well as in his providence, considers the poor. It is observable that those creatures were chosen for sacrifice which were most mild and gentle, har...', 'teologico');
add('lv', 2, 1, 'Matthew Henry', 'There were some meat-offerings that were only appendices to the burnt-offerings, as that which was offered with the daily sacrifice (Exo 29:38, Exo 29:39) and with the peace-offerings; these had drink-offerings joined with them (see Num 15:4, Num 15:7, Num 15:9, Num 15:10), and in these the quantity was appointed. But the law of this chapter concerns those meat-offerings that were offered by themselves, whenever a man saw cause thus to express his devotion. The first offering we read of in sc...', 'teologico');
add('lv', 2, 11, 'Matthew Henry', 'Here, I. Leaven and honey are forbidden to be put in any of their meat-offerings: No leaven, nor any honey, in any offering made by fire, Lev 2:11. 1. The leaven was forbidden in remembrance of the unleavened bread they ate when they came out of Egypt. So much despatch was required in the offerings they made that it was not convenient they should stay for the leavening of them. The New Testament comparing pride and hypocrisy to leaven because they swell like leaven, comparing also malice and ...', 'teologico');
add('lv', 3, 1, 'Matthew Henry', 'The burnt-offerings had regard to God as in himself the best of beings, most perfect and excellent; they were purely expressive of adoration, and therefore were wholly burnt. But the peace-offerings had regard to God as a benefactor to his creatures, and the giver of all good things to us; and therefore these were divided between the altar, the priest, and the owner. Peace signifies, 1. Reconciliation, concord, and communion. And so these were called peace-offerings, because in them God and h...', 'teologico');
add('lv', 3, 6, 'Matthew Henry', 'Directions are here given concerning the peace-offering, if it was a sheep or a goat. Turtle-doves or young pigeons, which might be brought for whole burnt offerings, were not allowed for peace-offerings, because they have no fat considerable enough to be burnt upon the altar; and they would be next to nothing if they were to be divided according to the law of the peace-offerings. The laws concerning a lamb or goat offered for a peace offering are much the same with those concerning a bullock...', 'teologico');
add('lv', 4, 1, 'Matthew Henry', 'The laws contained in the first three chapters seem to have been delivered to Moses at one time. Here begin the statutes of another session, another day. From the throne of glory between the cherubim God delivered these orders. And he enters now upon a subject more strictly new than those before. Burnt-offerings, meat-offerings, and peace-offerings, it should seem, had been offered before the giving of the law upon mount Sinai; those sacrifices the patriarchs had not been altogether unacquain...', 'teologico');
add('lv', 4, 13, 'Matthew Henry', 'This is the law for expiating the guilt of a national sin, by a sin offering. If the leaders of the people, through mistake concerning the law, caused them to err, when the mistake was discovered an offering must be brought, that wrath might not come upon the whole congregation. Observe, 1. It is possible that the church may err, and that her guides may mislead her. It is here supposed that the whole congregation may sin, and sin through ignorance. God will always have a church on earth; but ...', 'teologico');
add('lv', 4, 22, 'Matthew Henry', 'Observe here, 1. That God takes notice of and is displeased with the sins of rulers. Those who have power to call others to account are themselves accountable to the ruler of rulers; for, as high as they are, there is a higher than they. This is intimated in that the commandment transgressed is here said to be the commandment of the Lord his God, Lev 4:22. He is a prince to others, but let him know the Lord is a God to him. 2. The sin of the ruler which he committed through ignorance is suppo...', 'teologico');
add('lv', 4, 27, 'Matthew Henry', 'I. Here is the law of the sin-offering for a common person, which differs from that for a ruler only in this, that a private person might bring either a kid or a lamb, a ruler only a kid; and that for a ruler must be a male, for the other a female: in all the circumstances of the management of the offering they agreed. Observe, 1. The case supposed: If any one of the common people sin through ignorance, Lev 4:27. The prophet supposes that they were not so likely as the great men to know the w...', 'teologico');
add('lv', 5, 1, 'Matthew Henry', 'I. The offences here supposed are, 1. A man\'s concealing the truth when he was sworn as a witness to speak the truth, the whole truth, and nothing but the truth. Judges among the Jews had power to adjure not only the witnesses, as with us, but the person suspected (contrary to a rule of our law, that no man is bound to accuse himself), as appears by the high priest adjuring our Saviour, who thereupon answered, though before he stood silent, Mat 26:63, Mat 26:64. Now (Lev 5:1), If a soul sin (...', 'teologico');
add('lv', 5, 7, 'Matthew Henry', 'Provision is here made for the poor of God\'s people, and the pacifying of their consciences under the sense of guilt. Those that were not able to bring a lamb might bring for a sin-offering a pair of turtle-doves or two young pigeons; nay, if any were so extremely poor that they were not able to procure these so often as they would have occasion, they might bring a pottle of fine flour, and this should be accepted. Thus the expense of the sin-offering was brought lower than that of any other ...', 'teologico');
add('lv', 5, 14, 'Matthew Henry', 'Hitherto in this chapter orders were given concerning those sacrifices that were both sin-offerings and trespass-offerings, for they go by both names, Lev 5:6. Here we have the law concerning those that were properly and peculiarly trespass-offerings, which were offered to atone for trespasses done against a neighbour, those sins we commonly call trespasses. Now injuries done to another may be either in holy things or in common things; of the former we have the law in these verses; of the lat...', 'teologico');
add('lv', 6, 1, 'Matthew Henry', 'This is the latter part of the law of the trespass-offering: the former part, which concerned trespasses about holy things, we had in the close of the foregoing chapter; this concerns trespasses in common things. Observe here,\nI. The trespass supposed, Lev 6:2, Lev 6:3. Though all the instances relate to our neighbour, yet it is called a trespass against the Lord, because, though the injury be done immediately to our neighbour, yet an affront is thereby given to his Maker and our Master. He t...', 'teologico');
add('lv', 6, 8, 'Matthew Henry', 'Hitherto we have had the instructions which Moses was directed to give to the people concerning the sacrifices; but here begin the instructions he was to give to the priests; he must command Aaron and his sons, Lev 6:9. The priests were rulers in the house of God, but these rulers must be ruled; and those that had the command of others must themselves be commanded. Let ministers remember that not only commissions, but commands, were given to Aaron and his sons, who must be in subjection to th...', 'teologico');
add('lv', 6, 14, 'Matthew Henry', 'The meat-offering was either that which was offered by the people or that by the priests at their consecration. Now,\nI. As to the common meat-offering,\n1. Only a handful of it was to be burnt upon the altar; all the rest was allowed to the priests for their food. The law of the burnt-offerings was such as imposed upon the priests a great deal of care and work, but allowed them little profit; for the flesh was wholly burnt, and the priests had nothing but the skin. But to make them amends the ...', 'teologico');
add('lv', 6, 24, 'Matthew Henry', 'We have here so much of the law of the sin-offering as did peculiarly concern the priests that offered it. As, 1. That it must be killed in the place where the burnt-offering was killed (Lev 6:25), that is, on the north side of the altar (Lev 1:11), which, some think typified the crucifying of Christ on mount Calvary, which was on the north side of Jerusalem. 2. That the priest who offered it for the sinner was (with his sons, or other priests, Lev 6:29) to eat the flesh of it, after the bloo...', 'teologico');
add('lv', 7, 1, 'Matthew Henry', 'Observe here, 1. Concerning the trespass-offering, that, being much of the same nature with the sin-offering, it was to be governed by the same rules, Lev 7:6. When the blood and fat were offered to God to make atonement, the priests were to eat the flesh, as that of the sin-offering, in the holy place. The Jews have a tradition (as we have it from the learned bishop Patrick) concerning the sprinkling of the blood of the trespass-offering round about upon the altar, "That there was a scarlet ...', 'teologico');
add('lv', 7, 11, 'Matthew Henry', 'All this relates to the peace-offerings: it is the repetition and explication of what we had before, with various additions.\nI. The nature and intention of the peace-offerings are here more distinctly opened. They were offered either, 1. In thankfulness for some special mercy received, such as recovery from sickness, preservation in a journey, deliverance at sea, redemption out of captivity, all which are specified in Ps. 107, and for them men are called upon to offer the sacrifice of thanksg...', 'teologico');
add('lv', 7, 35, 'Matthew Henry', 'Here is the conclusion of these laws concerning the sacrifices, though some of them are afterwards repeated and explained. The are to be considered, 1. As a grant to the priests, Lev 7:35, Lev 7:36. In the day they were ordained to that work and office this provision was made for their comfortable maintenance. Note, God will take care that those who are employed for him be well paid and well provided for. Those that receive the anointing of the Spirit to minister unto the Lord shall have thei...', 'teologico');
add('lv', 8, 1, 'Matthew Henry', 'God had given Moses orders to consecrate Aaron and his sons to the priests\' office, when he was with him the first time upon mount Sinai, Ex. 28 and Exo 29:1, where we have also the particular instructions he had how to do it. Now here we have,\nI. The orders repeated. What was there commanded to be done is here commanded to be done now, Lev 8:2, Lev 8:3. The tabernacle was newly set up, which, without the priests, would be as a candlestick without a candle; the law concerning sacrifices was n...', 'teologico');
add('lv', 8, 14, 'Matthew Henry', 'The covenant of priesthood must be made by sacrifice, as well as other covenants, Psa 50:5. And thus Christ was consecrated by the sacrifice of himself, once for all. Sacrifices of each kind must be offered for the priests, that they might with the more tenderness and concern offer the gifts and sacrifices of the people, with compassion on the ignorant, and on those that were out of the way, not insulting over those for whom sacrifices were offered, remembering that they themselves had had sa...', 'teologico');
add('lv', 8, 31, 'Matthew Henry', 'Moses, having done his part of the ceremony, now leaves Aaron and his sons to do theirs.\nI. They must boil the flesh of their peace-offering, and eat it in the court of the tabernacle, and what remained they must burn with fire, Lev 8:31, Lev 8:32. This signified their thankful consent to the consecration: when God gave Ezekiel his commission, he told him to eat the roll, Eze 3:1, Eze 3:2.\nII. They must not stir out of the court of the tabernacle for seven days, Lev 8:33. The priesthood being...', 'teologico');
add('lv', 9, 1, 'Matthew Henry', 'Orders are here given for another solemnity upon the eighth day; for the newly-ordained priests were set to work immediately after the days of their consecration were finished, to let them know that they were not ordained to be idle: He that desires the office of a bishop desires a good work, which must be looked at with desire, more than the honour and benefit. The priests had not so much as one day\'s respite from service allowed them, that they might divert themselves, and receive the compl...', 'teologico');
add('lv', 9, 8, 'Matthew Henry', 'These being the first offerings that ever were offered by the levitical priesthood, according to the newly-enacted law of sacrifices, the manner of offering them is particularly related, that it might appear how exactly they agreed with the institution. 1. Aaron with his own hands slew the offering (Lev 9:8), and did the work of the inferior priests; for, great as he was, he must not think any service below him which he could do for the honour of God: and, as Moses had shown him how to do thi...', 'teologico');
add('lv', 9, 23, 'Matthew Henry', 'We are not told what Moses and Aaron went into the tabernacle to do, Lev 9:23. Some of the Jewish writers say, "They went in to pray for the appearance of the divine glory;" most probably they went in that Moses might instruct Aaron how to do the service that was to be done there - burn incense, light the lamps, set the show-bread, etc., that he might instruct his sons in it. But, when they came out, they both joined in blessing the people, who stood expecting the promised appearance of the d...', 'teologico');
add('lv', 10, 1, 'Matthew Henry', 'Here is, I. The great sin that Nadab and Abihu were guilty of: and a great sin we must call it, how little soever it appears in our eye, because it is evident by the punishment of it that it was highly provoking to the God of heaven, whose judgment, we are sure, is according to truth. But what was their sin? All the account here given of it is that they offered strange fire before the Lord, which he commanded them not (Lev 10:1), and the same Num 3:4. 1. It does not appear the they had any or...', 'teologico');
add('lv', 10, 3, 'Matthew Henry', 'We may well think that when Nadab and Abihu were struck with death all about them were struck with horror, and every face, as well as theirs, gathered blackness. Great consternation, no doubt, seized them, and they were all full of confusion; but, whatever the rest were, Moses was composed, and knew what he said and did, not being displeased, as David was in a like case, Sa2 6:8. But though it touched him in a very tender part, and was a dreadful damp to one of the greatest joys he ever knew,...', 'teologico');
add('lv', 10, 8, 'Matthew Henry', 'Aaron having been very observant of what God said to him by Moses, now God does him the honour to speak to him immediately (Lev 10:8): The Lord spoke unto Aaron, and the rather because what was now to be said Aaron might perhaps have taken amiss from Moses, as if he had suspected him to have been a gluttonous man and a wine-bibber, so apt are we to resent cautions as accusations; therefore God saith it himself to him, Do not drink wine, nor strong drink, when you go into the tabernacle, and t...', 'teologico');
add('lv', 10, 12, 'Matthew Henry', 'Moses is here directing Aaron to go on with his service after this interruption. Afflictions should rather quicken us to our duty than take us off from it. Observe (Lev 10:12), He spoke unto Aaron and to his sons that were left. The notice taken of their survivorship intimates, 1. That Aaron should take comfort under the loss of two of his sons, from this consideration, that God had graciously spared him the other two, and that he had reason to be thankful for the remnant that was left, and a...', 'teologico');
add('lv', 11, 1, 'Matthew Henry', 'Now that Aaron was consecrated a high priest over the house of God, God spoke to him with Moses, and appointed them both as joint-commissioners to deliver his will to the people. He spoke both to Moses and to Aaron about this matter; for it was particularly required of the priests that they should put a difference between clean and unclean, and teach the people to do so. After the flood, when God entered into covenant with Noah and his sons, he allowed them to eat flesh (Gen 9:13), whereas be...', 'teologico');
add('lv', 11, 9, 'Matthew Henry', 'Here is, 1. A general rule concerning fishes, which were clean and which not. All that had fins and scales they might eat, and only those odd sorts of water-animals that have not were forbidden, Lev 11:9, Lev 11:10. The ancients accounted fish the most delicate food (so far were they from allowing it on fasting-days, or making it an instance of mortification to eat fish); therefore God did not lay much restraint upon his people in them; for he is a Master that allows his servants not only for...', 'teologico');
add('lv', 11, 20, 'Matthew Henry', 'Here is the law, 1. Concerning flying insects, as flies, wasps, bees, etc.; these they might not eat (Lev 11:20), nor indeed are they fit to be eaten; but there were several sorts of locusts which in those countries were very good meat, and much used: John Baptist lived upon them in the desert, and they are here allowed them, Lev 11:21, Lev 11:22. 2. Concerning the creeping things on the earth; these were all forbidden (Lev 11:29, Lev 11:30, and again, Lev 11:41, Lev 11:42); for it was the cu...', 'teologico');
add('lv', 11, 43, 'Matthew Henry', 'Here is, I. The exposition of this law, or a key to let us into the meaning of it. It was not intended merely for a bill of fare, or as the directions of a physician about their diet, but God would hereby teach them to sanctify themselves and to be holy, Lev 11:44. That is, 1. They must hereby learn to put a difference between good and evil, and to reckon that it could not be all alike what they did, when it was not all alike what they ate. 2. To maintain a constant observance of the divine l...', 'teologico');
add('lv', 12, 1, 'Matthew Henry', 'The law here pronounces women lying-in ceremonially unclean. The Jews say, "The law extended even to an abortion, if the child was so formed as that the sex was distinguishable." 1. There was some time of strict separation immediately after the birth, which continued seven days for a son and fourteen for a daughter, Lev 12:2, Lev 12:5. During these days she was separated from her husband and friends, and those that necessarily attended her were ceremonially unclean, which was one reason why t...', 'teologico');
add('lv', 12, 6, 'Matthew Henry', 'A woman that had lain in, when the time set for her return to the sanctuary had come, was not to attend there empty, but must bring her offerings, Lev 12:6. 1. A burnt-offering; a lamb if she was able, if poor, a pigeon. This she was to offer in thankfulness to God for his mercy to her, in bringing her safely through the pains of child-bearing and all the perils of child-bed, and in desire and hopes of God\'s further favour both to her and to the child. When a child is born there is joy and th...', 'teologico');
add('lv', 13, 1, 'Matthew Henry', 'I. Concerning the plague of leprosy we may observe in general, 1. That it was rather an uncleanness than a disease; or, at least, so the law considered it, and therefore employed not the physicians but the priests about it. Christ is said to cleanse lepers, not to cure them. We do not read of any that died of the leprosy, but it rather buried them alive, by rendering them unfit for conversation with any but such as were infected like themselves. Yet there is a tradition that Pharaoh, who soug...', 'teologico');
add('lv', 13, 18, 'Matthew Henry', 'The priest is here instructed what judgment to make if there was any appearance of a leprosy, either, 1. In an old ulcer, or bile, that has been healed, Lev 13:18, etc. When old sores, that seemed to be cured, break out again, it is to be feared there is a leprosy in them; such is the danger of those who, having escaped the pollutions of the world, are again entangled therein and overcome. Or, 2. In a burn by accident, for this seems to be meant, Lev 13:24, etc. The burning of strife and cont...', 'teologico');
add('lv', 13, 38, 'Matthew Henry', 'We have here,\nI. Provisos that neither a freckled skin nor a bald head should be mistaken for a leprosy, Lev 13:38-41. Every deformity must not forthwith be made a ceremonial defilement. Elisha was jeered for his bald head (Kg2 2:23); but it was the children of Bethel, that knew not the judgments of their God, who turned it to his reproach.\nII. A particular brand set upon the leprosy if at any time it did appear in a bald head: The plague is in his head, he is utterly unclean, Lev 13:44. If t...', 'teologico');
add('lv', 13, 47, 'Matthew Henry', 'This is the law concerning the plague of leprosy in a garment, whether linen or woollen. A leprosy in a garment, with discernible indications of it, the colour changed by it, the garment fretted, the nap worn off, and this in some one particular part of the garment, and increasing when it was shut up, and not to be got out by washing is a thing which to us now is altogether unaccountable. The learned confess that it was a sign and a miracle in Israel, an extraordinary punishment inflicted by ...', 'teologico');
add('lv', 14, 1, 'Matthew Henry', 'Here, I. It is supposed that the plague of the leprosy was not an incurable disease. Uzziah\'s indeed continued to the day of his death, and Gehazi\'s was entailed upon his seed; but Miriam\'s lasted only seven days: we may suppose that it often wore off in process of time. Though God contend long, he will not contend for ever.\nII. The judgment of the cure, as well as that of the disease, was referred to the priest. He must go out of the camp to the leper, to see whether his leprosy was healed, ...', 'teologico');
add('lv', 14, 10, 'Matthew Henry', 'Observe, I. To complete the purification of the leper, on the eighth day, after the former solemnity performed without the camp, and, as it should seem, before he returned to his own habitation, he was to attend at the door of the tabernacle, and was there to be presented to the Lord, with his offering, Lev 14:11. Observe here, 1. That the mercies of God oblige us to present ourselves to him, Rom 12:1. 2. When God has restored us to the liberty of ordinances again, after restraint by sickness...', 'teologico');
add('lv', 14, 21, 'Matthew Henry', 'We have here the gracious provision which the law made for the cleansing of poor lepers. If they were not able to bring three lambs, and three tenth-deals of flour, they must bring one lamb, and one tenth-deal of flour, and, instead of the other two lambs, two turtle-doves or two young pigeons, Lev 14:21, Lev 14:22. Here see, 1. That the poverty of the person concerned would not excuse him if he brought no offering at all. Let none think that because they are poor God requires no service from...', 'teologico');
add('lv', 14, 33, 'Matthew Henry', 'This is the law concerning the leprosy in a house. Now that they were in the wilderness they dwelt in tents, and had no houses, and therefore the law is made only an appendix to the former laws concerning the leprosy, because it related, not to their present state, but to their future settlement. The leprosy in a house is as unaccountable as the leprosy in a garment; but, if we see not what natural causes of it can be assigned, we may resolve it into the power of the God of nature, who here s...', 'teologico');
add('lv', 14, 54, 'Matthew Henry', 'This is the conclusion of this law concerning the leprosy. There is no repetition of it in Deuteronomy, only a general memorandum given (Deu 24:8), Take heed in the plague of leprosy. We may see in this law, 1. The gracious care God took of his people Israel, for to them only this law pertained, and not to the Gentiles. When Naaman the Syrian was cured of his leprosy he was not bidden to show himself to the priest, though he was cured in Jordan, as the Jews that were cured by our Saviour were...', 'teologico');
add('lv', 15, 1, 'Matthew Henry', 'We have here the law concerning the ceremonial uncleanness that was contracted by running issues in men. It is called in the margin (Lev 15:2) the running of the reins: a very grievous and loathsome disease, which was, usually the effect and consequent of wantonness and uncleanness, and a dissolute course of life, filling men\'s bones with the sins of their youth, and leaving them to mourn at the last, when all the pleasures of their wickedness have vanished, and nothing remains but the pain a...', 'teologico');
add('lv', 15, 19, 'Matthew Henry', 'This is concerning the ceremonial uncleanness which women lay under from their issues, both those that were regular and healthful, and according to the course of nature (Lev 15:19-24), and those that were unseasonable, excessive, and the disease of the body; such was the bloody issue of that poor woman who was suddenly cured by touching the hem of Christ\'s garment, after she had lain twelve years under her distemper, and had spent her estate upon physicians and physic in vain. This made the w...', 'teologico');
add('lv', 16, 1, 'Matthew Henry', 'Here is, I. The date of this law concerning the day of atonement: it was after the death of the two sons of Aaron (Lev 16:1), which we read, Lev 10:1. 1. Lest Aaron should fear that any remaining guilt of that sin should cleave to his family, or (seeing the priests were so apt to offend) that some after-sin of his other sons should be the ruin of his family, he is directed how to make atonement for his house, that it might keep in with God; for the atonement for it would be the establishment ...', 'teologico');
add('lv', 16, 5, 'Matthew Henry', 'The Jewish writers say that for seven days before the day of expiation the high priest was to retire from his own house, and to dwell in a chamber of the temple, that he might prepare himself for the service of this great day. During those seven days he himself did the work of the inferior priests about the sacrifices, incense, etc., that he might have his hand in for this day: he must have the institution read to him again and again, that he might be fully apprised of the whole method. 1. He...', 'teologico');
add('lv', 16, 15, 'Matthew Henry', 'When the priest had come out from the sprinkling the blood of the bullock before the mercy-seat, 1. He must next kill the goat which was the sin-offering for the people (Lev 16:15) and go the third time into the holy of holies, to sprinkle the blood of the goat, as he had done that of the bullock; and thus he was to make atonement for the holy place (Lev 16:16); that is, whereas the people by their sins had provoked God to take away those tokens of his favourable presence with them, and rende...', 'teologico');
add('lv', 16, 20, 'Matthew Henry', 'The high priest having presented unto the Lord the expiatory sacrifices, by the sprinkling of their blood, the remainder of which, it is probable, he poured out at the foot of the brazen altar, 1. He is next to confess the sins of Israel, with both his hands upon the head of the scape-goat (Lev 16:20, Lev 16:21); and whenever hands were imposed upon the head of any sacrifice it was always done with confession, according as the nature of the sacrifice was; and, this being a sin-offering, it mu...', 'teologico');
add('lv', 16, 29, 'Matthew Henry', 'I. We have here some additional directions in reference to this great solemnity, particularly,\n1. The day appointed for this solemnity. It must be observed yearly on the tenth day of the seventh month, Lev 16:29. The seventh had been reckoned the first month, till God appointed that the month in which the children of Israel came out of Egypt should thenceforward be accounted and called the first month. Some have fancied that this tenth day of the seventh month was the day of the year on which...', 'teologico');
add('lv', 17, 1, 'Matthew Henry', 'This statute obliged all the people of Israel to bring all their sacrifices to God\'s altar, to be offered there. And as to this matter we must consider,\nI. How it stood before. 1. It was allowed to all people to build altars, and offer sacrifices to God, where they pleased. Wherever Abraham had a tent he built an altar, and every master of a family was a priest to his own family, as Job 1:5. 2. This liberty had been an occasion of idolatry. When every man was his own priest, and had an altar ...', 'teologico');
add('lv', 17, 10, 'Matthew Henry', 'We have here, I. A repetition and confirmation of the law against eating blood. We have met with this prohibition twice before in the levitical law (Lev 3:17; Lev 7:26), besides the place it had in the precepts of Noah, Gen 9:4. But here, 1. The prohibition is repeated again and again, and reference had to the former laws to this purport (Lev 17:12): I said to the children of Israel, No soul of you shall eat blood; and again (Lev 17:14), You shall eat the blood of no manner of flesh. A great ...', 'teologico');
add('lv', 18, 1, 'Matthew Henry', 'After divers ceremonial institutions, God here returns to the enforcement of moral precepts. The former are still of use to us as types, the latter still binding as laws. We have here, 1. The sacred authority by which these laws are enacted: I am the Lord your God (Lev 18:1, Lev 18:4, Lev 18:30), and I am the Lord, Lev 18:5, Lev 18:6, Lev 18:21. "The Lord, who has a right to rule all; your God, who has a peculiar right to rule you." Jehovah is the fountain of being, and therefore the fountain...', 'teologico');
add('lv', 18, 6, 'Matthew Henry', 'These laws relate to the seventh commandment, and, no doubt, are obligatory on us under the gospel, for they are consonant to the very light and law of nature: one of the articles, that of a man\'s having his father\'s wife, the apostle speaks of as a sin not so much as named among the Gentiles, Co1 5:1. Though some of the incests here forbidden were practised by some particular persons among the heathen, yet they were disallowed and detested, unless among those nations who had become barbarous...', 'teologico');
add('lv', 18, 19, 'Matthew Henry', 'Here is, I. A law to preserve the honour of the marriage-bed, that it should not be unseasonably used (Lev 18:19), nor invaded by an adulterer, Lev 18:20.\nII. A law against that which was the most unnatural idolatry, causing their children to pass through the fire to Moloch, Lev 18:21. Moloch (as some think) was the idol in and by which they worshipped the sun, that great fire of the world; and therefore in the worship of it they made their own children either sacrifices to this idol, burning...', 'teologico');
add('lv', 19, 1, 'Matthew Henry', 'Moses is ordered to deliver the summary of the laws to all the congregation of the children of Israel (Lev 19:2); not to Aaron and his sons only, but to all the people, for they were all concerned to know their duty. Even in the darker ages of the law, that religion could not be of God which boasted of ignorance as its mother. Moses must make known God\'s statutes to all the congregation, and proclaim them through the camp. These laws, it is probable, he delivered himself to as many of the peo...', 'teologico');
add('lv', 19, 11, 'Matthew Henry', 'We are taught here,\nI. To be honest and true in all our dealings, Lev 19:11. God, who has appointed every man\'s property by his providence, forbids by his law the invading of that appointment, either by downright theft, You shall not steal, or by fraudulent dealing, "You shall not cheat, or deal falsely." Whatever we have in the world, we must see to it that it be honestly come by, for we cannot be truly rich, nor long rich, with that which is not. The God of truth, who requires truth in the ...', 'teologico');
add('lv', 19, 19, 'Matthew Henry', 'Here is, I. A law against mixtures, Lev 19:19. God in the beginning made the cattle after their kind (Gen 1:25), and we must acquiesce in the order of nature God hath established, believing that is best and sufficient, and not covet monsters. Add thou not unto his works, lest he reprove thee; for it is the excellency of the work of God that nothing can, without making it worse, be either put to it or taken from it, Ecc 3:14. As what God has joined we must not separate, so what he has separate...', 'teologico');
add('lv', 19, 30, 'Matthew Henry', 'Here is, I. A law for the preserving of the honour of the time and place appropriated to the service of God, Lev 19:30. This would be a means to secure them both from the idolatries and superstitions of the heathen and from all immoralities in conversation. 1. Sabbaths must be religiously observed, and not those times mentioned (Lev 19:26) to which the heathen had a superstitious regard. 2. The sanctuary must be reverenced: great care must be taken to approach the tabernacle with that purity ...', 'teologico');
add('lv', 20, 1, 'Matthew Henry', 'Moses is here directed to say that again to the children of Israel which he had in effect said before, Lev 20:2. We are sure it was no vain repetition, but very necessary, that they might give the more earnest heed to the things that were spoken, and might believe them to be of great consequence, being so often inculcated. God speaketh once, yea, twice, and what he orders to be said again we must be willing to hear again, because for us it is safe, Phi 3:1.\nI. Three sins are in these verses t...', 'teologico');
add('lv', 20, 10, 'Matthew Henry', 'Sins against the seventh commandment are here ordered to be severely punished. These are sins which, of all others, fools are most apt to make a mock at; but God would teach those the heinousness of the guilt by the extremity of the punishment that would not otherwise be taught it.\nI. Lying with another man\'s wife was made a capital crime. The adulterer and the adulteress that had joined in the sin must fall alike under the sentence: they shall both be put to death, Lev 20:10. Long before thi...', 'teologico');
add('lv', 20, 22, 'Matthew Henry', 'The last verse is a particular law, which comes in after the general conclusion, as if omitted in its proper place: it is for the putting of those to death that dealt with familiar spirits, Lev 20:27. It would be an affront to God and to his lively oracles, a scandal to the country, and a temptation to ignorant bad people, to consult them, if such were known and suffered to live among them. Those that are in league with the devil have in effect made a covenant with death and an agreement with...', 'teologico');
add('lv', 21, 1, 'Matthew Henry', 'It was before appointed that the priests should teach the people the statutes God had given concerning the difference between clean and unclean, Lev 10:10, Lev 10:11. Now here it is provided that they should themselves observe what they were to teach the people. Note, Those whose office it is to instruct must do it by example as well as precept, Ti1 4:12. The priests were to draw nearer to God than any of the people, and to be more intimately conversant with sacred things, and therefore it wa...', 'teologico');
add('lv', 21, 10, 'Matthew Henry', 'More was expected from a priest than from other people, but more from the high priest than from other priests, because upon his head the anointing oil was poured, and he was consecrated to put on the garments (Lev 21:10), both which were typical of the anointing and adorning of the Lord Jesus, with all the gifts and graces of the Holy Spirit, which he received without measure. It is called the crown of the anointing oil of his God (Lev 21:12); for the anointing of the Spirit is, to all that h...', 'teologico');
add('lv', 21, 16, 'Matthew Henry', 'The priesthood being confined to one particular family, and entailed upon all the male issue of that family throughout their generations, it was very likely that some or other in after-ages that were born to the priesthood would have natural blemishes and deformities: the honour of the priesthood would not secure them from any of those calamities which are common to men. Divers blemishes are here specified; some that were ordinarily for life, as blindness; others that might be for a time, as ...', 'teologico');
add('lv', 22, 1, 'Matthew Henry', 'Those that had a natural blemish, though they were forbidden to do the priests\' work, were yet allowed to eat of the holy things: and the Jewish writers say that "to keep them from idleness they were employed in the wood-room, to pick out that which was worm-eaten, that it might not be used in the fire upon the altar; they might also be employed in the judgment of leprosy:" but,\nI. Those that were under any ceremonial uncleanness, which possibly they contracted by their own fault, might no so...', 'teologico');
add('lv', 22, 10, 'Matthew Henry', 'The holy things were to be eaten by the priests and their families. Now,\nI. Here is a law that no stranger should eat of them, that is, no person whatsoever but the priests only, and those that pertained to them, Lev 22:10. The priests are charged with this care, not to profane the holy things by permitting the strangers to eat of them (Lev 22:15) or suffer them to bear the iniquity of trespass (Lev 22:16); that is, suffer them to bring guilt upon themselves, by meddling with that which they ...', 'teologico');
add('lv', 22, 17, 'Matthew Henry', 'Here are four laws concerning sacrifices: - \nI. Whatever was offered in sacrifice to God should be without blemish, otherwise it should not be accepted. This had often been mentioned in the particular institutions of the several sorts of offerings. Now here they are told what was to be accounted a blemish which rendered a beast unfit for sacrifice: if it was blind, or lame, had a wen, or the mange (Lev 22:22), - if it was bruised, or crushed, or broken, or cut (Lev 22:24), that is, as the Jew...', 'teologico');
add('lv', 23, 1, 'Matthew Henry', 'Here is, I. A general account of the holy times which God appointed (Lev 23:2), and it is only his appointment that can make time holy; for he is the Lord of time, and as soon as ever he had set its wheels a-going it was he that sanctified and blessed one day above the rest, Gen 2:3. Man may by his appointment make a good day (Est 9:19), but it is God\'s prerogative to make a holy day; nor is any thing sanctified but by the stamp of his institution. As all inherent holiness comes from his spec...', 'teologico');
add('lv', 23, 4, 'Matthew Henry', 'Here again the feasts are called the feasts of the Lord, because he appointed them. Jeroboam\'s feast, which he devised of his own heart (Kg1 12:33), was an affront to God, and a reproach upon the people. These feasts were to be proclaimed in their seasons (Lev 23:4), and the seasons God chose for them were in March, May and September (according to our present computation), not in winter, because travelling would then be uncomfortable, when the days were short, and the ways foul; not in the mi...', 'teologico');
add('lv', 23, 15, 'Matthew Henry', 'Here is the institution of the feast of pentecost, or weeks, as it is called (Deu 16:9), because it was observed fifty days, or seven weeks, after the passover. It is also called the feast of harvest, Exo 23:16. For as the presenting of the sheaf of first-fruits was an introduction to the harvest, and gave them liberty to put in the sickle, so they solemnized the finishing of their corn-harvest at this feast. 1. Then they offered a handful of ears of barley, now they offered two loaves of whe...', 'teologico');
add('lv', 23, 23, 'Matthew Henry', 'Here is, I. The institution of the feast of trumpets, on the first day of the seventh month, Lev 23:24, Lev 23:25. That which was now the seventh month had been reckoned the first month, and the year of jubilee was still to begin with this month (Lev 25:8), so that this was their new year\'s day. It was to be as their other yearly sabbaths, a day of holy rest - You shall do no servile work therein; and a day of holy work - You shall offer an offering to the Lord; concerning these particular di...', 'teologico');
add('lv', 23, 33, 'Matthew Henry', 'We have here, I. The institution of the feast of tabernacles, which was one of the three great feasts at which all the males were bound to attend, and celebrated with more expressions of joy than any of them.\n1. As to the directions for regulating this feast, observe, (1.) It was to be observed on the fifteenth day of the seventh month (Lev 23:34), but five days after the day of atonement. We may suppose, though they were not all bound to attend on the day of atonement, as on the three great ...', 'teologico');
add('lv', 24, 1, 'Matthew Henry', 'Care is here taken, and orders are given, for the decent furnishing of the candlestick and table in God\'s house.\nI. The lamps must always be kept burning. The law for this we had before, Exo 27:20, Exo 27:21. It is here repeated, probably because it now began to be put in execution, when other things were settled. 1. The people were to provide oil (Lev 24:2), and this, as every thing else that was to be used in God\'s service, must be of the best, pure olive-oil, beaten, probably it was double...', 'teologico');
add('lv', 24, 10, 'Matthew Henry', 'Evil manners, we say, beget good laws. We have here an account of the evil manners of a certain nameless mongrel Israelite, and the good laws occasioned thereby.\nI. The offender was the son of an Egyptian father and an Israelitish mother (Lev 24:10); his mother was of the tribe of Dan, Lev 24:11. Neither he nor his father is named, but his mother only, who was an Israelite. This notice is taken of his parentage either, 1. To intimate what occasioned the quarrel he was engaged in. The Jews say...', 'teologico');
add('lv', 25, 1, 'Matthew Henry', 'The law of Moses laid a great deal of stress upon the sabbath, the sanctification of which was the earliest and most ancient of all divine institutions, designed for the keeping up of the knowledge and worship of the Creator among men; that law not only revived the observance of the weekly sabbath, but, for the further advancement of the honour of them, added the institution of a sabbatical year: In the seventh year shall be a sabbath of rest unto the land, Lev 25:4. And hence the Jews collec...', 'teologico');
add('lv', 25, 8, 'Matthew Henry', 'Here is, I. The general institution of the jubilee, Lev 25:8. etc.\n1. When it was to be observed: after seven sabbaths of years (Lev 25:8), whether the forty-ninth or fiftieth is a great question among learned men: that it should be the seventh sabbatical year, that is, the forty-ninth (which by a very common form of speech is called the fiftieth), seems to me most probable, and is, I think, made pretty clear and the objections removed by that learned chronologer Calvisius; but this is not a ...', 'teologico');
add('lv', 25, 23, 'Matthew Henry', 'Here is, I. A law concerning the real estates of the Israelites in the land of Canaan, and the transferring of them. 1. No land should be sold for ever from the family to whose lot it fell in the division of the land. And the reason given is, The land is mine, and you are strangers and sojourners with me, Lev 25:23. (1.) God having a particular propriety in this land, he would by this restraint keep them sensible of it. The possessions of good people, who, having given up themselves to God, h...', 'teologico');
add('lv', 25, 39, 'Matthew Henry', 'We have here the laws concerning servitude, designed to preserve the honour of the Jewish nation as a free people, and rescued by a divine power out of the house of bondage, into the glorious liberty of God\'s sons, his first-born. Now the law is,\nI. That a native Israelite should never be made a bondman for perpetuity. If he was sold for debt, or for a crime, by the house of judgment, he was to serve but six years, and to go out the seventh; this was appointed, Exo 21:2. But if he sold himsel...', 'teologico');
add('lv', 26, 1, 'Matthew Henry', 'Here is, I. The inculcating of those precepts of the law which were of the greatest consequence, and by which were of the greatest consequence, and by which especially their obedience would be tried, Lev 26:1, Lev 26:2. They are the abstract of the second and fourth commandments, which, as they are by much the largest in the decalogue, so they are most frequently insisted on in other parts of the law. As, when a master has given many things in charge to his servant, he concludes with the repe...', 'teologico');
add('lv', 26, 14, 'Matthew Henry', 'After God had set the blessing before them (the life and good which would make them a happy people if they would be obedient), he here sets the curse before them, the death and evil which would make them as miserable if they were disobedient. Let them not think themselves so deeply rooted as that God\'s power could not ruin them, nor so highly favoured as that his justice would not ruin them if they revolted from him and rebelled against him; no You only have I known, therefore I will punish y...', 'teologico');
add('lv', 26, 40, 'Matthew Henry', 'Here the chapter concludes with gracious promises of the return of God\'s favour to them upon their repentance, that they might not (unless it were their own fault) pine away in their iniquity. Behold, with wonder, the riches of God\'s mercy to a people that had obstinately stood it out against the judgments of God, and would never think of surrendering till they were reduced to the last extremity. Yet turn to strong-hold, you prisoners of hope, Zac 9:12. As bad as things are, they may be mende...', 'teologico');
add('lv', 27, 1, 'Matthew Henry', 'This is part of the law concerning singular vows, extraordinary ones, which though God did not expressly insist on, yet, if they were consistent with and conformable to the general precepts, he would be well pleased with. Note, We should not only ask, What must we do, but, What may we do, for the glory and honour of God? As the liberal devises liberal things (Isa 32:8), so the pious devises pious things, and the enlarged heart would willingly do something extraordinary in the service of so go...', 'teologico');
add('lv', 27, 14, 'Matthew Henry', 'Here is the law concerning real estates dedicated to the service of God by a singular vow.\nI. Suppose a man, in his zeal for the honour of God, should sanctify his house to God (Lev 27:14), the house must be valued by the priest, and the money got by the sale of it was to be converted to the use of the sanctuary, which by degrees came to be greatly enriched with dedicated things, Kg1 15:15. But, if the owner be inclined to redeem it himself, he must not have it so cheap as another, but must a...', 'teologico');
add('lv', 27, 26, 'Matthew Henry', 'Here is, I. A caution given that no man should make such a jest of sanctifying things to the Lord as to sanctify any firstling to him, for that was his already by the law, Lev 27:26. Though the matter of a general vow be that which we were before obliged to, as of our sacramental covenant, yet a singular vow should be of that which we were not, in such circumstances and proportions, antecedently bound to. The law concerning the firstlings of unclean beasts (Lev 27:27) is the same with that be...', 'teologico');

// NM (97 comentários)
add('nm', 6, 24, 'Matthew Henry', 'O Senhor te abençoe — A bênção sacerdotal: graça, proteção e paz fluem da face de Deus voltada para o povo.', 'cultural');
add('nm', 14, 18, 'Spurgeon', 'O Senhor é longânimo — A paciência de Deus não é fraqueza, mas espaço para arrependimento.', 'teologico');
add('nm', 21, 8, 'Calvino', 'A serpente de bronze — Tipologia exata de Cristo crucificado: olhar e viver pela fé.', 'teologico');
add('nm', 24, 17, 'Irineu', 'Surgirá de Jacó uma estrela — Profecia messiânica da estrela de Jacó cumprida em Cristo.', 'escatologico');
add('nm', 1, 1, 'Matthew Henry', 'I. We have here a commission issued out for the numbering of the people of Israel; and David, long after, paid dearly for doing it without a commission. Here is,\n1. The date of this commission, Num 1:1. (1.) The place: it is given at God\'s court in the wilderness of Sinai, from his royal palace, the tabernacle of the congregation. (2.) The time: In the second year after they came up out of Egypt; we may call it the second year of that reign. The laws in Leviticus were given in the first month...', 'teologico');
add('nm', 1, 17, 'Matthew Henry', 'We have here the speedy execution of the orders given for the numbering of the people. It was begun the same day that the orders were given, The first day of the second month; compare Num 1:18 with Num 1:1. Note, When any work is to be done for God it is good to set about it quickly, while the sense of duty is strong and pressing. And, for aught that appears, it was but one day\'s work, for many other things were done between this and the twentieth day of this month, when they removed their ca...', 'teologico');
add('nm', 1, 44, 'Matthew Henry', 'We have here the sum total at the foot of the account; they were in all 600,000 fighting men, and 3550 over. Some think that when this was their number some months before (Exo 38:26) the Levites were reckoned with them, but now that tribe was separated for the service of God, yet so many more had by this time attained to the age of twenty years as that still they were the same number, to show that whatever we part with for the honour and service of God it shall certainly be made up to us one ...', 'teologico');
add('nm', 1, 47, 'Matthew Henry', 'Care is here taken to distinguish from the rest of the tribes the tribe of Levi, which, in the matter of the golden calf, had distinguished itself, Exo 32:26. Note, Singular services shall be recompensed with singular honours. Now,\nI. It was the honour of the Levites that they were made guardians of the spiritualities; to them was committed the care of the tabernacle and the treasures thereof, both in their camps and in their marches. 1. When they moved the Levites were to take down the taber...', 'teologico');
add('nm', 2, 1, 'Matthew Henry', 'Here is the general appointment given both for their orderly encampment where they rested and their orderly march when they moved. Some order, it is possible, they had observed hitherto; they came out of Egypt in rank and file (Exo 13:18), but now they were put into a better model. 1. They all dwelt in tents, and when they marched carried all their tents along with them, for they found no city to dwell in, Psa 107:4. This represents to us our state in this world. It is a movable state (we are...', 'teologico');
add('nm', 2, 3, 'Matthew Henry', 'We have here the particular distribution of the twelve tribes into four squadrons, three tribes in a squadron, one of which was to lead the other two. Observe, 1. God himself appointed them their place, to prevent strife and envy among them. Had they been left to determine precedency among themselves, they would have been in danger of quarrelling with one another (as the disciples who strove which should be greatest); each would have had a pretence to be first, or at least not to be last. Had...', 'teologico');
add('nm', 3, 1, 'Matthew Henry', 'Here, I. The family of Aaron is confirmed in the priests\' office, Num 3:10. They had been called to it before, and consecrated; here they are appointed to wait on their priests\' office: the apostle uses this phrase (Rom 12:7), Let us wait on our ministry. The office of the ministry requires a constant attendance and great diligence; so frequent are the returns of its work, and yet so transient its favourable opportunities, that it must be waited on. Here is repeated what was said before (Num ...', 'teologico');
add('nm', 3, 14, 'Matthew Henry', 'The Levites being granted to Aaron to minister to him, they are here delivered to him by tale, that he might know what he had, and employ them accordingly. Observe,\nI. By what rule they were numbered: Every male from a month old and upward, Num 3:15. The rest of the tribes were numbered only from twenty years old and upwards, and of them those only that were able to go forth to war; but into the number of the Levites they must take in both infants, and infirm; being exempted from the war, it ...', 'teologico');
add('nm', 3, 40, 'Matthew Henry', 'Here is the exchange made of the Levites for the first-born. 1. The first-born were numbered from a month old, Num 3:42, Num 3:43. Those certainly were not reckoned who, though first-born, had become heads of families themselves, but those only that were under age; and the learned bishop Patrick is decidedly of opinion that none were numbered but those only that were born since their coming out of Egypt, when the first-born were sanctified, Exo 13:2. If there were 22,000 first-born males, we ...', 'teologico');
add('nm', 4, 1, 'Matthew Henry', 'We have here a second muster of the tribe of Levi. As that tribe was taken out of all Israel to be God\'s peculiar, so the middle-aged men of that tribe were taken from among the rest to be actually employed in the service of the tabernacle. Now observe,\nI. Who were to be taken into this number. All the males from thirty years old to fifty. Of the other tribes, those that were numbered to go forth to war were from twenty years old and upward, but of the Levites only from thirty to fifty; for t...', 'teologico');
add('nm', 4, 21, 'Matthew Henry', 'We have here the charge of the other two families of the Levites, which, though not so honourable as the first, yet was necessary, and was to be done regularly. 1. The Gershonites were charged with all the drapery of the tabernacle, the curtains, and hangings, and the coverings of badgers\' skins, Num 4:22-26. These they were to take down when the cloud removed, and the ark and the rest of the holy things were carried away, to pack up and bring with them, and then to set up again, where the cl...', 'teologico');
add('nm', 4, 34, 'Matthew Henry', 'We have here a particular account of the numbers of the three families of the Levites respectively, that is, of the effective men, between thirty years old and fifty. Observe, 1. The Kohathites were, in all, 8600 from a month old and upwards; but of these there were but 2750 serviceable men, not a third part. The Gershonites, in all, 7500, and of them but 2630 serviceable men, little more than a third part. Note, Of the many that add to the numbers of the church, there are comparatively but f...', 'teologico');
add('nm', 5, 1, 'Matthew Henry', 'Here is, I. A command for the purifying of the camp, by turning out from within its lines all those that were ceremonially unclean, by issues, leprosies, or the touch of dead bodies, until they were cleansed according to the law, Num 5:2, Num 5:3.\n1. These orders are executed immediately, Num 5:4. (1.) The camp was now newly-modelled and put in order, and therefore, to complete the reformation of it, it is next to be cleansed. Note, The purity of the church must be as carefully consulted and ...', 'teologico');
add('nm', 5, 11, 'Matthew Henry', 'We have here the law concerning the solemn trial of a wife whose husband was jealous of her. Observe,\nI. What was the case supposed: That a man had some reason to suspect his wife to have committed adultery, Num 5:12-14. Here, 1. The sin of adultery is justly represented as an exceedingly sinful sin; it is going aside from God and virtue, and the good way, Pro 2:17. It is committing a trespass against the husband, robbing him of his honour, alienating his right, introducing a spurious breed i...', 'teologico');
add('nm', 6, 1, 'Matthew Henry', 'After the law for the discovery and shame of those that by sin had made themselves vile, fitly follows this for the direction and encouragement of those who by their eminent piety and devotion had made themselves honourable, and distinguished themselves from their neighbours. It is very probable that there were those before the making of this law who went under the character of Nazarites, and were celebrated by that title as persons professing greater strictness and zeal in religion than othe...', 'teologico');
add('nm', 6, 22, 'Matthew Henry', 'Here, I. The priests, among other good offices which they were to do, are appointed solemnly to bless the people in the name of the Lord, Num 6:23. It was part of their work, Deu 21:5. Hereby God put an honour upon the priests, for the less is blessed of the better; and hereby he gave great comfort and satisfaction to the people, who looked upon the priest as God\'s mouth to them. Though the priests of himself could do no more than beg a blessing, yet being an intercessor by office, and doing ...', 'teologico');
add('nm', 7, 1, 'Matthew Henry', 'Here is the offering of the princes to the service of the tabernacle. Observe,\nI. When it was; not till it was fully set up, Num 7:1. When all things were done both about the tabernacle itself, and the camp of Israel which surrounded it, according to the directions given, then they began their presents, probably about the eighth day of the second month. Note, Necessary observances must always take place of free-will offerings: first those, and then these.\nII. Who it was that offered: The prin...', 'teologico');
add('nm', 7, 10, 'Matthew Henry', 'We have here an account of the great solemnity of dedicating the altars, both that of burnt-offerings and that of incense; they had been sanctified before, when they were anointed (Lev 8:10, Lev 8:11), but now they were handselled, as it were, by the princes, with their free-will offerings. They began the use of them with rich presents, great expressions of joy and gladness, and extraordinary respect to those tokens of God\'s presence with them. Now observe here,\nI. That the princes and great ...', 'teologico');
add('nm', 8, 1, 'Matthew Henry', 'Directions were given long before this for the making of the golden candlestick (Exo 25:31), and it was made according to the pattern shown to Moses in the mount, Exo 38:17. But now it was that the lamps were first ordered to be lighted, when other things began to be used. Observe, 1. Who must light the lamps; Aaron himself, he lighted the lamps, Num 8:3. As the people\'s representative to God, he thus did the office of a servant in God\'s house, lighting his Master\'s candle; as the representat...', 'teologico');
add('nm', 8, 5, 'Matthew Henry', 'We read before of the separating of the Levites from among the children of Israel when they were numbered, and the numbering of them by themselves (Num 3:6, Num 3:15), that they might be employed in the service of the tabernacle. Now here we have directions given for their solemn ordination (Num 8:6), and the performance of it, Num 8:20. All Israel must know that they took not this honour to themselves, but were called of God to it; nor was it enough that they were distinguished from their ne...', 'teologico');
add('nm', 9, 1, 'Matthew Henry', 'Here we have,\nI. An order given for the solemnization of the passover, the day twelvemonth after they came out of Egypt, on the fourteenth day of the first month of the second year, some days before they were numbered, for that was done in the beginning of the second month. Observe, 1. God gave particular orders for the keeping of this passover, otherwise (it should seem) they would not have kept it, for, in the first institution of this ordinance, it was appointed to be kept when they should...', 'teologico');
add('nm', 9, 15, 'Matthew Henry', 'We have here the history of the cloud; not a natural history: who knows the balancings of the clouds? but a divine history of a cloud that was appointed to be the visible sign and symbol of God\'s presence with Israel.\nI. When the tabernacle was finished this cloud, which before had hung on high over their camp, settled upon the tabernacle, and covered it, to show that God manifests his presence with his people in and by his ordinances; there he makes himself known, and to them we must look if...', 'teologico');
add('nm', 10, 1, 'Matthew Henry', 'We have here directions concerning the public notices that were to be given to the people upon several occasions by sound of trumpet. In a thing of this nature, one would think, Moses needed not to have been taught of God: his own reason might teach him the conveniency of trumpets; but the constitution of Israel was to be in every thing divine, and therefore even in this matter, small as it seems. Moses is here directed, 1. About the making of them. They must be made of silver; not cast but o...', 'teologico');
add('nm', 10, 11, 'Matthew Henry', 'Here is, I. A general account of the removal of the camp of Israel from mount Sinai, before which mountain it had lain now about a year, in which time and place a great deal of memorable business was done. Of this removal, it should seem, God gave them notice some time before (Deu 1:6, Deu 1:7): You have dwelt long enough in this mountain, turn you and take your journey towards the land of promise. The apostle tells us that mount Sinai genders to bondage (Gal 4:24), and signifies the law ther...', 'teologico');
add('nm', 10, 29, 'Matthew Henry', 'Here is, I. An account of what passed between Moses and Hobab, now upon this advance which the camp of Israel made towards Canaan. Some think that Hobab was the same with Jethro, Moses\'s father-in-law, and that the story, Ex. 18, should come in here; it seems more probable that Hobab was the son of Jethro, alias Reuel, or Raguel (Exo 2:18), and that when the father, being aged, went to his own land (Exo 18:27), he left his son Hobab with Moses, as Barzillai left Chimham with David; and the sa...', 'teologico');
add('nm', 11, 1, 'Matthew Henry', 'Here is, I. The people\'s sin. They complained, Num 11:1. They were, as it were, complainers. So it is in the margin. There were some secret grudgings and discontents among them, which as yet did not break out in an open mutiny. But how great a matter did this little fire kindle! They had received from God excellent laws and ordinances, and yet no sooner had they departed from the mount of the Lord than they began to quarrel with God himself. See in this, 1. The sinfulness of sin, which takes ...', 'teologico');
add('nm', 11, 4, 'Matthew Henry', 'These verses represent things sadly unhinged and out of order in Israel, both the people and the prince uneasy.\nI. Here is the people fretting, and speaking against God himself (as it is interpreted, Psa 78:19), notwithstanding his glorious appearances both to them and for them. Observe,\n1. Who were the criminals. (1.) The mixed multitude began, they fell a lusting, Num 11:4. The rabble that came with them out of Egypt, expecting only the land of promise, but not a state of probation in the w...', 'teologico');
add('nm', 11, 16, 'Matthew Henry', 'We have here God\'s gracious answer to both the foregoing complaints, wherein his goodness takes occasion from man\'s badness to appear so much the more illustrious.\nI. Provision is made for the redress of the grievances Moses complains of. If he find the weight of government lie too heavy upon him, though he was a little too passionate in his remonstrance, yet he shall be eased, not by being discarded from the government himself, as he justly might have been if God had been extreme to mark wha...', 'teologico');
add('nm', 11, 24, 'Matthew Henry', 'We have here the performance of God\'s word to Moses, that he should have help in the government of Israel.\nI. Here is the case of the seventy privy-counsellors in general. Moses, though a little disturbed by the tumult of the people, yet was thoroughly composed by the communion he had with God, and soon came to himself again. And according as the matter was concerted, 1. He did his part; he presented the seventy elders before the Lord, round the tabernacle (Num 11:24), that they might there s...', 'teologico');
add('nm', 11, 31, 'Matthew Henry', 'God, having performed his promise to Moses by giving him assessors in the government, thereby proving the power he has over the spirits of men by his Spirit, he here performs his promise to the people by giving them flesh, proving thereby his power over the inferior creatures and his dominion in the kingdom of nature. Observe, 1. How the people were gratified with flesh in abundance: A wind (a south-east wind, as appears, Psa 78:26) brought quails, Num 11:31. It is uncertain what sort of anim...', 'teologico');
add('nm', 12, 1, 'Matthew Henry', 'Here is, I. The unbecoming passion of Aaron and Miriam: they spoke against Moses, Num 12:1. If Moses, that received so much honour from God, yet received so many slights and affronts from men, shall any of us think such trials either strange or hard, and be either provoked or discouraged by them? But who would have thought that disturbance should be created to Moses, 1. From those that were themselves serious and good; nay, that were eminent in religion, Miriam a prophetess, Aaron the high pr...', 'teologico');
add('nm', 12, 4, 'Matthew Henry', 'Moses did not resent the injury done him, nor complain of it to God, nor make any appeal to him; but God resented it. He hears all we say in our passion, and is a swift witness of our hasty speeches, which is a reason why we should resolutely bridle our tongues, that we speak not ill of others, and why we should patiently stop our ears, and not take notice of it, if others speak ill of us. I heard not, for thou wilt hear, Psa 38:13-15. The more silent we are in our own cause the more is God e...', 'teologico');
add('nm', 12, 10, 'Matthew Henry', 'Here is, I. God\'s judgment upon Miriam (Num 12:10): The cloud departed from off that part of the tabernacle, in token of God\'s displeasure, and presently Miriam became leprous; when God goes, evil comes; expect no good when God departs. The leprosy was a disease often inflicted by the immediate hand of God as the punishment of some particular sin, as on Gehazi for lying, on Uzziah for invading the priest\'s office, and here on Miriam for scolding and making mischief among relations. The plague...', 'teologico');
add('nm', 13, 1, 'Matthew Henry', 'Here we have, I. Orders given to send spies to search out the land of Canaan. It is here said, God directed Moses to send them (Num 13:1, Num 13:2), but it appears by the repetition of the story afterwards (Deu 1:22) that the motion came originally from the people; they came to Moses, and said, We will send men before us; and it was the fruit of their unbelief. They would not take God\'s word that it was a good land, and that he would, without fail, put them in possession of it. They could not...', 'teologico');
add('nm', 13, 21, 'Matthew Henry', 'We have here a short account of the survey which the spies made of the promised land. 1. They went quite through it, from Zin in the south, to Rehob, near Hamath, in the north, Num 13:21. See Num 34:3, Num 34:8. It is probable that they did not go altogether in a body, lest they should be suspected and taken up, which there would be the more danger of if the Canaanites knew (and one would think they could not but know) how near the Israelites were to them; but they divided themselves into sev...', 'teologico');
add('nm', 13, 26, 'Matthew Henry', 'It is a wonder how the people of Israel had patience to stay forty days for the return of their spies, when they were just ready to enter Canaan, under all the assurances of success they could have from the divine power, and a constant series of miracles that had hitherto attended them; but they distrusted God\'s power and promise, and were willing to be held in suspense by their own counsels, rather than be brought to a certainty by God\'s covenant. How much do we stand in our own light by our...', 'teologico');
add('nm', 14, 1, 'Matthew Henry', 'Here we see what mischief the evil spies made by their unfair representation. We may suppose that these twelve that were impanelled to enquire concerning Canaan had talked it over among themselves before they brought in their report in public; and Caleb and Joshua, it is likely, had done their utmost to bring the rest over to be of their mind, and if they would but have agreed that Caleb, according to his pose, should have spoken for them all, as their foreman, all had been well; but the evil...', 'teologico');
add('nm', 14, 5, 'Matthew Henry', 'The friends of Israel here interpose to save them if possible from ruining themselves, but in vain. The physicians of their state would have healed them, but they would not be healed; their watchmen gave them warning, but they would not take warning, and so their blood is upon their own heads.\nI. The best endeavours were used to still the tumult, and, if now at last they would have understood the things that belonged to their peace, all the following mischief would have been prevented.\n1. Mos...', 'teologico');
add('nm', 14, 11, 'Matthew Henry', 'Here is, I. The righteous sentence which God gave against Israel for their murmuring and unbelief, which, though afterwards mitigated, showed what was the desert of their sin and the demand of injured justice, and what would have been done if Moses had not interposed. When the glory of the Lord appeared in the tabernacle we may suppose that Moses took it for a call to him immediately to come and attend there, as before the tabernacle was erected he went up to the mount in a similar case, Exo ...', 'teologico');
add('nm', 14, 20, 'Matthew Henry', 'We have here God\'s answer to the prayer of Moses, which sings both of mercy and judgment. It is given privately to Moses (Num 14:20-25), and then directed to be made public to the people, Num 14:26-35. The frequent repetitions of the same things in it speak these resolves to be unalterable. Let us see the particulars.\nI. The extremity of the sentence is receded from (Num 14:20): "I have pardoned, so as not to cut them all off at once, and disinherit them." See the power of prayer, and the del...', 'teologico');
add('nm', 14, 36, 'Matthew Henry', 'Here is, I. The sudden death of the ten evil spies. While the sentence was passing upon the people, before it was published, they died of the plague before the Lord, Num 14:36, Num 14:37. Now,\n1. God hereby showed his particular displeasure against those who sinned and made Israel to sin. (1.) They sinned themselves, in bringing up a slander upon the land of promise. Note, Those greatly provoke God who misrepresent religion, cast reproach upon it, and raise prejudices in men\'s minds against i...', 'teologico');
add('nm', 15, 1, 'Matthew Henry', 'Here we have,\nI. Full instructions given concerning the meat-offerings and drink-offerings, which were appendages to all the sacrifices of animals. The beginning of this law is very encouraging: When you come into the land of your habitation which I give unto you, they you shall do so and so, Num 15:2. This was a plain intimation, not only that God was reconciled to them notwithstanding the sentence he had passed upon them, but that he would secure the promised land to their seed notwithstand...', 'teologico');
add('nm', 15, 22, 'Matthew Henry', 'We have here the laws concerning sacrifices for sins of ignorance; the Jews understand it of idolatry, or false worship, through the error of their teachers. The case here supposed is that they had not observed all these commandments, Num 15:22, Num 15:23. If they had failed in the offerings of their acknowledgment, and had not brought them according to the law, then they must bring an offering of atonement, yea, though the omission had been through forgetfulness or mistake. If they failed in...', 'teologico');
add('nm', 15, 30, 'Matthew Henry', 'Here is, I. The general doom passed upon presumptuous sinners. 1. Those are to be reckoned presumptuous sinners that sin with a high hand, as the original phrase is (Num 15:30), that is, that avowedly confront God\'s authority, and set up their own lust in competition with it, that sin for sinning-sake, in contradiction to the precept of the law, and in defiance of the penalty, that fight against God, and dare him to do his worst; see Job 15:25. It is not only to sin against knowledge, but to ...', 'teologico');
add('nm', 15, 37, 'Matthew Henry', 'Provision had been just now made by the law for the pardon of sins of ignorance and infirmity; now here is an expedient provided for the preventing of such sins. They are ordered to make fringes upon the borders of their garments, which were to be memorandums to them of their duty, that they might not sin through forgetfulness. 1. The sign appointed is a fringe of silk, or thread, or worsted, or the garment itself ravelled at the bottom, and a blue riband bound on the top of it to keep it tig...', 'teologico');
add('nm', 16, 1, 'Matthew Henry', 'Here is, I. An account of the rebels, who and what they were, not, as formerly, the mixed multitude and the dregs of the people, who are therefore never named, but men of distinction and quality, that made a figure. Korah was the ring-leader: he formed and headed the faction; therefore it is called the gainsaying of Korah, Jde 1:11. He was cousin-german to Moses, they were brothers\' children, yet the nearness of the relation could not restrain him from being insolent and rude to Moses. Think ...', 'teologico');
add('nm', 16, 12, 'Matthew Henry', 'Here is, I. The insolence of Dathan and Abiram, and their treasonable remonstrance. Moses had heard what Korah had to say, and had answered it; now he summons Dathan and Abiram to bring in their complaints (Num 16:12); but they would not obey his summons, either because they could not for shame say that to his face which they were resolved to say, and then it is an instance of some remains of modesty in them; or, rather, because they would not so far own his authority, and then it is an insta...', 'teologico');
add('nm', 16, 23, 'Matthew Henry', 'We have here the determining of the controversy with Dathan and Abiram, who rebelled against Moses, as in the next paragraph the determining of the controversy with Korah and his company, who would be rivals with Aaron. It should seem that Dathan and Abiram had set up a spacious tabernacle in the midst of the tents of their families, where they kept court, met in council, and hung out their flag of defiance against Moses; it is here called the tabernacle of Korah, Dathan, and Abiram, Num 16:2...', 'teologico');
add('nm', 16, 35, 'Matthew Henry', 'We must now look back to the door of the tabernacle, where we left the pretenders to the priesthood with their censers in their hands ready to offer incense; and here we find,\nI. Vengeance taken on them, Num 16:35. It is probable that when the earth opened in the camp to swallow up Dathan and Abiram a fire went out from the Lord and consumed the 250 men that offered incense, while Aaron that stood with them was preserved alive. This punishment was not indeed so new a thing as the former, for ...', 'teologico');
add('nm', 16, 41, 'Matthew Henry', 'Here is, I. A new rebellion raised the very next day against Moses and Aaron. Be astonished, O heavens, at this, and wonder, O earth! Was there ever such an instance of the incurable corruption of sinners? On the morrow (Num 16:41) the body of the people mutinied. 1. Though they were so lately terrified by the sight of the punishment of the rebels. The shrieks of those sinking sinners, those sinners against their own souls, were yet sounding in their ears, the smell of the fire yet remained, ...', 'teologico');
add('nm', 17, 1, 'Matthew Henry', 'Here we have, I. Orders given for the bringing in of a rod for every tribe (which was peculiarly significant, for the word here used for a rod sometimes signifies a tribe, as particularly Num 34:13), that God by a miracle, wrought on purpose, might make it known on whom he had conferred the honour of the priesthood. 1. It seems then the priesthood was a preferment worth seeking and striving for, even by the princes of the tribes. It is an honour to the greatest of men to be employed in the se...', 'teologico');
add('nm', 17, 8, 'Matthew Henry', 'Here is, I. The final determination of the controversy concerning the priesthood by a miracle, Num 17:8, Num 17:9. The rods or staves were brought out from the most holy place where they were laid up, and publicly produced before the people; and, while all the rest of the rods remained as they were, Aaron\'s rod only, of a dry stick, became a living branch, budded, and blossomed, and yielded almonds. In some places there were buds, in others blossoms, in others fruit, at the same time. This wa...', 'teologico');
add('nm', 18, 1, 'Matthew Henry', 'The coherence of this chapter with that foregoing is very observable.\nI. The people, in the close of that chapter, had complained of the difficulty and peril that there were in drawing near to God, which put them under some dreadful apprehensions that the tabernacle in the midst of them, which they hoped would have been their joy and glory, would rather be their terror and ruin. Now, in answer to this complaint, God here gives them to understand by Aaron that the priests should come near for ...', 'teologico');
add('nm', 18, 8, 'Matthew Henry', 'The priest\'s service is called a warfare; and who goes a warfare at his own charges? As they were well employed, so they were well provided for, and well paid. None shall serve God for nought. All believers are spiritual priests, and God has promised to take care of them; they shall dwell in the land, and verily they shall be fed, and shall not want any good thing. Godliness has the promise of the life that now is. And from this plentiful provision here made for the priests the apostle infers...', 'teologico');
add('nm', 18, 20, 'Matthew Henry', 'Here is a further account of the provision that was made both for the Levites and for the priests, out of the country.\nI. They must have no inheritance in the land; only cities to dwell in were afterwards allowed them, but no ground to occupy: Thou shalt not have any part among them, Num 18:20. It is repeated again Num 18:23, and again Num 18:24, Among the children of Israel they shall have no inheritance, either by purchase or descent. God would have them comfortably provided for, but would ...', 'teologico');
add('nm', 19, 1, 'Matthew Henry', 'We have here the divine appointment concerning the solemn burning of a red heifer to ashes, and the preserving of the ashes, that of them might be made, not a beautifying, but a purifying, water, for that was the utmost the law reached to; it offered not to adorn as the gospel does, but to cleanse only. This burning of the heifer, though it was not properly a sacrifice of expiation, being not performed at the altar, yet was typical of the death and sufferings of Christ, by which he intended, ...', 'teologico');
add('nm', 19, 11, 'Matthew Henry', 'Directions are here given concerning the use and application of the ashes which were prepared for purification. they were laid up to be laid out; and therefore, though now one place would serve to keep them in, while all Israel lay so closely encamped, yet it is probable that afterwards, when they came to Canaan, some of these ashes were kept in every town, for there would be daily use for them. Observe,\nI. In what cases there needed a purification with these ashes. No other is mentioned here...', 'teologico');
add('nm', 20, 1, 'Matthew Henry', 'After thirty-eight years\' tedious marches, or rather tedious rests, in the wilderness, backward towards the Red Sea, the armies of Israel now at length set their faces towards Canaan again, and had come not far off from the place where they were when, by the righteous sentence of divine Justice, they were made to begin their wanderings. Hitherto they had been led about as in a maze or labyrinth, while execution was doing upon the rebels that were sentenced; but they were now brought into the ...', 'teologico');
add('nm', 20, 14, 'Matthew Henry', 'We have here the application made by Israel to the Edomites. The nearest way to Canaan from the place where Israel now lay encamped was through the country of Edom. Now,\nI. Moses sends ambassadors to treat with the king of Edom for leave to pass through his country, and gives them instructions what to say, Num 20:14-17. 1. They are to claim kindred with the Edomites: Thus saith thy brother Israel. Both nations descended from Abraham and Isaac, their common ancestors; Esau and Jacob, the two f...', 'teologico');
add('nm', 20, 22, 'Matthew Henry', 'The chapter began with the funeral of Miriam, and it ends with the funeral of her brother Aaron. When death comes into a family, it often strikes double. Israel had not improved the former affliction they were under, by the death of the prophetess, and therefore, soon after, God took away their priest, to try if they would lay that to heart. This happened at the very next stage, when they removed to Mount Hor, fetching a compass round the Edomites\' country, leaving it on their left hand. Wher...', 'teologico');
add('nm', 21, 1, 'Matthew Henry', 'Here is, 1. The descent which Arad the Canaanite made upon the camp of Israel, hearing that they came by the way of the spies; for, though the spies which Moses had sent thirty-eight years before then passed and repassed unobserved, yet their coming, and their errand, it is likely, were afterwards known to the Canaanites, gave them an alarm, and induced them to keep an eye upon Israel and get intelligence of all their motions. Now, when they understood that they were facing about towards Cana...', 'teologico');
add('nm', 21, 4, 'Matthew Henry', 'Here is, I. The fatigue of Israel by a long march round the land of Edom, because they could not obtain passage through it the nearest way: The soul of the people was much discouraged because of the way, Num 21:4. Perhaps the way was rough and uneven, or foul and dirty; or it fretted them to go far about, and that they were not permitted to force their passage through the Edomites\' country. Those that are of a fretful discontented spirit will always find something or other to make them uneasy...', 'teologico');
add('nm', 21, 10, 'Matthew Henry', 'We have here an account of the several stages and removals of the children of Israel, till they came into the plains of Moab, out of which they at length passed over Jordan into Canaan, as we read in the beginning of Joshua. Natural motions are quicker the nearer they are to their centre. The Israelites were now drawing near to the promised rest, and now they set forward, as the expression is, Num 21:10. It were well if we would do thus in our way to heaven, rid ground in the latter end of ou...', 'teologico');
add('nm', 21, 21, 'Matthew Henry', 'We have here an account of the victories obtained by Israel over Sihon and Og, which must be distinctly considered, not only because they are here distinctly related, but because long afterwards the memorial of them is distinctly celebrated, and they are severally assigned as instances of everlasting mercy. He slew Sihon king of the Amorites, for his mercy endureth for ever, and Og the king of Bashan, for his mercy endureth for ever, Psa 136:19, Psa 136:20.\nI. Israel sent a peaceable message ...', 'teologico');
add('nm', 22, 1, 'Matthew Henry', 'The children of Israel have at length finished their wanderings in the wilderness, out of which they went up (Num 21:18), and are now encamped in the plains of Moab near Jordan, where they continued till they passed through Jordan under Joshua, after the death of Moses. Now we have here,\nI. The fright which the Moabites were in upon the approach of Israel, Num 22:2-4. They needed not to fear any harm from them if they knew (and it is probable that Moses let them know) the orders God had given...', 'teologico');
add('nm', 22, 15, 'Matthew Henry', 'We have here a second embassy sent to Balaam, to fetch him over to curse Israel. It were well for us if we were as earnest and constant in prosecuting a good work, notwithstanding disappointments, as Balak was in pursuing this ill design. The enemies of the church are restless and unwearied in their attempts against it; but he that sits in heaven laughs at them. Observe,\nI. The temptation Balak laid before Balaam. He contrived to make this assault more vigorous than the former. It is very pro...', 'teologico');
add('nm', 22, 22, 'Matthew Henry', 'We have here an account of the opposition God gave to Balaam in his journey towards Moab; probably the princes had gone before, or gone some other way, and Balaam had pointed out where he would meet them, or where they should stay for him, for we read nothing of them in this part of our narrative, only that Balaam, like a person of some quality, was attended with his two men-honour enough, one would think, for such a man, he needed not be beholden to Balak for promotion.\nI. Here is God\'s disp...', 'teologico');
add('nm', 22, 36, 'Matthew Henry', 'We have here the meeting between Balak and Balaam, confederate enemies to God\'s Israel; but here they seem to differ in their expectations of the success. 1. Balak speaks of it with confidence, not doubting but to gain his point now that Balaam had come. In expectation of this, he went out to meet him, even to the utmost border of his country (Num 22:36), partly to gratify his own impatient desire to see one he had such great expectations from, and partly to do honour to Balaam, and so to eng...', 'teologico');
add('nm', 23, 1, 'Matthew Henry', 'Here is, I. Great preparation made for the cursing of Israel. That which was aimed at was to engage the God of Israel to forsake them, and either to be on Moab\'s side or to stand neuter. O the sottishness of superstition, to imagine that God will be at men\'s beck! Balaam and Balak think to bribe him with altars and sacrifices, offered without any warrant or institution of his: as if he would eat the flesh of bulls or drink the blood of goats. Ridiculous nonsense, to think that these would ple...', 'teologico');
add('nm', 23, 13, 'Matthew Henry', 'Here is, I. Preparation made the second time, as before, for the cursing of Israel. 1. The place is changed, Num 23:13. Balak fancied that Balaam, having so full a prospect of the whole camp of Israel, from the top of the rocks (Num 23:9), was either so enamoured with the beauty of it that he would not curse them or so affrighted with the terror of it that he durst not; and therefore he would bring him to another place, form which he might see only some part of them, which would appear more d...', 'teologico');
add('nm', 24, 1, 'Matthew Henry', 'The blessing itself which Balaam here pronounces upon Israel is much the same with the two we had in the foregoing chapter; but the introduction to it is different.\nI. The method of proceeding here varies much in several instances. 1. Balaam laid aside the enchantments which he had hitherto depended on, used no spells, or charms, or magic arts, finding they did him no service; it was to no purpose to deal with the devil for a curse, when it was plain that God was determined immovably to bless...', 'teologico');
add('nm', 24, 10, 'Matthew Henry', 'We have here the conclusion of this vain attempt to curse Israel, and the total abandonment of it. 1. Balak made the worst of it. He broke out into a rage against Balaam (Num 24:10), expressed both in words and gesture the highest degree of vexation at the disappointment; he smote his hands together, for indignation, to see all his measures thus broken, and his project baffled. He charged Balaam with putting upon him the basest affront and cheat imaginable: "I called thee to curse my enemies,...', 'teologico');
add('nm', 24, 15, 'Matthew Henry', 'The office of prophets was both to bless and to prophesy in the name of the Lord. Balaam, as a prophet, per force had blessed Israel; here he foretels future events.\nI. His preface is much the same as that, Num 24:3, Num 24:4. He personates a true prophet admirably well, God permitting and directing him to do so, because, whatever he was, the prophecy itself was a true prophecy. He boasts, 1. That his eyes are open (Num 24:15), for prophets were in old time called seers (Sa1 9:9), because the...', 'teologico');
add('nm', 25, 1, 'Matthew Henry', 'Here is, I. The sin of Israel, to which they were enticed by the daughters of Moab and Midian; they were guilty both of corporal and spiritual whoredoms, for Israel joined himself unto Baal-peor, Num 25:3. Not all, nor the most, but very many, were taken in this snare. Now concerning this observe, 1. That Balak, by the advice of Balaam, cast this stumbling-block before the children of Israel, Rev 2:14. Note, Those are our worst enemies that draw us to sin, for that is the greatest mischief an...', 'teologico');
add('nm', 25, 6, 'Matthew Henry', 'Here is a remarkable contest between wickedness and righteousness, which shall be most bold and resolute; and righteousness carries the day, as no doubt it will at last.\nI. Never was vice more daring than it was in Zimri, a prince of a chief house in the tribe of Simeon. Such a degree of impudence in wickedness had he arrived at that he publicly appeared leading a Midianitish harlot (and a harlot of quality too like himself, a daughter of a chief house in Midian) in the sight of Moses, and al...', 'teologico');
add('nm', 25, 16, 'Matthew Henry', 'God had punished the Israelites for their sin with a plague; as a Father he corrected his own children with a rod. But we read not that any of the Midianites died of the plague; God took another course with them, and punished them with the sword of an enemy, not with the rod of a father. 1. Moses, though the meekest man, and far from a spirit of revenge, is ordered to vex the Midianites and smite them, Num 25:17. Note, We must set ourselves against that, whatever it is, which is an occasion o...', 'teologico');
add('nm', 26, 1, 'Matthew Henry', 'Observe here, 1. That Moses did not number the people but when God commanded him. David in his time did it without a command, and paid dearly for it. God was Israel\'s king, and he would not have this act of authority done but by his express orders. Moses, perhaps, by this time, had heard of the blessing with which Balaam was constrained, sorely against his will, to bless Israel, and particularly the notice he took of their numbers; and he was sufficiently pleased with that general testimony b...', 'teologico');
add('nm', 26, 5, 'Matthew Henry', 'This is the register of the tribes as they were now enrolled, in the same order that they were numbered in ch. 1. Observe,\nI. The account that is here kept of the families of each tribe, which must not be understood of such as we call families, those that live in a house together, but such as were the descendants of the several sons of the patriarchs, by whose names, in honour of them, their posterity distinguished themselves and one another. The families of the twelve tribes are thus numbere...', 'teologico');
add('nm', 26, 52, 'Matthew Henry', 'If any ask why such a particular account is kept of the tribes, and families, and numbers, of the people of Israel, here is an answer for them; as they were multiplied, so they were portioned, not by common providence, but by promise; and, for the support of the honour of divine revelation, God will have the fulfilling of the promise taken notice of both in their increase and in their inheritance. When Moses had numbered the people God did not say, By these shall the land be conquered; but, t...', 'teologico');
add('nm', 26, 57, 'Matthew Henry', 'Levi was God\'s tribe, a tribe that was to have no inheritance with the rest in the land of Canaan, and therefore was not numbered with the rest, but by itself; so it had been numbered in the beginning of this book at Mount Sinai, and therefore came not under the sentence passed upon all that were then numbered, that none of them should enter Canaan but Caleb and Joshua; for of the Levites that were not numbered with them, nor were to go forth to war, Eleazar and Ithamar, and perhaps others wh...', 'teologico');
add('nm', 26, 63, 'Matthew Henry', 'That which is observable in this conclusion of the account is the execution of the sentence passed upon the murmurers (Num 14:29), that not one of those who were numbered from twenty years old and upwards (and that the Levites were not, but either from a month old or from thirty years old to fifty) should enter Canaan, except Caleb and Joshua. In the muster now made particular directions, no doubt, were given to those of each tribe that were employed in taking the account, to compare these ro...', 'teologico');
add('nm', 27, 1, 'Matthew Henry', 'Mention is made of the case of these daughters of Zelophehad in the chapter before, v. 33. It should seem, by the particular notice taken of it, that it was a singular case, and that the like did not at this time occur in all Israel, that the head of a family had no sons, but daughters only. Their case is again debated (Num 36:1-13) upon another article of it; and, according to the judgments given in their case, we find them put in possession, Jos 17:3, Jos 17:4. One would suppose that their ...', 'teologico');
add('nm', 27, 12, 'Matthew Henry', 'Here, 1. God tells Moses of his fault, his speaking unadvisedly with his lips at the waters of strife, where he did not express, so carefully as he ought to have done, a regard to the honour both of God and Israel, Num 27:14. Though Moses was a servant of the Lord, a faithful servant, yet once he rebelled against God\'s commandment, and failed in his duty; and though a very honourable servant, and highly favoured, yet he shall hear of his miscarriage, and all the world shall hear of it too, ag...', 'teologico');
add('nm', 27, 15, 'Matthew Henry', 'Here, I. Moses prays for a successor. When God had told him that he must die, though it appears elsewhere that he solicited for a reprieve for himself (Deu 3:24, Deu 3:25), yet, when this could not be obtained, he begged earnestly that the work of God might be carried on, though he might not have the honour of finishing it. Envious spirits do not love their successors, but Moses was not one of these. We should concern ourselves, both in our prayers and in our endeavours, for the rising genera...', 'teologico');
add('nm', 28, 1, 'Matthew Henry', 'Here is, I. A general order given concerning the offerings of the Lord, which were to be brought in their season, Num 28:2. These laws are here given afresh, not because the observance of them was wholly disused during their thirty-eight years\' wandering in the wilderness (we cannot think that they were so long without any public worship, but that at least the daily lamb was offered morning and evening, and doubled on the sabbath day; so bishop Patrick conjectures); but that many of the sacri...', 'teologico');
add('nm', 28, 9, 'Matthew Henry', 'The new moons and the sabbaths are often spoken of together, as great solemnities in the Jewish church, very comfortable to the saints then, and typical of gospel grace. Now we have here the sacrifices appointed, 1. For the sabbaths. Every sabbath day the offering must be doubled; besides the two lambs offered for the daily burnt-offering, there must be two more offered, one (it is probable) added to the morning sacrifice, and the other to the evening, Num 28:9, Num 28:10. This teaches us to ...', 'teologico');
add('nm', 28, 16, 'Matthew Henry', 'Here is, I. The appointment of the pass-over sacrifices; not that which was the chief, the paschal lamb (sufficient instructions had formerly been given concerning that), but those which were to be offered upon the seven days of unleavened bread, which followed it, Num 28:17-25. The first and last of those seven days were to be sanctified as sabbaths, by a holy rest and a holy convocation, and on each of the seven days they were to be liberal in their sacrifices, in token of their great and c...', 'teologico');
add('nm', 29, 1, 'Matthew Henry', 'There were more sacred solemnities in the seventh month than in any other month of the year, not only because it had been the first month till the deliverance of Israel out of Egypt (which, falling in the month Abib, occasioned that to be thenceforth made the beginning of the months in all ecclesiastical computations), but because still it continued the first month in the civil reckonings of the jubilees and years of release, and also because it was the time of vacation between harvest and se...', 'teologico');
add('nm', 29, 12, 'Matthew Henry', 'Soon after the day of atonement, that day in which men were to afflict their souls, followed the feast of tabernacles, in which they were to rejoice before the Lord; for those that sow in tears shall soon reap in joy. To the former laws about this feast, which we had, Lev 23:34, etc., here are added directions about the offerings by fire, which they were to offer unto the Lord during the seven days of that feast, Lev 23:36. Observe here, 1. Their days of rejoicing were to be days of sacrifice...', 'teologico');
add('nm', 30, 1, 'Matthew Henry', 'This law was delivered to the heads of the tribes that they might instruct those who were under their charge, explain the law to them, give then necessary cautions, and call them to account, if there were occasion, for the breach of their vows. Perhaps the heads of the tribes had, upon some emergency of this kind, consulted Moses, and desired by him to know the mind of God, and here they are told it: This is the thing which the Lord has commanded concerning vows, and it is a command still in ...', 'teologico');
add('nm', 30, 3, 'Matthew Henry', 'It is here taken for granted that all such persons as are sui juris - at their own disposal, and are likewise of sound understanding and memory, are bound to perform whatever they vow that is lawful and possible; but, if the person vowing be under the dominion and at the disposal of another, the case is different. Two cases much alike are here put and determined: - \nI. The case of a daughter in her father\'s house: and some think, probably enough, that it extends to a son likewise, while he is...', 'teologico');
add('nm', 36, 1, 'Matthew Henry', 'We have here the humble address which the heads of the tribe of Manasseh made to Moses and the princes, on occasion of the order lately made concerning the daughters of Zelophehad. The family they belonged to was part of that half of the tribe of Manasseh which we yet to have their lot within Jordan, not that half that was already settled; and yet they speak of the land of their possession, and the inheritance of their fathers, with as great assurance as if they had it already in their hands,...', 'teologico');
add('nm', 36, 5, 'Matthew Henry', 'Here is, I. The matter settled by express order from God between the daughters of Zelophehad and the rest of the tribe of Manasseh. The petition is assented to, and care taken to prevent the inconvenience feared: The tribe of the sons of Joseph hath said well, Num 36:5. Thus those that consult the oracles of God concerning the making of their heavenly inheritance sure shall not only be directed what to do, but their enquiries shall be graciously accepted, and they shall have not only their we...', 'teologico');

// DT (103 comentários)
add('dt', 6, 4, 'Calvino', 'Ouve, Israel: o Senhor é um — O Shema afirma o monoteísmo exclusivo. Um só Deus, uma só lealdade.', 'teologico');
add('dt', 6, 5, 'Agostinho', 'Amarás o Senhor de todo o coração — O amor total a Deus é o resumo da Lei e o fruto da graça.', 'teologico');
add('dt', 30, 19, 'Lutero', 'Escolhe a vida — A responsabilidade moral é real: Deus coloca diante de nós bênção e maldição.', 'aplicacao');
add('dt', 1, 1, 'Matthew Henry', 'We have here, I. The date of this sermon which Moses preached to the people of Israel. A great auditory, no question, he had, as many as could crowd within hearing, and particularly all the elders and officers, the representatives of the people; and, probably, it was on the sabbath day that he delivered this to them. 1. The place were they were now encamped was in the plain, in the land of Moab (Deu 1:1, Deu 1:5), where they were just ready to enter Canaan, and engage in a war with the Canaan...', 'teologico');
add('dt', 1, 9, 'Matthew Henry', 'Moses here reminds them of the happy constitution of their government, which was such as might make them all safe and easy if it was not their own fault. When good laws were given them good men were entrusted with the execution of them, which, as it was an instance of God\'s goodness to them, so it was of the care of Moses concerning them; and, it should seem, he mentions it here to recommend himself to them as a man that sincerely sought their welfare, and so to make way for what he was about...', 'teologico');
add('dt', 1, 19, 'Matthew Henry', 'Moses here makes a large rehearsal of the fatal turn which was given to their affairs by their own sins, and God\'s wrath, when, from the very borders of Canaan, the honour of conquering it, and the pleasure of possessing it, the whole generation was hurried back into the wilderness, and their carcases fell there. It was a memorable story; we read it Num. 13 and 14, but divers circumstances are found here which are not related there.\nI. He reminds them of their march from Horeb to Kadesh-barne...', 'teologico');
add('dt', 2, 1, 'Matthew Henry', 'Here is, I. A short account of the long stay of Israel in the wilderness: We compassed Mount Seir many days, Deu 2:1. Nearly thirty-eight years they wandered in the deserts of Seir; probably in some of their rests they staid several years, and never stirred; God by this not only chastised them for their murmuring and unbelief, but, 1. Prepared them for Canaan, by humbling them for sin, teaching them to mortify their lusts, to follow God, and to comfort themselves in him. It is a work of time ...', 'teologico');
add('dt', 2, 8, 'Matthew Henry', 'It is observable here that Moses, speaking of the Edomites (Deu 2:8), calls them, "our brethren, the children of Esau." Though they had been unkind to Israel, in refusing them a peaceable passage through their country, yet he calls them brethren. For, though our relations fail in their duty to us, we must retain a sense of the relation, and not be wanting in our duty to them, as there is occasion. Now in these verses we have,\nI. The account which Moses gives of the origin of the nations of wh...', 'teologico');
add('dt', 2, 24, 'Matthew Henry', 'God having tried the self-denial of his people in forbidding them to meddle with the Moabites and Ammonites, and they having quietly passed by those rich countries, and, though superior in number, not made any attack upon them, here he recompenses them for their obedience by giving them possession of the country of Sihon king of the Amorites. If we forbear what God forbids, we shall receive what he promises, and shall be no losers at last by our obedience, though it may seem for the present t...', 'teologico');
add('dt', 3, 1, 'Matthew Henry', 'We have here another brave country delivered into the hand of Israel, that of Bashan; the conquest of Sihon is often mentioned together with that of Og, to the praise of God, the rather because in these Israel\'s triumphs began, Psa 135:11; Psa 136:19, Psa 136:20. See,\nI. How they got the mastery of Og, a very formidable prince, 1. Very strong, for he was of the remnant of the giants (Deu 3:11); his personal strength was extraordinary, a monument of which was preserved by the Ammonites in his ...', 'teologico');
add('dt', 3, 12, 'Matthew Henry', 'Having shown how this country which they were now in was conquered, in these verses he shows how it was settled upon the Reubenites, Gadites, and half the tribe of Manasseh, which we had the story of before, Num. 32. Here is the rehearsal. 1. Moses specifies the particular parts of the country that were allotted to each tribe, especially the distribution of the lot to the half tribe of Manasseh, the subdividing of which tribe is observable. Joseph was divided into Ephraim and Manasseh; Manass...', 'teologico');
add('dt', 3, 21, 'Matthew Henry', 'Here is I. The encouragement which Moses gave to Joshua, who was to succeed him in the government, Deu 3:21, Deu 3:22. He commanded him not to fear. This those that are aged and experienced in the service of God should do all they can to strengthen the hands of those that are young, and setting out in religion. Two things he would have him consider for his encouragement: - 1. What God has done. Joshua had seen what a total defeat God had given by the forces of Israel to these two kings, and t...', 'teologico');
add('dt', 4, 1, 'Matthew Henry', 'This most lively and excellent discourse is so entire, and the particulars of it are so often repeated, that we must take it altogether in the exposition of it, and endeavour to digest it into proper heads, for we cannot divide it into paragraphs.\nI. In general, it is the use and application of the foregoing history; it comes in by way of inference from it: Now therefore harken, O Israel, Deu 4:1. This use we should make of the review of God\'s providences concerning us, we should by them be q...', 'teologico');
add('dt', 4, 41, 'Matthew Henry', 'Here is, 1. The nomination of the cities of refuge on that side Jordan where Israel now lay encamped. Three cities were appointed for that purpose, one in the lot of Reuben, another in that of Gad, and another in that of the half tribe of Manasseh, Deu 4:41-43. What Moses could do for that people while he was yet with them he did, to give example to the rulers who were settled that they might observe them the better when he was gone. 2. The introduction to another sermon that Moses preached t...', 'teologico');
add('dt', 5, 1, 'Matthew Henry', 'Here, 1. Moses summons the assembly. He called all Israel; not only the elders, but, it is likely, as many of the people as could come within hearing, Deu 5:1. The greatest of them were not above God\'s command, nor the meanest of them below his cognizance; but they were all bound to do. 2. He demands attention: "Hear, O Israel; hear and heed, hear and remember, hear, that you may learn, and keep, and do; else your hearing is to no purpose." When we hear the word of God we must set ourselves t...', 'teologico');
add('dt', 5, 6, 'Matthew Henry', 'Here is the repetition of the ten commandments, in which observe, 1. Though they had been spoken before, and written, yet they are again rehearsed; for precept must be upon precept, and line upon line, and all little enough to keep the word of God in our minds and to preserve and renew the impressions of it. We have need to have the same things often inculcated upon us. See Phi 3:1. 2. There is some variation here from that record (Ex. 20), as there is between the Lord\'s prayer as it is in Mt...', 'teologico');
add('dt', 5, 23, 'Matthew Henry', 'Here, I. Moses reminds them of the agreement of both the parties that were now treating, in the mediation of Moses.\n1. Here is the consternation that the people were put into by that extreme terror with which the law was given. They owned that they could not bear it any more: "This great fire will consume us; this dreadful voice will be fatal to us; we shall certainly die if we hear it any more," Deu 5:25. They wondered that they were not already struck dead with it, and took it for an extrao...', 'teologico');
add('dt', 6, 1, 'Matthew Henry', 'Observe here, 1. That Moses taught the people all that, and that only, which God commanded him to teach them, Deu 6:1. Thus Christ\'s ministers are to teach his churches all that he has commanded, and neither more nor less, Mat 28:20. 2. That the end of their being taught was that they might do as they were taught (Mat 28:1), might keep God\'s statutes (Deu 6:2), and observe to do them, Deu 6:3. Good instructions from parents and ministers will but aggravate our condemnation if we do not live u...', 'teologico');
add('dt', 6, 17, 'Matthew Henry', 'Here, I. Moses charges them to keep God\'s commandments themselves: You shall diligently keep God\'s commandments, Deu 6:17-19. Note, It requires a great deal of care and pains to keep up religion in the power of it in our hearts and lives. Negligence will ruin us; but we cannot be saved without diligence. To induce them to this, he here shows them, 1. That this would be very acceptable to God: it is right and good in the sight of the Lord; and that is right and good indeed that is, so in God\'s...', 'teologico');
add('dt', 7, 1, 'Matthew Henry', 'Here is, I. A very strict caution against all friendship and fellowship with idols and idolaters. Those that are taken into communion with God must have no communication with the unfruitful works of darkness. These things they are charged about for the preventing of this snare now before them.\n1. They must show them no mercy, Deu 7:1, Deu 7:2. Bloody work is here appointed them, and yet it is God\'s work, and good work, and in its time and place needful, acceptable, and honourable.\n(1.) God he...', 'teologico');
add('dt', 7, 12, 'Matthew Henry', 'Here, I. The caution against idolatry is repeated, and against communion with idolaters: "Thou shalt consume the people, and not serve their gods." Deu 7:16. We are in danger of having fellowship with the works of darkness if we take pleasure in fellowship with those that do those works. Here is also a repetition of the charge to destroy the images, Deu 7:25, Deu 7:26. The idols which the heathen had worshipped were an abomination to God, and therefore must be so to them: all that truly love ...', 'teologico');
add('dt', 8, 1, 'Matthew Henry', 'The charge here given them is the same as before, to keep and do all God\'s commandments. Their obedience must be, 1. Careful: Observe to do. 2. Universal: To do all the commandments, Deu 8:1. And, 3. From a good principle, with a regard to God as the Lord, and their God, and particularly with a holy fear of him (Deu 8:6), from a reverence of his majesty, a submission to his authority, and a dread of his wrath. To engage them to this obedience, besides the great advantages of it, which he sets...', 'teologico');
add('dt', 8, 10, 'Matthew Henry', 'Moses, having mentioned the great plenty they would find in the land of Canaan, finds it necessary to caution them against the abuse of that plenty, which was a sin they would be the more prone to new that they came into the vineyard of the Lord, immediately out of a barren desert.\nI. He directs them to the duty of a prosperous condition, Deu 8:10. They are allowed to eat even to fulness, not to surfeiting no excess; but let them always remember their benefactor, the founder of their feast, a...', 'teologico');
add('dt', 9, 1, 'Matthew Henry', 'The call to attention (Deu 9:1), Hear, O Israel, intimates that this was a new discourse, delivered at some distance of time after the former, probably the next sabbath day.\nI. Moses represents to the people the formidable strength of the enemies which they were now to encounter, Deu 9:1. The nations they were to dispossess were mightier than themselves, not a rude and undisciplined rout, like the natives of America, that were easily made a prey of. But, should they besiege them, they would f...', 'teologico');
add('dt', 9, 7, 'Matthew Henry', 'That they might have no pretence to think that God brought them to Canaan for their righteousness, Moses here shows them what a miracle of mercy it was that they had not long ere this been destroyed in the wilderness: "Remember, and forget not, how thou provokedst the Lord thy God (Deu 9:7); so far from purchasing his favour, thou hast many a time laid thyself open to his displeasure." Their fathers\' provocations are here charged upon them; for, if God had dealt with their fathers according t...', 'teologico');
add('dt', 10, 1, 'Matthew Henry', 'There were four things in and by which God showed himself reconciled to Israel and made them truly great and happy, and in which God\'s goodness took occasion from their badness to make him the more illustrious: - \nI. He gave them his law, gave it to them in writing, as a standing pledge of his favour. Though the tables that were first written were broken, because Israel had broken the commandments, and God might justly break the covenant, yet when his anger was turned away the tables were ren...', 'teologico');
add('dt', 10, 12, 'Matthew Henry', 'Here is a most pathetic exhortation to obedience, inferred from the premises, and urged with very powerful arguments and a great deal of persuasive rhetoric. Moses brings it in like an orator, with an appeal to his auditors And now, Israel, what doth the Lord thy God require of thee? Deu 10:12. Ask what he requires; as David (Psa 116:12), What shall I render? When we have received mercy from God it becomes us to enquire what returns we shall make to him. Consider what he requires, and you wil...', 'teologico');
add('dt', 11, 1, 'Matthew Henry', 'Because God has made thee as the stars of heaven for multitude (so the preceding chapter concludes), therefore thou shalt love the Lord thy God (so this begins). Those whom God has built up into families, whose beginning was small, but whose latter end greatly increases, should use that as an argument with themselves why they should serve God. Thou shalt keep his charge, that is, the oracles of his word and ordinances of his worship, with which they were entrusted and for which they were acco...', 'teologico');
add('dt', 11, 8, 'Matthew Henry', 'Still Moses urges the same subject, as loth to conclude till he had gained his point. "If thou wilt enter into life, if thou wilt enter into Canaan, a type of that life, and find it a good land indeed to thee, keep the commandments: Keep all the commandments which I command you this day; love God, and serve him with all your heart."\nI. Because this was the way to get and keep possession of the promised land. 1. It was the way to get possession (Deu 11:8): That you may be strong for war, and s...', 'teologico');
add('dt', 11, 18, 'Matthew Henry', 'Here, I. Moses repeats the directions he had given for the guidance and assistance of the people in their obedience, and for the keeping up of religion among them (Deu 11:18-20), which is much to the same purport with what we had before, Deu 6:6, etc. Let us all be directed by the three rules here given: - 1. Let our hearts be filled with the word of God: Lay up these words in your heart and in your soul. The heart must be the treasury or store-house in which the word of God must be laid up, ...', 'teologico');
add('dt', 11, 26, 'Matthew Henry', 'Here Moses concludes his general exhortations to obedience; and his management is very affecting, and such as, one would think, should have engaged them for ever to God, and should have left impressions upon them never to be worn out.\nI. He sums up all his arguments for obedience in two words, the blessing and the curse (Deu 11:26), that is, the rewards and the punishments, as they stand in the promises and the threatenings, which are the great sanctions of the law, taking hold of hope and fe...', 'teologico');
add('dt', 12, 1, 'Matthew Henry', 'From those great original truths, That there is a God, and that there is but one God, arise those great fundamental laws, That that God is to be worshipped, and he only, and that therefore we are to have no other God before him: this is the first commandment, and the second is a guard upon it, or a hedge about it. To prevent a revolt to false gods, we are forbidden to worship the true God in such a way and manner as the false gods were worshipped in, and are commanded to observe the institute...', 'teologico');
add('dt', 12, 5, 'Matthew Henry', 'There is not any one particular precept (as I remember) in all the law of Moses so largely pressed and inculcated as this, by which they are all tied to bring their sacrifices to that one altar which was set up in the court of the tabernacle, and there to perform all the rituals of their religion; for, as to moral services, then, no doubt, as now, men might pray every where, as they did in their synagogues. The command to do this, and the prohibition of the contrary, are here repeated again a...', 'teologico');
add('dt', 13, 1, 'Matthew Henry', 'Here is, I. A very strange supposition, Deu 13:1, Deu 13:2. 1. It is strange that there should arise any among themselves, especially any pretending to vision and prophecy, who should instigate them to go and serve other gods. Was it possible that any who had so much knowledge of the methods of divine revelation as to be able to personate a prophet should yet have so little knowledge of the divine nature and will as to go himself and entice his neighbours after other gods? Could an Israelite ...', 'teologico');
add('dt', 13, 6, 'Matthew Henry', 'Further provision is made by this branch of the statute against receiving the infection of idolatry from those that are near and dear to us.\nI. It is the policy of the tempter to send his solicitations by the hand of those whom we love, whom we least suspect of any ill design upon us, and whom we are desirous to please and apt to conform ourselves to. The enticement here is supposed to come from a brother or child that are near by nature, from a wife or friend that are near by choice, and are...', 'teologico');
add('dt', 13, 12, 'Matthew Henry', 'Here the case is put of a city revolting from its allegiance to the God of Israel, and serving other gods.\nI. The crime is supposed to be committed, 1. By one of the cities of Israel, that lay within the jurisdiction of their courts. The church then judged those only that were within, Co1 5:12, Co1 5:13. And, even when they were ordered to preserve their religion in the first principles of it by fire and sword to propagate it. Those that are born within the allegiance of a prince, if they tak...', 'teologico');
add('dt', 14, 1, 'Matthew Henry', 'Moses here tells the people of Israel,\nI. How God had dignified them, as a peculiar people, with three distinguishing privileges, which were their honour, and figures of those spiritual blessings in heavenly things with which God has in Christ blessed us. 1. Here is election: The Lord hath chosen thee, v: 2. Not for their own merit, nor for any good works foreseen, but because he would magnify the riches of his power and grace among them. He did not choose them because they were by their own ...', 'teologico');
add('dt', 14, 22, 'Matthew Henry', 'We have here a part of the statute concerning tithes. The productions of the ground were twice tithed, so that, putting both together, a fifth part was devoted to God out of their increase, and only four parts of five were for their own common use; and they could not but own they paid an easy rent, especially since God\'s part was disposed of to their own benefit and advantage. The first tithe was for the maintenance of their Levites, who taught them the good knowledge of God, and ministered t...', 'teologico');
add('dt', 15, 1, 'Matthew Henry', 'Here is, I. A law for the relief of poor debtors, such (we may suppose) as were insolvent. Every seventh year was a year of release, in which the ground rested from being tilled and servants were discharged from their services; and, among other acts of grace, this was one, that those who had borrowed money, and had not been able to pay it before, should this year be released from it; and though, if they were able, they were afterwards bound in conscience to repay it, yet thenceforth the credi...', 'teologico');
add('dt', 15, 12, 'Matthew Henry', 'Here is, I. A repetition of the law that had been given concerning Hebrew servants who had sold themselves for servants, or were sold by their parents through extreme poverty, or were sold by the court of judgment for some crime committed. The law was, 1. That they should serve but six years, and in the seventh should go out free, Deu 15:12. Compare Exo 21:2. And, if the year of jubilee happened before they served out their time, that would be their discharge. God\'s Israel were a free people,...', 'teologico');
add('dt', 15, 19, 'Matthew Henry', 'Here is, 1. A repetition of the law concerning the firstlings of their cattle, that, if they were males, they were to be sanctified to the Lord (Deu 15:19), in remembrance of, and in thankfulness for, the sparing of the first-born of Israel, when the first-born of the Egyptians, both of man and beast, were slain by the destroying angel (Exo 13:2, Exo 13:15); on the eighth day it was to be given to God (Exo 22:30), and to be divided between the priest and the altar, Num 18:17, Num 18:18. 2. An...', 'teologico');
add('dt', 16, 1, 'Matthew Henry', 'Much of the communion between God and his people Israel was kept up, and a face of religion preserved in the nation, by the three yearly feasts, the institution of which, and the laws concerning them, we have several times met with already; and here they are repeated.\nI. The law of the passover, so great a solemnity that it made the whole month, in the midst of which it was placed, considerable: Observe the month Abib, Deu 16:1. Though one week only of this month was to be kept as a festival,...', 'teologico');
add('dt', 16, 18, 'Matthew Henry', 'Here is, I. Care taken for the due administration of justice among them, that controversies might be determined, matters in variance adjusted, the injured redressed, and the injurious punished. While they were encamped in the wilderness, they had judges and officers according to their numbers, rulers of thousands and hundreds, Exo 18:25. When they came to Canaan, they must have them according to their towns and cities, in all their gates; for the courts of judgment sat in the gates. Now, 1. H...', 'teologico');
add('dt', 17, 1, 'Matthew Henry', 'Here is, I. A law for preserving the honour of God\'s worship, by providing that no creature that had any blemish should be offered in sacrifice to him, Deu 17:1. This caveat we have often met with: Thou shalt not sacrifice that which has any blemish, which renders it unsightly, or any evil matter or thing (as the following word night better be rendered), any sickness or weakness, though not discernible at first view; it is an abomination to God. God is the best of beings, and therefore whatso...', 'teologico');
add('dt', 17, 8, 'Matthew Henry', 'Courts of judgment were ordered to be erected in every city (Deu 16:18), and they were empowered to hear and determine causes according to law, both those which we call pleas of the crown and those between party and party; and we may suppose that ordinarily they ended the matters that were brought before them, and their sentence was definitive; but, 1. It is here taken for granted that sometimes a case might come into their court too difficult for those inferior judges to determine, who could...', 'teologico');
add('dt', 17, 14, 'Matthew Henry', 'After the laws which concerned subjects fitly followed the laws which concern kings; for those that rule others must themselves remember that they are under command. Here are laws given,\nI. To the electors of the empire, what rules they must go by in making their choice, Deu 17:14, Deu 17:15. 1. It is here supposed that the people would, in process of time, be desirous of a king, whose royal pomp and power would be thought to make their nation look great among their neighbours. Their having a...', 'teologico');
add('dt', 18, 1, 'Matthew Henry', 'Magistracy and ministry are two divine institutions of admirable use for the support and advancement of the kingdom of God among men. Laws concerning the former we had in the close of the foregoing chapter, directions are in this given concerning the latter. Land-marks are here set between the estates of the priests and those of the people.\nI. Care is taken that the priests entangle not themselves with the affairs of this life, nor enrich themselves with the wealth of this world; they have be...', 'teologico');
add('dt', 18, 9, 'Matthew Henry', 'One would not think there had been so much need as it seems there was to arm the people of Israel against the infection of the idolatrous customs of the Canaanites. Was it possible that a people so blessed with divine institutions should ever admit the brutish and barbarous inventions of men and devils? Were they in any danger of making those their tutors and directors in religion whom God had made their captives and tributaries? It seems they were in danger, and therefore, after many similar...', 'teologico');
add('dt', 18, 15, 'Matthew Henry', 'Here is, I. The promise of the great prophet, with a command to receive him, and hearken to him. Now,\n1. Some think it is the promise of a succession of prophets, that should for many ages be kept up in Israel. Besides the priests and Levites, their ordinary ministers, whose office it was to teach Jacob God\'s law, they should have prophets, extraordinary ministers, to reprove them for their faults, remind them of their duty, and foretel things to come, judgments for warning and deliverances f...', 'teologico');
add('dt', 19, 1, 'Matthew Henry', 'It was one of the precepts given to the sons of Noah that whoso sheddeth man\'s blood by man shall his blood be shed, that is, by the avenger of blood, Gen 9:6. Now here we have the law settled between blood and blood, between the blood of the murdered and the blood of the murderer, and effectual provision made,\nI. That the cities of refuge should be a protection to him that slew another casually, so that he should not die for that as a crime which was not his voluntary act, but only his unhap...', 'teologico');
add('dt', 19, 14, 'Matthew Henry', 'Here is a statute for the preventing of frauds and perjuries; for the divine law takes care of men\'s rights and properties, and has made a hedge about them. Such a friend is it to human society and men\'s civil interest.\nI. A law against frauds, Deu 19:14. 1. Here is an implicit direction given to the first planters of Canaan to fix land-marks, according to the distribution of the land to the several tribes and families by lot. Note, It is the will of God that every one should know his own, an...', 'teologico');
add('dt', 20, 1, 'Matthew Henry', 'Israel was at this time to be considered rather as a camp than as a kingdom, entering upon an enemy\'s country, and not yet settled in a country of their own; and, besides the war they were now entering upon in order to their settlement, even after their settlement they could neither protect nor enlarge their coast without hearing the alarms of war. It was therefore needful that they should have directions given them in their military affairs; and in these verses they are directed in managing,...', 'teologico');
add('dt', 20, 10, 'Matthew Henry', 'They are here directed what method to take in dealing with the cities (these only are mentioned, Deu 20:10, but doubtless the armies in the field, and the nations they had occasion to deal with, are likewise intended) upon which they made war. They must not make a descent upon any of their neighbours till they had first given them fair notice, by a public manifesto, or remonstrance, stating the ground of their quarrel with them. In dealing with the worst of enemies, the laws of justice and ho...', 'teologico');
add('dt', 21, 1, 'Matthew Henry', 'Care had been taken by some preceding laws for the vigorous and effectual persecution of a wilful murderer (Deu 19:11 etc.), the putting of whom to death was the putting away of the guilt of blood from the land; but if this could not be done, the murderer not being discovered, they must not think that the land was in no danger of contracting any pollution because it was not through any neglect of theirs that the murderer was unpunished; no, a great solemnity is here provided for the putting a...', 'teologico');
add('dt', 21, 10, 'Matthew Henry', 'By this law a soldier is allowed to marry his captive if he pleased. For the hardness of their hearts Moses gave them this permission, lest, if they had not had liberty given them to marry such, they should have taken liberty to defile themselves with them, and by such wickedness the camp would have been troubled. The man is supposed to have a wife already, and to take this wife for a secondary wife, as the Jews called them. This indulgence of men\'s inordinate desires, in which their hearts w...', 'teologico');
add('dt', 21, 15, 'Matthew Henry', 'This law restrains men from disinheriting their eldest sons out of mere caprice, and without just provocation.\nI. The case here put (Deu 21:15) is very instructive. 1. It shows the great mischief of having more wives than one, which the law of Moses did not restrain, probably in hopes that men\'s own experience of the great inconvenience of it in families would at last put an end to it and make them a law to themselves. Observe the supposition here: If a man have two wives, it is a thousand to...', 'teologico');
add('dt', 21, 18, 'Matthew Henry', 'Here is, I. A law for the punishing of a rebellious son. Having in the former law provided that parents should not deprive their children of their right, it was fit that it should next be provided that children withdraw not the honour and duty which are owing to their parents, for there is no partiality in the divine law. Observe,\n1. How the criminal is here described. He is a stubborn and rebellious son, Deu 21:18. No child was to fare the worse for the weakness of his capacity, the slowness...', 'teologico');
add('dt', 22, 1, 'Matthew Henry', 'The kindness that was commanded to be shown in reference to an enemy (Exo 23:4, etc.) is here required to be much more done for a neighbour, though he were not an Israelite, for the law is consonant to natural equity. 1. That strayed cattle should be brought back, either to the owner or to the pasture out of which they had gone astray, Deu 22:1, Deu 22:2. This must be done in pity to the very cattle, which, while they wandered, were exposed; and in civility and respect to the owner, nay, and ...', 'teologico');
add('dt', 22, 5, 'Matthew Henry', 'Here are several laws in these verses which seem to stoop very low, and to take cognizance of things mean and minute. Men\'s laws commonly do not so: De minimis non curat lex - The law takes no cognizance of little things; but because God\'s providence extends itself to the smallest affairs, his precepts do so, that even in them we may be in the fear of the Lord, as we are under his eye and care. And yet the significancy and tendency of these statutes, which seem little, are such that, notwiths...', 'teologico');
add('dt', 22, 13, 'Matthew Henry', 'These laws relate to the seventh commandment, laying a restraint by laying a penalty upon those fleshly lusts which war against the soul.\nI. If a man, lusting after another woman, to get rid of his wife slander her and falsely accuse her, as not having the virginity she pretended to when he married her, upon the disproof of his slander he must be punished, Deu 22:13-19. What the meaning of that evidence is by which the husband\'s accusation was to be proved false the learned are not agreed, no...', 'teologico');
add('dt', 23, 1, 'Matthew Henry', 'Interpreters are not agreed what is here meant by entering into the congregation of the Lord, which is here forbidden to eunuchs and to bastards, Ammonites and Moabites, for ever, but to Edomites and Egyptians only till the third generation. 1. Some think they are hereby excluded from communicating with the people of God in their religious services. Though eunuchs and bastards were owned as members of the church, and the Ammonites and Moabites might be circumcised and proselyted to the Jewish...', 'teologico');
add('dt', 23, 9, 'Matthew Henry', 'Israel was now encamped, and this vast army was just entering upon action, which was likely to keep them together for a long time, and therefore it was fit to give them particular directions for the good ordering of their camp. And the charge is in one word to be clean. They must take care to keep their camp pure from moral, ceremonial, and natural pollution.\nI. From moral pollution (Deu 23:9): When the host goes forth against thy enemy then look upon thyself as in a special manner engaged to...', 'teologico');
add('dt', 23, 15, 'Matthew Henry', 'Orders are here given about five several things which have no relation one to another: - \nI. The land of Israel is here made a sanctuary, or city of refuge, for servants that were wronged and abused by their masters, and fled thither for shelter from the neighbouring countries, Deu 23:15, Deu 23:16. We cannot suppose that they were hereby obliged to give entertainment to all the unprincipled men that ran from service; Israel needed not (as Rome at first did) to be thus peopled. But, 1. They m...', 'teologico');
add('dt', 24, 1, 'Matthew Henry', 'This is that permission which the Pharisees erroneously referred to as a precept, Mat 19:7, Moses commanded to give a writing of divorcement. It was not so; our Saviour told them that he only suffered it because of the hardness of their hearts, lest, if they had not had liberty to divorce their wives, they should have ruled them with rigour, and it may be, have been the death of them. It is probable that divorces were in use before (they are taken for granted, Lev 21:14), and Moses thought it...', 'teologico');
add('dt', 24, 5, 'Matthew Henry', 'Here is, I. Provision made for the preservation and confirmation of love between new-married people, Deu 24:5. This fitly follows upon the laws concerning divorce, which would be prevented if their affection to each other were well settled at first. If the husband were much abroad from his wife the first year, his love to her would be in danger of cooling, and of being drawn aside to others whom he would meet with abroad; therefore his service to his country in war, embassies, or other public...', 'teologico');
add('dt', 24, 14, 'Matthew Henry', 'Here, I. Masters are commanded to be just to their poor servants, Deu 24:14, Deu 24:15. 1. They must not oppress them, by overloading them with work, by giving them undue and unreasonable rebukes, or by withholding from them proper maintenance. A servant, though a stranger to the commonwealth of Israel, must not be abused: "For thou wast a bondman in the land where thou wast a stranger (Deu 24:18), and thou knowest what a grievous thing it is to be oppressed by a task-master, and therefore, i...', 'teologico');
add('dt', 25, 1, 'Matthew Henry', 'Here is, I. A direction to the judges in scourging malefactors, Deu 25:1-3. 1. It is here supposed that, if a man be charged with a crime, the accuser and the accused (Actor and Reus) should be brought face to face before the judges, that the controversy may be determined. 2. If a man were accused of a crime, and the proof fell short, so that the charge could not be made out against him by the evidence, then he was to be acquitted: "Thou shalt justify the righteous," that is, "him that appear...', 'teologico');
add('dt', 25, 5, 'Matthew Henry', 'Here is, I. The law settled concerning the marrying of the brother\'s widow. It appears from the story of Judah\'s family that this had been an ancient usage (Gen 38:8), for the keeping up of distinct families. The case put is a case that often happens, of a man\'s dying without issue, it may be in the prime of his time, soon after his marriage, and while his brethren were yet so young as to be unmarried. Now in this case, 1. The widow was not to marry again into any other family, unless all the...', 'teologico');
add('dt', 25, 13, 'Matthew Henry', 'Here is, I. A law against deceitful weights and measures: they must not only not use them, but they must not have them, not have them in the bag, not have them in the house (Deu 25:13, Deu 25:14); for, if they had them, they would be strongly tempted to use them. They must not have a great weight and measure to buy by and a small one to sell by, for that was to cheat both ways, when either was bad enough; as we read of those that made the ephah small, in which they measured the corn they sold...', 'teologico');
add('dt', 26, 1, 'Matthew Henry', 'Here is, I. A good work ordered to be done, and that is the presenting of a basket of their first-fruits to God every year, Deu 26:1, Deu 26:2. Besides the sheaf of first-fruits, which was offered for the whole land, on the morrow after the passover (Lev 23:10), every man was to bring for himself a basket of first-fruits at the feast of pentecost, when the harvest was ended, which is therefore called the feast of first-fruits (Exo 34:22), and is said to be kept with a tribute of free-will-off...', 'teologico');
add('dt', 26, 12, 'Matthew Henry', 'Concerning the disposal of their tithe the third year we had the law before, Deu 14:28, Deu 14:29. The second tithe, which in the other two years was to be spent in extraordinaries at the feasts, was to be spent the third year at home, in entertaining the poor. Now because this was done from under the eye of the priests, and a great confidence was put in the people\'s honesty, that they would dispose of it according to the law, to the Levite, the stranger, and the fatherless (Deu 26:12), it is...', 'teologico');
add('dt', 26, 16, 'Matthew Henry', 'Two things Moses here urges to enforce all these precepts: - 1. That they were the commands of God, Deu 26:16. They were not the dictates of his own wisdom, nor were they enacted by any authority of his own, but infinite wisdom framed them, and the power of the King of kings made them binding to them: "The Lord thy God commands thee, therefore thou art bound in duty and gratitude to obey him, and it is at thy peril if thou disobey. They are his laws, therefore thou shalt do them, for to that ...', 'teologico');
add('dt', 27, 1, 'Matthew Henry', 'Here is, I. A general charge to the people to keep God\'s commandments; for in vain did they know them, unless they would do them. This is pressed upon them, 1. With all authority. Moses with the elders of Israel, the rulers of each tribe (Deu 27:1), and again, Moses and the priests the Levites (Deu 27:9); so that the charge is given by Moses who was king in Jeshurun, and by their lords, both spiritual and temporal, in concurrence with him. Lest they should think that it was Moses only, an old...', 'teologico');
add('dt', 27, 11, 'Matthew Henry', 'When the law was written, to be seen and read by all men, the sanctions of it were to be published, which, to complete the solemnity of their covenanting with God, they were deliberately to declare their approbation of. This they were before directed to do (Deu 11:29, Deu 11:30), and therefore the appointment here begins somewhat abruptly, Deu 27:12. There were, it seems, in Canaan, that part of it which afterwards fell to the lot of Ephraim (Joshua\'s tribe), two mountains that lay near toget...', 'teologico');
add('dt', 28, 1, 'Matthew Henry', 'The blessings are here put before the curses, to intimate, 1. That God is slow to anger, but swift to show mercy: he has said it, and sworn, that he would much rather we would obey and live than sin and die. It is his delight to bless. 2. That though both the promises and the threatenings are designed to bring and hold us to our duty, yet it is better that we be allured to that which is good by a filial hope of God\'s favour than that we be frightened to it by a servile fear of his wrath. That...', 'teologico');
add('dt', 28, 15, 'Matthew Henry', 'Having viewed the bright side of the cloud, which is towards the obedient, we have now presented to us the dark side, which is towards the disobedient. If we do not keep God\'s commandments, we not only come short of the blessing promised, but we lay ourselves under the curse, which is as comprehensive of all misery as the blessing is of all happiness. Observe,\nI. The equity of this curse. It is not a curse causeless, nor for some light cause; God seeks not occasion against us, nor is he apt t...', 'teologico');
add('dt', 28, 45, 'Matthew Henry', 'One would have thought that enough had been said to possess them with a dread of that wrath of God which is revealed from heaven against the ungodliness and unrighteousness of men. But to show how deep the treasures of that wrath are, and that still there is more and worse behind, Moses, when one would have thought that he had concluded this dismal subject, begins again, and adds to this roll of curses many similar words: as Jeremiah did to his, Jer 36:32. It should seem that in the former pa...', 'teologico');
add('dt', 29, 1, 'Matthew Henry', 'Now that Moses had largely repeated the commands which the people were to observe as their part of the covenant, and the promises and threatenings which God would make good (according as they behaved themselves) as part of the covenant, the whole is here summed up in a federal transaction. The covenant formerly made is here renewed, and Moses, who was before, is still, the mediator of it (Deu 29:1): The Lord commanded Moses to make it. Moses himself, though king in Jeshurun, could not make th...', 'teologico');
add('dt', 29, 10, 'Matthew Henry', 'It appears by the length of the sentences here, and by the copiousness and pungency of the expressions, that Moses, now that he was drawing near to the close of his discourse, was very warm and zealous, and very desirous to impress what he said upon the minds of this unthinking people. To bind them the faster to God and duty, he here, with great solemnity of expression (to make up the want of the external ceremony that was used Exo 24:4 etc.), concludes a bargain (as it were) between them and...', 'teologico');
add('dt', 30, 1, 'Matthew Henry', 'These verses may be considered either as a conditional promise or as an absolute prediction.\nI. They are chiefly to be considered as a conditional promise, and so they belong to all persons and all people, and not to Israel only; and the design of them is to assure us that the greatest sinners, if they repent and be converted, shall have their sins pardoned, and be restored to God\'s favour. This is the purport of the covenant of grace, it leaves room for repentance in case of misdemeanour, an...', 'teologico');
add('dt', 30, 11, 'Matthew Henry', 'Moses here urges them to obedience from the consideration of the plainness and easiness of the command.\nI. This is true of the law of Moses. They could never plead in excuse of their disobedience that God had enjoined them that which was either unintelligible or impracticable, impossible to be known or to be done (Deu 30:11): It is not hidden from thee. That is, not send messengers to heaven (Deu 30:12), to enquire what thou must do to please God; nor needest thou go beyond sea (Deu 30:13), a...', 'teologico');
add('dt', 30, 15, 'Matthew Henry', 'Moses here concludes with a very bright light, and a very strong fire, that, if possible, what he had been preaching of might find entrance into the understanding and affections of this unthinking people. What could be said more moving, and more likely to make deep and lasting impressions? The manner of his treating with them is so rational, so prudent, so affectionate, and every way so apt to gain the point, that it abundantly shows him to be in earnest, and leaves them inexcusable in their ...', 'teologico');
add('dt', 31, 1, 'Matthew Henry', 'Loth to part (we say) bids oft farewell. Moses does so to the children of Israel: not because he was loth to go to God, but because he was loth to leave them, fearing that when he had left them they would leave God. He had finished what he had to say to them by way of counsel and exhortation: here he calls them together to give them a word of encouragement, especially with reference to the wars of Canaan, in which they were now to engage. It was a discouragement to them that Moses was to be r...', 'teologico');
add('dt', 31, 9, 'Matthew Henry', 'The law was given by Moses; so it is said, Joh 1:17. He was not only entrusted to deliver it to that generation, but to transmit it to the generations to come; and here it appears that he was faithful to that trust.\nI. Moses wrote this law, Deu 31:9. The learned bishop Patrick understands this of all the five books of Moses, which are often called the law; he supposes that though Moses had written most of the Pentateuch before, yet he did not finish it till now; now he put his last hand to th...', 'teologico');
add('dt', 31, 14, 'Matthew Henry', 'Here, I. Moses and Joshua are summoned to attend the divine majesty at the door of the tabernacle, Deu 31:14. Moses is told again that he must shortly die; even those that are most ready and willing to die have need to be often reminded of the approach of death. In consideration of this, he must come himself to meet God; for whatever improves our communion with God furthers our preparation for death. He must also bring Joshua with him to be presented to God for a successor, and to receive his...', 'teologico');
add('dt', 31, 22, 'Matthew Henry', 'Here, I. The charge is given to Joshua, which God has said (v. 14) he would give him. The same in effect that Moses had given him. The same in effect that Moses had given him (v. 7): Be strong and of a good courage, v. 23. Joshua had now heard from God so much of the wickedness of the people whom he was to have the conduct of as could not but be a discouragement to him: "Nay," says God, "how bad soever they are, thou shalt go through thy understanding, for I will be with thee. Thou shalt put ...', 'teologico');
add('dt', 32, 1, 'Matthew Henry', 'Here is, I. A commanding preface or introduction to this song of Moses, Deu 32:1, Deu 32:2. He begins, 1. With a solemn appeal to heaven and earth concerning the truth and importance of what he was about to say, and the justice of the divine proceedings against a rebellious and backsliding people, for he had said (Deu 31:28) that he would in this song call heaven and earth to record against them. Heaven and earth would sooner hear than this perverse and unthinking people; for they revolt not ...', 'teologico');
add('dt', 32, 7, 'Matthew Henry', 'Moses, having in general represented God to them as their great benefactor, whom they were bound in gratitude to observe and obey, in these verses gives particular instances of God\'s kindness to them and concern for them. 1. Some instances were ancient, and for proof of them he appeals to the records (Deu 32:7): Remember the days of old; that is, "Keep in remembrance the history of those days, and of the wonderful providences of God concerning the old world, and concerning your ancestors Abra...', 'teologico');
add('dt', 32, 15, 'Matthew Henry', 'We have here a description of the apostasy of Israel from God, which would shortly come to pass, and to which already they had a disposition. One would have thought that a people under so many obligations to their God, in duty, gratitude, and interest, would never have turned from him; but, alas! they turned aside quickly. Here are two great instances of their wickedness, and each of them amounted to an apostasy from God: - \nI. Security and sensuality, pride and insolence, and the other commo...', 'teologico');
add('dt', 32, 19, 'Matthew Henry', 'The method of this song follows the method of the predictions in the foregoing chapter, and therefore, after the revolt of Israel from God, described in the foregoing verses, here follow immediately the resolves of divine Justice concerning them; we deceive ourselves if we think that God will be thus mocked by a foolish faithless people, that play fast and loose with him.\nI. He had delighted in them, but now he would reject them with detestation and disdain, Deu 32:19. When the Lord saw their...', 'teologico');
add('dt', 32, 26, 'Matthew Henry', 'After many terrible threatenings of deserved wrath and vengeance, we have here surprising intimations of mercy, undeserved mercy, which rejoices against judgment, and by which it appears that God has no pleasure in the death of sinners, but would rather they should turn and live.\nI. In jealousy for his own honour, he will not make a full end of them, Deu 32:26-28. 1. It cannot be denied but that they deserved to be utterly ruined, and that their remembrance should be made to cease from among ...', 'teologico');
add('dt', 32, 39, 'Matthew Henry', 'This conclusion of the song speaks three things:\nI. Glory to God, Deu 32:39. "See now upon the whole matter, that I, even I, am he. Learn this from the destruction of idolaters, and the inability of their idols to help them." The great God here demands the glory, 1. Of a self-existence: I, even I, am he. Thus Moses concludes with that name of God by which he was first made to know him (Exo 3:14), "I am that I am. I am he that I have been, that I will be, that I have promised to be, that I hav...', 'teologico');
add('dt', 32, 44, 'Matthew Henry', 'Here is, I. The solemn delivery of this song to the children of Israel, Deu 32:44, Deu 32:45. Moses spoke it to as many as could hear him, while Joshua, in another assembly, at the same time, delivered it to as many as his voice would reach. Thus coming to them from the mouth of both their governors, Moses who was laying down the government, and Joshua who was taking it up, they would see they were both in the same mind, and that, though they changed their commander, there was no change in th...', 'teologico');
add('dt', 33, 1, 'Matthew Henry', 'The first verse is the title of the chapter: it is a blessing. In the foregoing chapter he had thundered out the terrors of the Lord against Israel for their sin; it was a chapter like Ezekiel\'s roll, full of lamentation, and mourning, and woe. Now to soften that, and that he might not seem to part in anger, he here subjoins a blessing, and leaves his peace, which should descend and rest upon all those among them that were the sons of peace. Thus Christ\'s last work on earth was to bless his d...', 'teologico');
add('dt', 33, 6, 'Matthew Henry', 'Here is, I. The blessing of Reuben. Though Reuben had lost the honour of his birthright, yet Moses begins with him; for we should not insult over those that are disgraced, nor desire to perpetuate marks of infamy upon any, though ever so justly fastened at first, Deu 33:6. Moses desires and foretels, 1. The preserving of this tribe. Though a frontier tribe on the other side Jordan, yet, "Let it live, and not be either ruined by its neighbours or lost among them." And perhaps he refers to thos...', 'teologico');
add('dt', 33, 8, 'Matthew Henry', 'In blessing the tribe of Levi, Moses expresses himself more at large, not so much because it was his own tribe (for he takes no notice of his relation to it) as because it was God\'s tribe. The blessing of Levi has reference.\nI. To the high priest, here called God\'s holy one (Deu 33:8), because his office was holy, in token of which, Holiness to the Lord was written upon his forehead. 1. He seems to acknowledge that God might justly have displaced Aaron and his seed, for his sin at Meribah, (E...', 'teologico');
add('dt', 33, 12, 'Matthew Henry', 'Here is, I. The blessing of Benjamin, Deu 33:12. Benjamin is put next to Levi, because the temple, where the priests\' work lay, was just upon the edge of the lot of this tribe; and it is put before Joseph because of the dignity of Jerusalem (part of which was in this tribe) above Samaria, which was in the tribe of Ephraim, and because Benjamin adhered to the house of David, and to the temple of the Lord, when the rest of the tribes deserted both with Jeroboam. 1. Benjamin is here called the b...', 'teologico');
add('dt', 33, 18, 'Matthew Henry', 'Here we have, I. The blessings of Zebulun and Issachar put together, for they were both the sons of Jacob by Leah, and by their lot in Canaan they were neighbours; it is foretold,\n1. That they should both have a comfortable settlement and employment, Deu 33:18. Zebulun must rejoice, for he shall have cause to rejoice; and Moses prays that he may have cause in his going out, either to war (for Zebulun jeoparded their lives in the high places of the field, Jdg 5:18), or rather to sea, for Zebul...', 'teologico');
add('dt', 33, 22, 'Matthew Henry', 'Here is, I. The blessing of Dan, Deu 33:22. Jacob in his blessing had compared him to a serpent for subtlety; Moses compares him to a lion for courage and resolution: and what could stand before those that had the head of a serpent and the heart of a lion? He is compared to the lions that leaped from Bashan, a mountain noted for fierce lions, whence they came down to leap upon their prey in the plains. This may refer either, 1. To the particular victories obtained by Samson (who was of this t...', 'teologico');
add('dt', 33, 26, 'Matthew Henry', 'These are the last words of all that ever Moses, that great writer, that great dictator, either wrote himself or had written from his dictation; they are therefore very remarkable, and no doubt we shall find them very improving. Moses, the man of God (who had as much reason as ever any mere man had to know both), with his last breath magnifies both the God of Israel and the Israel of God. They are both incomparable in his eye; and we are sure that in this his judgment of both his eye did not ...', 'teologico');
add('dt', 34, 1, 'Matthew Henry', 'Here is, I. Moses climbing upwards towards heaven, as high as the top of Pisgah, there to die; for that was the place appointed, Deu 32:49, Deu 32:50. Israel lay encamped upon the flat grounds in the plains of Moab, and thence he went up, according to order, to the mountain of Nebo, to the highest point or ridge of that mountain, which was called Pisgah, Deu 32:1. Pisgah is an appellative name for all such eminences. It should seem, Moses went up alone to the top of Pisgah, alone without help...', 'teologico');
add('dt', 34, 5, 'Matthew Henry', 'Here is, I. The death of Moses (Deu 34:5): Moses the servant of the Lord died. God told him he must not go over Jordan, and, though at first he prayed earnestly for the reversing of the sentence yet God\'s answer to his prayer sufficed him, and now he spoke no more of that matter, Deu 3:26. Thus our blessed Saviour prayed that the cup might pass from him, yet, since it might not, he acquiesced with, Father, thy will be done. Moses had reason to desire to live a while longer in the world. He wa...', 'teologico');
add('dt', 34, 9, 'Matthew Henry', 'We have here a very honourable encomium passed both on Moses and Joshua; each has his praise, and should have. It is ungrateful so to magnify our living friends as to forget the merits of those that are gone, to whose memories there is a debt of honour due: all the respect must not be paid to the rising sun; and, on the other hand, it is unjust so to cry up the merits of those that are gone as to despise the benefit we have in those that survive and succeed them. Let God be glorified in both,...', 'teologico');

// JS (71 comentários)
add('js', 1, 8, 'Joshua Harris', 'Não se aparte da tua boca — A meditação constante na Lei produz prosperidade espiritual e obediência.', 'aplicacao');
add('js', 1, 9, 'Spurgeon', 'Sê forte e corajoso — A coragem brota da presença de Deus, não da própria força.', 'teologico');
add('js', 24, 15, 'Matthew Henry', 'Escolhei hoje a quem servireis — A decisão de fé é pessoal e definitiva: não se pode servir a dois senhores.', 'aplicacao');
add('js', 1, 1, 'Matthew Henry', 'Honour is here put upon Joshua, and great power lodged in his hand, by him that is the fountain of honour and power, and by whom kings reign. Instructions are given him by Infinite Wisdom, and encouragements by the God of all consolation. God had before spoken to Moses concerning him (Num 27:18), but now he speaks to him (v. 1), probably as he spoke to Moses (Lev 1:1) out of the tabernacle of the congregation, where Joshua had with Moses presented himself (Deu 31:14), to learn the way of atte...', 'teologico');
add('js', 1, 10, 'Matthew Henry', 'Joshua, being settled in the government, immediately applies himself to business; not to take state or to take his pleasure, but to further the work of God among, the people over whom God had set him. As he that desires the office of a minister (Ti1 3:1), so he that desires the office of a magistrate, desires a work, a good work; neither is preferred to be idle.\nI. He issues out orders to the people to provide for a march; and they had been so long encamped in their present post that it would...', 'teologico');
add('js', 1, 16, 'Matthew Henry', 'This answer was given not by the two tribes and a half only (though they are spoken of immediately before), but by the officers of all the people (Jos 1:10), as their representatives, concurring with the divine appointment, by which Joshua was set over them, and they did it heartily, and with a great deal of cheerfulness and resolution.\nI. They promise him obedience (v. 16), not only as subjects to their prince, but as soldiers to their general, of whose particular orders they are to be obser...', 'teologico');
add('js', 2, 1, 'Matthew Henry', 'In these verses we have,\nI. The prudence of Joshua, in sending spies to observe this important pass, which was likely to be disputed at the entrance of Israel into Canaan (v. 1). Go view the land, even Jericho. Moses had sent spies (Num. 13) Joshua himself was one of them and it proved of ill consequence. Yet Joshua now sent spies, not, as the former were sent, to survey the whole land, but Jericho only; not to bring the account to the whole congregation, but to Joshua only, who, like a watch...', 'teologico');
add('js', 2, 8, 'Matthew Henry', 'The matter is here settled between Rahab and the spies respecting the service she was now to do for them, and the favour they were afterwards to show to her. She secures them on condition that they should secure her.\nI. She gives them, and by them sends to Joshua and Israel, all the encouragement that could be desired to make their intended descent upon Canaan. this was what they came for, and it was worth coming for. Having got clear of the officers, she comes up to them to the roof of the h...', 'teologico');
add('js', 2, 22, 'Matthew Henry', 'We have here the safe return of the spies Joshua had sent, and the great encouragement they brought with them to Israel to proceed in their descent upon Canaan. Had they been disposed to discourage the people, as the evil spies did that Moses sent, they might have told them what they had observed of the height and strength of the walls of Jericho, and the extraordinary vigilance of the king of Jericho, and how narrowly they escaped out of his hands; but they were of another spirit, and, depen...', 'teologico');
add('js', 3, 1, 'Matthew Henry', 'Rahab, in mentioning to the spies the drying up of the Red Sea (Jos 2:10), the report of which terrified the Canaanites more than anything else, intimates that those on that side the water expected that Jordan, that great defence of their country, would in like manner give way to them. Whether the Israelites had any expectation of it does not appear. God often did things for them which they looked not for, Isa 64:3. Now here we are told,\nI. That they came to Jordan and lodged there, Jos 3:1. ...', 'teologico');
add('js', 3, 7, 'Matthew Henry', 'We may observe here how God honours Joshua, and by this wondrous work he is about to do designs to make Israel know that he is their governor, and then how Joshua honours God and endeavours by it to make Israel know that he is their God. Thus those that honour God he will honour, and those whom he has advanced should do what they can in their places to exalt him.\nI. God speaks to Joshua to put honour upon him, v. 7, 8. 1. It was a great honour God id him that he spoke to him as he had done to...', 'teologico');
add('js', 3, 14, 'Matthew Henry', 'Here we have a short and plain account of the dividing of the river Jordan, and the passage of the children of Israel through it. The story is not garnished with the flowers of rhetoric (gold needs not to be painted), but it tell us, in short, matter of fact.\nI. That this river was now broader and deeper than usually it was at other times of the year, Jos 3:15. The melting of the snow on the mountains of Lebanon, near which this river had its rise, was the occasion that at the time of harvest...', 'teologico');
add('js', 4, 1, 'Matthew Henry', 'We may well imagine how busy Joshua and all the men of war were while they were passing over Jordan, when besides their own marching into an enemy\'s country, and in the face of the enemy, which could not but occasion them many thoughts of hear, they had their wives, and children, and families, their cattle, and tents, and all their effects, bag and baggage, to convey by this strange and untrodden path, which we must suppose either very muddy or very stony, troublesome to the weak and frightfu...', 'teologico');
add('js', 4, 10, 'Matthew Henry', 'The inspired historian seems to be so well pleased with his subject here that he is loth to quit it, and is therefore very particular in his narrative, especially in observing how closely Joshua pursued the orders God gave him, and that he did nothing without divine direction, finishing all that the Lord had commanded him (v. 10), which is also said to be what Moses commanded. We read not of any particular commands that Moses gave to Joshua about this matter: the thing was altogether new to h...', 'teologico');
add('js', 4, 20, 'Matthew Henry', 'The twelve stones which were laid down in Gilgal (Jos 4:8) are here set up either one upon another, yet so as that they might be distinctly counted, or one by another in rows; for after they were fixed they ar not call a heap of stones, but these stones.\nI. It is here taken for granted that posterity would enquire into the meaning of them, supposing them intended for a memorial: Your children shall ask their fathers (for who else should they ask?) What mean these stones? Notes, Those that wil...', 'teologico');
add('js', 5, 1, 'Matthew Henry', 'A vast show, no doubt, the numerous camp of Israel made in the plains of Jericho, where now they had pitched their tents. Who can count the dust of Jacob? That which had long been the church in the wilderness has now come up from the wilderness, leaning upon her beloved, and looks forth as the morning, fair as the moon, clear as the sun, and terrible as an army with banners. How terrible she was in the eyes of her enemies we are here told, Jos 5:1. How fair and clear she was made in the eyes ...', 'teologico');
add('js', 5, 10, 'Matthew Henry', 'We may well imagine that the people of Canaan were astonished, and that when they observed the motions of the enemy they could not but think them very strange. When soldiers take the field they are apt to think themselves excused from religious exercises (they have not time nor thought to attend to them), yet Joshua opens the campaign with one act of devotion after another. What was afterwards said to another Joshua might truly be said to this, Hear now, O Joshua! thou and thy fellows that si...', 'teologico');
add('js', 5, 13, 'Matthew Henry', 'We have hitherto found God often speaking to Joshua, but we read not till now of any appearance of God\'s glory to him; now that his difficulties increased his encouragements were increased in proportion. Observe,\nI. The time when he was favoured with this vision. It was immediately after he had performed the great solemnities of circumcision and the passover; then God made himself known to him. Note, We may then expect the discoveries of the divine grace when we are found in the way of our du...', 'teologico');
add('js', 6, 1, 'Matthew Henry', 'We have here a contest between God and the men of Jericho, and their different resolutions, upon which it is easy to say whose word shall prevail.\nI. Jericho resolves Israel shall not be its master, Jos 6:1. It was straitly shut up, because of the children of Israel. It did shut up, and it was shut up (so it is in the margin); it did shut up itself, being strongly fortified both by art and nature, and it was shut up by the obstinacy and resolution of the inhabitants, who agreed never to surre...', 'teologico');
add('js', 6, 6, 'Matthew Henry', 'We have here an account of the cavalcade which Israel made about Jericho, the orders Joshua gave concerning it, as he had received them from the Lord and their punctual observance of these orders. We do not find that he gave the people the express assurances God had given him that he would deliver the city into their hands; but he tried whether they would obey orders with a general confidence that it would end well, and we find them very observant both of God and Joshua.\nI. Wherever the ark w...', 'teologico');
add('js', 6, 17, 'Matthew Henry', 'The people had religiously observed the orders given them concerning the besieging of Jericho, and now at length Joshua had told them (Jos 6:16), "The Lord hath given you the city, enter and take possession." Accordingly in these verses we have,\nI. The rules they were to observe in taking possession. God gives it to them, and therefore may direct it to what uses and intents, and clog it with what provisos and limitations he thinks fit. It is given to them to be devoted to God, as the first an...', 'teologico');
add('js', 7, 1, 'Matthew Henry', 'The story of this chapter begins with a but. The Lord was with Joshua, and his fame was noised through all that country, so the foregoing chapter ends, and it left no room to doubt but that he would go on as he had begun conquering and to conquer. He did right, and observed his orders in every thing. But the children of Israel committed a trespass, and so set God against them; and then even Joshua\'s name and fame, his wisdom and courage, could do them no service. If we lose our God, we lose o...', 'teologico');
add('js', 7, 6, 'Matthew Henry', 'We have here an account of the deep concern Joshua was in upon this sad occasion. He, as a public person, interested himself more than any other in this public loss, and is therein an example to princes and great men, and teaches them to lay much to heart the calamities that befal their people: he is also a type of Christ, to whom the blood of his subjects is precious, Psa 72:14. Observe,\nI. How he grieved: He rent his clothes (Jos 7:6), in token of great sorrow for this public disaster, and ...', 'teologico');
add('js', 7, 10, 'Matthew Henry', 'We have here God\'s answer to Joshua\'s address, which, we may suppose, came from the oracle over the ark, before which Joshua had prostrated himself, v. 6. Those that desire to know the will of God must attend with their desires upon the lively oracles, and wait at wisdom\'s gates for wisdom\'s dictates, Pro 8:34. And let those that find themselves under the tokens of God\'s displeasure never complain of him, but complain to him, and they shall receive an answer of peace. The answer came immediat...', 'teologico');
add('js', 7, 16, 'Matthew Henry', 'We have in these verses,\nI. The discovery of Achan by the lot, which proved a perfect lot, though it proceeded gradually. Though we may suppose that Joshua slept the better, and with more ease and satisfaction, when he knew the worst of the disease of that body of which, under God, he was the head, and was put into a certain method of cure, yet he rose up early in the morning (Jos 7:16), so much was his heart upon it, to put away the accursed thing. We have found Joshua upon other occasions a...', 'teologico');
add('js', 8, 1, 'Matthew Henry', 'Israel were very happy in having such a commander as Joshua, but Joshua was more happy in having such a director as God himself; when any difficulty occurred, he needed not to call a council of war who had God so nigh unto him, not only to answer, but even to anticipate, his enquiries. It should seem, Joshua was now at a stand, had scarcely recovered the discomposure he was put into by the trouble Achan gave them, and could not think, without fear and trembling, of pushing forward, lest there...', 'teologico');
add('js', 8, 3, 'Matthew Henry', 'We have here an account of the taking of Ai by stratagem. The stratagem here used, we are sure, was lawful and good; God himself appointed it, and we have no reason to think but that the like is lawful and good in other wars. Here was no league broken, no treaty of peace, that the advantage was gained; no, these are sacred things, and not to be jested with, nor used to serve a turn; truth, when once it is plighted, becomes a debt even to the enemy. But in this stratagem here was no untruth to...', 'teologico');
add('js', 8, 23, 'Matthew Henry', 'We have here an account of the improvement which the Israelites made of their victory over Ai. 1. They put all to the sword, not only in the field, but in the city, man, woman, and child, none of them remained, Jos 8:24. God, the righteous Judge, had passed this sentence upon them for their wickedness, so that the Israelites were only the ministers of his justice and the executioners of his doom. Once in this story, and but once, mention is made of the men of Beth-el, as confederates with the...', 'teologico');
add('js', 8, 30, 'Matthew Henry', 'This religious solemnity of which we have here an account comes in somewhat surprisingly in the midst of the history of the wars of Canaan. After the taking of Jericho and Ai, we should have expected that the next news would be of their taking possession of the country, the pushing on of their victories in other cities, and the carrying of the war into the bowels of the nation, now that they had made themselves masters of these frontier towns. But here a scene opens of quite another nature; t...', 'teologico');
add('js', 9, 1, 'Matthew Henry', 'Hitherto the Canaanites had acted defensively; the Israelites were the aggressors upon Jericho and Ai. But here the kings of Canaan are in consultation to attack Israel, and concert matters for a vigorous effort of their united forces to check the progress of their victorious arms. Now, 1. It was strange they did not do this sooner. They had notice long since of their approach; Israel\'s design upon Canaan was no secret; one would have expected that a prudent concern for their common safety wo...', 'teologico');
add('js', 9, 3, 'Matthew Henry', 'Here, I. The Gibeonites desire to make peace with Israel, being alarmed by the tidings they heard of the destruction of Jericho, Jos 9:3. Other people heard those tidings, and were irritated thereby to make war upon Israel; but the Gibeonites heard them and were induced to make peace with them. Thus the discovery of the glory and grace of God in the gospel is to some a savour of life unto life, but to others a savour of death unto death, Co2 2:16. The same sun softens wax and hardens clay. I ...', 'teologico');
add('js', 9, 15, 'Matthew Henry', 'Here is, I. The treaty soon concluded with the Gibeonites, Jos 9:15. The thing was not done with much formality, but in short, 1. They agreed to let them live, and more the Gibeonites did not ask. In a common war this would have been but a small matter to be granted; but in the wars of Canaan, which were to make a general destruction, it was a great favour to a Canaanite to have his life given him for a prey, Jer 45:5. 2. This agreement was made not by Joshua only, but by the princes of the c...', 'teologico');
add('js', 9, 22, 'Matthew Henry', 'The matter is here settled between Joshua and the Gibeonites, and an explanation of the league agreed upon. We may suppose that now, not the messengers who were first sent, but the elders of Gibeon, and of the cities that were dependent upon it, were themselves present and treated with, that the matter might be fully compromised.\nI. Joshua reproves them for their fraud, Jos 9:22. And they excuse it as well as they can, Jos 9:24. 1. Joshua gives the reproof very mildly: Wherefore have you begu...', 'teologico');
add('js', 10, 1, 'Matthew Henry', 'Joshua and the hosts of Israel had now been a good while in the land of Canaan, and no great matters were effected; they were made masters of Jericho by a miracle, of Ai by stratagem, and of Gibeon by surrender, and that was all; hitherto the progress of their victories had not seemed proportionable to the magnificence of their entry and the glory of their beginnings. Those among them that were impatient of delays, it is probable, complained of Joshua\'s slowness, and asked why they did not im...', 'teologico');
add('js', 10, 7, 'Matthew Henry', 'Here, I. Joshua resolves to assist the Gibeonites, and God encourages him in this resolve. 1. He ascended from Gilgal (Jos 10:7), that is, he designed, determined, and prepared for, this expedition to relieve Gibeon, for it is probable it was before he stirred a step that God spoke to him to encourage him. It was generous and just in Joshua to help his new allies, though perhaps the king of Jerusalem, when he attacked them, little thought that Joshua would be so ready to help them, but expect...', 'teologico');
add('js', 10, 15, 'Matthew Henry', 'It was a brave appearance, no doubt, which the five kings made when they took the field for the reducing of Gibeon, and a brave army they had following them; but they were all routed, put into disorder first, and then brought to destruction by the hail-stones. And now Joshua thought, his work being done, he might go with his army into quarters of refreshment. Accordingly it was resolved, perhaps in a council of war, that they should presently return to the camp at Gilgal (Jos 10:15), till the...', 'teologico');
add('js', 10, 28, 'Matthew Henry', 'We are here informed how Joshua improved the late glorious victory he had obtained and the advantages he had gained by it, and to do this well is a general\'s praise.\nI. Here is a particular account of the several cities which he immediately made himself master of. 1. The cities of three of the kings whom he had conquered in the field he went and took possession of, Lachish (Jos 10:31, Jos 10:32), Eglon (Jos 10:34, Jos 10:35), and Hebron, Jos 10:36, Jos 10:37. The other two, Jerusalem and Jarm...', 'teologico');
add('js', 11, 1, 'Matthew Henry', 'We are here entering upon the story of another campaign that Joshua made, and it was a glorious one, no less illustrious than the former in the success of it, though in respect of miracles it was inferior to it in glory. The wonders God then wrought for them were to animate and encourage them to act vigorously themselves. Thus the war carried on by the preaching of the gospel against Satan\'s kingdom was at first forwarded by miracles; but, the war being by them sufficiently proved to be of Go...', 'teologico');
add('js', 11, 10, 'Matthew Henry', 'We have here the same improvement made of this victory as was made of that in the foregoing chapter. 1. The destruction of Hazor is particularly recorded, because in it, and by the king thereof, this daring design against Israel was laid, Jos 11:10, Jos 11:11. The king of Hazor, it seems, escaped with his life out of the battle, and thought himself safe when he had got back into his own city, and Joshua had gone in pursuit of the scattered troops another way. But it proved that that which he ...', 'teologico');
add('js', 11, 15, 'Matthew Henry', 'We have here the conclusion of this whole matter.\nI. A short account is here given of what was done in four things: - 1. The obstinacy of the Canaanites in their opposition to the Israelites. It was strange that though it appeared so manifestly that God fought for Israel, and in every engagement the Canaanites had the worst of it, yet they stood it out to the last; not one city made peace with Israel, but the Gibeonites only, who understood the things that belonged to their peace better than ...', 'teologico');
add('js', 12, 1, 'Matthew Henry', 'Joshua, or whoever else is the historian before he comes to sum up the new conquests Israel had made, in these verses receives their former conquests in Moses\'s time, under whom they became masters of the great and potent kingdoms of Sihon and Og. Note, Fresh mercies must not drown the remembrance of former mercies, nor must the glory of the present instruments of good to the church be suffered to eclipse and diminish the just honour of those who have gone before them, and who were the blessi...', 'teologico');
add('js', 12, 7, 'Matthew Henry', 'We have here a breviate of Joshua\'s conquests.\nI. The limits of the country he conquered. It lay between Jordan on the east and the Mediterranean Sea on the west, and extended from Baal-gad near Lebanon in the north to Halak, which lay upon the country of Edom in the south, v. 7. The boundaries are more largely described, Num 34:2, etc. But what is here said is enough to show that God had been as good as his word, and had given them possession of all he had promised them by Moses, if they wou...', 'teologico');
add('js', 13, 1, 'Matthew Henry', 'Here, I. God puts Joshua in mind of his old age, v. 1. 1. It is said that Joshua was old and stricken in years, and he and Caleb were at this time the only old men among the thousands of Israel, none except them of all those who were numbered at Mount Sinai being now alive. He had been a man of war from his youth (Exo 17:10); but now he yielded to the infirmities of age, with which it is in vain for the stoutest to think of contesting. It should seem Joshua had not the same strength and vigou...', 'teologico');
add('js', 13, 7, 'Matthew Henry', 'Here we have, I. Orders given to Joshua to assign to each tribe its portion of this land, including that which was yet unsubdued, which must be brought into the lot, in a believing confidence that it should be conquered when Israel was multiplied so as to have occasion for it (Jos 13:7): Now divide this land. Joshua thought all must be conquered before any must be divided. "No," said, God, "there is as much conquered as will serve your turn for the present; divide this, and make your best of ...', 'teologico');
add('js', 14, 1, 'Matthew Henry', 'The historian, having in the foregoing chapter given an account of the disposal of the countries on the other side Jordan, now comes to tell us what they did with the countries in the land of Canaan. They were not conquered to be left desert, a habitation for dragons, and a court for owls, Isa 34:13. No, the Israelites that had hitherto been closely encamped in a body, and the greatest part of them such as never knew any other way of living, must now disperse themselves to replenish these new...', 'teologico');
add('js', 14, 6, 'Matthew Henry', 'Before the lot was cast into the lap for the determining of the portions of the respective tribes, the particular portion of Caleb was assigned to him. He was now, except Joshua, not only the oldest man in all Israel, but was twenty years older than any of them, for all that were above twenty years old when he was forty were dead in the wilderness; it was fit therefore that this phoenix of his age should have some particular marks of honour put upon him in the dividing of the land. Now,\nI. Ca...', 'teologico');
add('js', 15, 1, 'Matthew Henry', 'Judah and Joseph were the two sons of Jacob on whom Reuben\'s forfeited birth-right devolved. Judah had the dominion entailed on him, and Joseph the double portion, and therefore these two tribes were first seated, Judah in the southern part of the land of Canaan and Joseph in the northern part, and on them the other seven did attend, and had their respective lots as appurtenances to these two; the lots of Benjamin, Simeon, and Dan, were appendant to Judah, and those of Issachar and Zebulun, N...', 'teologico');
add('js', 15, 13, 'Matthew Henry', 'The historian seems pleased with every occasion to make mention of Caleb and to do him honour, because he had honoured God in following him fully. Observe,\nI. The grant Joshua made him of the mountain of Hebron for his inheritance is here repeated (Jos 15:13), and it is said to be given him. 1. According to the commandment of the Lord to Joshua. Though Caleb, in his petition, had made out a very good title to it by promise, yet, because God had ordered Joshua to divide the land by lot, he wou...', 'teologico');
add('js', 15, 20, 'Matthew Henry', 'We have here a list of the several cities that fell within the lot of the tribe of Judah, which are mentioned by name, that they might know their own, and both keep it and keep to it, and might neither through cowardice nor sloth lose the possession of what was their own.\nI. The cities are here named, and numbered in several classes, which they then could account for the reason of better than we can now. Here are, 1. Some that are said to be the uttermost cities towards the coast of Edom, Jos...', 'teologico');
add('js', 16, 1, 'Matthew Henry', 'Though Joseph was one of the younger sons of Jacob, yet he was his eldest by his most just and best beloved wife Rachel, was himself his best beloved son, and had been the greatest ornament and support of his family, kept it from perishing in a time of famine, and had been the shepherd and stone of Israel, and therefore his posterity were very much favoured by the lot. Their portion lay in the very heart of the land of Canaan. It extended from Jordan in the east (Jos 16:1) to the sea, the Med...', 'teologico');
add('js', 16, 5, 'Matthew Henry', 'Here, 1. The border of the lot of Ephraim is set down, by which it was divided on the south from Benjamin and Dan, who lay between it and Judah, and on the north from Manasseh; for east and west it reached from Jordan to the great sea. The learned, who aim to be exact in drawing the line according to the directions here, find themselves very much at a loss, the description being short and intricate. The report of those who in these latter ages have travelled those countries will not serve to ...', 'teologico');
add('js', 17, 1, 'Matthew Henry', 'Manasseh was itself but one half of the tribe of Joseph, and yet was divided and subdivided. 1. It was divided into two parts, one already settled on the other side Jordan, consisting of those who were the posterity of Machir, Jos 17:1. This Machir was born to Manasseh in Egypt; there he had signalized himself as a man of war, probably in the contests between the Ephraimites and the men of Gath, Ch1 7:21. His warlike disposition descended to his posterity, and therefore Moses gave them Gileax...', 'teologico');
add('js', 17, 7, 'Matthew Henry', 'We have here a short account of the lot of this half tribe. It reached from Jordan on the east to the great sea on the west; on the south it lay all along contiguous to Ephraim, but on the north it abutted upon Asher and Issachar. Asher lay north-west, and Issachar north-east, which seems to be the meaning of that (Jos 17:10), that they (that is, Manasseh and Ephraim, as related to it, both together making the tribe of Joseph) met in Asher on the north and Issachar on the east, for Ephraim it...', 'teologico');
add('js', 17, 14, 'Matthew Henry', 'Here, I. The children of Joseph quarrel with their lot; if they had had any just cause to quarrel with it, we have reason to think Joshua would have relieved them, by adding to it, or altering it, which it does not appear he did. It is probable, because Joshua was himself of the tribe of Ephraim, they promised themselves that they should have some particular favour shown them, and should not be confined to the decision of the lot so closely as the other tribes; but Joshua makes them know that...', 'teologico');
add('js', 18, 1, 'Matthew Henry', 'In the midst of the story of the dividing of the land comes in this account of the setting up of the tabernacle, which had hitherto continued in its old place in the centre of their camp; but now that three of the four squadrons that used to surround it in the wilderness were broken and diminished, those of Judah, Ephraim, and Reuben, by the removal of those tribes to their respective possessions, and that of Dan only remained entire, it was time to think of removing the tabernacle itself int...', 'teologico');
add('js', 18, 2, 'Matthew Henry', 'Here, I. Joshua reproves those tribes which were yet unsettled that they did not bestir themselves to gain a settlement in the land which God had given them. Seven tribes were yet unprovided for, though sure of an inheritance, yet uncertain where it should be, and it seems in no great care about it, Jos 18:2. And with them Joshua reasons (Jos 18:3): How long are you slack? 1. They were too well pleased with their present condition, liked well enough to live in a body together, the more the me...', 'teologico');
add('js', 18, 11, 'Matthew Henry', 'We have here the lot of the tribe of Benjamin, which Providence cast next to Joseph on the one hand, because Benjamin was own and only brother to Joseph, and was little Benjamin (Psa 68:27), that needed the protection of great Joseph, and yet had a better protector, for the Lord shall cover him all the day long, Deu 33:12. And it was next to Judah on the other hand, that this tribe might hereafter unite with Judah in an adherence to the throne of David and the temple at Jerusalem. Here we hav...', 'teologico');
add('js', 19, 1, 'Matthew Henry', 'Simeon\'s lot was drawn after Judah\'s, Joseph\'s, and Benjamin\'s, because Jacob had put that tribe under disgrace; yet it is put before the two younger sons of Leah and the three sons of the handmaids. Not one person of note, neither judge nor prophet, was of this tribe, that we know of.\nI. The situation of their lot was within that of Judah (Jos 19:1) and was taken from it, Jos 19:9. It seems, those that first surveyed the land thought it larger than it was, and that it would have held out to ...', 'teologico');
add('js', 19, 10, 'Matthew Henry', 'This is the lot of Zebulun, who, though born of Leah after Issachar, yet was blessed by Jacob and Moses before him; and therefore it was so ordered that his lot was drawn before that of Issachar, north of which it lay and south of Asher. 1. The lot of this tribe was washed by the great sea on the west, and by the sea of Tiberias on the east, answering Jacob\'s prophecy (Gen 49:13), Zebulun shall be a haven of ships, trading ships on the great sea and fishing ships on the sea of Galilee. 2. Tho...', 'teologico');
add('js', 19, 17, 'Matthew Henry', 'The lot of Issachar ran from Jordan in the east to the great sea in the west, Manasseh on the south, and Zebulun on the north. A numerous tribe, Num 26:25. Tola, one of the judges, was of this tribe, Jdg 10:1. So was Baasha, one of the kings of Israel, Kg1 15:27. The most considerable places in this tribe were, 1. Jezreel, in which was Ahab\'s palace, and near it Naboth\'s vineyard. 2. Shunem, where lived that good Shunamite that entertained Elisha. 3. The river Kishon, on the banks of which, i...', 'teologico');
add('js', 19, 24, 'Matthew Henry', 'The lot of Asher lay upon the coast of the great sea. We read not of any famous person of this tribe but Anna the prophetess, who was a constant resident in the temple at the time of our Saviour\'s birth, Luk 2:36. Nor were there many famous places in this tribe. Aphek (mentioned Jos 19:30) was the place near which Benhadad was beaten by Ahad, Kg1 20:30. But close adjoining to this tribe were the celebrated sea-port towns of Tyre and Sidon, which we read so much of. Tyre is called here that st...', 'teologico');
add('js', 19, 32, 'Matthew Henry', 'Naphtali lay furthest north of all the tribes, bordering on Mount Libanus. The city of Leshem, or Liash, lay on the utmost edge of it to the north, and therefore when the Danites had made themselves masters of it, and called it Dan, the length of Canaan from north to south was reckoned from Dan to Beersheba. It had Zebulun on the south, Asher on the west, and Judah upon Jordan, probably a city of that name, and so distinguished from the tribe of Judah on the east. It was in the lot of this tr...', 'teologico');
add('js', 19, 40, 'Matthew Henry', 'Dan, though commander of one of the four squadrons of the camp of Israel, in the wilderness, that which brought up the rear, yet was last provided for in Canaan, and his lot fell in the southern part of Canaan, between Judah on the east and the land of the Philistines on the west, Ephraim on the north and Simeon on the south. Providence ordered this numerous and powerful tribe into a post of danger, as best able to deal with those vexatious neighbours the Philistines, and so it was found in S...', 'teologico');
add('js', 19, 49, 'Matthew Henry', 'Before this account of the dividing of the land is solemnly closed up, in the last verse, which intimates that the thing was done to the satisfaction of all, here is an account of the particular inheritance assigned to Joshua. 1. He was last served, though the eldest and greatest man of all Israel, and who, having commanded in the conquest of Canaan, might have demanded the first settlement in it for himself and his family. But he would make it to appear that in all he did he sought the good ...', 'teologico');
add('js', 20, 1, 'Matthew Henry', 'Many things were by the law of Moses ordered to be done when they came to Canaan and this among the rest, the appointing of sanctuaries for the protecting of those that were guilty of casual murder, which was a privilege to all Israel, since no man could be sure but some time or other it might be his own case; and it was for the interest of the land that the blood of an innocent person, whose hand only was guilty but not his heart, should not be shed, no, not by the avenger of blood: of this ...', 'teologico');
add('js', 20, 7, 'Matthew Henry', 'We have here the nomination of the cities of refuge in the land of Canaan, which was made by the advice and authority of Joshua and the princes (Jos 19:7); and upon occasion of the mention of this is repeated the nomination of the other three in the lot of the other two tribes and a half, which was made by Moses (Deu 4:43), but (as bishop Patrick thinks) they had not the privilege till now. 1. They are said to sanctify these cities, that is the original word for appointed, Jos 19:7. Not that ...', 'teologico');
add('js', 21, 1, 'Matthew Henry', 'Here is, I. The Levites\' petition presented to this general convention of the states, now sitting at Shiloh, Jos 21:1, Jos 21:2. Observe, 1. They had not their lot assigned them till they made their claim. There is an inheritance provided for all the saints, that royal priesthood, but then they must petition for it. Ask, and it shall be given you. Joshua had quickened the rest of the tribes who were slack to put in their claims, but the Levites, it may be supposed, knew their duty and interes...', 'teologico');
add('js', 21, 9, 'Matthew Henry', 'We have here a particular account of the cities which were given to the children of Levi out of the several tribes, not only to be occupied and inhabited by them, as tenants to the several tribes in which they lay - no, their interest in them was not dependent and precarious, but to be owned and possessed by them as lords and proprietors, and as having the same title to them that the rest of the tribes had to their cities or lands, as appears by the law which preserved the house in the Levite...', 'teologico');
add('js', 21, 43, 'Matthew Henry', 'We have here the conclusion of this whole matter, the foregoing history summed up, and, to make it appear the more bright, compared with the promise of which it was the full accomplishment. God\'s word and his works mutually illustrate each other. The performance makes the promise appear very true and the promise makes the performance appear very kind.\nI. God had promised to give the seed of Abraham the land of Canaan for a possession, and now at last he performed this promise (Jos 21:43): The...', 'teologico');
add('js', 24, 1, 'Matthew Henry', 'Joshua thought he had taken his last farewell of Israel in the solemn charge he gave them in the foregoing chapter, when he said, I go the way of all the earth; but God graciously continuing his life longer than expected, and renewing his strength, he was desirous to improve it for the good of Israel. He did not say, "I have taken my leave of them once, and let that serve;" but, having yet a longer space given him, he summons them together again, that he might try what more he could do to eng...', 'teologico');
add('js', 24, 29, 'Matthew Henry', 'This book, which began with triumphs, here ends with funerals, by which all the glory of man is stained. We have here 1. The burial of Joseph, Jos 24:32. He died about 200 years before in Egypt, but gave commandment concerning his bones, that they should not rest in their grave until Israel had rest in the land of promise; now therefore the children of Israel, who had brought this coffin full of bones with them out of Egypt, carried it along with them in all their marches through the wilderne...', 'teologico');

// JZ (74 comentários)
add('jz', 2, 18, 'Calvino', 'O Senhor se compadeceu — A misericórdia divina interrompe o ciclo de juízo quando o povo clama.', 'teologico');
add('jz', 21, 25, 'Agostinho', 'Cada um fazia o que era reto — A ausência de autoridade divina gera caos moral. Necessidade de Rei.', 'historico');
add('jz', 1, 1, 'Matthew Henry', 'Here, I. The children of Israel consult the oracle of God for direction which of all the tribes should first attempt to clear their country of the Canaanites, and to animate and encourage the rest. It was after the death of Joshua. While he lived he directed them, and all the tribes were obedient to him, but when he died he left no successor in the same authority that he had; but the people must consult the breast-plate of judgment, and thence receive the word of command; for God himself, as ...', 'teologico');
add('jz', 1, 9, 'Matthew Henry', 'We have here a further account of that glorious and successful campaign which Judah and Simeon made. 1. The lot of Judah was pretty well cleared of the Canaanites, yet not thoroughly. Those that dwelt in the mountain (the mountains that were round about Jerusalem) were driven out (Jdg 1:9, Jdg 1:19), but those in the valley kept their ground against them, having chariots of iron, such as we read of, Jos 17:16. Here the men of Judah failed, and thereby spoiled the influence which otherwise the...', 'teologico');
add('jz', 1, 21, 'Matthew Henry', 'We are here told upon what terms the rest of the tribes stood with the Canaanites that remained.\nI. Benjamin neglected to drive the Jebusites out of that part of the city of Jerusalem which fell to their lot, Jdg 1:21. Judah had set them a good example, and gained them great advantages by what they did (Jdg 1:9), but they did not follow the blow for want of resolution.\nII. The house of Joseph,\n1. Bestirred themselves a little to get possession of Beth-el, Jdg 1:22. That city is mentioned in t...', 'teologico');
add('jz', 2, 1, 'Matthew Henry', 'It was the privilege of Israel that they had not only a law in general sent them from heaven, once for all, to direct them into and keep them in the way of happiness, but that they had particular messages sent them from heaven, as there was occasion, for reproof, for correction, and for instruction in righteousness, when at any time they turned aside out of that way. Besides the written word which they had before them to read, they often heard a word behind them, saying, This is the way, Isa ...', 'teologico');
add('jz', 2, 6, 'Matthew Henry', 'The beginning of this paragraph is only a repetition of what account we had before of the people\'s good character during the government of Joshua, and of his death and burial (Jos 24:29, Jos 24:30), which comes in here again only to make way for the following account, which this chapter gives, of their degeneracy and apostasy. The angel had foretold that the Canaanites and their idols would be a snare to Israel; now the historian undertakes to show that they were so, and, that this may appear...', 'teologico');
add('jz', 3, 1, 'Matthew Henry', 'We are here told what remained of the old inhabitants of Canaan. 1. There were some of them that kept together in united bodies, unbroken (Jdg 3:3): The five lords of the Philistines, namely, Ashdod, Gaza, Askelon, Gath, and Ekron, Sa1 6:17. Three of these cities had been in part reduced (Jdg 1:18), but it seems the Philistines (probably with the help of the other two, which strengthened their confederacy with each other thenceforward) recovered the possession of them. These gave the greatest...', 'teologico');
add('jz', 3, 8, 'Matthew Henry', 'We now come to the records of the government of the particular judges, the first of which was Othniel, in whom the story of this book is knit to that of Joshua, for even in Joshua\'s time Othniel began to be famous, by which it appears that it was not long after Israel\'s settlement in Canaan before their purity began to be corrupted and their peace (by consequence) disturbed. And those who have taken pains to enquire into the sacred chronology are generally agreed that the Danites\' idolatry, a...', 'teologico');
add('jz', 3, 12, 'Matthew Henry', 'Ehud is the next of the judges whose achievements are related in this history, and here is an account of his actions.\nI. When Israel sins again God raises up a new oppressor, Jdg 3:12-14. It was an aggravation of their wickedness that they did evil again after they had smarted so long for their former iniquities, promised so fair when Othniel judged them, and received so much mercy from God in their deliverance. What, and after all this, again to break his commandments! Was the disease obstin...', 'teologico');
add('jz', 3, 31, 'Matthew Henry', 'When it is said the land had rest eighty years, some think it meant chiefly of that part of the land which lay eastward on the banks of Jordan, which had been oppressed by the Moabites; but it seems, by this passage here, that the other side of the country which lay south-west was in that time infested by the Philistines, against whom Shamgar made head. 1. It seems Israel needed deliverance, for he delivered Israel; how great the distress was Deborah afterwards related in her song (Jdg 5:6), ...', 'teologico');
add('jz', 4, 1, 'Matthew Henry', 'Here is, I. Israel backsliding from God: They again did evil in his sight, forsook his service, and worshipped idols; for this was the sin which now most easily beset them, Jdg 4:1. See in this, 1. The strange strength of corruption, which hurries men into sin notwithstanding the most frequent experience of its fatal consequences. The bent to backslide is with great difficulty restrained. 2. The common ill effects of a long peace. The land had rest eighty years, which should have confirmed th...', 'teologico');
add('jz', 4, 4, 'Matthew Henry', 'The year of the redeemed at length came, when Israel was to be delivered out of the hands of Jabin, and restored again to their liberty, which we may suppose the northern tribes, that lay nearest to the oppressors and felt most the effects of his fury, did in a particular manner cry to God for. For the oppression of the poor, and the sighing of the needy, now will God arise. Now here we have,\nI. The preparation of the people for their deliverance, by the prophetic conduct and government of De...', 'teologico');
add('jz', 4, 10, 'Matthew Henry', 'Here, I. Barak beats up for volunteers, and soon has his quota of men ready, Jdg 4:10. Deborah had appointed him to raise an army of 10,000 men (Jdg 4:6), and so many he has presently at his feet, following him, and subject to his command. God is said to call us to his feet (Isa 41:2), that is, into obedience to him. Some think it intimates that they were all footmen, and so the armies of the Jews generally were, which made the disproportion of strength between them and the enemy (who had hor...', 'teologico');
add('jz', 4, 17, 'Matthew Henry', 'We have seen the army of the Canaanites totally routed. It is said (Psa 83:9, Psa 83:10, where the defeat of this army is pleaded as a precedent for God\'s doing the like in after times) that they became as dung for the earth. Now here we have,\nI. The fall of their general, Sisera, captain of the host, in whom, it is likely, Jabin their king put an entire confidence, and therefore was not himself present in the action. Let us trace the steps of this mighty man\'s fall.\n1. He quitted his chariot...', 'teologico');
add('jz', 5, 1, 'Matthew Henry', 'The former chapter let us know what great things God had done for Israel; in this we have the thankful returns they made to God, that all ages of the church might learn that work of heaven to praise God.\nI. God is praised by a song, which is, 1. A very natural expression of rejoicing. Is any merry? Let him sing; and holy joy is the very soul and root of praise and thanksgiving. God is pleased to reckon himself glorified by our joy in him, and in his wondrous works. His servants\' joy is his de...', 'teologico');
add('jz', 5, 6, 'Matthew Henry', 'Here, I. Deborah describes the distressed state of Israel under the tyranny of Jabin, that the greatness of their trouble might make their salvation appear the more illustrious and the more gracious (Jdg 5:6): From the days of Shamgar, who did something towards the deliverance of Israel from the Philistines, to the days of Jael, the present day, in which Jael has so signalized herself, the country has been in a manner desolate. 1. No trade. For want of soldiers to protect men of business in t...', 'teologico');
add('jz', 5, 12, 'Matthew Henry', 'Here, I. Deborah stirs up herself and Barak to celebrate this victory in the most solemn manner, to the glory of God and the honour of Israel, for the encouragement of their friends and the greater confusion of their enemies, Jdg 5:12. 1. Deborah, as a prophetess, must do it by a song, to compose and sing which she excites herself: Awake, awake, and again, awake, awake, which intimates the sense she had of the excellency and difficulty of the work; it needed and well deserved the utmost livel...', 'teologico');
add('jz', 5, 24, 'Matthew Henry', 'Deborah here concludes this triumphant song,\nI. With the praises of Jael, her sister-heroine, whose valiant act had completed and crowned the victory. She had mentioned her before (Jdg 5:6) as one that would have served her country if it had been in her power; now she applauds her as one that did serve it admirably well when it was in her power. Her poetry is finest and most florid here in the latter end of the song. How honourably does she speak of Jael (Jdg 5:24), who preferred her peace wi...', 'teologico');
add('jz', 6, 1, 'Matthew Henry', 'We have here, I. Israel\'s sin renewed: They did evil in the sight of the Lord, Jdg 6:1. The burnt child dreads the fire; yet this perverse unthinking people, that had so often smarted sorely for their idolatry, upon a little respite of God\'s judgments return to it again. This people hath a revolting rebellious heart, not kept in awe by the terror of God\'s judgments, nor engaged in honour and gratitude by the great things he had done for them to keep themselves in his love. The providence of G...', 'teologico');
add('jz', 6, 7, 'Matthew Henry', 'Observe here, I. The cognizance God took of the cries of Israel, when at length they were directed towards him. Though in their prosperity they had neglected him and made court to his rivals, and though they never looked towards him until they were driven to it by extremity, yet, upon their complain and prayer, he intended relief for them. Thus would he show how ready he is to forgive, how swift he is to show mercy, and how inclinable to hear prayer, that sinners may be encouraged to return a...', 'teologico');
add('jz', 6, 11, 'Matthew Henry', 'It is not said what effect the prophet\'s sermon had upon the people, but we may hope it had a good effect, and that some of them at least repented and reformed upon it; for here, immediately after, we have the dawning of the day of their deliverance, by the effectual calling of Gideon to take upon him the command of their forces against the Midianites.\nI. The person to be commissioned for this service was Gideon, the son of Joash, Jdg 6:14. The father was now living, but he was passed by, and...', 'teologico');
add('jz', 6, 25, 'Matthew Henry', 'Here, I. Orders are given to Gideon to begin his government with the reformation of his father\'s house, Jdg 6:25, Jdg 6:26. A correspondence being settled between God and Gideon, by the appearance of the angel to him, it was kept up in another way; the same night after he had seen God, when he was full of thoughts concerning what had passed, which probably he had not yet communicated to any, The Lord said unto him in a dream, Do so and so. Note, God\'s visits, if gratefully received, shall be ...', 'teologico');
add('jz', 6, 33, 'Matthew Henry', 'Here we have, I. The descent which the enemies of Israel made upon them, Jdg 6:33. A vast number of Midianites, Amalekites, and Arabians, got together, and came over Jordan, none either caring or daring to guard that important and advantageous pass against them, and they made their headquarters in the valley of Jezreel, in the heart of Manasseh\'s tribe, not far from Gideon\'s city. Some think that the notice they had of Gideon\'s destroying Baal\'s altar brought them over, and that they came to ...', 'teologico');
add('jz', 7, 1, 'Matthew Henry', 'Here, I. Gideon applies himself with all possible care and industry to do the part of a good general, in leading on the hosts of Israel against the Midianites (Jdg 7:1): He rose up early, as one whose heart was upon his business, and who was afraid of losing time. Now that he is sure God is with him he is impatient of delay. He pitched near a famous well, that his army might not be distressed for want of water, and gained the higher ground, which possibly might be some advantage to him, for t...', 'teologico');
add('jz', 7, 9, 'Matthew Henry', 'Gideon\'s army being diminished as we have found it was, he must either fight by faith or not at all; God therefore here provides recruits for his faith, instead of recruits for his forces.\nI. He furnishes him with a good foundation to build his faith upon. Nothing but a word from God will be a footing for faith. He has this as full and express as he can desire, Jdg 7:9. 1. A word of command to warrant the action, which otherwise seemed rash and indiscreet, and unbecoming a wise general: Arise...', 'teologico');
add('jz', 7, 16, 'Matthew Henry', 'Here is, I. The alarm which Gideon gave to the hosts of Midian in the dead time of the night; for it was intended that those who had so long been a terror to Israel, and had so often frightened them, should themselves be routed and ruined purely by terror.\n1. The attack here made was, in many circumstances, like that which Abraham made upon the army that had taken Lot captive. The number of men was much the same: Abraham had 318, Gideon 300; they both divided their forces, both made their att...', 'teologico');
add('jz', 7, 23, 'Matthew Henry', 'We have here the prosecution of this glorious victory. 1. Gideon\'s soldiers that had been dismissed, and perhaps had begun to disperse themselves, upon notice of the enemies\' flight got together again, and vigorously pursued those whom they had not courage to face. The men of Israel out of Naphtali and Asher who did this (Jdg 7:23) were not such as now came from those distant countries, but the same that had enlisted themselves (Jdg 6:35), but had been cashiered. Those who were fearful and af...', 'teologico');
add('jz', 8, 1, 'Matthew Henry', 'No sooner were the Midianites, the common enemy, subdued, than, through the violence of some hot spirits, the children of Israel were ready to quarrel among themselves; an unhappy spark was struck, which, if Gideon had not with a great deal of wisdom and grace extinguished immediately, might have broken out into a flame of fatal consequence. The Ephraimites, when they brought the heads of Oreb and Zeeb to Gideon as general, instead of congratulating him upon his successes and addressing him w...', 'teologico');
add('jz', 8, 4, 'Matthew Henry', 'In these verses we have,\nI. Gideon, as a valiant general, pursuing the remaining Midianites, and bravely following his blow. A very great slaughter was made of the enemy at first: 120,000 men that drew the sword, Jdg 8:10. Such a terrible execution did they make among themselves, and so easy a prey were they to Israel. But, it seems, the two kings of Midian, being better provided than the rest for an escape, with 15,000 men got over Jordan before the passes could be secured by the Ephraimites...', 'teologico');
add('jz', 8, 18, 'Matthew Henry', 'Judgment began at the house of God, in the just correction of the men of Succoth and Penuel, who were Israelites, but it did not end there. The kings of Midian, when they had served to demonstrate Gideon\'s victories, and grace his triumphs, must now be reckoned with. 1. They are indicted for the murder of Gideon\'s brethren some time ago at Mount Tabor. When the children of Israel, for fear of the Midianites, made themselves dens in the mountains (Jdg 6:2), those young men, it is likely, took ...', 'teologico');
add('jz', 8, 22, 'Matthew Henry', 'Here is, I. Gideon\'s laudable modesty, after his great victory, in refusing the government which the people offered him. 1. It was honest in them to offer it: Rule thou over us, for thou hast delivered us, Jdg 8:22. They thought it very reasonable that he who had gone through the toils and perils of their deliverance should enjoy the honour and power of commanding them ever afterwards, and very desirable that he who in this great and critical juncture had had such manifest tokens of God\'s pre...', 'teologico');
add('jz', 8, 29, 'Matthew Henry', 'We have here the conclusion of the story of Gideon. 1. He lived privately, Jdg 8:29. He was not puffed up with his great honours, did not covet a palace or castle to dwell in, but retired to the house he had lived in before his elevation. Thus that brave Roman Who was called from the plough upon a sudden occasion to command the army when the action was over returned to his plough again. 2. His family was multiplied. He had many wives (therein he transgressed the law); by them he had seventy s...', 'teologico');
add('jz', 9, 1, 'Matthew Henry', 'We are here told by what arts Abimelech got into authority, and made himself great. His mother perhaps had instilled into his mind some towering ambitious thoughts, and the name his father gave him, carrying royalty in it, might help to blow up these sparks; and now that he has buried his father nothing will serve his proud spirit but he will succeed him in the government of Israel, directly contrary to his father\'s will, for he had declared no son of his should rule over them. He had no call...', 'teologico');
add('jz', 9, 7, 'Matthew Henry', 'We have here the only testimony that appears to have been borne against the wicked confederacy of Abimelech and the men of Shechem. It was a sign they had provoked God to depart from them that neither any prophet was sent nor any remarkable judgment, to awaken this stupid people, and to stop the progress of this threatening mischief. Only Jotham, the youngest son of Gideon, who by a special providence escaped the common ruin of his family (Jdg 9:5), dealt plainly with the Shechemites, and his...', 'teologico');
add('jz', 9, 22, 'Matthew Henry', 'Three years Abimelech reigned, after a sort, without any disturbance; it is not said, He judged Israel, or did any service at all to his country, but so long he enjoyed the title and dignity of a king; and not only the Shechemites, but many other places, paid him respect. They must have been fond of a king that could please themselves with such a one as this. But the triumphing of the wicked is short. Within three years, as the years of a hireling, all this glory shall be contemned, and laid ...', 'teologico');
add('jz', 9, 50, 'Matthew Henry', 'We have seen the ruin of the Shechemites completed by the hand of Abimelech; and now it comes to his turn to be reckoned with who was their leader in villany. Thebez was a small city, probably not far from Shechem, dependent upon it, and in confederacy with it. Now,\nI. Abimelech attempted the destruction of this city (Jdg 9:50), drove all the inhabitants of the town into the castle, or citadel, Jdg 9:51. When he had them there he did not doubt but he should do the same execution here that he ...', 'teologico');
add('jz', 10, 1, 'Matthew Henry', 'Quiet and peaceable reigns, though the best to live in, are the worst to write of, as yielding least variety of matter for the historian to entertain his reader with; such were the reigns of these two judges, Tola and Jair, who make but a small figure and take up but a very little room in this history. But no doubt they were both raised up of God to serve their country in the quality of judges, not pretending, as Abimelech had done, to the grandeur of kings, nor, like him, taking the honour t...', 'teologico');
add('jz', 10, 6, 'Matthew Henry', 'While those two judges, Tola and Jair, presided in the affairs of Israel, things went well, but afterwards,\nI. Israel returned to their idolatry, that sin which did most easily beset them (Jdg 10:6): They did evil again in the sight of the Lord, from whom they were unaccountably bent to backslide, as a foolish people and unwise. 1. They worshipped many gods; not only their old demons Baalim and Ashtaroth, which the Canaanites had worshipped, but, as if they would proclaim their folly to all t...', 'teologico');
add('jz', 10, 10, 'Matthew Henry', 'Here is, I. A humble confession which Israel make to God in their distress, Jdg 10:10. Now they own themselves guilty, like a malefactor upon the rack, and promise reformation, like a child under the rod. They not only complain of the distress, but acknowledge it is their own sin that has brought them into the distress; therefore God is righteous, and they have no reason to repine. They confess their omissions, for in them their sin began - "We have forsaken our God," and their commissions - ...', 'teologico');
add('jz', 11, 1, 'Matthew Henry', 'The princes and people of Gilead we left, in the close of the foregoing chapter, consulting about the choice of a general, having come to this resolve, that whoever would undertake to lead their forces against the children of Ammon should by common consent be head over all the inhabitants of Gilead. The enterprise was difficult, and it was fit that so great an encouragement as this should be proposed to him that would undertake it. Now all agreed that Jephthah, the Gileadite, was a mighty man...', 'teologico');
add('jz', 11, 4, 'Matthew Henry', 'Here is, I. The distress which the children of Israel were in upon the Ammonites\' invasion of their country, Jdg 11:4. Probably this was the same invasion with that mentioned, Jdg 10:17, when the children of Ammon were gathered together and encamped in or against Gilead. And those words, in process of time, refer to what goes immediately before of the expulsion of Jephthah; many days after he had been thus thrust out in disgrace was he fetched back again with honour.\nII. The court which the e...', 'teologico');
add('jz', 11, 12, 'Matthew Henry', 'We have here the treaty between Jephthah, now judge of Israel, and the king of the Ammonites (who is not named), that the controversy between the two nations might, if possible, be accommodated without the effusion of blood.\nI. Jephthah, as one having authority, sent to the king of Ammon, who in this war was the aggressor, to demand his reasons for invading the land of Israel: "Why hast thou come to fight against me in my land? Jdg 11:12. Had I come first into thy land to disturb thee in thy ...', 'teologico');
add('jz', 11, 29, 'Matthew Henry', 'We have here Jephthah triumphing in a glorious victory, but, as an alloy to his joy, troubled and distressed by an unadvised vow.\nI. Jephthah\'s victory was clear, and shines very brightly, both to his honour and to the honour of God, his in pleading and God\'s in owning a righteous cause. 1. God gave him an excellent spirit, and he improved it bravely, Jdg 11:29. When it appeared by the people\'s unanimous choice of him for their leader that he had so clear a call to engage, and by the obstinat...', 'teologico');
add('jz', 12, 1, 'Matthew Henry', 'Here Is, I. The unreasonable displeasure of the men of Ephraim against Jephthah, because he had not called them in to his assistance against the Ammonites, that they might share in the triumphs and spoils, Jdg 12:1. Pride was at the bottom of the quarrel. Only by that comes contention. Proud men think all the honours lost that go beside themselves, and then who can stand before envy? The Ephraimites had the same quarrel with Gideon (Jdg 8:1), who was of Manasseh on their side Jordan, as Jepht...', 'teologico');
add('jz', 12, 8, 'Matthew Henry', 'We have here a short account of the short reigns of three more of the judges of Israel, the first of whom governed but seven years, the second ten, and the third eight. For the transgression of a land, many are the princes thereof, many in a short time, successively (Pro 28:2), good men being removed in the beginning of their usefulness and by the time that they have applied themselves to their business.\nI. Ibzan of Bethlehem, most probably Bethlehem of Judah, David\'s city, not that in Zebulu...', 'teologico');
add('jz', 13, 1, 'Matthew Henry', 'The first verse gives us a short account, such as we have too often met with already, of the great distress that Israel was in, which gave occasion for the raising up of a deliverer. They did evil, as they had done, in the sight of the Lord, and then God delivered them, as he had done, into the hands of their enemies. If there had been no sin, there would have needed no Saviour; but sin was suffered to abound, that grace might much more abound. The enemies God now sold them to were the Philis...', 'teologico');
add('jz', 13, 8, 'Matthew Henry', 'We have here an account of a second visit which the angel of God made to Manoah and his wife.\nI. Manoah earnestly prayed for it, Jdg 13:8. He was not incredulous of the story his wife told him; he knew she was a virtuous woman, and therefore the heart of her husband did safely trust in her; he knew she would not go about to impose upon him, much less was he, as Josephus unworthily represents him, jealous of his wife\'s conversation with this stranger; but, 1. He takes it for granted that this ...', 'teologico');
add('jz', 13, 15, 'Matthew Henry', 'We have here an account,\nI. Of what further passed between Manoah and the angel at this interview. It was in kindness to him that while the angel was with him it was concealed from him that he was an angel; for, had he known it, it would have been such a terror to him that he durst not have conversed with him as he did (Jdg 13:16): He knew not that he was an angel. So Christ was in the world, and the world knew him not. Verily thou art a God that hidest thyself. We could not bear the sight of...', 'teologico');
add('jz', 13, 24, 'Matthew Henry', 'Here is, 1. Samson\'s birth. The woman that had been long barren bore a son, according to the promise; for no word of God shall fall to the ground. Hath he spoken, and shall he not make it good? 2. His name, Samson, has been derived by some, from Shemesh, the sun, turned into a diminutive, sol exiguus - the sun in miniature, perhaps because, being born like Moses to be a deliverer, he was like him exceedingly fair, his face shone like a little sun; or his parents so named him in remembrance of...', 'teologico');
add('jz', 14, 1, 'Matthew Henry', 'Here, I. Samson, under the extraordinary guidance of Providence, seeks an occasion of quarrelling with the Philistines, by joining in affinity with them - a strange method, but the truth is Samson was himself a riddle, a paradox of a man, did that which was really great and good, by that which was seemingly weak and evil, because he was designed not to be a pattern to us (who must walk by rule, not by example), but a type of him who, though he knew no sin, was made sin for us, and appeared in...', 'teologico');
add('jz', 14, 10, 'Matthew Henry', 'We have here an account of Samson\'s wedding feast and the occasion it gave him to fall foul upon the Philistines.\nI. Samson conformed to the custom of the country in making a festival of his nuptial solemnities, which continued seven days, Jdg 14:10. Though he was a Nazarite, he did not affect, in a thing of this nature, to be singular, but did as the young men used to do upon such occasions. It is no part of religion to go contrary to the innocent usages of the places where we live: nay, it ...', 'teologico');
add('jz', 15, 1, 'Matthew Henry', 'Here is, I. Samson\'s return to his wife, whom he had left in displeasure; not hearing perhaps that she was given to another, when time had a little cooled his resentments, he came back to her, visited her with a kid, Jdg 15:1. The value of the present was inconsiderable, but it was intended as a token of reconciliation, and perhaps was then so used, when those that had been at variance were brought together again; he sent this, that he might sup with her in her apartments, and she with him, o...', 'teologico');
add('jz', 15, 9, 'Matthew Henry', 'Here is, I. Samson violently pursued by the Philistine. They went up in a body, a more formidable force than they had together when Samson smote them hip and thigh; and they pitched in Judah, and spread themselves up and down the country, to find out Samson, who they heard had come this way, Jdg 15:9. When the men of Judah, who had tamely submitted to their yoke, pleaded that they had paid their tribute, and that none of their tribe had given them any offence, they freely own they designed no...', 'teologico');
add('jz', 15, 18, 'Matthew Henry', 'Here is, I. The distress which Samson was in after this great performance (Jdg 15:18): He was sore athirst. It was a natural effect of the great heat he had been in, and the great pains he had taken; his zeal consumed him, ate him up, and made him forget himself, till, when he had time to pause a little, he found himself reduced to the last extremity for want of water and ready to faint. Perhaps there was a special hand of God in it, as there was in the whole transaction; and God would hereby...', 'teologico');
add('jz', 16, 1, 'Matthew Henry', 'Here is, 1. Samson\'s sin, Jdg 16:1. His taking a Philistine to wife, in the beginning of his time, was in some degree excusable, but to join himself to a harlot that he accidentally saw among them was such a profanation of his honour as an Israelite, as a Nazarite, that we cannot but blush to read it. Tell it not in Gath. This vile impurity makes the graceful visage of this Nazarite blacker than a coal, Lam 4:7, Lam 4:8. We find not that Samson had any business in Gaza; if he went thither in ...', 'teologico');
add('jz', 16, 4, 'Matthew Henry', 'The burnt child dreads the fire; yet Samson, that has more than the strength of a man, in this comes short of the wisdom of a child; for, though he had been more than once brought into the highest degree of mischief and danger by the love of women and lusting after them, yet he would not take warning, but is here again taken in the same snare, and this third time pays for all. Solomon seems to refer especially to this story of Samson when, in his caution against uncleanness, he gives this acc...', 'teologico');
add('jz', 16, 18, 'Matthew Henry', 'We have here the fatal consequences of Samson\'s folly in betraying his own strength; he soon paid dearly for it. A whore is a deep ditch; he that is abhorred of the Lord shall fall therein. In that pit Samson sinks. Observe, 1. What care Delilah took to make sure of the money for herself. She now perceived, by the manner of his speaking, that he had told her all his heart, and the lords of the Philistines that hired her to do this base thing are sent for; but they must be sure to bring the mo...', 'teologico');
add('jz', 16, 22, 'Matthew Henry', 'Though the last stage of Samson\'s life was inglorious, and one could wish there were a veil drawn over it, yet this account here given of his death may be allowed to lessen, though it does not quite roll away, the reproach of it; for there was honour in his death. No doubt he greatly repented of his sin, the dishonour he had by it done to God and his forfeiture of the honour God had put upon him; for that God was reconciled to him appears, 1. By the return of the sign of his Nazariteship (Jdg...', 'teologico');
add('jz', 17, 1, 'Matthew Henry', 'Here we have, I. Micah and his mother quarrelling. 1. The son robs the mother. The old woman had hoarded, with long scraping and saving, a great sum of money, 1100 pieces of silver. It is likely she intended, when she died, to leave it to her son: in the mean time it did her good to look upon it, and to count it over. The young man had a family of children grown up, for he had one of age to be a priest, Jdg 17:5. He knows where to find his mother\'s cash, thinks he has more need of it than she...', 'teologico');
add('jz', 17, 7, 'Matthew Henry', 'We have here an account of Micah\'s furnishing himself with a Levite for his chaplain, either thinking his son, because the heir of his estate, too good to officiate, or rather, because not of God\'s tribe, not good enough. Observe,\nI. What brought this Levite to Micah. By his mother\'s side he was of the family of Judah, and lived at Bethlehem among his mother\'s relations (for that was not a Levites\' city), or, upon some other account, as a stranger or inmate, sojourned there, Jdg 17:7. Thence ...', 'teologico');
add('jz', 18, 1, 'Matthew Henry', 'Here is, 1. The eye which these Danites had upon Laish, not the whole tribe of Dan, but one family of them, to whose lot, in the subdivision of Canaan, that city fell. Hitherto this family had sojourned with their brethren, who had taken possession of their lot, which lay between Judah and the Philistines, and had declined going to their own city, because there was no king in Israel to rule over them, Jdg 18:1. It lay a great way off, separate from the rest of their tribe; it was entirely in ...', 'teologico');
add('jz', 18, 7, 'Matthew Henry', 'Here is, I. The observation which the spies made upon the city of Laish, and the posture of its inhabitants, Jdg 18:7. Never was place so ill governed and so ill guarded, which would make it a very easy prey to the invader.\n1. It was ill governed, for every man might be as bad as he would, and there was no magistrate, no heir of restraint (as the word is), that might so much as put them to shame in any thing, much less put them to death, so that by the most impudent immoralities they provoked...', 'teologico');
add('jz', 18, 14, 'Matthew Henry', 'The Danites had sent out their spies to find out a country for them, and they sped well in their search; but here, now that they came to the place (for till this brought it to their mind it does not appear that they had mentioned it to their brethren), they oblige them with a further discovery - they can tell them where there are gods: "Here, in these houses, there are an ephod, and teraphim, and a great many fine things for devotion, such as we have not the like in our country; now therefore...', 'teologico');
add('jz', 18, 27, 'Matthew Henry', 'Here is, I. Laish conquered by the Danites. They proceeded on their march, and, because they met with no disaster, perhaps concluded they had not done amiss in robbing Micah. Many justify themselves in their impiety by their prosperity. Observe, 1. What posture they found the people of Laish in, both those of the city and those of the country about. They were quiet and secure, not jealous of the five spies that had been among them to search out the land, nor had they any intelligence of the a...', 'teologico');
add('jz', 19, 1, 'Matthew Henry', 'The domestic affairs of this Levite would not have been related thus largely but to make way for the following story of the injuries done him, in which the whole nation interested themselves. Bishop Hall\'s first remark upon this story is, That there is no complain of a public ordered state but there is a Levite at one end of it, either as an agent or as a patient. In Micah\'s idolatry a Levite was active; in the wickedness of Gibeah a Levite was passive; no tribe shall sooner feel the want of ...', 'teologico');
add('jz', 19, 16, 'Matthew Henry', 'Though there as not one of Gibeah, yet it proved there was one in Gibeah, that showed some civility to this distressed Levite, who was glad that any one took notice of him. It was strange that some of those wicked people, who, when it was dark, designed so ill to him and his concubine, did not, under pretence of kindness, invite them in, that they might have a fairer opportunity of perpetrating their villany; but either they had not wit enough to be so designing, or not wickedness enough to b...', 'teologico');
add('jz', 19, 22, 'Matthew Henry', 'Here is, I. The great wickedness of the men of Gibeah. One could not imagine that ever it should enter into the heart of men that had the use of human reason, of Israelites that had the benefit of divine revelation, to be so very wicked. "Lord, what is man!" said David, "what a mean creature is he!" "Lord, what is man," may we say upon the reading of this story, "what a vile creature is he, when he is given up to his own heart\'s lusts!" The sinners are here called sons of Belial, that is, ung...', 'teologico');
add('jz', 20, 1, 'Matthew Henry', 'Here is, I. A general meeting of all the congregation of Israel to examine the matter concerning the Levite\'s concubine, and to consider what was to be done upon it, Jdg 20:1, Jdg 20:2. It does not appear that they were summoned by the authority of any one common head, but they came together by the consent and agreement, as it were, of one common heart, fired with a holy zeal for the honour of God and Israel. 1. The place of their meeting was Mizpeh; they gathered together unto the Lord there...', 'teologico');
add('jz', 20, 12, 'Matthew Henry', 'Here is, I. The fair and just demand which the tribes of Israel, now encamped, sent to the tribe of Benjamin, to deliver up the malefactors of Gibeah to justice, Jdg 20:12, Jdg 20:13. If the tribe of Benjamin had come up, as they ought to have done, to the assembly, and agreed with them in their resolution, there would have been none to deal with but the men of Gibeah only, but they, by their absence, taking part with the criminals, application must be made to them all. The Israelites were ze...', 'teologico');
add('jz', 20, 18, 'Matthew Henry', 'We have here the defeat of the men of Israel in their first and second battle with the Benjamites.\nI. Before their first engagement they asked counsel of God concerning the order of their battle and were directed, and yet they were sorely beaten. They did not think it was proper to ask of God whether they should go up at all against Benjamin (the case was plain enough, the men of Gibeah must be punished for their wickedness, and Israel must inflict the punishment or it will not be done), but ...', 'teologico');
add('jz', 20, 26, 'Matthew Henry', 'We have here a full account of the complete victory which the Israelites obtained over the Benjamites in the third engagement: the righteous cause was victorious at last, when the managers of it amended what had been amiss; for, when a good cause suffers, it is for want of good management. Observe then how the victory was obtained, and how it was pursued.\nI. How the victory was obtained. Two things they had trusted too much to in the former engagements - the goodness of their cause and the su...', 'teologico');
add('jz', 21, 1, 'Matthew Henry', 'We may observe in these verses,\nI. The ardent zeal which the Israelites had expressed against the wickedness of the men of Gibeah, as it was countenanced by the tribe of Benjamin. Occasion is here given to mention two instances of their zeal on this occasion, which we did not meet with before: - 1. While the general convention of the states was gathering together, and was waiting for a full house before they would proceed, they bound themselves with the great execration, which they called the...', 'teologico');
add('jz', 21, 16, 'Matthew Henry', 'We have here the method that was taken to provide the 200 Benjamites that remained with wives. And, though the tribe was reduced to a small number, they were only in care to provide each man with one wife, not with more under pretence of multiplying them the faster. They may not bestow their daughters upon them, but to save their oath, and yet marry some of their daughters to them, they put them into a way of taking them by surprise, and marrying them, which should be ratified by their parent...', 'teologico');

// RT (14 comentários)
add('rt', 1, 16, 'Matthew Henry', 'O teu povo será o meu povo — A lealdade de Rute revela graça que ultrapassa fronteiras étnicas.', 'cultural');
add('rt', 4, 14, 'Lutero', 'O Senhor não te deixou sem resgatador — A providência de Deus opera através de parentes redentores.', 'teologico');
add('rt', 1, 1, 'Matthew Henry', 'The first words give all the date we have of this story. It was in the days when the judges ruled (Rut 1:1), not in those disorderly times when there was no king in Israel; but under which of the judges these things happened we are not told, and the conjectures of the learned are very uncertain. It must have been towards the beginning of the judges\' time, for Boaz, who married Ruth, was born of Rahab, who received the spies in Joshua\'s time. Some think it was in the days of Ehud, others of De...', 'teologico');
add('rt', 1, 6, 'Matthew Henry', 'See here, I. The good affection Naomi bore to the land of Israel, Rut 1:6. Though she could not stay in it while the famine lasted, she would not stay out of it when the famine ceased. Though the country of Moab had afforded her shelter and supply in a time of need, yet she did not intend it should be her rest for ever; no land should be that but the holy land, in which the sanctuary of God was, of which he had said, This is my rest for ever. Observe,\n1. God, at last, returned in mercy to his...', 'teologico');
add('rt', 1, 19, 'Matthew Henry', 'Naomi and Ruth, after many a weary step (the fatigue of the journey, we may suppose, being somewhat relieved by the good instructions Naomi gave to her proselyte and the good discourse they had together), came at last to Bethlehem. And they came very seasonably, in the beginning of the barley-harvest, which was the first of their harvests, that of wheat following after. Now Naomi\'s own eyes might convince her of the truth of what she had heard in the country of Moab, that the Lord had visited...', 'teologico');
add('rt', 2, 1, 'Matthew Henry', 'Naomi had now gained a settlement in Bethlehem among her old friends; and here we have an account,\nI. Of her rich kinsman, Boaz, a mighty man of wealth, Rut 2:1. The Chaldee reads it, mighty in the law. If he was both, it was a most rare and excellent conjunction, to be mighty in wealth and mighty in the scriptures too; those that are so are mighty indeed. He was grandson of Nahshon, who was prince of the tribe of Judah in the wilderness, and son of Salmon, probably a younger son, by Rahab, t...', 'teologico');
add('rt', 2, 4, 'Matthew Henry', 'Now Boaz himself appears, and a great deal of decency there appears in his carriage both towards his own servants and towards this poor stranger.\nI. Towards his own servants, and those that were employed for him in reaping and gathering in his corn. Harvest-time is busy time, many hands must then be at work. Boaz that had much, being a mighty man of wealth, had much to do, and consequently many to work under him and to live upon him. As goods are increased those are increased that eat them, a...', 'teologico');
add('rt', 2, 17, 'Matthew Henry', 'Here, I. Ruth finishes her day\'s work, Rut 2:17. 1. She took care not to lose time, for she gleaned until evening. We must not be weary of well-doing, because in due season we shall reap. She did not make an excuse to sit still, or go home, till the evening. Let us work the works of him that sent us, while it is day. She scarcely used, much less did she abuse, the kindness of Boaz; for, though he ordered his servants to leave handfuls for her, she continued to glean the scattered ears. 2. She...', 'teologico');
add('rt', 3, 1, 'Matthew Henry', 'Here is, I. Naomi\'s care for her daughter\'s comfort is without doubt very commendable, and is recorded for imitation. She had no thoughts of marrying herself, Rut 1:12. But, though she that was old had resolved upon a perpetual widowhood, yet she was far from the thoughts of confining her daughter-in-law to it, that was young. Age must not make itself a standard to youth. On the contrary, she is full of contrivance how to get her well married. Her wisdom projected that for her daughter which ...', 'teologico');
add('rt', 3, 6, 'Matthew Henry', 'Here is, I. Boaz\'s good management of his common affairs. It is probable, according to the common usage, 1. When his servants winnowed, he was with them, and had his eye upon them, to prevent, not their stealing any of his corn (he had no reason to fear that), but their waste of it through carelessness in the winnowing of it. Masters may sustain great losses by servants that are heedless, though they be honest, which is a reason why men should be diligent to know the state of their own flocks...', 'teologico');
add('rt', 3, 14, 'Matthew Henry', 'We are here told, I. How Ruth was dismissed by Boaz. It would not have been safe for her to go home in the dead of the night; therefore she lay at his feet (not by his side) until morning. But as soon as ever the day broke, that she had light to go home by, she got away, before one could know another, that, if she were seen, yet she might not be known to be abroad so unseasonably. She was not shy of being known to be a gleaner in the field, nor ashamed of that mark of her poverty. But she wou...', 'teologico');
add('rt', 4, 1, 'Matthew Henry', 'Here, 1. Boaz calls a court immediately. It is probable he was himself one of the elders (or aldermen) of the city; for he was a mighty man of wealth. Perhaps he was father of the city, and sat chief; for he seems here to have gone up to the gate as one having authority, and not as a common person; like Job, Job 29:7, etc. We cannot suppose him less than a magistrate in his city who was grandson to Nahshon, prince of Judah; and his lying at the end of a heap of corn in the threshing-floor the...', 'teologico');
add('rt', 4, 9, 'Matthew Henry', 'Boaz now sees his way clear, and therefore delays not to perform his promise made to Ruth that he would do the kinsman\'s part, but in the gate of the city, before the elders and all the people, publishes a marriage-contract between himself and Ruth the Moabitess, and therewith the purchase of all the estate that belonged to the family of Elimelech. If he had not been (Rut 2:1) a mighty man of wealth, he could not have compassed this redemption, nor done this service to his kinsman\'s family. W...', 'teologico');
add('rt', 4, 13, 'Matthew Henry', 'Here is, I. Ruth a wife. Boaz took her, with the usual solemnities, to his house, and she became his wife (Rut 4:13), all the city, no doubt, congratulating the preferment of a virtuous woman, purely for her virtues. We have reason to think that Orpah, who returned from Naomi to her people and her gods, was never half so well preferred as Ruth was. He that forsakes all for Christ shall find more than all with him; it shall be recompensed a hundred-fold in this present time. Now Orpah wished s...', 'teologico');

// 1SM (106 comentários)
add('1sm', 3, 10, 'Calvino', 'Fala, Senhor — A disponibilidade de Samuel: ouvir a Deus exige silêncio diante da Sua voz.', 'teologico');
add('1sm', 16, 7, 'Agostinho', 'O Senhor olha para o coração — Deus avalia a realidade interior, não a aparência externa.', 'teologico');
add('1sm', 15, 22, 'Gregório Magno', 'Obediência é melhor que sacrifício — A submissão a Deus vale mais que rituais vazios.', 'teologico');
add('1sm', 1, 1, 'Matthew Henry', 'We have here an account of the state of the family into which Samuel the prophet was born. His father\'s name was Elkanah, a Levite, and of the family of the Kohathites (the most honourable house of that tribe) as appears, Ch1 6:33, Ch1 6:34. His ancestor Zuph was an Ephrathite, that is, of Bethlehem-Judah, which was called Ephrathah, Ruth, Rut 1:2. There this family of the Levites was first seated, but one branch of it, in process of time, removed to Mount Ephraim, from which Elkanah descende...', 'teologico');
add('1sm', 1, 9, 'Matthew Henry', 'Elkanah had gently reproved Hannah for her inordinate grief, and here we find the good effect of the reproof.\nI. It brought her to her meat. She ate and drank, Sa1 1:9. She did not harden herself in sorrow, nor grow sullen when she was reproved for it; but, when she perceived her husband uneasy that she did not come and eat with them, she cheered up her own spirits as well as she could, and came to table. it is as great a piece of self-denial to control our passions as it is to control our ap...', 'teologico');
add('1sm', 1, 19, 'Matthew Henry', 'Here is, I. The return of Elkanah and his family to their own habitation, when the days appointed for the feast were over, Sa1 1:19. Observe how they improved their time at the tabernacle. Every day they were there, even that which was fixed for their journey home, they worshipped God; and they rose up early to do it. It is good to begin the day with God. Let him that is the first have the first. They had a journey before them, and a family of children to take with them, and yet they would no...', 'teologico');
add('1sm', 2, 1, 'Matthew Henry', 'We have here Hannah\'s thanksgiving, dictated, not only by the spirit of prayer, but by the spirit of prophecy. Her petition for the mercy she desired we had before (Sa1 1:11), and here we have her return of praise; in both out of the abundance of a heart deeply affected (in the former with her own wants, and in the latter with God\'s goodness) her mouth spoke. Observe in general, 1. When she had received mercy from God she owned it, with thankfulness to his praise. Not like the nine lepers, Lu...', 'teologico');
add('1sm', 2, 11, 'Matthew Henry', 'In these verses we have the good character and posture of Elkanah\'s family, and the bad character and posture of Eli\'s family. The account of these two is observably interwoven throughout this whole paragraph, as if the historian intended to set the one over against the other, that they might set off one another. The devotion and good order of Elkanah\'s family aggravated the iniquity of Eli\'s house; while the wickedness of Eli\'s sons made Samuel\'s early piety appear the more bright and illust...', 'teologico');
add('1sm', 2, 27, 'Matthew Henry', 'Eli reproved his sons too gently, and did not threaten them as he should, and therefore God sent a prophet to him to reprove him sharply, and to threaten him, because, by his indulgence of them, he had strengthened their hands in their wickedness. If good men be wanting in their duty, and by their carelessness and remissness contribute any thing to the sin of sinners, they must expect both to hear of it and to smart for it. Eli\'s family was now nearer to God than all the families of the earth...', 'teologico');
add('1sm', 3, 1, 'Matthew Henry', 'To make way for the account of God\'s revealing himself first to Samuel, we are here told, 1. How industrious Samuel was in serving God, according as his place and capacity were (Sa1 3:1): The child Samuel, though but a child, ministered unto the Lord before Eli. It was an aggravation of the wickedness of Eli\'s sons that the child Samuel shamed them. They rebelled against the Lord, but Samuel ministered to him; they slighted their father\'s admonitions, but Samuel was observant of them; he mini...', 'teologico');
add('1sm', 3, 11, 'Matthew Henry', 'Here is, I. The message which, after all this introduction, God delivered to Samuel concerning Eli\'s house. God did not come to him now to tell him how great a man he should be in his day, what a figure he should make, and what a blessing he should be in Israel. Young people have commonly a great curiosity to be told their fortune, but God came to Samuel, not to gratify his curiosity, but to employ him in his service and send him on an errand to another person, which was much better; and yet ...', 'teologico');
add('1sm', 3, 19, 'Matthew Henry', 'Samuel being thus brought acquainted with the visions of God, we have here an account of the further honour done him as a prophet.\nI. God did him honour. Having begun to favour him, he carried on and crowned his own work in him: Samuel grew, for the Lord was with him, Sa1 3:19. All our increase in wisdom and grace is owing to the presence of God with us; this is all in all to our growth. God honoured Samuel, 1. By further manifestations of himself to him. Samuel had faithfully delivered the m...', 'teologico');
add('1sm', 4, 1, 'Matthew Henry', 'The first words of this paragraph, which relate to Samuel, that his word came to all Israel, seem not to have any reference to the following story, as if it was by any direction of his that the Israelites went out against the Philistines. Had they consulted him, though but newly initiated as a prophet, his counsel might have stood them in more stead than the presence of the ark did; but perhaps the princes of Israel despised his youth, and would not have recourse to him as an oracle, and he d...', 'teologico');
add('1sm', 4, 10, 'Matthew Henry', 'Here is a short account of the issue of this battle.\nI. Israel was smitten, the army dispersed and totally routed, not retiring into the camp, as before (Sa1 4:2) when they hoped to rally again, but returning to their tents, every man shifting for his own safety and making the best of his way home, despairing to make head any more; and 30,000 were slain in the field of battle, Sa1 4:10. Israel was put to the worse, 1. Though they had the better cause, were the people of God and the Philistine...', 'teologico');
add('1sm', 4, 12, 'Matthew Henry', 'Tidings are here brought to Shiloh of the fatal issue of their battle with the Philistines. Bad news flies fast. This soon spread through all Israel; every man that fled to his tent brought it, with too plain a proof of it, to his neighbours. But no place was so nearly concerned as Shiloh. Thither therefore an express posted away immediately; it was a man of Benjamin; the Jews fancy it was Saul. He rent his clothes, and put earth upon his head, by these signs to proclaim the sorrowful news to...', 'teologico');
add('1sm', 4, 19, 'Matthew Henry', 'We have here another melancholy story, that carries on the desolations of Eli\'s house, and the sorrowful feeling which the tidings of the ark\'s captivity excited. It is concerning the wife of Phinehas, one of those ungracious sons of Eli that had brought all this mischief on Israel. It cost her her life, though young, as well as that of her father-in-law, that was old; for many a green head, as well as many a hoary head, has been brought by sorrow to the grave: it worketh death. By what is he...', 'teologico');
add('1sm', 5, 1, 'Matthew Henry', 'Here is, I. The Philistines\' triumph over the ark, which they were the more pleased, the more proud, to be now masters of, because before the battle they were possessed with a great fear of it, Sa1 4:7. When they had it in their hands God restrained them, that they did not offer any violence to it, did not break it to pieces, as the Israelites were ordered to do by the idols of the heathen, but showed some respect to it, and carefully carried it to a place of safety. Whether their curiosity l...', 'teologico');
add('1sm', 5, 6, 'Matthew Henry', 'The downfall of Dagon (if the people had made a good use of it, and had been brought by it to repent of their idolatries and to humble themselves before the God of Israel and seek his face) might have prevented the vengeance which God here proceeds to take upon them for the indignities done to his ark, and their obstinate adherence to their idol, in defiance of the plainest conviction. Lord, when thy hand is lifted up they will not see, but they shall see, Isa 26:11. And, if they will not see...', 'teologico');
add('1sm', 6, 1, 'Matthew Henry', 'The first words of the chapter tell us how long the captivity of the ark continued - it was in the country of the Philistines seven months. In the field of the Philistines (so it is in the original), from which some gather that, having tried it in all their cities, and found it a plague to the inhabitants of each, at length they sent it into the open fields, upon which mice sprang up out of the ground in great multitudes, and destroyed the corn which was now nearly ripe and marred the land. W...', 'teologico');
add('1sm', 6, 10, 'Matthew Henry', 'We are here told,\nI. How the Philistines dismissed the ark, Sa1 6:10, Sa1 6:11. They were made as glad to part with it as ever they had been to take it. As God had fetched Israel out of the house of bondage, so now he fetched the ark out of its captivity, in such a manner as that Egypt was glad when they departed, Psa 105:38. 1. They received no money or price for the ransom of it, as they hoped to do, even beyond a king\'s ransom. Thus it is prophesied of Cyrus (Isa 45:13), He shall let go my...', 'teologico');
add('1sm', 6, 19, 'Matthew Henry', 'Here is, 1. The sin of the men of Beth-shemesh: They looked into the ark of the Lord, Sa1 6:19. Every Israelite had heard great talk of the ark, and had been possessed with a profound veneration for it; but they had been told that it was lodged within a veil, and even the high priest himself might not look upon it but once a year, and then through a cloud of incense. Perhaps this made many say (as we are apt to covet that which is forbidden) what a great deal they would give for a sight of it...', 'teologico');
add('1sm', 7, 1, 'Matthew Henry', 'Here we must attend the ark to Kirjath-jearim, and then leave it there, to hear not a word more of it except once (Sa1 14:18), till David fetched it thence, about forty years after, Ch1 13:6.\nI. We are very willing to attend it thither, for the men of Beth-shemesh have by their own folly made that a burden which might have been a blessing; and gladly would we see it among those to whom it will be a savour of life unto life, for in every place where it has been of late it has been a savour of ...', 'teologico');
add('1sm', 7, 3, 'Matthew Henry', 'We may well wonder where Samuel was and what he was doing all this while, for we have not had him so much as named till now, since Sa1 4:1, not as if he were unconcerned, but his labours among his people are not mentioned till there appears the fruit of them. When he perceived that they began to lament after the Lord he struck while the iron was hot, and two things he endeavoured to do for them, as a faithful servant of God and a faithful friend to the Israel of God: - \nI. He endeavoured to s...', 'teologico');
add('1sm', 7, 7, 'Matthew Henry', 'Here, I. The Philistines invade Israel (Sa1 7:7), taking umbrage from that general meeting for repentance and prayer as if it had been a rendezvous for war, and, if so, they thought it prudent to keep the war out of their own country. They had no just cause for this suspicion; but those that seek to do mischief to others will be forward to imagine that others design mischief to them. Now see here, 1. How evil sometimes seems to come out of good. The religious meeting of the Israelites at Mizp...', 'teologico');
add('1sm', 7, 13, 'Matthew Henry', 'We have here a short account of the further good services that Samuel did to Israel. Having parted them from their idols, and brought them home to their God, he had put them into a capacity of receiving further benefits by his ministry. Having prevailed in that, he becomes, in other instances, a great blessing to them; yet, writing it himself, he is brief in the relation. We are not told here, but it appears (Ch2 35:18) that in the days of Samuel the prophet the people of Israel kept the ordi...', 'teologico');
add('1sm', 8, 1, 'Matthew Henry', 'Two sad things we find here, but not strange things: - 1. A good and useful man growing old and unfit for service (Sa1 8:1): Samuel was old, and could not judge Israel, as he had done. He is not reckoned to be past sixty years of age now, perhaps not so much; but he was a man betimes, was full of thoughts and cared when he was a child, which perhaps hastened the infirmities of age upon him. The fruits that are the first ripe keep the worst. He had spent his strength and spirits in the fatigue...', 'teologico');
add('1sm', 8, 4, 'Matthew Henry', 'We have here the starting of a matter perfectly new and surprising, which was the setting up of kingly government in Israel. Perhaps the thing had been often talked of among them by those that were given to change and affected that which looked great. But we do not find that it was ever till now publicly proposed and debated. Abimelech was little better than a titular king, though he is said to reign over Israel (Jdg 9:22), and perhaps his fall had for a great while rendered the title of king...', 'teologico');
add('1sm', 9, 1, 'Matthew Henry', 'We are here told, 1. What a good family Saul was of, Sa1 9:1. He was of the tribe of Benjamin; so was the New Testament Saul, who also was called Paul, and he mentions it as his honour, for Benjamin was a favourite, Rom 11:1; Phi 3:5. That tribe had been reduced to a very small number by the fatal war with Gibeah, and much ado there was to provide wives for those 600 men that were the poor remains of it out of that diminished tribe, which is here called, with good reason, the smallest of the ...', 'teologico');
add('1sm', 9, 3, 'Matthew Henry', 'Here is, I. A great man rising from small beginnings. It does not appear that Saul had any preferment at all, or was in any post of honour or trust, till he was chosen king of Israel. Most that are advanced rise gradually, but Saul, from the level with his neighbours, stepped at once into the throne, according to that of Hannah, He raiseth up the poor out of the dust, to set them among princes, Sa1 2:8. Saul, it should seem, though he was himself married and had children grown up, yet lived i...', 'teologico');
add('1sm', 9, 11, 'Matthew Henry', 'Here, I. Saul, by an ordinary enquiry, is directed to Samuel, Sa1 9:11-14. Gibeah of Saul was not twenty miles from Ramah where Samuel dwelt, and was near to Mizpeh where he often judged Israel, and yet, it seems, Saul had lived so very privately, and had taken so little notice of public affairs, that he had never seen Samuel, for when he met him (Sa1 9:18) he did not know him, so that there was no cause to suspect any secret compact or collusion between them in this matter. I knew him not, s...', 'teologico');
add('1sm', 9, 18, 'Matthew Henry', 'Providence having at length brought Samuel and Saul together, we have here an account of what passed between them in the gate, at the feast, and in private.\nI. In the gate of the city; passing through that, Saul found him (Sa1 9:18), and, little thinking that he was Samuel himself, asked him the way to Samuel\'s house: Tell me where the seer\'s house is; for there he expected to find him. See how mean a figure Samuel made, though so great a man: he took not any state, had no attendants, no ensi...', 'teologico');
add('1sm', 10, 1, 'Matthew Henry', 'Samuel is here executing the office of a prophet, giving Saul full assurance from God that he should be king, as he was afterwards, according to these prophecies which went before of him.\nI. He anointed him and kissed him, Sa1 10:1. This was not done in a solemn assembly, but it was done by divine appointment, which made up the want of all external solemnities, nor was it ever the less valid for its being done in private, under a hedge, or, as the Jews say, by a fountain. God\'s institutions a...', 'teologico');
add('1sm', 10, 9, 'Matthew Henry', 'Saul has now taken his leave of Samuel, much amazed, we may well suppose, at what has been done to him, almost ready to question whether he be awake or no, and whether it be not all a dream. Now here we are told,\nI. What occurred by the way, Sa1 10:9. Those signs which Samuel had given him came to pass very punctually; but that which gave him the greatest satisfaction of all was this, he found immediately that God had given him another heart. A new fire was kindled in his breast, such as he h...', 'teologico');
add('1sm', 10, 17, 'Matthew Henry', 'Saul\'s nomination to the throne is here made public, in a general assembly of the elders of Israel, the representatives of their respective tribes at Mizpeh. It is probable that this convention of the states was called as soon as conveniently it might, after Saul was anointed, for, if there must be a change in their government, the sooner the better: it might be of bad consequence to be long in the doing. The people having met in a solemn assembly, in which God was in a peculiar manner presen...', 'teologico');
add('1sm', 11, 1, 'Matthew Henry', 'The Ammonites were bad neighbours to those tribes of Israel that lay next them, though descendants from just Lot, and, for that reason, dealt civilly with by Israel. See Deu 2:19. Jephthah, in his time, had humbled them, but now the sin of Israel had put them into a capacity to make head again, and avenge that quarrel. The city of Jabesh-Gilead had been, some ages ago, destroyed by Israel\'s sword of justice, for not appearing against the wickedness of Gibeah (Jdg 21:10); and now being repleni...', 'teologico');
add('1sm', 11, 5, 'Matthew Henry', 'What is here related turns very much to the honour of Saul, and shows the happy fruits of that other spirit with which he was endued. Observe here,\nI. His humility. Though he was anointed king, and accepted by his people, yet he did not think it below him to know the state of his own flocks, but went himself to see them, and came in the evening, with his servants, after the herd out of the field, Sa1 11:5. This was an evidence that he was not puffed up with his advancement, as those are most ...', 'teologico');
add('1sm', 11, 12, 'Matthew Henry', 'We have here the improvement of the glorious victory which Saul had obtained, not the improvement of it abroad, though we take it for granted that the men of Jabesh-Gilead, having so narrowly saved their right eyes, would with them now discern the opportunity they had of avenging themselves upon these cruel enemies and disabling them from ever straitening them in like manner again; now shall they be avenged on the Ammonites for their right eyes condemned, as Samson on the Philistines for his ...', 'teologico');
add('1sm', 12, 1, 'Matthew Henry', 'Here, I. Samuel gives them a short account of the late revolution, and of the present posture of their government, by way of preface to what he had further to say to them, Sa1 12:1, Sa1 12:2. 1. For his own part, he had spent his days in their service; he began betimes to be useful among them, and had continued long so: "I have walked before you, as a guide to direct you, as a shepherd that leads his flock (Psa 80:1), from my childhood unto this day." As soon as he was illuminated with the li...', 'teologico');
add('1sm', 12, 6, 'Matthew Henry', 'Samuel, having sufficiently secured his own reputation, instead of upbraiding the people upon it with their unkindness to him, sets himself to instruct them, and keep them in the way of their duty, and then the change of the government would be the less damage to them.\nI. He reminds them of the great goodness of God to them and to their fathers, gives them an abstract of the history of their nation, that, by the consideration of the great things God had done for them, they might be for ever e...', 'teologico');
add('1sm', 12, 16, 'Matthew Henry', 'Two things Samuel here aims at: - \nI. To convince the people of their sin in desiring a king. They were now rejoicing before God in and with their king (Sa1 11:15), and offering to God the sacrifices of praise, which they hoped God would accept; and this perhaps made them think that there was no harm in their asking a king, but really they had done well in it. Therefore Samuel here charges it upon them as their sin, as wickedness, great wickedness in the sight of the Lord. Note, Though we mee...', 'teologico');
add('1sm', 13, 1, 'Matthew Henry', 'We are not told wherein it was that the people of Israel offended God, so as to forfeit his presence and turn his hand against them, as Samuel had threatened (Sa1 12:15); but doubtless they left God, else he would not have left them, as here it appears he did; for,\nI. Saul was very weak and impolitic, and did not order his affairs with discretion. Saul was the son of one year (so the first words are in the original), a phrase which we make to signify the date of his reign, but ordinarily it s...', 'teologico');
add('1sm', 13, 8, 'Matthew Henry', 'Here is, I. Saul\'s offence in offering sacrifice before Samuel came. Samuel, when he anointed him, had ordered him to tarry for him seven days in Gilgal, promising that, at the end of those days, he would be sure to come to him, and both offer sacrifices for him and direct him what he should do. This we had Sa1 10:8. Perhaps that order, though inserted there, was given him afterwards, or was given him as a general rule to be observed in every public congress at Gilgal, or, as is most probable...', 'teologico');
add('1sm', 13, 15, 'Matthew Henry', 'Here, 1. Samuel departs in displeasure. Saul has set up for himself, and now he is left to himself: Samuel gat him from Gilgal (Sa1 13:15), and it does not appear that he either prayed with Saul or directed him. Yet in going up to Gibeah of Benjamin, which was Saul\'s city, he intimated that he had not quite abandoned him, but waited to do him a kindness another time. Or he went to the college of the prophets there, to pray for Saul when he did not think fit to pray with him. 2. Saul goes afte...', 'teologico');
add('1sm', 14, 1, 'Matthew Henry', 'We must here take notice,\nI. Of the goodness of God in restraining the Philistines, who had a vast army of valiant men in the field, from falling upon that little handful of timorous trembling people that Saul had with him, whom they would easily have swallowed up at once. It is an invisible power that sets bounds to the malice of the church\'s enemies, and suffers them not to do that which we should think there is nothing to hinder them from.\nII. Of the weakness of Saul, who seems here to hav...', 'teologico');
add('1sm', 14, 16, 'Matthew Henry', 'We have here the prosecution and improvement of the wonderful advantages which Jonathan and his armour-bearer gained against the Philistines.\nI. The Philistines were, by the power of God, set against one another. They melted away like snow before the sun, and went on beating down one another (Sa1 14:16), for (Sa1 14:20) every man\'s sword was against his fellow. When they fled for fear, instead of turning back upon those that chased them, they reckoned those only their enemies that stood in th...', 'teologico');
add('1sm', 14, 24, 'Matthew Henry', 'We have here an account of the distress of the children of Israel, even in the day of their triumphs. Such alloys are all present joys subject to. And such obstructions does many a good cause meet with, even when it seems most prosperous, through the mismanagement of instruments.\nI. Saul forbade the people, under the penalty of a curse, to taste any food that day, Sa1 14:24. Here we will suppose, 1. That as king he had power to put his soldiers under this interdict, and to bind it on with a c...', 'teologico');
add('1sm', 14, 36, 'Matthew Henry', 'Here is, I. Saul\'s boasting against the Philistines. He proposed, as soon as his soldiers had got their suppers, to pursue them all night, and not leave a man of them, Sa1 14:36. Here he showed much zeal, but little discretion; for his army, thus fatigued, could as ill spare a night\'s sleep as a meal\'s meat. But it is common for rash and foolish men to consider nobody but themselves, and, so that they might but have their humour, not to care what hardships they put upon those that are under t...', 'teologico');
add('1sm', 14, 47, 'Matthew Henry', 'Here is a general account of Saul\'s court and camp. 1. Of his court and family, the names of his sons and daughters (Sa1 14:49), and of his wife and his cousin-german that was general of his army, Sa1 14:50. There is mention of another wife of Saul\'s (Sa2 21:8), Rizpah, a secondary wife, and of the children he had by her. 2. Of his camp and military actions. (1.) How he levied his army: When he saw any strong valiant man, that was remarkably fit for service, he took him unto him (Sa1 14:52), ...', 'teologico');
add('1sm', 15, 1, 'Matthew Henry', 'Here, I. Samuel, in God\'s name, solemnly requires Saul to be obedient to the command of God, and plainly intimates that he was now about to put him upon a trial, in one particular instance, whether he would be obedient or no, Sa1 15:1. And the making of this so expressly the trial of his obedience did very much aggravate his disobedience. 1. He reminds him of what God had done for him: "The Lord sent me to anoint thee to be a king. God gave thee thy power, and therefore he expects thou should...', 'teologico');
add('1sm', 15, 10, 'Matthew Henry', 'Saul is here called to account by Samuel concerning the execution of his commission against the Amalekites; and remarkable instances we are here furnished with of the strictness of the justice of God and the treachery and deceitfulness of the heart of man. We are here told,\nI. What passed between God and Samuel, in secret, upon this occasion, Sa1 15:10, Sa1 15:11. 1. God determines Saul\'s rejection, and acquaints Samuel with it: It repenteth me that I have set up Saul to be king. Repentance i...', 'teologico');
add('1sm', 15, 24, 'Matthew Henry', 'Saul is at length brought to put himself into the dress of the penitent; but it is too evident that he only acts the part of a penitent, and is not one indeed. Observe,\nI. How poorly he expressed his repentance. It was with much ado that he was made sensible of his fault, and not till he was threatened with being deposed. This touched him in a tender part. Then he began to relent, and not till then. When Samuel told him he was rejected from being king, then he said, I have sinned, Sa1 15:24. ...', 'teologico');
add('1sm', 15, 32, 'Matthew Henry', 'Samuel, as a prophet, is here set over kings, Jer 1:10.\nI. He destroys king Agag, doubtless by such special direction from heaven as none now can pretend to. He hewed Agag in pieces. Some think he only ordered it to be done; or perhaps he did it with his own hands, as a sacrifice to God\'s injured justice (Sa1 15:33), and sacrifices used to be cut in pieces. Now observe in this,\n1. How Agag\'s present vain hopes were frustrated: He came delicately, in a stately manner, to show that he was a kin...', 'teologico');
add('1sm', 16, 1, 'Matthew Henry', 'Samuel had retired to his own house in Ramah, with a resolution not to appear any more in public business, but to addict himself wholly to the instructing and training up of the sons of the prophets, over whom he presided, as we find, Sa1 19:20. He promised himself more satisfaction in young prophets than in young princes; and we do not find that, to his dying day, God called him out to any public action relating to the state, but only here to anoint David.\nI. God reproves him for continuing ...', 'teologico');
add('1sm', 16, 6, 'Matthew Henry', 'If the sons of Jesse were told that God would provide himself a king among them (as he had said, Sa1 16:1), we may well suppose they all made the best appearance they could, and each hoped he should be the man; but here we are told,\nI. How all the elder sons, who stood fairest for the preferment, were passed by.\n1. Eliab, the eldest, was privately presented first to Samuel, probably none being present but Jesse only, and Samuel thought he must needs be the man: Surely this is the Lord\'s anoin...', 'teologico');
add('1sm', 16, 14, 'Matthew Henry', 'We have here Saul falling and David rising.\nI. Here is Saul made a terror to himself (Sa1 16:14): The Spirit of the Lord departed from him. He having forsaken God and his duty, God, in a way of righteous judgment, withdrew from him those assistances of the good Spirit with which he was directed, animated, and encouraged in his government and wars. He lost all his good qualities. This was the effect of his rejecting God, and an evidence of his being rejected by him. Now God took his mercy from...', 'teologico');
add('1sm', 17, 1, 'Matthew Henry', 'It was not long ago that the Philistines were soundly beaten, and put to the worse, before Israel, and they would have been totally routed if Saul\'s rashness had not prevented; but here we have them making head again. Observe,\nI. How they defied Israel with their armies, Sa1 17:1. They made a descent upon the Israelites\' country, and possessed themselves, as it should seem, of some part of it, for they encamped in a place which belonged to Judah. Israel\'s ground would never have been footing ...', 'teologico');
add('1sm', 17, 12, 'Matthew Henry', 'Forty days the two armies lay encamped facing one another, each advantageously posted, but neither forward to engage. Either they were parleying and treating of an accommodation or they were waiting for recruits; and perhaps there were frequent skirmishes between small detached parties. All this while, twice a day, morning and evening, did the insulting champion appear in the field and repeat his challenge, his own heart growing more and more proud for his not being answered and the people of...', 'teologico');
add('1sm', 17, 31, 'Matthew Henry', 'David is at length presented to Saul for his champion (Sa1 17:31) and he bravely undertakes to fight the Philistine (Sa1 17:32): Let no man\'s heart fail because of him. It would have reflected too much upon the valour of his prince if he had said, Let not thy heart fail; therefore he speaks generally: Let no man\'s heart fail. A little shepherd, come but this morning from keeping sheep, has more courage than all the mighty men of Israel, and encourages them. Thus does God often send good words...', 'teologico');
add('1sm', 17, 40, 'Matthew Henry', 'We are now coming near this famous combat, and have in these verses the preparations and remonstrances made on both sides.\nI. The preparations made on both sides for the encounter. The Philistine was already fixed, as he had been daily for the last forty days. Well might he go with his armour, for he had sufficiently proved it. Only we are told (Sa1 17:41) that he came on and drew near, a signal, it is likely, being given that his challenge was accepted, and, as if he distrusted his helmet an...', 'teologico');
add('1sm', 17, 48, 'Matthew Henry', 'Here is 1. The engagement between the two champions, Sa1 17:48. To this engagement the Philistine advanced with a great deal of state and gravity; if he must encounter a pigmy, yet it shall be with the magnificence of a giant and a grandee. This is intimated in the manner of expression: He arose, and came, and drew nigh, like a stalking mountain, overlaid with brass and iron, to meet David. David advanced with no less activity and cheerfulness, as one that aimed more to do execution than to m...', 'teologico');
add('1sm', 18, 1, 'Matthew Henry', 'David was anointed to the crown to take it out of Saul\'s hand, and over Jonathan\'s head, and yet here we find,\nI. That Saul, who was now in possession of the crown, reposed a confidence in him, God so ordering it, that he might by his preferment at court be prepared for future service. Saul now took David home with him, and would not suffer him to return again to his retirement, Sa1 18:2. And David having signalized himself above the men of war, in taking up the challenge which they declined,...', 'teologico');
add('1sm', 18, 6, 'Matthew Henry', 'Now begin David\'s troubles, and they not only tread on the heels of his triumphs, but take rise from them, such is the vanity of that in this world which seems greatest.\nI. He was too much magnified by the common people. Some time after the victory Saul went a triumphant progress through the cities of Israel that lay next him, to receive the congratulations of the country. And, when he made his public entry into any place, the women were most forward to show him respect, as was usual then in ...', 'teologico');
add('1sm', 18, 12, 'Matthew Henry', 'Saul had now, in effect, proclaimed war with David. He began in open hostility when he threw the javelin at him. Now we are here told how his enmity proceeded, and how David received the attacks of it.\nI. See how Saul expressed his malice against David. 1. He was afraid of him, Sa1 18:12. Perhaps he pretended to be afraid that David would do himself mischief, to force his way to the crown. Those that design ill against others are commonly willing to have it thought that others design ill agai...', 'teologico');
add('1sm', 19, 1, 'Matthew Henry', 'Saul and Jonathan appear here in their different characters, with reference to David.\nI. Never was enemy so unreasonably cruel as Saul. He spoke to his son and all his servants that they should kill David, Sa1 19:1. His projects to take him off had failed, and therefore he proclaims him an out-law, and charges all about him, upon their allegiance, to take the first opportunity to kill David. It is strange that he was not ashamed thus to avow his malice when he could give no reason for it, and...', 'teologico');
add('1sm', 19, 8, 'Matthew Henry', 'Here I. David continues his good services to his king and country. Though Saul had requited him evil for good, and even his usefulness was the very thing for which Saul envied him, yet he did not therefore retire in sullenness and decline public service. Those that are ill paid for doing good, yet must not be weary of well doing, remembering what a bountiful benefactor our heavenly Father is, even to the froward and unthankful. Notwithstanding the many affronts Saul had given to David, yet we...', 'teologico');
add('1sm', 19, 11, 'Matthew Henry', 'Here is, I. Saul\'s further design of mischief to David. When David had escaped the javelin, supposing he went straight to his own house, as indeed he did, Saul sent some of his guards after him to lay wait at the door of his house, and to assassinate him in the morning as soon as he stirred out, Sa1 19:11. Josephus says the design was to seize him and to hurry him before a court of justice that was ordered to condemn him and put him to death as a traitor; but we are here told it was a shorter...', 'teologico');
add('1sm', 19, 18, 'Matthew Henry', 'Here is, I. David\'s place of refuge. Having got away in the night from his own house, he fled not to Bethlehem to his relations, nor to any of the cities of Israel that had caressed and cried him up, to make an interest in them for his own preservation; but he ran straight to Samuel and told him all that Saul had done to him, Sa1 19:18. 1. Because Samuel was the man that had given him assurance of the crown, and his faith in that assurance now beginning to fail, and he being ready to say in h...', 'teologico');
add('1sm', 20, 1, 'Matthew Henry', 'Here, I. David makes a representation to Jonathan of his present troubles. While Saul lay bound by his trance at Naioth David escaped to the court, and got to speak with Jonathan. And it was happy for him that he had such a friend at court, when he had such an enemy on the throne. If there be those that hate and despise us, let us not be disturbed at that, for there are those also that love and respect us. God hath set the one over against the other, and so must we. Jonathan was a friend that...', 'teologico');
add('1sm', 20, 9, 'Matthew Henry', 'Here, I. Jonathan protests his fidelity to David in his distress. Notwithstanding the strong confidence David had in Jonathan, yet, because he might have some reason to fear that his father\'s influence, and his own interest, should make him warp, or grow cool towards him, Jonathan thought it requisite solemnly to renew the professions of his friendship to him (Sa1 20:9): "Far be it from thee to think that I suspect thee of any crime for which I should either slay thee myself or deliver thee t...', 'teologico');
add('1sm', 20, 24, 'Matthew Henry', 'Jonathan is here effectually convinced of that which he was so loth to believe, that his father had an implacable enmity to David, and would certainly be the death of him if it were in his power; and he had like to have paid very dearly himself for the conviction.\nI. David is missed from the feast on the first day, but nothing is said of him. The king sat upon his seat, to feast upon the peace-offerings as at other times (Sa1 20:25), and yet had his heart as full of envy and malice against Da...', 'teologico');
add('1sm', 20, 35, 'Matthew Henry', 'Here is, 1. Jonathan\'s faithful performance of his promise to give David notice of the success of his dangerous experiment. He went at the time and to the place appointed (Sa1 20:35), within sight of which he knew David lay hid, sent his footboy to fetch his arrows, which he would shoot at random (Sa1 20:36), and gave David the fatal signal by shooting an arrow beyond the lad (Sa1 20:37): Is not the arrow beyond thee? That word [beyond] David knew the meaning of better than the lad. Jonathan ...', 'teologico');
add('1sm', 21, 1, 'Matthew Henry', 'Here, I. David, in distress, flies in the tabernacle of God, now pitched at Nob, supposed to be a city in the tribe of Benjamin. Since Shiloh was forsaken, the tabernacle was often removed, though the ark still remained at Kirjath-jearim. Hither David came in his flight from Saul\'s fury (Sa1 21:1), and applied to Ahimelech the priest. Samuel the prophet could not protect him, Jonathan the prince could not. He therefore has recourse next to Ahimelech the priest. He foresees he must now be an e...', 'teologico');
add('1sm', 21, 10, 'Matthew Henry', 'David, though king elect, is here an exile - designed to be master of vast treasures, yet just now begging his bread - anointed to the crown, and yet here forced to flee from his country. Thus do God\'s providences sometimes seem to run counter to his promises, for the trial of his people\'s faith, and the glorifying of his name, in the accomplishment of his counsels, notwithstanding the difficulties that lay in the way. Here is, 1. David\'s flight into the land of the Philistines, where he hope...', 'teologico');
add('1sm', 22, 1, 'Matthew Henry', 'Here, I. David shelters himself in the cave of Adullam, Sa1 22:1. Whether it was a natural or artificial fastness does not appear; it is probable that the access to it was so difficult that David thought himself able, with Goliath\'s sword, to keep it against all the forces of Saul, and therefore buried himself alive in it, while he was waiting to see (and he says here, Sa1 22:3) what God would do with him. The promise of the kingdom implied a promise of preservation to it, and yet David used ...', 'teologico');
add('1sm', 22, 6, 'Matthew Henry', 'We have seen the progress of David\'s troubles; now here we have the progress of Saul\'s wickedness. He seems to have laid aside the thoughts of all other business and to have devoted himself wholly to the pursuit of David. He heard at length, by the common fame of the country, that David was discovered (that is, that he appeared publicly and enlisted men into his service); and hereupon he called all his servants about him, and sat down under a tree, or grove, in the high place at Gibeah, with ...', 'teologico');
add('1sm', 22, 20, 'Matthew Henry', 'Here is, 1. The escape of Abiathar, the son of Ahimelech, out of the desolations of the priests\' city. Probably when his father went to appear, upon Saul\'s summons, he was left at home to attend the altar, by which means he escaped the first execution, and, before Doeg and his bloodhounds came to Nob, he had intelligence of the danger, and had time to shift for his own safety. And whither should he go but to David? Sa1 22:20. Let those that suffer for the Son of David commit the keeping of th...', 'teologico');
add('1sm', 23, 1, 'Matthew Henry', 'Now we find why the prophet Gad (by divine direction, no doubt) ordered David to go into the land of Judah, Sa1 22:5. It was that, since Saul neglected the public safety, he might take care of it, notwithstanding the ill treatment that was given him; for he must render good for evil, and therein be a type of him who not only ventured his life, but laid down his life, for those that were his enemies.\nI. Tidings are brought to David, as to the patron and protector of his country\'s liberties, th...', 'teologico');
add('1sm', 23, 7, 'Matthew Henry', 'Here is, I. Saul contriving within himself the destruction of David (Sa1 23:7, Sa1 23:8): He heard that he had come to Keilah; and did he not hear what brought him thither? Was it not told him that he had bravely relieved Keilah and delivered it out of the hands of the Philistines? This, one would think, should have put Saul upon considering what honour and dignity should be done to David for this. But, instead of that, he catches at it as an opportunity of doing David a mischief. An ungratef...', 'teologico');
add('1sm', 23, 14, 'Matthew Henry', 'Here is, I. David absconding. He abode in a wilderness, in a mountain (Sa1 23:14), in a wood, Sa1 23:15. We must here, 1. Commend his eminent virtues, his humility, modesty, fidelity to his prince, and patient attendance on the providence of his God, that he did not draw up his forces against Saul, fight him in the field, or surprise him by some stratagem or other, and so avenge his own quarrel and that of the Lord\'s priests upon him, and put an end to his own troubles and the calamities of t...', 'teologico');
add('1sm', 23, 19, 'Matthew Henry', 'Here, 1. The Ziphites offer their service to Saul, to betray David to him, Sa1 23:19, Sa1 23:20. He was sheltering himself in the wilderness of Ziph (Sa1 23:14, Sa1 23:15), putting the more confidence in the people of that country because they were of his own tribe. They had reason to think themselves happy that they had an opportunity of serving one who was the ornament of their tribe and was likely to be much more so, who was so far from plundering the country, or giving it any disturbance ...', 'teologico');
add('1sm', 24, 1, 'Matthew Henry', 'Here, I. Saul renews his pursuit of David, Sa1 24:1, Sa1 24:2. No sooner had he come home safely from chasing the Philistines, in which it should seem he had good success, than he enquired after David to do him a mischief, and resolved to have another thrust at him, as if he had been delivered to do all these abominations, Jer 7:10. By the frequent incursions of the Philistines, he might have seen how necessary it was to recall David from his banishment and restore him to his place in the arm...', 'teologico');
add('1sm', 24, 9, 'Matthew Henry', 'We have here David\'s warm and pathetic speech to Saul, wherein he endeavours to convince him that he did him a great deal of wrong in persecuting him thus and to persuade him therefore to be reconciled.\nI. He calls him father (Sa1 24:11), for he was not only, as king, the father of his country, but he was, in particular, his father-in-law. From a father one may expect compassion and a favourable opinion. For a prince to seek the ruin of any of his good subjects is as unnatural as for a father...', 'teologico');
add('1sm', 24, 16, 'Matthew Henry', 'Here we have,\nI. Saul\'s penitent reply to David\'s speech. It was strange that he had patience to hear him out, considering how outrageous he was against him, and how cutting David\'s discourse was. But God restrained him and his men; and we may suppose Saul struck with amazement at the singularity of the event, and much more when he found how much he had lain at David\'s mercy. His heart must have been harder than a stone if this had not affected him. 1. He melted into tears, and we will not su...', 'teologico');
add('1sm', 25, 1, 'Matthew Henry', 'We have here a short account of Samuel\'s death and burial. 1. Though he was a great man, and one that was admirably well qualified for public service, yet he spent the latter end of his days in retirement and obscurity, not because he was superannuated (for he knew how to preside in a college of the prophets, Sa1 19:20), but because Israel had rejected him, for which God thus justly chastised them, and because his desire was to be quiet and to enjoy himself and his God in the exercises of dev...', 'teologico');
add('1sm', 25, 2, 'Matthew Henry', 'Here begins the story of Nabal.\nI. A short account of him, who and what he was (Sa1 25:2, Sa1 25:3), a man wee should never have heard of if there had not happened some communication between him and David. Observe, 1. His name: Nabal - a fool; so it signifies. It was a wonder that his parents would give him that name and an ill omen of what proved to be this character. Yet indeed we all of us deserve to be so called when we come into the world, for man is born like the wild ass\'s colt and foo...', 'teologico');
add('1sm', 25, 12, 'Matthew Henry', 'Here is, I. The report made to David of the abuse Nabal had given to his messengers (Sa1 25:12): They turned their way. They showed their displeasure, as became them to do, by breaking off abruptly from such a churl, but prudently governed themselves so well as not to render railing for railing, not to call him as he deserved, much less to take by force what ought of right to have been given them, but came and told David that he might do as he thought fit. Christ\'s servants, when they are thu...', 'teologico');
add('1sm', 25, 18, 'Matthew Henry', 'We have here an account of Abigail\'s prudent management for the preserving of her husband and family from the destruction that was just coming upon them; and we find that she did her part admirably well and fully answered her character. The passion of fools often makes those breaches in a little time which the wise, with all their wisdom, have much ado to make up again. It is hard to say whether Abigail was more miserable in such a husband or Nabal happy in such a wife. A virtuous woman is a ...', 'teologico');
add('1sm', 25, 32, 'Matthew Henry', 'As an ear-ring of gold, and an ornament of fine gold, so is a wise reprover upon an obedient ear, Pro 25:12. Abigail was a wise reprover of David\'s passion, and he gave an obedient ear to the reproof, according to his own principle (Psa 141:5): Let the righteous smite me, it shall be a kindness. Never was such an admonition either better given or better taken.\nI. David gives God thanks for sending him this happy check to a sinful way (Sa1 25:32): Blessed be the Lord God of Israel, who sent th...', 'teologico');
add('1sm', 25, 36, 'Matthew Henry', 'We are now to attend Nabal\'s funeral and Abigail\'s wedding.\nI. Nabal\'s funeral. The apostle speaks of some that were twice dead, Jde 1:12. We have hare Nabal thrice dead, though but just now wonderfully rescued from the sword of David and delivered from so great a death; for the preservations of wicked men are but reservations for some further sorer strokes of divine wrath. Here is,\n1. Nabal dead drunk, Sa1 25:36. Abigail came home, and, it should seem, he had so many people and so much plent...', 'teologico');
add('1sm', 26, 1, 'Matthew Henry', 'Here, 1. Saul gets information of David\'s movements and acts offensively. The Ziphites came to him and told him where David now was, in the same place where he was when they formerly betrayed him, Sa1 23:19. Perhaps (though it is not mentioned) Saul had given them intimation, under-hand, that he continued his design against David, and would be glad of their assistance. If not, they were very officious to Saul, aware of what would please him, and very malicious against David, to whom they desp...', 'teologico');
add('1sm', 26, 6, 'Matthew Henry', 'Here is, I. David\'s bold adventure into Saul\'s camp in the night, accompanied only by his kinsman Abishai, the son of Zeruiah. He proposed it to him and to another of his confidants (Sa1 26:6), but the other either declined it as too dangerous an enterprise, or at least was content that Abishai, who was forward to it, should run the risk of it rather than himself. Whether David was prompted to do this by his own courage, or by an extraordinary impression upon his spirits, or by the oracle, do...', 'teologico');
add('1sm', 26, 13, 'Matthew Henry', 'David having got safely from Saul\'s camp himself, and having brought with him proofs sufficient that he had been there, posts himself conveniently, so that they might hear him and yet not reach him (Sa1 26:13), and then begins to reason with them upon what had passed.\nI. He reasons ironically with Abner, and keenly banters him. David knew well that it was from the mighty power of God that Abner and the rest of the guards were cast into so deep a sleep, and that God\'s immediate hand was in it;...', 'teologico');
add('1sm', 26, 21, 'Matthew Henry', 'Here is, I. Saul\'s penitent confession of his fault and folly in persecuting David and his promise to do so no more. This second instance of David\'s respect to him wrought more upon him than the former, and extorted from him better acknowledgements, Sa1 26:21. 1. He owns himself melted and quite overcome by David\'s kindness to him: "My soul was precious in thy eyes this day, which, I thought, had been odious!" 2. He acknowledges he has done very wrong to persecute him, that he has therein act...', 'teologico');
add('1sm', 27, 1, 'Matthew Henry', 'Here is, I. The prevalency of David\'s fear, which was the effect of the weakness of his faith (Sa1 27:1): He said to his heart (so it may be read), in his communings with it concerning his present condition, I shall now perish one day by the hand of Saul. He represented to himself the restless rage and malice of Saul (who could not be wrought into a reconciliation) and the treachery of his own countrymen, witness that of the Ziphites, once and again; he looked upon his own forces, and observe...', 'teologico');
add('1sm', 27, 8, 'Matthew Henry', 'Here is an account of David\'s actions while he was in the land of the Philistines, a fierce attack he made upon some remains of the devoted nations, his success in it, and the representation he gave of it to Achish. 1. We may acquit him of injustice and cruelty in this action because those people whom he cut off were such as heaven had long since doomed to destruction, and he that did it was one whom heaven had ordained to dominion; so that the thing was very fit to be done, and he was very f...', 'teologico');
add('1sm', 28, 1, 'Matthew Henry', 'Here is, I. The design of the Philistines against Israel. They resolved to fight them, Sa1 28:1. If the Israelites had not forsaken God, there would have been no Philistines remaining to molest them; if Saul had not forsaken him, they would by this time have been put out of all danger by them. The Philistines took an opportunity to make this attempt when they had David among them, whom they feared more than Saul and all his forces.\nII. The expectation Achish had of assistance from David in th...', 'teologico');
add('1sm', 28, 7, 'Matthew Henry', 'Here, I. Saul seeks for a witch, Sa1 28:7. When God answered him not, if he had humbled himself by repentance and persevered in seeking God, who knows but that at length he might have been entreated for him? but, since he can discern no comfort either from heaven or earth (Isa 8:21, Isa 8:22), he resolves to knock at the gates of hell, and to see if any there will befriend him and give him advice: Seek me a woman that has a familiar spirit, Sa1 28:7. And his servants were too officious to ser...', 'teologico');
add('1sm', 28, 15, 'Matthew Henry', 'We have here the conference between Saul and Satan. Saul came in disguise (Sa1 28:8), but Satan soon discovered him, Sa1 28:12. Satan comes in disguise, in the disguise of Samuel\'s mantle, and Saul cannot discover him. Such is the disadvantage we labour under, in wrestling with the rulers of the darkness of this world, that they know us, while we are ignorant of their wiles and devices.\nI. The spectre, or apparition, personating Samuel, asks why he is sent for (Sa1 28:15): Why hast thou disqu...', 'teologico');
add('1sm', 28, 20, 'Matthew Henry', 'We are here told how Saul received this terrible message from the ghost he consulted. He desired to be told what he should do (Sa1 28:15), but was only told what he had not done and what should be done to him. Those that expect any good counsel or comfort otherwise than from God, and in the way of his institutions, will be as wretchedly disappointed as Saul here was. Observe,\nI. How he sunk under the load, Sa1 28:20. He was indeed unfit to bear it, having eaten nothing all the day before, nor...', 'teologico');
add('1sm', 29, 1, 'Matthew Henry', 'Here is, I. The great strait that David was in, which we may suppose he himself was aware of, though we read not of his asking advice from God, nor of any project of his own to get clear of it. The two armies of the Philistines and the Israelites were encamped and ready to engage, Sa1 29:1. Achish, who had been kind to David, had obliged him to come himself and bring the forces he had into his service. David came accordingly, and, upon a review of the army, was found with Achish, in the post ...', 'teologico');
add('1sm', 29, 6, 'Matthew Henry', 'If the reasons Achish had to trust David were stronger than the reasons which the princes offered why they should distrust him (as I do not see that, in policy, they were, for the princes were certainly in the right), yet Achish was but one of five, though the chief, and the only one that had the title of king; accordingly, in a council of war held on this occasion, he was over-voted, and obliged to dismiss David, though he was extremely fond of him. Kings cannot always do as they would, nor ...', 'teologico');
add('1sm', 30, 1, 'Matthew Henry', 'Here we have, I. The descent which the Amalekites made upon Ziklag in David\'s absence, and the desolations they made there. They surprised the city when it was left unguarded, plundered it, burnt it, and carried all the women and children captives, Sa1 30:1, Sa1 30:2. They intended, by this to revenge the like havoc that David had lately made of them and their country, Sa1 27:8. He that had made so many enemies ought not to have left his own concerns so naked and defenceless. Those that make ...', 'teologico');
add('1sm', 30, 7, 'Matthew Henry', 'Solomon observes that the righteous is delivered out of trouble and the wicked cometh in his stead, that the just falleth seven times a-day and riseth again; so it was with David. Many were his troubles, but the Lord delivered him out of them all, and particularly out of this of which we have here an account.\nI. He enquired of the Lord both concerning his duty - Shall I pursue after this troop? and concerning the event - Shall I overtake them? Sa1 30:8. It was a great advantage to David that ...', 'teologico');
add('1sm', 30, 21, 'Matthew Henry', 'We have here an account of the distribution of the spoil which as taken from the Amalekites. When the Amalekites had carried away a rich booty from the land of Judah and the Philistines they spent it in sensuality, in eating, and drinking, and making merry with it; but David disposed of the spoil taken after another manner, as one that knew that justice and charity must govern us in the use we make of whatever we have in this world. What God gives us he designs we should do good with, not ser...', 'teologico');
add('1sm', 31, 1, 'Matthew Henry', 'The day of recompence has now come, in which Saul must account for the blood of the Amalekites which he had sinfully spared, and that of the priests which he had more sinfully spilt; that of David too, which he would have spilt, must come into the account. Now his day has come to fall, as David foresaw, when he should descend into battle and perish, Sa1 26:10. Come and see the righteous judgments of God.\nI. He sees his soldiers fall about him, Sa1 31:1. Whether the Philistines were more numer...', 'teologico');
add('1sm', 31, 8, 'Matthew Henry', 'The scripture makes no mention of the souls of Saul and his sons, what became of them after they were dead (secret things belong not to us), but of their bodies only.\nI. How they were basely abused by the Philistines. The day after the battle, when they had recovered their fatigue, they came to strip the slain, and, among the rest, found the bodies of Saul and his three sons, Sa1 31:8. Saul\'s armour-bearer perhaps intended to honour his master by following the example of his self-murder, and ...', 'teologico');

// 2SM (75 comentários)
add('2sm', 7, 16, 'Calvino', 'A tua casa será estabelecida para sempre — A aliança davídica aponta para o reino eterno de Cristo.', 'teologico');
add('2sm', 12, 13, 'Agostinho', 'O Senhor perdoou o teu pecado — O arrependimento sincero encontra perdão imediato em Deus.', 'teologico');
add('2sm', 22, 31, 'Spurgeon', 'O caminho do Senhor é perfeito — A Palavra de Deus é escudo para os que nEle se refugiam.', 'teologico');
add('2sm', 1, 1, 'Matthew Henry', 'Here is, I. David settling again in Ziklag, his own city, after he had rescued his family and friends out of the hands of the Amalekites (Sa2 1:1): He abode in Ziklag. Thence he was now sending presents to his friends (Sa1 30:26), and there he was ready to receive those that came into his interests; not men in distress and debt, as his first followers were, but persons of quality in their country, mighty men, men of war, and captains of thousands (as we find, Ch1 12:1, Ch1 12:8, Ch1 12:20); s...', 'teologico');
add('2sm', 1, 11, 'Matthew Henry', 'Here is, I. David\'s reception of these tidings. So far was he from falling into a transport of joy, as the Amalekite expected, that he fell into a passion of weeping, rent his clothes (Sa2 1:11), mourned and fasted (Sa2 1:12), not only for his people Israel and Jonathan his friend but for Saul his enemy. This he did, not only as a man of honour, in observance of that decorum which forbids us to insult over those that are fallen, and requires us to attend our relations to the grave with respec...', 'teologico');
add('2sm', 1, 17, 'Matthew Henry', 'When David had rent his clothes, mourned, and wept, and fasted, for the death of Saul, and done justice upon him who made himself guilty of it, one would think he had made full payment of the debt of honour he owed to his memory; yet this is not all: we have here a poem he wrote on that occasion; for he was a great master of his pen as well as of his sword. By this elegy he designed both to express his own sorrow for this great calamity and to impress the like on the minds of others, who ough...', 'teologico');
add('2sm', 2, 1, 'Matthew Henry', 'When Saul and Jonathan were dead, though David knew himself anointed to be king, and now saw his way very clear, yet he did not immediately send messengers through all the coasts of Israel to summon all people to come in and swear allegiance to him, upon pain of death, but proceeded leisurely; for he that believeth doth not make haste, but waits God\'s time for the accomplishment of God\'s promises. Many had come in to his assistance from several tribes while he continued at Ziklag, as we find ...', 'teologico');
add('2sm', 2, 8, 'Matthew Henry', 'Here is, I. A rivalship between two kings - David, whom God made king, and Ishbosheth, whom Abner made king. One would have thought, when Saul was slain, and all his sons that had sense and spirit enough to take the field with him, David would come to the throne without any opposition, since all Israel knew, not only how he had signalized himself, but how manifestly God had designated him to it; but such a spirit of contradiction is there, in the devices of men, to the counsels of God, that s...', 'teologico');
add('2sm', 2, 18, 'Matthew Henry', 'We have here the contest between Abner and Asahel. Asahel, the brother of Joab and cousin-german to David, was one of the principal commanders of David\'s forces, and was famous for swiftness in running: he was as light of foot as a wild roe (Sa2 2:18); this he got the name of by swift pursuing, not swift flying. Yet, we may suppose, he was not comparable to Abner as a skilful experienced soldier; we must therefore observe,\nI. How rash he was in aiming to make Abner his prisoner. He pursued af...', 'teologico');
add('2sm', 2, 25, 'Matthew Henry', 'Here, I. Abner, being conquered, meanly begs for a cessation of arms. He rallied the remains of his forces on the top of a hill (Sa2 2:25), as if he would have made head again, but becomes a humble supplicant to Joab for a little breathing-time, Sa2 2:26. He that was most forward to fight was the first that had enough of it. He that made a jest of bloodshed (Let the young men arise and play before us, Sa2 2:14) is now shocked at it, when he finds himself on the losing side, and the sword he m...', 'teologico');
add('2sm', 3, 1, 'Matthew Henry', 'Here is, I. The struggle that David had with the house of Saul before his settlement in the throne was completed, Sa2 3:1. 1. Both sides contested. Saul\'s house, though beheaded and diminished, would not fall tamely. It is not strange between them, but one would wonder it should be a long war, when David\'s house had right on its side, and therefore God on its side; but, though truth and equity will triumph at last, God made for wise and holy ends prolonged the conflict. The length of this war...', 'teologico');
add('2sm', 3, 7, 'Matthew Henry', 'Here, I. Abner breaks with Ish-bosheth, and deserts his interest, upon a little provocation which Ish-bosheth unadvisedly gave him. God can serve his own purposes by the sins and follies of men. 1. Ish-bosheth accused Abner of no less a crime than debauching one of his father\'s concubines, Sa2 3:7. Whether it was so or no does not appear, nor what ground he had for the suspicion: but, however it was, it would have been Ish-bosheth\'s prudence to be silent, considering how much it was his inter...', 'teologico');
add('2sm', 3, 22, 'Matthew Henry', 'We have here an account of the murder of Abner by Joab, and David\'s deep resentment of it.\nI. Joab very insolently fell foul upon David for treating with Abner. He happened to be abroad upon service when Abner was with David, pursuing a troop, either of Philistines or of Saul\'s party; but, upon his return, he was informed that Abner was just gone (Sa2 3:22, Sa2 3:23), and that a great many kind things had passed between David and him. He had all the reason in the world to be satisfied of Davi...', 'teologico');
add('2sm', 4, 1, 'Matthew Henry', 'Here is, I. The weakness of Saul\'s house. Still it grew weaker and weaker. 1. As for Ishbosheth, who was in possession of the throne, his hands were feeble, Sa2 4:1. All the strength they ever had was from Abner\'s support, and now that he was dead he had no spirit left in him. Though Abner had, in a passion, deserted his interest, yet he hoped, by his means, to make good terms with David; but now even this hope fails him, and he sees himself forsaken by his friends and at the mercy of his ene...', 'teologico');
add('2sm', 4, 9, 'Matthew Henry', 'We have here justice done upon the murderers of Ish-bosheth.\nI. Sentence passed upon them. There needed no evidence, their own tongues witnessed against them; they were so far from denying the fact that they gloried in it. David therefore shows them the heinousness of the crime, and that blood called for blood from his hand, who was now the chief magistrate, and was by office the avenger of blood. And, perhaps, he was the more vigorous in the prosecution because for reasons of state he had sp...', 'teologico');
add('2sm', 5, 1, 'Matthew Henry', 'Here is, I. The humble address of all the tribes to David, beseeching him to take upon him the government (for they were now as sheep having no shepherd), and owning him for their king. Though David might by no means approve the murder of Ish-bosheth, yet he might improve the advantages he gained thereby, and accept the applications made to him thereupon. Judah had submitted to David as their king above seven years ago, and their ease and happiness, under his administration, encouraged the re...', 'teologico');
add('2sm', 5, 6, 'Matthew Henry', 'If Salem, the place of which Melchizedec was king, was Jerusalem (as seems probable from Psa 76:2), it was famous in Abraham\'s time. Joshua, in his time, found it the chief city of the south part of Canaan, Jos 10:1-3. It fell to Benjamin\'s lot (Jos 18:28), but joined close to Judah\'s, Jos 15:8. The children of Judah had taken it (Jdg 1:8), but the children of Benjamin suffered the Jebusites to dwell among them (Jdg 1:21), and they grew so upon them that it became a city of Jebusites, Jdg 19:...', 'teologico');
add('2sm', 5, 11, 'Matthew Henry', 'Here is, I. David\'s house built, a royal palace, fit for the reception of the court he kept and the homage that was paid to him, Sa2 5:11. The Jews were husbandmen and shepherds, and did not much addict themselves either to merchandise or manufactures; and therefore Hiram, king of Tyre, a wealthy prince, when he sent to congratulate David on his accession to the throne, offered him workmen to build him a house. David thankfully accepted the offer, and Hiram\'s workmen built David a house to hi...', 'teologico');
add('2sm', 5, 17, 'Matthew Henry', 'The particular service for which David was raised up was to save Israel out of the hand of the Philistines, Sa2 3:18. This therefore divine Providence, in the first place, gives him an opportunity of accomplishing. Two great victories obtained over the Philistines we have here an account of, by which David not only balanced the disgrace and retrieved the loss Israel had sustained in the battle wherein Saul was slain, but went far towards the total subduing of those vexatious neighbours, the l...', 'teologico');
add('2sm', 6, 1, 'Matthew Henry', 'We have not heard a word of the ark since it was lodged in Kirjath-jearim, immediately after its return out of its captivity among the Philistines (Sa1 7:1, Sa1 7:2), except that, once, Saul called for it, Sa1 14:18. That which in former days had made so great a figure is now thrown aside, as a neglected thing, for many years. And, if now the ark was for so many years in a house, let it not seem strange that we find the church so long in the wilderness, Rev 12:14. Perpetual visibility is no m...', 'teologico');
add('2sm', 6, 6, 'Matthew Henry', 'We have here Uzzah struck dead for touching the ark, when it was upon its journey towards the city of David, a sad providence, which damped their mirth, stopped the progress of the ark, and for the present, dispersed this great assembly, which had come together to attend it, and sent them home in a fright.\nI. Uzzah\'s offence seems very small. He and his brother Ahio, the sons of Abinadab, in whose house the ark had long been lodged, having been used to attend it, to show their willingness to ...', 'teologico');
add('2sm', 6, 12, 'Matthew Henry', 'We have here the second attempt to bring the ark home to the city of David; and this succeeded, though the former miscarried.\nI. It should seem the blessing with which the house of Obed-edom was blessed for the ark\'s sake was a great inducement to David to bring it forward; for when that was told him (Sa2 6:12) he hastened to fetch it to him. For, 1. It was an evidence that God was reconciled to them, and his anger was turned away. As David could read God\'s frowns upon them all in Uzzah\'s str...', 'teologico');
add('2sm', 6, 20, 'Matthew Henry', 'David, having dismissed the congregation with a blessing, returned to bless his household (Sa2 6:20), that is, to pray with them and for them, and to offer up his family thanksgiving for this national mercy. Ministers must not think that their public performances will excuse them from their family-worship; but when they have, with their instructions and prayers, blessed the solemn assemblies, they must return in the same manner to bless their households, for with them they are in a particular...', 'teologico');
add('2sm', 7, 1, 'Matthew Henry', 'Here is, I. David at rest. He sat in his house (Sa2 7:1), quiet and undisturbed, having no occasion to take the field: The Lord had given him rest round about, from all those that were enemies to his settlement in the throne, and he set himself to enjoy that rest. Though he was a man of war, he was for peace (Psa 120:7) and did not delight in war. He had not been long at rest, nor was it long before he was again engaged in war; but at present he enjoyed a calm, and he was in his element when ...', 'teologico');
add('2sm', 7, 4, 'Matthew Henry', 'We have here a full revelation of God\'s favour to David and the kind intentions of that favour, the notices and assurances of which God sent him by Nathan the prophet, whom he entrusted to deliver this long message to him. The design of it is to take him off from his purpose of building the temple and it was therefore sent, 1. By the same hand that had given him encouragement to do it, lest, if it had been sent by any other, Nathan should be despised and insulted and David should be perplexed...', 'teologico');
add('2sm', 7, 18, 'Matthew Henry', 'We have here the solemn address David made to God, in answer to the gracious message God had sent him. We are not told what he said to Nathan; no doubt he received him very kindly and respectfully as God\'s messenger. But his answer to God he took himself, and did not send by Nathan. When ministers deliver God\'s message to us, it is not to them, but to God, that our hearts must reply; he understands the language of the heart, and to him we may come boldly. David had no sooner received the mess...', 'teologico');
add('2sm', 8, 1, 'Matthew Henry', 'God had given David rest from all his enemies that opposed him and made head against him; and he having made a good use of that rest, has now commission given him to make war upon them, and to act offensively for the avenging of Israel\'s quarrels and the recovery of their rights; for as yet they were not in full possession of that country to which by the promise of God they were entitled.\nI. He quite subdued the Philistines, Sa2 8:1. They had attacked him when they thought him weak (Sa2 5:17)...', 'teologico');
add('2sm', 8, 9, 'Matthew Henry', 'Here is, 1. The court made to David by the king of Hamath, who, it seems was at this time at war with the king of Zobah. He hearing of David\'s success against his enemy, sent his own son ambassador to him (Sa2 8:9, Sa2 8:10), to congratulate him on his victory, to return him thanks for the favour he had done him in breaking the power of one he was in fear of, and to beg his friendship. Thus he not only secured but strengthened himself. And David lost nothing by taking this little prince under...', 'teologico');
add('2sm', 8, 15, 'Matthew Henry', 'David was not so engaged in his wars abroad as to neglect the administration of the government at home.\nI. His care extended itself to all the parts of his dominion: He reigned over all Israel (Sa2 8:15); not only he had a right to reign over all the tribes, but he did so; they were all safe under his protection, and shared in the fruits of his good government.\nII. He did justice with an unbiased unshaken hand: He executed judgment unto all his people, neither did wrong nor denied or delayed ...', 'teologico');
add('2sm', 9, 1, 'Matthew Henry', 'Here is, I. David\'s enquiry after the remains of the ruined house of Saul, Sa2 9:1. This was a great while after his accession to the throne, for it should seem that Mephibosheth, who was but five years old when Saul died, had now a son born, Sa2 9:12. David had too long forgotten his obligations to Jonathan, but now, at length, they are brought to his mind. It is good sometimes to bethink ourselves whether there be any promises or engagements that we have neglected to make good; better do it...', 'teologico');
add('2sm', 9, 9, 'Matthew Henry', 'The matter is here settled concerning Mephibosheth. 1. This grant of his father\'s estate is confirmed to him, and Ziba called to be a witness to it (Sa2 9:9); and, it should seem, Saul had a very good estate, for his father was a mighty man of substance (Sa1 9:1), and he had fields and vineyards to bestow, Sa1 22:7. Be it ever so much, Mephibosheth is now master of it all. 2. The management of the estate is committed to Ziba, who knew what it was and how to make the most of it, in whom, havin...', 'teologico');
add('2sm', 10, 1, 'Matthew Henry', 'Here is, I. The great respect David paid to his neighbour, the king of the Ammonites, Sa2 10:1, Sa2 10:2. 1. The inducement to it was some kindness he had formerly received from Nahash the deceased king. He showed kindness to me, says David (Sa2 10:2), and therefore (having lately had satisfaction in showing kindness to Mephibosheth for his father\'s sake) he resolves to show kindness to his son, and to keep up a friendly correspondence with him. Thus the pleasure of doing one kind and generou...', 'teologico');
add('2sm', 10, 6, 'Matthew Henry', 'Here we have, I. The preparation which the Ammonites made for war, Sa2 10:6. They saw they had made themselves very odious to David and obnoxious to his just displeasure. This they might easily have foreseen when they abused his ambassadors, which was no other than a challenge to war, and a bold defiance of him. Yet, it seems, they had not considered how unable they were, with their thousands, to meet his; for now they found themselves an unequal match, and were forced to hire forces of other...', 'teologico');
add('2sm', 10, 15, 'Matthew Henry', 'Here is, 1. A new attempt of the Syrians to recover their lost honour and to check the progress of David\'s victorious arms. The forces that were lately dispersed rallied again, and gathered themselves together, Sa2 10:15. Even the baffled cause will make head as long as there is any life in it; the enemies of the Son of David do so, Matt, Sa2 22:34; Rev 19:19. These, being conscious of their insufficiency, called in the aid of their allies and dependencies on the other side of the river (Sa2 ...', 'teologico');
add('2sm', 11, 1, 'Matthew Henry', 'Here is, I. David\'s glory, in pursuing the war against the Ammonites, Sa2 11:1. We cannot take that pleasure in viewing this great action which hitherto we have taken in observing David\'s achievements, because the beauty of it was stained and sullied by sin; otherwise we might take notice of David\'s wisdom and bravery in following his blow. Having routed the army of the Ammonites in the field, as soon as ever the season of the year permitted he sent more forces to waste the country and furthe...', 'teologico');
add('2sm', 11, 6, 'Matthew Henry', 'Uriah, we may suppose, had now been absent from his wife some weeks, making the campaign in the country of the Ammonites, and not intending to return till the end of it. The situation of his wife would bring to light the hidden works of darkness; and when Uriah, at his return, should find how he had been abused, and by whom, it might well be expected, 1. That he would prosecute his wife, according to law, and have her stoned to death; for jealousy is the rage of a man, especially a man of hon...', 'teologico');
add('2sm', 11, 14, 'Matthew Henry', 'When David\'s project of fathering the child upon Uriah himself failed, so that, in process of time, Uriah would certainly know the wrong that had been done him, to prevent the fruits of his revenge, the devil put it into David\'s heart to take him off, and then neither he nor Bath-sheba would be in any danger (what prosecution could there be when there was no prosecutor?), suggesting further that, when Uriah was out of the way, Bath-sheba might, if he pleased, be his own for ever. Adulteries h...', 'teologico');
add('2sm', 12, 1, 'Matthew Henry', 'It seems to have been a great while after David had been guilty of adultery with Bath-sheba before he was brought to repentance for it. For, when Nathan was sent to him, the child was born (Sa2 12:14), so that it was about nine months that David lay under the guilt of that sin, and, for aught that appears, unrepented of. What shall we think of David\'s state all this while? Can we imagine that his heart never smote him for it, or that he never lamented it in secret before God? I would willingl...', 'teologico');
add('2sm', 12, 15, 'Matthew Henry', 'Nathan, having delivered his message, staid not at court, but went home, probably to pray for David, to whom he had been preaching. God, in making use of him as an instrument to bring David to repentance, and as the herald both of mercy and judgment, put an honour upon the ministry, and magnified his word above all his name. David named one of his sons by Bath-sheba Nathan, in honour of this prophet (Ch1 3:5), and it was that son of whom Christ, the great prophet, lineally descended, Luk 3:31...', 'teologico');
add('2sm', 12, 26, 'Matthew Henry', 'We have here an account of the conquest of Rabbah, and other cities of the Ammonites. Though this comes in here after the birth of David\'s child, yet it is most probable that it was effected a good while before, and soon after the death of Uriah, perhaps during the days of Bath-sheba\'s mourning for him. Observe, 1. That God was very gracious in giving David this great success against his enemies, notwithstanding the sin he had been guilty of just at that time when he was engaged in this war, ...', 'teologico');
add('2sm', 13, 1, 'Matthew Henry', 'We have here a particular account of the abominable wickedness of Amnon in ravishing his sister, a subject not fit to be enlarged upon nor indeed to be mentioned without blushing, that ever any man should be so vile, especially that a son of David should be so. Amnon\'s character, we have reason to think, was bad in other things; if he had not forsaken God, he would never have been given up to these vile affections. Godly parents have often been afflicted with wicked children; grace does not r...', 'teologico');
add('2sm', 13, 21, 'Matthew Henry', 'What Solomon says of the beginning of strife is as true of the beginning of all sin, it is as the letting forth of water; when once the flood-gates are plucked up, an inundation follows; one mischief begets another, and it is hard to say what shall be in the end thereof.\nI. We are here told how David resented the tidings of Amnon\'s sin: He was very wroth, Sa2 13:21. So he had reason to be, that his own son should do such a wicked thing and draw him to be accessory to it. It would be a reproac...', 'teologico');
add('2sm', 13, 30, 'Matthew Henry', 'Here is, I. The fright that David was put into by a false report brought to Jerusalem that Absalom had slain all the king\'s sons, Sa2 13:30. It is common for fame to make bad worse; and the first news of such a thing as this represents it as more dreadful than afterwards it proves. Let us not therefore be afraid of evil tidings, while they want confirmation, but, when we hear the worst, hope the best, at least hope better. However, this false news gave as much affliction to David, for the pre...', 'teologico');
add('2sm', 14, 1, 'Matthew Henry', 'Here is, I. Joab\'s design to get Absalom recalled out of banishment, his crime pardoned, and his attainder reversed, Sa2 14:1. Joab made himself very busy in this affair. 1. As a courtier that was studious, by all ways possible, to ingratiate himself with his prince and improve his interest in his favour: He perceived that the king\'s heart was towards Absalom, and that, the heat of his displeasure being over, he still retained his old affection for him, and only wanted a friend to court him t...', 'teologico');
add('2sm', 14, 21, 'Matthew Henry', 'Observe here, I. Orders given for the bringing back of Absalom. The errand on which the woman came to David was so agreeable, and her management of it so very ingenious and surprising, that he was brought into a peculiarly kind humour: Go (says he to Joab), bring the young man Absalom again, Sa2 14:21. He was himself inclined to favour him, yet, for the honour of his justice, he would not do it but upon intercession made for him, which may illustrate the methods of divine grace. It is true Go...', 'teologico');
add('2sm', 14, 28, 'Matthew Henry', 'Three years Absalom had been an exile from his father-in-law, and now two years a prisoner at large in his own house, and, in both, better dealt with than he deserved; yet his spirit was still unhumbled, his pride unmortified, and, instead of being thankful that his life is spared, he thinks himself sorely wronged that he is not restored to all his places at court. Had he truly repented of his sin, his distance from the gaieties of the court, and his solitude and retirement in his own house, ...', 'teologico');
add('2sm', 15, 1, 'Matthew Henry', 'Absalom is no sooner restored to his place at court than he aims to be in the throne. He that was unhumbled under his troubles became insufferably proud when they were over; and he cannot be content with the honour of being the king\'s son, and the prospect of being his successor, but he must be king now. His mother was a king\'s daughter; on that perhaps he valued himself, and despised his father, who was but the son of Jesse. She was the daughter of a heathen king, which made him the less con...', 'teologico');
add('2sm', 15, 7, 'Matthew Henry', 'We have here the breaking out of Absalom\'s rebellion, which he had long been contriving. It is said to be after forty years, Sa2 15:7. But whence it is to be dated we are not told; not from David\'s beginning his reign, for then it would fall in the last year of his life, which is not probable; but either from his first anointing by Samuel seven years before, or rather (I think) from the people\'s desiring a king, and the first change of the government into a monarchy, which might be about ten ...', 'teologico');
add('2sm', 15, 13, 'Matthew Henry', 'Here is, I. The notice brought to David of Absalom\'s rebellion, Sa2 15:13. The matter was bad enough, and yet it seems to have been made worse to him (as such things commonly are) than really it was; for he was told that the hearts of the men of Israel (that is, the generality of them, at least the leading men) were after Absalom. But David was the more apt to believe it because now he could call to mind the arts that Absalom had used to inveigle them, and perhaps reflected upon it with regre...', 'teologico');
add('2sm', 15, 24, 'Matthew Henry', 'Here we have, I. The fidelity of the priests and Levites and their firm adherence to David and his interest. They knew David\'s great affection to them and their office, notwithstanding his failings. The method Absalom took to gain people\'s affections made no impression upon them; he had little religion in him, and therefore they steadily adhered to David. Zadok and Abiathar, and all the Levites, if he go, will accompany him, and take the ark with them, that, by it, they may ask counsel of God...', 'teologico');
add('2sm', 15, 31, 'Matthew Henry', 'Nothing, it seems, appeared to David more threatening in Absalom\'s plot than that Ahithophel was in it; for one good head, in such a design, is worth a thousand good hands. Absalom was himself no politician, but he had got one entirely in his interest that was, and would be the more dangerous because he had been all along acquainted with David\'s counsels and affairs; if therefore he can be baffled, Absalom is as good as routed and the head of the conspiracy cut off. This David endeavours to d...', 'teologico');
add('2sm', 16, 1, 'Matthew Henry', 'We read before how kind David was to Mephibosheth the son of Jonathan, how he prudently entrusted his servant Ziba with the management of his estate, while he generously entertained him at his own table, Sa2 9:10. This matter was well settled; but, it seems, Ziba is not content to be manager, he longs to be master, of Mephibosheth\'s estate. Now, he thinks, is his time to make himself so; if he can procure a grant of it from the crown, whether David or Absalom get the better it is all one to h...', 'teologico');
add('2sm', 16, 5, 'Matthew Henry', 'We here find how David bore Shimei\'s curses much better than he had borne Ziba\'s flatteries. By the latter he was brought to pass a wrong judgment on another, by the former to pass a right judgment on himself. The world\'s smiles are more dangerous than its frowns. Observe here,\nI. How insolent and furious Shimei was, and how his malice took occasion from David\'s present distress to be so much the more outrageous. David, in his flight, had come to Bahurim, a city of Benjamin in or near which t...', 'teologico');
add('2sm', 16, 15, 'Matthew Henry', 'Absalom had notice sent him speedily by some of his friends at Jerusalem that David had withdrawn, and with what a small retinue he had gone; so that the coasts were clear, Absalom might take possession of Jerusalem when he pleased. The gates were open, and there was none to oppose him. Accordingly he came without delay (Sa2 16:15), extremely elevated, no doubt, with this success at first, and that that in which, when he formed his design, he probably apprehended the greatest difficulty, was ...', 'teologico');
add('2sm', 17, 1, 'Matthew Henry', 'Absalom is now in peaceable possession of Jerusalem; the palace-royal is his own, as are the thrones of judgment, even the thrones of the house of David. His good father reigned in Hebron, and only over the tribe of Judah, above seven years, and was not hasty to destroy his rival; his government was built upon a divine promise, the performance of which he was sure of in due time, and therefore he waited patiently in the mean time. But the young man, Absalom, not only hastens from Hebron to Je...', 'teologico');
add('2sm', 17, 15, 'Matthew Henry', 'We must now leave David\'s enemies pleasing themselves with the thoughts of a sure victory by following Hushai\'s counsel, and sending a summons, no doubt, to all the tribes of Israel, to come to the general rendezvous at a place appointed, pursuant to that counsel; and we next find David\'s friends consulting how to get him notice of all this, that he might steer his course accordingly. Hushai tells the priests what had passed in council, Sa2 17:15. But, it should seem, he was not sure but that...', 'teologico');
add('2sm', 17, 22, 'Matthew Henry', 'Here is, I. The transporting of David and his forces over Jordan, pursuant to the advice he had received from his friends at Jerusalem, Sa2 17:22. He, and all that were with him, went over in the night, whether in ferryboats, which probably always plied there, or through the fords, does not appear. But special notice is taken of this, that there lacked not one of them: none deserted him, though his distress was great, none staid behind sick or weary, nor were any lost or cast away in passing ...', 'teologico');
add('2sm', 18, 1, 'Matthew Henry', 'Which way David raised an army here, and what reinforcements were sent him, we are not told; many, it is likely, from all the coasts of Israel, at least from the neighbouring tribes, came in to his assistance, so that, by degrees, he was able to make head against Absalom, as Ahithophel foresaw. Now here we have,\nI. His army numbered and marshalled, Sa2 18:1, Sa2 18:2. He had, no doubt, committed his cause to God by prayer, for that was his relief in all his afflictions; and then he took an ac...', 'teologico');
add('2sm', 18, 9, 'Matthew Henry', 'Here is Absalom quite at a loss, at his wit\'s end first, and then at his life\'s end. He that began the fight, big with the expectation of triumphing over David himself, with whom, if he had had him in his power, he would not have dealt gently, is now in the greatest consternation, when he meets the servants of David, Sa2 18:9. Though they were forbidden to meddle with him, he durst not look them in the face; but, finding they were near him, he clapped spurs to his mule and made the best of hi...', 'teologico');
add('2sm', 18, 19, 'Matthew Henry', 'Absalom\'s business is done; and we are now told,\nI. How David was informed of it. He staid behind at the city of Mahanaim, some miles from the wood where the battle was, and in the utmost border of the land. Absalom\'s scattered forces all made homeward toward Jordan, which was the contrary way from Mahanaim, so that his watchmen could not perceive how the battle went, till an express came on purpose to bring advice of the issue, which the king sat in the gate expecting to hear, Sa2 18:24.\n1. ...', 'teologico');
add('2sm', 19, 1, 'Matthew Henry', 'Soon after the messengers had brought the news of the defeat and death of Absalom to the court of Mahanaim, Joab and his victorious army followed, to grace the king\'s triumphs and receive his further orders. Now here we are told,\nI. What a damp and disappointment it was to them to find the king in tears for Absalom\'s death, which they construed as a token of displeasure against them for what they had done, whereas they expected him to have met them with joy and thanks for their good services:...', 'teologico');
add('2sm', 19, 9, 'Matthew Henry', 'It is strange that David did not immediately upon the defeat and dispersion of Absalom\'s forces march with all expedition back to Jerusalem, to regain the possession of his capital city, while the rebels were in confusion and before they could rally again. What occasion was there to bring him back? Could not he himself go back with the victorious army he had with him in Gilead? He could, no doubt; but, 1. He would go back as a prince, with the consent and unanimous approbation of the people, ...', 'teologico');
add('2sm', 19, 16, 'Matthew Henry', 'Perhaps Jordan was never passed with so much solemnity, nor with so many remarkable occurrences, as it was now, since Israel passed it under Joshua. David, in his afflictive flight, remembered God particularly from the land of Jordan (Psa 42:6), and now that land, more than any other, was graced with the glories of his return. David\'s soldiers furnished themselves with accommodations for their passage over this river, but, for his own family, a ferry-boat was sent on purpose, Sa2 19:18. A fle...', 'teologico');
add('2sm', 19, 24, 'Matthew Henry', 'The day of David\'s return was a day of bringing to remembrance, a day of account, in which what had passed in his flight was called over again; among other things, after the case of Shimei, that of Mephibosheth comes to be enquired into, and he himself brings it on.\nI. He went down in the crowd to meet the king (Sa2 19:24), and as a proof of the sincerity of his joy in the king\'s return, we are here told what a true mourner he was for the king\'s banishment. During that melancholy time, when o...', 'teologico');
add('2sm', 19, 31, 'Matthew Henry', 'David had already graced the triumphs of his restoration with the generous remission of the injuries that had been done to him; we have him here gracing them with a no less generous reward of the kindnesses that had been shown to him. Barzillai, the Gileadite, who had a noble seat at Rogelim, not far from Mahanaim, was the man who, of all the nobility and gentry of that country, had been most kind to David in his distress. If Absalom had prevailed, it is likely he would have suffered for his ...', 'teologico');
add('2sm', 19, 40, 'Matthew Henry', 'David came over Jordan attended and assisted only by the men of Judah; but when he had advanced as far as Gilgal, the first stage on this side Jordan, half the people of Israel (that is, of their elders and great men) had come to wait upon him, to kiss his hand, and congratulate him on his return, but found they came too late to witness the solemnity of his first entrance. This put them out of humour, and occasioned a quarrel between them and the men of Judah, which was a damp to the joy of t...', 'teologico');
add('2sm', 20, 1, 'Matthew Henry', 'David, in the midst of his triumphs, has here the affliction to see his kingdom disturbed and his family disgraced.\nI. His subjects revolting from him at the instigation of a man of Belial, whom they followed when they forsook the man after God\'s own heart. Observe, 1. That this happened immediately upon the crushing of Absalom\'s rebellion. We must not think it strange, while we are in this world, if the end of one trouble be the beginning of another: deep sometimes calls unto deep. 2. That t...', 'teologico');
add('2sm', 20, 4, 'Matthew Henry', 'We have here Amasa\'s fall just as he began to rise. He was nephew to David (Sa2 17:25), had been Absalom\'s general and commander-in-chief of his rebellious army, but, that being routed, he came over into David\'s interest, upon a promise that he should be general of his forces instead of Joab. Sheba\'s rebellion gives David an occasion to fulfil his promise sooner than he could wish, but Joab\'s envy and emulation rendered its fulfillment of ill consequence both to him and David.\nI. Amasa has a ...', 'teologico');
add('2sm', 20, 14, 'Matthew Henry', 'We have here the conclusion of Sheba\'s attempt.\nI. The rebel, when he had rambled over all the tribes of Israel, and found them not so willing, upon second thoughts, to follow him, as they had been upon a sudden provocation to desert David (having only picked up a few like himself, that sided with him), at length entered Abel-Beth-maacah, a strong city in the north, in the lot of Naphtali, where we find it placed, Kg2 15:29. Here he took shelter, whether by force or with consent does not appe...', 'teologico');
add('2sm', 20, 23, 'Matthew Henry', 'Here is an account of the state of David\'s court after his restoration. Joab retained the office of general, being too great to be displaced. Benaiah, as before, was captain of the guards. Here is one new office erected, which we had not (Sa2 8:16-18), that of treasurer, or one over the tribute, for it was not till towards the latter end of his time that David began to raise taxes. Adoram was long in this office, but it cost him his life at last, Kg1 12:18.', 'teologico');
add('2sm', 21, 1, 'Matthew Henry', 'Here I. Were are told of the injury which Saul had, long before this, done to the Gibeonites, which we had no account of in the history of his reign, nor should we have heard of it here but that it came now to be reckoned for. The Gibeonites were of the remnant of the Amorites (Sa2 21:2), who by a stratagem had made peace with Israel, and had the public faith pledged to them by Joshua for their safety. We had the story Jos. 9, where it was agreed (v. 23) that they should have their lives secu...', 'teologico');
add('2sm', 21, 10, 'Matthew Henry', 'Here we have, I. Saul\'s sons not only hanged, but hanged in chains, their dead bodies left hanging, and exposed, till the judgment ceased, which their death was to turn away, by the sending of rain upon the land. They died as sacrifices, and thus they were, in a manner, offered up, not consumed all at once by fire, but gradually by the air. They died as anathemas, and by this ignominious usage they were represented as execrable, because iniquity was laid upon them. When our blessed Saviour wa...', 'teologico');
add('2sm', 21, 15, 'Matthew Henry', 'We have here the story of some conflicts with the Philistines, which happened, as it should seem, in the latter end of David\'s reign. Though he had so subdued them that they could not bring any great numbers into the field, yet as long as they had any giants among them to be their champions, they would never be quiet, but took all occasions to disturb the peace of Israel, to challenge them, or make incursions upon them.\nI. David himself was engaged with one of the giants. The Philistines bega...', 'teologico');
add('2sm', 22, 1, 'Matthew Henry', 'Observe here, I. That it has often been the lot of God\'s people to have many enemies, and to be in imminent danger of falling into their hands. David was a man after God\'s heart, but not after men\'s heart: many were those that hated him, and sought his ruin; Saul is particularly named, either, 1. As distinguished from his enemies of the heathen nations. Saul hated David, but David did not hate Saul, and therefore would not reckon him among his enemies; or, rather, 2. As the chief of his enemi...', 'teologico');
add('2sm', 22, 2, 'Matthew Henry', 'Let us observe, in this song of praise,\nI. How David adores God, and gives him the glory of his infinite perfections. There is none like him, nor any to be compared with him (Sa2 22:32): Who is God, save the Lord? All others that are adored as deities are counterfeits and pretenders. None is to be relied on but he. Who is a rock, save our God? They are dead, but the Lord liveth, Sa2 22:47. They disappoint their worshippers when they most need them. But as for God his way is perfect, Sa2 22:31...', 'teologico');

// 1RS (76 comentários)
add('1rs', 3, 11, 'Matthew Henry', 'Pediste sabedoria — Deus concede sabedoria aos que buscam governar com justiça.', 'teologico');
add('1rs', 8, 27, 'Calvino', 'Os céus não te podem conter — A transcendência de Deus: nenhum templo O limita.', 'teologico');
add('1rs', 19, 12, 'Elias', 'Uma voz mansa e delicada — Deus fala no silêncio, não no tumulto. A verdadeira direção vem em quietude.', 'teologico');
add('1rs', 1, 1, 'Matthew Henry', 'David, as recorded in the foregoing chapter, had, by the great mercy of God, escaped the sword of the destroying angel. But our deliverances from or through diseases and dangers are but reprieves; if the candle be not blown out, it will burn out of itself. We have David here sinking under the infirmities of old age, and brought by them to the gates of the grave. He that cometh up out of the pit shall fall into the snare; and, one way or other, we must needs die. 1. It would have troubled one ...', 'teologico');
add('1rs', 1, 5, 'Matthew Henry', 'David had much affliction in his children. Amnon and Absalom had both been his grief; the one his first-born, the other his third, Sa2 3:2, Sa2 3:3. His second, whom he had by Abigail, we will suppose he had comfort in; his fourth was Adonijah (Sa2 3:4); he was one of those that were born in Hebron; we have heard nothing of him till now, and here we are told that he was a comely person, and that he was next in age, and (as it proved) next in temper to Absalom, Kg1 1:6. And, further, that in h...', 'teologico');
add('1rs', 1, 11, 'Matthew Henry', 'We have here the effectual endeavours that were used by Nathan and Bathsheba to obtain from David a ratification of Solomon\'s succession, for the crushing of Adonijah\'s usurpation. 1. David himself knew not what was doing. Disobedient children think that they are well enough off if they can but keep their good old parents ignorant of their bad courses; but a bird of the air will carry the voice. 2. Bathsheba lived retired, and knew nothing of it either, till Nathan informed her. Many get very...', 'teologico');
add('1rs', 1, 32, 'Matthew Henry', 'We have here the effectual care David took both to secure Solomon\'s right and to preserve the public peace, by crushing Adonijah\'s project in the bud. Observe,\nI. The express orders he gave for the proclaiming of Solomon. The persons he entrusted with this great affair were Zadok, Nathan, and Benaiah, men of power and interest whom David had always reposed a confidence in and found faithful to him, and whom Adonijah had passed by in his invitation, Kg1 1:10. David orders them forthwith, with ...', 'teologico');
add('1rs', 1, 41, 'Matthew Henry', 'We have here,\nI. The tidings of Solomon\'s inauguration brought to Adonijah and his party, in the midst of their jollity: They had made an end of eating, and, it should seem, it was a great while before they made an end, for all the affair of Solomon\'s anointing was ordered and finished while they were at dinner, glutting themselves. Thus those who serve not our Lord Christ, but oppose him, are commonly such as serve their own belly (Rom 16:18) and made a god of it, Phi 3:19. Their long feast ...', 'teologico');
add('1rs', 2, 12, 'Matthew Henry', 'Here is, I. Solomon\'s accession to the throne, Kg1 2:12. He came to it much more easily and peaceably than David did, and much sooner saw his government established. It is happy for a kingdom when the end of one good reign is the beginning of another, as it was here.\nII. His just and necessary removal of Adonijah his rival, in order to the establishment of his throne. Adonijah had made some bold pretensions to the crown, but was soon obliged to let them fail and throw himself upon Solomon\'s m...', 'teologico');
add('1rs', 2, 26, 'Matthew Henry', 'Abiathar and Joab were both aiding and abetting in Adonijah\'s rebellious attempt, and it is probable were at the bottom of this new motion made of Adonijah for Abishag, and it should seem Solomon knew it, Kg1 2:22. This was, in both, an intolerable affront both to God and to the government, and the worse because of their high station and the great influence their examples might have upon many. They therefore come next to be reckoned with. They are both equally guilty of the treason, but, in t...', 'teologico');
add('1rs', 2, 35, 'Matthew Henry', 'Here is, I. The preferment of Benaiah and Zadok, two faithful friends to Solomon and his government, Kg1 2:35. Joab being put to death, Benaiah was advanced to be general of the forces in his room, and, Abiathar being deposed, Zadok was made high priest in his room, and therein was fulfilled the word of God, when he threatened to cut off the house of Eli (Sa1 2:35), I will raise me up a faithful priest, and will build him a sure house. Though sacred offices may be disgraced, they shall not be...', 'teologico');
add('1rs', 3, 1, 'Matthew Henry', 'We are here told concerning Solomon,\nI. Something that was unquestionably good, for which he is to be praised and in which he is to be imitated. 1. He loved the Lord, Kg1 3:3. Particular notice was taken of God\'s love to him, Sa2 12:24. He had his name from it: Jedidiah - beloved of the Lord. And here we find he returned that love, as John, the beloved disciple, was most full of love. Solomon was a wise man, a rich man; yet the brightest encomium of him is that which is the character of all t...', 'teologico');
add('1rs', 3, 5, 'Matthew Henry', 'We have here an account of a gracious visit which God paid to Solomon, and the communion he had with God in it, which put a greater honour upon Solomon than all the wealth and power of his kingdom did.\nI. The circumstances of this visit, Kg1 3:5. 1. The place. It was in Gibeon; that was the great high place, and should have been the only one, because there the tabernacle and the brazen altar were, Ch2 1:3. There Solomon offered his great sacrifices, and there God owned him more than in any ot...', 'teologico');
add('1rs', 3, 16, 'Matthew Henry', 'An instance is here given of Solomon\'s wisdom, to show that the grant lately made him had a real effect upon him. The proof is fetched, not from the mysteries of state and the policies of the council-board, though there no doubt he excelled, but from the trial and determination of a cause between party and party, which princes, though they devolve them upon their judges, must not think it below them to take cognizance of. Observe,\nI. The case opened, not by lawyers, but by the parties themsel...', 'teologico');
add('1rs', 4, 1, 'Matthew Henry', 'Here we have,\nI. Solomon upon his throne (Kg1 4:1): So king Solomon was king, that is, he was confirmed and established king over all Israel, and not, as his successors, only over two tribes. He was a king, that is, he did the work and duty of a king, with the wisdom God had given him. Those preserve the name and honour of their place that mind the business of it and make conscience of it.\nII. The great officers of his court, in the choice of whom, no doubt, his wisdom much appeared. It is ob...', 'teologico');
add('1rs', 4, 20, 'Matthew Henry', 'Such a kingdom, and such a court, surely never any prince had, as Solomon\'s are here described to be.\nI. Such a kingdom. Never did the crown of Israel shine so brightly as it did when Solomon wore it, never in his father\'s days, never in the days of any of his successors; nor was that kingdom ever so glorious a type of the kingdom of the Messiah as it was then. The account here given of it is such as fully answers the prophecies which we have concerning it in Ps. 72, which is a psalm for Solo...', 'teologico');
add('1rs', 4, 29, 'Matthew Henry', 'Solomon\'s wisdom was more his glory than his wealth, and here we have a general account of it.\nI. The fountain of his wisdom: God gave it him, Kg1 4:29. He owns it himself. Pro 2:6, The Lord giveth wisdom. He gives the powers of reason (Job 38:36), preserves and improves them. The ordinary advances of them are owing to his providence, the sanctification of them to his grace, and this extraordinary pitch at which they arrived in Solomon to a special grant of his favour to him in answer to pray...', 'teologico');
add('1rs', 5, 1, 'Matthew Henry', 'We have here an account of the amicable correspondence between Solomon and Hiram. Tyre was a famous trading city, that lay close upon the sea, in the border of Israel; its inhabitants (as should seem) were none of the devoted nations, nor ever at enmity with Israel, and therefore David never offered to destroy them, but lived in friendship with them. It is here said of Hiram their king that he was ever a lover of David; and we have reason to think he was a worshipper of the true God, and had ...', 'teologico');
add('1rs', 5, 10, 'Matthew Henry', 'Here is, I. The performance of the agreement between Solomon and Hiram. Each of the parties made good his engagement. 1. Hiram delivered Solomon the timber, according to his bargain, Kg1 5:10. The trees were Solomon\'s, but perhaps - Materiam superabat opus - The workmanship was of more value than the article. Hiram is therefore said to deliver the trees. 2. Solomon conveyed to Hiram the corn which he had promised him, Kg1 5:11. Thus let justice be followed (as the expression is, Deu 16:20), j...', 'teologico');
add('1rs', 6, 1, 'Matthew Henry', 'Here, I. The temple is called the house of the Lord (Kg1 6:1), because it was, 1. Directed and modelled by him. Infinite Wisdom was the architect, and gave David the plan or pattern by the Spirit, not by word of mouth only, but, for the greater certainty and exactness, in writing (Ch1 28:11, Ch1 28:12), as he had given to Moses in the mouth a draught of the tabernacle. 2. Dedicated and devoted to him and to his honour, to be employed in his service, so his as never any other house was, for he...', 'teologico');
add('1rs', 6, 11, 'Matthew Henry', 'Here is, I. The word God sent to Solomon, when he was engaged in building the temple. God let him know that he took notice of what he was doing, the house he was now building, Kg1 6:12. None employ themselves for God without having his eye upon them. "I know thy works, thy good works." He assured him that if he would proceed and persevere in obedience to the divine law, and keep in the way of duty and the true worship of God, the divine loving-kindness should be drawn out both to himself (I w...', 'teologico');
add('1rs', 6, 15, 'Matthew Henry', 'Here, I. We have a particular account of the details of the building.\n1. The wainscot of the temple. It was of cedar (Kg1 6:15), which was strong and durable, and of a very sweet smell. The wainscot was curiously carved with knops (like eggs or apples) and flowers, no doubt as the fashion then was, Kg1 6:18.\n2. The gilding. It was not like ours, washed over, but the whole house, all the inside of the temple (Kg1 6:22), even the floor (Kg1 6:30), he overlaid with gold, and the most holy place ...', 'teologico');
add('1rs', 7, 1, 'Matthew Henry', 'Never had any man so much of the spirit of building as Solomon had, nor to better purpose; he began with the temple, built for God first, and then all his other buildings were comfortable. The surest foundations of lasting prosperity are those which are laid in an early piety, Mat 6:33. 1. He built a house for himself (Kg1 7:1), where he dwelt, Kg1 7:8. His father had built a good house; but it was no reflection upon his father for him to build a better, in proportion to the estate wherewith ...', 'teologico');
add('1rs', 7, 13, 'Matthew Henry', 'We have here an account of the brass-work about the temple. There was no iron about the temple, though we find David preparing for the temple iron for things of iron, Ch1 29:2. What those things were we are not told, but some of the things of brass are here described and the rest mentioned.\nI. The brasier whom Solomon employed to preside in this part of the work was Hiram, or Huram (Ch2 4:11), who was by his mother\'s side an Israelite, of the tribe of Naphtali, by his father\'s side a man of T...', 'teologico');
add('1rs', 7, 48, 'Matthew Henry', 'Here is, 1. The making of the gold work of the temple, which it seems was done last, for with it the work of the house of God ended. All within doors was gold, and all made new (except the ark, with its mercy-seat and cherubim), the old being either melted down or laid by - the golden altar, table, and candlestick, with all their appurtenances. The altar of incense was still one, for Christ and his intercession are so: but he made ten golden tables, Ch2 4:8 (though here mention is made of tha...', 'teologico');
add('1rs', 8, 1, 'Matthew Henry', 'The temple, though richly beautified, yet while it was without the ark was like a body without a soul, or a candlestick without a candle, or (to speak more properly) a house without an inhabitant. All the cost and pains bestowed on this stately structure are lost if God do not accept them; and, unless he please to own it as the place where he will record his name, it is after all but a ruinous heap. When therefore all the work is ended (Kg1 7:51), the one thing needful is yet behind, and that...', 'teologico');
add('1rs', 8, 12, 'Matthew Henry', 'Here, I. Solomon encourages the priests, who came out of the temple from their ministration, much astonished at the dark cloud that overshadowed them. The disciples of Christ feared when they entered into the cloud, though it was a bright cloud (Luk 9:34), so did the priests when they found themselves wrapped in a thick cloud. To silence their fears, 1. He reminds them of that which they could not but know, that this was a token of God\'s presence (Kg1 8:12): The Lord said he would dwell in th...', 'teologico');
add('1rs', 8, 22, 'Matthew Henry', 'Solomon having made a general surrender of this house to God, which God had signified his acceptance of by taking possession, next follows Solomon\'s prayer, in which he makes a more particular declaration of the uses of that surrender, with all humility and reverence, desiring that God would agree thereto. In short, it is his request that this temple may be deemed and taken, not only for a house of sacrifice (no mention is made of that in all this prayer, that was taken for granted), but a ho...', 'teologico');
add('1rs', 8, 54, 'Matthew Henry', 'Solomon, after his sermon in Ecclesiastes, gives us the conclusion of the whole matter; so he does here, after this long prayer; it is called his blessing the people, Kg1 8:55. He pronounced it standing, that he might be the better heard, and because he blessed as one having authority. Never were words more fitly spoken, nor more pertinently. Never was congregation dismissed with that which was more likely to affect them and abide with them.\nI. He gives God the glory of the great and kind thi...', 'teologico');
add('1rs', 8, 62, 'Matthew Henry', 'We read before that Judah and Israel were eating and drinking, and very cheerful under their own vines and fig-trees; here we have them so in God\'s courts. Now they found Solomon\'s words true concerning Wisdom\'s ways, that they are ways of pleasantness.\nI. They had abundant joy and satisfaction while they attended at God\'s house, for there, 1. Solomon offered a great sacrifice, 22,000 oxen and 120,000 sheep, enough to have drained the country of cattle if it had not been a very fruitful land....', 'teologico');
add('1rs', 9, 1, 'Matthew Henry', 'God had given a real answer to Solomon\'s prayer, and tokens of his acceptance of it, immediately, by the fire from heaven which consumed the sacrifices (as we find Ch2 7:1); but here we have a more express and distinct answer to it. Observe,\nI. In what way God gave him this answer. He appeared to him, as he had done at Gibeon, in the beginning of his reign, in a dream or vision, Kg1 9:2. The comparing of it with that intimates that it was the very night after he had finished the solemnities o...', 'teologico');
add('1rs', 9, 10, 'Matthew Henry', 'What agreement was made between Solomon and Hiram, when the building-work was to be begun, we read before, ch. 5. Here we have an account of their fair and friendly parting when the work was done. 1. Hiram made good his bargain to the utmost. He had furnished Solomon with materials for his buildings, according to all his desire (Kg1 9:11), and with gold, Kg1 9:15. So far was he from envying Solomon\'s growing greatness and reputation, and being jealous of him, that he helped to magnify him. So...', 'teologico');
add('1rs', 9, 15, 'Matthew Henry', 'We have here a further account of Solomon\'s greatness.\nI. His buildings. He raised a great levy both of men and money, because he projected a great deal of building, which would both employ many hands and put him to a vast expense, Kg1 9:15. And he was a wise builder, who sat down first, and counted the cost, and would not begin to build till he found himself able to finish. Perhaps there was some complaint of the heaviness of the taxes, which the historian excuses from the greatness of his u...', 'teologico');
add('1rs', 10, 1, 'Matthew Henry', 'We have here an account of the visit which the queen of Sheba made to Solomon, no doubt when he was in the height of his piety and prosperity. Our Saviour calls her the queen of the south, for Sheba lay south of Canaan. The common opinion is that it was in Africa; and the Christians in Ethiopia, to this day, are confident that she came from their country, and that Candace was her successor, who is mentioned Act 8:27. But it is more probable that she came from the south part of Arabia the happ...', 'teologico');
add('1rs', 10, 14, 'Matthew Henry', 'We have here a further account of Solomon\'s prosperity.\nI. How he increased his wealth. Though he had much, he still coveted to have more, being willing to try the utmost the things of this world could do to make men happy. 1. Besides the gold that came from Ophir (Kg1 9:28), he brought so much into his country from other places that the whole amounted, every year, to 666 talents (Kg1 10:14), an ominous number, compare Rev 13:18, and Ezr 2:13. 2. He received a great deal in customs from the m...', 'teologico');
add('1rs', 11, 1, 'Matthew Henry', 'This is a sad story, and very surprising, of Solomon\'s defection and degeneracy.\nI. Let us enquire into the occasions and particulars of it. Shall Solomon fall, that was the beauty of Israel, and so great a blessing of his generation? Yes, it is too true, and the scripture is faithful in relating it, and repeating it, and referring to it long after, Neh 13:26. There was no king like Solomon who was beloved of his God, yet even him did outlandish women cause to sin. There is the summary of his...', 'teologico');
add('1rs', 11, 9, 'Matthew Henry', 'Here is, I. God\'s anger against Solomon for his sin. The thing he did displeased the Lord. Time was then the Lord loved Solomon (Sa2 12:24) and delighted in him (Kg1 10:9), but now the Lord was angry with Solomon (Kg1 11:9), for there was in his sin, 1. The most base ingratitude that could be. He turned from the Lord who had appeared unto him twice, once before he began to build the temple (Kg1 3:5) and once after he had dedicated it, Kg1 9:2. God keeps account of the gracious visits he makes...', 'teologico');
add('1rs', 11, 14, 'Matthew Henry', 'While Solomon kept closely to God and to his duty there was no adversary nor evil occurrent (Kg1 5:4), nothing to create him any disturbance or uneasiness in the least; but here we have an account of two adversaries that appeared against him, inconsiderable, and that could not have done any thing worth taking notice of if Solomon had not first made God his enemy. What hurt could Hadad or Rezon have done to so great and powerful a king as Solomon was if he had not, by sin, made himself mean an...', 'teologico');
add('1rs', 11, 26, 'Matthew Henry', 'We have here the first mention of that infamous name Jeroboam the son of Nebat, that made Israel to sin; he is here brought upon the stage as an adversary to Solomon, whom God had expressly told (Kg1 11:11) that he would give the greatest part of his kingdom to his servant, and Jeroboam was the man. We have here an account,\nI. Of his extraction, Kg1 11:26. He was of the tribe of Ephraim, he next in honour to Judah. His mother was a widow, to whom Providence had made up the loss of a husband i...', 'teologico');
add('1rs', 11, 41, 'Matthew Henry', 'We have here the conclusion of Solomon\'s story, and in it, 1. Reference is had to another history then extant, but (not being divinely inspired) since lost, the Book of the Acts of Solomon, Kg1 11:41. Probably this book was written by a chronologer or historiographer, whom Solomon employed to write his annals, out of which the sacred writer extracted what God saw fit to transmit to the church. 2. A summary of the years of his reign (Kg1 11:42): He reigned in Jerusalem (not, as his father, par...', 'teologico');
add('1rs', 12, 1, 'Matthew Henry', 'Solomon had 1000 wives and concubines, yet we read but of one son he had to bear up his name, and he a fool. It is said (Hos 4:10), They shall commit whoredom, and shall not increase. Sin is a bad way of building up a family. Rehoboam was the son of the wisest of men, yet did not inherit his father\'s wisdom, and then it stood him in little stead to inherit his father\'s throne. Neither wisdom nor grace runs in the blood. Solomon came to the crown very young, yet he was then a wise man. Rehoboa...', 'teologico');
add('1rs', 12, 16, 'Matthew Henry', 'We have here the rending of the kingdom of the ten tribes from the house of David, to effect which,\nI. The people were hold and resolute in their revolt. They highly resented the provocation that Rehoboam had given them, were incensed at his menaces, concluded that that government would in the progress of it be intolerably grievous which in the beginning of it was so very haughty, and therefore immediately came to this resolve, one and all: What portion have we in David? Kg1 12:16. They speak...', 'teologico');
add('1rs', 12, 25, 'Matthew Henry', 'We have here the beginning of the reign of Jeroboam. He built Shechem first and then Penuel - beautified and fortified them, and probably had a palace in each of them for himself (Kg1 12:25), the former in Ephraim, the latter in Gad, on the other side Jordan. This might be proper; but he formed another project for the establishing of his kingdom which was fatal to the interests of religion in it.\nI. That which he designed was by some effectual means to secure those to himself who had now chos...', 'teologico');
add('1rs', 13, 1, 'Matthew Henry', 'Here is, I. A messenger sent to Jeroboam, to signify to him God\'s displeasure against his idolatry, Kg1 13:1. The army of Judah that aimed to ruin him was countermanded, and might not draw a sword against him (Kg1 12:24); but a prophet of Judah is, instead thereof, sent to reclaim him from his evil way, and is sent in time, while he is but dedicating his altar, before his heart is hardened by the deceitfulness of his sin; for God delights not in the death of sinners, but would rather they wou...', 'teologico');
add('1rs', 13, 11, 'Matthew Henry', 'The man of God had honestly and resolutely refused the king\'s invitation, though he promised him a reward; yet he was over-persuaded by an old prophet to come back with him, and dine in Beth-el, contrary to the command given him. Here we find how dearly his dinner cost him. Observe with wonder,\nI. The old prophet\'s wickedness. I cannot but call him a false prophet and a bad man, it being much easier to believe that from one of such a bad character should be extorted a confirmation of what the...', 'teologico');
add('1rs', 13, 23, 'Matthew Henry', 'Here is, I. The death of the deceived disobedient prophet. The old prophet that had deluded him, as if he would make him some amends for the wrong he had done him or help to prevent the mischief threatened him, furnished him with an ass to ride home on; but by the way a lion set upon him, and killed him, Kg1 13:23, Kg1 13:24. He did but return back to refresh himself when he was hungry, and behold he must die for it; see Sa1 14:43. But we must consider, 1. That his offence was great, and it w...', 'teologico');
add('1rs', 14, 1, 'Matthew Henry', 'How Jeroboam persisted in his contempt of God and religion we read in the close of the foregoing chapter. Here we are told how God proceeded in his controversy with him; for when God judges he will overcome, and sinners shall either bend or break before him.\nI. His child fell sick, Kg1 14:1. It is probable that he was his eldest son, and heir-apparent to the crown; for at his death all the kingdom went into mourning for him, ch. 13. His dignity as a prince, his age as a young prince, and his ...', 'teologico');
add('1rs', 14, 7, 'Matthew Henry', 'When those that set up idols, and keep them up, go to enquire of the Lord, he determines to answer them, not according to the pretensions of their enquiry, but according to the multitude of their idols, Eze 14:4. So Jeroboam is answered here.\nI. The prophet anticipates the enquiry concerning the child, and foretels the ruin of Jeroboam\'s house for the wickedness of it. No one else durst have carried such a message: a servant would have smothered it, but his own wife cannot be suspected of ill...', 'teologico');
add('1rs', 14, 21, 'Matthew Henry', 'Judah\'s story and Israel\'s are intermixed in this book. Jeroboam out-lived Rehoboam, four or five years, yet his history is despatched first, that the account of Rehoboam\'s reign may be laid together; and a sad account it is.\nI. Here is no good said of the king. All the account we have of him here is, 1. That he was forty-one years old when he began to reign, by which reckoning he was born in the last year of David, and had his education, and the forming of his mind, in the best days of Solom...', 'teologico');
add('1rs', 15, 1, 'Matthew Henry', 'We have here a short account of the short reign of Abijam the son of Rehoboam king of Judah. He makes a better figure, 2 Chr. 13, where we have an account of his war with Jeroboam, the speech which he made before the armies engaged, and the wonderful victory he obtained by the help of God. There he is called Abijah - My father is the Lord, because no wickedness is there laid to his charge. But here, where we are told of his faults, Jah, the name of God, is, in disgrace to him, taken away from...', 'teologico');
add('1rs', 15, 9, 'Matthew Henry', 'We have here a short account of the reign of Asa; we shall find a more copious history of it Ch2 14:1-15, 15, and Ch2 16:1-14. Here is,\nI. The length of it: He reigned forty-one years in Jerusalem, Kg1 15:10. In the account we have of the kings of Judah we find the number of the good kings and the bad ones nearly equal; but then we may observe, to our comfort, that the reign of the good kings was generally long, but that of the bad kings short, the consideration of which will make the state o...', 'teologico');
add('1rs', 15, 25, 'Matthew Henry', 'We are now to take a view of the miserable state of Israel, while the kingdom of Judah was happy under Asa\'s good government. It was threatened that they should be as a reed shaken in the water (Kg1 14:15), and so they were, when, during the single reign of Asa, the government of their kingdom was in six or seven different hands, as we find in this and the following chapter. Jeroboam was upon the throne in the beginning of his reign and Ahab at the end of it, and between them were Nadab, Baas...', 'teologico');
add('1rs', 16, 1, 'Matthew Henry', 'Here is, I. The ruin of the family of Baasha foretold. He was a man likely enough to have raised and established his family - active, politic, and daring; but he was an idolater, and this brought destruction upon his family.\n1. God sent him warning of it before. (1.) That, if he were thereby wrought upon to repent and reform, the ruin might be prevented; for God threatens, that he may not strike, as one that desires not the death of sinners. (2.) That, if not, it might appear that the destruc...', 'teologico');
add('1rs', 16, 15, 'Matthew Henry', 'Solomon observes (Pro 28:2) that for the transgression of a land many were the princes thereof (so it was here in Israel), but by a man of understanding the state thereof shall be prolonged - so it was with Judah at the same time under Asa. When men forsake God they are out of the way of rest and establishment. Zimri, and Tibni, and Omri, are here striving for the crown. Proud aspiring men ruin one another, and involve others in the ruin. These confusions end in the settlement of Omri; we mus...', 'teologico');
add('1rs', 16, 29, 'Matthew Henry', 'We have here the beginning of the reign of Ahab, of whom we have more particulars recorded than of any of the kings of Israel. We have here only a general idea given us of him, as the worst of all the kings, that we may expect what the particulars will be. He reigned twenty-two years, long enough to do a great deal of mischief.\nI. He exceeded all his predecessors in wickedness, did evil above all that were before him (Kg1 16:30), and, as if it were done with a particular enmity both to God an...', 'teologico');
add('1rs', 17, 1, 'Matthew Henry', 'The history of Elijah begins somewhat abruptly. Usually, when a prophet enters, we have some account of his parentage, are told whose son he was and of what tribe; but Elijah drops (so to speak) out of the clouds, as if, like Melchisedek, he were without father, without mother, and without descent, which made some of the Jews fancy that he was an angel sent from heaven; but the apostle has assured us that he was a man subject to like passions as we are (Jam 5:17), which perhaps intimates, not...', 'teologico');
add('1rs', 17, 8, 'Matthew Henry', 'We have here an account of the further protection Elijah was taken under, and the further provision made for him in his retirement. At destruction and famine he shall laugh that has God for his friend to guard and maintain him. The brook Cherith is dried up, but God\'s care of his people, and kindness to them, never slacken, never fail, but are still the same, are still continued and drawn out to those that know him, Psa 36:10. When the brook was dried up Jordan was not; why did not God send h...', 'teologico');
add('1rs', 17, 17, 'Matthew Henry', 'We have here a further recompence made to the widow for her kindness to the prophet; as if it were a small thing to be kept alive, her son, when dead, is restored to life, and so restored to her. Observe,\nI. The sickness and death of the child. For aught that appears he was her only son, the comfort of her widowed estate. He was fed miraculously, and yet that did not secure him from sickness and death. Your fathers did eat manna, and are dead, but there is bread of which a man may eat and not...', 'teologico');
add('1rs', 18, 1, 'Matthew Henry', 'In these verses we find,\nI. The sad state of Israel at this time, upon two accounts: - \n1. Jezebel cut off the prophets of the Lord (Kg1 18:4), slew them, Kg1 18:13. Being an idolater, she was a persecutor, and made Ahab one. Even in those bad times, when the calves were worshipped and the temple at Jerusalem deserted, yet there were some good people that feared God and served him, and some good prophets that instructed them in the knowledge of him and assisted them in their devotions. The pr...', 'teologico');
add('1rs', 18, 17, 'Matthew Henry', 'We have here the meeting between Ahab and Elijah, as bad a king as ever the world was plagued with and as good a prophet as ever the church was blessed with. 1. Ahab, like himself, basely accused Elijah. He durst not strike him, remembering that Jeroboam\'s hand withered when it was stretched out against a prophet, but gave him bad language, which was no less an affront to him that sent him. It was a very coarse compliment with which he accosted him at the first word: Art thou he that troublet...', 'teologico');
add('1rs', 18, 21, 'Matthew Henry', 'Ahab and the people expected that Elijah would, in this solemn assembly, bless the land, and pray for rain; but he had other work to do first. The people must be brought to repent and reform, and then they may look for the removal of the judgment, but not till then. This is the right method. God will first prepare our heart, and then cause his ear to hear, will first turn us to him, and then turn to us, Psa 10:17; Psa 80:3. Deserters must not look for God\'s favour till they return to their al...', 'teologico');
add('1rs', 18, 41, 'Matthew Henry', 'Israel being thus far reformed that they had acknowledged the Lord to be God, and had consented to the execution of Baal\'s prophets, that they might not seduce them any more, though this was far short of a thorough reformation, yet it was so far accepted that God thereupon opened the bottles of heaven, and poured out blessings upon his land, that very evening (as it should seem) on which they did this good work, which should have confirmed them in their reformation; see Hag 2:18, Hag 2:19.\nI....', 'teologico');
add('1rs', 19, 1, 'Matthew Henry', 'One would have expected, after such a public and sensible manifestation of the glory of God and such a clear decision of the controversy depending between him and Baal, to the honour of Elijah, the confusion of Baal\'s prophets, and the universal satisfaction of the people - after they had seen both fire and water come from heaven at the prayer of Elijah, and both in mercy to them, the one as it signified the acceptance of their offering, the other as it refreshed their inheritance, which was ...', 'teologico');
add('1rs', 19, 9, 'Matthew Henry', 'Here is, I. Elijah housed in a cave at Mount Horeb, which is called the mount of God, because on it God had formerly manifested his glory. And perhaps this was the same cave, or cleft of a rock, in which Moses was hidden when the Lord passed by before him and proclaimed his name, Exo 33:22. What Elijah proposed to himself in coming to lodge here, I cannot conceive, unless it was to indulge his melancholy, or to satisfy his curiosity and assist his faith and devotion with the sight of that fam...', 'teologico');
add('1rs', 19, 19, 'Matthew Henry', 'Elisha was named last in the orders God gave to Elijah, but he was first called, for by him the other two were to be called. He must come in Elijah\'s room; yet Elijah is forward to raise him, and is far from being jealous of his successor, but rejoices to think that he shall leave the work of God in such good hands. Concerning the call of Elisha observe, 1. That it was an unexpected surprising call. Elijah found him by divine direction, or perhaps he was before acquainted with him and knew wh...', 'teologico');
add('1rs', 20, 1, 'Matthew Henry', 'Here is, I. The threatening descent which Ben-hadad made upon Ahab\'s kingdom, and the siege he laid to Samaria, his royal city, Kg1 20:1. What the ground of the quarrel was we are not told; covetousness and ambition were the principle, which would never want some pretence or other. David in his time had quite subdued the Syrians and made them tributaries to Israel, but Israel\'s apostasy from God makes them formidable again. Asa had tempted the Syrians to invade Israel once (Kg1 15:18-20), and...', 'teologico');
add('1rs', 20, 12, 'Matthew Henry', 'The treaty between the besiegers and the besieged being broken off abruptly, we have here an account of the battle that ensued immediately.\nI. The Syrians, the besiegers, had their directions from a drunken king, who gave orders over his cups, as he was drinking (Kg1 20:12), drinking himself drunk (Kg1 20:16) with the kings in the pavilions, and this at noon. Drunkenness is a sin which armies and their officers have of old been addicted to. Say not thou then that the former days were, in this...', 'teologico');
add('1rs', 20, 22, 'Matthew Henry', 'We have here an account of another successful campaign which Ahab, by divine aid, made against the Syrians, in which he gave them a greater defeat than in the former. Strange! Ahab idolatrous and yet victorious, a persecutor and yet a conqueror! God has wise and holy ends in suffering wicked men to prosper, and glorifies his own name thereby.\nI. Ahab is admonished by a prophet to prepare for another war, Kg1 20:22. It should seem, he was now secure, and looked but a little way before him. Tho...', 'teologico');
add('1rs', 20, 31, 'Matthew Henry', 'Here is an account of what followed upon the victory which Israel obtained over the Syrians.\nI. Ben-hadad\'s tame and mean submission. Even in his inner chamber he feared, and would, if he could, flee further, though none pursued. His servants, seeing him and themselves reduced to the last extremity, advised that they should surrender at discretion, and make themselves prisoners and petitioners to Ahab for their lives, Kg1 20:31. The servants will put their lives in their hands, and venture fi...', 'teologico');
add('1rs', 21, 1, 'Matthew Henry', 'Here is, 1. Ahab coveting his neighbour\'s vineyard, which unhappily lay near his palace and conveniently for a kitchen-garden. Perhaps Naboth had been pleased that he had a vineyard which lay so advantageously for a prospect of the royal gardens, or the vending of its productions to the royal family; but the situation of it proved fatal to him. If he had had no vineyard, or it had lain obscure in some remote place, he would have preserved his life. But many a man\'s possessions have been his s...', 'teologico');
add('1rs', 21, 5, 'Matthew Henry', 'Nothing but mischief is to be expected when Jezebel enters into the story - that cursed woman, Kg2 9:34.\nI. Under pretence of comforting her afflicted husband, she feeds his pride and passion, and blows the coals of his corruptions. It became her to take notice of his grief and to enquire into the cause of it, Kg1 21:5. Those have forgotten both the duty and affection of the conjugal relation that interest not themselves in each other\'s troubles. He told her what troubled him (Kg1 21:6), yet ...', 'teologico');
add('1rs', 21, 17, 'Matthew Henry', 'In these verses we may observe,\nI. The very bad character that is given of Ahab (Kg1 21:25, Kg1 21:26), which comes in here to justify God in the heavy sentence passed upon him, and to show that though it was passed upon occasion of his sin in the matter of Naboth (which David\'s sin in the matter of Uriah did too much resemble), yet God would not have punished him so severely if he had not been guilty of many other sins, especially idolatry; whereas David, except in that one matter, did that ...', 'teologico');
add('1rs', 22, 1, 'Matthew Henry', 'Though Ahab continued under guilt and wrath, and the dominion of the lusts to which he had sold himself, yet, as a reward for his professions of repentance and humiliation, though the time drew near when he should descend into battle and perish, yet we have him blessed with a three years\' peace (Kg1 22:1) and an honourable visit made him by Jehoshaphat king of Judah, Kg1 22:2. The Jews have a fabulous conceit, that when Ahab humbled himself for his sin, and lay in sackcloth, he sent for Jehos...', 'teologico');
add('1rs', 22, 15, 'Matthew Henry', 'Here Micaiah does well, but, as is common, suffers ill for so doing.\nI. We are told how faithfully he delivered his message, as one that was more solicitous to please God than to humour either the great or the many. In three ways he delivers his message, and all displeasing to Ahab: - \n1. He spoke as the rest of the prophets had spoken, but ironically: Go, and prosper, Kg1 22:15. Ahab put the same question to him that he had put to his own prophets (Shall we go, or shall we forbear?) seeming ...', 'teologico');
add('1rs', 22, 29, 'Matthew Henry', 'The matter in contest between God\'s prophet and Ahab\'s prophets is here soon determined, and it is made to appear which was in the right. Here,\nI. The two kings march with their forces to Ramoth-Gilead, Kg1 22:29. That the king of Israel, who hated God\'s prophet, should so far disbelieve his admonition as to persist in his resolution, notwithstanding, is not strange; but that Jehoshaphat, that pious prince, who had desired to enquire by a prophet of the Lord, as disrelishing and discrediting ...', 'teologico');
add('1rs', 22, 41, 'Matthew Henry', 'Here is, I. A short account of the reign of Jehoshaphat king of Judah, of which we shall have a much fuller narrative in the book of Chronicles, and of the greatness and goodness of that prince, neither of which was lessened or sullied by any thing but his intimacy with the house of Ahab, which, upon several accounts, was a diminution to him. His confederacy with Ahab in war we have already found dangerous to him, and his confederacy with Ahaziah his son in trade sped no better. He offered to...', 'teologico');

// 2RS (83 comentários)
add('2rs', 2, 9, 'Eliseu', 'Que o duplo do teu espírito — A herança espiritual exige busca fervorosa.', 'teologico');
add('2rs', 17, 13, 'Calvino', 'Deus enviou mensageiros — A persistência de Deus em alertar Seu povo revela Sua paciência.', 'historico');
add('2rs', 1, 1, 'Matthew Henry', 'We have here Ahaziah, the wicked king of Israel, under God\'s rebukes both by his providence and by his prophet, by his rod and by his word.\nI. He is crossed in his affairs. How can those expect to prosper that do evil in the sight of the Lord, and provoke him to anger? When he rebelled against God, and revolted from his allegiance to him, Moab rebelled against Israel, and revolted from the subjection that had long paid to the kings of Israel, Kg2 1:1. The Edomites that bordered on Judah, and ...', 'teologico');
add('2rs', 1, 9, 'Matthew Henry', 'Here, I. The king issues out a warrant for the apprehending of Elijah. If the God of Ekron had told him he should die, it is probable he would have taken it quietly; but now that a prophet of the Lord tells him so, reproving him for his sin and reminding him of the God of Israel, he cannot bear it. So far is he from making any good improvement of the warning given him that he is enraged against the prophet; neither his sickness, nor the thoughts of death, made any good impressions upon him, n...', 'teologico');
add('2rs', 2, 1, 'Matthew Henry', 'Elijah\'s times, and the events concerning him, are as little dated as those of any great man in scripture; we are not told of his age, nor in what year of Ahab\'s reign he first appeared, nor in what year of Joram\'s he disappeared, and therefore cannot conjecture how long he flourished; it is supposed about twenty years in all. Here we are told,\nI. That God had determined to take him up into heaven by a whirlwind, Kg2 2:1. He would do it, and it is probable let him know of his purpose some tim...', 'teologico');
add('2rs', 2, 13, 'Matthew Henry', 'We have here an account of what followed immediately after the translation of Elijah.\nI. The tokens of God\'s presence with Elisha, and the marks of his elevation into Elijah\'s room, to be, as he had been, a father to the sons of the prophets, and the chariots and horsemen of Israel.\n1. He was possessed of Elijah\'s mantle, the badge of his office, which, we may suppose, he put on and wore for his master\'s sake, Kg2 2:13. When Elijah went to heaven, though he did not let fall his body as others...', 'teologico');
add('2rs', 2, 19, 'Matthew Henry', 'Elisha had, in this respect, a double portion of Elijah\'s spirit, that he wrought more miracles than Elijah. Some reckon them in number just double. Two are recorded in these verses - a miracle of mercy to Jericho and a miracle of judgment to Bethel, Psa 101:1.\nI. Here is a blessing upon the waters of Jericho, which was effectual to heal them. Jericho was built in disobedience to a command, in defiance to a threatening, and at the expense of the lives of all the builder\'s children; yet, when ...', 'teologico');
add('2rs', 3, 1, 'Matthew Henry', 'Jehoram, the son of Ahab, and brother of Ahaziah, is here upon the throne of Israel; and, though he was but a bad man, yet two commendable things are here recorded of him: - \nI. That he removed his father\'s idols. He did evil in many things, but not like his father Ahab or his mother Jezebel, Kg2 3:2. Bad he was, but not so bad, so overmuch wicked, as Solomon speaks, Ecc 7:17. Perhaps Jehoshaphat, though by his alliance with the house of Ahab he made his own family worse, did something toward...', 'teologico');
add('2rs', 3, 6, 'Matthew Henry', 'Jehoram has no sooner got the sceptre into his hand than he takes the sword into his hand, to reduce Moab. Crowns bring great cares and perils to the heads that wear them; no sooner in honour than in war. Now here we have,\nI. The concerting of this expedition between Jehoram king of Israel and Jehoshaphat king of Judah. Jehoram levied an army (Kg2 3:6), and such an opinion he had of the godly king of Judah that, 1. He courted him to be his confederate: Wilt thou go with me against Moab? And h...', 'teologico');
add('2rs', 3, 20, 'Matthew Henry', 'I. We have here the divine gift of both those things which God had promised by Elisha - water and victory, and the former not only a pledge of the latter, but a means of it. God, who created, and commands, all the waters, both above and beneath the firmament, sent them an abundance of water on a sudden, which did them double service.\n1. It relieved their armies, which were ready to perish, Kg2 3:20. And, which was very observable, this relief came just at the time of the offering of the morni...', 'teologico');
add('2rs', 4, 1, 'Matthew Henry', 'Elisha\'s miracles were for use, not for show; this recorded here was an act of real charity. Such also were the miracles of Christ, not only great wonders, but great favours to those for whom they were wrought. God magnifies his goodness with his power.\nI. Elisha readily receives a poor widow\'s complaint. She was a prophet\'s widow; to whom therefore should she apply, but to him that was a father to the sons of the prophets, and concerned himself in the welfare of their families? It seems, the...', 'teologico');
add('2rs', 4, 8, 'Matthew Henry', 'The giving of a son to such as were old, and had been long childless, was an ancient instance of the divine power and favour, in the case of Abraham, and Isaac, and Manoah, and Elkanah; we find it here among the wonders wrought by Elisha. This was wrought in recompence for the kind entertainment which a good woman gave him, as the promise of a son was given to Abraham when he entertained angels. Observe here,\nI. The kindness of the Shunammite woman to Elisha. Things are bad enough in Israel, ...', 'teologico');
add('2rs', 4, 18, 'Matthew Henry', 'We may well suppose that, after the birth of this son, the prophet was doubly welcome to the good Shunammite. He had thought himself indebted to her, but henceforth, as long as she lives, she will think herself in his debt, and that she can never do too much for him. We may also suppose that the child was very dear to the prophet, as the son of his prayers, and very dear to the parents, as the son of their old age. But here is,\nI. The sudden death of the child, though so much a darling. he wa...', 'teologico');
add('2rs', 4, 38, 'Matthew Henry', 'We have here Elisha in his place, in his element, among the sons of the prophets, teaching them, and, as a father, providing for them; and happy it was for them that they had one over them who naturally cared for their state, under whom they were well fed and well taught. There was a dearth in the land, for the wickedness of those that dwelt therein, the same that we read of, Kg2 8:1. It continued seven years, just as long again as that in Elijah\'s time. A famine of bread there was, but not o...', 'teologico');
add('2rs', 5, 1, 'Matthew Henry', 'Our saviour\'s miracles were intended for the lost sheep of the house of Israel, yet one, like a crumb, fell from the table to a woman of Canaan; so this one miracle Elisha wrought for Naaman, a Syrian; for God does good to all, and will have all men to be saved. Here is,\nI. The great affliction Naaman was under, in the midst of all his honours, Kg2 5:1. He was a great man, in a great place; not only rich and raised, but particularly happy for two things: - 1. That he had been very serviceable...', 'teologico');
add('2rs', 5, 9, 'Matthew Henry', 'We have here the cure of Naaman\'s leprosy.\nI. The short and plain direction which the prophet gave him, with assurance of success. Naaman designed to do honour to Elisha when he came in his chariot, and with all his retinue, to Elisha\'s door, Kg2 5:9. Those that showed little respect to prophets at other times were very complaisant to them when they needed them. He attended at Elisha\'s door as a beggar for an alms. Those that would be cleansed from the spiritual leprosy must wait at Wisdom\'s ...', 'teologico');
add('2rs', 5, 15, 'Matthew Henry', 'Of the ten lepers that our Saviour cleansed, the only one that returned to give thanks was a Samaritan, Luk 17:16. This Syrian did so, and here expresses himself.\nI. Convinced of the power of the God of Israel, not only that he is God, but that he is God alone, and that indeed there is no God in all the earth but in Israel (Kg2 5:15) - a noble confession, but such as intimates the misery of the Gentile world; for the nations that had many gods really had no God, but were without God in the wo...', 'teologico');
add('2rs', 5, 20, 'Matthew Henry', 'Naaman, a Syrian, a courtier, a soldier, had many servants, and we read how wise and good they were, Kg2 5:13. Elisha, a holy prophet, a man of God, has but one servant, and he proves a base, lying, naughty fellow. Those that heard of Elisha at a distance honoured him, and got good by what they heard; but he that stood continually before him, to hear his wisdom, had no good impressions made upon him either by his doctrine or miracles. One would have expected that Elisha\'s servant should be a ...', 'teologico');
add('2rs', 6, 1, 'Matthew Henry', 'Several things may be observed here,\nI. Concerning the sons of the prophets, and their condition and character. The college here spoken of seems to be that at Gilgal, for there Elisha was (Kg2 4:38), and it was near Jordan; and, probably, wherever Elisha resided as many as could of the sons of the prophets flocked to him for the advantage of his instructions, counsels, and prayers. Every one would covet to dwell with him and be near him. Those that would be teachers should lay out themselves ...', 'teologico');
add('2rs', 6, 8, 'Matthew Henry', 'Here we have Elisha, with his spirit of prophecy, serving the king, as before helping the sons of the prophets; for that, as other gifts, is given to every man to profit withal; and, whatever abilities any man has of doing good, he is by them made a debtor both to the wise and unwise. Observe here,\nI. How the king of Israel was informed by Elisha of all the designs and motions of his enemy, the king of Syria, more effectually than he could have been by the most vigilant and faithful spies. If...', 'teologico');
add('2rs', 6, 13, 'Matthew Henry', 'Here is, 1. The great force which the king of Syria sent to seize Elisha. He found out where he was, at Dothan (Kg2 6:13), which was not far from Samaria; thither he sent a great host, who were to come upon him by night, and to bring him dead or alive, Kg2 6:14. Perhaps he had heard that when only one captain and his fifty men were sent to take Elijah they were baffled in the attempt, and therefore he sent an army against Elisha, as if the fire from heaven that consumed fifty men could not as...', 'teologico');
add('2rs', 6, 24, 'Matthew Henry', 'This last paragraph of this chapter should, of right, have been the first of the next chapter, for it begins a new story, which is there continued and concluded. Here is,\nI. The siege which the king of Syria laid to Samaria and the great distress which the city was reduced to thereby. The Syrians had soon forgotten the kindnesses they had lately received in Samaria, and very ungratefully, for aught that appears without any provocation, sought the destruction of it, Kg2 6:24. There are base sp...', 'teologico');
add('2rs', 7, 1, 'Matthew Henry', 'Here, I. Elisha foretels that, notwithstanding the great straits to which the city of Samaria is reduced, yet within twenty-four hours they shall have plenty, Kg2 7:1. The king of Israel despaired of it and grew weary of waiting: then Elisha foretold it, when things were at the worst. Man\'s extremity is God\'s opportunity of magnifying his own power; his time to appear for his people is when their strength is gone, Deu 32:36. When they had given over expecting help it came. When the son of man...', 'teologico');
add('2rs', 7, 3, 'Matthew Henry', 'We are here told,\nI. How the siege of Samaria was raised in the evening, at the edge of night (Kg2 7:6, Kg2 7:7), not by might or power, but by the Spirit of the Lord of hosts, striking terror upon the spirits of the besiegers. Here was not a sword drawn against them, not a drop of blood shed, it was not by thunder or hailstones that they were discomfited, nor were they slain, as Sennacherib\'s army before Jerusalem, by a destroying angel; but, 1. The Lord made them to hear a noise of chariots...', 'teologico');
add('2rs', 7, 12, 'Matthew Henry', 'Here we have,\nI. The king\'s jealousy of a stratagem in the Syrian\'s retreat, Kg2 7:12. He feared that they had withdrawn into an ambush, to draw out the besieged, that they might fall on them with more advantage. he knew he had no reason to expect that God should appear thus wonderfully for him, having forfeited his favour by his unbelief and impatience. He knew no reason the Syrians had to fly, for it does not appear that he or any of this attendants heard the noise of the chariots which the...', 'teologico');
add('2rs', 8, 1, 'Matthew Henry', 'Here we have,\nI. The wickedness of Israel punished with a long famine, one of God\'s sore judgments often threatened in the law. Canaan, that fruitful land, was turned into barrenness, for the iniquity of those that dwelt therein. The famine in Samaria was soon relieved by the raising of that siege, but neither that judgment nor that mercy had a due influence upon them, and therefore the Lord called for another famine; for when he judgeth he will overcome. If less judgments do not prevail to b...', 'teologico');
add('2rs', 8, 7, 'Matthew Henry', 'Here, I. We may enquire what brought Elisha to Damascus, the chief city of Syria. Was he sent to any but the lost sheep of the house of Israel? It seems he was. Perhaps he went to pay a visit to Naaman his convert, and to confirm him in his choice of the true religion, which was the more needful now because, it should seem, he was not out of his place (for Hazael is supposed to be captain of that host); either he resigned it or was turned out of it, because he would not bow, or not bow hearti...', 'teologico');
add('2rs', 8, 16, 'Matthew Henry', 'We have here a brief account of the life and reign of Jehoram (or Joram), one of the worst of the kings of Judah, but the son and successor of Jehoshaphat, one of the best. Note, 1. Parents cannot give grace to their children. Many that have themselves been godly have had the grief and shame of seeing those that came forth out of their bowels wicked and vile. Let not the families that are thus afflicted think it strange. 2. If the children of good parents prove wicked, commonly they are worse...', 'teologico');
add('2rs', 8, 25, 'Matthew Henry', 'As among common persons there are some that we call little men, who make no figure, are little regarded, as less valued, so among kings there are some whom, in comparison with others, we may call little kings. This Ahaziah was one of these; he looks mean in the history, and in God\'s account vile, because wicked. It is too plain an evidence of the affinity between Jehoshaphat and Ahab that they had the same names in their families at the same time, in which, we may suppose, they designed to co...', 'teologico');
add('2rs', 9, 1, 'Matthew Henry', 'We have here the anointing of Jehu to be king, who was, at this time, a commander (probably commander-in-chief) of the forces employed at Ramoth-Gilead, Kg2 9:14. There he was fighting for the king his master, but received orders from a higher king to fight against him. It does not appear that Jehu aimed at the government, or that he ever thought of it, but the commission given him was a perfect surprise to him. Some think that he had been anointed before by Elijah, whom God ordered to do it,...', 'teologico');
add('2rs', 9, 11, 'Matthew Henry', 'Jehu, after some pause, returned to his place at the board, taking no notice of what had passed, but, as it should seem, designing, for the present, to keep it to himself, if they had not urged him to disclose it. Let us therefore see what passed between him and the captains.\nI. With what contempt the captains speak of the young prophet (Kg2 9:11): "Wherefore came this mad fellow to thee? What business had he with thee? And why wouldst thou humour him so far as to retire for conversation with...', 'teologico');
add('2rs', 9, 16, 'Matthew Henry', 'From Ramoth-Gilead to Jezreel was more than one day\'s march; about the mid-way between them the river Jordan must be crossed. We may suppose Jehu to have marched with all possible expedition, and to have taken the utmost precaution to prevent the tidings from getting to Jezreel before him; and, at length, we have him within sight first, and then within reach, of the devoted king.\nI. Joram\'s watchman discovers him first at a distance, him and his retinue, and gives notice to the king of the ap...', 'teologico');
add('2rs', 9, 30, 'Matthew Henry', 'The greatest delinquent in the house of Ahab was Jezebel: it was she that introduced Baal, slew the Lord\'s prophets, contrived the murder of Naboth, stirred up her husband first, and then her sons, to do wickedly; a cursed woman she is here called (Kg2 9:34), a curse to the country, and whom all that wished well to their country had a curse for. Three reigns her reign had lasted, but now, at length, her day had come to fall. We read of a false prophetess in the church of Thyatira that is comp...', 'teologico');
add('2rs', 10, 1, 'Matthew Henry', 'We left Jehu in quiet possession of Jezreel, triumphing over Joram and Jezebel; and we must now attend his further motions. He knew the whole house of Ahab must be cut off, and therefore proceeded in this bloody work, and did not do it deceitfully, or by halves, Jer 48:10.\nI. He got the heads of all the sons of Ahab cut off by their own guardians at Samaria. Seventy sons (or grandsons) Ahab had, Gideon\'s number, Jdg 8:30. In such a number that bore his name his family was likely to be perpetu...', 'teologico');
add('2rs', 10, 15, 'Matthew Henry', 'Jehu, pushing on his work, is here,\nI. Courting the friendship of a good man, Jehonadab the son of Rechab, Kg2 10:15, Kg2 10:16. This Jehonadab, though mortified to the world and meddling little with the business of it (as appears by his charge to his posterity, which they religiously observed 300 years after, not to drink wine nor dwell in cities, Jer 35:6, etc.), yet, upon this occasion, went to meet Jehu, that he might encourage him in the work to which God had called him. The countenance ...', 'teologico');
add('2rs', 10, 29, 'Matthew Henry', 'Here is all the account of the reign of Jehu, though it continued twenty-eight years. The progress of it answered not to the glory of its beginning. We have here,\nI. God\'s approbation of what Jehu had done. Many, it is probable, censured him as treacherous and barbarous - called him a rebel, a usurper, a murderer, and prognosticated ill concerning him, that a family thus raised would soon be ruined; but God said, Well done (Kg2 10:30), and then it signified little who said otherwise. 1. God p...', 'teologico');
add('2rs', 11, 1, 'Matthew Henry', 'God had assured David of the continuance of his family, which is called his ordaining a lamp for his anointed; and this cannot but appear a great thing, now that we have read of the utter extirpation of so many royal families, one after another. Now here we have David\'s promised lamp almost extinguished and yet wonderfully preserved.\nI. It was almost extinguished by the barbarous malice of Athaliah, the queen-mother, who, when she heard that her son Ahaziah was slain by Jehu, arose and destro...', 'teologico');
add('2rs', 11, 4, 'Matthew Henry', 'Six years Athaliah tyrannised. We have not a particular account of her reign; no doubt it was of a piece with the beginning. While Jehu was extirpating the worship of Baal in Israel, she was establishing it in Judah, as appears, Ch2 24:7. The court and kingdom of Judah had been debauched by their alliance with the house of Ahab, and now one of that house is a curse and a plague to both: sinful friendships speed no better. All this while, Joash lay hid, entitled to a crown and intended for it,...', 'teologico');
add('2rs', 11, 13, 'Matthew Henry', 'We may suppose it was designed when they had finished the solemnity of the king\'s inauguration, to pay a visit to Athaliah, and call her to an account for her murders, usurpation, and tyranny; but, like her mother Jezebel, she saved them the labour, went out to meet them, and hastened her own destruction. 1. Hearing the noise, she came in a fright to see what was the matter, Kg2 11:13. Jehoiada and his friends began in silence, but now that they found their strength, they proclaimed what they...', 'teologico');
add('2rs', 11, 17, 'Matthew Henry', 'Jehoiada had now got over the harlot part of his work, when, by the death of Athaliah, the young prince had his way to the throne cleared of all opposition. He had now to improve his advantages for the perfecting of the revolution and the settling of the government. Two things we have an account of here: - \nI. The good foundations he laid, by an original contract, Kg2 11:17. Now that prince and people were together in God\'s house, as it should seem before they stirred, Jehoiada took care that...', 'teologico');
add('2rs', 12, 1, 'Matthew Henry', 'The general account here given of Joash is, 1. That he reigned forty years. As he began his reign when he was very young, he might, in the course of nature, have continued much longer, for he was cut off when he was but forty-seven years old, Kg2 12:1. 2. That he did that which was right as long as Jehoiada lived to instruct him, Kg2 12:2. Many young men have come too soon to an estate - have had wealth, and power, and liberty, before they knew how to use them - and it has been of bad consequ...', 'teologico');
add('2rs', 12, 4, 'Matthew Henry', 'We have here an account of the repairing of the temple in the reign of Joash.\nI. It seems, the temple had gone out of repair. Though Solomon built it very strong, of the best materials and in the best manner, yet in time it went to decay, and there were breaches found in it (Kg2 12:5), in the roofs, or walls, or floors, the ceiling, or wainscoting, or windows, or the partitions of the courts. Even temples themselves are the worse for the wearing; but the heavenly temple will never wax old. Ye...', 'teologico');
add('2rs', 12, 17, 'Matthew Henry', 'When Joash had revolted from God and become both an idolater and a persecutor the hand of the Lord went out against him, and his last state was worse than his first.\nI. His wealth and honour became an easy prey to his neighbours. Hazael, when he had chastised Israel (Kg2 10:32), threatened Judah and Jerusalem likewise, took Gath, a strong city (Kg2 12:17), and thence intended to march with his forces against Jerusalem, the royal city, the holy city, but whose defence, on account of its sinful...', 'teologico');
add('2rs', 13, 1, 'Matthew Henry', 'This general account of the reign of Jehoahaz, and of the state of Israel during his seventeen years, though short, is long enough to let us see two things which are very affecting and instructive: - \nI. The glory of Israel raked up in the ashes, buried and lost, and turned into shame. How unlike does Israel appear here to what it had been and might have been! How is its crown profaned and its honour laid in the dust! 1. It was the honour of Israel that they worshipped the only living and tru...', 'teologico');
add('2rs', 13, 10, 'Matthew Henry', 'We have here Jehoash, or Joash, the son of Jehoahaz and grandson of Jehu, upon the throne of Israel. Probably the house of Jehu intended some respect to the house of David when they gave this heir-apparent to the crown the same name with him that was then king of Judah.\nI. The general account here given of him and his reign is much the same with what we have already met with, and has little in it remarkable, Kg2 13:10-13. He was none of the worst, and yet, because he kept up that ancient and ...', 'teologico');
add('2rs', 13, 20, 'Matthew Henry', 'We must here attend,\nI. The sepulchre of Elisha: he died in a good old age, and they buried him; and what follows shows, 1. What power there was in his life to keep off judgments; for, as soon as he was dead, the bands of the Moabites invaded the land - not great armies to face them in the field, but roving skulking bands, that murdered and plundered by surprise. God has many ways to chastise a provoking people. The king was apprehensive of danger only from the Syrians, but, behold, the Moabi...', 'teologico');
add('2rs', 14, 1, 'Matthew Henry', 'Amaziah, the son and successor of Joash, is the king whom here we have an account of. Let us take a view of him,\nI. In the temple; and there he acted, in some measure, well, like Joash, but not like David, Kg2 14:3. He began well, but did not persevere: He did that which was right in the sight of the Lord, kept up his attendance on God\'s altars and his attention to God\'s word, yet not like David. It is not enough to do that which our pious predecessors did, merely to keep up the usage, but we...', 'teologico');
add('2rs', 14, 8, 'Matthew Henry', 'For several successions after the division of the kingdoms that of Judah suffered much by the enmity of Israel. After Asa\'s time, for several successions, it suffered more by the friendship of Israel, and by the alliance and affinity made with them. But now we meet with hostility between them again, which had not been for some ages before.\nI. Amaziah, upon no provocation, and without showing any cause of quarrel, challenged Joash into the field (Kg2 14:8): "Come, let us look one another in th...', 'teologico');
add('2rs', 14, 15, 'Matthew Henry', 'Here are three kings brought to their graves in these few verses: - 1. Joash king of Israel, Kg2 14:15, Kg2 14:16. We attended his funeral once before, Kg2 13:12, Kg2 13:13. But, because the historian had occasion to give a further account of his life and actions, he again mentions his death and burial. 2. Amaziah king of Judah. Fifteen years he survived his conqueror the king of Israel, Kg2 14:17. A man may live a great while after he has been shamed, may be thoroughly mortified (as Amaziah ...', 'teologico');
add('2rs', 14, 23, 'Matthew Henry', 'Here is an account of the reign of Jeroboam the second. I doubt it is an indication of the affection and adherence of the house of Jehu to the sins of Jeroboam the son of Nebat, who made Israel to sin, that they called an heir-apparent to the crown by his name, thinking that an honourable name which in the book of God is infamous and stigmatized as much as any.\nI. His reign was long, the longest of all the reigns of the kings of Israel: He reigned forty-one years; yet his contemporary Azariah...', 'teologico');
add('2rs', 15, 1, 'Matthew Henry', 'This is a short account of the reign of Azariah. 1. Most of it is general, and the same that has been given of others; he began young and reigned long (Kg2 15:2), did, for the most part, that which was right, Kg2 15:3 (it was happy for the kingdom that a good reign was a long one), only he had not zeal and courage enough to take away the high places, Kg2 15:4. 2. That which is peculiar, Kg2 15:5 (that God smote him with a leprosy) is more largely related, with the occasion of it, Ch2 26:16, e...', 'teologico');
add('2rs', 15, 8, 'Matthew Henry', 'The best days of the kingdom of Israel were while the government was in Jehu\'s family. In his reign, and the next three reigns, though there were many abominable corruptions and miserable grievances in Israel, yet the crown went in succession, the kings died in their beds, and some care was taken of public affairs; but, now that those days are at an end, the history which we have in these verses of about thirty-three years represents the affairs of that kingdom in the utmost confusion imagina...', 'teologico');
add('2rs', 15, 32, 'Matthew Henry', 'We have here a short account of the reign of Jotham king of Judah, of whom we are told, 1. That he reigned very well, did that which was right in the sight of the Lord, Kg2 15:34. Josephus gives him a very high character, stating that he was pious towards God, just towards men, and laid out himself for the public good, - that, whatever was amiss, he took care to have it rectified, - and, in short, wanted no virtue that became a good prince. Though the high places were not taken away, yet to d...', 'teologico');
add('2rs', 16, 1, 'Matthew Henry', 'We have here a general character of the reign of Ahaz. Few and evil were his days - few, for he died at thirty-six - evil, for we are here told, 1. That he did not that which was right like David (Kg2 16:2), that is, he had none of that concern and affection for the instituted service and worship of God for which David was celebrated. He had no love for the temple, made no conscience of his duty to God, nor had any regard to his law. Herein he was unlike David; it was his honour that he was o...', 'teologico');
add('2rs', 16, 5, 'Matthew Henry', 'Here is, 1. The attempt of his confederate neighbours, the kings of Syria and Israel, upon him. They thought to make themselves masters of Jerusalem, and to set a king of their own in it, Isa 7:6. In this they fell short, but the king of Syria recovered Elath, a considerable port upon the Red Sea, which Amaziah had taken from the Syrians, Kg2 14:22. What can those keep that have lost their religion? Let them expect, thenceforward, to be always on the losing hand. 2. His project to get clear o...', 'teologico');
add('2rs', 16, 10, 'Matthew Henry', 'Though Ahaz had himself sacrificed in high places, on hills, and under every green tree (Kg2 16:4), yet God\'s altar had hitherto continued in its place and in use, and the king\'s burnt-offering and his meat-offering (Kg2 16:15) had been offered upon it by the priests that attended it; but here we have it taken away by wicked Ahaz, and another altar, an idolatrous one, put in the room of it - a bolder stroke than the worst of the kings had yet given to religion. We have here,\nI. The model of t...', 'teologico');
add('2rs', 16, 17, 'Matthew Henry', 'Here is, I. Ahaz abusing the temple, not the building itself, but some of the furniture of it. 1. He defaced the bases on which the lavers were set (Kg1 7:28, Kg1 7:29) and took down the molten sea, Kg2 16:17. These the priests used for washing; against them therefore he seems to have had a particular spite. It is one of the greatest prejudices that can be done to religion to obstruct the purifying of the priests, the Lord\'s ministers. 2. He removed the covert for the sabbath, erected either ...', 'teologico');
add('2rs', 17, 1, 'Matthew Henry', 'We have here the reign and ruin of Hoshea, the last of the kings of Israel, concerning whom observe,\nI. That, though he forced his way to the crown by treason and murder (as we read Kg2 15:30), yet he gained not the possession of it till seven or eight years after; for it was in the fourth year of Ahaz that he slew Pekah, but did not himself begin to reign till the twelfth year of Ahaz, Kg2 17:1. Whether by the king of Assyria, or by the king of Judah, or by some of his own people, does not a...', 'teologico');
add('2rs', 17, 7, 'Matthew Henry', 'Though the destruction of the kingdom of the ten tribes was but briefly related, it is in these verses largely commented upon by our historian, and the reasons of it assigned, not taken from the second causes - the weakness of Israel, their impolitic management, and the strength and growing greatness of the Assyrian monarch (these things are overlooked) - but only from the First Cause. Observe, 1. It was the Lord that removed Israel out of his sight; whoever were the instruments, he was the a...', 'teologico');
add('2rs', 17, 24, 'Matthew Henry', 'Never was land lost, we say, for want of an heir. When the children of Israel were dispossessed, and turned out of Canaan, the king of Assyria soon transplanted thither the supernumeraries of his own country, such as it could well spare, who should be servants to him and masters to the Israelites that remained; and here we have an account of these new inhabitants, whose story is related here that we may take our leave of Samaria, as also of the Israelites that were carried captive into Assyri...', 'teologico');
add('2rs', 18, 1, 'Matthew Henry', 'We have here a general account of the reign of Hezekiah. It appears, by comparing his age with his father\'s, that he was born when his father was about eleven or twelve years old, divine Providence so ordering that he might be of full age, and fit for business, when the measure of his father\'s iniquity should be full. Here is,\nI. His great piety, which was the more wonderful because his father was very wicked and vile, one of the worst of the kings, yet he was one of the best, which may intim...', 'teologico');
add('2rs', 18, 9, 'Matthew Henry', 'The kingdom of Assyria had now grown considerable, though we never read of it till the last reign. Such changes there are in the affairs of nations and families: those that have been despicable become formidable, and those, on the contrary, are brought low that have made a great noise and figure. We have here an account,\nI. Of the success of Shalmaneser, king of Assyria, against Israel, his besieging Samaria (Kg2 18:9), taking it (Kg2 18:10), and carrying the people into captivity (Kg2 18:11)...', 'teologico');
add('2rs', 18, 17, 'Matthew Henry', 'Here is, I. Jerusalem besieged by Sennacherib\'s army, Kg2 18:17. He sent three of his great generals with a great host against Jerusalem. Is this the great king, the king of Assyria? No, never call him so; he is a base, false, perfidious man, and worthy to be made infamous to all ages; let him never be named with honour that could do such a dishonourable thing as this, to take Hezekiah\'s money, which he gave him upon condition he should withdraw his army, and then, instead of quitting his cou...', 'teologico');
add('2rs', 19, 1, 'Matthew Henry', 'The contents of Rabshakeh\'s speech being brought to Hezekiah, one would have expected (and it is likely Rabshakeh did expect) that he would call a council of war and it would be debated whether it was best to capitulate or no. Before the siege, he had taken counsel with his princes and his mighty men, Ch2 32:3. But that would not do now; his greatest relief is that he has a God to go to, and what passed between him and his God on this occasion we have here an account of.\nI. Hezekiah discovere...', 'teologico');
add('2rs', 19, 8, 'Matthew Henry', 'Rabshakeh, having delivered his message and received no answer (whether he took this silence for a consent or a slight does not appear), left his army before Jerusalem, under the command of the other generals, and went himself to attend the king his master for further orders. He found him besieging Libnah, a city that had revolted from Judah, Kg2 8:22. Whether he had taken Lachish or no is not certain; some think he departed from it because he found the taking of it impracticable, Kg2 19:8. H...', 'teologico');
add('2rs', 19, 20, 'Matthew Henry', 'We have here the gracious copious answer which God gave to Hezekiah\'s prayer. The message which he sent him by the same hand (Kg2 19:6, Kg2 19:7), one would think, was an answer sufficient to his prayer; but, that he might have strong consolation, he was encouraged by two immutable things, in which it was impossible for God to lie, Heb 6:18. In general, God assured him that his prayer was heard, his prayer against Sennacherib, Kg2 19:20. Note, The case of those that have the prayers of God\'s ...', 'teologico');
add('2rs', 19, 35, 'Matthew Henry', 'Sometimes it was long ere prophecies were accomplished and promises performed; but here the word was no sooner spoken than the work was done.\nI. The army of Assyria was entirely routed. That night which immediately followed the sending of this message to Hezekiah, when the enemy had just set down before the city and were preparing (as we now say) to open the trenches, that night was the main body of their army slain upon the spot by an angel, Kg2 19:35. Hezekiah had not force sufficient to sa...', 'teologico');
add('2rs', 20, 1, 'Matthew Henry', 'The historian, having shown us blaspheming Sennacherib destroyed in the midst of the prospects of life, here shows us praying Hezekiah delivered in the midst of the prospects of death - the days of the former shortened, of the latter prolonged.\nI. Here is Hezekiah\'s sickness. In those days, that is, in the same year in which the king of Assyria besieged Jerusalem; for he reigning reigned? in all twenty-nine years, and surviving this fifteen years, this must be in his fourteenth year, and so w...', 'teologico');
add('2rs', 20, 12, 'Matthew Henry', 'Here is, I. An embassy sent to Hezekiah by the king of Babylon, to congratulate him on his recovery, Kg2 20:12. The kings of Babylon had hitherto been only deputies and tributaries to the kings of Assyria, and Nineveh was the royal city. We find Babylon subject to the king of Assyria, Kg2 17:24. But this king of Babylon began to set up for himself, and by degrees things were so changed that Assyria became subject to the kings of Babylon. This king of Babylon sent to compliment Hezekiah, and i...', 'teologico');
add('2rs', 21, 1, 'Matthew Henry', 'How delightful were our meditations on the last reign! How many pleasing views had we of Sion in its glory (that is, in its purity and in its triumphs), of the king in his beauty! (for Isa 33:17 refers to Hezekiah), and (as it follows there, Kg2 21:20) Jerusalem was a quiet habitation because a city of righteousness, Isa 1:26. But now we have melancholy work upon our hands, unpleasant ground to travel, and cannot but drive heavily. How has the gold become dim and the most fine gold changed! T...', 'teologico');
add('2rs', 21, 10, 'Matthew Henry', 'Here is the doom of Judah and Jerusalem read, and it is heavy doom. The prophets were sent, in the first place, to teach them the knowledge of God, to remind them of their duty and direct them in it. If they succeeded not in that, their next work was to reprove them for their sins, and to set them in view before them, that they might repent and reform, and return to their duty. If in this they prevailed not, but sinners went on frowardly, their next work was to foretel the judgments of God, t...', 'teologico');
add('2rs', 21, 19, 'Matthew Henry', 'Here is a short account of the short and inglorious reign of Amon, the son of Manasseh. Whether Manasseh, in his blind and brutish zeal for his idols, had sacrificed his other sons - or whether, having been dedicated to his idols, they were refused by the people - so it was that his successor was a son not born till he was forty-five years old. And of him we are here told, 1. That his reign was very wicked: He forsook the God of his fathers (Kg2 21:22), disobeyed the commands given to his fat...', 'teologico');
add('2rs', 22, 1, 'Matthew Henry', 'Concerning Josiah we are here told,\nI. That he was very young when he began to reign (Kg2 22:1), only eight years old. Solomon says, Woe unto thee, O land! when thy king is a child; but happy art thou, O land! when thy king is such a child. Our English Israel had once a king that was such a child, Edward VI. Josiah, being young, had not received any bad impressions from the example of his father and grandfather, but soon saw their errors, and God gave his grace to take warning by them. See Ez...', 'teologico');
add('2rs', 22, 11, 'Matthew Henry', 'We hear no more of the repairing of the temple: no doubt that good work went on well; but the book of the law that was found in it occupies us now, and well it may. It is not laid up in the king\'s cabinet as a piece of antiquity, a rarity to be admired, but it is read before the king. Those put the truest honour upon their Bibles that study them and converse with them daily, feed on that bread and walk by that light. Men of honour and business must look upon an acquaintance with God\'s word to...', 'teologico');
add('2rs', 23, 1, 'Matthew Henry', 'Josiah had received a message from God that there was no preventing the ruin of Jerusalem, but that he should deliver only his own soul; yet he did not therefore sit down in despair, and resolve to do nothing for his country because he could not do all he would. No, he would do his duty, and then leave the event to God. A public reformation was the thing resolved on; if any thing could prevent the threatened ruin it must be that; and here we have the preparations for that reformation. 1. He s...', 'teologico');
add('2rs', 23, 4, 'Matthew Henry', 'We have here an account of such a reformation as we have not met with in all the history of the kings of Judah, such thorough riddance made of all the abominable things and such foundations laid of a glorious good work; and here I cannot but wonder at two things: - 1. That so many wicked things should have got in, and kept standing so long, as we find here removed. 2. That notwithstanding the removal of these wicked things, and the hopeful prospects here given of a happy settlement, yet withi...', 'teologico');
add('2rs', 23, 25, 'Matthew Henry', 'Upon the reading of these verses we must say, Lord, though thy righteousness be as the great mountains - evident, conspicuous, and past dispute, yet thy judgments are a great deep, unfathomable and past finding out, Psa 36:6. What shall we say to this?\nI. It is here owned that Josiah was one of the best kings that ever sat upon the throne of David, Kg2 23:25. As Hezekiah was a non-such for faith and dependence upon God in straits (Kg2 18:5), so Josiah was a non-such for sincerity and zeal in ...', 'teologico');
add('2rs', 23, 31, 'Matthew Henry', 'Jerusalem saw not a good day after Josiah was laid in his grave, but one trouble came after another, till within twenty-two years it was quite destroyed. Of the reign of two of his sons here is a short account; the former we find here a prisoner and the latter a tributary to the king of Egypt, and both so in the very beginning of their reign. This king of Egypt having slain Josiah, though he had not had any design upon Judah, yet, being provoked by the opposition which Josiah gave him, now, i...', 'teologico');
add('2rs', 24, 1, 'Matthew Henry', 'We have here the first mention of a name which makes a great figure both in the histories and in the prophecies of the Old Testament; it is that of Nebuchadnezzar, king of Babylon (Kg2 24:1), that head of gold. He was a potent prince, and one that was the terror of the mighty in the land of the living; and yet his name would not have been known in sacred writ if he had not been employed in the destruction of Jerusalem and the captivity of the Jews.\nI. He made Jehoiakim his tributary and kept ...', 'teologico');
add('2rs', 24, 8, 'Matthew Henry', 'This should have been the history of king Jehoiachin\'s reign, but, alas! it is only the history of king Jehoiachin\'s captivity, as it is called, Eze 1:2. He came to the crown, not to have the honour of wearing it, but the shame of losing it. Ideo tantum venerat, ut exiret - He came in only to go out.\nI. His reign was short and inconsiderable. He reigned but three months, and then was removed and carried captive to Babylon, as his father, it is likely, would have been if he had lived but so mu...', 'teologico');
add('2rs', 25, 1, 'Matthew Henry', 'We left king Zedekiah in rebellion against the king of Babylon (Kg2 24:20), contriving and endeavouring to shake off his yoke, when he was no way able to do it, nor took the right method by making God his friend first. Now here we have an account of the fatal consequences of that attempt.\nI. The king of Babylon\'s army laid siege to Jerusalem, Kg2 25:1. What should hinder them when the country was already in their possession? Kg2 24:2. They built forts against the city round about, whence, by ...', 'teologico');
add('2rs', 25, 8, 'Matthew Henry', 'Though we have reason to think that the army of the Chaldeans were much enraged against the city for holding out with so much stubbornness, yet they did not therefore put all to fire and sword as soon as they had taken the city (which is too commonly done in such cases), but about a month after (compare Kg2 25:8 with Kg2 25:3) Nebuzar-adan was sent with orders to complete the destruction of Jerusalem. This space God gave them to repent, after all the foregoing days of his patience, but in vai...', 'teologico');
add('2rs', 25, 22, 'Matthew Henry', 'In these verses we have,\nI. The dispersion of the remaining people. The city of Jerusalem was quite laid waste. Some people there were in the land of Judah (Kg2 25:22) that had weathered the storm, and (which was no small favour at this time, Jer 45:5) had their lives given them for a prey. Now see, 1. What a good posture they were put into. The king of Babylon appointed Gedaliah, one of themselves, to be their governor and protector under him, a very good man, and one that would make the bes...', 'teologico');

// 1CR (68 comentários)
add('1cr', 16, 34, 'Spurgeon', 'O Senhor é bom — A bondade eterna de Deus é o tema central da adoração.', 'teologico');
add('1cr', 29, 11, 'Calvino', 'Teu, ó Senhor, é o reino — Toda soberania pertence a Deus; nada escapa ao Seu domínio.', 'teologico');
add('1cr', 1, 1, 'Matthew Henry', 'This paragraph has Adam for its first word and Abraham for its last. Between the creation of the former and the birth of the latter were 2000 years, almost the one-half of which time Adam himself lived. Adam was the common father of our flesh, Abraham the common father of the faithful. By the breach which the former made of the covenant of innocency, we were all made miserable; by the covenant of grace made with the latter, we all are, or may be, made happy. We all are, by nature, the seed of...', 'teologico');
add('1cr', 1, 28, 'Matthew Henry', 'All nations but the seed of Abraham are already shaken off from this genealogy: they have no part nor lot in this matter. The Lord\'s portion is his people. Of them he keeps an account, knows them by name; but those who are strangers to him he beholds afar off. Not that we are to conclude that therefore no particular persons of any other nation but the seed of Abraham found favour with God. It was a truth, before Peter perceived it, that in every nation he that feared God and wrought righteous...', 'teologico');
add('1cr', 2, 1, 'Matthew Henry', 'Here is, I. The family of Jacob. His twelve sons are here named, that illustrious number so often celebrated almost throughout the whole Bible, from the first to the last book of it. At every turn we meet with the twelve tribes that descended from these twelve patriarchs. The personal character of several of them was none of the best (the first four were much blemished), and yet the covenant was entailed on their seed; for it was of grace, free grace, that it was said, Jacob have I loved - no...', 'teologico');
add('1cr', 2, 18, 'Matthew Henry', 'The persons mentioned in the former paragraph are most of them such as we read of, and most of them such as we read much of, in other scriptures; but very few of those to whom this paragraph relates are mentioned any where else. It should seem, the tribe of Judah were more full and exact in their genealogies than any other of the tribes, in which we must acknowledge a special providence, for the clearing of the genealogy of Christ. 1. Here we find Bezaleel, who was head-workman in building th...', 'teologico');
add('1cr', 3, 1, 'Matthew Henry', 'We had an account of David\'s sons, Sa2 3:2, etc., and Sa2 5:14, etc. 1. He had many sons; and no doubt wrote as he thought, Psa 127:5. Happy is the man that hath his quiver full of these arrows. 2. Some of them were a grief to him, as Amnon, Absalom, and Adonijah; and we do not read of any of them that imitated his piety or devotion except Solomon, and he came far short of it. 3. One of them, which Bath-sheba bore to him, he called Nathan, probably in honour of Nathan the prophet, who reprove...', 'teologico');
add('1cr', 3, 10, 'Matthew Henry', 'David having nineteen sons, we may suppose them to have raised many noble families in Israel whom we never hear of in the history. But the scripture gives us an account only of the descendants of Solomon here, and of Nathan, Lu. 3. The rest had the honour to be the sons of David; but these only had the honour to be related to the Messiah. The sons of Nathan were his fathers as man, the sons of Solomon his predecessors as king. We have here, 1. The great and celebrated names by which the line ...', 'teologico');
add('1cr', 4, 1, 'Matthew Henry', 'One reason, no doubt, why Ezra is here most particular in the register of the tribe of Judah is because it was that tribe which, with its appendages, Simeon, Benjamin, and Levi, made up the kingdom of Judah, which not only long survived the other tribes in Canaan, but in process of time, now when this was written, returned out of captivity, when the generality of the other tribes were lost in the kingdom of Assyria. The most remarkable person in this paragraph is Jabez. It is not said whose s...', 'teologico');
add('1cr', 4, 11, 'Matthew Henry', 'We may observe in these verses, 1. That here is a whole family of craftsmen, handicraft tradesmen, that applied themselves to all sorts of manufactures, in which they were ingenious and industrious above their neighbours, Ch1 4:14. There was a valley where they lived which was, from them, called the valley of craftsmen. Those that are craftsmen are not therefore to be looked upon as mean men. These craftsmen, though two of a trade often disagree, yet chose to live together, for the improving ...', 'teologico');
add('1cr', 4, 24, 'Matthew Henry', 'We have here some of the genealogies of the tribe of Simeon (though it was not a tribe of great note), especially the princes of that tribe, Ch1 4:38. Of this tribe it is said that they increased greatly, but not like the children of Judah, Ch1 4:27. Those whom God increases ought to be thankful, though they see others that are more increased. Here observe, 1. The cities allotted them (Ch1 4:28), of which see Jos 19:1, etc. When it is said that they were theirs unto the reign of David (Ch1 4:...', 'teologico');
add('1cr', 5, 1, 'Matthew Henry', 'We have here an extract out of the genealogies,\nI. Of the tribe of Reuben, where we have,\n1. The reason why this tribe is thus postponed. It is confessed that Reuben was the first-born of Israel, and, upon that account, might challenge the precedency; but he forfeited his birthright by defiling his father\'s concubine, and was, for that, sentenced not to excel, Gen 49:4. Sin lessens men, thrusts them down from their excellency. Seventh-commandment sins especially leave an indelible stain upon ...', 'teologico');
add('1cr', 5, 18, 'Matthew Henry', 'The heads of the half-tribe of Manasseh, that were seated on the other side Jordan, are named here, Ch1 5:23, Ch1 5:24. Their lot, at first, was Bashan only; but afterwards they increased so much in wealth and power that they spread far north, even unto Hermon. Two things only are here recorded concerning these tribes on the other side Jordan, in which they were all concerned. They all shared,\nI. In a glorious victory over the Hagarites, so the Ishmaelites were now called, to remind them that...', 'teologico');
add('1cr', 6, 1, 'Matthew Henry', 'The priests and Levites were more concerned than any other Israelites to preserve their pedigree clear and to be able to prove it, because all the honours and privileges of their office depended upon their descent. And we read of those who, though perhaps they really were children of the priests, yet, because they could not find the register of their genealogies, nor make out their descent by any authentic record, were, as polluted, put from the priesthood, and forbidden to eat of the holy th...', 'teologico');
add('1cr', 6, 31, 'Matthew Henry', 'When the Levites were first ordained in the wilderness much of the work then appointed them lay in carrying and taking care of the tabernacle and the utensils of it, while they were in their march through the wilderness. In David\'s time their number was increased; and, though the greater part of them was dispersed all the nation over, to teach the people the good knowledge of the Lord, yet those that attended the house of God were so numerous that there was not constant work for them all; and...', 'teologico');
add('1cr', 6, 54, 'Matthew Henry', 'We have here an account of the Levites\' cities. They are here called their castles (Ch1 6:54), not only because walled and fortified, and well guarded by the country (for it is the interest of every nation to protect its ministers), but because they and their possessions were, in a particular manner, the care of the divine providence: as God was their portion, so God was their protection; and a cottage will be a castle to those that abide under the shadow of the Almighty. This account is much...', 'teologico');
add('1cr', 7, 1, 'Matthew Henry', 'We have here a short view given us,\nI. Of the tribe of Issachar, whom Jacob had compared to a strong ass, couching between two burdens (Gen 49:14), an industrious tribe, that minded their country business very closely and rejoiced in their tents, Deu 33:18. And here it appears, 1. That they were a numerous tribe; for they had many wives. So fruitful their country was that they saw no danger of over-stocking the pasture, and so ingenious the people were that they could find work for all hands....', 'teologico');
add('1cr', 7, 20, 'Matthew Henry', 'We have here an account,\nI. Of the tribe of Ephraim. Great things we read of that tribe when it came to maturity. Here we have an account of the disasters of its infancy, while it was in Egypt as it should seem; for Ephraim himself was alive when those things were done, which yet is hard to imagine if it were, as is here computed, seven generations off. Therefore I am apt to think that either it was another Ephraim or that those who were slain were the immediate sons of that Ephraim that was ...', 'teologico');
add('1cr', 8, 1, 'Matthew Henry', 'There is little or nothing of history in all these verses; we have not therefore much to observe. 1. As to the difficulties that occur in this and the foregoing genealogies we need not perplex ourselves. I presume Ezra took them as he found them in the books of the kings of Israel and Judah (Ezr 9:1), according as they were given in by the several tribes, each observing what method they thought fit. Hence some ascend, others desecnd; some have numbers affixed, others places; some have histori...', 'teologico');
add('1cr', 8, 33, 'Matthew Henry', 'It is observable that among all the genealogies of the tribes there is no mention of any of the kings of Israel after the defection from the house of David, much less of their families; not a word of Jeroboam\'s house or Baasha\'s, of Umri\'s or Jehu\'s; for they were all idolaters. But of the family of Saul, which was the royal family before the elevation of David, we have here a particular account. 1. Before Saul, Kish and Ner only are named, his father and grandfather, Ch1 8:33. His pedigree i...', 'teologico');
add('1cr', 9, 1, 'Matthew Henry', 'The first verse looks back upon the foregoing genealogies, and tells us they were gathered out of the books of the kings of Israel and Judah, not that which we have in the canon of scripture, but another civil record, which was authentic, as the king\'s books with us. Mentioning Israel and Judah, the historian takes notice of their being carried away to Babylon for their transgression. Let that judgment never be forgotten, but ever be remembered, for warning to posterity to take heed of those ...', 'teologico');
add('1cr', 9, 14, 'Matthew Henry', 'We have here a further account of the good posture which the affairs of religion were put into immediately upon the return of the people out of Babylon. They had smarted for their former neglect of ordinances and under the late want of ordinances. Both these considerations made them very zealous and forward in setting up the worship of God among them; so they began their worship of God at the right end. Instances hereof we have here.\nI. Before the house of the Lord was built they had the hous...', 'teologico');
add('1cr', 9, 35, 'Matthew Henry', 'These verses are the very same with Ch1 8:29-38, giving an account of the ancestors of Saul and the posterity of Jonathan. There it is the conclusion of the genealogy of Benjamin; here it is an introduction to the story of Saul. We take the repetition as we find it; but if we admit that there are in the originals, especially in these books, some errors of the transcribers, I should be tempted to think this repetition arose from a blunder. Some one, in copying out these genealogies, having wri...', 'teologico');
add('1cr', 10, 1, 'Matthew Henry', 'This account of Saul\'s death is the same with that which we had, Sa1 31:1, etc. We need not repeat the exposition of it. Only let us observe, 1. Princes sin and the people suffer for it. It was a bad time with Israel when they fled before the Philistines and fell down slain (Ch1 10:1), when they quitted their cities, and the Philistines came and dwelt in them, Ch1 10:7. We do not find that they were at this time guilty of idolatry, as they had been before, in the days of the judges, and were ...', 'teologico');
add('1cr', 10, 8, 'Matthew Henry', 'Here, I. From the triumph of the Philistines over the body of Saul we may learn, 1. That the greater dignity men are advanced to the greater disgrace they are in danger of falling into. Saul\'s dead body, because he was king, was abused more than any other of the slain. Advancement makes men a mark for malice. 2. That, if we give not to God the glory of our successes, even the Philistines will rise up in judgment against us and condemn us; for, when they had obtained a victory over Saul, they ...', 'teologico');
add('1cr', 11, 1, 'Matthew Henry', 'David is here brought to the possession.\nI. Of the throne of Israel, after he had reigned seven years in Hebron, over Judah only. In consideration of his relation to them (Ch1 11:1), his former good services, and especially the divine designation (Ch1 11:2), they anointed him their king: he covenanted to protect them, and they to bear faith and true allegiance to him, Ch1 11:3. Observe, 1. God\'s counsels will be fulfilled at last, whatever difficulties lie in the way. If God had said, David s...', 'teologico');
add('1cr', 11, 10, 'Matthew Henry', 'We have here an account of David\'s worthies, the great men of his time that served him and were preferred by him. The first edition of this catalogue we had, Sa2 23:8, etc. This is much the same, only that those named here from Ch1 11:41 to the end are added. Observe,\nI. The connexion of this catalogue with that which is said concerning David, Ch1 11:9. 1. David waxed greater and greater, and these were his mighty men. Much of the strength and honour of great men is borrowed from their servan...', 'teologico');
add('1cr', 12, 1, 'Matthew Henry', 'We have here an account of those that appeared and acted as David\'s friends, upon the death of Saul, to bring about the revolution. All the forces he had, while he was persecuted, was but 600 men, who served for his guards; but, when the time had come that he must begin to act offensively, Providence brought in more to his assistance. Even while he kept himself close, because of Saul (Ch1 12:1), while he did not appear, to invite or encourage his friends and well-wishers to come in to him (no...', 'teologico');
add('1cr', 12, 23, 'Matthew Henry', 'We have here an account of those who were active in perfecting the settlement of David upon the throne, after the death of Ishbosheth. We read (Ch1 11:1, and before Sa2 5:1) that all the tribes of Israel came, either themselves or by their representatives, to Hebron, to make David king; now here we have an account of the quota which every tribe brought in ready armed to the war, in case there should be any opposition, Ch1 12:23. We may observe here,\nI. That those tribes that lived nearest bro...', 'teologico');
add('1cr', 13, 1, 'Matthew Henry', 'Here is, I. David\'s pious proposal to bring up the ark of God to Jerusalem, that the royal city might be the holy city, Ch1 13:1-3. This part of the story we had not in Samuel. We may observe in this proposal,\n1. That as soon as David was well seated on his throne he had thoughts concerning the ark of God: Let us bring the ark to us, Ch1 13:3. Two things he aimed at herein: - (1.) To do honour to God, by showing respect to his ark, the token of his presence. As soon as he had power in his han...', 'teologico');
add('1cr', 13, 9, 'Matthew Henry', 'This breach upon Uzza, which caused all the joy to cease, we had an account of, Sa2 6:6, etc. 1. Let the sin of Uzza warn us all to take heed of presumption, rashness, and irreverence, in dealing about holy things (Ch1 13:9), and not to think that a good intention will justify a bad action. In our communion with God we must carefully watch over our own hearts, lest familiarity breed contempt, and we think God is in any way beholden to us. 2. Let the punishment of Uzza convince us that the God...', 'teologico');
add('1cr', 14, 1, 'Matthew Henry', 'We may observe here, 1. There is no man that has such a sufficiency in himself but he has need of his neighbours and has reason to be thankful for their help: David had a very large kingdom, Hiram a very little one; yet David could not build himself a house to his mind unless Hiram furnished him with both workmen and materials, Ch1 14:1. This is a reason why we should despise none, but, as we have opportunity, be obliging to all. 2. It is a great satisfaction to a wise man to be settled, and ...', 'teologico');
add('1cr', 14, 8, 'Matthew Henry', 'This narrative of David\'s triumph over the Philistines is much the same with that, Sa2 5:17, etc. 1. Let the attack which the Philistines made upon David forbid us to be secure in any settlement or advancement, and engage us to expect molestation in this world. When we are most easy something or other may come to be a terror or vexation to us. Christ\'s kingdom will thus be insulted by the serpent\'s seed, especially when it makes any advances. 2. Let David\'s enquiry of God, once and again, upo...', 'teologico');
add('1cr', 15, 1, 'Matthew Henry', 'Preparation is here made for the bringing of the ark home to the city of David from the house of Obed-edom. It is here owned that in the former attempt, though it was a very good work and in it they sought God, yet they sought him, not after the due order, Ch1 15:13. "We did not go about our work considerately; and therefore we sped so ill." Note, It is not enough that we do that which is good, but we must do it well - not enough that we seek God in a due ordinance, but we must seek after him...', 'teologico');
add('1cr', 15, 25, 'Matthew Henry', 'All things being got ready for the carrying of the ark to the city of David, and its reception there, we have here an account of the solemnity of this conveyance thither from the house of Obed-edom.\nI. God helped the Levites that carried it. The ark was no very great burden, that those who carried it needed any extraordinary help. But, 1. It is good to take notice of the assistance of the divine providence even in those things that fall within the compass of our natural powers: if God did not...', 'teologico');
add('1cr', 16, 1, 'Matthew Henry', 'It was a glorious day when the ark of God was safely lodged in the tent David had pitched for it. That good man had his heart much upon it, could not sleep contentedly till it was done, Psa 132:4, Psa 132:5.\nI. The circumstances of the ark were now, 1. Better than what they had been. It had been obscure in a country town, in the fields of the wood; now it was removed to a public place, to the royal city, where all might resort to it. It had been neglected, as a despised broken vessel; now it ...', 'teologico');
add('1cr', 16, 7, 'Matthew Henry', 'We have here the thanksgiving psalm which David, by the Spirit, composed, and delivered to the chief musician, to be sung upon occasion of the public entry the ark made into the tent prepared for it. Some think he appointed this hymn to be daily used in the temple service, as duly as the day came; whatever other psalms they sung, they must not omit this. David had penned many psalms before this, some in the time of his trouble by Saul. This was composed before, but was now first delivered int...', 'teologico');
add('1cr', 16, 37, 'Matthew Henry', 'The worship of God is not only to be the work of a solemn day now and then, brought in to grace a triumph; but it ought to be the work of every day. David therefore settles it here for a constancy, puts it into a method, which he obliged those that officiated to observe in their respective posts. In the tabernacle of Moses, and afterwards in the temple of Solomon, the ark and the altar were together; but, ever since Eli\'s time, they had been separated, and still continued so till the temple w...', 'teologico');
add('1cr', 17, 1, 'Matthew Henry', 'Let us observe here,\nI. How desirous and solicitous good people should be to serve the interests of God\'s kingdom in the world, to the utmost of their capacity. David could not be easy in a house of cedar while the ark was lodged within curtains, Ch1 17:1. The concerns of the public should always be near our hearts. What pleasure can we take in our own prosperity if we see not the good of Jerusalem? When David is advanced to wealth and power see what his cares and projects are. Not, "What sha...', 'teologico');
add('1cr', 17, 16, 'Matthew Henry', 'We have here David\'s solemn address to God, in answer to the gracious message he had now received from him. By faith he receives the promises, embraces them, and is persuaded of them, as the patriarchs, Heb, Ch1 11:13. How humbly does he here abase himself, and acknowledge his own unworthiness! How highly does he advance the name of God and admire his condescending grace and favour! With what devout affections does he magnify the God of Israel and what a value has he for the Israel of God! Wi...', 'teologico');
add('1cr', 18, 1, 'Matthew Henry', 'After this, it is said (Ch1 18:1), David did those great exploits. After the sweet communion he had had with God by the word and prayer, as mentioned in the foregoing chapter, he went on his work with extraordinary vigour and courage, conquering and to conquer. Thus Jacob, after his vision, lifted up his feet, Gen 29:1.\nWe have taken a view of these victories before, and shall now only observe, 1. Those that have been long enemies to the Israel of God will be brought down at last. The Philist...', 'teologico');
add('1cr', 18, 9, 'Matthew Henry', 'Here let us learn, 1. That it is our interest to make those our friends who have the presence of God with them. The king of Hamath, hearing of David\'s great success, sent to congratulate him and to court his favour with a noble present, Ch1 18:9, Ch1 18:10. It is in vain to contend with the Son of David. Kiss the Son, therefore, lest he be angry; let the kings and judges of the earth, and all inferior people too, be thus wise, thus instructed. The presents we are to bring him are not vessels ...', 'teologico');
add('1cr', 19, 1, 'Matthew Henry', 'Let us here observe, 1. That is becomes good people to be neighbourly, and especially to be grateful. David will pay respect to Hanun because he is his neighbour; and religion teaches us to be civil and obliging to all, to honour all men, and to be ready to do all offices of kindness to those we live among; nor must difference in religion be any obstruction to this. But, besides this, David remembered the kindness which his father showed to him. Those that have received kindness must return i...', 'teologico');
add('1cr', 19, 6, 'Matthew Henry', 'We may see here, 1. How the hearts of sinners that are marked for ruin are hardened to their destruction. The children of Ammon saw that they had made themselves odious to David (Ch1 19:6), and then it would have been their wisdom to desire conditions of peace, to humble themselves and offer any satisfaction for the injury they had done him, the rather because they had made themselves not only odious to David, but obnoxious to the justice of God, who is King of nations, and will assert the in...', 'teologico');
add('1cr', 20, 1, 'Matthew Henry', 'How the army of the Ammonites and their allies was routed in the field we read in the foregoing chapters. Here we have the destruction of Rabbah, the metropolis of their kingdom (Ch1 20:1), the putting of their king\'s crown upon David\'s head (Ch1 20:2), and the great severity that was used towards the people, Ch1 20:3. Of this we had a more full account in 2 Sa. 11, 12, and cannot but remember it by this sad token, that while Joab was besieging Rabbah David fell into that great sin in the mat...', 'teologico');
add('1cr', 20, 4, 'Matthew Henry', 'The Philistines were nearly subdued (Ch1 18:1); but, as in the destruction of the Canaanites by Joshua the sons of Anak were last subdued (Jos 11:21), so here in the conquest of the Philistines the giants of Gath were last brought down. In the conflicts between grace and corruption there are some sins which, like these giants, keep their ground a great while and are not mastered without much difficulty and a long struggle: but judgment will be brought forth unto victory at last. Observe, 1. W...', 'teologico');
add('1cr', 21, 1, 'Matthew Henry', 'Numbering the people, one would think, was no bad thing. Why should not the shepherd know the number of his flock? But God sees not as man sees. It is plain it was wrong in David to do it, and a great provocation to God, because he did it in the pride of his heart; and there is no sin that has in it more of contradiction and therefore more of offence to God than pride. The sin was David\'s; he alone must bear the blame of it. But here we are told,\nI. How active the tempter was in it (Ch1 21:1)...', 'teologico');
add('1cr', 21, 7, 'Matthew Henry', 'David is here under the rod for numbering the people, that rod of correction which drives out the foolishness that is bound up in the heart, the foolishness of pride. Let us briefly observe,\nI. How he was corrected. If God\'s dearest children do amiss, they must expect to smart for it. 1. He is given to understand that God is displeased; and that it is no small uneasiness to so good a man as David, Ch1 21:7. God takes notice of, and is displeased with, the sins of his people; and no sin is mor...', 'teologico');
add('1cr', 21, 18, 'Matthew Henry', 'We have here the controversy concluded, and, upon David\'s repentance, his peace made with God. Though thou wast angry with me, thy anger is turned away. 1. A stop was put to the progress of the execution, Ch1 21:15. When David repented of the sin God repented of the judgment, and ordered the destroying angel to stay his hand and sheath his sword, Ch1 21:27. 2. Direction was given to David to rear an altar in the threshing-floor of Ornan, Ch1 21:18. The angel commanded the prophet Gad to bring...', 'teologico');
add('1cr', 22, 1, 'Matthew Henry', 'Here is, I. The place fixed for the building of the temple (Ch1 22:1): Then David said, by inspiration of God, and as a declaration of his mind, This is the house of the Lord God. If a temple must be built for God, it is fit that it be left to him to choose the ground, for all the earth is his; and this is the ground he makes choice of - ground that pertained to a Jebusite, and perhaps there was not a spot of ground besides, in or about Jerusalem, that did so - a happy presage of the setting ...', 'teologico');
add('1cr', 22, 6, 'Matthew Henry', 'Though Solomon was young and tender, he was capable of receiving instructions, which his father accordingly gave him, concerning the work for which he was designed. When David came to the throne he had many things to do, for the foundations were all out of course; but Solomon had only one thing in charge, and that was to build a house for the Lord God of Israel, Ch1 22:6. Now,\nI. David tells him why he did not do it himself. It was in his mind to do it (Ch1 22:7), but God forbade him, because...', 'teologico');
add('1cr', 22, 17, 'Matthew Henry', 'David here engages the princes of Israel to assist Solomon in the great work he had to do, and every one to lend him a hand towards the carrying of it on. Those that are in the throne cannot do the good they would, unless those about the throne set in with them. David would therefore have the princes to advise Solomon and quicken him, and make the work as easy to him as they could, by promoting it every one in his place. 1. He shows them what obligations they lay under to be zealous in this m...', 'teologico');
add('1cr', 23, 1, 'Matthew Henry', 'Here we have, I. The crown entailed, according to the divine appointment, Ch1 23:1. David made Solomon king, not to reign with him, or reign under him, but only to reign after him. This he did, 1. When he was old and full of days. He was but seventy years old when he died, and yet he was full of days, satur dierum - satisfied with living in this world. When he found himself going off, he made provision for the welfare of the kingdom after his decease, and pleased himself with the hopeful pros...', 'teologico');
add('1cr', 23, 24, 'Matthew Henry', 'Here is, I. An alteration made in the computation of the effective men of the Levites - that whereas, in Moses\'s time, they were not enlisted, or taken into service, till they were thirty-years old, nor admitted as probationers till twenty-five (Num 8:24), David ordered, by direction from God, that they should be numbered for the service of the house of the Lord, from the age of twenty years and upwards, Ch1 23:24. This order he confirmed by his last words, Ch1 23:27. When he put his last han...', 'teologico');
add('1cr', 24, 1, 'Matthew Henry', 'The particular account of these establishments is of little use to us now; but, when Ezra published it, it was of great use to direct their church affairs after their return from captivity into the old channel again. The title of this record we have v. 1 - These are the divisions of the sons of Aaron, not by which they divided one from another, or were at variance one with another (it is a pity there should ever be any such divisions among the sons of Israel, but especially among the sons of ...', 'teologico');
add('1cr', 24, 20, 'Matthew Henry', 'Most of the Levites here named were mentioned before, Ch1 23:16, etc. They were of those who were to attend the priests in the service of the house of God. But they are here mentioned again as heads of the twenty-four courses of Levites (and about so many are here named), who were to attend the twenty-four courses of the priests: they are therefore said to cast lots over against their brethren (so they are called, not their lords), the sons of Aaron, who were not to lord it over God\'s clergy,...', 'teologico');
add('1cr', 25, 1, 'Matthew Henry', 'Observe, I. Singing the praises of God is here called prophesying (Ch1 25:1-3), not that all those who were employed in this service were honoured with the visions of God, or could foretel things to come. Heman indeed is said to be the king\'s seer in the words of God (Ch1 25:5); but the psalms they sang were composed by the prophets, and many of them were prophetical; and the edification of the church was intended in it, as well as the glory of God. In Samuel\'s time singing the praises of God...', 'teologico');
add('1cr', 25, 8, 'Matthew Henry', 'Twenty-four persons are named in the beginning of this chapter as sons of those three great men, Asaph, Heman, and Jeduthun. Ethan was the third (Ch1 6:44), but probably he was dead before the establishment was perfected and Jeduthun came in his room. [Or perhaps Ethan and Jeduthun were two names for the same person.] Of these three Providence so ordered it that Asaph had four sons, Jeduthun six [only five are mentioned Ch1 25:3; Shimei, mentioned Ch1 25:17, is supposed to have been the sixth...', 'teologico');
add('1cr', 26, 1, 'Matthew Henry', 'Observe, I. There were porters appointed to attend the temple, who guarded all the avenues that let to it, opened and shut all the outer gates and attended at them, not only for the state, but for service, to direct and instruct those who were going to worship in the courts of the sanctuary in the decorum they were to observe, to encourage those that were timorous, to send back the strangers and unclean, and to guard against thieves and others that were enemies to the house of God. In allusio...', 'teologico');
add('1cr', 26, 20, 'Matthew Henry', 'Observe, 1. There were treasures of the house of God. A great house cannot be well kept without stores of all manner of provisions. Much was expended daily upon the altar - flour, wine, oil, salt, fuel, besides the lamps; quantities of these were to be kept beforehand, besides the sacred vestments and utensils. These were the treasures of the house of God. And, because money answers all things, doubtless they had an abundance of it, which was received from the people\'s offerings, wherewith th...', 'teologico');
add('1cr', 26, 29, 'Matthew Henry', 'All the offices of the house of God being well provided with Levites, we have here an account of those that were employed as officers and judges in the outward business, which must not be neglected, no, not for the temple itself. The magistracy is an ordinance of God for the good of the church as truly as the ministry is. And here we are told, 1. That the Levites were employed in the administration of justice in concurrence with the princes and elders of the several tribes, who could not be s...', 'teologico');
add('1cr', 27, 1, 'Matthew Henry', 'We have here an account of the regulation of the militia of the kingdom. David was himself a man of war, and had done great things with the sword; he had brought into the field great armies. Now here we are told how he marshalled them when God had given him rest from all his enemies. He did not keep them all together, for that would have been a hardship on them and the country; yet he did not disband and disperse them all, for then he would have left his kingdom naked, and his people would ha...', 'teologico');
add('1cr', 27, 16, 'Matthew Henry', 'We have here an account,\nI. Of the princes of the tribes. Something of the ancient order instituted by Moses in the wilderness was still kept up, that every tribe should have its prince or chief. It is probable that it was kept up all along, either by election or by succession, in the same family; and those are here named who were found in that office when this account was taken. Elihu, or Eliab, who was prince of Judah, was the eldest son of Jesse, and descended in a right line from Nahshon ...', 'teologico');
add('1cr', 28, 1, 'Matthew Henry', 'A great deal of service David had done in his day, had served his generation according to the will of God, Act 13:36. But now the time draws night that he must die, and, as a type of the Son of David, the nearer he comes to his end the more busy he is, and does his work with all his might. He is now a little recovered from the indisposition mentioned Kg1 1:1, when they covered him with clothes, and he got no heat: but was cure is there for old age? He therefore improves his recovery, as givin...', 'teologico');
add('1cr', 28, 11, 'Matthew Henry', 'As for the general charge that David gave his son to seek God and serve him, the book of the law was, in that, his only rule, and there needed no other; but, in building the temple, David was now to give him three things: - 1. A model of the building, because it was to be such a building as neither he nor his architects ever saw. Moses had a pattern of the tabernacle shown him in the mount (Heb 8:5), so had David of the temple, by the immediate hand of God upon him, Ch1 28:19. It was given hi...', 'teologico');
add('1cr', 29, 1, 'Matthew Henry', 'We may here observe,\nI. How handsomely David spoke to the great men of Israel, to engage them to contribute towards the building of the temple. It is our duty to provoke one another to love and to good works, not only to do good ourselves, but to draw in others to do good too as much as we can. There were many very rich men in Israel; they were all to share in the benefit of the temple, and of those peaceable days which were to befriend the building of it; and therefore, though David would no...', 'teologico');
add('1cr', 29, 10, 'Matthew Henry', 'We have here,\nI. The solemn address which David made to God upon occasion of the noble subscriptions of the princes towards the building of the temple (Ch1 29:10): Wherefore David blessed the Lord, not only alone in his closet, but before all the congregation. This I expected when we read (Ch1 29:9) that David rejoiced with great joy; for such a devout man as he would no doubt make that the matter of his thanksgiving which was so much the matter of his rejoicing. He that looked round with com...', 'teologico');
add('1cr', 29, 23, 'Matthew Henry', 'These verses bring king Solomon to his throne and king David to his grave. Thus the rising generation thrusts out that which went before, and says, "Make room for us." Every one has his day.\nI. Here is Solomon rising (Ch1 29:23): Solomon sat on the throne of the Lord. Not his throne which he prepared in the heavens, but the throne of Israel is called the throne of the Lord because not only is he King of all nations, and all kings rule under him, but he was in a peculiar manner King of Israel,...', 'teologico');

// 2CR (85 comentários)
add('2cr', 7, 14, 'Matthew Henry', 'Se o meu povo se humilhar — O avivamento exige humildade, oração e conversão.', 'aplicacao');
add('2cr', 20, 15, 'Josafá', 'A batalha não é vossa — A vitória pertence a Deus; o povo deve confiar, não confiar em armas.', 'teologico');
add('2cr', 1, 1, 'Matthew Henry', 'Here is, I. Solomon\'s great prosperity, Ch2 1:1. Though he had a contested title, yet, God being with him, he was strengthened in his kingdom; his heart and hands were strengthened, and his interest in the people. God\'s presence will be our strength.\nII. His great piety and devotion. His father was a prophet, a psalmist, and kept mostly to the ark; but Solomon, having read much in his Bible concerning the tabernacle which Moses built and the altars there, paid more respect to them than, it sh...', 'teologico');
add('2cr', 1, 13, 'Matthew Henry', 'Here is, 1. Solomon\'s entrance upon the government (Ch2 1:13): He came from before the tabernacle, and reigned over Israel. He would not do any acts of government till he had done his acts of devotion, would not take honour to himself till he had given honour to God - first the tabernacle, and then the throne. But, when he had obtained wisdom from God, he did not bury his talent, but as he received the gift ministered the same, did not give up himself to ease and pleasure, but minded business...', 'teologico');
add('2cr', 2, 1, 'Matthew Henry', 'Solomon\'s wisdom was given him, not merely for speculation, to entertain himself (though it is indeed a princely entertainment), nor merely for conversation, to entertain his friends, but for action; and therefore to action he immediately applies himself. Observe,\nI. His resolution within himself concerning his business (Ch2 2:1): He determined to build, in the first place, a house for the name of the Lord. It is fit that he who is the first should be served - first a temple and then a palace...', 'teologico');
add('2cr', 2, 11, 'Matthew Henry', 'Here we have, I. The return which Huram made to Solomon\'s embassy, in which he shows a great respect for Solomon and a readiness to serve him. Meaner people may learn of these great ones to be neighbourly and complaisant. 1. He congratulates Israel on having such a king as Solomon was (Ch2 2:11): Because the Lord loved his people, he has made thee king. Note, A wise and good government is a great blessing to a people, and may well be accounted a singular token of God\'s favour. He does not say...', 'teologico');
add('2cr', 3, 1, 'Matthew Henry', 'Here is, I. The place where the temple was built. Solomon was neither at liberty to choose nor at a loss to fix the place. It was before determined (Ch1 22:1), which was an ease to his mind. 1. It must be at Jerusalem; for that was the place where God had chosen to put his name there. The royal city must be the holy city. There must be the testimony of Israel; for there are set the thrones of judgment, Psa 122:4, Psa 122:5. 2. It must be on Mount Moriah, which, some think, was that very place...', 'teologico');
add('2cr', 3, 10, 'Matthew Henry', 'Here is an account of 1. The two cherubim, which were set up in the holy of holies. There were two already over the ark, which covered the mercy-seat with their wings; these were small ones. Now that the most holy place was enlarged, though these were continued (being appurtenances to the ark, which was not to be made new, as all the other utensils of the tabernacle were), yet those two large ones were added, doubtless by divine appointment, to fill up the holy place, which otherwise would ha...', 'teologico');
add('2cr', 4, 1, 'Matthew Henry', 'David often speaks with much affection both of the house of the Lord and of the courts of our God. Both without doors and within there was that which typified the grace of the gospel and shadowed out good things to come, of which the substance is Christ.\nI. There were those things in the open court, in the view of all the people, which were very significant.\n1. There was the brazen altar, Ch2 4:1. The making of this was not mentioned in the Kings. On this all the sacrifices were offered, and ...', 'teologico');
add('2cr', 4, 11, 'Matthew Henry', 'We have here such a summary both of the brass-work and the gold-work of the temple as we had before (Kg1 7:13, etc.), in which we have nothing more to observe than, 1. That Huram the workman was very punctual: He finished all that he was to make (Ch2 4:11), and left no part of his work undone. Huram, his father, he is called, Ch2 4:16. Probably it was a sort of nickname by which he was commonly known, Father Huram; for the king of Tyre called him Huram Abi, my father, in compliance with whom ...', 'teologico');
add('2cr', 5, 1, 'Matthew Henry', 'This agrees with what we had Kg1 8:2, etc., where an account was given of the solemn introduction of the ark into the new-erected temple. 1. There needed no great solemnity for the bringing in of the dedicated things, Ch2 5:1. They added to the wealth, and perhaps were so disposed as to add to the beauty of it; but they could not add to the holiness, for it was the temple that sanctified the gold, Mat 23:17. See how just Solomon was both to God and to his father. Whatever David had dedicated ...', 'teologico');
add('2cr', 5, 11, 'Matthew Henry', 'Solomon, and the elders of Israel, had done what they could to grace the solemnity of the introduction of the ark; but God, by testifying his acceptance of what they did, put the greatest honour upon it. The cloud of glory that filled the house beautified it more than all the gold with which it was overlaid or the precious stones with which it was garnished; and yet that was no glory in comparison with the glory of the gospel dispensation, Co2 3:8-10. Observe,\nI. How God took possession of th...', 'teologico');
add('2cr', 6, 1, 'Matthew Henry', 'It is of great consequence, in all our religious actions, that we design well, and that our eye be single. If Solomon had built this temple in the pride of his heart, as Ahasuerus made his feast, only to show the riches of his kingdom and the honour of his majesty, it would not have turned at all to his account. But here he declares upon what inducements he undertook it, and they are such as not only justify, but magnify, the undertaking. 1. He did it for the glory and honour of God; this was...', 'teologico');
add('2cr', 6, 12, 'Matthew Henry', 'Solomon had, in the foregoing verses, signed and sealed, as it were, the deed of dedication, by which the temple was appropriated to the honour and service of God. Now here he prays the consecration-prayer, by which it was made a figure of Christ, the great Mediator, through whom we are to offer all our prayers, and to expect all God\'s favours, and to whom we are to have an eye in every thing where we have to do with God. We have opened the particulars of this prayer (1 Kings 8) and therefore...', 'teologico');
add('2cr', 7, 1, 'Matthew Henry', 'Here is, I. The gracious answer which God immediately made to Solomon\'s prayer: The fire came down from heaven and consumed the sacrifice, Ch2 7:1. In this way God testified his acceptance of Moses (Lev 9:24), of Gideon (Jdg 6:21), of David (Ch1 21:26), of Elijah (Kg1 18:38); and, in general, to accept the burnt-sacrifice is, in the Hebrew phrase, to turn it to ashes, Psa 20:3. The fire came down here, not upon the killing of the sacrifices, but the praying of the prayer.\n1. This fire intimat...', 'teologico');
add('2cr', 7, 12, 'Matthew Henry', 'That God accepted Solomon\'s prayer appeared by the fire from heaven. But a prayer may be accepted and yet not answered in the letter of it; and therefore God appeared to him in the night, as he did once before (Ch2 1:7), and after a day of sacrifice too, as then, and gave him a peculiar answer to his prayer. We had the substance of it before, Kg1 9:2-9.\nI. He promised to own this house for a house of sacrifice to Israel and a house of prayer for all people (Isa 56:7): My name shall be there f...', 'teologico');
add('2cr', 8, 1, 'Matthew Henry', 'This we had Kg1 9:10-24, and therefore shall only observe here,\nI. Though Solomon was a man of great learning and knowledge, yet he spent his days, not in contemplation, but in action, not in his study, but in his country, in building cities and fortifying them, in a time of peace preparing for a time of war, which is as much a man\'s business as it is in summer to provide food for winter.\nII. As he was a man of business himself, and did not consult his own ease, so he employed a great many ha...', 'teologico');
add('2cr', 8, 12, 'Matthew Henry', 'Here is, I. Solomon\'s devotion. The building of the temple was in order to the service of the temple. Whatever cost he was at in rearing the structure, if he had neglected the worship that was to be performed there, it would all have been to no purpose. Assisting the devotion of others will not atone for our own neglects. When Solomon had built the temple, 1. He kept up the holy sacrifices there, according to the law of Moses, Ch2 8:12, Ch2 8:13. In vain had the altar been built, and in vain ...', 'teologico');
add('2cr', 9, 1, 'Matthew Henry', 'This passage of story had been largely considered in the Kings; yet, because our Saviour has proposed it as an example to us in our enquiries after him (Mat 12:42), we must not pass it over without observing briefly, 1. Those who honour God he will honour, Sa1 2:30. Solomon had greatly honoured God, in building, beautifying, and dedicating the temple; all his wisdom and all his wealth were employed for the making of that a consummate piece: and now God made his wisdom and wealth to redound gr...', 'teologico');
add('2cr', 9, 13, 'Matthew Henry', 'We have here Solomon in his throne, and Solomon in his grave; for the throne would not secure him from the grave. Mors sceptra ligonibus aequat - Death wrenches from the hand the sceptre as well as the spade.\nI. Here is Solomon reigning in wealth and power, in ease and fulness, such as, for aught I know, could never since be paralleled by any king whatsoever. In cannot pretend to be critical in comparing the grandeur of Solomon with that of some of the great princes of the earth. But I may ob...', 'teologico');
add('2cr', 10, 1, 'Matthew Henry', 'We may observe here, 1. The wisest and best cannot give every body content. Solomon enriched and advanced his kingdom, did all (one would think) that could be done to make then happy and easy; and yet either he was indiscreet in burdening them with the imposition of taxes and services, or at least there was some colour of reason to think him so. No man is perfectly wise. It is probable that it was when Solomon had declined from God and his duty that his wisdom failed him, and God left him to ...', 'teologico');
add('2cr', 10, 12, 'Matthew Henry', 'We may learn here, 1. That when public affairs are in a ferment violent proceedings do but make bad worse. Rough answers (such as Rehoboam here gave) do but stir up anger and bring oil to the flames. The pilot has need to steer steadily in a storm. Many have been driven to the mischief they did not intend by being too severely dealt with for what they did intend. 2. That, whatever the devices and designs of men are, God is, by all, doing his own work, and fulfilling the word which he has spok...', 'teologico');
add('2cr', 11, 1, 'Matthew Henry', 'How the ten tribes deserted the house of David we read in the foregoing chapter. They had formerly sat loose to that family (Sa2 20:1, Sa2 20:2), and now they quite threw it off, not considering how much it would weaken the common interest and take Israel down from that pitch of glory at which it had arrived in the last reign. But thus the kingdom must be corrected as well as the house of David. 1. Rehoboam at length, like a bold man, raises an army, with a design to reduce the revolters, Ch2...', 'teologico');
add('2cr', 11, 13, 'Matthew Henry', 'See here,\nI. How Rehoboam was strengthened by the accession of the priests and Levites, and all the devout and pious Israelites, to him, even all that were true to their God and their religion.\n1. Jeroboam cast them off, that is, he set up such a way of worship as he knew they could not in conscience comply with, which obliged them to withdraw from his altar, and at the same time he would not allow them to go up to Jerusalem to worship at the altar there; so that he totally cast them off from...', 'teologico');
add('2cr', 12, 1, 'Matthew Henry', 'Israel was very much disgraced and weakened by being divided into two kingdoms; yet the kingdom of Judah, having both the temple and the royal city, both the house of David and the house of Aaron, might have done very well if they had continued in the way of their duty; but here we have all out of order there.\nI. Rehoboam and his people left God: He forsook the law of the Lord, and so in effect forsook God, and all Israel with him, Ch2 12:1. He had his happy triennium, when he walked in the w...', 'teologico');
add('2cr', 12, 13, 'Matthew Henry', 'The story of Rehoboam\'s reign is here concluded, much as the story of the other reigns concludes. Two things especially are observable here: - 1. That he was at length pretty well fixed in his kingdom, Ch2 12:13. His fenced cities in Judah did not answer his expectation, so he now strengthened himself in Jerusalem, which he made it his business to fortify, and there he reigned seventeen years, in the city which the Lord had chosen to put his name there. This intimates his honour and privilege...', 'teologico');
add('2cr', 13, 1, 'Matthew Henry', 'Abijah\'s mother was called Maachah, the daughter of Absalom, Ch2 11:20; here she is called Michaiah, the daughter of Uriel. It is most probable that she was a grand-daughter of Absalom, by his daughter Tamar (Sa2 14:27), and that her immediate father was this Uriel. But we are here to attend Abijah into the field of battle with Jeroboam king of Israel.\nI. God gave him leave to engage with Jeroboam, and owned him in the conflict, though he would not permit Rehoboam to do it, Ch2 11:4. 1. Jerob...', 'teologico');
add('2cr', 13, 13, 'Matthew Henry', 'We do not find that Jeroboam offered to make any answer at all to Abijah\'s speech. Though it was much to the purpose, he resolved not to heed it, and therefore he heard it as though he heard it not. He came to fight, not to dispute. The longest sword, he thought, would determine the matter, not the better cause. Let us therefore see the issue, whether right and religion carried the day or no.\nI. Jeroboam, who trusted to his politics, was beaten. He was so far from fair reasoning that he was n...', 'teologico');
add('2cr', 14, 1, 'Matthew Henry', 'Here is, I. Asa\'s general character (Ch2 14:2): He did that which was good and right in the eyes of the Lord his God. 1. He aimed at pleasing God, studied to approve himself to him. Happy are those that walk by this rule, to do that which is right, not in their own eyes, or in the eye of the world, but in the eyes of God. 2. He saw God\'s eye always upon him, and that helped much to keep him to what was good and right. 3. God graciously accepted him in what he did, and approved his conduct as ...', 'teologico');
add('2cr', 14, 9, 'Matthew Henry', 'Here is, I. Disturbance given to the peace of Asa\'s kingdom by a formidable army of Ethiopians that invaded them, Ch2 14:9, Ch2 14:10. Though still they sought God, yet this fear came upon them, that their faith in God might be tried, and that God might have an opportunity of doing great things for them. It was a vast number that the Ethiopians brought against him: 1,000,000 men; and now he found the benefit of having an army ready raised against such a time of need. That provision which we t...', 'teologico');
add('2cr', 15, 1, 'Matthew Henry', 'It was a great happiness to Israel that they had prophets among them; yet, while they were thus blessed, they were strangely addicted to idolatry, whereas, when the spirit of prophecy had ceased under the second temple, and the canon of the Old Temple was completed (which was constantly read in their synagogues), they were pure from idolatry; for the scriptures are of all other the most sure word of prophecy, and most effectual, and the church could not be so easily imposed upon by a counterf...', 'teologico');
add('2cr', 15, 8, 'Matthew Henry', 'We are here told what good effect the foregoing sermon had upon Asa.\nI. He grew more bold for God than he had been. His victory would inspire him with some new degrees of resolution, but this message from God with much more. Now he took courage. he saw how necessary a further reformation was, and what assurance he had of God\'s presence with him in it; and this made him daring, and helped him over the difficulties which had before deterred him and driven him off from the undertaking. Now he ve...', 'teologico');
add('2cr', 16, 1, 'Matthew Henry', 'How to reconcile the date of this event with the history of the kings I am quite at a loss. Baasha died in the twenty-sixth year of Asa, Kg1 16:8. How then could this be done in his thirty-sixth year, when Baasha\'s family was quite cut off, and Omri was upon the throne? It is generally said to be meant of the thirty-sixth year of the kingdom of Asa, namely, that of Judah, beginning from the first of Rehoboam, and so it coincides with the sixteenth of Asa\'s reign; but then Ch2 15:19 must be so...', 'teologico');
add('2cr', 16, 7, 'Matthew Henry', 'Here is, I. A plain and faithful reproof given to Asa by a prophet of the Lord, for making this league with Baasha. The reprover was Hanani the seer, the father of Jehu, another prophet, whom we read of Kg1 16:1; Ch2 19:2. We observed several things amiss in Asa\'s treaty with Benhadad. But that which the prophet here charges upon him as the greatest fault he was guilty of in that matter is his relying on the king of Syria and not on the Lord his God, Ch2 16:7. He thought that, though God was ...', 'teologico');
add('2cr', 17, 1, 'Matthew Henry', 'Here we find concerning Jehoshaphat,\nI. What a wise man he was. As soon as he came to the crown he strengthened himself against Israel, Ch2 17:1. Ahab, an active warlike prince, had now been three years upon the throne of Israel, the vigour of his beginning falling in with the decay of Asa\'s conclusion. It is probable that the kingdom of Israel had, of late, got ground of the kingdom of Judah and began to grow formidable to it; so that the first thing Jehoshaphat had to do was to make his par...', 'teologico');
add('2cr', 17, 10, 'Matthew Henry', 'We have here a further account of Jehoshaphat\'s great prosperity and the flourishing state of his kingdom.\nI. He had good interest in the neighbouring princes and nations. Though he was not perhaps so great a soldier as David (which might have made him their terror), nor so great a scholar as Solomon (which might have made him their oracle), yet the fear of the Lord fell so upon them (that is, God so influenced and governed their spirits) that they had all a reverence for him, Ch2 17:10. And,...', 'teologico');
add('2cr', 18, 1, 'Matthew Henry', 'Here is, I. Jehoshaphat growing greater. It was said before (Ch2 17:5) that he had riches and honour in abundance; and here it is said again that his wealth and honour increased upon him by piety and good management.\nII. Not growing wiser, else he would not have joined with Ahab, that degenerate Israelite, who had sold himself to work wickedness. What good could he get by a man that was so bad? What good could he do to a man that was so obstinately wicked - an idolater, a persecutor? With him...', 'teologico');
add('2cr', 18, 4, 'Matthew Henry', 'This is almost word for word the same with what we had, 1 Kings 22. We will not repeat what was there said, nor have we much to add, but may take occasion to think, 1. Of the great duty of acknowledging God in all our ways and enquiring at his word, whatever we undertake. Jehoshaphat was not willing to proceed till he had done this, Ch2 18:4. By particular believing prayer, by an unbiased consultation of the scripture and our own consciences, and by an observant regard to the hints of provide...', 'teologico');
add('2cr', 18, 28, 'Matthew Henry', 'We have here, 1. Good Jehoshaphat exposing himself in his robes, thereby endangered, and yet delivered. We have reason to think that Ahab, while he pretended friendship, really aimed at Jehoshaphat\'s life, to take him off, that he might have the management of his successor, who was his son-in-law, else he would never have advised him to enter into the battle with his robes on, which was but to make himself an easy mark to the enemy: and, if really he intended that, it was as unprincipled a pi...', 'teologico');
add('2cr', 19, 1, 'Matthew Henry', 'Here is, I. The great favour God showed to Jehoshaphat,\n1. In bringing him back in safety from his dangerous expedition with Ahab, which had like to have cost him dearly (Ch2 19:1): He returned to his house in peace. Notice is taken of this to intimate, (1.) That he fared better than he had expected. He had been in imminent peril, and yet came home in peace. Whenever we return in peace to our houses we ought to acknowledge God\'s providence in preserving our going out and our coming in. But, i...', 'teologico');
add('2cr', 19, 5, 'Matthew Henry', 'Jehoshaphat, having done what he could to make his people good, is here providing, if possible, to keep them so by the influence of a settled magistracy. He had sent preachers among them, to instruct them (Ch2 17:7-9), and that provision did well; but now he saw it further requisite to send judges among them, to see the laws put in execution, and to be a terror to evil-doers. It is probable that there were judges up and down the country before, but either they neglected their business or the ...', 'teologico');
add('2cr', 20, 1, 'Matthew Henry', 'We left Jehoshaphat, in the foregoing chapter, well employed in reforming his kingdom and providing for the due administration of justice and support of religion in it, and expected nothing but to hear of the peace and prosperity of his reign; but here we have him in distress, which distress, however, was followed by such a glorious deliverance as was an abundant recompence for his piety. If we meet with trouble in the way of duty, we may believe it is that God may have an opportunity of show...', 'teologico');
add('2cr', 20, 14, 'Matthew Henry', 'We have here God\'s gracious answer to Jehoshaphat\'s prayer; and it was a speedy answer. While he was yet speaking God heard: before the congregation was dismissed they had assurance given them that they should be victorious; for it is never in vain to seek God. 1. The spirit of prophecy came upon a Levite that was present, not in any place of eminency, but in the midst of the congregation, Ch2 20:14. The Spirit, like the wind, blows where and on whom he listeth. He was of the sons of Asaph, a...', 'teologico');
add('2cr', 20, 20, 'Matthew Henry', 'We have here the foregoing prayer answered and the foregoing promise performed, in the total overthrow of the enemies\' forces and the triumph (for so it was rather than a victory) of Jehoshaphat\'s forces over them.\nI. Never was army drawn out to the field of battle as Jehoshaphat\'s was. He had soldiers ready prepared for war (Ch2 17:18), but here is no notice taken of their military equipment, their swords or spears, their shields or bows. But Jehoshaphat took care, 1. That faith should be th...', 'teologico');
add('2cr', 20, 31, 'Matthew Henry', 'We are now drawing towards the close of the history of Jehoshaphat\'s reign, for a further account of which those who lived when this book was published were referred to an authentic history of it, written by Jehu the prophet (Ch2 19:2), which was then extant, Ch2 20:34. This was the general character of his reign, that he did that which was right in the sight of the Lord, kept close to the worship of God himself and did what he could to keep his people close to it. But two things are here to ...', 'teologico');
add('2cr', 21, 1, 'Matthew Henry', 'We find here,\nI. That Jehoshaphat was a very careful indulgent father to Jehoram. He had many sons, who are here named (Ch2 21:2), and it is said (Ch2 21:13) that they were better than Jehoram, had a great deal more wisdom and virtue, and lived up to their education, which he went counter to. They were very hopeful, and any of them more fit for the crown than he; and yet, because he was the first-born (Ch2 21:3), his father secured the kingdom to him, and portioned his brethren and disposed o...', 'teologico');
add('2cr', 21, 12, 'Matthew Henry', 'Here we have, I. A warning from God sent to Jehoram by a writing from Elijah the prophet. By this it appears that Jehoram came to the throne, and showed himself what he was before Elijah\'s translation. It is true we find Elisha attending Jehoshaphat, and described as pouring water on the hands of Elijah, after the story of Elijah\'s translation (Kg2 3:11); but that might be, and that description might be given of him, while Elijah was yet on earth: and it is certain that that history is put ou...', 'teologico');
add('2cr', 22, 1, 'Matthew Henry', 'We have here an account of the reign of Ahaziah, a short reign (of one year only), yet long enough, unless it had been better. He was called Jeho-ahaz (Ch2 21:17); here he is called Ahaz-iah, which is the same name and of the same signification, only the words of which it is compounded are transposed. He is here said to be forty-two years old when he began to reign (Ch2 22:2), which could not be, for his father, his immediate predecessor, was but forty when he died, and it is said (Kg2 8:26) ...', 'teologico');
add('2cr', 22, 10, 'Matthew Henry', 'We have here what we had before, Kg2 11:1, etc. 1. A wicked woman endeavouring to destroy the house of David, that she might set up a throne for herself upon the ruins of it. Athaliah barbarously cut off all the seed-royal (Ch2 22:10), perhaps intending to transmit the crown of Judah after herself to some of her own relations, that though her family was cut off in Israel by Jehu it might be planted in Judah. 2. A good woman effectually preserving it from being wholly extirpated. One of the la...', 'teologico');
add('2cr', 23, 1, 'Matthew Henry', 'We may well imagine the bad posture of affairs in Jerusalem during Athaliah\'s six years\' usurpation, and may wonder that God permitted it and his people bore it so long; but after such a dark and tedious night the returning day in this revolution was the brighter and the more welcome. The continuance of David\'s seed and throne was what God had sworn by his holiness (Psa 89:35), and an interruption was no defeasance; the stream of government here runs again in the right channel. The instrument...', 'teologico');
add('2cr', 23, 12, 'Matthew Henry', 'Here we have, I. The people pleased, Ch2 23:12, Ch2 23:13. When the king stood at his pillar, whose right it was to stand there, all the people of the land rejoiced to see a rod sprung out of the stem of Jesse, Isa 11:1. When it seemed a withered root in a dry ground, to see what they despaired of ever seeing - a king of the house of David, what a pleasing surprise was it to them! They ran in transports of joy to see this sight, praised the king, and praised God, for they had with them such a...', 'teologico');
add('2cr', 24, 1, 'Matthew Henry', 'This account of Joash\'s good beginnings we had as it stands here Kg2 12:1, etc., though the latter part of this chapter, concerning his apostasy, we had little of there. What is good in men we should take all occasions to speak of and often repeat it; what is evil we should make mention of but sparingly, and no more than is needful. We shall here only observe, 1. That it is a happy thing for young people, when they are setting out in the world, to be under the direction of those that are wise...', 'teologico');
add('2cr', 24, 15, 'Matthew Henry', 'We have here a sad account of the degeneracy and apostasy of Joash. God had done great things for him; he had done something for God; but now he proved ungrateful to his God and false to the engagements he had laid himself under to him. How has the gold become dim, and the most fine gold changed! Here we find,\nI. The occasions of his apostasy. When he did that which was right it was not with a perfect heart. He never was sincere, never acted from principle, but in compliance to Jehoiada, who ...', 'teologico');
add('2cr', 25, 1, 'Matthew Henry', 'Here is, I. The general character of Amaziah: He did that which was right in the eyes of the Lord, worshipped the true God, kept the temple service a going, and countenanced religion in his kingdom; but he did not do it with a perfect heart (Ch2 25:2), that is, he was not a man of serious piety or devotion himself, nor had he any zeal for the exercises of religion. He was no enemy to it, but a cool and indifferent friend. Such is the character of too many in this Laodicean age: they do that w...', 'teologico');
add('2cr', 25, 14, 'Matthew Henry', 'Here is, I. The revolt of Amaziah from the God of Israel to the gods of the Edomites. Egregious folly! Ahaz worshipped the gods of those that had conquered him, for which he had some little colour, Ch2 28:23. But to worship the gods of those whom he had conquered, who could not protect their own worshippers, was the greatest absurdity that could be. What did he see in the gods of the children of Seir that could tempt him to set them up for his gods and bow himself down before them? Ch2 25:14....', 'teologico');
add('2cr', 25, 17, 'Matthew Henry', 'We have here this degenerate prince mortified by his neighbour and murdered by his own subjects.\nI. Never was proud prince more thoroughly mortified than Amaziah was by Joash king of Israel.\n1. This part of the story (which was as fully related Kg2 14:8, etc., as it is here) - embracing the foolish challenge which Amaziah sent to Joash (Ch2 25:17), his haughty scornful answer to it (Ch2 25:18), with the friendly advice he gave him to sit still and know when he was well off, (Ch2 25:19), - his...', 'teologico');
add('2cr', 26, 1, 'Matthew Henry', 'We have here an account of two things concerning Uzziah: - \nI. His piety. In this he was not very eminent or zealous; yet he did that which was right in the sight of the Lord. He kept up the pure worship of the true God as his father did, and was better than his father, inasmuch as we have no reason to think he ever worshipped idols as his father did, no, not in his latter days, when his heart was lifted up. It is said (Ch2 26:5), He sought God in the days of Zechariah, who, some think, was t...', 'teologico');
add('2cr', 26, 16, 'Matthew Henry', 'Here is the only blot we find on the name of king Uzziah, and it is such a one as lies not on any other of the kings. Whoredom, murder, oppression, persecution, and especially idolatry, gave characters to the bad kings and some of them blemishes to the good ones, David himself not excepted, witness the matter of Uriah. But we find not Uzziah charged with any of these; and yet he transgressed against the Lord his God, and fell under the marks of his displeasure in consequence, not, as other ki...', 'teologico');
add('2cr', 27, 1, 'Matthew Henry', 'There is not much more related here concerning Jotham than we had before, Kg2 15:32, etc.\nI. He reigned well. He did that which was right in the sight of the Lord; the course of his reign was good, and pleasing to God, whose favour he made his end, and his word his rule, and (which shows that he acted from a good principle) he prepared his ways before the Lord his God (Ch2 27:6), that is, he walked circumspectly and with much caution, contrived how to shun that which was evil and compass that...', 'teologico');
add('2cr', 28, 1, 'Matthew Henry', 'Never surely had a man greater opportunity of doing well than Ahaz had, finding things in a good posture, the kingdom rich and strong and religion established; and yet here we have him in these few verses, 1. Wretchedly corrupted and debauched. He had had a good education given him and a good example set him: but parents cannot give grace to their children. All the instructions he had were lost upon him: He did not that which was right in the sight of the Lord (Ch2 28:1), nay, he did a great ...', 'teologico');
add('2cr', 28, 6, 'Matthew Henry', 'We have here,\nI. Treacherous Judah under the rebukes of God\'s providence, and they are very severe. Never was such bloody work made among them since they were a kingdom, and by Israelites too. Ahaz walked in the ways of the kings of Israel, and the king of Israel was the instrument God made use of for his punishment. It is just with God to make those our plagues whom we make our patterns or make ourselves partners with in sin. A war broke out between Judah and Israel, in which Judah was worst...', 'teologico');
add('2cr', 28, 16, 'Matthew Henry', 'Here is, I. The great distress which the kingdom of Ahaz was reduced to for his sin. In general, 1. The Lord brought Judah low, Ch2 28:19. They had lately been very high in wealth and power; but God found means to bring them down, and make them as despicable as they had been formidable. Those that will not humble themselves under the word of God will justly be humbled by his judgments. Iniquity brings men low, Psa 106:43. 2. Ahaz made Judah naked. As his sin debased them, so it exposed them. ...', 'teologico');
add('2cr', 29, 1, 'Matthew Henry', 'Here is, I. Hezekiah\'s age when he came to the crown. He was twenty-five years old. Joash, who came to the crown after two bad reigns, was but seven years old; Josiah, who came after two bad reigns, was but eight, which occasioned the delay of the reformation; but Hezekiah had come to years, and so applied himself immediately to it. We may well think with what a sorrowful heart he beheld his father\'s idolatry and profaneness, how it troubled him to see the doors of the temple shut, though, wh...', 'teologico');
add('2cr', 29, 12, 'Matthew Henry', 'We have here busy work, good work, and needful work, the cleansing of the house of the Lord.\nI. The persons employed in this work were the priests and Levites, who should have kept the temple clean, but, not having done that, were concerned to make it clean. Several of the Levites are here named, two of each of the three principal houses, Kohath, Gershon, and Merari (Ch2 29:12), and two of each of the three families of singers, Asaph, Heman, and Jeduthun, Ch2 29:13, Ch2 29:14. We cannot think...', 'teologico');
add('2cr', 29, 20, 'Matthew Henry', 'The temple being cleansed, we have here an account of the good use that was immediately made of it. A solemn assembly was called to meet the king at the temple, the very next day (Ch2 29:20); and very glad, no doubt, all the good people in Jerusalem were, when it was said, Let us go up to the house of the Lord, Psa 122:1. As soon as Hezekiah heard that the temple was ready for him he lost no time, but made it appear that he was ready for it. He rose early to go up to the house of the Lord, ea...', 'teologico');
add('2cr', 30, 1, 'Matthew Henry', 'Here is, I. A passover resolved upon. That annual feast was instituted as a memorial of the bringing of the children of Israel out of Egypt. It happened that the reviving of the temple service fell within the appointed days of that feast, the seventeenth day of the first month: this brought that forgotten solemnity to mind. "What shall we do," says Hezekiah, "about the passover? It is a very comfortable ordinance, and has been long neglected. How shall we revive it? The time has elapsed for t...', 'teologico');
add('2cr', 30, 13, 'Matthew Henry', 'The time appointed for the passover having arrived, a very great congregation came together upon the occasion, Ch2 30:13. Now here we have,\nI. The preparation they made for the passover, and good preparation it was: They took away all the idolatrous altars that were found, not only in the temple, but in Jerusalem, Ch2 30:14. Before they kept the feast, they cast out this old leaven. The best preparation we can make for the gospel passover is to cast away our iniquities, our spiritual idolatri...', 'teologico');
add('2cr', 30, 21, 'Matthew Henry', 'After the passover followed the feast of unleavened bread, which continued seven days. How that was observed we are here told, and every thing in this account looks pleasant and lively. 1. Abundance of sacrifices were offered to God in peace-offerings, by which they both acknowledged and implored the favour of God, and on part of which the offerers feasted with their friends during these seven days (Ch2 30:22), in token of their communion with God and the comfort they took in his favour and t...', 'teologico');
add('2cr', 31, 1, 'Matthew Henry', 'We have here an account of what was done after the passover. What was wanting in the solemnities of preparation for it before was made up in that which is better, a due improvement of it after. When the religious exercises of a Lord\'s day or a communion are finished we must not think that then the work is done. No, then the hardest part of our work begins, which is to exemplify the impressions of the ordinance upon our minds in all the instances of a holy conversation. So it was here; when al...', 'teologico');
add('2cr', 31, 11, 'Matthew Henry', 'Here we have,\nI. Two particular instances of the care of Hezekiah concerning church matters, having put them into good order, to keep them so. The tithes and other holy things being brought in, he provided, 1. That they should be carefully laid up, and not left exposed in loose heaps, liable to be wasted and embezzled. He ordered chambers to be made ready in some of the courts of the temple for store-chambers (Ch2 31:11), and into them the offerings were brought and there kept under lock and ...', 'teologico');
add('2cr', 32, 1, 'Matthew Henry', 'Here is, I. The formidable design of Sennacherib against Hezekiah\'s kingdom, and the vigorous attempt he made upon it. This Sennacherib was now, as Nebuchadnezzar was afterwards, the terror and scourge and great oppressor of that part of the world. He aimed to raise a boundless monarchy for himself upon the ruins of all his neighbours. His predecessor Shalmaneser had lately made himself master of the kingdom of Israel, and carried the ten tribes captives. Sennacherib thought, in like manner, ...', 'teologico');
add('2cr', 32, 9, 'Matthew Henry', 'This story of the rage and blasphemy of Sennacherib, Hezekiah\'s prayer, and the deliverance of Jerusalem by the destruction of the Assyrian army, we had more at large in the book of Kings, 2 Kings 18 and 19. It is contracted here, yet large enough to show these three things: - \nI. The impiety and malice of the church\'s enemies. Sennacherib has his hands full in besieging Lachish (Ch2 32:9), but hears that Hezekiah is fortifying Jerusalem and encouraging his people to stand it out; and therefo...', 'teologico');
add('2cr', 32, 24, 'Matthew Henry', 'Here we conclude the story of Hezekiah with an account of three things concerning him: - \nI. His sickness and his recovery from it, Ch2 32:24. The account of his sickness is but briefly mentioned here; we had a large narrative of it, 2 Kings 20. His disease seemed likely to be mortal. In the extremity of it he prayed. God answered him, and gave him a sign that he should recover, the going back of the sun ten degrees.\nII. His sin and his repentance for it, which were also more largely related,...', 'teologico');
add('2cr', 33, 1, 'Matthew Henry', 'We have here an account of the great wickedness of Manasseh. It is the same almost word for word with that which we had Kg2 21:1-9, and took a melancholy view of. It is no such pleasing subject that we should delight to dwell upon it again. This foolish young prince, in contradiction to the good example and good education his father gave him, abandoned himself to all impiety, transcribed the abominations of the heathen (Ch2 33:2), ruined the established religion, unravelled his father\'s glori...', 'teologico');
add('2cr', 33, 11, 'Matthew Henry', 'We have seen Manasseh by his wickedness undoing the good that his father had done; here we have him by repentance undoing the evil that he himself had done. It is strange that this was not so much as mentioned in the book of Kings, nor does any thing appear there to the contrary but that he persisted and perished in his son. But perhaps the reason was because the design of that history was to show the wickedness of the nation which brought destruction upon them; and this repentance of Manasse...', 'teologico');
add('2cr', 33, 21, 'Matthew Henry', 'We have little recorded concerning Amon, but enough unless it were better. Here is,\nI. His great wickedness. He did as Manasseh had done in the days of his apostasy, v. 22. Those who think this an evidence that Manasseh did not truly repent forget how many good kings had wicked sons. Only it should seem that Manasseh was in this defective, that, when he cast out the images, he did not utterly deface and destroy them, according to the law which required Israel to burn the images with fire, Deu...', 'teologico');
add('2cr', 34, 1, 'Matthew Henry', 'Concerning Josiah we are here told, 1. That he came to the crown when he was very young, only eight years old (yet his infancy did not debar him from his right), and he reigned thirty-one years (Ch2 34:1), a considerable time. I fear, however, that in the beginning of his reign things went much as they had done in his father\'s time, because, being a child, he must have left the management of them to others; so that it was not till his twelfth year, which goes far in the number of his years, t...', 'teologico');
add('2cr', 34, 8, 'Matthew Henry', 'Here, 1. Orders are given by the king for the repair of the temple, Ch2 34:8. When he had purged the house of the corruptions of it he began to fit it up for the services that were to be performed in it. Thus we must do by the spiritual temple of the heart, get it cleansed from the pollutions of sin, and then renewed, so as to be transformed into the image of God. Josiah, in this order, calls God the Lord his God. Those that truly love God will love the habitation of his house. 2. Care is tak...', 'teologico');
add('2cr', 34, 14, 'Matthew Henry', 'This whole paragraph we had, just as it is here related, Kg2 22:8-20, and have nothing to add here to what was there observed. But, 1. We may hence take occasion to bless God that we have plenty of Bibles, and that they are, or may be, in all hands, - that the book of the law and gospel is not lost, is not scarce, - that, in this sense, the word of the Lord is not precious. Bibles are jewels, but, thanks be to God, they are not rarities. The fountain of the waters of life is not a spring shut...', 'teologico');
add('2cr', 34, 29, 'Matthew Henry', 'We have here an account of the further advances which Josiah made towards the reformation of his kingdom upon the hearing of the law read and the receipt of the message God sent him by the prophetess. Happy the people that had such a king; for here we find that, 1. They were well taught. He did not go about to force them to do their duty, till he had first instructed them in it. He called all the people together, great and small, young and old, rich and poor, high and low. He that hath ears t...', 'teologico');
add('2cr', 35, 1, 'Matthew Henry', 'The destruction which Josiah made of idols and idolatry was more largely related in the Kings, but just mentioned here in the foregoing chapter (v. 33); but his solemnizing the passover, which was touched upon there (Kg2 23:21), is very particularly related here. Many were the feasts of the Lord, appointed by the ceremonial law, but the passover was the chief. It began them all in the night wherein Israel came out of Egypt; it concluded them all in the night wherein Christ was betrayed; and i...', 'teologico');
add('2cr', 35, 20, 'Matthew Henry', 'It was thirteen years from Josiah\'s famous passover to his death. During this time, we may hope, thing went well in his kingdom, that he prospered, and religion flourished; yet we are not entertained with the pleasing account of those years, but they are passed over in silence, because the people, for all this, were not turned from the love of their sins nor God from the fierceness of his anger. The next news therefore we hear of Josiah is that he is cut off in the midst of his days and usefu...', 'teologico');
add('2cr', 36, 1, 'Matthew Henry', 'The destruction of Judah and Jerusalem is here coming on by degrees. God so ordered it to show that he has no pleasure in the ruin of sinners, but had rather they would turn and live, and therefore gives them both time and inducement to repent and waits to be gracious. The history of these reigns was more largely recorded in the last three chapters of the second of Kings. 1. Jehoahaz was set up by the people (Ch2 36:1), but in one quarter of a year was deposed by Pharaoh-necho, and carried a ...', 'teologico');
add('2cr', 36, 11, 'Matthew Henry', 'We have here an account of the destruction of the kingdom of Judah and the city of Jerusalem by the Chaldeans. Abraham, God\'s friend, was called out of that country, from Ur of the Chaldees, when God took him into covenant and communion with himself; and now his degenerate seed were carried into that country again, to signify that they had forfeited all that kindness wherewith they had been regarded for the father\'s sake, and the benefit of that covenant into which he was called; all was now ...', 'teologico');
add('2cr', 36, 22, 'Matthew Henry', 'These last two verses of this book have a double aspect. 1. They look back to the prophecy of Jeremiah, and show how that was accomplished, Ch2 36:22. God had, by him, promised the restoring of the captives and the rebuilding of Jerusalem, at the end of seventy years; and that time to favour Sion, that set time, came at last. After a long and dark night the day-spring from on high visited them. God will be found true to every word he has spoken. 2. They look forward to the history of Ezra, wh...', 'teologico');

// ED (28 comentários)
add('ed', 7, 10, 'Esdras', 'Dedicou o seu coração — O estudo e ensino da Lei brotam de coração consagrado.', 'aplicacao');
add('ed', 3, 11, 'Calvino', 'Porque o Senhor é bom — O fundamento do Templo restaurado celebra a fidelidade de Deus.', 'teologico');
add('ed', 1, 1, 'Matthew Henry', 'It will be proper for us here to consider, 1. What was the state of the captive Jews in Babylon. It was upon many accounts very deplorable; they were under the power of those that hated them, had nothing they could call their own; they had no temple, no altar; if they sang psalms, their enemies ridiculed them; and yet they had prophets among them. Ezekiel and Daniel were kept distinct from the heathen. Some of them were preferred at court, others had comfortable settlements in the country, an...', 'teologico');
add('ed', 1, 5, 'Matthew Henry', 'We are here told,\nI. How Cyrus\'s proclamation succeeded with others. 1. He having given leave to the Jews to go up to Jerusalem, many of them went up accordingly, Ezr 1:5. The leaders herein were the chief of the fathers of Judah and Benjamin, eminent and experienced men, from whom it might justly be expected that, as they were above their brethren in dignity, so they should go before them in duty. The priests and Levites were (as became them) with the first that set their faces again towards...', 'teologico');
add('ed', 2, 1, 'Matthew Henry', 'We may observe here, 1. That an account was kept in writing of the families that came up out of captivity, and the numbers of each family. This was done for their honour, as part of their recompence for their faith and courage, their confidence in God and their affection to their own land, and to stir up others to follow their good example. Those that honour God he will thus honour. The names of all those Israelites indeed that accept the offer of deliverance by Christ shall be found, to thei...', 'teologico');
add('ed', 2, 36, 'Matthew Henry', 'Here is an account, I. Of the priests that returned, and they were a considerable number, about a tenth part of the whole company: for the whole were above 42,000 (Ezr 2:64), and four families of priests made up above 4200 (Ezr 2:36-39); thus was the tenth God\'s part - a blessed decimation. Three of the fathers of the priests here named were heads of courses, Ch1 24:7, Ch1 24:8, Ch1 24:14. The fourth was Pashur, v. 38. If these were of the posterity of that Pashur that abused Jeremiah (Jer 20...', 'teologico');
add('ed', 2, 64, 'Matthew Henry', 'Here is, I. The sum total of the company that returned out of Babylon. The particular sums before mentioned amount not quite to 30,000 (29,818), so that there were above 12,000 that come out into any of those accounts, who, it is probable, were of the rest of the tribes of Israel, besides Judah and Benjamin, that could not tell of what particular family or city they were, but that they were Israelites, and of what tribe. Now, 1. This was more than double the number that were carried captive i...', 'teologico');
add('ed', 3, 1, 'Matthew Henry', 'Here is, I. A general assembly of the returned Israelites at Jerusalem, in the seventh month, Ezr 3:1. We may suppose that they came from Babylon in the spring, and must allow at least four months for the journey, for so long Ezra and his company were in coming, Ezr 7:9. The seventh month therefore soon came, in which many of the feasts of the Lord were to be solemnized; and then they gathered themselves together by agreement among themselves, rather than by the command of authority, to Jerus...', 'teologico');
add('ed', 3, 8, 'Matthew Henry', 'There was no dispute among the returned Jews whether they should build the temple or no; that was immediately resolved on, and that it should be done with all speed; what comfort could they take in their own land if they had not that token of God\'s presence with them and the record of his name among them? We have here therefore an account of the beginning of that good work. Observe,\nI. When it was begun-in the second month of the second year, as soon as ever the season of the year would permi...', 'teologico');
add('ed', 4, 1, 'Matthew Henry', 'We have here an instance of the old enmity that was put between the seed of the woman and the seed of the serpent. God\'s temple cannot be built, but Satan will rage, and the gates of hell will fight against it. The gospel kingdom was, in like manner, to be set up with much struggling and contention. In this respect the glory of the latter house was greater than the glory of the former, and it was more a figure of the temple of Christ\'s church, in that Solomon built his temple when there was n...', 'teologico');
add('ed', 4, 6, 'Matthew Henry', 'Cyrus stedfastly adhered to the Jews\' interest, and supported his own grant. It was to no purpose to offer any thing to him in prejudice of it. What he did was from a good principle, and in the fear of God, and therefore he adhered to it. But, though his reign in all was thirty years, yet after the conquest of Babylon, and his decree for the release of the Jews, some think that he reigned but three years, others seven, and then either died or gave up that part of his government, in which his ...', 'teologico');
add('ed', 4, 17, 'Matthew Henry', 'Here we have,\nI. The orders which the king of Persia gave, in answer to the information sent him by the Samaritans against the Jews. He suffered himself to be imposed upon by their fraud and falsehood, took no care to examine the allegations of their petition concerning that which the Jews were now doing, but took it for granted that the charge was true, and was very willing to gratify them with an order of council to stay proceedings. 1. He consulted the records concerning Jerusalem, and fou...', 'teologico');
add('ed', 5, 1, 'Matthew Henry', 'Some reckon that the building of the temple was suspended for only nine years; I am willing to believe that fifteen years were the utmost. During this time they had an altar and a tabernacle, which no doubt they made use of. When we cannot do what we would we must do what we can in the service of God, and be sorry we can do no better. But the counsellors that were hired to hinder the work (Ezr 4:5) told them, and perhaps with a pretence to inspiration, that the time had not come for the build...', 'teologico');
add('ed', 5, 3, 'Matthew Henry', 'We have here, I. The cognizance which their neighbours soon took of the reviving of this good work. A jealous eye, it seems, they had upon them, and no sooner did the Spirit of God stir up the friends of the temple to appear for it than the evil spirit stirred up its enemies to appear against it. While the people built and ceiled their own houses their enemies gave them no molestation (Hag 1:4), though the king\'s order was to put a stop to the building of the city (Ezr 4:21); but when they fe...', 'teologico');
add('ed', 6, 1, 'Matthew Henry', 'We have here, I. The decree of Cyrus for the building of the temple repeated. To this the Samaritans referred because the Jews pleaded it, and perhaps hoped it would not be found, and then their plea would be over-ruled and a stop put to their work. Search was ordered to be made for it among the records; for, it seems, the tribes had not taken care to provide themselves with an authentic copy of it, which might have stood them in good stead, but they must appeal to the original. It was looked...', 'teologico');
add('ed', 6, 13, 'Matthew Henry', 'Here we have, I. The Jews\' enemies made their friends. When they received this order from the king they came with as much haste to encourage and assist the work as their predecessors had done to put a stop to it, Ezr 4:23. What the king ordered they did, and, because they would not be thought to do it with reluctance, they did it speedily, Ezr 6:13. The king\'s moderation made them, contrary to their own inclination, moderate too.\nII. The building of the temple carried on, and finished in a li...', 'teologico');
add('ed', 7, 1, 'Matthew Henry', 'Here is, I. Ezra\'s pedigree. He was one of the sons of Aaron, a priest. Him God chose to be an instrument of good to Israel, that he might put honour upon the priesthood, the glory of which had been much eclipsed by the captivity. He is said to be the son of Seraiah, that Seraiah, as is supposed, whom the king of Babylon put to death when he sacked Jerusalem, Kg2 25:18, Kg2 25:21. If we take the shortest computation, it was seventy-five years since Seraiah died; many reckon it much longer, an...', 'teologico');
add('ed', 7, 11, 'Matthew Henry', 'We have here the commission which the Persian emperor granted to Ezra, giving him authority to act for the good of the Jews; and it is very ample and full, and beyond what could have been expected. The commission runs, we suppose, in the usual form: Artaxerxes, King of kings. This however is too high a title for any mortal man to assume; he was indeed king of some kings, but to speak as if he were king of all kings was to usurp his prerogative who hath all power both in heaven and in earth. H...', 'teologico');
add('ed', 7, 27, 'Matthew Henry', 'Ezra cannot proceed in his story without inserting his thankful acknowledgement of the goodness of God to him and his people in this matter. As soon as he has concluded the king\'s commission, instead of subjoining, God save the king (though that would have been proper enough), he adds, Blessed be the Lord; for we must in every thing give thanks, and, whatever occurrences please us, we must own God\'s hand in them, and praise his name. Two things Ezra blessed God for: - 1. For his commission. W...', 'teologico');
add('ed', 8, 1, 'Matthew Henry', 'Ezra, having received his commission from the king, beats up for volunteers, as it were, sets up an ensign to assemble the outcasts of Israel and the dispersed of Judah, Isa 11:12. "Whoever of the sons of Sion, that swell with the daughters of Babylon, is disposed to go to Jerusalem, now that the temple there is finished and the temple-service set a-going, now is their time." Now one would think that under such a leader, with such encouragements, all the Jews should at length have shaken them...', 'teologico');
add('ed', 8, 21, 'Matthew Henry', 'Ezra has procured Levites to go along with him; but what will that avail, unless he have God with him? That is therefore his chief care. In all our ways we must acknowledge God, and in those particularly wherein we are endeavouring to serve the interest of his kingdom among men. Ezra does so here. Observe,\nI. The stedfast confidence he had in God and in his gracious protection. He told the king (Ezr 8:22) what principles he went upon, that those who seek God are safe under the shadow of his w...', 'teologico');
add('ed', 8, 24, 'Matthew Henry', 'We have here an account of the particular care which Ezra took of the treasure he had with him, that belonged to God\'s sanctuary, Observe, 1. Having committed the keeping of it to God, he committed the keeping of it to proper men, whose business it was to watch it, though without God they would have waked in vain. Note, Our prayers must always be seconded with our endeavours; the care of Christ\'s gospel, his church, and ordinances, must not be so left with him but that it must also be committ...', 'teologico');
add('ed', 8, 31, 'Matthew Henry', 'We are now to attend Ezra to Jerusalem, a journey of about four months in all; but his multitude made his marches slow and his stages short. Now here we are told,\nI. That his God was good, and he acknowledged his goodness: The hand of our God was upon us, to animate us for our undertaking. To him they owed it, 1. That they were preserved in their journey, and not all cut off; for there were enemies that laid wait for them by the way to do them a mischief, or at least, like Amalek, to smite th...', 'teologico');
add('ed', 9, 1, 'Matthew Henry', 'Ezra, like Barnabas when he came to Jerusalem and saw the grace of God to his brethren there, no doubt was glad, and exhorted them all that with purpose of heart they would cleave to the Lord, Act 11:23. He saw nothing amiss (many corruptions lurk out of the view of the most vigilant rulers); but here is a damp upon his joys: information is brought him that many of the people, yea, and some of the rulers, had married wives out of heathen families, and joined themselves in affinity with strang...', 'teologico');
add('ed', 9, 5, 'Matthew Henry', 'What the meditations of Ezra\'s heart were, while for some hours he sat down astonished, we may guess by the words of his mouth when at length he spoke with his tongue; and a most pathetic address he here makes to Heaven upon this occasion. Observe,\nI. The time when he made this address - at the evening sacrifice, Ezr 9:5. Then (it is likely) devout people used to come into the courts of the temple, to grace the solemnity of the sacrifice and to offer up their own prayers to God in concurrence...', 'teologico');
add('ed', 10, 1, 'Matthew Henry', 'We are here told,\nI. What good impressions were made upon the people by Ezra\'s humiliation and confession of sin. No sooner was it noised in the city that their new governor, in whom they rejoiced, was himself in grief, and to so great a degree, for them and their sin, than presently there assembled to him a very great congregation, to see what the matter was and to mingle their tears with his, Ezr 10:1. Our weeping for other people\'s sins may perhaps set those a weeping for them themselves w...', 'teologico');
add('ed', 10, 6, 'Matthew Henry', 'We have here an account of the proceedings upon the resolutions lately taken up concerning the strange wives; no time was lost; they struck when the iron was hot, and soon set the wheels of reformation a-going. 1. Ezra went to the council-chamber where, it is probable, the priests used to meet upon public business; and till he came thither (so bishop Patrick thinks it should be read), till he saw something done, and more likely to be done, for the redress of this grievance, he did neither eat...', 'teologico');
add('ed', 10, 15, 'Matthew Henry', 'The method of proceeding in this matter being concluded on, and the congregation dismissed, that each in his respective place might gain and give intelligence to facilitate the matter, we are here told, 1. Who were the persons that undertook to manage the matter and bring the causes regularly before the commissioners - Jonathan and Jahaziah, two active men, whether of the priests or of the people does not appear; probably they were the men that made that proposal (Ezr 10:13, Ezr 10:14) and we...', 'teologico');

// NE (34 comentários)
add('ne', 8, 8, 'Neemias', 'Davam o sentido — A exposição clara da Palavra produz entendimento e edificação.', 'cultural');
add('ne', 8, 10, 'Spurgeon', 'A alegria do Senhor é a vossa força — A força espiritual brota da alegria em Deus.', 'aplicacao');
add('ne', 1, 1, 'Matthew Henry', 'What tribe Nehemiah was of does nowhere appear; but, if it be true (which we are told by the author of the Maccabees, 2 Macc. 1:18) that he offered sacrifice, we must conclude him to have been a priest. Observe,\nI. Nehemiah\'s station at the court of Persia. We are here told that he was in Shushan the palace, or royal city, of the king of Persia, where the court was ordinarily kept (Neh 1:1), and (Neh 1:11) that he was the king\'s cup-bearer. Kings and great men probably looked upon it as a pie...', 'teologico');
add('ne', 1, 5, 'Matthew Henry', 'We have here Nehemiah\'s prayer, a prayer that has reference to all the prayers which he had for some time before been putting up to God day and night, while he continued his sorrows for the desolations of Jerusalem, and withal to the petition he was now intending to present to the king his master for his favour to Jerusalem. We may observe in this prayer,\nI. His humble and reverent address to God, in which he prostrates himself before him, and gives unto him the glory due unto his name, Neh 1...', 'teologico');
add('ne', 2, 1, 'Matthew Henry', 'When Nehemiah had prayed for the relief of his countrymen, and perhaps in David\'s words (Psa 51:18, Build thou the walls of Jerusalem), he did not sit still and say, "Let God now do his own work, for I have no more to do," but set himself to forecast what he could do towards it. our prayers must be seconded with our serious endeavours, else we mock God. Nearly four months passed, from Chisleu to Nisan (from November to March), before Nehemiah made his application to the king for leave to go t...', 'teologico');
add('ne', 2, 9, 'Matthew Henry', 'We are here told,\nI. Now Nehemiah was dismissed by the court he was sent from. The king appointed captains of the army and horsemen to go with him (Neh 2:9), both for his guard and to show that he was a man whom the king did delight to honour, that all the king\'s servants might respect him accordingly. Those whom the King of kings sends he thus protects, he thus dignifies with a host of angels to attend them.\nII. How he was received by the country he was sent to.\n1. By the Jews and their frie...', 'teologico');
add('ne', 3, 1, 'Matthew Henry', 'The best way to know how to divide this chapter is to observe how the work was divided among the undertakers, that every one might know what he had to do, and mind it accordingly with a holy emulation, and desire to excel, yet without any contention, animosity, or separate interest. No strife appears among them but which should do most for the public good. Several things are observable in the account here given of the building of the wall about Jerusalem: - \nI. That Eliashib the high priest, ...', 'teologico');
add('ne', 4, 1, 'Matthew Henry', 'Here is, I. The spiteful scornful reflection which Sanballat and Tobiah cast upon the Jews for their attempt to build the wall about Jerusalem. The country rang of it presently; intelligence was brought of it to Samaria, that nest of enemies to the Jews and their prosperity; and here we are told how they received the tidings. 1. In heart. They were very angry at the undertaking, and had great indignation, Neh 4:1. It vexed them that Nehemiah came to seek the welfare of the children of Israel ...', 'teologico');
add('ne', 4, 7, 'Matthew Henry', 'We have here,\nI. The conspiracy which the Jews\' enemies formed against them, to stay the building by slaying the builders. The conspirators were not only Sanballat and Tobiah, but other neighbouring people whom they had drawn into the plot. They flattered themselves with a fancy that the work would soon stand still of itself; but, when they heard that it went on a prospered, they were angry at the Jews for being so hasty to push the work forward and angry at themselves for being so slow in op...', 'teologico');
add('ne', 4, 16, 'Matthew Henry', 'When the builders had so far reason to think the design of the enemies broken as to return to their work, yet they were not so secure as to lay down their arms, knowing how restless and unwearied they were in their attempts, and that, if one design failed, they would be hatching another. Thus must we watch always against our spiritual enemies, and not expect that our warfare will be accomplished till our work is. See what course Nehemiah took, that the people might hold themselves in a readin...', 'teologico');
add('ne', 5, 1, 'Matthew Henry', 'We have here the tears of the oppressed, which Solomon considered, Ecc 4:1. Let us consider them as here they are dropped before Nehemiah, whose office it was, as governor, to deliver the poor and needy, and rid them out of the hand of the wicked oppressors, Psa 82:4. Hard times and hard hearts made the poor miserable.\nI. The times they lived in were hard. There was a dearth of corn (Neh 5:3), probably for want of rain, with which God had chastised their neglect of his house (Hag 1:9-11) and ...', 'teologico');
add('ne', 5, 6, 'Matthew Henry', 'It should seem the foregoing complaint was made to Nehemiah at the time when he had his head and hands as full as possible of the public business about building the wall; yet, perceiving it to be just, he did not reject it because it was unseasonable; he did not chide the petitioners, nor fall into a passion with them, for disturbing him when they saw how much he had to do, a fault which men of business are too often guilty of; nor did he so much as adjourn the hearing of the cause or proceed...', 'teologico');
add('ne', 5, 14, 'Matthew Henry', 'Nehemiah had mentioned his own practice, as an inducement to the nobles not to burden the poor, no, not with just demands; here he relates more particularly what his practice was, not inn pride or vain-glory, nor to pass a compliment upon himself, but as an inducement both to his successors and to the inferior magistrates to be as tender as might be of the people\'s ease.\nI. He intimates what had been the way of his predecessors, Neh 5:15. He does not name them, because what he had to say of t...', 'teologico');
add('ne', 6, 1, 'Matthew Henry', 'Two plots upon Nehemiah we have here an account of, how cunningly they were laid by his enemies and how happily frustrated by God\'s good providence and his prudence.\nI. A plot to trepan him into a snare. The enemies had an account of the good forwardness the work was in, that all the breaches of the wall were made up, so that they considered it as good as done, though at that time the doors of the gates were off the hinges (Neh 6:1); they must therefore now or never, by one bold stroke, take ...', 'teologico');
add('ne', 6, 10, 'Matthew Henry', 'The Jews\' enemies leave no stone unturned, no way untried, to take Nehemiah off from building the wall about Jerusalem. In order to this they had tried to fetch him into the country to them, but in vain; now they try to drive him into the temple for his own safety; let him be any where but at his work. Observing him to be a cautious man, they will endeavour to gain their point by making him cowardly. Observe,\nI. How basely the enemies managed this temptation.\n1. That which they designed was t...', 'teologico');
add('ne', 6, 15, 'Matthew Henry', 'Nehemiah is here finishing the wall of Jerusalem, and yet still has trouble created him by his enemies.\nI. Tobiah, and the other adversaries of the Jews, had the mortification to see the wall built up, notwithstanding all their attempts to hinder it. The wall was begun and finished in fifty-two days, and yet we have reason to believe they rested on the sabbaths, Neh 6:15. Many were employed, and there was room for them; what they did they did cheerfully, and minded their business because they...', 'teologico');
add('ne', 7, 1, 'Matthew Henry', 'God saith concerning his church (Isa 62:6), I have set watchmen upon thy walls, O Jerusalem! This is Nehemiah\'s care here; for dead walls, without living watchmen, are but a poor defence to a city.\nI. He appointed the porters, singers, and Levites, in their places to their work. This is meant of their work in general, which was to attend the temple service; it had been neglected in some degree, but now was revived. God\'s worship is the defence of a place, and his ministers, when they mind the...', 'teologico');
add('ne', 7, 5, 'Matthew Henry', 'We have here another good project of Nehemiah\'s; for wise and zealous men will be always contriving something or other for the glory of God and the edification of his church. He knew very well that the safety of a city, under God, depends more upon the number and valour of the inhabitants than upon the height or strength of its walls; and therefore, observing that the people were few that dwelt in it, he thought fit to take an account of the people, that he might find what families had former...', 'teologico');
add('ne', 8, 1, 'Matthew Henry', 'We have here an account of a solemn religious assembly, and the good work that was done in that assembly, to the honour of God and the edification of the church.\nI. The time of it was the first day of the seventh month, Neh 8:2. That was the day of the feast of trumpets, which is called a sabbath, and on which they were to have a holy convocation, Lev 23:24; Num 29:1. But that was not all: it was one that day that the altar was set up, and they began to offer their burnt-offerings after their...', 'teologico');
add('ne', 8, 9, 'Matthew Henry', 'We may here observe,\nI. How the people were wounded with the words of the law that were read to them. The law works death, and speaks terror, shows men their sins, and their misery and danger because of sin, and thunders a curse against every one that continues not in every part of his duty. Therefore when they heard it they all wept (Neh 8:9): it was a good sign that their hearts were tender, like Josiah\'s when he heard the words of the law. They wept to think how they had offended God, and ...', 'teologico');
add('ne', 8, 13, 'Matthew Henry', 'We have here,\nI. The people\'s renewed attendance upon the word. They had spent the greatest part of one day in praying and hearing, and yet were so far from being weary of that new moon and sabbath that the next day after, though it was no festival, the chief of them came together again to hear Ezra expound (Neh 8:13), which they found more delightful and gainful than any worldly pleasure or profit whatsoever. Note, The more we converse with the word of God, if we rightly understand it and be...', 'teologico');
add('ne', 9, 1, 'Matthew Henry', 'We have here a general account of a public fast which the children of Israel kept, probably by order from Nehemiah, by and with the advice and consent of the chief of the fathers. It was a fast that men appointed, but such a fast as God had chosen; for, 1. It was a day to afflict the soul, Isa 58:5. Probably they assembled in the courts of the temple, and they there appeared in sackcloth and in the posture of mourners, with earth on their heads, Neh 9:1. By these outward expressions of sorrow...', 'teologico');
add('ne', 9, 4, 'Matthew Henry', 'We have here an account how the work of this fast-day was carried on. 1. The names of the ministers that were employed. They are twice named (Neh 9:4, Neh 9:5), only with some variation of the names. Either they prayed successively, according to that rule which the apostle gives (Co1 14:31, You may all prophesy one by one), or, as some think, there were eight several congregations at some distance from each other, and each had a Levite to preside in it. 2. The work itself in which they employ...', 'teologico');
add('ne', 10, 1, 'Matthew Henry', 'When Israel was first brought into covenant with God it was done by sacrifice and the sprinkling of blood, Ex. 24. But here it was done by the more natural and common way of sealing and subscribing the written articles of the covenant, which bound them to no more than was already their duty. Now here we have,\nI. The names of those public persons who, as the representatives and heads of the congregation, set their hands and seals to this covenant, because it would have been an endless piece of...', 'teologico');
add('ne', 10, 32, 'Matthew Henry', 'Having covenanted against the sins they had been guilty of, they proceed in obliging themselves to revive and observe the duties they had neglected. We must not only cease to do evil, but learn to do well.\nI. It was resolved, in general, that the temple service should be carefully kept up, that the work of the house of their God should be done in its season, according to the law, Neh 10:33. Let not any people expect the blessing of God unless they make conscience of observing his ordinances a...', 'teologico');
add('ne', 11, 1, 'Matthew Henry', 'Jerusalem is called here the holy city (Neh 11:1), because there the temple was, and that was the place God had chosen to put his name there; upon this account, one would think, the holy seed should all have chosen to dwell there and have striven for a habitation there; but, on the contrary, it seems they declined dwelling there, 1. Because a greater strictness of conversation was expected from the inhabitants of Jerusalem than from others, which they were not willing to come up to. Those who...', 'teologico');
add('ne', 11, 20, 'Matthew Henry', 'Having given an account of the principal persons that dwelt in Jerusalem (a larger account of whom he had before, Ch1 9:2, etc.), Nehemiah, in these verses, gives us some account of the other cities, in which dwelt the residue of Israel, Neh 11:20. It was requisite that Jerusalem should be replenished, yet not so as to drain the country. The king himself is served of the field, which will do little service if there be not hands to manage it. Let there therefore be no strife, no envy, no conte...', 'teologico');
add('ne', 12, 1, 'Matthew Henry', 'We have here the names, and little more than the names, of a great many priests and Levites, that were eminent in their day among the returned Jews. Why this register should be here inserted by Nehemiah does not appear, perhaps to keep in remembrance those good men, that posterity might know to whom they were beholden, under God, for the happy revival and re-establishment of their religion among them. Thus must we contribute towards the performance of that promise, Psa 112:6, The righteous sh...', 'teologico');
add('ne', 12, 27, 'Matthew Henry', 'We have read of the building of the wall of Jerusalem with a great deal of fear and trembling; we have here an account of the dedicating of it with a great deal of joy and triumph. Those that sow in tears shall thus reap.\nI. We must enquire what was the meaning of this dedication of the wall; we will suppose it to include the dedication of the city too (continens pro contentothe thing containing for the thing contained), and therefore it was not done till the city was pretty well replenished,...', 'teologico');
add('ne', 12, 44, 'Matthew Henry', 'We have here an account of the remaining good effects of the universal joy that was at the dedication of the wall. When the solemnities of a thanksgiving day leave such impressions on ministers and people as that both are more careful and cheerful in doing their duty afterwards, then they are indeed acceptable to God and turn to a good account. So it was here. 1. The ministers were more careful than they had been of their work; the respect the people paid them upon this occasion encouraged th...', 'teologico');
add('ne', 13, 1, 'Matthew Henry', 'It was the honour of Israel, and the greatest preservation of their holiness, that they were a peculiar people, and were so to keep themselves, and not to mingle with the nations, nor suffer any of them to incorporate with them. Now here we have,\nI. The law to this purport, which happened to be read on that day, in the audience of the people (Neh 13:1), on the day of the dedication of the wall, as it should seem, for with their prayers and praises they joined the reading of the word; and thou...', 'teologico');
add('ne', 13, 10, 'Matthew Henry', 'Here is another grievance redressed by Nehemiah.\nI. The Levites had been wronged. This was the grievance: their portions had not been given them, Neh 13:10. Perhaps Tobiah, when he took possession of the store-chambers, seized the stores too, and, by the connivance of Eliashib, converted them to his own use. The complaint is not that they were not collected from the people, but that they were not given to the Levites, and the Levites were so modest as not to sue for them; for the Levites and ...', 'teologico');
add('ne', 13, 15, 'Matthew Henry', 'Here is another instance of that blessed reformation in which Nehemiah was so active. He revived sabbath-sanctification, and maintained the authority of the fourth commandment; and a very good deed this was for the house of God and the offices thereof, for, where holy time is over-looked and made nothing of, it is not strange if all holy duties be neglected. Here is,\nI. A remonstrance of the abuse. The law of the sabbath was very strict and much insisted one, and with good reason, for religio...', 'teologico');
add('ne', 13, 23, 'Matthew Henry', 'We have here one instance more of Nehemiah\'s pious zeal for the purifying of his countrymen as a peculiar people to God; that was the thing he aimed at in the use of his power, not the enriching of himself. See here,\nI. How they had corrupted themselves by marrying strange wives. This was complained of in Ezra\'s time, and much done towards a reformation, Ezr 9:1-15 and 10. But, when the unclean spirit is cast out, if a watchful eye be not kept upon him, he will re-enter; so he did here. Thoug...', 'teologico');

// ET (22 comentários)
add('et', 4, 14, 'Lutero', 'Quem sabe se para tal momento — A providência de Deus prepara Suas pessoas para Sua obra.', 'teologico');
add('et', 1, 1, 'Matthew Henry', 'Which of the kings of Persia this Ahasuerus was the learned are not agreed. Mordecai is said to have been one of those that were carried captive from Jerusalem (Est 2:5, Est 2:6), whence it should seem that this Ahasuerus was one of the first kings of that empire. Dr. Lightfoot thinks that he was that Artaxerxes who hindered the building of the temple, who is called also Ahasuerus (Ezr 4:6, Ezr 4:7), after his great-grandfather of the Medes, Dan 9:1. We have here an account,\nI. Of the vast ex...', 'teologico');
add('et', 1, 10, 'Matthew Henry', 'We have here a damp to all the mirth of Ahasuerus\'s feast; it ended in heaviness, not as Job\'s children\'s feast by a wind from the wilderness, not as Belshazzar\'s by a hand-writing on the wall, but by is own folly. An unhappy falling out there was, at the end of the feast, between the king and queen, which broke of the feast abruptly, and sent the guests away silent and ashamed.\nI. It was certainly the king\'s weakness to send for Vashti into his presence when he was drunk, and in company with...', 'teologico');
add('et', 2, 1, 'Matthew Henry', 'How God put down one that was high and mighty from her seat we read in the chapter before, and are now to be told how he exalted one of low degree, as the virgin Mary observes in her song (Luk 1:52) and Hannah before her, Sa1 2:4-8. Vashti being humbled for her height, Esther is advanced for her humility. Observe,\nI. The extravagant course that was taken to please the king with another wife instead of Vashti. Josephus says that when his anger was over he was exceedingly grieved that the matte...', 'teologico');
add('et', 2, 21, 'Matthew Henry', 'This good service which Mordecai did to the government, in discovering a plot against the life of the king, is here recorded, because the mention of it will again occur to his advantage. No step is yet taken towards Haman\'s design of the Jews\' destruction, but several steps are taken towards God\'s design of their deliverance, and this for one. God now gives Mordecai an opportunity of doing the king a good turn, that he might have the fairer opportunity afterwards of doing the Jews a good turn...', 'teologico');
add('et', 3, 1, 'Matthew Henry', 'Here we have,\nI. Haman advanced by the prince, and adored thereupon by the people. Ahasuerus had lately laid Esther in his bosom, but she had no such interest in him as to get her friends preferred, or to prevent the preferring of one who she knew was an enemy to her people. When those that are good become great they still find that they cannot do good, nor prevent mischief, as they would. This Haman was an Agagite (an Amalekite, says Josephus), probably of the descendants of Agag, a common n...', 'teologico');
add('et', 3, 7, 'Matthew Henry', 'Haman values himself upon that bold and daring thought, which he fancied well became his great spirit, of destroying all the Jews - an undertaking worthy of its author, and which he promised himself would perpetuate his memory. He doubts not but to find desperate and bloody hands enough to cut all their throats if the king will but give him leave. How he obtained leave, and commission to do it, we are here told. He had the king\'s ear, let him alone to manage him.\nI. He makes a false and malic...', 'teologico');
add('et', 4, 1, 'Matthew Henry', 'Here we have an account of the general sorrow that there was among the Jews upon the publishing of Haman\'s bloody edict against them. It was a sad time with the church. 1. Mordecai cried bitterly, rent his clothes, and put on sackcloth, Est 4:1, Est 4:2. He not only thus vented his grief, but proclaimed it, that all might take notice of it that he was not ashamed to own himself a friend to the Jews, and a fellow-sufferer with them, their brother and companion in tribulation, how despicable an...', 'teologico');
add('et', 4, 5, 'Matthew Henry', 'So strictly did the laws of Persia confine the wives, especially the king\'s wives, that it was not possible for Mordecai to have a conference with Esther about this important affair, but divers messages are here carried between them by Hatach, whom the king had appointed to attend her, and it seems he was one she could confide in.\nI. She sent to Mordecai to know more particularly and fully what the trouble was which he was now lamenting (Est 4:5) and why it was that he would not put off his s...', 'teologico');
add('et', 5, 1, 'Matthew Henry', 'Here is, I. Esther\'s bold approach to the king, Est 5:1. When the time appointed for their fast was finished she lost no time, but on the third day, when the impression of her devotions were fresh upon her spirit, she addressed the king. When the heart is enlarged in communion with God it will be emboldened in doing and suffering for him. Some think that the three days\' fast was only one whole day and two whole nights, in all which time they did not take any food at all, and that this is call...', 'teologico');
add('et', 5, 9, 'Matthew Henry', 'This account here given of Haman is a comment upon that of Solomon, Pro 21:24. Proud and haughty scorner is his name that deals in proud wrath. Never did any man more answer that name than Haman, in whom pride and wrath had so much the ascendant. See him,\nI. Puffed up with the honour of being invited to Esther\'s feast. He was joyful and glad of heart at it, Est 5:9. Observe with what a high gust he speaks of it (Est 5:12), how he values himself upon it, and how near he thinks it brings him to...', 'teologico');
add('et', 6, 1, 'Matthew Henry', 'Now Satan put it into the heart of Haman to contrive Mordecai\'s death we read in the foregoing chapter; how God put it into the heart of the king to contrive Mordecai\'s honour we are here told. Now, if the king\'s word will prevail above Haman\'s (for, though Haman be a great man, the king in the throne must be above him), much more will the counsel of God stand, whatever devices there are in men\'s hearts. It is to no purpose therefore for Haman to oppose it, when both God and the king will hav...', 'teologico');
add('et', 6, 4, 'Matthew Henry', 'It is now morning, and people begin to stir.\nI. Haman is so impatient to get Mordecai hanged that he comes early to court, to be ready at the king\'s levee, before any other business is brought before him, to get a warrant for his execution (Est 6:4), which he makes sure that he shall have at the first word. The king would gratify him in a greater thing than that; and he could tell the king that he was so confident of the justice of his request, and the king\'s favour to him in it, that he had ...', 'teologico');
add('et', 6, 12, 'Matthew Henry', 'We may here observe,\nI. How little Mordecai was puffed up with his advancement. he came again to the king\'s gate (Est 6:12); he returned to his place and the duty of it immediately, and minded his business as closely as he had done before. Honour is well bestowed on those that are not made proud and idle by it, and will not think themselves above their business.\nII. How much Haman was cast down with his disappointment. he could not bear it. To wait upon any man, especially Mordecai, and at th...', 'teologico');
add('et', 7, 1, 'Matthew Henry', 'The king in humour, and Haman out of humour, meet at Esther\'s table. Now,\nI. The king urged Esther, a third time, to tell him what her request was, for he longed to know, and repeated his promise that it should be granted, Est 7:2. If the king had now forgotten that Esther had an errand to him, and had not again asked what it was, she could scarcely have known how to renew it herself; but he was mindful of it, and now was bound with the threefold cord of a promise thrice made to favour her.\nI...', 'teologico');
add('et', 7, 7, 'Matthew Henry', 'Here, I. The king retires in anger. He rose from table in a great passion, and went into the palace garden to cool himself and to consider what was to be done, Est 7:7. He sent not for his seven wise counsellors who knew the times, being ashamed to consult them about the undoing of that which he had rashly done without their knowledge or advice; but he went to walk in the garden awhile, to compare in his thoughts what Esther had now informed him of with what had formerly passed between him an...', 'teologico');
add('et', 8, 1, 'Matthew Henry', 'It was but lately that we had Esther and Mordecai in tears and in fears, but fasting and praying; now let us see how to them there arose light in darkness. Here is, 1. Esther enriched. Haman was hanged as a traitor, therefore his estate was forfeited to the crown, and the king gave it all to Esther, in recompence for the fright that wicked man had put her into and the vexation he had created her, Est 8:1. His houses and lands, good sand chattels, and all the money he had heaped up which he wa...', 'teologico');
add('et', 8, 3, 'Matthew Henry', 'Haman, the chief enemy of the Jews, was hanged, Mordecai and Esther, their chief friends, were sufficiently protected; but many others there were in the king\'s dominions that hated the Jews and desired their ruin, and to their rage and malice all the rest of that people lay exposed; for the edict against them was still in force, and, in pursuance of it, their enemies would on the day appointed fall upon them, and they would be deemed as rebels against the king and his government if they shoul...', 'teologico');
add('et', 8, 15, 'Matthew Henry', 'It was but a few days ago that we had Mordecai in sackcloth and all the Jews in sorrow; but here is a blessed change, Mordecai in purple and all the Jews in joy. See Psa 30:5, Psa 30:11, Psa 30:12. 1. Mordecai in purple, Est 8:15. Having obtained an order for the relief of all the Jews, he was easy, he parted with his mourning weeds, and put on the royal apparel, which either belonged to his place or which the king appointed him as a favourite. His robes were rich, blue and white, of fine lin...', 'teologico');
add('et', 9, 1, 'Matthew Henry', 'We have here a decisive battle fought between the Jews and their enemies, in which the Jews were victorious. Neither side was surprised; for both had notice of it long enough before, so that it was a fair trial of skill between them. Nor could either side call the other rebels, for they were both supported by the royal authority.\nI. The enemies of the Jews were the aggressors. They hoped, notwithstanding the latter edict, to have power over them, by virtue of the former (Est 9:1), and made as...', 'teologico');
add('et', 9, 20, 'Matthew Henry', 'We may well imagine how much affected Mordecai and Esther were with the triumphs of the Jews over their enemies, and how they saw the issue of that decisive day with a satisfaction proportionable to the care and concern with which they expected it. How were their hearts enlarged with joy in God and his salvation, and what new songs of praise were put into their mouths! But here we are told what course they took to spread the knowledge of it among their people, and to perpetuate the remembranc...', 'teologico');
add('et', 10, 1, 'Matthew Henry', 'We are here told,\nI. How great and powerful king Ahasuerus was. He had a vast dominion, both in the continent and among the islands, from which he raised a vast revenue. Besides the usual customs which the kings of Persia exacted (Ezr 4:13), he laid an additional tribute upon his subjects, to serve for some great occasion he had for money (Est 10:1): The king laid a tribute. Happy is our island, that pays no tribute but what is laid upon it by its representatives, and those of its own choosin...', 'teologico');

// JÓ (137 comentários)
add('jó', 1, 21, 'Calvino', 'Nu saí do ventre de minha mãe — A soberania de Deus sobre a vida e a morte: receber e perder vêm dEle.', 'teologico');
add('jó', 19, 25, 'Agostinho', 'Eu sei que o meu Redentor vive — A esperança da ressurreição: Jó antecipa o Libertador eterno.', 'escatologico');
add('jó', 38, 4, 'Tomás de Aquino', 'Onde estavas tu — A resposta de Deus a Jó afirma a incompreensibilidade da Sabedoria divina.', 'teologico');
add('jó', 42, 5, 'Lutero', 'Antes te ouvia, mas agora te vejo — O conhecimento experiential de Deus supera o intelectual.', 'teologico');
add('jó', 1, 1, 'Matthew Henry', 'Concerning Job we are here told,\nI. That he was a man; therefore subject to like passions as we are. He was Ish, a worthy man, a man of note and eminency, a magistrate, a man in authority. The country he lived in was the land of Uz, in the eastern part of Arabia, which lay towards Chaldea, near Euphrates, probably not far from Ur of the Chaldees, whence Abraham was called. When God called one good man out of that country, yet he left not himself without witness, but raised up another in it to...', 'teologico');
add('jó', 1, 4, 'Matthew Henry', 'We have here a further account of Job\'s prosperity and his piety.\nI. His great comfort in his children is taken notice of as an instance of his prosperity; for our temporal comforts are borrowed, depend upon others, and are as those about us are. Job himself mentions it as one of the greatest joys of his prosperous estate that his children were about him, Job 29:5. They kept a circular feast at some certain times (Job 1:4); they went and feasted in their houses. It was a comfort to this good ...', 'teologico');
add('jó', 1, 6, 'Matthew Henry', 'Job was not only so rich and great, but withal so wise and good, and had such an interest both in heaven and earth, that one would think the mountain of his prosperity stood so strong that it could not be moved; but here we have a thick cloud gathering over his head, pregnant with a horrible tempest. We must never think ourselves secure from storms while we are in this lower region. Before we are told how his troubles surprised and seized him here in this visible world, we are here told how t...', 'teologico');
add('jó', 1, 13, 'Matthew Henry', 'We have here a particular account of Job\'s troubles.\nI. Satan brought them upon him on the very day that his children began their course of feasting, at their eldest brother\'s house (Job 1:13), where, he having (we may suppose) the double portion, the entertainment was the richest and most plentiful. The whole family, no doubt, was in perfect repose, and all were easy and under no apprehension of the trouble, now when they revived this custom; and this time Satan chose, that the trouble, comi...', 'teologico');
add('jó', 1, 20, 'Matthew Henry', 'The devil had done all he desired leave to do against Job, to provoke him to curse God. He had touched all he had, touched it with a witness; he whom the rising sun saw the richest of all the men in the east was before night poor to a proverb. If his riches had been, as Satan insinuated, the only principle of his religion now that he had lost his riches he would certainly have lost his religion; but the account we have, in these verses, of his pious deportment under his affliction, sufficient...', 'teologico');
add('jó', 2, 1, 'Matthew Henry', 'Satan, that sworn enemy to God and all good men, is here pushing forward his malicious prosecution of Job, whom he hated because God loved him, and did all he could to separate between him and his God, to sow discord and make mischief between them, urging God to afflict him and then urging him to blaspheme God. One would have thought that he had enough of his former attempt upon Job, in which he was so shamefully baffled and disappointed; but malice is restless: the devil and his instruments ...', 'teologico');
add('jó', 2, 7, 'Matthew Henry', 'The devil, having got leave to tear and worry poor Job, presently fell to work with him, as a tormentor first and then as a tempter. His own children he tempts first, and draws them to sin, and afterwards torments, when thereby he has brought them to ruin; but this child of God he tormented with an affliction, and then tempted to make a bad use of his affliction. That which he aimed at was to make Job curse God; now here we are told what course he took both to move him to it and move it to hi...', 'teologico');
add('jó', 2, 11, 'Matthew Henry', 'We have here an account of the kind visit which Job\'s three friends paid him in his affliction. The news of his extraordinary troubles spread into all parts, he being an eminent man both for greatness and goodness, and the circumstances of his troubles being very uncommon. Some, who were his enemies, triumphed in his calamities, Job 16:10; Job 19:18; Job 30:1, etc. Perhaps they made ballads on him. But his friends concerned themselves for him, and endeavoured to comfort him. A friend loveth a...', 'teologico');
add('jó', 3, 1, 'Matthew Henry', 'Long was Job\'s heart hot within him; and, while he was musing, the fire burned, and the more for being stifled and suppressed. At length he spoke with his tongue, but not such a good word as David spoke after a long pause: Lord, make me to know my end, Psa 39:3, Psa 39:4. Seven days the prophet Ezekiel sat down astonished with the captives, and then (probably on the sabbath day) the word of the Lord came to him, Eze 3:15, Eze 3:16. So long Job and his friends sat thinking, but said nothing; t...', 'teologico');
add('jó', 3, 11, 'Matthew Henry', 'Job, perhaps reflecting upon himself for his folly in wishing he had never been born, follows it, and thinks to mend it, with another, little better, that he had died as soon as he was born, which he enlarges upon in these verses. When our Saviour would set forth a very calamitous state of things he seems to allow such a saying as this, Blessed are the barren, and the wombs that never bore, and the paps which never gave suck (Luk 23:29); but blessing the barren womb is one thing and cursing t...', 'teologico');
add('jó', 3, 20, 'Matthew Henry', 'Job, finding it to no purpose to wish either that he had not been born or had died as soon as he was born, here complains that his life was now continued and not cut off. When men are set on quarrelling there is no end of it; the corrupt heart will carry on the humour. Having cursed the day of his birth, here he courts the day of his death. The beginning of this strife and impatience is as the letting forth of water.\nI. He thinks it hard, in general, that miserable lives should be prolonged (...', 'teologico');
add('jó', 4, 1, 'Matthew Henry', 'In these verses,\nI. Eliphaz excuses the trouble he is now about to give to Job by his discourse (Job 4:2): "If we assay a word with thee, offer a word of reproof and counsel, wilt thou be grieved and take it ill?" We have reason to fear thou wilt; but there is no remedy: "Who can refrain from words?" Observe, 1. With what modesty he speaks of himself and his own attempt. He will not undertake the management of the cause alone, but very humbly joins his friends with him: "We will commune with ...', 'teologico');
add('jó', 4, 7, 'Matthew Henry', 'Eliphaz here advances another argument to prove Job a hypocrite, and will have not only his impatience under his afflictions to be evidence against him but even his afflictions themselves, being so very great and extraordinary, and there being no prospect at all of his deliverance out of them. To strengthen his argument he here lays down these two principles, which seem plausible enough: - \nI. That good men were never thus ruined. For the proof of this he appeals to Job\'s own observation (Job...', 'teologico');
add('jó', 4, 12, 'Matthew Henry', 'Eliphaz, having undertaken to convince Job of the sin and folly of his discontent and impatience, here vouches a vision he had been favoured with, which he relates to Job for his conviction. What comes immediately from God all men will pay a particular deference to, and Job, no doubt, as much as any. Some think Eliphaz had this vision now lately, since he came to Job, putting words into his mouth wherewith to reason with him; and it would have been well if he had kept to the purport of this v...', 'teologico');
add('jó', 5, 1, 'Matthew Henry', 'A very warm dispute being begun between Job and his friends, Eliphaz here makes a fair motion to put the matter to a reference. In all debates perhaps the sooner this is done the better if the contenders cannot end it between themselves. So well assured is Eliphaz of the goodness of his own cause that he moves Job himself to choose the arbitrators (Job 5:1): Call now, if there be any that will answer thee; that is, 1. "If there be any that suffer as thou sufferest. Canst thou produce an insta...', 'teologico');
add('jó', 5, 6, 'Matthew Henry', 'Eliphaz, having touched Job in a very tender part, in mentioning both the loss of his estate and the death of his children as the just punishment of his sin, that he might not drive him to despair, here begins to encourage him, and puts him in a way to make himself easy. Now he very much changes his voice (Gal 4:20), and speaks in the accents of kindness, as if he would atone for the hard words he had given him.\nI. He reminds him that no affliction comes by chance, nor is to be attributed to ...', 'teologico');
add('jó', 5, 17, 'Matthew Henry', 'Eliphaz, in this concluding paragraph of his discourse, gives Job (what he himself knew not how to take) a comfortable prospect of the issue of his afflictions, if he did but recover his temper and accommodate himself to them. Observe,\nI. The seasonable word of caution and exhortation that he gives him (Job 5:17): "Despise not thou the chastening of the Almighty. Call it a chastening, which comes from the father\'s love and is designed for the child\'s good. Call it the chastening of the Almigh...', 'teologico');
add('jó', 6, 1, 'Matthew Henry', 'Eliphaz, in the beginning of his discourse, had been very sharp upon Job, and yet it does not appear that Job gave him any interruption, but heard him patiently till he had said all he had to say. Those that would make an impartial judgment of a discourse must hear it out, and take it entire. But, when he had concluded, he makes his reply, in which he speaks very feelingly.\nI. He represents his calamity, in general, as much heavier than either he had expressed it or they had apprehended it, J...', 'teologico');
add('jó', 6, 8, 'Matthew Henry', 'Ungoverned passion often grows more violent when it meets with some rebuke and check. The troubled sea rages most when it dashes against a rock. Job had been courting death, as that which would be the happy period of his miseries, ch. 3. For this Eliphaz had gravely reproved him, but he, instead of unsaying what he had said, says it here again with more vehemence than before; and it is as ill said as almost any thing we meet with in all his discourses, and is recorded for our admonition, not ...', 'teologico');
add('jó', 6, 14, 'Matthew Henry', 'Eliphaz had been very severe in his censures of Job; and his companions, though as yet they had said little, yet had intimated their concurrence with him. Their unkindness therein poor Job here complains of, as an aggravation of his calamity and a further excuse of his desire to die; for what satisfaction could he ever expect in this world when those that should have been his comforters thus proved his tormentors?\nI. He shows what reason he had to expect kindness from them. His expectation wa...', 'teologico');
add('jó', 6, 22, 'Matthew Henry', 'Poor Job goes on here to upbraid his friends with their unkindness and the hard usage they gave him. He here appeals to themselves concerning several things which tended both to justify him and to condemn them. If they would but think impartially, and speak as they thought, they could not but own,\nI. That, though he was necessitous, yet he was not craving, nor burdensome to his friends. Those that are so, whose troubles serve them to beg by, are commonly less pitied than the silent poor. Job ...', 'teologico');
add('jó', 7, 1, 'Matthew Henry', 'Job is here excusing what he could not justify, even his inordinate desire of death. Why should he not wish for the termination of life, which would be the termination of his miseries? To enforce this reason he argues,\nI. From the general condition of man upon earth (Job 7:1): "He is of few days, and full of trouble. Every man must die shortly, and every man has some reason (more or less) to desire to die shortly; and therefore why should you impute it to me as so heinous a crime that I wish ...', 'teologico');
add('jó', 7, 7, 'Matthew Henry', 'Job, observing perhaps that his friends, though they would not interrupt him in his discourse, yet began to grow weary, and not to heed much what he said, here turns to God, and speaks to him. If men will not hear us, God will; if men cannot help us, he can; for his arm is not shortened, neither is his ear heavy. Yet we must not go to school to Job here to learn how to speak to God; for, it must be confessed, there is a great mixture of passion and corruption in what he here says. But, if God...', 'teologico');
add('jó', 7, 17, 'Matthew Henry', 'Job here reasons with God,\nI. Concerning his dealings with man in general (Job 7:17, Job 7:18): What is man, that thou shouldst magnify him? This may be looked upon either, 1. As a passionate reflection upon the proceedings of divine justice; as if the great God did diminish and disparage himself in contending with man. "Great men think it below them to take cognizance of those who are much their inferiors so far as to reprove and correct their follies and indecencies; why then does God magni...', 'teologico');
add('jó', 8, 1, 'Matthew Henry', 'Here, I. Bildad reproves Job for what he had said (Job 8:2), checks his passion, but perhaps (as is too common) with greater passion. We thought Job spoke a great deal of good sense and much to the purpose, and that he had reason and right on his side; but Bildad, like an eager angry disputant, turns it all off with this, How long wilt thou speak these things? taking it for granted that Eliphaz had said enough to silence him, and that therefore all he said was impertinent. Thus (as Caryl obse...', 'teologico');
add('jó', 8, 8, 'Matthew Henry', 'Bildad here discourses very well on the sad catastrophe of hypocrites and evil-doers and the fatal period of all their hopes and joys. He will not be so bold as to say with Eliphaz that none that were righteous were ever cut off thus (Job 4:7); yet he takes it for granted that God, in the course of his providence, does ordinarily bring wicked men, who seemed pious and were prosperous, to shame and ruin in this world, and that, by making their prosperity short, he discovers their piety to be c...', 'teologico');
add('jó', 8, 20, 'Matthew Henry', 'Bildad here, in the close of his discourse, sums up what he has to say in a few words, setting before Job life and death, the blessing and the curse, assuring him that as he was so he should fare, and therefore they might conclude that as he fared so he was. 1. On the one hand, if he were a perfect upright man, God would not cast him away, Job 8:20. Though now he seemed forsaken of God, he would yet return to him, and by degrees would turn his mourning into dancing (Psa 30:11) and comforts sh...', 'teologico');
add('jó', 9, 1, 'Matthew Henry', 'Bildad began with a rebuke to Job for talking so much, Job 8:2. Job makes no answer to that, though it would have been easy enough to retort it upon himself; but in what he next lays down as his principle, that God never perverts judgment, Job agrees with him: I know it is so of a truth, Job 9:2. Note, We should be ready to own how far we agree with those with whom we dispute, and should not slight, much less resist, a truth, though produced by an adversary and urged against us, but receive i...', 'teologico');
add('jó', 9, 14, 'Matthew Henry', 'What Job had said of man\'s utter inability to contend with God he here applies to himself, and in effect despairs of gaining his favour, which (some think) arises from the hard thoughts he had of God, as one who, having set himself against him, right or wrong, would be too hard for him. I rather think it arises from the sense he had of the imperfection of his own righteousness, and the dark and cloudy apprehensions which at present he had of God\'s displeasure against him.\nI. He durst not disp...', 'teologico');
add('jó', 9, 22, 'Matthew Henry', 'Here Job touches briefly upon the main point now in dispute between him and his friends. They maintained that those who are righteous and good always prosper in this world, and none but the wicked are in misery and distress; he asserted, on the contrary, that it is a common thing for the wicked to prosper and the righteous to be greatly afflicted. This is the one thing, the chief thing, wherein he and his friends differed; and they had not proved their assertion, therefore he abides by his: "...', 'teologico');
add('jó', 9, 25, 'Matthew Henry', 'Job here grows more and more querulous, and does not conclude this chapter with such reverent expressions of God\'s wisdom and justice as he began with. Those that indulge a complaining humour know not to what indecencies, nay, to what impieties, it will hurry them. The beginning of that strife with God is as the letting forth of water; therefore leave it off before it be meddled with. When we are in trouble we are allowed to complain to God, as the Psalmist often, but must by no means complai...', 'teologico');
add('jó', 10, 1, 'Matthew Henry', 'Here is, I. A passionate resolution to persist in his complaint, Job 10:1. Being daunted with the dread of God\'s majesty, so that he could not plead his cause with him, he resolves to give himself some ease by giving vent to his resentments. He begins with vehement language: "My soul is weary of my life, weary of this body, and impatient to get clear of it, fallen out with life, and displeased at it, sick of it, and longing for death." Through the weakness of grace he went contrary to the dic...', 'teologico');
add('jó', 10, 8, 'Matthew Henry', 'In these verses we may observe,\nI. How Job eyes God as his Creator and preserver, and describes his dependence upon him as the author and upholder of his being. This is one of the first things we are all concerned to know and consider.\n1. That God made us, he, and not our parents, who were only the instruments of his power and providence in our production. He made us, and not we ourselves. His hands have made and fashioned these bodies of ours and every part of them (Job 10:8), and they are f...', 'teologico');
add('jó', 10, 14, 'Matthew Henry', 'Here we have,\nI. Job\'s passionate complaints. On this harsh and unpleasant string he harps much, in which, though he cannot be justified, he may be excused. He complained not for nothing, as the murmuring Israelites, but had cause to complain. If we think it looks ill in him, let it be a warning to us to keep our temper better.\n1. He complains of the strictness of God\'s judgment and the rigour of his proceedings against him, and is ready to call it summum jus - justice bordering on severity. ...', 'teologico');
add('jó', 11, 1, 'Matthew Henry', 'It is sad to see what intemperate passions even wise and good men are sometimes betrayed into by the heat of disputation, of which Zophar here is an instance. Eliphaz began with a very modest preface, Job 4:2. Bildad was a little more rough upon Job, Job 8:2. But Zophar falls upon him without mercy, and gives him very bad language: Should a man full of talk be justified? And should thy lies make men hold their peace? Is this the way to comfort Job? No, nor to convince him neither. Does this b...', 'teologico');
add('jó', 11, 7, 'Matthew Henry', 'Zophar here speaks very good things concerning God and his greatness and glory, concerning man and his vanity and folly: these two compared together, and duly considered, will have a powerful influence upon our submission to all the dispensations of the divine Providence.\nI. See here what God is, and let him be adored.\n1. He is an incomprehensible Being, infinite and immense, whose nature and perfections our finite understandings cannot possibly form any adequate conceptions of, and whose cou...', 'teologico');
add('jó', 11, 13, 'Matthew Henry', 'Zophar, as the other two, here encourages Job to hope for better times if he would but come to a better temper.\nI. He gives him good counsel (Job 11:13, Job 11:14), as Eliphaz did (Job 5:8), and Bildad, Job 8:5. He would have him repent and return to God. Observe the steps of that return. 1. He must look within, and get his mind changed and the tree made good. He must prepare his heart; there the work of conversion and reformation must begin. The heart that wandered from God must be reduced -...', 'teologico');
add('jó', 12, 1, 'Matthew Henry', 'The reproofs Job here gives to his friends, whether they were just or no, were very sharp, and may serve for a rebuke to all that are proud and scornful, and an exposure of their folly.\nI. He upbraids them with their conceitedness of themselves, and the good opinion they seemed to have of their own wisdom in comparison with him, than which nothing is more weak and unbecoming, nor better deserves to be ridiculed, as it is here. 1. He represents them as claiming the monopoly of wisdom, Job 12:2...', 'teologico');
add('jó', 12, 6, 'Matthew Henry', 'Job\'s friends all of them went upon this principle, that wicked people cannot prosper long in this world, but some remarkable judgment or other will suddenly light on them: Zophar had concluded with it, that the eyes of the wicked shall fail, Job 11:20. This principle Job here opposes, and maintains that God, in disposing men\'s outward affairs, acts as a sovereign, reserving the exact distribution of rewards and punishments for the future state.\nI. He asserts it as an undoubted truth that wic...', 'teologico');
add('jó', 12, 12, 'Matthew Henry', 'This is a noble discourse of Job\'s concerning the wisdom, power, and sovereignty of God, in ordering and disposing of all the affairs of the children of men, according to the counsel of his own will, which none dares gainsay or can resist. Take both him and them out of the controversy in which they were so warmly engaged, and they all spoke admirably well; but, in that, we sometimes scarcely know what to make of them. It were well if wise and good men, that differ in their apprehensions about...', 'teologico');
add('jó', 13, 1, 'Matthew Henry', 'Job here warmly expresses his resentment of the unkindness of his friends.\nI. He comes up with them as one that understood the matter in dispute as well as they, and did not need to be taught by them, Job 13:1, Job 13:2. They compelled him, as the Corinthians did Paul, to commend himself and his own knowledge, yet not in a way of self-applause, but of self-justification. All he had before said his eye had seen confirmed by many instances, and his ear had heard seconded by many authorities, an...', 'teologico');
add('jó', 13, 13, 'Matthew Henry', 'Job here takes fresh hold, fast hold, of his integrity, as one that was resolved not to let it go, nor suffer it to be wrested from him. His firmness in this matter is commendable and his warmth excusable.\nI. He entreats his friends and all the company to let him alone, and not interrupt him in what he was about to say (Job 13:13), but diligently to hearken to it, Job 13:17. He would have his own protestation to be decisive, for none but God and himself knew his heart. "Be silent therefore, a...', 'teologico');
add('jó', 13, 23, 'Matthew Henry', 'Here, I. Job enquires after his sins, and begs to have them discovered to him. He looks up to God, and asks him what was the number of them (How many are my iniquities?) and what were the particulars of them: Make me to know my transgressions, Job 13:23. His friends were ready enough to tell him how numerous and how heinous they were, Job 22:5. "But, Lord," says he, "let me know them from thee; for thy judgment is according to truth, theirs is not." This may be taken either, 1. As a passionat...', 'teologico');
add('jó', 14, 1, 'Matthew Henry', 'We are here led to think,\nI. Of the original of human life. God is indeed its great original, for he breathed into man the breath of life and in him we live; but we date it from our birth, and thence we must date both its frailty and its pollution. 1. Its frailty: Man, that is born of a woman, is therefore of few days, Job 14:1. This may refer to the first woman, who was called Eve, because she was the mother of all living. Of her, who being deceived by the tempter was first in the transgress...', 'teologico');
add('jó', 14, 7, 'Matthew Henry', 'We have seen what Job has to say concerning life; let us now see what he has to say concerning death, which his thoughts were very much conversant with, now that he was sick and sore. It is not unseasonable, when we are in health, to think of dying; but it is an inexcusable incogitancy if, when we are already taken into the custody of death\'s messengers, we look upon it as a thing at a distance. Job had already shown that death will come, and that its hour is already fixed. Now here he shows,...', 'teologico');
add('jó', 14, 16, 'Matthew Henry', 'Job here returns to his complaints; and, though he is not without hope of future bliss, he finds it very hard to get over his present grievances.\nI. He complains of the particular hardships he apprehended himself under from the strictness of God\'s justice, Job 14:16, Job 14:17. Therefore he longed to go hence to that world where God\'s wrath will be past, because now he was under the continual tokens of it, as a child, under the severe discipline of the rod, longs to be of age. "When shall my ...', 'teologico');
add('jó', 15, 1, 'Matthew Henry', 'Eliphaz here falls very foul upon Job, because he contradicted what he and his colleagues had said, and did not acquiesce in it and applaud it, as they expected. Proud people are apt thus to take it very much amiss if they may not have leave to dictate and give law to all about them, and to censure those as ignorant and obstinate, and all that is naught, who cannot in every thing say as they say. Several great crimes Eliphaz here charges Job with, only because he would not own himself a hypoc...', 'teologico');
add('jó', 15, 17, 'Matthew Henry', 'Eliphaz, having reproved Job for his answers, here comes to maintain his own thesis, upon which he built his censure of Job. His opinion is that those who are wicked are certainly miserable, whence he would infer that those who are miserable are certainly wicked, and that therefore Job was so. Observe,\nI. His solemn preface to this discourse, in which he bespeaks Job\'s attention, which he had little reason to expect, he having given so little heed to and put so little value upon what Job had ...', 'teologico');
add('jó', 16, 1, 'Matthew Henry', 'Both Job and his friends took the same way that disputants commonly take, which is to undervalue one another\'s sense, and wisdom, and management. The longer the saw of contention is drawn the hotter it grows; and the beginning of this sort of strife is as the letting forth of water; therefore leave it off before it be meddled with. Eliphaz had represented Job\'s discourses as idle, and unprofitable, and nothing to the purpose; and Job here gives his the same character. Those who are free in pa...', 'teologico');
add('jó', 16, 6, 'Matthew Henry', 'Job\'s complaint is here as bitter as any where in all his discourses, and he is at a stand whether to smother it or to give it vent. Sometimes the one and sometimes the other is a relief to the afflicted, according as the temper or the circumstances are; but Job found help by neither, Job 16:6. 1. Sometimes giving vent to grief gives ease; but, "Though I speak" (says Job), "my grief is not assuaged, my spirit is never the lighter for the pouring out of my complaint; nay, what I speak is so mi...', 'teologico');
add('jó', 16, 17, 'Matthew Henry', 'Job\'s condition was very deplorable; but had he nothing to support him, nothing to comfort him? Yes, and he here tells us what it was.\nI. He had the testimony of his conscience for him that he had walked uprightly, and had never allowed himself in any gross sin. None was ever more ready than he to acknowledge his sins of infirmity; but, upon search, he could not charge himself with any enormous crime, for which he should be made more miserable than other men, Job 16:17.\n1. He had kept a consc...', 'teologico');
add('jó', 17, 1, 'Matthew Henry', 'Job\'s discourse is here somewhat broken and interrupted, and he passes suddenly from one thing to another, as is usual with men in trouble; but we may reduce what is here said to three heads: - \nI. The deplorable condition which poor Job was now in, which he describes, to aggravate the great unkindness of his friends to him and to justify his own complaints. Let us see what his case was.\n1. He was a dying man, Job 17:1. He had said (Job 16:22), "When a few years have come, I shall go that lon...', 'teologico');
add('jó', 17, 10, 'Matthew Henry', 'Job\'s friends had pretended to comfort him with the hopes of his return to a prosperous estate again; now he here shows,\nI. That it was their folly to talk so (Job 17:10): "Return, and come now, be convinced that you are in an error, and let me persuade you to be of my mind; for I cannot find one wise man among you, that knows how to explain the difficulties of God\'s providence or how to apply the consolations of his promises." Those do not go wisely about the work of comforting the afflicted...', 'teologico');
add('jó', 18, 1, 'Matthew Henry', 'Bildad here shoots his arrows, even bitter words, against poor Job, little thinking that, though he was a wise and good man, in this instance he was serving Satan\'s design in adding to Job\'s affliction.\nI. He charges him with idle endless talk, as Eliphaz had done (Job 15:2, Job 15:3): How long will it be ere you make an end of words? Job 18:2. Here he reflects, not only upon Job himself, but either upon all the managers of the conference (thinking perhaps that Eliphaz and Zophar did not spea...', 'teologico');
add('jó', 18, 5, 'Matthew Henry', 'The rest of Bildad\'s discourse is entirely taken up in an elegant description of the miserable condition of a wicked man, in which there is a great deal of certain truth, and which will be of excellent use if duly considered - that a sinful condition is a sad condition, and that iniquity will be men\'s ruin if they do not repent of it. But it is not true that all wicked people are visibly and openly made thus miserable in this world; nor is it true that all who are brought into great distress ...', 'teologico');
add('jó', 18, 11, 'Matthew Henry', 'Bildad here describes the destruction itself which wicked people are reserved for in the other world, and which, in some degree, often seizes them in this world. Come, and see what a miserable condition the sinner is in when his day comes to fall.\nI. See him disheartened and weakened by continual terrors arising from the sense of his own guilt and the dread of God\'s wrath (Job 18:11, Job 18:12): Terror shall make him afraid on every side. The terrors of his own conscience shall haunt him, so ...', 'teologico');
add('jó', 19, 1, 'Matthew Henry', 'Job\'s friends had passed a very severe censure upon him as a wicked man because he was so grievously afflicted; now here he tells them how ill he took it to be so censured. Bildad had twice begun with a How long (Job 8:2, Job 18:2), and therefore Job, being now to answer him particularly, begins with a How long too, Job 19:2. What is not liked is commonly thought long; but Job had more reason to think those long who assaulted him than they had to think him long who only vindicated himself. Be...', 'teologico');
add('jó', 19, 8, 'Matthew Henry', 'Bildad had very disingenuously perverted Job\'s complaints by making them the description of the miserable condition of a wicked man; and yet he repeats them here, to move their pity, and to work upon their good nature, if they had any left in them.\nI. He complains of the tokens of God\'s displeasure which he was under, and which infused the wormwood and gall into the affliction and misery. How doleful are the accents of his complaints! "He hath kindled his wrath against me, which flames and te...', 'teologico');
add('jó', 19, 23, 'Matthew Henry', 'In all the conferences between Job and his friends we do not find any more weighty and considerable lines than these; would one have expected it? Here is much both of Christ and heaven in these verses: and he that said such things as these declared plainly that he sought the better country, that is, the heavenly; as the patriarchs of that age did, Heb 11:14. We have here Job\'s creed, or confession of faith. His belief in God the Father Almighty, the Maker of heaven and earth, and the principl...', 'teologico');
add('jó', 20, 1, 'Matthew Henry', 'Here, I. Zophar begins very passionately, and seems to be in a great heat at what Job had said. Being resolved to condemn Job for a bad man, he was much displeased that he talked so like a good man, and, as it should seem, broke in upon him, and began abruptly (Job 20:2): Therefore do my thoughts cause me to answer. He takes no notice of what Job had said to move their pity, or to evidence his own integrity, but fastens upon the reproof he gave them in the close of his discourse, counts that ...', 'teologico');
add('jó', 20, 10, 'Matthew Henry', 'The instances here given of the miserable condition of the wicked man in this world are expressed with great fulness and fluency of language, and the same thing returned to again and repeated in other words. Let us therefore reduce the particulars to their proper heads, and observe,\nI. What his wickedness is for which he is punished.\n1. The lusts of the flesh, here called the sins of his youth (Job 20:11); for those are the sins which, at that age, people are most tempted to. The forbidden pl...', 'teologico');
add('jó', 20, 23, 'Matthew Henry', 'Zophar, having described the many embarrassments and vexations which commonly attend the wicked practices of oppressors and cruel men, here comes to show their utter ruin at last.\nI. Their ruin will take its rise from God\'s wrath and vengeance, Job 20:23. The hand of the wicked was upon him (Job 20:22), every hand of the wicked. His hand was against every one, and therefore every man\'s hand will be against him. Yet, in grappling with these, he might go near to make his part good; but his hear...', 'teologico');
add('jó', 21, 1, 'Matthew Henry', 'Job here recommends himself, both his case and his discourse, both what he suffered and what he said, to the compassionate consideration of his friends. 1. That which he entreats of them is very fair, that they would suffer him to speak (Job 21:3) and not break in upon him, as Zophar had done, in the midst of his discourse. Losers, of all men, may have leave to speak; and, if those that are accused and censured are not allowed to speak for themselves, they are wronged without remedy, and have...', 'teologico');
add('jó', 21, 7, 'Matthew Henry', 'All Job\'s three friends, in their last discourses, had been very copious in describing the miserable condition of a wicked man in this world. "It is true," says Job, "remarkable judgments are sometimes brought upon notorious sinners, but not always; for we have many instances of the great and long prosperity of those that are openly and avowedly wicked; though they are hardened in their wickedness by their prosperity, yet they are still suffered to prosper."\nI. He here describes their prosper...', 'teologico');
add('jó', 21, 17, 'Matthew Henry', 'Job had largely described the prosperity of wicked people; now, in these verses,\nI. He opposes this to what his friends had maintained concerning their certain ruin in this life. "Tell me how often do you see the candle of the wicked put out? Do you not as often see it burnt down to the socket, until it goes out of itself? Job 21:17. How often do you see their destruction come upon them, or God distributing sorrows in his anger among them? Do you not as often see their mirth and prosperity co...', 'teologico');
add('jó', 21, 27, 'Matthew Henry', 'In these verses,\nI. Job opposes the opinion of his friends, which he saw they still adhered to, that the wicked are sure to fall into such visible and remarkable ruin as Job had now fallen into, and none but the wicked, upon which principle they condemned Job as a wicked man. "I know your thoughts," says Job (Job 21:27); "I know you will not agree with me; for your judgments are tinctured and biassed by your piques and prejudices against me, and the devices which you wrongfully imagine agains...', 'teologico');
add('jó', 22, 1, 'Matthew Henry', 'Eliphaz here insinuates that, because Job complained so much of his afflictions, he thought God was unjust in afflicting him; but it was a strained innuendo. Job was far from thinking so. What Eliphaz says here is therefore unjustly applied to Job, but in itself it is very true and good,\nI. That when God does us good it is not because he is indebted to us; if he were, there might be some colour to say, when he afflicts us, "He does not deal fairly with us." But whoever pretends that he has by...', 'teologico');
add('jó', 22, 5, 'Matthew Henry', 'Eliphaz and his companions had condemned Job, in general, as a wicked man and a hypocrite; but none of them had descended to particulars, nor drawn up any articles of impeachment against him, until Eliphaz did so here, where he positively and expressly charges him with many high crimes and misdemeanours, which, if he had really been guilty of them, might well have justified them in their harsh censures of him. "Come," says Eliphaz, "we have been too long beating about the bush, too tender of ...', 'teologico');
add('jó', 22, 15, 'Matthew Henry', 'Eliphaz, having endeavoured to convict Job, by setting his sins (as he thought) in order before him, here endeavours to awaken him to a sight and sense of his misery and danger by reason of sin; and this he does by comparing his case with that of the sinners of the old world; as if he had said, "Thy condition is bad now, but, unless thou repent, it will be worse, as theirs was - theirs who were overflown with a flood, as the old world (Job 22:16), and theirs the remnant of whom the fire consu...', 'teologico');
add('jó', 22, 21, 'Matthew Henry', 'Methinks I can almost forgive Eliphaz his hard censures of Job, which we had in the beginning of the chapter, though they were very unjust and unkind, for this good counsel and encouragement which he gives him in these verses with which he closes his discourse, and than which nothing could be better said, nor more to the purpose. Though he thought him a bad man, yet he saw reason to have hopes concerning him, that, for all this, he would be both pious and prosperous. But it is strange that ou...', 'teologico');
add('jó', 23, 1, 'Matthew Henry', 'Job is confident that he has wrong done him by his friends, and therefore, ill as he is, he will not give up the cause, nor let them have the last word. Here,\nI. He justifies his own resentments of his trouble (Job 23:2): Even to day, I own, my complaint is bitter; for the affliction, the cause of the complaint, is so. There are wormwood and gall in the affliction and misery; my soul has them still in remembrance and is embittered by them, Lam 3:19, Lam 3:20. Even to day is my complaint count...', 'teologico');
add('jó', 23, 8, 'Matthew Henry', 'Here, I. Job complains that he cannot understand the meaning of God\'s providences concerning him, but is quite at a loss about them (Job 23:8, Job 23:9): I go forward, but he is not there, etc. Eliphaz had bid him acquaint himself with God. "So I would, with all my heart," says Job, "If I knew how to get acquainted with him." He had himself a great desire to appear before God, and get a hearing of his case, but the Judge was not to be found. Look which way he would, he could see no sign of Go...', 'teologico');
add('jó', 23, 13, 'Matthew Henry', 'Some make Job to complain here that God dealt unjustly and unfairly with him in proceeding to punish him without the least relenting or relaxation, though he had such incontestable evidences to produce of his innocency. I am loth to think holy Job would charge the holy God with iniquity; but his complaint is indeed bitter and peevish, and he reasons himself into a sort of patience per force, which he cannot do without reflecting upon God as dealing hardly with him, but he must bear it because...', 'teologico');
add('jó', 24, 1, 'Matthew Henry', 'Job\'s friends had been very positive in it that they should soon see the fall of wicked people, how much soever they might prosper for a while. By no means, says Job; though times are not hidden from the Almighty, yet those that know him do not presently see his day, Job 24:1. 1. He takes it for granted that times are not hidden from the Almighty; past times are not hidden from his judgment (Ecc 3:15), present times are not hidden from his providence (Mat 10:29), future times are not hidden f...', 'teologico');
add('jó', 24, 13, 'Matthew Henry', 'These verses describe another sort of sinners who therefore go unpunished, because they go undiscovered. They rebel against the light, Job 24:13. Some understand it figuratively: they sin against the light of nature, the light of God\'s law, and that of their own consciences; they profess to know God, but they rebel against the knowledge they have of him, and will not be guided and governed, commanded and controlled, by it. Others understand it literally: they have the day-light and choose the...', 'teologico');
add('jó', 24, 18, 'Matthew Henry', 'Job here, in the conclusion of his discourse,\nI. Gives some further instances of the wickedness of these cruel bloody men. 1. Some are pirates and robbers at sea. To this many learned interpreters apply those difficult expressions (Job 24:18), He is swift upon the waters. Privateers choose those ships that are the best sailors. In these swift ships they cruise from one channel to another, to pick up prizes; and this brings them in so much wealth that their portion is cursed in the earth, and ...', 'teologico');
add('jó', 25, 1, 'Matthew Henry', 'Bildad is to be commended here for two things: - 1. For speaking no more on the subject about which Job and he differed. Perhaps he began to think Job was in the right, and then it was justice to say no more concerning it, as one that contended for truth, not for victory, and therefore, for the finding of truth, would be content to lose the victory; or, if he still thought himself in the right, yet he knew when he had said enough, and would not wrangle endlessly for the last word. Perhaps ind...', 'teologico');
add('jó', 26, 1, 'Matthew Henry', 'One would not have thought that Job, when he was in so much pain and misery, could banter his friend as he does here and make himself merry with the impertinency of his discourse. Bildad thought that he had made a fine speech, that the matter was so weighty, and the language so fine, that he had gained the reputation both of an oracle and of an orator; but Job peevishly enough shows that his performance was not so valuable as he thought it and ridicules him for it. He shows,\nI. That there was...', 'teologico');
add('jó', 26, 5, 'Matthew Henry', 'The truth received a great deal of light from the dispute between Job and his friends concerning those points about which they differed; but now they are upon a subject in which they were all agreed, the infinite glory and power of God. How does truth triumph, and how brightly does it shine, when there appears no other strife between the contenders than which shall speak most highly and honourably of God and be most copious in showing forth his praise! It were well if all disputes about matte...', 'teologico');
add('jó', 27, 1, 'Matthew Henry', 'Job\'s discourse here is called a parable (mashal), the title of Solomon\'s proverbs, because it was grave and weighty, and very instructive, and he spoke as one having authority. It comes from a word that signifies to rule, or have dominion; and some think it intimates that Job now triumphed over his opponents, and spoke as one that had baffled them. We say of an excellent preacher that he knows how dominari in concionibus - to command his hearers. Job did so here. A long strife there had been...', 'teologico');
add('jó', 27, 7, 'Matthew Henry', 'Job having solemnly protested the satisfaction he had in his integrity, for the further clearing of himself, here expresses the dread he had of being found a hypocrite.\nI. He tells us how he startled at the thought of it, for he looked upon the condition of a hypocrite and a wicked man to be certainly the most miserable condition that any man could be in (Job 27:7): Let my enemy be as the wicked, a proverbial expression, like that (Dan 4:19), The dream be to those that hate thee. Job was so f...', 'teologico');
add('jó', 27, 11, 'Matthew Henry', 'Job\'s friends had seen a great deal of the misery and destruction that attend wicked people, especially oppressors; and Job, while the heat of disputation lasted, had said as much, and with as much assurance, of their prosperity; but now that the heat of the battle was nearly over he was willing to own how far he agreed with them, and where the difference between his opinion and theirs lay. 1. He agreed with them that wicked people are miserable people, that God will surely reckon with cruel ...', 'teologico');
add('jó', 28, 1, 'Matthew Henry', 'Here Job shows, 1. What a great way the wit of man may go in diving into the depths of nature and seizing the riches of it, what a great deal of knowledge and wealth men may, by their ingenious and industrious searches, make themselves masters of. But does it therefore follow that men may, by their wit, comprehend the reasons why some wicked people prosper and others are punished, why some good people prosper and others are afflicted? No, by no means. The caverns of the earth may be discovere...', 'teologico');
add('jó', 28, 12, 'Matthew Henry', 'Job, having spoken of the wealth of the world, which men put such a value upon and take so much pains for, here comes to speak of another more valuable jewel, and that is, wisdom and understanding, the knowing and enjoying of God and ourselves. Those that found out all those ways and means to enrich themselves thought themselves very wise; but Job will not own theirs to be wisdom. He supposes them to gain their point, and to bring to light what they sought for (Job 28:11), and yet asks, "Wher...', 'teologico');
add('jó', 28, 20, 'Matthew Henry', 'The question which Job had asked (Job 28:12) he asks again here; for it is too worthy, too weighty, to be let fall, until we speed in the enquiry. Concerning this we must seek till we find, till we get some satisfactory account of it. By a diligent prosecution of this enquiry he brings it, at length, to this issue, that there is a twofold wisdom, one hidden in God, which is secret and belongs not to us, the other made known by him and revealed to man, which belongs to us and to our children.\n...', 'teologico');
add('jó', 29, 1, 'Matthew Henry', 'Losers may have leave to speak, and there is nothing they speak of more feelingly than of the comforts they are stripped of. Their former prosperity is one of the most pleasing subjects of their thoughts and talk. It was so to Job, who begins here with a wish (Job 29:2): O that I were as in months past! so he brings in this account of his prosperity. His wish is, 1. "O that I were in as good a state as I was in then, that I had as much wealth, honour, and pleasure, as I had then!" This he wis...', 'teologico');
add('jó', 29, 7, 'Matthew Henry', 'We have here Job in a post of honour and power. Though he had comfort enough in his own house, yet he did not confine himself to that. We are not born for ourselves, but for the public. When any business was to be done in the gate, the place of judgment, Job went out to it through the city (Job 29:7), not in an affectation of pomp, but in an affection to justice. Observe, Judgment was administered in the gate, in the street, in the places of concourse, to which every man might have a free acc...', 'teologico');
add('jó', 29, 18, 'Matthew Henry', 'That which crowned Job\'s prosperity was the pleasing prospect he had of the continuance of it. Though he knew, in general, that he was liable to trouble, and therefore was not secure (Job 3:26, I was not in safety, neither had I rest), yet he had no particular occasion for fear, but as much reason as ever any man had to count upon the lengthening out of his tranquility.\nI. See here what his thoughts were in his prosperity (Job 29:18): Then I said, I shall die in my nest. Having made himself a...', 'teologico');
add('jó', 30, 1, 'Matthew Henry', 'Here Job makes a very large and sad complaint of the great disgrace he had fallen into, from the height of honour and reputation, which was exceedingly grievous and cutting to such an ingenuous spirit as Job\'s was. Two things he insists upon as greatly aggravating his affliction: - \nI. The meanness of the persons that affronted him. As it added much to his honour, in the day of his prosperity, that princes and nobles showed him respect and paid a deference to him, so it added no less to his d...', 'teologico');
add('jó', 30, 15, 'Matthew Henry', 'In this second part of Job\'s complaint, which is very bitter, and has a great many sorrowful accents in it, we may observe a great deal that he complains of and some little that he comforts himself with.\nI. Here is much that he complains of.\n1. In general, it was a day of great affliction and sorrow. (1.) Affliction seized him, and surprised him. It seized him (Job 30:16): The days of affliction have taken hold upon me, have caught me (so some); they have arrested me, as the bailiff arrests t...', 'teologico');
add('jó', 31, 1, 'Matthew Henry', 'The lusts of the flesh, and the love of the world, are the two fatal rocks on which multitudes split; against these Job protests he was always careful to stand upon his guard.\nI. Against the lusts of the flesh. He not only kept himself clear from adultery, from defiling his neighbour\'s wives (Job 31:9), but from all lewdness with any women whatsoever. He kept no concubine, no mistress, but was inviolably faithful to the marriage bed, though his wife was none of the wisest, best, or kindest. F...', 'teologico');
add('jó', 31, 9, 'Matthew Henry', 'Two more instances we have here of Job\'s integrity: - \nI. That he had a very great abhorrence of the sin of adultery. As he did not wrong his own marriage bed by keeping a concubine (he did not so much as think upon a maid, v. 1), so he was careful not to offer any injury to his neighbour\'s marriage bed. Let us see here, 1. How clear he was from this sin, Job 31:9. (1.) He did not so much as covet his neighbour\'s wife; for even his heart was not deceived by a woman. The beauty of another man\'...', 'teologico');
add('jó', 31, 16, 'Matthew Henry', 'Eliphaz had particularly charged Job with unmercifulness to the poor (Job 22:6, etc.): Thou hast withholden bread from the hungry, stripped the naked of their clothing, and sent widows away empty. One would think he could not have been so very positive and express in his charge unless there had been some truth in it, some ground, for it; and yet it appears, by Job\'s protestation, that it was utterly false and groundless; he was never guilty of any such thing. See here,\nI. The testimony which ...', 'teologico');
add('jó', 31, 24, 'Matthew Henry', 'Four articles more of Job\'s protestation we have in these verses, which, as all the rest, not only assure us what he was and did, but teach us what we should be and do: - \nI. He protests that he never set his heart upon the wealth of this world, nor took the things of it for his portions and happiness. He had gold; he had fine gold. His wealth was great, and he had gotten much. Our wealth is either advantageous or pernicious to us according as we stand affected to it. If we make it our rest a...', 'teologico');
add('jó', 31, 33, 'Matthew Henry', 'We have here Job\'s protestation against three more sins, together with his general appeal to God\'s bar and his petition for a hearing there, which, it is likely, was intended to conclude his discourse (and therefore we will consider it last), but that another particular sin occurred, from which he thought it requisite to acquit himself. He clears himself from the charge,\nI. Of dissimulation and hypocrisy. The general crime of which his friends accused him was that, under the cloak of a profes...', 'teologico');
add('jó', 32, 1, 'Matthew Henry', 'Usually young men are the disputants and old men the moderators; but here, when old men were the disputants, as a rebuke to them for their unbecoming heat, a young man is raised up to be the moderator. Divers of Job\'s friends were present, that came to visit him and to receive instruction. Now here we have,\nI. The reason why his three friends were now silent. They ceased to answer him, and let him have his saying, because he was righteous in his own eyes. This was the reason they gave why the...', 'teologico');
add('jó', 32, 6, 'Matthew Henry', 'Elihu here appears to have been,\nI. A man of great modesty and humility. Though a young man, and a man of abilities, yet not pert, and confident, and assuming: his face shone, and, like Moses, he did not know it, which made it shine so much the brighter. Let it be observed by all, especially by young people, as worthy their imitation, 1. What a diffidence he had of himself and of his own judgment (Job 32:6): "I am young, and therefore I was afraid, and durst not show you my opinion, for fear ...', 'teologico');
add('jó', 32, 15, 'Matthew Henry', 'Three things here apologize for Elihu\'s interposing as he does in this controversy which had already been canvassed by such acute and learned disputants: - \n1. That the stage was clear, and he did not break in upon any of the managers on either side: They were amazed (Job 32:15); they stood still, and answered no more, Job 32:16. They not only left off speaking themselves, but they stood still, to hear if any of the company would speak their minds, so that (as we say) he had room and fair pla...', 'teologico');
add('jó', 33, 1, 'Matthew Henry', 'Several arguments Elihu here uses to persuade Job not only to give him a patient hearing, but to believe that he designed him a good office, and to take it kindly, and be willing to receive the instructions he was now about to give him. Let Job consider, 1. That Elihu does not join with his three friends against him. He has, in the foregoing chapter, declared his dislike of their proceedings, disclaimed their hypothesis, and quite set aside the method they took of healing Job. "Wherefore, Job...', 'teologico');
add('jó', 33, 8, 'Matthew Henry', 'In these verses,\nI. Elihu particularly charges Job with some indecent expressions that had dropped from him, reflecting upon the justice and goodness of God in his dealings with him. He does not ground the charge upon report, but was himself an ear-witness of what he here reproves him for (Job 33:8): "Thou hast spoken it in my hearing, and in the hearing of all this company." He had it not at second hand; if so, he would have hoped it was not so bad as it was represented. He did not hear it f...', 'teologico');
add('jó', 33, 14, 'Matthew Henry', 'Job had complained that God kept him wholly in the dark concerning the meaning of his dealings with him, and therefore concluded he dealt with him as his enemy. "No," says Elihu, "he speaks to you, but you do not perceive him; so that the fault is yours, not his; and he is designing your real good even in those dispensations which you put this harsh construction upon." Observe in general, 1. What a friend God is to our welfare: He speaketh to us once, yea, twice, Job 33:14. It is a token of h...', 'teologico');
add('jó', 33, 19, 'Matthew Henry', 'God has spoken once to sinners by their own consciences, to keep them from the paths of the destroyer, but they perceive it not; they are not aware that the checks their own hearts give them in a sinful way are from God, but they are imputed to melancholy or the preciseness of their education; and therefore God speaks twice; he speaks a second time, and tries another way to convince and reclaim sinners, and that is by providences, afflictive and merciful (in which he speaks twice), and by the...', 'teologico');
add('jó', 33, 29, 'Matthew Henry', 'We have here the conclusion of this first part of Elihu\'s discourse, in which, 1. He briefly sums up what he had said, showing that God\'s great and gracious design, in all the dispensations of his providence towards the children of men, is to save them from being for ever miserable and bring them to be for ever happy, Job 33:29, Job 33:30. All these things God is working with the children of men. He deals with them by conscience, by providences, by ministers, by mercies, by afflictions. He ma...', 'teologico');
add('jó', 34, 1, 'Matthew Henry', 'Here, I. Elihu humbly addresses himself to the auditors, and endeavours, like an orator, to gain their good-will and their favourable attention. 1. He calls them wise men, and men that had knowledge, Job 34:2. It is comfortable dealing with such as understand sense. I speak as to wise men, who can judge what I say, Co1 10:15. Elihu differed in opinion from them, and yet he calls them wise and knowing men. Peevish disputants think all fools that are not of their mind; but it is a piece of just...', 'teologico');
add('jó', 34, 10, 'Matthew Henry', 'The scope of Elihu\'s discourse to reconcile Job to his afflictions and to pacify his spirit under them. In order to this he had shown, in the foregoing chapter, that God meant him no hurt in afflicting him, but intended it for his spiritual benefit. In this chapter he shows that he did him no wrong in afflicting him, nor punished him more than he deserved. If the former could not prevail to satisfy him, yet this ought to silence him. In these verses he directs his discourse to all the company...', 'teologico');
add('jó', 34, 16, 'Matthew Henry', 'Elihu here addresses himself more directly to Job. He had spoken to the rest (Job 34:10) as men of understanding; now, speaking to Job; he puts an if upon his understanding: If thou hast understanding, hear this and observe it, Job 34:16.\nI. Hear this, That God is not to be quarrelled with for any thing that he does. It is daring presumption to arraign and condemn God\'s proceedings, as Job had done by his discontents. It was, 1. As absurd as it would be to advance one to power that is a profe...', 'teologico');
add('jó', 34, 31, 'Matthew Henry', 'In these verses,\nI. Elihu instructs Job what he should say under his affliction, Job 34:31, Job 34:32. Having reproved him for his peevish passionate words, he here puts better words into his mouth. When we reprove for what is amiss we must direct to what is good, that our reproofs may be the reproofs of instruction, Pro 6:23. He does not impose it upon Job to use these words, but recommends it to him, as that which was meet to be said. In general, he would have him repent of his misconduct, ...', 'teologico');
add('jó', 35, 1, 'Matthew Henry', 'We have here,\nI. The bad words which Elihu charges upon Job, Job 35:2, Job 35:3. To evince the badness of them he appeals to Job himself, and his own sober thoughts, in the reflection: Thinkest thou this to be right? This intimates Elihu\'s confidence that the reproof he now gave was just, for he could refer the judgment of it even to Job himself. Those that have truth and equity on their side sooner or later will have every man\'s conscience on their side. It also intimates his good opinion of...', 'teologico');
add('jó', 35, 9, 'Matthew Henry', 'Elihu here returns an answer to another word that Job had said, which, he thought, reflected much upon the justice and goodness of God, and therefore ought not to pass without a remark. Observe,\nI. What it was that Job complained of; it was this, That God did not regard the cries of the oppressed against their oppressors (Job 35:9): "By reason of the multitude of oppressions, the many hardships which proud tyrants put upon poor people and the barbarous usage they give them, they make the oppr...', 'teologico');
add('jó', 35, 14, 'Matthew Henry', 'Here is, I. Another improper word for which Elihu reproves Job (Job 35:14): Thou sayest thou shalt not see him; that is, 1. "Thou complainest that thou dost not understand the meaning of his severe dealings with thee, nor discern the drift and design of them," Job 23:8, Job 23:9. And, 2. "Thou despairest of seeing his gracious returns to thee, of seeing better days again, and art ready to give up all for gone;" as Hezekiah (Isa 38:11), I shall not see the Lord. As, when we are in prosperity, ...', 'teologico');
add('jó', 36, 1, 'Matthew Henry', 'Once more Elihu begs the patience of the auditory, and Job\'s particularly, for he has not said all that he has to say, but he will not detain them long. Stand about me a little (so some read it), Job 36:2. "Let me have your attendance, your attention, awhile longer, and I will speak but this once, as plainly and as much to the purpose as I can." To gain this he pleads, 1. That he had a good cause, and a noble and very fruitful subject: I have yet to speak on God\'s behalf. He spoke as an advoc...', 'teologico');
add('jó', 36, 5, 'Matthew Henry', 'Elihu, being to speak on God\'s behalf, and particularly to ascribe righteousness to his Maker, here shows that the disposals of divine Providence are all, not only according to the eternal counsels of his will, but according to the eternal rules of equity. God acts as a righteous governor, for,\nI. He does not think it below him to take notice of the meanest of his subjects, nor does poverty or obscurity set any at a distance from his favour. If men are mighty, they are apt to look with a haug...', 'teologico');
add('jó', 36, 15, 'Matthew Henry', 'Elihu here comes more closely to Job; and,\nI. He tells him what God would have done for him before this if he had been duly humbled under his affliction. "We all know how ready God is to deliver the poor in his affliction (Job 36:15); he always was so. The poor in spirit, those that are of a broken and contrite heart, he looks upon with tenderness, and, when they are in affliction, is ready to help them. He opens their ears, and makes them to hear joy and gladness, even in their oppressions; ...', 'teologico');
add('jó', 36, 24, 'Matthew Henry', 'Elihu is here endeavouring to possess Job with great and high thoughts of God, and so to persuade him into a cheerful submission to his providence.\nI. He represents the work of God, in general, as illustrious and conspicuous, Job 36:24. His whole work is so. God does nothing mean. This is a good reason why we should acquiesce in all the operations of his providence concerning us in particular. His visible works, those of nature, and which concern the world in general, are such as we admire an...', 'teologico');
add('jó', 37, 1, 'Matthew Henry', 'Thunder and lightning, which usually go together, are sensible indications of the glory and majesty, the power and terror, of Almighty God, one to the ear and the other to the eye; in these God leaves not himself without witness of his greatness, as, in the rain from heaven and fruitful seasons, he leaves not himself without witness of his goodness (Act 14:17), even to the most stupid and unthinking. Though there are natural causes and useful effects of them, which the philosophers undertake ...', 'teologico');
add('jó', 37, 6, 'Matthew Henry', 'The changes and extremities of the weather, wet or dry, hot or cold, are the subject of a great deal of our common talk and observation; but how seldom do we think and speak of these things, as Elihu does here, with an awful regard to God the director of them, who shows his power and serves the purposes of his providence by them! We must take notice of the glory of God, not only in the thunder and lightning, but in the more common revolutions of the weather, which are not so terrible and whic...', 'teologico');
add('jó', 37, 14, 'Matthew Henry', 'Elihu here addresses himself closely to Job, desiring him to apply what he had hitherto said to himself. He begs that he would hearken to this discourse (Job 37:14), that he would pause awhile: Stand still, and consider the wondrous works of God. What we hear is not likely to profit us unless we consider it, and we are not likely to consider things fully unless we stand still and compose ourselves to the consideration of them. The works of God, being wondrous, both deserve and need our consid...', 'teologico');
add('jó', 37, 21, 'Matthew Henry', 'Elihu here concludes his discourse with some short but great sayings concerning the glory of God, as that which he was himself impressed, and desired to impress others, with a holy awe of. He speaks concisely, and in haste, because, it should seem, he perceived that God was about to take the work into his own hands. 1. He observes that God who has said that he will dwell in the thick darkness and make that his pavilion (Ch2 6:1, Psa 18:11) is in that awful chariot advancing towards them, as i...', 'teologico');
add('jó', 38, 1, 'Matthew Henry', 'Let us observe here, 1. Who speaks - The Lord, Jehovah, not a created angel, but the eternal Word himself, the second person in the blessed Trinity, for it is he by whom the worlds were made, and that was no other than the Son of God. The same speaks here that afterwards spoke from Mount Sinai. Here he begins with the creation of the world, there with the redemption of Israel out of Egypt, and from both is inferred the necessity of our subjection to him. Elihu had said, God speaks to men and ...', 'teologico');
add('jó', 38, 12, 'Matthew Henry', 'The Lord here proceeds to ask Job many puzzling questions, to convince him of his ignorance, and so to shame him for his folly in prescribing to God. If we will but try ourselves with such interrogatories as these, we shall soon be brought to own that what we know is nothing in comparison with what we know not. Job is here challenged to give an account of six things: - \nI. Of the springs of the morning, the day-spring from on high, Job 38:12-15. As there is no visible being of which we may be...', 'teologico');
add('jó', 38, 25, 'Matthew Henry', 'Hitherto God had put such questions to Job as were proper to convince him of his ignorance and short-sightedness. Now he comes, in the same manner, to show his impotency and weakness. As it is but little that he knows, and therefore he ought not to arraign the divine counsels, so it is but little that he can do, and therefore he ought not to oppose the proceedings of Providence. Let him consider what great things God does, and try whether he can do the like, or whether he thinks himself an eq...', 'teologico');
add('jó', 39, 1, 'Matthew Henry', 'God here shows Job what little acquaintance he had with the untamed creatures that run wild in the deserts and live at large, but are the care of the divine Providence. As,\nI. The wild goats and the hinds. That which is taken notice of concerning them is the bringing forth and bringing up of their young ones. For, as every individual is fed, so every species of animals is preserved, by the care of the divine Providence, and, for aught we know, none extinct to this day. Observe here, 1. Concer...', 'teologico');
add('jó', 39, 13, 'Matthew Henry', 'The ostrich is a wonderful animal, a very large bird, but it never flies. Some have called it a winged camel. God here gives an account of it, and observes,\nI. Something that it has in common with the peacock, that is, beautiful feathers (Job 39:13): Gavest thou proud wings unto the peacocks? so some read it. Fine feathers make proud birds. The peacock is an emblem of pride; when he struts, and shows his fine feathers, Solomon in all his glory is not arrayed like him. The ostrich too has good...', 'teologico');
add('jó', 39, 19, 'Matthew Henry', 'God, having displayed his own power in those creatures that are strong and despise man, here shows it in one scarcely inferior to any of them in strength, and yet very tame and serviceable to man, and that is the horse, especially the horse that is prepared against the day of battle and is serviceable to man at a time when he has more than ordinary occasion for his service. It seems, there was, in Job\'s country, a noble generous breed of horses. Job, it is probable, kept many, though they are...', 'teologico');
add('jó', 39, 26, 'Matthew Henry', 'The birds of the air are proofs of the wonderful power and providences of God, as well as the beasts of the earth; God here refers particularly to two stately ones: - 1. The hawk, a noble bird of great strength and sagacity, and yet a bird of prey, Job 39:26. This bird is here taken notice of for her flight, which is swift and strong, and especially for the course she steers towards the south, whither she follows the sun in winter, out of the colder countries in the north, especially when she...', 'teologico');
add('jó', 40, 1, 'Matthew Henry', 'Here is, I. A humbling challenge which God gave to Job. After he had heaped up many hard questions upon him, to show him, by his manifest ignorance in the works of nature, what an incompetent judge he was of the methods and designs of Providence, he clenches the nail with one demand more, which stands by itself here as the application of the whole. It should seem, God paused awhile, as Elihu had done, to give Job time to say what he had to say, or to think of what God had said; but Job was in...', 'teologico');
add('jó', 40, 6, 'Matthew Henry', 'Job was greatly humbled for what God had already said, but not sufficiently; he was brought low, but not low enough; and therefore God here proceeds to reason with him in the same manner and to the same purport as before, Job 40:6. Observe, 1. Those who duly receive what they have heard from God, and profit by it, shall hear more from him. 2. Those who are truly convinced of sin, and penitent for it, yet have need to be more thoroughly convinced and to be made more deeply penitent. Those who ...', 'teologico');
add('jó', 40, 15, 'Matthew Henry', 'God, for the further proving of his own power and disproving of Job\'s pretensions, concludes his discourse with the description of two vast and mighty animals, far exceeding man in bulk and strength, one he calls behemoth, the other leviathan. In these verses we have the former described. "Behold now behemoth, and consider whether thou art able to contend with him who made that beast and gave him all the power he has, and whether it is not thy wisdom rather to submit to him and make thy peace...', 'teologico');
add('jó', 41, 1, 'Matthew Henry', 'Whether this leviathan be a whale or a crocodile is a great dispute among the learned, which I will not undertake to determine; some of the particulars agree more easily to the one, others to the other; both are very strong and fierce, and the power of the Creator appears in them. The ingenious Sir Richard Blackmore, though he admits the more received opinion concerning the behemoth, that it must be meant of the elephant, yet agrees with the learned Bochart\'s notion of the leviathan, that it ...', 'teologico');
add('jó', 41, 11, 'Matthew Henry', 'God, having in the foregoing verses shown Job how unable he was to deal with the leviathan, here sets forth his own power in that massy mighty creature. Here is,\nI. God\'s sovereign dominion and independency laid down, Job 41:11. 1. That he is indebted to none of his creatures. If any pretend he is indebted to them, let them make their demand and prove their debt, and they shall receive it in full and not by composition: "Who has prevented me?" that is, "who has laid any obligations upon me by...', 'teologico');
add('jó', 42, 1, 'Matthew Henry', 'The words of Job justifying himself were ended, Job 31:40. After that he said no more to that purport. The words of Job judging and condemning himself began, Job 40:4, Job 40:5. Here he goes on with words to the same purport. Though his patience had not its perfect work, his repentance for his impatience had. He is here thoroughly humbled for his folly and unadvised speaking, and it was forgiven him. Good men will see and own their faults at last, though it may be some difficulty to bring the...', 'teologico');
add('jó', 42, 7, 'Matthew Henry', 'Job, in his discourses, had complained very much of the censures of his friends and their hard usage of him, and had appealed to God as Judge between him and them, and thought it hard that judgment was not immediately given upon the appeal. While God was catechising Job out of the whirlwind one would have thought that he only was in the wrong, and that the cause would certainly go against him; but here, to our great surprise, we find it quite otherwise, and the definitive sentence given in Jo...', 'teologico');
add('jó', 42, 10, 'Matthew Henry', 'You have heard of the patience of Job (says the apostle, Jam 5:11) and have seen the end of the Lord, that is, what end the Lord, at length, put to his troubles. In the beginning of this book we had Job\'s patience under his troubles, for an example; here, in the close, for our encouragement to follow that example, we have the happy issue of his troubles and the prosperous condition to which he was restored after them, which confirms us in counting those happy which endure. Perhaps, too, the e...', 'teologico');

// SL (473 comentários)
add('sl', 1, 1, 'Spurgeon', 'Bem-aventurado o homem — A bem-aventurança começa com a negativa: não andar, não estar, não assentar com os ímpios.', 'aplicacao');
add('sl', 1, 2, 'João Crisóstomo', 'Na sua lei medita — A meditação na Escritura produz transformação interior e frutificação espiritual.', 'aplicacao');
add('sl', 1, 3, 'Matthew Henry', 'Como árvore plantada — A imagem da árvore: frutífera, firme, sustentada pela água da Palavra.', 'cultural');
add('sl', 1, 6, 'R.C. Sproul', 'O Senhor guarda o caminho dos justos — A proteção divina é sobre o caminho dos que seguem a Deus.', 'teologico');
add('sl', 2, 7, 'Calvino', 'Tu és o meu Filho — Salmo messiânico: a relação Pai-Filho é eterna, não temporal.', 'teologico');
add('sl', 2, 12, 'Spurgeon', 'Beijai o Filho — A adoração ao Messias é necessária: a ira se aproxima dos que O rejeitam.', 'escatologico');
add('sl', 2, 1, 'Tomás de Aquino', 'Por que se tumultuam os povos — A revolta contra Deus é fútil: o ungido do Senhor prevalecerá.', 'teologico');
add('sl', 8, 1, 'João Crisóstomo', 'Ó SENHOR, nosso Senhor — A grandeza de Deus se manifesta na criação, especialmente na obra do homem.', 'teologico');
add('sl', 8, 5, 'Calvino', 'Coroaste-o de honra e de glória — A dignidade humana: feito um pouco menor que os anjos, mas coroado de glória.', 'teologico');
add('sl', 8, 6, 'Matthew Henry', 'Puseste tudo debaixo dos seus pés — O domínio humano sobre a criação é mandato divino.', 'cultural');
add('sl', 16, 10, 'Lutero', 'Não deixarás a minha alma — Profecia messiânica sobre a ressurreição: Deus não permite que o Seu Santo veja a corrupção.', 'escatologico');
add('sl', 16, 11, 'John Piper', 'Caminho da vida — A plenitude da alegria e os prazeres eternos à destra de Deus são o destino final do crente.', 'teologico');
add('sl', 19, 1, 'Calvino', 'Os céus proclamam a glória de Deus — A revelação geral da criação testemunha do Criador a todo o homem.', 'teologico');
add('sl', 19, 7, 'Lutero', 'A lei do Senhor é perfeita — A Escritura é suficiente para converter a alma, dar testemunho, trazer alegria e iluminar os olhos.', 'teologico');
add('sl', 19, 14, 'Albert Barnes', 'Meditação do meu coração — O homem interior deve ser puro: Deus vê o coração, não apenas as aparências.', 'aplicacao');
add('sl', 22, 1, 'N.T. Wright', 'Por que me desamparaste? — O grito de Jó e de Jesus: a angústia do justo abandonado, mas resgatado por Deus.', 'teologico');
add('sl', 22, 16, 'Barth', 'Cercaram-me como cão — A profecia do sofrimento: os inimigos cercam o Justo, prefigurando a paixão de Cristo.', 'escatologico');
add('sl', 22, 28, 'Spurgeon', 'O reino é do Senhor — Apesar do sofrimento, Deus reina. A ressurreição coroa a humilhação.', 'teologico');
add('sl', 22, 18, 'Albert Barnes', 'Repartiram as minhas vestes — Profecia precisa da crucificação: os soldados sortearam as vestes de Jesus.', 'historico');
add('sl', 22, 31, 'Adam Clarke', 'Ele fez — A proclamação da justiça de Deus: a obra redentora é consumada e anunciada.', 'escatologico');
add('sl', 23, 1, 'Matthew Henry', 'O Senhor é o meu pastor — A imagem do pastoreio: provisão, direção e proteção do Deus que cuida.', 'teologico');
add('sl', 23, 2, 'João Crisóstomo', 'Leva-me a pastagens verdes — O Senhor nos guia para descanso e nutrição espiritual.', 'aplicacao');
add('sl', 23, 4, 'Lutero', 'Ainda que ande pelo vale da sombra da morte — A presença do Pastor remove o temor mesmo diante da morte.', 'aplicacao');
add('sl', 23, 6, 'John Stott', 'Bondade e misericórdia me seguirão — A bondade e a misericórdia nos acompanham a vida toda. A morada eterna é a promessa final.', 'teologico');
add('sl', 34, 8, 'Lloyd-Jones', 'Provai e vede — A fé não é teoria, mas experiência viva do poder transformador de Deus.', 'aplicacao');
add('sl', 46, 10, 'John Piper', 'Sabei que eu sou Deus — A soberania de Deus é o fundamento da paz em meio ao caos.', 'teologico');
add('sl', 51, 1, 'John Stott', 'Tem compaixão de mim — O arrependimento verdadeiro começa com o reconhecimento da graça, não com o mérito próprio.', 'teologico');
add('sl', 51, 5, 'Lutero', 'Em pecado me concebeu minha mãe — A doutrina do pecado original: a corrupção está presente desde a concepção.', 'teologico');
add('sl', 51, 10, 'Agostinho', 'Cria em mim, ó Deus, um coração puro — O salmo penitencial de Davi após o pecado com Bate-Seba.', 'teologico');
add('sl', 51, 17, 'Tomás de Aquino', 'O sacrifício que Deus deseja — O coração contrito e humilhado é o sacrifício que Deus não despreza.', 'teologico');
add('sl', 51, 12, 'R.C. Sproul', 'Restitui-me o gozo da tua salvação — A alegria da salvação pode ser perdida pelo pecado, mas restaurada pela graça.', 'aplicacao');
add('sl', 86, 11, 'John Stott', 'Ensina-me o teu caminho — A sabedoria começa com a humildade de pedir orientação divina.', 'aplicacao');
add('sl', 90, 1, 'Tomás de Aquino', 'Senhor, tu tens sido o nosso refúgio — A eternidade de Deus é o refúgio da fragilidade humana.', 'teologico');
add('sl', 90, 2, 'Agostinho', 'Antes de nascerem os montes — Deus é anterior a toda criação: eterno, imutável, sempre presente.', 'teologico');
add('sl', 103, 8, 'João Crisóstomo', 'O Senhor é misericordioso — A misericórdia de Deus é paciente e abundante, superando toda iniquidade.', 'teologico');
add('sl', 103, 12, 'Spurgeon', 'Quanto o oriente está do ocidente — A distância do pecado perdoado: Deus remove o pecado completamente.', 'teologico');
add('sl', 103, 14, 'Albert Barnes', 'Lembra-se de que somos pó — A fraqueza humana é lembrada por Deus com compaixão, não com desdém.', 'teologico');
add('sl', 110, 1, 'Calvino', 'Assenta-te à minha direita — O Salmo messiânico citado por Cristo e pelos apóstolos sobre Sua exaltação.', 'escatologico');
add('sl', 110, 4, 'Barth', 'Tu és sacerdote para sempre — A linhagem de Melquisedeque prefigura o sacerdócio eterno de Cristo.', 'escatologico');
add('sl', 119, 105, 'João Crisóstomo', 'Lâmpada para os meus pés — A Palavra de Deus ilumina o caminho do crente em meio às trevas.', 'aplicacao');
add('sl', 139, 1, 'Calvino', 'Senhor, tu me examinas e me conheces — A onisciência de Deus: Ele conhece cada pensamento e ação.', 'teologico');
add('sl', 139, 14, 'John Piper', 'Louvo-te, porque de um modo assombroso — A preciosidade da vida humana: cada pessoa é obra-prima do Criador.', 'teologico');
add('sl', 139, 23, 'Wesley', 'Examina-me, ó Deus, e reconhece o meu coração — A oração de autodiagnóstico espiritual.', 'aplicacao');
add('sl', 1, 4, 'Matthew Henry', 'Here is, I. The description of the ungodly given, Psa 1:4. 1. In general, they are the reverse of the righteous, both in character and condition: They are not so. The Septuagint emphatically repeats this: Not so the ungodly; they are not so; they are led by the counsel of the wicked, in the way of sinners, to the seat of the scornful; they have no delight in the law of God, nor ever think of it; they bring forth no fruit but grapes of Sodom; they cumber the ground. 2. In particular, whereas t...', 'teologico');
add('sl', 2, 10, 'Matthew Henry', 'We have here the practical application of this gospel doctrine concerning the kingdom of the Messiah, by way of exhortation to the kings and judges of the earth. They hear that it is in vain to oppose Christ\'s government; let them therefore be so wise for themselves as to submit to it. He that has power to destroy them shows that he has no pleasure in their destruction, for he puts them into a way to make themselves happy, Psa 2:10. Those that would be wise must be instructed; and those are t...', 'teologico');
add('sl', 3, 1, 'Matthew Henry', 'The title of this psalm and many others is as a key hung ready at the door, to open it, and let us into the entertainments of it; when we know upon what occasion a psalm was penned we know the better how to expound it. This was composed, or at least the substance of it was meditated and digested in David\'s thought, and offered up to God, when he fled from Absalom his son, who formed a conspiracy against him, to take away, not his crown only, but his life; we have the story, 2 Sa. 15, etc. 1. ...', 'teologico');
add('sl', 3, 4, 'Matthew Henry', 'David, having stirred up himself by the irritations of his enemies to take hold on God as his God, and so gained comfort in looking upward when, if he looked round about him, nothing appeared but what was discouraging, here looks back with pleasing reflections upon the benefit he had derived from trusting in God and looks forward with pleasing expectations of a very bright and happy issue to which the dark dispensation he was now under would shortly be brought.\nI. See with what comfort he loo...', 'teologico');
add('sl', 4, 1, 'Matthew Henry', 'The title of the psalm acquaints us that David, having penned it by divine inspiration for the use of the church, delivered it to the chief musician, or master of the song, who (according to the divine appointment of psalmody made in his time, which he was chiefly instrumental in the establishment of) presided in that service. We have a particular account of the constitution, the modelling of the several classes of singers, each with a chief, and the share each bore in the work, 1 Chr. 25. So...', 'teologico');
add('sl', 4, 6, 'Matthew Henry', 'We have here,\nI. The foolish wish of worldly people: There be many that say, Who will show us any good? Who will make us to see good? What good they meant is intimated, Psa 4:7. It was the increase of their corn and wine; all they desired was plenty of the wealth of this world, that they might enjoy abundance of the delights of sense. Thus far they are right, that they are desirous of good and solicitous about it; but there are these things amiss in this wish: - 1. They enquire, in general, "...', 'teologico');
add('sl', 5, 1, 'Matthew Henry', 'The title of this psalm has nothing in it peculiar but that it is said to be upon Nehiloth, a word nowhere else used. It is conjectured (and it is but a conjecture) that is signifies wind - instruments, with which this psalm was sung, as Neginoth was supposed to signify the stringed - instruments. In these verses David had an eye to God,\nI. As a prayer-hearing God; such he has always been ever since men began to call upon the name of the Lord, and yet is still as ready to hear prayer as ever....', 'teologico');
add('sl', 5, 7, 'Matthew Henry', 'In these verses David gives three characters - of himself, of his enemies, and of all the people of God, and subjoins a prayer to each of them.\nI. He gives an account of himself and prays for himself, Psa 5:7, Psa 5:8.\n1. He is stedfastly resolved to keep closely to God and to his worship. Sinners go away from God, and so make themselves odious to his holiness and obnoxious to his justice: "But, as for me, that shall not keep me from thee." God\'s holiness and justice are so far from being a t...', 'teologico');
add('sl', 6, 1, 'Matthew Henry', 'These verses speak the language of a heart truly humbled under humbling providences, of a broken and contrite spirit under great afflictions, sent on purpose to awaken conscience and mortify corruption. Those heap up wrath who cry not when God binds them; but those are getting ready for mercy who, under God\'s rebukes, sow in tears, as David does here. Let us observe here,\nI. The representation he makes to God of his grievances. He pours out his complaint before him. Whither else should a chil...', 'teologico');
add('sl', 6, 8, 'Matthew Henry', 'What a sudden change is here for the better! He that was groaning, and weeping, and giving up all for gone (Psa 6:6, Psa 6:7), here looks and speaks very pleasantly. Having made his requests known to God, and lodged his case with him, he is very confident the issue will be good and his sorrow is turned into joy.\nI. He distinguishes himself from the wicked and ungodly, and fortifies himself against their insults (Psa 6:8): Depart from me, all you workers of iniquity. When he was in the depth o...', 'teologico');
add('sl', 7, 1, 'Matthew Henry', 'Shiggaion is a song or psalm (the word is used so only here and Hab 3:1) - a wandering song (so some), the matter and composition of the several parts being different, but artificially put together - a charming song (so others), very delightful. David not only penned it, but sang it himself in a devout religious manner unto the Lord, concerning the words or affairs of Cush the Benjamite, that is, of Saul himself, whose barbarous usage of David bespoke him rather a Cushite, or Ethiopian, than ...', 'teologico');
add('sl', 7, 10, 'Matthew Henry', 'David having lodged his appeal with God by prayer and a solemn profession of his integrity, in the former part of the psalm, in this latter part does, as it were, take out judgment upon the appeal, by faith in the word of God, and the assurance it gives of the happiness and safety of the righteous and the certain destruction of wicked people that continue impenitent.\nI. David is confident that he shall find God his powerful protector and Saviour, and the patron of his oppressed innocency (Psa...', 'teologico');
add('sl', 8, 3, 'Matthew Henry', 'David here goes on to magnify the honour of God by recounting the honours he has put upon man, especially the man Christ Jesus. The condescensions of the divine grace call for our praises as much as the elevations of the divine glory. How God has condescended in favour to man the psalmist here observes with wonder and thankfulness, and recommends it to our thoughts. See here,\nI. What it is that leads him to admire the condescending favour of God to man; it is his consideration of the lustre a...', 'teologico');
add('sl', 9, 1, 'Matthew Henry', 'The title of this psalm gives a very uncertain sound concerning the occasion of penning it. It is upon Muth-labben, which some make to refer to the death of Goliath, others of Nabal, others of Absalom; but I incline to think it signifies only some tone, or some musical instrument, to which this psalm was intended to be sung; and that the enemies David is here triumphing in the defeat of are the Philistines, and the other neighbouring nations that opposed his settlement in the throne, whom he ...', 'teologico');
add('sl', 9, 11, 'Matthew Henry', 'In these verses,\nI. David, having praised God himself, calls upon and invites others to praise him likewise, Psa 9:11. Those who believe God is greatly to be praised not only desire to do that work better themselves, but desire that others also may join with them in it and would gladly be instrumental to bring them to it: Sing praises to the Lord who dwelleth in Zion. As the special residence of his glory is in heaven, so the special residence of his grace is in his church, of which Zion was ...', 'teologico');
add('sl', 10, 1, 'Matthew Henry', 'David, in these verses, discovers,\nI. A very great affection to God and his favour; for, in the time of trouble, that which he complains of most feelingly is God\'s withdrawing his gracious presence (Psa 10:1): "Why standest thou afar off, as one unconcerned in the indignities done to thy name and the injuries done to the people?" Note, God\'s withdrawings are very grievous to his people at any time, but especially in times of trouble. Outward deliverance is afar off and is hidden from us, and ...', 'teologico');
add('sl', 10, 12, 'Matthew Henry', 'David here, upon the foregoing representation of the inhumanity and impiety of the oppressors, grounds an address to God, wherein observe,\nI. What he prays for. 1. That God would himself appear (Psa 10:12): "Arise, O Lord! O God! lift up thy hand, manifest thy presence and providence in the affairs of this lower world. Arise, O Lord! to the confusion of those who say that thou hidest thy face. Manifest thy power, exert it for the maintaining of thy own cause, lift up thy hand to give a fatal ...', 'teologico');
add('sl', 11, 1, 'Matthew Henry', 'Here is, I. David\'s fixed resolution to make God his confidence: In the Lord put I my trust, Psa 11:1. Those that truly fear God and serve him are welcome to put their trust in him, and shall not be made ashamed of their doing so. And it is the character of the saints, who have taken God for their God, that they make him their hope. Even when they have other things to stay themselves upon, yet they do not, they dare not, stay upon them, but on God only. Gold is not their hope, nor are horses ...', 'teologico');
add('sl', 11, 4, 'Matthew Henry', 'The shaking of a tree (they say) makes it take the deeper and faster root. The attempt of David\'s enemies to discourage his confidence in God engages him to cleave so much the more closely to his first principles, and to review them, which he here does, abundantly to his own satisfaction and the silencing of all temptations to infidelity. That which was shocking to his faith, and has been so to the faith of many, was the prosperity of wicked people in their wicked ways, and the straits and di...', 'teologico');
add('sl', 12, 1, 'Matthew Henry', 'This psalm furnishes us with good thoughts for bad times, in which, though the prudent will keep silent (Amo 5:13) because a man may then be made an offender for a word, yet we may comfort ourselves with such suitable meditations and prayers as are here got ready to our hand.\nI. Let us see here what it is that makes the times bad, and when they may be said to be so. Ask the children of this world what it is in their account that makes the times bad, and they will tell you, Scarcity of money, ...', 'teologico');
add('sl', 13, 1, 'Matthew Henry', 'David, in affliction, is here pouring out his soul before God; his address is short, but the method is very observable, and of use for direction and encouragement.\nI. His troubles extort complaints (Psa 13:1, Psa 13:2); and the afflicted have liberty to pour out their complaint before the Lord, Ps. 102 title. It is some ease to a troubled spirit to give vent to its griefs, especially to give vent to them at the throne of grace, where we are sure to find one who is afflicted in the afflictions...', 'teologico');
add('sl', 14, 1, 'Matthew Henry', 'If we apply our hearts as Solomon did (Ecc 7:25) to search out the wickedness of folly, even of foolishness and madness, these verses will assist us in the search and will show us that sin is exceedingly sinful. Sin is the disease of mankind, and it appears here to be malignant and epidemic.\n1. See how malignant it is (Psa 14:1) in two things: - \n(1.) The contempt it puts upon the honour of God: for there is something of practical atheism at the bottom of all sin. The fool hath said in his he...', 'teologico');
add('sl', 14, 4, 'Matthew Henry', 'In these verses the psalmist endeavours,\nI. To convince sinners of the evil and danger of the way they are in, how secure soever they are in that way. Three things he shows them, which, it may be, they are not very willing to see - their wickedness, their folly, and their danger, while they are apt to believe themselves very wise, and good, and safe. See here,\n1. Their wickedness. This is described in four instances: - (1.) They are themselves workers of iniquity; they design it, they practis...', 'teologico');
add('sl', 15, 1, 'Matthew Henry', 'Here is, I. A very serious and weighty question concerning the characters of a citizen of Zion (Psa 15:1): "Lord, who shall abide in thy tabernacle? Let me know who shall go to heaven." Not, who by name (in this way the Lord only knows those that are his), but who by description: "What kind of people are those whom thou wilt own and crown with distinguishing and everlasting favours?" This supposes that it is a great privilege to be a citizen of Zion, an unspeakable honour and advantage, - tha...', 'teologico');
add('sl', 16, 1, 'Matthew Henry', 'This psalm is entitled Michtam, which some translate a golden psalm, a very precious one, more to be valued by us than gold, yea, than much fine gold, because it speaks so plainly of Christ and his resurrection, who is the true treasure hidden in the field of the Old Testament.\nI. David here flies to God\'s protection with a cheerful believing confidence in it (Psa 16:1): "Preserve me, O God! from the deaths, and especially from the sins, to which I am continually exposed; for in thee, and in ...', 'teologico');
add('sl', 16, 8, 'Matthew Henry', 'All these verses are quoted by St. Peter in his first sermon, after the pouring out of the Spirit on the day of pentecost (Act 2:25-28); and he tells us expressly that David in them speaks concerning Christ and particularly of his resurrection. Something we may allow here of the workings of David\'s own pious and devout affections towards God, depending upon his grace to perfect every thing that concerned him, and looking for the blessed hope, and happy state on the other side death, in the en...', 'teologico');
add('sl', 17, 1, 'Matthew Henry', 'This psalm is a prayer. As there is a time to weep and a time to rejoice, so there is a time for praise and a time for prayer. David was now persecuted, probably by Saul, who hunted him like a partridge on the mountains; without were fightings, within were fears, and both urged him as a suppliant to the throne of mercy. He addresses himself to God in these verses both by way of appeal (Hear the right, O Lord! let my righteous cause have a hearing before thy tribunal, and give judgment upon it...', 'teologico');
add('sl', 17, 8, 'Matthew Henry', 'We may observe, in these verses,\nI. What David prays for. Being compassed about with enemies that sought his life, he prays to God to preserve him safely through all their attempts against him, to the crown to which he was anointed. This prayer is both a prediction of the preservation of Christ through all the hardships and difficulties of his humiliation, to the glories and joys of his exalted state, and a pattern to Christians to commit the keeping of their souls to God, trusting him to pre...', 'teologico');
add('sl', 18, 1, 'Matthew Henry', 'The title gives us the occasion of penning this psalm; we had it before (Sa2 22:1), only here we are told that the psalm was delivered to the chief musician, or precentor, in the temple-songs. Note, The private compositions of good men, designed by them for their own use, may be serviceable to the public, that others may not only borrow light from their candle, but heat from their fire. Examples sometimes teach better than rules. And David is here called the servant of the Lord, as Moses was,...', 'teologico');
add('sl', 18, 20, 'Matthew Henry', 'Here, I. David reflects with comfort upon his own integrity, and rejoices in the testimony of his conscience that he had had his conversation in godly sincerity and not with fleshly wisdom, Co2 1:12. His deliverances were an evidence of this, and this was the great comfort of his deliverances. His enemies had misrepresented him, and perhaps, when his troubles continued long, he began to suspect himself; but, when God visibly took his part, he had both the credit and the comfort of his righteo...', 'teologico');
add('sl', 18, 29, 'Matthew Henry', 'In these verses,\nI. David looks back, with thankfulness, upon the great things which God had done for him. He had not only wrought deliverance for him, but had given him victory and success, and made him triumph over those who thought to triumph over him. When we set ourselves to praise God for one mercy we must be led by that to observe the many more with which we have been compassed about, and followed, all our days. Many things had contributed to David\'s advancement, and he owns the hand o...', 'teologico');
add('sl', 20, 1, 'Matthew Henry', 'This prayer for David is entitled a psalm of David; nor was it any absurdity at all for him who was divinely inspired to draw up a directory, or form of prayer, to be used in the congregation for himself and those in authority under him; nay it is very proper for those who desire the prayers of their friends to tell them particularly what they would have to be asked of God for them. Note, Even great and good men, and those that know ever so well how to pray for themselves, must not despise, b...', 'teologico');
add('sl', 20, 6, 'Matthew Henry', 'Here is, I. Holy David himself triumphing in the interest he had in the prayers of good people (Psa 20:6): "Now know I (I that pen the psalm know it) that the Lord saveth his anointed, because he hath stirred up the hearts of the seed of Jacob to pray for him." Note, It bodes well to any prince and people, and may justly be taken as a happy presage, when God pours upon them a spirit of prayer. If he see us seeking him, he will be found of us; if he cause us to hope in his word, he will establ...', 'teologico');
add('sl', 21, 1, 'Matthew Henry', 'David here speaks for himself in the first place, professing that his joy was in God\'s strength and in his salvation, and not in the strength or success of his armies. He also directs his subjects herein to rejoice with him, and to give God all the glory of the victories he had obtained; and all with an eye to Christ, of whose triumphs over the powers of darkness David\'s victories were but shadows. 1. They here congratulate the king on his joys and concur with him in them (Psa 21:1): "The kin...', 'teologico');
add('sl', 21, 7, 'Matthew Henry', 'The psalmist, having taught his people to look back with joy and praise on what God had done for him and them, here teaches them to look forward with faith, and hope, and prayer, upon what God would further do for them: The king rejoices in God (Psa 21:1), and therefore we will be thankful; the king trusteth in God (Psa 21:7), therefore will we be encouraged. The joy and confidence of Christ our King is the ground of all our joy and confidence.\nI. They are confident of the stability of David\'...', 'teologico');
add('sl', 22, 11, 'Matthew Henry', 'In these verses we have Christ suffering and Christ praying, by which we are directed to look for crosses and to look up to God under them.\nI. Here is Christ suffering. David indeed was often in trouble, and beset with enemies; but many of the particulars here specified are such as were never true of David, and therefore must be appropriated to Christ in the depth of his humiliation.\n1. He is here deserted by his friends: Trouble and distress are near, and there is none to help, none to uphol...', 'teologico');
add('sl', 22, 22, 'Matthew Henry', 'The same that began the psalm complaining, who was no other than Christ in his humiliation, ends it here triumphing, and it can be no other than Christ in his exaltation. And, as the first words of the complaint were used by Christ himself upon the cross, so the first words of the triumph are expressly applied to him (Heb 2:12) and are made his own words: I will declare thy name unto my brethren, in the midst of the church will I sing praise unto thee. The certain prospect which Christ had of...', 'teologico');
add('sl', 24, 1, 'Matthew Henry', 'Here is, I. God\'s absolute propriety in this part of the creation where our lot is cast, Psa 24:1. We are not to think that the heavens, even the heavens only, are the Lord\'s, and the numerous and bright inhabitants of the upper world, and that this earth, being so small and inconsiderable a part of the creation, and at such a distance from the royal palace above, is neglected, and that he claims no interest in it. No, even the earth is his, and this lower world; and, though he has prepared t...', 'teologico');
add('sl', 24, 3, 'Matthew Henry', 'From this world, and the fulness thereof, the psalmist\'s meditations rise, of a sudden to the great things of another world, the foundation of which is not on the seas, nor on the floods. The things of this world God has given to the children of men and we are much indebted to his providence for them; but they will not make a portion for us. And therefore,\nI. Here is an enquiry after better things, Psa 24:3. This earth is God\'s footstool; but, if we had ever so much of it, we must be here but...', 'teologico');
add('sl', 24, 7, 'Matthew Henry', 'What is spoken once is spoken a second time in these verses; such repetitions are usual in songs, and have much beauty in them. Here is, 1. Entrance once and again demanded for the King of glory; the doors and gates are to be thrown open, thrown wide open, to give him admission, for behold he stands at the door and knocks, ready to come in. 2. Enquiry once and again made concerning this mighty prince, in whose name entrance is demanded: Who is this King of glory? As, when any knock at our doo...', 'teologico');
add('sl', 25, 1, 'Matthew Henry', 'Here we have David\'s professions of desire towards God and dependence on him. He often begins his psalms with such professions, not to move God, but to move himself, and to engage himself to answer those professions.\nI. He professes his desire towards God: Unto thee, O Lord! do I lift up my soul, Psa 25:1. In the foregoing psalm (Psa 25:4) it was made the character of a good man that he has not lifted up his soul to vanity; and a call was given to the everlasting gates to lift up their heads ...', 'teologico');
add('sl', 25, 8, 'Matthew Henry', 'God\'s promises are here mixed with David\'s prayers. Many petitions there were in the former part of the psalm, and many we shall find in the latter; and here, in the middle of the psalm, he meditates upon the promises, and by a lively faith sucks and is satisfied from these breasts of consolation; for the promises of God are not only the best foundation of prayer, telling us what to pray for and encouraging our faith and hope in prayer, but they are a present answer to prayer. Let the prayer ...', 'teologico');
add('sl', 25, 15, 'Matthew Henry', 'David, encouraged by the promises he had been meditating upon, here renews his addresses to God, and concludes the psalm, as he began, with professions of dependence upon God and desire towards him.\nI. He lays open before God the calamitous condition he was in. His feet were in the net, held fast and entangled, so that he could not extricate himself out of his difficulties, Psa 25:15. He was desolate and afflicted, Psa 25:16. It is common for those that are afflicted to be desolate; their fri...', 'teologico');
add('sl', 26, 1, 'Matthew Henry', 'It is probable that David penned this psalm when he was persecuted by Saul and his party, who, to give some colour to their unjust rage, represented him as a very bad man, and falsely accused him of many high crimes and misdemeanors, dressed him up in the skins of wild beasts that they might bait him. Innocency itself is no fence to the name, though it is to the bosom, against the darts of calumny. Herein he was a type of Christ, who was made a reproach of men, and foretold to his followers t...', 'teologico');
add('sl', 26, 6, 'Matthew Henry', 'In these verses,\nI. David mentions, as further evidence of his integrity, the sincere affection he had to the ordinances of God, the constant care he took about them, and the pleasure he took in them. Hypocrites and dissemblers may indeed be found attending on God\'s ordinances, as the proud Pharisee went up to the temple to pray with the penitent publican; but it is a good sign of sincerity if we attend upon them as David here tells us he did, Psa 26:6-8.\n1. He was very careful and conscienti...', 'teologico');
add('sl', 27, 1, 'Matthew Henry', 'We may observe here,\nI. With what a lively faith David triumphs in God, glories in his holy name, and in the interest he had in him. 1. The Lord is my light. David\'s subjects called him the light of Israel, Sa2 21:17. And he was indeed a burning and a shining light: but he owns that he shone, as the moon does, with a borrows light; what light God darted upon him reflected upon them: The Lord is my light. God is a light to his people, to show them the way when they are in doubt, to comfort and...', 'teologico');
add('sl', 27, 7, 'Matthew Henry', 'David in these verses expresses,\nI. His desire towards God, in many petitions. If he cannot now go up to the house of the Lord, yet, wherever he is, he can find a way to the throne of grace by prayer.\n1. He humbly bespeaks, because he firmly believes he shall have, a gracious audience: "Hear, O Lord, when I cry, not only with my heart, but, as one in earnest, with my voice too." He bespeaks also an answer of peace, which he expects, not from his own merit, but God\'s goodness: Have mercy upon ...', 'teologico');
add('sl', 28, 1, 'Matthew Henry', 'In these verses David is very earnest in prayer.\nI. He prays that God would graciously hear and answer him, now that, in his distress, he called upon him, Psa 28:1, Psa 28:2. Observe his faith in prayer: O Lord, my rock, denoting his belief of God\'s power (he is a rock) and his dependence upon that power - "He is my rock, on whom I build my hope." Observe his fervency in prayer: "To thee will I cry, as one in earnest, being ready to sink, unless thou come in with seasonable succour." And obse...', 'teologico');
add('sl', 28, 6, 'Matthew Henry', 'In these verses,\nI. David gives God thanks for the audience of his prayers as affectionately as a few verses before he had begged it: Blessed be the Lord, Psa 28:6. How soon are the saints\' sorrows turned into songs and their prayers into praises! It was in faith that David prayed (Psa 28:2), Hear the voice of my supplications; and by the same faith he gives thanks (Psa 28:6) that God has heard the voice of his supplications. Note, 1. Those that pray in faith may rejoice in hope. "He hath hea...', 'teologico');
add('sl', 29, 1, 'Matthew Henry', 'In this psalm we have,\nI. A demand of the homage of the great men of the earth to be paid to the great God. Every clap of thunder David interpreted as a call to himself and other princes to give glory to the great God. Observe, 1. Who they are that are called to this duty: "O you mighty (Psa 29:1), you sons of the mighty, who have power, and on whom that power is devolved by succession and inheritance, who have royal blood running in your veins!" It is much for the honour of the great God tha...', 'teologico');
add('sl', 30, 1, 'Matthew Henry', 'It was the laudable practice of the pious Jews, and, though not expressly appointed, yet allowed and accepted, when they had built a new house, to dedicate it to God, Deu 20:5. David did so when his house was built, and he took possession of it (Sa2 5:11); for royal palaces do as much need God\'s protection, and are as much bound to be at his service, as ordinary houses. Note, The houses we dwell in should, at our first entrance upon them, be dedicated to God, as little sanctuaries. We must so...', 'teologico');
add('sl', 30, 6, 'Matthew Henry', 'We have, in these verses, an account of three several states that David was in successively, and of the workings of his heart towards God in each of those states - what he said and did, and how his heart stood affected; in the first of these we may see what we are too apt to be, and in the other two what we should be.\nI. He had long enjoyed prosperity, and then he grew secure and over-confident of the continuance of it (Psa 30:6, Psa 30:7): "In my prosperity, when I was in health of body and ...', 'teologico');
add('sl', 31, 1, 'Matthew Henry', 'Faith and prayer must go together. He that believes, let his pray - I believe, therefore I have spoken: and he that prays, let him believe, for the prayer of faith is the prevailing prayer. We have both here.\nI. David, in distress, is very earnest with God in prayer for succour and relief. This eases a burdened spirit, fetches in promised mercies, and wonderfully supports and comforts the soul in the expectation of them. He prays, 1. That God would deliver him (Psa 31:1), that his life might ...', 'teologico');
add('sl', 31, 9, 'Matthew Henry', 'In the foregoing verses David had appealed to God\'s righteousness, and pleaded his relation to him and dependence on him; here he appeals to his mercy, and pleads the greatness of his own misery, which made his case the proper object of that mercy. Observe,\nI. The complaint he makes of his trouble and distress (Psa 31:9): "Have mercy upon me, O Lord! for I am in trouble, and need thy mercy." The remembrance he makes of his condition is not much unlike some even of Job\'s complaints. 1. His tro...', 'teologico');
add('sl', 31, 19, 'Matthew Henry', 'We have three things in these verses: - \nI. The believing acknowledgment which David makes of God\'s goodness to his people in general, Psa 31:19, Psa 31:20.\n1. God is good to all, but he is, in a special manner, good to Israel. His goodness to them is wonderful, and will be, to eternity, matter of admiration: O how great is thy goodness! How profound are the counsels of it! how rich are the treasures of it! how free and extensive are the communications of it! Those very persons whom men load ...', 'teologico');
add('sl', 32, 1, 'Matthew Henry', 'This psalm is entitled Maschil, which some take to be only the name of the tune to which it was set and was to be sung. But others think it is significant; our margin reads it, A psalm of David giving instruction, and there is nothing in which we have more need of instruction than in the nature of true blessedness, wherein it consists and the way that leads to it - what we must do that we may be happy. There are several things in which these verses instruct us. In general, we are here taught ...', 'teologico');
add('sl', 32, 7, 'Matthew Henry', 'David is here improving the experience he had had of the comfort of pardoning mercy.\nI. He speaks to God, and professes his confidence in him and expectation from him, Psa 32:7. Having tasted the sweetness of divine grace to a penitent sinner, he cannot doubt of the continuance of that grace to a praying saint, and that in that grace he should find both safety and joy. 1. Safety: "Thou art my hiding-place; when by faith I have recourse to thee I see all the reason in the world to be easy, and...', 'teologico');
add('sl', 33, 1, 'Matthew Henry', 'Four things the psalmist expresses in these verses:\nI. The great desire he had that God might be praised. He did not think he did it so well himself, but that he wished others also might be employed in this work; the more the better, in this concert: it is the more like heaven. 1. Holy joy is the heart and soul of praise, and that is here pressed upon all good people (Psa 33:1): Rejoice in the Lord, you righteous; so the foregoing psalm concluded and so this begins; for all our religious exer...', 'teologico');
add('sl', 33, 12, 'Matthew Henry', 'We are here taught to give to God the glory,\nI. Of his common providence towards all the children of men. Though he has endued man with understanding and freedom of will, yet he reserves to himself the government of him, and even of those very faculties by which he is qualified to govern himself. 1. The children of men are all under his eye, even their hearts are so; and all the motions and operations of their souls, which none know but they themselves, he knows better than they themselves, P...', 'teologico');
add('sl', 34, 1, 'Matthew Henry', 'The title of this psalm tells us both who penned it and upon what occasion it was penned. David, being forced to flee from his country, which was made too hot for him by the rage of Saul, sought shelter as near it as he could, in the land of the Philistines. There it was soon discovered who he was, and he was brought before the king, who, in the narrative, is called Achish (his proper name), here Abimelech (his title); and lest he should be treated as a spy, or one that came thither upon desi...', 'teologico');
add('sl', 34, 11, 'Matthew Henry', 'David, in this latter part of the psalm, undertakes to teach children. Though a man of war, and anointed to be king, he did not think it below him; though now he had his head so full of cares and his hands of business, yet he could find heart and time to give good counsel to young people, from his own experience. It does not appear that he had now any children of his own, at least any that were grown up to a capacity of being taught; but, by divine inspiration, he instructs the children of hi...', 'teologico');
add('sl', 35, 1, 'Matthew Henry', 'In these verses we have,\nI. David\'s representation of his case to God, setting forth the restless rage and malice of his persecutors. He was God\'s servant, expressly appointed by him to be what he was, followed his guidance, and aimed at his glory in the way of duty, had lived (as St. Paul speaks) in all good conscience before God unto this day; and yet there were those that strove with him, that did their utmost to oppose his advancement, and made all the interest they could against him; the...', 'teologico');
add('sl', 35, 11, 'Matthew Henry', 'Two very wicked things David here lays to the charge of his enemies, to make good his appeal to God against them - perjury and ingratitude.\nI. Perjury, Psa 35:11. When Saul would have David attainted of treason, in order to his being outlawed, perhaps he did it with the formalities of a legal prosecution, produced witnesses who swore some treasonable words or overt acts against him, and he being not present to clear himself (or, if he was, it was all the same), Saul adjudged him a traitor. Th...', 'teologico');
add('sl', 35, 17, 'Matthew Henry', 'In these verses, as before,\nI. David describes the great injustice, malice, and insolence, of his persecutors, pleading this with God as a reason why he should protect him from them and appear against them. 1. They were very unrighteous; they were his enemies wrongfully, for he never gave them any provocation: They hated him without a cause; nay, for that for which they ought rather to have loved and honoured him. This is quoted, with application to Christ, and is said to be fulfilled in him....', 'teologico');
add('sl', 36, 1, 'Matthew Henry', 'David, in the title of this psalm, is styled the servant of the Lord; why in this, and not in any other, except in Ps. 18 (title), no reason can be given; but so he was, not only as every good man is God\'s servant, but as a king, as a prophet, as one employed in serving the interests of God\'s kingdom among men more immediately and more eminently than any other in his day. He glories in it, Psa 116:16. It is no disparagement, but an honour, to the greatest of men, to be the servants of the gre...', 'teologico');
add('sl', 36, 5, 'Matthew Henry', 'David, having looked round with grief upon the wickedness of the wicked, here looks up with comfort upon the goodness of God, a subject as delightful as the former was distasteful and very proper to be set in the balance against it. Observe,\nI. His meditations upon the grace of God. He sees the world polluted, himself endangered, and God dishonoured, by the transgressions of the wicked; but, of a sudden, he turns his eye, and heart, and speech, to God "However it be, yet thou art good." He he...', 'teologico');
add('sl', 37, 1, 'Matthew Henry', 'The instructions here given are very plain; much need not be said for the exposition of them, but there is a great deal to be done for the reducing of them to practice, and there they will look best.\nI. We are here cautioned against discontent at the prosperity and success of evil-doers (Psa 37:1, Psa 37:2): Fret not thyself, neither be thou envious. We may suppose that David speaks this to himself first, and preaches it to his own heart (in his communing with that upon his bed), for the supp...', 'teologico');
add('sl', 37, 7, 'Matthew Henry', 'In these verses we have,\nI. The foregoing precepts inculcated; for we are so apt to disquiet ourselves with needless fruitless discontents and distrusts that it is necessary there should be precept upon precept, and line upon line, to suppress them and arm us against them. 1. Let us compose ourselves by believing in God: "Rest in the Lord, and wait patiently for him (Psa 37:7), that is, be well reconciled to all he does and acquiesce in it, for that is best that is, because it is what God has...', 'teologico');
add('sl', 37, 21, 'Matthew Henry', 'These verses are much to the same purport with the foregoing verses of this psalm, for it is a subject worthy to be dwelt upon. Observe here,\nI. What is required of us as the way to our happiness, which we may learn both from the characters here laid down and from the directions here given. If we would be blessed of God, 1. We must make conscience of giving every body his own; for the wicked borrows and pays not again, Psa 37:21. It is the first thing which the Lord our God requires of us, th...', 'teologico');
add('sl', 37, 34, 'Matthew Henry', 'The psalmist\'s conclusion of this sermon (for that is the nature of this poem) is of the same purport with the whole, and inculcates the same things.\nI. The duty here pressed upon us is still the same (Psa 37:34): Wait on the Lord and keep his way. Duty is ours, and we must mind it and make conscience of it, keep God\'s way and never turn out of it nor loiter in it, keep close, keep going; but events are God\'s and we must refer ourselves to him for the disposal of them; we must wait on the Lor...', 'teologico');
add('sl', 38, 1, 'Matthew Henry', 'The title of this psalm is very observable; it is a psalm to bring to remembrance; the 70th psalm, which was likewise penned in a day of affliction, is so entitled. It is designed, 1. To bring to his own remembrance. We will suppose it penned when he was sick and in pain, and then it teaches us that times of sickness are times to bring to remembrance, to bring the sin to remembrance, for which God contended with us, to awaken our consciences to deal faithfully and plainly with us, and set our...', 'teologico');
add('sl', 38, 12, 'Matthew Henry', 'In these verses,\nI. David complains of the power and malice of his enemies, who, it should seem, not only took occasion from the weakness of his body and the trouble of his mind to insult over him, but took advantage thence to do him a mischief. He has a great deal to say against them, which he humbly offers as a reason why God should appear for him, as Psa 25:19, Consider my enemies. 1. "They are very spiteful and cruel: They seek my hurt; nay, they seek after my life," Psa 38:12. That life ...', 'teologico');
add('sl', 39, 1, 'Matthew Henry', 'David here recollects, and leaves upon record, the workings of his heart under his afflictions; and it is good for us to do so, that what was thought amiss may be amended, and what was well thought of may be improved the next time.\nI. He remembered the covenants he had made with God to walk circumspectly, and to be very cautious both of what he did and what he said. When at any time we are tempted to sin, and are in danger of falling into it, we must call to mind the solemn vows we have made ...', 'teologico');
add('sl', 39, 7, 'Matthew Henry', 'The psalmist, having meditated on the shortness and uncertainty of life, and the vanity and vexation of spirit that attend all the comforts of life, here, in these verses, turns his eyes and heart heaven-ward. When there is no solid satisfaction to be had in the creature it is to be found in God, and in communion with him; and to him we should be driven by our disappointments in the world. David here expresses,\nI. His dependence on God, Psa 39:7. Seeing all is vanity, and man himself is so, 1...', 'teologico');
add('sl', 40, 1, 'Matthew Henry', 'In these verses we have,\nI. The great distress and trouble that the psalmist had been in. He had been plunged into a horrible pit and into miry clay (Psa 40:2), out of which he could not work himself, and in which he found himself sinking yet further. He says nothing here either of the sickness of his body or the insults of his enemies, and therefore we have reason to think it was some inward disquiet and perplexity of spirit that was now his greatest grievance. Despondency of spirit under th...', 'teologico');
add('sl', 40, 6, 'Matthew Henry', 'The psalmist, being struck with amazement at the wonderful works that God had done for his people, is strangely carried out here to foretel that work of wonder which excels all the rest and is the foundation and fountain of all, that of our redemption by our Lord Jesus Christ. God\'s thoughts, which were to us-ward concerning that work, were the most curious, the most copious, the most gracious, and therefore to be most admired. This paragraph is quoted by the apostle (Heb 10:5, etc.) and appl...', 'teologico');
add('sl', 40, 11, 'Matthew Henry', 'The psalmist, having meditated upon the work of redemption, and spoken of it in the person of the Messiah, now comes to make improvement of the doctrine of his mediation between us and God, and therefore speaks in his own person. Christ having done his Father\'s will, and finished his work, and given orders for the preaching of the gospel to every creature, we are encouraged to come boldly to the throne of grace, for mercy and grace.\nI. This may encourage us to pray for the mercy of God, and t...', 'teologico');
add('sl', 41, 1, 'Matthew Henry', 'In these verses we have,\nI. God\'s promises of succour and comfort to those that consider the poor; and,\n1. We may suppose that David makes mention of these with application either, (1.) To his friends, who were kind to him, and very considerate of his case, now that he was in affliction: Blessed is he that considers poor David. Here and there he met with one that sympathized with him, and was concerned for him, and kept up his good opinion of him and respect for him, notwithstanding his affli...', 'teologico');
add('sl', 41, 5, 'Matthew Henry', 'David often complains of the insolent conduct of his enemies towards him when he was sick, which, as it was very barbarous in them, so it could not but be very grievous to him. They had not indeed arrived at that modern pitch of wickedness of poisoning his meat and drink, or giving him something to make him sick; but, when he was sick, they insulted over him (Psa 41:5): My enemies speak evil of me, designing thereby to grieve his spirit, to ruin his reputation, and so to sink his interest. Le...', 'teologico');
add('sl', 42, 1, 'Matthew Henry', 'Holy love to God as the chief good and our felicity is the power of godliness, the very life and soul of religion, without which all external professions and performances are but a shell and carcase: now here we have some of the expressions of that love. Here is,\nI. Holy love thirsting, love upon the wing, soaring upwards in holy desires towards the Lord and towards the remembrance of his name (Psa 42:1, Psa 42:2): "My soul panteth, thirsteth, for God, for nothing more than God, but still for...', 'teologico');
add('sl', 42, 6, 'Matthew Henry', 'Complaints and comforts here, as before, take their turn, like day and night in the course of nature.\nI. He complains of the dejections of his spirit, but comforts himself with the thoughts of God, Psa 42:6. 1. In his troubles. His soul was dejected, and he goes to God and tells him so: O my God! my soul is cast down within me. It is a great support to us, when upon any account we are distressed, that we have liberty of access to God, and liberty of speech before him, and may open to him the ...', 'teologico');
add('sl', 43, 1, 'Matthew Henry', 'David here makes application to God, by faith and prayer, as his judge, his strength, his guide, his joy, his hope, with suitable affections and expressions.\nI. As his Judge, his righteous Judge, who he knew would judge him, and who (being conscious of his own integrity) he knew would judge for him (Psa 43:1): Judge me, O God! and plead my cause. There were those that impeached him; against them he is defendant, and from their courts, where he stood unjustly convicted and condemned, he appeal...', 'teologico');
add('sl', 44, 1, 'Matthew Henry', 'Some observe that most of the psalms that are entitled Maschil - psalms of instruction, are sorrowful psalms; for afflictions give instructions, and sorrow of spirit opens the ear to them. Blessed is the man whom thou chastenest and teachest.\nIn these verses the church, though now trampled upon, calls to remembrance the days of her triumph, of her triumph in God and over her enemies. This is very largely mentioned here, 1. As an aggravation of the present distress. The yoke of servitude canno...', 'teologico');
add('sl', 44, 9, 'Matthew Henry', 'The people of God here complain to him of the low and afflicted condition that they were now in, under the prevailing power of their enemies and oppressors, which was the more grievous to them because they were now trampled upon, who had always been used, in their struggles with their neighbours, to win the day and get the upper hand, and because those were now their oppressors whom they had many a time triumphed over and made tributaries, and especially because they had boasted in their God ...', 'teologico');
add('sl', 44, 17, 'Matthew Henry', 'The people of God, being greatly afflicted and oppressed, here apply to him; whither else should they go?\nI. By way of appeal, concerning their integrity, which he only is an infallible judge of, and which he will certainly be the rewarder of. Two things they call God to witness to: - \n1. That, though they suffered these hard things, yet they kept close to God and to their duty (Psa 44:17): "All this has come upon us, and it is as bad perhaps as bad can be, yet have we not forgotten thee, nei...', 'teologico');
add('sl', 45, 1, 'Matthew Henry', 'Some make Shoshannim, in the title, to signify an instrument of six strings; others take it in its primitive signification for lilies or roses, which probably were strewed, with other flowers, at nuptial solemnities; and then it is easily applicable to Christ who calls himself the rose of Sharon and the lily of the valleys, Sol 2:1. It is a song of loves, concerning the holy love that is between Christ and his church. It is a song of the well-beloved, the virgins, the companions of the bride ...', 'teologico');
add('sl', 45, 6, 'Matthew Henry', 'We have here the royal bridegroom filling his throne with judgment and keeping his court with splendour.\nI. He here fills his throne with judgment. It is God the Father that says to the Son here, Thy throne, O God! is forever and ever, as appears Heb 1:8, Heb 1:9, where this is quoted to prove that he is God and has a more excellent name than the angels. The Mediator is God, else he neither would have been able to do the Mediator\'s work nor fit to wear the Mediator\'s crown. Concerning his gov...', 'teologico');
add('sl', 45, 10, 'Matthew Henry', 'This latter part of the psalm is addressed to the royal bride, standing on the right hand of the royal bridegroom. God, who said to the Son, Thy throne is for ever and ever, says this to the church, which, upon the account of her espousals to the Son, he here calls his daughter.\nI. He tells her of the duties expected from her, which ought to be considered by all those that come into relation to the Lord Jesus: "Hearken, therefore, and consider this, and incline thy ear, that is, submit to tho...', 'teologico');
add('sl', 46, 1, 'Matthew Henry', 'The psalmist here teaches us by his own example.\nI. To triumph in God, and his relation to us and presence with us, especially when we have had some fresh experiences of his appearing in our behalf (Psa 46:1): God is our refuge and strength; we have found him so, he has engaged to be so, and he ever will be so. Are we pursued? God is our refuge to whom we may flee, and in whom we may be safe and think ourselves so; secure upon good grounds, Pro 18:10. Are we oppressed by troubles? Have we wor...', 'teologico');
add('sl', 46, 6, 'Matthew Henry', 'These verses give glory to God both as King of nations and as King of saints.\nI. As King of nations, ruling the world by his power and providence, and overruling all the affairs of the children of men to his own glory; he does according to his will among the inhabitants of the earth, and none may say, What doest thou? 1. He checks the rage and breaks the power of the nations that oppose him and his interests in the world (Psa 46:6): The heathen raged at David\'s coming to the throne, and at th...', 'teologico');
add('sl', 47, 1, 'Matthew Henry', 'The psalmist, having his own heart filled with great and good thoughts of God, endeavours to engage all about him in the blessed work of praise, as one convinced that God is worthy of all blessing and praise, and as one grieved at his own and others\' backwardness to and barrenness in this work. Observe, in these verses,\nI. Who are called upon to praise God: "All you people, all you people of Israel;" those were his own subjects, and under his charge, and therefore he will engage them to prais...', 'teologico');
add('sl', 47, 5, 'Matthew Henry', 'We are here most earnestly pressed to praise God, and to sing his praises; so backward are we to this duty that we have need to be urged to it by precept upon precept, and line upon line; so we are here (Psa 47:6): Sing praises to God, and again, Sing praises, Sing praises to our King, and again, Sing praises. This intimates that it is a very necessary and excellent duty, that it is a duty we ought to be frequent and abundant in; we may sing praises again and again in the same words, and it i...', 'teologico');
add('sl', 48, 1, 'Matthew Henry', 'The psalmist is designing to praise Jerusalem and to set forth the grandeur of that city; but he begins with the praises of God and his greatness (Psa 48:1), and ends with the praises of God and his goodness, Psa 48:14. For, whatever is the subject of our praises, God must be both the Alpha and Omega of them. And, particularly, whatever is said to the honour of the church must redound to the honour of the church\'s God.\nWhat is here said to the honour of Jerusalem is,\nI. That the King of heave...', 'teologico');
add('sl', 48, 8, 'Matthew Henry', 'We have here the good use and improvement which the people of God are taught to make of his late glorious and gracious appearances for them against their enemies, that they might work for their good.\nI. Let our faith in the word of God be hereby confirmed. If we compare what God has done with what he has spoken, we shall find that, as we have heard, so have we seen (Psa 48:8), and what we have seen obliges us to believe what we have heard. 1. "As we have heard done in former providences, in t...', 'teologico');
add('sl', 49, 1, 'Matthew Henry', 'This is the psalmist\'s preface to his discourse concerning the vanity of the world and its insufficiency to make us happy; and we seldom meet with an introduction more solemn than this is; for there is no truth of more undoubted certainty, nor of greater weight and importance, and the consideration of which will be of more advantage to us.\nI. He demands the attention of others to that which he was about to say (Psa 49:1, Psa 49:2): Hear this, all you people; hear it and heed it, hear it and c...', 'teologico');
add('sl', 49, 6, 'Matthew Henry', 'In these verses we have,\nI. A description of the spirit and way of worldly people, whose portion is in this life, Psa 17:14. It is taken for granted that they have wealth, and a multitude of riches (Psa 49:6), houses and lands of inheritance, which they call their own, Psa 49:11. God often gives abundance of the good things of this world to bad men who live in contempt of him and rebellion against him, by which it appears that they are not the best things in themselves (for then God would giv...', 'teologico');
add('sl', 49, 15, 'Matthew Henry', 'Good reason is here given to good people,\nI. Why they should not be afraid of death. There is no cause for that fear if they have such a comfortable prospect as David here has of a happy state on the other side death, Psa 49:15. He had shown (Psa 49:14) how miserable the dead are that die in their sins, where he shows how blessed the dead are that die in the Lord. The distinction of men\'s outward condition, how great a difference soever it makes in life, makes none at death; rich and poor mee...', 'teologico');
add('sl', 50, 1, 'Matthew Henry', 'It is probable that Asaph was not only the chief musician, who was to put a tune to this psalm, but that he was himself the penman of it; for we read that in Hezekiah\'s time they praised God in the words of David and of Asaph the seer, Ch2 29:30. Here is,\nI. The court called, in the name of the King of kings (Psa 50:2): The mighty God, even the Lord, hath spoken - El, Elohim, Jehovah, the God of infinite power justice and mercy, Father, Son, and Holy Ghost. God is the Judge, the Son of God ca...', 'teologico');
add('sl', 50, 7, 'Matthew Henry', 'God is here dealing with those that placed all their religion in the observances of the ceremonial law, and thought those sufficient.\nI. He lays down the original contract between him and Israel, in which they had avouched him to be their God, and he them to be his people, and so both parties were agreed (Psa 50:7): Hear, O my people! and I will speak. Note, It is justly expected that whatever others doe, when he speaks, his people should give ear; who will, if they do not? And then we may co...', 'teologico');
add('sl', 50, 16, 'Matthew Henry', 'God, by the psalmist, having instructed his people in the right way of worshipping him and keeping up their communion with him, here directs his speech to the wicked, to hypocrites, whether they were such as professed the Jewish or the Christian religion: hypocrisy is wickedness for which God will judge. Observe here,\nI. The charge drawn up against them. 1. They are charged with invading and usurping the honours and privileges of religion (Psa 50:16): What has thou to do, O wicked man! to dec...', 'teologico');
add('sl', 51, 7, 'Matthew Henry', 'I. See here what David prays for. Many excellent petitions he here puts up, to which if we do but add, "for Christ\'s sake," they are as evangelical as any other.\n1. He prays that God would cleanse him from his sins and the defilement he had contracted by them (Psa 51:7): "Purge me with hyssop; that is, pardon my sins, and let me know that they are pardoned, that I may be restored to those privileges which by sin I have forfeited and lost." The expression here alludes to a ceremonial distincti...', 'teologico');
add('sl', 51, 14, 'Matthew Henry', 'I. David prays against the guilt of sin, and prays for the grace of God, enforcing both petitions from a plea taken from the glory of God, which he promises with thankfulness to show forth. 1. He prays against the guilt of sin, that he might be delivered from that, and promises that then he would praise God, Psa 51:14. The particular sin he prays against is blood-guiltiness, the sin he had now been guilty of, having slain Uriah with the sword of the children of Ammon. Hitherto perhaps he had ...', 'teologico');
add('sl', 52, 1, 'Matthew Henry', 'The title is a brief account of the story which the psalm refers to. David now, at length, saw it necessary to quit the court, and shift for his own safety, for fear of Saul, who had once and again attempted to murder him. Being unprovided wit harms and victuals, he, by a wile, got Ahimelech the priest to furnish him with both. Doeg an Edomite happened to be there, and he went and informed Saul against Ahimelech, representing him as confederate with a traitor, upon which accusation Saul groun...', 'teologico');
add('sl', 52, 6, 'Matthew Henry', 'David was at this time in great distress; the mischief Doeg had done him was but the beginning of his sorrows; and yet here we have him triumphing, and that is more than rejoicing, in tribulation. Blessed Paul, in the midst of his troubles, is in the midst of his triumphs, Co2 2:14. David here triumphs,\nI. In the fall of Doeg. Yet, lest this should look like personal revenge, he does not speak of it as how own act, but the language of other righteous persons. They shall observe God\'s judgment...', 'teologico');
add('sl', 53, 1, 'Matthew Henry', 'This psalm was opened before, and therefore we shall here only observe, in short, some things concerning sin, in order to the increasing of our sorrow for it and hatred of it. 1. The fact of sin. Is that proved? Can the charge be made out? Yes, God is a witness to it, an unexceptionable witness: from the place of his holiness he looks on the children of men, and sees how little good there is among them, Psa 53:2. All the sinfulness of their hearts and lives in naked and open before him. 2. Th...', 'teologico');
add('sl', 54, 1, 'Matthew Henry', 'We may observe here, 1. The great distress that David was now in, which the title gives an account of. The Ziphim came of their own accord, and informed Saul where David was, with a promise to deliver him into his hand. One would have thought that when David had retired into the country he would not be pursued, into a desert country he would not be discovered, and into his own country he would not be betrayed; and yet it seems he was. Never let a good man expect to be safe an easy till he com...', 'teologico');
add('sl', 54, 4, 'Matthew Henry', 'We have here the lively actings of David\'s faith in his prayer, by which he was assured that the issue would be comfortable, though the attempt upon him was formidable.\nI. He was sure that he had God on his side, that God took his part (Psa 54:4); he speaks it with an air of triumph and exultation, Behold, God is my helper. If we be for him, he is for us; and, if he be for us, we shall have such help in him that we need not fear any power engaged against us. Though men and devils aim to be ou...', 'teologico');
add('sl', 55, 1, 'Matthew Henry', 'In these verses we have,\nI. David praying. Prayer is a salve for every sore and a relief to the spirit under every burden: Give ear to my prayer, O God! Psa 55:1, Psa 55:2. He does not set down the petitions he offered up to God in his distress, but begs that God would hear the prayers which, at every period, his heart lifted up to God, and grant an answer of peace to them: Attend to me, hear me. Saul would not hear his petitions; his other enemies regarded not his pleas; but, "Lord, be thou ...', 'teologico');
add('sl', 55, 9, 'Matthew Henry', 'David here complains of his enemies, whose wicked plots had brought him, though not to his faith\'s end, yet to his wits\' end, and prays against them by the spirit of prophecy. Observe here,\nI. The character he gives of the enemies he feared. They were of the worst sort of men, and his description of them agrees very well with Absalom and his accomplices. 1. He complains of the city of Jerusalem, which strangely fell in with Absalom and fell off from David, so that he had none there but how ow...', 'teologico');
add('sl', 55, 16, 'Matthew Henry', 'In these verses,\nI. David perseveres in his resolution to call upon God, being well assured that he should not seek him in vain (Psa 55:16): "As for me, let them take what course they please to secure themselves, let violence and strife be their guards, prayer shall be mind; this I have found comfort in, and therefore this will I abide by: I will call upon God, and commit myself to him, and the Lord shall save me;" for whosoever shall call on the name of the Lord, in a right manner, shall be ...', 'teologico');
add('sl', 56, 1, 'Matthew Henry', 'David, in this psalm, by his faith throws himself into the hands of God, even when he had by his fear and folly thrown himself into the hands of the Philistines; it was when they took him in Gath, whither he fled for fear of Saul, forgetting the quarrel they had with him for killing Goliath; but they soon put him in mid of it, Sa1 21:10, Sa1 21:11. Upon that occasion he changed his behaviour, but with so little ruffle to his temper that then he penned both this psalm and the 34th. This is cal...', 'teologico');
add('sl', 56, 8, 'Matthew Henry', 'Several things David here comforts himself with in the day of his distress and fear.\nI. That God took particular notice of all his grievances and all his griefs, Psa 56:8. 1. Of all the inconveniences of his state: Thou tellest my wanderings, my flittings, so the old translation. David was now but a young (under thirty) and yet he had had many removes, from his father\'s house to the court, thence to the camp, and now driven out to sojourn where he could find a place, but not allowed to rest a...', 'teologico');
add('sl', 57, 1, 'Matthew Henry', 'The title of this psalm has one word new in it, Al-taschith - Destroy not. Some make it to be only some known tune to which this psalm was set; others apply it to the occasion and matter of the psalm. Destroy not; that is, David would not let Saul be destroyed, when now in the cave there was a fair opportunity of killing him, and his servants would fain have done so. No, says David, destroy him not, Sa1 24:4, Sa1 24:6. Or, rather, God would not let David be destroyed by Saul; he suffered him ...', 'teologico');
add('sl', 57, 7, 'Matthew Henry', 'How strangely is the tune altered here! David\'s prayers and complaints, by the lively actings of faith, are here, all of a sudden, turned into praises and thanksgivings; his sackcloth is loosed, he is girded with gladness, and his hallelujahs are as fervent as his hosannas. This should make us in love with prayer, that, sooner or later, it will be swallowed up in praise. Observe,\nI. How he prepares himself for the duty of praise (Psa 57:7): My heart is fixed, O God! my heart is fixed. My hear...', 'teologico');
add('sl', 58, 1, 'Matthew Henry', 'We have reason to think that this psalm refers to the malice of Saul and his janizaries against David, because it bears the same inscription (Al-taschith, and Michtam of David) with that which goes before and that which follows, both which appear, by the title, to have been penned with reference to that persecution through which God preserved him (Al-taschith - Destroy not), and therefore the psalms he then penned were precious to him, Michtams - David\'s jewels, as Dr. Hammond translates it.\n...', 'teologico');
add('sl', 58, 6, 'Matthew Henry', 'In these verses we have,\nI. David\'s prayers against his enemies, and all the enemies of God\'s church and people; for it is as such that he looks upon them, so that he was actuated by a public spirit in praying against them, and not by any private revenge. 1. He prays that they might be disabled to do any further mischief (Psa 58:6): Break their teeth, O God! Not so much that they might not feed themselves as that they might not be able to make prey of others, Psa 3:7. He does not say, "Break ...', 'teologico');
add('sl', 59, 1, 'Matthew Henry', 'The title of this psalm acquaints us particularly with the occasion on which it was penned; it was when Saul sent a party of his guards to beset David\'s house in the night, that they might seize him and kill him; we have the story Sa1 19:11. It was when his hostilities against David were newly begun, and he had but just before narrowly escaped Saul\'s javelin. These first eruptions of Saul\'s malice could not but put David into disorder and be both grievous and terrifying, and yet he kept up hi...', 'teologico');
add('sl', 59, 8, 'Matthew Henry', 'David here encourages himself, in reference to the threatening power of his enemies, with a pious resolution to wait upon God and a believing expectation that he should yet praise him.\nI. He resolves to wait upon God (Psa 59:9): "Because of his strength" (either the strength of his enemies, the fear of which drove him to God, or because of God\'s strength, the hope of which drew him to God) "Will I wait upon thee, with a believing dependence upon thee and confidence in thee." It is our wisdom ...', 'teologico');
add('sl', 60, 1, 'Matthew Henry', 'The title gives us an account, 1. Of the general design of the psalm. It is Michtam - David\'s jewel, and it is to teach. The Levites must teach it to the people, and by it teach them both to trust in God and to triumph in him; we must, in it, teach ourselves and one another. In a day of public rejoicing we have need to be taught to direct our joy to God and to terminate it in him, to give none of that praise to the instruments of our deliverance which is due to him only, and to encourage our ...', 'teologico');
add('sl', 60, 6, 'Matthew Henry', 'David is here rejoicing in hope and praying in hope; such are the triumphs of the saints, not so much upon the account of what they have in possession as of what they have in prospect (Psa 60:6): "God has spoken in his holiness (that is, he has given me his word of promise, has sworn by his holiness, and he will not lie unto David, Psa 89:35), therefore I will rejoice, and please myself with the hopes of the performance of the promise, which was intended for more than a pleasing promise," Not...', 'teologico');
add('sl', 61, 1, 'Matthew Henry', 'In these verses we may observe,\nI. David\'s close adherence and application to God by prayer in the day of his distress and trouble: "Whatever comes, I will cry unto thee (Psa 61:2), - not cry unto other gods, but to thee only, - not fall out with thee because thou afflictest me, but still look unto thee, and wait upon thee, - not speak to thee in a cold and careless manner, but cry to thee with the greatest importunity and fervency of spirit, as one that will not let thee go except thou bless...', 'teologico');
add('sl', 61, 5, 'Matthew Henry', 'In these verses we may observe,\nI. With what pleasure David looks back upon what God had done for him formerly (Psa 61:5): Thou, O God! hast heard my vows, that is, 1. "The vows themselves which I made, and with which I bound my soul: thou hast taken notice of them; thou hast accepted them, because made in sincerity, and been well pleased with them; thou hast been mindful of them, and put me in mind of them." God put Jacob in mind of his vows, Gen 31:13; Gen 35:1. note, God is a witness to al...', 'teologico');
add('sl', 62, 1, 'Matthew Henry', 'In these verses we have,\nI. David\'s profession of dependence upon God, and upon him only, for all good (Psa 62:1): Truly my soul waiteth upon God. Nevertheless (so some) or "However it be, whatever difficulties or dangers I may meet with, though God frown upon me and I meet with discouragements in my attendance on him, yet still my soul waits upon God" (or is silent to God, as the word is), "Says nothing against what he does, but quietly expects what he will do." We are in the way both of dut...', 'teologico');
add('sl', 62, 8, 'Matthew Henry', 'Here we have David\'s exhortation to others to trust in God and wait upon him, as he had done. Those that have found the comfort of the ways of God themselves will invite others into those ways; there is enough in God for all the saints to draw from, and we shall have never the less for others sharing with us.\nI. He counsels all to wait upon God, as he did, Psa 62:8. Observe,\n1. To whom he gives this good counsel: You people (that is, all people); all shall be welcome to trust in God, for he i...', 'teologico');
add('sl', 63, 1, 'Matthew Henry', 'The title tells us when the psalm was penned, when David was in the wilderness of Judah; that is, in the forest of Hareth (Sa1 22:5) or in the wilderness of Ziph, Sa1 23:15. 1. Even in Canaan, though a fruitful land and the people numerous, yet there were wildernesses, places less fruitful and less inhabited than other places. It will be so in the world, in the church, but not in heaven; there it is all city, all paradise, and no desert ground; the wilderness there shall blossom as the rose. ...', 'teologico');
add('sl', 63, 3, 'Matthew Henry', 'How soon are David\'s complaints and prayers turned into praises and thanksgivings! After two verses that express his desire in seeking God, here are some that express his joy and satisfaction in having found him. Faithful prayers may quickly be turned into joyful praises, if it be not our own fault. Let the hearts of those rejoice that seek the Lord (Psa 105:3), and let them praise him for working those desires in them, and giving them assurance that he will satisfy them. David was now in a w...', 'teologico');
add('sl', 63, 7, 'Matthew Henry', 'David, having expressed his desires towards God and his praises of him, here expresses his confidence in him and his joyful expectations from him (Psa 63:7): In the shadow of thy wings I will rejoice, alluding either to the wings of the cherubim stretched out over the ark of the covenant, between which God is said to dwell ("I will rejoice in thy oracles, and in covenant and communion with thee"), or to the wings of a fowl, under which the helpless young ones have shelter, as the eagle\'s youn...', 'teologico');
add('sl', 64, 1, 'Matthew Henry', 'David, in these verses, puts in before God a representation of his own danger and of his enemies\' character, to enforce his petition that God would protect him and punish them.\nI. He earnestly begs of God to preserve him (Psa 64:1, Psa 64:2): Hear my voice, O God! in my prayer; that is, grant me the thing I pray for, and this is it, Lord, preserve my life from fear of the enemy, that is, fro the enemy that I am in fear of. He makes request for his life, which is, in a particular manner, dear ...', 'teologico');
add('sl', 64, 7, 'Matthew Henry', 'We may observe here,\nI. The judgments of God which should certainly come upon these malicious persecutors of David. Though they encouraged themselves in their wickedness, here is that which, if they would believe and consider it, was enough to discourage them. And it is observable how the punishment answers the sin. 1. They shot at David secretly and suddenly, to wound him; but God shall shoot at them, for the ordains his arrows against the persecutors (Psa 7:13), against the face of them, Ps...', 'teologico');
add('sl', 65, 1, 'Matthew Henry', 'The psalmist here has no particular concern of his own at the throne of grace, but begins with an address to God, as the master of an assembly and the mouth of a congregation; and observe,\nI. How he gives glory to God, Psa 65:1. 1. By humble thankfulness: Praise waiteth for thee, O God! in Zion, waits till it arrives, that it may be received with thankfulness at its first approach. When God is coming towards us with his favours we must go forth to meet him with our praises, and wait till the ...', 'teologico');
add('sl', 65, 6, 'Matthew Henry', 'That we may be the more affected with the wonderful condescensions of the God of grace, it is of use to observe his power and sovereignty as the God of nature, the riches and bounty of his providential kingdom.\nI. He establishes the earth and it abides, Psa 119:90. By his own strength he setteth fast the mountains (Psa 65:6), did set them fast at first and still keeps them firm, though they are sometimes shaken by earthquakes.\n- Feriuntque summos. Fulmina montes.\nThe lightning blasts and loft...', 'teologico');
add('sl', 66, 1, 'Matthew Henry', 'I. In these verses the psalmist calls upon all people to praise God, all lands, all the earth, all the inhabitants of the world that are capable of praising God, Psa 66:1. 1. This speaks the glory of God, that he is worthy to be praised by all, for he is good to all and furnishes every nation with matter for praise. 2. The duty of man, that all are obliged to praise God; it is part of the law of creation, and therefore is required of every creature. 3. A prediction of the conversion of the Ge...', 'teologico');
add('sl', 66, 8, 'Matthew Henry', 'In these verses the psalmist calls upon God\'s people in a special manner to praise him. Let all lands do it, but Israel\'s land particularly. Bless our God; bless him as ours, a God in covenant with us, and that takes care of us as his own. Let them make the voice of his praise to be heard (Psa 66:8); for from whom should it be heard but from those who are his peculiar favourites and select attendants? Two things we have reason to bless God for: - \nI. Common protection (Psa 66:9): He holdeth o...', 'teologico');
add('sl', 66, 13, 'Matthew Henry', 'The psalmist, having before stirred up all people, and all God\'s people in particular, to bless the Lord, here stirs up himself and engages himself to do it.\nI. In his devotions to his God, Psa 66:13-15. He had called upon others to sing God\'s praises and to make a joyful noise with them; but, for himself, his resolutions go further, and he will praise God, 1. By costly sacrifices, which, under the law, were offered to the honour of God. All people had not wherewithal to offer these sacrifice...', 'teologico');
add('sl', 67, 1, 'Matthew Henry', 'The composition of this psalm is such as denotes the penman\'s affections to have been very warm and lively, by which spirit of devotion he was elevated to receive the spirit of prophecy concerning the enlargement of God\'s kingdom.\nI. He begins with a prayer for the welfare and prosperity of the church then in being, in the happiness of which he should share, and think himself happy, Psa 67:1. Our Saviour, in teaching us to say, Our Father, has intimated that we ought to pray with and for othe...', 'teologico');
add('sl', 68, 1, 'Matthew Henry', 'In these verses,\nI. David prays that God would appear in his glory,\n1. For the confusion of his enemies (Psa 68:1, Psa 68:2): "Let God arise, as a judge to pass sentence upon them, as a general to take the field and do execution upon them; and let them be scattered, and flee before him, as unable to keep their ground, much less to make head against him. Let God arise, as the sun when he goes forth in his strength; and the children of darkness shall be scattered, as the shadows of the evening ...', 'teologico');
add('sl', 68, 7, 'Matthew Henry', 'The psalmist here, having occasion to give God thanks for the great things he had done for him and his people of late, takes occasion thence to praise him for what he had done for their fathers in the days of old. Fresh mercies should put us in mind of former mercies and revive our grateful sense of them. Let it never be forgotten,\nI. That God himself was the guide of Israel through the wilderness; when he had brought them out of their chains he did not leave them in the dry land, but he hims...', 'teologico');
add('sl', 68, 15, 'Matthew Henry', 'David, having given God praise for what he had done for Israel in general, as the God of Israel (Psa 68:8), here comes to give him praise as Zion\'s God in a special manner; compare Psa 9:11. Sing praises to the Lord who dwelleth in Zion, for which reason Zion is called the hill of God.\nI. He compares it with the hill of Bashan and other high and fruitful hills, and prefers it before them, Psa 68:15, Psa 68:16. It is true, Zion was but little and low in comparison with them, and was not covere...', 'teologico');
add('sl', 68, 22, 'Matthew Henry', 'In these verses we have three things: - \nI. The gracious promise which God makes of the redemption of his people, and their victory over his and their enemies (Psa 68:22, Psa 68:23): The Lord said, in his own gracious purpose and promise, "I will do great things for my people, as the God of their salvation," Psa 68:20. God will not fail the expectations of those who by faith take him for their God. It is promised, 1. That he will set them in safety from their danger, as he had done formerly: ...', 'teologico');
add('sl', 68, 32, 'Matthew Henry', 'The psalmist, having prayed for and prophesied of the conversion of the Gentiles, here invites them to come in and join with the devout Israelites in praising God, intimating that their accession to the church would be the matter of their joy and praise (Psa 68:32): Let the kingdoms of the earth sing praises to the Lord; they all ought to do it, and, when they become the kingdoms of the Lord and of his Christ, they will do it. God is here proposed to them as the proper object of praise upon s...', 'teologico');
add('sl', 69, 1, 'Matthew Henry', 'In these verses David complains of his troubles, intermixing with those complaints some requests for relief.\nI. His complaints are very sad, and he pours them out before the Lord, as one that hoped thus to ease himself of a burden that lay very heaven upon him.\n1. He complains of the deep impressions that his troubles made upon his spirit (Psa 69:1, Psa 69:2): "The waters of affliction, those bitter waters, have come unto my soul, not only threaten my life, but disquiet my mind; they fill my ...', 'teologico');
add('sl', 69, 13, 'Matthew Henry', 'David had been speaking before of the spiteful reproaches which his enemies cast upon him; here he adds, But, as for me, my prayer is unto thee. They spoke ill of him for his fasting and praying, and for that he was made the song of the drunkards; but, notwithstanding that, he resolves to continue praying. Note, Though we may be jeered for well-doing, we must never be jeered out of it. Those can bear but little for God, and their confessing his name before men, that cannot bear a scoff and a ...', 'teologico');
add('sl', 69, 22, 'Matthew Henry', 'These imprecations are not David\'s prayers against his enemies, but prophecies of the destruction of Christ\'s persecutors, especially the Jewish nation, which our Lord himself foretold with tears, and which was accomplished about forty years after the death of Christ. The first two verses of this paragraph are expressly applied to the judgments of God upon the unbelieving Jews by the apostle (Rom 11:9, Rom 11:10), and therefore the whole must look that way. The rejection of the Jews for rejec...', 'teologico');
add('sl', 69, 30, 'Matthew Henry', 'The psalmist here, both as a type of Christ and as an example to Christians, concludes a psalm with holy joy and praise which he began with complaints and remonstrances of his griefs.\nI. He resolves to praise God himself, not doubting but that therein he should be accepted of him (Psa 69:30, Psa 69:31): "I will praise the name of God, not only with my heart, but with my song, and magnify him with thanksgiving;" for he is pleased to reckon himself magnified by the thankful praises of his peopl...', 'teologico');
add('sl', 70, 1, 'Matthew Henry', 'The title tells us that this psalm was designed to bring to remembrance; that is, to put God in remembrance of his mercy and promises (for so we are said to do when we pray to him and plead with him. Isa 43:26, Put me in remembrance) - not that the Eternal Mind needs a remembrancer, but this honour he is pleased to put upon the prayer of faith. Or, rather, to put himself and others in remembrance of former afflictions, that we may never be secure, but always in expectation of troubles, and of...', 'teologico');
add('sl', 71, 1, 'Matthew Henry', 'Two things in general David here prays for - that he might not be confounded and that his enemies and persecutors might be confounded.\nI. He prays that he might never be made ashamed of his dependence upon God nor disappointed in his believing expectations from him. With this petition every true believer may come boldly to the throne of grace; for God will never disappoint the hope that is of his own raising. Now observe here,\n1. How David professes his confidence in God, and with what pleasu...', 'teologico');
add('sl', 71, 14, 'Matthew Henry', 'David is here in a holy transport of joy and praise, arising from his faith and hope in God; we have both together Psa 71:14, where there is a sudden and remarkable change of his voice; his fears are all silenced, his hopes raised, and his prayers turned into thanksgivings. "Let my enemies say what they will, to drive me to despair, I will hope continually, hope in all conditions, in the most cloudy and dark day; I will live upon hope and will hope to the end." Since we hope in one that will ...', 'teologico');
add('sl', 73, 1, 'Matthew Henry', 'This psalm begins somewhat abruptly: Yet God is good to Israel (so the margin reads it); he had been thinking of the prosperity of the wicked; while he was thus musing the fire burned, and at last he spoke by way of check to himself for what he had been thinking of. "However it be, yet God is good." Though wicked people receive many of the gifts of his providential bounty, yet we must own that he is, in a peculiar manner, good to Israel; they have favours from him which others have not.\nThe p...', 'teologico');
add('sl', 73, 15, 'Matthew Henry', 'We have seen what a strong temptation the psalmist was in to envy prospering profaneness; now here we are told how he kept his footing and got the victory.\nI. He kept up a respect for God\'s people, and with that he restrained himself from speaking what he had thought amiss, Psa 73:15. He got the victory by degrees, and this was the first point he gained; he was ready to say, Verily, I have cleansed my heart in vain, and thought he had reason to say it, but he kept his mouth with this consider...', 'teologico');
add('sl', 73, 21, 'Matthew Henry', 'Behold Samson\'s riddle again unriddled, Out of the eater came forth meat, and out of the strong sweetness; for we have here an account of the good improvement which the psalmist made of that sore temptation with which he had been assaulted and by which he was almost overcome. He that stumbles and does not fall, by recovering himself takes so much the longer steps forward. It was so with the psalmist here; many good lessons he learned from his temptation, his struggles with it, and his victori...', 'teologico');
add('sl', 74, 1, 'Matthew Henry', 'This psalm is entitled Maschil - a psalm to give instruction, for it was penned in a day of affliction, which is intended for instruction; and this instruction in general it gives us, That when we are, upon any account, in distress, it is our wisdom and duty to apply to God by faithful and fervent prayer, and we shall not find it in vain to do so. Three things the people of God here complain of: - \nI. The displeasure of God against them, as that which was the cause and bitterness of all their...', 'teologico');
add('sl', 74, 12, 'Matthew Henry', 'The lamenting church fastens upon something here which she calls to mind, and therefore hath she hope (as Lam 3:21), with which she encourages herself and silences her own complaints. Two things quiet the minds of those that are here sorrowing for the solemn assembly: - \nI. That God is the God of Israel, a God in covenant with his people (Psa 74:12): God is my King of old. This comes in both as a plea in prayer to God (Psa 44:4, thou art my King, O God!) and as a prop to their own faith and h...', 'teologico');
add('sl', 74, 18, 'Matthew Henry', 'The psalmist here, in the name of the church, most earnestly begs that God would appear fro them against their enemies, and put an end to their present troubles. To encourage his own faith, he interests God in this matter (Psa 74:22): Arise, O God! plead thy own cause. This we may be sure he will do, for he is jealous for his own honour; whatever is his own cause he will plead it with a strong hand, will appear against those that oppose it and with and for those that cordially espouse it. He ...', 'teologico');
add('sl', 75, 1, 'Matthew Henry', 'In these verses,\nI. The psalmist gives to God the praise of his advancement to honour and power, and the other great things he had done for him and for his people Israel (Psa 75:1): Unto thee, O God! do we give thanks for all the favours thou hast bestowed upon us; and again, unto thee do we give thanks; for our thanksgivings must be often repeated. Did not we often pray for mercy when we were in pursuit of it; and shall we think it will suffice once or twice to give thanks when we have obtai...', 'teologico');
add('sl', 75, 6, 'Matthew Henry', 'In these verses we have two great doctrines laid down and two good inferences drawn from them, for the confirmation of what he had before said.\nI. Here are two great truths laid down concerning God\'s government of the world, which we ought to mix faith with, both pertinent to the occasion: - \n1. That from God alone kings receive their power (Psa 75:6, Psa 75:7), and therefore to God alone David would give the praise of his advancement; having his power from God he would use it for him, and th...', 'teologico');
add('sl', 76, 1, 'Matthew Henry', 'The church is here triumphant even in the midst of its militant state. The psalmist, in the church\'s name, triumphs here in God, the centre of all our triumphs.\nI. In the revelation God had made of himself to them, Psa 76:1. It is the honour and privilege of Judah and Israel that among them God is known, and where he is known his name will be great. God is known as he is pleased to make himself known; and those are happy to whom he discovers himself - happy people that have their land filled ...', 'teologico');
add('sl', 76, 7, 'Matthew Henry', 'This glorious victory with which God had graced and blessed his church is here made to speak three things: - \nI. Terror to God\'s enemies (Psa 76:7-9): "Thou, even thou, art to be feared; thy majesty is to be reverenced, thy sovereignty to be submitted to, and thy justice to be dreaded by those that have offended thee." Let all the world learn by this event to stand in awe of the great God. 1. Let all be afraid of his wrath against the daring impiety of sinners: Who may stand in thy sight from...', 'teologico');
add('sl', 77, 1, 'Matthew Henry', 'We have here the lively portraiture of a good man under prevailing melancholy, fallen into and sinking in that horrible pit and that miry clay, but struggling to get out. Drooping saints, that are of a sorrowful spirit, may here as in a glass see their own faces. The conflict which the psalmist had with his griefs and fears seems to have been over when he penned this record of it; for he says (Psa 77:1), I cried unto God, and he gave ear unto me, which, while the struggle lasted, he had not t...', 'teologico');
add('sl', 77, 11, 'Matthew Henry', 'The psalmist here recovers himself out of the great distress and plague he was in, and silences his own fears of God\'s casting off his people by the remembrance of the great things he had done for them formerly, which though he had in vain tried to quiet himself with (Psa 77:5, Psa 77:6) yet he tried again, and, upon this second trial, found it not in vain. It is good to persevere in the proper means for the strengthening of faith, though they do not prove effectual at first: "I will remember...', 'teologico');
add('sl', 78, 1, 'Matthew Henry', 'These verses, which contain the preface to this history, show that the psalm answers the title; it is indeed Maschil - a psalm to give instruction; if we receive not the instruction it gives, it is our own fault. Here,\nI. The psalmist demands attention to what he wrote (Psa 78:1): Give ear, O my people! to my law. Some make these the psalmist\'s words. David, as a king, or Asaph, in his name, as his secretary of state, or scribe to the sweet singer of Israel, here calls upon the people, as his...', 'teologico');
add('sl', 78, 9, 'Matthew Henry', 'In these verses,\nI. The psalmist observes the late rebukes of Providence that the people of Israel had been under, which they had brought upon themselves by their dealing treacherously with God, Psa 78:9-11. The children of Ephraim, in which tribe Shiloh was, though they were well armed and shot with bows, yet turned back in the day of battle. This seems to refer to that shameful defeat which the Philistines gave them in Eli\'s time, when they took the ark prisoner, Sa1 4:10, Sa1 4:11. Of this...', 'teologico');
add('sl', 78, 40, 'Matthew Henry', 'The matter and scope of this paragraph are the same with the former, showing what great mercies God had bestowed upon Israel, how provoking they had been, what judgments he had brought upon them for their sins, and yet how, in judgment, he remembered mercy at last. Let not those that receive mercy from God be thereby emboldened to sin, for the mercies they receive will aggravate their sin and hasten the punishment of it; yet let not those that are under divine rebukes for sin be discouraged f...', 'teologico');
add('sl', 79, 1, 'Matthew Henry', 'We have here a sad complaint exhibited in the court of heaven. The world is full of complaints, and so is the church too, for it suffers, not only with it, but from it, as a lily among thorns. God is complained to; whither should children go with their grievances, but to their father, to such a father as is able and willing to help? The heathen are complained of, who, being themselves aliens from the commonwealth of Israel, were sworn enemies to it. Though they knew not God, nor owned him, ye...', 'teologico');
add('sl', 79, 6, 'Matthew Henry', 'The petitions here put up to God are very suitable to the present distresses of the church, and they have pleas to enforce them, interwoven with them, taken mostly from God\'s honour.\nI. They pray that God would so turn away his anger from them as to turn it upon those that persecuted and abused them (Psa 79:6): "Pour out thy wrath, the full vials of it, upon the heathen; let them wring out the dregs of it, and drink them." This prayer is in effect a prophecy, in which the wrath of God is reve...', 'teologico');
add('sl', 80, 1, 'Matthew Henry', 'The psalmist here, in the name of the church, applies to God by prayer, with reference to the present afflicted state of Israel.\nI. He entreats God\'s favour for them (Psa 80:1, Psa 80:2); that is all in all to the sanctuary when it is desolate, and is to be sought in the first place. Observe, 1. How he eyes God in his address as the Shepherd of Israel, whom he had called the sheep of his pasture (Psa 79:13), under whose guidance and care Israel was, as the sheep are under the care and conduct...', 'teologico');
add('sl', 80, 8, 'Matthew Henry', 'The psalmist is here presenting his suit for the Israel of God, and pressing it home at the throne of grace, pleading with God for mercy and grace for them. The church is here represented as a vine (Psa 80:8, Psa 80:14) and a vineyard, Psa 80:15. The root of this vine is Christ, Rom 11:18. The branches are believers, Joh 15:5. The church is like a vine, weak and needing support, unsightly and having an unpromising outside, but spreading and fruitful, and its fruit most excellent. The church i...', 'teologico');
add('sl', 81, 1, 'Matthew Henry', 'When the people of God were gathered together in the solemn day, the day of the feast of the Lord, they must be told that they had business to do, for we do not go to church to sleep nor to be idle; no, there is that which the duty of every day requires, work of the day, which is to be done in its day. And here,\nI. The worshippers of God are excited to their work, and are taught, by singing this psalm, to stir up both themselves and one another to it, Psa 81:1-3. Our errand is, to give unto G...', 'teologico');
add('sl', 81, 8, 'Matthew Henry', 'God, by the psalmist, here speaks to Israel, and in them to us, on whom the ends of the world are come.\nI. He demands their diligent and serious attention to what he was about to say (Psa 81:8): "Hear, O my people! and who should hear me if my people will not? I have heard and answered thee; now wilt thou hear me? Hear what is said with the greatest solemnity and the most unquestionable certainty, for it is what I will testify unto thee. Do not only give me the hearing, but hearken unto me, t...', 'teologico');
add('sl', 82, 1, 'Matthew Henry', 'We have here,\nI. God\'s supreme presidency and power in all councils and courts asserted and laid down, as a great truth necessary to be believed both by princes and subjects (Psa 82:1): God stands, as chief director, in the congregation of the mighty, the mighty One, in coetu fortis - in the councils of the prince, the supreme magistrate, and he judges among the gods, the inferior magistrates; both the legislative and the executive power of princes is under his eye and his hand. Observe here,...', 'teologico');
add('sl', 82, 6, 'Matthew Henry', 'We have here,\nI. Earthly gods abased and brought down, Psa 82:6, Psa 82:7. The dignity of their character is acknowledged (Psa 82:6): I have said, You are gods. They have been honoured with the name and title of gods. God himself called them so in the statute against treasonable words Exo 22:28, Thou shalt not revile the gods. And, if they have this style from the fountain of honour, who can dispute it? But what is man, that he should be thus magnified? He called them gods because unto them t...', 'teologico');
add('sl', 83, 1, 'Matthew Henry', 'The Israel of God were now in danger, and fear, and great distress, and yet their prayer is called, A song or psalm; for singing psalms is not unseasonable, no, not when the harps are hung upon the willow-trees.\nI. The psalmist here begs of God to appear on the behalf of his injured threatened people (Psa 83:1): "Keep not thou silence, O God! but give judgment for us against those that do us an apparent wrong." Thus Jehoshaphat prayed upon occasion of that invasion (Ch2 20:11), Behold, how th...', 'teologico');
add('sl', 83, 9, 'Matthew Henry', 'The psalmist here, in the name of the church, prays for the destruction of those confederate forces, and, in God\'s name, foretels it; for this prayer that it might be so amounts to a prophecy that it shall be so, and this prophecy reaches to all the enemies of the gospel-church; whoever they be that oppose the kingdom of Christ, here they may read their doom. The prayer is, in short, that these enemies, who were confederate against Israel, might be defeated in all their attempts, and that the...', 'teologico');
add('sl', 84, 1, 'Matthew Henry', 'The psalmist here, being by force restrained from waiting upon God in public ordinances, by the want of them is brought under a more sensible conviction than ever of the worth of them. Observe,\nI. The wonderful beauty he saw in holy institutions (Psa 84:1): How amiable are thy tabernacles, O Lord of hosts! Some think that he here calls God the Lord of hosts (that is, in a special manner of the angels, the heavenly hosts) because of the presence of the angels in God\'s sanctuary; they attended ...', 'teologico');
add('sl', 84, 8, 'Matthew Henry', 'Here, I. The psalmist prays for audience and acceptance with God, not mentioning particularly what he desired God would do for him. He needed to say no more when he had professed such an affectionate esteem for the ordinances of God, which now he was restrained and banished from. All his desire was, in that profession, plainly before God, and his longing, his groaning, was not hidden from him; therefore he prays (Psa 84:8, Psa 84:9) only that God would hear his prayer and give ear, that he wo...', 'teologico');
add('sl', 85, 1, 'Matthew Henry', 'The church, in affliction and distress, is here, by direction from God, making her application to God. So ready is God to hear and answer the prayers of his people that by his Spirit in the word, and in the heart, he indites their petitions and puts words into their mouths. The people of God, in a very low and weak condition, are here taught how to address themselves to God.\nI. They are to acknowledge with thankfulness the great things God had done for them (Psa 85:1-3): "Thou has done so and...', 'teologico');
add('sl', 85, 8, 'Matthew Henry', 'We have here an answer to the prayers and expostulations in the foregoing verses.\nI. In general, it is an answer of peace. This the psalmist is soon aware of (Psa 85:8), for he stands upon his watch-tower to hear what God will say unto him, as the prophet, Hab 2:1, Hab 2:2. I will hear what God the Lord will speak. This intimates, 1. The stilling of his passions - his grief, his fear - and the tumult of his spirit which they occasioned: "Compose thyself, O my soul! in a humble silence to atte...', 'teologico');
add('sl', 86, 1, 'Matthew Henry', 'This psalm was published under the title of a prayer of David; not as if David sung all his prayers, but into some of his songs he inserted prayers; for a psalm will admit the expressions of any pious and devout affections. But it is observable how very plain the language of this psalm is, and how little there is in it of poetic flights or figures, in comparison with some other psalms; for the flourishes of wit are not the proper ornaments of prayer. Now here we may observe,\nI. The petitions ...', 'teologico');
add('sl', 86, 8, 'Matthew Henry', 'David is here going on in his prayer.\nI. He gives glory to God; for we ought in our prayers to praise him, ascribing kingdom, power, and glory, to him, with the most humble and reverent adorations. 1. As a being of unparalleled perfection, such a one that there is none like him nor any to be compared with him, Psa 86:8. Among the gods, the false gods, whom the heathens worshipped, the angels, the kings of the earth, among them all, there is none like unto thee, O Lord! none so wise, so mighty...', 'teologico');
add('sl', 87, 1, 'Matthew Henry', 'Some make the first words of the psalm to be part of the title; it is a psalm or song whose subject is the holy mountains - the temple built in Zion upon Mount Moriah. This is the foundation of the argument, or beginning of the psalm. Or we may suppose the psalmist had now the tabernacle or temple in view and was contemplating the glories of it, and at length he breaks out into this expression, which has reference, though not to what he had written before, yet to what he had thought of; every...', 'teologico');
add('sl', 87, 4, 'Matthew Henry', 'Zion is here compared with other places, and preferred before them; the church of Christ is more glorious and excellent than the nations of the earth. 1. It is owned that other places have their glories (Psa 87:4): "I will make mention of Rahab" (that is, Egypt) "and Babylon, to those that know me and are about me, and with whom I discourse about public affairs; behold Philistia and Tyre, with Ethiopia" (or rather Arabia), "we will observe that this man was born there; here and there one famo...', 'teologico');
add('sl', 88, 1, 'Matthew Henry', 'It should seem, by the titles of this and the following psalm, that Heman was the penman of the one and Ethan of the other. There were two, of these names, who were sons of Zerah the son of Judah, Ch1 2:4, Ch1 2:6. There were two others famed for wisdom, Kg1 4:31, where, to magnify Solomon\'s wisdom, he is said to be wiser than Heman and Ethan. Whether the Heman and Ethan who were Levites and precentors in the songs of Zion were the same we are not sure, nor which of these, nor whether any of ...', 'teologico');
add('sl', 88, 10, 'Matthew Henry', 'In these verses,\nI. The psalmist expostulates with God concerning the present deplorable condition he was in (Psa 88:10-12): "Wilt thou do a miraculous work to the dead, and raise them to life again? Shall those that are dead and buried rise up to praise thee? No; they leave it to their children to rise up in their room to praise God; none expects that they should do it; and wherefore should they rise, wherefore should they live, but to praise God? The life we are born to at first, and the li...', 'teologico');
add('sl', 89, 1, 'Matthew Henry', 'The psalmist has a very sad complaint to make of the deplorable condition of the family of David at this time, and yet he begins the psalm with songs of praise; for we must, in every thing, in every state, give thanks; thus we must glorify the Lord in the fire. We think, when we are in trouble, that we get ease by complaining; but we do more - we get joy, by praising. Let our complaints therefore be turned into thanksgivings; and in these verses we find that which will be matter of praise and...', 'teologico');
add('sl', 89, 5, 'Matthew Henry', 'These verses are full of the praises of God. Observe,\nI. Where, and by whom, God is to be praised. 1. God is praised by the angels above: The heavens shall praise thy wonders, O Lord! Psa 89:5; that is, "the glorious inhabitants of the upper world continually celebrate thy praises." Bless the Lord, you his angels, Psa 103:20. The works of God are wonders even to those that are best acquainted and most intimately conversant with them; the more God\'s works are known the more they are admired an...', 'teologico');
add('sl', 89, 15, 'Matthew Henry', 'The psalmist, having largely shown the blessedness of the God of Israel, here shows the blessedness of the Israel of God. As there is none like unto the God of Jeshurun, so, happy art thou, O Israel! there is none like unto thee, O people! especially as a type of the gospel-Israel, consisting of all true believers, whose happiness is here described.\nI. Glorious discoveries are made to them, and glad tidings of good brought to them; they hear, they know, the joyful sound, Psa 89:15. This may a...', 'teologico');
add('sl', 89, 19, 'Matthew Henry', 'The covenant God made with David and his seed was mentioned before (Psa 89:3, Psa 89:4); but in these verses it is enlarged upon, and pleaded with God, for favour to the royal family, now almost sunk and ruined; yet certainly it looks at Christ, and has its accomplishment in him much more than in David; nay, some passages here are scarcely applicable at all to David, but must be understood of Christ only (who is therefore called David our king, Hos 3:5), and very great and precious promises t...', 'teologico');
add('sl', 89, 38, 'Matthew Henry', 'In these verses we have,\nI. A very melancholy complaint of the present deplorable state of David\'s family, which the psalmist thinks hard to be reconciled to the covenant God made with David. "Thou saidst thou wouldst not take away thy lovingkindness, but thou hast cast off." Sometimes, it is no easy thing to reconcile God\'s providences with his promises, and yet we are sure they are reconcilable; for God\'s works fulfil his word and never contradict it. 1. David\'s house seemed to have lost it...', 'teologico');
add('sl', 90, 7, 'Matthew Henry', 'Moses had, in the foregoing verses, lamented the frailty of human life in general; the children of men are as a sleep and as the grass. But here he teaches the people of Israel to confess before God that righteous sentence of death which they were under in a special manner, and which by their sins they had brought upon themselves. Their share in the common lot of mortality was not enough, but they are, and must live and die, under peculiar tokens of God\'s displeasure. Here they speak of thems...', 'teologico');
add('sl', 90, 12, 'Matthew Henry', 'These are the petitions of this prayer, grounded upon the foregoing meditations and acknowledgments. Is any afflicted? Let him learn thus to pray. Four things they are here directed to pray for: - \nI. For a sanctified use of the sad dispensation they were now under. Being condemned to have our days shortened, "Lord, teach us to number our days (Psa 90:12); Lord, give us grace duly to consider how few they are, and how little a while we have to live in this world." Note, 1. It is an excellent ...', 'teologico');
add('sl', 91, 1, 'Matthew Henry', 'In these verses we have,\nI. A great truth laid down in general, That all those who live a life of communion with God are constantly safe under his protection, and may therefore preserve a holy serenity and security of mind at all times (Psa 91:1): He that dwells, that sits down, in the secret place of the Most High, shall abide under the shadow of the Almighty; he that by faith chooses God for his guardian shall find all that in him which he needs or can desire. Note, 1. It is the character o...', 'teologico');
add('sl', 91, 9, 'Matthew Henry', 'Here are more promises to the same purport with those in the foregoing verses, and they are exceedingly great and precious, and sure to all the seed.\nI. The psalmist assures believers of divine protection, from his own experience; and that which he says is the word of God, and what we may rely upon. Observe, 1. The character of those who shall have the benefit and comfort of these promises; it is much the same with that, Psa 91:1. They are such as make the Most High their habitation (Psa 91:9...', 'teologico');
add('sl', 92, 1, 'Matthew Henry', 'This psalm was appointed to be sung, at least it usually was sung, in the house of the sanctuary on the sabbath day, that day of rest, which was an instituted memorial of the work of creation, of God\'s rest from that work, and the continuance of it in his providence; for the Father worketh hitherto. Note, 1. The sabbath day must be a day, not only of holy rest, but of holy work, and the rest is in order to the work. 2. The proper work of the sabbath is praising God; every sabbath day must be ...', 'teologico');
add('sl', 92, 7, 'Matthew Henry', 'The psalmist had said (Psa 92:4) that from the works of God he would take occasion to triumph; and here he does so.\nI. He triumphs over God\'s enemies (Psa 92:7, Psa 92:9, Psa 92:11), triumphs in the foresight of their destruction, not as it would be the misery of his fellow-creatures, but as it would redound to the honour of God\'s justice and holiness. He is confident of the ruin of sinners, 1. Though they are flourishing (Psa 92:7): When the wicked spring as the grass in spring (so numerous,...', 'teologico');
add('sl', 93, 1, 'Matthew Henry', 'Next to the being of God there is nothing that we are more concerned to believe and consider than God\'s dominion, that Jehovah is God, and that this God reigns (Psa 93:1), not only that he is King of right, and is the owner and proprietor of all persons and things, but that he is King in fact, and does direct and dispose of all the creatures and all their actions according to the counsel of his own will. This is celebrated here, and in many other psalms: The Lord reigns. It is the song of the...', 'teologico');
add('sl', 94, 1, 'Matthew Henry', 'In these verses we have,\nI. A solemn appeal to God against the cruel oppressors of his people, Psa 94:1, Psa 94:2. This speaks terror enough to them, that they have the prayers of God\'s people against them, who cry day and night to him to avenge them of their adversaries; and shall he not avenge them speedily? Luk 18:3, Luk 18:7. Observe here,\n1. The titles they give to God for the encouraging of their faith in this appeal: O God! to whom vengeance belongeth; and thou Judge of the earth. We m...', 'teologico');
add('sl', 94, 12, 'Matthew Henry', 'The psalmist, having denounced tribulation to those that trouble God\'s people, here assures those that are troubled of rest. See Th2 1:6, Th2 1:7. He speaks comfort to suffering saints from God\'s promises and his own experience.\nI. From God\'s promises, which are such as not only save them from being miserable, but secure a happiness to them (Psa 94:12): Blessed is the man whom thou chastenest. Here he looks above the instruments of trouble, and eyes the hand of God, which gives it another nam...', 'teologico');
add('sl', 95, 1, 'Matthew Henry', 'The psalmist here, as often elsewhere, stirs up himself and others to praise God; for it is a duty which ought to be performed with the most lively affections, and which we have great need to be excited to, being very often backward to it and cold in it. Observe,\nI. How God is to be praised. 1. With holy joy and delight in him. The praising song must be a joyful noise, Psa 95:1 and again Psa 95:2. Spiritual joy is the heart and soul of thankful praise. It is the will of God (such is the conde...', 'teologico');
add('sl', 95, 7, 'Matthew Henry', 'The latter part of this psalm, which begins in the middle of a verse, is an exhortation to those who sing gospel psalms to live gospel lives, and to hear the voice of God\'s word; otherwise, how can they expect that he should hear the voice of their prayers and praises? Observe,\nI. The duty required of all those that are the people of Christ\'s pasture and the sheep of his hand. He expects that they hear his voice, for he has said, My sheep hear my voice, Joh 10:27. We are his people, say they....', 'teologico');
add('sl', 96, 1, 'Matthew Henry', 'These verses will be best expounded by pious and devout affections working in our souls towards God, with a high veneration for his majesty and transcendent excellency. The call here given us to praise God is very lively, the expressions are raised and repeated, to all which the echo of a thankful heart should make agreeable returns.\nI. We are here required to honour God,\n1. With songs, Psa 96:1, Psa 96:2. Three times we are here called to sing unto the Lord; sing to the Father, to the Son, t...', 'teologico');
add('sl', 96, 10, 'Matthew Henry', 'We have here instructions given to those who were to preach the gospel to the nations what to preach, or to those who had themselves received the gospel what account to give of it to their neighbours, what to say among the heathen; and it is an illustrious prophecy of the setting up of the kingdom of Christ upon the ruins of the devil\'s kingdom, which began immediately after his ascension and will continue in the doing till the mystery of God be finished.\nI. Let it be told that the Lord reign...', 'teologico');
add('sl', 97, 1, 'Matthew Henry', 'What was to be said among the heathen in the foregoing psalm (Psa 97:10) is here said again (Psa 97:1) and is made the subject of this psalm, and of psalm 99. The Lord reigns; that is the great truth here laid down. The Lord Jehovah reigns, he that made the world governs it; he that gave being gives motion and power, gives law and commission, gives success and event. Every man\'s judgment proceeds from the Lord, from his counsel and providence, and in all affairs, both public and private, he p...', 'teologico');
add('sl', 97, 8, 'Matthew Henry', 'The kingdom of the Messiah, like the pillar of cloud and fire, as it has a dark side towards the Egyptians, so it has a bright side towards the Israel of God. It is set up in spite of opposition; and then the earth saw and trembled (Psa 97:4), but Zion heard and was glad, very glad, to hear of the conversion of some and of the confusion of others, that is, the conquest of all that stood it out against Christ. Rejoice greatly, O daughter of Zion! for behold thy king comes unto thee, Zac 9:9. A...', 'teologico');
add('sl', 98, 1, 'Matthew Henry', 'We are here called upon again to sing unto the Lord a new song, as before, Psa 96:1. "Sing a most excellent song, the best song you have." Let the song of Christ\'s love be like Solomon\'s on that subject, a song of songs. A song of praise for redeeming love is a new song, such a song as had not been sung before; for this is a mystery which was hidden from ages and generations. Converts sing a new song, very different from what they had sung; they change their wonder and change their joy, and t...', 'teologico');
add('sl', 98, 4, 'Matthew Henry', 'The setting up of the kingdom of Christ is here represented as a matter of joy and praise.\nI. Let all the children of men rejoice in it, for they all have, or may have, benefit by it. Again and again we are here called upon by all ways and means possible to express our joy in it and give God praise for it: Make a joyful noise, as before, Psa 95:1, Psa 95:2. Make a loud noise, as those that are affected with those glad tidings and are desirous to affect others with them. Rejoice and sing prais...', 'teologico');
add('sl', 99, 1, 'Matthew Henry', 'The foundation of all religion is laid in this truth, That the Lord reigns. God governs the world by his providence, governs the church by his grace, and both by his Son. We are to believe not only that the Lord lives, but that the Lord reigns. This is the triumph of the Christian church, and here it was the triumph of the Jewish church, that Jehovah was their King; and hence it is inferred, Let the people tremble, that is, 1. Let even the subjects of this kingdom tremble; for the Old Testame...', 'teologico');
add('sl', 99, 6, 'Matthew Henry', 'The happiness of Israel in God\'s government is here further made out by some particular instances of his administration, especially with reference to those that were, in their day, the prime leaders and most active useful governors of that people - Moses, Aaron, and Samuel, in the two former of whom the theocracy or divine government began (for they were employed to form Israel into a people) and in the last of whom that form of government, in a great measure, ended; for when the people rejec...', 'teologico');
add('sl', 100, 1, 'Matthew Henry', 'Here, I. The exhortations to praise are very importunate. The psalm does indeed answer to the title, A psalm of praise; it begins with that call which of late we have several times met with (Psa 100:1), Make a joyful noise unto the Lord, all you lands, or all the earth, all the inhabitants of the earth. When all nations shall be discipled, and the gospel preached to every creature, then this summons will be fully answered to. But, if we take the foregoing psalm to be (as we have opened it) a ...', 'teologico');
add('sl', 101, 1, 'Matthew Henry', 'David here cuts out to himself and others a pattern both of a good magistrate and a good master of a family; and, if these were careful to discharge the duty of their place, it would contribute very much to a universal reformation. Observe,\nI. The chosen subject of the psalm (Psa 101:1): I will sing of mercy and judgment, that is,\n1. Of God\'s mercy and judgment, and then it looks back upon the dispensations of Providence concerning David since he was first anointed to be king, during which ti...', 'teologico');
add('sl', 102, 1, 'Matthew Henry', 'The title of this psalm is very observable; it is a prayer of the afflicted. It was composed by one that was himself afflicted, afflicted with the church and for it; and on those that are of a public spirit afflictions of that kind lie heavier than any other. It is calculated for an afflicted state, and is intended for the use of others that may be in the like distress; for whatsoever things were written aforetime were written designedly for our use. The whole word of God is of use to direct ...', 'teologico');
add('sl', 102, 12, 'Matthew Henry', 'Many exceedingly great and precious comforts are here thought of, and mustered up, to balance the foregoing complaints; for unto the upright there arises light in the darkness, so that, though they are cast down, they are not in despair. It is bad with the psalmist himself, bad with the people of God; but he has many considerations to revive himself with.\nI. We are dying creatures, and our interests and comforts are dying, but God is an everliving everlasting God (Psa 102:12): "My days are li...', 'teologico');
add('sl', 102, 23, 'Matthew Henry', 'We may here observe,\nI. The imminent danger that the Jewish church was in of being quite extirpated and cut off by the captivity in Babylon (Psa 102:23): He weakened my strength in the way. They were for many ages in the way to the performance of the great promise made to their fathers concerning the Messiah, longing as much for it as ever a traveller did to be at his journey\'s end. The legal institutions led them in the way; but when the ten tribes were lost in Assyria, and the two almost lo...', 'teologico');
add('sl', 103, 1, 'Matthew Henry', 'David is here communing with his own heart, and he is no fool that thus talks to himself and excites his own soul to that which is good. Observe,\nI. How he stirs up himself to the duty of praise, Psa 103:1, Psa 103:2. 1. It is the Lord that is to be blessed and spoken well of; for he is the fountain of all good, whatever are the channels or cisterns; it is to his name, his holy name, that we are to consecrate our praise, giving thanks at the remembrance of his holiness. 2. It is the soul that...', 'teologico');
add('sl', 103, 6, 'Matthew Henry', 'Hitherto the psalmist had only looked back upon his own experiences and thence fetched matter for praise; here he looks abroad and takes notice of his favour to others also; for in them we should rejoice and give thanks for them, all the saints being fed at a common table and sharing in the same blessings.\nI. Truly God is good to all (Psa 103:6): He executes righteousness and judgment, not only for his own people, but for all that are oppressed; for even in common providence he is the patron ...', 'teologico');
add('sl', 103, 19, 'Matthew Henry', 'Here is, I. The doctrine of universal providence laid down, Psa 103:19. He has secured the happiness of his peculiar people by promise and covenant, but the order of mankind, and the world in general, he secures by common providence. The Lord has a throne of his own, a throne of glory, a throne of government. He that made all rules all, and both by a word of power: He has prepared his throne, has fixed and established it that it cannot be shaken; he has afore-ordained all the measures of his ...', 'teologico');
add('sl', 104, 1, 'Matthew Henry', 'When we are addressing ourselves to any religious service we must stir up ourselves to take hold on God in it (Isa 64:7); so David does here. "Come, my soul, where art thou? What art thou thinking of? Here is work to be done, good work, angels\' work; set about it in good earnest; let all the powers and faculties be engaged and employed in it: Bless the Lord, O my soul!" In these verses,\nI. The psalmist looks up to the divine glory shining in the upper world, of which, though it is one of the ...', 'teologico');
add('sl', 104, 10, 'Matthew Henry', 'Having given glory to God as the powerful protector of this earth, in saving it from being deluged, here he comes to acknowledge him as its bountiful benefactor, who provides conveniences for all the creatures.\nI. He provides fresh water for their drink: He sends the springs into the valleys, Psa 104:10. There is water enough indeed in the sea, that is, enough to drown us, but not one drop to refresh us, be we ever so thirsty - it is all so salt; and therefore God has graciously provided wate...', 'teologico');
add('sl', 104, 19, 'Matthew Henry', 'We are here taught to praise and magnify God,\nI. For the constant revolutions and succession of day and night, and the dominion of sun and moon over them. The heathen were so affected with the light and influence of the sun and moon, and their serviceableness to the earth, that they worshipped them as deities; and therefore the scripture takes all occasions to show that the gods they worshipped are the creatures and servants of the true God (Psa 104:19): He appointed the moon for seasons, for...', 'teologico');
add('sl', 104, 31, 'Matthew Henry', 'The psalmist concludes this meditation with speaking,\nI. Praise to God, which is chiefly intended in the psalm.\n1. He is to be praised, (1.) As a great God, and a God of matchless perfection: The glory of the Lord shall endure for ever, Psa 104:31. It shall endure to the end of time in his works of creation and providence; it shall endure to eternity in the felicity and adorations of saints and angels. Man\'s glory is fading; God\'s glory is everlasting. Creatures change, but with the Creator t...', 'teologico');
add('sl', 105, 1, 'Matthew Henry', 'Our devotion is here warmly excited; and we are stirred up, that we may stir up ourselves to praise God. Observe,\nI. The duties to which we are here called, and they are many, but the tendency of them all is to give unto God the glory due unto his name. 1. We must give thanks to him, as one who has always been our bountiful benefactor and requires only that we give him thanks for his favours - poor returns for rich receivings. 2. Call upon his name, as one whom you depend upon for further fav...', 'teologico');
add('sl', 105, 8, 'Matthew Henry', 'We are here taught, in praising God, to look a great way back, and to give him the glory of what he did for his church in former ages, especially when it was in the founding and forming, which those in its latter ages enjoy the benefit of and therefore should give thanks for. Doubtless we may fetch as proper matter for praise from the histories of the gospels, and the acts of the apostles, which relate the birth of the Christian church, as the psalmist here does from the histories of Genesis ...', 'teologico');
add('sl', 105, 25, 'Matthew Henry', 'After the history of the patriarchs follows here the history of the people of Israel, when they grew into a nation.\nI. Their affliction in Egypt (Psa 105:25): He turned the heart of the Egyptians, who had protected them, to hate them and deal subtilely with them. God\'s goodness to his people exasperated the Egyptians against them; and, though their old antipathy to the Hebrews (which we read of Gen 43:32; Gen 46:34) was laid asleep for a while, yet now it revived with more violence than ever:...', 'teologico');
add('sl', 106, 1, 'Matthew Henry', 'We are here taught,\nI. To bless God (Psa 106:1, Psa 106:2): Praise you the Lord, that is, 1. Give him thanks for his goodness, the manifestation of it to us, and the many instances of it. He is good and his mercy endures for ever; let us therefore own our obligations to him and make him a return of our best affections and services. 2. Give him the glory of his greatness, his mighty acts, proofs of his almighty power, wherein he has done great things, and such as would be opposed. Who can utte...', 'teologico');
add('sl', 106, 6, 'Matthew Henry', 'Here begins a penitential confession of sin, which was in a special manner seasonable now that the church was in distress; for thus we must justify God in all that he brings upon us, acknowledging that therefore he has done right, because we have done wickedly; and the remembrance of former sins, notwithstanding which God did not cast off his people, is an encouragement to us to hope that, though we are justly corrected for our sins, yet we shall not be utterly abandoned.\nI. God\'s afflicted p...', 'teologico');
add('sl', 106, 13, 'Matthew Henry', 'This is an abridgment of the history of Israel\'s provocations in the wilderness, and of the wrath of God against them for those provocations: and this abridgment is abridged by the apostle, with application to us Christians (Co1 10:5, etc.); for these things were written for our admonition, that we sin not like them, lest we suffer like them.\nI. The cause of their sin was disregard to the works and word of God, Psa 106:13. 1. They minded not what he had done for them: They soon forgot his wor...', 'teologico');
add('sl', 106, 34, 'Matthew Henry', 'Here, I. The narrative concludes with an account of Israel\'s conduct in Canaan, which was of a piece with that in the wilderness, and God\'s dealings with them, wherein, as all along, both justice and mercy appeared.\n1. They were very provoking to God. The miracles and mercies which settled them in Canaan made no more deep and durable impressions upon them than those which fetched them out of Egypt; for by the time they were just settled in Canaan they corrupted themselves, and forsook God. Ob...', 'teologico');
add('sl', 107, 1, 'Matthew Henry', 'Here is, I. A general call to all to give thanks to God, Psa 107:1. Let all that sing this psalm, or pray over it, set themselves herein to give thanks to the Lord; and those that have not any special matter for praise may furnish themselves with matter enough from God\'s universal goodness. In the fountain he is good; in the streams his mercy endures for ever and never fails.\nII. A particular demand hereof from the redeemed of the Lord, which may well be applied spiritually to those that have...', 'teologico');
add('sl', 107, 10, 'Matthew Henry', 'We are to take notice of the goodness of God towards prisoners and captives. Observe, 1. A description of this affliction. Prisoners are said to sit in darkness (Psa 107:10), in dark dungeons, close prisons, which intimates that they are desolate and disconsolate; they sit in the shadow of death, which intimates not only great distress and trouble, but great danger. Prisoners are many times appointed to die; they sit despairing to get out, but resolving to make the best of it. They are bound ...', 'teologico');
add('sl', 107, 17, 'Matthew Henry', 'Bodily sickness is another of the calamities of this life which gives us an opportunity of experiencing the goodness of God in recovering us, and of that the psalmist speaks in these verses, where we may observe,\nI. That we, by our sins, bring sickness upon ourselves and then it is our duty to pray, Psa 107:17-19. 1. It is the sin of the soul that is the cause of sickness; we bring it upon ourselves both meritoriously and efficiently: Fools, because of their transgression, are thus afflicted;...', 'teologico');
add('sl', 107, 23, 'Matthew Henry', 'The psalmist here calls upon those to give glory to God who are delivered from dangers at sea. Though the Israelites dealt not much in merchandise, yet their neighbours the Tyrians and Zidonians did, and for them perhaps this part of the psalm was especially calculated.\nI. Much of the power of God appears at all times in the sea, Psa 107:23, Psa 107:24. It appears to those that go down to the sea in ships, as mariners, merchants, fishermen, or passengers, that do business in great waters. And...', 'teologico');
add('sl', 107, 33, 'Matthew Henry', 'The psalmist, having given God the glory of the providential reliefs granted to persons in distress, here gives him the glory of the revolutions of providence, and the surprising changes it sometimes makes in the affairs of the children of men.\nI. He gives some instances of these revolutions.\n1. Fruitful countries are made barren and barren countries are made fruitful. Much of the comfort of this life depends upon the soil in which our lot is cast. Now, (1.) The sin of man has often marred th...', 'teologico');
add('sl', 108, 1, 'Matthew Henry', 'We may here learn how to praise God from the example of one who was master of the art. 1. We must praise God with fixedness of heart. Our heart must be employed in the duty (else we make nothing of it) and engaged to the duty (Psa 108:1): O God! my heart is fixed, and then I will sing and give praise. Wandering straggling thoughts must be gathered in, and kept close to the business; for they must be told that here is work enough for them all. 2. We must praise God with freeness of expression:...', 'teologico');
add('sl', 108, 6, 'Matthew Henry', 'We may here learn how to pray as well as praise. 1. We must be public-spirited in prayer, and bear upon our hearts, at the throne of grace, the concerns of the church of God, Psa 108:6. It is God\'s beloved, and therefore must be ours; and therefore we must pray for its deliverance, and reckon that we are answered if God grant what we ask for his church, though he delay to give us what we ask for ourselves. "Save thy church, and thou answerest me; I have what I would have." Let the earth be fi...', 'teologico');
add('sl', 109, 1, 'Matthew Henry', 'It is the unspeakable comfort of all good people that, whoever is against them, God is for them, and to him they may apply as to one that is pleased to concern himself for them. Thus David here.\nI. He refers himself to God\'s judgment (Psa 109:1): "Hold not thy peace, but let my sentence come forth from thy presence, Psa 17:2. Delay not to give judgment upon the appeal made to thee." God saw what his enemies did against him, but seemed to connive at it, and to keep silence: "Lord," says he, "d...', 'teologico');
add('sl', 109, 6, 'Matthew Henry', 'David here fastens upon some one particular person that was worse than the rest of his enemies, and the ringleader of them, and in a devout and pious manner, not from a principle of malice and revenge, but in a holy zeal for God and against sin and with an eye to the enemies of Christ, particularly Judas who betrayed him, whose sin was greater than Pilate\'s that condemned him (Joh 19:11), he imprecates and predicts his destruction, foresees and pronounces him completely miserable, and such a ...', 'teologico');
add('sl', 109, 21, 'Matthew Henry', 'David, having denounced God\'s wrath against his enemies, here takes God\'s comforts to himself, but in a very humble manner, and without boasting.\nI. He pours out his complaint before God concerning the low condition he was in, which, probably, gave advantage to his enemies to insult over him: "I am poor and needy, and therefore a proper object of pity, and one that needs and craves thy help." 1. He was troubled in mind (Psa 109:22): My heart is wounded within me, not only broken with outward ...', 'teologico');
add('sl', 110, 5, 'Matthew Henry', 'Here we have our great Redeemer,\nI. Conquering his enemies (Psa 110:5, Psa 110:6) in order to the making of them his footstool, Psa 110:1. Our Lord Jesus will certainly bring to nought all the opposition made to his kingdom, and bring to ruin all those who make that opposition and persist in it. He will be too hard for those, whoever they may be, that fight against him, against his subjects and the interest of his kingdom among men, either by persecutions or by perverse disputings. Observe he...', 'teologico');
add('sl', 111, 1, 'Matthew Henry', 'The title of the psalm being Hallelujah, the psalmist (as every author ought to have) has an eye to his title, and keeps to his text.\nI. He resolves to praise God himself, Psa 111:1. What duty we call others to we must oblige and excite ourselves to; nay, whatever others do, whether they will praise God or no, we and our houses must determine to do it, we and our hearts; for such is the psalmist\'s resolution here: I will praise the Lord with my whole heart. My heart, my whole heart, being dev...', 'teologico');
add('sl', 111, 6, 'Matthew Henry', 'We are here taught to give glory to God,\nI. For the great things he has done for his people, for his people Israel, of old and of late: He has shown his people the power of his works (Psa 111:6), in what he has wrought for them; many a time he has given proofs of his omnipotence, and shown them what he can do, and that there is nothing too hard for him to do. Two things are specified to show the power of his works: - 1. The possession God gave to Israel in the land of Canaan, that he might gi...', 'teologico');
add('sl', 112, 1, 'Matthew Henry', 'The psalmist begins with a call to us to praise God, but immediately applies himself to praise the people of God; for whatever glory is acknowledged to be on them it comes from God, and must return to him; as he is their praise, so they are his. We have reason to praise the Lord that there are a people in the world who fear him and serve him, and that they are a happy people, both which are owing entirely to the grace of God. Now here we have,\nI. A description of those who are here pronounced...', 'teologico');
add('sl', 112, 6, 'Matthew Henry', 'In these verses we have,\nI. The satisfaction of saints, and their stability. It is the happiness of a good man that he shall not be moved for ever, Psa 112:6. Satan and his instruments endeavour to move him, but his foundation is firm and he shall never be moved, at least not moved for ever; if he be shaken for a time, yet he settles again quickly.\n1. A good man will have a settled reputation, and that is a great satisfaction. A good man shall have a good name, a name for good things, with Go...', 'teologico');
add('sl', 113, 1, 'Matthew Henry', 'In this psalm,\nI. We are extorted to give glory to God, to give him the glory due to his name.\n1. The invitation is very pressing: praise you the Lord, and again and again, Praise him, praise him; blessed be his name, for it is to be praised, Psa 113:1-3. This intimates, (1.) That it is a necessary and most excellent duty, greatly pleasing to God, and has a large room in religion. (2.) That it is a duty we should much abound in, in which we should be frequently employed and greatly enlarged. ...', 'teologico');
add('sl', 114, 1, 'Matthew Henry', 'The psalmist is here remembering the days of old, the years of the right hand of the Most High, and the wonders which their fathers told them of (Jdg 6:13), for time, as it does not wear out the guilt of sin, so it should not wear out the sense of mercy. Let it never be forgotten,\nI. That God brought Israel out of the house of bondage with a high hand and a stretched-out arm: Israel went out of Egypt, Psa 114:1. They did not steal out clandestinely, nor were they driven out, but fairly went o...', 'teologico');
add('sl', 115, 1, 'Matthew Henry', 'Sufficient care is here taken to answer both the pretensions of self and the reproaches of idolaters.\nI. Boasting is here for ever excluded, Psa 115:1. Let no opinion of our own merits have any room either in our prayers or in our praises, but let both centre in God\'s glory. 1. Have we received any mercy, gone through any service, or gained any success? We must not assume the glory of it to ourselves, but ascribe it wholly to God. We must not imagine that we do any thing for God by our own st...', 'teologico');
add('sl', 115, 9, 'Matthew Henry', 'In these verses,\nI. We are earnestly exhorted, all of us, to repose our confidence in God, and not suffer our confidence in him to be shaken by the heathens\' insulting over us upon the account of our present distresses. It is folly to trust in dead images, but it is wisdom to trust in the living God, for he is a help and a shield to those that do trust in them, a help to furnish them with and forward them in that which is good, and a shield to fortify them against and protect them from every ...', 'teologico');
add('sl', 116, 1, 'Matthew Henry', 'In this part of the psalm we have,\nI. A general account of David\'s experience, and his pious resolutions (Psa 116:1, Psa 116:2), which are as the contents of the whole psalm, and give an idea of it. 1. He had experienced God\'s goodness to him in answer to prayer: He has heard my voice and my supplications. David, in straits, had humbly and earnestly begged mercy of God, and God had heard him, that is, had graciously accepted his prayer, taken cognizance of his case, and granted him an answer ...', 'teologico');
add('sl', 116, 10, 'Matthew Henry', 'The Septuagint and some other ancient versions make these verses a distinct psalm separate from the former; and some have called it the Martyr\'s psalm, I suppose for the sake of Psa 116:15. Three things David here makes confession of: - \nI. His faith (Psa 116:10): I believed, therefore have I spoken. This is quoted by the apostle (Co2 4:13) with application to himself and his fellow-ministers, who, though they suffered for Christ, were not ashamed to own him. David believed the being, provide...', 'teologico');
add('sl', 117, 1, 'Matthew Henry', 'There is a great deal of gospel in this psalm. The apostle has furnished us with a key to it (Rom 15:11), where he quotes it as a proof that the gospel was to be preached to, and would be entertained by, the Gentile nations, which yet was so great a stumbling-block to the Jews. Why should that offend them when it is said, and they themselves had often sung it, Praise the Lord, all you Gentiles, and laud him, all you people. Some of the Jewish writers confess that this psalm refers to the king...', 'teologico');
add('sl', 118, 1, 'Matthew Henry', 'It appears here, as often as elsewhere, that David had his heart full of the goodness of God. He loved to think of it, loved to speak of it, and was very solicitous that God might have the praise of it and others the comfort of it. The more our hearts are impressed with a sense of God\'s goodness the more they will be enlarged in all manner of obedience. In these verses,\nI. He celebrates God\'s mercy in general, and calls upon others to acknowledge it, from their own experience of it (Psa 118:1...', 'teologico');
add('sl', 118, 19, 'Matthew Henry', 'We have here an illustrious prophecy of the humiliation and exaltation of our Lord Jesus, his sufferings, and the glory that should follow. Peter thus applies it directly to the chief priests and scribes, and none of them could charge him with misapplying it, Act 4:11. Now observe here,\nI. The preface with which this precious prophecy is introduced, Psa 118:19-21. 1. The psalmist desires admission into the sanctuary of God, there to celebrate the glory of him that cometh in the name of the Lo...', 'teologico');
add('sl', 119, 1, 'Matthew Henry', 'The psalmist here shows that godly people are happy people; they are, and shall be, blessed indeed. Felicity is the thing we all pretend to aim at and pursue. He does not say here wherein it consists; it is enough for us to know what we must do and be that we may attain to it, and that we are here told. All men would be happy, but few take the right way; God has here laid before us the right way, which we may be sure will end in happiness, though it be strait and narrow. Blessednesses are to ...', 'teologico');
add('sl', 119, 4, 'Matthew Henry', 'We are here taught, 1. To own ourselves under the highest obligations to walk in God\'s law. The tempter would possess men with an opinion that they are at their liberty whether they will make the word of God their rule or no, that, though it may be good, yet it is not so necessary as they are made to believe it is. He taught our first parents to question the command: Hath God said, You shall not eat? And therefore we are concerned to be well established in this (Psa 119:4): Thou hast commande...', 'teologico');
add('sl', 119, 7, 'Matthew Henry', 'Here is, I. David\'s endeavour to perfect himself in his religion, and to make himself (as we say) master of his business. He hopes to learn God\'s righteous judgments. He knew much, but he was still pressing forward and desired to know more, as knowing this, that he had not yet attained; but as far as perfection is attainable in this life he reached towards it, and would not take up short of it. As long as we live we must be scholars in Christ\'s school, and sit at his feet; but we should aim t...', 'teologico');
add('sl', 119, 9, 'Matthew Henry', 'Here is, 1. A weighty question asked. By what means may the next generation be made better than this? Wherewithal shall a young man cleanse his way? Cleansing implies that it is polluted. Besides the original corruption we all brought into the world with us (from which we are not cleansed unto this day), there are many particular sins which young people are subject to, by which they defile their way, youthful lusts (Ti2 2:22); these render their way offensive to God and disgraceful to themsel...', 'teologico');
add('sl', 119, 10, 'Matthew Henry', 'Here is, 1. David\'s experience of a good work God had wrought in him, which he takes the comfort of and pleads with God: "I have sought thee, sought to thee as my oracle, sought after thee as my happiness, sought thee as my God; for should not a people seek unto their God? If I have not yet found thee, I have sought thee, and thou never saidst, Seek in vain, nor wilt say so to me, for I have sought thee with my heart, with my whole heart, sought thee only, sought thee diligently." 2. His pray...', 'teologico');
add('sl', 119, 11, 'Matthew Henry', 'Here is, 1. The close application which David made of the word of God to himself: He hid it in his heart, laid it up there, that it might be ready to him whenever he had occasion to use it; he laid it up as that which he valued highly, and had a warm regard for, and which he was afraid of losing and being robbed of. God\'s word is a treasure worth laying up, and there is no laying it up safely but in our hearts; if we have it only in our houses and hands, enemies may take it from us; if only i...', 'teologico');
add('sl', 119, 12, 'Matthew Henry', 'Here, 1. David gives glory to God: "Blessed art thou, O Lord! Thou art infinitely happy in the enjoyment of thyself and hast no need of me or my services; yet thou art pleased to reckon thyself honoured by them; assist me therefore, and then accept me." In all our prayers we should intermix praises. 2. He asks grace from God: "Teach me thy statutes; give me to know and do my duty in every thing. Thou art the fountain of all blessedness; O let me have this drop from that fountain, this blessin...', 'teologico');
add('sl', 119, 13, 'Matthew Henry', 'Here, I. David looks back with comfort upon the respect he had paid to the word of God. He had the testimony of his conscience for him, 1. That he had edified others with what he had been taught out of the word of God (Psa 119:13): With my lips have I declared all the judgments of thy mouth. This he did, not only as a king in making orders, and giving judgment, according to the word of God, nor only as a prophet by his psalms, but in his common discourse. Thus he showed how full he was of the...', 'teologico');
add('sl', 119, 17, 'Matthew Henry', 'We are here taught, 1. That we owe our lives to God\'s mercy. David prays, Deal bountifully with me, that I may live. It was God\'s bounty that gave us life, that gave us this life; and the same bounty that gave it continues it, and gives all the supports and comforts of it; if these be withheld, we die, or, which is equivalent, our lives are embittered and we become weary of them. If God deals in strict justice with us, we die, we perish, we all perish; if these forfeited lives be preserved an...', 'teologico');
add('sl', 119, 18, 'Matthew Henry', 'Observe here, 1. That there are wondrous things in God\'s law, which we are all concerned, and should covet, to behold, not only strange things, which are very surprising and unexpected, but excellent things, which are to be highly esteemed and valued, and things which were long hidden from the wise and prudent, but are now revealed unto babes. If there were wonders in the law, much more in the gospel, where Christ is all in all, whose name is Wonderful. Well may we, who are so nearly interest...', 'teologico');
add('sl', 119, 19, 'Matthew Henry', 'Here we have, 1. The acknowledgment which David makes of his own condition: I am a stranger in the earth. We all are so, and all good people confess themselves to be so; for heaven is their home, and the world is but their inn, the land of their pilgrimage. David was a man that knew as much of the world, and was as well known in it, as most men. God built him a house, established his throne; strangers submitted to him, and people that he had not known served him; he had a name like the names ...', 'teologico');
add('sl', 119, 20, 'Matthew Henry', 'David had prayed that God would open his eyes (Psa 119:18) and open the law (Psa 119:19); now here he pleads the earnestness of his desire for knowledge and grace, for it is the fervent prayer that avails much. 1. His desire was importunate: My soul breaketh for the longing it hath to thy judgments, or (as some read it) "It is taken up, and wholly employed, in longing for thy judgments; the whole stream of its desires runs in this channel. I shall think myself quite broken and undone if I wan...', 'teologico');
add('sl', 119, 21, 'Matthew Henry', 'Here is, 1. The wretched character of wicked people. The temper of their minds is bad. They are proud; they magnify themselves above others. And yet that is not all: they magnify themselves against God, and set up their wills in competition with and opposition to the will of God, as if their hearts, and tongues, and all, were their own. There is something of pride at the bottom of every wilful sin, and the tenour of their lives is no better: They do err from thy commandments, as Israel, that ...', 'teologico');
add('sl', 119, 22, 'Matthew Henry', 'Here, 1. David prays against the reproach and contempt of men, that they might be removed, or (as the word is) rolled, from off him. This intimates that they lay upon him, and that neither his greatness nor his goodness could secure him from being libelled and lampooned. Some despised him and endeavoured to make him mean; others reproached him and endeavoured to make him odious. It has often been the lot of those that do well to be ill-spoken of. It intimates that they lay heavily upon him. H...', 'teologico');
add('sl', 119, 23, 'Matthew Henry', 'See here, 1. How David was abused even by great men, who should have known better his character and his case, and have been more generous: Princes did sit, sit in council, sit in judgment, and speak against me. What even princes say is not always right; but it is sad when judgment is thus turned to wormwood, when those that should be the protectors of the innocent are their betrayers. Herein David was a type of Christ, for they were the princes of this world that vilified and crucified the Lo...', 'teologico');
add('sl', 119, 24, 'Matthew Henry', 'Here David explains his meditating in God\'s statutes (Psa 119:23), which was of such use to him when princes sat and spoke against him. 1. Did the affliction make his sad? The word of God comforted him, and was his delight, more his delight than any of the pleasures either of court or camp, of city or country. Sometimes it proves that the comforts of the word of God are most pleasant to a gracious soul when other comforts are embittered. 2. Did it perplex him? Was he at a loss what to do when...', 'teologico');
add('sl', 119, 25, 'Matthew Henry', 'Here is, I. David\'s complaint. We should have thought his soul soaring to heaven; but he says himself, My soul not only rolls in the dust, but cleaves to the dust, which is a complaint either, 1. Of his corruptions, his inclination to the world and the body (both which are dust), and that which follows upon it, a deadness to holy duties. When he would do good evil was present with him. God intimated that Adam was not only mortal, but sinful, when he said, Dust thou art, Gen 3:19. David\'s comp...', 'teologico');
add('sl', 119, 26, 'Matthew Henry', 'We have here, 1. The great intimacy and freedom that had been between David and his God. David had opened his case, opened his very heart to God: "I have declared my ways, and acknowledged thee in them all, have taken thee along with me in all my designs and enterprises." Thus Jephthah uttered all his words, and Hezekiah spread his letters, before the Lord. "I have declared my ways, my wants, and burdens, and troubles, that I meet with in my way, or my sins, my by-ways (I have made an ingenuo...', 'teologico');
add('sl', 119, 28, 'Matthew Henry', 'Here is, 1. David\'s representation of his own griefs: My soul melteth for heaviness, which is to the same purport with Psa 119:25, My soul cleaveth to the dust. Heaviness in the heart of man makes it to melt, to drop away like a candle that wastes. The penitent soul melts in sorrow for sin, and even the patient soul may melt in the sense of affliction, and it is then its interest to pour out its supplication before God. 2. His request for God\'s grace. (1.) That God would enable him to bear hi...', 'teologico');
add('sl', 119, 30, 'Matthew Henry', 'Observe, I. That those who will make anything to purpose of their religion must first make it their serious and deliberate choice; so David did: I have chosen the way of truth. Note, 1. The way of serious godliness is the way of truth; the principles it is founded on are principles of eternal truth, and it is the only true way to happiness. 2. We must choose to walk in this way, not because we know no other way, but because we know no better; nay we know no other safe and good way. Let us cho...', 'teologico');
add('sl', 119, 33, 'Matthew Henry', 'Here, I. David prays earnestly that God himself would be his teacher; he had prophets, and wise men, and priests, about him, and was himself well instructed in the law of God, yet he begs to be taught of God, as knowing that none teaches like him, Job 36:22. Observe here, 1. What he desires to be taught, not the notions or language of God\'s statutes, but the way of them - "the way of applying them to myself and governing myself by them; teach me the way of my duty which thy statutes prescribe...', 'teologico');
add('sl', 119, 35, 'Matthew Henry', 'He had before prayed to God to enlighten his understanding, that he might know his duty, and not mistake concerning it; here he prays to God to bow his will, and quicken the active powers of his soul, that he might do his duty; for it is God that works in us both to will and to do, as well as to understand, what is good, Phi 2:13. Both the good head and the good heart are from the good grace of God, and both are necessary to every good work. Observe here,\nI. The grace he prays for. 1. That Go...', 'teologico');
add('sl', 119, 37, 'Matthew Henry', 'Here, 1. David prays for restraining grace, that he might be prevented and kept back from that which would hinder him in the way of his duty: Turn away my eyes from beholding vanity. The honours, pleasures, and profits of the world are the vanities, the aspect and prospect of which draw multitudes away from the paths of religion and godliness. The eye, when fastened on these, infects the heart with the love of them, and so it is alienated from God and divine things; and therefore, as we ought...', 'teologico');
add('sl', 119, 38, 'Matthew Henry', 'Here is 1. The character of a good man, which is the work of God\'s grace in him; he is God\'s servant, subject to his law and employed in his work, that is, devoted to his fear, given up to his direction and disposal, and taken up with high thoughts of him and all those acts of devotion which have a tendency to his glory. Those are truly God\'s servants who, though they have their infirmities and defects, are sincerely devoted to the fear of God and have all their affections and motions governe...', 'teologico');
add('sl', 119, 39, 'Matthew Henry', 'Here, 1. David prays against reproach, as before, Psa 119:22. David was conscious to himself that he had done that which might give occasion to the enemies of the Lord to blaspheme, which would blemish his own reputation and turn to the dishonour of his family; now he prays that God, who has all men\'s hearts and tongues in his hands, would be pleased to prevent this, to deliver him from all his transgressions, that he might not be the reproach of the foolish, which he feared (Psa 39:8); or he...', 'teologico');
add('sl', 119, 40, 'Matthew Henry', 'Here, 1. David professes the ardent affection he had to the word of God: "I have longed after thy precepts, not only loved them, and delighted in what I have already attained, but I have earnestly desired to know them more and do them better, and am still pressing forward towards perfection." Tastes of the sweetness of God\'s precepts will but set us a longing after a more intimate acquaintance with them. He appeals to God concerning this passionate desire after his precepts: "Behold, I have t...', 'teologico');
add('sl', 119, 41, 'Matthew Henry', 'Here is, 1. David\'s prayer for the salvation of the Lord. "Lord, thou art my Saviour; I am miserable in myself, and thou only canst make me happy; let thy salvation come to me. Hasten temporal salvation to me from my present distresses, and hasten me to the eternal salvation, by giving me the necessary qualifications for it and the comfortable pledges and foretastes of it." 2. David\'s dependence upon the grace and promise of God for that salvation. These are the two pillars on which our hope ...', 'teologico');
add('sl', 119, 43, 'Matthew Henry', 'Here is, 1. David\'s humble petition for the tongue of the learned, that he might know how to speak a word in season for the glory of God: Take not the word of truth utterly out of my mouth. He means, "Lord, let the word of truth be always in my mouth; let me have the wisdom and courage which are necessary to enable me both to use my knowledge for the instruction of others, and, like the good householder, to bring out of my treasury things new and old, and to make profession of my faith whenev...', 'teologico');
add('sl', 119, 45, 'Matthew Henry', 'We may observe in these verses, 1. What David experienced of an affection to the law of God: "I seek thy precepts, Psa 119:45. I desire to know and do my duty, and consult thy word accordingly; I do all I can to understand what the will of the Lord is and to discover the intimations of his mind. I seek thy precepts, for I have loved them, Psa 119:47, Psa 119:48. I not only give consent to them as good, but take complacency in them as good for me." All that love God love his government and the...', 'teologico');
add('sl', 119, 49, 'Matthew Henry', 'Two things David here pleads with God in prayer for that mercy and grace which he hoped for, according to the word, by which his requests were guided: - 1. That God had given him the promise on which he hoped: "Lord, I desire no more than that thou wouldst remember thy word unto thy servant, and do as thou hast said;" see Ch1 17:23. "Thou art wise, and therefore wilt perfect what thou hast purposed, and not change thy counsel. Thou art faithful, and therefore wilt perform what thou hast promi...', 'teologico');
add('sl', 119, 50, 'Matthew Henry', 'Here is David\'s experience of benefit by the word. 1. As a means of his sanctification: "Thy word has quickened me. It made me alive when I was dead in sin; it has many a time made me lively when I was dead in duty; it has quickened me to that which is good when I was backward and averse to it, and it has quickened me in that which is good when I was cold and indifferent." 2. Therefore as a means of his consolation when he was in affliction and needed something to support him: "Because thy wo...', 'teologico');
add('sl', 119, 51, 'Matthew Henry', 'David here tells us, and it will be of use to us to know it, 1. That he had been jeered for his religion. Though he was a man of honour, a man of great prudence, and had done eminent services to his country, yet, because he was a devout conscientious man, the proud had him greatly in derision; they ridiculed him, bantered him, and did all they could to expose him to contempt; they laughed at him for his praying, and called it cant, for his seriousness, and called it mopishness, for his strict...', 'teologico');
add('sl', 119, 52, 'Matthew Henry', 'When David was derided for his godliness he not only held fast his integrity, but, 1. He comforted himself. He not only bore reproach, but bore it cheerfully. It did not disturb his peace, nor break in upon the repose of his spirit in God. It was a comfort to him to think that it was for God\'s sake that he bore reproach, and that his worst enemies could find no occasion against him, save only in the matter of his God, Dan 6:5. Those that are derided for their adherence to God\'s law may comfor...', 'teologico');
add('sl', 119, 53, 'Matthew Henry', 'Here is, 1. The character of wicked people; he means those that are openly and grossly wicked: They forsake thy law. Every sin is a transgression of the law, but a course and way of wilful and avowed sin is downright forsaking it and throwing it off. 2. The impression which the wickedness of the wicked made upon David; it frightened him, it put him into an amazement. He trembled to think of the dishonour thereby done to God, the gratification thereby given to Satan, and the mischiefs thereby ...', 'teologico');
add('sl', 119, 54, 'Matthew Henry', 'Here is, 1. David\'s state and condition; he was in the house of his pilgrimage, which may be understood either as his peculiar trouble (he was often tossed and hurried, and forced to fly) or as his lot in common with all. This world is the house of our pilgrimage, the house in which we are pilgrims; it is our tabernacle; it is our inn. We must confess ourselves strangers and pilgrims upon earth, who are not at home here, nor must be here long. Even David\'s palace is but the house of his pilgr...', 'teologico');
add('sl', 119, 55, 'Matthew Henry', 'Here is, 1. The converse David had with the word of God; he kept it in mind, and upon every occasion he called it to mind. God\'s name is the discovery he has made of himself to us in and by his word. This is his memorial unto all generations, and therefore we should always keep it in memory - remember it in the night, upon a waking bed, when we are communing with our own hearts. When others were sleeping David was remembering God\'s name, and, by repeating that lesson, increasing his acquainta...', 'teologico');
add('sl', 119, 57, 'Matthew Henry', 'We may hence gather the character of a godly man. 1. He makes the favour of God his felicity: Thou art my portion, O Lord! Others place their happiness in the wealth and honours of this world. Their portion is in this life; they look no further; they desire no more; these are their good things, Luk 16:25. But all that are sanctified take the Lord for the portion of their inheritance and their cup, and nothing less will satisfy them. David can appeal to God in this matter: "Lord, thou knowest ...', 'teologico');
add('sl', 119, 58, 'Matthew Henry', 'David, having in the foregoing verse reflected upon his covenants with God, here reflects upon his prayers to God, and renews his petition. Observe, 1. What he prayed for. Having taken God for his portion, he entreated his favour, as one that knew he had forfeited it, was unworthy of it, and yet undone without it, but for ever happy if he could obtain it. We cannot demand God\'s favour as a debt, but must be humble suppliants for it, that God will not only be reconciled to us, but accept us an...', 'teologico');
add('sl', 119, 59, 'Matthew Henry', 'David had said he would keep God\'s word (Psa 119:57), and it was well said; now here he tells us how and in what method he pursued that resolution. 1. He thought on his ways. He thought beforehand what he should do, pondering the path of his feet (Pro 4:26), that he might walk surely, and not at all adventures. He thought after what he had done, reflected upon his life past, and recollected the paths he had walked in and the steps he had taken. The word signifies a fixed abiding thought. Some...', 'teologico');
add('sl', 119, 61, 'Matthew Henry', 'Here is, 1. The malice of David\'s enemies against him. They were wicked men, who hated him for his godliness. There were bands or troops of them confederate against him. They did him all the mischief they could; they robbed him; having endeavoured to take away his good name (Psa 119:51), they set upon his goods, and spoiled him of them, either by plunder in time of war or by fines and confiscations under colour of law. Saul (it is likely) seized his effects, Absalom his palace, and the Amalek...', 'teologico');
add('sl', 119, 62, 'Matthew Henry', 'Though David is, in this psalm, much in prayer, yet he did not neglect the duty of thanksgiving; for those that pray much will have much to give thanks for. See, 1. How much God\'s hand was eyed in his thanksgivings. He does not say, "I will give thanks because of thy favours to me, which I have the comfort of," but, "Because of thy righteous judgments, all the disposals of thy providence in wisdom and equity, which thou hast the glory of." We must give thanks for the asserting of God\'s honour...', 'teologico');
add('sl', 119, 63, 'Matthew Henry', 'David had often expressed the great love he had to God; here he expresses the great love he had to the people of God; and observe, 1. Why he loved them; not so much because they were his best friends, most firm to his interest and most forward to serve him, but because they were such as feared God and kept his precepts, and so did him honour and helped to support his kingdom among men. Our love to the saints is then sincere when we love them for the sake of what we see of God in them and the ...', 'teologico');
add('sl', 119, 64, 'Matthew Henry', 'Here, 1. David pleads that God is good to all the creatures according to their necessities and capacities; as the heaven is full of God\'s glory, so the earth is full of his mercy, full of the instances of his pity and bounty. Not only the land of Canaan, where God is known and worshipped, but the whole earth, in many parts of which he has no homage paid him, is full of his mercy. Not only the children of men upon the earth, but even the inferior creatures, taste of God\'s goodness. His tender ...', 'teologico');
add('sl', 119, 65, 'Matthew Henry', 'Here, 1. David makes a thankful acknowledgment of God\'s gracious dealings with him all along: Thou hast dealt well with thy servant. However God has dealt with us, we must own he has dealt well with us, better than we deserve, and all in love and with design to work for our good. In many instances God has done well for us beyond our expectations. He has done well for all his servants; never any of them complained that he had used them hardly. Thou hast dealt well with me, not only according t...', 'teologico');
add('sl', 119, 67, 'Matthew Henry', 'David here tells us what he had experienced, 1. Of the temptations of a prosperous condition: "Before I was afflicted, while I lived in peace and plenty, and knew no sorrow, I went astray from God and my duty." Sin is going astray; and we are most apt to wander from God when we are easy and think ourselves at home in the world. Prosperity is the unhappy occasion of much iniquity; it makes people conceited of themselves, indulgent of the flesh, forgetful of God, in love with the world, and dea...', 'teologico');
add('sl', 119, 68, 'Matthew Henry', 'Here, 1. David praises God\'s goodness and gives him the glory of it: Thou art good and doest good. All who have any knowledge of God and dealings with him wilt own that he does good, and therefore will conclude that he is good. The streams of God\'s goodness are so numerous, and run so full, so strong, to all the creatures, that we must conclude the fountain that is in himself to be inexhaustible. We cannot conceive how much good our God does every day, much less can we conceive how good he is...', 'teologico');
add('sl', 119, 69, 'Matthew Henry', 'David here tells us how he was affected as to the proud and wicked people that were about him. 1. He did not fear their malice, nor was he by it deterred from his duty: They have forged a lie against me. Thus they aimed to take away his good name. Nay, all we have in the world, even life itself, may be brought into danger by those who make no conscience of forging a lie. Those that were proud envied David\'s reputation, because it eclipsed them, and therefore did all they could to blemish him....', 'teologico');
add('sl', 119, 71, 'Matthew Henry', 'See here, 1. That it has been the lot of the best saints to be afflicted. The proud and the wicked lived in pomp and pleasure, while David, though he kept close to God and his duty, was still in affliction. Waters of a full cup are wrung out to God\'s people, Psa 73:10. 2. That it has been the advantage of God\'s people to be afflicted. David could speak experimentally: It was good for me; many a good lesson he had learnt by his afflictions, and many a good duty he had been brought to which oth...', 'teologico');
add('sl', 119, 72, 'Matthew Henry', 'This is a reason why David reckoned that when by his afflictions he learned God\'s statutes, an the profit did so much counterbalance the loss, he was really a gainer by them; for God\'s law, which he got acquaintance with by his affliction, was better to him than all the gold and silver which he lost by his affliction. 1. David had but a little of the word of God in comparison with what we have, yet see how highly he valued it; how inexcusable then are we, who have both the Old and New Testame...', 'teologico');
add('sl', 119, 73, 'Matthew Henry', 'Here, 1. David adores God as the God of nature and the author of his being: Thy hands have made me and fashioned me, Job 10:8. Every man is as truly the work of God\'s hands as the first man was, Psa 139:15, Psa 139:16. "Thy hands have not only made me, and given me a being, otherwise I should never have been, but fashioned me, and given me this being, this noble and excellent being, endued with these powers and faculties;" and we must own that we are fearfully and wonderfully made. 2. He addr...', 'teologico');
add('sl', 119, 74, 'Matthew Henry', 'Here is, 1. The confidence of this good man in the hope of God\'s salvation: "I have hoped in thy word; and I have not found it in vain to do so; it has not failed me, nor have I been disappointed in my expectations from it. It is a hope that maketh not ashamed; but is present satisfaction, and fruition at last." 2. The concurrence of other good men with him in the joy of that salvation: "Those that fear thee will be glad when they see me relieved by my hope in thy word and delivered according...', 'teologico');
add('sl', 119, 75, 'Matthew Henry', 'Still David is in affliction, and being so he owns, 1. That his sin was justly corrected: I know, O Lord! that thy judgments are right, are righteousness itself. However God is pleased to afflict us, he does us no wrong, nor can we charge him with any iniquity, but most acknowledge that it is less than we have deserved. We know that God is holy in his nature and wise and just in all the acts of his government, and therefore we cannot but know, in the general, that his judgments are right, tho...', 'teologico');
add('sl', 119, 76, 'Matthew Henry', 'Here is, 1. An earnest petition to God for his favour. Those that own the justice of God in their afflictions (as David had done, Psa 119:75) may, in faith, and with humble boldness, be earnest for the mercy of God, and the tokens and fruits of that mercy, in their affliction. He prays for God\'s merciful kindness (Psa 119:76), his tender mercies, Psa 119:77. He can claim nothing as his due, but all his supports under his affliction must come from mere mercy and compassion to one in misery, on...', 'teologico');
add('sl', 119, 78, 'Matthew Henry', 'Here David shows,\nI. How little he valued the will - will of sinners. There were those that dealt perversely with him, that were peevish and ill-conditioned towards him, that sought advantages against him, and misconstrued all he said and did. Even those that deal most fairly may meet with those that deal perversely. But David regarded it not, for, 1. He knew it was without cause, and that for his love they were his adversaries. The causeless reproach, like the curse causeless, may be easily ...', 'teologico');
add('sl', 119, 80, 'Matthew Henry', 'Here is, 1. David\'s prayer for sincerity, that his heart might be brought to God\'s statutes, and that it might be sound in them, not rotten and deceitful, that he might not rest in the form of godliness, but be acquainted with the subject to the power of it, - that he might be hearty and constant in religion, and that his soul might be in health. 2. His dread of the consequences of hypocrisy: That I be not ashamed. Shame is the portion of hypocrites, either here, if it be repented of, or here...', 'teologico');
add('sl', 119, 81, 'Matthew Henry', 'Here we have the psalmist,\nI. Longing for help from heaven: My soul faints; my eyes fail. He longs for the salvation of the Lord and for his word, that is, salvation according to the word. He is not thus eager for the creatures of fancy, but for the objects of faith, salvation from the present calamities under which he was groaning and the doubts and fears which he was oppressed with. It may be understood of the coming of the Messiah, and so he speaks in the name of the Old Testament church; ...', 'teologico');
add('sl', 119, 83, 'Matthew Henry', 'David begs God would make haste to comfort him, 1. Because his affliction was great, and therefore he was an object of God\'s pity: Lord, make haste to help me, for I have become like a bottle in the smoke, a leathern bottle, which, if it hung any while in the smoke, was not only blackened with soot, but dried, and parched, and shrivelled up. David was thus wasted by age, and sickness, and sorrow. See how affliction will mortify the strongest and stoutest of men! David had been of a ruddy coun...', 'teologico');
add('sl', 119, 84, 'Matthew Henry', 'Here, I. David prays against the instruments of his troubles, that God would make haste to execute judgment on those that persecuted him. He prays not for power to avenge himself (he bore no malice to any), but that God would take to himself the vengeance that belonged to him, and would repay (Rom 12:19), as the God that sits in the throne judging right. There is a day coming, and a great and terrible day it will be, when God will execute judgment on all the proud persecutors of his people, t...', 'teologico');
add('sl', 119, 85, 'Matthew Henry', 'David\'s state was herein a type and figure of the state both of Christ and Christians that he was grievously persecuted; as there are many of his psalms, so there are many of the verses of this psalm, which complain of this, as those here. Here observe,\nI. The account he gives of his persecutors and their malice against him. 1. They were proud, and in their pride they persecuted him, glorying in this, that they could trample upon one who was so much cried up, and hoping to raise themselves on...', 'teologico');
add('sl', 119, 88, 'Matthew Henry', 'Here is, 1. David in care to be found in the way of his duty. His constant desire and design are to keep the testimony of God\'s mouth, to keep to it as his rule and to keep hold of it as his confidence and portion for ever. This we must keep, whatever we lose. 2. David at prayer for divine grace to assist him therein: "Quicken me after thy lovingkindness (make me alive and make me lively), so shall I keep thy testimonies," implying that otherwise he should not keep them. We cannot proceed, no...', 'teologico');
add('sl', 119, 89, 'Matthew Henry', 'Here, 1. The psalmist acknowledges the unchangeableness of the word of God and of all his counsels: "For ever, O Lord! thy word is settled. Thou art for ever thyself (so some read it); thou art the same, and with thee there is no variableness, and this is a proof of it. Thy word, by which the heavens were made, is settled there in the abiding products of it;" or the settling of God\'s word in heaven is opposed to the changes and revolutions that are here upon earth. All flesh is grass; but the...', 'teologico');
add('sl', 119, 92, 'Matthew Henry', 'Here is, 1. The great distress that David was in. He was in affliction, and ready to perish in his affliction, not likely to die, so much as likely to despair; he was ready to give up all for gone, and to look upon himself as cut off from God\'s sight; he therefore admires the goodness of God to him, that he had not perished, that he kept the possession of his own soul, and was not driven out of his wits by his troubles, but especially that he was enabled to keep close to his God and was not d...', 'teologico');
add('sl', 119, 93, 'Matthew Henry', 'Here is, 1. A very good resolution: "I will never forget thy precepts, but will always retain a remembrance of and regard to thy word as my rule." It is a resolution for perpetuity, never to be altered. Note, The best evidence of our love to the word of God is never to forget it. We must resolve that we will never, at any time, cast off our religion, and never, upon any occasion, lay aside our religion, but that we will be constant to it and persevere in it. 2. A very good reason for it: "For...', 'teologico');
add('sl', 119, 94, 'Matthew Henry', 'Here, 1. David claims relation to God: "I am thine, devoted to thee and owned by thee, thine in covenant." He does not say, Thou art mine (as Dr. Manton observes), though that follows of course, because that were a higher challenge; but, I am thine, expressing himself in a more humble and dutiful way of resignation; nor does he say, I am thus, but, I am thine, not pleading his own good property or qualification, but God\'s propriety in him: "I am thine, not my own, not the world\'s." 2. He prov...', 'teologico');
add('sl', 119, 95, 'Matthew Henry', 'Here, 1. David complains of the malice of his enemies: The wicked (and none but such would be enemies to so good a man) have waited for me to destroy me. They were very cruel, and aimed at no less than his destruction; they were very crafty, and sought all opportunities to do him a mischief; and they were confident (they expected, so some read it), that they should destroy him; they thought themselves sure of their prey. 2. He comforts himself in the word of God as his protection: "While they...', 'teologico');
add('sl', 119, 96, 'Matthew Henry', 'Here we have David\'s testimony from his own experience, 1. Of the vanity of the world and its insufficiency to make us happy: I have seen an end of all perfection. Poor perfection which one sees an end of! Yet such are all those things in this world which pass for perfections. David, in his time, had seen Goliath, the strongest, overcome, Asahel, the swiftest, overtaken, Ahithophel, the wisest, befooled, Absalom, the fairest, deformed; and, in short, he had seen an end of perfection, of all p...', 'teologico');
add('sl', 119, 97, 'Matthew Henry', 'Here is, 1. David\'s inexpressible love to the word of God: O how love I thy law! He protests his affection to the word of God with a holy vehemency; he found that love to it in his heart which, considering the corruption of his nature and the temptations of the world, he could not but wonder at, and at that grace which had wrought it in him. He not only loved the promises, but loved the law, and delighted in it after the inner man. 2. An unexceptionable evidence of this. What we love we love ...', 'teologico');
add('sl', 119, 98, 'Matthew Henry', 'We have here an account of David\'s learning, not that of the Egyptians, but of the Israelites indeed.\nI. The good method by which he got it. In his youth he minded business in the country as a shepherd; from his youth he minded business in the court and camp. Which way then could he get any great stock of learning? He tells us here how he came by it; he had it from God as the author: Thou hast made me wise. All true wisdom is from God. He had it by the word of God as the means, by his command...', 'teologico');
add('sl', 119, 101, 'Matthew Henry', 'Here is, 1. David\'s care to avoid the ways of sin: "I have refrained my feet from the evil ways they were ready to step aside into. I checked myself and drew back as soon as I was aware that I was entering into temptation." Though it was a broad way, a green way, a pleasant way, and a way that many walked in, yet, being a sinful way, it was an evil way, and he refrained his feet from it, foreseeing the end of that way. And his care was universal; he shunned every evil way. By the words of thy...', 'teologico');
add('sl', 119, 102, 'Matthew Henry', 'Here is, 1. David\'s constancy in his religion. He had not departed from God\'s judgments; he had not chosen any other rule than the word of God, nor had he wilfully deviated from that rule. A constant adherence to the ways of God in trying times will be a good evidence of our integrity. 2. The cause of his constancy: "For thou hast taught me; that is, they were divine instructions that I learned; I was satisfied that the doctrine was of God, and therefore I stuck to it." Or rather, "It was div...', 'teologico');
add('sl', 119, 103, 'Matthew Henry', 'Here is, 1. The wonderful pleasure and delight which David took in the word of God; it was sweet to his taste, sweeter than honey. There is such a thing as a spiritual taste, an inward savour and relish of divine things, such an evidence of them to ourselves, by experience, as we cannot give to others. We have heard him ourselves, Joh 4:42. To this scripture-taste the word of God is sweet, very sweet, sweeter than any of the gratifications of sense, even those that are most delicious. David s...', 'teologico');
add('sl', 119, 106, 'Matthew Henry', 'Here is, 1. The notion David had of religion; it is keeping God\'s righteous judgments. God\'s commands are his judgments, the dictates of infinite wisdom. They are righteous judgments, consonant to the eternal rules of equity, and it is our duty to keep them carefully. 2. The obligation he here laid upon himself to be religious, binding himself, by his own promise, to that which he was already bound to by the divine precept, and all little enough. "I have sworn (I have lifted up my head to the...', 'teologico');
add('sl', 119, 107, 'Matthew Henry', 'Here is, 1. The representation David makes of the sorrowful condition he was in: I am afflicted very much, afflicted in spirit; he seems to mean that especially. He laboured under many discouragements; without were fightings, within were fears. This is often the lot of the best saints; therefore think it not strange if sometimes it be ours. 2. The recourse he has to God in this condition; he prays for his grace: "Quicken me, O Lord! make me lively, make me cheerful; quicken me by afflictions ...', 'teologico');
add('sl', 119, 108, 'Matthew Henry', 'Two things we are here taught to pray for, in reference to our religious performances: - 1. Acceptance of them. This we must aim at in all we do in religion, that, whether present or absent, we may be accepted of the Lord. What David here earnestly prays for the acceptance of are the free-will-offerings, not of his purse, but of his mouth, his prayers and praises. The calves of our lips (Hos 14:2), the fruit of our lips (Heb 13:15), these are the spiritual offerings which all Christians, as s...', 'teologico');
add('sl', 119, 109, 'Matthew Henry', 'Here is, 1. David in danger of losing his life. There is but a step between him and death, for the wicked have laid a snare for him; Saul did so many a time, because he hated him for his piety. Wherever he was he found some design or other laid against him to take away his life, for it was that they aimed at. What they could not effect by open force they hoped to compass by treachery, which made him say, My soul is continually in my hand. It was so with him, not only as a man (so it is true o...', 'teologico');
add('sl', 119, 111, 'Matthew Henry', 'The psalmist here in a most affectionate manner, like an Israelite indeed, resolves to stick to the word of God and to live and die by it.\nI. He resolves to portion himself in it, and there to seek his happiness, nay, there to enjoy it; "Thy testimonies (the truths, the promises, of thy word) have I taken as a heritage for ever, for they are the rejoicing of my heart." The present delight he took in them was an evidence that the good things contained in them were in his account the best thing...', 'teologico');
add('sl', 119, 113, 'Matthew Henry', 'Here we have, 1. David\'s dread of the risings of sin, and the first beginnings of it: I hate vain thoughts. He does not mean that he hated them in others, for there he could not discern them, but he hated them in his own heart. Every good man makes conscience of his thoughts, for they are words to God. Vain thoughts, how light soever most make of them, are sinful and hurtful, and therefore we should account them hateful and dreadful, for they do not only divert the mind from that which is goo...', 'teologico');
add('sl', 119, 114, 'Matthew Henry', 'Here is, 1. God\'s care of David to protect and defend him, which he comforted himself with when his enemies were very malicious against him: Thou art my hiding-place and my shield. David, when Saul pursued him, often betook himself to close places for shelter; in war he guarded himself with his shield. Now God was both these to him, a hiding-place to preserve him from danger and a shield to preserve him in danger, his life from death and his soul from sin. Good people are safe under God\'s pro...', 'teologico');
add('sl', 119, 115, 'Matthew Henry', 'Here is, 1. David\'s firm and fixed resolution to live a holy life: I will keep the commandments of my God. Bravely resolved! like a saint, like a soldier; for true courage consists in a steady resolution against all sin and for all duty. Those that would keep God\'s commandments must be often renewing their resolutions to do so: "I will keep them. Whatever others do, this I will do; though I be singular, though all about me be evil-doers, and desert me; whatever I have done hitherto, I will fo...', 'teologico');
add('sl', 119, 116, 'Matthew Henry', 'Here, 1. David prays for sustaining grace; for this grace sufficient he besought the Lord twice: Uphold me; and again, Hold thou me up. He sees himself not only unable to go on in his duty by any strength of his own, but in danger of falling into sin unless he was prevented by divine grace; and therefore he is thus earnest for that grace to uphold him in his integrity (Psa 41:12), to keep him from falling and to keep him from tiring, that he might neither turn aside to evil-doing nor be weary...', 'teologico');
add('sl', 119, 118, 'Matthew Henry', 'Here is, I. God\'s judgment on wicked people, on those that wander from his statutes, that take their measures from other rules and will not have God to reign over them. All departure from God\'s statutes is certainly an error, and will prove a fatal one. These are the wicked of the earth; they mind earthly things, lay up their treasures in the earth, live in pleasure on the earth, and are strangers and enemies to heaven and heavenly things. Now see how God deals with them, that you may neither...', 'teologico');
add('sl', 119, 121, 'Matthew Henry', 'David here appeals to God, 1. As his witness that he had not done wrong; he could truly say, "I have done judgment and justice, that is, I have made conscience of rendering to all their due, and have not by force or fraud hindered any of their right." Take him as a king, he executed judgment and justice to all his people, Sa2 8:15. Take him in a private capacity, he could appeal to Saul himself that there was no evil or transgression in his hand, Sa1 24:11. Note, Honesty is the best policy an...', 'teologico');
add('sl', 119, 123, 'Matthew Henry', 'David, being oppressed, is here waiting and wishing for the salvation of the Lord, which would make him easy. 1. He cannot but think that it comes slowly: My eyes fail for thy salvation. His eyes were towards it and had been long so. He looked for help from heaven (and we deceive ourselves if we look for it any other way), but it did not come so soon as he expected, so that his eyes began to fail, and he was sometimes ready to despair, and to think that, because the salvation did not come whe...', 'teologico');
add('sl', 119, 124, 'Matthew Henry', 'Here is, 1. David\'s petition for divine instruction: "Teach me thy statutes; give me to know all my duty; when I am in doubt, and know not for certain what is my duty, direct me, and make it plain to me; now that I am afflicted, oppressed, and my eyes are ready to fail for thy salvation, let me know what my duty is in this condition." In difficult times we should desire more to be told what we must do than what we may expect, and should pray more to be led into the knowledge of scripture-prec...', 'teologico');
add('sl', 119, 126, 'Matthew Henry', 'Here is, 1. A complaint of the daring impiety of the wicked. David, having in himself a holy indignation at it, humbly represents it to God: "Lord, there are those that have made void thy law, have set thee and thy government at defiance, and have done what in them lay to cancel and vacate the obligation of thy commands." Those that sin through infirmity transgress the law, but presumptuous sinners do in effect make void the law, saying, Who is the Lord? What is the Almighty, that we should f...', 'teologico');
add('sl', 119, 127, 'Matthew Henry', 'David here, as often in this psalm, professes the great love he had to the word and law of God; and, to evidence the sincerity of it, observe, 1. The degree of his love. He loved his Bible better than he loved his money - above gold, yea, above fine gold. Gold, fine gold, is what most men set their hearts upon; nothing charms them and dazzles their eyes so much as gold does. It is fine gold, a fine thing in their eyes; they will venture their souls, their God, their all, to get and keep it. B...', 'teologico');
add('sl', 119, 129, 'Matthew Henry', 'See here how David was affected towards the word of God. 1. He admired it, as most excellent in itself: Thy testimonies are wonderful. The word of God gives us admirable discoveries of God, and Christ, and another world; admirable proofs of divine love and grace. The majesty of the style, the purity of the matter, the harmony of the parts, are all wonderful. Its effects upon the consciences of men, both for conviction and comfort, are wonderful; and it is a sign that we are not acquainted wit...', 'teologico');
add('sl', 119, 130, 'Matthew Henry', 'Here is, 1. The great use for which the word of God was intended, to give light, that is, to give understanding, to give us to understand that which will be of use to us in our travels through this world; and it is the outward and ordinary means by which the Spirit of God enlightens the understanding of all that are sanctified. God\'s testimonies are not only wonderful for the greatness of them, but useful, as a light in a dark place. 2. Its efficacy for this purpose. It admirably answers the ...', 'teologico');
add('sl', 119, 131, 'Matthew Henry', 'Here is, 1. The desire David had towards the word of God: I longed for thy commandments. When he was under a forced absence from God\'s ordinances he longed to be restored to them again; when he enjoyed ordinances he greedily sucked in the word of God, as new-born babes desire the milk. When Christ is formed in the soul there are gracious longings, unaccountable to one that is a stranger to the work. 2. The degree of that desire appearing in the expressions of it: I opened my mouth and panted,...', 'teologico');
add('sl', 119, 132, 'Matthew Henry', 'Here is, 1. David\'s request for God\'s favour to himself: "Look graciously upon me; let me have thy smiles, and the light of thy countenance. Take cognizance of me and my affairs, and be merciful to me; let me taste the sweetness of thy mercy and receive the gifts of thy mercy." See how humble his petition is. He asks not for the operations of God\'s hand, only for the smiles of his face; a good look is enough; and for that he does not plead merit, but implores mercy. 2. His acknowledgment of h...', 'teologico');
add('sl', 119, 133, 'Matthew Henry', 'Here David prays for two great spiritual blessings, and is, in this verse, as earnest for the good work of God in him as, in the verse before, for the good-will of God towards him. He prays, 1. For direction in the paths of duty: "Order my steps in thy word; having led me into the right way, let every step I take in that way be under the guidance of thy grace." We ought to walk by rule; all the motions of the soul must not only be kept within the bounds prescribed by the word, so as not to tr...', 'teologico');
add('sl', 119, 134, 'Matthew Henry', 'Here, 1. David prays that he might live a quiet and peaceable life, and might not be harassed and discomposed by those that studied to be vexatious: "Deliver me from the oppression of man - man, whom God can control, and whose power is limited. Let them know themselves to be but men (Psa 9:20), and let me be delivered out of the hands of my enemies, that I may serve God without fear; so will I keep thy precepts." Not but that he would keep God\'s precepts, though he should be continued under o...', 'teologico');
add('sl', 119, 135, 'Matthew Henry', 'David here, as often as elsewhere, writes himself God\'s servant, a title he gloried in, though he was a king; now here, as became a good servant, 1. He is very ambitious of his Master\'s favour, accounting that his happiness and chief good. He asks not for corn and wine, for silver and gold, but, "Make thy face to shine upon thy servant; let me be accepted of thee, and let me know that I am so. Comfort me with the light of thy countenance in every cloudy and dark day. If the world frown upon m...', 'teologico');
add('sl', 119, 136, 'Matthew Henry', 'Here we have David in sorrow. 1. It is a great sorrow, to such a degree that he weeps rivers of tears. Commonly, where there is a gracious heart, there is a weeping eye, in conformity to Christ, who was a man of sorrows and acquainted with grief. David had prayed for comfort in God\'s favour (Psa 119:135), now he pleads that he was qualified for that comfort, and had need of it, for he was one of those that mourned in Zion, and those that do so shall be comforted, Isa 61:3. 2. It is godly sorr...', 'teologico');
add('sl', 119, 137, 'Matthew Henry', 'Here is, 1. The righteousness of God, the infinite rectitude and perfection of his nature. As he is what he is, so he is what he should be, and in every thing acts as becomes him; there is nothing wanting, nothing amiss, in God; his will is the eternal rule of equity, and he is righteous, for he does all according to it. 2. The righteousness of his government. He rules the world by his providence, according to the principles of justice, and never did, nor ever can do, any wrong to any of his ...', 'teologico');
add('sl', 119, 139, 'Matthew Henry', 'Here is, 1. The great contempt which wicked men put upon religion: My enemies have forgotten thy words. They have often heard them, but so little did they heed them that they soon forgot them, they willingly forgot them, not only through carelessness let them slip out of their minds, but contrived how to cast them behind their backs. This is at the bottom of all the wickedness of the wicked, and particularly of their malignity and enmity to the people of God; they have forgotten the words of ...', 'teologico');
add('sl', 119, 140, 'Matthew Henry', 'Here is, 1. David\'s great affection for the word of God: Thy servant loves it. Every good man, being a servant of God, loves the word of God, because it lets him know his Master\'s will and directs him in his Master\'s work. Wherever there is grace there is a warm attachment to the word of God. 2. The ground and reason of that affection; he saw it to be very pure, and therefore he loved it. Our love to the word of God is then an evidence of our love to God when we love it for the sake of its pu...', 'teologico');
add('sl', 119, 141, 'Matthew Henry', 'Here is, 1. David pious and yet poor. He was a man after God\'s own heart, one whom the King of kings did delight to honour, and yet small and despised in his own account and in the account of many others. Men\'s excellency cannot always secure them from contempt; nay, it often exposes them to the scorn of others and always makes them low in their own eyes. God has chosen the foolish things of the world, and it has been the common lot of his people to be a despised people. 2. David poor and yet...', 'teologico');
add('sl', 119, 142, 'Matthew Henry', 'Observe, 1. That God\'s word is righteousness, and it is an everlasting righteousness. It is the rule of God\'s judgment, and it is consonant to his counsels from eternity and will direct his sentence for eternity. The word of God will judge us, it will judge us in righteousness, and by it our everlasting state will be determined. This should possess us with a very great reverence for the word of God that it is righteousness itself, the standard of righteousness, and it is everlasting in its re...', 'teologico');
add('sl', 119, 143, 'Matthew Henry', 'These two verses are almost a repetition of the two foregoing verses, but with improvement. 1. David again professes his constant adherence to God and his duty, notwithstanding the many difficulties and discouragements he met with. He had said (Psa 119:14), I am small and despised, and yet adhere to my duty. Here he finds himself not only mean, but miserable, as far as this world could make him so: Trouble and anguish have taken hold on me - trouble without, anguish within; they surprised him...', 'teologico');
add('sl', 119, 145, 'Matthew Henry', 'Here we have, I. David\'s good prayers, by which he sought to God for mercy; these he mentions here, not as boasting of them, or trusting to any merit in them, but reflecting upon them with comfort, that he had taken the appointed way to comfort. Observe here, 1. That he was inward with God in prayer; he prayed with his heart, and prayer is acceptable no further than the heart goes along with it. Lip-labour, if that be all, is lost labour. 2. He was importunate with God in prayer; he cried, as...', 'teologico');
add('sl', 119, 147, 'Matthew Henry', 'David goes on here to relate how he had abounded in the duty of prayer, much to his comfort and advantage: he cried unto God, that is, offered up to him his pious and devout affections with all seriousness. Observe,\nI. The handmaids of his devotion. The two great exercises that attended his prayers, and were helpful to them, were, 1. Hope in God\'s word, which encouraged him to continue instant in prayer, though the answer did not come immediately: "I cried, and hoped that at last I should spe...', 'teologico');
add('sl', 119, 149, 'Matthew Henry', 'Here, 1. David applies to God for grace and comfort with much solemnity. He begs of God to hear his voice: "Lord, I have something to say to thee; shall I obtain a gracious audience?" Well, what has he to say? What is his petition and what is his request? It is not long, but it has much in a little: "Lord, quicken me; stir me up to that which is good, and make me vigorous, and lively, and cheerful in it. Let habits of grace be drawn out into act." 2. He encourages himself to hope that he shal...', 'teologico');
add('sl', 119, 150, 'Matthew Henry', 'Here is, I. The apprehension David was in of danger from his enemies. 1. They were very malicious, and industrious in prosecuting their malicious designs: They follow after mischief, any mischief they could do to David or his friends; they would let slip no opportunity nor let fall any pursuit that might be to his hurt. 2. They were very impious, and had no fear of God before their eyes: They are far from thy law, setting themselves as far as they can out of the reach of its convictions and c...', 'teologico');
add('sl', 119, 152, 'Matthew Henry', 'This confirms what he had said in the close of the foregoing verses, All thy commandments are truth; he means the covenant, the word which God has commanded to a thousand generations. This is firm, as true as truth itself. For, 1. God has founded it so; he has framed it for a perpetuity. Such is the constitution of it, and so well ordered is it in all things, that it cannot but be sure. The promises are founded for ever, so that when heaven and earth shall have passed away every iota and titt...', 'teologico');
add('sl', 119, 153, 'Matthew Henry', 'Here, I. David prays for succour in distress. Is any afflicted? let him pray; let him pray as David does here. 1. He has an eye to God\'s pity, and prays, "Consider my affliction; take it into thy thoughts, and all the circumstances of it, and sit not by as one unconcerned." God is never unmindful of his people\'s afflictions, but he will have us to put him in remembrance (Isa 43:26), to spread our case before him, and then leave it to his compassionate consideration to do in it as in his wisdo...', 'teologico');
add('sl', 119, 155, 'Matthew Henry', 'Here is, 1. The description of wicked men. They do not only do God\'s statutes, but they do not so much as seek them; they do not acquaint themselves with them, nor so much as desire to know their duty, nor in the least endeavour to do it. Those are wicked indeed who do not think the law of God worth enquiring after, but are altogether regardless of it, being resolved to live at large and to walk in the way of their heart. 2. Their doom: Salvation is far from them. They cannot upon any good gr...', 'teologico');
add('sl', 119, 156, 'Matthew Henry', 'Here, 1. David admires God\'s grace: Great are thy tender mercies, O Lord! The goodness of God\'s nature, as it is his glory, so it is the joy of all the saints. His mercies are tender, for he is full of compassion; they are many, they are great, a fountain that can never be exhausted. He is rich in mercy to all that call upon him. David had spoken of the misery of the wicked (Psa 119:155); but God is good notwithstanding; there were tender mercies sufficient in God to have saved them, if they ...', 'teologico');
add('sl', 119, 157, 'Matthew Henry', 'Here is, 1. David surrounded with difficulties and dangers: Many are my persecutors and my enemies. When Saul the king was his persecutor and enemy no marvel that many more were so: multitudes will follow the pernicious ways of abused authority. David, being a public person, had many enemies, but withal he had many friends, who loved him and wished him well; let him set the one over-against the other. In this David was a type both of Christ and his church. The enemies, the persecutors, of bot...', 'teologico');
add('sl', 119, 158, 'Matthew Henry', 'Here is, 1. David\'s sorrow for the wickedness of the wicked. Though he conversed much at home, yet sometimes he looked abroad, and could not but see the wicked walking on every side. He beheld the transgressors, those whose sins were open before all men, and it grieved him to see them dishonour God, serve Satan, debauch the world, and ruin their own souls, to see the transgressors so numerous, so daring, so very impudent, and so industrious to draw unstable souls into their snares. All this c...', 'teologico');
add('sl', 119, 159, 'Matthew Henry', 'Here is, 1. David\'s appeal to God concerning his love to his precepts: "Lord, thou knowest all things, thou knowest that I love them; consider it then, and deal with me as thou usest to deal with those that love thy word, which thou hast magnified above all thy name." He does not say, "Consider how I fulfil thy precepts;" he was conscious to himself that in many things he came short; but, "Consider how I love them." Our obedience is pleasing to God, and pleasant to ourselves, only when it com...', 'teologico');
add('sl', 119, 160, 'Matthew Henry', 'David here comforts himself with the faithfulness of God\'s word, for the encouragement of himself and others to rely upon it. 1. It has always been found faithful hitherto, and never failed any that ventured upon it; It is true from the beginning. Ever since God began to reveal himself to the children of men all he said was true and to be trusted. The church, from its beginning, was built upon this rock. It has not gained its validity by lapse of time, as many governments, whose best plea is ...', 'teologico');
add('sl', 119, 161, 'Matthew Henry', 'David here lets us know, 1. How he was discouraged in his duty by the fear of man: Princes persecuted him. They looked upon him as a traitor and an enemy to the government, and under that notion sought his life, and bade him go serve other gods, Sa1 26:19. It has been the common lot of the best men to be persecuted; and the case is the worse if princes be the persecutors, for they have not only the sword in their hand, and therefore can do the more hurt, but they have the law on their side, a...', 'teologico');
add('sl', 119, 162, 'Matthew Henry', 'Here is, 1. The pleasure David took in the word of God. He rejoiced at it, rejoiced that God had made such a discovery of his mind, that Israel was blessed with that light when other nations sat in darkness, that he was himself let into the understanding of it and had had experience of the power of it. He took a pleasure in reading it, hearing it, and meditating on it, and every thing he met with in it was agreeable to him. He had just now said that his heart stood in awe of his word, and yet...', 'teologico');
add('sl', 119, 163, 'Matthew Henry', 'Love and hatred are the leading affections of the soul; if those be fixed aright, the rest move accordingly. Here we have them fixed aright in David. 1. He had a rooted antipathy to sin; he could not endure to think of it: I hate and abhor lying, which may be taken for all sin, inasmuch as by it we deal treacherously and perfidiously with God and put a cheat upon ourselves. Hypocrisy is lying; false doctrine is lying; breach of faith is lying. Lying, in commerce or conversation, is a sin whic...', 'teologico');
add('sl', 119, 164, 'Matthew Henry', 'David, in this psalm, is full of complaints, yet those did neither jostle out his praises nor put him out of tune for them; whatever condition a child of God is in he does not want matter for praise and therefore should not want a heart. See here, 1. How often David praised God - Seven times a day, that is, very frequently, not only every day, but often every day. Many think that once a week will serve, or once or twice a day, but David would praise God seven times a day at least. Praising Go...', 'teologico');
add('sl', 119, 165, 'Matthew Henry', 'Here is an account of the happiness of good men, who are governed by a principle of love to the word of God, who make it their rule and are ruled by it. 2. They are easy, and have a holy serenity; none enjoy themselves more than they do: Great peace have those that love thy law, abundant satisfaction in doing their duty and pleasure in reflecting upon it. The work of righteousness is peace (Isa 32:17), such peace as the world can neither give nor take away. They may be in great troubles witho...', 'teologico');
add('sl', 119, 166, 'Matthew Henry', 'Here is the whole duty of man; for we are taught, 1. To keep our eye upon God\'s favour as our end: "Lord, I have hoped for thy salvation, not only temporal but eternal salvation. I have hoped for that as my happiness and laid up my treasure in it; I have hoped for it as thine, as a happiness of thy preparing, thy promising, and which consists in being with thee. Hope of this has raised me above the world, and borne me up under all my burdens in it." 2. To keep our eye upon God\'s word as our r...', 'teologico');
add('sl', 119, 167, 'Matthew Henry', 'David\'s conscience here witnesses for him,\nI. That his practices were good. 1. He loved God\'s testimonies, he loved them exceedingly. Our love to the word of God must be a superlative love (we must love it better than the wealth and pleasure of this world), and it must be a victorious love, such as will subdue and mortify our lusts and extirpate carnal affections. 2. He kept them, his soul kept them. Bodily exercise profits little in religion; we must make heart-work of it or we make nothing ...', 'teologico');
add('sl', 119, 169, 'Matthew Henry', 'Here we have, I. A general petition for audience repeated: Let my cry come near before thee; and again, Let my supplication come before thee. He calls his prayer his cry, which denotes the fervency and vehemence of it, and his supplication, which denotes the humility of it. We must come to God as beggars come to our doors for an alms. He is concerned that his prayer might come before God, might come near before him, that is, that he might have grace and strength by faith and fervency to lift ...', 'teologico');
add('sl', 119, 171, 'Matthew Henry', 'Here is, 1. A great favour which David expects from God, that he will teach him his statutes. This he had often prayed for in this psalm, and urged his petition for it with various arguments; and now that he is drawing towards the close of the psalm he speaks of it as taken for granted. Those that are humbly earnest with God for his grace, and resolve with Jacob that they will not let him go unless he bless them with spiritual blessings, may be humbly confident that they shall at length obtai...', 'teologico');
add('sl', 119, 172, 'Matthew Henry', 'Observe here, 1. The good knowledge David had of the word of God; he knew it so well that he was ready to own, with the utmost satisfaction, that all God\'s commandments are not only righteous, but righteousness itself, the rule and standard of righteousness. 2. The good use he resolved to make of that knowledge: My tongue shall speak of thy word, not only utter praise for it to the glory of God, but discourse of it for the instruction and edification of others, as that which he himself was fu...', 'teologico');
add('sl', 119, 173, 'Matthew Henry', 'Here, 1. David prays that divine grace would work for him: Let thy hand help me. He finds his own hands are not sufficient for him, nor can any creature lend him a helping hand to any purpose; therefore he looks up to God in hopes that the hand that had made him would help him; for, if the Lord do not help us, whence can any creature help us? All our help must be expected from God\'s hand, from his power and his bounty. 2. He pleads what divine grace had already wrought in him as a pledge of f...', 'teologico');
add('sl', 119, 175, 'Matthew Henry', 'David\'s heart is still upon praising God; and therefore, 1. He prays that God would give him time to praise him: "Let my soul live, and it shall praise thee, that is, let my life be prolonged, that I may live to thy glory." The reason why a good man desires to live is that he may praise God in the land of the living, and do something to his honour. Not, "Let me live and serve my country, live and provide for my family;" but, "Let me live that, in doing this, I may praise God here in this worl...', 'teologico');
add('sl', 119, 176, 'Matthew Henry', 'Here is, 1. A penitent confession: I have gone astray, or wander up and down, like a lost sheep. As unconverted sinners are like lost sheep (Luk 15:4), so weak unsteady saints are like lost sheep, Mat 18:12, Mat 18:13. We are apt to wander like sheep, and very unapt, when we have gone astray, to find the way again. By going astray we lose the comfort of the green pastures and expose ourselves to a thousand mischiefs. 2. A believing petition: Seek thy servant, as the good shepherd seeks a wand...', 'teologico');
add('sl', 120, 1, 'Matthew Henry', 'Here is, I. Deliverance from a false tongue obtained by prayer. David records his own experience of this.\n1. He was brought into distress, into great distress, by lying lips and a deceitful tongue. There were those that sought his ruin, and had almost effected it, by lying. (1.) By telling lies to him. They flattered him with professions and protestations of friendships, and promises of kindness and service to him, that they might the more securely and without suspicion carry on their designs...', 'teologico');
add('sl', 120, 5, 'Matthew Henry', 'The psalmist here complains of the bad neighbourhood into which he was driven; and some apply the two foregoing verses to this: "What shall the deceitful tongue give, what shall it do to those that lie open to it? What shall a man get by living among such malicious deceitful men? Nothing but sharp arrows and coals of juniper," all the mischiefs of a false and spiteful tongue, Psa 57:4. Woe is me, says David, that I am forced to dwell among such, that I sojourn in Mesech and Kedar. Not that Da...', 'teologico');
add('sl', 121, 1, 'Matthew Henry', 'This psalm teaches us,\nI. To stay ourselves upon God as a God of power and a God all-sufficient for us. David did so and found the benefit of it. 1. We must not rely upon creatures, upon men and means, instruments and second causes, nor make flesh our arm: "Shall I lift up my eyes to the hills?" - so some read it. "Does my help come thence? Shall I depend upon the powers of the earth, upon the strength of the hills, upon princes and great men, who, like hills, fill the earth, and hold up thei...', 'teologico');
add('sl', 122, 1, 'Matthew Henry', 'Here we have,\nI. The pleasure which David and other pious Israelites took in approaching to and attending upon God in public ordinances, Psa 122:1, Psa 122:2.\n1. The invitation to them was very welcome. David was himself glad, and would have every Israelite to say that he was glad, when he was called upon to go up to the house of the Lord. Note, (1.) It is the will of God that we should worship him in concert, that many should join together to wait upon him in public ordinances. We ought to w...', 'teologico');
add('sl', 122, 6, 'Matthew Henry', 'Here, I. David calls upon others to which well to Jerusalem, Psa 122:6, Psa 122:7. Pray for the peace of Jerusalem, for the welfare of it, for all good to it, particularly for the uniting of the inhabitants among themselves and their preservation from the incursions of enemies. This we may truly desire, that in the peace thereof we may have peace; and this we must earnestly pray for, for it is the gift of God, and for it he will be enquired of. Those that can do nothing else for the peace of ...', 'teologico');
add('sl', 123, 1, 'Matthew Henry', 'We have here,\nI. The solemn profession which God\'s people make of faith and hope in God, Psa 123:1, Psa 123:2. Observe, 1. The title here given to God: O thou that dwellest in the heavens. Our Lord Jesus has taught us, in prayer, to have an eye to God as our Father in heaven; not that he is confined there, but there especially he manifests his glory, as the King in his court. Heaven is a place of prospect and a place of power; he that dwells there beholds thence all the calamities of his peop...', 'teologico');
add('sl', 124, 1, 'Matthew Henry', 'The people of God, being here called upon to praise God for their deliverance, are to take notice,\nI. Of the malice of men, by which they were reduced to the very brink of ruin. Let Israel say that there was but a step between them and death: the more desperate the disease appears to have been the more does the skill of the Physician appear in the cure. Observe, 1. Whence the threatening danger came: Men rose up against us, creatures of our own kind, and yet bent upon our ruin. Homo homini lu...', 'teologico');
add('sl', 124, 6, 'Matthew Henry', 'Here the psalmist further magnifies the great deliverance God had lately wrought for them.\nI. That their hearts might be the more enlarged in thankfulness to him (Psa 124:6): Blessed be the Lord. God is the author of all our deliverances, and therefore he must have the glory of them. We rob him of his due if we do not return thanks to him. And we are the more obliged to praise him because we had such a narrow escape. We were delivered, 1. Like a lamb out of the very jaws of a beast of prey: G...', 'teologico');
add('sl', 125, 1, 'Matthew Henry', 'Here are three very precious promises made to the people of God, which, though they are designed to secure the welfare of the church in general, may be applied by particular believers to themselves, as other promises of this nature may. Here is,\nI. The character of God\'s people, to whom these promises belong. Many call themselves God\'s people who have no part nor lot in this matter. But those shall have the benefit of them and may take the comfort of them, (1.) Who are righteous (Psa 125:3), ...', 'teologico');
add('sl', 125, 4, 'Matthew Henry', 'Here is, 1. The prayer the psalmist puts up for the happiness of those that are sincere and constant (Psa 125:4): Do good, O Lord! unto those that are good. This teaches us to pray for all good people, to make supplication for all saints; and we may pray in faith for them, being assured that those who do well shall certainly be well dealt with. Those that are as they should be shall be as they would be, provided they be upright in heart, that they be really as good as they seem to be. With th...', 'teologico');
add('sl', 126, 1, 'Matthew Henry', 'While the people of Israel were captives in Babylon their harps were hung upon the willow-trees, for then God called to weeping and mourning, then he mourned unto them and they lamented; but now that their captivity is turned they resume their harps; Providence pipes to them, and they dance. Thus must we accommodate ourselves to all the dispensations of Providence and be suitably affected with them. And the harps are never more melodiously tunable than after such a melancholy disuse. The long...', 'teologico');
add('sl', 126, 4, 'Matthew Henry', 'These verses look forward to the mercies that were yet wanted. Those that had come out of captivity were still in distress, even in their own land (Neh 1:3), and many yet remained in Babylon; and therefore they rejoiced with trembling, and bore upon their hearts the grievances that were yet to be redressed. We have here, 1. A prayer for the perfecting of their deliverance (Psa 126:4): "Turn again our captivity. Let those that have returned to their own land be eased of the burdens which they ...', 'teologico');
add('sl', 127, 1, 'Matthew Henry', 'We are here taught to have a continual regard to the divine Providence in all the concerns of this life. Solomon was cried up for a wise man, and would be apt to lean to his own understanding and forecast, and therefore his father teaches him to look higher, and to take God along with him in his undertakings. He was to be a man of business, and therefore David instructed him how to manage his business under the direction of his religion. Parents, in teaching their children, should suit their ...', 'teologico');
add('sl', 128, 1, 'Matthew Henry', 'It is here shown that godliness has the promise of the life that now is and of that which is to come.\nI. It is here again and again laid down as an undoubted truth that those who are truly holy are truly happy. Those whose blessed state we are here assured of are such as fear the Lord and walk in his ways, such as have a deep reverence of God upon their spirits and evidence it by a regular and constant conformity to his will. Where the fear of God is a commanding principle in the heart the te...', 'teologico');
add('sl', 129, 1, 'Matthew Henry', 'The church of God, in its several ages, is here spoken of, or, rather, here speaks, as one single person, now old and gray-headed, but calling to remembrance the former days, and reflecting upon the times of old. And, upon the review, it is found, 1. That the church has been often greatly distressed by its enemies on earth: Israel may now say, "I am the people that has been oppressed more than any people, that has been as a speckled bird, pecked at by all the birds round about," Jer 12:9. It ...', 'teologico');
add('sl', 129, 5, 'Matthew Henry', 'The psalmist, having triumphed in the defeat of the many designs that had been laid as deep as hell to ruin the church, here concludes his psalm as Deborah did her song, So let all thy enemies perish, O Lord! Jdg 5:31.\nI. There are many that hate Zion, that hate Zion\'s God, his worship, and his worshippers, that have an antipathy to religion and religious people, that seek the ruin of both, and do what they can that God may not have a church in the world.\nII. We ought to pray that all their a...', 'teologico');
add('sl', 130, 1, 'Matthew Henry', 'In these verses we are taught,\nI. Whatever condition we are in, though ever so deplorable, to continue calling upon God, Psa 130:1. The best men may sometimes be in the depths, in great trouble and affliction, and utterly at a loss what to do, in the depths of distress and almost in the depths of despair, the spirit low and dark, sinking and drooping, cast down and disquieted. But, in the greatest depths, it is our privilege that we may cry unto God and be heard. A prayer may reach the height...', 'teologico');
add('sl', 130, 5, 'Matthew Henry', 'Here, I. The psalmist engages himself to trust in God and to wait for him, Psa 130:5, Psa 130:6. Observe, 1. His dependence upon God, expressed in a climax, it being a a song of degrees, or ascents: "I wait for the Lord; from him I expect relief and comfort, believing it will come, longing till it does come, but patiently bearing the delay of it, and resolving to look for it from no other hand. My soul doth wait; I wait for him in sincerity, and not in profession only. I am an expectant, and ...', 'teologico');
add('sl', 131, 1, 'Matthew Henry', 'Here are two things which will be comforts to us: - \nI. Consciousness of our integrity. This was David\'s rejoicing, that his heart could witness for him that he had walked humbly with his God, notwithstanding the censures he was under and the temptations he was in.\n1. He aimed not at a high condition, nor was he desirous of making a figure in the world, but, if God had so ordered, could have been well content to spend all his days, as he did in the beginning of them, in the sheep-folds. His o...', 'teologico');
add('sl', 132, 1, 'Matthew Henry', 'In these verses we have Solomon\'s address to God for his favour to him and to his government, and his acceptance of his building a house to God\'s name. Observe,\nI. What he pleads - two things: - \n1. That what he had done was in pursuance of the pious vow which his father David had made to build a house for God. Solomon was a wise man, yet pleads not any merit of his own: "I am not worthy, for whom thou shouldst do this; but, Lord, remember David, with whom thou madest the covenant" (as Moses ...', 'teologico');
add('sl', 132, 11, 'Matthew Henry', 'These are precious promises, confirmed by an oath, that the heirs of them might have strong consolation, Heb 6:17, Heb 6:18. It is all one whether we take them as pleas urged in the prayer or as answers returned to the prayer; believers know how to make use of the promises both ways, with them to speak to God and in them to hear what God the Lord will speak to us. These promises relate to the establishment both in church and state, both to the throne of the house of David and to the testimony...', 'teologico');
add('sl', 133, 1, 'Matthew Henry', 'Here see, I. What it is that is commended - brethren\'s dwelling together in unity, not only not quarrelling, and devouring one another, but delighting in each other with mutual endearments, and promoting each other\'s welfare with mutual services. Sometimes it is chosen, as the best expedient for preserving peace, that brethren should live asunder and at a distance from each other; that indeed may prevent enmity and strife (Gen 13:9), but the goodness and pleasantness are for brethren to dwell...', 'teologico');
add('sl', 134, 1, 'Matthew Henry', 'This psalm instructs us concerning a two-fold blessing: - \nI. Our blessing God, that is, speaking well of him, which here we are taught to do, Psa 134:1, Psa 134:2. 1. It is a call to the Levites to do it. They were the servants of the Lord by office, appointed to minister in holy things; they attended the sanctuary, and kept the charge of the house of the Lord, Num 3:6, etc. Some of them did by night stand in the house of the Lord, to guard the holy things of the temple, that they might not ...', 'teologico');
add('sl', 135, 1, 'Matthew Henry', 'Here is, 1. The duty we are called to - to praise the Lord, to praise his name; praise him, and again praise him. We must not only thank him for what he has done for us, but praise him for what he is in himself and has done for others; take all occasions to speak well of God and to give his truths and ways a good word. 2. The persons that are called upon to do this - the servants of the Lord, the priests and Levites that stand in his house, and all the devout and pious Israelites that stand i...', 'teologico');
add('sl', 135, 5, 'Matthew Henry', 'The psalmist had suggested to us the goodness of God, as the proper matter of our cheerful praises; here he suggests to us the greatness of God as the proper matter of our awful praises; and on this he is most copious, because this we are less forward to consider.\nI. He asserts the doctrine of God\'s greatness (Psa 135:5): The Lord is great, great indeed, who knows no limits of time or place. He asserts it with assurance, "I know that he is so; know it not only by observation of the proofs of ...', 'teologico');
add('sl', 135, 15, 'Matthew Henry', 'The design of these verses is,\nI. To arm the people of God against idolatry and all false worship, by showing what sort of gods they were that the heathen worshipped, as we had it before, Psa 115:4, etc. 1. They were gods of their own making; being so, they could have no power but what their makers gave them, and then what power could their makers receive from them? The images were the work of men\'s hands, and the deities that were supposed to inform them were as much the creatures of men\'s f...', 'teologico');
add('sl', 136, 1, 'Matthew Henry', 'The duty we are here again and again called to is to give thanks, to offer the sacrifice of praise continually, not the fruits of our ground or cattle, but the fruit of our lips, giving thanks to his name, Heb 13:15. We are never so earnestly called upon to pray and repent as to give thanks; for it is the will of God that we should abound most in the most pleasant exercises of religion, in that which is the work of heaven. Now here observe, 1. Whom we must give thanks to - to him that we rece...', 'teologico');
add('sl', 136, 10, 'Matthew Henry', 'The great things God for Israel, when he first formed them into a people, and set up his kingdom among them, are here mentioned, as often elsewhere in the psalms, as instances both of the power of God and of the particular kindness he had for Israel. See Psa 135:8, etc. 1. He brought them out of Egypt, Psa 136:10-12. That was a mercy which endured long to them, and our redemption by Christ, which was typified by that, does indeed endure for ever, for it is an eternal redemption. Of all the pl...', 'teologico');
add('sl', 136, 23, 'Matthew Henry', 'God\'s everlasting mercy is here celebrated, 1. In the redemption of his church, Psa 136:23, Psa 136:24. In the many redemptions wrought for the Jewish church out of the hands of their oppressors (when, in the years of their servitude, their estate was very low, God remembered them, and raised them up saviours, the judges, and David, at length, by whom God gave them rest from all their enemies), but especially in the great redemption of the universal church, of which these were types, we have ...', 'teologico');
add('sl', 137, 1, 'Matthew Henry', 'We have here the daughter of Zion covered with a cloud, and dwelling with the daughter of Babylon; the people of God in tears, but sowing in tears. Observe,\nI. The mournful posture they were in as to their affairs and as to their spirits. 1. They were posted by the rivers of Babylon, in a strange land, a great way from their own country, whence they were brought as prisoners of war. The land of Babylon was now a house of bondage to that people, as Egypt had been in their beginning. Their conq...', 'teologico');
add('sl', 137, 7, 'Matthew Henry', 'The pious Jews in Babylon, having afflicted themselves with the thoughts of the ruins of Jerusalem, here please themselves with the prospect of the ruin of her impenitent implacable enemies; but this not from a spirit of revenge, but from a holy zeal for the glory of God and the honour of his kingdom.\nI. The Edomites will certainly be reckoned with, and all others that were accessaries to the destruction of Jerusalem, that were aiding and abetting, that helped forward the affliction (Zac 1:15...', 'teologico');
add('sl', 138, 1, 'Matthew Henry', 'I. How he would praise God, compare Psa 111:1. 1. He will praise him with sincerity and zeal - "With my heart, with my whole heart, with that which is within me and with all that is within me, with uprightness of intention and fervency of affection, inward impressions agreeing with outward expressions." 2. With freedom and boldness: Before the gods will I sing praise unto thee, before the princes, and judges, and great men, either those of other nations that visited him or those of his own na...', 'teologico');
add('sl', 138, 6, 'Matthew Henry', 'David here comforts himself with three things: - \nI. The favour God bears to his humble people (Psa 138:6): Though the Lord be high, and neither needs any of his creatures nor can be benefited by them, yet has he respect unto the lowly, smiles upon them as well pleased with them, overlooks heaven and earth to cast a gracious look upon them (Isa 57:15; Isa 66:1), and, sooner or later, he will put honour upon them, while he knows the proud afar off, knows them, but disowns them and rejects them...', 'teologico');
add('sl', 139, 7, 'Matthew Henry', 'It is of great use to us to know the certainty of the things wherein we have been instructed, that we may not only believe them, but be able to tell why we believe them, and to give a reason of the hope that is in us. David is sure that God perfectly knows him and all his ways,\nI. Because he is always under his eye. If God is omnipresent, he must needs be omniscient; but he is omnipresent; this supposes the infinite and immensity of his being, from which follows the ubiquity of his presence; ...', 'teologico');
add('sl', 139, 17, 'Matthew Henry', 'Here the psalmist makes application of the doctrine of God\'s omniscience, divers ways.\nI. He acknowledges, with wonder and thankfulness, the care God had taken of him all his days, Psa 139:17, Psa 139:18. God, who knew him, thought of him, and his thoughts towards him were thoughts of love, thought of good, and not of evil, Jer 29:11. God\'s omniscience, which might justly have watched over us to do us hurt, has been employed for us, and has watched over us to do us good, Jer 31:28. God\'s coun...', 'teologico');
add('sl', 140, 1, 'Matthew Henry', 'In this, as in other things, David was a type of Christ, that he suffered before he reigned, was humbled before he was exalted, and that as there were many who loved and valued him, and sought to do him honour, so there were many who hated and envied him, and sought to do him mischief, as appears by these verses, where,\nI. He gives a character of his enemies, and paints them out in their own colours, as dangerous men, whom he had reason to be afraid of, but wicked men, whom he had no reason t...', 'teologico');
add('sl', 140, 8, 'Matthew Henry', 'Here is the believing foresight David had,\nI. Of the shame and confusion of persecutors.\n1. Their disappointment. This he prays for (Psa 140:8), that their lusts might not be gratified, their lust of ambition, envy, and revenge: "Grant not, O Lord! the desires of the wicked, but frustrate them; let them not see the ruin of my interest, which they so earnestly wish to see; but hear the voice of my supplications." He prays that their projects might not take effect, but be blasted: "O further no...', 'teologico');
add('sl', 141, 1, 'Matthew Henry', 'Mercy to accept what we do well, and grace to keep us from doing ill, are the two things which we are here taught by David\'s example to pray to God for.\nI. David loved prayer, and he begs of God that his prayers might be heard and answered, Psa 141:1, Psa 141:2. David cried unto God. His crying denotes fervency in prayer; he prayed as one in earnest. His crying to God denotes faith and fixedness in prayer. And what did he desire as the success of his prayer? 1. That God would take cognizance ...', 'teologico');
add('sl', 141, 5, 'Matthew Henry', 'Here, I. David desires to be told of his faults. His enemies reproached him with that which was false, which he could not but complain of; yet, at the same time, he desired his friends would reprove him for that which was really amiss in him, particularly if there was any thing that gave the least colour to those reproaches (Psa 141:5): let the righteous smite me; it shall be a kindness. The righteous God (so some); "I will welcome the rebukes of his providence, and be so far from quarrelling...', 'teologico');
add('sl', 142, 1, 'Matthew Henry', 'Whether it was in the cave of Adullam, or that of Engedi, that David prayed this prayer, is not material; it is plain that he was in distress. It was a great disgrace to so great a soldier, so great a courtier, to be put to such shifts for his own safety, and a great terror to be so hotly pursued and every moment in expectation of death; yet then he had such a presence of mind as to pray this prayer, and, wherever he was, still had his religion about him. Prayers and tears were his weapons, a...', 'teologico');
add('sl', 142, 4, 'Matthew Henry', 'The psalmist here tells us, for our instruction, 1. How he was disowned and deserted by his friends, Psa 142:4. When he was in favour at court he seemed to have a great interest, but when he was made an out-law, and it was dangerous for any one to harbour him (witness Ahimelech\'s fate), then no man would know him, but every body was shy of him. He looked on his right hand for an advocate (Psa 109:31), some friend or other to speak a good word for him; but, since Jonathan\'s appearing for him h...', 'teologico');
add('sl', 143, 1, 'Matthew Henry', 'Here, I. David humbly begs to be heard (Psa 143:1), not as if he questioned it, but he earnestly desired it, and was in care about it, for, having desired it, and was in care about it, for having directed his prayer, he looked up to see how it sped, Hab 2:1. He is a suppliant to his God, and he begs that his requests may be granted: Hear my prayer; give ear to my supplications. He is an appellant against his persecutors, and he begs that his case may be brought to hearing and that God will gi...', 'teologico');
add('sl', 143, 7, 'Matthew Henry', 'David here tells us what he said when he stretched forth his hands unto God; he begins not only as one in earnest, but as one in haste: "Hear me speedily, and defer no longer, for my spirit faileth. I am just ready to faint; reach the cordial - quickly, quickly, or I am gone." It was not a haste of unbelief, but of vehement desire and holy love. Make haste, O God! to help me. Three things David here prays for: - \nI. The manifestations of God\'s favour towards him, that God would be well please...', 'teologico');
add('sl', 144, 1, 'Matthew Henry', 'Here, I. David acknowledges his dependence upon God and his obligations to him, Psa 144:1, Psa 144:2. A prayer for further mercy is fitly begun with a thanksgiving for former mercy; and when we are waiting upon God to bless us we should stir up ourselves to bless him. He gives to God the glory of two things: - \n1. What he was to him: Blessed be the Lord my rock (Psa 144:1), my goodness, my fortress, Psa 144:2. He has in the covenant engaged himself to be so, and encouraged us, accordingly, to...', 'teologico');
add('sl', 144, 9, 'Matthew Henry', 'The method is the same in this latter part of the psalm as in the former; David first gives glory to God and then begs mercy from him.\nI. He praises God for the experiences he had had of his goodness to him and the encouragements he had to expect further mercy from him, Psa 144:9, Psa 144:10. In the midst of his complaints concerning the power and treachery of his enemies, here is a holy exultation in his God: I will sing a new song to thee, O God! a song of praise for new mercies, for those ...', 'teologico');
add('sl', 145, 1, 'Matthew Henry', 'The entitling of this David\'s psalm of praise may intimate not only that he was the penman of it, but that he took a particular pleasure in it and sung it often; it was his companion wherever he went. In this former part of the psalm God\'s glorious attributes are praised, as, in the latter part of the psalm, his kingdom and the administration of it. Observe,\nI. Who shall be employed in giving glory to God.\n1. Whatever others do, the psalmist will himself be much in praising God. To this good ...', 'teologico');
add('sl', 145, 10, 'Matthew Henry', 'The greatness and goodness of him who is optimus et maximus - the best and greatest of beings, were celebrated in the former part of the psalm; here, in these verses, we are taught to give him the glory of his kingdom, in the administration of which his greatness and goodness shine so clearly, so very brightly. Observe, as before,\nI. From whom the tribute of praise is expected (Psa 145:10): All God\'s works shall praise him. They all minister to us matter for praise, and so praise him accordin...', 'teologico');
add('sl', 146, 1, 'Matthew Henry', 'David is supposed to have penned this psalm; and he was himself a prince, a mighty prince; as such, it might be thought, 1. That he should be exempted from the service of praising God, that it was enough for him to see that his priests and people did it, but that he needed not to do it himself in his own person. Michal thought it a disparagement to him to dance before the ark; but he was so far from being of this mind that he would himself be first and foremost in the work, Psa 146:1, Psa 146...', 'teologico');
add('sl', 146, 5, 'Matthew Henry', 'The psalmist, having cautioned us not to trust in princes (because, if we do, we shall be miserably disappointed), here encourages us to put our confidence in God, because, if we do so, we shall be happily secured: Happy is he that has the God of Jacob for his help, that has an interest in his attributes and promises, and has them engaged for him, and whose hope is in the Lord his God.\nI. Let us take a view of the character here given of those whom God will uphold. Those shall have God for th...', 'teologico');
add('sl', 147, 1, 'Matthew Henry', 'Here, I. The duty of praise is recommended to us. It is not without reason that we are thus called to it again and again: Praise you the Lord (Psa 147:1), and again (Psa 147:7), Sing unto the Lord with thanksgiving, sing praise upon the harp to our God (let all our praises be directed to him and centre in him), for it is good to do so; it is our duty, and therefore good in itself; it is our interest, and therefore good for us. It is acceptable to our Creator and it answers the end of our crea...', 'teologico');
add('sl', 147, 12, 'Matthew Henry', 'Jerusalem, and Zion, the holy city, the holy hill, are here called upon to praise God, Psa 147:12. For where should praise be offered up to God but where his altar is? Where may we expect that glory should be given to him but in the beauty of holiness? Let the inhabitants of Jerusalem praise the Lord in their own houses; let the priests and Levites, who attend in Zion, the city of their solemnities, in a special manner praise the Lord. They have more cause to do it than others, and they lie u...', 'teologico');
add('sl', 148, 1, 'Matthew Henry', 'We, in this dark and depressed world, know but little of the world of light and exaltation, and, conversing within narrow confines, can scarcely admit any tolerable conceptions of the vast regions above. But this we know,\nI. That there is above us a world of blessed angels by whom God is praised, an innumerable company of them. Thousand thousands minister unto him, and ten thousand times ten thousand stand before him; and it is his glory that he has such attendants, but much more his glory th...', 'teologico');
add('sl', 148, 7, 'Matthew Henry', 'Considering that this earth, and the atmosphere that surrounds it, are the very sediment of the universe, it concerns us to enquire after those considerations that may be of use to reconcile us to our place in it; and I know none more likely than this (next to the visit which the Son of God once made to it), that even in this world, dark and as bad as it is, God is praised: Praise you the Lord from the earth, Psa 148:7. As the rays of the sun, which are darted directly from heaven, reflect ba...', 'teologico');
add('sl', 149, 1, 'Matthew Henry', 'We have here,\nI. The calls given to God\'s Israel to praise. All his works were, in the foregoing psalm, excited to praise him; but here his saints in a particular manner are required to bless him. Observe then, 1. Who are called upon to praise God. Israel in general, the body of the church (Psa 149:2), the children of Zion particularly, the inhabitants of that holy hill, who are nearer to God than other Israelites; those that have the word and ordinances of God near to them, that are not requ...', 'teologico');
add('sl', 149, 6, 'Matthew Henry', 'The Israel of God are here represented triumphing over their enemies, which is both the matter of their praise (let them give to God the glory of those triumphs) and the recompence of their praise; those that are truly thankful to God for their tranquillity shall be blessed with victory. Or it may be taken as a further expression of their praise (Psa 149:6): let the high praises of God be in their mouth, and then, in a holy zeal for his honour, let them take a two-edged sword in their hand, t...', 'teologico');
add('sl', 150, 1, 'Matthew Henry', 'We are here, with the greatest earnestness imaginable, excited to praise God; if, as some suppose, this psalm was primarily intended for the Levites, to stir them up to do their office in the house of the Lord, as singers and players on instruments, yet we must take it as speaking to us, who are made to our God spiritual priests. And the repeated inculcating of the call thus intimates that it is a great and necessary duty, a duty which we should be much employed and much enlarged in, but whic...', 'teologico');

// PV (524 comentários)
add('pv', 1, 7, 'Calvino', 'O temor do Senhor — A sabedoria começa com a reverência a Deus. Sem ela, o conhecimento é vaidade.', 'teologico');
add('pv', 3, 5, 'Tim Keller', 'Não te estribes no teu próprio entendimento — A humildade intelectual: reconhecer que Deus vê o que nós não vemos.', 'aplicacao');
add('pv', 3, 6, 'John Stott', 'Em todos os teus caminhos — Deus se interessa por cada detalhe da vida, não apenas pelo sagrado.', 'aplicacao');
add('pv', 4, 23, 'Lloyd-Jones', 'Guarda o teu coração — O coração é o centro da vida espiritual. Proteja-o com vigilância constante.', 'aplicacao');
add('pv', 9, 10, 'Agostinho', 'O temor do Senhor é o princípio da sabedoria — O conhecimento de Deus e a santificação estão inseparavelmente ligados.', 'teologico');
add('pv', 11, 25, 'Matthew Henry', 'A alma que abençoa será cevada — A generosidade produz abundância: dar é receber.', 'aplicacao');
add('pv', 15, 1, 'Charles Ellicott', 'A resposta mole — A brandura da resposta é mais eficaz que a severidade no trato com os irados.', 'cultural');
add('pv', 16, 3, 'Spurgeon', 'Confia ao Senhor os teus feitos — A oração sobre os projetos: Deus orienta e estabelece os propósitos do justo.', 'aplicacao');
add('pv', 22, 6, 'John Piper', 'Instrui o menino — A responsabilidade dos pais na formação espiritual dos filhos é séria e urgente.', 'aplicacao');
add('pv', 27, 17, 'Tim Keller', 'O ferro afia o ferro — Precisamos de relacionamentos desafiadores para crescer na santidade.', 'aplicacao');
add('pv', 31, 10, 'Adam Clarke', 'Mulher virtuosa quem a achará — O valor da mulher íntegra: o temor do Senhor é sua força.', 'cultural');
add('pv', 1, 1, 'Matthew Henry', 'We have here an introduction to this book, which some think was prefixed by the collector and publisher, as Ezra; but it is rather supposed to have been penned by Solomon himself, who, in the beginning of his book, proposes his end in writing it, that he might keep to his business, and closely pursue that end. We are here told,\nI. Who wrote these wise sayings, Pro 1:1. They are the proverbs of Solomon. 1. His name signifies peaceable, and the character both of his spirit and of his reign answ...', 'teologico');
add('pv', 1, 10, 'Matthew Henry', 'Here Solomon gives another general rule to young people, in order to their finding out, and keeping in, the paths of wisdom, and that is to take heed of the snare of bad company. David\'s psalms begin with this caution, and so do Solomon\'s proverbs; for nothing is more destructive, both to a lively devotion and to a regular conversation (Pro 1:10): "My son, whom I love, and have a tender concern for, if sinners entice thee, consent thou not." This is good advice for parents to give their child...', 'teologico');
add('pv', 1, 20, 'Matthew Henry', 'Solomon, having shown how dangerous it is to hearken to the temptations of Satan, here shows how dangerous it is not to hearken to the calls of God, which we shall for ever rue the neglect of. Observe,\nI. By whom God calls to us - by wisdom. It is wisdom that crieth without. The word is plural - wisdoms, for, as there is infinite wisdom in God, so there is the manifold wisdom of God, Eph 3:10. God speaks to the children of men by all the kinds of wisdom, and, as in every will, so in every wor...', 'teologico');
add('pv', 2, 1, 'Matthew Henry', 'Job had asked, long before this, Where shall wisdom be found? Whence cometh wisdom? (Job 28:12, Job 28:20) and he had given this general answer (v. 23), God knoweth the place of it; but Solomon here goes further, and tells us both where we may find it and how we may get it. We are here told,\nI. What means we must use that we may obtain wisdom.\n1. We must closely attend to the word of God, for that is the word of wisdom, which is able to make us wise unto salvation, Pro 2:1, Pro 2:2. (1.) We m...', 'teologico');
add('pv', 2, 10, 'Matthew Henry', 'The scope of these verses is to show, 1. What great advantage true wisdom will be of to us; it will keep us from the paths of sin, which lead to ruin, and will therein do us a greater kindness than if it enriched us with all the wealth of the world. 2. What good use we should make of the wisdom God gives us; we must use it for our own guidance in the paths of virtue, and for the arming of us against temptations of every kind. 3. By what rules we may try ourselves whether we have this wisdom o...', 'teologico');
add('pv', 3, 1, 'Matthew Henry', 'We are here taught to live a life of communion with God; and without controversy great is this mystery of godliness, and of great consequence to us, and, as is here shown, will be of unspeakable advantage.\nI. We must have a continual regard to God\'s precepts, Pro 3:1, Pro 3:2.\n1. We must, (1.) Fix God\'s law, and his commandments, as our rule, by which we will in every thing be ruled and to which we will yield obedience. (2.) We must acquaint ourselves with them; for we cannot be said to forge...', 'teologico');
add('pv', 3, 7, 'Matthew Henry', 'We have here before us three exhortations, each of them enforced with a good reason: - \nI. We must live in a humble and dutiful subjection to God and his government (Pro 3:7): "Fear the Lord, as your sovereign Lord and Master; be ruled in every thing by your religion and subject to the divine will." This must be, 1. A humble subjection: Be not wise in thy own eyes. Note, There is not a greater enemy to the power of religion, and the fear of God in the heart, than conceitedness of our own wisd...', 'teologico');
add('pv', 3, 13, 'Matthew Henry', 'Solomon had pressed us earnestly to seek diligently for wisdom (Pro 2:1, etc.), and had assured us that we should succeed in our sincere and constant pursuits. But the question is, What shall we get by it when we have found it? Prospect of advantage is the spring and spur of industry; he therefore shows us how much it will be to our profit, laying this down for an unquestionable truth, Happy is the man that findeth wisdom, that true wisdom which consists in the knowledge and love of God, and ...', 'teologico');
add('pv', 3, 21, 'Matthew Henry', 'Solomon, having pronounced those happy who not only lay hold on wisdom, but retain her, here exhorts us therefore to retain her, assuring us that we ourselves shall have the comfort of doing so.\nI. The exhortation is, to have religion\'s rules always in view and always at heart, Pro 3:21. 1. To have them always in view: "My son, let them not depart from thy eyes; let not thy eyes ever depart from them to wander after vanity. Have them always in mind, and do not forget them; be ever and anon th...', 'teologico');
add('pv', 3, 27, 'Matthew Henry', 'True wisdom consists in the due discharge of our duty towards man, as well as towards God, in honesty as well as piety, and therefore we have here divers excellent precepts of wisdom which relate to our neighbour.\nI. We must render to all their due, both in justice and charity, and not delay to do it (Pro 3:27, Pro 3:28): "Withhold not good from those to whom it is due (either for want of love to them or through too much love to thy money) when it is in the power of thy hand to do it, for, if...', 'teologico');
add('pv', 4, 1, 'Matthew Henry', 'Here we have,\nI. The invitation which Solomon gives to his children to come and receive instruction from him (Pro 4:1, Pro 4:2): Hear, you children, the instruction of a father. That is, 1. "Let my own children, in the first place, receive and give good heed to those instructions which I set down for the use of others also." Note, Magistrates and ministers, who are entrusted with the direction of larger societies, are concerned to take a more than ordinary care for the good instruction of the...', 'teologico');
add('pv', 4, 14, 'Matthew Henry', 'Some make David\'s instructions to Solomon, which began Pro 4:4, to continue to the end of the chapter; nay, some continue them to the end of the ninth chapter; but it is more probable that Solomon begins here again, if not sooner. In these verses, having exhorted us to walk in the paths of wisdom, he cautions us against the path of the wicked. 1. We must take heed of the ways of sin and avoid them, every thing that looks like sin and leads to it. 2. In order to this we must keep out of the wa...', 'teologico');
add('pv', 4, 20, 'Matthew Henry', 'Solomon, having warned us not to do evil, here teaches us how to do well. It is not enough for us to shun the occasions of sin, but we must study the methods of duty.\nI. We must have a continual regard to the word of God and endeavour that it may be always ready to us.\n1. The sayings of wisdom must be our principles by which we must govern ourselves, our monitors to warn us of duty and danger; and therefore, (1.) We must receive them readily: "Incline thy ear to them (Pro 4:20); humbly bow to...', 'teologico');
add('pv', 5, 1, 'Matthew Henry', 'Here we have,\nI. A solemn preface, to introduce the caution which follows, Pro 5:1, Pro 5:2. Solomon here addresses himself to his son, that is, to all young men, as unto his children, whom he has an affection for and some influence upon. In God\'s name, he demands attention; for he writes by divine inspiration, and is a prophet, though he begins not with, Thus saith the Lord. "Attend, and bow thy ear; not only hear what is said, and read what is written, but apply thy mind to it and consider ...', 'teologico');
add('pv', 5, 15, 'Matthew Henry', 'Solomon, having shown the great evil that there is in adultery and fornication, and all such lewd and filthy courses, here prescribes remedies against them.\nI. Enjoy with satisfaction the comforts of lawful marriage, which was ordained for the prevention of uncleanness, and therefore ought to be made use of in time, lest it should not prove effectual for the cure of that which it might have prevented. Let none complain that God has dealt unkindly with them in forbidding them those pleasures w...', 'teologico');
add('pv', 6, 1, 'Matthew Henry', 'It is the excellency of the word of God that it teaches us not only divine wisdom for another world, but human prudence for this world, that we may order our affairs with discretion; and this is one good rule, To avoid suretiship, because by it poverty and ruin are often brought into families, which take away that comfort in relations which he had recommended in the foregoing chapter. 1. We must look upon suretiship as a snare and decline it accordingly, Pro 6:1, Pro 6:2. "It is dangerous eno...', 'teologico');
add('pv', 6, 6, 'Matthew Henry', 'Solomon, in these verses, addresses himself to the sluggard who loves his ease, lives in idleness, minds no business, sticks to nothing, brings nothing to pass, and in a particular manner is careless in the business of religion. Slothfulness is as sure a way to poverty, though not so short a way, as rash suretiship. He speaks here to the sluggard,\nI. By way of instruction, Pro 6:6-8. He sends him to school, for sluggards must be schooled. He is to take him to school himself, for, if the schol...', 'teologico');
add('pv', 6, 12, 'Matthew Henry', 'Solomon here gives us,\nI. The characters of one that is mischievous to man and dangerous to be dealt with. If the slothful are to be condemned, that do nothing, much more those that do ill, and contrive to do all the ill they can. It is a naughty person that is here spoken of, Heb. A man of Belial; I think it should have been so translated, because it is a term often used in scripture, and this is the explication of it. Observe,\n1. How a man of Belial is here described. He is a wicked man, th...', 'teologico');
add('pv', 6, 20, 'Matthew Henry', 'Here is, I. A general exhortation faithfully to adhere to the word of God and to take it for our guide in all our actions.\n1. We must look upon the word of God both as a light (Pro 6:23) and as a law, Pro 6:20, Pro 6:23. (1.) By its arguments it is a light, which our understandings must subscribe to; it is a lamp to our eyes for discovery, and so to our feet for direction. The word of God reveals to us truths of eternal certainty, and is built upon the highest reason. Scripture-light is the s...', 'teologico');
add('pv', 7, 1, 'Matthew Henry', 'These verses are an introduction to his warning against fleshly lusts, much the same with that, Pro 6:20, etc., and ending (Pro 7:5) as that did (Pro 6:24), To keep thee from the strange woman; that is it he aims at; only there he had said, Keep thy father\'s commandment, here (which comes all to one), Keep my commandments, for he speaks to us as unto sons. He speaks in God\'s name; for it is God\'s commandments that we are to keep, his words, his law. The word of God must be to us, 1. As that w...', 'teologico');
add('pv', 7, 6, 'Matthew Henry', 'Solomon here, to enforce the caution he had given against the sin of whoredom, tells a story of a young man that was ruined to all intents and purposes by the enticements of an adulterous woman. Such a story as this would serve the lewd profane poets of our age to make a play of, and the harlot with them would be a heroine; nothing would be so entertaining to the audience, nor give them so much diversion, as her arts of beguiling the young gentleman and drawing in the country squire; her conq...', 'teologico');
add('pv', 7, 24, 'Matthew Henry', 'We have here the application of the foregoing story: "Hearken to me therefore, and not to such seducers (Pro 7:24); give ear to a father, and not to an enemy." 1. "Take good counsel when it is given you. Let not thy heart decline to her ways (Pro 7:25); never leave the paths of virtue, though strait and narrow, solitary and up-hill, for the way of the adulteress, though green, and broad, and crowded with company. Do not only keep thy feet from those ways, but let not so much as thy heart incl...', 'teologico');
add('pv', 8, 1, 'Matthew Henry', 'The will of God revealed to us for our salvation is here largely represented to us as easy to be known and understood, that none may have an excuse for their ignorance or error, and as worthy to be embraced, that none may have an excuse for their carelessness and unbelief.\nI. The things revealed are easy to be known, for they belong to us and to our children (Deu 29:29), and we need not soar up to heaven, or dive into the depths, to get the knowledge of them (Deu 30:11), for they are publishe...', 'teologico');
add('pv', 8, 12, 'Matthew Henry', 'Wisdom here is Christ, in whom are hidden all the treasures of wisdom and knowledge; it is Christ in the word and Christ in the heart, not only Christ revealed to us, but Christ revealed in us. It is the word of God, the whole compass of divine revelation; it is God the Word, in whom all divine revelation centres; it is the soul formed by the word; it is Christ formed in the soul; it is religion in the purity and power of it. Glorious things are here spoken of this excellent person, this exce...', 'teologico');
add('pv', 8, 22, 'Matthew Henry', 'That it is an intelligent and divine person that here speaks seems very plain, and that it is not meant of a mere essential property of the divine nature, for Wisdom here has personal properties and actions; and that intelligent divine person can be no other than the Son of God himself, to whom the principal things here spoken of wisdom are attributed in other scriptures, and we must explain scripture by itself. If Solomon himself designed only the praise of wisdom as it is an attribute of Go...', 'teologico');
add('pv', 8, 32, 'Matthew Henry', 'We have here the application of Wisdom\'s discourse; the design and tendency of it is to bring us all into an entire subjection to the laws of religion, to make us wise and good, not to fill our heads with speculations, or our tongues with disputes, but to rectify what is amiss in our hearts and lives. In order to this, here is,\nI. An exhortation to hear and obey the voice of Wisdom, to attend and comply with the good instructions that the word of God gives us, and in them to discern the voice...', 'teologico');
add('pv', 9, 1, 'Matthew Henry', 'Wisdom is here introduced as a magnificent and munificent queen, very great and very generous; that Word of God is this Wisdom in which God makes known his goodwill towards men; God the Word is this Wisdom, to whom the Father has committed all judgment. He who, in the chapter before, showed his grandeur and glory as the Creator of the world, here shows his grace and goodness as the Redeemer of it. The word is plural, Wisdoms; for in Christ are hid treasures of wisdom, and in his undertaking a...', 'teologico');
add('pv', 9, 13, 'Matthew Henry', 'We have heard what Christ has to say, to engage our affections to God and godliness, and one would think the whole world should go after him; but here we are told how industrious the tempter is to seduce unwary souls into the paths of sin, and with the most he gains his point, and Wisdom\'s courtship is not effectual. Now observe,\nI. Who is the tempter - a foolish woman, Folly herself, in opposition to Wisdom. Carnal sensual pleasure I take to be especially meant by this foolish woman (Pro 9:1...', 'teologico');
add('pv', 10, 1, 'Matthew Henry', 'Solomon, speaking to us as unto children, observes here how much the comfort of parents, natural, political, and ecclesiastical, depends upon the good behaviour of those under their charge, as a reason, 1. Why parents should be careful to give their children a good education, and to train them up in the ways of religion, which, if it obtain the desired effect, they themselves will have the comfort of it, or, if not, they will have for their support under their heaviness that they have done th...', 'teologico');
add('pv', 10, 2, 'Matthew Henry', 'These two verses speak to the same purport, and the latter may be the reason of the former. 1. That wealth which men get unjustly will do them no good, because God will blast it: Treasures of wickedness profit nothing, Pro 10:2. The treasures of wicked people, much more the treasure which they have made themselves masters of by any wicked people, by oppression of fraud, though it be ever so much, as a treasure, and laid up ever so safely, though it be hidden treasure, yet it profits nothing; ...', 'teologico');
add('pv', 10, 4, 'Matthew Henry', 'We are here told, 1. Who those are who, though rich, are in a fair way to become poor - those who deal with a slack hand, who are careless and remiss in their business, and never mind which end goes foremost, nor ever set their hands vigorously to their work or stick to it; those who deal with a deceitful hand (so it may be read); those who think to enrich themselves by fraud and tricking will, in the end, impoverish themselves, not only by bringing the curse of God on what they have, but by ...', 'teologico');
add('pv', 10, 5, 'Matthew Henry', 'Here is, 1. The just praise of those who improve their opportunities, who take pains to gather and increase what they have, both for soul and body, who provide for hereafter while provision is to be made, who gather in summer, which is gathering time. He who does so is a wise son, and it is his honour; he acts wisely for his parents, whom, if there be occasion, he ought to maintain, and he gives reputation to himself, his family, and his education. 2. The just reproach and blame of those who ...', 'teologico');
add('pv', 10, 6, 'Matthew Henry', 'Here is, 1. The head of the just crowned with blessings, with the blessings both of God and man. Variety of blessings, abundance of blessings, shall descend from above, and visibly abide on the head of good men, real blessings; they shall not only be spoken well of, but done well to. Blessings shall be on their head as a coronet to adorn and dignify them and as a helmet to protect and secure them. 2. The mouth of the wicked covered with violence. Their mouths shall be stopped with shame for t...', 'teologico');
add('pv', 10, 7, 'Matthew Henry', 'Both the just and the wicked, when their days are fulfilled, must die. Between their bodies in the grave thee is no visible difference; between the souls of the one and the other, in the world of spirits, thee is a vast difference, and so there is, or ought to be, between their memories, which survive them.\nI. Good men are and ought to be well spoken of when they are gone; it is one of the blessings that comes upon the head of the just, even when their head is laid. Blessed men leave behind t...', 'teologico');
add('pv', 10, 8, 'Matthew Henry', 'Here is, 1. The honour and happiness of the obedient. They will receive commandments; they will take it as a privilege, and really an ease to them, to be under government, which saves them the labour of deliberating and choosing for themselves; and they will take it as a favour to be told their duty and admonished concerning it. And this is their wisdom; those are wise in heart who are tractable, and those who thus bend, thus stoop, shall stand and be established, shall prosper, being well ad...', 'teologico');
add('pv', 10, 9, 'Matthew Henry', 'We are here told, and we may depend upon it, 1. That men\'s integrity will be their security: He that walks uprightly towards God and man, that is faithful to both, that designs as he ought and means as he says, walks surely; he is safe under a divine protection and easy in a holy security. He goes on his way with a humble boldness, being well armed against the temptations of Satan, the troubles of the world, and the reproaches of men. he knows what ground he stands on, what guide he follows, ...', 'teologico');
add('pv', 10, 10, 'Matthew Henry', 'Mischief is here said to attend, 1. Politic, designing, self-disguising sinners: He that winks with the eye, as if he took no notice of you, when at the same time he is watching an opportunity to do you an ill turn, that makes signs to his accomplices when to come into assist him in executing his wicked projects, which are all carried on by trick and artifice, causes sorrow both to others and to himself. Ingenuity will be no excuse for iniquity, but the sinner must either repent or do worse, ...', 'teologico');
add('pv', 10, 11, 'Matthew Henry', 'See here, 1. How industrious a good man is, by communicating his goodness, to do good with it: His mouth, the outlet of his mind, is a well of life; it is a constant spring, whence issues good discourse for the edification of others, like streams that water the ground and make it fruitful, and for their consolation, like streams that quench the thirst of the weary traveller. It is like a well of life, that is pure and clean, not only not poisoned, but not muddled, with any corrupt communicati...', 'teologico');
add('pv', 10, 12, 'Matthew Henry', 'Here is, 1. The great mischief-maker, and that is malice. Even where there is no manifest occasion of strife, yet hatred seeks occasion and so stirs it up and does the devil\'s work. Those are the most spiteful ill-natured people that can be who take a pleasure in setting their neighbours together by the ears, by tale-bearing, evil surmises, and misrepresentations, blowing up the sparks of contention, which had lain buried, into a flame, at which, with an unaccountable pleasure, they warm thei...', 'teologico');
add('pv', 10, 13, 'Matthew Henry', 'Observe, 1. Wisdom and grace are the honour of good men: He that has understanding, that good understanding which those have that do the commandments, wisdom is found in his lips, that is, it is discovered to be there, and consequently that he has within a good treasure of it, and it is derived thence for the benefit of others. It is a man\'s honour to have wisdom, but much more to be instrumental to make others wise. 2. Folly and sin are the shame of bad men: A rod is for the back of him that...', 'teologico');
add('pv', 10, 14, 'Matthew Henry', 'Observe, 1. It is the wisdom of the wise that they treasure up a stock of useful knowledge, which will be their preservation: Wisdom is therefore found in their lips (Pro 10:13), because it is laid up in their hearts, out of which store, like the good householder, they bring things new and old. Whatever knowledge may be at any time useful to us we must lay it up, because we know not but some time or other we may have occasion for it. We must continue laying up as long as we live; and be sure ...', 'teologico');
add('pv', 10, 15, 'Matthew Henry', 'This may be taken two ways: - 1. As a reason why we should be diligent in our business, that we may avoid that sinking dispiriting uneasiness which attends poverty, and may enjoy the benefit and comfort which those have that are beforehand in the world. Taking pains is really the way to make ourselves and our families easy. Or, rather, 2. As a representation of the common mistakes both of rich and poor, concerning their outward condition. (1.) Rich people think themselves happy because they a...', 'teologico');
add('pv', 10, 16, 'Matthew Henry', 'Solomon here confirms what his father had said (Psa 37:16), A little that a righteous man has is better than the riches of many wicked. 1. Perhaps a righteous man has no more than what he works hard for; he eats only the labour of his hands, but that labour tends to life; he aims at nothing but to get an honest livelihood, covets not to be rich and great, but is willing to live and maintain his family. Nor does it tend only to his own life, but he would enable himself to do good to others; he...', 'teologico');
add('pv', 10, 17, 'Matthew Henry', 'See here, 1. That those are in the right that do not only receive instruction, but retain it, that do not let it slip through carelessness, as most do, nor let it go to those that would rob them of it, that keep instruction safely, keep it pure and entire, keep it for their own use, that they may govern themselves by it, keep it for the benefit of others, that they may instruct them; those that do so are in the way of life, the way that has true comfort in it and eternal life at the end of it...', 'teologico');
add('pv', 10, 18, 'Matthew Henry', 'Observe here, Malice is folly and wickedness. 1. It is so when it is concealed by flattery and dissimulation: He is a fool, though he may think himself a politician, that hides hatred with lying lips, lest, if it break out, he should be ashamed before men and should lose the opportunity of gratifying his malice. Lying lips are bad enough of themselves, but have a peculiar malignity in them when they are made a cloak of maliciousness. But he is a fool who thinks to hide any thing from God. 2. ...', 'teologico');
add('pv', 10, 19, 'Matthew Henry', 'We are here admonished concerning the government of the tongue, that necessary duty of a Christian. 1. It is good to say little, because in the multitude of words there wanteth not sin, or sin doth not cease. Usually, those that speak much speak much amiss, and among many words there cannot but be many idle words, which they must shortly give an account of. Those that love to hear themselves talk do not consider what work they are making for repentance; for that will be wanted, and first or l...', 'teologico');
add('pv', 10, 20, 'Matthew Henry', 'We are here taught how to value men, not by their wealth and preferment in the world, but by their virtue.\nI. Good men are good for something. Though they may be poor and low in the world, and may not have power and riches to do good with, yet, as long as they have a mouth to speak, that will make them valuable and useful, and upon that account we must honour those that fear the Lord, because out of the good treasure of their heart they bring forth good things. 1. This makes them valuable: Th...', 'teologico');
add('pv', 10, 22, 'Matthew Henry', 'Worldly wealth is that which most men have their hearts very much upon, but they generally mistake both in the nature of the thing they desire and in the way by which they hope to obtain it; we are therefore told here, 1. What that wealth is which is indeed desirable, not having abundance only, but having it and no sorrow with it, no disquieting care to get and keep it, no vexation of spirit in the enjoyment of it, no tormenting grief for the loss of it, no guilt contracted by the abuse of it...', 'teologico');
add('pv', 10, 23, 'Matthew Henry', 'Here is, 1. Sin exceedingly sinful: It is as laughter to a fool to do mischief; it is as natural to him, and as pleasant, as it is to a man to laugh. Wickedness is his Isaac (that is the word here); it is his delight, his darling, and that in which he pleases himself. He makes a laughing matter of sin. When he is warned not to sin, from the consideration of the law of God and the revelation of his wrath against sin, he makes a jest of the admonition, and laughs at the shaking of the spear; wh...', 'teologico');
add('pv', 10, 24, 'Matthew Henry', 'It is here said, and said again, to the righteous, that it shall be well with them, and to the wicked, Woe to them; and these are set the one over against the other, for their mutual illustration.\nI. It shall be as ill with the wicked as they can fear, and as well with the righteous as they can desire. 1. The wicked, it is true, buoy themselves up sometimes in their wickedness with vain hopes which will deceive them, but at other times they cannot but be haunted with just fears, and those fea...', 'teologico');
add('pv', 10, 26, 'Matthew Henry', 'Observe, 1. Those that are of a slothful disposition, that love their ease and cannot apply their minds to any business, are not fit to be employed, no, not so much as to be sent on an errand, for they will neither deliver a message with any care nor make any haste back. Such therefore are very unmeet to be ministers, Christ\'s messengers; he will not own the sending forth of sluggards into his harvest. 2. Those that are guilty of so great an oversight as to entrust such with any affair, and p...', 'teologico');
add('pv', 10, 27, 'Matthew Henry', 'Observe, 1. Religion lengthens men\'s lives and crowns their hopes. What man is he that loves life? Let him fear God, and that will secure him from many things that would prejudice his life, and secure to him life enough in this world and eternal life in the other; the fear of the Lord will add days more than was expected, will add them endlessly, will prolong them to the days of eternity. What man is he that would see good days? Let him be religious, and then his days shall not only be many, ...', 'teologico');
add('pv', 10, 29, 'Matthew Henry', 'These two verses are to the same purport with those next before, intimating the happiness of the godly and the misery of the wicked; it is necessary that this be inculcated upon us, so loth are we to believe and consider it. 1. Strength and stability are entailed upon integrity: The way of the Lord (the providence of God, the way in which he walks towards us) is strength to the upright, confirms him in his uprightness. All God\'s dealings with him, merciful and afflictive, serve to quicken him...', 'teologico');
add('pv', 10, 31, 'Matthew Henry', 'Here, as before, men are judged of, and, accordingly, are justified or condemned, by their words, Mat 12:37. 1. It is both the proof and the praise of a man\'s wisdom and goodness that he speaks wisely and well. A good man, in his discourse, brings forth wisdom for the benefit of others. God gives him wisdom as a reward of his righteousness (Ecc 2:26), and he, in gratitude for that gift and justice to the giver, does good with it, and with his wise and pious discourses edifies many. He knows w...', 'teologico');
add('pv', 11, 2, 'Matthew Henry', 'Observe, 1. How he that exalts himself is here abased, and contempt put upon him. When pride comes then comes shame. Pride is a sin which men have reason to be themselves ashamed of; it is a shame to a man who springs out of the earth, who lives upon alms, depends upon God, and has forfeited all he has, to be proud. It is a sin which others cry out shame on and look upon with disdain; he that is haughty makes himself contemptible; it is a sin for which God often brings men down, as he did Neb...', 'teologico');
add('pv', 11, 3, 'Matthew Henry', 'It is not only promised that God will guide the upright, and threatened that he will destroy the transgressors, but, that we may be the more fully assured of both, it is here represented as if the nature of the thing were such on both sides that it would do it itself. 1. The integrity of an honest man will itself be his guide in the way of duty and the way of safety. His principles are fixed, his rule is certain, and therefore his way is plain; his sincerity keeps him steady, and he needs not...', 'teologico');
add('pv', 11, 4, 'Matthew Henry', 'Note, 1. The day of death will be a day of wrath. It is a messenger of God\'s wrath; therefore when Moses had meditated on man\'s mortality he takes occasion thence to admire the power of God\'s anger, Psa 110:1-7 :11. It is a debt owing, not to nature, but to God\'s justice. After death the judgment, and that is a day of wrath, Rev 6:17. 2. Riches will stand men in no stead that day. They will neither put by the stroke nor ease the pain, much less take out the sting; what profit will this world\'...', 'teologico');
add('pv', 11, 5, 'Matthew Henry', 'These two verses are, in effect, the same, and both to the same purport with Pro 11:3. For the truths are here of such certainty and weight that they cannot be too often inculcated. Let us govern ourselves by these principles.\nI. That the ways of religion are plain and safe, and in them we may enjoy a holy security. A living principle of honesty and grace will be, 1. Our best direction in the right way, in every doubtful case to say to us, This is the way, walk in it. He that acts without a g...', 'teologico');
add('pv', 11, 7, 'Matthew Henry', 'Note, 1. Even wicked men, while they live, may keep up a confident expectation of a happiness when they die, or at least a happiness in this world. The hypocrite has his hope, in which he wraps himself as the spider in her web. The worldling expects great matters from his wealth; he calls it goods laid up for many years, and hopes to take his ease in it and to be merry; but in death their expectation will be frustrated: the worldling must leave this world which he expected to continue in and ...', 'teologico');
add('pv', 11, 8, 'Matthew Henry', 'As always in death, so sometimes in life, the righteous are remarkably favoured and the wicked crossed. 1. Good people are helped out of the distresses which they thought themselves lost in, and their feet are set in a large room, Psa 66:12; Psa 34:19. God has found out a way to deliver his people even when they have despaired and their enemies have triumphed, as if the wilderness had shut them in. 2. The wicked have fallen into the distresses which they thought themselves far from, nay, whic...', 'teologico');
add('pv', 11, 9, 'Matthew Henry', 'Here is, 1. Hypocrisy designing ill. It is not only the murderer with his sword, but the hypocrite with his mouth, that destroys his neighbour, decoying him into sin, or into mischief, by the specious pretences of kindness and good-will. Death and life are in the power of the tongue, but no tongue more fatal than the flattering tongue. 2. Honesty defeating the design and escaping the snare: Through knowledge of the devices of Satan shall the just be delivered from the snares which the hypocri...', 'teologico');
add('pv', 11, 10, 'Matthew Henry', 'It is here observed,\nI. That good men are generally well-beloved by their neighbours, but nobody cares for wicked people. 1. It is true there are some few that are enemies to the righteous, that are prejudiced against God and godliness, and are therefore vexed to see good men in power and prosperity; but all indifferent persons, even those that have no great stock of religion themselves, have a good word for a good man; and therefore when it goes well with the righteous, when they are advance...', 'teologico');
add('pv', 11, 12, 'Matthew Henry', 'I. Silence is here recommended as an instance of true friendship, and a preservative of it, and therefore an evidence, 1. Of wisdom: A man of understanding, that has rule over his own spirit, if he be provoked, holds his peace, that he may neither give vent to his passion nor kindle the passion of others by any opprobrious language or peevish reflections. 2. Of sincerity: He that is of a faithful spirit, that is true, not only to his own promise, but to the interest of his friend, conceals ev...', 'teologico');
add('pv', 11, 14, 'Matthew Henry', 'Here is, 1. The bad omen of a kingdom\'s ruin: Where no counsel is, no consultation at all, but every thing done rashly, or no prudent consultation for the common good, but only caballing for parties and divided interests, the people fall, crumble into factions, fall to pieces, fall together by the ears, and fall an easy prey to their common enemies. Councils of war are necessary to the operations of war; two eyes see more than one; and mutual advice is in order to mutual assistance. 2. The go...', 'teologico');
add('pv', 11, 15, 'Matthew Henry', 'Here we are taught, 1. In general, that we may not use our estates as we will (he that gave them to us has reserved to himself a power to direct us how we shall use them, for they are not our own; we are but stewards), and further that God in his law consults our interests and teaches us that charity which begins at home, as well as that which must not end there. There is a good husbandry which is good divinity, and a discretion in ordering our affairs which is part of the character of a good...', 'teologico');
add('pv', 11, 16, 'Matthew Henry', 'Here, 1. It is allowed that strong men retain riches, that those who bustle in the world, who are men of spirit and interest, and are able to make their part good against all who stand in their way, are likely to keep what they have and to get more, while those who are weak are preyed upon by all about them. 2. It is taken for granted that a gracious woman is as solicitous to preserve her reputation for wisdom and modesty, humility and courtesy, and all those other graces that are the true or...', 'teologico');
add('pv', 11, 17, 'Matthew Henry', 'It is a common principle, Every one for himself. Proximus egomet mihi - None so near to me as myself. Now, if this be rightly understood, it will be a reason for the cherishing of gracious dispositions in ourselves and the crucifying of corrupt ones. We are friends or enemies to ourselves, even in respect of present comfort, according as we are or are not governed by religious principles. 1. A merciful, tender, good humoured man, does good to his own soul, makes and keeps himself easy. He has...', 'teologico');
add('pv', 11, 18, 'Matthew Henry', 'Note, 1. Sinners put a most fatal cheat upon themselves: The wicked works a deceitful work, builds himself a house upon the sand, which will deceive him when the storm comes, promises himself that by his sin which he will never gain; nay, it is cutting his throat when it smiles upon him. Sin deceived me, and by it slew me. 2. Saints lay up the best securities for themselves: He that sows righteousness, that is good, and makes it his business to do good, with an eye to a future recompence, he ...', 'teologico');
add('pv', 11, 19, 'Matthew Henry', 'It is here shown that righteousness, not only by the divine judgment, will end in life, and wickedness in death, but that righteousness, in its own nature, has a direct tendency to life and wickedness to death. 1. True holiness is true happiness; it is a preparative for it, a pledge and earnest of it. Righteousness inclines, disposes, and leads, the soul to life. 2. In like manner, those that indulge themselves in sin are fitting themselves for destruction. The more violent a man is in sinful...', 'teologico');
add('pv', 11, 20, 'Matthew Henry', 'It concerns us to know what God hates and what he loves, that we may govern ourselves accordingly, may avoid his displeasure and recommend ourselves to his favour. Now here we are told, 1. That nothing is more offensive to God than hypocrisy and double-dealing, for these are signified by the word which we translate frowardness, pretending justice, but intending wrong, walking in crooked ways, to avoid discovery. Those are of a froward heart who act in contradiction to that which is good, unde...', 'teologico');
add('pv', 11, 21, 'Matthew Henry', 'Observe, 1. That confederacies in sin shall certainly be broken, and shall not avail to protect the sinners: Though hand join in hand, though there are many that concur by their practice to keep wickedness in countenance, and engage to stand by one another in defending it against all the attacks of virtue and justice, - though they are in league for the support and propagation of it, - though wicked children tread in the steps of their wicked parents, and resolve to keep up the trade, in defi...', 'teologico');
add('pv', 11, 22, 'Matthew Henry', 'By discretion here we must understand religion and grace, a true taste and relish (so the word signifies) of the honours and pleasures that attend an unspotted virtue; so that a woman without discretion is a woman of a loose and dissolute conversation; and then observe, 1. It is taken for granted here that beauty or comeliness of body is as a jewel of gold, a thing very valuable, and, where there is wisdom and grace to guard against the temptations of it, it is a great ornament, (Gratior est ...', 'teologico');
add('pv', 11, 23, 'Matthew Henry', 'This tells us what the desire and expectation of the righteous and of the wicked are and how they will prove, what they would have and what they shall have. 1. The righteous would have good, only good; all they desire is that it may go well with all about them; they wish no hurt to any, but happiness to all; as to themselves, their desire is not to gratify any evil lust, but to obtain the favour of a good God and to preserve the peace of a good conscience; and good they shall have, that good ...', 'teologico');
add('pv', 11, 24, 'Matthew Henry', 'Note, 1. It is possible a man may grow rich by prudently spending what he has, may scatter in works of piety, charity, and generosity, and yet may increase; nay, by that means may increase, as the corn is increased by being sown. By cheerfully using what we have our spirits are exhilarated, and so fitted for the business we have to do, by minding which closely what we have is increased; it gains a reputation which contributes to the increase. But it is especially to be ascribed to God; he ble...', 'teologico');
add('pv', 11, 26, 'Matthew Henry', 'See here, 1. What use we are to make of the gifts of God\'s bounty; we must not hoard them up merely for our own advantage, that we may be enriched by them, but we must bring them forth for the benefit of others, that they may be supported and maintained by them. It is a sin, when corn is dear and scarce, to withhold it, in hopes that it will still grow dearer, so to keep up and advance the market, when it is already so high that the poor suffer by it; and at such a time it is the duty of thos...', 'teologico');
add('pv', 11, 27, 'Matthew Henry', 'Observe, 1. Those that are industrious to do good in the world get themselves beloved both with God and man: He that rises early to that which is good (so the word is), that seeks opportunities of serving his friends and relieving the poor, and lays out himself therein, procures favour. All about him love him, and speak well of him, and will be ready to do him a kindness; and, which is better than that, better than life, he has God\'s lovingkindness. 2. Those that are industrious to do mischie...', 'teologico');
add('pv', 11, 28, 'Matthew Henry', 'Observe, 1. Our riches will fail us when we are in the greatest need: He that trusts in them, as if they would secure him the favour of God and be his protection and portion, shall fall, as a man who lays his weight on a broken reed, which will not only disappoint him, but run into his hand and pierce him. 2. Our righteousness will stand us in stead when our riches fail us: The righteous shall then flourish as a branch, the branch of righteousness, like a tree whose leaf shall not wither, Psa...', 'teologico');
add('pv', 11, 29, 'Matthew Henry', 'Two extremes in the management of family-affairs are here condemned and the ill consequences of them foretold: - 1. Carefulness and carnal policy, on the one hand. There are those that by their extreme earnestness in pursuit of the world, their anxiety about their business and fretfulness about their losses, their strictness with their servants and their niggardliness towards their families, trouble their own houses and give continual vexation to all about them; while others think, by support...', 'teologico');
add('pv', 11, 30, 'Matthew Henry', 'This shows what great blessings good men are, especially those that are eminently wise, to the places where they live, and therefore how much to be valued. 1. The righteous are as trees of life; the fruits of their piety and charity, their instructions, reproofs, examples, and prayers, their interest in heaven, and their influence upon earth, are like the fruits of that tree, precious and useful, contributing to the support and nourishment of the spiritual life in many; they are the ornaments...', 'teologico');
add('pv', 11, 31, 'Matthew Henry', 'This, I think, is the only one of Solomon\'s proverbs that has that note of attention prefixed to it, Behold! which intimates that it contains not only an evident truth, which may be beheld, but an eminent truth, which must be considered. 1. Some understand both parts of a recompence in displeasure: The righteous, if they do amiss, shall be punished for their offences in this world; much more shall wicked people be punished for theirs, which are committed, not through infirmity, but with a hig...', 'teologico');
add('pv', 12, 2, 'Matthew Henry', 'Note, 1. We are really as we are with God. Those are happy, truly happy, for ever happy, that obtain favour of the Lord, though the world frown upon them, and they find little favour with men; for in God\'s favour is life, and that is the fountain of all good. On the other hand those are miserable whom he condemns, however men may applaud them, and cry them up; whom he condemns he condemns to the second death. 2. We are with God as we are with men, as we have our conversation in this world. Ou...', 'teologico');
add('pv', 12, 3, 'Matthew Henry', 'Note, 1. Though men may advance themselves by sinful arts, they cannot by such arts settle and secure themselves; though they may get large estates they cannot get such as will abide: A man shall not be established by wickedness; it may set him in high places, but they are slippery places, Psa 73:18. That prosperity which is raised by sin is built on the sand, and so it will soon appear. 2. Though good men may have but little of the world, yet that little will last, and what is honestly got w...', 'teologico');
add('pv', 12, 4, 'Matthew Henry', 'Note, 1. He that is blessed with a good wife is as happy as if he were upon the throne, for she is no less than a crown to him. A virtuous woman, that is pious and prudent, ingenious and industrious, that is active for the good of her family and looks well to the ways of her household, that makes conscience of her duty in every relation, a woman of spirit, that can bear crosses without disturbance, such a one owns her husband for her head, and therefore she is a crown to him, not only a credi...', 'teologico');
add('pv', 12, 5, 'Matthew Henry', 'Note, 1. The word of God is a discerner of the thoughts and intents of the heart, and judges them. We mistake if we imagine that thoughts are free. No, they are under the divine cognizance, and therefore under the divine command. 2. We ought to be observers of the thoughts and intents of our own hearts, and to judge of ourselves by them; for they are the first-born of the soul, that have most of its image undisguised. Right thoughts are a righteous man\'s best evidences, as nothing more certai...', 'teologico');
add('pv', 12, 6, 'Matthew Henry', 'In the foregoing verse the thoughts of the wicked and righteous were compared; here their words, and those are as the abundance of the heart is. 1. Wicked people speak mischief to their neighbours; and wicked indeed those are whose words are to lie in wait for blood; their tongues are swords to those that stand in their way, to good men whom they hate and persecute. See an instance, Luk 20:20, Luk 20:21. 2. Good men speak help to their neighbours: The mouth of the upright is ready to be opene...', 'teologico');
add('pv', 12, 7, 'Matthew Henry', 'We are here taught as before (Pro 12:3 and Pro 10:25, Pro 10:30), 1. That the triumphing of the wicked is short. They may be exalted for a while, but in a little time they are overthrown and are not; their trouble proves their overthrow, and those who made a great show disappear, and their place knows them no more. Turn the wicked, and they are not; they stand in such a slippery place that the least touch of trouble brings them down, like the apples of Sodom, which look fair, but touch them a...', 'teologico');
add('pv', 12, 8, 'Matthew Henry', 'We are here told whence to expect a good name. Reputation is what most have a high regard to and stand much upon. Now it is certain, 1. The best reputation is that which attends virtue and serious piety, and the prudent conduct of life: A man shall be commended by all that are wise and good, in conformity to the judgment of God himself, which we are sure is according to truth, not according to his riches or preferments, his craft and subtlety, but according to his wisdom, the honesty of his d...', 'teologico');
add('pv', 12, 9, 'Matthew Henry', 'Note, 1. It is the folly of some that they covet to make a great figure abroad, take place, and take state, as persons of quality, and yet want necessaries at home, and, if their debts were paid, would not be worth a morsel of bread, nay, perhaps, pinch their bellies to put it on their backs, that they may appear very gay, because fine feathers make fine birds. 2. The condition and character of those is every way better who content themselves in a lower sphere, where they are despised for the...', 'teologico');
add('pv', 12, 10, 'Matthew Henry', 'See here, 1. To how great a degree a good man will be merciful; he has not only a compassion for the human nature under its greatest abasements, but he regards even the life of his beast, not only because it is his servant, but because it is God\'s creature, and in conformity to Providence, which preserves man and beast. The beasts that are under our care must be provided for, must have convenient food and rest, must in no case be abused or tyrannised over. Balaam was checked for beating his a...', 'teologico');
add('pv', 12, 11, 'Matthew Henry', 'Note, 1. It is men\'s wisdom to mind their business and follow an honest calling, for that is the way, by the blessing of God, to get a livelihood: He that tills his land, of which he is either the owner or the occupant, that keeps to his word and is willing to take pains, if he do not raise an estate by it (what need is there of that?), yet he shall be satisfied with bread, shall have food convenient for himself and his family, enough to bear his charges comfortably through the world. Even th...', 'teologico');
add('pv', 12, 12, 'Matthew Henry', 'See here, 1. What is the care and aim of a wicked man; he would do mischief: He desires the net of evil men. "Oh that I were but as cunning as such a man, to make a hand of those I deal with, that I had but his art of over-reaching, that I could but take my revenge on one I have spite to as effectually as he can!" He desires the strong-hold, or fortress, of evil men (so some read it), to act securely in doing mischief, that it may not turn upon him. 2. What is the care and aim of a good man: ...', 'teologico');
add('pv', 12, 13, 'Matthew Henry', 'See here, 1. The wicked entangling themselves in trouble by their folly, when God in justice leaves them to themselves. They are often snared by the transgression of their lips and their throats are cut with their own tongues. By speaking evil of dignities they expose themselves to public justice; by giving ill language they become obnoxious to private resentments, are sued for defamation, and actions on the case for words are brought against them. Many a man has paid dearly in this world for...', 'teologico');
add('pv', 12, 14, 'Matthew Henry', 'We are here assured, for our quickening to every good word and work, 1. That even good words will turn to a good account (Pro 12:14): A man shall be satisfied with good (that is, he shall gain present comfort, that inward pleasure which is truly satisfying) by the fruit of his mouth, by the good he does with his pious discourse and prudent advice. While we are teaching others we may ourselves learn, and feed on the bread of life we break to others. 2. That good works, much more, will be abund...', 'teologico');
add('pv', 12, 15, 'Matthew Henry', 'See here, 1. What it is that keeps a fool from being wise: His way is right in his own eyes; he thinks he is in the right in every thing he does, and therefore asks no advice, because he does not apprehend he needs it; he is confident he knows the way, and cannot miss it, and therefore never enquires the way. The rule he goes by is to do that which is right in his own eyes, to walk in the way of his heart. Quicquid libet, licet - He makes his will his law. He is a fool that is governed by his...', 'teologico');
add('pv', 12, 16, 'Matthew Henry', 'Note, 1. Passion is folly: A fool is known by his anger (so some read it); not but that a wise man may be angry when there is just cause for it, but then he has his anger under check and direction, is lord of his anger, whereas a fool\'s anger lords it over him. He that, when he is provoked, breaks out into indecent expressions, in words or behaviour, whose passion alters his countenance, makes him outrageous, and leads him to forget himself, Nabal certainly is his name and folly is with him. ...', 'teologico');
add('pv', 12, 17, 'Matthew Henry', 'Here is, 1. A faithful witness commended for an honest man. He that makes conscience of speaking truth, and representing every thing fairly, to the best of his knowledge, whether in judgment or in common conversation, whether he be upon his oath or no, he shows forth righteousness; he makes it to appear that he is governed and actuated by the principles and laws of righteousness, and he promotes justice by doing honour to it and serving the administration of it. 2. A false witness condemned f...', 'teologico');
add('pv', 12, 18, 'Matthew Henry', 'The tongue is death or life, poison or medicine, as it is used. 1. There are words that are cutting and killing, that are like the piercings of a sword. Opprobrious words grieve the spirits of those to whom they are spoken, and cut them to the heart. Slanders, like a sword, wound the reputation of those of whom they are uttered, and perhaps incurably. Whisperings and evil surmises, like a sword, divide and cut asunder the bounds of love and friendship, and separate those that have been deares...', 'teologico');
add('pv', 12, 19, 'Matthew Henry', 'Be it observed, to the honour of truth, that sacred thing, 1. That, if truth be spoken, it will hold good, and, whoever may be disobliged by it and angry at it, yet it will keep its ground. Great is the truth and will prevail. What is true will be always true; we may abide by it, and need not fear being disproved and put to shame. 2. That, if truth be denied, yet in time it will transpire. A lying tongue, that puts false colours upon things, is but for a moment. The lie will be disproved. The...', 'teologico');
add('pv', 12, 20, 'Matthew Henry', 'Note, 1. Those that devise mischief contrive, for the accomplishing of it, how to impose upon others; but it will prove, in the end, that they deceive themselves. Those that imagine evil, under colour of friendship, have their hearts full of this and the other advantage and satisfaction which they shall gain by it, but it is all a cheat. Let them imagine it ever so artfully, deceivers will be deceived. 2. Those that consult the good of their neighbours, that study the things which make for pe...', 'teologico');
add('pv', 12, 21, 'Matthew Henry', 'Note, 1. Piety is a sure protection. If men be sincerely righteous, the righteous God has engaged that no evil shall happen to them. He will, by the power of his grace in them, that principle of justice, keep them from the evil of sin; so that, though they be tempted, yet they shall not be overcome by the temptation, and though they may come into trouble, into many troubles, yet to them those troubles shall have no evil in them, whatever they have to others (Psa 91:10), for they shall be over...', 'teologico');
add('pv', 12, 22, 'Matthew Henry', 'We are here taught, 1. To hate lying, and to keep at the utmost distance from it, because it is an abomination to the Lord, and renders those abominable in his sight that allow themselves in it, not only because it is a breach of his law, but because it is destructive to human society. 2. To make conscience of truth, not only in our words, but in all our actions, because those that deal truly and sincerely in all their dealings are his delight, and he is well pleased with them. We delight to ...', 'teologico');
add('pv', 12, 23, 'Matthew Henry', 'Note, 1. He that is wise does not affect to proclaim his wisdom, and it is his honour that he does not. He communicates his knowledge when it may turn to the edification of others, but he conceals it when the showing of it would only tend to his own commendation. Knowing men, if they be prudent men, will carefully avoid every thing that savours of ostentation, and not take all occasions to show their learning and reading, but only to use it for good purposes, and then let their own works prai...', 'teologico');
add('pv', 12, 24, 'Matthew Henry', 'Note, 1. Industry is the way to preferment. Solomon advanced Jeroboam because he saw that he was an industrious young man, and minded his business, Kg1 11:28. Men that take pains in study and serviceableness will thereby gain such an interest and reputation as will give them a dominion over all about them, by which means many have risen strangely. He that has been faithful in a few things shall be made ruler over many things. The elders, that labour in the word and doctrine, are worthy of dou...', 'teologico');
add('pv', 12, 25, 'Matthew Henry', 'Here is, 1. The cause and consequence of melancholy. It is heaviness in the heart; it is a load of care, and fear, and sorrow, upon the spirits, depressing them, and disabling them to exert themselves with any vigour on what is to be done or fortitude in what is to borne; it makes them stoop, prostrates and sinks them. Those that are thus oppressed can neither do the duty nor take the comfort of any relation, condition, or conversation. Those therefore that are inclined to it should watch and...', 'teologico');
add('pv', 12, 26, 'Matthew Henry', 'See here, 1. That good men do well for themselves; for they have in themselves an excellent character, and they secure to themselves an excellent portion, and in both they excel other people: The righteous is more abundant than his neighbour (so the margin); he is richer, though not in this world\'s goods, yet in the graces and comforts of the Spirit, which are the true riches. There is a true excellency in religion; it ennobles men, inspires them with generous principles, makes them substanti...', 'teologico');
add('pv', 12, 27, 'Matthew Henry', 'Here is, 1. That which may make us hate slothfulness and deceit, for the word here, as before, signifies both: The slothful deceitful man has roast meat, but that which he roasts is not what he himself took in hunting, no, it is what others took pains for, and he lives upon the fruit of their labours, like the drones in the hive. Or, if slothful deceitful men have taken any thing by hunting (as sportsmen are seldom men of business), yet they do not roast it when they have taken it; they have ...', 'teologico');
add('pv', 12, 28, 'Matthew Henry', 'The way of religion is here recommended to us, 1. As a straight, plain, easy way; it is the way of righteousness. God\'s commands (the rule we are to walk by) are all holy, just, and good. Religion has right reason and equity on its side; it is a path-way, a way which God has cast up for us (Isa 35:8); it is a highway, the king\'s highway, the King of kings\' highway, a way which is tracked before us by all the saints, the good old way, full of the footsteps of the flock. 2. As a safe, pleasant,...', 'teologico');
add('pv', 13, 2, 'Matthew Henry', 'Note, 1. If that which comes from within, out of the heart, be good, and from a good treasure, it will return with advantage. Inward comfort and satisfaction will be daily bread; nay, it will be a continual feast to those who delight in that communication which is to the use of edifying. 2. Violence done will recoil in the face of him that does it: The soul of the transgressors that harbours and plots mischief, and vents it by word and deed, shall eat violence; they shall have their belly ful...', 'teologico');
add('pv', 13, 3, 'Matthew Henry', 'Note, 1. A guard upon the lips is a guard to the soul. He that is cautious, that thinks twice before he speaks once, that, if he have thought evil, lays his hand upon his mouth to suppress it, that keeps a strong bridle on his tongue and a strict hand on that bridle, he keeps his soul from a great deal both of guilt and grief and saves himself the trouble of many bitter reflections on himself and reflections of others upon him. 2. There is many a one ruined by an ungoverned tongue: He that op...', 'teologico');
add('pv', 13, 4, 'Matthew Henry', 'Here is, 1. The misery and shame of the slothful. See how foolish and absurd they are; they desire the gains which the diligent get, but they hate the pains which the diligent take; they covet every thing that is to be coveted, but will do nothing that is to be done; and therefore it follows, They have nothing; for he that will not labour let him hunger, and let him not eat, Th2 3:10. The desire of the slothful, which should be his excitement, is his torment, which should make him busy, makes...', 'teologico');
add('pv', 13, 5, 'Matthew Henry', 'Note, 1. Where grace reigns sin is loathsome. It is the undoubted character of every righteous man that he hates lying (that is, all sin, for every sin is a lie, and particularly all fraud and falsehood in commerce and conversation), not only that he will not tell a lie, but he abhors lying, from a rooted reigning principle of love to truth and justice, and conformity to God. 2. Where sin reigns the man is loathsome. If his eyes were opened, and his conscience awakened, he would be so to hims...', 'teologico');
add('pv', 13, 6, 'Matthew Henry', 'See here, 1. Saints secured from ruin. Those that are upright in their way, that mean honestly in all their actions, adhere conscientiously to the sacred and eternal rules of equity, and deal sincerely both with God and man, their integrity will keep them from the temptations of Satan, which shall not prevail over them, the reproaches and injuries of evil men, which shall not fasten upon them, to do them any real mischief, Psa 25:21.\nHic murus aheneus esto, nil conscire sibi.\nBe this thy braz...', 'teologico');
add('pv', 13, 7, 'Matthew Henry', 'This observation is applicable,\nI. To men\'s worldly estate. The world is a great cheat, not only the things of the world, but the men of the world. All men are liars. Here is an instance in two sore evils under the sun: - 1. Some that are really poor would be thought to be rich and are thought to be so; they trade and spend as if they were rich, make a great bustle and a great show as if they had hidden treasures, when perhaps, if all their debts were paid, they are not worth a groat. This is...', 'teologico');
add('pv', 13, 8, 'Matthew Henry', 'We are apt to judge of men\'s blessedness, at least in this world, by their wealth, and that they are more or less happy accordingly as they have more or less of this world\'s goods; but Solomon here shows what a gross mistake it is, that we may be reconciled to a poor condition, and may neither covet riches ourselves nor envy those that have abundance. 1. Those that are rich, if by some they are respected for their riches, yet, to balance that, by others they are envied and struck at, and brou...', 'teologico');
add('pv', 13, 9, 'Matthew Henry', 'Here is, 1. The comfort of good men flourishing and lasting: The light of the righteous rejoices, that is, it increases, and makes them glad. Even their outward prosperity is their joy, and much more those gifts, graces, and comforts, with which their souls are illuminated; these shine more and more, Pro 4:18. The Spirit is their light, and he gives them a fulness of joy, and rejoices to do them good. 2. The comfort of bad men withering and dying: The lamp of the wicked burns dimly and faint;...', 'teologico');
add('pv', 13, 10, 'Matthew Henry', 'Note, 1. Foolish pride is the great make-bate. Would you know whence come wars and fightings? They come from this root of bitterness. Whatever hand other lusts may have in contention (passion, envy, covetousness), pride has the great hand; it is its pride that it will itself sow discord and needs no help. Pride makes men impatient of contradiction in either their opinions or their desires, impatient of competition and rivalship, impatient of contempt, or any thing that looks like a slight, an...', 'teologico');
add('pv', 13, 11, 'Matthew Henry', 'This shows that riches wear as they are won and woven. 1. That which is won ill will never wear well, for a curse attends it which will waste it, and the same corrupt dispositions which incline men to the sinful ways of getting well incline them to the like sinful ways of spending: Wealth gotten by vanity will be bestowed upon vanity, and then it will be diminished. That which is got by such employments as are not lawful, or not becoming Christians, such as only serve to feed pride and luxury...', 'teologico');
add('pv', 13, 12, 'Matthew Henry', 'Note, 1. Nothing is more grievous than the disappointment of a raised expectation, though not in the thing itself by a denial, yet in the time of it by a delay: Hope deferred makes the heart sick and languishing, fretful and peevish; but hope quite dashed kills the heart, and the more high the expectation was raised the more cutting is the frustration of it. It is therefore our wisdom not to promise ourselves any great matters from the creature, not to feed ourselves with any vain hopes from ...', 'teologico');
add('pv', 13, 13, 'Matthew Henry', 'Here is, 1. The character of one that is marked for ruin: He that despises the word of God, and has no regard to it, no veneration for it, nor will be ruled by it, certainly he shall be destroyed, for he slights that which is the only means of curing a destructive disease and makes himself obnoxious to that divine wrath which will certainly be his destruction. Those that prefer the rules of carnal policy before divine precepts, and the allurements of the world and the flesh before God\'s promi...', 'teologico');
add('pv', 13, 14, 'Matthew Henry', 'By the law of the wise and righteous, here, we may understand either the principles and rules by which they govern themselves or (which comes all to one) the instructions which they give to others, which ought to be as a law to all about them; and if they be so, 1. They will be constant springs of comfort and satisfaction, as a fountain of life, sending forth streams of living water; the closer we keep to those rules the more effectually we secure our own peace. 2. They will be constant prese...', 'teologico');
add('pv', 13, 15, 'Matthew Henry', 'If we compare not only the end, but the way, we shall find that religion has the advantage; for, 1. The way of saints is pleasant and agreeable: Good understanding gains favour with God and man; our Saviour grew in that favour when he increased in wisdom. Those that conduct themselves prudently, and order their conversation aright in every thing, that serve Christ in righteousness, and peace, and joy in the Holy Ghost, are accepted of God and approved of men, Rom 14:17, Rom 14:18. And how com...', 'teologico');
add('pv', 13, 16, 'Matthew Henry', 'Note, 1. It is wisdom to be cautious. Every prudent discreet man does all with knowledge (considering with himself and consulting with others), acts with deliberation and is upon the reserve, is careful not to meddle with that which he has not some knowledge of, not to launch out into business which he has not acquainted himself with, will not deal with those that he has not some knowledge of, whether they may be confided in. He is still dealing in knowledge, that he may increase the stock he...', 'teologico');
add('pv', 13, 17, 'Matthew Henry', 'Here we have, 1. The ill consequences of betraying a trust. A wicked messenger, who, being sent to negotiate any business, is false to him that employed him, divulges his counsels, and so defeats his designs, cannot expect to prosper, but will certainly fall into some mischief or other, will be discovered and punished, since nothing is more hateful to God and man than the treachery of those that have a confidence reposed in them. 2. The happy effects of fidelity: An ambassador who faithfully ...', 'teologico');
add('pv', 13, 18, 'Matthew Henry', 'Note, 1. He that is so proud that he scorns to be taught will certainly be abased. he that refuses the good instruction offered him, as if it were a reflection upon his honour and an abridgment of his liberty, poverty and shame shall be to him: he will become a beggar and live and die in disgrace; every one will despise him as foolish, and stubborn, and ungovernable. 2. He that is so humble that he takes it well to be told of his faults shall certainly be exalted: He that regards a reproof, w...', 'teologico');
add('pv', 13, 19, 'Matthew Henry', 'This shows the folly of those that refuse instruction, for they might be happy and will not. 1. They might be happy. There are in man strong desires of happiness; God has provided for the accomplishment of those desires, and that would be sweet to the soul, whereas the pleasures of sense are grateful only to the carnal appetite. The desire of good men towards the favour of God and spiritual blessings brings that which is sweet to their souls; we know those that can say so by experience, Psa 4...', 'teologico');
add('pv', 13, 20, 'Matthew Henry', 'Note, 1. Those that would be good must keep good company, which is an evidence for them that they would be good (men\'s character is known by the company they choose) and will be a means of making them good, of showing them the way and of quickening and encouraging them in it. He that would be himself wise must walk with those that are so, must choose such for his intimate acquaintance, and converse with them accordingly; must ask and receive instruction from them, and keep up pious and profit...', 'teologico');
add('pv', 13, 21, 'Matthew Henry', 'Here see, 1. How unavoidable the destruction of sinners is; the wrath of God pursues them, and all the terrors of that wrath: Evil pursues them closely wherever they go, as the avenger of blood pursued the manslayer, and they have no city of refuge to flee to; they attempt an escape, but in vain. Whom God pursues he is sure to overtake. They may prosper for a while and grow very secure, but their damnation slumbers not, though they do. 2. How indefeasible the happiness of the saints is; the G...', 'teologico');
add('pv', 13, 22, 'Matthew Henry', 'See here, 1. How a good man\'s estate lasts: He leaves an inheritance to his children\'s children. It is part of his praise that he is thoughtful for posterity, that he does not lay all out upon himself, but is in care to do well for those that come after him, not by withholding more than is meet, but by a prudent and decent frugality. He trains up his children to this, that they may leave it to their children; and especially he is careful, both by justice and charity, to obtain the blessing of...', 'teologico');
add('pv', 13, 23, 'Matthew Henry', 'See here, 1. How a small estate may be improved by industry, so that a man, by making the best of every thing, may live comfortably upon it: Much food is in the tillage of the poor, the poor farmers, that have but a little, but take pains with that little and husband it well. Many make it an excuse for their idleness that they have but a little to work on, a very little to be doing with; but the less compass the field is of the more let the skill and labour of the owner be employed about it, ...', 'teologico');
add('pv', 13, 24, 'Matthew Henry', 'Note, 1. To the education of children in that which is good there is necessary a due correction of them for what is amiss; every child of ours is a child of Adam, and therefore has that foolishness bound up in its heart which calls for rebuke, more or less, the rod and reproof which give wisdom. Observe, It is his rod that must be used, the rod of a parent, directed by wisdom and love, and designed for good, not the rod of a servant. 2. It is good to begin betimes with the necessary restraint...', 'teologico');
add('pv', 13, 25, 'Matthew Henry', 'Note, 1. It is the happiness of the righteous that they shall have enough and that they know when they have enough. They desire not to be surfeited, but, being moderate in their desires, they are soon satisfied. nature is content with a little and grace with less; enough is as good as a feast. Those that feed on the bread of life, that feast on the promises, meet with abundant satisfaction of soul there, eat, and are filled. 2. It is the misery of the wicked that, through the insatiableness o...', 'teologico');
add('pv', 14, 2, 'Matthew Henry', 'Here are, 1. Grace and sin in their true colours. Grace reigning is a reverence of God, and gives honour to him who is infinitely great and high, and to whom all honour is due, than which what is more becoming or should be more pleasing to the rational creature? Sin reigning is no less than a contempt of God. In this, more than in any thing, sin appears exceedingly sinful, that it despises God, whom angels adore. Those that despise God\'s precepts, and will not be ruled by them, his promises, ...', 'teologico');
add('pv', 14, 3, 'Matthew Henry', 'See here, 1. A proud fool exposing himself. Where there is pride in the heart, and no wisdom in the head to suppress it, it commonly shows itself in the words: In the mouth there is pride, proud boasting, proud censuring, proud scorning, proud commanding and giving law; this is the rod, or branch, of pride; the word is used only here and Isa 11:1. It grows from that root of bitterness which is in the heart; it is a rod from that stem. The root must be plucked up, or we cannot conquer this bra...', 'teologico');
add('pv', 14, 4, 'Matthew Henry', 'Note, 1. The neglect of husbandry is the way to poverty: Where no oxen are, to till the ground and tread out the corn, the crib is empty, is clean; there is no straw for the cattle, and consequently no bread for the service of man. Scarcity is represented by cleanness of teeth, Amo 4:6. Where no oxen are there is nothing to be done at the ground, and then nothing to be had out of it; the crib indeed is clean from dung, which pleases the neat and nice, that cannot endure husbandry because ther...', 'teologico');
add('pv', 14, 5, 'Matthew Henry', 'In the administration of justice much depends upon the witnesses, and therefore it is necessary to the common good that witnesses be principled as they ought to be; for, 1. A witness that is conscientious will not dare to give in a testimony that is in the least untrue, nor, for good-will or ill-will, represent a thing otherwise than according to the best of his knowledge, whoever is pleased or displeased, and then judgment runs down like a river. 2. But a witness that will be bribed, and bia...', 'teologico');
add('pv', 14, 6, 'Matthew Henry', 'Note, 1. The reason why some people seek wisdom, and do not find it, is because they do not seek it from a right principle and in a right manner. They are scorners, and it is in scorn that they ask instruction, that they may ridicule what is told them and may cavil at it. Many put questions to Christ, tempting him, and that they might have whereof to accuse him, but they were never the wiser. No marvel if those who seek wisdom, as Simon Magus sought the gifts of the Holy Ghost, to serve their...', 'teologico');
add('pv', 14, 7, 'Matthew Henry', 'See here, 1. How we may discern a fool and discover him, a wicked man, for he is a foolish man. If we perceive not in him the lips of knowledge, if we find there is no relish or savour of piety in his discourse, that his communication is all corrupt and corrupting, and nothing in it good and to the use of edifying, we may conclude the treasure is bad. 2. How we must decline such a one and depart from him: Go from his presence, for thou perceivest there is no good to be gotten by his company, ...', 'teologico');
add('pv', 14, 8, 'Matthew Henry', 'See here, 1. The good conduct of a wise and good man; he manages himself well. it is not the wisdom of the learned, which consists only in speculation, that is here recommended, but the wisdom of the prudent, which is practical, and is of use to direct our counsels and actions. Christian prudence consists in a right understanding of our way; for we are travellers, whose concern it is, not to spy wonders, but to get forward towards their journey\'s end. It is to understand our own way, not to b...', 'teologico');
add('pv', 14, 9, 'Matthew Henry', 'See here, 1. How wicked people are hardened in their wickedness: they make a mock at sin. They make a laughing matter of the sins of others, making themselves and their companions merry with that for which they should mourn, and they make a light matter of their own sins, both when they are tempted to sin and when they have committed it; they call evil good and good evil (Isa 5:20), turn it off with a jest, rush into sin (Jer 8:6) and say they shall have peace though they go on. They care not...', 'teologico');
add('pv', 14, 10, 'Matthew Henry', 'This agrees with Co1 2:11, What man knows the things of a man, and the changes of his temper, save the spirit of a man? 1. Every man feels most from his own burden, especially that which is a burden upon the spirits, for that is commonly concealed and the sufferer keeps it to himself. We must not censure the griefs of others, for we know not what they feel; their stroke perhaps is heavier than their groaning. 2. Many enjoy a secret pleasure, especially in divine consolations, which others are...', 'teologico');
add('pv', 14, 11, 'Matthew Henry', 'Note, 1. Sin is the ruin of great families: The house of the wicked, though built ever so strong and high, shall be overthrown, shall be brought to poverty and disgrace, and at length be extinct. His hope for heaven, the house on which he leans, shall not stand, but fail in the storm; the deluge that comes will sweep it away. 2. Righteousness is the rise and stability even of mean families: Even the tabernacle of the upright, though movable and despicable as a tent, shall flourish, in outward...', 'teologico');
add('pv', 14, 12, 'Matthew Henry', 'We have here an account of the way and end of a great many self-deluded souls. 1. Their way is seemingly fair: It seems right to themselves; they please themselves with a fancy that they are as they should be, that their opinions and practices are good, and such as will bear them out. The way of ignorance and carelessness, the way of worldliness and earthly-mindedness, the way of sensuality and flesh-pleasing, seem right to those that walk in them, much more the way of hypocrisy in religion, ...', 'teologico');
add('pv', 14, 13, 'Matthew Henry', 'This shows the vanity of carnal mirth, and proves what Solomon said of laughter, that it is mad; for, 1. There is sadness under it. Sometimes when sinners are under convictions, or some great trouble, they dissemble their grief by a forced mirth, and put a good face on it, because they will not seem to yield: they cry not when he binds them. Nay, when men really are merry, yet at the same time there is some alloy or other to their mirth, something that casts a damp upon it, which all their ga...', 'teologico');
add('pv', 14, 14, 'Matthew Henry', 'Note, 1. The misery of sinners will be an eternal surfeit upon their sins: The backslider in heart, who for fear of suffering, or in hope of profit or pleasure, forsakes God and his duty, shall be filled with his own ways; God will give him enough of them. They would not leave their brutish lusts and passions, and therefore they shall stick by them, to their everlasting terror and torment. He that is filthy shall be filthy still. "Son, remember," shall fill them with their own ways, and set t...', 'teologico');
add('pv', 14, 15, 'Matthew Henry', 'Note, 1. It is folly to be credulous, to heed every flying report, to give ear to every man\'s story, though ever so improbable, to take things upon trust from common fame, to depend upon every man\'s profession of friendship and give credit to every one that will promise payment; those are simple who thus believe every word, forgetting that all men, in some sense, are liars in comparison with God, all whose words we are to believe with an implicit faith, for he cannot lie. 2. It is wisdom to b...', 'teologico');
add('pv', 14, 16, 'Matthew Henry', 'Note, 1. Holy fear is an excellent guard upon every holy thing, and against every thing that is unholy. It is wisdom to depart from evil, from the evil of sin, and thereby from all other evil; and therefore it is wisdom to fear, that is, to be jealous over ourselves with a godly jealousy, to keep up a dread of God\'s wrath, to be afraid of coming near the borders of sin or dallying with the beginnings of it. A wise man, for fear of harm, keeps out of harm\'s way, and starts back in a fright whe...', 'teologico');
add('pv', 14, 17, 'Matthew Henry', 'Note, 1. Passionate men are justly laughed at. Men who are peevish and touchy, and are soon angry upon every the least provocation, deal foolishly; they say and do that which is ridiculous, and so expose themselves to contempt; they themselves cannot but be ashamed of it when the heat is over. The consideration of this should engage those especially who are in reputation for wisdom and honour with the utmost care to bridle their passion. 2. Malicious men are justly dreaded and detested, for t...', 'teologico');
add('pv', 14, 18, 'Matthew Henry', 'Note, 1. Sin is the shame of sinners: The simple, who love simplicity, get nothing by it; they inherit folly. They have it by inheritance, so some. This corruption of nature is derived from our first parents, and all the calamities that attend it we have by kind; it was the inheritance they transmitted to their degenerate race, an hereditary disease. They are as fond of it as a man of his inheritance, hold it as fast, and are as loth to part with it. What they value themselves upon is really ...', 'teologico');
add('pv', 14, 19, 'Matthew Henry', 'That is, 1. The wicked are oftentimes impoverished and brought low, so that they are forced to beg, their wickedness having reduced them to straits; while good men, by the blessing of God, are enriched, and enabled to give, and do give, even to the evil; for where God grants life we must not deny a livelihood. 2. Sometimes God extorts, even from bad men, an acknowledgement of the excellency of God\'s people. The evil ought always to bow before the good, and sometimes they are made to do it and...', 'teologico');
add('pv', 14, 20, 'Matthew Henry', 'This shows, not what should be, but what is the common way of the world - to be shy of the poor and fond of the rich. 1. Few will give countenance to those whom the world frowns upon, though otherwise worthy of respect: The poor, who should be pitied, and encouraged, and relieved, is hated, looked strange upon, and kept at a distance, even by his own neighbour, who, before he fell into disgrace, was intimate with him and pretended to have a kindness for him. Most are swallow-friends, that are...', 'teologico');
add('pv', 14, 21, 'Matthew Henry', 'See here how men\'s character and condition are measured and judged of by their conduct towards their poor neighbours. 1. Those that look upon them with contempt have here assigned them a bad character, and their condition will be accordingly: He that despises his neighbour because he is low in the world, because he is of a mean extraction, rustic education, and makes but a mean figure, that thinks it below him to take notice of him, converse with him, or concern himself about him, and sets hi...', 'teologico');
add('pv', 14, 22, 'Matthew Henry', 'See here, 1. How miserably mistaken those are that not only do evil, but devise it: Do they not err? Yes, certainly they do; every one knows it. They think that by sinning with craft and contrivance, and carrying on their intrigues with more plot and artifice than others, they shall make a better hand of their sins than others do, and come off better. But they are mistaken. God\'s justice cannot be out-witted. Those that devise evil against their neighbours greatly err, for it will certainly t...', 'teologico');
add('pv', 14, 23, 'Matthew Henry', 'Note, 1. Working, without talking, will make men rich: In all labour of the head, or of the hand, there is profit; it will turn to some good account or other. Industrious people are generally thriving people, and where there is something done there is something to be had. The stirring hand gets a penny. It is good therefore to keep in business, and to keep in action, and what our hand finds to do to do it with all our might. 2. Talking, without working, will make men poor. Those that love to ...', 'teologico');
add('pv', 14, 24, 'Matthew Henry', 'Observe, 1. If men be wise and good, riches make them so much the more honourable and useful: The crown of the wise is their riches; their riches make them to be so much the more respected, and give them the more authority and influence upon others. Those that have wealth, and wisdom to use it, will have a great opportunity of honouring God and doing good in the world. Wisdom is good without an inheritance, but better with it. 2. If men be wicked and corrupt, their wealth will but the more ex...', 'teologico');
add('pv', 14, 25, 'Matthew Henry', 'See here, 1. How much praise is due to a faithful witness: He delivers the souls of the innocent, who are falsely accused, and their good names, which are as dear to them as their lives. A man of integrity will venture the displeasure of the greatest, to bring truth to light and rescue those who are injured by falsehood. A faithful minister, who truly witnesses for God against sin, is thereby instrumental to deliver souls from eternal death. 2. How little regard is to be had to a false witnes...', 'teologico');
add('pv', 14, 26, 'Matthew Henry', 'In these two verses we are invited and encouraged to live in the fear of God by the advantages which attend a religious life. The fear of the Lord is here put for all gracious principles, producing gracious practices. 1. Where this reigns it produces a holy security and serenity of mind. There is in it a strong confidence; it enables a man still to hold fast both his purity and his peace, whatever happens, and gives him boldness before God and the world. I know that I shall be justified - Non...', 'teologico');
add('pv', 14, 28, 'Matthew Henry', 'Here are two maxims in politics, which carry their own evidence with them: - 1. That it is much for the honour of a king to have a populous kingdom; it is a sign that he rules well, since strangers are hereby invited to come and settle under his protection and his own subjects live comfortably; it is a sign that he and his kingdom are under the blessing of God, the effect of which is being fruitful and multiplying. It is his strength, and makes him considerable and formidable; happy is the ki...', 'teologico');
add('pv', 14, 29, 'Matthew Henry', 'Note, 1. Meekness is wisdom. He rightly understands himself, and his duty and interest, the infirmities of human nature, and the constitution of human society, who is slow to anger, and knows how to excuse the faults of others as well as his own, how to adjourn his resentments, and moderate them, so as by no provocation to be put out of the possession of his own soul. A mild patient man is really to be accounted an intelligent man, one that learns of Christ, who is Wisdom itself. 2. Unbridled...', 'teologico');
add('pv', 14, 30, 'Matthew Henry', 'The foregoing verse showed how much our reputation, this how much our health, depends on the good government of our passions and the preserving of the temper of the mind. 1. A healing spirit, made up of love and meekness, a hearty, friendly, cheerful disposition, is the life of the flesh; it contributes to a good constitution of body; people grow fat with good humour. 2. A fretful, envious, discontented spirit, is its own punishment; it consumes the flesh, preys upon the animal spirits, makes...', 'teologico');
add('pv', 14, 31, 'Matthew Henry', 'God is here pleased to interest himself more than one would imagine in the treatment given to the poor. 1. He reckons himself affronted in the injuries that are done them. Whosoever he be that wrongs a poor man, taking advantage against him because he is poor and cannot help himself, let him know that he puts an affront upon his Maker. God made him, and gave him his being, the same that is the author of our being; we have all one Father, one Maker; see how Job considered this, Job 31:15. God ...', 'teologico');
add('pv', 14, 32, 'Matthew Henry', 'Here is, 1. The desperate condition of a wicked man when he goes out of the world: He is driven away in his wickedness. He cleaves so closely to the world that he cannot find in his heart to leave it, but is driven away out of it; his soul is required, is forced from him, And sin cleaves so closely to him that it is inseparable; it goes with him into another world; he is driven away in his wickedness, dies in his sins, under the guilt and power of them, unjustified, unsanctified. His wickedne...', 'teologico');
add('pv', 14, 33, 'Matthew Henry', 'Observe, 1. Modesty is the badge of wisdom. He that is truly wise hides his treasure, so as not to boast of it (Mat 13:44), though he does not hide his talent, so as not to trade with it. His wisdom rests in his heart; he digests what he knows, and has it ready to him, but does not unseasonably talk of it and make a noise with it. The heart is the seat of the affections, and there wisdom must rest in the practical love of it, and not swim in the head. 2. Openness and ostentation are a mark of...', 'teologico');
add('pv', 14, 34, 'Matthew Henry', 'Note, 1. Justice, reigning in a nation, puts an honour upon it. A righteous administration of the government, impartial equity between man and man, public countenance given to religion, the general practice and profession of virtue, the protecting and preserving of virtuous men, charity and compassion to strangers (alms are sometimes called righteousness), these exalt a nation; they uphold the throne, elevate the people\'s minds, and qualify a nation for the favour of God, which will make them...', 'teologico');
add('pv', 14, 35, 'Matthew Henry', 'This shows that in a well-ordered court and government smiles and favours are dispensed among those that are employed in public trusts according to their merits; Solomon lets them know he will go by that rule, 1. That those who behave themselves wisely shall be respected and preferred, whatever enemies they may have that seek to undermine them. No man\'s services shall be neglected to please a party or a favourite. 2. That those who are selfish and false, who betray their country, oppress the ...', 'teologico');
add('pv', 15, 2, 'Matthew Henry', 'Note, 1. A good heart by the tongue becomes very useful. He that has knowledge is not only to enjoy it, for his own entertainment, but to use it, to use it aright, for the edification of others; and it is the tongue that must make use of it in pious profitable discourse, in giving suitable and seasonable instructions, counsels, and comforts, with all possible expressions of humility and love, and then knowledge is used aright; and to him that has, and thus uses what he has, more shall be give...', 'teologico');
add('pv', 15, 3, 'Matthew Henry', 'The great truths of divinity are of great use to enforce the precepts of morality, and none more than this - That the eye of God is always upon the children of men. 1. An eye to discern all, not only from which nothing can be concealed, but by which every thing is actually inspected, and nothing overlooked or looked slightly upon: The eyes of the Lord are in every place; for he not only sees all from on high (Psa 33:13), but he is every where present. Angels are full of eyes (Rev 4:8), but Go...', 'teologico');
add('pv', 15, 4, 'Matthew Henry', 'Note, 1. A good tongue is healing, healing to wounded consciences by comforting them, to sin-sick souls by convincing them, to peace and love when it is broken by accommodating differences, compromising matters in variance, and reconciling parties at variance; this is the healing of the tongue, which is a tree of life, the leaves of which have a sanative virtue, Rev 22:2. He that knows how to discourse will make the place he lives in a paradise. 2. An evil tongue is wounding (perverseness, pa...', 'teologico');
add('pv', 15, 5, 'Matthew Henry', 'Hence, 1. Let superiors be admonished to give instruction and reproof to those that are under their charge, as they will answer it in the day of account. They must not only instruct with the light of knowledge, but reprove with the heat of zeal; and both these must be done with the authority and affection of a father, and must be continued, though the desired effect be not immediately perceived. If the instruction be despised, give reproof, and rebuke sharply. It is indeed against the grain w...', 'teologico');
add('pv', 15, 6, 'Matthew Henry', 'Note, 1. Where righteousness is riches are, and the comforts of them: In the house of the righteous is much treasure. Religion teaches men to be diligent, temperate, and just, and by these means, ordinarily, the estate is increased. But that is not all: God blesses the habitation of the just, and that blessing makes rich without trouble. Or, if there be not much of this world\'s goods, yet where there is grace there is true treasure; and those who have but little, if they have a heart to be th...', 'teologico');
add('pv', 15, 7, 'Matthew Henry', 'This is to the same purport with Pro 15:2, and shows what a blessing a wise man is and what a burden a fool is to those about him. Only here observe further, 1. That we then use knowledge aright when we disperse it, not confine it to a few of our intimates, and grudge it to others who would make as good use of it, but give a portion of this spiritual alms to seven and also to eight, not only be communicative, but diffusive, of this good, with humility and prudence. We must take pains to sprea...', 'teologico');
add('pv', 15, 8, 'Matthew Henry', 'Note, 1. God so hates wicked people, whose hearts are malicious and their lives mischievous, that even their sacrifices are an abomination to him. God has sacrifices brought him even by wicked men, to stop the mouth of conscience and to keep up their reputation in the world, as malefactors come to a sanctuary, not because it is a holy place, but because it shelters them from justice; but their sacrifices, though ever so costly, are not accepted of God, because not offered in sincerity nor fro...', 'teologico');
add('pv', 15, 9, 'Matthew Henry', 'This is a reason of what was said in the foregoing verse. 1. The sacrifices of the wicked are an abomination to God, not for want of some nice points of ceremony, but because their way, the whole course and tenour of their conversation, is wicked, and consequently an abomination to him. Sacrifices for sin were not accepted of those that resolved to go on in sin, and were to the highest degree abominable if intended to obtain a connivance at sin and a permission to go on in it. 2. Therefore th...', 'teologico');
add('pv', 15, 10, 'Matthew Henry', 'This shows that those who cannot bear to be corrected must expect to be destroyed. 1. It is common for those who have known the way of righteousness, but have forsaken it, to reckon it a great affront to be reproved and admonished. They are very uneasy at reproof; they cannot, they will not, bear it; nay, because they hate to be reformed, they hate to be reproved, and hate those who deal faithfully and kindly with them. Of all sinners, reproofs are worst resented by apostates. 2. It is certai...', 'teologico');
add('pv', 15, 11, 'Matthew Henry', 'This confirms what was said (Pro 15:3) concerning God\'s omnipresence, in order to his judging of evil and good. 1. God knows all things, even those things that are hidden from the eyes of all living: Hell and destruction are before the Lord, not only the centre of the earth, and its subterraneous caverns, but the grave, and all the dead bodies which are there buried out of our sight; they are all before the Lord, all under his eye, so that none of them can be lost or be to seek when they are ...', 'teologico');
add('pv', 15, 12, 'Matthew Henry', 'A scorner is one that not only makes a jest of God and religion, but bids defiance to the methods employed for his conviction and reformation, and, as an evidence of that, 1. He cannot endure the checks of his own conscience, nor will he suffer it to deal plainly with him: He loves not to reprove him (so some read it); he cannot endure to retire into his own heart and commune seriously with that, will not admit of any free thought or fair reasoning with himself, nor let his own heart smite hi...', 'teologico');
add('pv', 15, 13, 'Matthew Henry', 'Here, 1. Harmless mirth is recommended to us, as that which contributes to the health of the body, making men lively and fit for business, and to the acceptableness of the conversation, making the face to shine and rendering us pleasant one to another. A cheerful spirit, under the government of wisdom and grace, is a great ornament to religion, puts a further lustre upon the beauty of holiness, and makes men the more capable of doing good. 2. Hurtful melancholy is what we are cautioned agains...', 'teologico');
add('pv', 15, 14, 'Matthew Henry', 'Here are two things to be wondered at: - 1. A wise man not satisfied with his wisdom, but still seeking the increase of it; the more he has the more he would have: The heart of him that has understanding, rejoices so in the knowledge it has attained to that it is still coveting more, and in the use of the means of knowledge is still labouring for more, growing in grace, and in the knowledge of Christ. Si dixisti, Sufficit, periisti - If you say, I have enough, you are undone. 2. A fool well s...', 'teologico');
add('pv', 15, 15, 'Matthew Henry', 'See here what a great difference there is between the condition and temper of some and others of the children of men. 1. Some are much in affliction, and of a sorrowful spirit, and all their days are evil days, like those of old age, and days of which they say they have no pleasure in them. They eat in darkness (Ecc 5:17) and never eat with pleasure, Job 21:25. How many are the afflictions of the afflicted in this world! Such are not to be censured or despised, but pitied and prayed for, succ...', 'teologico');
add('pv', 15, 16, 'Matthew Henry', 'Solomon had said in the foregoing verse that he who has not a large estate, or a great income, but a cheerful spirit, has a continual feast; Christian contentment, and joy in God, make the life easy and pleasant; now here he tells us what is necessary to that cheerfulness of spirit which will furnish a man with a continual feast, though he has but little in the world - holiness and love.\nI. Holiness. A little, if we manage it and enjoy it in the fear of the Lord, if we keep a good conscience ...', 'teologico');
add('pv', 15, 18, 'Matthew Henry', 'Here is, 1. Passion the great make-bate. Thence come wars and fightings. Anger strikes the fire which sets cities and churches into a flame: A wrathful man, with his peevish passionate reflections, stirs up strife, and sets people together by the ears; he gives occasion to others to quarrel, and takes the occasion that others give, though ever so trifling. When men carry their resentments too far, one quarrel still produces another. 2. Meekness the great peace-maker: He that is slow to anger ...', 'teologico');
add('pv', 15, 19, 'Matthew Henry', 'See here, 1. Whence those difficulties arise which men pretend to meet with in the way of their duty, and to be insuperable; they arise not from any thing in the nature of the duty, but from the slothfulness of those that have really no mind to it. Those that have no heart to their work pretend that their way is hedged up with thorns, and they cannot do their work at all (as if God were a hard Master, reaping where he had not sown), at least that their way is strewed with thorns, that they ca...', 'teologico');
add('pv', 15, 20, 'Matthew Henry', 'Observe here, 1. To the praise of good children, that they are the joy of their parents, who ought to have joy of them, having taken so much care and pains about them. And it adds much to the satisfaction of those that are good if they have reason to think that they have been a comfort to their parents in their declining years, when evil days come. 2. To the shame of wicked children, that by their wickedness they put contempt upon their parents, slight their authority, and make an ill requita...', 'teologico');
add('pv', 15, 21, 'Matthew Henry', 'Note, 1. It is the character of a wicked man that he takes pleasure in sin; he has an appetite to the bait, and swallows it greedily, and has no dread of the hook, nor feels from it when he has swallowed it: Folly is joy to him; the folly of others is so, and his own much more. He sins, not only without regret, but with delight, not only repents not of it, but makes his boast of it. This is a certain sign of one that is graceless. 2. It is the character of a wise and good man that he makes co...', 'teologico');
add('pv', 15, 22, 'Matthew Henry', 'See here, 1. Of what ill consequence it is to be precipitate and rash, and to act without advice: Men\'s purposes are disappointed, their measures broken, and they come short of their point, gain not their end, because they would not ask counsel about the way. If men will not take time and pains to deliberate with themselves, or are so confident of their own judgment that they scorn to consult with others, they are not likely to bring any thing considerable to pass; circumstances defeat them w...', 'teologico');
add('pv', 15, 23, 'Matthew Henry', 'Note, 1. We speak wisely when we speak seasonably: The answer of the mouth will be our credit and joy when it is pertinent and to the purpose, and is spoken in due season, when it is needed and will be regarded, and, as we say, hits the joint. Many a good word comes short of doing the good it might have done, for want of being well-timed. Nor is any thing more the beauty of discourse than to have a proper answer ready off-hand, just when there is occasion for it, and it comes in well. 2. If w...', 'teologico');
add('pv', 15, 24, 'Matthew Henry', 'The way of wisdom and holiness is here recommended to us, 1. As very safe and comfortable: It is the way of life, the way that leads to eternal life, in which we shall find the joy and satisfaction which will be the life of the soul, and at the end of which we shall find the perfection of blessedness. Be wise and live. It is the way to escape that misery which we cannot but see ourselves exposed to, and in danger of. It is to depart from hell beneath, from the snares of hell, the temptations ...', 'teologico');
add('pv', 15, 25, 'Matthew Henry', 'Note, 1. Those that are elevated God delights to abase, and commonly does it in the course of his providence: The proud, that magnify themselves, bid defiance to the God above them and trample on all about them, are such as God resists and will destroy, not them only, but their houses, which they are proud of and are confident of the continuance and perpetuity of. Pride is the ruin of multitudes. 2. Those that are dejected God delights to support, and often does it remarkably: He will establi...', 'teologico');
add('pv', 15, 26, 'Matthew Henry', 'The former part of this verse speaks of thoughts, the latter of words, but they come all to one; for thoughts are words to God, and words are judged of by the thoughts from which they proceed, so that, 1. The thoughts and words of the wicked, which are, like themselves, wicked, which aim at mischief, and have some ill tendency or other, are an abomination to the Lord; he is displeased at them and will reckon for them. The thoughts of wicked men, for the most part, are such as God hates, and a...', 'teologico');
add('pv', 15, 27, 'Matthew Henry', 'Note, 1. Those that are covetous entail trouble upon their families: He that is greedy of gain, and therefore makes himself a slave to the world, rises up early, sits up late, and eats the bread of carefulness, in pursuit of it - he that hurries, and puts himself and all about him upon the stretch, in business, frets and vexes at every loss and disappointment, and quarrels with every body that stands in the way of his profit - he troubles his own house, is a burden and vexation to his childre...', 'teologico');
add('pv', 15, 28, 'Matthew Henry', 'Here is, 1. A good man proved to be a wise man by this, that he governs his tongue well; he that does so the same is a perfect man, Jam 3:2. It is part of the character of a righteous man that being convinced of the account he must give of his words, and of the good and bad influence of them upon others, he makes conscience of speaking truly (it is his heart that answers, that is, he speaks as he thinks, and dares not do otherwise, he speaks the truth in his heart, Psa 15:2), and of speaking ...', 'teologico');
add('pv', 15, 29, 'Matthew Henry', 'Note, 1. God sets himself at a distance from those that set him at defiance: The wicked say to the Almighty, Depart from us, and he is, accordingly, far from them; he does not manifest himself to them, has no communion with them, will not hear them, will not help them, no, not in the time of their need. They shall be for ever banished from his presence and he will behold them afar off. Depart from me, you cursed. 2. He will draw nigh to those in a way of mercy who draw nigh to him in a way of...', 'teologico');
add('pv', 15, 30, 'Matthew Henry', 'Two things are here pronounced pleasant: - 1. It is pleasant to have a good prospect to see the light of the sun (Ecc 11:7) and by it to see the wonderful works of God, with which this lower world is beautified and enriched. Those that want the mercy know how to value it; how would the light of the eyes rejoice their hearts! The consideration of this should make us thankful for our eyesight. 2. It is more pleasant to have a good name, a name for good things with God and good people; this is a...', 'teologico');
add('pv', 15, 31, 'Matthew Henry', 'Note, 1. It is the character of a wise man that he is very willing to be reproved, and therefore chooses to converse with those that, both by their words and example, will show him what is amiss in him: The ear that can take the reproof will love the reprover. Faithful friendly reproofs are here called the reproofs of life, not only because they are to be given in a lively manner, and with a prudent zeal (and we must reprove by our lives as well as by our doctrine), but because, where they ar...', 'teologico');
add('pv', 15, 32, 'Matthew Henry', 'See here, 1. The folly of those that will not be taught, that refuse instruction, that will not heed it, but turn their backs upon it, or will not hear it, but turn their hearts against it. They refuse correction (margin); they will not take it, no, not from God himself, but kick against the pricks. Those that do so despise their own souls; they show that they have a low and mean opinion of them, and are in little care and concern about them, considered as rational and immortal, instruction b...', 'teologico');
add('pv', 15, 33, 'Matthew Henry', 'See here how much it is our interest, as well as duty, 1. To submit to our God, and keep up a reverence for him: The fear of the Lord, as it is the beginning of wisdom, so it is the instruction and correction of wisdom; the principles of religion, closely adhered to, will improve our knowledge, rectify our mistakes, and be the best and surest guide of our way. An awe of God upon our spirits will put us upon the wisest counsels and chastise us when we say or do unwisely. 2. To stoop to our bre...', 'teologico');
add('pv', 16, 2, 'Matthew Henry', 'Note, 1. We are all apt to be partial in judging of ourselves: All the ways of a man, all his designs, all his doings, are clean in his own eyes, and he sees nothing amiss in them, nothing for which to condemn himself, or which should make his projects prove otherwise than well; and therefore he is confident of success, and that the answer of the tongue shall be according to the expectations of the heart; but there is a great deal of pollution cleaving to our ways, which we are not aware of, ...', 'teologico');
add('pv', 16, 4, 'Matthew Henry', 'Note, 1. That God is the first cause. He is the former of all things and all persons, the fountain of being; he gave every creature the being it has and appointed it its place. Even the wicked are his creatures, though they are rebels; he gave them those powers with which they fight against him, which aggravates their wickedness, that they will not let him that made them rule them, and therefore, though he made them, he will not save them. 2. That God is the last end. All is of him and from h...', 'teologico');
add('pv', 16, 5, 'Matthew Henry', 'Note, 1. The pride of sinners sets God against them. He that, being high in estate is proud in heart, whose spirit is elevated with his condition, so that he becomes insolent in his conduct towards God and man, let him know that though he admires himself, and others caress him, yet he is an abomination to the Lord. The great God despises him; the holy God detest him. 2. The power of sinners cannot secure them against God, though they strengthen themselves with body hands. Though they may stre...', 'teologico');
add('pv', 16, 6, 'Matthew Henry', 'See here, 1. How the guilt of sin is taken away from us - by the mercy and truth of God, mercy in promising, truth in performing, the mercy and truth which kiss each other in Jesus Christ the Mediator - by the covenant of grace, in which mercy and truth shine so brightly - by our mercy and truth, as the condition of the pardon and a necessary qualification for it - by these, and not by the legal sacrifices, Mic 6:7, Mic 6:8. 2. How the power of sin is broken in us. By the principles of mercy ...', 'teologico');
add('pv', 16, 7, 'Matthew Henry', 'Note, 1. God can turn foes into friends when he pleases. He that has all hearts in his hand has access to men\'s spirits and power over them, working insensibly, but irresistibly upon them, can make a man\'s enemies to be at peace with him, can change their minds, or force them into a feigned submission. He can slay all enemies, and bring those together that were at the greatest distance from each other. 2. He will do it for us when we please him. If we make it our care to be reconciled to God,...', 'teologico');
add('pv', 16, 8, 'Matthew Henry', 'Here, 1. It is supposed that an honest good man may have but a little of the wealth of this world (all the righteous are not rich), - that a man may have but little, and yet may be honest (though poverty is a temptation to dishonesty, Pro 30:9, yet not an invincible one), - and that a man may grow rich, for a while, by fraud and oppression, may have great revenues, and those got and kept without right, may have no good title to them nor make any good use of them. 2. It is maintained that a sm...', 'teologico');
add('pv', 16, 9, 'Matthew Henry', 'Man is here represented to us, 1. As a reasonable creature, that has the faculty of contriving for himself: His heart devises his way, designs an end, and projects ways and means leading to that end, which the inferior creatures, who are governed by sense and natural instinct, cannot do. The more shame for him if he do not devise the way how to please God and provide for his everlasting state. 2. But as a depending creature, that is subject to the direction and dominion of his Maker. If men d...', 'teologico');
add('pv', 16, 10, 'Matthew Henry', 'We wish this were always true as a proposition, and we ought to make it our prayer for kings, and all in authority, that a divine sentence may be in their lips, both in giving orders, that they may do that in wisdom, and in giving sentence, that they may do that in equity, both which are included in judgment, and that in neither their mouth may transgress, Ti1 2:1. But it is often otherwise; and therefore, 1. it may be read as a precept to the kings and judges of the earth to be wise and inst...', 'teologico');
add('pv', 16, 11, 'Matthew Henry', 'Note, 1. The administration of public justice by the magistrate is an ordinance of God; in it the scales are held, and ought to be held by a steady and impartial hand; and we ought to submit to it, for the Lord\'s sake, and to see his authority in that of the magistrate, Rom 13:1; Pe1 2:13. 2. The observance of justice in commerce between man and man is likewise a divine appointment. He taught men discretion to make scales and weights for the adjusting of right exactly between buyer and seller...', 'teologico');
add('pv', 16, 12, 'Matthew Henry', 'Here is, 1. The character of a good king, which Solomon intended not for his own praise, but for instruction to his successors, his neighbours, and the viceroys under him. A good king not only does justice, but it is an abomination to him to do otherwise. He hates the thought of doing wrong and perverting justice; he not only abhors the wickedness done by others, but abhors the wickedness done by others, but abhors to do any himself, though, having power, he might easily and safety do it. 2. ...', 'teologico');
add('pv', 16, 13, 'Matthew Henry', 'Here is a further character of good kings, that they love and delight in those that speak right. 1. They hate parasites and those that flatter them, and are very willing that all about them should deal faithfully with them and tell them that which is true, whether it be pleasing or displeasing, both concerning persons and things, that every thing should be set in a true light and nothing disguised, Pro 29:12. 2. They not only do righteousness themselves, but take care to employ those under th...', 'teologico');
add('pv', 16, 14, 'Matthew Henry', 'These two verses show the power of kings, which is every where great, but was especially so in those eastern countries, where they were absolute and arbitrary. Whom they would they slew and whom they would they kept alive. Their will was a law. We have reason to bless God for the happy constitution of the government we live under, which maintains the prerogative of the prince without any injury to the liberty of the subject. But here it is intimated, 1. How formidable the wrath of a king is: ...', 'teologico');
add('pv', 16, 16, 'Matthew Henry', 'Solomon here not only asserts that it is better to get wisdom than gold (Pro 3:14, Pro 8:19), but he speaks it with assurance, that it is much better, better beyond expression - with admiration (How much better!) as one amazed at the disproportion - with an appeal to men\'s consciences ("Judge in yourselves how much better it is") - and with an addition to the same purport, that understanding is rather to be chosen than silver and all the treasures of kings and their favourites. Note, 1. Heave...', 'teologico');
add('pv', 16, 17, 'Matthew Henry', 'Note, 1. It is the way of the upright to avoid sin, and every thing that looks like it and leads towards it; and this is a highway marked out by authority, tracked by many that have gone before us, and in which we meet with many that keep company with us; it is easy to find and safe to be travelled in, like a highway, Isa 35:8. To depart from evil is understanding. 2. It is the care of the upright to preserve their own souls, that they be not polluted with sin, and that by the troubles of the...', 'teologico');
add('pv', 16, 18, 'Matthew Henry', 'Note, 1. Pride will have a fall. Those that are of a haughty spirit, that think of themselves above what is meet, and look with contempt upon others, that with their pride affront God and disquiet others, will be brought down, either by repentance or by ruin. It is the honour of God to humble the proud, Job 40:11, Job 40:12. It is the act of justice that those who have lifted up themselves should be laid low. Pharaoh, Sennacherib, Nebuchadnezzar, were instances of this. Men cannot punish prid...', 'teologico');
add('pv', 16, 19, 'Matthew Henry', 'This is a paradox which the children of this world cannot understand and will not subscribe to, that it is better to be poor and humble than to be rich and proud. 1. Those that divide the spoil are commonly proud; they value themselves and despise others, and their mind rises with their condition; those therefore that are rich in this world have need to be charged that they be not high-minded, Ti1 6:17. Those that are proud and will put forth themselves, that thrust, and shove, and scramble, ...', 'teologico');
add('pv', 16, 20, 'Matthew Henry', 'Note, 1. Prudence gains men respect and success: He that handles a matter wisely (that is master of his trade and makes it to appear he understands what he undertakes, that is considerate in his affairs, and, when he speaks or writes on any subject, does it pertinently) shall find good, shall come into good repute, and perhaps may make a good hand of it. 2. But it is piety only that will secure men\'s true happiness: Those that handle a matter wisely, if they are proud and lean to their own un...', 'teologico');
add('pv', 16, 21, 'Matthew Henry', 'Note, 1. Those that have solid wisdom will have the credit of it; it will gain them reputation, and they shall be called prudent grave men, and a deference will be paid to their judgment. Do that which is wise and good and thou shalt have the praise of the same. 2. Those that with their wisdom have a happy elocution, that deliver their sentiments easily and with a good grace, are communicative of their wisdom and have words at will, and good language as well as good sense, increase learning; ...', 'teologico');
add('pv', 16, 22, 'Matthew Henry', 'Note, 1. There is always some good to be gotten by a wise and good man: His understanding is a well-spring of life to him, which always flows and can never be drawn dry; he has something to say upon all occasions that is instructive, and of use to those that will make use of it, things new and old to bring out of his treasure; at least, his understanding is a spring of life to himself, yielding him abundant satisfaction; within his own thoughts he entertains and edifies himself, if not others...', 'teologico');
add('pv', 16, 23, 'Matthew Henry', 'Solomon had commended eloquence, or the sweetness of the lips (Pro 16:21), and seemed to prefer it before wisdom; but here he corrects himself, as it were, and shows that unless there be a good treasure within to support the eloquence it is worth little. Wisdom in the heart is the main matter. 1. It is this that directs us in speaking, that teaches the mouth what to speak, and when, and how, so that what is spoken may be proper, and pertinent, and seasonable; otherwise, though the language be...', 'teologico');
add('pv', 16, 24, 'Matthew Henry', 'The pleasant words here commended must be those which the heart of the wise teaches, and adds learning to (Pro 16:23), words of seasonable advice, instruction, and comfort, words taken from God\'s word, for that is it which Solomon had learned from his father to account sweeter than honey and the honey-comb, Psa 19:10. These words, to those that know how to relish them, 1. Are pleasant. They are like the honey-comb, sweet to the soul, which tastes in them that the Lord is gracious; nothing mor...', 'teologico');
add('pv', 16, 25, 'Matthew Henry', 'This we had before (Pro 14:12), but here it is repeated, as that which is very necessary to be thought of, 1. By way of caution to us all to take heed of deceiving ourselves in the great concerns of our souls by resting in that which seems right and is not really so, and, for the preventing of a self-delusion, to be impartial in self-examination and keep up a jealousy over ourselves. 2. By way of terror to those whose way is not right, is not as it should be, however it may seem to themselves...', 'teologico');
add('pv', 16, 26, 'Matthew Henry', 'This is designed to engage us to diligence, and quicken us, what our hand finds to do, to do it with all our might, both in our worldly business and in the work of religion; for in the original it is, The soul that labours labours for itself. It is heart-work which is here intended, the labour of the soul, which is here recommended to us, 1. As that which will be absolutely needful. Our mouth is continually craving it of us; the necessities both of soul and body are pressing, and require cons...', 'teologico');
add('pv', 16, 27, 'Matthew Henry', 'There are those that are not only vicious themselves, but spiteful and mischievous to others, and they are the worst of men; two sorts of such are here described: - 1. Such as envy a man the honour of his good name, and do all they can to blast that by calumnies and misrepresentations: They dig up evil; they take a great deal of pains to find out something or other on which to ground a slander, or which may give some colour to it. If none appear above ground, rather than want it they will dig...', 'teologico');
add('pv', 16, 29, 'Matthew Henry', 'Here is another sort of evil men described to us, that we may neither do like them, nor have any thing to do with them. 1. Such as (like Satan) do all the mischief they can by force and violence, as roaring lions, and not only by fraud and insinuation, as subtle serpents: They are violent men, that do all by rapine and oppression, that shut their eyes, meditating with the closest intention and application of mind to devise froward things, to contrive how they may do the greatest mischief to t...', 'teologico');
add('pv', 16, 31, 'Matthew Henry', 'Note, 1. It ought to be the great care of old people to be found in the way of righteousness, the way of religion and serious godliness. Both God and man will look for them in that way; it will be expected that those that are old should be good, that the multitude of their years should teach them the best wisdom; let them therefore be found in that way. Death will come; the Judge is coming; the Lord is at hand. That they may be found of him in peace, let them be found in the way of righteousn...', 'teologico');
add('pv', 16, 32, 'Matthew Henry', 'This recommends the grace of meekness to us, which will well become us all, particularly the hoary head, Pro 16:31. Observe, 1. The nature of it. it is to be slow to anger, not easily put into a passion, nor apt to resent provocation, taking time to consider before we suffer our passion to break out, that it may not transgress due bounds, so slow in our motions towards anger that we may be quickly stopped and pacified. It is to have the rule of our own spirits, our appetites and affections, a...', 'teologico');
add('pv', 16, 33, 'Matthew Henry', 'Note, 1. The divine Providence orders and directs those things which to us are perfectly casual and fortuitous. Nothing comes to pass by chance, nor is an event determined by a blind fortune, but every thing by the will and counsel of God. What man has neither eye nor hand in God is intimately concerned in. 2. When solemn appeals are made to Providence by the casting of lots, for the deciding of that matter of moment which could not otherwise be at all, or not so well, decided, God must be ey...', 'teologico');
add('pv', 17, 2, 'Matthew Henry', 'Note, 1. True merit does not go by dignity. All agree that the son in the family is more worthy than the servant (Joh 8:35), and yet sometimes it so happens that the servant is wise, and a blessing and credit to the family, when the son is a fool, and a burden and shame to the family. Eliezer of Damascus, though Abram could not bear to think that he should be his heir, was a stay to the family, when he obtained a wife for Isaac; whereas Ishmael, a son, was a shame to it, when he mocked Isaac....', 'teologico');
add('pv', 17, 3, 'Matthew Henry', 'Note, 1. The hearts of the children of men are subject, not only to God\'s view, but to his judgment: As the fining-pot is for silver, both to prove it and to improve it so the Lord tries the hearts; he searches whether they are standard or no, and those that are he refines and makes purer, Jer 17:10. God tries the heart by affliction (Psa 66:10, Psa 66:11), and often chooses his people in that furnace (Isa 48:10) and makes them choice. 2. It is God only that tries the hearts. Men may try thei...', 'teologico');
add('pv', 17, 4, 'Matthew Henry', 'Note, 1. Those that design to do ill support themselves by falsehood and lying: A wicked doer gives ear, with a great deal of pleasure, to false lips, that will justify him in the ill he does, to those that aim to make public disturbances, catch greedily at libels, and false stories, that defame the government and the administration. 2. Those that take the liberty to tell lies take a pleasure in hearing them told: A liar gives heed to a malicious backbiting tongue, that he may have something ...', 'teologico');
add('pv', 17, 5, 'Matthew Henry', 'See here, 1. What a great sin those are guilty of who trample upon the poor, who ridicule their wants and the meanness of their appearance, upbraid them with their poverty, and take advantage from their weakness to be abusive and injurious to them. They reproach their Maker, put a great contempt and affront upon him, who allotted the poor to the condition they are in, owns them, and takes care of them, and can, when he pleases, reduce us to that condition. Let those that thus reproach their M...', 'teologico');
add('pv', 17, 6, 'Matthew Henry', 'They are so, that is, they should be so, and, if they conduct themselves worthily, they are so. 1. It is an honour to parents when they are old to leave children, and children\'s children, growing up, that tread in the steps of their virtues, and are likely to maintain and advance the reputation of their families. It is an honour to a man to live so long as to see his children\'s children (Psa 128:6; Gen 50:23), to see his house built up in them, and to see them likely to serve their generation...', 'teologico');
add('pv', 17, 7, 'Matthew Henry', 'Two things are here represented as very absurd: 1. That men of no repute should be dictators. What can be more unbecoming than for fools, who are known to have little sense and discretion, to pretend to that which is above them and which they were never cut out for? A fool, in Solomon\'s proverbs, signifies a wicked man, whom excellent speech does not become, because his conversation gives the lie to his excellent speech. What have those to do to declare God\'s statutes who hate instruction? Ps...', 'teologico');
add('pv', 17, 8, 'Matthew Henry', 'The design of this observation is to show, 1. That those who have money in their hand think they can do any thing with it. Rich men value a little money as if it were a precious stone, and value themselves on it as if it gave them not only ornament, but power, and every one were bound to be at their beck, even justice itself. Whithersoever they turn this sparkling diamond they expect it should dazzle the eyes of all, and make them do just what they would have them do in hopes of it. The deepe...', 'teologico');
add('pv', 17, 9, 'Matthew Henry', 'Note, 1. The way to preserve peace among relations and neighbours is to make the best of every thing, not to tell others what has been said or done against them when it is not at all necessary to their safety, nor to take notice of what has been said or done against them when it is not at all necessary to their safety, nor to take notice of what has been said or done against ourselves, but to excuse both, and put the best construction upon them. "It was an oversight; therefore overlook it. It...', 'teologico');
add('pv', 17, 10, 'Matthew Henry', 'Note, 1. A word is enough to the wise. A gentle reproof will enter not only into the head, but into the heart of a wise man, so as to have a strong influence upon him; for, if but a hint be given to conscience, let it alone to carry it on and prosecute it. 2. Stripes are not enough for a fool, to make him sensible of his errors, that he may repent of them, and be more cautious for the future. He that is sottish and wilful is very rarely benefited by severity. David is softened with, Thou art ...', 'teologico');
add('pv', 17, 11, 'Matthew Henry', 'Here is the sin and punishment of an evil man. 1. His sin. He is an evil man indeed that seeks all occasions to rebel against God, and the government God has set over him, and to contradict and quarrel with those about him. Quaerit jurgia - He picks quarrels; so some. There are some that are actuated by a spirit of opposition, that will contradict for contradiction-sake, that will go on frowardly in their wicked ways in spite of all restraint and check. A rebellious man seeks mischief (so som...', 'teologico');
add('pv', 17, 12, 'Matthew Henry', 'Note, 1. A passionate man is a brutish man. However at other times he may have some wisdom, take him in his passion ungoverned, and he is a fool in his folly; those are fools in whose bosom anger rests and in whose countenance anger rages. He has put off man, and is become like a bear, a raging bear, a bear robbed of her whelps; he is as fond of the gratifications of his lusts and passions as a bear of her whelps (which, though ugly, are her own), as eager in the pursuit of them as she is in ...', 'teologico');
add('pv', 17, 13, 'Matthew Henry', 'A malicious mischievous man is here represented, 1. As ungrateful to his friends. He oftentimes is so absurd and insensible of kindnesses done him that he renders evil for good. David met with those that were his adversaries for his love, Psa 109:4. To render evil for evil is brutish, but to render evil for good is devilish. He is an ill-natured man who, because he is resolved not to return a kindness, will revenge it. 2. As therein unkind to his family, for he entails a curse upon it. This i...', 'teologico');
add('pv', 17, 14, 'Matthew Henry', 'Here is, 1. The danger that there is in the beginning of strife. One hot word, one peevish reflection, one angry demand, one spiteful contradiction, begets another, and that a third, and so on, till it proves like the cutting of a dam; when the water has got a little passage it does itself widen the breach, bears down all before it, and there is then no stopping it, no reducing it. 2. A good caution inferred thence, to take heed of the first spark of contention and to put it out as soon as ev...', 'teologico');
add('pv', 17, 15, 'Matthew Henry', 'This shows what an offence it is to God, 1. When those that are entrusted with the administration of public justice, judges, juries, witnesses, prosecutors, counsel, do either acquit the guilty or condemn those that are not guilty, or in the least contribute to either; this defeats the end of government, which is to protect the good and punish the bad, Rom 13:3, Rom 13:4. It is equally provoking to God to justify the wicked, though it be in pity and in favorem vitae - to safe life, as to cond...', 'teologico');
add('pv', 17, 16, 'Matthew Henry', 'Two things are here spoken of with astonishment: - 1. God\'s great goodness to foolish man, in putting a price into his hand to get wisdom, to get knowledge and grace to fit him for both worlds. We have rational souls, the means of grace, the strivings of the Spirit, access to God by prayer; we have time and opportunity. He that has a good estate (so some understand it) has advantages thereby of getting wisdom by purchasing instruction. Good parents, relations, ministers, friends, are helps to...', 'teologico');
add('pv', 17, 17, 'Matthew Henry', 'This intimates the strength of those bonds by which we are bound to each other and which we ought to be sensible of. 1. Friends must be constant to each other at all times. That is not true friendship which is not constant; it will be so if it be sincere, and actuated by a good principle. Those that are fanciful or selfish in their friendship will love no longer than their humour is pleased and their interest served, and therefore their affections turn with the wind and change with the weathe...', 'teologico');
add('pv', 17, 18, 'Matthew Henry', 'Though Solomon had commended friendship in adversity (Pro 17:17), yet let not any, under pretence of being generous to their friends, be unjust to their families and wrong them; one part of our duty must be made to consist with another. Note, 1. It is a piece of wisdom to keep out of debt as much as may be, especially to dread suretiship. There may be a just occasion for a man to pass his word for his friend in his absence, till he come to engage himself; but to be surety in the presence of h...', 'teologico');
add('pv', 17, 19, 'Matthew Henry', 'Note, 1. Those that are quarrelsome involve themselves in a great deal of guilt: He that loves strife, that in his worldly business loves to go to law, in religion loves controversies, and in common conversation loves to thwart and fall out, that is never well but when he is in the fire, he loves transgression; for a great deal of sin attends that sin, and the way of it is down-hill. He pretends to stand up for truth, and for his honour and right, but really he loves sin, which God hates. 2. ...', 'teologico');
add('pv', 17, 20, 'Matthew Henry', 'Note, 1. Framing ill designs will be of no advantage to us; there is nothing got by them: He that has a froward heart, that sows discord and is full of resentment, cannot promise himself to get by it sufficient to counterbalance the loss of his repose and reputation, nor can he take any rational satisfaction in it; he finds no good. 2. Giving ill language will be a great disadvantage to us: He that has a perverse tongue, spiteful and abusive, scurrilous or backbiting, falls into one mischief ...', 'teologico');
add('pv', 17, 21, 'Matthew Henry', 'This expresses that very emphatically which many wise and good men feel very sensibly, what a grievous vexatious thing it is to have a foolish wicked child. See here, 1. How uncertain all our creature-comforts are, so that we are often not only disappointed in them, but that proves the greatest cross in which we promised ourselves most satisfaction. There was joy when a man-child was born into the world, and yet, if he prove vicious, his own father will wish he had never been born. The name o...', 'teologico');
add('pv', 17, 22, 'Matthew Henry', 'Note, 1. It is healthful to be cheerful. The Lord is for the body, and has provided for it, not only meat, but medicine, and has here told us that the best medicine is a merry heart, not a heart addicted to vain, carnal, sensual mirth; Solomon himself said of that mirth, It is not medicine, but madness; it is not food, but poison; what doth it? But he means a heart rejoicing in God, and serving him with gladness, and then taking the comfort of outward enjoyments and particularly that of pleas...', 'teologico');
add('pv', 17, 23, 'Matthew Henry', 'See here, 1. What an evil thing bribery is: He is a wicked man that will take a gift to engage him to give a false testimony, verdict, or judgment; when he does it he is ashamed of it, for he takes it, with all the secresy imaginable, out of the bosom where he knows it is laid ready for him; it is industriously concealed, and so slyly that, if he could, he would hide it from his own conscience. A gift is taken out of the bosom of a wicked man (so some read it); for he is a bad man that gives ...', 'teologico');
add('pv', 17, 24, 'Matthew Henry', 'Note, 1. He is to be reckoned an intelligent man that not only has wisdom, but has it ready when he has occasion for it. He lays his wisdom before him, as his card and compass which he steers by, has his eye always upon it, as he that writes has on his copy; and then he has it before him; it is not to seek, but still at hand. 2. He that has a giddy head, a roving rambling fancy, will never be fit for any solid business. He is a fool, and good for nothing, whose eyes are in the ends of the ear...', 'teologico');
add('pv', 17, 25, 'Matthew Henry', 'Observe, 1. Wicked children are an affliction to both their parents. They are an occasion of anger to the father (so the word signifies), because they contemn his authority, but of sorrow and bitterness to the mother, because they abuse her tenderness. The parents, being joint-sufferers, should therefore bring mutual comfort to bear them up under it, and strive to make it as easy as they can, the mother to mollify the father\'s anger, the father to alleviate the mother\'s grief. 2. That Solomon...', 'teologico');
add('pv', 17, 26, 'Matthew Henry', 'In differences that happen between magistrates and subjects, and such differences often arise, 1. Let magistrates see to it that they never punish the just, that they be in no case a terror to good works, for that is to abuse their power and betray that great trust which is reposed in them. It is not good, that is, it is a very evil thing, and will end ill, whatever end they may aim at in it. When princes become tyrants and persecutors their thrones will be neither easy nor firm. 2. Let subje...', 'teologico');
add('pv', 17, 27, 'Matthew Henry', 'Two ways a man may show himself to be a wise man: - 1. By the good temper, the sweetness and the sedateness, of his mind: A man of understanding is of an excellent spirit, a precious spirit (so the word is); he is one that looks well to his spirit, that it be as it should be, and so keeps it in an even frame, easy to himself and pleasant to others. A gracious spirit is a precious spirit, and renders a man amiable and more excellent than his neighbour. He is of a cool spirit (so some read it),...', 'teologico');
add('pv', 18, 2, 'Matthew Henry', 'A fool may pretend to understanding, and to seek and intermeddle with the means of it, but, 1. He has no true delight in it; it is only to please his friends or save his credit; he does not love his book, nor his business, nor his Bible, nor his prayers; he would rather be playing the fool with his sports. Those who take no pleasure in learning or religion will make nothing to purpose of either. No progress is made in them if they are a task and a drudgery. 2. He has no good design in it, onl...', 'teologico');
add('pv', 18, 3, 'Matthew Henry', 'This may include a double sense: - 1. That wicked people are scornful people, and put contempt upon others. When the wicked comes into any company, comes into the schools of wisdom or into the assemblies for religious worship, then comes contempt of God, of his people and ministers, and of every thing that is said and done. You can expect no other from those that are profane than that they will be scoffers; they will be an ignominy and reproach; they will flout and jeer every thing that is se...', 'teologico');
add('pv', 18, 4, 'Matthew Henry', 'The similitudes here seem to be elegantly transposed. 1. The well-spring of wisdom is as deep waters. An intelligent knowing man has in him a good treasure of useful things, which furnishes him with something to say upon all occasions that is pertinent and profitable. This is as deep waters, which make no noise, but never run dry. 2. The words of such a man\'s mouth are as a flowing brook. What he sees cause to speak flows naturally from him and with a great deal of ease, and freedom, and natu...', 'teologico');
add('pv', 18, 5, 'Matthew Henry', 'This justly condemns those who, being employed in the administration of justice, pervert judgment, 1. By conniving at men\'s crimes, and protecting and countenancing them in oppression and violence, because of their dignity, or wealth, or some personal kindness they have for them. Whatever excuses men may make for it, certainly it is not good thus to accept the person of the wicked; it is an offence to God, an affront to justice, a wrong to mankind, and a real service done to the kingdom of si...', 'teologico');
add('pv', 18, 6, 'Matthew Henry', 'Solomon has often shown what mischief bad men do to others with their ungoverned tongues; here he shows what mischief they do to themselves. 1. They embroil themselves in quarrels: A fool\'s lips, without any cause or call, enter into contention, by advancing foolish notions which others find themselves obliged to oppose, and so a quarrel is begun, or by giving provoking language, which will be resented, and satisfaction demanded, or by setting men at defiance, and bidding them do if they dare...', 'teologico');
add('pv', 18, 8, 'Matthew Henry', 'Tale-bearers are those who secretly carry stories from house to house, which perhaps have some truth in them, but are secrets not fit to be told, or are basely misrepresented, and false colours put upon them, and are all told with design to blast men\'s reputation, to break their friendship, to make mischief between relations and neighbours, and set them at variance. Now the words of such are here said to be, 1. Like as when men are wounded (so the margin reads it); they pretend to be very muc...', 'teologico');
add('pv', 18, 9, 'Matthew Henry', 'Note, 1. Prodigality is very bad husbandry. Those are not only justly branded as fools among men, but will give an uncomfortable account to God of the talents they are entrusted with, who are wasters of their estates, who live above what they have, spend and give more than they can afford, and so, in effect, throw away what they have, and suffer it to run to waste. 2. Idleness is no better. He that is remiss in his work, whose hands hang down (so the word signifies), that stands, as we may, w...', 'teologico');
add('pv', 18, 10, 'Matthew Henry', 'Here is, 1. God\'s sufficiency for the saints: His name is a strong tower for them, in which they may take rest when they are weary and take sanctuary when they are pursued, where they may be lifted up above their enemies and fortified against them. There is enough in God, and in the discoveries which he has made of himself to us, to make us easy at all times. The wealth laid up in this tower is enough to enrich them, to be a continual feast and a continuing treasure to them. The strength of t...', 'teologico');
add('pv', 18, 11, 'Matthew Henry', 'Having described the firm and faithful defence of the righteous man (Pro 18:10), Solomon here shows what is the false and deceitful defence of the rich man, that has his portion and treasure in the things of this world, and sets his heart upon them. His wealth is as much his confidence, and he expects as much from it, as a godly man from his God. See, 1. How he supports himself. He makes his wealth his city, where he dwells, where he rules, with a great deal of self-complacency, as if he had ...', 'teologico');
add('pv', 18, 12, 'Matthew Henry', 'Note, 1. Pride is the presage of ruin, and ruin will at last be the punishment of pride; for before destruction men are commonly so infatuated by the just judgment of God that they are more haughty than ever, that their ruin may be the sorer and the more surprising. Of, if that do not always hold, yet after the heart has been lifted up with pride, a fall comes, Pro 16:18. 2. Humility is the presage of honour and prepares men for it, and honour shall at length be the reward of humility, as he ...', 'teologico');
add('pv', 18, 13, 'Matthew Henry', 'See here how men often expose themselves by that very thing by which they hope to gain applause. 1. Some take a pride in being quick. They answer a matter before they hear it, hear it out, nay, as soon as they but hear of it. They think it is their honour to take up a cause suddenly; and, when they have heard one side, they think the matter so plain that they need not trouble themselves to hear the other; they are already apprized of it, and masters of all the merits of the cause. Whereas, th...', 'teologico');
add('pv', 18, 14, 'Matthew Henry', 'Note, 1. Outward grievances are tolerable as long as the mind enjoys itself and is at ease. Many infirmities, many calamities, we are liable to in this world, in body, name, and estate, which a man may bear, and bear up under, if he have but good conduct and courage, and be able to act with reason and resolution, especially if he have a good conscience, and the testimony of that be for him; and, if the spirit of a man will sustain the infirmity, much more will the spirit of a Christian, or ra...', 'teologico');
add('pv', 18, 15, 'Matthew Henry', 'Note, 1. Those that are prudent will seek knowledge, and apply their ear and heart to the pursuit of it, their ear to attend to the means of knowledge and their heart to mix faith with what they hear and make a good improvement of it. Those that are prudent do not think they have prudence enough, but still see they have need of more; and the more prudent a man is the more inquisitive will he be after knowledge, the knowledge of God and his duty, and the way to heaven, for that is the best kno...', 'teologico');
add('pv', 18, 16, 'Matthew Henry', 'Of what great force gifts (that is, bribes) are he had intimated before, Pro 17:8, Pro 17:23. Here he shows the power of gifts, that is, presents made even by inferiors to those that are above them and have much more than they have. A good present will go far, 1. Towards a man\'s liberty: A man\'s gift, if he be in prison, may procure his enlargement; there are courtiers, who, if they use their interest even for oppressed innocency, expect to receive a gratuity for it. Or, if a mean man know no...', 'teologico');
add('pv', 18, 17, 'Matthew Henry', 'This shows that one tale is good till another is told. 1. He that speaks first will be sure to tell a straight story, and relate that only which makes for him, and put the best colour he can upon it, so that his cause shall appear good, whether it really be so or no. 2. The plaintiff having done his evidence, it is fit that the defendant should be heard, should have leave to confront the witnesses and cross-examine them, and show the falsehood and fallacy of what has been alleged, which perha...', 'teologico');
add('pv', 18, 18, 'Matthew Henry', 'Note, 1. Contentions commonly happen among the mighty, that are jealous for their honour and right and stand upon the punctilios of both, that are confident of their being able to make their part good and therefore will hardly condescend to the necessary terms of an accommodation; whereas those that are poor are forced to be peaceable, and sit down losers. 2. Even the contentions of the mighty may be ended by lot if they cannot otherwise be compromised, and sometimes better so than by argumen...', 'teologico');
add('pv', 18, 19, 'Matthew Henry', 'Note, 1. Great care must be taken to prevent quarrels among relations, and those that are under special obligation to each other, not only because they are most unnatural and unbecoming, but because between such things are commonly taken most unkindly, and resentments are apt to be carried too far. Wisdom and grace would indeed make it most easy to us to forgive our relations and friends if they offend us, but corruption makes it most difficult to forgive them; let us therefore take heed of d...', 'teologico');
add('pv', 18, 20, 'Matthew Henry', 'Note, 1. Our comfort depends very much upon the testimony of our own consciences, for us or against us. The belly is here put for the conscience, as Pro 20:27. Now it is of great consequence to us whether that be satisfied, and what that is filled with, for, accordingly, will our satisfaction be and our inward peace. 2. The testimony of our consciences will be for us, or against us, according as we have or have not governed our tongues well. According as the fruit of the mouth is good or bad,...', 'teologico');
add('pv', 18, 21, 'Matthew Henry', 'Note, 1. A man may do a great deal of good, or a great deal of hurt, both to others and to himself, according to the use he makes of his tongue. Many a one has been his own death by a foul tongue, or the death of others by a false tongue; and, on the contrary, many a one has saved his own life, or procured the comfort of it, by a prudent gentle tongue, and saved the lives of others by a seasonable testimony or intercession for them. And, if by our words we must be justified or condemned, deat...', 'teologico');
add('pv', 18, 22, 'Matthew Henry', 'Note, 1. A good wife is a great blessing to a man. He that finds a wife (that is, a wife indeed; a bad wife does not deserve to be called by a name of so much honour), that finds a help meet for him (that is a wife in the original acceptation of the word), that sought such a one with care and prayer and has found what he sought, he has found a good thing, a jewel of great value, a rare jewel; he has found that which will not only contribute more than any thing to his comfort in this life, but...', 'teologico');
add('pv', 18, 23, 'Matthew Henry', 'Note, 1. Poverty, though many inconveniences to the body attend it, has often a good effect upon the spirit, for it makes men humble and submissive, and mortifies their pride. It teaches them to use entreaties. When necessity forces men to beg it tells them they must not prescribe or demand, but take what is given them and be thankful. At the throne of God\'s grace we are all poor, and must use entreaties, not answer, but make application, must sue sub forma pauperis - as a pauper. 2. A prospe...', 'teologico');
add('pv', 18, 24, 'Matthew Henry', 'Solomon here recommends friendship to us, and shows, 1. What we must do that we may contract and cultivate friendship; we must show ourselves friendly. Would we have friends and keep them, we must not only not affront them, or quarrel with them, but we must love them, and make it appear that we do so by all expressions that are endearing, by being free with them, pleasing to them, visiting them and bidding them welcome, and especially by doing all the good offices we can and serving them in e...', 'teologico');
add('pv', 19, 2, 'Matthew Henry', 'Two things are here declared to be of bad consequence: - 1. Ignorance: To be without the knowledge of the soul is not good, so some read it. Know we not our own selves, our own hearts? A soul without knowledge is not good; it is a great privilege that we have souls, but, if these souls have not knowledge, what the better are we? If man has not understanding, he is as the beasts, Psa 49:20. An ignorant soul cannot be a good soul. That the soul be without knowledge is not safe, nor pleasant; wh...', 'teologico');
add('pv', 19, 3, 'Matthew Henry', 'We have here two instances of men\'s folly: - 1. That they bring themselves into straits and troubles, and run themselves a-ground, and embarrass themselves: The foolishness of man perverts his way. Men meet with crosses and disappointments in their affairs, and things do not succeed as they expected and wished, and it is owing to themselves and their own folly; it is their own iniquity that corrects them. 2. That when they have done so they lay the blame upon God, and their hearts fret agains...', 'teologico');
add('pv', 19, 4, 'Matthew Henry', 'Here, 1. We may see how strong men\'s love of money is, that they will love any man, how undeserving soever he be otherwise, if he has but a deal of money and is free with it, so that they may hope to be the better for it. Wealth enables a man to send many presents, make many entertainments, and do many good offices, and so gains him many friends, who pretend to love him, for they flatter him and make their court to him, but really love what he has, or rather love themselves, hoping to get by ...', 'teologico');
add('pv', 19, 5, 'Matthew Henry', 'Here we have, 1. The sins threatened - bearing false witness in judgment and speaking lies in common conversation. Men could not arrive at such a pitch of impiety as to bear false witness (where to the guilt of a lie is added that of perjury and injury) if they had not advanced to it by allowing themselves to speak untruths in jest and banter, or under pretence of doing good. Thus men teach their tongues to speak lies, Jer 9:5. Those that will take a liberty to tell lies in discourse are in a...', 'teologico');
add('pv', 19, 6, 'Matthew Henry', 'These two verses are a comment upon Pro 19:4, and show, 1. How those that are rich and great are courted and caressed, and have suitors and servants in abundance. The prince that has power in his hand, and preferments at his disposal, has his gate and his ante-chamber thronged with petitioners, that are ready to adore him for what they can get. Many will entreat his favour, and think themselves happy in it. Even great men are humble suppliants to the prince. How earnest then should we be for ...', 'teologico');
add('pv', 19, 8, 'Matthew Henry', 'Those are here encouraged, 1. That take pains to get wisdom, to get knowledge, and grace, and acquaintance with God; those that do so show that they love their own souls, and will be found to have done themselves the greatest kindness imaginable. No man ever hated his own flesh, but loves that, yet many are wanting in love to their own souls, for only those love their souls, and consequently love themselves, aright, that get wisdom, true wisdom. 2. That take care to keep it when they have got...', 'teologico');
add('pv', 19, 9, 'Matthew Henry', 'Here is, 1. A repetition of what was said before (Pro 19:5), for we have need to be again and again warned of the danger of the sin of lying and false-witness-bearing, since nothing is of more fatal consequence. 2. An addition to it in one word; there it was said, He that speaks lies shall not escape, and intimated that he shall be punished. Here it is said, His punishment shall be such as will be his destruction: he shall perish; the lies he forged against others will be his own ruin. It is ...', 'teologico');
add('pv', 19, 10, 'Matthew Henry', 'Note, 1. Pleasure and liberty ill become a fool: Delight is not seemly for such a one. A man that has not wisdom and grace has no right nor title to true joy, and therefore it is unseemly. It ill becomes those that do not delight in God to delight in any thing, nor how to manage themselves, and therefore they do but expose themselves. It becomes ungracious fools to be afflicted, and mourn, and weep, not to laugh and be merry; rebukes are more proper for them than delights. Delight is seemly f...', 'teologico');
add('pv', 19, 11, 'Matthew Henry', 'A wise man will observe these two rules about his anger: 1. Not to be over-hasty in his resentments: Discretion teaches us to defer our anger, to defer the admission of it till we have thoroughly considered all the merits of the provocation, seen them in a true light and weighed them in a just balance; and then to defer the prosecution of it till there be no danger of running into any indecencies. Plato said to his servant, "I would beat thee, but that I am angry." Give it time, and it will c...', 'teologico');
add('pv', 19, 12, 'Matthew Henry', 'This is to the same purport with what we had Pro 16:14, Pro 16:15, and the design of it is, 1. To make kings wise and considerate in dispensing their frowns and smiles. They are not like those of common persons; their frowns are very terrible and their smiles very comfortable, and therefore it concerns them to be very careful that they never frighten a good man from doing well with their frowns, nor ever give countenance to a wicked man in doing ill with their smiles, for then they abuse thei...', 'teologico');
add('pv', 19, 13, 'Matthew Henry', 'It is an instance of the vanity of the world that we are liable to the greatest grief in those things wherein we promise ourselves the greatest comfort. It is as it proves. What greater temporal comfort can a man have than a good wife and good children? Yet, 1. A foolish son is a great affliction, and may make a man wish a thousand times he had been written childless. A son that will apply himself to no study or business, that will take no advice, that lives a lewd, loose, rakish life, and sp...', 'teologico');
add('pv', 19, 14, 'Matthew Henry', 'Note, 1. A discreet and virtuous wife is a choice gift of God\'s providence to a man - a wife that is prudent, in opposition to one that is contentious, Pro 19:13. For, though a wife that is continually finding fault may think it is her wit and wisdom to be so, it is really her folly; a prudent wife is meek and quiet, and makes the best of every thing. If a man has such a wife, let him not ascribe it to the wisdom of his own choice or his own management (for the wisest have been deceived both ...', 'teologico');
add('pv', 19, 15, 'Matthew Henry', 'See here the evil of a sluggish slothful disposition. 1. It stupefies men, and makes them senseless, and mindless of their own affairs, as they were cast into a deep sleep, dreaming much, but doing nothing. Slothful people doze away their time, bury their talents, live a useless life, and are the unprofitable burdens of the earth; for any service they do when they are awake they might as well be always asleep. Even their souls are idle and lulled asleep, their rational powers chilled and froz...', 'teologico');
add('pv', 19, 16, 'Matthew Henry', 'Here is, 1. The happiness of those that walk circumspectly. Those that make conscience of keeping the commandment in every thing, that live by rule, as becomes servants and patients, keep their own souls; they secure their present peace and future bliss, and provide every way well for themselves. If we keep God\'s word, God\'s word will keep us from every thing really hurtful. 2. The misery of those that live at large and never mind what they do: Those that despair their ways shall die, shall p...', 'teologico');
add('pv', 19, 17, 'Matthew Henry', 'Here is, I. The duty of charity described. It includes two things: - 1. Compassion, which is the inward principle of charity in the heart; it is to have pity on the poor. Those that have not a penny for the poor, yet may have pity for them, a charitable concern and sympathy; and, if a man give all his goods to feed the poor and have not this charity in his heart, it is nothing, Co1 13:3. We must draw out our souls to the hungry, Isa 58:10. 2. Bounty and liberality. We must not only pity the p...', 'teologico');
add('pv', 19, 18, 'Matthew Henry', 'Parents are here cautioned against a foolish indulgence of their children that are untoward and viciously inclined, and that discover such an ill temper of mind as is not likely to be cured but by severity. 1. Do not say that it is all in good time to correct them; no, as soon as ever there appears a corrupt disposition in them check it immediately, before it gets head, and takes root, and is hardened into a habit: Chasten thy son while there is hope, for perhaps, if he be let alone awhile, h...', 'teologico');
add('pv', 19, 19, 'Matthew Henry', '1. As we read this, it intimates, in short, that angry men never want woe. Those that are of strong, or rather headstrong, passions, commonly bring themselves and their families into trouble by vexatious suits and quarrels and the provocations they give; they are still smarting, in one instance or other, for their ungoverned heats; and, if their friends deliver them out of one trouble, they will quickly involve themselves in another, and they must do it again, all which troubles to themselves...', 'teologico');
add('pv', 19, 20, 'Matthew Henry', 'Note, 1. It is well with those that are wise in their latter end, wise for their latter end, for their future state, wise for another world, that are found wise when their latter end comes, wise virgins, wise builders, wise stewards, that are wise at length, and understand the things that belong to their peace, before they be hidden from their eyes. A carnal worldling at his end shall be a fool (Jer 17:11), but godliness will prove wisdom at last. 2. Those that would be wise in their latter e...', 'teologico');
add('pv', 19, 21, 'Matthew Henry', 'Here we have, 1. Men projecting. They keep their designs to themselves, but they cannot hide them from God; he knows the many devices that are in men\'s hearts, - devices against his counsels (as those, Psa 2:1-3; Mic 4:11), - devices without his counsel (no regard had to his providence, as those Jam 4:13, this and the other they will do, and not take God along with them), - devices unlike God\'s counsels; men are wavering in their devices, and often absurd and unjust, but God\'s counsels are wi...', 'teologico');
add('pv', 19, 22, 'Matthew Henry', 'Note, 1. The honour of doing good is what we may laudably be ambitious of. It cannot but be the desire of man, if he have any spark of virtue in him, to be kind; one would not covet an estate for any thing so much as thereby to be put into a capacity of relieving the poor and obliging our friends. 2. It is far better to have a heart to do good and want ability for it than have ability for it and want a heart to it: The desire of a man to be kind, and charitable, and generous, is his kindness,...', 'teologico');
add('pv', 19, 23, 'Matthew Henry', 'See what those that get by it that live in the fear of God, and always make conscience of their duty to him. 1. Safety: They shall not be visited with evil; they may be visited with sickness or other afflictions, but there shall be no evil in them, nothing to hurt them, because nothing to separate them from the love of God, or hurt to the soul. 2. Satisfaction: They shall abide satisfied; they shall have those comforts which are satisfying, and shall have a constant contentment and complacenc...', 'teologico');
add('pv', 19, 24, 'Matthew Henry', 'A sluggard is here exposed as a fool, for, 1. All his care is to save himself from labour and cold. See his posture: He hides his hand in his bosom, pretends he is lame and cannot work; his hands are cold, and he must warm them in his bosom; and, when they are warm there, he must keep them so. He hugs himself in his own ease and is resolved against labour and hardship. Let those work that love it; for his part he thinks there is no such fine life as sitting still and doing nothing. 2. He will...', 'teologico');
add('pv', 19, 25, 'Matthew Henry', 'Note, 1. The punishment of scorners will be a means of good to others. When men are so hardened in wickedness that they will not themselves be wrought upon by the severe methods that are used to reclaim and reform them, yet such methods must be used for the sake of others, that they may hear and fear, Deu 19:20. If the scorner will not be recovered from his sin, the disease being inveterate, yet the simple will beware of venturing upon the sin which exposes men thus. If it cure not the infect...', 'teologico');
add('pv', 19, 26, 'Matthew Henry', 'Here is, 1. The sin of a prodigal son. Besides the wrong he does to himself, he is injurious to his good parents, and basely ungrateful to those that were instruments of his being and have taken so much care and pains about him, which is a great aggravation of his sin and renders it exceedingly sinful in the eyes of God and man: He wastes is father, wastes his estate which he should have to support him in his old age, wastes his spirits, and breaks his heart, and brings his gray head with sor...', 'teologico');
add('pv', 19, 27, 'Matthew Henry', 'This is a good caution to those that have had a good education to take heed of hearkening to those who, under pretence of instructing them, draw them off from those good principles under the influence of which they were trained up. Observe, 1. There is that which seems designed for instruction, but really tends to the destruction of young men. The factors for vice will undertake to teach them free thoughts and a fashionable conversation, how to palliate the sins they have a mind to and stop t...', 'teologico');
add('pv', 19, 28, 'Matthew Henry', 'Here is a description of the worst of sinners, whose hearts are fully set in them to do evil. 1. They set that at defiance which would deter and detain them from sin: An ungodly witness is one that bears false witness against his neighbour, and will forswear himself to do another a mischief, in which there is not only great injustice, but great impiety; this is one of the worst of men. Or an ungodly witness is one that profanely and atheistically witnesses against religion and godliness, whos...', 'teologico');
add('pv', 19, 29, 'Matthew Henry', 'Note, 1. Scorners are fools. Those that ridicule things sacred and serious do but make themselves ridiculous. Their folly shall be manifest unto all men. 2. Those that scorn judgments cannot escape them, Pro 19:28. The unbelief of man shall not make God\'s threatenings of no effect; those that devour iniquity swallow the hook with the bait. The civil magistrate has judgments prepared for scorners, for otherwise he would bear the sword in vain; but if he be remiss, and connive at sin, yet God\'s...', 'teologico');
add('pv', 20, 2, 'Matthew Henry', 'See here, 1. How formidable kings are, and what a terror they strike upon those they are angry with. Their fear, with which (especially when they are absolute and their will is a law) they keep their subjects in awe, is as the roaring of a lion, which is very dreadful to the creatures he preys upon, and makes them tremble so that they cannot escape from him. Those princes that rule by wisdom and love rule like God himself, and bear his image; but those that rule merely by terror, and with a h...', 'teologico');
add('pv', 20, 3, 'Matthew Henry', 'This is designed to rectify men\'s mistakes concerning strife. 1. Men think it is their wisdom to engage in quarrels; whereas it is the greatest folly that can be. He thinks himself a wise man that is quick in resenting affronts, that stands upon every nicety of honour and right, and will not abate an ace of either, that prescribes, and imposes, and gives law, to every body; but he that thus meddles is a fool, and creates a great deal of needless vexation to himself. 2. Men think, when they ar...', 'teologico');
add('pv', 20, 4, 'Matthew Henry', 'See here the evil of slothfulness and the love of ease. 1. It keeps men from the most necessary business, from ploughing and sowing when the season is: The sluggard has ground to occupy, and has ability for it; he can plough, but he will not; some excuse or other he has to shift it off, but the true reason is that it is cold weather. Though ploughing time is not in the depth of winter, it is in the borders of winter, when he thinks it too cold for him to be abroad. Those are scandalously slug...', 'teologico');
add('pv', 20, 5, 'Matthew Henry', 'A man\'s wisdom is here said to be of use to him for the pumping of other people, and diving into them, 1. To get the knowledge of them. Though men\'s counsels and designs are ever so carefully concealed by them, so that they are as deep water which one cannot fathom, yet there are those who by sly insinuations, and questions that seem foreign, will get out of them both what they have done and what they intend to do. Those therefore who would keep counsel must not only put on resolution, but st...', 'teologico');
add('pv', 20, 6, 'Matthew Henry', 'Note, 1. It is easy to find those that will pretend to be kind and liberal. Many a man will call himself a man of mercy, will boast what good he has done and what good he designs to do, or, at least, what an affection he has to well-doing. Most men will talk a great deal of their charity, generosity, hospitality, and piety, will sound a trumpet to themselves, as the Pharisees, and what little goodness they have will proclaim it and make a mighty matter of it. 2. But it is hard to find those t...', 'teologico');
add('pv', 20, 7, 'Matthew Henry', 'It is here observed to the honour of a good man, 1. That he does well for himself. He has a certain rule, which with an even steady hand he governs himself by: He walks in his integrity; he keeps good conscience, and he has the comfort of it, for it is his rejoicing. He is not liable to those uneasinesses, either in contriving what he shall do or reflecting on what he has done, which those are liable to that walk in deceit. 2. That he does well for his family: His children are blessed after h...', 'teologico');
add('pv', 20, 8, 'Matthew Henry', 'Here is, 1. The character of a good governor: He is a king that deserves to be called so who sits in the throne, not as a throne of honour, to take his ease, and take state upon him, and oblige men to keep their distance, but as a throne of judgment, that he may do justice, give redress to the injured and punish the injurious, who makes his business his delight and loves no pleasure comparably to it, who does not devolve the whole care and trouble upon others, but takes cognizance of affairs ...', 'teologico');
add('pv', 20, 9, 'Matthew Henry', 'This question is not only a challenge to any man in the world to prove himself sinless, whatever he pretends, but a lamentation of the corruption of mankind, even that which remains in the best. Alas! Who can say, "I am sinless?" Observe, 1. Who the persons are that are excluded from these pretensions - all, one as well as another. Here, in this imperfect state, no person whatsoever can pretend to be without sin. Adam could say so in innocency, and saints can say so in heaven, but none in thi...', 'teologico');
add('pv', 20, 10, 'Matthew Henry', 'See here, 1. The various arts of deceiving that men have, all which evils the love of money is the root of. In paying and receiving money, which was then commonly done by the scale, they had divers weights, an under-weight for what they paid and an over-weight for what they received; in delivering out and taking in goods they had divers measures, a scanty measure to sell by and a large measure to buy by. This was done wrong with plot and contrivance, and under colour of doing right. Under the...', 'teologico');
add('pv', 20, 11, 'Matthew Henry', 'The tree is known by its fruits, a man by his doings, even a young tree by its first fruits, a child by his childish things, whether his work be clean only, appearing good (the word is used Pro 16:2), or whether it be right, that is, really good. This intimates, 1. That children will discover themselves. One may soon see what their temper is, and which way their inclination leads them, according as their constitution is. Children have not learned the art of dissembling and concealing their be...', 'teologico');
add('pv', 20, 12, 'Matthew Henry', 'Note, 1. God is the God of nature, and all the powers and faculties of nature are derived from him and depend upon him, and therefore are to be employed for him. It was he that formed the eye and planted the ear (Psa 94:9), and the structure of both is admirable; and it is he that preserves to us the use of both; to his providence we owe it that our eyes are seeing eyes and our ears hearing ears. Hearing and seeing are the learning senses, and must particularly own God\'s goodness in them. 2. ...', 'teologico');
add('pv', 20, 13, 'Matthew Henry', 'Note, 1. Those that indulge themselves in their ease may expect to want necessaries, which should have been gotten by honest labour. "Therefore, though thou must sleep (nature requires it), yet love not sleep, as those do that hate business. Love not sleep for its own sake, but only as it fits for further work. Love not much sleep, but rather grudge the time that is spent in it, and wish thou couldst live without it, that thou mightest always be employed in some good exercise." We must allow ...', 'teologico');
add('pv', 20, 14, 'Matthew Henry', 'See here 1. What arts men use to get a good bargain and to buy cheap. They not only cheapen carelessly, as if they had no need, no mind for the commodity, when perhaps they cannot go without it (there may be prudence in that), but they vilify and run down that which yet they know to be of value; they cry, "It is naught, it is naught; it has this and the other fault, or perhaps may have; it is not good of the sort; and it is too dear; we can have better and cheaper elsewhere, or have bought be...', 'teologico');
add('pv', 20, 15, 'Matthew Henry', 'The lips of knowledge (a good understanding to guide the lips and a good elocution to diffuse the knowledge) are to be preferred far before gold, and pearl, and rubies; for, 1. They are more rare in themselves, more scarce and hard to be got. There is gold in many a man\'s pocket that has no grace in his heart. In Solomon\'s time there was plenty of gold (Kg1 10:21) and abundance of rubies; every body wore them; they were to be bought in every town. But wisdom is a rare thing, a precious jewel;...', 'teologico');
add('pv', 20, 16, 'Matthew Henry', 'Two sorts of persons are here spoken of that are ruining their own estates, and will be beggars shortly, and therefore are not to be trusted with any good security: - 1. Those that will be bound for any body that will ask them, that entangle themselves in rash suretiship to oblige their idle companions; they will break at last, nay, they cannot hold out long; these waste by wholesale. 2. Those that are in league with abandoned women, that treat them, and court them, and keep company with them...', 'teologico');
add('pv', 20, 17, 'Matthew Henry', 'Note, 1. Sin may possibly be pleasant in the commission: Bread of deceit, wealth gotten by fraud, by lying and oppression, may be sweet to a man, and the more sweet for its being ill-gotten, such pleasure does the carnal mind take in the success of its wicked projects. All the pleasures and profits of sin are bread of deceit. They are stolen, for they are forbidden fruit; and they will deceive men, for they are not what they promise. For a time, however, they are rolled under the tongue as a ...', 'teologico');
add('pv', 20, 18, 'Matthew Henry', 'Note, 1. It is good in every thing to act with deliberation, and to consult with ourselves at least, and, in matters of moment, with our friends, too, before we determine, but especially to ask counsel of God, and beg direction from him, and observe the guidance of this eye. This is the way to have both our minds and our purposes established, and to succeed well in our affairs; whereas what is done hastily and with precipitation is repented of at leisure. Take time, and you will have done the...', 'teologico');
add('pv', 20, 19, 'Matthew Henry', 'Two sorts of people are dangerous to be conversed with: - 1. Tale-bearers, though they are commonly flatterers, and by fair speeches insinuate themselves into men\'s acquaintance. Those are unprincipled people that go about carrying stories, that make mischief among neighbours and relations, that sow in the minds of people jealousies of their governors, of their ministers, and of one another, that reveal secrets which they are entrusted with or which by unfair means they come to the knowledge ...', 'teologico');
add('pv', 20, 20, 'Matthew Henry', 'Here is, 1. An undutiful child become very wicked by degrees. He began with despising his father and mother, slighting their instructions, disobeying their commands, and raging at their rebukes, but at length he arrives at such a pitch of impudence and impiety as to curse them, to give them scurrilous and opprobrious language, and to wish mischief to those that were instruments of his being and have taken so much care and pains about him, and this in defiance of God and his law, which had mad...', 'teologico');
add('pv', 20, 21, 'Matthew Henry', 'Note, 1. It is possible that an estate may be suddenly raised. There are those that will be rich, by right or wrong, who make no conscience of what they say or do if they can but get money by it, who, when it is in their power, will cheat their own father, and who sordidly spare and hoard up what they get, grudging themselves and their families food convenient and thinking all lost but what they buy land with or put out to interest. By such ways as these a man may grow rich, may grow very ric...', 'teologico');
add('pv', 20, 22, 'Matthew Henry', 'Those that live in this world must expect to have injuries done them, affronts given them, and trouble wrongfully created them, for we dwell among briers. Now here we are told what to do when we have wrong done us. 1. We must not avenge ourselves, no, nor so much as think of revenge, or design it: "Say not thou, no, not in thy heart, I will recompense evil for evil. Do not please thyself with the thought that some time or other thou shalt have an opportunity of being quits with him. Do not wi...', 'teologico');
add('pv', 20, 23, 'Matthew Henry', 'This is to the same purport with what was said Pro 20:20. 1. It is here repeated, because it is a sin that God doubly hates (as lying, which is of the same nature with this sin, is mentioned twice among the seven things that God hates, Pro 6:17, Pro 6:19), and because it was probably a sin very much practised at that time in Israel, and therefore made light of as if there were no harm in it, under pretence that, being commonly used, there was no trading without it. 2. It is here added, A fals...', 'teologico');
add('pv', 20, 24, 'Matthew Henry', 'We are here taught that in all our affairs, 1. We have a necessary and constant dependence upon God. All our natural actions depend upon his providence, all our spiritual actions upon his grace. The best man is no better than God makes him; and every creature is that to us which it is the will of God that it should be. Our enterprises succeed, not as we desire and design, but as God directs and disposes. The goings even of a strong man (so the word signifies) are of the Lord, for his strength...', 'teologico');
add('pv', 20, 25, 'Matthew Henry', 'Two things, by which God is greatly affronted, men are here said to be ensnared by, and entangled not only in guilt, but in trouble and ruin at length: - 1. Sacrilege, men\'s alienating holy things and converting them to their own use, which is here called devouring them. What is devoted in any way to the service and honour of God, for the support of religion and divine worship or the relief of the poor, ought to be conscientiously preserved to the purposes designed; and those that directly or...', 'teologico');
add('pv', 20, 26, 'Matthew Henry', 'See here, 1. What is the business of magistrates. They are to be a terror to evil-doers. They must scatter the wicked, who are linked in confederacies to assist and embolden one another in doing mischief; and there is no doing this but by bringing the wheel over them, that is, putting the laws in execution against them, crushing their power and quashing their projects. Severity must sometimes be used to rid the country of those that are openly vicious and mischievous, debauched and debauching...', 'teologico');
add('pv', 20, 27, 'Matthew Henry', 'We have here the dignity of the soul, the great soul of man, that light which lighteth every man. 1. It is a divine light; it is the candle of the Lord, a candle of his lighting, for it is the inspiration of the Almighty that gives us understanding. He forms the spirit of man within him. It is after the image of God that man is created in knowledge. Conscience, that noble faculty, is God\'s deputy in the soul; it is a candle not only lighted by him, but lighted for him. The Father of spirits i...', 'teologico');
add('pv', 20, 28, 'Matthew Henry', 'Here we have, 1. The virtues of a good king. Those are mercy and truth, especially mercy, for that is mentioned twice here. He must be strictly faithful to his word, must be sincere, and abhor all dissimulation, must religiously discharge all the trusts reposed in him, must support and countenance truth. He must likewise rule with clemency, and by all acts of compassion gain the affections of his people. Mercy and truth are the glories of God\'s throne, and kings are called gods. 2. The advant...', 'teologico');
add('pv', 20, 29, 'Matthew Henry', 'This shows that both young and old have their advantages, and therefore must each of them be, according to their capacities, serviceable to the public, and neither of them despise nor envy the other. 1. Let not old people despise the young, for they are strong and fit for action, able to go through business and break through difficulties, which the aged and weak cannot grapple with. The glory of young men is their strength, provided they use it well (in the service of God and their country, n...', 'teologico');
add('pv', 20, 30, 'Matthew Henry', 'Note, 1. Many need severe rebukes. Some children are so obstinate that their parents can do no good with them without sharp correction; some criminals must feel the rigour of the law and public justice; gentle methods will not work upon them; they must be beaten black and blue. And the wise God sees that his own children sometimes need very sharp afflictions. 2. Severe rebukes sometimes do a great deal of good, as corrosives contribute to the cure of a wound, eating out the proud flesh. The r...', 'teologico');
add('pv', 21, 2, 'Matthew Henry', 'Note, 1. We are all apt to be partial in judging of ourselves and our own actions, and to think too favourably of our own character, as if there was nothing amiss in it: Every way of a man, even his by-way, is right in his own eyes. The proud heart is very ingenious in putting a fair face upon a foul matter, and in making that appear right to itself which is far from being so, to stop the mouth of conscience. 2. We are sure that the judgment of God concerning us is according to truth. Whateve...', 'teologico');
add('pv', 21, 3, 'Matthew Henry', 'Here, 1. It is implied that many deceive themselves with a conceit that, if they offer sacrifice, that will excuse them from doing justice, and procure them a dispensation for their unrighteousness; and this makes their way seem right, Pro 21:2. We have fasted, Isa 58:3. I have peace-offerings with me, Pro 7:14. 2. It is plainly declared that living a good life (doing justly and loving mercy) is more pleasing to God than the most pompous and expensive instances of devotion. Sacrifices were of...', 'teologico');
add('pv', 21, 4, 'Matthew Henry', 'This may be taken as showing us, 1. The marks of a wicked man. He that has a high look and a proud heart, that carries himself insolently and scornfully towards both God and man, and that is always ploughing and plotting, designing and devising some mischief or other, is indeed a wicked man. The light of the wicked is sin. Sin is the pride, the ambition, the glory and joy, and the business of wicked men. 2. The miseries of wicked man. His raised expectations, his high designs, and most elabor...', 'teologico');
add('pv', 21, 5, 'Matthew Henry', 'Here is, 1. The way to be rich. If we would live plentifully and comfortably in the world, we must be diligent in our business, and not shrink from the toil and trouble of it, but prosecute it closely, improving all advantages and opportunities for it, and doing what we do with all our might; yet we must not be hasty in it, nor hurry ourselves and others with it, but keep doing fair and softly, which, we say, goes far in a day. With diligence there must be contrivance. The thoughts of the dil...', 'teologico');
add('pv', 21, 6, 'Matthew Henry', 'This shows the folly of those that hope to enrich themselves by dishonest practices, by oppressing and over-reaching those with whom they deal, by false-witness-bearing, or by fraudulent contracts, of those that make no scruples of lying when there is any thing to be got by it. They may perhaps heap up treasures by these means, that which they make their treasure; but, 1. They will not meet with the satisfaction they expect. It is a vanity tossed to and fro; it will be disappointment and vexa...', 'teologico');
add('pv', 21, 7, 'Matthew Henry', 'See here, 1. The nature of injustice. Getting money by lying (Pro 21:6) is no better than downright robbery. Cheating is stealing; you might as well pick a man\'s pocket as impose upon him by a lie in making a bargain, which he had no fence against but by not believing you; and it will be no excuse from the guilt of robbery to say that he might choose whether he would believe you, for that is a debt we should owe to all men. 2. The cause of injustice. Men refuse to do judgment; they will not r...', 'teologico');
add('pv', 21, 8, 'Matthew Henry', 'This shows that as men are so is their way. 1. Evil men have evil ways. If the man be froward, his way also is strange; and this is the way of most men, such is the general corruption of mankind. They have all gone aside (Psa 14:2, Psa 14:3); all flesh have perverted their way. But the froward man, the man of deceit, that acts by craft and trick in all he does, his way is strange, contrary to all the rules of honour and honesty. It is strange, for you know not where to find him nor when you h...', 'teologico');
add('pv', 21, 9, 'Matthew Henry', 'See here, 1. What a great affliction it is to a man to have a brawling scolding woman for his wife, who upon every occasion, and often upon no occasion, breaks out into a passion, and chides either him or those about her, is fretful to herself and furious to her children and servants, and, in both, vexatious to her husband. If a man has a wide house, spacious and pompous, this will embitter the comfort of it to him - a house of society (so the word is), in which a man may be sociable, and ent...', 'teologico');
add('pv', 21, 10, 'Matthew Henry', 'See here the character of a very wicked man. 1. The strong inclination he has to do mischief. His very soul desires evil, desires that evil may be done and that he may have the pleasure, not only of seeing it, but of having a hand in it. The root of wickedness lies in the soul; the desire that men have to do evil, that is the lust which conceives and brings forth sin. 2. The strong aversion he has to do good: His neighbour, his friend, his nearest relation, finds no favour in his eyes, cannot...', 'teologico');
add('pv', 21, 11, 'Matthew Henry', 'This we had before (Pro 19:25), and it shows that there are two ways by which the simple may be made wise: - 1. By the punishments that are inflicted on those that are incorrigibly wicked. Let the law be executed upon a scorner, and even he that is simple will be awakened and alarmed by it, and will discern, more than he did, the evil of sin, and will take warning by it and take heed. 2. By the instructions that are given to those that are wise and willing to be taught: When the wise is instr...', 'teologico');
add('pv', 21, 12, 'Matthew Henry', '1. As we read this verse, it shows why good men, when they come to understand things aright, will not envy the prosperity of evil-doers. When they see the house of the wicked, how full it is perhaps of all the good things of this life, they are tempted to envy; but when they wisely consider it, when they look upon it with an eye of faith, when they see God overthrowing the wicked for their wickedness, that there is a curse upon their habitation which will certainly be the ruin of it ere long,...', 'teologico');
add('pv', 21, 13, 'Matthew Henry', 'Here we have the description and doom of an uncharitable man. 1. His description: He stops his ears at the cry of the poor, at the cry of their wants and miseries (he resolves to take no cognizance of them), at the cry of their requests and supplications - he resolves he will not so much as give them the hearing, turns them away from his door, and forbids them to come near him, or, if he cannot avoid hearing them, he will not need them, nor be moved by their complaints, no be prevailed with b...', 'teologico');
add('pv', 21, 14, 'Matthew Henry', 'Here is, 1. The power that is commonly found to be in gifts. Nothing is more violent than anger. O the force of strong wrath! And yet a handsome present, prudently managed, will turn away some men\'s wrath when it seemed implacable, and disarm the keenest and most passionate resentments. Covetousness is commonly a master-sin and has the command of other lusts. Pecuniae obediunt omnia - Money commands all things. Thus Jacob pacified Esau and Abigail David. 2. The policy that is commonly used in...', 'teologico');
add('pv', 21, 15, 'Matthew Henry', 'Note, 1. It is a pleasure and satisfaction to good men both to see justice administered by the government they live under, right taking place and iniquity suppressed, and also to practise it themselves, according as their sphere is. They no only do justice, but do it with pleasure, not only for fear of shame, but for love of virtue. 2. It is a terror to wicked men to see the laws put in execution against vice and profaneness. It is destruction to them; as it is also a vexation to them to be f...', 'teologico');
add('pv', 21, 16, 'Matthew Henry', 'Here is, 1. The sinner upon his ramble: He wanders out of the way of understanding, and when once he has left that good way he wanders endlessly. The way of religion is the way of understanding; those that are not truly pious are not truly intelligent; those that wander out of this way break the hedge which God has set, and follow the conduct of the world and the flesh; and they go astray like lost sheep. 2. The sinner at his rest, or rather his ruin: He shall remain (quiescet - he shall rest...', 'teologico');
add('pv', 21, 17, 'Matthew Henry', 'Here is an argument against a voluptuous luxurious life, taken from the ruin it brings upon men\'s temporal interests. Here is 1. The description of an epicure: He loves pleasure. God allows us to use the delights of sense soberly and temperately, wine to make glad the heart and put vigour into the spirits, and oil to make the face to shine and beautify the countenance; but he that loves these, that sets his heart upon them, covets them earnestly, is solicitous to have all the delights of sens...', 'teologico');
add('pv', 21, 18, 'Matthew Henry', 'This intimates, 1. What should be done by the justice of men: The wicked, that are the troublers of a land, ought to be punished, for the preventing and turning away of those national judgments which otherwise will be inflicted and in which even the righteous are many times involved. Thus when Achan was stoned he was a ransom for the camp of righteous Israel; and the seven sons of Saul, when they were hanged, were a ransom for the kingdom of righteous David. 2. What is often done by the provi...', 'teologico');
add('pv', 21, 19, 'Matthew Henry', 'Note, 1. Unbridled passions embitter and spoil the comfort of all relations. A peevish angry wife makes her husband\'s life uneasy, to whom she should be a comfort and a meet help. Those cannot dwell in peace and happiness that cannot dwell in peace and love. Even those that are one flesh, if they be not withal one spirit, have no joy of their union. 2. It is better to have no company than bad company. The wife of thy covenant is thy companion, and yet, if she be peevish and provoking, it is b...', 'teologico');
add('pv', 21, 20, 'Matthew Henry', 'Note, 1. Those that are wise will increase what they have and live plentifully; their wisdom will teach them to proportion their expenses to their income and to lay up for hereafter; so that there is a treasure of things to be desired, and as much as needs be desired, a good stock of all things convenient, laid up in season, and particularly of oil, one of the staple commodities of Canaan, Deu 8:8. This is in the habitation, or cottage, of the wise; and it is better to have an old-fashioned h...', 'teologico');
add('pv', 21, 21, 'Matthew Henry', 'See here, 1. What it is to make religion our business; it is to follow after righteousness and mercy, not to content ourselves with easy performances, but to do our duty with the utmost care and pains, as those that are pressing forward and in fear of coming short. We must both do justly and love mercy, and must proceed and persevere therein; and, though we cannot attain to perfection, yet it will be a comfort to us if we aim at it and follow after it. 2. What will be the advantage of doing s...', 'teologico');
add('pv', 21, 22, 'Matthew Henry', 'Note, 1. Those that have power are apt to promise themselves great things from their power. The city of the mighty thinks itself impregnable, and therefore its strength is the confidence thereof, what it boasts of and trust in, bidding defiance to danger. 2. Those that have wisdom, though they are so modest as not to promise much, often perform great things, even against those that are so confident of their strength, by their wisdom. Good conduct will go far even against great force; and a st...', 'teologico');
add('pv', 21, 23, 'Matthew Henry', 'Note, 1. It is our great concern to keep our souls from straits, being entangled in snares and perplexities, and disquieted with troubles, that we may preserve the possession and enjoyment of ourselves and that our souls may be in frame for the service of God. 2. Those that would keep their souls must keep a watch before the door of their lips, must keep the mouth by temperance, that no forbidden fruit go into it, no stolen waters, that nothing be eaten or drunk to excess; they must keep the ...', 'teologico');
add('pv', 21, 24, 'Matthew Henry', 'See here the mischief of pride and haughtiness. 1. It exposes men to sin; it makes them passionate, and kindles in them the fire of proud wrath. They are continually dealing in it, as if it were their trade to be angry, and they had nothing so much to do as to barter passions and exchange bitter words. Most of the wrath that inflames the spirits and societies of men is proud wrath. Men cannot bear the least slight, nor in any thing to be crossed or contradicted, but they are out of humour, na...', 'teologico');
add('pv', 21, 25, 'Matthew Henry', 'Here we have, 1. The miseries of the slothful, whose hands refuse to labour in an honest calling, by which they might get an honest livelihood. They are as fit for labour as other men, and business offers itself, to which they might lay their hands and apply their minds, but they will not; herein they fondly think they do well for themselves, see Pro 26:16. Soul, take thy ease. But really they are enemies to themselves; for, besides that their slothfulness starves them, depriving them of thei...', 'teologico');
add('pv', 21, 27, 'Matthew Henry', 'Sacrifices were of divine institution; and when they were offered in faith, and with repentance and reformation, God was greatly honoured by them and well-pleased in them. But they were often not only unacceptable, but an abomination, to God, and he declared so, which was an indication both that they were not required for their own sakes and that there were better things, and for effectual, in reserve, when sacrifice and offering should be done away. They were an abomination, 1. When they wer...', 'teologico');
add('pv', 21, 28, 'Matthew Henry', 'Here is, 1. The doom of a false witness. He who, for favour to one side or malice to the other, gives in a false evidence, or makes an affidavit of that which he knows to be false, or at least does not know to be true, if it be discovered, his reputation will be ruined. A man may tell a lie perhaps in his haste; but he that gives a false testimony does it with deliberation and solemnity, and it cannot but be a presumptuous sin, and a forfeiture of man\'s credit. But, though he should not be di...', 'teologico');
add('pv', 21, 29, 'Matthew Henry', 'Here is, 1. The presumption and impudence of a wicked man: He hardens his face - brazens it, that he may not blush - steels it, that he may not tremble when he commits the greatest crimes; he bids defiance to the terrors of the law and the checks of his own conscience, the reproofs of the word and the rebukes of Providence; he will have his way and nothing shall hinder him, Isa 57:17. 2. The caution and circumspection of a good man: As for the upright, he does not say, What would I do? What h...', 'teologico');
add('pv', 21, 30, 'Matthew Henry', 'The designing busy part of mankind are directed, in all their counsels and undertakings, to have their eye to God, and to believe, 1. That there can be no success against God, and therefore they must never act in opposition to him, in contempt of his commands, or in contradiction to his counsels. Though they think they have wisdom, and understanding, and counsel, the best politics and politicians, on their side, yet, if it be against the Lord, it cannot prosper long; it shall not prevail at l...', 'teologico');
add('pv', 22, 2, 'Matthew Henry', 'Note, 1. Among the children of men divine Providence has so ordered it that some are rich and others poor, and these are intermixed in societies: The Lord is the Maker of both, both the author of their being and the disposer of their lot. The greatest man in the world must acknowledge God to be his Maker, and is under the same obligations to be subject to him that the meanest is; and the poorest has the honour to be the work of God\'s hands as much as the greatest. Have they not all one Father...', 'teologico');
add('pv', 22, 3, 'Matthew Henry', 'See here, 1. The benefit of wisdom and consideration: A prudent man, by the help of his prudence, will foresee an evil, before it comes, and hide himself; he will be aware when he is entering into a temptation and will put on his armour and stand on his guard. When the clouds are gathering for a storm he takes the warning, and flies to the name of the Lord as his strong tower. Noah foresaw the deluge, Joseph the years of famine, and provided accordingly. 2. The mischief of rashness and incons...', 'teologico');
add('pv', 22, 4, 'Matthew Henry', 'See here, 1. Wherein religion does very much consist - in humility and the fear of the Lord; that is, walking humbly with God. We must so reverence God\'s majesty and authority as to submit with all humility to the commands of his word and the disposals of his providence. We must have such low thoughts of ourselves as to behave humbly towards God and man. Where the fear of God is there will be humility. 2. What is to be gotten by it - riches, and honour, and comfort, and long life, in this wor...', 'teologico');
add('pv', 22, 5, 'Matthew Henry', 'Note 1. The way of sin is vexatious and dangerous: In the way of the froward, that crooked way, which is contrary to the will and word of God, thorns and snares are found, thorns of grief for past sins and snares entangling them in further sin. He that makes no conscience of what he says and does will find himself hampered by that imaginary liberty, and tormented by his pleasures. Froward people, who are soon angry, expose themselves to trouble at every step. Every thing will fret and vex him...', 'teologico');
add('pv', 22, 7, 'Matthew Henry', 'He had said (Pro 22:2.), Rich and poor meet together; but here he finds, here he shows, that, as to the things of this life, there is a great difference; for, 1. Those that have little will be in subjection to those that have much, because they have dependence upon them, they have received, and expect to receive, support from them: The rich rule over the poor, and too often more than becomes them, with pride and rigour, unlike to God, who, though he be great, yet despises not any. It is part ...', 'teologico');
add('pv', 22, 8, 'Matthew Henry', 'Note 1. Ill-gotten gains will not prosper: He that sows iniquity, that does an unjust thing in hopes to get by it, shall reap vanity; what he gets will never do him any good nor give him any satisfaction. He will meet nothing but disappointment. Those that create trouble to others do but prepare trouble for themselves. Men shall reap as they sow. 2. Abused power will not last. If the rod of authority turn into a rod of anger, if men rule by passion instead of prudence, and, instead of the pub...', 'teologico');
add('pv', 22, 9, 'Matthew Henry', 'Here is, 1. The description of a charitable man; he has a bountiful eye, opposed to the evil eye (Pro 23:6) and the same with the single eye (Mat 6:22), - an eye that seeks out objects of charity, besides those that offer themselves, - an eye that, upon the sight of one in want and misery, affects the heart with compassion, - an eye that with the alms gives a pleasant look, which makes the alms doubly acceptable. He has also a liberal hand: He gives of his bread to those that need - his bread...', 'teologico');
add('pv', 22, 10, 'Matthew Henry', 'See here, 1. What the scorner does. It is implied that he sows discord and makes mischief wherever he comes. Much of the strife and contention which disturb the peace of all societies is owing to the evil interpreter (as some read it), that construes every thing into the worst, to those that despise and deride every one that comes in their way and take a pride in bantering and abusing all mankind. 2. What is to be done with the scorner that will not be reclaimed: Cast him out of your society,...', 'teologico');
add('pv', 22, 11, 'Matthew Henry', 'Here is, 1. The qualification of an accomplished, a complete gentleman, that is fit to be employed in public business. He must be an honest man, a man that loves pureness of heart and hates all impurity, not only pure from all fleshly lusts, but from all deceit and dissimulation, from all selfishness and sinister designs, that takes care to approve himself a man of sincerity, is just and fair from principle, and delights in nothing more than in keeping his own conscience clean and void of off...', 'teologico');
add('pv', 22, 12, 'Matthew Henry', 'Here is, 1. The special care God takes to preserve knowledge, that is, to keep up religion in the world by keeping up among men the knowledge of himself and of good and evil, notwithstanding the corruption of mankind, and the artifices of Satan to blind men\'s minds and keep them in ignorance. It is a wonderful instance of the power and goodness of the eyes of the Lord, that is, his watchful providence. He preserves men of knowledge, wise and good men (Ch2 16:9), particularly faithful witnesse...', 'teologico');
add('pv', 22, 13, 'Matthew Henry', 'Note, 1. Those that have no love for their business will never want excuses to shake it off. Multitudes are ruined, both for soul and body, by their slothfulness, and yet still they have something or other to say for themselves, so ingenious are men in putting a cheat upon their own souls. And who, I pray, will be the gainer at last, when the pretences will be all rejected as vain and frivolous? 2. Many frighten themselves from real duties by imaginary difficulties: The slothful man has work ...', 'teologico');
add('pv', 22, 14, 'Matthew Henry', 'This is designed to warn all young men against the lusts of uncleanness. As they regard the welfare of their souls, let them take heed of strange women, lewd women, whom they ought to be strange to, of the mouth of strange women, of the kisses of their lips (Pro 7:13), of the words of their lips, their charms and enticements. Dread them; have nothing to do with them; for, 1. Those who abandon themselves to that sin give proof that they are abandoned of God: it is a deep pit, which those fall ...', 'teologico');
add('pv', 22, 15, 'Matthew Henry', 'We have here two very sad considerations: - 1. That corruption is woven into our nature. Sin is foolishness; it is contrary both to our right reason and to our true interest. It is in the heart; there is an inward inclination to sin, to speak and act foolishly. It is in the heart of children; they bring it into the world with them; it is what they were shapen and conceived in. It is not only found there, but it is bound there; it is annexed to the heart (so some); vicious dispositions cleave ...', 'teologico');
add('pv', 22, 16, 'Matthew Henry', 'This shows what evil courses rich men sometimes take, by which, in the end, they will impoverish themselves and provoke God, notwithstanding their abundance, to bring them to want; they oppress the poor and give to the rich. 1. They will not in charity relieve the poor, but withhold from them, that by saving that which is really the best, but which they think the most needless part of their expenses, they may increase their riches; but they will make presents to the rich, and give them great ...', 'teologico');
add('pv', 22, 17, 'Matthew Henry', 'Solomon here changes his style and manner of speaking. Hitherto, for the most part, since the beginning of ch. 10, he had laid down doctrinal truths, and but now and then dropped a word of exhortation, leaving us to make the application as we went along; but here, to the end of ch. 24, he directs his speech to his son, his pupil, his reader, his hearer, speaking as to a particular person. Hitherto, for the most part, his sense was comprised in one verse, but here usually it is drawn out furth...', 'teologico');
add('pv', 22, 22, 'Matthew Henry', 'After this solemn preface, one would have expected something new and surprising; but no; here is a plain and common, but very needful caution against the barbarous and inhuman practices of oppressing poor people. Observe,\nI. The sin itself, and that is robbing the poor and making them poorer, taking from those that have but little to lose and so leaving them nothing. It is bad to rob any man, but most absurd to rob the poor, whom we should relieve, - to squeeze those with our power whom we sh...', 'teologico');
add('pv', 22, 24, 'Matthew Henry', 'Here is, 1. A good caution against being intimate with a passionate man. It is the law of friendship that we accommodate ourselves to our friends and be ready to serve them, and therefore we ought to be wise and wary in the choice of a friend, that we come not under the sacred tie to any one whom it would be our folly to accommodate ourselves to. Thought we must be civil to all, yet we must be careful whom we lay in our bosoms and contract a familiarity with. And, among others, a man who is e...', 'teologico');
add('pv', 22, 26, 'Matthew Henry', 'We have here, as often before, a caution against suretiship, as a thing both imprudent and unjust. 1. We must not associate ourselves, nor contract an intimacy, with men of broken fortunes, and reputations, who need and will urge their friends to be bound for them, that they may cheat their neighbours to feed their lusts, and by keeping up a little longer may do the more damage at last to those that give them credit. Have nothing to do with such; be not thou among them. 2. We must not cheat p...', 'teologico');
add('pv', 22, 28, 'Matthew Henry', '1. We are here taught not to invade another man\'s right, though we can find ways of doing it ever so secretly and plausibly, clandestinely and by fraud, without any open force. Let not property in general be entrenched upon, by robbing men of their liberties and privileges, or of any just ways of maintaining them. Let not the property of particular persons be encroached upon. The land-marks, or meer-stones, are standing witnesses to every man\'s right; let not those be removed quite away, for ...', 'teologico');
add('pv', 22, 29, 'Matthew Henry', 'Here is, 1. A plain intimation what a hard thing it is to find a truly ingenious industrious man: "Seest thou a man diligent in his business? Thou wilt not see many such, so epidemical are dulness and slothfulness." He is here commended who lays out himself to get business, though it be but in a very low and narrow sphere, and is not easy when he is out of business, who loves business, is quick and active in it, and goes through it, not only with constancy and resolution, but with dexterity a...', 'teologico');
add('pv', 23, 4, 'Matthew Henry', 'As some are given to appetite (Pro 23:2) so others to covetousness, and those Solomon here takes to task. Men cheat themselves as much by setting their hearts on money (though it seems most substantial) as by setting them on dainties. Observe,\nI. How he dissuades the covetous man from toiling and tormenting himself (Pro 23:4). "Do not aim to be rich, to raise an estate, and to make what thou hast in abundance more than it is." We must endeavor to live comfortably, and provide for our children...', 'teologico');
add('pv', 23, 6, 'Matthew Henry', 'Those that are voluptuous and given to appetite (Pro 23:2) are glad to be where there is good cheer stirring, and those that are covetous and saving, that they may spare at home, will be glad to get a dinner at another man\'s table; and therefore both are here advised not to be forward to accept of every man\'s invitation, but especially not to thrust themselves in uninvited. Observe, 1. There are those that pretend to bid their friends welcome that are not hearty and sincere in it. They have a...', 'teologico');
add('pv', 23, 9, 'Matthew Henry', 'We are here directed not to cast pearls before swine (Mat 7:6) and not to expose things sacred to the contempt and ridicule of profane scoffers. It is our duty to take all fit occasions to speak of divine things; but, 1. There are some that will make a jest of every thing, though it be ever so prudently and pertinently spoken, that will not only despise a wise man\'s words, but despise even the wisdom of them, that in them which is most improvable for their own edification; they will particula...', 'teologico');
add('pv', 23, 10, 'Matthew Henry', 'Note, 1. The fatherless are taken under God\'s special protection; with him they not only find mercy shown to them (Hos 14:3) but justice done for them. He is their Redeemer, their Goel, their near kinsman, that will take their part and stand up for them with jealousy, as taking himself affronted in the injuries done to them. As their Redeemer he will plead their cause against those that do them any injury, and, one way or other, will not only defend their right, and recover it for them, but a...', 'teologico');
add('pv', 23, 12, 'Matthew Henry', 'Here is, 1. A parent instructing his child. He is here brought in persuading him to give his mind to his book, and especially to the scriptures and his catechism, to attend to the words of knowledge, by which he might come to know his duty, and danger, and interest, and not to think it enough to give them the hearing, but to apply his heart to them, to delight in them, and bow his will to the authority of them. The heart is then applied to the instruction when the instruction is applied to th...', 'teologico');
add('pv', 23, 17, 'Matthew Henry', 'Here is, 1. A necessary caution against entertaining any favourable thoughts of prospering profaneness: "Let not thy heart envy sinners; do not grudge them either the liberty they take to sin or the success they are to be pitied rather than envied. Their prosperity is their portion (Psa 73:3), nay, it is their poison," Pro 1:32. We must not harbour in our hearts any secret discontent at the providence of God, though it seem to smile upon them, nor wish ourselves in their condition. "Let not t...', 'teologico');
add('pv', 23, 19, 'Matthew Henry', 'Here is good advice for parents to give to their children; words are put into their mouths, that they may train them up in the way they should go. Here we have,\nI. An earnest call to young people to attend to the advice of their godly parents, not only to this that is here given, but to all other profitable instructions: "Here, my son, and be wise, Pro 23:19. This will be an evidence that thou art wise and a means to make thee wiser." Wisdom, as faith, comes by hearing. And again (Pro 23:22):...', 'teologico');
add('pv', 23, 29, 'Matthew Henry', 'Solomon here gives fair warning against the sin of drunkenness, to confirm what he had said, Pro 23:20.\nI. He cautions all people to keep out of the way of temptations to this sin (Pro 23:31): Look not thou upon the wine when it is red. Red wine was in Canaan looked upon as the best wine, it is therefore called the blood of the grape. Critics judge of wine, among other indications, by the colour of it; some wine, they say, looks charmingly, looks so well that it even says, "Come and drink me;...', 'teologico');
add('pv', 24, 3, 'Matthew Henry', 'We are tempted to envy those that grow rich, and raise their estates and families, by such unjust courses as our consciences will by no means suffer us to use. But, to set aside that temptation, Solomon here shows that a man, with prudent management, may raise his estate and family by lawful and honest means, with a good conscience, and a good name, and the blessing of God upon his industry; and, if the other be raised a little sooner, yet these will last a great deal longer. 1. That which is...', 'teologico');
add('pv', 24, 7, 'Matthew Henry', 'Here is the description, 1. Of a weak man: Wisdom is too high for him; he thinks it so, and therefore, despairing to attain it, he will take no pains in the pursuit of it, but sit down content without it. And really it is so; he has not capacity for it, and therefore the advantages he has for getting it are all in vain to him. It is no easy thing to get wisdom; those that have natural parts good enough, yet if they be foolish, that is, if they be slothful and will not take pains, if they be p...', 'teologico');
add('pv', 24, 10, 'Matthew Henry', 'Note, 1. In the day of adversity we are apt to faint, to droop and be discouraged, to desist from our work, and to despair of relief. Our spirits sink, and then our hands hang down and our knees grow feeble, and we become unfit for anything. And often those that are most cheerful when they are well droop most, and are most dejected, when any thing ails them. 2. This is an evidence that our strength is small, and is a means of weakening it more. "It is a sign that thou art not a man of any res...', 'teologico');
add('pv', 24, 11, 'Matthew Henry', 'Here is, 1. A great duty required of us, and that is to appear for the relief of oppressed innocency. If we see the lives or livelihoods of any in danger of being taken away unjustly, we ought to bestir ourselves all we can to save them, by disproving the false accusations on which they are condemned and seeking out proofs of their innocency. Though the persons be not such as we are under any particular obligation to, we must help them, out of a general zeal for justice. If any be set upon by...', 'teologico');
add('pv', 24, 13, 'Matthew Henry', 'We are here quickened to the study of wisdom by the consideration both of the pleasure and the profit of it. 1. It will be very pleasant. We eat honey because it is sweet to the taste, and upon that account we call it good, especially that which runs first from the honey-comb. Canaan was said to flow with milk and honey, and honey was the common food of the country (Luk 24:41, Luk 24:42), even for children, Isa 7:15. Thus should we feed upon wisdom, and relish the good instructions of it. Tho...', 'teologico');
add('pv', 24, 15, 'Matthew Henry', 'This is spoken, not so much by way of counsel to wicked men (they will not receive instruction, Pro 23:9), but rather in defiance of them, for the encouragement of good people that are threatened by them. See here, 1. The designs of the wicked against the righteous, and the success they promise themselves in those designs. The plot is laid deeply: They lay wait against the dwelling of the righteous, thinking to charge some iniquity upon it, or compass dome design against it; they lie in wait ...', 'teologico');
add('pv', 24, 17, 'Matthew Henry', 'Here, 1. The pleasure we are apt to take in the troubles of an enemy is forbidden us. If any have done us an ill turn, or if we bear them ill-will only because they stand in our light or in our way, when any damage comes to them (suppose they fall), or any danger (suppose they stumble), our corrupt hearts are too apt to conceive a secret delight and satisfaction in it - Aha! so would we have it; they are entangled; the wilderness has shut them in - or, as Tyrus said concerning Jerusalem (Eze ...', 'teologico');
add('pv', 24, 19, 'Matthew Henry', 'Here, 1. He repeats the caution he had before given against envying the pleasures and successes of wicked man in their wicked ways. This he quotes from his father David, Psa 37:1. We must not in any case fret ourselves, or make ourselves uneasy, whatever God does in his providence how disagreeable soever it is to our sentiments, interests, and expectations, we must acquiesce in it. Even that which grieves us must not fret us; nor must our eye be evil against any because God is good. Are we mo...', 'teologico');
add('pv', 24, 21, 'Matthew Henry', 'Note, 1. Religion and loyalty must go together. As men, it is our duty to honour our Creator, to worship and reverence him, and to be always in his fear; as members of a community, incorporated for mutual benefit, it is our duty to be faithful and dutiful to the government God has set over us, Rom 13:1, Rom 13:2. Those that are truly religious will be loyal, in conscience towards God; the godly in the land will be the quite in the land; and those are not truly loyal, or will be so no longer t...', 'teologico');
add('pv', 24, 23, 'Matthew Henry', 'Here are lessons for wise men, that is, judges and princes. As subjects must do their duty, and be obedient to magistrates, so magistrates must do their duty in administering justice to their subjects, both in pleas of the crown and causes between party and party. These are lessons for them. 1. They must always weigh the merits of a cause, and not be swayed by any regard, one way or other, to the parties concerned: It is not good in itself, nor can it ever do well, to have respect of persons ...', 'teologico');
add('pv', 24, 27, 'Matthew Henry', 'This is a rule of prudence in the management of household affairs; for all good men should be good husbands, and manage with discretion, which would prevent a great deal of sin, and trouble, and disgrace to their profession. 1. We must prefer necessaries before conveniences, and not lay that out for show which should be expended for the support of the family. We must be contented with a mean cottage for a habitation, rather than want, or go in debt for, food convenient. 2. We must not think o...', 'teologico');
add('pv', 24, 28, 'Matthew Henry', 'We are here forbidden to be in any thing injurious to our neighbour, particularly in and by the forms of law, either, 1. As a witness: "Never bear a testimony against any man without cause, unless what thou sayest thou knowest to be punctually true and thou hast a clear call to testify it. Never bear a false testimony against any one;" for it follows, "Deceive not with thy lips; deceive not the judge and jury, deceive not those whom thou conversest with, into an ill opinion of thy neighbour. ...', 'teologico');
add('pv', 24, 30, 'Matthew Henry', 'Here is, 1. The view which Solomon took of the field and vineyard of the slothful man. He did not go on purpose to see it, but, as he passed by, observing the fruitfulness of the ground, as it is very proper for travellers to do, and his subjects\' management of their land, as it is very proper for magistrates to do, he cast his eye upon a field and a vineyard unlike all the rest; for, though the soil was good, yet there was nothing growing in them but thorns and nettles, not here and there on...', 'teologico');
add('pv', 25, 2, 'Matthew Henry', 'Here is, 1. An instance given of the honour of God: It is his glory to conceal a matter. He needs not search into any thing, for he perfectly knows every thing by a clear and certain view, and nothing can be hidden from him; and yet his own way is in the sea and his path in the great waters. There is an unfathomable depth in his counsels, Rom 11:33. It is but a little portion that is heard of him. Clouds and darkness are round about him. We see what he does, but we know not the reasons. Some ...', 'teologico');
add('pv', 25, 4, 'Matthew Henry', 'This shows that the vigorous endeavour of a prince to suppress vice, and reform the manners of his people, is the most effectual way to support his government. Observe, 1. what the duty of magistrates is: To take away the wicked, to use their power for the terror of evil works and evil workers, not only to banish those that are vicious and profane from their presence, and forbid them the court, but so to frighten them and restrain them that they may not spread the infection of their wickednes...', 'teologico');
add('pv', 25, 6, 'Matthew Henry', 'Here we see, 1. That religion is so far from destroying good manners that it reaches us to behave ourselves lowly and reverently towards our superiors, to keep our distance, and give place to those to whom it belongs "Put not forth thyself rudely and carelessly in the king\'s presence, or in the presence of great men; do not compare with them" (so some understand it); "do not vie with them in apparel, furniture, gardens, house-keeping, or retinue, for that is an affront to them and will waste ...', 'teologico');
add('pv', 25, 8, 'Matthew Henry', 'I. Here is good counsel given about going to law: - 1. "Be not hasty in bringing an action, before thou hast thyself considered it, and consulted with thy friends about it: Go not forth hastily to strive; do not send for a writ in a passion, or upon the first appearance of right on thy side, but weigh the matter deliberately, because we are apt to be partial in our own cause; consider the certainty of the expenses and the uncertainty of the success, how much care and vexation it will be the o...', 'teologico');
add('pv', 25, 11, 'Matthew Henry', 'Solomon here shows how much it becomes a man, 1. To speak pertinently: A word upon the wheels, that runs well, is well-circumstanced, in proper time and place - instruction, advice, or comfort, given seasonably, and in apt expressions, adapted to the case of the person spoken to and agreeing with the character of the person speaking - is like golden balls resembling apples, or like true apples of a golden colour (golden rennets), or perhaps gilded, as sometimes we have gilded laurels, and tho...', 'teologico');
add('pv', 25, 13, 'Matthew Henry', 'See here, 1. What ought to be the care of a servant, the meanest that is sent on an errand and entrusted with any business, much more the greatest, the agent and ambassador of a prince; he ought to be faithful to him that sends him, and to see to it that he do not, by mistake or with design, falsify his trust, and that he be in nothing that lies in his power wanting to his master\'s interest. Those that act as factors, by commission, ought to act as carefully as for themselves. 2. How much thi...', 'teologico');
add('pv', 25, 14, 'Matthew Henry', 'He may be said to boast of a false gift, 1. Who pretends to have received or given that which he never had, which he never gave, makes a noise of his great accomplishments and his good services, but it is all false; he is not what he pretends to be. Or, 2. Who promises what he will give and what he will do, but performs nothing, who raises people\'s expectations of the mighty things he will do for his country, for his friends, what noble legacies he will leave, but either he has not wherewitha...', 'teologico');
add('pv', 25, 15, 'Matthew Henry', 'Two things are here recommended to us, in dealing with others, as likely means to gain our point: - 1. Patience, to bear a present heat without being put into a heat by it, and to wait for a fit opportunity to offer our reasons and to give persons time to consider them. By this means even a prince may be persuaded to do a thing which he seemed very averse to, much more a common person. That which is justice and reason now will be so another time, and therefore we need not urge them with viole...', 'teologico');
add('pv', 25, 16, 'Matthew Henry', 'Here, 1. We are allowed a sober and moderate use of the delights of sense: Hast thou found honey? It is not forbidden fruit to thee, as it was to Jonathan; thou mayest eat of it with thanksgiving to God, who, having created things grateful to our senses, has given us leave to make use of them. Eat as much as is sufficient, and no more. Enough is as good as a feast. 2. We are cautioned to take heed of excess. We must use all pleasures as we do honey, with a check upon our appetite, lest we tak...', 'teologico');
add('pv', 25, 17, 'Matthew Henry', 'Here he mentions another pleasure which we must not take too much of, that of visiting our friends, the former for fear of surfeiting ourselves, this for fear of surfeiting our neighbour. 1. It is a piece of civility to visit our neighbours sometimes, to show our respect to them and concern for them, and to cultivate and improve mutual acquaintance and love, and that we may have both the satisfaction and advantage of their conversation. 2. It is wisdom, as well as good manners, not to be trou...', 'teologico');
add('pv', 25, 18, 'Matthew Henry', 'Here, 1. The sin condemned is bearing false witness against our neighbour, either in judgment or in common conversation, contrary to the law of the ninth commandment. 2. That which it is here condemned for is the mischievousness of it; it is in its power to ruin not only men\'s reputation, but their lives, estates, families, all that is dear to them. A false testimony is every thing that is dangerous; it is a maul (or club to knock a man\'s brains out with), a flail, which there is no fence aga...', 'teologico');
add('pv', 25, 19, 'Matthew Henry', '1. The confidence of an unfaithful man (so some read it) will be like a broken tooth; his policy, his power, his interest, all that which he trusted in to support him in his wickedness, will fail him in time of trouble, Psa 52:7. 2. Confidence in an unfaithful man (so we read it), in a man whom we thought trusty and therefore depended on, but who proves otherwise; it proves not only unserviceable, but painful and vexatious, like a broken tooth, or a foot out of joint, which, when we put any s...', 'teologico');
add('pv', 25, 20, 'Matthew Henry', '1. The absurdity here censured is singing songs to a heavy heart. Those that are in great sorrow are to be comforted by sympathizing with them, condoling with them, and concurring in their lamentation. If we take that method, the moving of our lips may assuage their grief (Job 16:5); but we take a wrong course with them if we think to relieve them by being merry with them, and endeavouring to make them merry; for it adds to their grief to see their friends so little concerned for them; it put...', 'teologico');
add('pv', 25, 21, 'Matthew Henry', 'By this it appears that, however the scribes and Pharisees had corrupted the law, not only the commandment of loving our brethren, but even that of loving our enemies, was not only a new, but also an old commandment, an Old Testament commandment, though our Saviour has given it to us with the new enforcement of his own great example in loving us when we were enemies. Observe, 1. How we must express our love to our enemies by the real offices of kindness, even those that are expensive to ourse...', 'teologico');
add('pv', 25, 23, 'Matthew Henry', 'Here see, 1. How we must discourage sin and witness against it, and particularly the sin of slandering and backbiting; we must frown upon it, and, by giving it an angry countenance, endeavour to put it out of countenance. Slanders would not be so readily spoken as they are if they were not readily heard; but good manners would silence the slanderer if he saw that his tales displeased the company. We should show ourselves uneasy if we heard a dear friend, whom we value, evil-spoken of; the sam...', 'teologico');
add('pv', 25, 24, 'Matthew Henry', 'This is the same with what he had said, Pro 21:9. Observe, 1. How those are to be pitied that are unequally yoked, especially with such as are brawling and contentious, whether husband or wife; for it is equally true of both. It is better to be alone than to be joined to one who, instead of being a meet-help, is a great hindrance to the comfort of life. 2. How those may sometimes be envied that live in solitude; as they want the comfort of society, so they are free from the vexation of it. An...', 'teologico');
add('pv', 25, 25, 'Matthew Henry', 'See here, 1. How natural it is to us to desire to hear good news from our friends, and concerning our affairs at a distance. It is sometimes with impatience that we expect to hear from abroad; our souls thirst after it. But we should check the inordinateness of that desire; if it be bad news, it will come too soon, if good, it will be welcome at any time. 2. How acceptable such good news will be when it does come, as refreshing as cold water to one that is thirsty. Solomon himself had much tr...', 'teologico');
add('pv', 25, 26, 'Matthew Henry', 'It is here represented as a very lamentable thing, and a public grievance, and of ill consequence to many, like the troubling of a fountain and the corrupting of a spring, for the righteous to fall down before the wicked, that is, 1. For the righteous to fall into sin in the sight of the wicked - for them to do any thing unbecoming their profession, which is told in Gath, and published in the streets of Ashkelon, and in which the daughters of the Philistines rejoice. For those that have been ...', 'teologico');
add('pv', 25, 27, 'Matthew Henry', 'I. Two things we must be graciously dead to: - 1. To the pleasures of sense, for it is not good to eat much honey; though it pleases the taste, and, if eaten with moderation, is very wholesome, yet, if eaten to excess, it becomes nauseous, creates bile, and is the occasion of many diseases. It is true of all the delights of the children of men that they will surfeit, but never satisfy, and they are dangerous to those that allow themselves the liberal use of them. 2. To the praise of man. We m...', 'teologico');
add('pv', 25, 28, 'Matthew Henry', 'Here is, 1. The good character of a wise and virtuous man implied. He is one that has rule over his own spirit; he maintains the government of himself, and of his own appetites and passions, and does not suffer them to rebel against reason and conscience. He has the rule of his own thoughts, his desires, his inclinations, his resentments, and keeps them all in good order. 2. The bad case of a vicious man, who has not this rule over his own spirit, who, when temptations to excess in eating or ...', 'teologico');
add('pv', 26, 2, 'Matthew Henry', 'Here is, 1. The folly of passion. It makes men scatter causeless curses, wishing ill to others upon presumption that they are bad and have done ill, when either they mistake the person or misunderstand the fact, or they call evil good and good evil. Give honour to a fool, and he thunders out his anathemas against all that he is disgusted with, right or wrong. Great men, when wicked, think they have a privilege to keep those about them in awe, by cursing them, and swearing at them, which yet i...', 'teologico');
add('pv', 26, 3, 'Matthew Henry', 'Here, 1. Wicked men are compared to the horse and the ass, so brutish are they, so unreasonable, so unruly, and not to be governed but by force or fear, so low has sin sunk men, so much below themselves. Man indeed is born like the wild ass\'s colt, but as some by the grace of God are changed, and become rational, so others by custom in sin are hardened, and become more and more sottish, as the horse and the mule, Psa 32:9. 2. Direction is given to use them accordingly. Princes, instead of giv...', 'teologico');
add('pv', 26, 4, 'Matthew Henry', 'See here the noble security of the scripture-style, which seems to contradict itself, but really does not. Wise men have need to be directed how to deal with fools; and they have never more need of wisdom than in dealing with such, to know when to keep silence and when to speak, for there may be a time for both. 1. In some cases a wise man will not set his wit to that of a fool so far as to answer him according to his folly "If he boast of himself, do not answer him by boasting of thyself. If...', 'teologico');
add('pv', 26, 6, 'Matthew Henry', 'To recommend wisdom to us, and to quicken us to the diligent use of all the means for the getting of wisdom, Solomon here shows that fools are fit for nothing; they are either sottish men, who will never think and design at all, or vicious men, who will never think and design well. 1. They are not fit to be entrusted with any business, not fit to go on an errand (Pro 26:6): He that does but send a message by the hand of a fool, of a careless heedless person, one who is so full of his jests an...', 'teologico');
add('pv', 26, 10, 'Matthew Henry', 'Our translation gives this verse a different reading in the text and in the margin; and accordingly it expresses either, 1. The equity of a good God. The Master, or Lord (so Rab signifies), or, as we read it, The great God that formed all things at first, and still governs them in infinite wisdom, renders to every man according to his work. He rewards the fool, who sinned through ignorance, who knew not his Lord\'s will, with few stripes; and he rewards the transgressor, who sinned presumptuou...', 'teologico');
add('pv', 26, 11, 'Matthew Henry', 'See here, 1. What an abominable thing sin is, and how hateful sometimes it is made to appear, even to the sinner himself. When his conscience is convinced, or he feels smart from his sin, he is sick of it, and vomits it up; he seems then to detest it and to be willing to part with it. It is in itself, and, first or last, will be to the sinner, more loathsome than the vomit of a dog, Psa 36:2. 2. How apt sinners are to relapse into it notwithstanding. As the dog, after he has gained ease by vo...', 'teologico');
add('pv', 26, 12, 'Matthew Henry', 'Here is, 1. A spiritual disease supposed, and that is self-conceit: Seest thou a man? Yes, we see many a one, wise in his own conceit, who has some little sense, but is proud of it, thinks it much more than it is, more than any of his neighbours, have, and enough, so that he needs no more, has such a conceit of his own abilities as makes him opinionative, dogmatical, and censorious; and all the use he makes of his knowledge is that it puffs him up. Or, if by a wise man we understand a religio...', 'teologico');
add('pv', 26, 13, 'Matthew Henry', 'When a man talks foolishly we say, He talks idly; for none betray their folly more than those who are idle and go about to excuse themselves in their idleness. As men\'s folly makes them slothful, so their slothfulness makes them foolish. Observe, 1. What the slothful man really dreads. He dreads the way, the streets, the place where work is to be done and a journey to be gone; he hates business, hates every thing that requires care and labour. 2. What he dreams of, and pretends to dread - a l...', 'teologico');
add('pv', 26, 14, 'Matthew Henry', 'Having seen the slothful man in fear of his work, here we find him in love with his ease; he lies in his bed on one side till he is weary of that, and then turns to the other, but still in his bed, when it is far in the day and work is to be done, as the door is moved, but not removed; and so his business is neglected and his opportunities are let slip. See the sluggard\'s character. 1. He is one that does not care to get out of his bed, but seems to be hung upon it, as the door upon the hinge...', 'teologico');
add('pv', 26, 15, 'Matthew Henry', 'The sluggard has now, with much ado, got out of his bed, but he might as well have lain there still for any thing he is likely to bring to pass in his work, so awkwardly does he go about it. Observe, 1. The pretence he makes for his slothfulness: He hides his hand in his bosom for fear of cold; next to his warm bed in his warm bosom. Or he pretends that he is lame, as some do that make a trade of begging; something ails his hand; he would have it thought that it is blistered with yesterday\'s ...', 'teologico');
add('pv', 26, 16, 'Matthew Henry', 'Observe, 1. The high opinion which the sluggard has of himself, notwithstanding the gross absurdity and folly of his slothfulness: He thinks himself wiser than seven men, than seven wise men, for they are such as can render a reason. It is the wisdom of a man to be able to render a reason, of a good man to be able to give a reason of the hope that is in him, Pe1 3:15. What we do we should be able to render a reason for, though perhaps we may not have wit enough to show the fallacy of every ob...', 'teologico');
add('pv', 26, 17, 'Matthew Henry', '1. That which is here condemned is meddling with strife that belongs not to us. If we must not be hasty to strive in our own cause (Pro 25:8), much less in other people\'s, especially theirs that we are no way related to or concerned in, but light on accidentally as we pass by. If we can be instrumental to make peace between those that are at variance we must do it, though we should thereby get the ill-will of both sides, at least while they are in their heat; but to make ourselves busy in oth...', 'teologico');
add('pv', 26, 18, 'Matthew Henry', 'See here, 1. How mischievous those are that make no scruple of deceiving their neighbours; they are as madmen that cast firebrands, arrows, and death, so much hurt may they do by their deceits. They value themselves upon it as polite cunning men, but really they are as madmen. There is not a greater madness in the world than a wilful sin. It is not only the passionate furious man, but the malicious deceitful man, that is a madman; he does in effect cast fire-brands, arrows, and death; he does...', 'teologico');
add('pv', 26, 20, 'Matthew Henry', 'Contention is as a fire; it heats the spirit, burns up all that is good, and puts families and societies into a flame. Now here we are told how that fire is commonly kindled and kept burning, that we may avoid the occasions of strife and so prevent the mischievous consequences of it. If then we would keep the peace, 1. We must not give ear to talebearers, for they feed the fire of contention with fuel; nay, they spread it with combustible matter; the tales they carry are fireballs. Those who ...', 'teologico');
add('pv', 26, 23, 'Matthew Henry', 'This may be meant either, 1. Of a wicked heart showing itself in burning lips, furious, passionate, outrageous words, burning in malice, and persecuting those to whom, or of whom, they are spoken; ill words and ill-will agree as well together as a potsherd and the dross of silver, which, now that the pot is broken and the dross separated from the silver, are fit to be thrown together to the dunghill. 2. Or of a wicked heart disguising itself with burning lips, burning with the professions of ...', 'teologico');
add('pv', 26, 24, 'Matthew Henry', 'There is cause to complain, not only of the want of sincerity in men\'s profession of friendship, and that they do not love so well as they pretend nor will serve their friends so much as they promise, but, which is much worse, of wicked designs in the profession of friendship, and the making of it subservient to the most malicious intentions. This is here spoken of as a common thing (Pro 26:24): He that hates his neighbour, and is contriving to do him a mischief, yet dissembles with his lips,...', 'teologico');
add('pv', 26, 27, 'Matthew Henry', 'See here, 1. What pains men take to do mischief to others. As they put a force upon themselves by concealing their design with a profession of friendship, so they put themselves to a great deal of labour to bring it about; it is digging a pit, it is rolling a stone, hard work, and yet men will not stick at it to gratify their passion and revenge. 2. What preparation they hereby make of mischief to themselves. Their violent dealing will return upon their own heads; they shall themselves fall i...', 'teologico');
add('pv', 26, 28, 'Matthew Henry', 'There are two sorts of lies equally detestable: - 1. A slandering lie, which avowedly hates those it is spoken of: A lying tongue hates those that are afflicted by it; it afflicts them by calumnies and reproaches because it hates them, and can thus smite them secretly where they are without defence; and it hates them because it has afflicted them and made them its enemies. The mischief of this is open and obvious; it afflicts, it hates, and owns it, and every body sees it. 2. A flattering lie...', 'teologico');
add('pv', 27, 2, 'Matthew Henry', 'Note, 1. We must do that which is commendable, for which even strangers may praise us. Our light must shine before men, and we must do good works that may be seen, though we must not do them on purpose that they may be seen. Let our own works be such as will praise us, even in the gates, Phi 4:8. 2. When we have done it we must not commend ourselves, for that is an evidence of pride, folly, and self-love, and a great lessening to a man\'s reputation. Every one will be forward to run him down t...', 'teologico');
add('pv', 27, 3, 'Matthew Henry', 'These two verses show the intolerable mischief, 1. Of ungoverned passion. The wrath of a fool, who when he is provoked cares not what he says and does, is more grievous than a great stone or a load of sand. It lies heavily upon himself. Those who have no command of their passions do themselves even sink under the load of them. The wrath of a fool lies heavily upon those he is enraged at, to whom, in his fury, he will be in danger of doing some mischief. It is therefore our wisdom not to give ...', 'teologico');
add('pv', 27, 5, 'Matthew Henry', 'Note, 1. It is good for us to be reproved, and told of our faults, by our friends. If true love in the heart has but zeal and courage enough to show itself in dealing plainly with our friends, and reproving them for what they say and do amiss, this is really better, not only than secret hatred (as Lev 19:17), but than secret love, that love to our neighbours which does not show itself in this good fruit, which compliments them in their sins, to the prejudice of their souls. Faithful are the r...', 'teologico');
add('pv', 27, 7, 'Matthew Henry', 'Solomon here, as often in this book, shows that the poor have in some respects the advantage of the rich; for, 1. They have a better relish of their enjoyments than the rich have. Hunger is the best sauce. Coarse fare, with a good appetite to it has a sensible pleasantness in it, which those are strangers to whose hearts are overcharged with surfeiting. Those that fare sumptuously every day nauseate even delicate food, as the Israelites did the quails; whereas those that have no more than the...', 'teologico');
add('pv', 27, 8, 'Matthew Henry', 'Note, 1. There are many that do not know when they are well off, but are uneasy with their present condition, and given to change. God, in his providence, has appointed them a place fit for them and has made it comfortable to them; but they affect unsettledness; they love to wander; they are glad of a pretence to go abroad, and do not care for staying long at a place; they needlessly absent themselves from their own work and care, and meddle with that which belongs not to them. 2. Those that ...', 'teologico');
add('pv', 27, 9, 'Matthew Henry', 'Here is, 1. A charge given to be faithful and constant to our friends, our old friends, to keep up an intimacy with them, and to be ready to do them all the offices that lie in our power. It is good to have a friend, a bosom-friend, whom we can be free with, and with whom we may communicate counsels. It is not necessary that this friend should be a relation, or any way akin to us, though it is happiest when, among those who are so, we find one fit to make a friend of. Peter and Andrew were br...', 'teologico');
add('pv', 27, 11, 'Matthew Henry', 'Children are here exhorted to be wise and good, 1. That they may be a comfort to their parents and may make their hearts glad, even when the evil days come, and so recompense them for their care, Pro 23:15. 2. That they may be a credit to them: "That I may answer him that reproaches me with having been over-strict and severe in bringing up my children, and having taken a wrong method with them in restraining them from the liberties which other young people take. My son, be wise, and then it w...', 'teologico');
add('pv', 27, 12, 'Matthew Henry', 'This we had before, Pro 22:3. Note, 1. Evil may be foreseen. Where there is temptation, it is easy to foresee that if we thrust ourselves into it there will be sin, and as easy to foresee that if we venture upon the evil of sin there will follow the evil of punishment; and, commonly, God warns before he wounds, having set watchmen over us, Jer 6:17. 2. It will be well or ill with us according as we do or do not improve the foresight we have of evil before us: The prudent man, foreseeing the e...', 'teologico');
add('pv', 27, 13, 'Matthew Henry', 'This also we had before, Pro 20:16. 1. It shows who those are that are hastening to poverty, those that have so little consideration as to be bound for every body that will ask them and those that are given to women. Such as these will take up money as far as ever their credit will go, but they will certainly cheat their creditors at last, nay, they are cheating them all along. An honest man may be made a beggar, but he is not honest that makes himself one. 2. It advises us to be so discreet ...', 'teologico');
add('pv', 27, 14, 'Matthew Henry', 'Note, 1. It is a great folly to be extravagant in praising even the best of our friends and benefactors. It is our duty to give every one his due praise, to applaud those who excel in knowledge, virtue, and usefulness, and to acknowledge the kindnesses we have received with thankfulness; but to do this with a loud voice, rising early in the morning, to be always harping on this string, in all companies, even to our friend\'s face, or so as that he may be sure to hear it, to do it studiously, a...', 'teologico');
add('pv', 27, 15, 'Matthew Henry', 'Here, as before, Solomon laments the case of him that has a peevish passionate wife, that is continually chiding, and making herself and all about her uneasy. 1. It is a grievance that there is no avoiding, for it is like a continual dropping in a very rainy day. The contentions of a neighbour may be like a sharp shower, troublesome for the time, yet, while it lasts, one may take shelter; but the contentions of a wife are like a constant soaking rain, for which there is no remedy but patience...', 'teologico');
add('pv', 27, 18, 'Matthew Henry', 'This is designed to encourage diligence, faithfulness, and constancy, even in mean employments. Though the calling be laborious and despicable, yet those who keep to it will find there is something to be got by it. 1. Let not a poor gardener, who keeps the fig-tree, be discouraged; though it require constant care and attendance to nurse up fig-trees, and, when they have grown to maturity, to keep them in good order, and gather the figs in their season, yet he shall be paid for his pains: He s...', 'teologico');
add('pv', 27, 19, 'Matthew Henry', 'This shows us that there is a way, 1. Of knowing ourselves. As the water is a looking-glass in which we may see our faces by reflection, so there are mirrors by which the heart of a man is discovered to a man, that is, to himself. Let a man examine his own conscience, his thoughts, affections, and intentions. Let him behold his natural face in the glass of the divine law (Jam 1:23), and he may discern what kind of man he is and what is his true character, which it will be of great use to ever...', 'teologico');
add('pv', 27, 20, 'Matthew Henry', 'Two things are here said to be insatiable, and they are two things near of kin - death and sin. 1. Death is insatiable. The first death, the second death, both are so. The grave is not clogged with the multitude of dead bodies that are daily thrown into it, but is still an open sepulchre, and cries, Give, give. Hell also has enlarged itself, and still has room for the damned spirits that are committed to that prison. Tophet is deep and large, Isa 30:33. 2. Sin is insatiable: The eyes of man a...', 'teologico');
add('pv', 27, 21, 'Matthew Henry', 'This gives us a touchstone by which we may try ourselves. Silver and gold are tried by putting them into the furnace and fining-pot; so is man tried by praising him. Let him be extolled and preferred, and then he will show himself what he is. 1. If a man be made, by the applause that is given him, proud, conceited, and scornful, - if he take the glory to himself which he should transmit to God, as Herod did, - if, the more he is praised, the more careless he is of what he says and does, - if ...', 'teologico');
add('pv', 27, 22, 'Matthew Henry', 'Solomon had said (Pro 22:15), The foolishness which is bound in the heart of a child may be driven out by the rod of correction, for then the mind is to be moulded, the vicious habits not having taken root; but here he shows that, if it be not done then, it will be next to impossible to do it afterwards; if the disease be inveterate, there is a danger of its being incurable. Can the Ethiopian change his skin? Observe, 1. Some are so bad that rough and severe methods must be used with them, af...', 'teologico');
add('pv', 27, 23, 'Matthew Henry', 'Here is, I. A command given us to be diligent in our callings. It is directed to husbandmen and shepherds, and those that deal in cattle, but it is to be extended to all other lawful callings; whatever our business is, within doors or without, we must apply our minds to it. This command intimates, 1. That we ought to have some business to do in this world and not to live in idleness. 2. We ought rightly and fully to understand our business, and know what we have to do, and not meddle with tha...', 'teologico');
add('pv', 28, 1, 'Matthew Henry', 'See here, 1. What continual frights those are subject to that go on in wicked ways. Guilt in the conscience makes men a terror to themselves, so that they are ready to flee when none pursues; like one that absconds for debt, who thinks every one he meets a bailiff. Though they pretend to be easy, there are secret fears which haunt them wherever they go, so that they fear where no present or imminent danger is, Psa 53:5. Those that have made God their enemy, and know it, cannot but see the who...', 'teologico');
add('pv', 28, 2, 'Matthew Henry', 'Note, 1. National sins bring national disorders and the disturbance of the public repose: For the transgression of a land, and a general defection from God and religion to idolatry, profaneness, or immorality, many are the princes thereof, many at the same time pretending to the sovereignty and contending for it, by which the people are crumbled into parties and factions, biting and devouring one another, or many successively, in a little time, one cutting off another, as Kg1 16:8, etc., or s...', 'teologico');
add('pv', 28, 3, 'Matthew Henry', 'See here, 1. How hard-hearted poor people frequently are to one another, not only not doing such good offices as they might do one to another, but imposing upon and over-reaching one another. Those who know by experience the miseries of poverty should be compassionate to those who suffer the like, but they are inexcusably barbarous if they be injurious to them. 2. How imperious and griping those commonly are who, being indigent and necessitous, get into power. If a prince prefer a poor man, h...', 'teologico');
add('pv', 28, 4, 'Matthew Henry', 'Note, 1. Those that praise the wicked make it to appear that they do themselves forsake the law, and go contrary to it, for that curses and condemns the wicked. Wicked people will speak well of one another, and so strengthen one another\'s hands in their wicked ways, hoping thereby to silence the clamours of their own consciences and to serve the interests of the devil\'s kingdom, which is not done by any thing so effectually as by keeping vice in reputation. 2. Those that do indeed make consci...', 'teologico');
add('pv', 28, 5, 'Matthew Henry', 'Note, I. As the prevalency of men\'s lusts is owing to the darkness of their understandings, so the darkness of their understandings is very much owing to the dominion of their lusts: Men understand not judgment, discern not between truth and falsehood, right and wrong; they understand not the law of God as the rule either of their duty or of their doom; and, 1. Therefore it is that they are evil men; their wickedness is the effect of their ignorance and error, Eph 4:18. 2. Therefore they unde...', 'teologico');
add('pv', 28, 6, 'Matthew Henry', 'Here, 1. It is supposed that a man may walk in his uprightness and yet be poor in this world, which is a temptation to dishonesty, and yet may resist the temptation and continue to walk in his uprightness - also that a man may be perverse in his ways, injurious to God and man, and yet be rich, and prosper in the world, for a while, may be rich, and so lie under great obligations and have great opportunities to do good, and yet be perverse in his ways and do a great deal of hurt. 2. It is main...', 'teologico');
add('pv', 28, 7, 'Matthew Henry', 'Note, 1. Religion is true wisdom, and it makes men wise in every relation. He that conscientiously keeps the law is wise, and he will be particularly a wise son, that is, will act discreetly towards his parents, for the law of God teaches him to do so. 2. Bad company is a great hindrance to religion. Those that are companions of riotous men, that choose such for their companions and delight in their conversation, will certainly be drawn from keeping the law of God and drawn to transgress it, ...', 'teologico');
add('pv', 28, 8, 'Matthew Henry', 'Note, 1. That which is ill-got, though it may increase much, will not last long. A man may perhaps raise a great estate, in a little time, by usury and extortion, fraud, and oppression of the poor, but it will not continue; he gathers it for himself, but it shall prove to have been gathered for somebody else that he has no kindness for. His estate shall go to decay, and another man\'s shall be raised out of the ruins of it. 2. Sometimes God in his providence so orders it that that which one go...', 'teologico');
add('pv', 28, 9, 'Matthew Henry', 'Note, 1. It is by the word and prayer that our communion with God is kept up. God speaks to us by his law, and expects we should hear him and heed him; we speak to him by prayer, to which we wait for an answer of peace. How reverent and serious should we be, whenever we are hearing from and speaking to the Lord of glory! 2. If God\'s word be not regarded by us, our prayers shall not only not be accepted of God, but they shall be an abomination to him, not only our sacrifices, which were ceremo...', 'teologico');
add('pv', 28, 10, 'Matthew Henry', 'Here is, 1. The doom of seducers, who attempt to draw good people, or those who profess to be such, into sin and mischief, who take pride in causing the righteous to go astray in an evil way, in drawing them into a snare, that they may insult over them. They shall not gain their point; it is impossible to deceive the elect. But they shall fall themselves into their own pit; and having been not only sinners, but tempters, not only unrighteous, but enemies to the righteous, their condemnation w...', 'teologico');
add('pv', 28, 11, 'Matthew Henry', 'Note, 1. Those that are rich are apt to think themselves wise, because, whatever else they are ignorant of, they know how to get and save; and those that are purse-proud expect that all they say should be regarded as an oracle and a law, and that none should dare to contradict them, but every sheaf bow to theirs; this humour is fed by flatterers, who, because (like Jezebel\'s prophets) they are fed at their table, cry up their wisdom. 2. Those that are poor often prove themselves wiser than th...', 'teologico');
add('pv', 28, 12, 'Matthew Henry', 'Note, 1. The comfort of the people of God is the honour of the nation in which they live. There is a great glory dwelling in the land when the righteous do rejoice, when they have their liberty, the free exercise of their religion, and are not persecuted, when the government countenances them and speaks comfortably to them, when they prosper and grow rich, and, much more, when they are preferred and employed and have power put into their hands. 2. The advancement of the wicked is the eclipsin...', 'teologico');
add('pv', 28, 13, 'Matthew Henry', 'Here is, 1. The folly of indulging sin, of palliating and excusing it, denying or extenuating it, diminishing it, dissembling it, or throwing the blame of it upon others: He that thus covers his sins shall not prosper, let him never expect it. He shall not succeed in his endeavour to cover his sin, for it will be discovered, sooner or later. There is nothing hid which shall not be revealed. A bird of the air shall carry the voice. Murder will out, and so will other sins. He shall not prosper,...', 'teologico');
add('pv', 28, 14, 'Matthew Henry', 'Here is, 1. The benefit of a holy caution. It sounds strangely, but it is very true: Happy is the man that feareth always. Most people think that those are happy who never fear; but there is a fear which is so far from having torment in it that it has in it the greatest satisfaction. Happy is the man who always keeps up in his mind a holy awe and reverence of God, his glory, goodness, and government, who is always afraid of offending God and incurring his displeasure, who keeps conscience ten...', 'teologico');
add('pv', 28, 15, 'Matthew Henry', 'It is written indeed, Thou shalt not speak evil of the ruler of thy people; but if he be a wicked ruler, that oppresses the people, especially the poor people, robbing them of the little they have and making a prey of them, whatever we may call him, this scripture calls him a roaring lion and a ranging bear. 1. In respect of his character. He is brutish, barbarous, and blood-thirsty; he is rather to be put among the beasts of prey, the wildest and most savage, than to be reckoned of that nobl...', 'teologico');
add('pv', 28, 16, 'Matthew Henry', 'Two things are here intimated to be the causes of the mal-administration of princes: - 1. The love of money, that root of all evil; for hating covetousness here stands opposed to oppression, according to Moses\'s character of good magistrates, men fearing God and hating covetousness (Exo 18:21), not only not being covetous, but hating it, and shaking the hands from the holding of bribes. A ruler that is covetous will neither do justly nor love mercy, but the people under him shall be bought an...', 'teologico');
add('pv', 28, 17, 'Matthew Henry', 'This agrees with that ancient law, Whoso sheddeth man\'s blood, by man shall his blood be shed (Gen 9:6), and proclaims, 1. The doom of the shedder of blood. He that has committed murder, though he flees for his life, shall be continually haunted with terrors, shall himself flee to the pit, betray himself, and torment himself, like Cain, who, when he had killed his brother, became a fugitive and a vagabond, and trembled continually. 2. The duty of the avenger of blood, whether the magistrate o...', 'teologico');
add('pv', 28, 18, 'Matthew Henry', 'Note, 1. Those that are honest are always safe. He that acts with sincerity, that speaks as he thinks, has a single eye, in every thing, to the glory of God and the good of his brethren, that would not, for a world, do an unjust thing if he knew it, that in all manner of conversation walks uprightly, he shall be saved hereafter. We find a glorious company of those in whose mouth was found no guile, Rev 14:5. They shall be safe now. Integrity and uprightness will preserve men, will give them a...', 'teologico');
add('pv', 28, 19, 'Matthew Henry', 'Note, 1. Those that are diligent in their callings take the way to live comfortably: He that tills his land, and tends his shop, and minds his business, whatever it is, he shall have plenty of bread, of that which is necessary for himself and his family and with which he may be charitable to the poor; he shall eat the labour of his hands. 2. Those that are idle, and careless, and company-keepers, though they indulge themselves in living (as they think) easily and pleasantly, they take the way...', 'teologico');
add('pv', 28, 20, 'Matthew Henry', 'Here, 1. We are directed in the true way to be happy, and that is to be holy and honest. He that is faithful to God and man shall be blessed of the Lord, and he shall abound with blessings of the upper and nether springs. Men shall praise him, and pray for him, and be ready to do him any kindness. He shall abound in doing good, and shall himself be a blessing to the place where he lives. Usefulness shall be the reward of faithfulness, and it is a good reward. 2. We are cautioned against a fal...', 'teologico');
add('pv', 28, 21, 'Matthew Henry', 'Note, 1. It is a fundamental error in the administration of justice, and that which cannot but lead men to abundance of transgression, to consider the parties concerned more than the merits of the cause, so as to favour one because he is a gentleman, a scholar, my countryman, my old acquaintance, has formerly done me a kindness, or may do me one, or is of my party and persuasion, and to bear hard on the other party because he is a stranger, a poor man, has done me an ill turn, is or has been ...', 'teologico');
add('pv', 28, 22, 'Matthew Henry', 'Here again Solomon shows the sin and folly of those that will be rich; they are resolved that they will be so, per fas, per nefas - right or wrong; they will be so with all speed; they are getting hastily an estate. 1. They have no comfort in it: They have an evil eye, that is, they are always grieving at those that have more than they, and always grudging their necessary expenses, because they think the former keep them from seeming rich, the latter from being so, and between both they must ...', 'teologico');
add('pv', 28, 23, 'Matthew Henry', 'Note, 1. Flatterers may please those for a time who, upon second thoughts, will detest and despise them. If ever they come to be convinced of the evil of those sinful courses they were flattered in, and to be ashamed of the pride and vanity which were humoured and gratified by those flatteries, they will hate the fawning flatterers as having had an ill design upon them, and the fulsome flatteries as having had an ill effect upon them and become nauseous. 2. Reprovers may displease those at fi...', 'teologico');
add('pv', 28, 24, 'Matthew Henry', 'As Christ shows the absurdity and wickedness of those children who think it is no duty, in some cases, to maintain their parents (Mat 15:5), so Solomon here shows the absurdity and wickedness of those who think it is no sin to rob their parents, either by force or secretly, by wheedling them or threatening them, or by wasting what they have, and (which is no better than robbing them) running into debt and leaving them to pay it. Now, 1. This is commonly made light of by untoward children; the...', 'teologico');
add('pv', 28, 25, 'Matthew Henry', 'Note, 1. Those make themselves lean, and continually unquiet, that are haughty and quarrelsome, for they are opposed to those that shall be made fat: He that is of a proud heart, that is conceited of himself and looks with a contempt upon all about him, that cannot bear either competition or contradiction, he stirs up strife, makes mischief, and creates disturbance to himself and every body else. 2. Those make themselves fat, and always easy, that live in a continual dependence upon God and h...', 'teologico');
add('pv', 28, 26, 'Matthew Henry', 'Here is, 1. The character of a fool: He trusts to his own heart, to his own wisdom and counsels, his own strength and sufficiency, his own merit and righteousness, and the good opinion he has of himself; he that does so is a fool, for he trusts to that, not only which is deceitful above all things (Jer 17:9), but which has often deceived him. This implies that it is the character of a wise man (as before, Pro 28:25) to put his trust in the Lord, and in his power and promise, and to follow his...', 'teologico');
add('pv', 28, 27, 'Matthew Henry', 'Here is, 1. A promise to the charitable: He that gives to the poor shall himself be never the poorer for so doing; he shall not lack. If he have but little, and so be in danger of lacking, let him give out of his little, and that will prevent it from coming to nothing; as the bounty of the widow of Sarepta to Elijah (for whom she made a little cake first) saved what she had, when it was reduced to a handful of meal. If he have much, let him give much out of it, and that will prevent its growi...', 'teologico');
add('pv', 28, 28, 'Matthew Henry', 'This is to the same purport with what we had, Pro 28:12. 1. When bad men are preferred, that which is good is clouded and run down. When power is put into the hands of the wicked, men hide themselves; wise men retire into privacy, and decline public business, not caring to be employed under them; rich men get out of the way, for fear of being squeezed for what they have; and, which is worst of all, good men abscond, despairing to do good and fearing to be persecuted and ill-treated. 2. When b...', 'teologico');
add('pv', 29, 2, 'Matthew Henry', 'This is what was said before, Pro 28:12, Pro 28:28. 1. The people will have cause to rejoice or mourn according as their rulers are righteous or wicked; for, if the righteous be in authority, sin will be punished and restrained, religion and virtue will be supported and kept in reputation; but, if the wicked get power in their hands, wickedness will abound, religion and religious people will be persecuted, and so the ends of government will be perverted. 2. The people will actually rejoice or...', 'teologico');
add('pv', 29, 3, 'Matthew Henry', 'Both the parts of this verse repeat what has been often said, but, on comparing them together, the sense of them will be enlarged from each other. 1. Be it observed, to the honour of a virtuous young man, that he loves wisdom, he is a philosopher (for that signifies a lover of wisdom), for religion is the best philosophy; he avoids bad company, and especially the company of lewd women. Hereby he rejoices his parents, and has the satisfaction of being a comfort to them, and increases his estat...', 'teologico');
add('pv', 29, 4, 'Matthew Henry', 'Here is, 1. The happiness of a people under a good government. The care and business of a prince should be to establish the land, to maintain its fundamental laws, to settle the minds of his subjects and make them easy, to secure their liberties and properties from hostilities and for posterity, and to set in order the things that are wanting; this he must do by judgment, by wise counsels, and by the steady administration of justice, without respect of persons, which will have these good effe...', 'teologico');
add('pv', 29, 5, 'Matthew Henry', 'Those may be said to flatter their neighbours who commend and applaud that good in them (the good they do or the good they have) which really either is not or is not such as they represent it, and who profess that esteem and that affection for them which really they have not; these spread a net for their feet. 1. For their neighbours\' feet, whom they flatter. They have an ill design in it; they would not praise them as they do but that they hope to make an advantage of them; and it is therefo...', 'teologico');
add('pv', 29, 6, 'Matthew Henry', 'Here is, 1. The peril of a sinful way. There is not only a punishment at the end of it, but a snare in it. One sin is a temptation to another, and there are troubles which, as a snare, come suddenly upon evil men in the midst of their transgressions; nay, their transgression itself often involves them in vexations; their sin is their punishment, and they are holden in the cords of their own iniquity, Pro 5:22. 2. The pleasantness of the way of holiness. The snare that is in the transgression ...', 'teologico');
add('pv', 29, 7, 'Matthew Henry', 'It is a pity but that every one who sues sub form pauperis - as a pauper, should have an honest cause (they are of all others inexcusable if they have not), because the scripture has so well provided that it should have a fair hearing, and that the judge himself should be of counsel, as for the prisoner, so for the pauper. 1. It is here made the character of a righteous judge that he considers the cause of the poor. It is every man\'s duty to consider the poor (Psa 41:1), but the judgment of t...', 'teologico');
add('pv', 29, 8, 'Matthew Henry', 'See here, 1. Who are the men that are dangerous to the public - scornful men. When such are employed in the business of the state they do things with precipitation, because they scorn to deliberate, and will not take time for consideration and consultation; they do things illegal and unjustifiable, because they scorn to be hampered by laws and constitutions; they break their faith, because they scorn to be bound by their word, and provoke the people, because they scorn to please them. Thus th...', 'teologico');
add('pv', 29, 9, 'Matthew Henry', 'A wise man is here advised not to set his wit to a fool\'s, not to dispute with him, or by contending with him to think either of fastening reason upon him or gaining right from him: If a wise man contend with a wise man, he may hope to be understood, and, as far as he has reason and equity on his side, to carry his point, at least to bring the controversy to a head and make it issue amicably; but, if he contend with a foolish man, there is no rest; he will see no end of it, nor will he have a...', 'teologico');
add('pv', 29, 10, 'Matthew Henry', 'Note, 1. Bad men hate their best friends: The blood-thirsty, all the seed of the old serpent, who was a murderer from the beginning, all that inherit his enmity against the seed of the woman, hate the upright; they seek the ruin of good men because they condemn the wicked world and witness against it. Christ told his disciples that they should be hated of all men. Bloody men do especially hate upright magistrates, who would restrain and reform them, and put the laws in execution against them,...', 'teologico');
add('pv', 29, 11, 'Matthew Henry', 'Note, 1. It is a piece of weakness to be very open: He is a fool who utters all his mind, - who tells every thing he knows, and has in his mouth instantly whatever he has in his thoughts, and can keep no counsel, - who, whatever is started in discourse, quickly shoots his bolt, - who, when he is provoked, will say any thing that comes uppermost, whoever is reflected upon by it, - who, when he is to speak of any business, will say all he thinks, and yet never thinks he says enough, whether cho...', 'teologico');
add('pv', 29, 12, 'Matthew Henry', 'Note, 1. It is a great sin in any, especially in rulers, to hearken to lies; for thereby they not only give a wrong judgment themselves of persons and things, according to the lies they give credit to, but they encourage others to give wrong informations. Lies will be told to those that will hearken to them; but the receiver, in this case, is as bad as the thief. 2. Those that do so will have all their servants wicked. All their servants will appear wicked, for they will have lies told of the...', 'teologico');
add('pv', 29, 13, 'Matthew Henry', 'This shows how wisely the great God serves the designs of his providence by persons of very different tempers, capacities, and conditions in the world, even, 1. By those that are contrary the one to the other. Some are poor and forced to borrow; others are rich, have a great deal of the mammon of unrighteousness (deceitful riches they are called), and they are creditors, or usurers, as it is in the margin. Some are poor, and honest, and laborious; others are rich, slothful, and deceitful. The...', 'teologico');
add('pv', 29, 14, 'Matthew Henry', 'Here is, 1. The duty of magistrates, and that is, to judge faithfully between man and man, and to determine all causes brought before them, according to truth and equity, particularly to take care of the poor, not to countenance them in an unjust cause for the sake of their poverty (Exo 23:3), but to see that their poverty do not turn to their prejudice if they have a just cause. The rich will look to themselves, but the poor and needy the prince must defend (Psa 82:3) and plead for, Pro 31:9...', 'teologico');
add('pv', 29, 15, 'Matthew Henry', 'Parents, in educating their children, must consider, 1. The benefit of due correction. They must not only tell their children what is good and evil, but they must chide them, and correct them too, if need be, when they either neglect that which is good or do that which is evil. If a reproof will serve without the rod, it is well, but the rod must never be used without a rational and grave reproof; and then, though it may be a present uneasiness both to the father and to the child, yet it will...', 'teologico');
add('pv', 29, 16, 'Matthew Henry', 'Note, 1. The more sinners there are the more sin there is: When the wicked, being countenanced by authority, grow numerous, and walk on every side, no marvel if transgression increases, as a plague in the country is said to increase when still more and more are infected with it. Transgression grows more impudent and bold, more imperious and threatening, when there are many to keep it in countenance. In the old world, when men began to multiply, they began to degenerate and corrupt themselves ...', 'teologico');
add('pv', 29, 17, 'Matthew Henry', 'Note, 1. It is a very happy thing when children prove the comfort of their parents. Good children are so; they give them rest, make them easy, and free from the many cares they have had concerning them; yea, they give delight unto their souls. It is a pleasure to parents, which none know but those that are blessed with it, to see the happy fruit of the good education they have given their children, and to have a prospect of their well-doing for both worlds; it gives delight proportionable to ...', 'teologico');
add('pv', 29, 18, 'Matthew Henry', 'See here, I. The misery of the people that want a settled ministry: Where there is no vision, no prophet to expound the law, no priest or Levite to teach the good knowledge of the Lord, no means of grace, the word of the Lord is scarce, there is no open vision (Sa1 3:1), where it is so the people perish; the word has many significations, any of which will apply here. 1. The people are made naked, stripped of their ornaments and so exposed to shame, stripped of their armour and so exposed to d...', 'teologico');
add('pv', 29, 19, 'Matthew Henry', 'Here is the description of an unprofitable, slothful, wicked servant, a slave that serves not from conscience, or love, but purely from fear. Let those that have such servants put on patience to bear the vexation and not disturb themselves at it. See their character. 1. No rational words will work upon them; they will not be corrected and reformed, not brought to their business, nor cured of their idleness and laziness, by fair means, no, nor by foul words; even the most gentle master will be...', 'teologico');
add('pv', 29, 20, 'Matthew Henry', 'Solomon here shows that there is little hope of bringing a man to wisdom that is hasty either, 1. Through rashness and inconsideration: Seest thou a man that is hasty in his matters, that is of a light desultory wit, that seems to take a thing quickly, but takes it by the halves, gallops over a book or science, but takes no time to digest it, no time to pause or muse upon a business? There is more hope of making a scholar and a wise man of one that is dull and heavy, and slow in his studies, ...', 'teologico');
add('pv', 29, 21, 'Matthew Henry', 'Note, 1. It is an imprudent thing in a master to be too fond of a servant, to advance him too fast, and admit him to be too familiar with him, to suffer him to be over-nice and curious in his diet, and clothing, and lodging, and so to bring him up delicately, because he is a favourite, and an agreeable servant; it should be remembered that he is a servant, and, by being thus indulged, will be spoiled for any other place. Servants must endure hardness. 2. It is an ungrateful thing in a servant...', 'teologico');
add('pv', 29, 22, 'Matthew Henry', 'See here the mischief that flows from an angry, passionate, furious disposition. 1. It makes men provoking to one another: An angry man stirs up strife, is troublesome and quarrelsome in the family and in the neighbourhood, blows the coals, and even forces those to fall out with him that would live peaceable and quietly by him. 2. It makes men provoking to God: A furious man, who is wedded to his humours and passions, cannot but abound in transgressions. Undue anger is a sin which is the caus...', 'teologico');
add('pv', 29, 23, 'Matthew Henry', 'This agrees with what Christ said more than once, 1. That those who exalt themselves shall be abased. Those that think to gain respect by lifting up themselves above their rank, by looking high, talking big, appearing fine, and applauding themselves, will on the contrary expose themselves to contempt, lose their reputation, and provoke God by humbling providences to bring them down and lay them low. 2. That those who humble themselves shall be exalted, and shall be established in their dignit...', 'teologico');
add('pv', 29, 24, 'Matthew Henry', 'See here what sin and ruin those involve themselves in who are drawn away by the enticement of sinners. 1. They incur a great deal of guilt: He does so that goes partner with such as rob and defraud, and casts in his lot among them, Pro 1:11, etc. The receiver is as bad as the thief; and, being drawn in to join with him in the commission of the sin, he cannot escape joining with him in the concealment of it, though it be with the most horrid perjuries and execrations. They hear cursing when t...', 'teologico');
add('pv', 29, 25, 'Matthew Henry', 'Here, 1. We are cautioned not to dread the power of man, neither the power of a prince nor the power of the multitude; both are formidable enough, but the slavish fear of either brings a snare, that is, exposes men to many insults (some take a pride in terrifying the timorous), or rather exposes men to many temptations. Abraham, for fear of man, denied his wife, and Peter his Master, and many a one his God and religion. We must not shrink from duty, nor commit sin, to avoid the wrath of man, ...', 'teologico');
add('pv', 29, 26, 'Matthew Henry', 'See here, 1. What is the common course men take to advance and enrich themselves, and make themselves great: they seek the ruler\'s favour, and, as if all their judgment proceeded from him, to him they make all their court. Solomon was himself a ruler, and knew with what sedulity men made their application to him, some on one errand, others on another, but all for his favour. It is the way of the world to make interest with great men, and expect much from the smiles of second causes, which yet...', 'teologico');
add('pv', 29, 27, 'Matthew Henry', 'This expresses not only the innate contrariety that there is between virtue and vice, as between light and darkness, fire and water, but the old enmity that has always been between the seed of the woman and the seed of the serpent, Gen 3:15. 1. All that are sanctified have a rooted antipathy to wickedness and wicked people. They have a good will to the souls of all (God has, and would have none perish); but they hate the ways and practices of those that are impious towards God and injurious t...', 'teologico');
add('pv', 30, 1, 'Matthew Henry', 'Some make Agur to be not the name of this author, but his character; he was a collector (so it signifies), a gatherer, one that did not compose things himself, but collected the wise sayings and observations of others, made abstracts of the writings of others, which some think is the reason why he says (Pro 30:3), "I have not learned wisdom myself, but have been a scribe, or amanuensis, to other wise and learned men." Note, We must not bury our talent, though it be but one, but, as we have re...', 'teologico');
add('pv', 30, 7, 'Matthew Henry', 'After Agur\'s confession and creed, here follows his litany, where we may observe,\nI. The preface to his prayer: Two things have I required (that is, requested) of thee, O God! Before we go to pray it is good to consider what we need, and what the things are which we have to ask of God. - What does our case require? What do our hearts desire? What would we that God should do for us? - that we may not have to seek for our petition and request when we should be presenting it. He begs, Deny me no...', 'teologico');
add('pv', 30, 10, 'Matthew Henry', 'Here is, I. A caution not to abuse other people\'s servants any more than our own, nor to make mischief between them and their masters, for it is an ill office, invidious, and what will make a man odious, Pro 30:10. Consider, 1. It is an injury to the servant, whose poor condition makes him an object of pity, and therefore it is barbarous to add affliction to him that is afflicted: Hurt not a servant with thy tongue (so the margin reads it); for it argues a sordid disposition to smite any body...', 'teologico');
add('pv', 30, 15, 'Matthew Henry', 'He had spoken before of those that devoured the poor (Pro 30:14), and had spoken of them last, as the worst of all the four generations there mentioned; now here he speaks of their insatiableness in doing this. The temper that puts them upon it is made up of cruelty and covetousness. Now those are two daughters of the horse-leech, its genuine offspring, that still cry, "Give, give, give more blood, give more money;" for the bloody are still blood-thirsty; being drunk with blood, they add thir...', 'teologico');
add('pv', 30, 18, 'Matthew Henry', 'Here is, I. An account of four things that are unsearchable, too wonderful to be fully known. And here,\n1. The first three are natural things, and are only designed as comparisons for the illustration of the last. We cannot trace, (1.) An eagle in the air. Which way she has flown cannot be discovered either by the footstep or by the scent, as the way of a beast may upon ground; nor can we account for the wonderful swiftness of her flight, how soon she has gone beyond our ken. (2.) A serpent u...', 'teologico');
add('pv', 30, 24, 'Matthew Henry', 'I. Agur, having specified four things that seem great and yet are really contemptible, here specifies four things that are little and yet are very admirable, great in miniature, in which, as bishop Patrick observes, he teaches us several good lessons; as, 1. Not to admire bodily bulk, or beauty, or strength, nor to value persons or think the better of them for such advantages, but to judge of men by their wisdom and conduct, their industry and application to business, which are characters tha...', 'teologico');
add('pv', 30, 29, 'Matthew Henry', 'Here is, I. An enumeration of four things which are majestic and stately in their going, which look great: - 1. A lion, the king of beasts, because strongest among beasts. Among beasts it is strength that gives the pre-eminence, but it is a pity that it should do so among men, whose wisdom is their honour, not their strength and force. The lion turns not away, nor alters his pace, for fear of any pursuers, since he knows he is too hard for them. Herein the righteous are bold as a lion, that t...', 'teologico');
add('pv', 31, 1, 'Matthew Henry', 'Most interpreters are of opinion that Lemuel is Solomon; the name signifies one that is for God, or devoted to God; and so it agrees well enough with that honourable name which, by divine appointment, was given to Solomon (Sa2 12:25), Jedediah - beloved of the Lord. Lemuel is supposed to be a pretty, fond, endearing name, by which his mother used to call him; and so much did he value himself upon the interest he had in his mother\'s affections that he was not ashamed to call himself by it. One...', 'teologico');

// EC (42 comentários)
add('ec', 3, 1, 'Calvino', 'Para tudo há um tempo — A soberania de Deus sobre os tempos e estações da vida humana.', 'teologico');
add('ec', 3, 11, 'N.T. Wright', 'Deus fez tudo formoso — O anseio por eternidade aponta para a nova criação prometida.', 'escatologico');
add('ec', 1, 1, 'Matthew Henry', 'Here is, I. An account of the penman of this book; it was Solomon, for no other son of David was king of Jerusalem; but he conceals his name Solomon, peaceable, because by his sin he had brought trouble upon himself and his kingdom, had broken his peace with God and lost the peace of his conscience, and therefore was no more worthy of that name. Call me not Solomon, call me Marah, for, behold, for peace I had great bitterness. But he calls himself,\n1. The preacher, which intimates his present...', 'teologico');
add('ec', 1, 4, 'Matthew Henry', 'To prove the vanity of all things under the sun, and their insufficiency to make us happy, Solomon here shows, 1. That the time of our enjoyment of these things is very short, and only while we accomplish as a hireling his day. We continue in the world but for one generation, which is continually passing away to make room for another, and we are passing with it. Our worldly possessions we very lately had from others, and must very shortly leave to others, and therefore to us they are vanity; ...', 'teologico');
add('ec', 1, 9, 'Matthew Henry', 'Two things we are apt to take a great deal of pleasure and satisfaction in, and value ourselves upon, with reference to our business and enjoyments in the world, as if they helped to save them from vanity. Solomon shows us our mistake in both.\n1. The novelty of the invention, that it is such as was never known before. How grateful is it to think that none ever made such advances in knowledge, and such discoveries by it, as we, that none ever made such improvements of an estate or trade, and h...', 'teologico');
add('ec', 1, 12, 'Matthew Henry', 'Solomon, having asserted in general that all is vanity, and having given some general proofs of it, now takes the most effectual method to evince the truth of it, 1. By his own experience; he tried them all, and found them vanity. 2. By an induction of particulars; and here he begins with that which bids fairest of all to be the happiness of a reasonable creature, and that is knowledge and learning; if this be vanity, every thing else must needs be so. Now as to this,\nI. Solomon tells us here...', 'teologico');
add('ec', 2, 1, 'Matthew Henry', 'Solomon here, in pursuit of the summum bonum - the felicity of man, adjourns out of his study, his library, his elaboratory, his council-chamber, where he had in vain sought for it, into the park and the playhouse, his garden and his summer-house; he exchanges the company of the philosophers and grave senators for that of the wits and gallants, and the beaux-esprits, of his court, to try if he could find true satisfaction and happiness among them. Here he takes a great step downward, from the...', 'teologico');
add('ec', 2, 12, 'Matthew Henry', 'Solomon having tried what satisfaction was to be had in learning first, and then in the pleasures of sense, and having also put both together, here compares them one with another and passes a judgment upon them.\nI. He sets himself to consider both wisdom and folly. He had considered these before (Ecc 1:17); but lest it should be thought he was then too quick in passing a judgment upon them, he here turns himself again to behold them, to see if, upon a second view and second thoughts, he could...', 'teologico');
add('ec', 2, 17, 'Matthew Henry', 'Business is a thing that wise men have pleasure in. They are in their element when they are in their business, and complain if they be out of business. They may sometimes be tired with their business, but they are not weary of it, nor willing to leave it off. Here therefore one would expect to have found the good that men should do, but Solomon tried this too; after a contemplative life and a voluptuous life, he betook himself to an active life, and found no more satisfaction in it than in th...', 'teologico');
add('ec', 3, 16, 'Matthew Henry', 'Solomon is still showing that every thing in this world, without piety and the fear of God, is vanity. Take away religion, and there is nothing valuable among men, nothing for the sake of which a wise man would think it worth while to live in this world. In these verses he shows that power (than which there is nothing men are more ambitious of) and life itself (than which there is nothing men are more fond, more jealous of) are nothing without the fear of God.\nI. Here is the vanity of man as ...', 'teologico');
add('ec', 4, 1, 'Matthew Henry', 'Solomon had a large soul (Kg1 4:29) and it appeared by this, among other things, that he had a very tender concern for the miserable part of mankind and took cognizance of the afflictions of the afflicted. He had taken the oppressors to task (Ecc 3:16, Ecc 3:17) and put them in mind of the judgment to come, to be a curb to their insolence; now here he observes the oppressed. This he did, no doubt, as a prince, to do them justice and avenge them of their adversaries, for he both feared God and...', 'teologico');
add('ec', 4, 4, 'Matthew Henry', 'Here Solomon returns to the observation and consideration of the vanity and vexation of spirit that attend the business of this world, which he had spoken of before, Ecc 2:11.\nI. If a man be acute, and dexterous, and successful in his business, he gets the ill-will of his neighbours, Ecc 4:4. Though he takes a great deal of pains, and goes through all travail, does not get his estate easily, but it costs him a great deal of hard labour, nor does he get it dishonestly, he wrongs no man, defrau...', 'teologico');
add('ec', 4, 7, 'Matthew Henry', 'Here Solomon fastens upon another instance of the vanity of this world, that frequently the more men have of it the more they would have; and on this they are so intent that they have no enjoyment of what they have. Now Solomon here shows,\nI. That selfishness is the cause of this evil (Ecc 4:7, Ecc 4:8): There is one alone, that minds none but himself, cares for nobody, but would, if he could, be placed alone in the midst of the earth; there is not a second, nor does he desire there should be...', 'teologico');
add('ec', 4, 13, 'Matthew Henry', 'Solomon was himself a king, and therefore may be allowed to speak more freely than another concerning the vanity of kingly state and dignity, which he shows here to be an uncertain thing; he had before said so (Pro 27:24, The crown doth not endure to every generation), and his son found it so. Nothing is more slippery than the highest post of honour without wisdom and the people\'s love.\nI. A king is not happy unless he have wisdom, Ecc 4:13, Ecc 4:14. He that is truly wise, prudent, and pious...', 'teologico');
add('ec', 5, 1, 'Matthew Henry', 'Solomon\'s design, in driving us off from the world, by showing us its vanity, is to drive us to God and to our duty, that we may not walk in the way of the world, but by religious rules, nor depend upon the wealth of the world, but on religious advantages; and therefore,\nI. He here sends us to the house of God, to the place of public worship, to the temple, which he himself had built at a vast expense. When he reflected with regret on all his other works (Ecc 2:4), he did not repent of that, ...', 'teologico');
add('ec', 5, 4, 'Matthew Henry', 'Four things we are exhorted to in these verses: - \nI. To be conscientious in paying our vows.\n1. A vow is a bond upon the soul (Num 30:2), by which we solemnly oblige ourselves, not only, in general, to do that which we are already bound to do, but, in some particular instances, to do that to do which we were not under any antecedent obligation, whether it respects honouring God or serving the interests of his kingdom among men. When, under the sense of some affliction (Psa 66:14), or in the ...', 'teologico');
add('ec', 5, 9, 'Matthew Henry', 'Solomon had shown the vanity of pleasure, gaiety, and fine works, of honour, power, and royal dignity; and there is many a covetous worldling that will agree with him, and speak as slightly as he does of these things; but money, he thinks, is a substantial thing, and if he can but have enough of that he is happy. This is the mistake which Solomon attacks, and attempts to rectify, in these verses; he shows that there is as much vanity in great riches, and the lust of the eye about them, as the...', 'teologico');
add('ec', 5, 18, 'Matthew Henry', 'Solomon, from the vanity of riches hoarded up, here infers that the best course we can take is to use well what we have, to serve God with it, to do good with it, and take the comfort of it to ourselves and our families; this he had pressed before, Ecc 2:24; Ecc 3:22. Observe, 1. What it is that is here recommended to us, not to indulge the appetites of the flesh, or to take up with present pleasures or profits for our portion, but soberly and moderately to make use of what Providence has all...', 'teologico');
add('ec', 6, 1, 'Matthew Henry', 'Solomon had shown, in the close of the foregoing chapter, how good it is to make a comfortable use of the gifts of God\'s providence; now here he shows the evil of the contrary, having and not using, gathering to lay up for I know not what contingent emergencies to come, not to lay out on the most urgent occasions present. This is an evil which Solomon himself saw under the sun, Ecc 6:1. A great deal of evil there is under the sun. There is a world above the sun where there is no evil, yet God...', 'teologico');
add('ec', 6, 7, 'Matthew Henry', 'The preacher here further shows the vanity and folly of heaping up worldly wealth and expecting happiness in it.\nI. How much soever we toil about the world, and get out of it, we can have for ourselves no more than a maintenance (Ecc 6:7): All the labour of man is for his mouth, which craves it of him (Pro 16:26); it is but food and raiment; what is more others have, not we; it is all for the mouth. Meats are but for the belly and the belly for meats; there is nothing for the head and heart, ...', 'teologico');
add('ec', 6, 11, 'Matthew Henry', 'Here, 1. Solomon lays down his conclusion which he had undertaken to prove, as that which was fully confirmed by the foregoing discourse: There be many things that increase vanity; the life of man is vain, at the best, and there are abundance of accidents that concur to make it more so; even that which pretends to increase the vanity and make it more vexatious. 2. He draws some inferences from it, which serve further to evince the truth of it. (1.) That a man is never the nearer to true happi...', 'teologico');
add('ec', 7, 1, 'Matthew Henry', 'In these verses Solomon lays down some great truths which seem paradoxes to the unthinking part, that is, the far greatest part, of mankind.\nI. That the honour of virtue is really more valuable and desirable than all the wealth and pleasure in this world (Ecc 7:1): A good name is before good ointment (so it may be read); it is preferable to it, and will be rather chosen by all that are wise. Good ointment is here put for all the profits of the earth (among the products of which oil was reckon...', 'teologico');
add('ec', 7, 7, 'Matthew Henry', 'Solomon had often complained before of the oppressions which he saw under the sun, which gave occasion for many melancholy speculations and were a great discouragement to virtue and piety. Now here,\nI. He grants the temptation to be strong (Ecc 7:7): Surely it is often too true that oppression makes a wise man mad. If a wise man be much and long oppressed, he is very apt to speak and act unlike himself, to lay the reins on the neck of his passions, and break out into indecent complaints again...', 'teologico');
add('ec', 7, 11, 'Matthew Henry', 'Solomon, in these verses, recommends wisdom to us as the best antidote against those distempers of mind which we are liable to, by reason of the vanity and vexation of spirit that there are in the things of this world. Here are some of the praises and the precepts of wisdom.\nI. The praises of wisdom. Many things are here said in its commendation, to engage us to get and retain wisdom. 1. Wisdom is necessary to the right managing and improving of our worldly possessions: Wisdom is good with an...', 'teologico');
add('ec', 7, 23, 'Matthew Henry', 'Solomon had hitherto been proving the vanity of the world and its utter insufficiency to make men happy; now here he comes to show the vileness of sin, and its certain tendency to make men miserable; and this, as the former, he proves from his own experience, and it was a dear-bought experience. He is here, more than any where in all this book, putting on the habit of a penitent. He reviews what he had been discoursing of already, and tells us that what he had said was what he knew and was we...', 'teologico');
add('ec', 8, 1, 'Matthew Henry', 'Here is, I. An encomium of wisdom (Ecc 8:1), that is, of true piety, guided in all its exercises by prudence and discretion. The wise man is the good man, that knows God and glorifies him, knows himself and does well for himself; his wisdom is a great happiness to him, for, 1. It advances him above his neighbours, and makes him more excellent than they: Who is as the wise man? Note, Heavenly wisdom will make a man an incomparable man. No man without grace, though he be learned, or noble, or r...', 'teologico');
add('ec', 8, 6, 'Matthew Henry', 'Solomon had said (Ecc 8:5) that a wise man\'s heart discerns time and judgment, that is, a man\'s wisdom will go a great way, by the blessing of God, in moral prognostications; but here he shows that few have that wisdom, and that even the wisest may yet be surprised by a calamity which they had not any foresight of, and therefore it is our wisdom to expect and prepare for sudden changes. Observe, 1. All the events concerning us, with the exact time of them, are determined and appointed in the ...', 'teologico');
add('ec', 8, 9, 'Matthew Henry', 'Solomon, in the beginning of the chapter, had warned us against having any thing to do with seditious subjects; here, in these verses, he encourages us, in reference to the mischief of tyrannical and oppressive rulers, such as he had complained of before, Ecc 3:16; Ecc 4:1.\n1. He had observed many such rulers, Ecc 8:9. In the serious views and reviews he had taken of the children of men and their state he had observed that many a time one man rules over another to his hurt; that is, (1.) To t...', 'teologico');
add('ec', 8, 14, 'Matthew Henry', 'Wise and good men have, of old, been perplexed with this difficulty, how the prosperity of the wicked and the troubles of the righteous can be reconciled with the holiness and goodness of the God that governs the world. Concerning this Solomon here gives us his advice.\nI. He would not have us to be surprised at it, as though some strange thing happened, for he himself saw it in his days, Ecc 8:14. 1. He saw just men to whom it happened according to the work of the wicked, who, notwithstanding...', 'teologico');
add('ec', 9, 1, 'Matthew Henry', 'It has been observed concerning those who have pretended to search for the philosophers\' stone that, though they could never find what they sought for, yet in the search they have hit upon many other useful discoveries and experiments. Thus Solomon, when, in the close of the foregoing chapter, he applied his heart to know the work of God, and took a great deal of pains to search into it, though he despaired of finding it out, yet he found out that which abundantly recompensed him for the sear...', 'teologico');
add('ec', 9, 4, 'Matthew Henry', 'Solomon, in a fret, had praised the dead more than the living (Ecc 4:2); but here, considering the advantages of life to prepare for death and make sure the hope of a better life, he seems to be of another mind.\nI. He shows the advantages which the living have above those that are dead, Ecc 9:4-6. 1. While there is life there is hope. Dum spiro, spero - While I breathe, I hope. It is the privilege of the living that they are joined to the living, in relation, commerce, and conversation, and, ...', 'teologico');
add('ec', 9, 11, 'Matthew Henry', 'The preacher here, for a further proof of the vanity of the world, and to convince us that all our works are in the hand of God, and not in our own hand, shows the uncertainty and contingency of future events, and how often they contradict the prospects we have of them. He had exhorted us (Ecc 9:10) to do what we have to do with all our might; but here he reminds us that, when we have done all, we must leave the issue with God, and not be confident of the success.\nI. We are often disappointed...', 'teologico');
add('ec', 9, 13, 'Matthew Henry', 'Solomon still recommends wisdom to us as necessary to the preserving of our peace and the perfecting of our business, notwithstanding the vanities and crosses which human affairs are subject to. He had said (Ecc 9:11), Bread is not always to the wise; yet he would not therefore be thought either to disparage, or to discourage, wisdom, no, he still retains his principle, that wisdom excels folly as much as light excels darkness (Ecc 2:13), and we ought to love and embrace it, and be governed b...', 'teologico');
add('ec', 10, 1, 'Matthew Henry', 'In these verses Solomon shows,\nI. What great need wise men have to take heed of being guilty of any instance of folly; for a little folly is a great blemish to him that is in reputation for wisdom and honour, and is as hurtful to his good name as dead flies are to a sweet perfume, not only spoiling the sweetness of it, but making it to send forth a stinking savour. Note, 1. True wisdom is true honour, and will gain a man a reputation, which is like a box of precious ointment, pleasing and ver...', 'teologico');
add('ec', 10, 4, 'Matthew Henry', 'The scope of these verses is to keep subjects loyal and dutiful to the government. In Solomon\'s reign the people were very rich, and lived in prosperity, which perhaps made them proud and petulant, and when the taxes were high, though they had enough to pay them with, it is probable that many conducted themselves insolently towards the government and threatened to rebel. To such Solomon here gives some necessary cautions.\nI. Let not subjects carry on a quarrel with their prince upon any priva...', 'teologico');
add('ec', 10, 12, 'Matthew Henry', 'Solomon, having shown the benefit of wisdom, and of what great advantage it is to us in the management of our affairs, here shows the mischief of folly and how it exposes men, which perhaps comes in as a reflection upon those rulers who set folly in great dignity.\nI. Fools talk a great deal to no purpose, and they show their folly as much by the multitude, impertinence, and mischievousness of their words, as by any thing; whereas the words of a wise man\'s mouth are gracious, are grace, manife...', 'teologico');
add('ec', 10, 16, 'Matthew Henry', 'Solomon here observes,\nI. How much the happiness of a land depends upon the character of its rulers; it is well or ill with the people according as the princes are good or bad. 1. The people cannot be happy when their princes are childish and voluptuous (Ecc 10:16): Woe unto thee, O land! even the land of Canaan itself, though otherwise the glory of all lands, when thy king is a child, not so much in age (Solomon himself was young when his kingdom was happy in him) as in understanding; when t...', 'teologico');
add('ec', 11, 1, 'Matthew Henry', 'Solomon had often, in this book, pressed it upon rich people to take the comfort of their riches themselves; here he presses it upon them to do good to others with them and to abound in liberality to the poor, which will, another day, abound to their account. Observe,\nI. How the duty itself is recommended to us, Ecc 11:1. 1. Cast thy bread upon the waters, thy bread-corn upon the low places (so some understand it), alluding to the husbandman, who goes forth, bearing precious seed, sparing bre...', 'teologico');
add('ec', 11, 7, 'Matthew Henry', 'Here is an admonition both to old people and to young people, to think of dying, and get ready for it. Having by many excellent precepts taught us how to live well, the preacher comes now, towards the close of his discourse, to teach us how to die well and to put us in mind of our latter end.\nI. He applies himself to the aged, writes to them as fathers, to awaken them to think of death, Ecc 11:7, Ecc 11:8. Here is, 1. A rational concession of the sweetness of life, which old people find by ex...', 'teologico');
add('ec', 12, 1, 'Matthew Henry', 'Here is, I. A call to young people to think of God, and mind their duty to him, when they are young: Remember now thy Creator in the days of thy youth. This is, 1. The royal preacher\'s application of his sermon concerning the vanity of the world and every thing in it. "You that are young flatter yourselves with expectations of great things from it, but believe those that have tried it; it yields no solid satisfaction to a soul; therefore, that you may not be deceived by this vanity, nor too m...', 'teologico');
add('ec', 12, 8, 'Matthew Henry', 'Solomon is here drawing towards a close, and is loth to part till he has gained his point, and prevailed with his hearers, with his readers, to seek for that satisfaction in God only and in their duty to him which they can never find in the creature.\nI. He repeats his text (Ecc 12:8), 1. As that which he had fully demonstrated the truth of, and so made good his undertaking in this sermon, wherein he had kept closely to his text, and both his reasons and his application were to the purpose. 2....', 'teologico');
add('ec', 12, 13, 'Matthew Henry', 'The great enquiry which Solomon prosecutes in this book is, What is that good which the sons of men should do? Ecc 2:3. What is the true way to true happiness, the certain means to attain our great end? He had in vain sought it among those things which most men are eager in pursuit of, but here, at length, he has found it, by the help of that discovery which God anciently made to man (Job 28:28), that serious godliness is the only way to true happiness: Let us hear the conclusion of the whole...', 'teologico');

// CT (2 comentários)
add('ct', 8, 6, 'Bernardo de Claraval', 'Põe-me como selo sobre o teu coração — O amor de Deus é forte como a morte; a devoção mística expressa a intimidade com Cristo.', 'cultural');
add('ct', 2, 7, 'Spurgeon', 'Não acordeis o amor — A comunhão com Deus não se força; floresce no tempo certo.', 'aplicacao');

// IS (202 comentários)
add('is', 6, 3, 'Calvino', 'Santo, Santo, Santo — A trina santificação: a plenitude da glória divina em superlativo triplo.', 'teologico');
add('is', 6, 5, 'Lutero', 'Ai de mim, que estou perdido — O reconhecimento da impureza diante da santidade divina é o primeiro passo da vocação.', 'teologico');
add('is', 6, 8, 'Spurgeon', 'Aqui estou, envia-me — A vocação profética: responderei quando Deus chamar.', 'aplicacao');
add('is', 7, 14, 'Tomás de Aquino', 'A virgem conceberá — A profecia indica nascimento virginal: miraculoso, acima da natureza.', 'teologico');
add('is', 9, 6, 'João Crisóstomo', 'Pai eterno — O título messiânico: o Filho que nasce é eterno, gerado antes dos tempos.', 'teologico');
add('is', 40, 3, 'Matthew Henry', 'Preparai no deserto o caminho — A preparação para a vinda do Messias exige humilhação e arrependimento.', 'teologico');
add('is', 42, 1, 'Calvino', 'Eis o meu servo — O Servo do Senhor: Cristo como modelo de obediência e humildade.', 'teologico');
add('is', 42, 3, 'John Stott', 'Não apagará o wick — A compaixão do Messias: gentil com os fracos, firme na verdade.', 'aplicacao');
add('is', 53, 3, 'Agostinho', 'Desprezado e rejeitado — A humilhação do Servo Sofredor: o Messias sofre voluntariamente por nós.', 'teologico');
add('is', 53, 5, 'Tomás de Aquino', 'Ferido por nossas transgressões — O sofrimento do Servo é substitutivo: Ele paga o que devíamos.', 'teologico');
add('is', 53, 7, 'Spurgeon', 'Como cordeiro será conduzido — A submissão voluntária do Servo: Ele não abre a boca contra a injustiça.', 'teologico');
add('is', 53, 10, 'Lutero', 'O Senhor quis mará-lo — A vontade de Deus está no sofrimento de Cristo: não é acidente, mas propósito.', 'teologico');
add('is', 53, 12, 'N.T. Wright', 'Intercedeu por muitos — O Servo Sofredor não apenas morre, mas intercede: seu sofrimento é frutífero.', 'escatologico');
add('is', 53, 6, 'Albert Barnes', 'Todos nós andamos desgarrados — A universalidade do pecado: todos como ovelhas, mas Deus o castiga nele.', 'teologico');
add('is', 1, 1, 'Matthew Henry', 'Here is, I. The name of the prophet, Isaiah, or Jesahiahu (for so it is in the Hebrew), which, in the New Testament is read Esaias. His name signifies the salvation of the Lord - a proper name for a prophet by whom God gives knowledge of salvation to his people, especially for this prophet, who prophesies so much of Jesus the Saviour and of the great salvation wrought out by him. He is said to be the son of Amoz, not Amos the prophet (the two names in the Hebrew differ more than in the Englis...', 'teologico');
add('is', 1, 2, 'Matthew Henry', 'We will hope to meet with a brighter and more pleasant scene before we come to the end of this book; but truly here, in the beginning of it, every thing looks very bad, very black, with Judah and Jerusalem. What is the wilderness of the world, if the church, the vineyard, has such a dismal aspect as this?\nI. The prophet, though he speaks in God\'s name, yet, despairing to gain audience with the children of his people, addresses himself to the heavens and the earth, and bespeaks their attention...', 'teologico');
add('is', 1, 10, 'Matthew Henry', 'Here, I. God calls to them (but calls in vain) to hear his word, Isa 1:10. 1. The title he gives them is very strange; You rulers of Sodom, and people of Gomorrah. This intimates what a righteous thing it would have been with God to make them like Sodom and Gomorrah in respect of ruin (Isa 1:9), because that had made themselves like Sodom and Gomorrah in respect of sin. The men of Sodom were wicked, and sinners before the Lord exceedingly (Gen 13:13), and so were the men of Judah. When the ru...', 'teologico');
add('is', 1, 16, 'Matthew Henry', 'Though God had rejected their services as insufficient to atone for their sins while they persisted in them, yet he does not reject them as in a hopeless condition, but here calls upon them to forsake their sins, which hindered the acceptance of their services, and then all would be well. Let them not say that God picked quarrels with them; no, he proposes a method of reconciliation. Observe here,\nI. A call to repentance and reformation: "If you would have your sacrifices accepted, and your p...', 'teologico');
add('is', 1, 21, 'Matthew Henry', 'Here, I. The woeful degeneracy of Judah and Jerusalem is sadly lamented. See, 1. What the royal city had been, a faithful city, faithful to God and the interests of his kingdom among men, faithful to the nation and its public interests. It was full of judgment; justice was duly administered upon the thrones of judgment which were set there, the thrones of the house of David, Psa 122:5. Men were generally honest in their dealings, and abhorred to do an unjust thing. Righteousness lodged in it,...', 'teologico');
add('is', 2, 1, 'Matthew Henry', 'The particular title of this sermon (Isa 2:1) is the same with the general title of the book (Isa 1:1), only that what is there called the vision is here called the word which Isaiah saw (or the matter, or thing, which he saw), the truth of which he had as full an assurance of in his own mind as if he had seen it with his bodily eyes. Or this word was brought to him in a vision; something he saw when he received this message from God. John turned to see the voice that spoke with him. Rev 1:12...', 'teologico');
add('is', 2, 6, 'Matthew Henry', 'The calling in of the Gentiles was accompanied with the rejection of the Jews; it was their fall, and the diminishing of them, that was the riches of the Gentiles; and the casting off of them was the reconciling of the world (Rom 11:12-15); and it should seem that these verses have reference to that, and are designed to justify God therein, and yet it is probable that they are primarily intended for the convincing and awakening of the men of that generation in which the prophet lived, it bein...', 'teologico');
add('is', 2, 10, 'Matthew Henry', 'The prophet here goes on to show what a desolation would be brought upon their land when God should have forsaken them. This may refer particularly to their destruction by the Chaldeans first, and afterwards by the Romans, or it may have a general respect to the method God takes to awaken and humble proud sinners, and to put them out of conceit with that which they delighted in and depended on more than God. We are here told that sooner or later God will find out a way,\nI. To startle and awak...', 'teologico');
add('is', 3, 1, 'Matthew Henry', 'The prophet, in the close of the foregoing chapter, had given a necessary caution to all not to put confidence in man, or any creature; he had also given a general reason for that caution, taken from the frailty of human life and the vanity and weakness of human powers. Here he gives a particular reason for it - God was now about to ruin all their creature-confidences, so that they should meet with nothing but disappointments in all their expectations from them (Isa 3:1): The stay and the sta...', 'teologico');
add('is', 3, 9, 'Matthew Henry', 'Here God proceeds in his controversy with his people. Observe,\nI. The ground of his controversy. It was for sin that God contended with them; if they vex themselves, let them look a little further and they will see that they must thank themselves: Woe unto their souls! For they have rewarded evil unto themselves. Alas for their souls! (so it may be read, in a way of lamentation), for they have procured evil to themselves, Isa 3:9. Note, The condition of sinners is woeful and very deplorable. ...', 'teologico');
add('is', 3, 16, 'Matthew Henry', 'The prophet\'s business was to show all sorts of people what they had contributed to the national guilt and what share they must expect in the national judgments that were coming. Here he reproves and warns the daughters of Zion, tells the ladies of their faults; and Moses, in the law, having denounced God\'s wrath against the tender and delicate woman (the prophets being a comment upon the law, Deu 28:56), he here tells them how they shall smart by the calamities that are coming upon them. Obs...', 'teologico');
add('is', 4, 1, 'Matthew Henry', 'It was threatened (Isa 3:25) that the mighty men should fall by the sword in war, and it was threatened as a punishment to the women that affected gaiety and a loose sort of conversation. Now here we have the effect and consequence of that great slaughter of men, 1. That though Providence has so wisely ordered that, communibus annis - on an average of years, there is nearly an equal number of males and females born into the world, yet, through the devastations made by war, there should scarce...', 'teologico');
add('is', 4, 2, 'Matthew Henry', 'By the foregoing threatenings Jerusalem is brought into a very deplorable condition: every thing looks melancholy. But here the sun breaks out from behind the cloud. Many exceedingly great and precious promises we have in these verses, giving assurance of comfort which may be discerned through the troubles, and of happy days which shall come after them, and these certainly point at the kingdom of the Messiah, and the great redemption to be wrought out by him, under the figure and type of the ...', 'teologico');
add('is', 5, 1, 'Matthew Henry', 'See what variety of methods the great God takes to awaken sinners to repentance by convincing them of sin, and showing them their misery and danger by reason of it. To this purport he speaks sometimes in plain terms and sometimes in parables, sometimes in prose and sometimes in verse, as here. "We have tried to reason with you (Isa 1:18); now let us put your case into a poem, inscribed to the honour of my well beloved." God the Father dictates it to the honour of Christ his well beloved Son, ...', 'teologico');
add('is', 5, 8, 'Matthew Henry', 'The world and the flesh are the two great enemies that we are in danger of being overpowered by; yet we are in no danger if we do not ourselves yield to them. Eagerness of the world, and indulgence of the flesh, are the two sins against which the prophet, in God\'s name, here denounces woes. These were sins which then abounded among the men of Judah, some of the wild grapes they brought forth (Isa 5:4), and for which God threatens to bring ruin upon them. They are sins which we have all need t...', 'teologico');
add('is', 5, 18, 'Matthew Henry', 'Here are, I. Sins described which will bring judgments upon a people: and this perhaps is not only a charge drawn up against the men of Judah who lived at that time, and the particular articles of that charge, though it may relate primarily to them, but is rather intended for warning to all people, in all ages, to take heed of these sins, as destructive both to particular persons and to communities, and exposing men to God\'s wrath and his righteous judgments. Those are here said to be in a wo...', 'teologico');
add('is', 6, 1, 'Matthew Henry', 'The vision which Isaiah saw when he was, as is said of Samuel, established to be a prophet of the Lord (Sa1 3:20), was intended, 1. To confirm his faith, that he might himself be abundantly satisfied of the truth of those things which should afterwards be made known to him. This God opened the communications of himself to him; but such visions needed not to be afterwards repeated upon every revelation. Thus God appeared at first as a God of glory to Abraham (Act 7:2), and to Moses, Exo 3:2. E...', 'teologico');
add('is', 6, 9, 'Matthew Henry', 'God takes Isaiah at his word, and here sends him on a strange errand - to foretel the ruin of his people and even to ripen them for that ruin - to preach that which, by their abuse of it, would be to them a savour of death unto death. And this was to be a type and figure of the state of the Jewish church in the days of the Messiah, when they should obstinately reject the gospel, and should thereupon be rejected of God. These verses are quoted in part, or referred to, six times, in the New Tes...', 'teologico');
add('is', 7, 1, 'Matthew Henry', 'The prophet Isaiah had his commission renewed in the year that king Uzziah died, Isa 6:1. Jotham his son reigned, and reigned well, sixteen years. All that time, no doubt, Isaiah prophesied as he was commanded, and yet we have not in this book any of his prophecies dated in the reign of Jotham; but this, which is put first, was in the days of Ahaz the son of Jotham. Many excellent useful sermons he preached which were not published and left upon record; for, if all that was memorable had been...', 'teologico');
add('is', 7, 10, 'Matthew Henry', 'Here, I. God, by the prophet, makes a gracious offer to Ahaz, to confirm the foregoing predictions, and his faith in them, by such sign or miracle as he should choose (Isa 7:10, Isa 7:11): Ask thee a sign of the Lord thy God; See here the divine faithfulness and veracity. God tells us nothing but what he is able and ready to prove. See his wonderful condescension to the children of men, in that he is so willing to show to the heirs of promise the immutability of his counsel, Heb 6:17. He cons...', 'teologico');
add('is', 7, 17, 'Matthew Henry', 'After the comfortable promises made to Ahaz as a branch of the house of David, here follow terrible threatenings against him, as a degenerate branch of that house; for though the loving-kindness of God shall not be utterly taken away, for the sake of David and the covenant made with him, yet his iniquity shall be chastened with the rod, and his sin with stripes. Let those that will not mix faith with the promises of God expect to hear the alarms of his threatenings.\nI. The judgment threatened...', 'teologico');
add('is', 8, 1, 'Matthew Henry', 'In these verses we have a prophecy of the successes of the king of Assyria against Damascus, Samaria, and Judah, that the two former should be laid waste by him, and the last greatly frightened. Here we have,\nI. Orders given to the prophet to write this prophecy, and publish it to be seen and read of all men, and to leave it upon record, that when the thing came to pass they might know that God had sent him; for that was one end of prophecy, Joh 14:29. He must take a great roll, which would c...', 'teologico');
add('is', 8, 9, 'Matthew Henry', 'The prophet here returns to speak of the present distress that Ahaz and his court and kingdom were in upon account of the threatening confederacy of the ten tribes and the Syrians against them. And in these verses,\nI. He triumphs over the invading enemies, and, in effect, sets them at defiance, and bids them do their worst (Isa 8:9, Isa 8:10): "O you people, you of far countries, give ear to what the prophet says to you in God\'s name." 1. "We doubt not but you will now make your utmost effort...', 'teologico');
add('is', 8, 16, 'Matthew Henry', 'In these verses we have,\nI. The unspeakable privilege which the people of God enjoy in having the oracles of God consigned over to them, and being entrusted with the sacred writings. That they may sanctify the Lord of hosts, may make him their fear and find him their sanctuary, bind up the testimony, Isa 8:16. Note, It is a great instance of God\'s care of his church and love to it that he has lodged in it the invaluable treasure of divine revelation. 1. It is a testimony and a law; not only t...', 'teologico');
add('is', 9, 1, 'Matthew Henry', 'The first words of this chapter plainly refer to the close of the foregoing chapter, where every thing looked black and melancholy: Behold, trouble, and darkness, and dimness - very bad, yet not so bad but that to the upright there shall arise light in the darkness (Psa 112:4) and at evening time it shall be light, Zac 14:7. Nevertheless it shall not be such dimness (either not such for kind or not such for degree) as sometimes there has been. Note, In the worst of times God\'s people have a n...', 'teologico');
add('is', 9, 8, 'Matthew Henry', 'Here are terrible threatenings, which are directed primarily against Israel, the kingdom of the ten tribes, Ephraim and Samaria, the ruin of which is here foretold, with all the woeful confusions that were the prefaces to that ruin, all which came to pass within a few years after; but they look further, to all the enemies of the throne and kingdom of Christ the Son of David, and read the doom of all the nations that forget God, and will not have Christ to reign over them. Observe,\nI. The pref...', 'teologico');
add('is', 10, 1, 'Matthew Henry', 'Whether they were the princes and judges of Israel of Judah, or both, that the prophet denounced this woe against, is not certain: if those of Israel, these verses are to be joined with the close of the foregoing chapter, which is probable enough, because the burden of that prophecy (for all this his anger is not turned away) is repeated here (Isa 10:4); if those of Judah, they then show what was the particular design with which God brought the Assyrian army upon them - to punish their magist...', 'teologico');
add('is', 10, 5, 'Matthew Henry', 'The destruction of the kingdom of Israel by Shalmaneser king of Assyria was foretold in the foregoing chapter, and it had its accomplishment in the sixth year of Hezekiah, Kg2 18:10. It was total and final, head and tail were all cut off. Now the correction of the kingdom of Judah by Sennacherib king of Assyria is foretold in this chapter; and this prediction was fulfilled in the fourteenth year of Hezekiah, when that potent prince, encouraged by the successes of his predecessor against the t...', 'teologico');
add('is', 10, 20, 'Matthew Henry', 'The prophet had said (Isa 10:12) that the Lord would perform his whole work upon Mount Zion and upon Jerusalem, by Sennacherib\'s invading the land. Now here we are told what that work should be, a twofold work: - \nI. The conversion of some, to whom this providence should be sanctified and yield the peaceable fruit of righteousness, though for the present it was not joyous, but grievous; these are but a remnant (Isa 10:22), the remnant of Israel (Isa 10:20), the remnant of Jacob (Isa 10:21), b...', 'teologico');
add('is', 10, 24, 'Matthew Henry', 'The prophet, in his preaching, distinguishes between the precious and the vile; for God in his providence, even in the same providence, does so. He speaks terror, in Sennacherib\'s invasion, to the hypocrites, who were the people of God\'s wrath, Isa 10:6. But here he speaks comfort to the sincere, who were the people of God\'s love. The judgment was sent for the sake of the former; the deliverance was wrought for the sake of the latter. Here we have,\nI. An exhortation to God\'s people not to be ...', 'teologico');
add('is', 11, 1, 'Matthew Henry', 'The prophet had before, in this sermon, spoken of a child that should be born, a son that should be given, on whose shoulders the government should be, intending this for the comfort of the people of God in times of trouble, as dying Jacob, many ages before, had intended the prospect of Shiloh for the comfort of his seed in their affliction in Egypt. He had said (Isa 10:27) that the yoke should be destroyed because of the anointing; now here he tells us on whom that anointing should rest. He ...', 'teologico');
add('is', 11, 10, 'Matthew Henry', 'We have here a further prophecy of the enlargement and advancement of the kingdom of the Messiah, under the type and figure of the flourishing condition of the kingdom of Judah in the latter end of Hezekiah\'s reign, after the defeat of Sennacherib.\nI. This prediction was in part accomplished when the great things God did for Hezekiah and his people proved as an ensign, inviting the neighbouring nations to them to enquire of the wonders done in the land, on which errand the king of Babylon\'s a...', 'teologico');
add('is', 12, 1, 'Matthew Henry', 'This is the former part of the hymn of praise which is prepared for the use of the church, of the Jewish church when God would work great deliverances for them, and of the Christian church when the kingdom of the Messiah should be set up in the world in despite of the opposition of the powers of darkness: In that day thou shalt say, O Lord! I will praise thee. The scattered church, being united into one body, shall, as one man, with one mind and one mouth, thus praise God, who is one and his ...', 'teologico');
add('is', 12, 4, 'Matthew Henry', 'This is the second part of this evangelical song, and to the same purport with the former; there believers stir up themselves to praise God, here they invite and encourage one another to do it, and are contriving to spread his praise and draw in others to join with them in it. Observe,\nI. Who are here called upon to praise God - the inhabitants of Zion and Jerusalem, whom God had in a particular manner protected from Sennacherib\'s violence, Isa 12:6. Those that have received distinguishing fa...', 'teologico');
add('is', 13, 1, 'Matthew Henry', 'The general title of this book was, The vision of Isaiah the son of Amoz, Isa 1:1. Here we have that which Isaiah saw, which was represented to his mind as clearly and fully as if he had seen it with his bodily eyes; but the particular inscription of this sermon is the burden of Babylon. 1. It is a burden, a lesson they were to learn (so some understand it), but they would be loth to learn it, and it would be a burden to their memories, or a load which should lie heavily upon them and under w...', 'teologico');
add('is', 13, 6, 'Matthew Henry', 'We have here a very elegant and lively description of the terrible confusion and desolation which should be made in Babylon by the descent which the Medes and Persians should make upon it. Those that were now secure and easy were bidden to howl and make sad lamentation; for,\nI. God was about to appear in wrath against them, and it is a fearful thing to fall into his hands: The day of the Lord is at hand (Isa 13:6), a little day of judgment, when God will act as a just avenger of his own and h...', 'teologico');
add('is', 13, 19, 'Matthew Henry', 'The great havoc and destruction which it was foretold should be made by the Medes and Persians in Babylon here end in the final destruction of it. 1. It is allowed that Babylon was a noble city. It was the glory of kingdoms and the beauty of the Chaldees\' excellency; it was that head of gold (Dan 2:37, Dan 2:38); it was called the lady of kingdoms (Isa 47:5), the praise of the whole earth (Jer 51:41), like a pleasant roe (so the word signifies); but it shall be as a chased roe, Isa 13:14. The...', 'teologico');
add('is', 14, 1, 'Matthew Henry', 'This comes in here as the reason why Babylon must be overthrown and ruined, because God has mercy in store for his people, and therefore, 1. The injuries done to them must be reckoned for and revenged upon their persecutors. Mercy to Jacob will be wrath and ruin to Jacob\'s impenitent implacable adversaries, such as Babylon was. 2. The yoke of oppression which Babylon had long laid on their necks must be broken off, and they must be set at liberty; and, in order to this, the destruction of Bab...', 'teologico');
add('is', 14, 4, 'Matthew Henry', 'The kings of Babylon, successively, were the great enemies and oppressors of God\'s people, and therefore the destruction of Babylon, the fall of the king, and the ruin of his family, are here particularly taken notice of and triumphed in. In the day that God has given Israel rest they shall take up this proverb against the king of Babylon. We must not rejoice when our enemy falls, as ours; but when Babylon, the common enemy of God and his Israel, sinks, then rejoice over her, thou heaven, and...', 'teologico');
add('is', 14, 24, 'Matthew Henry', 'The destruction of Babylon and the Chaldean empire was a thing at a great distance; the empire had not risen to any considerable height when its fall was here foretold: it was almost 200 years from this prediction of Babylon\'s fall to the accomplishment of it. Now the people to whom Isaiah prophesied might ask, "What is this to us, or what shall we be the better for it, and what assurance shall we have of it?" To both questions he answers in these verses, by a prediction of the ruin both of t...', 'teologico');
add('is', 15, 1, 'Matthew Henry', 'The country of Moab was of small extent, but very fruitful. It bordered upon the lot of Reuben on the other side Jordan and upon the Dead Sea. Naomi went to sojourn there when there was a famine in Canaan. This is the country which (it is here foretold) should be wasted and grievously harassed, not quite ruined, for we find another prophecy of its ruin (Jer. 48), which was accomplished by Nebuchadnezzar. This prophecy here was to be fulfilled within three years (Isa 16:14), and therefore was ...', 'teologico');
add('is', 15, 6, 'Matthew Henry', 'Here the prophet further describes the woeful and piteous lamentations that should be heard throughout all the country of Moab when it should become a prey to the Assyrian army. "By this time the cry has gone round about all the borders of Moab," Isa 15:8. Every corner of the country has received the alarm, and is in the utmost confusion upon it. It has reached to Eglaim, a city at one end of the country, and to Beer-elim, a city as far the other way. Where sin has been general, and all flesh...', 'teologico');
add('is', 16, 1, 'Matthew Henry', 'God has made it to appear that he delights not in the ruin of sinners by telling them what they may do to prevent the ruin; so he does here to Moab.\nI. He advises them to be just to the house of David, and to pay the tribute they had formerly covenanted to pay to the kings of his line (Isa 16:1): Send you the lamb to the ruler of the land. David made the Moabites tributaries to him, Sa2 8:2. They became his servants, and brought gifts. Afterwards they paid their tribute to the kings of Israel...', 'teologico');
add('is', 16, 6, 'Matthew Henry', 'Here we have, I. The sins with which Moab is charged, Isa 16:6. The prophet seems to check himself for going about to give good counsel to the Moabites, concluding they would not take the advice he gave them. He told them their duty (whether they would hear or whether they would forbear), but despairs of working any good upon them; he would have healed them, but they would not be healed. Those that will not be counselled cannot be helped. Their sins were, 1. Pride. This is most insisted upon;...', 'teologico');
add('is', 17, 1, 'Matthew Henry', 'We have here the burden of Damascus; the Chaldee paraphrase reads it, The burden of the cup of the curse to drink to Damascus in; and, the ten tribes being in alliance, they must expect to pledge Damascus in this cup of trembling that is to go round. 1. Damascus itself, the head city of Syria, must be destroyed; the houses, it is likely, will be burnt, as least the walls, and gates, and fortifications demolished, and the inhabitants carried away captive, so that for the present it is taken aw...', 'teologico');
add('is', 17, 6, 'Matthew Henry', 'Mercy is here reserved, in a parenthesis, in the midst of judgment, for a remnant that should escape the common ruin of the kingdom of the ten tribes. Though the Assyrians took all the care they could that none should slip out of their net, yet the meek of the earth were hidden in the day of the Lord\'s anger, and had their lives given them for a prey and made comfortable to them by their retirement to the land of Judah, where they had the liberty of God\'s courts. 1. They shall be but a small ...', 'teologico');
add('is', 17, 9, 'Matthew Henry', 'Here the prophet returns to foretel the woeful desolations that should be made in the land of Israel by the army of the Assyrians. 1. That the cities should be deserted. Even the strong cities, which should have protected the country, shall not be able to protect themselves: They shall be as a forsaken bough and an uppermost branch of an old tree, which has gone to decay, is forsaken of its leaves, and appears on the top of the tree, bare, and dry, and dead; so shall their strong cities look ...', 'teologico');
add('is', 17, 12, 'Matthew Henry', 'These verses read the doom of those that spoil and rob the people of God. If the Assyrians and Israelites invade and plunder Judah, if the Assyrian army take God\'s people captive and lay their country waste, let them know that ruin will be their lot and portion. They are here brought in, 1. Triumphing over the people of God. They relied upon their numbers. The Assyrian army was made up out of divers nations: it was the multitude of many people (Isa 17:12), by which weight they hoped to carry ...', 'teologico');
add('is', 18, 1, 'Matthew Henry', 'Interpreters are very much at a loss where to find this land that lies beyond the rivers of Cush. Some take it to be Egypt, a maritime country, and full of rivers, and which courted Israel to depend upon them, but proved broken reeds; but against this it is strongly objected that the next chapter is distinguished from this by the title of the burden of Egypt. Others take it to be Ethiopia, and read it, which lies near, or about, the rivers of Ethiopia, not that in Africa, which lay south of E...', 'teologico');
add('is', 19, 1, 'Matthew Henry', 'Though the land of Egypt had of old been a house of bondage to the people of God, where they had been ruled with rigour, yet among the unbelieving Jews there still remained much of the humour of their fathers, who said, Let us make us a captain and return into Egypt. Upon all occasions they trusted to Egypt for help (Isa 30:2), and thither they fled, in disobedience to God\'s express command, when things were brought to the last extremity in their own country, Jer 43:7. Rabshakeh upbraided Hez...', 'teologico');
add('is', 19, 18, 'Matthew Henry', 'Out of the thick and threatening clouds of the foregoing prophecy the sun of comfort here breaks forth, and it is the sun of righteousness. Still God has mercy in store for Egypt, and he will show it, not so much by reviving their trade and replenishing their river again as by bringing the true religion among them, calling them to, and accepting them in, the worship of the one only living and true God; and these blessings of grace were much more valuable than all the blessings of nature where...', 'teologico');
add('is', 20, 1, 'Matthew Henry', 'God here, as King of nations, brings a sore calamity upon Egypt and Ethiopia, but, as King of saints, brings good to his people out of it. Observe,\nI. The date of this prophecy. It was in the year that Ashdod, a strong city of the Philistines (but which some think was lately recovered from them by Hezekiah, when he smote the Philistines even unto Gaza, Kg2 18:8), was besieged and taken by an army of the Assyrians. It is uncertain what year of Hezekiah that was, but the event was so remarkable...', 'teologico');
add('is', 21, 1, 'Matthew Henry', 'We had one burden of Babylon before (ch. 13); here we have another prediction of its fall. God saw fit thus to possess his people with the belief of this event by line upon line, because Babylon sometimes pretended to be a friend to them (as Isa 39:1), and God would hereby warn them not to trust to that friendship, and sometimes was really an enemy to them, and God would hereby warn them not to be afraid of that enmity. Babylon is marked for ruin; and all that believe God\'s prophets can, thro...', 'teologico');
add('is', 21, 11, 'Matthew Henry', 'This prophecy concerning Dumah is very short, and withal dark and hard to be understood. Some think that Dumah is a part of Arabia, and that the inhabitants descended from Dumah the sixth son of Ishmael, as those of Kedar (Isa 21:16, Isa 21:17) from Ishmael\'s second son, Gen 25:13, Gen 25:14. Others, because Mount Seir is here mentioned, by Dumah understand Idumea, the country of the Edomites. Some of Israel\'s neighbours are certainly meant, and their distress is foretold, not only for warnin...', 'teologico');
add('is', 21, 13, 'Matthew Henry', 'Arabia was a large country, that lay eastward and southward of the land of Canaan. Much of it was possessed by the posterity of Abraham. The Dedanim, here mentioned (Isa 21:13), descended from Dedan, Abraham\'s son by Keturah; the inhabitants of Tema and Kedar descended from Ishmael, Gen 25:3, Gen 25:13, Gen 25:15. The Arabians generally lived in tents, and kept cattle, were a hardy people, inured to labour; probably the Jews depended upon them as a sort of a wall between them and the more war...', 'teologico');
add('is', 22, 1, 'Matthew Henry', 'The title of this prophecy is very observable. It is the burden of the valley of vision, of Judah and Jerusalem; so all agree. Fitly enough is Jerusalem called a valley, for the mountains were round about it, and the land of Judah abounded with fruitful valleys; and by the judgments of God, though they had been as a towering mountain, they should be brought low, sunk and depressed, and become dark and dirty, as a valley. But most emphatically is it called a valley of vision because there God ...', 'teologico');
add('is', 22, 8, 'Matthew Henry', 'What is meant by the covering of Judah, which in the beginning of this paragraph is said to be discovered, is not agreed. The fenced cities of Judah were a covering to the country; but these, being taken by the army of the Assyrians, ceased to be a shelter, so that the whole country lay exposed to be plundered. The weakness of Judah, its nakedness, and inability to keep itself, now appeared more than ever; and thus the covering of Judah was discovered. Its magazines and stores, which had been...', 'teologico');
add('is', 22, 15, 'Matthew Henry', 'We have here a prophecy concerning the displacing of Shebna, a great officer at court, and the preferring of Eliakim to the post of honour and trust that he was in. Such changes are common in the courts of princes; it is therefore strange that so much notice should be taken of it by the prophet here; but by the accomplishment of what was foretold concerning these particular persons God designed to confirm his word in the mouth of Isaiah concerning other and greater events; and it is likewise ...', 'teologico');
add('is', 23, 1, 'Matthew Henry', 'Tyre being a sea-port town, this prophecy of its overthrow fitly begins and ends with, Howl, you ships of Tarshish; for all its business, wealth, and honour, depended upon its shipping; if that be ruined, they will be all undone. Observe,\nI. Tyre flourishing. This is taken notice of that her fall may appear the more dismal. 1. The merchants of Zidon, who traded at sea, had at first replenished her, Isa 23:2. Zidon was the more ancient city, situated upon the same sea-cost, a few leagues more ...', 'teologico');
add('is', 23, 15, 'Matthew Henry', 'Here is, I. The time fixed for the continuance of the desolations of Tyre, which were not to be perpetual desolations: Tyre shall be forgotten seventy years, Isa 23:15. So long it shall lie neglected and buried in obscurity. It was destroyed by Nebuchadnezzar much about the time that Jerusalem was, and lay as long as it did in its ruins. See the folly of that proud ambitious conqueror. What the richer, what the stronger, was he for making himself master of Tyre, when all the inhabitants were ...', 'teologico');
add('is', 24, 1, 'Matthew Henry', 'It is a very dark and melancholy scene that this prophecy presents to our view; turn our eyes which way we will, every thing looks dismal. The threatened desolations are here described in a great variety of expressions to the same purport, and all aggravating.\nI. The earth is stripped of all its ornaments and looks as if it were taken off its basis; it is made empty and waste (Isa 24:1), as if it were reduced to its first chaos, Tohu and Bohu, nothing but confusion and emptiness again (Gen 1:...', 'teologico');
add('is', 24, 13, 'Matthew Henry', 'Here is mercy remembered in the midst of wrath. In Judah and Jerusalem, and the neighbouring countries, when they are overrun by the enemy, Sennacherib or Nebuchadnezzar, there shall be a remnant preserved from the general ruin, and it shall be a devout and pious remnant. And this method God usually observes when his judgments are abroad; he does not make a full end, Isa 6:13. Or we may take it thus: Though the greatest part of mankind have all their comfort ruined by the emptying of the eart...', 'teologico');
add('is', 24, 16, 'Matthew Henry', 'These verses, as those before, plainly speak,\nI. Comfort to saints. They may be driven, by the common calamities of the places where they live, into the uttermost parts of the earth, or perhaps they are forced thither for their religion; but there they are singing, not sighing. Thence have we heard songs, and it is a comfort to us to hear them, to hear that good people carry their religion along with them even to the most distant regions, to hear that God visits them there and gives encourage...', 'teologico');
add('is', 25, 1, 'Matthew Henry', 'It is said in the close of the foregoing chapter that the Lord of hosts shall reign gloriously; now, in compliance with this, the prophet here speaks of the glorious majesty of his kingdom (Psa 145:12), and gives him the glory of it; and, however this prophecy might have an accomplishment in the destruction of Babylon and the deliverance of the Jews out of their captivity there, it seems to look further, to the praises that should be offered up to God by the gospel church for Christ\'s victori...', 'teologico');
add('is', 25, 6, 'Matthew Henry', 'If we suppose (as many do) that this refers to the great joy which there should be in Zion and Jerusalem when the army of the Assyrians was routed by an angel, or when the Jews were released out of their captivity in Babylon, or upon occasion of some other equally surprising deliverance, yet we cannot avoid making it to look further, to the grace of the gospel and the glory which is the crown and consummation of that grace; for it is at our resurrection through Christ that the saying here wri...', 'teologico');
add('is', 25, 9, 'Matthew Henry', 'Here is, I. The welcome which the church shall give to these blessings promised in the foregoing verses (Isa 25:9): It shall be said in that day, with a humble holy triumph and exultation, Lo, this is our God; we have waited for him! Thus will the deliverance of the church out of long and sore troubles be celebrated; thus will it be as life from the dead. With such transports of joy and praise will those entertain the glad tidings of the Redeemer who looked for him, and for redemption in Jeru...', 'teologico');
add('is', 26, 1, 'Matthew Henry', 'To the prophecies of gospel grace very fitly is a song annexed, in which we may give God the glory and take to ourselves the comfort of that grace: In that day, the gospel day, which the day of the victories and enlargements of the Old Testament church was typical of (to some of which perhaps this has a primary reference), in that day this song shall be sung; there shall be persons to sing it, and cause and hearts to sing it; it shall be sung in the land of Judah, which was a figure of the go...', 'teologico');
add('is', 26, 5, 'Matthew Henry', 'Here the prophet further encourages us to trust in the Lord for ever, and to continue waiting on him; for,\nI. He will make humble souls that trust in him to triumph over their proud enemies, Isa 26:5, Isa 26:6. Those that exalt themselves shall be abased: For he brings down those that dwell on high; and wherein they deal proudly he is, and will be, above them. Even the lofty city Babylon itself, or Nineveh, he lays it low, Isa 25:12. He can do it, be it ever so well fortified. He has often do...', 'teologico');
add('is', 26, 12, 'Matthew Henry', 'The prophet in these verses looks back upon what God had done with them, both in mercy and judgment, and sings unto God of both, and then looks forward upon what he hoped God would do for them. Observe,\nI. His reviews and reflections are mixed. When he looks back upon the state of the church he finds,\n1. That God had in many instances been very gracious to them and had done great things for them. (1.) In general (Isa 26:12): Thou hast wrought all our works in us, or for us. Whatever good work...', 'teologico');
add('is', 26, 20, 'Matthew Henry', 'These two verses are supposed not to belong to the song which takes up the rest of the chapter, but to begin a new matter, and to be rather an introduction to the following chapter than the conclusion of this. Of whereas, in the foregoing song, the people of God had spoken to him, complaining of their grievances, here he returns an answer to their complaints, in which,\nI. He invites them into their chambers (Isa 26:20): "Come, my people, come to me, come with me" (he calls them nowhere but wh...', 'teologico');
add('is', 27, 1, 'Matthew Henry', 'The prophet is here singing of judgment and mercy,\nI. Of judgment upon the enemies of God\'s church (Isa 27:1), tribulation to those that trouble it, Th2 1:6. When the Lord comes out of his place, to punish the inhabitants of the earth (Isa 26:21), he will be sure to punish leviathan, the dragon that is in the sea, every proud oppressing tyrant, that is the terror of the mighty, and, like the leviathan, is so fierce that none dares stir him up, and his heart as hard as a stone, and when he rai...', 'teologico');
add('is', 27, 7, 'Matthew Henry', 'Here is the prophet again singing of mercy and judgment, not, as before, judgment to the enemies and mercy to the church, but judgment to the church and mercy mixed with that judgment.\nI. Here is judgment threatened even to Jacob and Israel. They shall blossom and bud (Isa 27:6), but, 1. They shall be smitten and slain (Isa 27:7), some of them shall. If God find any thing amiss among them, he will lay them under the tokens of his displeasure for it. Judgment shall begin at the house of God, a...', 'teologico');
add('is', 28, 1, 'Matthew Henry', 'Here, I. The prophet warns the kingdom of the ten tribes of the judgments that were coming upon them for their sins, which were soon after executed by the king of Assyria, who laid their country waste, and carried the people into captivity. Ephraim had his name from fruitfulness, their soil being very fertile and the products of it abundant and the best of the kind; they had a great many fat valleys (Isa 28:1, Isa 28:4), and Samaria, which was situated on a hill, was, as it were, on the head ...', 'teologico');
add('is', 28, 9, 'Matthew Henry', 'The prophet here complains of the wretched stupidity of this people, that they were unteachable and made no improvement of the means of grace which they possessed; they still continued as they were, their mistakes not rectified, their hearts not renewed, nor their lives reformed. Observe,\nI. What it was that their prophets and ministers designed and aimed at. It was to teach them knowledge, the knowledge of God and his will, and to make them understand doctrine, Isa 28:9. This is God\'s way of...', 'teologico');
add('is', 28, 14, 'Matthew Henry', 'The prophet, having reproved those that made a jest of the word of God, here goes on to reprove those that made a jest of the judgments of God, and set them at defiance; for he is a jealous God, and will not suffer either his ordinances or his providences to be brought into contempt. He addressed himself to the scornful men who ruled in Jerusalem, who were the magistrates of the city, Isa 28:14. It is bad with a people when their thrones of judgment become the seats of the scornful, when rule...', 'teologico');
add('is', 28, 23, 'Matthew Henry', 'This parable, which (like many of our Saviour\'s parables) is borrowed from the husbandman\'s calling, is ushered in with a solemn preface demanding attention, He that has ears to hear, let him hear, hear and understand, Isa 28:23.\nI. The parable here is plain enough, that the husbandman applies himself to the business of his calling with a great deal of pains and prudence, secundum artem - according to rule, and, as his judgment directs him, observes a method and order in his work. 1. In his p...', 'teologico');
add('is', 29, 1, 'Matthew Henry', 'That it is Jerusalem which is here called Ariel is agreed, for that was the city where David dwelt; that part of it which was called Zion was in a particular manner the city of David, in which both the temple and the palace were. But why it is so called is very uncertain: probably the name and the reason were then well known. Cities, as well as persons, get surnames and nicknames. Ariel signifies the lion of God, or the strong lion: as the lion is king among beasts, so was Jerusalem among the...', 'teologico');
add('is', 29, 9, 'Matthew Henry', 'Here, I. The prophet stands amazed at the stupidity of the greatest part of the Jewish nation. They had Levites, who taught the good knowledge of the Lord and had encouragement from Hezekiah in doing so, Ch2 30:22. They had prophets, who brought them messages immediately from God, and signified to them what were the causes and what would be the effects of God\'s displeasure against them. Now, one would think, surely this great nation, that has all the advantages of divine revelation, is a wise...', 'teologico');
add('is', 29, 17, 'Matthew Henry', 'Those that thought to hide their counsels from the Lord were said to turn things upside down (Isa 29:16), and they intended to do it unknown to God; but God here tells them that he will turn things upside down his way; and let us see whose word shall stand, his or theirs. They disbelieve Providence: "Wait awhile," says God, "and you shall be convinced by ocular demonstration that there is a God who governs the world, and that he governs it and orders all the changes that are in it for the goo...', 'teologico');
add('is', 30, 1, 'Matthew Henry', 'It was often the fault and folly of the people of the Jews that, when they were insulted by their neighbours on one side, they sought for succour from their neighbours on the other side, instead of looking up to God and putting their confidence in him. Against the Israelites they sought to the Syrians, Ch2 16:2, Ch2 16:3. Against the Syrians they sought to the Assyrians, Kg2 16:7. Against the Assyrians they here sought to the Egyptians, and Rabshakeh upbraided them with so doing, Kg2 18:21. N...', 'teologico');
add('is', 30, 8, 'Matthew Henry', 'Here, I. The preface is very awful. The prophet must not only preach this, but he must write it (Isa 30:8), write it in a table, to be hung up and exposed to public view; he must carefully note it, not in loose papers which might be lost or torn, but in a book, to be preserved for posterity, in perpetuam rei memoriam - for a standing testimony against this wicked generation; let it remain not only to the next succeeding ages, but for ever and ever, while the world stands; and so it shall, for...', 'teologico');
add('is', 30, 18, 'Matthew Henry', 'The closing words of the foregoing paragraph (You shall be left as a beacon upon a mountain) some understand as a promise that a remnant of them should be reserved as monuments of mercy; and here the prophet tells them what good times should succeed these calamities. Or the first words in this paragraph may be read by way of antithesis, Notwithstanding this, yet will the Lord wait that he may be gracious. The prophet, having shown that those who made Egypt their confidence would be ashamed of...', 'teologico');
add('is', 30, 27, 'Matthew Henry', 'This terrible prediction of the ruin of the Assyrian army, though it is a threatening to them, is part of the promise to the Israel of God, that God would not only punish the Assyrians for the mischief they had done to the Israel of God, but would disable and deter them from doing the like again; and this prediction, which would now shortly be accomplished, would ratify and confirm the foregoing promises, which should be accomplished in the latter days. Here is,\nI. God Almighty angry, and com...', 'teologico');
add('is', 31, 1, 'Matthew Henry', 'This is the last of four chapters together that begin with woe; and they are all woes to the sinners that were found among the professing people of God, to the drunkards of Ephraim (Isa 28:1), to Ariel (Isa 29:1), to the rebellious children (Isa 30:1), and here to those that go down to Egypt for help; for men\'s relation to the church will not secure them from divine woes if they live in contempt of divine laws. Observe,\nI. What the sin was that is here reproved, Isa 31:1. 1. Idolizing the Egy...', 'teologico');
add('is', 31, 6, 'Matthew Henry', 'This explains the foregoing promise of the deliverance of Jerusalem; she shall be fitted for deliverance, and then it shall be wrought for her; for in that method God delivers.\nI. Jerusalem shall be reformed, and so she shall be delivered from her enemies within her walls, Isa 31:6, Isa 31:7. Here is, 1. A gracious call to repentance. This was the Lord\'s voice crying in the city, the voice of the rod, the voice of the sword, and the voice of the prophets interpreting the judgment: "Turn you, ...', 'teologico');
add('is', 32, 1, 'Matthew Henry', 'We have here the description of a flourishing kingdom. "Blessed art thou, O land! when it is thus with thee, when kings, princes, and people, are in their places such as they should be." It may be taken as a directory both to magistrates and subjects, what both ought to do, or as a panegyric to Hezekiah, who ruled well and saw something of the happy effects of his good government, and it was designed to make the people sensible how happy they were under his administration and how careful they...', 'teologico');
add('is', 32, 9, 'Matthew Henry', 'In these verses we have God rising up to judgment against the vile persons, to punish them for their villainy; but at length returning in mercy to the liberal, to reward them for their liberality.\nI. When there was so great a corruption of manners, and so much provocation given to the holy God, bad times might well be expected, and here is a warning given of such times coming. The alarm is sounded to the women that were at ease (Isa 32:9) and the careless daughters, to feed whose pride, vanit...', 'teologico');
add('is', 33, 1, 'Matthew Henry', 'Here we have,\nI. The proud and false Assyrian justly reckoned with for all his fraud and violence, and laid under a woe, Isa 33:1. Observe, 1. The sin which the enemy had been guilty of. He had spoiled the people of God, and made a prey of them, and herein had broken his treaty of peace with them, and dealt treacherously. Truth and mercy are two such sacred things, and have so much of God in them, that those cannot but be under the wrath of God that make conscience of neither, but are perfect...', 'teologico');
add('is', 33, 13, 'Matthew Henry', 'Here is a preface that commands attention; and it is fit that all should attend, both near and afar off, to what God says and does (Isa 33:13): Hear, you that are afar off, whether in place or time. Let distant regions and future ages hear what God has done. They do so; they will do so from the scripture, with as much assurance as those that were near, the neighbouring nations and those that lived at that time. But whoever hears what God has done, whether near or afar off, let them acknowledg...', 'teologico');
add('is', 34, 1, 'Matthew Henry', 'Here we have a prophecy, as elsewhere we have a history, of the wars of the Lord, which we are sure are all both righteous and successful. This world, as it is his creature, he does good to; but as it is in the interest of Satan, who is called the god of this world, he fights against it.\nI. Here is the trumpet sounded and the war proclaimed, Isa 34:1. All nations must hear and hearken, not only because what God is about to do is well worthy their remark (as Isa 33:13), but because they are al...', 'teologico');
add('is', 34, 9, 'Matthew Henry', 'This prophecy looks very black, but surely it looks so further than upon Edom and Bozrah. 1. It describes the melancholy changes that are often made by the divine Providence, in countries, cities, palaces, and families. Places that have flourished and been much frequented strangely go to decay. We know not where to find the places where many great towns, celebrated in history, once stood. Fruitful countries, in process of time, are turned into barrenness, and pompous populous cities into ruin...', 'teologico');
add('is', 35, 1, 'Matthew Henry', 'In these verses we have,\nI. The desert land blooming. In the foregoing chapter we had a populous and fruitful country turned into a horrid wilderness; here we have in lieu of that, a wilderness turned into a good land. When the land of Judah was freed from the Assyrian army, those parts of the country that had been made as a wilderness by the ravages and outrages they committed began to recover themselves, and to look pleasantly again, and to blossom as the rose. When the Gentile nations, tha...', 'teologico');
add('is', 35, 5, 'Matthew Henry', '"Then, when your God shall come, even Christ, to set up his kingdom in the world, to which all the prophets bore witness, especially towards the conclusion of their prophecies of the temporal deliverances of the church, and this evangelical prophet especially - then look for great things."\nI. Wonders shall be wrought in the kingdoms both of nature and grace, wonders of mercy wrought upon the children of men, sufficient to evince that it is no less than a God that comes to us. 1. Wonders shall...', 'teologico');
add('is', 36, 1, 'Matthew Henry', 'We shall here only observe some practical lessons. 1. A people may be in the way of their duty and yet meet with trouble and distress. Hezekiah was reforming, and his people were in some measure reformed; and yet their country is at that time invaded and a great part of it laid waste. Perhaps they began to grow remiss and cool in the work of reformation, were doing it by halves, and ready to sit down short of a thorough reformation; and then God visited them with this judgment, to put life in...', 'teologico');
add('is', 36, 11, 'Matthew Henry', 'We may hence learn these lessons: - 1. That, while princes and counsellors have public matters under debate, it is not fair to appeal to the people. It was a reasonable motion which Hezekiah\'s plenipotentiaries made, that this parley should be held in a language which the people did not understand (Isa 36:11), because reasons of state are secret things and ought to be kept secret, the vulgar being incompetent judges of them. It is therefore an unfair practice, and not doing as men would be do...', 'teologico');
add('is', 37, 1, 'Matthew Henry', 'We may observe here, 1. That the best way to baffle the malicious designs of our enemies against us is to be driven by them to God and to our duty and so to fetch meat out of the eater. Rabshakeh intended to frighten Hezekiah from the Lord, but it proves that he frightens him to the Lord. The wind, instead of forcing the traveller\'s coat from him, makes him wrap it the closer about him. The more Rabshakeh reproaches God the more Hezekiah studies to honour him, by rending his clothes for the d...', 'teologico');
add('is', 37, 8, 'Matthew Henry', 'We may observe here, 1. That, if God give us inward satisfaction in his promise, this may confirm us in our silently bearing reproaches. God answered Hezekiah, but it does not appear that he, after deliberation, sent any answer to Rabshakeh; but, God having taken the work into his own hands, he quietly left the matter with him. So Rabshakeh returned to the king his master for fresh instructions. 2. Those that delight in war shall have enough of it. Sennacherib, without provocation given to hi...', 'teologico');
add('is', 37, 21, 'Matthew Henry', 'We may here observe, 1. That those who receive messages of terror from men with patience, and send messages of faith to God by prayer, may expect messages of grace and peace from God for their comfort, even when they are most cast down. Isaiah sent a long answer to Hezekiah\'s prayer in God\'s name, sent it in writing (for it was too long to be sent by word of mouth), and sent it by way of return to his prayer, relation being thereunto had: "Whereas thou hast prayed to me, know, for thy comfort...', 'teologico');
add('is', 38, 1, 'Matthew Henry', 'We may hence observe, among others, these good lessons: - 1. That neither men\'s greatness nor their goodness will exempt them from the arrests of sickness and death. Hezekiah, a mighty potentate on earth and a mighty favourite of Heaven, is struck with a disease, which, without a miracle, will certainly be mortal; and this in the midst of his days, his comforts, and usefulness. Lord, behold, he whom thou lovest is sick. It should seem, this sickness seized him when he was in the midst of his ...', 'teologico');
add('is', 38, 9, 'Matthew Henry', 'We have here Hezekiah\'s thanksgiving-song, which he penned, by divine direction, after his recovery. He might have taken some of the psalms of his father David, and made use of them for his purpose; he might have found many very pertinent ones. He appointed the Levites to praise the Lord with the words of David, Ch2 29:30. But the occasion here was extraordinary, and, his heart being full of devout affections, he would not confine himself to the compositions he had, though of divine inspirati...', 'teologico');
add('is', 39, 1, 'Matthew Henry', 'Hence we may learn these lessons: - 1. That humanity and common civility teach us to rejoice with our friends and neighbours when they rejoice, and to congratulate them on their deliverances, and particularly their recoveries from sickness. The king of Babylon, having heard that Hezekiah had been sick, and had recovered, sent to compliment him upon the occasion. If Christians be unneighbourly, heathens will shame them. 2. It becomes us to give honour to those whom our God puts honour upon. Th...', 'teologico');
add('is', 39, 5, 'Matthew Henry', 'Hence let us observe, 1. That, if God love us, he will humble us, and will find some way or other to pull down our spirits when they are lifted up above measure. A mortifying message is sent to Hezekiah, that he might be humbled for the pride of his heart, and be convinced of the folly of it; for though God may suffer his people to fall into sin, as he did Hezekiah here, to prove him, that he might know all that was in his heart, yet he will not suffer them to lie still in it. 2. It is just w...', 'teologico');
add('is', 40, 1, 'Matthew Henry', 'We have here the commission and instructions given, not to this prophet only, but, with him, to all the Lord\'s prophets, nay, and to all Christ\'s ministers, to proclaim comfort to God\'s people. 1. This did not only warrant, but enjoin, this prophet himself to encourage the good people who lived in his own time, who could not but have very melancholy apprehensions of things when they saw Judah and Jerusalem by their daring impieties ripening apace for ruin, and God in his providence hastening ...', 'teologico');
add('is', 40, 9, 'Matthew Henry', 'It was promised (Isa 40:5) that the glory of the Lord shall be revealed; that is it with the hopes of which God\'s people must be comforted. Now here we are told,\nI. How it shall be revealed, Isa 40:9. 1. It shall be revealed to Zion and Jerusalem; notice shall be given of it to the remnant that are left in Zion and Jerusalem, the poor of the land, who were vine-dressers and husbandmen; it shall be told them that their brethren shall return to them. This shall be told also to the captives who ...', 'teologico');
add('is', 40, 12, 'Matthew Henry', 'The scope of these verses is to show what a great and glorious being the Lord Jehovah is, who is Israel\'s God and Saviour. It comes in here, 1. To encourage his people that were captives in Babylon to hope in him, and to depend upon him for deliverance, though they were ever so weak and their oppressors ever so strong. 2. To engage them to cleave to him, and not to turn aside after other gods; for there are none to be compared with him. 3. To possess all those who receive the glad tidings of ...', 'teologico');
add('is', 40, 18, 'Matthew Henry', 'The prophet here reproves those, 1. Who represented God by creatures, and so changed his truth into a lie and his glory into shame, who made images and then said that they resembled God, and paid their homage to them accordingly. 2. Who put creatures in the place of God, who feared them more than God, as if they were a match for him, or loved them more than God, as if they were fit to be rivals with him. Twice the challenge is here made, To whom will you liken God? Isa 40:18, and again Isa 40...', 'teologico');
add('is', 40, 27, 'Matthew Henry', 'Here, I. The prophet reproves the people of God, who are now supposed to be captives in Babylon for their unbelief and distrust of God, and the dejections and despondencies of their spirit under their affliction (Isa 40:27): "Why sayest thou, O Jacob! to thyself and to those about thee, My way is hidden from the Lord? Why dost thou make hard and melancholy conclusions concerning thyself and thy present case as if the latter were desperate?" 1. The titles he here gives them were enough to sham...', 'teologico');
add('is', 41, 1, 'Matthew Henry', 'That particular instance of God\'s care for his people Israel in raising up Cyrus to be their deliverer is here insisted upon as a great proof both of his sovereignty above all idols and of his power to protect his people. Here is,\nI. A general challenge to the worshippers and admirers of idols to make good their pretensions, in competition with God and opposition to him, Isa 41:1. Is is renewed (Isa 41:21): Produce your cause. The court is set, summonses are sent to the islands that lay most ...', 'teologico');
add('is', 41, 10, 'Matthew Henry', 'The scope of these verses is to silence the fears, and encourage the faith, of the servants of God in their distresses. Perhaps it is intended, in the first place, for the support of God\'s Israel, in captivity; but all that faithfully serve God through patience and comfort of this scripture may have hope. And it is addressed to Israel as a single person, that it might the more easily and readily be accommodated and applied by every Israelite indeed to himself. That is a word of caution, couns...', 'teologico');
add('is', 41, 21, 'Matthew Henry', 'The Lord, by the prophet, here repeats the challenge to idolaters to make out the pretentions of their idols: "Produce your cause (Isa 41:21) and make your best of it; bring forth the strongest reasons you have to prove that your idols are gods, and worthy of your adoration." Note, There needs no more to show the absurdity of sin than to produce the reasons that are given in defence of it, for they carry with them their own confutation.\nI. The idols are here challenged to bring proofs of thei...', 'teologico');
add('is', 42, 5, 'Matthew Henry', 'Here is I. The covenant God made with and the commission he gave to the Messiah, Isa 42:5-7, which are an exposition of Isa 42:1, Behold my servant, whom I uphold.\n1. The royal titles by which the great God here makes himself known, and distinguishes himself from all pretenders, speak very much his glory (Isa 42:5): Thus saith God the Lord. And who are thou, Lord? Why, he is the fountain of all being and therefore the fountain of all power. He is the fountain of being, 1. In the upper world; ...', 'teologico');
add('is', 42, 13, 'Matthew Henry', 'It comes all to one whether we make these verses (as some do) the song itself that is to be sung by the Gentile world or a prophecy of what God will do to make way for the singing of that song, that evangelical new song.\nI. He will appear in his power and glory more than ever. So he did in the preaching of his gospel, in the divine power and energy which went along with it, and in the wonderful success it had in the pulling down of Satan\'s stronghold, Isa 42:13, Isa 42:14. He had long held hi...', 'teologico');
add('is', 42, 18, 'Matthew Henry', 'The prophet, having spoken by way of comfort and encouragement to the believing Jews who waited for the consolation of Israel, here turns to those among them who were unbelieving, for their conviction and humiliation. Among those who were in captivity in Babylon there were some who were as the evil figs in Jeremiah\'s vision, who were sent thither for their hurt, to be removed into all the kingdoms of the earth, for a reproach and a proverb, Jer 24:9. In them there was a type of the Jews who r...', 'teologico');
add('is', 43, 1, 'Matthew Henry', 'This chapter has a plain connexion with the close of the foregoing chapter, but a very surprising one. It was there said that Jacob and Israel would not walk in God\'s ways, and that when he corrected them for their disobedience they were stubborn and laid it not to heart; and now one would think it should have followed that God would utterly abandon and destroy them; but no, the next words are, But now, fear not, O Jacob! O Israel! I have redeemed thee, and thou art mine. Though many among th...', 'teologico');
add('is', 43, 8, 'Matthew Henry', 'God here challenges the worshippers of idols to produce such proofs of the divinity of their false gods as even this very instance (to go no further) of the redemption of the Jews out of Babylon furnished the people of Israel with, to prove that their God is the true and living God, and he only.\nI. The patrons of idolatry are here called to appear, and say what they have to say in defence of their idols, Isa 43:8, Isa 43:9. Their gods have eyes and see not, ears and hear not, and those that m...', 'teologico');
add('is', 43, 14, 'Matthew Henry', 'To so low an ebb were the faith and hope of God\'s people in Babylon brought that there needed line upon line to assure them that they should be released out of their captivity; and therefore, that they might have strong consolation, the assurances of it are often repeated, and here very expressly and encouragingly.\nI. God here takes to himself such titles of his honour as were very encouraging to them. He is the Lord their Redeemer, not only he will redeem them, but will take it upon him as h...', 'teologico');
add('is', 43, 22, 'Matthew Henry', 'This charge (and a high charge it is which is here exhibited against Jacob and Israel, God\'s professing people) comes in here, 1. To clear God\'s justice in bringing them into captivity, and to vindicate that. Were they not in covenant with him? Had they not his sanctuary among them? Why then did the Lord deal thus with his land? Deu 29:24. Here is a good reason given: they had neglected God and had cast him off, and therefore he justly rejected them and gave them to the curse (Isa 43:28); and...', 'teologico');
add('is', 44, 1, 'Matthew Henry', 'Two great truths are abundantly made out in these verses: - \nI. That the people of God are a happy people, especially upon account of the covenant that is between them and God. The people of Israel were so as a figure of the gospel Israel. Three things complete their happiness: - \n1. The covenant-relations wherein they stand to God, Isa 44:1, Isa 44:2. Israel is here called Jeshurun - the upright one; for those only, like Nathanael, are Israelites indeed, in whom is no guile, and those only s...', 'teologico');
add('is', 44, 9, 'Matthew Henry', 'Often before, God, by the prophet, had mentioned the folly and strange sottishness of idolaters; but here he enlarges upon that head, and very fully and particularly exposes them to contempt and ridicule. This discourse is intended, 1. To arm the people of Israel against the strong temptation they would be in to worship idols when they were captives in Babylon, in compliance with the custom of the country (they being far from the city of their own solemnities) and to humour those who were now...', 'teologico');
add('is', 44, 21, 'Matthew Henry', 'In these verses we have,\nI. The duty which Jacob and Israel, now in captivity, were called to, that they might be qualified and prepared for the deliverance designed them. Our first care must be to get good by our afflictions, and then we may hope to get out of them. The duty is expressed in two words: Remember and return, as in the counsel to Ephesus, Rev 2:4, Rev 2:5. 1. "Remember these, O Jacob! Remember what thou hast been told of the folly of idolatry, and let the convictions thou art no...', 'teologico');
add('is', 45, 1, 'Matthew Henry', 'Cyrus was a Mede, descended (as some say) from Astyages king of Media. The pagan writers are not agreed in their accounts of his origin. Some tell us that in his infancy he was an outcast, left exposed, and was saved from perishing by a herdsman\'s wife. However, it is agreed that, being a man of an active genius, he soon made himself very considerable, especially when Croesus king of Lydia made a descent upon his country, which he not only repulsed, but revenged, prosecuting the advantages he...', 'teologico');
add('is', 45, 5, 'Matthew Henry', 'God here asserts his sole and sovereign dominion, as that which he designed to prove and manifest to the world in all the great things he did for Cyrus and by him. Observe,\nI. How this doctrine is here laid down concerning the sovereignty of the great Jehovah, in two things: - 1. That he is God alone, and there is no God besides him. This is here inculcated as a fundamental truth, which, if it were firmly believed, would abolish idolatry out of the world. With what an awful, commanding, air o...', 'teologico');
add('is', 45, 11, 'Matthew Henry', 'The people of God in captivity, who reconciled themselves to the will of God in their affliction and were content to wait his time for their deliverance, are here assured that they should not wait in vain.\nI. They are invited to enquire concerning the issue of their troubles, Isa 45:11. The Holy One of Israel, and his Maker, though he does not allow them to strive with him, yet encourages them, 1. To consult his word: "Ask of me things to come; have recourse to the prophets and their propheci...', 'teologico');
add('is', 45, 20, 'Matthew Henry', 'What here is said is intended, as before,\nI. For the conviction of idolators, to show them their folly in worshipping gods that cannot help them, and neglecting a God that can. Let all that have escaped of the nations, not only the people of the Jews, but those of other nations that were by Cyrus released out of captivity in Babylon, let them come, and hear what is to be said against the worshipping of idols, that they may be cured of it as well as the Jews, that Babylon, which had of old bee...', 'teologico');
add('is', 46, 1, 'Matthew Henry', 'We are here told,\nI. That the false gods will certainly fail their worshippers when they have most need of them, Isa 46:1, Isa 46:2. Bel and Nebo were two celebrated idols of Babylon. Some make Bel to be a contraction of Baal; others rather think not, but that it was Belus, one of their first kings, who after his death was deified. As Bel was a deified prince, so (some think) Nebo was a deified prophet, for so Nebo signifies; so that Bel and Nebo were their Jupiter and their Mercury or Apollo...', 'teologico');
add('is', 46, 5, 'Matthew Henry', 'The deliverance of Israel by the destruction of Babylon (the general subject of all these chapters) is here insisted upon, and again promised, for the conviction both of idolaters who set up as rivals with God, and of oppressors who were enemies to the people of God.\nI. For the conviction of those who made and worshipped idols, especially those of Israel who did so, who would have images of their God, as the Babylonians had of theirs,\n1. He challenges them either to frame an image that should...', 'teologico');
add('is', 47, 1, 'Matthew Henry', 'In these verses God by the prophet sends a messenger even to Babylon, like that of Jonah to Nineveh: "The time is at hand when Babylon shall be destroyed." Fair warning is thus given her, that she may by repentance prevent the ruin and there may be a lengthening of her tranquility. We may observe here,\nI. God\'s controversy with Babylon. We will begin with that, for there all the calamity begins; she has made God her enemy, and then who can befriend her: Let her know that the righteous Judge, ...', 'teologico');
add('is', 47, 7, 'Matthew Henry', 'Babylon, now doomed to ruin, is here justly upbraided with her pride, luxury, and security, in the day of her prosperity, and the confidence she had in her own wisdom and forecast, and particularly in the prognostications and counsels of the astrologers. These things are mentioned both to justify God in bringing these judgments upon her and to mortify her, and put her to so much the greater shame, under these judgments; for, when God comes forth to take vengeance, glory belongs to him, but co...', 'teologico');
add('is', 48, 1, 'Matthew Henry', 'We may observe here,\nI. The hypocritical profession which many of the Jews made of religion and relation to God. To those who made such a profession the prophet is here ordered to address himself, for their conviction and humiliation, that they might own God\'s justice in what he had brought upon them. Now observe here,\n1. How high their profession of religion soared, what a fair show they made in the flesh and how far they went towards heaven, what a good livery they wore and what a good face...', 'teologico');
add('is', 48, 9, 'Matthew Henry', 'The deliverance of God\'s people out of their captivity in Babylon was a thing upon many accounts so improbable that there was need of line upon line for the encouragement of the faith and hope of God\'s people concerning it. Two things were discouraging to them - their own unworthiness that God should do it for them and the many difficulties in the thing itself; now, in these verses, both these discouragements are removed, for here is,\nI. A reason why God would do it for them, though they were...', 'teologico');
add('is', 48, 16, 'Matthew Henry', 'Here, as before, Jacob and Israel are summoned to hearken to the prophet speaking in God\'s name, or rather to God speaking in and by the prophet, and that as a type of the great prophet by whom God has in these last days spoken unto us, and that is sufficient: Come near therefore, and hear this. Note, Those that would hear and understand what God says must come near, and approach to him; let them come as near as they can. Let those that have hearkened to the tempter now come near, and hear th...', 'teologico');
add('is', 49, 1, 'Matthew Henry', 'Here, I. An auditory is summoned together and attention demanded. The sermon in the foregoing chapter was directed to the house of Jacob and the people of Israel, Isa 49:1, Isa 49:12. But this is directed to the isles (that is, the Gentiles, for they are called the isles of the Gentiles, Gen 10:5) and to the people from far, that were strangers to the commonwealth of Israel, and afar off. Let these listen (Isa 49:1) as to a thing at a distance, which yet they are to hear with desire and atten...', 'teologico');
add('is', 49, 7, 'Matthew Henry', 'In these verses we have,\nI. The humiliation and exaltation of the Messiah (Isa 49:7): The Lord, the Redeemer of Israel, and Israel\'s Holy One, who had always taken care of the Jewish church and wrought out for them those deliverances that were typical of the great salvation, speaks here to him, who was the undertaker of that salvation. And, 1. He takes notice of his humiliation, the instances of which were uncommon, nay, unparalleled. He was one whom man despised. He is despised and rejected ...', 'teologico');
add('is', 49, 13, 'Matthew Henry', 'The scope of these verses is to show that the return of the people of God out of their captivity, and the eternal redemption to be wrought out by Christ (of which that was a type), would be great occasions of joy to the church and great proofs of the tender care God has of the church.\nI. Nothing can furnish us with better matter for songs of praise and thanksgiving, Isa 49:13. Let the whole creation join with us in songs of joy, for it shares with us in the benefits of the redemption, and all...', 'teologico');
add('is', 49, 18, 'Matthew Henry', 'Two things are here promised, which were to be in part accomplished in the reviving of the Jewish church after its return out of captivity, but more fully in the planting of the Christian church by the preaching of the gospel of Christ; and we may take the comfort of these promises.\nI. That the church shall be replenished with great numbers added to it. It was promised (Isa 49:17) that her children should make haste; that promise is here enlarged upon, and is made very encouraging. It is prom...', 'teologico');
add('is', 49, 24, 'Matthew Henry', 'Here is, I. An objection started against the promise of the Jews\' release out of their captivity in Babylon, suggesting that it was a thing not to be expected; for (Isa 49:24) they were a prey in the hand of the mighty, of such as were then the greatest potentates on earth, and therefore it was not likely they should be rescued by force. Yet that was not all: they were lawful captives; by the law of God, having offended, they were justly delivered into captivity; and by the law of nations, be...', 'teologico');
add('is', 50, 1, 'Matthew Henry', 'Those who have professed to be the people of God, and yet seem to be dealt severely with, are apt to complain of God, and to lay the fault upon him, as if he had been hard with them. But, in answer to their murmurings, we have here,\nI. A challenge given them to prove, or produce any evidence, that the quarrel began on God\'s side, Isa 50:1. They could not say that he had done them any wrong or had acted arbitrarily. 1. He had been a husband to them; and husbands were then allowed a power to pu...', 'teologico');
add('is', 50, 4, 'Matthew Henry', 'Our Lord Jesus, having proved himself able to save, here shows himself as willing as he is able to save, here shows himself as willing as he is able. We suppose the prophet Isaiah to say something of himself in these verses, engaging and encouraging himself to go on in his work as a prophet, notwithstanding the many hardships he met with, not doubting but that God would stand by him and strengthen him; but, like David, he speaks of himself as a type of Christ, who is here prophesied of and pr...', 'teologico');
add('is', 50, 10, 'Matthew Henry', 'The prophet, having the tongue of the learned given him, that he might give to every one his portion, here makes use of it, rightly dividing the word of truth. It is the summary of the gospel. He that believes shall be saved (he that trusts in the name of the Lord shall be comforted, though for a while he walk in darkness and have no light), but he that believes not shall be damned; though for a while he walk in the light of his own fire, yet he shall lie down in sorrow.\nI. Comfort is here sp...', 'teologico');
add('is', 51, 1, 'Matthew Henry', 'Observe, 1. How the people of God are here described, to whom the word of this consolation is sent and who are called upon to hearken to it, Isa 51:1. They are such as follow after righteousness, such as are very desirous and solicitous both to be justified and to be sanctified, are pressing hard after this, to have the favour of God restored to them and the image of God renewed on them. These are those that seek the Lord, for it is only in the say of righteousness that we can seek him with a...', 'teologico');
add('is', 51, 4, 'Matthew Henry', 'Both these proclamations, as I may call them, end alike with an assurance of the perpetuity of God\'s righteousness and his salvation; and therefore we put them together, both being designed for the comfort of God\'s people. Observe,\nI. Who they are to whom this comfort belongs: "My people, and my nation, that I have set apart for myself, that own me and are owned by me." Those are God\'s people and his nation who are subject to him as their King and their God, pay allegiance to him, and put the...', 'teologico');
add('is', 51, 9, 'Matthew Henry', 'In these verses we have,\nI. A prayer that God would, in his providence, appear and act for the deliverance of his people and the mortification of his and their enemies. Awake, awake! put on strength, O arm of the Lord! Isa 51:9. The arm of the Lord is Christ, or it is put for God himself, as Psa 44:23. Awake! why sleepest thou? He that keeps Israel neither slumbers nor sleeps; but, when we pray that he would awake, we mean that he would make it to appear that he watches over his people and is...', 'teologico');
add('is', 51, 17, 'Matthew Henry', 'God, having awoke for the comfort of his people, here calls upon them to awake, as afterwards, Isa 52:1. It is a call to awake not so much out of the sleep of sin (though that also is necessary in order to their being ready for deliverance) as out of the stupor of despair. When the inhabitants of Jerusalem were in captivity they, as well as those who remained upon the spot, were so overwhelmed with the sense of their troubles that they had no heart or spirit to mind any thing that tended to t...', 'teologico');
add('is', 52, 1, 'Matthew Henry', 'Here, I. God\'s people are stirred up to appear vigorous for their own deliverance, Isa 52:1, Isa 52:2. They had desired that God would awake and put on his strength, Isa 51:9. Here he calls upon them to awake and put on their strength, to bestir themselves; let them awake from their despondency, and pluck up their spirits, encourage themselves and one another with the hope that all will be well yet, and no longer succumb and sink under their burden. Let them awake from their distrust, look ab...', 'teologico');
add('is', 52, 7, 'Matthew Henry', 'The removal of the Jews from Babylon to their own land again is here spoken of both as a mercy and as a duty; and the application of Isa 52:7 to the preaching of the gospel (by the apostle, Rom 10:15) plainly intimates that that deliverance was a type and figure of the redemption of mankind by Jesus Christ, to which what is here said of their redemption out of Babylon ought to be accommodated.\nI. It is here spoken of as a great blessing, which ought to be welcomed with abundance of joy and th...', 'teologico');
add('is', 52, 13, 'Matthew Henry', 'Here, as in other places, for the confirming of the faith of God\'s people and the encouraging of their hope in the promises of temporal deliverances, the prophet passes from them to speak of the great salvation which should in the fulness of time be wrought out by the Messiah. As the prophecy of Christ\'s incarnation was intended for the ratification of the promise of their deliverance from the Assyrian army, so this of Christ\'s death and resurrection is to confirm the promise of their return ...', 'teologico');
add('is', 53, 1, 'Matthew Henry', 'The prophet, in the close of the former chapter, had foreseen and foretold the kind reception which the gospel of Christ should find among the Gentiles, that nations and their kings should bid it welcome, that those who had not seen him should believe in him; and though they had not any prophecies among them of gospel grace, which might raise their expectations, and dispose them to entertain it, yet upon the first notice of it they should give it its due weight and consideration. Now here he ...', 'teologico');
add('is', 53, 4, 'Matthew Henry', 'In these verses we have,\nI. A further account of the sufferings of Christ. Much was said before, but more is said here, of the very low condition to which he abased and humbled himself, to which he became obedient even to the death of the cross. 1. He had griefs and sorrows; being acquainted with them, he kept up the acquaintance, and did not grow shy, no, not of such melancholy acquaintance. Were griefs and sorrows allotted him? He bore them, and blamed not his lot; he carried them, and did ...', 'teologico');
add('is', 54, 1, 'Matthew Henry', 'If we apply this to the state of the Jews after their return out of captivity, it is a prophecy of the increase of their nation after they were settled in their own land. Jerusalem had been in the condition of a wife written childless, or a desolate solitary widow; but now it is promised that the city should be replenished and the country peopled again, that not only the ruins of Jerusalem should be repaired, but the suburbs of it extended on all sides and a great many buildings erected upon ...', 'teologico');
add('is', 54, 6, 'Matthew Henry', 'The seasonable succour and relief which God sent to his captives in Babylon, when they had a discharge from their bondage there, are here foretold, as a type and figure of all those consolations of God which are treasured up for the church in general and all believers in particular, in the covenant of grace.\nI. Look back to former troubles, and in comparison with them God\'s favours to his people appear very comfortable, Isa 54:6-8. Observe, 1. How sorrowful the church\'s condition had been. Sh...', 'teologico');
add('is', 54, 11, 'Matthew Henry', 'Very precious promises are here made to the church in her low condition, that God would not only continue his love to his people under their troubles as before, but that he would restore them to their former prosperity, nay, that he would raise them to greater prosperity than any they had yet enjoyed. In the foregoing chapter we had the humiliation and exaltation of Christ; here we have the humiliation and exaltation of the church; for, if we suffer with him, we shall reign with him. Observe,...', 'teologico');
add('is', 55, 1, 'Matthew Henry', 'Here, I. We are all invited to come and take the benefit of that provision which the grace of God has made for poor souls in the new covenant, of that which is the heritage of the servants of the Lord (Isa 54:17), and not only their heritage hereafter, but their cup now, Isa 55:1. Observe,\n1. Who are invited: Ho, every one. Not the Jews only, to whom first the word of salvation was sent, but the Gentiles, the poor and the maimed, the halt and the blind, are called to this marriage supper, who...', 'teologico');
add('is', 55, 6, 'Matthew Henry', 'We have here a further account of that covenant of grace which is made with us in Jesus Christ, both what is required and what is promised in the covenant, and of those considerations that are sufficient abundantly to confirm our believing compliance with and reliance on that covenant. This gracious discovery of God\'s good-will to the children of men is not to be confined either to the Jew or to the Gentile, to the Old Testament or to the New, much less to the captives in Babylon. No, both th...', 'teologico');
add('is', 56, 1, 'Matthew Henry', 'The scope of these verses is to show that when God is coming towards us in a way of mercy we must go forth to meet him in a way of duty.\nI. God here tells us what are his intentions of mercy to us (Isa 56:1): My salvation is near to come - the great salvation wrought out by Jesus Christ (for that was the salvation of which the prophets enquired and searched diligently, Pe1 1:10), typified by the salvation of the Jews from Sennacherib or out of Babylon. Observe, 1. The gospel salvation is the ...', 'teologico');
add('is', 56, 3, 'Matthew Henry', 'The prophet is here, in God\'s name, encouraging those that were hearty in joining themselves to God and yet laboured under great discouragements. 1. Some were discouraged because they were not of the seed of Abraham. They had joined themselves to the Lord, and bound their souls with a bond to be his for ever (this is the root and life of religion, to break off from the world and the flesh, and devote ourselves entirely to the service and honour of God); but they questioned whether God would a...', 'teologico');
add('is', 56, 9, 'Matthew Henry', 'From words of comfort the prophet here, by a very sudden change of his style, passes to words of reproof and conviction, and goes on in that strain, for the most part, in the three following chapters; and therefore some here begin a new sermon. He had assured the people that in due time God would deliver them out of captivity, which was designed for the comfort of those that should live when God would do this. Now here he shows what their sins and provocations were, for which God would send t...', 'teologico');
add('is', 57, 1, 'Matthew Henry', 'The prophet, in the close of the foregoing chapter, had condemned the watchmen for their ignorance and sottishness; here he shows the general stupidity and senselessness of the people likewise. No wonder they were inconsiderate when their watchmen were so, who should have awakened them to consideration. We may observe here,\nI. The providence of God removing good men apace out of this world. The righteous, as to this world, perish; they are gone and their place knows them no more. Piety exempt...', 'teologico');
add('is', 57, 3, 'Matthew Henry', 'We have here a high charge, but a just one no doubt, drawn up against that wicked generation out of which God\'s righteous ones were removed, because the world was not worthy of them. Observe,\nI. The general character here given of them, or the name and title by which they stand indicted, Isa 57:3. They are told to draw near and hear the charge, are set to the bar, and arraigned there as sons of the sorceress, or of a witch, the seed of an adulterer and a whore, that is, they were such themsel...', 'teologico');
add('is', 57, 13, 'Matthew Henry', 'Here, I. God shows how insufficient idols and creatures were to relieve and succour those that worshipped them and confided in them (Isa 57:13): "When thou criest in thy distress and anguish, lamentest thy misery and callest for help, let thy companies deliver thee, thy idol-gods which thou hast heaped to thyself companies of, the troops of the confederate forces which thou hast relied so much upon, let them deliver thee if they can; expect no other relief than what they can give." Thus God s...', 'teologico');
add('is', 57, 17, 'Matthew Henry', 'The body of the people of Israel, in this account of God\'s dealings with them, is spoken of as a particular person (Isa 57:17, Isa 57:18), but divided into two sorts, differently dealt with - some who were sons of peace, to whom peace is spoken (Isa 57:19), and others who were not, who have nothing to do with peace, Isa 57:20, Isa 57:21. Observe here,\nI. The just rebukes which that people were brought under for their sin: For the iniquity of his covetousness I was wroth, and smote him. Coveto...', 'teologico');
add('is', 58, 1, 'Matthew Henry', 'When our Lord Jesus promised to send the Comforter he added, When he shall come he shall convince (Joh 16:7, Joh 16:8); for conviction must prepare for comfort, and must also separate between the precious and the vile, and mark out those to whom comfort does not belong. God had appointed this prophet to comfort his people (Isa 40:1); here he appoints him to convince them, and show them their sins.\nI. He must tell them how very bad they really were, Isa 58:1. 1. He must deal faithfully and pla...', 'teologico');
add('is', 58, 3, 'Matthew Henry', 'Here we have, I. The displeasure which these hypocrites conceived against God for not accepting the services which they themselves had a mighty opinion of (Isa 58:3): Wherefore have we fasted, say they, and thou seest not? Thus they went in the way of Cain, who was angry at God, and resented it as a gross affront that his offering was not accepted. Having gone about to put a cheat upon God by their external services, here they go about to pick a quarrel with God for not being pleased with the...', 'teologico');
add('is', 58, 8, 'Matthew Henry', 'Here are precious promises for those to feast freely and cheerfully upon by faith who keep the fast that God has chosen; let them know that God will make it up to them. Here is,\nI. A further account of the duty to be done in order to our interest in these promises (Isa 58:9, Isa 58:10); and here, as before, it is required that we both do justly and love mercy, that we cease to do evil and learn to do well. 1. We must abstain from all acts of violence and fraud. "Those must be taken away from ...', 'teologico');
add('is', 58, 13, 'Matthew Henry', 'Great stress was always laid upon the due observance of the sabbath day, and it was particularly required from the Jews when they were captives in Babylon, because by keeping that day, in honour of the Creator, they distinguished themselves from the worshippers of the gods that have not made the heavens and the earth. See Isa 56:1, Isa 56:2, where keeping the sabbath is joined, as here, with keeping judgment and doing justice. Some, indeed, understand this of the day of atonement, which they ...', 'teologico');
add('is', 59, 1, 'Matthew Henry', 'The prophet here rectifies the mistake of those who had been quarrelling with God because they had not the deliverances wrought for them which they had been often fasting and praying for, Isa 58:3. Now here he shows,\nI. That it was not owing to God. They had no reason to lay the fault upon him that they were not saved out of the hands of their enemies; for, 1. He was still as able to help as ever: His hand is not shortened, his power is not at all lessened, straitened, or abridged. Whether we...', 'teologico');
add('is', 59, 9, 'Matthew Henry', 'The scope of this paragraph is the same with that of the last, to show that sin is the great mischief-maker; as it is that which keeps good things from us, so it is that which brings evil things upon us. But as there it is spoken by the prophet, in God\'s name, to the people, for their conviction and humiliation, and that God might be justified when he speaks and clear when he judges, so here it seems to be spoken by the people to God, as an acknowledgment of that which was there told them and...', 'teologico');
add('is', 59, 16, 'Matthew Henry', 'How sin abounded we have read, to our great amazement, in the former part of the chapter; how grace does much more abound we read in these verses. And, as sin took occasion from the commandment to become more exceedingly sinful, so grace took occasion from the transgression of the commandment to appear more exceedingly gracious. Observe,\nI. Why God wrought salvation for this provoking people, notwithstanding their provocations. It was purely for his own name\'s sake; because there was nothing ...', 'teologico');
add('is', 60, 1, 'Matthew Henry', 'It is here promised that the gospel temple shall be very lightsome and very large.\nI. It shall be very lightsome: Thy light has come. When the Jews returned out of captivity they had light and gladness, and joy and honour; they then were made to know the Lord and to rejoice in his great goodness; and upon both accounts their light came. When the Redeemer came to Zion he brought light with him, he himself came to be a light. Now observe, 1. What this light is, and whence it springs: The Lord s...', 'teologico');
add('is', 60, 9, 'Matthew Henry', 'The promises made to the church in the foregoing verses are here repeated, ratified, and enlarged upon, designed still for the comfort and encouragement of the Jews after their return out of captivity, but certainly looking further, to the enlargement and advancement of the gospel church and the abundance of spiritual blessings with which it shall be enriched.\nI. God will be very gracious and propitious to them. We must begin with that promise, because thence all the rest take rise. The sanct...', 'teologico');
add('is', 60, 15, 'Matthew Henry', 'The happy and glorious state of the church is here further foretold, referring principally and ultimately to the Christian church and the spiritual peace of that, but under the type of that little gleam of outward peace which the Jews sometimes enjoyed after their return out of captivity. This is here spoken of,\nI. As compared with what it had been. This made her peace and honour the more pleasant, that her condition had been much otherwise.\n1. She had been despised, but now she should be hon...', 'teologico');
add('is', 61, 1, 'Matthew Henry', 'He that is the best expositor of scripture has no doubt given us the best exposition of these verses, even our Lord Jesus himself, who read this in the synagogue at Nazareth (perhaps it was the lesson for the day) and applied it entirely to himself, saying, This day is this scripture fulfilled in your ears (Luk 4:17, Luk 4:18, Luk 4:21); and the gracious words which proceeded out of his mouth, in the opening of this text, were admired by all that heard them. As Isaiah was authorized and direc...', 'teologico');
add('is', 61, 4, 'Matthew Henry', 'Promises are here made to the Jews now returned out of captivity, and settled again in their own land, which are to be extended to the gospel church, and all believers, who through grace are delivered out of spiritual thraldom; for they are capable of being spiritually applied.\nI. It is promised that their houses shall be rebuilt (Isa 61:4), that their cities shall be raised out of the ruins in which they had long lain, and be fitted up for their use again: They shall build the old wastes; th...', 'teologico');
add('is', 61, 10, 'Matthew Henry', 'Some make this the song of joy and praise to be sung by the prophet in the name of Jerusalem, congratulating her on the happy change of her circumstances in the accomplishment of the foregoing promises; others make it to be spoken by Christ in the name of the New Testament church triumphing in gospel grace. We may take in both, the former as a type of the latter. We are here taught to rejoice with holy joy, to God\'s honour, 1. In the beginning of this good work, the clothing of the church wit...', 'teologico');
add('is', 62, 1, 'Matthew Henry', 'The prophet here tells us,\nI. What he will do for the church. A prophet, as he is a seer, so he is a spokesman. This prophet resolves to perform that office faithfully, Isa 62:1. He will not hold his peace; he will not rest; he will mind his business, will take pains, and never desire to take his ease; and herein he was a type of Christ, who was indefatigable in executing the office of a prophet and made it his meat and drink till he had finished his work. Observe here, 1. What the prophet\'s ...', 'teologico');
add('is', 62, 6, 'Matthew Henry', 'Two things are here promised to Jerusalem: - \nI. Plenty of the means of grace - abundance of good preaching and good praying (Isa 62:6, Isa 62:7), and this shows the method God takes when he designs mercy for a people; he first brings them to their duty and pours out a spirit of prayer upon them, and then brings salvation to them. Provision is made,\n1. That ministers may do their duty as watchmen. It is here spoken of as a token for good, as a step towards further mercy and an earnest of it, ...', 'teologico');
add('is', 62, 10, 'Matthew Henry', 'This, as many like passages before, refers to the deliverance of the Jews out of Babylon, and, under the type and figure of that, to the great redemption wrought out by Jesus Christ, and the proclaiming of gospel grace and liberty through him. 1. Way shall be made for this salvation; all difficulties shall be removed, and whatever might obstruct it shall be taken out of the way, Isa 62:10. The gates of Babylon shall be thrown open, that they may with freedom go through them; the way from Baby...', 'teologico');
add('is', 63, 1, 'Matthew Henry', 'It is a glorious victory that is here enquired into first and then accounted for. 1. It is a victory obtained by the providence of God over the enemies of Israel; over the Babylonians (say some), whom Cyrus conquered and God by him, and they will have the prophet to make the first discovery of him in his triumphant return when he is in the country of Edom: but this can by no means be admitted, because the country of Babylon is always spoken of as the land of the north, whereas Edom lay south ...', 'teologico');
add('is', 63, 7, 'Matthew Henry', 'The prophet is here, in the name of the church, taking a review, and making a thankful recognition, of God\'s dealings with his church all along, ever since he founded it, before he comes, in the latter end of this chapter and in the next, as a watchman upon the walls, earnestly to pray to God for his compassion towards her in her present deplorable state; and it was usual for God\'s people, in their prayers, thus to look back.\nI. Here is a general acknowledgment of God\'s goodness to them all a...', 'teologico');
add('is', 63, 15, 'Matthew Henry', 'The foregoing praises were intended as an introduction to this prayer, which is continued to the end of the next chapter, and it is an affectionate, importunate, pleading prayer. It is calculated for the time of the captivity. As they had promises, so they had prayers, prepared for them against that time of need, that they might take with them words in turning to the Lord, and say unto him what he himself taught them to say, in which they might the better hope to prevail, the words being of G...', 'teologico');
add('is', 64, 1, 'Matthew Henry', 'Here, I. The petition is that God would appear wonderfully for them now, Isa 64:1, Isa 64:2. Their case was represented in the close of the foregoing chapter as very sad and very hard, and in this case it was time to cry, "Help, Lord; O that God would manifest his zeal and his strength!" They had prayed (Isa 63:15) that God would look down from heaven; here they pray that he would come down to deliver them, as he had said, Exo 3:8. 1. They desire that God would in his providence manifest hims...', 'teologico');
add('is', 64, 6, 'Matthew Henry', 'As we have the Lamentations of Jeremiah, so here we have the Lamentations of Isaiah; the subject of both is the same - the destruction of Jerusalem by the Chaldeans and the sin of Israel that brought that destruction - only with this difference, Isaiah sees it at a distance and laments it by the Spirit of prophecy, Jeremiah saw it accomplished. In these verses,\nI. The people of God in their affliction confess and bewail their sins, thereby justifying God in their afflictions, owning themselve...', 'teologico');
add('is', 65, 1, 'Matthew Henry', 'The apostle Paul (an expositor we may depend upon) has given us the true sense of these verses, and told us what was the event they pointed at and were fulfilled in, namely, the calling in of the Gentiles and the rejection of the Jews, by the preaching of the gospel, Rom 10:20, Rom 10:21. And he observes that herein Esaias is very bold, not only in foretelling a thing so improbable ever to be brought about, but in foretelling it to the Jews, who would take it as a gross affront to their natio...', 'teologico');
add('is', 65, 8, 'Matthew Henry', 'This is expounded by St. Paul, Rom 11:1-5, where, when, upon occasion of the rejection of the Jews, it is asked, Hath God then cast away his people? he answers, No; for at this time there is a remnant according to the election of grace. This prophecy has reference to that distinguished remnant. When that hypocritical nation is to be destroyed God will separate and secure to himself some from among them; some of the Jews shall be brought to embrace the Christian faith, shall be added to the ch...', 'teologico');
add('is', 65, 11, 'Matthew Henry', 'Here the different states of the godly and wicked, of the Jews that believed and of those that still persisted in unbelief, are set the one over - against the other, as life and death, good and evil, the blessing and the curse.\nI. Here is the fearful doom of those that persisted in their idolatry after the deliverance out of Babylon, and in infidelity after the preaching of the gospel of Christ. Observe,\n1. What the doom is that is here threatened: "I will number you to the sword as sheep for...', 'teologico');
add('is', 65, 17, 'Matthew Henry', 'If these promises were in part fulfilled when the Jews, after their return out of captivity, were settled in peace in their own land and brought as it were into a new world, yet they were to have their full accomplishment in the gospel church, militant first and at length triumphant. The Jerusalem that is from above is free and is the mother of us all. In the graces and comforts which believers have in and from Christ we are to look for this new heaven and new earth. It is in the gospel that ...', 'teologico');
add('is', 66, 1, 'Matthew Henry', 'Here, I. The temple is slighted in comparison with a gracious soul, Isa 66:1, Isa 66:2. The Jews in the prophet\'s time, and afterwards in Christ\'s time, gloried much in the temple and promised themselves great things from it; to humble them therefore, and to shake their vain confidence, both the prophets and Christ foretold the ruin of the temple, that God would leave it and then it would soon be desolate. After it was destroyed by the Chaldeans it soon recovered itself and the ceremonial ser...', 'teologico');
add('is', 66, 5, 'Matthew Henry', 'The prophet, having denounced God\'s judgments against a hypocritical nation, that made a jest of God\'s word and would not answer him when he called to them, here turns his speech to those that trembled at his word, to comfort and encourage them; they shall not be involved in the judgments that are coming upon their unbelieving nation. Ministers must distinguish thus, that, when they speak terror to the wicked, they may not make the hearts of the righteous sad. Bone Christiane, hoc nihil ad te...', 'teologico');
add('is', 66, 15, 'Matthew Henry', 'These verses, like the pillar of cloud and fire, have a dark side towards the enemies of God\'s kingdom and all that are rebels against his crown, and a bright side towards his faithful loyal subjects. Probably they refer to the Jews in captivity in Babylon, of whom some are said to have been sent thither for their hurt, and with them God here threatens to proceed in his controversy; they hated to be reformed, and therefore should be ruined by the calamity (Jer 24:9); others were sent thither ...', 'teologico');

// JR (157 comentários)
add('jr', 1, 5, 'Calvino', 'Eu te constituí profeta — A chamada divina precede o nascimento: Deus designa para serviço antes da existência.', 'teologico');
add('jr', 9, 24, 'Agostinho', 'Eu sou o Senhor que pratica misericórdia — O conhecimento de Deus é experimental: conhece-lo é Experimentar Sua graça.', 'teologico');
add('jr', 17, 5, 'Matthew Henry', 'Maldito o homem que confia no homem — A maldição da confiança na carne: contraste com a bênção da confiança em Deus.', 'teologico');
add('jr', 17, 7, 'Spurgeon', 'Bem-aventurado o homem que confia no Senhor — A felicidade está na dependência total de Deus.', 'aplicacao');
add('jr', 23, 5, 'Calvino', 'Levantarei a Davi um rebento justo — A promessa messiânica: um rei justo que governará com retidão.', 'escatologico');
add('jr', 23, 6, 'N.T. Wright', 'O Senhor é a nossa justiça — O nome messiânico: Cristo é a justiça que Deus dá ao Seu povo.', 'teologico');
add('jr', 29, 11, 'Wesley', 'Pensamentos de paz — O plano de Deus para Seu povo é de esperança e restauração, não de destruição.', 'teologico');
add('jr', 31, 31, 'Calvino', 'Nova aliança — A promessa da nova aliança: lei escrita no coração, perdão completo, conhecimento direto de Deus.', 'teologico');
add('jr', 31, 33, 'Barth', 'Eu porei a minha lei no interior — A obra do Espírito: transformação interior, não apenas obediência externa.', 'teologico');
add('jr', 31, 34, 'João Crisóstomo', 'Todos me conhecerão — A nova aliança traz conhecimento direto de Deus: não mais mediadores distantes.', 'teologico');
add('jr', 1, 1, 'Matthew Henry', 'We have here as much as it was thought fit we should know of the genealogy of this prophet and the chronology of this prophecy. 1. We are told what family the prophet was of. He was the son of Hilkiah, not that Hilkiah, it is supposed, who was high priest in Josiah\'s time (for then he would have been called so, and not, as here, one of the priests that were in Anathoth), but another of the same name. Jeremiah signifies one raised up by the Lord. It is said of Christ that he is a prophet whom ...', 'teologico');
add('jr', 1, 4, 'Matthew Henry', 'Here is, I. Jeremiah\'s early designation to the work and office of a prophet, which God gives him notice of as a reason for his early application to that business (Jer 1:4, Jer 1:5): The word of the Lord came to him, with a satisfying assurance to himself that it was the word of the Lord and not a delusion; and God told him, 1. That he had ordained him a prophet to the nations, or against the nations, the nation of the Jews in the first place, who are now reckoned among the nations because th...', 'teologico');
add('jr', 1, 11, 'Matthew Henry', 'Here, I. God gives Jeremiah, in vision, a view of the principal errand he was to go upon, which was to foretel the destruction of Judah and Jerusalem by the Chaldeans, for their sins, especially their idolatry. This was at first represented to him in a way proper to make an impression upon him, that he might have it upon his heart in all his dealings with this people.\n1. He intimates to him that the people were ripening apace for ruin and that ruin was hastening apace towards them. God, havin...', 'teologico');
add('jr', 2, 1, 'Matthew Henry', 'Here is, I. A command given to Jeremiah to go and carry a message from God to the inhabitants of Jerusalem. He was charged in general (Jer 1:17) to go and speak to them; here he is particularly charged to go and speak this to them. Note, It is good for ministers by faith and prayer to take out a fresh commission when they address themselves solemnly to any part of their work. Let a minister carefully compare what he has to deliver with the word of God, and see that it agrees with it, that he ...', 'teologico');
add('jr', 2, 9, 'Matthew Henry', 'The prophet, having shown their base ingratitude in forsaking God, here shows their unparalleled fickleness and folly (Jer 2:9): I will yet plead with you. Note, Before God punishes sinners he pleads with them, to bring them to repentance. Note, further, When much has been said of the evil of sin, still there is more to be said; when one article of the charge is made good, there is another to be urged; when we have said a great deal, still we have yet to speak on God\'s behalf, Job 36:2. Those...', 'teologico');
add('jr', 2, 14, 'Matthew Henry', 'The prophet, further to evince the folly of their forsaking God, shows them what mischiefs they had already brought upon themselves by so doing; it had already cost them dear, for to this were owing all the calamities their country was now groaning under, which were but an earnest of more and greater if they repented not. See how they smarted for their folly.\nI. Their neighbours, who were their professed enemies, prevailed against them, and this was owing to their sin. 1. They were enslaved a...', 'teologico');
add('jr', 2, 20, 'Matthew Henry', 'In these verses the prophet goes on with his charge against this backsliding people. Observe here,\nI. The sin itself that he charges them with - idolatry, that great provocation which they were so notoriously guilty of. 1. They frequented the places of idol-worship (Jer 2:20): "Upon every high hill and under every green tree, in the high places and the groves, such as the heathen had a foolish fondness and veneration for, thou wanderest, first to one and then to another, like one unsettled, a...', 'teologico');
add('jr', 2, 29, 'Matthew Henry', 'The prophet here goes on in the same strain, aiming to bring a sinful people to repentance, that their destruction might be prevented.\nI. He avers the truth of the charge. It was evident beyond contradiction; it was the greatest absurdity imaginable in them to think of denying it (Jer 2:29): "Wherefore will you plead with me, and put me upon the proof of it, or wherefore will you go about to plead any thing in excuse of the crime or to obtain a mitigation of the sentence? Your plea will certa...', 'teologico');
add('jr', 3, 1, 'Matthew Henry', 'These verses some make to belong to the sermon in the foregoing chapter, and they open a door of hope to those who receive the conviction of the reproofs we had there; God wounds that he may heal. Now observe here,\nI. How basely this people had forsaken God and gone a whoring from him. The charge runs very high here. 1. They had multiplied their idols and their idolatries. To have admitted one strange God among them would have been bad enough, but they were insatiable in their lustings after ...', 'teologico');
add('jr', 3, 6, 'Matthew Henry', 'The date of this sermon must be observed, in order to the right understanding of it; it was in the days of Josiah, who set on foot a blessed work of reformation, in which he was hearty, but the people were not sincere in their compliance with it; to reprove them for that, and warn them of the consequences of their hypocrisy, is the scope of that which God here said to the prophet, and which he delivered to them. The case of the two kingdoms of Israel and Judah is here compared, the ten tribes...', 'teologico');
add('jr', 3, 12, 'Matthew Henry', 'Here is a great deal of gospel in these verses, both that which was always gospel, God\'s readiness to pardon sin and to receive and entertain returning repenting sinners, and those blessings which were in a special manner reserved for gospel times, the forming and founding of the gospel church by bringing into it the children of God that were scattered abroad, the superseding of the ceremonial law, and the uniting of Jews and Gentiles, typified by the uniting of Israel and Judah in their retu...', 'teologico');
add('jr', 3, 20, 'Matthew Henry', 'Here is, I. The charge God exhibits against Israel for their treacherous departures from him, Jer 3:20. As an adulterous wife elopes from her husband, so have they gone a whoring from God. They were joined to God by a marriage-covenant, but they broke that covenant, they dealt treacherously with God, who had always dealt kindly and faithfully with them. Treacherous dealing with men like ourselves is bad enough, but to deal treacherously with God is to deal treasonably.\nII. Their conviction an...', 'teologico');
add('jr', 4, 1, 'Matthew Henry', 'When God called to backsliding Israel to return (Jer 3:22) they immediately answered, Lord, we return; now God here takes notice of their answer, and, by way of reply to it,\nI. He directs them how to pursue their good resolutions: "Dost thou say, I will return?" 1. "Then thou must return unto me; make a thorough work of it. Do not only turn from thy idolatries, but return to the instituted worship of the God of Israel." Or, "Thou must return speedily and not delay (as Isa 21:12, If you will e...', 'teologico');
add('jr', 4, 3, 'Matthew Henry', 'The prophet here turns his speech, in God\'s name, to the men of the place where he lived. We have heard what words he proclaimed towards the north (Jer 3:12), for the comfort of those that were now in captivity and were humbled under the hand of God; let us now see what he says to the men of Judah and Jerusalem, who were now in prosperity, for their conviction and awakening. In these two verses he exhorts them to repentance and reformation, as the only way left them to prevent the desolating ...', 'teologico');
add('jr', 4, 5, 'Matthew Henry', 'God\'s usual method is to warn before he wounds. In these verses, accordingly, God gives notice to the Jews of the general desolation that would shortly be brought upon them by a foreign invasion. This must be declared and published in all the cities of Judah and streets of Jerusalem, that all might hear and fear, and by this loud alarm be either brought to repentance or left inexcusable. The prediction of this calamity is here given very largely, and in lively expressions, which one would thi...', 'teologico');
add('jr', 4, 19, 'Matthew Henry', 'The prophet is here in an agony, and cries out like one upon the rack of pain with some acute distemper, or as a woman in travail. The expressions are very pathetic and moving, enough to melt a heart of stone into compassion: My bowels! my bowels! I am pained at my very heart; and yet well, and in health himself, and nothing ails him. Note, A good man, in such a bad world as this is, cannot but be a man of sorrows. My heart makes a noise in me, through the tumult of my spirits, and I cannot h...', 'teologico');
add('jr', 5, 1, 'Matthew Henry', 'Here is, I. A challenge to produce any one right honest man, or at least any considerable number of such, in Jerusalem, Jer 5:1. Jerusalem had become like the old world, in which all flesh had corrupted their way. There were some perhaps who flattered themselves with hopes that there were yet many good men in Jerusalem, who would stand in the gap to turn away the wrath of God; and there might be others who boasted of its being the holy city and thought that this would save it. But God bids th...', 'teologico');
add('jr', 5, 10, 'Matthew Henry', 'We may observe in these verses, as before,\nI. The sin of this people, upon which the commission signed against them is grounded. God disowns them and dooms them to destruction, Jer 5:10. But is there not a cause? Yes; for, 1. They have deserted the law of God (Jer 5:11): The house of Israel and the house of Judah, though at variance with one another, yet both agreed to deal very treacherously against God. They forsook the worship of him, and therein violated their covenants with him; they rev...', 'teologico');
add('jr', 5, 20, 'Matthew Henry', 'The prophet, having reproved them for sin and threatened the judgments of God against them, is here sent to them again upon another errand, which he must publish in Judah; the purport of it is to persuade them to fear God, which would be an effectual principle of their reformation, as the want of that fear had been at the bottom of their apostasy.\nI. He complains of the shameful stupidity of this people, and their bent to backslide from God, speaking as if he knew not what course to take with...', 'teologico');
add('jr', 5, 25, 'Matthew Henry', 'Here, I. The prophet shows them what mischief their sins had done them: They have turned away these things (Jer 5:25), the former and the latter rain, which they used to have in due season (Jer 5:24), but which had of late been withheld (Jer 3:3), by reason of which the appointed weeks of harvest had sometimes disappointed them. "It is your sin that has withholden good from you, when God was ready to bestow it upon you." Note, It is sin that stops the current of God\'s favour to us, and depriv...', 'teologico');
add('jr', 6, 1, 'Matthew Henry', 'Here is I. Judgment threatened against Judah and Jerusalem. The city and the country were at this time secure and under no apprehension of danger; they saw no cloud gathering, but every thing looked safe and serene: but the prophet tells them that they shall shortly be invaded by a foreign power, an army shall be brought against them from the north, which shall lay all waste, and shall cause not only a general consternation, but a general desolation. It is here foretold,\n1. That the alarm of ...', 'teologico');
add('jr', 6, 9, 'Matthew Henry', 'The heads of this paragraph are the very same with those of the last; for precept must be upon precept and line upon line.\nI. The ruin of Judah and Jerusalem is here threatened. We had before the haste which the Chaldea army made to the war (Jer 6:4, Jer 6:5); now here we have the havoc made by the war. How lamentable are the desolations here described! The enemy shall so long quarter among them, and be so insatiable in their thirst after blood and treasure, that they shall seize all they can...', 'teologico');
add('jr', 6, 18, 'Matthew Henry', 'Here, I. God appeals to all the neighbours, nay, to the whole world, concerning the equity of his proceedings against Judah and Jerusalem (Jer 6:18, Jer 6:19): "Hear, you nations, and know particularly, O congregation of the mighty, the great men of the nations, that take cognizance of the affairs of states about you and make remarks upon them. Observe now what is doing among those of Judah and Jerusalem; you hear of the desolations brought upon them, the earth rings of it, trembles under it;...', 'teologico');
add('jr', 7, 1, 'Matthew Henry', 'These verses begin another sermon, which is continued in this and the two following chapters, much to the same effect with those before, to reason them to repentance. Observe,\nI. The orders given to the prophet to preach this sermon; for he had not only a general commission, but particular directions and instructions for every message he delivered. This was a word that came to him from the Lord, Jer 7:1. We are not told when this sermon was to be preached; but are told, 1. Where it must be pr...', 'teologico');
add('jr', 7, 16, 'Matthew Henry', 'God had shown them, in the foregoing verses, that the temple and the service of it, of which they boasted and in which they trusted, should not avail to prevent the judgment threatened. But there was another thing which might stand them in some stead, and which yet they had no value for, and that was the prophet\'s intercession for them; his prayers would do them more good than their own pleas: now here that support is taken from them; and their case is said indeed who have lost their interest...', 'teologico');
add('jr', 7, 21, 'Matthew Henry', 'God, having shown the people that the temple would not protect them while they polluted it with their wickedness, here shows them that their sacrifices would not atone for them, nor be accepted, while they went on in disobedience. See with what contempt he here speaks of their ceremonial service (Jer 7:21). "Put your burnt-offerings to your sacrifices; go on in them as long as you please; add one sort of sacrifice to another; turn your burnt-offerings (which were to be wholly burnt to the hon...', 'teologico');
add('jr', 7, 29, 'Matthew Henry', 'Here is, I. A loud call to weeping and mourning. Jerusalem, that had been a joyous city, the joy of the whole earth, must now take up a lamentation on high places (Jer 7:29), the high places where they had served their idols; there must they now bemoan their misery. In token both of sorrow and slavery, Jerusalem must now cut off her hair and cast it away; the word is peculiar to the hair of the Nazarites, which was the badge and token of their dedication to God, and it is called their crown. ...', 'teologico');
add('jr', 8, 1, 'Matthew Henry', 'These verses might fitly have been joined to the close of the foregoing chapter, as giving a further description of the dreadful desolation which the army of the Chaldeans should make in the land. It shall strangely alter the property of death itself, and for the worse too.\nI. Death shall not now be, as it always used to be - the repose of the dead. When Job makes his court to the grave it is in hope of this, that there he shall rest with kings and counsellors of the earth; but now the ashes ...', 'teologico');
add('jr', 8, 4, 'Matthew Henry', 'The prophet here is instructed to set before this people the folly of their impenitence, which was it that brought this ruin upon them. They are here represented as the most stupid senseless people in the world, that would not be made wise by all the methods that Infinite Wisdom took to bring them to themselves and their right mind, and so to prevent the ruin that was coming upon them.\nI. They would not attend to the dictates of reason. They would not act in the affairs of their souls with th...', 'teologico');
add('jr', 8, 13, 'Matthew Henry', 'In these verses we have,\nI. God threatening the destruction of a sinful people. He has borne long with them, but they are still more and more provoking, and therefore now their ruin is resolved on: I will surely consume them (Jer 8:13), consuming I will consume them, not only surely, but utterly, consume them, will follow them with one judgment after another, till they are quite consumed; it is a consumption determined, Isa 10:23. 1. They shall be quite stripped of all their comforts (Jer 8:1...', 'teologico');
add('jr', 9, 1, 'Matthew Henry', 'The prophet, being commissioned both to foretel the destruction coming upon Judah and Jerusalem and to point out the sin for which that destruction was brought upon them, here, as elsewhere, speaks of both very feelingly: what he said of both came from the heart, and therefore one would have thought it would reach to the heart.\nI. He abandons himself to sorrow in consideration of the calamitous condition of his people, which he sadly laments, a one that preferred Jerusalem before his chief jo...', 'teologico');
add('jr', 9, 12, 'Matthew Henry', 'Two things the prophet designs, in these verses, with reference to the approaching destruction of Judah and Jerusalem: - 1. To convince people of the justice of God in it, that they had by sin brought it upon themselves and that therefore they had no reason to quarrel with God, who did them no wrong at all, but a great deal of reason to fall out with their sins, which did them all this mischief. 2. To affect people with the greatness of the desolation that was coming, and the miserable effect...', 'teologico');
add('jr', 9, 23, 'Matthew Henry', 'The prophet had been endeavouring to possess this people with a holy fear of God and his judgments, to convince them both of sin and wrath; but still they had recourse to some sorry subterfuge or other, under which to shelter themselves from the conviction and with which to excuse themselves in the obstinacy and carelessness. He therefore sets himself here to drive them from these refuges of lies and to show them the insufficiency of them.\nI. When they were told how inevitable the judgment wo...', 'teologico');
add('jr', 10, 1, 'Matthew Henry', 'The prophet Isaiah, when he prophesied of the captivity in Babylon, added warnings against idolatry and largely exposed the sottishness of idolaters, not only because the temptations in Babylon would be in danger of drawing the Jews there to idolatry, but because the afflictions in Babylon were designed to cure them of their idolatry. Thus the prophet Jeremiah here arms people against the idolatrous usages and customs of the heathen, not only for the use of those that had gone to Babylon, but...', 'teologico');
add('jr', 10, 17, 'Matthew Henry', 'In these verses,\nI. The prophet threatens, in God\'s name, the approaching ruin of Judah and Jerusalem, Jer 10:17, Jer 10:18. The Jews that continued in their own land, after some were carried into captivity, were very secure; they thought themselves inhabitants of a fortress; their country was their strong hold, and, in their own conceit, impregnable; but they are here told to think of leaving it: they must prepare to go after their brethren, and pack up their effects in expectation of it: "G...', 'teologico');
add('jr', 11, 1, 'Matthew Henry', 'The prophet here, as prosecutor in God\'s name, draws up an indictment against the Jews for wilful disobedience to the commands of their rightful Sovereign. For the more solemn management of this charge,\nI. He produces the commission he had to draw up the charge against them. He did not take pleasure in accusing the children of his people, but God commanded him to speak it to the men of Judah, Jer 11:1, Jer 11:2. In the original it is plural: Speak you this. For what he said to Jeremiah was th...', 'teologico');
add('jr', 11, 11, 'Matthew Henry', 'This paragraph, which contains so much of God\'s wrath, might very well be expected to follow upon that which goes next before, which contained so much of his people\'s sin. When God found so much evil among them we cannot think it strange if it follows, Therefore I will bring evil upon them (Jer 11:11), the evil of punishment for the evil of sin; and there is no remedy, no relief: the decree has gone forth and the sentence will be executed.\nI. They cannot help themselves, but will be found too...', 'teologico');
add('jr', 11, 18, 'Matthew Henry', 'The prophet Jeremiah has much in his writings concerning himself, much more than Isaiah had, the times he lived in being very troublesome. Here we have (as it should seem) the beginning of his sorrows, which arose from the people of his own city, Anathoth, a priest\'s city, and yet a malignant one. Observe here,\nI. Their plot against him, Jer 11:19. They devised devices against him, laid their heads together to contrive how they might be in the most plausible and effectual manner the death of ...', 'teologico');
add('jr', 12, 1, 'Matthew Henry', 'The prophet doubts not but it would be of use to others to know what had passed between God and his soul, what temptations he had been assaulted with and how he had got over them; and therefore he here tells us,\nI. What liberty he humbly took, and was graciously allowed him, to reason with God concerning his judgments, Jer 12:1. He is about to plead with God, not to quarrel with him, or find fault with his proceedings, but to enquire into the meaning of them, that he might more and more see r...', 'teologico');
add('jr', 12, 7, 'Matthew Henry', 'The people of the Jews are here marked for ruin.\nI. God is here brought in falling out with them and leaving them desolate; and they could never have been undone if they had not provoked God to desert them. It is a terrible word that God here says (Jer 12:7): I have forsaken my house - the temple, which had been his palace; they had polluted it, and so forced him out of it: I have left my heritage, and will look after it no more. His people that he has taken such delight in, and care of, are ...', 'teologico');
add('jr', 12, 14, 'Matthew Henry', 'The prophets sometimes, in God\'s name, delivered messages both of judgment and mercy to the nations that bordered on the land of Israel: but here is a message to all those in general who had in their turns been one way or other injurious to God\'s people, had either oppressed them or triumphed in their being oppressed. Observe,\nI. What the quarrel was that God had with them. They were his evil neighbours (Jer 12:14), evil neighbours to his church, and what they did against it he took as done a...', 'teologico');
add('jr', 13, 1, 'Matthew Henry', 'Here is, I. A sign, the marring of a girdle, which the prophet had worn for some time, by hiding it in a hole of a rock near the river Euphrates. It was usual with the prophets to teach by signs, that a stupid unthinking people might be brought to consider, and believe, and be affected with what was thus set before them. 1. He was to wear a linen girdle for some time, Jer 13:1, Jer 13:2. Some think he wore it under his clothes, because it was linen, and it is said to cleave to his loins, Jer ...', 'teologico');
add('jr', 13, 12, 'Matthew Henry', 'Here is, I. A judgment threatened against this people that would quite intoxicate them. This doom is pronounced against them in a figure, to make it the more taken notice of and the more affecting (Jer 13:12): Thus saith the Lord God of Israel, every bottle shall be filled with wine; that is, those that by their sins have made themselves vessels of wrath fitted to destruction shall be filled with the wrath of God as a bottle is with wine; and, as every vessel of mercy prepared for glory shall...', 'teologico');
add('jr', 13, 22, 'Matthew Henry', 'Here is, I. Ruin threatened as before, that the Jews shall go into captivity, and fall under all the miseries of beggary and bondage, shall be stripped of their clothes, their skirts discovered for want of upper garments to cover them, and their heels made bare for want of shoes, Jer 13:22. Thus they used to deal with prisoners taken in war, when they drove them into captivity, naked and barefoot, Isa 20:4. Being thus carried off into a strange country, they shall be scattered there, as the s...', 'teologico');
add('jr', 14, 1, 'Matthew Henry', 'The first verse is the title of the whole chapter: it does indeed all concern the dearth, but much of it consists of the prophet\'s prayers concerning it; yet these are not unfitly said to be, The word of the Lord which came to him concerning it, for every acceptable prayer is that which God puts into our hearts; nothing is our word that comes to him but what is first his word that comes from him. In these verses we have,\nI. The language of nature lamenting the calamity. When the heavens were ...', 'teologico');
add('jr', 14, 10, 'Matthew Henry', 'The dispute between God and his prophet, in this chapter, seems to be like that between the owner and the dresser of the vineyard concerning the barren fig-tree, Luk 13:7. The justice of the owner condemns it to be cut down; the clemency of the dresser intercedes for a reprieve. Jeremiah had been earnest with God, in prayer, to return in mercy to this people. Now here,\nI. God overrules the plea which he had offered in their favour, and shows him that it would not hold. In answer to it thus he...', 'teologico');
add('jr', 14, 17, 'Matthew Henry', 'The present deplorable state of Judah and Jerusalem is here made the matter of the prophet\'s lamentation (Jer 14:17, Jer 14:18) and the occasion of his prayer and intercession for them (Jer 14:19), and I am willing to hope that the latter, as well as the former, was by divine direction, and that these words (Jer 14:17), Thus shalt thou say unto them (or concerning them, or in their hearing), refer to the intercession, as well as to the lamentation, and then it amounts to a revocation of the d...', 'teologico');
add('jr', 15, 1, 'Matthew Henry', 'We scarcely find any where more pathetic expressions of divine wrath against a provoking people than we have here in these verses. The prophet had prayed earnestly for them, and found some among them to join with him; and yet not so much as a reprieve was gained, nor the least mitigation of the judgment; but this answer is given to the prophet\'s prayers, that the decree had gone forth, was irreversible, and would shortly be executed. Observe here,\nI. What the sin was upon which this severe se...', 'teologico');
add('jr', 15, 10, 'Matthew Henry', 'Jeremiah has now returned from his public work and retired into his closet; what passed between him and his God there we have an account of in these and the following verses, which he published afterwards, to affect the people with the weight and importance of his messages to them. Here is,\nI. The complaint which the prophet makes to God of the many discouragements he met with in his work, Jer 15:10.\n1. He met with a great deal of contradiction and opposition. He was a man of strife and conte...', 'teologico');
add('jr', 15, 15, 'Matthew Henry', 'Here, as before, we have,\nI. The prophet\'s humble address to God, containing a representation both of his integrity and of the hardships he underwent notwithstanding. It is a matter of comfort to us that, whatever ails us, we have a God to go to, before whom we may spread our case and to whose omniscience we may appeal, as the prophet here, "O Lord! thou knowest; thou knowest my sincerity, which men are resolved they will not acknowledge; thou knowest my distress, which men disdain to take no...', 'teologico');
add('jr', 16, 1, 'Matthew Henry', 'The prophet is here for a sign to the people. They would not regard what he said; let it be tried whether they will regard what he does. In general, he must conduct himself so, in every thing, as became one that expected to see his country in ruins very shortly. This he foretold, but few regarded the prediction; therefore he is to show that he is himself fully satisfied in the truth of it. Others go on in their usual course, but he, in the prospect of these sad times, is forbidden and therefo...', 'teologico');
add('jr', 16, 10, 'Matthew Henry', 'Here is, 1. An enquiry made into the reasons why God would bring those judgments upon them (Jer 16:10): When thou shalt show this people all these words, the words of this curse, they will say unto thee, Wherefore has the Lord pronounced all this great evil against us? One would hope that there were some among them that asked this question with a humble penitent heart, desiring to know what was the sin for which God contended with them, that they might cast it away and prevent the judgment: "...', 'teologico');
add('jr', 16, 14, 'Matthew Henry', 'There is a mixture of mercy and judgment in these verses, and it is hard to know to which to apply some of the passages here - they are so interwoven, and some seem to look as far forward as the times of the gospel.\nI. God will certainly execute judgment upon them for their idolatries. Let them expect it, for the decree has gone forth. 1. God sees all their sins, though they commit them ever so secretly and palliate them ever so artfully (Jer 16:17): My eyes are upon all their ways. They have...', 'teologico');
add('jr', 17, 1, 'Matthew Henry', 'The people had asked (Jer 16:10), What is our iniquity, and what is our sin? as if they could not be charged with any thing worth speaking of, for which God should enter into judgment with them; their challenge was answered there, but here we have a further reply to it, in which,\nI. The indictment is fully proved upon the prisoners, both the fact and the fault; their sin is too plain to be denied and too bad to be excused, and they have nothing to plead either in extenuation of the crime or i...', 'teologico');
add('jr', 17, 12, 'Matthew Henry', 'Here, as often before, we have the prophet retired for private meditation, and alone with God. Those ministers that would have comfort in their work must be much so. In his converse here with God and his own heart he takes the liberty which devout souls sometimes use in their soliloquies, to pass from one thing to another, without tying themselves too strictly to the laws of method and coherence.\nI. He acknowledges the great favour of God to his people in setting up a revealed religion among ...', 'teologico');
add('jr', 17, 19, 'Matthew Henry', 'These verses are a sermon concerning sabbath-sanctification. It is a word which the prophet received from the Lord, and was ordered to deliver in the most solemn and public manner to the people; for they were sent not only to reprove sin, and to press obedience, in general, but they must descend to particulars. This message concerning the sabbath was probably sent in the days of Josiah, for the furtherance of that work of reformation which he set on foot; for the promises here (Jer 17:25, Jer...', 'teologico');
add('jr', 18, 1, 'Matthew Henry', 'The prophet is here sent to the potter\'s house (he knew where to find it), not to preach a sermon as before to the gates of Jerusalem, but to prepare a sermon, or rather to receive it ready prepared. Those needed not to study their sermons that had them, as he had this, by immediate inspiration. "Go to the potter\'s house, and observe how he manages his work, and there I will cause thee, by silent whispers, to hear my words. There thou shalt receive a message, to be delivered to the people." N...', 'teologico');
add('jr', 18, 11, 'Matthew Henry', 'These verses seem to be the application of the general truths laid down in the foregoing part of the chapter to the nation of the Jews and their present state.\nI. God was now speaking concerning them to pluck up, and to pull down, and to destroy; for it is that part of the rule of judgment that their case agrees with (Jer 18:11): "Go, and tell them" (saith God), "Behold I frame evil against you and devise against you. Providence in all its operations is plainly working towards your ruin. Look...', 'teologico');
add('jr', 18, 18, 'Matthew Henry', 'The prophet here, as sometimes before, brings in his own affairs, but very much for instruction to us.\nI. See here what are the common methods of the persecutors. We may see this in Jeremiah\'s enemies, Jer 18:18.\n1. They laid their heads together to consult what they should do against him, both to be revenged on him for what he had said and to stop his mouth for the future: They said, Come and let us devise devices against Jeremiah. The enemies of God\'s people and ministers have been often ve...', 'teologico');
add('jr', 19, 1, 'Matthew Henry', 'The corruption of man having made it necessary that precept should be upon precept, and line upon line (so unapt are we to receive, and so very apt to let slip, the things of God), the grace of God has provided that there shall be, accordingly, precept upon precept, and line upon line, that those who are irreclaimable may be inexcusable. For this reason the prophet is here sent with a message to the same purport with what he had often delivered, but with some circumstances that might make it ...', 'teologico');
add('jr', 19, 10, 'Matthew Henry', 'The message of wrath delivered in the foregoing verses is here enforced, that it might gain credit, two ways: - \nI. By a visible sign. The prophet was to take along with him an earthen bottle (Jer 19:1), and, when he had delivered his message, he was to break the bottle to pieces (Jer 19:10), and the same that were auditors of the sermon must be spectators of the sign. He had compared this people, in the chapter before, to the potter\'s clay, which is easily marred in the making. But some migh...', 'teologico');
add('jr', 20, 1, 'Matthew Henry', 'Here is, I. Pashur\'s unjust displeasure against Jeremiah, and the fruits of that displeasure, Jer 20:1, Jer 20:2. This Pashur was a priest, and therefore, one would think, should have protected Jeremiah, who was of his own order, a priest too, and the more because he was a prophet of the Lord, whose interests the priests, his ministers, ought to consult. But this priest was a persecutor of him whom he should have patronized. He was the son of Immer; that is, he was of the sixteenth course of ...', 'teologico');
add('jr', 20, 7, 'Matthew Henry', 'Pashur\'s doom was to be a terror to himself; Jeremiah, even now, in this hour of temptation, is far from being so; and yet it cannot be denied but that he is here, through the infirmity of the flesh, strangely agitated within himself. Good men are but men at the best. God is not extreme to mark what they say and do amiss, and therefore we must not be so, but make the best of it. In these verses it appears that, upon occasion of the great indignation and injury that Pashur did to Jeremiah, the...', 'teologico');
add('jr', 20, 14, 'Matthew Henry', 'What is the meaning of this? Does there proceed out of the same mouth blessing and cursing? Could he that said so cheerfully (Jer 20:13), Sing unto the Lord, praise you the Lord, say so passionately (Jer 20:14), Cursed be the day wherein I was born? How shall we reconcile these? What we have in these verses the prophet records, I suppose, to his own shame, as he had recorded that in the foregoing verses to God\'s glory. It seems to be a relation of the ferment he had been in while he was in th...', 'teologico');
add('jr', 21, 1, 'Matthew Henry', 'Here is, I. A very humble decent message which king Zedekiah, when he was in distress, sent to Jeremiah the prophet. It is indeed charged upon this Zedekiah that he humbled not himself before Jeremiah the prophet, speaking from the mouth of the Lord (Ch2 36:12); he did not always humble himself as he did sometimes; he never humbled himself till necessity forced him to it; he humbled himself so far as to desire the prophet\'s assistance, but not so far as to take his advice, or to be ruled by h...', 'teologico');
add('jr', 21, 8, 'Matthew Henry', 'By the civil message which the king sent to Jeremiah it appeared that both he and the people began to have a respect for him, which it would have been Jeremiah\'s policy to make some advantage of for himself; but the reply which God obliges him to make is enough to crush the little respect they begin to have for him, and to exasperate them against him more than ever. Not only the predictions in the foregoing verses, but the prescriptions in these, were provoking; for here,\nI. He advises the pe...', 'teologico');
add('jr', 22, 1, 'Matthew Henry', 'Here we have,\nI. Orders given to Jeremiah to go and preach before the king. In the foregoing chapter we are told that Zedekiah sent messengers to the prophet, but here the prophet is bidden to go, in his own proper person, to the house of the king, and demand his attention to the word of the King of kings (Jer 22:2): Hear the word of the Lord, O king of Judah! Subjects must own that where the word of the king is there is power over them, but kings must own that where the word of the Lord is t...', 'teologico');
add('jr', 22, 10, 'Matthew Henry', 'Kings, though they are gods to us, are men to God, and shall die like men; so it appears in these verses, where we have a sentence of death passed upon two kings who reigned successively in Jerusalem, two brothers, and both the ungracious sons of a very pious father.\nI. Here is the doom of Shallum, who doubtless is the same with Jehoahaz, for he is that son of Josiah king of Judah who reigned in the stead of Josiah his father (Jer 22:11), which Jehoahaz did by the act of the people, who made ...', 'teologico');
add('jr', 22, 20, 'Matthew Henry', 'This prophecy seems to have been calculated for the ungracious inglorious reign of Jeconiah, or Jehoiachin, the son of Jehoiakim, who succeeded him in the government, reigned but three months, and was then carried captive to Babylon, where he lived many years, Jer 52:31. We have, in these verses, a prophecy,\nI. Of the desolations of the kingdom, which were now hastening on apace, Jer 22:20-23. Jerusalem and Judah are here spoken to, or the Jewish state as a single person, and we have it here ...', 'teologico');
add('jr', 23, 1, 'Matthew Henry', 'I. Here is a word of terror to the negligent shepherds. The day is at hand when God will reckon with them concerning the trust and charge committed to them: Woe be to the pastors (to the rulers, both in church and state) who should be to those they are set over as pastors to lead them, feed them, protect them, and take care of them. They are not owners of the sheep. God here calls them the sheep of my pasture, whom I am interested in, and have provided good pasture for. Woe be to those theref...', 'teologico');
add('jr', 23, 9, 'Matthew Henry', 'Here is a long lesson for the false prophets. As none were more bitter and spiteful against God\'s true prophets than they, so there were none on whom the true prophets were more severe, and justly. The prophet had complained to God of those false prophets (Jer 14:13), and had often foretold that they should be involved in the common ruin; but here they have woes of their own.\nI. He expresses the deep concern that he was under upon this account, and what a trouble it was to him to see men who ...', 'teologico');
add('jr', 23, 33, 'Matthew Henry', 'The profaneness of the people, with that of the priests and prophets, is here reproved in a particular instance, which may seem of small moment in comparison of their greater crimes; but profaneness in common discourse, and the debauching of the language of a nation, being a notorious evidence of the prevalency of wickedness in it, we are not to think it strange that this matter was so largely and warmly insisted upon here. Observe,\nI. The sin here charged upon them is bantering God\'s prophet...', 'teologico');
add('jr', 24, 1, 'Matthew Henry', 'This short chapter helps us to put a very comfortable construction upon a great many long ones, by showing us that the same providence which to some is a savour of death unto death may by the grace and blessing of God be made to others a savour of life unto life; and that, though God\'s people share with others in the same calamity, yet it is not the same to them that it is to others, but is designed for their good and shall issue in their good; to them it is a correcting rod in the hand of a ...', 'teologico');
add('jr', 25, 1, 'Matthew Henry', 'We have here a message from God concerning all the people of Judah (Jer 25:1), which Jeremiah delivered, in his name, unto all the people of Judah, Jer 25:2. Note, That which is of universal concern ought to be of universal cognizance. It is fit that the word which concerns all the people, as the word of God does, the word of the gospel particularly, should be divulged to all in general, and, as far as may be, addressed to each in particular. Jeremiah had been sent to the house of the king (J...', 'teologico');
add('jr', 25, 8, 'Matthew Henry', 'Here is the sentence grounded upon the foregoing charge: "Because you have not heard my words, I must take another course with you," Jer 25:8. Note, When men will not regard the judgments of God\'s mouth they may expect to feel the judgments of his hands, to hear the rod, since they would not hear the word; for the sinner must either be parted from his sin or perish in it. Wrath comes without remedy against those only that sin without repentance. It is not so much men\'s turning aside that ruin...', 'teologico');
add('jr', 25, 15, 'Matthew Henry', 'Under the similitude of a cup going round, which all the company must drink of, is here represented the universal desolation that was now coming upon that part of the world which Nebuchadrezzar, who just now began to reign and act, was to be the instrument of, and which should at length recoil upon his own country. The cup in the vision is to be a sword in the accomplishment of it: so it is explained, Jer 25:16. It is the sword that I will send among them, the sword of war, that should be irr...', 'teologico');
add('jr', 25, 30, 'Matthew Henry', 'We have, in these verses, a further description of those terrible desolations which the king of Babylon with his armies should make in all the countries and nations round about Jerusalem. In Jerusalem God had erected his temple; there were his oracles and ordinances, which the neighbouring nations should have attended to and might have received benefit by; thither they should have applied for the knowledge of God and their duty, and then they might have had reason to bless God for their neigh...', 'teologico');
add('jr', 26, 1, 'Matthew Henry', 'We have here the sermon that Jeremiah preached, which gave such offence that he was in danger of losing his life for it. It is here left upon record, as it were, by way of appeal to the judgment of impartial men in all ages, whether Jeremiah was worthy to die for delivering such a message as this from God, and whether his persecutors were not very wicked and unreasonable men.\nI. God directed him where to preach this sermon, and when, and to what auditory, v. 2. Let not any censure Jeremiah as...', 'teologico');
add('jr', 26, 7, 'Matthew Henry', 'One would have hoped that such a sermon as that in the foregoing verses, so plain and practical, so rational and pathetic, and delivered in God\'s name, would work upon even this people, especially meeting them now at their devotions, and would prevail with them to repent and reform; but, instead of awakening their convictions, it did but exasperate their corruptions, as appears by this account of the effect of it.\nI. Jeremiah is charged with it as a crime that he had preached such a sermon, a...', 'teologico');
add('jr', 26, 16, 'Matthew Henry', 'Here is, I. The acquitting of Jeremiah from the charge exhibited against him. He had indeed spoken the words as they were laid in the indictment, but they are not looked upon to be seditious or treasonable, ill-intended or of any bad tendency, and therefore the court and country agree to find him not guilty. The priests and prophets, notwithstanding his rational plea for himself, continued to demand judgment against him; but the princes, and all the people, are clear in it that this man is no...', 'teologico');
add('jr', 27, 1, 'Matthew Henry', 'Some difficulty occurs in the date of this prophecy. This word is said to come to Jeremiah in the beginning of the reign of Jehoiakim (Jer 27:1), and yet the messengers, to whom he is to deliver the badges of servitude, are said (Jer 27:3) to come to Zedekiah king of Judah, who reigned not till eleven years after the beginning of Jehoiakim\'s reign. Some make it an error of the copy, and think that it should be read (Jer 27:1), In the beginning of the reign of Zedekiah, for which some negligen...', 'teologico');
add('jr', 27, 12, 'Matthew Henry', 'What was said to all the nations is here with a particular tenderness applied to the nation of the Jews, for whom Jeremiah was sensibly concerned. The case at present stood thus: Judah and Jerusalem had often contested with the king of Babylon, and still were worsted; many both of their valuable persons and their valuable goods were carried to Babylon already, and some of the vessels of the Lord\'s house particularly. Now how this struggle would issue was the question. They had those among the...', 'teologico');
add('jr', 28, 1, 'Matthew Henry', 'This struggle between a true prophet and a false one is said here to have happened in the beginning of the reign of Zedekiah, and yet in the fourth year, for the first four years of his reign might well be called the beginning, or former part, of it, because during those years he reigned under the dominion of the king of Babylon and as a tributary to him; whereas the rest of his reign, which might well be called the latter part of it, in distinction from that former part, he reigned in rebell...', 'teologico');
add('jr', 28, 10, 'Matthew Henry', 'We have here an instance,\nI. Of the insolence of the false prophet. To complete the affront he designed Jeremiah, he took the yoke from off his neck which he carried as a memorial of what he had prophesied concerning the enslaving of the nations to Nebuchadnezzar, and he broke it, that he might give a sign of the accomplishment of this prophecy, as Jeremiah had given of his, and might seem to have conquered him, and to have defeated the intention of his prophecy. See how the lying spirit, in ...', 'teologico');
add('jr', 29, 1, 'Matthew Henry', 'We are here told,\nI. That Jeremiah wrote to the captives in Babylon, in the name of the Lord. Jeconiah had surrendered himself a prisoner, with the queen his mother, the chamberlains of his household, called here the eunuchs, and many of the princes of Judah and Jerusalem, who were at that time the most active men; the carpenters and smiths likewise, being demanded, were yielded up, that those who remained might not have any proper hands to fortify their city or furnish themselves with weapon...', 'teologico');
add('jr', 29, 8, 'Matthew Henry', 'To make the people quiet and easy in their captivity,\nI. God takes them off from building upon the false foundation which their pretended prophets laid, Jer 29:8, Jer 29:9. They told them that their captivity should be short, and therefore that they must not think of taking root in Babylon, but be upon the wing to go back: "Now herein they deceive you," says God; "they prophesy a lie to you, though they prophesy in my name. But let them not deceive you, suffer not yourselves to be deluded by ...', 'teologico');
add('jr', 29, 15, 'Matthew Henry', 'Jeremiah, having given great encouragement to those among the captives whom he knew to be serious and well-affected, assuring them that God had very kind and favourable intentions concerning them, here turns to those among them who slighted the counsels and comforts that Jeremiah ministered to them and depended upon what the false prophets flattered them with. When this letter came from Jeremiah they would be ready to say, "Why should he make himself so busy, and take upon him to advise us? T...', 'teologico');
add('jr', 29, 24, 'Matthew Henry', 'We have perused the contents of Jeremiah\'s letter to the captives in Babylon, who had reason, with a great deal of thanks to God and him, to acknowledge the receipt of it, and lay it up among their treasures. But we cannot wonder if the false prophets they had among them were enraged at it; for it gave them their true character. Now here we are told concerning one of them,\nI. How he manifested his malice against Jeremiah. this busy fellow is called Shemaiah the Nehelamite, the dreamer (so the...', 'teologico');
add('jr', 30, 1, 'Matthew Henry', 'Here, I. Jeremiah is directed to write what God had spoken to him, which perhaps refers to all the foregoing prophecies. He must write them and publish them, in hopes that those who had not profited by what he said upon once hearing it might take more notice of it when in reading it they had leisure for a more considerate review. Or, rather, it refers to the promises of their enlargement, which had been often mixed with his other discourses. He must collect them and put them together, and God...', 'teologico');
add('jr', 30, 10, 'Matthew Henry', 'In these verses, as in those foregoing, the deplorable case of the Jews in captivity is set forth, but many precious promises are given them that in due time they should be relieved and a glorious salvation wrought for them.\nI. God himself appeared against them: he scattered them (Jer 30:11); he did all these things unto them, Jer 30:15. All their calamities came from his hands; whoever were the instruments, he was the principal agent. And this made their case very sad that God, even their ow...', 'teologico');
add('jr', 30, 18, 'Matthew Henry', 'We have here further intimations of the favour God had in reserve for them after the days of their calamity were over. It is promised,\nI. That the city and temple should be rebuilt, Jer 30:18. Jacob\'s tents, and his dwelling places, felt the effects of the captivity, for they lay in ruins when the inhabitants were carried away captives; but, when they have returned, the habitations shall be repaired, and raised up out of their ruins, and therein God will have mercy upon their dwelling places,...', 'teologico');
add('jr', 31, 1, 'Matthew Henry', 'God here assures his people,\nI. That he will again take them into a covenant relation to himself, from which they seemed to be cut off. At the same time, when God\'s anger breaks out against the wicked (Jer 30:24), his own people shall be owned by him as the children of his love: I will be the God (that is, I will show myself to be the God) of all the families of Israel (Jer 31:1), - not of the two tribes only, but of all the tribes, - not of the house of Aaron only, and the families of Levi, ...', 'teologico');
add('jr', 31, 10, 'Matthew Henry', 'This paragraph is much to the same purport with the last, publishing to the world, as well as to the church, the purposes of God\'s love concerning his people. This is a word of the Lord which the nations must hear, for it is a prophecy of a work of the Lord which the nations cannot but take notice of. Let them hear the prophecy, that they may the better understand and improve the performance; and let those that hear it themselves declare it to others, declare it in the isles afar off. It will...', 'teologico');
add('jr', 31, 18, 'Matthew Henry', 'We have here,\nI. Ephraim\'s repentance, and return to God. Not only Judah, but Ephraim the ten tribes, shall be restored, and therefore shall thus be prepared and qualified for it, Hos 14:8. Ephraim shall say, What have I do to any more with idols? Ephraim the people, is here spoken of as a single person to denote their unanimity; they shall be as one man in their repentance and shall glorify God in it with one mind and one mouth, one and all. it is likewise thus expressed that it might be the...', 'teologico');
add('jr', 31, 27, 'Matthew Henry', 'The prophet, having found his sleep sweet, made so by the revelations of divine grace, sets himself to sleep again, in hopes of further discoveries, and is not disappointed; for it is here further promised,\nI. That the people of God shall become both numerous and prosperous. Israel and Judah shall be replenished both with men and cattle, as if they were sown with the seed of both, Jer 31:27. They shall increase and multiply like a field sown with corn; and this is the product of God\'s blessin...', 'teologico');
add('jr', 31, 35, 'Matthew Henry', 'Glorious things have been spoken in the foregoing verses concerning the gospel church, which that epocha of the Jewish church that was to commence at the return from captivity would at length terminate in, and which all those promises were to have their full accomplishment in. But may we depend upon these promises? Yes, we have here a ratification of them, and the utmost assurance imaginable given of the perpetuity of the blessings contained in them. The great thing here secured to us is that...', 'teologico');
add('jr', 32, 1, 'Matthew Henry', 'It appears by the date of this chapter that we are now coming very nigh to that fatal year which completed the desolations of Judah and Jerusalem by the Chaldeans. God\'s judgments came gradually upon them, but, they not meeting him by repentance in the way of his judgments, he proceeded in his controversy till all was laid waste, which was in the eleventh year of Zedekiah; now what is here recorded happened in the tenth. The king of Babylon\'s army had now invested Jerusalem and was carrying o...', 'teologico');
add('jr', 32, 16, 'Matthew Henry', 'We have here Jeremiah\'s prayer to God upon occasion of the discoveries God had made to him of his purposes concerning this nation, to pull it down, and in process of time to build it up again, which puzzled the prophet himself, who, though he delivered his messages faithfully, yet, in reflecting upon them, was greatly at a loss within himself how to reconcile them; in that perplexity he poured out his soul before God in prayer, and so gave himself ease. That which disturbed him was not the ba...', 'teologico');
add('jr', 32, 26, 'Matthew Henry', 'We have here God\'s answer to Jeremiah\'s prayer, designed to quiet his mind and make him easy; and it is a full discovery of the purposes of God\'s wrath against the present generation and the purposes of his grace concerning the future generations. Jeremiah knew not how to sing both of mercy and judgment, but God here teaches to sing unto him of both. When we know not how to reconcile one word of God with another we may yet be sure that both are true, both are pure, both shall be made good, an...', 'teologico');
add('jr', 33, 1, 'Matthew Henry', 'Observe here, I. The date of this comfortable prophecy which God entrusted Jeremiah with. It is not exact in the time, only that it was after that in the foregoing chapter, when things were still growing worse and worse; it was the second time. God speaketh once, yea, twice, for the encouragement of his people. We are not only so disobedient that we have need of precept upon precept to bring us to our duty, but so distrustful that we have need of promise upon promise to bring us to our comfor...', 'teologico');
add('jr', 33, 10, 'Matthew Henry', 'Here is a further prediction of the happy state of Judah and Jerusalem after their glorious return out of captivity, issuing gloriously at length in the kingdom of the Messiah.\nI. It is promised that the people who were long in sorrow shall again be filled with joy. Every one concluded now that the country would lie for ever desolate, that no beasts would be found in the land of Judah, no inhabitant in the streets of Jerusalem, and consequently there would be nothing but universal and perpetu...', 'teologico');
add('jr', 33, 17, 'Matthew Henry', 'Three of God\'s covenants, that of royalty with David and his seed, that of the priesthood with Aaron and his seed, and that of Peculiarity with Abraham and his seed, seemed to be all broken and lost while the captivity lasted; but it is here promised that, notwithstanding that interruption and discontinuance for a time, they shall all three take place again, and the true intents and meaning of them all shall be abundantly answered in the New Testament blessings, typified by those conferred on...', 'teologico');
add('jr', 34, 1, 'Matthew Henry', 'This prophecy concerning Zedekiah was delivered to Jeremiah, and by him to the parties concerned, before he was shut up in the prison, for we find this prediction here made the ground of his commitment, as appears by the recital of some passages out of it, Jer 32:4. Observe,\nI. The time when this message was sent to Zedekiah; it was when the king of Babylon, with all his forces, some out of all the kingdoms of the earth that were within his jurisdiction, fought against Jerusalem and the citie...', 'teologico');
add('jr', 34, 8, 'Matthew Henry', 'We have here another prophecy upon a particular occasion, the history of which we must take notice of, as necessary to give light to the prophecy.\nI. When Jerusalem was closely besieged by the Chaldean army the princes and people agreed upon a reformation in one instance, and that was concerning their servants.\n1. The law of God was very express, that those of their own nation should not be held in servitude above seven years, but, after they had served one apprenticeship, they should be disc...', 'teologico');
add('jr', 35, 1, 'Matthew Henry', 'This chapter is of an earlier date than many of those before; for what is contained in it was said and done in the days of Jehoiakim (Jer 35:1); but then it must be in the latter part of his reign, for it was after the king of Babylon with his army came up into the land (Jer 35:11), which seems to refer to the invasion mentioned Kg2 24:2, which was upon occasion of Jehoiakim\'s rebelling against Nebuchadnezzar. After the judgments of God had broken in upon this rebellious people he continued t...', 'teologico');
add('jr', 35, 12, 'Matthew Henry', 'The trial of the Rechabites\' constancy was intended but for a sign; now here we have the application of it.\nI. The Rechabites\' observance of their father\'s charge to them is made use of as an aggravation of the disobedience of the Jews to God. Let them see it and be ashamed. The prophet asks them, in God\'s name, "Will you not at length receive instruction? Jer 35:13. Will nothing affect you? Will nothing fasten upon you? Will nothing prevail to discover sin and duty to you? You see how obedie...', 'teologico');
add('jr', 36, 1, 'Matthew Henry', 'In the beginning of Ezekiel\'s prophecy we meet with a roll written in vision, for discovery of the things therein contained to the prophet himself, who was to receive and digest them, Eze 2:9, Eze 2:10; Eze 3:1. Here, in the latter end of Jeremiah\'s prophecy, we meet with a roll written in fact, for discovery of the things contained therein to the people, who were to hear and give heed to them; for the written word and other good books are of great use both to ministers and people. We have he...', 'teologico');
add('jr', 36, 9, 'Matthew Henry', 'It should seem that Baruch had been frequently reading out of the book, to all companies that would give him the hearing, before the most solemn reading of it altogether which is here spoken of; for the directions were given about it in the fourth year of Jehoiakim, whereas this was done in the fifth year, Jer 36:9. But some think that the writing of the book fairly over took up so much time that it was another year ere it was perfected; and yet perhaps it might not be past a month or two; he...', 'teologico');
add('jr', 36, 20, 'Matthew Henry', 'We have traced the roll to the people, and to the princes, and here we are to follow it to the king; and we find,\nI. That, upon notice given him concerning it, he sent for it, and ordered it to be read to him, Jer 36:20, Jer 36:21. He did not desire that Baruch would come and read it himself, who could read it more intelligently and with more authority and affection than any one else; nor did he order one of his princes to do it (though it would have been no disparagement to the greatest of t...', 'teologico');
add('jr', 37, 1, 'Matthew Henry', 'Here is, 1. Jeremiah\'s preaching slighted, Jer 37:1, Jer 37:2. Zedekiah succeeded Coniah, or Jeconiah, and, though he saw in his predecessor the fatal consequences of contemning the word of God, yet he did not take warning, nor give any more regard to it than others had done before him. Neither he, nor his courtiers, nor the people of the land, hearkened unto the words of the Lord, though they already began to be fulfilled. Note, Those have hearts wretchedly hard indeed that see God\'s judgmen...', 'teologico');
add('jr', 37, 11, 'Matthew Henry', 'We have here a further account concerning Jeremiah, who relates more passages concerning himself than any other of the prophets; for the histories of the lives and sufferings of God\'s ministers have been very serviceable to the church, as well as their preaching and writing.\nI. We are here told that Jeremiah, when he had an opportunity for it, attempted to retire out of Jerusalem into the country (Jer 37:11, Jer 37:12): When the Chaldeans had broken up from Jerusalem because of Pharaoh\'s army...', 'teologico');
add('jr', 38, 1, 'Matthew Henry', 'Here, 1. Jeremiah persists in his plain preaching; what he had many a time said, he still says (Jer 38:3): This city shall be given into the hand of the king of Babylon; though it hold out long, it will taken at last. Nor would he have so often repeated this unwelcome message but that he could put them in a certain way, though not to save the city, yet to save themselves; so that every man might have his own life given him for a prey if he would be advised, Jer 38:2. Let him not stay in the c...', 'teologico');
add('jr', 38, 14, 'Matthew Henry', 'In the foregoing chapter we had the king in close conference with Jeremiah, and here again, though (Jer 38:5) he had given him up into the hands of his enemies; such a struggle there was in the breast of this unhappy prince between his convictions and his corruptions. Observe,\nI. The honour that Zedekiah did to the prophet. When he was newly fetched out of the dungeon he sent for him to advise with him privately. He met him in the third entry, or (as the margin reads it) the principal entry, ...', 'teologico');
add('jr', 39, 1, 'Matthew Henry', 'We were told, in the close of the foregoing chapter, that Jeremiah abode patiently in the court of the prison, until the day that Jerusalem was taken. He gave the princes no further disturbance by his prophesying, nor they him by their persecutions; for he had no more to say than what he had said, and, the siege being carried on briskly, God found them other work to do. See here what it came to.\nI. The city is at length taken by storm; for how could it hold out when God himself fought against...', 'teologico');
add('jr', 39, 11, 'Matthew Henry', 'Here we must sing of mercy, as in the former part of the chapter we sang of judgment, and must sing unto God of both. We may observe here,\nI. A gracious providence concerning Jeremiah. When Jerusalem was laid in ruins, and all men\'s hearts failed them for fear, then might he lift up his head with comfort, knowing that his redemption drew nigh, as Christ\'s followers when the second destruction of Jerusalem was hastening on, Luk 21:28. Nebuchadnezzar had given particular orders that care should...', 'teologico');
add('jr', 40, 1, 'Matthew Henry', 'The title of this part of the book, which begins the chapter, seems misapplied (The word which came to Jeremiah), for here is nothing of prophecy in this chapter, but it is to be referred to Jer 42:7, where we have a message that God sent by Jeremiah to the captains and the people that remained. The story between is only to introduce that prophecy and show the occasion of it, that it may be the better understood, and Jeremiah, being himself concerned in the story, was the better able to give ...', 'teologico');
add('jr', 40, 7, 'Matthew Henry', 'We have in these verses,\nI. A bright sky opening upon the remnant of the Jews that were left in their own land, and a comfortable prospect given them of some peace and quietness after the many years of trouble and terror with which they had been afflicted. Jeremiah indeed had never in his prophecies spoken of any such good days reserved for the Jews immediately after the captivity; but Providence seemed to raise and encourage such an expectation, and it would be to that miserable people as li...', 'teologico');
add('jr', 41, 1, 'Matthew Henry', 'It is hard to say which is more astonishing, God\'s permitting or men\'s perpetrating such villanies as here we find committed. Such base, barbarous, bloody work is here done by men who by their birth should have been men of honour, by their religion just men, and this done upon those of their own nature, their own nation, their own religion, and now their brethren in affliction, when they were all brought under the power of the victorious Chaldeans, and smarting under the judgments of God, upo...', 'teologico');
add('jr', 41, 11, 'Matthew Henry', 'It would have been well if Johanan, when he gave information to Gedaliah of Ishmael\'s treasonable design, though he could not obtain leave to kill Ishmael and to prevent it that way, yet had staid with Gedaliah; for he, and his captains, and their forces, might have been a life-guard to Gedaliah and a terror to Ishmael, and so have prevented the mischief without the effusion of blood: but, it seems they were out upon some expedition, perhaps no good one, and so were out of the way when they s...', 'teologico');
add('jr', 42, 1, 'Matthew Henry', 'We have reason to wonder how Jeremiah the prophet escaped the sword of Ishmael; it seems he did escape, and it was not the first time that the Lord hid him. It is strange also that in these violent turns he was not consulted before now, and his advice asked and taken. But it should seem as if they knew not that a prophet was among them. Though this people were as brands plucked out of the fire, yet have they not returned to the Lord. This people has a revolting and a rebellious heart; and con...', 'teologico');
add('jr', 42, 7, 'Matthew Henry', 'We have here the answer which Jeremiah was sent to deliver to those who employed him to ask counsel of God.\nI. It did not come immediately, not till ten days after, Jer 42:7. They were thus long held in suspense, perhaps, to punish them for their hypocrisy or to show that Jeremiah did not speak of himself, nor what he would, for he could not speak when he would, but must wait for instructions. However, it teaches us to continue waiting upon God for direction in our way. The vision is for an a...', 'teologico');
add('jr', 43, 1, 'Matthew Henry', 'What God said to the builders of Babel may be truly said of this people that Jeremiah is now dealing with: Now nothing will be restrained from them which they have imagined to do, Gen 11:6. They have a fancy for Egypt, and to Egypt they will go, whatever God himself says to the contrary. Jeremiah made them hear all he had to say, though he saw them uneasy at it; it was what the Lord their God had sent him to speak to them, and they shall have it all. And now let us see what they have to say t...', 'teologico');
add('jr', 43, 8, 'Matthew Henry', 'We have here, as also in the next chapter, Jeremiah prophesying in Egypt. Jeremiah was now in Tahpanhes, for there his lords and masters were; he was there among idolatrous Egyptians and treacherous Israelites; but there, 1. He received the word of the Lord; it came to him. God can find his people, with the visits of his grace, wherever they are; and, when his ministers are bound, yet the word of the Lord is not bound. The spirit of prophecy was not confined to the land of Israel. When Jeremi...', 'teologico');
add('jr', 44, 1, 'Matthew Henry', 'The Jews in Egypt were now dispersed into various parts of the country, into Migdol, and Noph, and other places, and Jeremiah was sent on an errand from God to them, which he delivered either when he had the most of them together in Pathros (Jer 44:15) or going about from place to place preaching to this purport. He delivered this message in the name of the Lord of hosts, the God of Israel, and in it,\nI. God puts them in mind of the desolations of Judah and Jerusalem, which, though the captiv...', 'teologico');
add('jr', 44, 15, 'Matthew Henry', 'We have here the people\'s obstinate refusal to submit to the power of the word of God in the mouth of Jeremiah. We have scarcely such an instance of downright daring contradiction to God himself as this, or such an avowed rebellion of the carnal mind. Observe,\nI. The persons who thus set God and his judgments at defiance; it was not some one that was thus obstinate, but the generality of the Jews; and they were such as knew either themselves or their wives to be guilty of the idolatry Jeremia...', 'teologico');
add('jr', 44, 20, 'Matthew Henry', 'Daring sinners may speak many a bold word and many a big word, but, after all, God will have the last word; for he will be justified when he speaks, and all flesh, even the proudest, shall be silent before him. Prophets may be run down, but God cannot; nay, here the prophet would not.\nI. Jeremiah has something to say to them from himself, which he could say without a spirit of prophecy, and that was to rectify their mistake (a wilful mistake it was) concerning the calamities they had been und...', 'teologico');
add('jr', 45, 1, 'Matthew Henry', 'How Baruch was employed in writing Jeremiah\'s prophecies, and reading them, we had an account ch. 36, and how he was threatened for it by the king, warrants being out for him and he forced to abscond, and how narrowly he escaped under a divine protection, to which story this chapter should have been subjoined, but that, having reference to a private person, it is here thrown into the latter end of the book, as St. Paul\'s epistle to Philemon is put after his other epistles. Observe,\nI. The con...', 'teologico');
add('jr', 46, 1, 'Matthew Henry', 'The first verse is the title of that part of this book, which relates to the neighbouring nations, and follows here. It is the word of the Lord which came to Jeremiah against the Gentiles; for God is King and Judge of nations, knows and will call to an account those who know him not nor take any notice of him. Both Isaiah and Ezekiel prophesied against these nations that Jeremiah here has a separate saying to, and with reference to the same events. In the Old Testament we have the word of the...', 'teologico');
add('jr', 46, 13, 'Matthew Henry', 'In these verses we have,\nI. Confusion and terror spoken to Egypt. The accomplishment of the prediction in the former part of the chapter disabled the Egyptians from making any attempts upon other nations; for what could they do when their army was routed? But still they remained strong at home, and none of their neighbours durst make any attempts upon them. Though the kings of Egypt came no more out of their land (Kg2 24:7), yet they kept safe and easy in their land; and what would they desir...', 'teologico');
add('jr', 47, 1, 'Matthew Henry', 'As the Egyptians had often proved false friends, so the Philistines had always been sworn enemies, to the Israel of God, and the more dangerous and vexatious for their being such near neighbours to them. They were considerably humbled in David\'s time, but, it seems they had got head again and were a considerable people till Nebuchadnezzar cut them off with their neighbours, which is the event here foretold. The date of this prophecy is observable; it was before Pharaoh smote Gaza. When this b...', 'teologico');
add('jr', 48, 1, 'Matthew Henry', 'We may observe in these verses,\nI. The author of Moab\'s destruction; it is the Lord of hosts, that has armies, all armies, at his command, and the God of Israel (Jer 48:1), who will herein plead the cause of his Israel against a people that have always been vexatious to them, and will punish them now for the injuries done to Israel of old, though Israel was forbidden to meddle with them (Deu 2:9), therefore the destruction of Moab is called the work of the Lord (Jer 48:10), for it is he that ...', 'teologico');
add('jr', 48, 14, 'Matthew Henry', 'The destruction is here further prophesied of very largely and with a great copiousness and variety of expression, and very pathetically and in moving language, designed not only to awaken them by a national repentance and reformation to prevent the trouble, or by a personal repentance and reformation to prepare for it, but to affect us with the calamitous state of human life, which is liable to such lamentable occurrences, and with the power of God\'s anger and the terror of his judgments, wh...', 'teologico');
add('jr', 49, 1, 'Matthew Henry', 'The Ammonites were next, both in kindred and neighbourhood, to the Moabites, and therefore are next set to the bar. Their country joined to that of the two tribes and a half, on the other side Jordan, and was but a bad neighbour; however, being a neighbour, they shall have a share in these circular predictions. 1. An action is here brought, in God\'s name, against the Ammonites, for an illegal encroachment upon the rightful possessions of the tribe of Gad, that lay next them, Jer 49:1. A writ ...', 'teologico');
add('jr', 49, 7, 'Matthew Henry', 'The Edomites come next to receive their doom from God, by the mouth of Jeremiah: they also were old enemies to the Israel of God; but their day will come to be reckoned with, and it is now at hand, and is foretold, not only for warning to them, but for comfort to the Israel of God, whose afflictions were very much aggravated by their triumphs over them and joy in their calamity, Psa 137:7. Many of the expressions used in this prophecy concerning Edom are borrowed from the prophecy of Obadiah,...', 'teologico');
add('jr', 49, 23, 'Matthew Henry', 'The kingdom of Syria lay north of Canaan, as that of Edom lay south, and thither we must now remove and take a view of the approaching fate of that kingdom, which had been often vexatious to the Israel of God. Damascus was the metropolis of that kingdom, and the ruin of the whole is supposed in the ruin of that: yet Hamath and Arpad, two other considerable cities, are names (Jer 49:23), and the palaces of Ben-hadad, which he built, are particularly marked for ruin, Jer 49:27; see also Amo 1:4...', 'teologico');
add('jr', 49, 28, 'Matthew Henry', 'These verses foretell the desolation that Nebuchadnezzar and his forces should make among the people of Kedar (who descended from Kedar the son of Ishmael, and inhabited a part of Arabia the Stony), and of the kingdoms, the petty principalities, of Hazor, that joined to them, who perhaps were originally Canaanites, of the kingdom of Hazor, in the north of Canaan, which had Jabin for its king, but, being driven thence, settled in the deserts of Arabia and associated themselves with the Kedaren...', 'teologico');
add('jr', 49, 34, 'Matthew Henry', 'This prophecy is dated in the beginning of Zedekiah\'s reign; it is probable that the other prophecies against the Gentiles, going before, were at the same time. The Elamites were the Persians, descended from Elam the son of Shem (Gen 10:22); yet some think it was only that part of Persia which lay nearest to the Jews which was called Elymais, and adjoined to Media-Elam, which, say they, had acted against God\'s Israel, bore the quiver in an expedition against them (Isa 22:6), and therefore mus...', 'teologico');
add('jr', 50, 1, 'Matthew Henry', 'I. Here is a word spoken against Babylon by him whose works all agree with his word and none of whose words fall to the ground. The king of Babylon had been very kind of Jeremiah, and yet he must foretel the ruin of that kingdom; for God\'s prophets must not be governed by favour or affection. Whoever are our friends, if, notwithstanding, they are God\'s enemies, we dare not speak peace to them. 1. The destruction of Babylon is here spoken of as a thing done, Jer 50:2. let it be published to th...', 'teologico');
add('jr', 50, 9, 'Matthew Henry', 'God is here by his prophet, as afterwards in his providence, proceeding in his controversy with Babylon. Observe,\nI. The commission and charge given to the instruments that were to be employed in destroying Babylon. The army that is to do it is called an assembly of great nations (Jer 50:9), the Medes and Persians, and all their allies and auxiliaries; it is called an assembly, because regularly formed by the divine will and counsel to do this execution. God will raise them up to do it, will ...', 'teologico');
add('jr', 50, 21, 'Matthew Henry', 'Here, 1. The forces are mustered and commissioned to destroy Babylon, and every thing is got ready for a descent upon that potent kingdom: Go up against that land by Merathaim, the country of the Mardi, that lay part in Assyria and part in Armenia; and go among the inhabitants of Pekod, another country (mentioned Eze 23:23) which Cyrus took in his way to Babylon. The forces of Cyrus are called to go up against Babylon (Jer 50:21), to come against her from the utmost border. Let all come toget...', 'teologico');
add('jr', 50, 33, 'Matthew Henry', 'We have in these verses,\nI. Israel\'s sufferings, and their deliverance out of those sufferings. God takes notice of the bondage of his people in Babylon, as he did of their bondage in Egypt; he has surely seen it, and has heard their cry. Israel and Judah were oppressed together, Jer 50:33. Those that remained of the captives of the ten tribes, upon the uniting of the kingdoms of Assyria and Chaldea, seem to have come and mingled with t hose of the two tribes, and to have mingled tears with t...', 'teologico');
add('jr', 51, 1, 'Matthew Henry', 'The particulars of this copious prophecy are dispersed and interwoven, and the same things left and returned to so often that it could not well be divided into parts, but we must endeavor to collect them under their proper heads. Let us then observe here,\nI. An acknowledgment of the great pomp and power that Babylon had been in and the use that God in his providence had made of it (Jer 51:7): Babylon hath been a golden cup, a rich and glorious empire, a golden city (Isa 14:4), a head of gold ...', 'teologico');
add('jr', 51, 59, 'Matthew Henry', 'We have been long attending the judgment of Babylon in this and the foregoing chapter; now here we have the conclusion of that whole matter. 1. A copy is taken of this prophecy, it should seem by Jeremiah himself, for Baruch his scribe is not mentioned here (Jer 51:60): Jeremiah wrote in a book all these words that are here written against Babylon. He received this notice that he might give it to all whom it might concern. It is of great advantage both to the propagating and to the perpetuati...', 'teologico');
add('jr', 52, 1, 'Matthew Henry', 'This narrative begins no higher than the beginning of the reign of Zedekiah, though there were two captivities before, one in the fourth year of Jehoiakim, the other in the first of Jeconiah; but probably it was drawn up by some of those that were carried away with Zedekiah, as a reproach to themselves for imagining that they should not go into captivity after their brethren, with which hopes they had long flattered themselves. We have here, 1. God\'s just displeasure against Judah and Jerusal...', 'teologico');
add('jr', 52, 12, 'Matthew Henry', 'We have here an account of the woeful havoc that was made by the Chaldean army, a month after the city was taken, under the command of Nebuzaradan, who was captain of the guard, or general of the army, in this action. In the margin he is called the chief of the slaughter-men, or executioners; for soldiers are but slaughter-men, and God employs them as executioners of his sentence against a sinful people. Nebuzaradan was chief of those soldiers, but, in the execution he did, we have reason to ...', 'teologico');
add('jr', 52, 24, 'Matthew Henry', 'We have here a very melancholy account, 1. Of the slaughter of some great men, in cold blood, at Riblah, seventy-two in number (according to the number of the elders of Israel, Num 11:24, Num 11:25), so they are computed, Kg2 25:18, Kg2 25:19. We read there of five out of the temple, two out of the city, five out of the court, and sixty out of the country. The account here agrees with that, except in one article; there it is said that there were five, here there were seven, of those that were...', 'teologico');
add('jr', 52, 31, 'Matthew Henry', 'This passage of story concerning the reviving which king Jehoiachin had in his bondage we had likewise before (Kg2 25:27-30), only there it is said to be done on the twenty-seventh day of the twelfth month, here on the twenty-fifth; but in a thing of this nature two days make a very slight difference in the account. It is probable that the orders were given for his release on the twenty-fifth day, but that he was not presented to the king till the twenty-seventh. We may observe in this story,...', 'teologico');

// LM (16 comentários)
add('lm', 3, 22, 'Spurgeon', 'As misericórdias do Senhor são a cada manhã — A fidelidade renovada de Deus sustenta no sofrimento.', 'teologico');
add('lm', 3, 25, 'Calvino', 'Bom é o Senhor para os que esperam — A espera paciente encontra bondade divina.', 'teologico');
add('lm', 1, 1, 'Matthew Henry', 'Those that have any disposition to weep with those that weep, one would think, should scarcely be able to refrain from tears at the reading of these verses, so very pathetic are the lamentations here.\nI. The miseries of Jerusalem are here complained of as very pressing and by many circumstances very much aggravated. Let us take a view of these miseries.\n1. As to their civil state. (1.) A city that was populous is now depopulated, Lam 1:1. It is spoken of by way of wonder - Who would have thou...', 'teologico');
add('lm', 1, 12, 'Matthew Henry', 'The complaints here are, for substance, the same with those in the foregoing part of the chapter; but in these verses the prophet, in the name of the lamenting church, does more particularly acknowledge the hand of god in these calamities, and the righteousness of his hand.\nI. The church in distress here magnifies her affliction, and yet no more than there was cause for; her groaning was not heavier than her strokes. She appeals to all spectators: See if there be any sorrow like unto my sorro...', 'teologico');
add('lm', 2, 1, 'Matthew Henry', 'It is a very sad representation which is here made of the state of God\'s church, of Jacob and Israel, of Zion and Jerusalem; but the emphasis in these verses seems to be laid all along upon the hand of God in the calamities which they were groaning under. The grief is not so much that such and such things are done as that God has done them, that he appears angry with them; it is he that chastens them, and chastens them in wrath and in his hot displeasure; he has become their enemy, and fights...', 'teologico');
add('lm', 2, 10, 'Matthew Henry', 'Justly are these called Lamentations, and they are very pathetic ones, the expressions of grief in perfection, mourning and woe, and nothing else, like the contents of Ezekiel\'s roll, Eze 2:10.\nI. Copies of lamentations are here presented and they are painted to the life. 1. The judges and magistrates, who used to appear in robes of state, have laid them aside, or rather are stripped of them, and put on the habit of mourners (Lam 2:10); the elders now sit no longer in the judgment-seats, the ...', 'teologico');
add('lm', 3, 1, 'Matthew Henry', 'The title of the 102nd Psalm might very fitly be prefixed to this chapter - The prayer of the afflicted, when he is overwhelmed, and pours out his complaint before the Lord; for it is very feelingly and fluently that the complaint is here poured out. Let us observe the particulars of it. The prophet complains, 1. That God is angry. This gives both birth and bitterness to the affliction (Lam 3:1): I am the man, the remarkable man, that has seen affliction, and has felt it sensibly, by the rod ...', 'teologico');
add('lm', 3, 21, 'Matthew Henry', 'Here the clouds begin to disperse and the sky to clear up; the complaint was very melancholy in the former part of the chapter, and yet here the tune is altered and the mourners in Zion begin to look a little pleasant. But for hope, the heart would break. To save the heart from being quite broken, here is something called to mind, which gives ground for hope (Lam 3:21), which refers to what comes after, not to what goes before. I make to return to my heart (so the margin words it); what we ha...', 'teologico');
add('lm', 3, 37, 'Matthew Henry', 'That we may be entitled to the comforts administered to the afflicted in the foregoing verses, and may taste the sweetness of them, we have here the duties of an afflicted state prescribed to us, in the performance of which we may expect those comforts.\nI. We must see and acknowledge the hand of God in all the calamities that befal us at any time, whether personal or public, Lam 3:37, Lam 3:38. This is here laid down as a great truth, which will help to quiet our spirits under our afflictions...', 'teologico');
add('lm', 3, 42, 'Matthew Henry', 'It is easier to chide ourselves for complaining than to chide ourselves out of it. The prophet had owned that a living man should not complain, as if he checked himself for his complaints in the former part of the chapter; and yet here the clouds return after the rain and the wound bleeds afresh; for great pains must be taken with a troubled spirit to bring it into temper.\nI. They confess the righteousness of God in afflicting them (Lam 3:42): We have transgressed and have rebelled. Note, It ...', 'teologico');
add('lm', 3, 55, 'Matthew Henry', 'We may observe throughout this chapter a struggle in the prophet\'s breast between sense and faith, fear and hope; he complains and then comforts himself, yet drops his comforts and returns again to his complaints, as Psa 42:1-11. But, as there, so here, faith gets the last word and comes off a conqueror; for in these verses he concludes with some comfort. And here are two things with which he comforts himself: - \nI. His experience of God\'s goodness even in his affliction. This may refer to th...', 'teologico');
add('lm', 4, 1, 'Matthew Henry', 'The elegy in this chapter begins with a lamentation of the very sad and doleful change which the judgments of God had made in Jerusalem. The city that was formerly as gold, as the most fine gold, so rich and splendid, the perfection of beauty and the joy of the whole earth, has become dim, and is changed, has lost its lustre, lost its value, is not what it was; it has become dross. Alas! what an alteration is here!\nI. The temple was laid waste, which was the glory of Jerusalem and its protect...', 'teologico');
add('lm', 4, 13, 'Matthew Henry', 'We have here,\nI. The sins they were charged with, for which God brought this destruction upon them, and which served to justify God in it (Lam 4:13, Lam 4:14): It is for the sins of her prophets, and the iniquities of her priests. Not that the people were innocent; no, they loved to have it so (Jer 5:31), and it was to please them that the prophets and priests did as they did; but the fault is chiefly laid upon them, who should have taught them better, should have reproved and admonished them...', 'teologico');
add('lm', 4, 21, 'Matthew Henry', 'David\'s psalms of lamentation commonly conclude with some word of comfort, which is as life from the dead and light shining out of darkness; so does this lamentation here in this chapter. The people of God are now in great distress, their aspects all doleful, their prospects all frightful, and their ill-natured neighbours the Edomites insult over them and do all they can to exasperate their destroyers against them. Such was their violence against their brother Jacob (Oba 1:10), such their spl...', 'teologico');
add('lm', 5, 1, 'Matthew Henry', 'Is any afflicted? let him pray; and let him in prayer pour out his complaint to God, and make known before him his trouble. The people of God do so here; being overwhelmed with grief, they give vent to their sorrows at the footstool of the throne of grace, and so give themselves ease. They complain not of evils feared, but of evils felt: "Remember what has come upon us, Lam 5:1. What was of old threatened against us, and was long in the coming, has now at length come upon us, and we are ready...', 'teologico');
add('lm', 5, 17, 'Matthew Henry', 'Here, I. The people of God express the deep concern they had for the ruins of the temple, more than for any other of their calamities; the interests of God\'s house lay nearer their hearts than those of their own (Lam 5:17, Lam 5:18): For this our heart is faint, and sinks under the load of its own heaviness; for these things our eyes are dim, and our sight is gone, as is usual in a deliquium, or fainting fit. "It is because of the mountain of Zion, which is desolate, the holy mountain, and th...', 'teologico');

// EZ (2 comentários)
add('ez', 36, 26, 'Calvino', 'Vos darei um coração novo — A regeneração é obra de Deus: Ele substitui o coração de pedra.', 'teologico');
add('ez', 37, 5, 'Agostinho', 'Vós revivereis — A visão dos ossos secos: Deus dá vida onde há apenas morte.', 'escatologico');

// DN (49 comentários)
add('dn', 2, 44, 'Spurgeon', 'Um reino eterno — O reino de Deus é permanente e indestrutível, superando todos os reinos da terra.', 'escatologico');
add('dn', 3, 17, 'N.T. Wright', 'Nosso Deus pode nos livrar — A fé que enfrenta o sofrimento: mesmo sem livramento, Deus é fiel.', 'aplicacao');
add('dn', 3, 18, 'Tim Keller', 'Mesmo que não — A fé que não depende do resultado: Deus é digno de confiança em qualquer circunstância.', 'aplicacao');
add('dn', 7, 13, 'N.T. Wright', 'Veio com as nuvens — O Filho do Homem recebido pelo Ancião de Dias: a transferência de autoridade.', 'escatologico');
add('dn', 7, 14, 'Tomás de Aquino', 'Domínio eterno — O poder do Filho do Homem é absoluto, universal e perpétuo.', 'teologico');
add('dn', 9, 25, 'Calvino', 'Setenta semanas — A profecia das setenta semanas: cronologia messiânica precisa.', 'escatologico');
add('dn', 9, 27, 'Matthew Henry', 'Ele confirmará a aliança — A aliança confirmada pelo Messias é a nova aliança prometida por Jeremias.', 'escatologico');
add('dn', 9, 24, 'Albert Barnes', 'Para consumar a profecia — As setenta semanas têm cumprimento em Cristo: a obra messiânica é definitiva.', 'escatologico');
add('dn', 12, 1, 'Spurgeon', 'Nesse tempo se levantará Miguel — A escatologia final: livramento para os que dormem na terra.', 'escatologico');
add('dn', 12, 3, 'Lloyd-Jones', 'Os que forem sábios brilharão — A sabedoria que vem de Deus tem recompensa eterna.', 'escatologico');
add('dn', 1, 1, 'Matthew Henry', 'We have in these verses an account,\nI. Of the first descent which Nebuchadnezzar, king of Babylon, in the first year of his reign, made upon Judah and Jerusalem, in the third year of the reign of Jehoiakim, and his success in that expedition (Dan 1:1, Dan 1:2.): He besieged Jerusalem, soon made himself master of it, seized the king, took whom he pleased and what he pleased away with him, and then left Jehoiakim to reign as tributary to him, which he did about eight years longer, but then rebe...', 'teologico');
add('dn', 1, 8, 'Matthew Henry', 'We observe here, very much to our satisfaction,\nI. That Daniel was a favourite with the prince of the eunuchs (Dan 1:9), as Joseph was with the keeper of the prison; he had a tender love for him. No doubt Daniel deserved it, and recommended himself by his ingenuity and sweetness of temper (he was greatly beloved, Dan 9:23); and yet it is said here that it was God that brought him into favour with the prince of the eunuchs, for every one does not meet with acceptance according to his merits. N...', 'teologico');
add('dn', 1, 17, 'Matthew Henry', 'Concerning Daniel and his fellows we have here,\nI. Their great attainments in learning, Dan 1:17. They were very sober and diligent, and studied hard; and we may suppose their tutors, finding them of an uncommon capacity, took a great deal of pains with them, but, after all, their achievements are ascribed to God only. It was he that gave them knowledge and skill in all learning and wisdom; for every good and perfect gift is from above, from the Father of the lights. It is the Lord our God th...', 'teologico');
add('dn', 2, 1, 'Matthew Henry', 'We meet with a great difficulty in the date of this story; it is said to be in the second year of the reign of Nebuchadnezzar, Dan 2:1. Now Daniel was carried to Babylon in his first year, and, it should seem, he was three years under tutors and governors before he was presented to the king, Dan 1:5. How then could this happen in the second year? Perhaps, though three years were appointed for the education of other children, yet Daniel was so forward that he was taken into business when he ha...', 'teologico');
add('dn', 2, 14, 'Matthew Henry', 'When the king sent for his wise men to tell them his dream, and the interpretation of it (Dan 2:2), Daniel, it seems, was not summoned to appear among them; the king, though he was highly pleased with him when he examined him, and thought him ten times wiser than the rest of his wise men, yet forgot him when he had most occasion for him; and no wonder, when all was done in a heat, and nothing with a cool and deliberate thought. But Providence so ordered it; that the magicians being nonplussed...', 'teologico');
add('dn', 2, 24, 'Matthew Henry', 'We have here the introduction to Daniel\'s declaring the dream, and the interpretation of it.\nI. He immediately bespoke the reversing of the sentence against the wise men of Babylon, Dan 2:24. He went with all speed to Arioch, to tell him that his commission was now superseded: Destroy not the wise men of Babylon. Though there were those of them perhaps that deserved to die, as magicians, by the law of God, yet here that which they stood condemned for was not a crime worth of death or of bonds...', 'teologico');
add('dn', 2, 31, 'Matthew Henry', 'Daniel here gives full satisfaction to Nebuchadnezzar concerning his dream and the interpretation of it. That great prince had been kind to this poor prophet in his maintenance and education; he had been brought up at the king\'s cost, preferred at court, and the land of his captivity had hereby been made much easier to him than to others of his brethren. And now the king is abundantly repaid for all the expense he had been at upon him; and for receiving this prophet, though not in the name of...', 'teologico');
add('dn', 2, 46, 'Matthew Henry', 'One might have expected that when Nebuchadnezzar was contriving to make his own kingdom everlasting he would be enraged at Daniel, who foretold the fall of it and that another kingdom of another nature should be the everlasting kingdom; but, instead of resenting it as an affront, he received it as an oracle, and here we are told what the expressions were of the impressions it made upon him. 1. He was ready to look upon Daniel as a little god. Though he saw him to be a man, yet from this wonde...', 'teologico');
add('dn', 3, 1, 'Matthew Henry', 'We have no certainty concerning the date of this story, only that if this image, which Nebuchadnezzar dedicated, had any relation to that which he dreamed of, it is probable that it happened not long after that; some reckon it to be about the seventh year of Nebuchadnezzar, a year before Jehoiachin\'s captivity, in which Ezekiel was carried away. Observe,\nI. A golden image set up to be worshipped. Babylon was full of idols already, yet nothing will serve this imperious prince but they must hav...', 'teologico');
add('dn', 3, 8, 'Matthew Henry', 'It was strange that Shadrach, Meshach, and Abednego, would be present at this assembly, when, it is likely, they knew for what intent it was called together. Daniel, we may suppose, was absent, either his business calling him away or having leave from the king to withdraw, unless we suppose that he stood so high in the king\'s favour that none durst complain of him for his noncompliance. But why did not his companions keep out of the way? Surely because they would obey the king\'s orders as far...', 'teologico');
add('dn', 3, 19, 'Matthew Henry', 'In these verses we have,\nI. The casting of these three faithful servants of God into the fiery furnace. Nebuchadnezzar had himself known and owned so much of the true God that, one would have thought, though his pride and vanity induced him to make this golden image, and set it up to be worshipped, yet what these young men now said (whom he had formerly found to be wiser than all his wise men) would revive his convictions, and at least engage him to excuse them; but it proved quite otherwise....', 'teologico');
add('dn', 3, 28, 'Matthew Henry', 'The strict observations that were made, super visum corporis - on inspecting their bodies, by the princes and governors, and all the great men who were present upon this public occasion, and who could not be supposed partial in favour of the confessors, contributed much to the clearing of this miracle and the magnifying of the power and grace of God in it. That indeed a notable miracle has been done is manifest, and we cannot deny it, Act 4:16. Let us now see what effect it had upon Nebuchadn...', 'teologico');
add('dn', 4, 1, 'Matthew Henry', 'Here is, I. Something of form, which was usual in writs, proclamations, or circular letters, issued by the king, Dan 4:1. The royal style which Nebuchadnezzar makes use of has nothing in it of pomp or fancy, but is plain, short, and unaffected - Nebuchadnezzar the king. If at other times he made use of great swelling words of vanity in his title, how he laid them all aside; for he was old, he had lately recovered from a distraction which had humbled and mortified him, and was now in the actua...', 'teologico');
add('dn', 4, 4, 'Matthew Henry', 'Nebuchadnezzar, before he relates the judgments of God that had been wrought upon him for his pride, gives an account of the fair warning he had of them before they came, a due regard to which might have prevented them. But he was told of them, and of the issue of them, before they came to pass, that, when they did come to pass, by comparing them with the prediction of them, he might see, and say, that they were the Lord\'s doing, and might be brought to believe that there is a divine revelati...', 'teologico');
add('dn', 4, 19, 'Matthew Henry', 'We have here the interpretation of Nebuchadnezzar\'s dream; and when once it is applied to himself, and it is declared that he is the tree in the dream (Mutato nomine de te fabula narratur - Change but the name, the fable speaks of thee), when once it is said, Thou art the man, there needs little more to be said for the explication of the dream. Out of his own mouth he is judged; so shall his doom be, he himself has decided it. The thing was so plain that Daniel, upon hearing the dream, was as...', 'teologico');
add('dn', 4, 28, 'Matthew Henry', 'We have here Nebuchadnezzar\'s dream accomplished, and Daniel\'s application of it to him justified and confirmed. How he took it we are not told, whether he was pleased with Daniel or displeased; but here we have,\nI. God\'s patience with him: All this came upon him, but not till twelve months after (Dan 4:29), so long there was a lengthening of his tranquility, though it does not appear that he broke off his sins, or showed any mercy to the poor captives, for this was still God\'s quarrel with h...', 'teologico');
add('dn', 4, 34, 'Matthew Henry', 'We have here Nebuchadnezzar\'s recovery from his distraction, and his return to his right mind, at the end of the days prefixed, that is, of the seven years. So long he continued a monument of God\'s justice and a trophy of his victory over the children of pride, and he was made more so by being struck mad than if he had been in an instant struck dead with a thunderbolt; yet it was a mercy to him that he was kept alive, for while there is life there is hope that we may yet praise God, as he did...', 'teologico');
add('dn', 5, 1, 'Matthew Henry', 'We have here Belshazzar the king very gay, but all of a sudden very gloomy, and in straits in the fulness of his sufficiency. See how he affronts God, and God affrights him; and wait what will be the issue of this contest; and whether he that hardened his heart against God prospered.\nI. See how the king affronted God, and put contempt upon him. He made a great feast, or banquet of wine; probably it was some anniversary solemnity, in honour off his birthday or coronation-day, or in honour of s...', 'teologico');
add('dn', 5, 10, 'Matthew Henry', 'Here is, I. The information given to the king, by the queen-mother, concerning Daniel, how fit he was to be consulted in this difficult case. It is supposed that this queen was the widow of Evil-Merodach, and was that famous Nitocris whom Herodotus mentions as a woman of extraordinary prudence. She was not present at the feast, as the king\'s wives and concubines were (Dan 5:2); it was not agreeable to her age and gravity to keep a merry night. But, tidings of the fright which the king and his...', 'teologico');
add('dn', 5, 30, 'Matthew Henry', 'Here is, 1. The death of the king. Reason enough he had to tremble, for he was just falling into the hands of the king of terrors, Dan 5:30. In that night, when his heart was merry with wine, the besiegers broke into the city, aimed at the palace; there they found the king, and gave him his death\'s wound. He could not find any place so secret as to conceal him, or so strong as to protect him. Heathen writers speak of Cyrus\'s taking Babylon by surprise, with the assistance of two deserters tha...', 'teologico');
add('dn', 6, 1, 'Matthew Henry', 'We are told concerning Daniel,\nI. What a great man he was. When Darius, upon his accession to the crown of Babylon by conquest, new-modelled the government, he made Daniel prime-minister of state, set him at the helm, and made him first commissioner both of the treasury and of the great seal. Darius\'s dominion was very large; all he got by his conquests and acquests was that he had so many more countries to take care of; no more can be expected from himself than what one man can do, and there...', 'teologico');
add('dn', 6, 6, 'Matthew Henry', 'Daniel\'s adversaries could have no advantage against him from any law now in being; they therefore contrive a new law, by which they hope to ensnare him, and in a matter in which they knew they should be sure of him; and such was his fidelity to his God that they gained their point. Here is,\nI. Darius\'s impious law. I call it Darius\'s, because he gave the royal assent to it, and otherwise it would not have been of force; but it was not properly his: he contrived it not, and was perfectly whee...', 'teologico');
add('dn', 6, 11, 'Matthew Henry', 'Here is 1. Proof made of Daniel\'s praying to his God, notwithstanding the late edict to the contrary (Dan 6:11): These men assembled; the came tumultuously together, so the word is, the same that was used Dan 6:6, borrowed from Psa 2:1, Why do the heathen rage? They came together to visit Daniel, perhaps under pretence of business, at that time which they knew to be his usual hour of devotion; and, if they had not found him so engaged, they would have upbraided him with his faint-heartedness ...', 'teologico');
add('dn', 6, 18, 'Matthew Henry', 'Here is, I. The melancholy night which the king had, upon Daniel\'s account, Dan 6:18. He had said, indeed, that God would deliver him out of the danger, but at the same time he could not forgive himself for throwing him into the danger; and justly might God deprive him of a friend whom he had himself used so barbarously. He went to his palace, vexed at himself for what he had done, and calling himself unwise and unjust for not adhering to the law of God and nature with a non obstante - a nega...', 'teologico');
add('dn', 6, 25, 'Matthew Henry', 'Darius here studies to make some amends for the dishonour he had done both to God and Daniel, in casting Daniel into the lions\' den, by doing honour to both.\nI. He gives honour to God by a decree published to all nations, by which they are required to fear before him. And this is a decree which is indeed fit to be made unalterable, according to the laws of the Medes and Persians, for it is the everlasting gospel, preached to those that dwell on the earth, Rev 14:7. Fear God, and give glory to...', 'teologico');
add('dn', 7, 1, 'Matthew Henry', 'The date of this chapter places it before ch. 5, which was in the last year of Belshazzar, and ch. 6, which was in the first of Darius; for Daniel had those visions in the first year of Belshazzar, when the captivity of the Jews in Babylon was drawing near a period. Belshazzar\'s name here is, in the original, spelt differently from what it used to be; before it was Bel-she-azar - Bel is he that treasures up riches. But this is Bel-eshe-zar - Bel is on fire by the enemy. Bel was the god of the...', 'teologico');
add('dn', 7, 9, 'Matthew Henry', 'Whether we understand the fourth beast to signify the Syrian empire, or the Roman, or the former as the figure of the latter, it is plain that these verses are intended for the comfort and support of the people of God in reference to the persecutions they were likely to sustain both from the one and from the other, and from all their proud enemies in every age; for it is written for their learning on whom the ends of the world have come, that they also, through patience and comfort of this sc...', 'teologico');
add('dn', 7, 15, 'Matthew Henry', 'Here we have, I. The deep impressions which these visions made upon the prophet. God in them put honour upon him, and gave him satisfaction, yet not without a great allay of pain and perplexity (Dan 7:15): I Daniel was grieved in my spirit, in the midst of my body. The word here used for the body properly signifies a sheath or scabbard, for the body is no more to the soul; that is the weapon; it is that which we are principally to take care of. The visions of my head troubled me, and again (D...', 'teologico');
add('dn', 8, 1, 'Matthew Henry', 'Here is, I. The date of this vision, Dan 8:1. It was in the third year of the reign of Belshazzar, which proved to be his last year, as many reckon; so that this chapter also should be, in order of time, before the fifth. That Daniel might not be surprised at the destruction of Babylon, now at hand, God gives him a foresight of the destruction of other kingdoms hereafter, which in their day had been as potent as that of Babylon. Could we foresee the changes that shall be hereafter, when we ar...', 'teologico');
add('dn', 8, 15, 'Matthew Henry', 'Here we have,\nI. Daniel\'s earnest desire to have this vision explained to him (Dan 8:15): I sought the meaning. Note, Those that rightly know the things of God cannot but desire to know more and more of them, and to be led further into the mystery of them; and those that would find the meaning of what they have seen or heard from God must seek it, and seek it diligently. Seek and you shall find. Daniel considered the thing, compared it with the former discoveries, to try if he could understan...', 'teologico');
add('dn', 9, 1, 'Matthew Henry', 'We left Daniel, in the close of the foregoing chapter, employed in the king\'s business; but here we have him employed in better business than any king had for him, speaking to God and hearing from him, not for himself only, but for the church, whose mouth he was to God, and for whose use the oracles of God were committed to him, relating to the days of the Messiah. Observe, 1. When it was that Daniel had this communion with God (Dan 9:1), in the first year of Darius the Mede, who was newly ma...', 'teologico');
add('dn', 9, 4, 'Matthew Henry', 'We have here Daniel\'s prayer to God as his God, and the confession which he joined with that prayer: I prayed, and made my confession. Note, In every prayer we must make confession, not only of the sins we have been guilty of (which we commonly call confession), but of our faith in God and dependence upon him, our sorrow for sin and our resolutions against it. It must be our confession, must be the language of our own convictions and that which we ourselves do heartily subscribe to.\nLet us go...', 'teologico');
add('dn', 9, 20, 'Matthew Henry', 'We have here the answer that was immediately sent to Daniel\'s prayer, and it is a very memorable one, as it contains the most illustrious prediction of Christ and gospel-grace that is extant in all the Old Testament. If John Baptist was the morning-star, this was the day-break to the Sun of righteousness, the day-spring from on high. Here is,\nI. The time when this answer was given.\n1. It was while Daniel was at prayer. This he observed and laid a strong emphasis upon: While I was speaking (Da...', 'teologico');
add('dn', 10, 1, 'Matthew Henry', 'This vision is dated in the third year of Cyrus, that is, of his reign after the conquest of Babylon, his third year since Daniel became acquainted with him and a subject to him. Here is,\nI. A general idea of this prophecy (Dan 10:1): The thing was true; every word of God is so; it was true that Daniel had such a vision, and that such and such things were said. This he solemnly attests upon the word of a prophet. Et hoc paratus est verificare - He was prepared to verify it; and, if it was a w...', 'teologico');
add('dn', 10, 10, 'Matthew Henry', 'Much ado here is to bring Daniel to be able to bear what Christ has to say to him. Still we have him in a fright, hardly and very slowly recovering himself; but he is still answered and supported with good words and comfortable words. Let us see how Daniel is by degrees brought to himself, and gather up the several passages that are to the same purport.\nI. Daniel is in a great consternation and finds it very difficult to get clear of it. The hand that touched him set him at first upon his kne...', 'teologico');
add('dn', 11, 1, 'Matthew Henry', 'Here, 1. The angel Gabriel lets Daniel know the good service he has done to the Jewish nation (Dan 11:1): "In the first year of Darius the Mede, who destroyed Babylon and released the Jews out of that house of bondage, I stood a strength and fortress to him, that is, I was instrumental to protect him, and give him success in his ward, and, after he had conquered Babylon, to confirm him in his resolution to release the Jews," which, it is likely, met with much opposition. Thus by the angel, an...', 'teologico');
add('dn', 11, 5, 'Matthew Henry', 'Here are foretold,\nI. The rise and power of two great kingdoms out of the remains of Alexander\'s conquests, Dan 11:5. 1. The kingdom of Egypt, which was made considerable by Ptolemaeus Lagus, one of Alexander\'s captains, whose successors were, from him, called the Lagidae. He is called the king of the south, that is, Egypt, named here, Dan 11:8, Dan 11:42, Dan 11:43. The countries that at first belonged to Ptolemy are reckoned to be Egypt, Phoenicia, Arabia, Libya, Ethiopia, etc. Theocr. Idyl...', 'teologico');
add('dn', 11, 21, 'Matthew Henry', 'All this is a prophecy of the reign of Antiochus Epiphanes, the little horn spoken of before (Dan 8:9) a sworn enemy to the Jewish religion, and a bitter persecutor of those that adhered to it. What troubles the Jews met with in the reigns of the Persian kings were not so particularly foretold to Daniel as these, because then they had living prophets with them, Haggai and Zechariah, to encourage them; but these troubles in the days of Antiochus were foretold, because, before that time, prophe...', 'teologico');
add('dn', 12, 5, 'Matthew Henry', 'Daniel had been made to foresee the amazing revolutions of states and kingdoms, as far as the Israel of God was concerned in them; in them he foresaw troublous times to the church, suffering trying times, the prospect of which much affected him and filled him with concern. Now there were two questions proper to be asked upon this head: - When shall the end be? And, What shall the end be? These two questions are asked and answered here, in the close of the book; and though the comforts prescri...', 'teologico');

// OS (33 comentários)
add('os', 11, 1, 'Calvino', 'Do Egito chamei meu filho — Referência tipológica ao Messias: Cristo cumpre o que Israel falhou.', 'teologico');
add('os', 1, 1, 'Matthew Henry', '1. Here is the prophet\'s name and surname; which he himself, as other prophets, prefixes to his prophecy, for the satisfaction of all that he is ready to attest what he writes to be of God; he sets his hand to it, as that which he will stand by. His name, Hosea, or Hoshea (for it is the very same with Joshua\'s original name), signifies a saviour; for prophets were instruments of salvation to the people of God, so are faithful ministers; they help to save many a soul from death, by saving it f...', 'teologico');
add('os', 1, 2, 'Matthew Henry', 'These words, The beginning of the word of the Lord by Hosea, may refer either, 1. To that glorious set of prophets which was raised up about this time. About this time there lived and prophesied Joel, Amos, Micah, Jonah, Obadiah, and Isaiah; but Hosea was the first of them that foretold the destruction of Israel; the beginning of this word of the Lord was by him. We read in the history of this Jeroboam here named (Kg2 14:27) that the Lord had not yet said he would blot out the name of Israel,...', 'teologico');
add('os', 1, 8, 'Matthew Henry', 'We have here a prediction,\nI. Of the rejection of Israel for a time, which is signified by the name of another child that Hosea had by his adulterous spouse, Hos 1:8, Hos 1:9. And still we must observe that those children whose names carried these direful omens in them to Israel were all children of whoredoms (Hos 1:2), all born of the harlot that Hosea married, to intimate that the ruin of Israel was the natural product of the sin of Israel. If they had not first revolted from God, they woul...', 'teologico');
add('os', 2, 1, 'Matthew Henry', 'The first words of this chapter some make the close of the foregoing chapter, and add them to the promises which we have here of the great things God would do for them. When they shall have appointed Christ their head, and centered in him, then let them say to one another, with triumph and exultation (let the prophets say it to them, so the Chaldee - Comfort you, comfort you, my people, is now their commission), "say to them, Ammi, and Ruhamah; call them so again, for they shall no longer lie...', 'teologico');
add('os', 2, 6, 'Matthew Henry', 'God here goes on to threaten what he would do with this treacherous idolatrous people; and he warns that he may not wound, he threatens that he may not strike. If he turn not, he will whet his sword (Psa 7:12); but, if he turn, he will sheathe it. They did not turn, and therefore all this came upon them: and its being threatened before shows that it was the execution of a divine sentence upon them for their wickedness; and it is written for admonition to us.\nI. They shall be perplexed and emb...', 'teologico');
add('os', 2, 14, 'Matthew Henry', 'The state of Israel ruined by their own sin did not look so black and dismal in the former part of the chapter, but that the state of Israel, restrained by the divine grace, looks as bright and pleasant here in the latter part of the chapter, and the more surprisingly so as the promises follow thus close upon the threatenings; nay, which is very strange, they are by a note of connexion joined to, and inferred from, that declaration of their sinfulness upon which the threatenings of their ruin...', 'teologico');
add('os', 3, 1, 'Matthew Henry', 'Some think that this chapter refers to Judah, the two tribes, as the adulteress the prophet married (Hos 1:3) represented the ten tribes; for this was not to be divorced, as the ten tribes were, but to be left desolate for a long time, and then to return, as the two tribes did. But these are called the children of Israel, which was the ten tribes, and therefore it is more probable that of them this parable, as well as that before, is to be understood. Go, and repeat it, says God to the prophe...', 'teologico');
add('os', 4, 1, 'Matthew Henry', 'Here is, I. The court set, and both attendance and attention demanded: "Hear the word of the Lord, you children of Israel, for to you is the word of this conviction sent, whether you will hear or whether you will forbear." Whom may God expect to give him a fair hearing, and take from him a fair warning, but the children of Israel, his own professing people? Yea, they will be ready enough to hear when God speaks comfortably to them; but are they willing to hear when he has a controversy with t...', 'teologico');
add('os', 4, 6, 'Matthew Henry', 'God is here proceeding in his controversy both with the priests and with the people. The people were as those that strove with the priests (Hos 4:4) when they had priests that did their duty; but the generality of them lived in the neglect of their duty, and here is a word for those priests, and for the people that love to have it so, Jer 5:31. And it is observable here how the punishment answers to the sin, and how, for the justifying of his own proceedings, God sets the one over-against the...', 'teologico');
add('os', 4, 12, 'Matthew Henry', 'In these verses we have, as before,\nI. The sins charged upon the people of Israel, for which God had a controversy with them, and they are,\n1. Spiritual whoredom, or idolatry. They have in them a spirit of whoredoms, a strong inclination to that sin; the bent and bias of their hearts are that way; it is their own iniquity; they are carried out towards it with an unaccountable violence, and this causes them to err. Note, The errors and mistakes of the judgment are commonly owing to the corrupt...', 'teologico');
add('os', 5, 1, 'Matthew Henry', 'Here, I. All orders and degrees of men are cited to appear and answer to such things as shall be laid to their charge (Hos 5:1): Hear you this, O priests! whether in holy orders (as those in Judah, and perhaps many in Israel too, for in the ten tribes there were divers cities of priests and Levites, who, it is probable, staid in their own lot after the revolt of the ten tribes and did so much of their office as might be done at a distance from the temple) or pretending holy orders, as the pri...', 'teologico');
add('os', 5, 8, 'Matthew Henry', 'Here is, I. A loud alarm sounded, giving notice of judgments coming (Hos 5:8): Blow you the cornet in Gibeah and in Ramah, two cities near together in the confines of the two kingdoms of Judah and Israel, Gibeah a frontier-town of the kingdom of Judah, Ramah of Israel; so that the warning is hereby sent into both kingdoms. "Cry aloud at Beth-aven, or Bethel, which place seems to be already seized upon by the enemy, and therefore the trumpet is not sounded there, but you hear the outcries of t...', 'teologico');
add('os', 6, 1, 'Matthew Henry', 'These may be taken either as the words of the prophet to the people, calling them to repentance, or as the words of the people to one another, exciting and encouraging one another to seek the Lord, and to humble themselves before him, in hopes of finding mercy with him. God had said, In their affliction they will seek me; now the prophet, and the good people his friends, would strike while the iron was hot, and set in with the convictions their neighbours seemed to be under. Note, Those who a...', 'teologico');
add('os', 6, 4, 'Matthew Henry', 'Two things, two evil things, both Judah and Ephraim are here charged with, and justly accused of: - \nI. That they were not firm to their own convictions, but were unsteady, unstable as water, Hos 6:4, Hos 6:5. O Ephraim! what shall I do unto thee? O Judah! what shall I do unto thee? This is a strange expression. Can Infinite Wisdom be at a loss what to do? Can it be nonplussed, or put upon taking new measures? By no means; but God speaks after the manner of men, to show how absurd and unreaso...', 'teologico');
add('os', 7, 1, 'Matthew Henry', 'Some take away the last words of the foregoing chapter, and make them the beginning of this: "When I returned, or would have returned, the captivity of my people, when I was about to come towards them in ways of mercy, even when I would have healed Israel, then the iniquity of Ephraim (the country and common people) was discovered, and the wickedness of Samaria, the court and the chief city." Now, in these verses, we may observe,\nI. A general idea given of the present state of Israel, Hos 7:1...', 'teologico');
add('os', 7, 8, 'Matthew Henry', 'Having seen how vicious and corrupt the court was, we now come to enquire how it is with the country, and we find that to be no better; and no marvel if the distemper that has so seized the head affect the whole body, so that there is no soundness in it; the iniquity of Ephraim is discovered, as well as the sin of Samaria, of the people as well as the princes, of which here are divers instances.\nI. They were not peculiar and entire for God, as they should have been, Hos 7:8. 1. They did not d...', 'teologico');
add('os', 8, 1, 'Matthew Henry', 'The reproofs and threatenings here are introduced with an order to the prophet to set the trumpet to his mouth (Hos 8:1), thus to call a solemn assembly, that all might take notice of what he had to deliver and take warning by it. He must sound an alarm, must, in God\'s name, proclaim war with this rebellious nation. An enemy is coming with speed and fury to seize their land, and he must awaken them to expect it. Thus the prophet must do the part of a watchman, that was by sound of trumpet to ...', 'teologico');
add('os', 8, 8, 'Matthew Henry', 'It was the honour and happiness of Israel that they had but one God to trust to and he all-sufficient in every strait, and but one God to serve, and he well worthy of all their devotions. But it was their sin, and folly, and shame, that they knew not when they were well off, that they forsook their own mercies for lying vanities; for,\nI. They multiplied their alliances (Hos 8:9): They have hired lovers, or (as the margin reads it) they have hired loves. They were at great expense to purchase ...', 'teologico');
add('os', 9, 1, 'Matthew Henry', 'Here, I. The people of Israel are charged with spiritual adultery: O Israel! thou hast gone a whoring from thy God, Hos 9:1. Their covenant with God was a marriage-covenant, by which they were joined to him as their God, renouncing all others. But when they set up idols and worshipped them, when they fled to creatures for succour and put a confidence in them, they went a whoring from God as their God, and honoured the pretenders and rivals with the affection, adoration, and confidence, which ...', 'teologico');
add('os', 9, 7, 'Matthew Henry', 'For their further awakening, it is here threatened,\nI. That the destruction spoken of shall come speedily. They shall have no reason to hope for a long reprieve, for the judgment slumbers not; it is at the door (Hos 9:7): The days of visitation have come, and there shall be no more delay; the days of recompence have come, which they have been so often warned to expect; their prophets have told them that destruction would come, and now it has come, and the time of the divine patience has expir...', 'teologico');
add('os', 9, 11, 'Matthew Henry', 'In the foregoing verses we saw the sin of Israel derived from their fathers; here we see the punishment of Israel derived to their children; for, as death entered by sin at first, so it is still entailed with it. We may observe, in these verses,\nI. The sin of Ephraim. Some expressions are here which describe that. 1. They did not hearken to God (Hos 9:17); they did not give attention to the voice either of his word or of his rod; they did not believe what he said, nor would they be ruled by h...', 'teologico');
add('os', 10, 1, 'Matthew Henry', 'Observe, I. What the sins are which are here laid to Israel\'s charge, the national sins which bring down national judgment. The prophet deals plainly with them; for what good would it do them to be flattered?\n1. They were not fruitful in the fruits of righteousness to the glory of God. Here all their other wickedness began (Hos 10:1): Israel is an empty vine. The church of God is fitly compared to a vine, weak, and of an unpromising outside, yet spreading and fruitful; believers are branches ...', 'teologico');
add('os', 10, 9, 'Matthew Henry', 'Here, I. They are put in mind of the sins of their fathers and predecessors, for which God would now reckon with them. It was told them (Hos 9:9) that they had corrupted themselves, as in the days of Gibeah, and here (Hos 10:9), O Israel! thou hast sinned from the days of Gibeah. Not only the wickedness that was committed in that age is revived in this, and reacted, a copy from that original, but the wickedness that was committed in that age has been continued in a constant series and success...', 'teologico');
add('os', 11, 8, 'Matthew Henry', 'In these verses we have,\nI. God\'s wonderful backwardness to destroy Israel (Hos 11:8, Hos 11:9): How shall I give thee up? Here observe,\n1. God\'s gracious debate within himself concerning Israel\'s case, a debate between justice and mercy, in which victory plainly inclines to mercy\'s side. Be astonished, O heavens! at this, and wonder, O earth! at the glory of God\'s goodness. Not that there are any such struggles in God as there are in us, or that he is ever fluctuating or unresolved; no, he i...', 'teologico');
add('os', 12, 1, 'Matthew Henry', 'In these verses,\nI. Ephraim is convicted of folly, in staying himself upon Egypt and Assyria, when he was in straits (Hos 12:1): Ephraim feeds on wind, that is, feeds himself with vain hopes of assistance from man, when he is at variance with God; and, when he meets with disappointments, he still pursues the same game, and greedily pants and follows after the east wind, which he cannot catch holy of, nor, if he could, would it be nourishing, nay, would be noxious. We say of the wind in the ea...', 'teologico');
add('os', 12, 7, 'Matthew Henry', 'Here are intermixed, in these verses,\nI. Reproofs for sin. When God is coming forth to contend with a people, that he may demonstrate his own righteousness, he will demonstrate their unrighteousness. Ephraim was called to turn to his God and keep judgment (Hos 12:6); now, to show that he had need of that call, he is charged with turning from his God by idolatry, and breaking the laws of justice and judgment.\n1. He is here charged with injustice against the precepts of the second table, Hos 12...', 'teologico');
add('os', 13, 1, 'Matthew Henry', 'Idolatry was the sin that did most easily beset the Jewish nation till after the captivity; the ten tribes from the first were guilty of it, but especially after the days of Ahab; and this is the sin which, in these verses, they are charged with. Observe,\nI. The provision that God made to prevent their falling into idolatry. This we have, Hos 13:4. God did what was fit to be done to keep them close to himself; what could have been done more? 1. He made known himself to them as the Lord their ...', 'teologico');
add('os', 13, 5, 'Matthew Henry', 'We may observe here, 1. The plentiful provision God had made for Israel and the seasonable supplies he had blessed them with (Hos 13:5): "I did know thee in the wilderness, took cognizance of thy case and made provision for thee, even in a land of great drought, when thou wast in extreme distress, and when no relief was to be had in an ordinary way." See a description of this wilderness, Deu 8:15, Jer 2:6, and say, The God that knew them, and owned them, and fed them there, was a friend indee...', 'teologico');
add('os', 13, 9, 'Matthew Henry', 'The first of these verses is the summary, or contents, of all the rest (Hos 13:9), where we have, 1. All the blame of Israel\'s ruin laid upon themselves: O Israel! thy perdition is thence; it is of and from thyself; or, "It has destroyed thee, O Israel! that is, all that sin and folly of thine which thou art before charged with. As thy own wickedness has many a time corrected thee, so that has now at length destroyed thee." Note, Wilful sinners are self-destroyers. Obstinate impenitence is th...', 'teologico');
add('os', 14, 1, 'Matthew Henry', 'Here we have,\nI. A kind invitation given to sinners to repent, Hos 14:1. It is directed to Israel, God\'s professing people. They are called to return. Note, Conversion must be preached even to those that are within the pale of the church as well as to heathen. "Thou are Israel, and therefore art bound to thy God in duty, gratitude, and interest; thy revolt from him is so much the more heinous, and thy return to him so much the more necessary." Let Israel see, 1. What work he has made for repe...', 'teologico');
add('os', 14, 4, 'Matthew Henry', 'We have here an answer of peace to the prayers of returning Israel. They seek God\'s face, and they shall not seek in vain. God will be sure to meet those in a way of mercy who return to him in a way of duty. If we speak to God in good prayers, God will speak to us in good promises, as he answered the angel with good words and comfortable words, Zac 1:13. If we take with us the foregoing words in our coming to God, we may take home with us these following words for our faith to feast upon; and...', 'teologico');
add('os', 14, 8, 'Matthew Henry', 'Let us now hear the conclusion of the whole matter.\nI. Concerning Ephraim; he is spoken of and spoken to, Hos 14:8. Here we have,\n1. His repentance and reformation: Ephraim shall say, What have I to do any more with idols? As some read it, God here reasons and argues with him, why he should renounce idolatry: "O Ephraim! what to me and idols? What concord or agreement can there be between me and idols? What communion between light and darkness, between Christ and Belial? Co2 6:14, Co2 6:15. T...', 'teologico');

// JL (2 comentários)
add('jl', 2, 28, 'Pedro', 'Derramarei do Meu Espírito — Profecia do Pentecostes: o Espírito sobre toda a carne (At 2:17).', 'escatologico');
add('jl', 2, 13, 'Calvino', 'Rasgai o vosso coração — O arrependimento verdadeiro é interno, não exterior.', 'teologico');

// AM (25 comentários)
add('am', 3, 2, 'Calvino', 'Só a vós conheci — A eleição especial de Israel traz maior responsabilidade; o privilégio da aliança exige santidade.', 'teologico');
add('am', 3, 7, 'Matthew Henry', 'O Senhor Deus não fará coisa alguma sem revelar o seu segredo — Deus avisa Seu povo por meio dos profetas antes do juízo.', 'teologico');
add('am', 4, 12, 'Spurgeon', 'Prepara-te para encontrares com o teu Deus — A advertência final: o juízo exige preparo espiritual.', 'aplicacao');
add('am', 5, 21, 'Lutero', 'Aborreci as vossas festas — O culto sem justiça é repelido por Deus; a forma religiosa não substitui a obediência.', 'teologico');
add('am', 5, 24, 'Martin Lloyd-Jones', 'Corra a justiça como as águas — A imagem da justiça como rio contínuo: ética social que brota da fé viva.', 'aplicacao');
add('am', 9, 11, 'N.T. Wright', 'Naquele dia erguerei o tabernáculo caído de Davi — A promessa de restauração messiânica citada por Tiago em Atos 15.', 'escatologico');
add('am', 1, 1, 'Matthew Henry', 'Here is, I. The general character of this prophecy. It consists of the words which the prophet saw. Are words to be seen? Yes, God\'s words are; the apostles speak of the word of life, which they had not only heard, but which they had seen with their eyes, which they had looked upon, and which their hands had handled (Jo1 1:1), such a real substantial thing is the word of God. The prophet saw these words, that is, 1. They were revealed to him in a vision, as John is said to see the voice that ...', 'teologico');
add('am', 1, 3, 'Matthew Henry', 'What the Lord says here may be explained by what he says Jer 12:14, Thus said the Lord, against all my evil neighbours that touch the inheritance of my people Israel, Behold, I will pluck them out. Damascus was a near neighbour to Israel on the north, Tyre and Gaza on the west, Edom on the south, Ammon and (in the next chapter) Moab on the east; and all of them had been, one time, one way, or other, pricking briers and grieving thorns to Israel, evil neighbours to them; and, because God espou...', 'teologico');
add('am', 2, 1, 'Matthew Henry', 'Here is, I. The judgment of Moab, another of the nations that bordered upon Israel. They are reckoned with and shall be punished for three transgressions and for four, as those before. Now, 1. Moab\'s fourth transgression, as theirs who were before set to the bar, was cruelty. The instance given refers not to the people of God, but to a heathen like themselves: The king of Moab burnt the bones of the king of Edom into lime. We find there was war between the Edomites and the Moabites, in which ...', 'teologico');
add('am', 2, 9, 'Matthew Henry', 'Here, I. God puts his people Israel in mind of the great things he has done for them, in putting them into possession of the land of Canaan, the greatest part of which these ten tribes now enjoyed, Amo 2:9, Amo 2:10. Note, We need often to be reminded of the mercies we have received, which are the heaviest aggravations of the sins we have committed. God gives liberally, and upbraids us not with our meanness and unworthiness, and the disproportion between his gifts and our merits; but he justl...', 'teologico');
add('am', 3, 1, 'Matthew Henry', 'The scope of these verses is to convince the people of Israel that God had a controversy with them. That which the prophet has to say to them is to let them know that the Lord has something to say against them, Amo 3:1. They were his peculiar people above others, knew his name, and were called by it; nevertheless he had something against them, and they were called to hear what it was, that they might consider what answer they should make, as the prisoner at the bar is told to hearken to his i...', 'teologico');
add('am', 3, 9, 'Matthew Henry', 'The Israelites are here again convicted and condemned, and particular notice given of the crimes they are convicted of and the punishment they are condemned to.\n1. Notice is given of it to their neighbours. The prophet is ordered to publish it in the palaces of Ashdod, one of the chief cities of the Philistines; nay, the summons must go further, even to the palaces in the land of Egypt. "The great men of both those nations, that dwell in the palaces, that are inquisitive concerning the affair...', 'teologico');
add('am', 4, 1, 'Matthew Henry', 'It is here foretold, in the name of God, that oppressors shall be humbled and idolaters shall be hardened.\nI. That proud oppressors shall be humbled for their oppressions: for he that does wrong shall receive according to the wrong that he has done. Now observe,\n1. How their sin is described, Amo 4:1. They are compared to the kine of Bashan, which were a breed of cattle very large and strong, especially if, though bred there, they were fed upon the mountain of Samaria, where the pastures were...', 'teologico');
add('am', 4, 6, 'Matthew Henry', 'Here, I. God complains of his people\'s incorrigibleness under the judgments which he had brought upon them in order to their humiliation and reformation. He had by several tokens intimated to them his displeasure, with this design, that they might by repentance make their peace with him; but it had not that effect.\n1. It is five times repeated in these verses, as the burden of the charge, "Yet have you not returned unto me, saith the Lord; you have been several times corrected, but in vain; y...', 'teologico');
add('am', 5, 1, 'Matthew Henry', 'This chapter begins, as those two next foregoing began, with, Hear this word. Where God has a mouth to speak we must have an ear to hear; it is our duty, it is our interest, yet so stupid are most men that they need to be again and again called upon to hear the word of the Lord, to give audience, to give attention. Hear this word. this convincing awakening word must be heard and heeded, as well as words of comfort and peace; the word that is taken up against us, as well as that which makes fo...', 'teologico');
add('am', 5, 4, 'Matthew Henry', 'This is a message from God to the house of Israel, in which,\nI. They are told of their faults, that they might see what occasion there was for them to repent and reform, and that, when they were called to return, they might not need to ask, Wherein shall we return?\n1. God tells them, in general (Amo 5:12), "I know your manifold transgressions, and your mighty sins; and you shall be made to know them too." In our penitent reflections upon our sins we must consider, as God does in his judicial ...', 'teologico');
add('am', 5, 16, 'Matthew Henry', 'Here is, I. A very terrible threatening of destruction approaching, Amo 5:16, Amo 5:17. Since they would not take the right course to obtain the favour of God, God would take an effectual course to make them feel the weight of his displeasure. The threatening is introduced with more than ordinary solemnity, to strike an awe upon them; it is not the word of the prophet only (if so, it might be made light of) but it is the Lord Jehovah, who has an infinite eternal being; it is the God of hosts,...', 'teologico');
add('am', 6, 1, 'Matthew Henry', 'The first words of the chapter are the contents of these verses; but they sound very strangely, and contrary to the sentiments of a vain world: Woe to those that are at ease! We are ready to say, Happy are those that are at ease, that neither feel any trouble nor fear any, that lie soft and warm, and lay nothing to heart; and wise we think are those that do so, that bathe themselves in the delights of sense and care not how the world goes. Those are looked upon as doing well for themselves th...', 'teologico');
add('am', 6, 8, 'Matthew Henry', 'In the former part of the chapter we had these secure Israelites loading themselves with pleasures, as if they could never be made merry enough; here we have God loading them with punishments, as if they could never be made miserable enough. And observe,\nI. How strongly this burden is bound on, not to be shaken off by their presumption and security; for it is bound by the Lord the God of hosts, by his mighty, his almighty, hand, which none can resist; it is bound with an oath, which puts the ...', 'teologico');
add('am', 7, 1, 'Matthew Henry', 'We here see that God bears long, but that he will not bear always, with a provoking people, both these God here showed the prophet: Thus hath the Lord God showed me, Amo 7:1, Amo 7:4, Amo 7:7. He showed him what was present, foreshowed him what was to come, gave him the knowledge both of what he did and of what he designed; for the Lord God reveals his secret unto his servants the prophets, Amo 3:7.\nI. We have here two instances of God\'s sparing mercy, remembered in the midst of judgment, the...', 'teologico');
add('am', 7, 10, 'Matthew Henry', 'One would have expected, 1. That what we met with in the former part of the chapter would awaken the people to repentance, when they saw that they were reprieved in order that they might have space to repent and that they could not obtain a pardon unless the did repent. 2. That it would endear the prophet Amos to them, who had not only shown his good-will to them in praying against the judgments that invaded them, but had prevailed to turn away those judgments, which, if they had had any sens...', 'teologico');
add('am', 8, 1, 'Matthew Henry', 'The great reason why sinners defer their repentance de die in diem - from day to day, is because they think God thus defers his judgments, and there is no song wherewith they so effectually sing themselves asleep as that, My Lord delays his coming; and therefore God, by his prophets, frequently represents to Israel the day of his wrath not only as just and certain, but as very near and hastening on apace; so he does in these verses.\nI. The approach of the threatened ruin is represented by a b...', 'teologico');
add('am', 8, 4, 'Matthew Henry', 'God is here contending with proud oppressors, and showing them,\nI. The heinousness of the sin they were guilty of; in short, they had the character of the unjust judge (Luk 18:2) that neither feared God nor regarded man.\n1. Observe them in their devotions, and you will say, "They had no reverence for God." Bad as they are, they do indeed keep up a show and form of godliness; they observe the sabbath and the new moon; they put some difference between those days and other days, but they were so...', 'teologico');
add('am', 8, 11, 'Matthew Henry', 'In these verses is threatened,\nI. A general judgment of spiritual famine coming upon the whole land, a famine of the word of God, the failing of oracles and the scarcity of good preaching. This is spoken of as a thing at some distance: The days come, they will come hereafter, when another kind of darkness shall come upon that land of light. When Amos prophesied, and for a considerable time after, they had great plenty of prophets, abundant opportunities of hearing the word of God, in season a...', 'teologico');
add('am', 9, 1, 'Matthew Henry', 'We have here the justice of God passing sentence upon a provoking people; and observe,\nI. With what solemnity the sentence is passed. The prophet saw in vision the Lord standing upon the altar (Amo 9:1), the altar of burnt-offerings; for the Lord has a sacrifice, and multitudes must fall as victims to his justice. He is removed from the mercy-seat between the cherubim, and stands upon the altar, the judgment-seat, on which the fire of God used to fall, to devour the sacrifices. He stands upon...', 'teologico');

// OB (3 comentários)
add('ob', 1, 21, 'Calvino', 'Subirão salvadores ao monte Sião — A vitória final de Deus sobre Edom aponta para o reino messiânico.', 'escatologico');
add('ob', 1, 10, 'Matthew Henry', 'When we have read Edom\'s doom, no less than utter ruin, it is natural to ask, Why, what evil has he done? What is the ground of God\'s controversy with him? Many things, no doubt, were amiss in Edom; they were a sinful people, and a people laden with iniquity. But that one single crime which is laid to their charge, as filling their measure and bringing this ruin upon them, that for which they here stand indicted, of which they are convicted, and for which they are condemned, is the injury the...', 'teologico');
add('ob', 1, 17, 'Matthew Henry', 'After the destruction of the church\'s enemies is threatened, which will be completely accomplished in the great day of recompence, and that judgment for which Christ came once, and will come again, into this world, here follow precious promises of the salvation of the church, with which this prophecy concludes, and those of Joel and Amos did, which, however they might be in part fulfilled in the return of the Jews out of Babylon notwithstanding the triumphs of Edom in their captivity, as if i...', 'teologico');

// JN (6 comentários)
add('jn', 2, 9, 'Agostinho', 'A salvação vem do Senhor — A soberania graciosa de Deus alcança até os ninivitas.', 'teologico');
add('jn', 3, 10, 'Spurgeon', 'Deus se arrependeu do mal — A mudança de Deus em relação ao pecado arrependido revela Sua misericórdia.', 'teologico');
add('jn', 4, 2, 'Calvino', 'Deus é misericordioso — A compaixão de Deus por toda a criatura confunde o nacionalismo estreito.', 'teologico');
add('jn', 1, 1, 'Matthew Henry', 'Observe, 1. The honour God put upon Jonah, in giving him a commission to go and prophesy against Nineveh. Jonah signifies a dove, a proper name for all God\'s prophets, all his people, who ought to be harmless as doves, and to mourn as doves for the sins and calamities of the land. His father\'s name was Amittai - My truth; for God\'s prophets should be sons of truth. To him the word of the Lord came - to him it was (so the word signifies), for God\'s word is a real thing; men\'s words are but win...', 'teologico');
add('jn', 1, 4, 'Matthew Henry', 'When Jonah was set on ship-board, and under sail for Tarshish, he thought himself safe enough; but here we find him pursued and overtaken, discovered and convicted as a deserter from God, as one that had run his colours.\nI. God sends a pursuer after him, a mighty tempest in the sea, Jon 1:4. God has the winds in his treasure (Psa 135:7), and out of these treasures God sent forth, he cast forth (so the word is), with force and violence, a great wind into the sea; even stormy winds fulfil his w...', 'teologico');
add('jn', 1, 11, 'Matthew Henry', 'It is plain that Jonah is the man for whose sake this evil is upon them, but the discovery of him to be so was not sufficient to answer the demands of this tempest; they had found him out, but something more was to be done, for still the sea wrought and was tempestuous (Jon 1:11), and again (Jon 1:13), it grew more and more tempestuous (so the margin reads it); for if we discover sin to be the cause of our troubles, and do not forsake it, we do but make bad worse. Therefore they went on with ...', 'teologico');

// MQ (20 comentários)
add('mq', 5, 2, 'Calvino', 'E tu, Belém Efrata — A profecia do Messias nascido em Belém, humilde mas eterno em origem.', 'escatologico');
add('mq', 6, 6, 'Tomás de Aquino', 'Com que me apresentarei ao Senhor? — A pergunta do culto externo cede lugar à exigência do coração quebrado.', 'teologico');
add('mq', 6, 8, 'João Crisóstomo', 'Fazer justiça, amar a misericórdia, humilhar-te — O resumo da exigência moral de Deus para com o homem.', 'aplicacao');
add('mq', 7, 18, 'Spurgeon', 'Quem é Deus como tu? — A celebração da graça que perdoa e lança os pecados no fundo do mar.', 'teologico');
add('mq', 7, 7, 'Matthew Henry', 'Eu, porém, olharei para o Senhor — A atitude de espera confiante em meio à corrupção geral.', 'aplicacao');
add('mq', 1, 1, 'Matthew Henry', 'Here is, I. A general account of this prophet and his prophecy, Mic 1:1. This is prefixed for the satisfaction of all that read and hear the prophecy of this book, who will give the more credit to it when they know the author and his authority. 1. The prophecy is the word of the Lord; it is a divine revelation. Note, What is written in the Bible, and what is preached by the ministers of Christ according to what is written there, must be heard and received, not as the word of dying men, which ...', 'teologico');
add('mq', 1, 8, 'Matthew Henry', 'We have here a long train of mourners attending the funeral of a ruined kingdom.\nI. The prophet is himself chief mourner (Mic 1:8, Mic 1:9): I will wail and howl; I will go stripped and naked, as a man distracted with grief. The prophets usually expressed their own grief for the public grievances, partly to mollify the predictions of them, and to make it appear that is was not out of ill-will that they denounced the judgments of God (so far were they from desiring the woeful day that they dre...', 'teologico');
add('mq', 2, 1, 'Matthew Henry', 'Here is, I. The injustice of man contriving the evil of sin, Mic 2:1, Mic 2:2. God was coming forth against this people to destroy them, and here he shows what was the ground of his controversy with them; it is that which is often mentioned as a sin that hastens the ruin of nations and families as much as any, the sin of oppression. Let us see the steps of it. 1. They eagerly desire that which is not their own - that is the root of bitterness, the root of all evil, Mic 2:2. They covet fields ...', 'teologico');
add('mq', 2, 6, 'Matthew Henry', 'Here are two sins charged upon the people of Israel, and judgments denounced against them for each, such judgments as exactly answer the sin - persecuting God\'s prophets and oppressing God\'s poor.\nI. Persecuting God\'s prophets, suppressing and silencing them, is a sin that provokes God as much as anything, for it not only spits in the face of his authority over us, but spurns at the bowels of his mercy to us; for his sending prophets to us is a sure and valuable token of his goodwill. Now obs...', 'teologico');
add('mq', 2, 12, 'Matthew Henry', 'After threatenings of wrath, the chapter here concludes, as is usual in the prophets, with promises of mercy, which were in part fulfilled when the Jews returned out of Babylon, and had their full accomplishment in the kingdom of the Messiah. Their grievances shall be all redressed. 1. Whereas they were dispersed, they shall be brought together again, and shall jointly receive the tokens of God\'s favour to them, and shall have communion with each other and comfort in each other (Mic 2:12): "I...', 'teologico');
add('mq', 3, 1, 'Matthew Henry', 'Princes and prophets, when they faithfully discharge the duty of their office, are to be highly honoured above other men; but when they betray their trust, and act contrary to it, they should hear of their faults as well as others, and shall be made to know that there is a God above them, to whom they are accountable; at his bar the prophet here, in his name, arraigns them.\nI. Let the princes hear their charge and their doom. The heads of Jacob, and the princes of the house of Israel, are cal...', 'teologico');
add('mq', 3, 8, 'Matthew Henry', 'Here, I. The prophet experiences a divine power going along with him in his work, and he makes a solemn profession and protestation of it, as that which would justify him, and bear him out, in his plain dealing with the princes and rulers. He would not, he durst not, make thus bold with the great men, but that he was carried out to do it by a prophetical impulse and impression. It was not he that said it, but God by him, and he could not but speak the word that God put into his mouth. It come...', 'teologico');
add('mq', 4, 1, 'Matthew Henry', 'It is a very comfortable but with which this chapter begins, and very reviving to those who lay the interests of God\'s church near their heart and are concerned for the welfare of it. When we sometimes see the corruptions of the church, especially of church-rulers, princes, priests, and prophets, seeking their own things and not the things of God, and when we soon after see the desolations of the church, Zion for their sakes ploughed as a field, we are ready to fear that it will one day peris...', 'teologico');
add('mq', 4, 8, 'Matthew Henry', 'These verses relate to Zion and Jerusalem, here called the tower of the flock or the tower of Edor; we read of such a place (Gen 35:21) near Bethlehem; and some conjecture it is the same place where the shepherds were keeping their flocks when the angels brought them tidings of the birth of Christ, and some think Bethlehem itself is here spoken of, as Mic 5:2. Some think it is a tower at that gate of Jerusalem which is called the sheep-gate (Neh 3:32), and conjecture that through that gate Ch...', 'teologico');
add('mq', 5, 1, 'Matthew Henry', 'Here, as before, we have,\nI. The abasement and distress of Zion, Mic 5:1. The Jewish nation, for many years before the captivity, dwindled, and fell into disgrace: Now gather thyself in troops, O daughter of troops! It is either a summons to Zion\'s enemies, that had troops at their service, to come and do their worst against her (God will suffer them to do it), or a challenge to Zion\'s friends, that had troops too at command, to come and do their best for her; Let them gather in troops, yet i...', 'teologico');
add('mq', 5, 7, 'Matthew Henry', 'Glorious things are here spoken of the remnant of Jacob, that remnant which was raised of her that halted (Mic 4:7), and it seems to be that remnant which the Lord our God shall call (Joe 2:32), on whom the Spirit shall be poured out, the remnant that shall be saved, Rom 9:27. Note, God\'s people are but a remnant, a small number in comparison with the many that are left to perish, a little flock; but they are the remnant of Jacob, a people in covenant with God, and in his favour. Now concerni...', 'teologico');
add('mq', 6, 1, 'Matthew Henry', 'Here, I. The prefaces to the message are very solemn and such as may engage our most serious attention. 1. The people are commanded to give audience: Hear you now what the Lord says. What the prophet speaks he speaks from God, and in his name; they are therefore bound to hear it, not as the word of a sinful dying man, but of the holy living God. Hear now what he saith, for, first or last, he will be heard. 2. The prophet is commanded to speak in earnest, and to put an emphasis upon what he sa...', 'teologico');
add('mq', 6, 9, 'Matthew Henry', 'God, having shown them how necessary it was that they should do justly, here shows them how plain it was that they had done unjustly; and since they submitted not to his controversy, nor went the right way to have it taken up, here he proceeds in it. Observe,\nI. How the action is entered against them, Mic 6:9. God speaks to the city, to Jerusalem, to Samaria. His voice cries to it by his servants the prophets who were to cry aloud and not spare. Note, The voice of the prophets is the Lord\'s v...', 'teologico');
add('mq', 7, 1, 'Matthew Henry', 'This is such a description of bad times as, some think, could scarcely agree to the times of Hezekiah, when this prophet prophesied; and therefore they rather take it as a prediction of what should be in the reign of Manasseh. But we may rather suppose it to be in the reign of Ahaz (and in that reign he prophesied, ch. 1:1) or in the beginning of Hezekiah\'s time, before the reformation he was instrumental in; nay, in the best of his days, and when he had done his best to purge out corruptions...', 'teologico');
add('mq', 7, 14, 'Matthew Henry', 'Here is, I. The prophet\'s prayer to God to take care of his own people, and of their cause and interest, Mic 7:14. When God is about to deliver his people he stirs up their friends to pray for them, and pours out a spirit of grace and supplication, Zac 12:10. And when we see God coming towards us in ways of mercy, we must go forth to meet him by prayer. It is a prophetic prayer, which amounts to a promise of the good prayed for; what God directed his prophet to ask no doubt he designed to giv...', 'teologico');

// NA (1 comentários)
add('na', 1, 7, 'Spurgeon', 'O Senhor é bom — Refúgio nos dias de angústia para os que confiam nEle.', 'teologico');

// HC (13 comentários)
add('hc', 1, 2, 'Calvino', 'Até quando clamarei? — O profeta expressa a angústia diante do aparente silêncio de Deus ante a injustiça.', 'teologico');
add('hc', 2, 4, 'Lutero', 'O justo viverá pela sua fé — Versículo-chave da Reforma: a justificação é pela fé, não pelas obras.', 'teologico');
add('hc', 2, 14, 'Matthew Henry', 'A terra se encherá do conhecimento da glória do Senhor — A visão universal da glória de Deus revelada.', 'escatologico');
add('hc', 3, 17, 'Spurgeon', 'A figueira não florescerá — A fé que se regozija em Deus ainda que faltem as bênçãos materiais.', 'aplicacao');
add('hc', 3, 19, 'João Crisóstomo', 'O Senhor Deus é a minha força — A imagem dos pés de cerva sobre os lugares altos: livramento e segurança.', 'teologico');
add('hc', 1, 5, 'Matthew Henry', 'We have here an answer to the prophet\'s complaint, giving him assurance that, though God bore long, he would not bear always with this provoking people; for the day of vengeance was in his heart, and he must tell them so, that they might by repentance and reformation turn away the judgment they were threatened with.\nI. The preamble to the sentence is very awful (Hab 1:5): Behold, you among the heathen, and regard. Since they will not be brought to repentance by the long-suffering of God, he w...', 'teologico');
add('hc', 1, 12, 'Matthew Henry', 'The prophet, having received of the Lord that which he was to deliver to the people, now turns to God, and again addresses himself to him for the ease of his own mind under the burden which he saw. And still he is full of complaints. If he look about him, he sees nothing but violence done by Israel; if he look before him, he sees nothing but violence done against Israel; and it is hard to say which is the more melancholy sight. His thoughts of both he pours out before the Lord. It is our duty...', 'teologico');
add('hc', 2, 1, 'Matthew Henry', 'Here, I. The prophet humbly gives his attendance upon God (Hab 2:1): "I will stand upon my watch, as a sentinel on the walls of a besieged city, or on the borders of an invaded country, that is very solicitous to gain intelligence. I will look up, will look round, will look within, and watch to see what he will say unto me, will listen attentively to the words of his mouth and carefully observe the steps of his providence, that I may not lose the least hint of instruction or direction. I will...', 'teologico');
add('hc', 2, 5, 'Matthew Henry', 'The prophet having had orders to write the vision, and the people to wait for the accomplishment of it, the vision itself follows; and it is, as divers other prophecies we have met with, the burden of Babylon and Babylon\'s king, the same that was said to pass over and offend, Hab 1:11. It reads the doom, some think, of Nebuchadnezzar, who was principally active in the destruction of Jerusalem, or of that monarchy, or of the whole kingdom of the Chaldeans, or of all such proud and oppressive p...', 'teologico');
add('hc', 2, 15, 'Matthew Henry', 'The three foregoing articles, upon which the woes here are grounded, are very near akin to each other. The criminals charged by them are oppressors and extortioners, that raise estates by rapine and injustice; and it is mentioned here again (Hab 2:17), the very same that was said Hab 2:8, for that is the crime upon which the greatest stress is laid; it is because of men\'s blood, innocent blood, barbarously and unjustly shed, which is a provoking crying thing; it is for the violence of the lan...', 'teologico');
add('hc', 3, 1, 'Matthew Henry', 'This chapter is entitled a prayer of Habakkuk. It is a meditation with himself, an intercession for the church. Prophets were praying men; this prophet was so (He is a prophet, and he shall pray for thee, Gen 20:7); and sometimes they prayed for even those whom they prophesied against. Those that were intimately acquainted with the mind of God concerning future events knew better than others how to order their prayers, and what to pray for, and, in the foresight of troublous times, could lay ...', 'teologico');
add('hc', 3, 3, 'Matthew Henry', 'It has been the usual practice of God\'s people, when they have been in distress and ready to fall into despair, to help themselves by recollecting their experiences, and reviving them, considering the days of old, and the years of ancient times (Psa 77:5), and pleading with God in prayer, as he is pleased sometimes to plead them with himself. Isa 63:11, Then he remembered the days of old. This is that which the prophet does here, and he looks as far back as the first forming of them into a pe...', 'teologico');
add('hc', 3, 16, 'Matthew Henry', 'Within the compass of these few lines we have the prophet in the highest degree both of trembling and triumphing, such are the varieties both of the state and of the spirit of God\'s people in this world. In heaven there shall be no more trembling, but everlasting triumphs.\nI. The prophet had foreseen the prevalence of the church\'s enemies and the long continuance of the church\'s troubles; and the sight made him tremble, Hab 3:16. Here he goes on with what he had said Hab 3:2, "I have heard th...', 'teologico');

// SF (12 comentários)
add('sf', 1, 7, 'Calvino', 'O dia do Senhor está próximo — A solenidade do juízo iminente de Deus sobre Judá e as nações.', 'escatologico');
add('sf', 1, 14, 'Matthew Henry', 'O dia do Senhor é grande e mui terrível — A urgência do arrependimento diante da proximidade do juízo.', 'aplicacao');
add('sf', 2, 3, 'Lutero', 'Buscai ao Senhor, vós os mansos — O chamado à humildade como caminho de livramento no dia da ira.', 'aplicacao');
add('sf', 3, 17, 'Spurgeon', 'Ele se deleitará em ti com alegria — O Deus guerreiro que também se regozija em amor por Seu povo.', 'teologico');
add('sf', 1, 1, 'Matthew Henry', 'Here is, I. The title-page of this book (Zep 1:1), in which we observe, 1. What authority it has, and who gave it that authority; it is from heaven, and not of men: It is the word of the Lord. 2. Who was the instrument of conveying it to the church. His name was Zephaniah, which signifies the servant of the Lord, for God revealed his secrets to his servants the prophets. The pedigree of other prophets, whose extraction we have an account of, goes no further back than their father, except Zech...', 'teologico');
add('sf', 2, 1, 'Matthew Henry', 'Here we see what the prophet meant in that terrible description of the approaching judgments which we had in the foregoing chapter. From first to last his design was, not to drive the people to despair, but to drive them to God and to their duty - not to frighten them out of their wits, but to frighten them out of their sins. In pursuance of that he here calls them to repentance, national repentance, as the only way to prevent national ruin. Observe,\nI. The summons given them to a national as...', 'teologico');
add('sf', 2, 4, 'Matthew Henry', 'The prophet here comes to foretel what share the neighbouring nations should have in the destruction made upon those parts of the world by Nebuchadnezzar and his victorious Chaldees, as others of the prophets did at that time, which is designed, 1. To awaken the people of the Jews, by making them sensible how strong, how deep, how large, the inundation of calamities should be, that the day of the Lord, which was near, might appear the more dreadful, and they might thereby be quickened to prep...', 'teologico');
add('sf', 2, 8, 'Matthew Henry', 'The Moabites and Ammonites were both of the posterity of Lot; their countries joined, and, both adjoining to Israel, they are here put together in the prophecy against them.\nI. They are both charged with the same crime, and that was reproaching and reviling the people of God and triumphing in their calamities (Zep 2:8): They have reproached my people; while God\'s people kept close to their duty it is probable that they reproached them for the singularities of their religion; and now that they...', 'teologico');
add('sf', 2, 12, 'Matthew Henry', 'The cup is going round, when Nebuchadnezzar is going on conquering and to conquer; and not only Israel\'s near neighbours, but those that lay more remote, must be reckoned with for the wrongs they have done to God\'s people; the Ethiopians and the Assyrians are here taken to task. 1. The Ethiopians, or Arabians, that had sometimes been a terror to Israel (as in Asa\'s time, Ch2 14:9), must now be reckoned with: They shall be slain by my sword, Zep 2:12. Nebuchadnezzar was God\'s sword, the instru...', 'teologico');
add('sf', 3, 1, 'Matthew Henry', 'One would wonder that Jerusalem, the holy city, where God was known, and his name was great, should be the city of which this black character is here given, that a place which enjoyed such abundance of the means of grace should become so very corrupt and vicious, and that God should permit it to be so; yet so it is, to show that the law made nothing perfect; but if this be the true character of Jerusalem, as no doubt it is (for God\'s judgments will make none worse than they are), it is no won...', 'teologico');
add('sf', 3, 8, 'Matthew Henry', 'Things looked very bad with Jerusalem in the foregoing verses; she has got into a very bad name, and seems to be incorrigible, incurable, mercy-proof and judgment-proof. Now one would think it should follow, Therefore expect no other but that she should be utterly abandoned and rejected as reprobate silver; since they will not be wrought upon by prophets or providences, let them be made a desolation as their neighbours have been. But behold and wonder at the riches of divine grace, which take...', 'teologico');
add('sf', 3, 14, 'Matthew Henry', 'After the promises of the taking away of sin, here follow promises of the taking away of trouble; for when the cause is removed the effect will cease. What makes a people holy will make them happy of course. The precious promises here made to the purified people were to have their full accomplishment in the comforts of the gospel, in the hope, and much more in the enjoyment, of which, they are here called upon, 1. To rejoice and sing (Zep 3:14): Sing, O daughter of Zion! sing for joy; Shout, ...', 'teologico');

// AG (6 comentários)
add('ag', 1, 5, 'Ageu', 'Considerai o vosso caminho — O despertar para as prioridades de Deus precede a bênção.', 'aplicacao');
add('ag', 1, 1, 'Matthew Henry', 'It was the complaint of the Jews in Babylon that they saw not their signs, and there was no more prophet (Psa 74:9), which was a just judgment upon them for mocking and misusing the prophets. We read of no prophets they had in their return, as they had in their coming out of Egypt, Hos 12:13. God stirred them up immediately by his Spirit to exert themselves in that escape (Ezr 1:5); for, though God makes use of prophets, he needs them not, he can do his work without them. But the lamp of Old ...', 'teologico');
add('ag', 1, 12, 'Matthew Henry', 'As an ear-ring of gold (says Solomon), and an ornament of fine gold, so amiable, so acceptable, in the sight of God and man, is a wise reprover upon an obedient ear, Pro 25:12. The prophet here was a wise but faithful reprover, in God\'s name, and he met with an obedient ear. The foregoing sermon met with the desired success among the people, and their obedience met with due encouragement from God. Observe,\nI. How the people returned to God in a way of duty. All those to whom that sermon was p...', 'teologico');
add('ag', 2, 1, 'Matthew Henry', 'Here is, I. The date of this message, Hag 2:1. It was sent on the twenty-first day of the seventh month, when the builders had been about a month at work (since the twenty-fourth day of the sixth month), and had got it in some forwardness. Note, Those that are hearty in the service of God shall receive fresh encouragements from him to proceed in it, as their case calls for them. Set the wheels a going, and God will oil them.\nII. The direction of this message, Hag 2:2. The encouragements here ...', 'teologico');
add('ag', 2, 10, 'Matthew Henry', 'This sermon was preached two months after that in the former part of the chapter. The priests and Levites preached constantly, but the prophets preached occasionally; both were good and needful. We have need to be taught our duty in season and out of season. The people were now going on vigorously with the building of the temple, and in hopes shortly to have it ready for their use and to be employed in the services of it; and now God sends them a message by his prophet, which would be of use ...', 'teologico');
add('ag', 2, 20, 'Matthew Henry', 'After Haggai\'s sermon ad populum - to the people, here follows one, the same day, ad magistratum - to the magistrates, a word directed particularly to Zerubbabel, the governor of Judah, who was a leading active man in this good work which the people now set about, and therefore he shall have some particular marks put upon him (Hag 2:21): Speak to Zerubbabel, governor of Judah, speak to him by himself. He has thoughts in his head far above those of the common people, as wise princes are wont t...', 'teologico');

// ZC (36 comentários)
add('zc', 4, 6, 'Zacarias', 'Não por força, nem por poder — A obra de Deus se faz pelo Seu Espírito.', 'teologico');
add('zc', 9, 9, 'Mateus', 'O teu Rei vem manso — Profecia da entrada triunfal de Cristo em Jerusalém (Mt 21:5).', 'escatologico');
add('zc', 12, 10, 'João', 'Olharão para aquele que traspassaram — Profecia da crucificação e arrependimento (Jo 19:37).', 'escatologico');
add('zc', 1, 1, 'Matthew Henry', 'Here is, I. The foundation of Zechariah\'s ministry; it is laid in a divine authority: The word of the Lord came to him. He received a divine commission to be God\'s mouth to the people and with it instructions what to say. He received of the Lord that which also he delivered unto them. The word of the Lord was to him; it came in the evidence and demonstration of the Spirit, as a real thing, and not a fancy. For the ascertaining of this, we have here, 1. The time when the word of the Lord came ...', 'teologico');
add('zc', 1, 7, 'Matthew Henry', 'We not come to visions and revelations of the Lord; for in that way God chose to speak by Zechariah, to awaken the people\'s attention, and to engage their humble reverence of the word and their humble enquiries into it, and to fix it the more in their minds and memories. Most of the following visions seem designed for the comfort of the Jews, now newly returned out of captivity, and their encouragement to go on with the building of the temple. The scope of this vision (which is as an introduc...', 'teologico');
add('zc', 1, 18, 'Matthew Henry', 'It is the comfort and triumph of the church (Isa 59:19) that when the enemy shall come in like a flood, with mighty force and fury, then the Spirit of the Lord shall lift up a standard against him. Now, in this vision (the second which this prophet had), we have an illustration of that, God\'s Spirit making a stand, and making head, against the formidable power of the church\'s adversaries.\nI. We have here the enemies of the church bold and daring, and threatening to be its death, to cut off th...', 'teologico');
add('zc', 2, 1, 'Matthew Henry', 'This prophet was ordered, in God\'s name, to assure the people (Zac 1:16) that a line should be stretched forth upon Jerusalem. Now here we have that promise illustrated and confirmed, that the prophet might deliver that part of his message to the people with the more clearness and assurance.\nI. He sees, in a vision, a man going to measure Jerusalem (Zac 2:1, Zac 2:2): He lifted up his eyes again, and looked. God had shown him that which was very encouraging to him, (Zac 1:20), and therefore n...', 'teologico');
add('zc', 2, 6, 'Matthew Henry', 'One would have thought that Cyrus\'s proclamation, which gave liberty to the captive Jews to return to their own land, would suffice to bring them all back, and that, as when Pharaoh gave them leave to quit Egypt and their house of bondage there, they would not leave a hoof behind; but it seems it had not that effect. There were about 40,000 whose spirits God stirred up to go, and they went; but many, perhaps the greater part, staid behind. The land of their captivity was to most of them the l...', 'teologico');
add('zc', 2, 10, 'Matthew Henry', 'Here is, I. Joy proclaimed to the church of God, to the daughter of Zion, that had separated herself from the daughter of Babylon. The Jews that had returned were in distress and danger, their enemies in the neighbourhood were spiteful against them, their friends that remained in Babylon were cool towards them, shy of them, and declined coming in to their assistance; and yet they are directed to sing, and to rejoice even in tribulation. Note, Those that have recovered their purity, and integr...', 'teologico');
add('zc', 3, 1, 'Matthew Henry', 'There was a Joshua that was a principal agent in the first settling of Israel in Canaan; here is another of the same name very active in their second settlement there after the captivity; Jesus is the same name, and it signifies Saviour; and they were both figures of him that was to come, our chief captain and our chief priest. The angel that talked with Zechariah showed him Joshua the high priest; it is probable that the prophet saw him frequently, that he spoke to him, and that there was a ...', 'teologico');
add('zc', 3, 8, 'Matthew Henry', 'As the promises made to David often slide insensibly into promises of the Messiah, whose kingdom David\'s was a type of, so the promises here made to Joshua immediately rise as far upward, and look as far forward, as to Christ, whose priesthood Joshua\'s was now a shadow of, not only in general, as it kept up the line of Aaron\'s priesthood, but especially as it was the reviving of that happy method of correspondence between heaven and earth, to which a great interruption had been given by the i...', 'teologico');
add('zc', 4, 1, 'Matthew Henry', 'Here is, I. The prophet prepared to receive the discovery that was to be made to him: The angel that talked with him came and waked him, Zac 4:1. It seems, though he was in conference with an angel, and about matters of great and public concern, yet he grew dull and fell asleep, as it should seem, while the angel was yet talking with him. Thus the disciples, when they saw Christ transfigured, were heavy with sleep, Luk 9:32. The prophet\'s spirit, no doubt, was willing to attend to that which ...', 'teologico');
add('zc', 4, 11, 'Matthew Henry', 'Enough is said to Zechariah to encourage him, and to enable him to encourage others, with reference to the good work of building the temple which they were now about, and that was the principal intention of the vision he saw; but still he is inquisitive about the particulars, which we will ascribe, not to any vain curiosity, but to the value he had for divine discoveries and the pleasure he took in acquainting himself with them. Those that know much of the things of God cannot but have a humb...', 'teologico');
add('zc', 5, 1, 'Matthew Henry', 'We do not find that the prophet now needed to be awakened, as he did Zac 4:1. Being awakened then, he kept wakeful after; nay, now he needs not be so much as called to look about him, for of his own accord he turns and lifts up his eyes. This good men sometimes get by their infirmities, they make them the more careful and circumspect afterwards. Now observe,\nI. What it was that the prophet saw; he looked up into the air, and behold a flying roll. A vast large scroll of parchment which had bee...', 'teologico');
add('zc', 5, 5, 'Matthew Henry', 'The foregoing vision was very plain and easy, but in this are things dark and hard to be understood; and some think that the scope of it is to foretel the final destruction of the Jewish church and nation and the dispersion of the Jews, when, by crucifying Christ and persecuting his gospel, they should have filled up the measure of their iniquities; therefore it is industriously set out in obscure figures and expressions, "lest the plain denunciation of the second overthrow of temple and stat...', 'teologico');
add('zc', 6, 1, 'Matthew Henry', 'The prophet is forward to receive this vision, and, as if he expected it, he turned and lifted up his eyes and looked. Though this was the seventh vision he had had, yet he did not think he had had enough; for the more we know of God and his will, if we know it aright, the more desirous we shall be to get a further acquaintance with God. Now observe here the sight that the prophet had offour chariots drawn by horses of divers colours, together with the explication of the sight, Zac 6:1-5. He ...', 'teologico');
add('zc', 6, 9, 'Matthew Henry', 'God did not only at sundry times, but in divers manners, speak in time past by the prophets to his church. In the former part of this chapter he spoke by a vision, which only the prophet himself saw; here, in this latter part, he speaks by a sign, or type, which many saw, and which, as it was explained, was an illustrious prediction of the Messiah as the priest and king of his church. Here is,\nI. The significant ceremony which God appointed, and that was the coronation of Joshua the high prie...', 'teologico');
add('zc', 7, 1, 'Matthew Henry', 'This occasional sermon, which the prophet preached, and which is recorded in this and the next chapter, was above two years after the former, in which he gave them an account of his visions, as appears by comparing the date of this (Zac 7:1), in the ninth month of the fourth year of Darius, with the date of that (Zac 1:1), in the eighth month of the second year of Darius; not that Zechariah was idle all that while (it is expressly said that he and Haggai continued prophesying till the temple ...', 'teologico');
add('zc', 7, 8, 'Matthew Henry', 'What was said Zac 7:7, that they should have heard the words of the former prophets, is here enlarged upon, for warning to these hypocritical enquirers, who continued their sins when they asked with great preciseness whether they should continue their fasts. This prophet had before put them in mind of their fathers\' disobedience to the calls of the prophets, and what was the consequence of it (Zac 1:4-6), and now here again; for others\' harms should be our warnings. God\'s judgments upon Israe...', 'teologico');
add('zc', 8, 1, 'Matthew Henry', 'The prophet, in his foregoing discourses, had left his hearers under a high charge of guilt and a deep sense of wrath; he had left them in a melancholy view of the desolations of their pleasant land, which was the effect of their fathers\' disobedience; but because he designed to bring them to repentance, not to drive them to despair, he here sets before them the great things God had in store for them, encouraging them hereby to hope that their case of conscience would shortly determine itself...', 'teologico');
add('zc', 8, 9, 'Matthew Henry', 'God, by the prophet, here gives further assurances of the mercy he had in store for Judah and Jerusalem. Here is line upon line for their comfort, as before there was for their conviction. These verses contain strong encouragements with reference to the difficulties they now laboured under. And we may observe,\nI. Who they were to whom these encouragements did belong - to those who, in obedience to the call of God by his prophets, applied in good earnest to the building of the temple (Zac 8:9)...', 'teologico');
add('zc', 8, 18, 'Matthew Henry', 'These verses contain two precious promises, for the further encouragement of those pious Jews that were hearty in building the temple.\nI. That a happy period should be put to their fasts, and there should be no more occasion for them, but they should be converted into thanksgiving days, Zac 8:19. This is a direct answer to the enquiry concerning their fasts, Zac 7:3. Those of them that fasted in hypocrisy had their doom in the foregoing chapter, but those that in sincerity humbled themselves ...', 'teologico');
add('zc', 9, 1, 'Matthew Henry', 'After the precious promises we had in the foregoing chapter of favour to God\'s people, their persecutors, who hated them, come to be reckoned with, those particularly that bordered close upon them.\nI. The Syrians had been bad neighbours to Israel, and God had a controversy with them. The word of the Lord shall be a burden in the land of Hadrach, that is, of Syria, but it does not appear why it was so called. That that kingdom is meant is plain, because Damascus, the metropolis of that kingdom...', 'teologico');
add('zc', 9, 12, 'Matthew Henry', 'The prophet, having taught those that had returned out of captivity to attribute their deliverance to the blood of the covenant and to the promise of the Messiah (for they were so wonderfully helped because that blessing was in them, was yet in the womb of their nation), now comes to encourage them with the prospect of a joyful and happy settlement, and of glorious times before them; and such a happiness they did enjoy, in a great measure, for some time; but these promises have their full acc...', 'teologico');
add('zc', 10, 1, 'Matthew Henry', 'Gracious things and glorious ones, very glorious and very gracious, were promised to this poor afflicted people in the foregoing chapter; now here God intimates to them that he will for these things be enquired of by them, and that he expects they should acknowledge him in all their ways and in all his ways towards them - and not idols that were rivals with him for their respects.\nI. The prophet directs them to apply to God by prayer for rain in the season thereof. He had promised, in the clo...', 'teologico');
add('zc', 10, 5, 'Matthew Henry', 'Here are divers precious promises made to the people of God, which look further than to the state of the Jews in the latter days of their church, and have certain reference to the spiritual Israel of God, the gospel-church, and all true believers.\nI. They shall have God\'s favour and presence, and shall be owned and accepted of him. This is the foundation of all the rest: The Lord is with them, Zac 10:5. He espouses their cause, takes their part, is on their side; and, if he be for them, who c...', 'teologico');
add('zc', 11, 1, 'Matthew Henry', 'In dark and figurative expressions, as is usual in the scripture predictions of things at a great distance, that destruction of Jerusalem and of the Jewish church and nation is here foretold which our Lord Jesus, when the time was at hand, prophesied of very plainly and expressly. We have here, 1. Preparation made for that destruction (Zac 11:1): "Open thy doors, O Lebanon! Thou wouldst not open them to let thy king in - he came to his own and his own received him not; now thou must open them...', 'teologico');
add('zc', 11, 4, 'Matthew Henry', 'The prophet here is made a type of Christ, as the prophet Isaiah sometimes was; and the scope of these verses is to show that for judgment Christ came into this world (Joh 9:39), for judgment to the Jewish church and nation, which were, about the time of his coming, wretchedly corrupted and degenerated by the worldliness and hypocrisy of their rulers. Christ would have healed them, but they would not be healed; they are therefore left desolate, and abandoned to ruin. Observe here,\nI. The desp...', 'teologico');
add('zc', 11, 15, 'Matthew Henry', 'God, having shown the misery of this people in their being justly abandoned by the good Shepherd, here shows their further misery in being shamefully abused by a foolish shepherd. The prophet is himself to personate and represent this pretended shepherd (Zac 11:15): Take unto thee the instruments or accoutrements of a foolish shepherd, that are no way fit for the business, such a shepherd\'s coat, and bag, and staff, as a foolish shepherd would appear in; for such a shepherd shall be set over ...', 'teologico');
add('zc', 12, 1, 'Matthew Henry', 'Here is, I. The title of this charter of promises made to God\'s Israel; it is the burden of the word of the Lord, a divine prediction; it is of weight in the delivery of it; it is to be pressed upon people, and will be very pressing in the accomplishment of it; it is a burden, a heavy burden, to all the church\'s enemies, like that talent of lead, Zac 5:7, Zac 5:8. But it is for Israel; it is for their comfort and benefit. As even the fiery law (Deu 33:2), so the fiery prophecies and fiery pro...', 'teologico');
add('zc', 12, 9, 'Matthew Henry', 'The day here spoken of is the day of Jerusalem\'s defence and deliverance, that glorious day when God will appear for the salvation of his people, which, if it do refer to the successes which the Jews had against their enemies in the time of the Maccabees, yet certainly looks further, to the gospel-day, to Christ\'s victories over the powers of darkness and the great salvation he has wrought for his chosen. Now we have here an account of two remarkable works designed in that day.\nI. A glorious ...', 'teologico');
add('zc', 13, 1, 'Matthew Henry', 'Behold the Lamb of God taking away the sin of the world, the sin of the church; for therefore was the Son of God manifested, to take away our sin, Jo1 3:5.\nI. He takes away the guilt of sin by the blood of his cross (Zac 13:1): In that day, in the gospel-day, there shall be a fountain opened, that is, provision made for the cleansing of all those from the pollutions of sin who truly repent and are sorry for them. In that day, when the Spirit of grace is poured out to set them a mourning for t...', 'teologico');
add('zc', 13, 7, 'Matthew Henry', 'Here is a prophecy,\nI. Of the sufferings of Christ, of him who was to be pierced, and was to be the fountain opened. Awake, O sword! against my Shepherd, Zac 13:7. These are the words of God the Father, giving order and commission to the sword of his justice to awake against his Son, when he had voluntarily made his soul an offering for sin; for it pleased the Lord to bruise him and put him to grief; and he was stricken, smitten of God, and afflicted, Isa 53:4, Isa 53:10. Observe, 1. How he c...', 'teologico');
add('zc', 14, 1, 'Matthew Henry', 'God\'s providences concerning his church are here represented as strangely changing and strangely mixed.\nI. As strangely changing. Sometimes the tide runs high and strong against them, but presently it turns, and comes to be in favour of them; and God has, for wise and holy ends, set the one over against the other.\n1. God here appears against Jerusalem; judgment begins at the house of God. When the day of the Lord comes (Zac 14:1) Jerusalem must pass through the fire to be refined. God himself...', 'teologico');
add('zc', 14, 8, 'Matthew Henry', 'Here are, I. Blessings promised to Jerusalem, the gospel-Jerusalem, in the day of the Messiah, and to all the earth, by virtue of the blessings poured out on Jerusalem, especially to the land of Israel.\n1. Jerusalem shall be a spring of living waters to the world; it was made so when there the Spirit was poured out upon the apostles, and thence the word of the Lord diffused itself to the nations about (Zac 14:8): Living waters shall go out from Jerusalem; for there they began, and thence thos...', 'teologico');
add('zc', 14, 16, 'Matthew Henry', 'Three things are here foretold: - \nI. That a gospel-way of worship being set up in the church there shall be a great resort to it and a general attendance upon it. Those that were left of the enemies of religion shall be so sensible of the mercy of God to them in their narrow escape that they shall apply themselves to the worship of the God of Israel, and pay their homage to him, Zac 14:16. Those that were not consumed shall be converted, and this makes their deliverance a mercy indeed, a dou...', 'teologico');

// ML (11 comentários)
add('ml', 3, 1, 'Charles Ellicott', 'O anjo da aliança — A dupla identidade: João como arauto, o Messias como senhor da aliança.', 'escatologico');
add('ml', 3, 10, 'Spurgeon', 'Trazei todos os dízimos — A fidelidade material é prova de confiança em Deus.', 'aplicacao');
add('ml', 4, 2, 'Calvino', 'Nascerá o Sol da Justiça — A vinda do Messias como cura e luz para os que O temem.', 'escatologico');
add('ml', 1, 1, 'Matthew Henry', 'The prophecy of this book is entitled, The burden of the word of the Lord (Mal 1:1), which intimates, 1. That it was of great weight and importance; what the false prophets said was light as the chaff, what the true prophets said was ponderous as the wheat, Jer 23:28. 2. That it ought to be often repeated to them and by them, as the burden of a song. 3. That there were those to whom it was a burden and a reproach; they were weary of it, and found themselves so aggrieved by it that they were n...', 'teologico');
add('ml', 1, 6, 'Matthew Henry', 'The prophet is here, by a special commission, calling the priests to account, though they were themselves appointed judges, to call the people to an account. Let the rulers in the house of God know that there is one above them, who will reckon with them for their mal-administrations. Thus saith the Lord of hosts to you, O priests! Mal 1:6. God will have a saying to unfaithful ministers; and it concerns those who speak from God to his people to hear and heed what he says to them, that they may...', 'teologico');
add('ml', 2, 1, 'Matthew Henry', 'What was said in the foregoing chapter was directed to the priests (Mal 1:6): Thus saith the Lord of hosts to you, O priests! that despise my name. But the crimes there charged upon them they were guilty of as sacrificers, and for those they might think it some excuse that they offered what the people brought, and therefore that, if they were not so good as they should be, it was not their fault, but the people\'s; and therefore here the corruptions there complained of are traced to the source...', 'teologico');
add('ml', 2, 10, 'Matthew Henry', 'Corrupt practices are the genuine fruit and product of corrupt principles; and the badness of men\'s hearts and lives is owing to some loose atheistical notions which they have got and which they govern themselves by. Now, in these verses, we have an instance of this; we here find men dealing falsely with one another, and it is because they think falsely of their God. Observe,\nI. How corrupt their practices were. In general, they dealt treacherously every man against his brother, Mal 2:10. It ...', 'teologico');
add('ml', 3, 7, 'Matthew Henry', 'We have here God\'s controversy with the men of that generation, for deserting his service and robbing him - wicked servants indeed, that not only run away from their Master, but run away with their Master\'s goods.\nI. They had run away from their Master, and quitted the work he gave them to do (Mal 3:7): You have gone away from my ordinances and have not kept them. The ordinances of God\'s worship were the business which as servants they must mind, the talents which they must trade with, and th...', 'teologico');
add('ml', 3, 13, 'Matthew Henry', 'Among the people of the Jews at this time, though they all enjoyed the same privileges and advantages, there were men of very different characters (as ever were, and ever will be, in the world and in the church), like Jeremiah\'s figs, some very good and others very bad, some that plainly appeared to be the children of God and others that as plainly discovered themselves to be the children of the wicked one. There are tares and wheat in the same field, chaff and corn in the same floor; and her...', 'teologico');
add('ml', 4, 1, 'Matthew Henry', 'The great and terrible day of the Lord is here prophesied of. This, like the pillar of cloud and fire, shall have a dark side turned towards the Egyptians that fight against God, and a bright side towards the faithful Israelites that follow him: The day cometh, that is, the Lord cometh, the day of the Lord; and it has reference both to the first and to the second coming of Jesus Christ; the day of both was fixed, and should answer the character here given of it.\nI. In both Christ is a consumi...', 'teologico');
add('ml', 4, 4, 'Matthew Henry', 'This is doubtless intended for a solemn conclusion, not only of this prophecy, but of the canon of the Old Testament, and is a plain information that they were not to expect any more sayings nor writing by divine inspiration, any more of the dictates of the Spirit of prophecy, till the beginning of the gospel of the Messiah, which sets aside the Apocrypha as no part of holy writ, and which therefore the Jews never received.\nNow that prophecy ceases, and is about to be sealed up, there are two...', 'teologico');

// MT (106 comentários)
add('mt', 1, 23, 'Tomás de Aquino', 'Emmanuel — A união hipostática: Deus e homem em uma pessoa, o mistério da encarnação.', 'teologico');
add('mt', 3, 2, 'Charles Ellicott', 'Arrependei-vos — João Batista proclama a iminência do reino: arrependimento é resposta ao reino.', 'escatologico');
add('mt', 5, 3, 'Calvino', 'Bem-aventurados os pobres de espírito — O Sermão do Monte inicia pela dependência espiritual de Deus.', 'aplicacao');
add('mt', 5, 4, 'Lloyd-Jones', 'Bem-aventurados os que choram — A tristeza segundo Deus leva ao consolo divino.', 'aplicacao');
add('mt', 5, 5, 'Spurgeon', 'Bem-aventurados os mansos — A mansidão não é fraqueza, mas força controlada pela graça.', 'aplicacao');
add('mt', 5, 6, 'John Piper', 'Bem-aventurados os que têm fome e sede — A fome de justiça é satisfeita por Deus.', 'aplicacao');
add('mt', 5, 8, 'Calvino', 'Bem-aventurados os limpos de coração — A pureza de coração é condição para ver a Deus.', 'teologico');
add('mt', 5, 9, 'Calvino', 'Bem-aventurados os pacificadores — Os que trazem paz refletem o caráter de Deus, o Príncipe da Paz.', 'aplicacao');
add('mt', 5, 10, 'N.T. Wright', 'Bem-aventurados os perseguidos — A perseguição é marca da fidelidade ao reino.', 'teologico');
add('mt', 6, 9, 'Lutero', 'Pai nosso que estás nos céus — O modelo de oração: relação filial com Deus, santidade do nome, vinda do reino.', 'teologico');
add('mt', 6, 10, 'Wesley', 'Venha o teu reino — A oração pela soberania de Deus: que Sua vontade se cumpra na terra.', 'teologico');
add('mt', 6, 13, 'Calvino', 'Não nos induzas à tentação — Deus permite provas para fortalecer, mas livra do mal final.', 'teologico');
add('mt', 10, 32, 'Tim Keller', 'Todo aquele que me confessar — A confissão de Cristo é necessária: fé privada exige declaração pública.', 'aplicacao');
add('mt', 11, 28, 'João Crisóstomo', 'Vinde a mim — O convite mais doce da Escritura: Cristo recebe todos os que vêm a Ele.', 'aplicacao');
add('mt', 11, 29, 'Wesley', 'Aprendei de mim — A mansidão de Cristo é o modelo para os discípulos.', 'aplicacao');
add('mt', 16, 16, 'Calvino', 'Tu és o Cristo, o Filho do Deus vivente — A confissão de Pedro é a pedra angular da fé cristã.', 'teologico');
add('mt', 16, 18, 'Spurgeon', 'Edificarei a minha igreja — A promessa de Cristo: a igreja é indestrutível, apesar das portas do inferno.', 'teologico');
add('mt', 18, 20, 'John Stott', 'Onde estiverem dois ou três — A presença comunitária de Cristo: a igreja reunida tem Sua companhia.', 'teologico');
add('mt', 22, 37, 'Tomás de Aquino', 'Amarás o teu Deus — O primeiro e maior mandamento: amor total a Deus com toda a pessoa.', 'teologico');
add('mt', 22, 39, 'Calvino', 'Amarás o teu próximo — O amor ao próximo é inseparável do amor a Deus: dois mandamentos, uma lei.', 'teologico');
add('mt', 24, 35, 'Adam Clarke', 'Minhas palavras não passarão — A permanência da Palavra divina: mais firme que os céus.', 'teologico');
add('mt', 26, 26, 'Tomás de Aquino', 'Isto é o meu corpo — A Eucaristia: Cristo institui o sacramento na Última Ceia.', 'teologico');
add('mt', 26, 28, 'Calvino', 'O meu sangue da nova aliança — O sangue de Cristo é o fundamento da nova aliança.', 'teologico');
add('mt', 27, 46, 'Calvino', 'Eli, Eli — Jesus assume o lugar do pecador, experimentando o abandono que merecíamos.', 'teologico');
add('mt', 28, 19, 'Atanásio', 'Fazei discípulos de todas as nações — A missão trinitária: batizando em nome do Pai, do Filho e do Espírito.', 'teologico');
add('mt', 28, 18, 'John Piper', 'Toda autoridade me é dada — A autoridade cósmica de Cristo é base para a missão mundial.', 'teologico');
add('mt', 28, 20, 'Lloyd-Jones', 'Eu estou convosco — A presença perpetua de Cristo: Ele nunca abandona Seu povo.', 'teologico');
add('mt', 5, 17, 'Lutero', 'Não vim ab-rogar a lei — Cristo cumpre a Lei e os Profetas; não os anula, mas os leva ao seu intento.', 'teologico');
add('mt', 6, 33, 'Matthew Henry', 'Buscai primeiro o reino — A prioridade do reino de Deus atrai todas as demais necessidades.', 'aplicacao');
add('mt', 1, 1, 'Matthew Henry', 'Concerning this genealogy of our Saviour, observe,\nI. The title of it. It is the book (or the account, as the Hebrew word sepher, a book, sometimes signifies) of the generation of Jesus Christ, of his ancestors according to the flesh; or, It is the narrative of his birth. It is Biblos Geneseōs - a book of Genesis. The Old Testament begins with the book of the generation of the world, and it is its glory that it does so; but the glory of the New Testament herein excelleth, that it begins with...', 'teologico');
add('mt', 1, 18, 'Matthew Henry', 'The mystery of Christ\'s incarnation is to be adored, not pried into. If we know not the way of the Spirit in the formation of common persons, nor how the bones are formed in the womb of any one that is with child (Ecc 11:5), much less do we know how the blessed Jesus was formed in the womb of the blessed virgin. When David admires how he himself was made in secret, and curiously wrought (Psa 139:13-16), perhaps he speaks in the spirit of Christ\'s incarnation. Some circumstances attending the ...', 'teologico');
add('mt', 2, 1, 'Matthew Henry', 'It was a mark of humiliation put upon the Lord Jesus that, though he was the Desire of all nations, yet his coming into the world was little observed and taken notice of, his birth was obscure and unregarded: herein he emptied himself, and made himself of no reputation. If the Son of God must be brought into the world, one might justly expect that he should be received with all the ceremony possible, that crowns and sceptres should immediately have been laid at his feet, and that the high and...', 'teologico');
add('mt', 2, 9, 'Matthew Henry', 'We have here the wise men\'s humble attendance upon this new-born King of the Jews, and the honours they paid him. From Jerusalem they went to Bethlehem, resolving to seek till they should find; but it is very strange that they went alone; that not one person of the court, church, or city, should accompany them, if not in conscience, yet in civility to them, or touched with a curiosity to see this young prince. As the queen of the south, so the wise men of the east, will rise up in judgment ag...', 'teologico');
add('mt', 2, 13, 'Matthew Henry', 'We have here Christ\'s flight into Egypt to avoid the cruelty of Herod, and this was the effect of the wise men\'s enquiry after him; for, before that, the obscurity he lay in was his protection. It was but little respect (compared with what should have been) that was paid to Christ in his infancy: yet even that, instead of honouring him among his people, did but expose him.\nNow here observe, 1. The command given to Joseph concerning it, Mat 2:13. Joseph knew neither the danger the child was in...', 'teologico');
add('mt', 2, 16, 'Matthew Henry', 'Here is, I. Herod\'s resentment of the departure of the wise men. He waited long for their return; he hopes, though they be slow, they will be sure, and he shall crush this rival at his first appearing; but he hears, upon enquiry, that they are gone off another way, which increases his jealousy, and makes him suspect they are in the interest of this new King, which made him exceedingly wroth; and he is the more desperate and outrageous for his being disappointed. Note, Inveterate corruption sw...', 'teologico');
add('mt', 2, 19, 'Matthew Henry', 'We have here Christ\'s return out of Egypt into the land of Israel again. Egypt may serve to sojourn in, or take shelter in, for a while, but not to abide in. Christ was sent to the lost sheep of the house of Israel, and therefore to them he must return. Observe,\nI. What it was that made way for his return - the death of Herod, which happened not long after the murder of the infants; some think not above three months. Such quick work did divine vengeance make! Note, Herods must die; proud tyra...', 'teologico');
add('mt', 3, 1, 'Matthew Henry', 'We have here an account of the preaching and baptism of John, which were the dawning of the gospel-day. Observe,\nI. The time when he appeared. In those days (Mat 3:1), or, after those days, long after what was recorded in the foregoing chapter, which left the child Jesus in his infancy. In those days, in the time appointed of the Father for the beginning of the gospel, when the fulness of time was come, which was often thus spoken of in the Old Testament, In those days. Now the last of Daniel...', 'teologico');
add('mt', 3, 7, 'Matthew Henry', 'The doctrine John preached was that of repentance, in consideration of the kingdom of heaven being at hand; now here we have the use of that doctrine. Application is the life of preaching, so it was of John\'s preaching.\nObserve, 1. To whom he applied it; to the Pharisees and Sadducees that came to his baptism, Mat 3:7. To others he thought it enough to say, Repent, for the kingdom of heaven is at hand; but when he saw these Pharisees and Sadducees come about him, he found it necessary to expl...', 'teologico');
add('mt', 3, 13, 'Matthew Henry', 'Our Lord Jesus, from his childhood till now, when he was almost thirty years of age, had lain hid in Galilee, as it were, buried alive; but now, after a long and dark night, behold, the Sun of righteousness rises in glory. The fulness of time was come that Christ should enter upon his prophetical office; and he chooses to do it, not at Jerusalem (though it is probable that he went thither at the three yearly feasts, as others did), but there where John was baptizing; for to him resorted those...', 'teologico');
add('mt', 4, 1, 'Matthew Henry', 'We have here the story of a famous duel, fought hand to hand, between Michael and the dragon, the Seed of the woman and the seed of the serpent, nay, the serpent himself; in which the seed of the woman suffers, being tempted, and so has his heel bruised; but the serpent is quite baffled in his temptations, and so has his head broken; and our Lord Jesus comes off a Conqueror, and so secures not only comfort, but conquest at last, to all his faithful followers. Concerning Christ\'s temptation, o...', 'teologico');
add('mt', 4, 12, 'Matthew Henry', 'We have here an account of Christ\'s preaching in the synagogues of Galilee, for he came into the world to be a Preacher; the great salvation which he wrought out, he himself began to publish (Heb 2:3) to show how much his heart was upon it, and ours should be.\nSeveral passages in the other gospels, especially in that of St. John, are supposed, in the order of the story of Christ\'s life, to intervene between his temptation and his preaching in Galilee. His first appearance after his temptation...', 'teologico');
add('mt', 4, 18, 'Matthew Henry', 'When Christ began to preach, he began to gather disciples, who should now be the hearers, and hereafter the preachers, of his doctrine, who should now be witnesses of his miracles, and hereafter concerning them. Now, in these verses, we have an account of the first disciples that he called into fellowship with himself.\nAnd this was an instance, 1. Of effectual calling to Christ. In all his preaching he gave a common call to all the country, but in this he gave a special and particular call to...', 'teologico');
add('mt', 4, 23, 'Matthew Henry', 'See here, I. What an industrious preacher Christ was; He went about all Galilee, teaching in their synagogues, and preaching the gospel of the kingdom. Observe, 1. What Christ preached - the gospel of the kingdom. The kingdom of heaven, that is, of grace and glory, is emphatically the kingdom, the kingdom that was now to come; that kingdom which shall survive, as it doth surpass, all the kingdoms of the earth. The gospel is the charter of that kingdom, containing the King\'s coronation oath, b...', 'teologico');
add('mt', 5, 1, 'Matthew Henry', 'We have here a general account of this sermon.\nI. The Preacher was our Lord Jesus, the Prince of preachers, the great Prophet of his church, who came into the world, to be the Light of the world. The prophets and John had done virtuously in preaching, but Christ excelled them all. He is the eternal Wisdom, that lay in the bosom of the Father, before all worlds, and perfectly knew his will (Joh 1:18); and he is the eternal Word, by whom he has in these last days spoken to us. The many miraculo...', 'teologico');
add('mt', 5, 13, 'Matthew Henry', 'Christ had lately called his disciples, and told them that they should be fishers of men; here he tells them further what he designed them to be - the salt of the earth, and lights of the world, that they might be indeed what it was expected they should be.\nI. Ye are the salt of the earth. This would encourage and support them under their sufferings, that, though they should be treated with contempt, yet they should really be blessings to the world, and the more so for their suffering thus. T...', 'teologico');
add('mt', 5, 21, 'Matthew Henry', 'Christ having laid down these principles, that Moses and the prophets were still to be their rulers, but that the scribes and Pharisees were to be no longer their rulers, proceeds to expound the law in some particular instances, and to vindicate it from the corrupt glosses which those expositors had put upon it. He adds not any thing new, only limits and restrains some permissions which had been abused: and as to the precepts, shows the breadth, strictness, and spiritual nature of them, addin...', 'teologico');
add('mt', 5, 27, 'Matthew Henry', 'We have here an exposition of the seventh commandment, given us by the same hand that made the law, and therefore was fittest to be the interpreter of it: it is the law against uncleanness, which fitly follows upon the former; that laid a restraint upon sinful passions, this upon sinful appetites, both which ought always to be under the government of reason and conscience, and if indulged, are equally pernicious.\nI. The command is here laid down (Mat 5:27), Thou shalt not commit adultery; whi...', 'teologico');
add('mt', 5, 33, 'Matthew Henry', 'We have here an exposition of the third commandment, which we are the more concerned right to understand, because it is particularly said, that God will not hold him guiltless, however he may hold himself, who breaks this commandment, by taking the name of the Lord in vain. Now as to this command,\nI. It is agreed on all hands that it forbids perjury, forswearing, and the violation of oaths and vows, Mat 5:33. This was said to them of old time, and is the true intent and meaning of the third c...', 'teologico');
add('mt', 5, 38, 'Matthew Henry', 'In these verses the law of retaliation is expounded, and in a manner repealed. Observe,\nI. What the Old Testament permission was, in case of injury; and here the expression is only, Ye have heard that is has been said; not, as before, concerning the commands of the decalogue, that it has been said by, or to, them of old time. It was a command, that every one should of necessity require such satisfaction; but they might lawfully insist upon it, if they pleased; an eye for an eye, and a tooth f...', 'teologico');
add('mt', 5, 43, 'Matthew Henry', 'We have here, lastly, an exposition of that great fundamental law of the second table, Thou shalt love thy neighbour, which was the fulfilling of the law.\nI. See here how this law was corrupted by the comments of the Jewish teachers, Mat 5:43. God said, Thou shalt love thy neighbour; and by neighbour they understood those only of their own country, nation, and religion; and those only that they were pleased to look upon as their friends: yet this was not the worst; from this command, Thou sha...', 'teologico');
add('mt', 6, 1, 'Matthew Henry', 'As we must do better than the scribes and Pharisees in avoiding heart-sins, heart-adultery, and heart-murder, so likewise in maintaining and keeping up heart-religion, doing what we do from an inward, vital principle, that we may be approved of God, not that we may be applauded of men; that is, we must watch against hypocrisy, which was the leaven of the Pharisees, as well as against their doctrine, Luk 12:1. Almsgiving, prayer, and fasting, are three great Christian duties - the three founda...', 'teologico');
add('mt', 6, 5, 'Matthew Henry', 'In prayer we have more immediately to do with God than in giving alms, and therefore are yet more concerned to be sincere, which is what we are here directed to. When thou prayest (Mat 6:5). It is taken for granted that all the disciples of Christ pray. As soon as ever Paul was converted, behold he prayeth. You may as soon find a living man that does not breathe, as a living Christian that does not pray. For this shall every one that is godly pray. If prayerless, then graceless. "Now, when th...', 'teologico');
add('mt', 6, 16, 'Matthew Henry', 'We are here cautioned against hypocrisy in fasting, as before in almsgiving, and in prayer.\nI. It is here supposed that religious fasting is a duty required of the disciples of Christ, when God, in his providence, calls to it, and when the case of their own souls upon any account requires it; when the bridegroom is taken away, then shall they fast, Mat 9:15. Fasting is here put last, because it is not so much a duty for its own sake, as a means to dispose us for other duties. Prayer comes in ...', 'teologico');
add('mt', 6, 19, 'Matthew Henry', 'Worldly-mindedness is as common and as fatal a symptom of hypocrisy as any other, for by no sin can Satan have a surer and faster hold of the soul, under the cloak of a visible and passable profession of religion, than by this; and therefore Christ, having warned us against coveting the praise of men, proceeds next to warn us against coveting the wealth of the world; in this also we must take heed, lest we be as the hypocrites are, and do as they do: the fundamental error that they are guilty...', 'teologico');
add('mt', 6, 25, 'Matthew Henry', 'There is scarcely any one sin against which our Lord Jesus more largely and earnestly warns his disciples, or against which he arms them with more variety of arguments, than the sin of disquieting, distracting, distrustful cares about the things of life, which are a bad sign that both the treasure and the heart are on the earth; and therefore he thus largely insists upon it. Here is,\nI. The prohibition laid down. It is the counsel and command of the Lord Jesus, that we take no thought about t...', 'teologico');
add('mt', 7, 1, 'Matthew Henry', 'Our Saviour is here directing us how to conduct ourselves in reference to the faults of others; and his expressions seem intended as a reproof to the scribes and Pharisees, who were very rigid and severe, very magisterial and supercilious, in condemning all about them, as those commonly are, that are proud and conceited in justifying themselves. We have here,\nI. A caution against judging Mat 7:1, Mat 7:2. There are those whose office it is to judge - magistrates and ministers. Christ, though ...', 'teologico');
add('mt', 7, 7, 'Matthew Henry', 'Our Saviour, in the foregoing chapter, had spoken of prayer as a commanded duty, by which God is honoured, and which, if done aright, shall be rewarded; here he speaks of it as the appointed means of obtaining what we need, especially grace to obey the precepts he had given, some of which are so displeasing to flesh and blood.\nI. Here is a precept in three words to the same purport, Ask, Seek, Knock (Mat 7:7); that is, in one word, "Pray; pray often; pray with sincerity and seriousness; pray,...', 'teologico');
add('mt', 7, 12, 'Matthew Henry', 'Our Lord Jesus here presses upon us that righteousness towards men which is an essential branch of true religion, and that religion towards God which is an essential branch of universal righteousness.\nI. We must make righteousness our rule, and be ruled by it, Mat 7:12. Therefore, lay this down for your principle, to do as you would be done by; therefore, that you may conform to the foregoing precepts, which are particular, that you may not judge and censure others, go by this rule in general...', 'teologico');
add('mt', 7, 15, 'Matthew Henry', 'We have here a caution against false prophets, to take heed that we be not deceived and imposed upon by them. Prophets are properly such as foretel things to come; there are some mentioned in the Old Testament, who pretended to that without warrant, and the event disproved their pretensions, as Zedekiah, Kg1 22:11, and another Zedekiah, Jer 29:21. But prophets did also teach the people their duty, so that false prophets here are false teachers. Christ being a Prophet and a Teacher come from G...', 'teologico');
add('mt', 7, 21, 'Matthew Henry', 'We have here the conclusion of this long and excellent sermon, the scope of which is to show the indispensable necessity of obedience to the commands of Christ; this is designed to clench the nail, that it might fix in a sure place: he speaks this to his disciples, that sat at his feet whenever he preached, and followed him wherever he went. Had he sought his own praise among men, he would have said, that was enough; but the religion he came to establish is in power, not in word only (Co1 4:2...', 'teologico');
add('mt', 8, 1, 'Matthew Henry', 'The first verse refers to the close of the foregoing sermon: the people that heard him were astonished at his doctrine; and the effect was, that when he came down from the mountain, great multitudes followed him; though he was so strict a Lawgiver, and so faithful a Reprover, they diligently attended him, and were loth to disperse, and go from him. Note, They to whom Christ has manifested himself, cannot but desire to be better acquainted with him. They who know much of Christ should covet to...', 'teologico');
add('mt', 8, 5, 'Matthew Henry', 'We have here an account of Christ\'s curing the centurion\'s servant of a palsy. This was done at Capernaum, where Christ now dwelt, Mat 4:13. Christ went about doing good, and came home to do good too; every place he came to was the better for him.\nThe persons Christ had now to do with were,\n1. A centurion; he was a supplicant, a Gentile, a Roman, an officer of the army; probably commander-in-chief of that part of the Roman army which was quartered at Capernaum, and kept garrison there. (1.) T...', 'teologico');
add('mt', 8, 14, 'Matthew Henry', 'They who pretend to be critical in the Harmony of the evangelists, place this passage, and all that follows to the end of ch. 9 before the sermon on the mount, according to the order which Mark and Luke observe in placing it. Dr. Lightfoot places only this passage before the sermon on the mount, and Mat 8:18, etc. after. Here we have,\nI. A particular account of the cure of Peter\'s wife\'s mother, who was ill of a fever; in which observe,\n1. The case, which was nothing extraordinary; fevers are...', 'teologico');
add('mt', 8, 18, 'Matthew Henry', 'Here is, I. Christ\'s removing to the other side of the sea of Tiberias, and his ordering his disciples, whose boats attended him, to get their transport-vessels ready, in order to it, Mat 8:18. The influences of this Sun of righteousness were not to be confined to one place, but diffused all the country over; he must go about to do good; the necessities of souls called to him, Come over, and help us (Act 16:9); he removed when he saw great multitudes about him. Though by this it appeared that...', 'teologico');
add('mt', 8, 23, 'Matthew Henry', 'Christ had given sailing orders to his disciples (Mat 8:18), that they should depart to the other side of the sea of Tiberias, into the country of Gadara, in the tribe of Gad, which lay east of Jordan; thither he would go to rescue a poor creature that was possessed with a legion of devils, though he foresaw how he should be affronted there. Now. 1. He chose to go by water. It had not been much about, if he had gone by land; but he chose to cross the lake, that he might have occasion to manif...', 'teologico');
add('mt', 8, 28, 'Matthew Henry', 'We have here the story of Christ\'s casting the devils out of two men that were possessed. The scope of this chapter is to show the divine power of Christ, by the instances of his dominion over bodily diseases, which to us are irresistible; over winds and waves, which to us are yet more uncontrollable; and lastly, over devils, which to us are most formidable of all. Christ has not only all power in heaven and earth and all deep places, but has the keys of hell too. Principalities and powers we...', 'teologico');
add('mt', 9, 1, 'Matthew Henry', 'The first words of this chapter oblige us to look back to the close of that which precedes it, where we find the Gadarenes so resenting the loss of their swine, that they were disgusted with Christ\'s company, and besought him to depart out of their coasts. Now here it follows, He entered into a ship, and passed over. They bid him begone, and he took them at their word, and we never read that he came into their coasts again. Now here observe, 1. His justice - that he left them. Note, Christ wi...', 'teologico');
add('mt', 9, 9, 'Matthew Henry', 'In these verses we have an account of the grace and favour of Christ to poor publicans, particularly to Matthew. What he did to the bodies of people was to make way for a kind design upon their souls. Now observe here,\nI. The call of Matthew, the penman of this gospel. Mark and Luke call him Levi; it was ordinary for the same person to have two names: perhaps Matthew was the name he was most known by as a publican, and, therefore, in his humility, he called himself by that name, rather than b...', 'teologico');
add('mt', 9, 14, 'Matthew Henry', 'The objections which were made against Christ and his disciples gave occasion to some of the most profitable of his discourses; thus are the interests of truth often served, even by the opposition it meets with from gainsayers, and thus the wisdom of Christ brings good out of evil. This is the third instance of it in this chapter; his discourse of his power to forgive sin, and his readiness to receive sinners, was occasioned by the cavils of the scribes and Pharisees; so here, from a reflecti...', 'teologico');
add('mt', 9, 18, 'Matthew Henry', 'We have here two passages of history put together; that of the raising of Jairus\'s daughter to life, and that of the curing of the woman that had the bloody issue, as he was going to Jairus\'s house, which is introduced in a parenthesis, in the midst of the other; for Christ\'s miracles were thick sown, and interwoven; the work of him that sent him was his daily work. He was called to do these good works from speaking the things foregoing, in answer to the cavils of the Pharisees, Mat 9:18 : Wh...', 'teologico');
add('mt', 9, 27, 'Matthew Henry', 'In these verses we have an account of two more miracles wrought together by our Saviour.\nI. The giving of sight to two blind men, Mat 9:27-31. Christ is the Fountain of light as well as life; and as, by raising the dead, he showed himself to be the same that at first breathed into man the breath of life, so, by giving sight to the blind, he showed himself to be the same that at first commanded the light to shine out of darkness. Observe,\n1. The importunate address of the blind men to Christ. ...', 'teologico');
add('mt', 9, 35, 'Matthew Henry', 'Here is, I. A conclusion of the foregoing account of Christ\'s preaching and miracles (Mat 9:35); He went about all the cities teaching and healing. This is the same we had before, Mat 4:23. There it ushers in the more particular record of Christ\'s preaching (ch. 5, 6 and 7) and of his cures (ch. 8 and 9), and here it is elegantly repeated in the close of these instances, as the quod erat demonstrandum - the point to be proved; as if the evangelist should say, "Now I hope I have made it out, b...', 'teologico');
add('mt', 10, 1, 'Matthew Henry', 'Here we are told, I. Who they were that Christ ordained to be his apostles or ambassadors; they were his disciples, Mat 10:1. He had called them some time before to be disciples, his immediate followers and constant attendants, and he then told them that they should be made fishers of men, which promise he now performed. Note, Christ commonly confers honours and graces by degrees; the light of both, like that of the morning, shines more and more. All this while Christ had kept these twelve,\n1...', 'teologico');
add('mt', 10, 5, 'Matthew Henry', 'We have here the instructions that Christ gave to his disciples, when he gave them their commission. Whether this charge was given them in a continued discourse, or the several articles of it hinted to them at several times, is not material; in this he commanded them. Jacob\'s blessing his sons, is called his commanding them, and with these commands Christ commanded a blessing. Observe,\nI. The people to whom he sent them. These ambassadors are directed what places to go to.\n1. Not to the Genti...', 'teologico');
add('mt', 10, 16, 'Matthew Henry', 'All these verses relate to the sufferings of Christ\'s ministers in their work, which they are here taught to expect, and prepare for; they are directed also how to bear them, and how to go on with their work in the midst of them. This part of the sermon looks further than to their present mission; for we find not that they met with any great hardships or persecutions while Christ was with them, nor were they well able to bear them; but they are here forewarned of the troubles they should meet...', 'teologico');
add('mt', 11, 1, 'Matthew Henry', 'The first verse of this chapter some join to the foregoing chapter, and make it (not unfitly) the close of that.\n1. The ordination sermon which Christ preached to his disciples in the foregoing chapter is here called his commanding them. Note, Christ\'s commissions imply commands. Their preaching of the gospel was not only permitted them, but it was enjoined them. It was not a thing respecting which they were left at their liberty, but necessity was laid upon them, Co1 9:16. The promises he ma...', 'teologico');
add('mt', 11, 7, 'Matthew Henry', 'We have here the high encomium which our Lord Jesus gave of John the Baptist; not only to revive his honour, but to revive his work. Some of Christ\'s disciples might perhaps take occasion from the question John sent, to reflect upon him, as weak and wavering, and inconsistent with himself, to prevent which Christ gives him this character. Note, It is our duty to consult the reputation of our brethren, and not only to remove, but to obviate and prevent, jealousies and ill thoughts of them; and...', 'teologico');
add('mt', 11, 16, 'Matthew Henry', 'Christ was going on in the praise of John the Baptist and his ministry, but here stops on a sudden, and turns that to the reproach of those who enjoyed both that, and the ministry of Christ and his apostles too, in vain. As to that generation, we may observe to whom he compares them (Mat 11:16-19), and as to the particular places he instances in, we may observe with whom he compares them, Mat 11:20-24.\nI. As to that generation, the body of the Jewish people at that time. There were many indee...', 'teologico');
add('mt', 11, 25, 'Matthew Henry', 'In these verses we have Christ looking up to heaven, with thanksgiving to his Father for the sovereignty and security of the covenant of redemption; and looking around him upon this earth, with an offer to all the children of men, to whom these presents shall come, of the privileges and benefits of the covenant of grace.\nI. Christ here returns thanks to God for his favour to those babes who had the mysteries of the gospel revealed to them (Mat 11:25, Mat 11:26). Jesus answered and said. It is...', 'teologico');
add('mt', 12, 1, 'Matthew Henry', 'The Jewish teachers had corrupted many of the commandments, by interpreting them more loosely than they were intended; a mistake which Christ discovered and rectified (ch. 5) in his sermon on the mount: but concerning the fourth commandment, they had erred in the other extreme, and interpreted it too strictly. Note, it is common for men of corrupt minds, by their zeal in rituals, and the external services of religion, to think to atone for the looseness of their morals. But they are cursed wh...', 'teologico');
add('mt', 12, 14, 'Matthew Henry', 'As in the midst of Christ\'s greatest humiliations, there were proofs of his dignity, so in the midst of his greatest honours, he gave proofs of his humility; and when the mighty works he did gave him an opportunity of making a figure, yet he made it appear that he emptied himself, and made himself of no reputation. Here we have,\nI. The cursed malice of the Pharisees against Christ (Mat 12:14); being enraged at the convincing evidence of his miracles, they went out, and held a council against ...', 'teologico');
add('mt', 12, 22, 'Matthew Henry', 'In these verses we have,\nI. Christ\'s glorious conquest of Satan, in the gracious cure of one who, by the divine permission, was under his power, and in his possession, Mat 12:22. Here observe,\n1. The man\'s case was very sad; he was possessed with a devil. More cases of this kind occurred in Christ\'s time than usual, that Christ\'s power might be the more magnified, and his purpose the more manifested, in opposing and dispossessing Satan; and that it might the more evidently appear, that he cam...', 'teologico');
add('mt', 12, 38, 'Matthew Henry', 'It is probable that these Pharisees with whom Christ is here in discourse were not the same that cavilled at him (Mat 12:24), and would not credit the signs he gave; but another set of them, who saw that there was no reason to discredit them, but would not content themselves with the signs he gave, nor admit the evidence of them, unless he would give them such further proof as they should demand. Here is,\nI. Their address to him, Mat 12:38. They compliment him with the title of Master, preten...', 'teologico');
add('mt', 12, 46, 'Matthew Henry', 'Many excellent, useful sayings came from the mouth of our Lord Jesus upon particular occasions; even his digressions were instructive, as well as his set discourses: as here,\nObserve, I. How Christ was interrupted in his preaching by his mother and his brethren, that stood without, desiring to speak with him (Mat 12:40, Mat 12:47); which desire of theirs was conveyed to him through the crowd. It is needless to enquire which of his brethren they were that came along with his mother (perhaps th...', 'teologico');
add('mt', 13, 1, 'Matthew Henry', 'We have here Christ preaching, and may observe,\n1. When Christ preached this sermon; it was the same day that he preached the sermon in the foregoing chapter: so unwearied was he in doing good, and working the works of him that sent him. Note, Christ was for preaching both ends of the day, and has by his example recommended that practice to his church; we must in the morning sow our seed, and in the evening not withhold our hand, Ecc 11:6. An afternoon sermon well heard, will be so far from d...', 'teologico');
add('mt', 13, 24, 'Matthew Henry', 'In these verses, we have, I. Another reason given why Christ preached by parables, Mat 13:34, Mat 13:35. All these things he spoke in parables, because the time was not yet come for the more clear and plain discoveries of the mysteries of the kingdom. Christ, to keep the people attending and expecting, preached in parables, and without a parable spake he not unto them; namely, at this time and in this sermon. Note, Christ tries all ways and methods to do good to the souls of men, and to make ...', 'teologico');
add('mt', 13, 44, 'Matthew Henry', 'We have four short parables in these verses.\nI. That of the treasure hid in the field. Hitherto he had compared the kingdom of heaven to small things, because its beginning was small; but, lest any should thence take occasion to think meanly of it, in this parable and the next he represents it as of great value in itself, and of great advantage to those who embrace it, and are willing to come up to its terms; it is here likened to a treasure hid in the field, which, if we will, we may make ou...', 'teologico');
add('mt', 13, 53, 'Matthew Henry', 'We have here Christ in his own country. He went about doing good, yet left not any place till he had finished his testimony there at that time. His own countrymen had rejected him once, yet he came to them again. Note, Christ does not take refusers at their first word, but repeats his offers to those who have often repulsed them. In this, as in other things, Christ was like his brethren; he had a natural affection to his own country; Patriam quisque amat, non quia pulchram, sed quia suam - Ev...', 'teologico');
add('mt', 14, 1, 'Matthew Henry', 'We have here the story of John\'s martyrdom. Observe,\nI. The occasion of relating this story here, Mat 14:1, Mat 14:2. Here is,\n1. The account brought to Herod of the miracles which Christ wrought. Herod the tetrarch or chief governor of Galilee heard of the fame of Jesus. At that time, when his countrymen slighted him, upon the account of his meanness and obscurity, he began to be famous at court. Note, God will honour those that are despised for his sake. And the gospel, like the sea, gets i...', 'teologico');
add('mt', 14, 13, 'Matthew Henry', 'This passage of story, concerning Christ\'s feeding five thousand men with five loaves and two fishes, is recorded by all the four Evangelists, which very few, if any, of Christ\'s miracles are: this intimates that there is something in it worthy of special remark. Observe,\nI. The great resort of people to Christ, when he was retired into a desert place, Mat 14:13. He withdrew into privacy when he heard, not of John\'s death, but of the thoughts Herod had concerning him, that he was John the Bap...', 'teologico');
add('mt', 14, 22, 'Matthew Henry', 'We have here the story of another miracle which Christ wrought for the relief of his friends and followers, his walking upon the water to his disciples. In the foregoing miracle he acted as the Lord of nature, improving its powers for the supply of those who were in want; in this, he acted as the Lord of nature, correcting and controlling its powers for the succour of those who were in danger and distress. Observe,\nI. Christ\'s dismissing of his disciples and the multitude, after he had fed th...', 'teologico');
add('mt', 14, 34, 'Matthew Henry', 'We have here an account of miracles by wholesale, which Christ wrought on the other side of the water, in the land of Gennesaret. Whithersoever Christ went, he was doing good. Gennesaret was a tract of land that lay between Bethsaida and Capernaum, and either gave the name to, or took the name fRom. this sea, which is called (Luk 5:1) The Lake of Gennesaret; it signifies the valley of branches. Observe here,\nI. The forwardness and faith of the men of that place. These were more noble than the...', 'teologico');
add('mt', 15, 1, 'Matthew Henry', 'Evil manners, we say, beget good laws. The intemperate heat of the Jewish teachers for the support of their hierarchy, occasioned many excellent discourses of our Saviour\'s for the settling of the truth, as here.\nI. Here, is the cavil of the scribes and Pharisees at Christ\'s disciples, for eating with unwashen hands. The scribes and Pharisees were the great men of the Jewish church, men whose gain was godliness, great enemies to the gospel of Christ, but colouring their opposition with a pret...', 'teologico');
add('mt', 15, 10, 'Matthew Henry', 'Christ having proved that the disciples, in eating with unwashen hands, were not to be blamed, as transgressing the traditions and injunctions of the elders, comes here to show that they were not to be blamed, as having done any thing that was in itself evil. In the former part of his discourse he overturned the authority of the law, and in this the reason of it. Observe,\nI. The solemn introduction to this discourse (Mat 15:10); He called the multitude. They were withdrawn while Christ discou...', 'teologico');
add('mt', 15, 21, 'Matthew Henry', 'We have here that famous story of Christ\'s casting the devil out of the woman of Canaan\'s daughter; it has something in it singular and very surprising, and which looks favourably upon the poor Gentiles, and is an earnest of the mercy which Christ had in store for them. Here is a gleam of that light which was to lighten the Gentiles, Luk 2:32. Christ came to his own, and his own received him not; but many of them quarrelled with him, and were offended in him; and observe what follows, Mat 15:...', 'teologico');
add('mt', 15, 29, 'Matthew Henry', 'Here is, I. A general account of Christ\'s cures, his curing by wholesale. The tokens of Christ\'s power and goodness are neither scarce nor scanty; for there is in him an overflowing fulness. Now observe,\n1. The place where these cures were wrought; it was near the sea of Galilee, a part of the country Christ was much conversant with. We read not of any thing he did in the coasts of Tyre and Sidon, but the casting of the devil out of the woman of Canaan\'s daughter, as if he took that journey o...', 'teologico');
add('mt', 16, 1, 'Matthew Henry', 'We have here Christ\'s discourse with the Pharisees and Sadducees, men at variance among themselves, as appears Act 23:7, Act 23:8, and yet unanimous in their opposition to Christ; because his doctrine did equally overthrow the errors and heresies of the Sadducees, who denied the existence of spirits and a future state; and the pride, tyranny, and hypocrisy of the Pharisees, who were the great imposters of the traditions of the elders. Christ and Christianity meet with opposition on all hands....', 'teologico');
add('mt', 16, 5, 'Matthew Henry', 'We have here Christ\'s discourse with his disciples concerning bread, in which, as in many other discourses, he speaks to them of spiritual things under a similitude, and they misunderstand him of carnal things. The occasion of it was, their forgetting to victual their ship, and to take along with them provisions for their family on the other side of the water; usually they carried bread along with them, because they were sometimes in desert places; and when they were not, yet they would not b...', 'teologico');
add('mt', 16, 13, 'Matthew Henry', 'We have here a private conference which Christ had with his disciples concerning himself. It was in the coasts of Cesarea Philippi, the utmost borders of the land of Canaan northward; there in that remote corner, perhaps, there was less flocking after him than in other places, which gave him leisure for this private conversation with his disciples. Note, When ministers are abridged in their public work, they should endeavour to do the more in their own families.\nChrist is here catechising his...', 'teologico');
add('mt', 16, 21, 'Matthew Henry', 'We have here Christ\'s discourse with his disciples concerning his own sufferings; in which observe,\nI. Christ\'s foretelling of his sufferings. Now he began to do it, and from this time he frequently spake of them. Some hints he had already given of his sufferings, as when he said, Destroy this temple: when he spake of the Son of man being lifted up, and of eating his flesh, and drinking his blood: but now he began to show it, to speak plainly and expressly of it. Hitherto he had not touched u...', 'teologico');
add('mt', 16, 24, 'Matthew Henry', 'Christ, having shown his disciples that he must suffer, and that he was ready and willing to suffer, here shows them that they must suffer too, and must be ready and willing. It is a weighty discourse that we have in these verses.\nI. Here is the law of discipleship laid down, and the terms fixed, upon which we may have the honour and benefit of it, Mat 16:24. He said this to his disciples, not only that they might instruct others concerning it, but that by this rule they might examine their o...', 'teologico');
add('mt', 17, 1, 'Matthew Henry', 'We have here the story of Christ\'s transfiguration; he had said that the Son of man should shortly come in his kingdom, with which promise all the three evangelists industriously connect this story; as if Christ\'s transfiguration were intended for a specimen and an earnest of the kingdom of Christ, and of that light and love of his, which therein appears to his select and sanctified ones. Peter speaks of this as the power and coming of our Lord Jesus (Pe2 1:16); because it was an emanation of...', 'teologico');
add('mt', 17, 14, 'Matthew Henry', 'We have here the miraculous cure of a child that was lunatic and vexed with a devil. Observe,\nI. A melancholy representation of the case of this child, made to Christ by the afflicted father. This was immediately upon his coming down from the mountain where he was transfigured. Note, Christ\'s glories do not make him unmindful of us and of our wants and miseries. Christ, when he came down from the mount, where had conversation with Moses and Elias, did not take state upon him, but was as easy ...', 'teologico');
add('mt', 17, 22, 'Matthew Henry', 'Christ here foretels his own sufferings; he began to do it before (Mat 16:21); and, finding that it was to his disciples a hard saying, he saw it necessary to repeat it. There are some things which God speaketh once, yea twice, and yet man perceiveth it not. Observe here,\n1. What he foretold concerning himself - that he should be betrayed and killed. He perfectly knew, before, all things that should come to him, and yet undertook the work of our redemption, which greatly commends his love; na...', 'teologico');
add('mt', 17, 24, 'Matthew Henry', 'We have here an account of Christ\'s paying tribute.\nI. Observe how it was demanded, Mat 17:24. Christ was now at Capernaum, his headquarters, where he mostly resided; he did not keep from thence, to decline being called upon for his dues, but rather came thither, to be ready to pay them.\n1. The tribute demanded was not any civil payment to the Roman powers, that was strictly exacted by the publicans, but the church-duties, the half shekel, about fifteen pence, which were required from every p...', 'teologico');
add('mt', 18, 1, 'Matthew Henry', 'As there never was a greater pattern of humility, so there never was a greater preacher of it, than Christ; he took all occasions to command it, to commend it, to his disciples and followers.\nI. The occasion of this discourse concerning humility was an unbecoming contest among the disciples for precedency; they came to him, saying, among themselves (for they were ashamed to ask him, Mar 9:34), Who is the greatest in the kingdom of heaven? They mean not, who by character (then the question had...', 'teologico');

// MC (11 comentários)
add('mc', 5, 2, 'N.T. Wright', 'De ti sairá — A origem messiânica é eterna: «Dele» vem de antes dos tempos.', 'escatologico');
add('mc', 1, 1, 'N.T. Wright', 'Princípio do evangelho de Jesus Cristo — Marcos começa com urgência: Cristo é Filho de Deus e Messias.', 'historico');
add('mc', 1, 15, 'Calvino', 'Arrependei-vos — O arrependimento e a fé são as duas respostas necessárias ao evangelho.', 'teologico');
add('mc', 8, 36, 'Lloyd-Jones', 'De que lhe aproveita? — A questão eterna supera qualquer ganho temporal.', 'aplicacao');
add('mc', 10, 43, 'Tim Keller', 'Quem quiser ser o maior — A liderança cristã é serviço, não domínio. O modelo é Cristo servo.', 'aplicacao');
add('mc', 10, 45, 'Tomás de Aquino', 'Dar a sua vida em resgate — O preço do resgate é a vida do Filho de Deus: o maior valor possível.', 'teologico');
add('mc', 12, 30, 'João Crisóstomo', 'Amarás o Senhor — O mandamento central: amor integral a Deus com toda a pessoa.', 'teologico');
add('mc', 12, 31, 'Albert Barnes', 'Amarás o teu próximo — O amor ao próximo é como o amor a si mesmo: a medida natural.', 'aplicacao');
add('mc', 14, 22, 'Calvino', 'Isto é o meu corpo — A Ceia do Senhor: memorial da morte de Cristo e participação em Sua graça.', 'teologico');
add('mc', 15, 33, 'Adam Clarke', 'Toda a terra se escureceu — A escuridão cósmica na crucificação: sinal da ira divina sobre o pecado.', 'cultural');
add('mc', 16, 6, 'N.T. Wright', 'Ele não está aqui — A ressurreição não é mito: o túmulo vazio é o fato central da história.', 'historico');

// LC (22 comentários)
add('lc', 1, 37, 'Wesley', 'Nenhuma palavra de Deus será sem efeito — A onipotência de Deus garante o cumprimento de Suas promessas.', 'teologico');
add('lc', 1, 46, 'João Crisóstomo', 'A minha alma magnifica o Senhor — O hino de Maria: modelo de humildade e louvor.', 'aplicacao');
add('lc', 1, 49, 'Calvino', 'Fez coisas grandes — A obra de Deus em Maria é fruto de Sua graça, não mérito dela.', 'teologico');
add('lc', 2, 10, 'Spurgeon', 'Boas novas de grande alegria — O evangelho é a notícia mais alegre da história: Cristo nasceu.', 'aplicacao');
add('lc', 2, 11, 'Calvino', 'Hoje, na cidade de Davi — A localização cumprida: Belém, a cidade de Davi, vê o nascimento do Messias.', 'historico');
add('lc', 2, 14, 'Adam Clarke', 'Glória a Deus nas alturas — O hino dos anjos: a encarnação traz paz aos homens de boa vontade.', 'teologico');
add('lc', 2, 35, 'Charles Ellicott', 'Uma espada traspassará a tua alma — A profecia sobre Maria: o sofrimento da mãe na missão do Filho.', 'escatologico');
add('lc', 10, 30, 'Tim Keller', 'Um homem descia — A parábola do Bom Samaritano: o amor vizinho não conhece fronteiras raciais.', 'aplicacao');
add('lc', 10, 33, 'Albert Barnes', 'O samaritano teve compaixão — O samaritano, desprezado pelos judeus, é o herói: inversão radical.', 'cultural');
add('lc', 10, 37, 'Spurgeon', 'Foi aquele que usou de misericórdia — A verdadeira religião é prática de amor, não teoria.', 'aplicacao');
add('lc', 15, 4, 'Wesley', 'Não deixa as noventa e nove — O valor de cada alma: Deus busca o perdido pessoalmente.', 'aplicacao');
add('lc', 15, 7, 'Calvino', 'Mais alegria no céu — A conversa de um pecador é a maior celebração no mundo espiritual.', 'teologico');
add('lc', 15, 13, 'N.T. Wright', 'Reuniu tudo — O filho pródigo desperdiça a herança: a busca de autonomia longe de Deus.', 'aplicacao');
add('lc', 15, 20, 'Lloyd-Jones', 'O pai o viu de longe — A graça precede o arrependimento: o pai corre antes do filho confessar.', 'teologico');
add('lc', 15, 22, 'John Stott', 'Trazei a melhor roupa — A restauração completa: o filho pródigo é recebido como filho, não servo.', 'teologico');
add('lc', 19, 10, 'John Piper', 'Procurar e salvar o que se havia perdido — A missão de Cristo: o propósito central de Sua vinda.', 'teologico');
add('lc', 22, 19, 'Tomás de Aquino', 'Fazei isto em memória — A Eucaristia é memorial sacrificial: presença real de Cristo.', 'teologico');
add('lc', 23, 34, 'Spurgeon', 'Não sabem o que fazem — A ignorância atenua a culpa: os crucificadores agem sem conhecimento pleno.', 'teologico');
add('lc', 23, 43, 'Wesley', 'Hoje estarás comigo — A salvação é instantânea: hoje mesmo, não depois de obras.', 'teologico');
add('lc', 24, 27, 'Charles Ellicott', 'Explicou-lhes — Cristo ensina as Escrituras: o AT inteiro aponta para Ele.', 'historico');
add('lc', 24, 32, 'Adam Clarke', 'Ardia-nos o coração — A presença de Cristo ilumina as Escrituras e aquece o coração.', 'aplicacao');
add('lc', 24, 46, 'N.T. Wright', 'Era necessário — A morte e ressurreição de Cristo são o centro da história: tudo aponta para isso.', 'teologico');

// JO (42 comentários)
add('jo', 1, 1, 'Tomás de Aquino', 'No princípio era o Verbo — O Logos é consubstancial ao Pai: da mesma essência, distinto na pessoa.', 'teologico');
add('jo', 1, 12, 'R.C. Sproul', 'Deu-lhes poder — A fé não é passiva: Deus dá poder ativo para a adoção filial.', 'teologico');
add('jo', 1, 14, 'Atanásio', 'O Verbo se fez carne — A encarnação: o eterno Logos assumiu a humanidade sem perder a divindade.', 'teologico');
add('jo', 3, 3, 'Lutero', 'Nascer de novo — A nova nascimento é indispensável: velho homem deve morrer para que o novo viva.', 'teologico');
add('jo', 3, 16, 'Calvino', 'De tal maneira amou o mundo — O cerne do evangelho: o dom do Filho unigênito para a vida eterna dos crentes.', 'teologico');
add('jo', 4, 13, 'Tim Keller', 'Água viva — A água que satisfaz: Cristo preenche o vazio que as coisas do mundo não preenchem.', 'aplicacao');
add('jo', 4, 14, 'John Stott', 'Nunca mais terá sede — O dom da vida eterna é satisfatório e permanente.', 'teologico');
add('jo', 6, 35, 'Agostinho', 'Eu sou o pão da vida — A Eucaristia nutre a alma: Cristo é o alimento verdadeiro.', 'teologico');
add('jo', 6, 68, 'R.C. Sproul', 'Senhor, para quem iríamos? — Pedro reconhece que só Cristo tem palavras de vida eterna.', 'teologico');
add('jo', 7, 37, 'Charles Ellicott', 'Se alguém tem sede — O convite universal: todos podem vir a Cristo.', 'aplicacao');
add('jo', 7, 38, 'Albert Barnes', 'Rios de água viva — O Espírito Santo flui do crente como rios vivificadores.', 'teologico');
add('jo', 8, 12, 'N.T. Wright', 'Eu sou a luz do mundo — Cristo é o cumprimento da festa dos tabernáculos: a coluna de fogo.', 'cultural');
add('jo', 8, 32, 'Spurgeon', 'A verdade vos libertará — A verdade cristã não é filosófica, mas salvadora: liberdade da culpa.', 'aplicacao');
add('jo', 8, 58, 'Calvino', 'Antes que Abraão existisse — A preexistência eterna de Cristo: Ele não é criado.', 'teologico');
add('jo', 10, 10, 'John Piper', 'Vim para que tenham vida — A vida abundante é o dom máximo: mais que perdão, é plenitude.', 'teologico');
add('jo', 10, 11, 'João Crisóstomo', 'O bom pastor — O contraste entre o mercenário e o pastor: o pastor verdadeiro ama até a morte.', 'teologico');
add('jo', 10, 28, 'Lloyd-Jones', 'Ninguém vos arrebatará — A segurança eterna: as ovelhas de Cristo estão guardadas para sempre.', 'teologico');
add('jo', 10, 29, 'R.C. Sproul', 'Ninguém pode arrebatá-las — A soberania do Pai garante a perseverança dos santos.', 'teologico');
add('jo', 11, 25, 'Lutero', 'Eu sou a ressurreição e a vida — A promessa de vida eterna fundamentada na pessoa de Cristo, não na lei.', 'escatologico');
add('jo', 11, 26, 'Calvino', 'Quem vive e crê em mim — A fé em Cristo é a chave da vida eterna.', 'teologico');
add('jo', 12, 24, 'N.T. Wright', 'Se o grão de trigo — A morte fecunda: a morte de Cristo produz frutos abundantes.', 'teologico');
add('jo', 13, 34, 'John Stott', 'Amai-vos uns aos outros — O mandamento novo não é quantitativo, mas qualitativo: amor sacrificial.', 'teologico');
add('jo', 13, 35, 'Tim Keller', 'Nisto reconhecerão — O amor cristão é o testemunho mais poderoso ao mundo.', 'aplicacao');
add('jo', 14, 1, 'Lutero', 'Não se perturbe o vosso coração — A promessa de conforto: Deus prepara lugar para os Seus.', 'aplicacao');
add('jo', 14, 2, 'Matthew Henry', 'Muitas moradas — A casa do Pai é ampla: há lugar para todos os crentes.', 'teologico');
add('jo', 14, 3, 'Spurgeon', 'Vou preparar-vos lugar — A garantia: Cristo voltará para levar os Seus.', 'escatologico');
add('jo', 14, 6, 'Tomás de Aquino', 'Eu sou o caminho, a verdade e a vida — A exclusividade de Cristo como mediador da salvação.', 'teologico');
add('jo', 14, 15, 'Albert Barnes', 'Se me amais, guardareis meus mandamentos — O amor a Cristo se prova pela obediência.', 'aplicacao');
add('jo', 14, 27, 'Adam Clarke', 'Não vos dou como o mundo dá — A paz de Cristo é real, não superficial: transforma o coração.', 'aplicacao');
add('jo', 15, 1, 'Agostinho', 'Eu sou a videira verdadeira — Cristo é a fonte: sem Ele, nada podemos produzir.', 'teologico');
add('jo', 15, 5, 'Tim Keller', 'Sem mim nada podeis fazer — A humildade radical: reconhecer que a vida espiritual depende de Cristo.', 'aplicacao');
add('jo', 15, 8, 'Lloyd-Jones', 'Nisto é glorificado meu Pai — O fruto espiritual glorifica a Deus: é o propósito final da vida cristã.', 'teologico');
add('jo', 15, 13, 'John Piper', 'Dar a vida — O amor cristão é sempre sacrificial: o evangelho é amor dado, não esperado.', 'aplicacao');
add('jo', 17, 3, 'N.T. Wright', 'Que te conheçam — A vida eterna começa agora: conhecimento de Deus que transforma.', 'teologico');
add('jo', 17, 17, 'Lutero', 'Santifica-os na verdade — A Palavra de Deus é instrumento de santificação: separa para Deus.', 'teologico');
add('jo', 17, 20, 'Charles Ellicott', 'Não rogo só por estes — A oração de Jesus se estende a todos os crentes de todos os tempos.', 'teologico');
add('jo', 19, 30, 'Calvino', 'Consumou-se — O verbo grego «tetelestai» significa «pago integralmente». A dívida do pecado foi quitada.', 'gramatical');
add('jo', 19, 34, 'Tomás de Aquino', 'Saiu sangue e água — O sangue e a água simbolizam a Eucaristia e o Batismo: frutos da paixão.', 'teologico');
add('jo', 20, 28, 'Atanásio', 'Meu Senhor e meu Deus! — A confissão de Tomé: Cristo é Deus, não apenas senhor humano.', 'teologico');
add('jo', 20, 31, 'Spurgeon', 'Para que creiais — O evangelho foi escrito para produzir fé: não é livro de curiosidade.', 'aplicacao');
add('jo', 21, 15, 'Agostinho', 'Amas-me mais do que estes? — A restauração de Pedro: três negações, três afirmações.', 'historico');
add('jo', 21, 17, 'Albert Barnes', 'Senhor, tu sabes todas as coisas — A humildade de Pedro: não ousa dizer que ama perfeitamente.', 'aplicacao');

// AT (17 comentários)
add('at', 1, 8, 'N.T. Wright', 'Recebereis poder — A missão cristã é habilitada pelo Espírito, não pela estratégia humana.', 'teologico');
add('at', 2, 1, 'Calvino', 'Pentecostes — O derramamento do Espírito Santo: cumprimento da promessa de Jesus.', 'teologico');
add('at', 2, 4, 'Wesley', 'Cheios do Espírito — A plenitude do Espírito para testemunho e poder.', 'teologico');
add('at', 2, 2, 'João Crisóstomo', 'Um vendaval — O Espírito desce com poder avassalador: transforma os medrosos em corajosos.', 'cultural');
add('at', 2, 38, 'Tomás de Aquino', 'Batizai-vos — O batismo confere a graça da remissão: sacramento de iniciação.', 'teologico');
add('at', 3, 19, 'John Stott', 'Arrependei-vos e convertei — O arrependimento é a porta: mudar de direção, voltar-se para Deus.', 'aplicacao');
add('at', 4, 12, 'Lloyd-Jones', 'Não há salvação — A afirmação mais exclusiva da Escritura: apenas Cristo salva.', 'teologico');
add('at', 4, 31, 'R.C. Sproul', 'Encheram-se todos do Espírito — O Espírito capacita para testemunhar com ousadia.', 'teologico');
add('at', 5, 31, 'Charles Ellicott', 'Deus o exaltou — A exaltação de Cristo: Rei e Salvador para dar arrependimento e perdão.', 'escatologico');
add('at', 7, 55, 'N.T. Wright', 'Viu a glória de Deus — Estêvão vê Cristo à destra de Deus: a exaltação é real e presente.', 'escatologico');
add('at', 9, 31, 'Adam Clarke', 'A igreja tinha paz — O período de crescimento: a perseguição momentânea produz frutos.', 'historico');
add('at', 13, 38, 'John Piper', 'Por meio dele se anuncia — O perdão de pecados é por Cristo: pela Lei de Moisés ninguém é justificado.', 'teologico');
add('at', 16, 30, 'Spurgeon', 'Que devo fazer para ser salvo? — A pergunta mais importante da história: a resposta é fé.', 'aplicacao');
add('at', 16, 31, 'Calvino', 'Crê no Senhor Jesus — A salvação pela fé: o caminho simples para o perdão.', 'teologico');
add('at', 17, 11, 'Albert Barnes', 'Examinavam as Escrituras — A nobreza de Bereia: buscar a verdade na Palavra.', 'aplicacao');
add('at', 17, 28, 'Tomás de Aquino', 'Nele vivemos, nos movemos — Deus é o sustentador de tudo: sem Ele, nada subsiste.', 'teologico');
add('at', 20, 28, 'Agostinho', 'A igreja de Deus — A igreja foi adquirida com o sangue do próprio Deus.', 'teologico');

// RM (69 comentários)
add('rm', 1, 16, 'Calvino', 'Não me envergonho do evangelho — O poder de Deus para salvação de todo aquele que crê, judeu e grego.', 'teologico');
add('rm', 1, 17, 'N.T. Wright', 'O justo viverá pela fé — A justiça de Deus é o fiel cumprimento da aliança.', 'teologico');
add('rm', 3, 10, 'Agostinho', 'Não há justo, nem um — A corrupção total: ninguém busca a Deus por iniciativa própria.', 'teologico');
add('rm', 3, 12, 'Tomás de Aquino', 'Não há quem faça o bem — A queda afeta toda a pessoa: razão, vontade e ação.', 'teologico');
add('rm', 3, 23, 'Lutero', 'Todos pecaram — A universalidade da culpa humana diante da glória de Deus.', 'teologico');
add('rm', 3, 24, 'João Crisóstomo', 'Justificados gratuitamente — A justificação é dom: sem mérito, pela graça de Deus em Cristo.', 'teologico');
add('rm', 3, 25, 'R.C. Sproul', 'Propiciação — O sacrifício de Cristo satisfaz a justiça de Deus: o preço do pecado é pago.', 'teologico');
add('rm', 5, 1, 'Tim Keller', 'Justificados pela fé — A paz com Deus é a base: sem ela, tudo mais desmorona.', 'aplicacao');
add('rm', 5, 8, 'João Crisóstomo', 'Deus prova o seu amor — Cristo morreu por nós sendo ainda pecadores: a graça preexistente ao mérito.', 'teologico');
add('rm', 6, 1, 'Lutero', 'Continuaremos no pecado — A graça não é licença para pecar: o crente morreu para o pecado.', 'teologico');
add('rm', 6, 23, 'Calvino', 'O dom de Deus é a vida eterna — A graça gratuita: não é salário, mas dom.', 'teologico');
add('rm', 7, 19, 'João Crisóstomo', 'Não faço o bem que quero — A luta interior do crente: o conflito entre a carne e o espírito.', 'aplicacao');
add('rm', 7, 25, 'Lloyd-Jones', 'Jesus Cristo, nosso Senhor — A vitória sobre a carne: somente em Cristo.', 'teologico');
add('rm', 8, 1, 'Calvino', 'Nenhuma condenação — A justificação traz liberdade: quem está em Cristo não é condenado.', 'teologico');
add('rm', 8, 18, 'N.T. Wright', 'As aflições do tempo presente — A criação inteira anseia pela redenção: o sofrimento é temporário.', 'escatologico');
add('rm', 8, 22, 'Adam Clarke', 'Toda a criação geme — A criação participa da maldição da queda: aguarda libertação.', 'teologico');
add('rm', 8, 28, 'Matthew Henry', 'Todas as coisas cooperam para o bem — A providência soberana de Deus sobre a vida dos que O amam.', 'aplicacao');
add('rm', 8, 29, 'Calvino', 'Predestinados para serem conformes — O plano eterno de Deus: conformidade com Cristo.', 'teologico');
add('rm', 8, 30, 'Spurgeon', 'Justificou, glorificou — A cadeia da salvação: chamar, justificar, glorificar. Ninguém se perde.', 'teologico');
add('rm', 8, 31, 'Tomás de Aquino', 'Se Deus é por nós, quem será contra nós? — A invencibilidade do crente: Deus é o maior aliado.', 'teologico');
add('rm', 8, 38, 'John Piper', 'Nem anjos, nem potestades — Nada pode separar do amor de Deus: a segurança é absoluta.', 'teologico');
add('rm', 8, 39, 'Charles Ellicott', 'Nem altura, nem profundidade — O amor de Cristo é inconquistável: nada pode rompê-lo.', 'teologico');
add('rm', 9, 14, 'Calvino', 'Há injustiça em Deus? — A soberania de Deus na eleição: misericórdia, não mérito, determina.', 'teologico');
add('rm', 9, 16, 'R.C. Sproul', 'Depende do que quer — A soberania divina não anula a responsabilidade humana.', 'teologico');
add('rm', 10, 9, 'Wesley', 'Se confessares com a boca — A salvação pela fé confessada: coração crente e boca confessante.', 'aplicacao');
add('rm', 10, 13, 'Spurgeon', 'Todo aquele que invocar o nome — A universalidade da salvação: todos que chamam são salvos.', 'teologico');
add('rm', 11, 33, 'Agostinho', 'Ó profundidade da riqueza — O mistério da soberania de Deus: inescrutável nos seus juízos.', 'teologico');
add('rm', 12, 1, 'Wesley', 'Apresentai os vossos corpos — O culto racional: a vida inteira é oferenda a Deus.', 'aplicacao');
add('rm', 12, 2, 'Spurgeon', 'Não vos conformeis com este século — A transformação pela renovação da mente como marca do discípulo.', 'aplicacao');
add('rm', 1, 1, 'Matthew Henry', 'In this paragraph we have,\nI. The person who writes the epistle described (Rom 1:1): Paul, a servant of Jesus Christ; this is his title of honour, which he glories in, not as the Jewish teachers, Rabbi, Rabbi; but a servant, a more immediate attendant, a steward in the house. Called to be an apostle. Some think he alludes to his old name Saul, which signifies one called for, or enquired after: Christ sought him to make an apostle of him, Act 9:15. He here builds his authority upon his call; h...', 'teologico');
add('rm', 1, 8, 'Matthew Henry', 'We may here observe,\nI. His thanksgivings for them (Rom 1:8): First, I thank my God. It is good to begin every thing with blessing God, to make that the alpha and omega of every song, in every thing to give thanks. - My God. He speaks this with delight and triumph. In all our thanksgivings, it is good for us to eye God as our God; this makes every mercy sweet, when we can say of God, "He is mine in covenant." - Through Jesus Christ. All our duties and performances are pleasing to God only thr...', 'teologico');
add('rm', 1, 19, 'Matthew Henry', 'In this last part of the chapter the apostle applies what he had said particularly to the Gentile world, in which we may observe,\nI. The means and helps they had to come to the knowledge of God. Though they had not such a knowledge of his law as Jacob and Israel had (Psa 147:20), yet among them he left not himself without witness (Act 14:17): For that which may be known, etc., Rom 1:19, Rom 1:20. Observe,\n1. What discoveries they had: That which may be known of God is manifest, en autois - am...', 'teologico');
add('rm', 2, 1, 'Matthew Henry', 'In the former chapter the apostle had represented the state of the Gentile world to be as bad and black as the Jews were ready enough to pronounce it. And now, designing to show that the state of the Jews was very bad too, and their sin in many respects more aggravated, to prepare his way he sets himself in this part of the chapter to show that God would proceed upon equal terms of justice with Jews and Gentiles; and now with such a partial hand as the Jews were apt to think he would use in t...', 'teologico');
add('rm', 2, 17, 'Matthew Henry', 'In the latter part of the chapter the apostle directs his discourse more closely to the Jews, and shows what sins they were guilty of, notwithstanding their profession and vain pretensions. He had said (Rom 2:13) that not the hearers but the doers of the law are justified; and he here applies that great truth to the Jews. Observe,\nI. He allows their profession (Rom 2:17-20) and specifies their particular pretensions and privileges in which they prided themselves, that they might see he did no...', 'teologico');
add('rm', 3, 1, 'Matthew Henry', 'I. Here the apostle answers several objections, which might be made, to clear his way. No truth so plain and evident but wicked wits and corrupt carnal hearts will have something to say against it; but divine truths must be cleared from cavil.\nObject. 1. If Jew and Gentile stand so much upon the same level before God, what advantage then hath the Jew? Hath not God often spoken with a great deal of respect for the Jews, as a non-such people (Deu 33:29), a holy nation, a peculiar treasure, the ...', 'teologico');
add('rm', 3, 19, 'Matthew Henry', 'From all this Paul infers that it is in vain to look for justification by the works of the law, and that it is to be had only by faith, which is the point he has been all along proving, from Rom 1:17, and which he lays down (Rom 3:28) as the summary of his discourse, with a quod erat demonstrandum - which was to be demonstrated. We conclude that a man is justified by faith, without the deeds of the law; not by the deeds of the first law of pure innocence, which left no room for repentance, no...', 'teologico');
add('rm', 4, 1, 'Matthew Henry', 'Here the apostle proves that Abraham was justified not by works, but by faith. Those that of all men contended most vigorously for a share in righteousness by the privileges they enjoyed, and the works they performed, were the Jews, and therefore he appeals to the case of Abraham their father, and puts his own name to the relation, being a Hebrew of the Hebrews: Abraham our father. Now surely his prerogative must needs be as great as theirs who claim it as his seed according to the flesh. Now...', 'teologico');
add('rm', 4, 9, 'Matthew Henry', 'St. Paul observes in this paragraph when and why Abraham was thus justified; for he has several things to remark upon that. It was before he was circumcised, and before the giving of the law; and there was a reason for both.\nI. It was before he was circumcised, Rom 4:10. His faith was counted to him for righteousness while he was in uncircumcision. It was imputed, Gen 15:6, and he was not circumcised till ch. 17. Abraham is expressly said to be justified by faith fourteen years, some say twen...', 'teologico');
add('rm', 4, 17, 'Matthew Henry', 'Having observed when Abraham was justified by faith, and why, for the honour of Abraham and for example to us who call him father, the apostle here describes and commends the faith of Abraham, where observe,\nI. Whom he believed: God who quickeneth. It is God himself that faith fastens upon: other foundation can no man lay. Now observe what in God Abraham\'s faith had an eye t - o that, certainly, which would be most likely to confirm his faith concerning the things promised: - 1. God who quick...', 'teologico');
add('rm', 4, 23, 'Matthew Henry', 'In the close of the chapter, he applies all to us; and, having abundantly proved that Abraham was justified by faith, he here concludes that his justification was to be the pattern or sampler of ours: It was not written for his sake alone. It was not intended only for an historical commendation of Abraham, or a relation of something peculiar to him (as some antipaedobaptists will needs understand that circumcision was a seal of the righteousness of the faith, Rom 4:11, only to Abraham himself...', 'teologico');
add('rm', 5, 6, 'Matthew Henry', 'The apostle here describes the fountain and foundation of justification, laid in the death of the Lord Jesus. The streams are very sweet, but, if you run them up to the spring-head, you will find it to be Christ\'s dying for us; it is in the precious stream of Christ\'s blood that all these privileges come flowing to us: and therefore he enlarges upon this instance of the love of God which is shed abroad. Three things he takes notice of for the explication and illustration of this doctrine: - 1...', 'teologico');
add('rm', 7, 1, 'Matthew Henry', 'Among other arguments used in the foregoing chapter to persuade us against sin, and to holiness, this was one (Rom 7:14), that we are not under the law; and this argument is here further insisted upon and explained (Rom 7:6): We are delivered from the law. What is meant by this? And how is it an argument why sin should not reign over us, and why we should walk in newness of life? 1. We are delivered from the power of the law which curses and condemns us for the sin committed by us. The senten...', 'teologico');
add('rm', 7, 7, 'Matthew Henry', 'To what he had said in the former paragraph, the apostle here raises an objection, which he answers very fully: What shall we say then? Is the law sin? When he had been speaking of the dominion of sin, he had said so much of the influence of the law as a covenant upon that dominion that it might easily be misinterpreted as a reflection upon the law, to prevent which he shows from his own experience the great excellency and usefulness of the law, not as a covenant, but as a guide; and further ...', 'teologico');
add('rm', 7, 14, 'Matthew Henry', 'Here is a description of the conflict between grace and corruption in the heart, between the law of God and the law of sin. And it is applicable two ways: - 1. To the struggles that are in a convinced soul, but yet unregenerate, in the person of whom it is supposed, by some, that Paul speaks. 2. To the struggles that are in a renewed sanctified soul, but yet in a state of imperfection; as other apprehend. And a great controversy there is of which of these we are to understand the apostle here...', 'teologico');
add('rm', 8, 10, 'Matthew Henry', 'In these verses the apostle represents two more excellent benefits, which belong to true believers.\nI. Life. The happiness is not barely a negative happiness, not to be condemned; but it is positive, it is an advancement to a life that will be the unspeakable happiness of the man (Rom 8:10, Rom 8:11): If Christ be in you. Observe, If the Spirit be in us, Christ is in us. He dwells in the heart by faith, Eph 3:17. Now we are here told what becomes of the bodies and souls of those in whom Chris...', 'teologico');
add('rm', 8, 17, 'Matthew Henry', 'In these words the apostle describes a fourth illustrious branch of the happiness of believers, namely, a title to the future glory. This is fitly annexed to our sonship; for as the adoption of sons entitles us to that glory, so the disposition of sons fits and prepares us for it. If children, then heirs, Rom 8:17. In earthly inheritances this rule does not hold, only the first-born are heirs; but the church is a church of first-born, for they are all heirs. Heaven is an inheritance that all ...', 'teologico');
add('rm', 8, 26, 'Matthew Henry', 'The apostle here suggests two privileges more to which true Christians are entitled: - \nI. The help of the Spirit in prayer. While we are in this world, hoping and waiting for what we see not, we must be praying. Hope supposes desire, and that desire offered up to God is prayer; we groan. Now observe,\n1. Our weakness in prayer: We know not what we should pray for as we ought. (1.) As to the matter of our requests, we know not what to ask. We are not competent judges of our own condition. Who ...', 'teologico');
add('rm', 9, 6, 'Matthew Henry', 'The apostle, having made his way to that which he had to say, concerning the rejection of the body of his countrymen, with a protestation of his own affection for them and a concession of their undoubted privileges, comes in these verses, and the following part of the chapter, to prove that the rejection of the Jews, by the establishment of the gospel dispensation, did not at all invalidate the word of God\'s promise to the patriarchs: Not as though the word of God hath taken no effect (Rom 9:...', 'teologico');
add('rm', 9, 25, 'Matthew Henry', 'Having explained the promise, and proved the divine sovereignty, the apostle here shows how the rejection of the Jews, and the taking in of the Gentiles, were foretold in the Old Testament, and therefore must needs be very well consistent with the promise made to the fathers under the Old Testament. It tends very much to the clearing of a truth to observe how the scripture is fulfilled in it. The Jews would, no doubt, willingly refer it to the Old Testament, the scriptures of which were commi...', 'teologico');
add('rm', 9, 30, 'Matthew Henry', 'The apostle comes here at last to fix the true reason of the reception of the Gentiles, and the rejection of the Jews. There was a difference in the way of their seeking, and therefore there was that different success, though still it was the free grace of God that made them differ. He concludes like an orator, What shall we say then? What is the conclusion of the whole dispute?\nI. Concerning the Gentiles observe, 1. How they had been alienated from righteousness: the followed not after it; t...', 'teologico');
add('rm', 10, 1, 'Matthew Henry', 'The scope of the apostle in this part of the chapter is to show the vast difference between the righteousness of the law and the righteousness of faith, and the great pre-eminence of the righteousness of faith above that of the law; that he might induce and persuade the Jews to believe in Christ, aggravate the folly and sin of those that refused, and justify God in the rejection of such refusers.\nI. Paul here professes his good affection to the Jews, with the reason of it (Rom 10:1, Rom 10:2)...', 'teologico');
add('rm', 10, 12, 'Matthew Henry', 'The first words express the design of the apostle through these verses, that there is no difference between Jews and Gentiles, but they stand upon the same level in point of acceptance with God. In Jesus Christ there is neither Greek nor Jews, Col 3:11. God doth not save any nor reject any because they are Jews, nor because they are Greeks, but doth equally accept both upon gospel terms: There is no difference. For the proof of this he urges two arguments: - \nI. That God is the same to all: T...', 'teologico');
add('rm', 11, 1, 'Matthew Henry', 'The apostle proposes here a plausible objection, which might be urged against the divine conduct in casting off the Jewish nation (Rom 11:1): "Hath God cast away his people? Is the rejection total and final? Are they all abandoned to wrath and ruin, and that eternal? Is the extent of the sentence so large as to be without reserve, or the continuance of it so long as to be without repeal? Will he have no more a peculiar people to himself?" In opposition to this, he shows that there was a great...', 'teologico');
add('rm', 13, 1, 'Matthew Henry', 'We are here taught how to conduct ourselves towards magistrates, and those that are in authority over us, called here the higher powers, intimating their authority (they are powers), and their dignity (they are higher powers), including not only the king as supreme, but all inferior magistrates under him: and yet it is expressed, not by the persons that are in that power, but the place of power itself, in which they are. However the persons themselves may be wicked, and of those vile persons ...', 'teologico');
add('rm', 13, 7, 'Matthew Henry', 'We are here taught a lesson of justice and charity.\nI. Of justice (Rom 13:7): Render therefore to all their dues, especially to magistrates, for this refers to what goes before; and likewise to all with whom we have to do. To be just is to give to all their due, to give every body his own. What we have we have as stewards; others have an interest in it, and must have their dues. "Render to God his due in the first place, to yourselves, to you families, your relations, to the commonwealth, to ...', 'teologico');
add('rm', 13, 11, 'Matthew Henry', 'We are here taught a lesson of sobriety and godliness in ourselves. Our main care must be to look to ourselves. Four things we are here taught, as a Christian\'s directory for his day\'s work: when to awake, how to dress ourselves, how to walk, and what provision to make.\nI. When to awake: Now it is high time to awake (Rom 13:11), to awake out of the sleep of sin (for a sinful condition is a sleeping condition), out of the sleep of carnal security, sloth and negligence, out of the sleep of spir...', 'teologico');
add('rm', 14, 1, 'Matthew Henry', 'We have in this chapter,\nI. An account of the unhappy contention which had broken out in the Christian church. Our Master had foretold that offences would come; and, it seems, so they did, for want of that wisdom and love which would have prevented discord, and kept up union among them.\n1. There was a difference among them about the distinction of meats and days; these are the two things specified. There might be other similar occasions of difference, while these made the most noise, and were...', 'teologico');
add('rm', 15, 1, 'Matthew Henry', 'The apostle here lays down two precepts, with reasons to enforce them, showing the duty of the strong Christian to consider and condescend to the weakest.\nI. We must bear the infirmities of the weak, Rom 15:1. We all have our infirmities; but the weak are more subject to them than others - the weak in knowledge or grace, the bruised reed and the smoking flax. We must consider these; not trample upon them, but encourage them, and bear with their infirmities. If through weakness they judge and ...', 'teologico');
add('rm', 15, 5, 'Matthew Henry', 'The apostle, having delivered two exhortations, before he proceeds to more, intermixes here a prayer for the success of what he had said. Faithful ministers water their preaching with their prayers, because, whoever sows the seed, it is God that gives the increase. We can but speak to the ear; it is God\'s prerogative to speak to the heart. Observe,\nI. The title he gives to God: The God of patience and consolation, who is both the author and the foundation of all the patience and consolation o...', 'teologico');
add('rm', 15, 7, 'Matthew Henry', 'The apostle here returns to his exhortation to Christians. What he says here (Rom 15:7) is to the same purport with the former; but the repetition shows how much the apostle\'s heart was upon it. "Receive one another into your affection, into your communion, and into your common conversation, as there is occasion." He had exhorted the strong to receive the weak (Rom 14:1), here, Receive one another; for sometimes the prejudices of the weak Christian make him shy of the strong, as much as the p...', 'teologico');
add('rm', 15, 13, 'Matthew Henry', 'Here is another prayer directed to God, as the God of hope; and it is, as the former (Rom 15:5, Rom 15:6), for spiritual blessings: these are the blest blessings, and to be first and chiefly prayed for.\nI. Observe how he addresses himself to God, as the God of hope. It is good in prayer to fasten upon those names, titles, and attributes of God, which are most suitable to the errand we come upon, and will best serve to encourage our faith concerning it. Every word in the prayer should be a ple...', 'teologico');
add('rm', 15, 14, 'Matthew Henry', 'Here, I. He commends these Christians with the highest characters that could be. He began his epistle with their praises (Rom 1:8), Your faith is spoken of throughout the world, thereby to make way for his discourse: and, because sometimes he had reproved them sharply, he now concludes with the like commendation, to qualify them, and to part friends. This he does like an orator. It was not a piece of idle flattery and compliment, but a due acknowledgment of their worth, and of the grace of Go...', 'teologico');
add('rm', 15, 17, 'Matthew Henry', 'The apostle here gives some account of himself and of his own affairs. Having mentioned his ministry and apostleship, he goes on further to magnify his office in the efficacy of it, and to mention to the glory of God the great success of his ministry and the wonderful things that God had done by him, for encouragement to the Christian church at Rome, that they were not alone in the profession of Christianity, but though, compared with the multitude of their idolatrous neighbours, they were bu...', 'teologico');
add('rm', 15, 22, 'Matthew Henry', 'St. Paul here declares his purpose to come and see the Christians at Rome. Upon this head his matter is but common and ordinary, appointing a visit to his friends; but the manner of his expression is gracious and savoury, very instructive, and for our imitation. We should learn by it to speak of our common affairs in the language of Canaan. Even our common discourse should have an air of grace; by this it will appear what country we belong to. it should seem that Paul\'s company was very much ...', 'teologico');
add('rm', 15, 30, 'Matthew Henry', 'Here we have, I. St. Paul\'s desire of a share in the prayers of the Romans for him, expressed very earnestly, Rom 15:30-32. Though Paul was a great apostle, yet he begged the prayers of the meanest Christians, not here only, but in several other of the epistles. He had prayed much for them, and this he desires as the return of his kindness. Interchanging prayers is an excellent token of the interchanging of loves. Paul speaks like one that knew himself, and would hereby teach us how to value ...', 'teologico');
add('rm', 16, 1, 'Matthew Henry', 'Such remembrances as these are usual in letters between friends; and yet Paul, by the savouriness of his expressions, sanctifies these common compliments.\nI. Here is the recommendation of a friend, by whom (as some think) this epistle was sent - one Phebe, Rom 16:1, Rom 16:2. It should seem that she was a person of quality and estate, who had business which called her to Rome, where she was a stranger; and therefore Paul recommends her to the acquaintance of the Christians there: an expressio...', 'teologico');
add('rm', 16, 17, 'Matthew Henry', 'The apostle having endeavoured by his endearing salutations to unite them together, it was not improper to subjoin a caution to take heed of those whose principles and practices were destructive to Christian love. And we may observe,\nI. The caution itself, which is given in the most obliging manner that could be: I beseech you, brethren. He does not will and command, as one that lorded it over God\'s heritage, but for love\'s sake beseeches. How earnest, how endearing, are Paul\'s exhortations! ...', 'teologico');
add('rm', 16, 21, 'Matthew Henry', 'As the Apostle had before sent his own salutations to many of this church, and that of the churches round him to them all, he here adds an affectionate remembrance of them from some particular persons who were now with him, the better to promote acquaintance and fellowship among distant saints, and that the subscribing of these worthy names, known to them, might the more recommend this epistle. He mentions, 1. Some that were his particular friends, and probably known to the Roman Christians: ...', 'teologico');
add('rm', 16, 25, 'Matthew Henry', 'Here the apostle solemnly closes his epistle with a magnificent ascription of glory to the blessed God, as one that terminated all in the praise and glory of God, and studied to return all to him, seeing all is of him and from him. He does, as it were, breathe out his soul to these Romans in the praise of God, choosing to make that the end of his epistle which he made the end of his life. Observe here,\nI. A description of the gospel of God, which comes in in a parenthesis; having occasion to ...', 'teologico');

// 1CO (81 comentários)
add('1co', 1, 18, 'Tim Keller', 'A palavra da cruz — O evangelho é loucura para os sábios, mas poder de Deus para os salvos.', 'teologico');
add('1co', 1, 23, 'N.T. Wright', 'Anunciamos Cristo crucificado — O cristianismo não começa com lição moral, mas com evento histórico.', 'historico');
add('1co', 2, 14, 'Albert Barnes', 'Loucura para ele — A sabedoria de Deus é loucura para quem não tem o Espírito.', 'teologico');
add('1co', 3, 16, 'John Stott', 'Sois templo de Deus — A igreja coletiva é o templo do Espírito Santo.', 'teologico');
add('1co', 6, 19, 'Spurgeon', 'Vosso corpo é templo — O crente deve cuidar do corpo: ele pertence a Deus.', 'aplicacao');
add('1co', 6, 20, 'Tomás de Aquino', 'Glificai a Deus — O corpo é resgatado pelo sangue de Cristo: dignidade e responsabilidade.', 'teologico');
add('1co', 10, 13, 'R.C. Sproul', 'Não vos sobrevaiu — A tentação não é pecado: Deus controla a intensidade e dá escape.', 'teologico');
add('1co', 12, 4, 'Albert Barnes', 'Diversidade de dons — Os dons espirituais são variados, mas o Espírito é um.', 'teologico');
add('1co', 12, 7, 'Lloyd-Jones', 'A manifestação do Espírito — Os dons são para edificação da igreja, não para exibição pessoal.', 'aplicacao');
add('1co', 13, 4, 'Barth', 'Não é invejoso — O amor verdadeiro celebra o bem do outro sem comparação ou competição.', 'aplicacao');
add('1co', 13, 5, 'João Crisóstomo', 'Não busca o que é seu — O amor despoja-se do egoísmo: é a antítese da avareza.', 'aplicacao');
add('1co', 15, 3, 'Calvino', 'Cristo morreu pelos nossos pecados — O resumo do evangelho: morte e ressurreição de Cristo.', 'teologico');
add('1co', 15, 4, 'Spurgeon', 'Ressuscitou ao terceiro dia — A ressurreição é o fundamento: sem ela, fé vã.', 'teologico');
add('1co', 15, 14, 'N.T. Wright', 'Se Cristo não ressuscitou — A ressurreição é o fato central: sem ela, tudo desmorona.', 'teologico');
add('1co', 15, 55, 'Spurgeon', 'Ó morte, onde está o teu aguilhão? — A vitória sobre a morte: Cristo triunfou.', 'escatologico');
add('1co', 15, 57, 'Charles Ellicott', 'Deus nos dá a vitória — A vitória não é nossa, mas de Deus em Cristo.', 'teologico');
add('1co', 1, 1, 'Matthew Henry', 'We have here the apostle\'s preface to his whole epistle, in which we may take notice,\nI. Of the inscription, in which, according to the custom of writing letters then, the name of the person by whom it was written and the persons to whom it was written are both inserted. 1. It is an epistle from Paul, the apostle of the Gentiles, to the church of Corinth, which he himself had planted, though there were some among them that now questioned his apostleship (Co1 9:1, Co1 9:2), and vilified his pe...', 'teologico');
add('1co', 1, 10, 'Matthew Henry', 'Here the apostle enters on his subject.\nI. He extorts them to unity and brotherly love, and reproves them for their divisions. He had received an account from some that wished them well of some unhappy differences among them. It was neither ill-will to the church, nor to their ministers, that prompted them to give this account; but a kind and prudent concern to have these heats qualified by Paul\'s interposition. He writes to them in a very engaging way: "I beseech you, brethren, by the name o...', 'teologico');
add('1co', 1, 14, 'Matthew Henry', 'Here the apostle gives an account of his ministry among them. He thanks God he had baptized but a few among them, Crispus, who had been a ruler of a synagogue at Corinth (Act 18:8), Gaius, and the household of Stephanas, besides whom, he says, he did not remember that he had baptized any. But how was this a proper matter for thankfulness? Was it not a part of the apostolical commission to baptize all nations? And could Paul give thanks to God for his own neglect of duty? He is not to be under...', 'teologico');
add('1co', 1, 17, 'Matthew Henry', 'We have here,\nI. The manner in which Paul preached the gospel, and the cross of Christ: Not with the wisdom of words (Co1 1:17), the enticing words of man\'s wisdom (Co1 2:4), the flourish of oratory, or the accuracies of philosophical language, upon which the Greeks so much prided themselves, and which seem to have been the peculiar recommendations of some of the heads of the faction in this church that most opposed this apostle. He did not preach the gospel in this manner, lest the cross of ...', 'teologico');
add('1co', 2, 1, 'Matthew Henry', 'In this passage the apostle pursues his design, and reminds the Corinthians how he acted when he first preached the gospel among them.\nI. As to the matter or subject he tell us (Co1 2:2), He determined to know nothing among them but Jesus Christ and him crucified - to make a show of no other knowledge than this, to preach nothing, to discover the knowledge of nothing, but Jesus Christ, and him crucified. Note, Christ, in his person and offices, is the sum and substance of the gospel, and ough...', 'teologico');
add('1co', 2, 6, 'Matthew Henry', 'In this part of the chapter the apostle shows them that though he had not come to them with the excellency of human wisdom, with any of the boasted knowledge and literature of the Jews or Greeks, yet he had communicated to them a treasure of the truest and the highest wisdom: We speak wisdom among those who are perfect (Co1 2:6), among those who are well instructed in Christianity, and come to some maturity in the things of God. Those that receive the doctrine as divine, and, having been illu...', 'teologico');
add('1co', 3, 1, 'Matthew Henry', 'Here, I. Paul blames the Corinthians for their weakness and nonproficiency. Those who are sanctified are so only in part: there is still room for growth and increase both in grace and knowledge, Pe2 3:18. Those who through divine grace are renewed to a spiritual life may yet in many things be defective. The apostle tells them he could not speak to them as unto spiritual men, but as unto carnal men, as to babes in Christ, Co1 3:1. They were so far from forming their maxims and measures upon th...', 'teologico');
add('1co', 3, 5, 'Matthew Henry', 'Here the apostle instructs them how to cure this humour, and rectify what was amiss among them upon this head,\nI. By reminding them that the ministers about whom they contended were but ministers: Who then is Paul, and who is Apollos, but ministers by whom you believed? Even as the Lord gave to every man, Co1 3:5. They are but ministers, mere instruments used by the God of all grace. Some of the factious people in Corinth seem to have made more of them, as if they were lords of their faith, a...', 'teologico');
add('1co', 3, 11, 'Matthew Henry', 'Here the apostle informs us what foundation he had laid at the bottom of all his labours among them - even Jesus Christ, the chief corner-stone, Eph 2:20. Upon this foundation all the faithful ministers of Christ build. Upon this rock all the Christians found their hopes. Those that build their hopes of heaven on any other foundation build upon the sand. Other foundation can no man lay besides what is laid - even Jesus Christ. Note, The doctrine of our Saviour and his mediation is the princip...', 'teologico');
add('1co', 3, 18, 'Matthew Henry', 'Here he prescribes humility, and a modest opinion of themselves, for the remedy of the irregularities in the church of Corinth, the divisions and contests among them: "Let no man deceive himself, Co1 3:18. Do not be led away from the truth and simplicity of the gospel by pretenders to science and eloquence, by a show of deep learning, or a flourish of words, by rabbis, orators, or philosophers." Note, We are in great danger of deceiving ourselves when we have too high an opinion of human wisd...', 'teologico');
add('1co', 3, 21, 'Matthew Henry', 'Here the apostle founds an exhortation against over-valuing their teachers on what he had just said, and on the consideration that they had an equal interest in all their ministers: Therefore let no man glory in men (Co1 3:21) - forget that their ministers are men, or pay that deference to them that is due only to God, set them at the head of parties, have them in immoderate esteem and admiration, and servilely and implicitly follow their directions and submit to their dictates, and especiall...', 'teologico');
add('1co', 4, 1, 'Matthew Henry', 'Here, I. The apostle challenges the respect due to him on account of his character and office, in which many among them had at least very much failed: Let a man so account of us as of the ministers of Christ, and stewards of the mysteries of God (Co1 4:1), though possibly others might have valued them too highly, by setting him up as the head of a party, and professing to be his disciples. In our opinion of ministers, as well as all other things, we should be careful to avoid extremes. Apostl...', 'teologico');
add('1co', 4, 7, 'Matthew Henry', 'Here the apostle improves the foregoing hint to a caution against pride and self-conceit, and sets forth the temptations the Corinthians had to despise him, from the difference of their circumstances.\nI. He cautions them against pride and self-conceit by this consideration, that all the distinction made among them was owing to God: Who maketh thee to differ? And what hast thou that thou didst not receive? Co1 4:7. Here the apostle turns his discourse to the ministers who set themselves at the...', 'teologico');
add('1co', 4, 14, 'Matthew Henry', 'Here Paul challenges their regard to him as their father. He tells them, 1. That what he had written was not for their reproach, but admonition; not with the gall of an enemy, but the bowels of a father (Co1 4:14): I write not to shame you, but as my beloved children I warn you. Note, In reproving for sin, we should have a tender regard to the reputation, as well as the reformation, of the sinner. We should aim to distinguish between them and their sins, and take care not to discover any spit...', 'teologico');
add('1co', 4, 17, 'Matthew Henry', 'Here, I. He tells them of his having sent Timothy to them, to bring them into remembrance of his ways in Christ, as he taught every where in every church (Co1 4:17) - to remind them of his ways in Christ, to refresh their memory as to his preaching and practice, what he taught, and how he lived among them. Note, Those who have had ever so good teaching are apt to forget, and need to have their memories refreshed. The same truth, taught over again, if it give no new light, may make new and qui...', 'teologico');
add('1co', 5, 1, 'Matthew Henry', 'Here the apostle states the case; and,\nI. Lets them know what was the common or general report concerning them, that one of their community was guilty of fornication, Co1 5:1. It was told in all places, to their dishonour, and the reproach of Christians. And it was the more reproachful because it could not be denied. Note, The heinous sins of professed Christians are quickly noted and noised abroad. We should walk circumspectly, for many eyes are upon us, and many mouths will be opened agains...', 'teologico');
add('1co', 5, 7, 'Matthew Henry', 'Here the apostle exhorts them to purity, by purging out the old leaven. In this observe,\nI. The advice itself, addressed either, 1. To the church in general; and so purging out the old leaven, that they might be a new lump, refers to the putting away from themselves that wicked person, Co1 5:13. Note, Christian churches should be pure and holy, and not bear such corrupt and scandalous members. They are to be unleavened, and should endure no such heterogeneous mixture to sour and corrupt them....', 'teologico');
add('1co', 5, 9, 'Matthew Henry', 'Here the apostle advises them to shun the company and converse of scandalous professors. Consider,\nI. The advice itself: I wrote to you in a letter not to company with fornicators, Co1 5:9. Some think this was an epistle written to them before, which is lost. Yet we have lost nothing by it, the Christian revelation being entire in those books of scripture which have come down to us, which are all that were intended by God for the general use of Christians, or he could and would in his provide...', 'teologico');
add('1co', 6, 1, 'Matthew Henry', 'Here the apostle reproves them for going to law with one another before heathen judges for little matters; and therein blames all vexatious law-suits. In the previous chapter he had directed them to punish heinous sins among themselves by church-censures. Here he directs them to determine controversies with one another by church-counsel and advice, concerning which observe,\nI. The fault he blames them for: it was going to law. Not but that the law is good, if a man use it lawfully. But, 1. Br...', 'teologico');
add('1co', 6, 9, 'Matthew Henry', 'Here he takes occasion to warn them against many heinous evils, to which they had been formerly addicted.\nI. He puts it to them as a plain truth, of which they could not be ignorant, that such sinners should not inherit the kingdom of God. The meanest among them must know thus much, that the unrighteous shall not inherit the kingdom of God (Co1 6:9), shall not be owned as true members of his church on earth, nor admitted as glorious members of the church in heaven. All unrighteousness is sin;...', 'teologico');
add('1co', 6, 12, 'Matthew Henry', 'The twelfth verse and former part of the thirteenth seem to relate to that early dispute among Christians about the distinction of meats, and yet to be prefatory to the caution that follows against fornication. The connection seems plain enough if we attend to the famous determination of the apostles, Acts 15, where the prohibition of certain foods was joined with that of fornication. Now some among the Corinthians seem to have imagined that they were as much at liberty in the point of fornic...', 'teologico');
add('1co', 7, 1, 'Matthew Henry', 'The apostle comes now, as a faithful and skilful casuist, to answer some cases of conscience which the Corinthians had proposed to him. Those were things whereof they wrote to him, Co1 7:1. As the lips of ministers should keep knowledge, so the people should ask the law at their mouths. The apostle was as ready to resolve as they were to propose their doubts. In the former chapter, he warns them to avoid fornication; here he gives some directions about marriage, the remedy God had appointed f...', 'teologico');
add('1co', 7, 10, 'Matthew Henry', 'In this paragraph the apostle gives them direction in a case which must be very frequent in that age of the world, especially among the Jewish converts; I mean whether they were to live with heathen relatives in a married state. Moses\'s law permitted divorce; and there was a famous instance in the Jewish state, when the people were obliged to put away their idolatrous wives, Ezr 10:3. This might move a scruple in many minds, whether converts to Christianity were not bound to put away or deser...', 'teologico');
add('1co', 7, 17, 'Matthew Henry', 'Here the apostle takes occasion to advise them to continue in the state and condition in which Christianity found them, and in which they became converts to it. And here,\nI. He lays down this rule in general - as God hath distributed to every one. Note, Our states and circumstances in this world are distributions of divine Providence. This fixes the bounds of men\'s habitations, and orders their steps. God setteth up and pulleth down. And again, As the Lord hath called every one, so let him wa...', 'teologico');
add('1co', 7, 25, 'Matthew Henry', 'The apostle here resumes his discourse, and gives directions to virgins how to act, concerning which we may take notice,\nI. Of the manner wherein he introduces them: "Now concerning virgins I have no commandment of the Lord, Co1 7:25. I have no express and universal law delivered by the Lord himself concerning celibacy; but I give my judgment, as one who hath obtained mercy of the Lord to be faithful," namely, in the apostleship. He acted faithfully, and therefore his direction was to be rega...', 'teologico');
add('1co', 7, 36, 'Matthew Henry', 'In this passage the apostle is commonly supposed to give advice about the disposal of children in marriage, upon the principle of his former determination. In this view the general meaning is plain. It was in that age, and those parts of the world, and especially among the Jews, reckoned a disgrace for a woman to remain unmarried past a certain number of years: it gave a suspicion of somewhat that was not for her reputation. "Now," says the apostle, "if any man thinks he behaves unhandsomely ...', 'teologico');
add('1co', 7, 39, 'Matthew Henry', 'The whole is here closed up with advice to widows: As long as the husband liveth the wife is bound by the law, confined to one husband, and bound to continue and cohabit with him. Note, The marriage - contract is for life; death only can annul the bond. But, the husband being dead, she is at liberty to marry whom she will. There is no limitation by God\'s law to be married only for such a number of times. It is certain, from this passage, that second marriages are not unlawful; for then the wi...', 'teologico');
add('1co', 8, 1, 'Matthew Henry', 'The apostle comes here to the case of things that had been offered to idols, concerning which some of them sought satisfaction: a case that frequently occurred in that age of Christianity, when the church of Christ was among the heathen, and the Israel of God must live among the Canaanites. For the better understanding of it, it must be observed that it was a custom among the heathens to make feasts on their sacrifices, and not only to eat themselves, but invite their friends to partake with ...', 'teologico');
add('1co', 8, 4, 'Matthew Henry', 'In this passage he shows the vanity of idols: As to the eating of things that have been sacrificed to idols, we know that an idol is nothing in the world; or, there is no idol in the world; or, an idol can do nothing in the world: for the form of expression in the original is elliptical. The meaning in the general is, that heathen idols have no divinity in them; and therefore the Old Testament they are commonly called lies and vanities, or lying vanities. They are merely imaginary gods, and m...', 'teologico');
add('1co', 8, 7, 'Matthew Henry', 'The apostle, having granted, and indeed confirmed, the opinion of some among the Corinthians, that idols were nothing, proceeds now to show them that their inference from this assumption was not just, namely, that therefore they might go into the idol-temple, and eat of the sacrifices, and feast there with their heathen neighbours. He does not indeed here so much insist upon the unlawfulness of the thing in itself as the mischief such freedom might do to weaker Christians, persons that had no...', 'teologico');
add('1co', 9, 1, 'Matthew Henry', 'Blessed Paul, in the work of his ministry, not only met with opposition from those without, but discouragement from those within. He was under reproach; false brethren questioned his apostleship, and were very industrious to lessen his character and sink his reputation; particularly here at Corinth, a place to which he had been instrumental in doing much good, and from which he had deserved well; and yet there were those among them who upon these heads created him great uneasiness. Note, It i...', 'teologico');
add('1co', 9, 3, 'Matthew Henry', 'Having asserted his apostolical authority, he proceeds to claim the rights belonging to his office, especially that of being maintained by it.\nI. These he states, Co1 9:3-6. "My answer to those that do examine me (that is, enquire into my authority, or the reasons of my conduct, if I am an apostle) is this: Have we not power to eat and drink (Co1 9:4), or a right to maintenance? Have we not power to lead about a sister, a wife, as well as other apostles, and the brethren of the Lord, and Ceph...', 'teologico');
add('1co', 9, 15, 'Matthew Henry', 'Here he tells them that he had, notwithstanding, waived his privilege, and lays down his reason for doing it.\nI. He tells them that he had neglected to claim his right in times past: I have used none of these things, Co1 9:15. He neither ate nor drank himself at their cost, nor led about a wife to be maintained by them, nor forbore working to maintain himself. From others he received a maintenance, but not from them, for some special reasons. Nor did he write this to make his claim now. Thoug...', 'teologico');
add('1co', 9, 19, 'Matthew Henry', 'The apostle takes occasion from what he had before discoursed to mention some other instances of his self-denial and parting with his liberty for the benefit of others.\nI. He asserts his liberty (Co1 9:19): Though I be free from all men. He was free-born, a citizen of Rome. He was in bondage to none, nor depended upon any for his subsistence; yet he made himself a servant to all, that he might gain the more. He behaved as a servant; he laboured for their good as a servant; he was careful to p...', 'teologico');
add('1co', 9, 24, 'Matthew Henry', 'In these verses the apostle hints at the great encouragement he had to act in this manner. He had a glorious prize, an incorruptible crown, in view. Upon this head he compares himself to the racers and combatants in the Isthmian games, an allusion well known to the Corinthians, because they were celebrated in their neighbourhood: "Know you not that those who run in a race run all, but one obtaineth the prize? Co1 9:24. All run at your games, but only one gets the race and wins the crown." And...', 'teologico');
add('1co', 10, 1, 'Matthew Henry', 'In order to dissuade the Corinthians from communion with idolaters, and security in any sinful course, he sets before them the example of the Jews, the church under the Old Testament. They enjoyed great privileges, but, having been guilty of heinous provocations, they fell under very grievous punishments. In these verses he reckons up their privileges, which, in the main, were the same with ours.\nI. He prefaces this discourse with a note of regard: "Moreover, brethren, I would not that you sh...', 'teologico');
add('1co', 10, 6, 'Matthew Henry', 'The apostle, having recited their privileges, proceeds here to an account of their faults and punishments, their sins and plagues, which are left upon record for an example to us, a warning against the like sins, if we would escape the like punishments. We must not do as they did, lest we suffer as they suffered.\nI. Several of their sins are specified as cautions to us; as, 1. We should shun inordinate desires after carnal objects: Not lust after evil things, as they lusted, Co1 10:6. God fed...', 'teologico');
add('1co', 10, 15, 'Matthew Henry', 'In this passage the apostle urges the general caution against idolatry, in the particular case of eating the heathen sacrifices as such, and out of any religious respect to the idol to whom they were sacrificed.\nI. He prefaces his argument with an appeal to their own reason and judgment: "I speak to wise men, judge you what I say, Co1 10:15. You are great pretenders to wisdom, to close reasoning and argument; I can leave it with your own reason and conscience whether I do not argue justly." N...', 'teologico');
add('1co', 10, 23, 'Matthew Henry', 'In this passage the apostle shows in what instances, notwithstanding, Christians might lawfully eat what had been sacrificed to idols. They must not eat it out of religious respect to the idol, nor go into his temple, and hold a feast there, upon what they knew was an idol-sacrifice; nor perhaps out of the temple, if they knew it was a feast held upon a sacrifice, but there were cases wherein they might without sin eat what had been offered. Some such the apostle here enumerates. - But,\nI. He...', 'teologico');
add('1co', 11, 1, 'Matthew Henry', 'Paul, having answered the cases put to him, proceeds in this chapter to the redress of grievances. The first verse of the chapter is put, by those who divided the epistle into chapters, as a preface to the rest of the epistle, but seems to have been a more proper close to the last, in which he had enforced the cautions he had given against the abuse of liberty, by his own example: Be ye followers of me, as I also am of Christ (Co1 11:1), fitly closes his argument; and the way of speaking in t...', 'teologico');
add('1co', 11, 17, 'Matthew Henry', 'In this passage the apostle sharply rebukes them for much greater disorders than the former, in their partaking of the Lord\'s supper, which was commonly done in the first ages, as the ancients tell us, with a love-feast annexed, which gave occasion to the scandalous disorders which the apostle here reprehends, concerning which observe,\nI. The manner in which he introduces his charge: "Now in this that I declare to you I praise you not, Co1 11:17. I cannot commend, but must blame and condemn y...', 'teologico');
add('1co', 11, 23, 'Matthew Henry', 'To rectify these gross corruptions and irregularities, the apostle sets the sacred institution here to view. This should be the rule in the reformation of all abuses.\nI. He tells us how he came by the knowledge of it. He was not among the apostles at the first institution; but he had received from the Lord what he delivered to them, Co1 11:23. He had the knowledge of this matter by revelation from Christ: and what he had received he communicated, without varying from the truth a tittle, witho...', 'teologico');
add('1co', 12, 1, 'Matthew Henry', 'The apostle comes now to treat of spiritual gifts, which abounded in the church of Corinth, but were greatly abused. What these gifts were is at large told us in the body of the chapter; namely, extraordinary offices and powers, bestowed on ministers and Christians in the first ages, for conviction of unbelievers, and propagation of the gospel. Gifts and graces, charismata and charis, greatly differ. Both indeed were freely given of God. But where grace is given it is for the salvation of tho...', 'teologico');
add('1co', 12, 12, 'Matthew Henry', 'The apostle here makes out the truth of what was above asserted, and puts the gifted men among the Corinthians in mind of their duty, by comparing the church of Christ to a human body.\nI. By telling us that one body may have many members, and that the many members of the same body make but one body (Co1 12:12): As the body is one, and hath many members, and all members of that one body, being many, are one body, so also is Christ; that is, Christ mystical, as divines commonly speak. Christ an...', 'teologico');
add('1co', 12, 27, 'Matthew Henry', 'I. Here the apostle sums up the argument, and applies this similitude to the church of Christ, concerning which observe,\n1. The relation wherein Christians stand to Christ and one another. The church, or whole collective body of Christians, in all ages, is his body. Every Christian is a member of his body, and every other Christian stands related to him as a fellow-member (Co1 12:27): Now you are the body of Christ, and members in particular, or particular members. Each is a member of the bod...', 'teologico');
add('1co', 13, 1, 'Matthew Henry', 'Here the apostle shows what more excellent way he meant, or had in view, in the close of the former chapter, namely, charity, or, as it is commonly elsewhere rendered, love - agapē: not what is meant by charity in our common use of the word, which most men understand of alms - giving, but love in its fullest and most extensive meaning, true love to God and man, a benevolent disposition of mind towards our fellow-christians, growing out of sincere and fervent devotion to God. This living prin...', 'teologico');
add('1co', 13, 8, 'Matthew Henry', 'Here the apostle goes on to commend charity, and show how much it is preferable to the gifts on which the Corinthians were so apt to pride themselves, to the utter neglect, and almost extinction, of charity. This he makes out,\nI. From its longer continuance and duration: Charity never faileth. It is a permanent and perpetual grace, lasting as eternity; whereas the extraordinary gifts on which the Corinthians valued themselves were of short continuance. They were only to edify the church on ea...', 'teologico');
add('1co', 14, 1, 'Matthew Henry', 'The apostle, in the foregoing chapter, had himself preferred, and advised the Corinthians to prefer, Christian charity to all spiritual gifts. Here he teaches them, among spiritual gifts, which they should prefer, and by what rules they should make comparison. He begins the chapter,\nI. With an exhortation to charity (Co1 14:1): Follow after charity, pursue it. The original, diōkete, when spoken of a thing, signifies a singular concern to obtain it; and is commonly taken in a good and laudabl...', 'teologico');
add('1co', 14, 6, 'Matthew Henry', 'In this paragraph he goes on to show how vain a thing the ostentation of speaking unknown and unintelligible language must be. It was altogether unedifying and unprofitable (Co1 14:6): If I come to you speaking with tongues, what will it profit you, unless I speak to you by revelation, or by knowledge, or by prophesying, or by doctrine? It would signify nothing to utter any of these in an unknown tongue. An apostle, with all his furniture, could not edify, unless he spoke to the capacity of h...', 'teologico');
add('1co', 14, 15, 'Matthew Henry', 'The apostle here sums up the argument hitherto, and,\nI. Directs them how they should sing and pray in public (Co1 14:15): What is it then? I will pray with the spirit, and I will pray with the understanding also. I will sing with the spirit, etc. He does not forbid their praying or singing under a divine afflatus, or when they were inspired for this purpose, or had such a spiritual gift communicated to them; but he would have them perform both so as to be understood by others, that others mig...', 'teologico');
add('1co', 14, 21, 'Matthew Henry', 'In this passage the apostle pursues the argument, and reasons from other topics; as,\nI. Tongues, as the Corinthians used them, were rather a token of judgment from God than mercy to any people (Co1 14:21): In the law (that is, the Old Testament) it is written, With men of other tongues and other lips will I speak to this people; and yet for all this they will not hear me, saith the Lord, Isa 28:11. Compare Deu 28:46, Deu 28:49. To both these passages, it is thought, the apostle refers. Both a...', 'teologico');
add('1co', 14, 26, 'Matthew Henry', 'In this passage the apostle reproves them for their disorder, and endeavours to correct and regulate their conduct for the future.\nI. He blames them for the confusion they introduced into the assembly, by ostentation of their gifts (Co1 14:26): When you come together every one hath a psalm, hath a doctrine, hath a tongue, etc.; that is, "You are apt to confound the several parts of worship; and, while one has a psalm to utter by inspiration, another has a doctrine, or revelation;" or else, "Y...', 'teologico');
add('1co', 14, 34, 'Matthew Henry', 'Here the apostle, 1. Enjoins silence on their women in public assemblies, and to such a degree that they must not ask questions for their own information in the church, but ask their husbands at home. They are to learn in silence with all subjection; but, says the apostle, I suffer them not to teach, Ti1 2:11, Ti1 2:12. There is indeed an intimation (Co1 11:5) as if the women sometimes did pray and prophecy in their assemblies, which the apostle, in that passage, does not simply condemn, but ...', 'teologico');
add('1co', 14, 36, 'Matthew Henry', 'In these verses the apostle closes his argument, 1. With a just rebuke of the Corinthians for their extravagant pride and self-conceit: they so managed with their spiritual gifts as no church did like them; they behaved in a manner by themselves, and would not easily endure control nor regulation. Now, says the apostle, to beat down this arrogant humour, "Came the gospel out from you? Or came it to you only? Co1 14:36. Did Christianity come our of Corinth? was its original among you? Or, if n...', 'teologico');
add('1co', 15, 1, 'Matthew Henry', 'It is the apostle\'s business in this chapter to assert and establish the doctrine of the resurrection of the dead, which some of the Corinthians flatly denied, Co1 15:12. Whether they turned this doctrine into allegory, as did Hymeneus and Philetus, by saying it was already past (Ti2 2:17, Ti2 2:18), and several of the ancient heretics, by making it mean no more than a changing of their course of life; or whether they rejected it as absurd, upon principles of reason and science; it seems they...', 'teologico');
add('1co', 15, 12, 'Matthew Henry', 'Having confirmed the truth of our Saviour\'s resurrection, the apostle goes on to refute those among the Corinthians who said there would be none: If Christ be preached that he rose from the dead, how say some among you that there is no resurrection of the dead? Co1 15:12. It seems from this passage, and the course of the argument, there were some among the Corinthians who thought the resurrection an impossibility. This was a common sentiment among the heathens. But against this the apostle pr...', 'teologico');
add('1co', 15, 20, 'Matthew Henry', 'In this passage the apostle establishes the truth of the resurrection of the dead, the holy dead, the dead in Christ,\nI. On the resurrection of Christ. 1. Because he is indeed the first-fruits of those that slept, Co1 15:20. He has truly risen himself, and he has risen in this very quality and character, as the first-fruits of those who sleep in him. As he has assuredly risen, so in his resurrection there is as much an earnest given that the dead in him shall rise as there was that the Jewish...', 'teologico');
add('1co', 15, 35, 'Matthew Henry', 'The apostle comes now to answer a plausible and principal objection against the doctrine of the resurrection of the dead, concerning which observe the proposal of the objection: Some man will say, How are the dead raised up? And with what body do they come? Co1 15:35. The objection is plainly two-fold. How are they raised up? that is, "By what means? How can they be raised? What power is equal to this effect?" It was an opinion that prevailed much among the heathens, and the Sadducees seem to...', 'teologico');
add('1co', 15, 51, 'Matthew Henry', 'To confirm what he had said of this change,\nI. He here tells them what had been concealed from or unknown to them till then - that all the saints would not die, but all would be changed. Those that are alive at our Lord\'s coming will be caught up into the clouds, without dying, Th1 4:11. But it is plain from this passage that it will not be without changing from corruption to incorruption. The frame of their living bodies shall be thus altered, as well as those that are dead; and this in a mo...', 'teologico');
add('1co', 15, 58, 'Matthew Henry', 'In this verse we have the improvement of the whole argument, in an exhortation, enforced by a motive resulting plainly from it.\nI. An exhortation, and this threefold: - 1. That they should be stedfast - hedraioi, firm, fixed in the faith of the gospel, that gospel which he had preached and they had received, namely, That Christ died for our sins, and arose again the third day, according to the scriptures (Co1 15:3, Co1 15:4), and fixed in the faith of the glorious resurrection of the dead, wh...', 'teologico');
add('1co', 16, 1, 'Matthew Henry', 'In this chapter Paul closes this long epistle with some particular matters of less moment; but, as all was written by divine inspiration, it is all profitable for our instruction. He begins with directing them about a charitable collection on a particular occasion, the distresses and poverty of Christians in Judea, which at this time were extraordinary, partly through the general calamities of that nation and partly through the particular sufferings to which they were exposed. Now concerning ...', 'teologico');
add('1co', 16, 5, 'Matthew Henry', 'In this passage the apostle notifies and explains his purpose of visiting them, concerning which, observe, 1. His purpose: he intended to pass out of Asia, where he now was (vide Co1 16:8, Co1 16:19) and to go through Macedonia into Achaia, where Corinth was, and to stay some time with them, and perhaps the winter, Co1 16:5, Co1 16:6. He had long laboured in this church, and done much good among them, and had his heart set upon doing much more (if God saw fit), and therefore he had it in his ...', 'teologico');
add('1co', 16, 10, 'Matthew Henry', 'In this passage,\nI. He recommends Timothy to them, in several particulars. As, 1. He bids them take care that he should be among them without feat, Co1 16:10. Timothy was sent by the apostle to correct the abuses which had crept in among them; and not only to direct, but to blame, and censure, and reprove, those who were culpable. They were all in factions, and no doubt the mutual strife and hatred ran very high among them. There were some very rich, as it is probable; and many very proud, up...', 'teologico');
add('1co', 16, 13, 'Matthew Henry', 'In this passage the apostle gives,\nI. Some general advices; as, 1. That they should watch (Co1 16:13), be wakeful and upon their guard. A Christian is always in danger, and therefore should ever be on the watch; but the danger is greater at some times and under some circumstances. The Corinthians were in manifest danger upon many accounts: their feuds ran high, the irregularities among them were very great, there were deceivers got among them, who endeavoured to corrupt their faith in the mos...', 'teologico');
add('1co', 16, 19, 'Matthew Henry', 'The apostle closes his epistle,\nI. With salutations to the church of Corinth, first from those of Asia, from Priscilla and Aquila (who seem to have been at this time inhabitants of Ephesus, vid. Act 18:26), with the church in their house (Co1 16:19), and from all the brethren (Co1 16:20) at Ephesus, where, it is highly probable at least, he then was. All these saluted the church at Corinth, by Paul. Note, Christianity does by no means destroy civility and good manners. Paul could find room in...', 'teologico');

// 2CO (42 comentários)
add('2co', 4, 6, 'Agostinho', 'Deus, que mandou — A luz do conhecimento da glória de Deus no rosto de Cristo.', 'teologico');
add('2co', 5, 17, 'John Stott', 'Nova criatura — A conversão é criação nova: um novo começo radical.', 'teologico');
add('2co', 5, 21, 'Tomás de Aquino', 'Deus o fez pecado — A troca maravilhosa: o pecado por justiça.', 'teologico');
add('2co', 12, 9, 'Lloyd-Jones', 'A graça é suficiente — Na fraqueza, a graça se manifesta com poder perfeito.', 'teologico');
add('2co', 1, 1, 'Matthew Henry', 'This is the introduction to this epistle, in which we have,\nI. The inscription; and therein, 1. The person from whom it was sent, namely, Paul, who calls himself an apostle of Jesus Christ by the will of God. The apostleship itself was ordained by Jesus Christ, according to the will of God; and Paul was called to it by Jesus Christ, according to the will of God. He joins Timotheus with himself in writing this epistle; not because he needed his assistance, but that out of the mouth of two witn...', 'teologico');
add('2co', 1, 3, 'Matthew Henry', 'After the foregoing preface, the apostle begins with the narrative of God\'s goodness to him and his fellow-labourers in their manifold tribulations, which he speaks of by way of thanksgiving to God, and to advance the divine glory (Co2 1:3-6); and it is fit that in all things, and in the first place, God be glorified. Observe,\nI. The object of the apostle\'s thanksgiving, to whom he offers up blessing and praise, namely, the blessed God, who only is to be praised, whom he describes by several ...', 'teologico');
add('2co', 1, 7, 'Matthew Henry', 'In these verses the apostle speaks for the encouragement and edification of the Corinthians; and tells them (Co2 1:7) of his persuasion or stedfast hope that they should receive benefit by the troubles he and his companions in labour and travel had met with, that their faith should not be weakened, but their consolations increased. In order to this he tells them, 1. What their sufferings had been (Co2 1:8): We would not have you ignorant of our trouble. It was convenient for the churches to k...', 'teologico');
add('2co', 1, 12, 'Matthew Henry', 'The apostle in these verses attests their integrity by the sincerity of their conversation. This he does not in a way of boasting and vain-glory, but as one good reason for desiring the help of prayer, as well as for the more comfortably trusting in God (Heb 13:18), and for the necessary vindication of himself from the aspersions of some persons at Corinth, who reproached his person and questioned his apostleship. Here,\nI. He appeals to the testimony of conscience with rejoicing (Co2 1:12), i...', 'teologico');
add('2co', 1, 15, 'Matthew Henry', 'The apostle here vindicates himself from the imputation of levity and inconstancy, in that he did not hold his purpose of coming to them at Corinth. His adversaries there sought all occasions to blemish his character, and reflect upon his conduct; and, it seemed, they took hold of this handle to reproach his person and discredit his ministry. Now, for his justification,\nI. He avers the sincerity of his intention (Co2 1:15-17), and he does this in confidence of their good opinion of him, and t...', 'teologico');
add('2co', 2, 1, 'Matthew Henry', 'In these verses, 1. The apostle proceeds in giving an account of the reason why he did not come to Corinth, as was expected; namely, because he was unwilling to grieve them, or be grieved by them, Co2 2:1, Co2 2:2. He had determined not to come to them in heaviness, which yet he would have done had he come and found scandal among them not duly animadverted upon: this would have been cause of grief both to him and them, for their sorrow or joy at meeting would have been mutual. If he had made ...', 'teologico');
add('2co', 2, 5, 'Matthew Henry', 'In these verses the apostle treats concerning the incestuous person who had been excommunicated, which seems to be one principal cause of his writing this epistle. Here observe, 1. He tells them that the crime of that person had grieved him in part; and that he was grieved also with a part of them, who, notwithstanding this scandal had been found among them, were puffed up and had not mourned, Co1 5:2. However, he was unwilling to lay too heavy a charge upon the whole church, especially seein...', 'teologico');
add('2co', 2, 12, 'Matthew Henry', 'After these directions concerning the excommunicated person the apostle makes a long digression, to give the Corinthians an account of his travels and labours for the furtherance of the gospel, and what success he had therein, declaring at the same time how much he was concerned for them in their affairs, how he had no rest in his spirit, when he found not Titus at Troas (Co2 2:13), as he expected, from whom he hoped to have understood more perfectly how it fared with them. And we find afterw...', 'teologico');
add('2co', 3, 1, 'Matthew Henry', 'In these verses,\nI. The apostle makes an apology for seeming to commend himself. He thought it convenient to protest his sincerity to them, because there were some at Corinth who endeavoured to blast his reputation; yet he was not desirous of vain-glory. And he tells them, 1. That he neither needed nor desired any verbal commendation to them, nor letters testimonial from them, as some others did, meaning the false apostles or teachers, Co2 3:1. His ministry among them had, without controversy...', 'teologico');
add('2co', 3, 6, 'Matthew Henry', 'Here the apostle makes a comparison between the Old Testament and the New, the law of Moses and the gospel of Jesus Christ, and values himself and his fellow-labourers by this, that they were able ministers of the New Testament, that God had made them so, Co2 3:6. This he does in answer to the accusations of false teachers, who magnify greatly the law of Moses.\nI. He distinguishes between the letter and the spirit even of the New Testament, Co2 3:6. As able ministers of the New Testament, the...', 'teologico');
add('2co', 3, 12, 'Matthew Henry', 'In these verses the apostle draws two inferences from what he had said about the Old and New Testament: - \nI. Concerning the duty of the ministers of the gospel to use great plainness or clearness of speech. They ought not, like Moses, to put a veil upon their faces, or obscure and darken those things which they should make plain. The gospel is a more clear dispensation than the law; the things of God are revealed in the New Testament, not in types and shadows, and ministers are much to blame...', 'teologico');
add('2co', 4, 1, 'Matthew Henry', 'The apostle had, in the foregoing chapter, been magnifying his office, upon the consideration of the excellency or glory of that gospel about which he did officiate; and now in this chapter his design is to vindicate their ministry from the accusation of false teachers, who charged them as deceitful workers, or endeavoured to prejudice the minds of the people against them on account of their sufferings. He tells them, therefore, how they believed, and how they showed their value for their off...', 'teologico');
add('2co', 4, 8, 'Matthew Henry', 'In these verses the apostle gives an account of their courage and patience under all their sufferings, where observe,\nI. How their sufferings, and patience under them, are declared, Co2 4:8-12. The apostles were great sufferers; therein they followed their Master: Christ had told them that in the world they should have tribulation, and so they had; yet they met with wonderful support, great relief, and many allays of their sorrows. "We are," says the apostle, "troubled on every side, afflicte...', 'teologico');
add('2co', 5, 1, 'Matthew Henry', 'The apostle in these verses pursues the argument of the former chapter, concerning the grounds of their courage and patience under afflictions. And,\nI. He mentions their expectation, and desire, and assurance, of eternal happiness after death, Co2 5:1-5. Observe particularly,\n1. The believer\'s expectation of eternal happiness after death, Co2 5:1. He does not only know, or is well assured by faith of the truth and reality of the thing itself - that there is another and a happy life after this...', 'teologico');
add('2co', 5, 12, 'Matthew Henry', 'Here observe, I. The apostle makes an apology for seeming to commend himself and his fellow-labourers (Co2 5:13), and tells them, 1. It was not to commend themselves, nor for their own sakes, that he had spoken of their fidelity and diligence in the former verses; nor was he willing to suspect their good opinion of him. But, 2. The true reason was this, to put an argument in their mouths wherewith to answer his accusers, who made vain boastings, and gloried in appearances only; that he might ...', 'teologico');
add('2co', 5, 16, 'Matthew Henry', 'In these verses the apostle mentions two things that are necessary in order to our living to Christ, both of which are the consequences of Christ\'s dying for us; namely, regeneration and reconciliation.\nI. Regeneration, which consists of two things; namely, 1. Weanedness from the world: "Henceforth we know no man after the flesh, Co2 5:16. We do not own nor affect any person or thing in this world for carnal ends and outward advantage: we are enabled, by divine grace, not to mind nor regard t...', 'teologico');
add('2co', 6, 1, 'Matthew Henry', 'In these verses we have an account of the apostle\'s general errand and exhortation to all to whom he preached in every place where he came, with the several arguments and methods he used. Observe,\nI. The errand or exhortation itself, namely, to comply with the gospel offers of reconciliation - that, being favoured with the gospel, they would not receive this grace of God in vain, Co2 6:1. The gospel is a word of grace sounding in our ears; but it will be in vain for us to hear it, unless we b...', 'teologico');
add('2co', 6, 11, 'Matthew Henry', 'The apostle proceeds to address himself more particularly to the Corinthians, and cautions them against mingling with unbelievers. Here observe,\nI. How the caution is introduced with a profession, in a very pathetic manner, of the most tender affection to them, even like that of a father to his children, Co2 6:11-13. Though the apostle was happy in a great fluency of expressions, yet he seemed to want words to express the warm affections he had for these Corinthians. As if he had said, "O ye ...', 'teologico');
add('2co', 7, 1, 'Matthew Henry', 'These verses contain a double exhortation: - \nI. To make a progress in holiness, or to perfect holiness in the fear of God, Co2 7:1. This exhortation is given with most tender affection to those who were dearly beloved, and enforced by strong arguments, even the consideration of those exceedingly great and precious promises which were mentioned in the former chapter, and which the Corinthians had an interest in and a title to. The promises of God are strong inducements to sanctification, in b...', 'teologico');
add('2co', 7, 5, 'Matthew Henry', 'There seems to be a connection between Co2 2:13 (where the apostle said he had no rest in his spirit when he found not Titus at Troas) and the fifth verse of this chapter: and so great was his affection to the Corinthians, and his concern about their behaviour in relation to the incestuous person, that, in his further travels, he still had no rest till he heard from them. And now he tells them,\nI. How he was distressed, Co2 7:5. He was troubled when he did not meet with Titus at Troas, and af...', 'teologico');
add('2co', 7, 12, 'Matthew Henry', 'In these verses the apostle endeavours to comfort the Corinthians, upon whom his admonitions had had such good effect. And in order thereto, 1. He tells them he had a good design in his former epistle, which might be thought severe, Co2 7:12. It was not chiefly for his cause that did the wrong, not only for his benefit, much less merely that he should be punished; nor was it merely for his cause that suffered wrong, namely, the injured father, and that he might have what satisfaction could be...', 'teologico');
add('2co', 8, 1, 'Matthew Henry', 'Observe here,\nI. The apostle takes occasion from the good example of the churches of Macedonia, that is, of Philippi, Thessalonica, Berea, and others in the region of Macedonia, to exhort the Corinthians and the Christians in Achaia to the good work of charity. And,\n1. He acquaints them with their great liberality, which he calls the grace of God bestowed on the churches, Co2 8:1. Some think the words should be rendered, the gift of God given in or by the churches. He certainly means the char...', 'teologico');
add('2co', 8, 7, 'Matthew Henry', 'In these verses the apostle uses several cogent arguments to stir up the Corinthians to this good work of charity.\nI. He urges upon them the consideration of their eminence in other gifts and graces, and would have them excel in this of charity also, Co2 8:7. Great address and much holy art are here used by the apostle. When he would persuade the Corinthians to this good thing, he commends them for other good things that were found in them. Most people love to be complimented, especially when...', 'teologico');
add('2co', 8, 16, 'Matthew Henry', 'In these verses the apostle commends the brethren who were sent to them to collect their charity; and as it were, gives them letters credential, that, if they were enquired after (Co2 8:23), if any should be inquisitive or suspicious concerning them, it might be known who they were and how safely they might be trusted.\nI. He commends Titus, 1. For his earnest care and great concern of heart for them, and desire in all things to promote their welfare. This is mentioned with thankfulness to God...', 'teologico');
add('2co', 9, 1, 'Matthew Henry', 'In these verses the apostle speaks very respectfully to the Corinthians, and with great skill; and, while he seems to excuse his urging them so earnestly to charity, still presses them thereto, and shows how much his heart was set upon this matter.\nI. He tells them it was needless to press them with further arguments to afford relief to their poor brethren (Co2 9:1), being satisfied he had said enough already to prevail with those of whom he had so good an opinion. For, 1. He knew their forwa...', 'teologico');
add('2co', 9, 6, 'Matthew Henry', 'Here we have,\nI. Proper directions to be observed about the right and acceptable manner of bestowing charity; and it is of great concernment that we not only do what is required, but do it as is commanded. Now, as to the manner in which the apostle would have the Corinthians give, observe, 1. It should be bountifully; this was intimated, Co2 9:5, that a liberal contribution was expected, a matter of bounty, not what savoured of covetousness; and he offers to their consideration that men who e...', 'teologico');
add('2co', 10, 1, 'Matthew Henry', 'Here we may observe,\nI. The mild and humble manner in which the blessed apostle addresses the Corinthians, and how desirous he is that no occasion may be given him to use severity. 1. He addresses them in a very mild and humble manner: I Paul myself beseech you, Co2 10:1. We find, in the introduction to this epistle, he joined Timothy with himself; but now he speaks only for himself, against whom the false apostles had particularly levelled their reproaches; yet in the midst of the greatest p...', 'teologico');
add('2co', 10, 7, 'Matthew Henry', 'In these verses the apostle proceeds to reason the case with the Corinthians, in opposition to those who despised him, judged him, and spoke hardly of him: "Do you," says he, "look on things after the outward appearance? Co2 10:7. Is this a fit measure or rule to make an estimate of things or persons by, and to judge between me and my adversaries?" In outward appearance, Paul was mean and despicable with some; he did not make a figure, as perhaps some of his competitors might do: but this was...', 'teologico');
add('2co', 10, 12, 'Matthew Henry', 'In these verses observe,\nI. The apostle refuses to justify himself, or to act by such rules as the false apostles did, Co2 10:12. He plainly intimates that they took a wrong method to commend themselves, in measuring themselves by themselves, and comparing themselves among themselves, which was not wise. They were pleased, and did pride themselves, in their own attainments, and never considered those who far exceeded them in gifts and graces, in power and authority; and this made them haughty...', 'teologico');
add('2co', 11, 1, 'Matthew Henry', 'Here we may observe, 1. The apology the apostle makes for going about to commend himself. He is loth to enter upon this subject of self-commendation: Would to God you could bear with me a little in my folly, Co2 11:1. He calls this folly, because too often it is really no better. In his case it was necessary; yet, seeing others might apprehend it to be folly in him, he desires them to bear with it. Note, As much against the grain as it is with a proud man to acknowledge his infirmities, so mu...', 'teologico');
add('2co', 11, 5, 'Matthew Henry', 'After the foregoing preface to what he was about to say, the apostle in these verses mentions,\nI. His equality with the other apostles - that he was not a whit behind the very chief of the apostles, Co2 11:5. This he expresses very modestly: I suppose so. He might have spoken very positively. The apostleship, as an office, was equal in all the apostles; but the apostles, like other Christians, differed one from another. These stars differed one from another in glory, and Paul was indeed of th...', 'teologico');
add('2co', 11, 16, 'Matthew Henry', 'Here we have a further excuse that the apostle makes for what he was about to say in his own vindication. 1. He would not have them think he was guilty of folly, in saying what he said to vindicate himself: Let no man think me a fool, Co2 11:16. Ordinarily, indeed, it is unbecoming a wise man to be much and often speaking in his own praise. Boasting of ourselves is usually not only a sign of a proud mind, but a mark of folly also. However, says the apostle, yet as a fool receive me; that is, ...', 'teologico');
add('2co', 11, 22, 'Matthew Henry', 'Here the apostle gives a large account of his own qualifications, labours, and sufferings (not out of pride or vain-glory, but to the honour of God, who had enabled him to do and suffer so much for the cause of Christ), and wherein he excelled the false apostles, who would lessen his character and usefulness among the Corinthians. Observe,\nI. He mentions the privileges of his birth (Co2 11:22), which were equal to any they could pretend to. He was a Hebrew of the Hebrews; of a family among th...', 'teologico');
add('2co', 12, 1, 'Matthew Henry', 'Here we may observe,\nI. The narrative the apostle gives of the favours God had shown him, and the honour he had done him; for doubtless he himself is the man in Christ of whom he speaks. Concerning this we may take notice, 1. Of the honour itself which was done to the apostle: he was caught up into the third heaven, Co2 12:2. When this was we cannot say, whether it was during those three days that he lay without sight at his conversion or at some other time afterwards, much less can we preten...', 'teologico');
add('2co', 12, 11, 'Matthew Henry', 'In these verses the apostle addresses himself to the Corinthians two ways: - \nI. He blames them for what was faulty in them; namely, that they had not stood up in his defence as they ought to have done, and so made it the more needful for him to insist so much on his own vindication. They in manner compelled him to commend himself, who ought to have been commended of them Co2 12:11. And had they, or some among them, not failed on their part, it would have been less needful for him to have sai...', 'teologico');
add('2co', 13, 1, 'Matthew Henry', 'In these verses observe,\nI. The apostle threatens to be severe against obstinate sinners when he should come to Corinth, having now sent to them a first and second epistle, with proper admonitions and exhortations, in order to reform what was amiss among them. Concerning this we may notice, 1. The caution with which he proceeded in his censures: he was not hasty in using severity, but gave a first and second admonition. So some understand his words (Co2 13:1): This is the third time I am comi...', 'teologico');
add('2co', 13, 7, 'Matthew Henry', 'Here we have,\nI. The apostle\'s prayer to God on the behalf of the Corinthians, that they might do no evil, Co2 13:7. This is the most desirable thing we can ask of God, both for ourselves and for our friends, to be kept from sin, that we and they may do no evil; and it is most needful that we often pray to God for his grace to keep us, because without this we cannot keep ourselves. We are more concerned to pray that we may not do evil than that we may not suffer evil.\nII. The reasons why the ...', 'teologico');
add('2co', 13, 11, 'Matthew Henry', 'Thus the apostle concludes this epistle with,\nI. A valediction. He gives them a parting farewell, and takes his leave of them for the present, with hearty good wishes for their spiritual welfare. In order to this,\n1. He gives them several good exhortations. (1.) To be perfect, or to be knit together in love, which would tend greatly to their advantage as a church, or Christian society. (2.) To be of good comfort under all the sufferings and persecutions they might endure for the cause of Chri...', 'teologico');

// GL (26 comentários)
add('gl', 2, 16, 'N.T. Wright', 'Justificados pela fé — A justificação é o veredicto divino: declarar justo.', 'teologico');
add('gl', 2, 20, 'João Crisóstomo', 'Fui crucificado — A identidade do crente: morto com Cristo, vivo por Cristo.', 'teologico');
add('gl', 3, 11, 'Lutero', 'Ninguém é justificado pela lei — A justificação é pela fé apenas: a lei não salva.', 'teologico');
add('gl', 3, 13, 'Calvino', 'Cristo nos resgatou — A maldade da lei é suportada por Cristo: maldição transformada em bênção.', 'teologico');
add('gl', 3, 28, 'N.T. Wright', 'Não há judeu nem grego — A igualdade no Cristo: todas as divisões são superadas na nova aliança.', 'teologico');
add('gl', 5, 1, 'Wesley', 'Libertai-vos — A liberdade cristã: não para o pecado, mas para o amor.', 'aplicacao');
add('gl', 5, 22, 'Tim Keller', 'Amor, gozo, paz — O fruto do Espírito é a personalidade de Cristo formada no crente.', 'aplicacao');
add('gl', 5, 23, 'Spurgeon', 'Contra estes não há lei — O fruto do Espírito transcende a lei: graça produz o que a lei exige.', 'teologico');
add('gl', 6, 14, 'Lloyd-Jones', 'Longe esteja de mim gloriarmo-se — A cruz é o único motivo de glória: o orgulho morre na cruz.', 'teologico');
add('gl', 1, 1, 'Matthew Henry', 'In these verses we have the preface or introduction to the epistle, where observe,\nI. The person or persons from whom this epistle is sent - from Paul an apostle, etc., and all the brethren that were with him. 1. The epistle is sent from Paul; he only was the penman of it. And, because there were some among the Galatians who endeavoured to lessen his character and authority, in the front of it he gives a general account both of his office and of the manner in which he was called to it, which ...', 'teologico');
add('gl', 1, 6, 'Matthew Henry', 'Here the apostle comes to the body of the epistle; and he begins it with a more general reproof of these churches for their unsteadiness in the faith, which he afterwards, in some following parts of it, enlarges more upon. Here we may observe,\nI. How much he was concerned at their defection: I marvel, etc. It filled him at once with the greatest surprise and sorrow. Their sin and folly were that they did not hold fast the doctrine of Christianity as it had been preached to them, but suffered ...', 'teologico');
add('gl', 1, 10, 'Matthew Henry', 'What Paul had said more generally, in the preface of this epistle, he now proceeds more particularly to enlarge upon. There he had declared himself to be an apostle of Christ; and here he comes more directly to support his claim to that character and office. There were some in the churches of Galatia who were prevailed with to call this in question; for those who preached up the ceremonial law did all they could to lessen Paul\'s reputation, who preached the pure gospel of Christ to the Gentil...', 'teologico');
add('gl', 2, 1, 'Matthew Henry', 'It should seem, by the account Paul gives of himself in this chapter, that, from the very first preaching and planting of Christianity, there was a difference of apprehension between those Christians who had first been Jews and those who had first been Gentiles. Many of those who had first been Jews retained a regard to the ceremonial law, and strove to keep up the reputation of that; but those who had first been Gentiles had no regard to the law of Moses, but took pure Christianity as perfec...', 'teologico');
add('gl', 2, 11, 'Matthew Henry', 'I. From the account which Paul gives of what passed between him and the other apostles at Jerusalem, the Galatians might easily discern both the falseness of what his enemies had insinuated against him and their own folly and weakness in departing from that gospel which he had preached to them. But to give the greater weight to what he had already said, and more fully to fortify them against the insinuations of the judaizing teachers, he acquaints them with another interview which he had with...', 'teologico');
add('gl', 3, 1, 'Matthew Henry', 'The apostle is here dealing with those who, having embraced the faith of Christ, still continued to seek for justification by the works of the law; that is, who depended upon their own obedience to the moral precepts as their righteousness before God, and, wherein that was defective, had recourse to the legal sacrifices and purifications to make it up. These he first sharply reproves, and then endeavours, by the evidence of truth, to convince them. This is the right method, when we reprove an...', 'teologico');
add('gl', 3, 6, 'Matthew Henry', 'The apostle having reproved the Galatians for not obeying the truth, and endeavoured to impress them with a sense of their folly herein, in these verses he largely proves the doctrine which he had reproved them for rejecting, namely, that of justification by faith without the works of the law. This he does several ways.\nI. From the example of Abraham\'s justification. This argument the apostle uses, Rom. 4. Abraham believed God, and that was accounted to him for righteousness (Gal 3:6); that i...', 'teologico');
add('gl', 3, 19, 'Matthew Henry', 'The apostle having just before been speaking of the promise made to Abraham, and representing that as the rule of our justification, and not the law, lest they should think he did too much derogate from the law, and render it altogether useless, he thence takes occasion to discourse of the design and tendency of it, and to acquaint us for what purposes it was given. It might be asked, "If that promise be sufficient for salvation, wherefore then serveth the law? Or, Why did God give the law by...', 'teologico');
add('gl', 4, 1, 'Matthew Henry', 'In this chapter the apostle deals plainly with those who hearkened to the judaizing teachers, who cried up the law of Moses in competition with the gospel of Christ, and endeavored to bring them under the bondage of it. To convince them of their folly, and to rectify their mistake herein, in these verses he prosecutes the comparison of a child under age, which he had touched upon in the foregoing chapter, and thence shows what great advantages we have now, under the gospel, above what they ha...', 'teologico');
add('gl', 4, 8, 'Matthew Henry', 'In these verses the apostle puts them in mind of what they were before their conversion to the faith of Christ, and what a blessed change their conversion had made upon them; and thence endeavours to convince them of their great weakness in hearkening to those who would bring them under the bondage of the law of Moses.\nI. He reminds them of their past state and behaviour, and what they were before the gospel was preached to them. Then they knew not God; they were grossly ignorant of the true ...', 'teologico');
add('gl', 4, 12, 'Matthew Henry', 'That these Christians might be the more ashamed of their defection from the truth of the gospel which Paul had preached to them, he here reminds them of the great affection they formerly had for him and his ministry, and puts them upon considering how very unsuitable their present behaviour was to what they then professed. And here we may observe,\nI. How affectionately he addresses himself to them. He styles them brethren, though he knew their hearts were in a great measure alienated from him...', 'teologico');
add('gl', 4, 17, 'Matthew Henry', 'The apostle is still carrying on the same design as in the foregoing verse, which was, to convince the Galatians of their sin and folly in departing from the truth of the gospel: having just before been expostulating with them about the change of their behaviour towards him who endeavoured to establish them in it, he here gives them the character of those false teachers who made it their business to draw them away from it, which if they would attend to, they might soon see how little reason t...', 'teologico');
add('gl', 4, 19, 'Matthew Henry', 'That the apostle might the better dispose these Christians to bear with him in the reproofs which he was obliged to give them, he here expresses his great affection to them, and the very tender concern he had for their welfare: he was not like them - one thing when among them and another when absent from them. Their disaffection to him had not removed his affection from them; but he still bore the same respect to them which he had formerly done, nor was he like their false teachers, who prete...', 'teologico');
add('gl', 4, 21, 'Matthew Henry', 'In these verses the apostle illustrates the difference between believers who rested in Christ only and those judaizers who trusted in the law, by a comparison taken from the story of Isaac and Ishmael. This he introduces in such a manner as was proper to strike and impress their minds, and to convince them of their great weakness in departing from the truth, and suffering themselves to be deprived of the liberty of the gospel: Tell me, says he, you that desire to be under the law, do you not ...', 'teologico');
add('gl', 5, 13, 'Matthew Henry', 'In the latter part of this chapter the apostle comes to exhort these Christians to serious practical godliness, as the best antidote against the snares of the false teachers. Two things especially he presses upon them: - \nI. That they should not strive with one another, but love one another. He tells them (Gal 5:13) that they had been called unto liberty, and he would have them to stand fast in the liberty wherewith Christ had made them free; but yet he would have them be very careful that th...', 'teologico');
add('gl', 6, 1, 'Matthew Henry', 'The apostle having, in the foregoing chapter, exhorted Christians by love to serve one another (Gal 6:13), and also cautioned us (Gal 6:16) against a temper which, if indulged, would hinder us from showing the mutual love and serviceableness which he had recommended, in the beginning of this chapter he proceeds to give some further directions, which, if duly observed, would both promote the one and prevent the other of these, and render our behaviour both more agreeable to our Christian profe...', 'teologico');
add('gl', 6, 11, 'Matthew Henry', 'The apostle, having at large established the doctrine of the gospel, and endeavoured to persuade these Christians to a behaviour agreeable to it, seems as if he intended here to have put an end to the epistle, especially when he had acquainted them that, as a particular mark of his respect for them, he had written this large letter with his own hand, and had not made use of another as his amanuensis, and only subscribed his name to it, as he was wont to do in his other epistles: but such is h...', 'teologico');

// EF (29 comentários)
add('ef', 1, 4, 'Tomás de Aquino', 'Ele nos escolheu — A escolha divina é anterior aos méritos: graça pura.', 'teologico');
add('ef', 1, 5, 'Barth', 'Predestinados — O propósito eterno de Deus: adoção em Cristo por amor.', 'teologico');
add('ef', 2, 4, 'João Crisóstomo', 'Deus, sendo rico — A riqueza da misericórdia: Deus nos deu vida quando estávamos mortos.', 'teologico');
add('ef', 2, 5, 'Spurgeon', 'Deus nos vivificou — A regeneração é ato soberano: Deus nos dá vida espiritual.', 'teologico');
add('ef', 2, 8, 'Calvino', 'Não vem de vós — Nem a fé, nem a salvação são produtos do esforço humano. Tudo é dom de Deus.', 'gramatical');
add('ef', 2, 9, 'Wesley', 'Para que ninguém se glorie — O plano da salvação exclui qualquer motivo de vanglória humana.', 'aplicacao');
add('ef', 2, 10, 'N.T. Wright', 'Somos feitura sua — A graça precede a obra: somos criados em Cristo para boas obras.', 'teologico');
add('ef', 3, 17, 'R.C. Sproul', 'Habitando o Cristo pela fé — A habitação interior de Cristo: presença transformadora.', 'teologico');
add('ef', 3, 19, 'Adam Clarke', 'Encher-vos de toda a plenitude — A plenitude de Deus: capacidade divina no crente.', 'teologico');
add('ef', 6, 10, 'Calvino', 'Fortalecei-vos — A bateria espiritual: para a guerra espiritual, o poder vem de Deus.', 'teologico');
add('ef', 6, 11, 'Lloyd-Jones', 'Armados — A armadura é completa: cada peça representa uma verdade fundamental.', 'aplicacao');
add('ef', 6, 16, 'Spurgeon', 'Escudo da fé — A fé é o escudo que apaga as setas do maligno.', 'aplicacao');
add('ef', 6, 17, 'Tim Keller', 'Espírito do qual é a palavra — A Palavra de Deus é ofensiva na guerra espiritual.', 'aplicacao');
add('ef', 1, 1, 'Matthew Henry', 'Here is, 1. The title St. Paul takes to himself, as belonging to him - Paul, an apostle of Jesus Christ, etc. He reckoned it a great honour to be employed by Christ, as one of his messengers to the sons of men. The apostles were prime officers in the Christian church, being extraordinary ministers appointed for a time only. They were furnished by their great Lord with extraordinary gifts and the immediate assistance of the Spirit, that they might be fitted for publishing and spreading the gos...', 'teologico');
add('ef', 1, 3, 'Matthew Henry', 'He begins with thanksgivings and praise, and enlarges with a great deal of fluency and copiousness of affection upon the exceedingly great and precious benefits which we enjoy by Jesus Christ. For the great privileges of our religion are very aptly recounted and enlarged upon in our praises to God.\nI. In general he blesses God for spiritual blessings, Eph 1:3, where he styles him the God and Father of our Lord Jesus Christ; for, as Mediator, the Father was his God; as God, and the second pers...', 'teologico');
add('ef', 1, 15, 'Matthew Henry', 'We have come to the last part of this chapter, which consists of Paul\'s earnest prayer to God in behalf of these Ephesians. We should pray for the persons for whom we give thanks. Our apostle blesses God for what he had done for them, and then he prays that he would do more for them. He gives thanks for spiritual blessings, and prays for further supplies of them; for God will for this be enquired of by the house of Israel, to do it for them. He has laid up these spiritual blessings for us in ...', 'teologico');
add('ef', 2, 1, 'Matthew Henry', 'The miserable condition of the Ephesians by nature is here in part described. Observed, 1. Unregenerate souls are dead in trespasses and sins. All those who are in their sins, are dead in sins; yea, in trespasses and sins, which may signify all sorts of sins, habitual and actual, sins of heart and of life. Sin is the death of the soul. Wherever that prevails there is a privation of all spiritual life. Sinners are dead in state, being destitute of the principles, and powers of spiritual life; ...', 'teologico');
add('ef', 2, 11, 'Matthew Henry', 'In these verses the apostle proceeds in his account of the miserable condition of these Ephesians by nature. Wherefore remember, etc., Eph 2:11. As if he had said, "You should remember what you have been, and compare it with what you now are, in order to humble yourselves and to excite your love and thankfulness to God." Note, Converted sinners ought frequently to reflect upon the sinfulness and misery of the state they were in by nature. Gentiles in the flesh, that is, living in the corrupti...', 'teologico');
add('ef', 2, 14, 'Matthew Henry', 'We have now come to the last part of the chapter, which contains an account of the great and mighty privileges that converted Jews and Gentiles both receive from Christ. The apostle here shows that those who were in a state of enmity are reconciled. Between the Jews and the Gentiles there had been a great enmity; so there is between God and every unregenerate man. Now Jesus Christ is our peace, Eph 2:14. He made peace by the sacrifice of himself; and came to reconcile, 1. Jews and Gentiles to...', 'teologico');
add('ef', 3, 1, 'Matthew Henry', 'Here we have the account which Paul gives the Ephesians concerning himself, as he was appointed by God the apostle of the Gentiles.\nI. We may observe that he acquaints them with the tribulations and sufferings which he endured in the discharge of that office, Eph 3:1. The first clause refers to the preceding chapter, and may be understood either of these two ways: - 1. "For this cause, - for having preached the doctrine contained in the foregoing chapter, and for asserting that the great priv...', 'teologico');
add('ef', 3, 14, 'Matthew Henry', 'We now come to the second part of this chapter, which contains Paul\'s devout and affectionate prayer to God for his beloved Ephesians. - For this cause. This may be referred either to the immediately foregoing verse, That you faint not, etc., or, rather, the apostle is here resuming what he began at the first verse, from which he digressed in those which are interposed. Observe,\nI. To whom he prays - to God, as the Father of our Lord Jesus Christ, of which see Eph 1:3.\nII. His outward posture...', 'teologico');
add('ef', 4, 1, 'Matthew Henry', 'This is a general exhortation to walk as becomes our Christian profession. Paul was now a prisoner at Rome; and he was the prisoner of the Lord, or in the Lord, which signifies as much as for the Lord. See of this, Eph 3:1. He mentions this once and again, to show that he was not ashamed of his bonds, well knowing that he suffered not as an evil doer: and likewise to recommend what he wrote to them with the greater tenderness and with some special advantage. It was a doctrine he thought worth...', 'teologico');
add('ef', 4, 2, 'Matthew Henry', 'Here the apostle proceeds to more particular exhortations. Two he enlarges upon in this chapter: - To unity an love, purity and holiness, which Christians should very much study. We do not walk worthy of the vocation wherewith we are called if we be not faithful friends to all Christians, and sworn enemies to all sin.\nThis section contains the exhortation to mutual love, unity, and concord, with the proper means and motives to promote them. Nothing is pressed upon us more earnestly in the scr...', 'teologico');
add('ef', 4, 17, 'Matthew Henry', 'The apostle having gone through his exhortation to mutual love, unity, and concord, in the foregoing verses, there follows in these an exhortation to Christian purity and holiness of heart and life, and that both more general (Eph 4:17-24) and in several particular instances, Eph 4:25-32. This is solemnly introduced: "This I say therefore, and testify in the Lord; that is, seeing the matter is as above described, seeing you are members of Christ\'s body and partakers of such gifts, this I urge...', 'teologico');
add('ef', 5, 1, 'Matthew Henry', 'Here we have the exhortation to mutual love, or to Christian charity. The apostle had been insisting on this in the former chapter, and particularly in the last verses of it, to which the particle therefore refers, and connects what he had said there with what is contained in these verses, thus: "Because God, for Christ\'s sake, has forgiven you, therefore be you followers of God, or imitators of him;" for so the word signifies. Pious persons should imitate the God whom they worship, as far as...', 'teologico');
add('ef', 5, 3, 'Matthew Henry', 'These verses contain a caution against all manner of uncleanness, with proper remedies and arguments proposed: some further cautions are added, and other duties recommended. Filthy lusts must be suppressed, in order to the supporting of holy love. Walk in love, and shun fornication and all uncleanness. Fornication is folly committed between unmarried persons. All uncleanness includes all other sorts of filthy lusts, which were too common among the Gentiles. Or covetousness, which being thus c...', 'teologico');
add('ef', 5, 21, 'Matthew Henry', 'Here the apostle begins his exhortation to the discharge of relative duties. As a general foundation for these duties, he lays down that rule Eph 5:21. There is a mutual submission that Christians owe one to another, condescending to bear one another\'s burdens: not advancing themselves above others, nor domineering over one another and giving laws to one another. Paul was an example of this truly Christian temper, for he became all things to all men. We must be of a yielding and of a submissi...', 'teologico');
add('ef', 6, 1, 'Matthew Henry', 'Here we have further directions concerning relative duties, in which the apostle is very particular.\nI. The duty of children to their parents. Come, you children, hearken to me, I will teach you the fear of the Lord. The great duty of children is to obey their parents (Eph 6:1), parents being the instruments of their being, God and nature having given them an authority to command, in subserviency to God; and, if children will be obedient to their pious parents, they will be in a fair way to b...', 'teologico');
add('ef', 6, 19, 'Matthew Henry', 'Here, I. He desires their prayers for him, Eph 6:19. Having mentioned supplication for all saints, he puts himself into the number. We must pray for all saints, and particularly for God\'s faithful ministers. Brethren, pray for us, that the word of the Lord may run and be glorified. Observe what it is he would have them pray for in his behalf: "That utterance may be given unto me; that I may be enlarged from my present restraints, and so have liberty to propagate the faith of Christ; that I ma...', 'teologico');

// FP (10 comentários)
add('fp', 1, 6, 'John Stott', 'Até o dia — A segurança da salvação: Deus completa o que começa.', 'teologico');
add('fp', 2, 5, 'Calvino', 'Que haja em vós este sentimento — O exemplo de Cristo: humilhação seguida de exaltação.', 'teologico');
add('fp', 2, 6, 'Atanásio', 'Que, sendo em forma de Deus — Cristo é verdadeiramente Deus, não uma representação. Sua natureza divina é real.', 'teologico');
add('fp', 2, 7, 'Tomás de Aquino', 'Esquizu-se — A kenose não é perda de divindade, mas assumir a condição de servo.', 'teologico');
add('fp', 2, 8, 'Barth', 'Até a morte de cruz — A humilhação de Cristo atinge seu ponto mais baixo na cruz.', 'cultural');
add('fp', 2, 9, 'Spurgeon', 'Deus o exaltou supremamente — A exaltação de Cristo: todo joelho se dobrará.', 'escatologico');
add('fp', 2, 10, 'João Crisóstomo', 'Todo joelo se dobre — A adoração cósmica: toda criatura reconhece a soberania de Cristo.', 'teologico');
add('fp', 4, 6, 'Albert Barnes', 'Em tudo, pela oração — A oração em todas as circunstâncias: o antídoto contra a ansiedade.', 'aplicacao');
add('fp', 4, 7, 'Spurgeon', 'Paz de Deus — A paz sobrenatural guarda o coração e a mente.', 'aplicacao');
add('fp', 4, 13, 'Lloyd-Jones', 'Tudo posso — Não é autoconfiança, mas confiança na suficiência de Cristo.', 'aplicacao');

// CL (24 comentários)
add('cl', 1, 15, 'Calvino', 'Imagem do Deus invisível — Cristo é a revelação perfeita de Deus: imagem do Pai.', 'teologico');
add('cl', 1, 16, 'Atanásio', 'Todas as coisas foram criadas — A preexistência de Cristo: tudo foi feito por Ele e para Ele.', 'teologico');
add('cl', 1, 17, 'Barth', 'Ele é antes de todas as coisas — A sustentação cósmica: tudo subsiste nele.', 'teologico');
add('cl', 1, 18, 'Charles Ellicott', 'Ele é o princípio — Cristo é a cabeça da igreja: prioridade e autoridade.', 'teologico');
add('cl', 1, 20, 'N.T. Wright', 'Reconciliar — O plano cósmico: Deus não salva apenas almas, mas toda a criação.', 'escatologico');
add('cl', 2, 9, 'Tomás de Aquino', 'Nele habita toda a plenitude — A plenitude da divindade em Cristo: Ele é verdadeiramente Deus.', 'teologico');
add('cl', 3, 23, 'Wesley', 'Tudo o que fizerdes — A ética do trabalho cristão: servir ao Senhor, não aos homens.', 'aplicacao');
add('cl', 1, 1, 'Matthew Henry', 'I. The inscription of this epistle is much the same with the rest; only it is observable that, 1. He calls himself an apostle of Jesus Christ by the will of God. An apostle is a prime-minister in the kingdom of Christ, immediately called by Christ, and extraordinarily qualified; his work was peculiarly to plant the Christian church, and confirm the Christian doctrine. He attributes this not to his own merit, strength, or sufficiency; but to the free grace and good-will of God. He thought hims...', 'teologico');
add('cl', 1, 3, 'Matthew Henry', 'Here he proceeds to the body of the epistle, and begins with thanksgiving to God for what he had heard concerning them, though he had no personal acquaintance with them, and knew their state and character only by the reports of others.\nI. He gave thanks to God for them, that they had embraced the gospel of Christ, and given proofs of their fidelity to him. Observe, In his prayers for them he gave thanks for them. Thanksgiving ought to be a part of every prayer; and whatever is the matter of o...', 'teologico');
add('cl', 1, 9, 'Matthew Henry', 'The apostle proceeds in these verses to pray for them. He heard that they were good, and he prayed that they might be better. He was constant in this prayer: We do not cease to pray for you. It may be he could hear of them but seldom, but he constantly prayed for them. - And desire that you may be filled with the knowledge, etc. Observe what it is that he begs of God for them,\nI. That they might be knowing intelligent Christians: filled with the knowledge of his will, in all wisdom and spirit...', 'teologico');
add('cl', 1, 12, 'Matthew Henry', 'Here is a summary of the doctrine of the gospel concerning the great work of our redemption by Christ. It comes in here not as the matter of a sermon, but as the matter of a thanksgiving; for our salvation by Christ furnishes us with abundant matter of thanksgiving in every view of it: Giving thanks unto the Father, Col 1:12. He does not discourse of the work of redemption in the natural order of it; for then he would speak of the purchase of it first, and afterwards of the application of it....', 'teologico');
add('cl', 2, 1, 'Matthew Henry', 'We may observe here the great concern which Paul had for these Colossians and the other churches which he had not any personal knowledge of. The apostle had never been at Colosse, and the church planted there was not of his planting; and yet he had as tender a care of it as if it had been the only people of his charge (Col 2:1): For I would that you knew what great conflict I have for you, and for those at Laodicea, and for as many as have not seen my face in the flesh. Observe, 1. Paul\'s car...', 'teologico');
add('cl', 2, 4, 'Matthew Henry', 'The apostle cautions the Colossians against deceivers (Col 2:4): And this I say lest any man beguile you with enticing words; and Col 2:8, Lest any man spoil you. He insists so much upon the perfection of Christ and the gospel revelation, to preserve them from the ensnaring insinuations of those who would corrupt their principles. Note, 1. The way in which Satan spoils souls is by beguiling them. He deceives them, and by this means slays them. He is the old serpent who beguiled Eve through hi...', 'teologico');
add('cl', 2, 13, 'Matthew Henry', 'The apostle here represents the privileges we Christians have above the Jews, which are very great.\nI. Christ\'s death is our life: And you, being dead in your sins and the uncircumcision of your flesh, hath he quickened together with him, Col 2:13. A state of sin is a state of spiritual death. Those who are in sin are dead in sin. As the death of the body consists in its separation from the soul, so the death of the soul consists in its separation from God and the divine favour. As the death ...', 'teologico');
add('cl', 2, 16, 'Matthew Henry', 'The apostle concludes the chapter with exhortations to proper duty, which he infers from the foregoing discourse.\nI. Here is a caution to take heed of judaizing teachers, or those who would impose upon Christians the yoke of the ceremonial law: Let no man therefore judge you in meat nor drink, etc., Col 2:16. Much of the ceremonies of the law of Moses consisted in the distinction of meats and days. It appears by Rom. 14 that there were those who were for keeping up those distinctions: but her...', 'teologico');
add('cl', 3, 1, 'Matthew Henry', 'The apostle, having described our privileges by Christ in the former part of the epistle, and our discharge from the yoke of the ceremonial law, comes here to press upon us our duty as inferred thence. Though we are made free from the obligation of the ceremonial law, it does not therefore follow that we may live as we list. We must walk the more closely with God in all the instances of evangelical obedience. He begins with exhorting them to set their hearts on heaven, and take them off from ...', 'teologico');
add('cl', 3, 5, 'Matthew Henry', 'The apostle exhorts the Colossians to the mortification of sin, the great hindrance to seeking the things which are above. Since it is our duty to set our affections upon heavenly things, it is our duty to mortify our members which are upon the earth, and which naturally incline us to the things of the world: "Mortify them, that is, subdue the vicious habits of mind which prevailed in your Gentile state. Kill them, suppress them, as you do weeds or vermin which spread and destroy all about th...', 'teologico');
add('cl', 3, 8, 'Matthew Henry', 'As we are to mortify inordinate appetites, so we are to mortify inordinate passions (Col 3:8): But now you also put off all these, anger wrath, malice; for these are contrary to the design of the gospel, as well as grosser impurities; and, though they are more spiritual wickedness, have not less malignity in them. The gospel religion introduces a change of the higher as well as the lower powers of the soul, and supports the dominion of right reason and conscience over appetite and passion. An...', 'teologico');
add('cl', 3, 12, 'Matthew Henry', 'The apostle proceeds to exhort to mutual love and compassion: Put on therefore bowels of mercy, Col 3:12. We must not only put off anger and wrath (as Col 3:8), but we must put on compassion and kindness; not only cease to do evil, but learn to do well; not only not do hurt to any, but do what good we can to all.\nI. The argument here used to enforce the exhortation is very affecting: Put on, as the elect of God, holy and beloved. Observe, 1. Those who are holy are the elect of God; and those ...', 'teologico');
add('cl', 3, 18, 'Matthew Henry', 'The apostle concludes the chapter with exhortations to relative duties, as before in the epistle to the Ephesians. The epistles which are most taken up in displaying the glory of divine grace, and magnifying the Lord Jesus, are the most particular and distinct in pressing the duties of the several relations. We must never separate the privileges and duties of the gospel religion.\nI. He begins with the duties of wives and husbands (Col 3:18): Wives, submit yourselves unto your own husbands, as...', 'teologico');
add('cl', 4, 1, 'Matthew Henry', 'The apostle proceeds with the duty of masters to their servants, which might have been joined to the foregoing chapter, and is a part of that discourse. Here observe, 1. Justice is required of them: Give unto your servants that which is just and equal (Col 4:1), not only strict justice, but equity and kindness. Be faithful to your promises to them, and perform your agreements; not defrauding them of their dues, nor keeping back by fraud the hire of the labourers, Jam 5:4. Require no more of t...', 'teologico');
add('cl', 4, 2, 'Matthew Henry', 'If this be considered as connected with the foregoing verse, then we may observe that it is part of the duty which masters owe their servants to pray with them, and to pray daily with them, or continue in prayer. They must not only do justly and kindly by them, but act a Christian and religious part, and be concerned for their souls as well as their bodies: "As parts of your charge, and under your influence, be concerned for the blessing of God upon them, as well as the success of your affair...', 'teologico');
add('cl', 4, 5, 'Matthew Henry', 'The apostle exhorts them further to a prudent and decent conduct towards all those with whom they conversed, towards the heathen world, or those out of the Christian church among whom they lived (Col 4:5): Walk in wisdom towards those who are without. Be careful, in all your converse with them, to get no hurt by them, or contract any of their customs; for evil communications corrupt good manners; and to do not hurt to them, or increase their prejudices against religion, and give them an occas...', 'teologico');
add('cl', 4, 7, 'Matthew Henry', 'In the close of this epistle the apostle does several of his friends the honour to leave their names upon record, with some testimony of his respect, which will be spoken of wherever the gospel comes, and last to the end of the world.\nI. Concerning Tychicus, Col 4:7. By him this epistle was sent; and he does not give them an account in writing of his present state, because Tychicus would do it by word of mouth more fully and particularly. He knew they would be glad to hear how it fared with h...', 'teologico');

// 1TS (18 comentários)
add('1ts', 4, 13, 'Calvino', 'Não vos entristeçais como os demais — A esperança da ressurreição transforma o luto dos crentes.', 'escatologico');
add('1ts', 5, 16, 'João Crisóstomo', 'Orai sem cessar — A oração contínua é atitude de dependência, não apenas atos isolados.', 'aplicacao');
add('1ts', 1, 1, 'Matthew Henry', 'In this introduction we have,\nI. The inscription, where we have, 1. The persons from whom this epistle came, or by whom it was written. Paul was the inspired apostle and writer of this epistle, though he makes no mention of his apostleship, which was not doubted of by the Thessalonians, nor opposed by any false apostle among them. He joins Silvanus (or Silas) and Timotheus with himself (who had now come to him with an account of the prosperity of the churches in Macedonia), which shows this g...', 'teologico');
add('1ts', 1, 2, 'Matthew Henry', 'I. The apostle begins with thanksgiving to God. Being about to mention the things that were matter of joy to him, and highly praiseworthy in them, and greatly for their advantage, he chooses to do this by way of thanksgiving to God, who is the author of all that good that comes to us, or is done by us, at any time. God is the object of all religious worship, of prayer and praise. And thanksgiving to God is a great duty, to be performed always or constantly; even when we do not actually give t...', 'teologico');
add('1ts', 1, 6, 'Matthew Henry', 'In these words we have the evidence of the apostle\'s success among the Thessalonians, which was notorious and famous in several places. For,\nI. They were careful in their holy conversation to imitate the good examples of the apostles and ministers of Christ, Th1 1:6. As the apostle took care to demean himself well, not only for his own credit\'s sake, but for the benefit of others, by a conversation suitable to his doctrine, that he might not pull down with one hand what he built up with the o...', 'teologico');
add('1ts', 2, 1, 'Matthew Henry', 'Here we have an account of Paul\'s manner of preaching, and his comfortable reflection upon his entrance in among the Thessalonians. As he had the testimony of his own conscience witnessing to his integrity, so he could appeal to the Thessalonians how faithful he, and Silas, and Timotheus, his helpers in the work of the Lord, had discharged their office: You yourselves, brethren, know our entrance in unto you. Note, It is a great comfort to a minister to have his own conscience and the conscie...', 'teologico');
add('1ts', 2, 7, 'Matthew Henry', 'In these words the apostle reminds the Thessalonians of the manner of his conversation among them. And,\nI. He mentions the gentleness of their behaviour: We were gentle among you, Th1 2:7. He showed great mildness and tenderness who might have acted with the authority of an apostle of Christ. Such behaviour greatly recommends religion, and is most agreeable to God\'s gracious dealing with sinners, in and by the gospel. This great apostle, though he abhorred and avoided flattery, was most conde...', 'teologico');
add('1ts', 2, 13, 'Matthew Henry', 'Here observe, I. The apostle makes mention of the success of his ministry among these Thessalonians (Th1 2:13), which is expressed,\n1. By the manner of their receiving the word of God: When you received the word of God, which you heard of us, you received it, not as the word of men, but (as it is in truth) the word of God. Where note, (1.) The word of the gospel is preached by men like ourselves, men of like passions and infirmities with others: We have this treasure in earthen vessels. The w...', 'teologico');
add('1ts', 2, 17, 'Matthew Henry', 'In these words the apostle apologizes for his absence. Here observe, 1. He tells them they were involuntarily forced from them: We, brethren, were taken from you, Th1 2:17. Such was the rage of his persecutors. He was unwillingly sent away by night to Berea, Act 17:10. 2. Though he was absent in body, yet he was present in heart. He had still a remembrance of them, and great care for them. 3. Even his bodily absence was but for a short time, the time of an hour. Time is short, all our time on...', 'teologico');
add('1ts', 3, 1, 'Matthew Henry', 'In these words the apostle gives an account of his sending Timothy to the Thessalonians. Though he was hindered from going to them himself, yet his love was such that he could not forbear sending Timothy to them. Though Timothy was very useful to him, and he could not well spare him, yet Paul was content, for their good, to be left alone at Athens. Note, Those ministers do not duly value the establishment and welfare of their people who cannot deny themselves in many things for that end. Obse...', 'teologico');
add('1ts', 3, 6, 'Matthew Henry', 'Here we have Paul\'s great satisfaction upon the return of Timothy with good tidings from the Thessalonians, in which we may observe,\nI. The good report Timothy made concerning them, Th1 3:6. Without question, he was a willing messenger of these good tidings. Concerning their faith, that is, concerning their stedfastness in the faith, that they were not shaken in mind, nor turned aside form the profession of the gospel. Their love also continued; their love to the gospel, and the ministers of ...', 'teologico');
add('1ts', 3, 11, 'Matthew Henry', 'In these words we have the earnest prayer of the apostle. He desired to be instrumental in the further benefit of the Thessalonians; and the only way to be so while at a distance was by prayer for them, together with his writing or sending to them. He desired that their faith might be perfected, which he could not be the proper cause or author of; for he pretended not to dominion over their faith, nor to have the donation of it, and he therefore concludes with prayer for them. Observe,\nI. Who...', 'teologico');
add('1ts', 4, 1, 'Matthew Henry', 'Here we have,\nI. An exhortation to abound in holiness, to abound more and more in that which is good, Th1 4:1, Th1 4:2. We may observe,\n1. The manner in which the exhortation is given - very affectionately. The apostle entreats them as brethren; he calls them so, and loved them as such. Because his love to them was very great, he exhorts them very earnestly: We beseech and exhort you. The apostle was unwilling to take any denial, and therefore repeats his exhortation again and again.\n2. The m...', 'teologico');
add('1ts', 4, 9, 'Matthew Henry', 'In these words the apostle mentions the great duties,\nI. Of brotherly love. This he exhorts them to increase in yet more and more. The exhortation is introduced, not with a compliment, but with a commendation, because they were remarkable in the exercise of it, which made it less needful that he should write to them about it, Th1 4:9. Thus by his good opinion of them he insinuated himself into their affections, and so made way for his exhortation to them. Note, We should take notice of that i...', 'teologico');
add('1ts', 5, 1, 'Matthew Henry', 'In these words observe,\nI. The apostle tells the Thessalonians it was needless or useless to enquire about the particular time of Christ\'s coming: Of the times and seasons you need not that I write unto you, Th1 5:1. The thing is certain that Christ will come, and there is a certain time appointed for his coming; but there was no need that the apostle should write about this, and therefore he had no revelation given him; nor should they or we enquire into this secret, which the Father has res...', 'teologico');
add('1ts', 5, 6, 'Matthew Henry', 'On what had been said, the apostle grounds seasonable exhortations to several needful duties.\nI. To watchfulness and sobriety, Th1 5:6. These duties are distinct, yet they mutually befriend one another. For, while we are compassed about with so many temptations to intemperance and excess, we shall not keep sober, unless we be upon our guard, and, unless we keep sober, we shall not long watch. 1. Then let us not sleep as do others, but let us watch; we must not be secure and careless, nor indu...', 'teologico');
add('1ts', 5, 11, 'Matthew Henry', 'In these words the apostle exhorts the Thessalonians to several duties.\nI. Towards those who were nearly related one to another. Such should comfort themselves, or exhort one another, and edify one another, Th1 5:11. 1. They must comfort or exhort themselves and one another; for the original word may be rendered both these ways. And we may observe, As those are most able and likely to comfort others who can comfort themselves, so the way to have comfort ourselves, or to administer comfort to ...', 'teologico');
add('1ts', 5, 23, 'Matthew Henry', 'In these words, which conclude this epistle, observe,\nI. Paul\'s prayer for them, Th1 5:23. He had told them, in the beginning of this epistle, that he always made mention of them in his prayers; and, now that he is writing to them, he lifts up his heart to God in prayer for them. Take notice, 1. To whom the apostle prays, namely, The very God of peace. He is the God of grace, and the God of peace and love. He is the author of peace and lover of concord; and by their peaceableness and unity, f...', 'teologico');

// 2TS (10 comentários)
add('2ts', 2, 3, 'Calvino', 'O homem da perdição — A apostasia precederá a vinda do Senhor; discernimento é necessário.', 'escatologico');
add('2ts', 3, 16, 'João Crisóstomo', 'O Senhor da paz vos dê paz — A paz de Cristo guarda a igreja em toda circunstância.', 'teologico');
add('2ts', 1, 1, 'Matthew Henry', 'Here we have,\nI. The introduction (Th2 1:1, Th2 1:2), in the same words as in the former epistle, from which we may observe that as this apostle did not count it grievous to him to write the same things (Phi 3:1) in his epistles that he had delivered in preaching, so he willingly wrote the same things to one church that he did to another. The occurrence of the same words in this epistle as in the former shows us that ministers ought not so much to regard the variety of expression and elegance...', 'teologico');
add('2ts', 1, 5, 'Matthew Henry', 'Having mentioned their persecutions and tribulations, which they endured principally for the cause of Christ, the apostle proceeds to offer several things for their comfort under them; as,\nI. He tells them of the present happiness and advantage of their sufferings, Th2 1:5. Their faith being thus tried, and patience exercised, they were improved by their sufferings, insomuch that they were counted worthy of the kingdom of God. Their sufferings were a manifest token of this, that they were wor...', 'teologico');
add('2ts', 1, 11, 'Matthew Henry', 'In these verses the apostle again tells the Thessalonians of his earnest and constant prayer for them. He could not be present with them, yet he had a constant remembrance of them; they were much upon his thoughts; he wished them well, and could not express his good-will and good wishes to them better than in earnest constant prayer to God for them: Wherefore also we pray, etc. Note, The believing thoughts and expectation of the second coming of Christ should put us upon prayer to God for our...', 'teologico');
add('2ts', 2, 1, 'Matthew Henry', 'From these words it appears that some among the Thessalonians had mistaken the apostle\'s meaning, in what he had written in his former epistle about the coming of Christ, by thinking that it was near at hand, - that Christ was just ready to appear and come to judgment. Or, it may be, some among them pretended that they had the knowledge of this by particular revelation from the Spirit, or from some words they had heard from the apostle, when he was with them, or some letter he had written or ...', 'teologico');
add('2ts', 2, 13, 'Matthew Henry', 'Here observe, I. The consolation the Thessalonians might take against the terrors of this apostasy, Th2 2:13, Th2 2:14. For they were chosen to salvation, and called to the obtaining of glory. Note, When we hear of the apostasy of many, it is matter of great comfort and joy that there is a remnant according to the election of grace which does and shall persevere; and especially we should rejoice if we have reason to hope that we are of that number. The apostle reckoned himself bound in duty t...', 'teologico');
add('2ts', 2, 16, 'Matthew Henry', 'In these words we have the apostle\'s earnest prayer for them, in which observe,\nI. To whom he prays: Our Lord Jesus Christ himself, and God, even our Father. We may and should direct our prayers, not only to God the Father, through the mediation of our Lord Jesus Christ, but also to our Lord Jesus Christ himself; and should pray in his name unto God, not only as his Father but as our Father in and through him.\nII. From what he takes encouragement in his prayer - from the consideration of what...', 'teologico');
add('2ts', 3, 1, 'Matthew Henry', 'In these words observe,\nI. The apostle desires the prayers of his friends: Finally, brethren, pray for us, Th2 3:1. He always remembered them in his prayers, and would not have them forget him and his fellow-labourers, but bear them on their hearts at the throne of grace. Note, 1. This is one way by which the communion of saints is kept us, not only by their praying together, or with one another, but by their praying for one another when they are absent one from another. And thus those who ar...', 'teologico');
add('2ts', 3, 6, 'Matthew Henry', 'The apostle having commended their obedience for the time past, and mentioned his confidence in their obedience for the time to come, proceeds to give them commands and directions to some who were faulty, correcting some things that were amiss among them. Observe, The best society of Christians may have some faulty persons among them, and some things that ought to be reformed. Perfection is not to be found on this side heaven: but evil manners beget good laws; the disorders that Paul heard of...', 'teologico');

// 1TM (19 comentários)
add('1tm', 2, 5, 'Calvino', 'Um só Mediador — Cristo é o único intermediário entre Deus e os homens.', 'teologico');
add('1tm', 3, 16, 'Atanásio', 'Deus se manifestou em carne — O mistério da encarnação: piedade grandiosa.', 'teologico');
add('1tm', 1, 1, 'Matthew Henry', 'Here is, I. The inscription of the epistle, from whom it is sent: Paul an apostle of Jesus Christ, constituted an apostle by the commandment of God our Saviour, and Lord Jesus Christ. His credentials were unquestionable. He had not only a commission, but a commandment, not only from God our Saviour, but from Jesus Christ: he was a preacher of the gospel of Christ, and a minister of the kingdom of Christ. Observe, God is our Saviour. - Jesus Christ, who is our hope. Observe, Jesus Christ is a ...', 'teologico');
add('1tm', 1, 5, 'Matthew Henry', 'Here the apostle instructs Timothy how to guard against the judaizing teachers, or others who mingled fables and endless genealogies with the gospel. He shows the use of the law, and the glory of the gospel.\nI. He shows the end and uses of the law: it is intended to promote love, for love is the fulfilling of the law, Rom 13:10.\n1. The end of the commandment is charity, or love, Rom 13:8. The main scope and drift of the divine law are to engage us to the love of God and one another; and whate...', 'teologico');
add('1tm', 1, 12, 'Matthew Henry', 'Here the apostle, I. Returns thanks to Jesus Christ for putting him into the ministry. Observe, 1. It is Christ\'s work to put men into the ministry, Act 26:16, Act 26:17. God condemned the false prophets among the Jews in these words, I have not sent these prophets, yet they ran: I have not spoken to them, yet they prophesied, Jer 23:21. Ministers, properly speaking, cannot make themselves ministers; for it is Christ\'s work, as king and head, prophet and teacher, of his church. 2. Those whom ...', 'teologico');
add('1tm', 1, 18, 'Matthew Henry', 'Here is the charge he gives to Timothy to proceed in his work with resolution, Ti1 1:18. Observe here, The gospel is a charge committed to the ministers of it; it is committed to their trust, to see that it be duly applied according to the intent and meaning of it, and the design of its great Author. It seems, there had been prophecies before concerning Timothy, that he should be taken into the ministry, and should prove eminent in the work of the ministry; this encouraged Paul to commit this...', 'teologico');
add('1tm', 2, 1, 'Matthew Henry', 'Here is, I. A charge given to Christians to pray for all men in general, and particularly for all in authority. Timothy must take care that this be done. Paul does not send him any prescribed form of prayer, as we have reason to think he would if he had intended that ministers should be tied to that way of praying; but, in general, that they should make supplications, prayers, intercessions, and giving of thanks: supplications for the averting of evil, prayers for the obtaining of good, inter...', 'teologico');
add('1tm', 2, 9, 'Matthew Henry', 'I. Here is a charge, that women who profess the Christian religion should be modest, sober, silent, and submissive, as becomes their place. 1. They must be very modest in their apparel, not affecting gaudiness, gaiety, or costliness (you may read the vanity of a person\'s mind in the gaiety and gaudiness of his habit), because they have better ornaments with which they should adorn themselves, with good works. Note, Good works are the best ornament; these are, in the sight of God, of great pri...', 'teologico');
add('1tm', 3, 1, 'Matthew Henry', 'The two epistles to Timothy, and that to Titus, contain a scripture-plan of church-government, or a direction to ministers. Timothy, we suppose, was an evangelist who was left at Ephesus, to take care of those whom the Holy Ghost had made bishops there, that is, the presbyters, as appears by Act 20:28, where the care of the church was committed to the presbyters, and they were called bishops. It seems they were very loth to part with Paul, especially because he told them they should see his f...', 'teologico');
add('1tm', 3, 8, 'Matthew Henry', 'We have here the character of deacons: these had the care of the temporal concerns of the church, that is, the maintenance of the ministers and provision for the poor: they served tables, while the ministers or bishops gave themselves only to the ministry of the word and prayer, Act 6:2, Act 6:4. Of the institution of this office, with that which gave occasion to it, you have an account in Act 6:1-7. Now it was requisite that deacons should have a good character, because they were assistants ...', 'teologico');
add('1tm', 3, 14, 'Matthew Henry', 'He concludes the chapter with a particular direction to Timothy. He hoped shortly to come to him, to give him further directions and assistance in his work, and to see that Christianity was well planted, and took root well, at Ephesus; he therefore wrote the more briefly to him. But he wrote lest he should tarry long, that Timothy might know how to behave himself in the house of God, how to conduct himself as became an evangelist, and the apostle\'s substitute. Observe,\nI. Those who are employ...', 'teologico');
add('1tm', 4, 1, 'Matthew Henry', 'We have here a prophecy of the apostasy of the latter times, which he had spoken of as a thing expected and taken for granted among Christians, 2 Th. 2.\nI. In the close of the foregoing chapter, we had the mystery of godliness summed up; and therefore very fitly, in the beginning of this chapter, we have the mystery of iniquity summed up: The Spirit speaks expressly that in the latter times some shall depart from the faith; whether he means the Spirit in the Old Testament, or the Spirit in th...', 'teologico');
add('1tm', 4, 6, 'Matthew Henry', 'The apostle would have Timothy to instil into the minds of Christians such sentiments as might prevent their being seduced by the judaizing teachers. Observe, Those are good ministers of Jesus Christ who are diligent in their work; not that study to advance new notions, but that put the brethren in remembrance of those things which they have received and heard. Wherefore I will not be negligent to put you always in remembrance of these things, though you knew them, Pe2 1:12. And elsewhere, I ...', 'teologico');
add('1tm', 5, 1, 'Matthew Henry', 'Here the apostle gives rules to Timothy, and in him to other ministers, in reproving. Ministers are reprovers by office; it is a part, though the least pleasing part, of their office; they are to preach the word, to reprove and rebuke, Ti2 4:2. A great difference is to be made in our reproofs, according to the age, quality, and other circumstances, of the persons rebuked; thus, and elder in age or office must be entreated as a father; on some have compassion, making a difference, Jde 1:22. No...', 'teologico');
add('1tm', 5, 3, 'Matthew Henry', 'Directions are here given concerning the taking of widows into the number of those who were employed by the church and had maintenance from the church: Honour widows that are widows indeed. Honour them, that is, maintain them, admit them into office. There was in those times an office in the church in which widows were employed, and that was to tend the sick and the aged, to look to them by the direction of the deacons. We read of the care taken of widows immediately upon the first forming of...', 'teologico');
add('1tm', 5, 17, 'Matthew Henry', 'Here are directions,\nI. Concerning the supporting of ministers. Care must be taken that they be honourably maintained (Ti1 5:17): Let the elders that rule well be counted worthy of double honour (that is, of double maintenance, double to what they have had, or to what others have), especially those who labour in the word and doctrine, those who are more laborious than others. Observe, The presbytery ruled, and the same that ruled were those who laboured in the word and doctrine: they had not ...', 'teologico');
add('1tm', 6, 1, 'Matthew Henry', 'I. Here is the duty of servants. The apostle had spoken before of church-relations, here of our family-relations. Servants are here said to be under the yoke, which denotes both subjection and labour; they are yoked to work, not to be idle. If Christianity finds servants under the yoke, it continues them under it; for the gospel does not cancel the obligations any lie under either by the law of nature or by mutual consent. They must respect their masters, count them worthy of all honour (beca...', 'teologico');
add('1tm', 6, 6, 'Matthew Henry', 'From the mention of the abuse which some put upon religion, making it to serve their secular advantages, the apostle,\nI. Takes occasion to show the excellency of contentment and the evil of covetousness.\n1. The excellency of contentment, Ti1 6:6-8. Some account Christianity an advantageous profession for this world. In the sense they mean this is false; yet it is undoubtedly true that, though Christianity is the worst trade, it is the best calling in the world. Those that make a trade of it, ...', 'teologico');
add('1tm', 6, 13, 'Matthew Henry', 'The apostle here charges Timothy to keep this commandment (that is, the whole work of his ministry, all the trust reposed in him, all the service expected from him) without spot, unrebukable; he must conduct himself so in his ministry that he might not lay himself open to any blame nor incur any blemish. What are the motives to move him to this?\nI. He gives him a solemn charge: I give thee charge in the sight of God that thou do this. He charges him as he will answer it at the great day to th...', 'teologico');

// 2TM (16 comentários)
add('2tm', 3, 16, 'Atanásio', 'Toda a Escritura é inspirada — A autoridade divina de toda a Palavra para ensino e correção.', 'teologico');
add('2tm', 1, 7, 'Paulo', 'Não nos deu espírito de temor — O Espírito concede poder, amor e domínio próprio.', 'teologico');
add('2tm', 4, 7, 'Lutero', 'Combati o bom combate — O exemplo de perseverança até o fim na fé.', 'aplicacao');
add('2tm', 1, 1, 'Matthew Henry', 'Here is, I. The inscription of the epistle Paul calls himself an apostle by the will of God, merely by the good pleasure of God, and by his grace, which he professes himself unworthy of. According to the promise of life which is in Christ Jesus, or according to the gospel. The gospel is the promise of life in Christ Jesus; life is the end, and Christ the way, Joh 14:6. The life is put into the promise, and both are sure in Christ Jesus the faithful witness; for all the promises of God in Chri...', 'teologico');
add('2tm', 1, 6, 'Matthew Henry', 'Here is an exhortation and excitation of Timothy to his duty (Ti2 1:6): I put thee in remembrance. The best men need remembrancers; what we know we should be reminded of. Pe2 3:1, I write this, to stir up your pure minds by way of remembrance.\nI. He exhorts him to stir up the gift of God that was in him. Stir it up as fire under the embers. It is meant of all the gifts and graces the God had given him, to qualify him for the work of an evangelist, the gifts of the Holy Ghost, the extraordinar...', 'teologico');
add('2tm', 1, 15, 'Matthew Henry', 'Having (Ti2 1:13, Ti2 1:14) exhorted Timothy to hold fast,\nI. He mentions the apostasy of many from the doctrine of Christ, Ti2 1:15. It seems, in the best and purest ages of the church, there were those that had embraced the Christian faith, and yet afterwards revolted from it, nay, there were many such. He does not say that they had turned away from the doctrine of Christ (though it should seem they had) but they had turned away from him, they had turned their backs upon him, and disowned h...', 'teologico');
add('2tm', 2, 1, 'Matthew Henry', 'Here Paul encourages Timothy to constancy and perseverance in his work: Be strong in the grace that is in Christ Jesus, Ti2 2:1. Observe, Those who have work to do for God must stir up themselves to do it, and strengthen themselves for it. Being strong in the grace that is in Christ Jesus may be understood in opposition to the weakness of grace. Where there is the truth of grace there must be a labouring after the strength of grace. As our trials increase, we have need to grow stronger and st...', 'teologico');
add('2tm', 2, 8, 'Matthew Henry', 'I. To encourage Timothy in suffering, the apostle puts him in mind of the resurrection of Christ (Ti2 2:8): Remember that Jesus Christ, of the seed of David, was raised from the dead, according to my gospel. This is the great proof of his divine mission, and therefore a great confirmation of the truth of the Christian religion; and the consideration of it should make us faithful to our Christian profession, and should particularly encourage us in suffering for it. Let suffering saints remembe...', 'teologico');
add('2tm', 2, 14, 'Matthew Henry', 'Having thus encouraged Timothy to suffer, he comes in the next place to direct him in his work.\nI. He must make it his business to edify those who were under his charge, to put them in remembrance of those things which they did already know; for this is the work of ministers; not to tell people that which they never knew before, but to put them in mind of that which they do know, charging them that they strive not about words. Observe, Those that are disposed to strive commonly strive about m...', 'teologico');
add('2tm', 2, 19, 'Matthew Henry', 'Here we see what we may comfort ourselves with, in reference to this, and the little errors and heresies that both infect and infest the church, and do mischief.\nI. It may be a great comfort to us that the unbelief of men cannot make the promise of God of no effect. Though the faith of some particular persons be overthrown, yet the foundation of God standeth sure (Ti2 2:19); it is not possible that they should deceive the elect. Or it may be meant of the truth itself, which they impugn. All t...', 'teologico');
add('2tm', 2, 22, 'Matthew Henry', 'I. Paul here exhorts Timothy to beware of youthful lusts, Ti2 2:22. Though he was a holy good man, very much mortified to the world, yet Paul thought it necessary to caution him against youthful lusts: "Flee them, take all possible care and pains to keep thyself pure from them." The lusts of the flesh are youthful lusts, which young people must carefully watch against, and the best must not be secure. He prescribes an excellent remedy against youthful lusts: Follow righteousness, faith, chari...', 'teologico');
add('2tm', 3, 1, 'Matthew Henry', 'Timothy must not think it strange if there were in the church bad men; for the net of the gospel was to enclose both good fish and bad, Mat 13:47, Mat 13:48. Jesus Christ had foretold (Mt. 24) that there would come seducers, and therefore we must not be offended at it, nor think the worse of religion or the church for it. Even in gold ore there will be dross, and a great deal of chaff among the wheat when it lies on the floor.\nI. Timothy must know that in the last days (Ti2 3:1), in gospel ti...', 'teologico');
add('2tm', 3, 10, 'Matthew Henry', 'Here the apostle, to confirm Timothy in that way wherein he walked,\nI. Sets before him his own example, which Timothy had been an eye-witness of, having long attended Paul (Ti2 3:10): Thou hast fully known my doctrine. The more fully we know the doctrine of Christ and the apostles, the more closely we shall cleave to it; the reason why many sit loose to it is because they do not fully know it. Christ\'s apostles had no enemies but those who did not know them, or not know them fully; those who ...', 'teologico');
add('2tm', 4, 1, 'Matthew Henry', 'Observe, I. How awfully this charge is introduced (Ti2 4:1): I charge thee before God, and the Lord Jesus Christ, who shall judge the quick and the dead at his appearing and his kingdom. Observe, The best of men have need to be awed into the discharge of their duty. The work of a minister is not an indifferent thing, but absolutely necessary. Woe be to him if he preach not the gospel, Co1 9:16. To induce him to faithfulness, he must consider, 1. That the eye of God and Jesus Christ was upon h...', 'teologico');
add('2tm', 4, 9, 'Matthew Henry', 'Here are divers particular matters which Paul mentions to Timothy, now at the closing of the epistle. 1. He bids him hasten to him, if possible (Ti2 4:9): So thy diligence to come shortly to me. For Timothy was an evangelist, one who was not a fixed pastor of any one place, but attended the motions of the apostles, to build upon their foundation. Paul wanted Timothy\'s company and help; and the reason he gives is because several had left him (Ti2 4:10); one from an ill principle, namely, Demas...', 'teologico');
add('2tm', 4, 16, 'Matthew Henry', 'Here, I. He gives Timothy an account of his own present circumstances.\n1. He had lately been called to appear before the emperor, upon his appeal to Caesar; and then no man stood with him (Ti2 4:16), to plead his cause, to bear testimony for him, or so much as to keep him in countenance, but all men forsook him. This was strange, that so good a man as Paul should have nobody to own him, even at Rome, where there were many Christians, whose faith was spoken of throughout the world, Rom 1:8. Bu...', 'teologico');

// TT (9 comentários)
add('tt', 2, 11, 'Tito', 'A graça de Deus se manifestou — A salvação universal oferecida a todos os homens.', 'teologico');
add('tt', 3, 5, 'Calvino', 'Não por obras de justiça — A salvação é pela misericórdia, mediante a regeneração do Espírito.', 'teologico');
add('tt', 1, 1, 'Matthew Henry', 'Here is the preface to the epistle, showing,\nI. The writer. Paul, a Gentile name taken by the apostle of the Gentiles, Act 13:9, Act 13:46, Act 13:47. Ministers will accommodate even smaller matters, so that they may be any furthering of acceptance in their work. When the Jews rejected the gospel, and the Gentiles received it, we read no more of this apostle by his Jewish name Saul, but by his Roman one, Paul. A servant of God, and an apostle of Jesus Christ. Here he is described by his relat...', 'teologico');
add('tt', 1, 5, 'Matthew Henry', 'Here is the end expressed,\nI. More generally: For this cause left I thee in Crete, that thou shouldst set in order the things that are wanting. This was the business of evangelists (in which office Titus was), to water where the apostles had planted (Co1 3:6), furthering and finishing what they had begun; so much epidiorthoun imports, to order after another. Titus was to go on in settling what the apostle himself had not time for, in his short stay there. Observe, 1. The apostle\'s great dilig...', 'teologico');
add('tt', 1, 6, 'Matthew Henry', 'The apostle here gives Titus directions about ordination, showing whom he should ordain, and whom not.\nI. Of those whom he should ordain. He points out their qualifications and virtues; such as respect their life and manners, and such as relate to their doctrine: the former in the sixth, seventh, and eighth verses, and the latter in the ninth.\n1. Their qualifications respecting their life and manners are,\n(1.) More general: If any be blameless; not absolutely without fault, so none are, for t...', 'teologico');
add('tt', 2, 1, 'Matthew Henry', 'Here is the third thing in the matter of the epistle. In the chapter foregoing, the apostle had directed Titus about matters of government, and to set in order the things that were wanting in the churches. Now here he exhorts him,\nI. Generally, to a faithful discharge of his own office. His ordaining others to preach would not excuse himself from preaching, nor might he take care of ministers and elders only, but he must instruct private Christians also in their duty. The adversative particle...', 'teologico');
add('tt', 2, 15, 'Matthew Henry', 'The apostle closes the chapter (as he began it) with a summary direction to Titus upon the whole, in which we have the matter and manner of ministers\' teaching, and a special instruction to Titus in reference to himself.\nI. The matter of ministers\' teaching: These thing, namely, those before mentioned: not Jewish fables and traditions, but the truths and duties of the gospel, of avoiding sin, and living soberly, righteously, and godly, in this present world. Observe, Ministers in their preach...', 'teologico');
add('tt', 3, 1, 'Matthew Henry', 'Here is the fourth thing in the matter of the epistle. The apostle had directed Titus in reference to the particular and special duties of several sorts of persons; now he bids him exhort to what concerned them more in common, namely, to quietness and submission to rulers, and readiness to do good, and to equitable and gentle behaviour towards all men - things comely and ornamental of religion; he must therefore put them in mind of such things. Ministers are people\'s remembrancers of their du...', 'teologico');
add('tt', 3, 9, 'Matthew Henry', 'Here is the fifth and last thing in the matter of the epistle: what Titus should avoid in teaching; how he should deal with a heretic; with some other directions. Observe,\nI. That the apostle\'s meaning might be more clear and full, and especially fitted to the time and state of things in Crete, and the many judaizers among them, he tells Titus what, in teaching, he should shun, Tit 3:9. There are needful questions to be discussed and cleared, such as make for improvement in useful knowledge; ...', 'teologico');

// FM (3 comentários)
add('fm', 1, 6, 'João Crisóstomo', 'A comunicação da fé — A fé se expressa em ações concretas de amor fraternal.', 'aplicacao');
add('fm', 1, 1, 'Matthew Henry', 'I. In the first two verses of the preface we have the persons from and to whom it is written, with some annexed note or title, implying somewhat of argument to the purpose of the letter.\n1. The persons writing: Paul, the principal, who calls himself a prisoner of Jesus Christ, that is, for Jesus Christ. To be a prisoner simply is no comfort nor honour; but such as Paul was, for the faith and preaching of the gospel, this was true glory, and proper to move Philemon upon the request made to him...', 'teologico');
add('fm', 1, 8, 'Matthew Henry', 'We have here,\nI. The main business of the epistle, which was to plead with Philemon on behalf of Onesimus, that he would receive him and be reconciled to him. Many arguments Paul urges for this purpose, Plm 1:8-21. The\n1st Argument is taken from what was before noted, and is carried in the illative wherefore: "Seeing so much good is reported of thee and found in thee, especially thy love to all saints, now let me see it on a fresh and further occasion; refresh the bowels of Onesimus and mine ...', 'teologico');

// HB (45 comentários)
add('hb', 1, 1, 'Calvino', 'Muitas vezes e de muitas maneiras — A revelação progressiva: Deus falou pelos profetas, agora pelo Filho.', 'teologico');
add('hb', 1, 3, 'João Crisóstomo', 'Ele é a imagem — O Filho é a imagem exata do Pai: o que se vê em Cristo, vê-se em Deus.', 'teologico');
add('hb', 4, 12, 'R.C. Sproul', 'Viva e eficaz — A Palavra de Deus não é letra morta: tem poder transformador.', 'teologico');
add('hb', 4, 14, 'Tomás de Aquino', 'Temos um grande sumo sacerdote — Cristo é nosso intercessor: passou pelos céus por nós.', 'teologico');
add('hb', 4, 16, 'John Stott', 'Cheguemos com confiança — O acesso ao trono da graça: liberdade para orar.', 'aplicacao');
add('hb', 6, 19, 'John Piper', 'Ancoragem da alma — A esperança cristã é firme e segura: o que Deus prometeu, cumprirá.', 'teologico');
add('hb', 7, 25, 'Albert Barnes', 'Intercedendo — Cristo é nosso advogado perpétuo: nunca para de interceder.', 'teologico');
add('hb', 9, 12, 'Calvino', 'Pelo seu próprio sangue — O sacrifício de Cristo é único e suficiente: uma vez por todas.', 'teologico');
add('hb', 9, 14, 'Lloyd-Jones', 'Do Espírito eterno — O sacrifício de Cristo é superior: pela graça do Espírito.', 'teologico');
add('hb', 10, 14, 'Charles Ellicott', 'Com uma única oblação — A suficiência do sacrifício: perfeição uma vez alcançada.', 'teologico');
add('hb', 11, 1, 'Tomás de Aquino', 'Fé é a substância — A fé é certeza das coisas invisíveis: fundamento da vida cristã.', 'teologico');
add('hb', 11, 6, 'Calvino', 'Sem fé é impossível agradar — A fé é indispensável: quem se aproxima cre que Deus existe e recompensa.', 'teologico');
add('hb', 12, 2, 'N.T. Wright', 'Pelo gozo proposto — Jesus suportou a cruz pelo gozo: a alegria que vem depois.', 'aplicacao');
add('hb', 13, 8, 'Adam Clarke', 'O mesmo — Cristo não muda: Sua Pessoa, obra e promessas são permanentes.', 'teologico');
add('hb', 1, 4, 'Matthew Henry', 'The apostle, having proved the pre-eminence of the gospel above the law from the pre-eminence of the Lord Jesus Christ above the prophets, now proceeds to show that he is much superior not only to the prophets, but to the angels themselves. In this he obviates an objection that the Jewish zealots would be ready to make, that the law was not only delivered by men, but ordained by angels (Gal 3:19), who attended at the giving forth of the law, the hosts of heaven being drawn forth to attend the...', 'teologico');
add('hb', 2, 1, 'Matthew Henry', 'The apostle proceeds in the plain profitable method of doctrine, reason, and use, through this epistle. Here we have the application of the truths before asserted and proved; this is brought in by the illative particle therefore, with which this chapter begins, and which shows its connection with the former, where the apostle having proved Christ to be superior to the angels by whose ministry the law was given, and therefore that the gospel dispensation must be more excellent than the legal, ...', 'teologico');
add('hb', 2, 5, 'Matthew Henry', 'The apostle, having made this serious application of the doctrine of the personal excellency of Christ above the angels, now returns to that pleasant subject again, and pursues it further (Heb 2:5): For to the angels hath he not put in subjection the world to come, whereof we speak.\nI. Here the apostle lays down a negative proposition, including a positive one - That the state of the gospel-church, which is here called the world to come, is not subjected to the angels, but under the special c...', 'teologico');
add('hb', 2, 10, 'Matthew Henry', 'Having mentioned the death of Christ, the apostle here proceeds to prevent and remove the scandal of the cross; and this he does by showing both how it became God that Christ should suffer and how much man should be benefited by those sufferings.\nI. How it became God that Christ should suffer: For it became him for whom are all things, and by whom are all things, in bringing many sons to glory, to make the captain of their salvation perfect through sufferings, Heb 2:10. Here,\n1. God is descri...', 'teologico');
add('hb', 2, 14, 'Matthew Henry', 'Here the apostle proceeds to assert the incarnation of Christ, as taking upon him not the nature of angels, but the seed of Abraham; and he shows the reason and design of his so doing.\nI. The incarnation of Christ is asserted (Heb 2:16): Verily he took not upon him the nature of angels, but he took upon him the seed of Abraham. He took part of flesh and blood. Though as God he pre-existed from all eternity, yet in the fulness of time he took our nature into union with his divine nature, and b...', 'teologico');
add('hb', 3, 1, 'Matthew Henry', 'In these verses we have the application of the doctrine laid down in the close of the last chapter concerning the priesthood of our Lord Jesus Christ. And observe,\nI. In how fervent and affectionate a manner the apostle exhorts Christians to have this high priest much in their thoughts, and to make him the object of their close and serious consideration; and surely no one in earth or heaven deserves our consideration more than he. That this exhortation might be made the more effectual, observ...', 'teologico');
add('hb', 3, 7, 'Matthew Henry', 'Here the apostle proceeds in pressing upon them serious counsels and cautions to the close of the chapter; and he recites a passage out of Psa 95:7, etc., where observe,\nI. What he counsels them to do - to give a speedy and present attention to the call of Christ. "Hear his voice, assent to, approve of, and consider, what God in Christ speaks unto you; apply it to yourselves with suitable affections and endeavours, and set about it this very day, for tomorrow it may be too late."\nII. What he ...', 'teologico');
add('hb', 4, 1, 'Matthew Henry', 'Here, I. The apostle declares that our privileges by Christ under the gospel are not only as great, but greater than those enjoyed under the Mosaic law. He specifies this, that we have a promise left us of entering into his rest; that is, of entering into a covenant-relation to Christ, and a state of communion with God through Christ, and of growing up therein, till we are made perfect in glory. We have discoveries of this rest, and proposals, and the best directions how we may attain unto it...', 'teologico');
add('hb', 4, 11, 'Matthew Henry', 'In this latter part of the chapter the apostle concludes, first, with a serious repeated exhortation, and then with proper and powerful motives.\nI. Here we have a serious exhortation: Let us labour therefore to enter into that rest, Heb 4:11. Observe, 1. The end proposed - rest spiritual and eternal, the rest of grace here and glory hereafter - in Christ on earth, with Christ in heaven. 2. The way to this end prescribed-labour, diligent labour; this is the only way to rest; those who will not...', 'teologico');
add('hb', 5, 1, 'Matthew Henry', 'We have here an account of the nature of the priestly office in general, though with an accommodation to the Lord Jesus Christ. We are told,\nI. Of what kind of beings the high priest must be. He must be taken from among men; he must be a man, one of ourselves, bone of our bones, flesh of our flesh, and spirit of our spirits, a partaker of our nature, and a standard-bearer among ten thousand. This implies, 1. That man had sinned. 2. That God would not admit sinful man to come to him immediatel...', 'teologico');
add('hb', 5, 10, 'Matthew Henry', 'Here the apostle returns to what he had in Heb 5:6 cited out of Psa 110:1-7, concerning the peculiar order of the priesthood of Christ, that is, the order of Melchisedec. And here,\nI. He declares he had many things which he could say to them concerning this mysterious person called Melchisedec, whose priesthood was eternal, and therefore the salvation procured thereby should be eternal also. We have a more particular account of this Melchisedec in ch. 7. Some think the things which the apostl...', 'teologico');
add('hb', 6, 1, 'Matthew Henry', 'We have here the apostle\'s advice to the Hebrews - that they would grow up from a state of childhood to the fullness of the stature of the new man in Christ. He declares his readiness to assist them all he could in their spiritual progress; and, for their greater encouragement, he puts himself with them: Let us go on. Here observe, In order to their growth, Christians must leave the principles of the doctrine of Christ. How must they leave them? They must not lose them, they must not despise ...', 'teologico');
add('hb', 6, 9, 'Matthew Henry', 'The apostle, having applied himself to the fears of the Hebrews, in order to excite their diligence and prevent their apostasy, now proceeds to apply himself to their hopes, and candidly declares the good hope he had concerning them, that they would persevere; and proposes to them the great encouragements they had in the way of their duty.\nI. He freely and openly declares the good hope he had concerning them, that they would endure to the end: But beloved, we are persuaded better things of yo...', 'teologico');
add('hb', 7, 1, 'Matthew Henry', 'The foregoing chapter ended with a repetition of what had been cited once and again before out of Psa 110:4, Jesus, a high priest for ever, after the order of Melchisedec. Now this chapter is as a sermon upon that text; here the apostle sets before them some of the strong meat he had spoken of before, hoping they would by greater diligence be better prepared to digest it.\nI. The great question that first offers itself is, Who was this Melchisedec? All the account we have of him in the Old Tes...', 'teologico');
add('hb', 7, 11, 'Matthew Henry', 'Observe the necessity there was of raising up another priest, after the order of Melchisedec and not after the order of Aaron, by whom that perfection should come which could not come by the Levitical priesthood, which therefore must be changed, and the whole economy with it, Heb 7:11, Heb 7:12, etc. Here,\nI. It is asserted that perfection could not come by the Levitical priesthood and the law. They could not put those who came to them into the perfect enjoyment of the good things they pointe...', 'teologico');
add('hb', 8, 1, 'Matthew Henry', 'Here is, I. A summary recital of what had been said before concerning the excellency of Christ\'s priesthood, showing what we have in Christ, where he now resides, and what sanctuary he is the minister of, Heb 8:1, Heb 8:2. Observe, 1. What we have in Christ; we have a high priest, and such a high priest as no other people ever had, no age of the world, or of the church, ever produced; all others were but types and shadows of this high priest. He is adequately fitted and absolutely sufficient ...', 'teologico');
add('hb', 8, 6, 'Matthew Henry', 'In this part of the chapter, the apostle illustrates and confirms the superior excellency of the priesthood of Christ above that of Aaron, from the excellency of that covenant, or that dispensation of the covenant of grace, of which Christ was the Mediator (Heb 8:6): his ministry is more excellent, by how much he is the Mediator of a better covenant. The body and soul too of all divinity (as some observe) consist very much in rightly distinguishing between the two covenants - the covenant of ...', 'teologico');
add('hb', 9, 1, 'Matthew Henry', 'Here, I. The apostle gives an account of the tabernacle, that place of worship which God appointed to be pitched on earth; it is called a worldly sanctuary, wholly of this world, as to the materials of which it was built, and a building that must be taken down; it is called a worldly sanctuary, because it was the court and palace of the King of Israel. God was their King, and, as other kings, had his court or place of residence, and attendants, furniture, and provision, suitable thereto. This...', 'teologico');
add('hb', 9, 8, 'Matthew Henry', 'In these verses the apostle undertakes to deliver to us the mind and meaning of the Holy Ghost in all the ordinances of the tabernacle and legal economy, comprehending both place and worship. The scriptures of the Old Testament were given by inspiration of God; holy men of old spoke and wrote as the Holy Ghost directed them. And these Old Testament records are of great use and significancy, not only to those who first received them, but even to Christians, who ought not to satisfy themselves ...', 'teologico');
add('hb', 9, 15, 'Matthew Henry', 'In these verses the apostle considers the gospel under the notion of a will or testament, the new or last will and testament of Christ, and shows the necessity and efficacy of the blood of Christ to make this testament valid and effectual.\nI. The gospel is here considered as a testament, the new and last will and testament of our Lord and Saviour Jesus Christ. It is observable that the solemn transactions that pass between God and man are sometimes called a covenant, here a testament. A coven...', 'teologico');
add('hb', 9, 23, 'Matthew Henry', 'In this last part of the chapter, the apostle goes on to tell us what the Holy Ghost has signified to us by the legal purifications of the patterns of the things in heaven, inferring thence the necessity of better sacrifices to consecrate the heavenly things themselves.\nI. The necessity of purifying the patterns of the things in heaven, Heb 9:23. This necessity arises both from the divine appointment, which must always be obeyed, and from the reason of that appointment, which was to preserve ...', 'teologico');
add('hb', 10, 1, 'Matthew Henry', 'Here the apostle, by the direction of the Spirit of God, sets himself to lay low the Levitical dispensation; for though it was of divine appointment, and very excellent and useful in its time and place, yet, when it was set up in competition with Christ, to whom it was only designed to lead the people, it was very proper and necessary to show the weakness and imperfection of it, which the apostle does effectually, from several arguments. As,\nI. That the law had a shadow, and but a shadow, of ...', 'teologico');
add('hb', 10, 7, 'Matthew Henry', 'Here the apostle raises up and exalts the Lord Jesus Christ, as high as he had laid the Levitical priesthood low. He recommends Christ to them as the true high priest, the true atoning sacrifice, the antitype of all the rest: and this he illustrates,\nI. From the purpose and promise of God concerning Christ, which are frequently recorded in the volume of the book of God, Heb 10:7. God had not only decreed, but declared by Moses and the prophets, that Christ should come and be the great high pr...', 'teologico');
add('hb', 10, 19, 'Matthew Henry', 'I. Here the apostle sets forth the dignities of the gospel state. It is fit that believers should know the honours and privileges that Christ has procured for them, that, while they take the comfort, they may give him the glory of all. The privileges are, 1. Boldness to enter into the holiest. They have access to God, light to direct them, liberty of spirit and of speech to conform to the direction; they have a right to the privilege and a readiness for it, assistance to use and improve it an...', 'teologico');
add('hb', 11, 4, 'Matthew Henry', 'The apostle, having given us a more general account of the grace of faith, now proceeds to set before us some illustrious examples of it in the Old Testament times, and these may be divided into two classes: - 1. Those whose names are mentioned, and the particular exercise and actings of whose faith are specified. 2. Those whose names are barely mentioned, and an account given in general of the exploits of their faith, which it is left to the reader to accommodate, and apply to the particular...', 'teologico');
add('hb', 11, 32, 'Matthew Henry', 'The apostle having given us a classis of many eminent believers, whose names are mentioned and the particular trials and actings of their faith recorded, now concludes his narrative with a more summary account of another set of believers, where the particular acts are not ascribed to particular persons by name, but left to be applied by those who are well acquainted with the sacred story; and, like a divine orator, he prefaces his part of the narrative with an elegant expostulation: What shal...', 'teologico');
add('hb', 12, 1, 'Matthew Henry', 'Here observe what is the great duty which the apostle urges upon the Hebrews, and which he so much desires they would comply with, and that is, to lay aside every weight, and the sin that did so easily beset them, and run with patience the race set before them. The duty consists of two parts, the one preparatory, the other perfective.\nI. Preparatory: Lay aside every weight, and the sin, etc. 1. Every weight, that is, all inordinate affection and concern for the body, and the present life and ...', 'teologico');
add('hb', 12, 4, 'Matthew Henry', 'Here the apostle presses the exhortation to patience and perseverance by an argument taken from the gentle measure and gracious nature of those sufferings which the believing Hebrews endured in their Christian course.\nI. From the gentle and moderate degree and measure of their sufferings: You have not yet resisted unto blood, striving against sin, Heb 12:4. Observe,\n1. He owns that they had suffered much, they had been striving to an agony against sin. Here, (1.) The cause of the conflict was...', 'teologico');
add('hb', 12, 18, 'Matthew Henry', 'Here the apostle goes on to engage the professing Hebrews to perseverance in their Christian course and conflict, and not to relapse again into Judaism. This he does by showing them how much the state of the gospel church differs from that of the Jewish church, and how much it resembles the state of the church in heaven, and on both accounts demands and deserves our diligence, patience, and perseverance in Christianity.\nI. He shows how much the gospel church differs from the Jewish church, an...', 'teologico');
add('hb', 13, 1, 'Matthew Henry', 'The design of Christ in giving himself for us is that he may purchase to himself a peculiar people, zealous of good works. Now the apostle calls the believing Hebrews to the performance of many excellent duties, in which it becomes Christians to excel.\nI. To brotherly love (Heb 13:1), by which he does not only mean a general affection to all men, as our brethren by nature, all made of the same blood, nor that more limited affection which is due to those who are of the same immediate parents, ...', 'teologico');
add('hb', 13, 18, 'Matthew Henry', 'Here, I. The apostle recommends himself, and his fellow-sufferers, to the prayers of the Hebrew believers (Heb 13:18): "Pray for us; for me and Timothy" (mentioned Heb 13:23), "and for all those of us who labour in the ministry of the gospel."\n1. This is one part of the duty which people owe to their ministers. Ministers need the prayers of the people; and the more earnestly the people pray for their ministers the more benefit they may expect to reap from their ministry. They should pray that...', 'teologico');

// TG (19 comentários)
add('tg', 1, 2, 'Wesley', 'Considerai como grande — A alegria na provação: a fé é provada para produzir perseverança.', 'aplicacao');
add('tg', 1, 4, 'Spurgeon', 'Perfeita e completa — O propósito da provação: maturidade espiritual sem falta.', 'aplicacao');
add('tg', 1, 5, 'Calvino', 'Peça a Deus — A oração é o meio que Deus designou para recebermos Sua sabedoria.', 'aplicacao');
add('tg', 2, 17, 'Albert Barnes', 'A fé, se não tem obras — A fé sem obras é morta: a verdadeira fé produz ação.', 'aplicacao');
add('tg', 2, 18, 'Lloyd-Jones', 'Mostra-me a tua fé — Fé e obras são inseparáveis: as obras são evidência da fé.', 'aplicacao');
add('tg', 4, 7, 'John Stott', 'Resisti ao diabo — A resistência espiritual: firmes na fé contra as investidas do maligno.', 'aplicacao');
add('tg', 5, 16, 'Tim Keller', 'Confessai as vossas culpas — A confissão mútua produz cura: a comunhão rompida é restaurada.', 'aplicacao');
add('tg', 1, 1, 'Matthew Henry', 'We have here the inscription of this epistle, which consists of three principal parts.\nI. The character by which our author desires to be known: James, a servant of God, and of the Lord Jesus Christ. Though he was a prime-minister in Christ\'s kingdom, yet he styles himself only a servant. Note hence, Those who are highest in office or attainments in the church of Christ are but servants. They should not therefore act as masters, but as ministers. Further, Though James is called by the evangel...', 'teologico');
add('tg', 1, 13, 'Matthew Henry', 'I. We are here taught that God is not the author of any man\'s sin. Whoever they are who raise persecutions against men, and whatever injustice and sin they may be guilty of in proceeding against them, God is not to be charged with it. And, whatever sins good men may themselves be provoked to by their exercises and afflictions, God is not the cause of them. It seems to be here supposed that some professors might fall in the hour of temptation, that the rod resting upon them might carry some in...', 'teologico');
add('tg', 1, 19, 'Matthew Henry', 'In this part of the chapter we are required,\nI. To restrain the workings of passion. This lesson we should learn under afflictions; and this we shall learn if we are indeed begotten again by the word of truth. For thus the connection stands - An angry and hasty spirit is soon provoked to ill things by afflictions, and errors and ill opinions become prevalent through the workings of our own vile and vain affections; but the renewing grace of God and the word of the gospel teach us to subdue th...', 'teologico');
add('tg', 2, 1, 'Matthew Henry', 'The apostle is here reproving a very corrupt practice. He shows how much mischief there is in the sin of prosōpolēpsia - respect of persons, which seemed to be a very growing evil in the churches of Christ even in those early ages, and which, in these after-times, has sadly corrupted and divided Christian nations and societies. Here we have,\nI. A caution against this sin laid down in general: My brethren, have not the faith of our Lord Jesus Christ, the Lord of glory, with respect of person...', 'teologico');
add('tg', 2, 8, 'Matthew Henry', 'The apostle, having condemned the sin of those who had an undue respect of persons, and having urged what was sufficient to convict them of the greatness of this evil, now proceeds to show how the matter may be mended; it is the work of a gospel ministry, not only to reprove and warn, but to teach and direct. Col 1:28, Warning every man, and teaching every man. And here,\nI. We have the law that is to guide us in all our regards to men set down in general. If you fulfil the royal law, accordin...', 'teologico');
add('tg', 2, 14, 'Matthew Henry', 'In this latter part of the chapter, the apostle shows the error of those who rested in a bare profession of the Christian faith, as if that would save them, while the temper of their minds and the tenour of their lives were altogether disagreeable to that holy religion which they professed. To let them see, therefore, what a wretched foundation they built their hopes upon, it is here proved at large that a man is justified, not by faith only, but by works. Now,\nI. Upon this arises a very grea...', 'teologico');
add('tg', 3, 1, 'Matthew Henry', 'The foregoing chapter shows how unprofitable and dead faith is without works. It is plainly intimated by what this chapter first goes upon that such a faith is, however, apt to make men conceited and magisterial in their tempers and their talk. Those who set up faith in the manner the former chapter condemns are most apt to run into those sins of the tongue which this chapter condemns. And indeed the best need to be cautioned against a dictating, censorious, mischievous use of their tongues. ...', 'teologico');
add('tg', 3, 13, 'Matthew Henry', 'As the sins before condemned arise from an affectation of being thought more wise than others, and being endued with more knowledge than they, so the apostle in these verses shows the difference between men\'s pretending to be wise and their being really so, and between the wisdom which is from beneath (from earth or hell) and that which is from above.\nI. We have some account of true wisdom, with the distinguishing marks and fruits of it: Who is a wise man, and endued with knowledge among you?...', 'teologico');
add('tg', 4, 1, 'Matthew Henry', 'The former chapter speaks of envying one another, as the great spring of strifes and contentions; this chapter speaks of a lust after worldly things, and a setting too great a value upon worldly pleasures and friendships, as that which carried their divisions to a shameful height.\nI. The apostle here reproves the Jewish Christians for their wars, and for their lusts as the cause of them: Whence come wars and fightings among you? Come they not hence, even of your lusts that war in your members...', 'teologico');
add('tg', 4, 11, 'Matthew Henry', 'In this part of the chapter,\nI. We are cautioned against the sin of evil-speaking: Speak not evil one of another, brethren, Jam 4:11. The Greek word, katalaleite, signifies speaking any thing that may hurt or injure another; we must not speak evil things of others, though they be true, unless we be called to it, and there be some necessary occasion for the; much less must we report evil things when they are false, or, for aught we know, may be so. Our lips must be guided by the law of kindnes...', 'teologico');
add('tg', 5, 1, 'Matthew Henry', 'The apostle is here addressing first sinners and then saints.\nI. Let us consider the address to sinners; and here we find James seconding what his great Master had said: Woe unto you that are rich; for you have received your consolation, Luk 6:24. The rich people to whom this word of warning was sent were not such as professed the Christian religion, but the worldly and unbelieving Jews, such as are here said to condemn and kill the just, which the Christians had no power to do; and though th...', 'teologico');
add('tg', 5, 12, 'Matthew Henry', 'This epistle now drawing to a close, the penman goes off very quickly from one thing to another: hence it is that matters so very different are insisted on in these few verses.\nI. The sin of swearing is cautioned against: But above all things, my brethren, swear not, etc., Jam 5:12. Some understand this too restrictedly, as if the meaning were, "Swear not at your persecutors, at those that reproach you and say all manner of evil of you; be not put into a passion by the injuries they do you, s...', 'teologico');

// 1PE (25 comentários)
add('1pe', 1, 6, 'Calvino', 'Vossa fé é provada — A provação é fogo que purifica a fé, mais preciosa que o ouro.', 'teologico');
add('1pe', 1, 8, 'João Crisóstomo', 'Amando-o — A fé em Cristo invisível é mais profunda que a visão física.', 'teologico');
add('1pe', 2, 9, 'N.T. Wright', 'Geração eleita — O povo de Deus é chamado para proclamar as virtudes de quem os chamou.', 'teologico');
add('1pe', 3, 15, 'R.C. Sproul', 'Estai sempre preparados — A apologética cristã: razões para a esperança.', 'teologico');
add('1pe', 5, 8, 'Albert Barnes', 'Sede sóbrios e vigiais — A vigilância espiritual: o diabo é um leão que rugi.', 'aplicacao');
add('1pe', 1, 1, 'Matthew Henry', 'In this inscription we have three parts: - \nI. The author of it, described, 1. By his name - Peter. His first name was Simon, and Jesus Christ gave him the surname of Peter, which signifies a rock, as a commendation of his faith, and to denote that he should be an eminent pillar in the church of God, Gal 2:9. 2. By his office - an apostle of Jesus Christ. The word signifies one sent, a legate, a messenger, any one sent in Christ\'s name and about his work; but more strictly it signifies the hi...', 'teologico');
add('1pe', 1, 3, 'Matthew Henry', 'We come now to the body of the epistle, which begins with,\nI. A congratulation of the dignity and happiness of the state of these believers, brought in under the form of a thanksgiving to God. Other epistles begin in like manner, Co2 1:3; Eph 1:3. Here we have,\n1. The duty performed, which is blessing God. A man blesses God by a just acknowledgment of his excellency and blessedness.\n2. The object of this blessing described by his relation to Jesus Christ: The God and Father of our Lord Jesus ...', 'teologico');
add('1pe', 1, 10, 'Matthew Henry', 'The apostle having described the persons to whom he wrote, and declared to them the excellent advantages they were under, goes on to show them what warrant he had for what he had delivered; and because they were Jews, and had a profound veneration for the Old Testament, he produces the authority of the prophets to convince them that the doctrine of salvation by faith in Jesus Christ was no new doctrine, but the same which the old prophets did enquire and search diligently into. Note,\nI. Who m...', 'teologico');
add('1pe', 1, 13, 'Matthew Henry', 'Here the apostle begins his exhortations to those whose glorious state he had before described, thereby instructing us that Christianity is a doctrine according to godliness, designed to make us not only wiser, but better.\nI. He exhorts them to sobriety and holiness.\n1. Wherefore gird up the loins of your mind, etc., Pe1 1:13. As if he had said, "Wherefore, since you are so honoured and distinguished, as above, Gird up the loins of your mind. You have a journey to go, a race to run, a warfare...', 'teologico');
add('1pe', 1, 24, 'Matthew Henry', 'The apostle having given an account of the excellency of the renewed spiritual man as born again, not of corruptible but incorruptible seed, he now sets before us the vanity of the natural man, taking him with all his ornaments and advantages about him: For all flesh is as grass, and all the glory of man as the flower of grass; and nothing can make him a solid substantial being, but the being born again of the incorruptible seed, the word of God, which will transform him into a most excellent...', 'teologico');
add('1pe', 2, 1, 'Matthew Henry', 'The holy apostle has been recommending mutual charity, and setting forth the excellences of the word of God, calling it an incorruptible seed, and saying that it liveth and abideth for ever. He pursues his discourse, and very properly comes in with this necessary advice, Wherefore laying aside all malice, etc. These are such sins as both destroy charity and hinder the efficacy of the word, and consequently they prevent our regeneration.\nI. His advice is to lay aside or put off what is evil, a...', 'teologico');
add('1pe', 2, 4, 'Matthew Henry', 'I. The apostle here gives us a description of Jesus Christ as a living stone; and though to a capricious wit, or an infidel, this description may seem rough and harsh, yet to the Jews, who placed much of their religion in their magnificent temple, and who understood the prophetical style, which calls the Messiah a stone (Isa 8:14; Isa 28:16), it would appear very elegant and proper.\n1. In this metaphorical description of Jesus Christ, he is called a stone, to denote his invincible strength an...', 'teologico');
add('1pe', 2, 13, 'Matthew Henry', 'The general rule of a Christian conversation is this, it must be honest, which it cannot be if there be not a conscientious discharge of all relative duties. The apostle here particularly treats of these distinctly.\nI. The case of subjects. Christians were not only reputed innovators in religion, but disturbers of the state; it was highly necessary, therefore, that the apostle should settle the rules and measures of obedience to the civil magistrate, which he does here, where,\n1. The duty req...', 'teologico');
add('1pe', 3, 1, 'Matthew Henry', 'The apostle having treated of the duties of subjects to their sovereigns, and of servants to their masters, proceeds to explain the duty of husbands and wives.\nI. Lest the Christian matrons should imagine that their conversion to Christ, and their interest in all Christian privileges, exempted them from subjection to their pagan or Jewish husbands, the apostle here tells them,\n1. In what the duty of wives consists.\n(1.) In subjection, or an affectionate submission to the will, and obedience t...', 'teologico');
add('1pe', 3, 8, 'Matthew Henry', 'The apostle here passes from special to more general exhortations.\nI. He teaches us how Christians and friends should treat one another. He advises Christians to be all of one mind, to be unanimous in the belief of the same faith, and the practice of the same duties of religion; and, whereas the Christians at that time were many of them in a suffering condition, he charges them to have compassion one of another, to love as brethren, to pity those who were in distress, and to be courteous to a...', 'teologico');
add('1pe', 3, 16, 'Matthew Henry', 'The confession of a Christian\'s faith cannot credibly be supported but by the two means here specified - a good conscience and a good conversation. conscience is good when it does its office well, when it is kept pure and uncorrupt, and clear from guilt; then it will justify you, though men accuse you. A good conversation in Christ is a holy life, according to the doctrine and example of Christ. "Look well to your conscience, and to your conversation; and then, though men speak evil of you, a...', 'teologico');
add('1pe', 3, 18, 'Matthew Henry', 'Here, I. The example of Christ is proposed as an argument for patience under sufferings, the strength of which will be discerned if we consider the several points contained in the words; observe therefore, 1. Jesus Christ himself was not exempted from sufferings in this life, though he had no guilt of his own and could have declined all suffering if he had pleased. 2. The reason or meritorious cause of Christ\'s suffering was the sins of men: Christ suffered for sins. The sufferings of Christ ...', 'teologico');
add('1pe', 3, 21, 'Matthew Henry', 'Noah\'s salvation in the ark upon the water prefigured the salvation of all good Christians in the church by baptism; that temporal salvation by the ark was a type, the antitype whereunto is the eternal salvation of believers by baptism, to prevent mistakes about which the apostle,\nI. Declares what he means by saving baptism; not the outward ceremony of washing with water, which, in itself, does no more than put away the filth of the flesh, but it is that baptism wherein there is a faithful an...', 'teologico');
add('1pe', 4, 1, 'Matthew Henry', 'The apostle here draws a new inference from the consideration of Christ\'s sufferings. As he had before made use of it to persuade to patience in suffering, so here to mortification of sin. Observe,\nI. How the exhortation is expressed. The antecedent or supposition is that Christ had suffered for us in the flesh, or in his human nature. The consequent or inference is, "Arm and fortify yourselves likewise with the same mind, courage, and resolution." The word flesh in the former part of the ver...', 'teologico');
add('1pe', 4, 4, 'Matthew Henry', 'I. Here you have the visible change wrought in those who in the foregoing verse were represented as having been in the former part of their life very wicked. They no longer run on in the same courses, or with the same companions, as they used to do. Hereupon observe the conduct of their wicked acquaintance towards them. 1. They think it strange, they are surprised and wonder at it, as at something new and unusual, that their old friends should be so much altered, and not run with as much viol...', 'teologico');
add('1pe', 4, 7, 'Matthew Henry', 'We have here an awful position or doctrine, and an inference drawn from it. The position is that the end of all things is at hand. The miserable destruction of the Jewish church and nation foretold by our Saviour is now very near; consequently, the time of their persecution and your sufferings is but very short. Your own life and that of your enemies will soon come to their utmost period. Nay, the world itself will not continue very long. The conflagration will put an end to it; and all thing...', 'teologico');
add('1pe', 4, 12, 'Matthew Henry', 'The frequent repetition of counsel and comfort to Christians, considered as sufferers, in every chapter of this epistle, shows that the greatest danger these new converts were in arose from the persecutions to which their embracing Christianity exposed them. The good behaviour of Christians under sufferings is the most difficult part of their duty, but yet necessary both for the honour of Christ and their own comfort; and therefore the apostle, having extorted them in the former part of this ...', 'teologico');
add('1pe', 5, 1, 'Matthew Henry', 'Here we may observe,\nI. The persons to whom this exhortation is given - to the presbyters, pastors, and spiritual guides of the church, elders by office, rather than by age, ministers of those churches to whom he wrote this epistle.\nII. The person who gives this exhortation - the apostle Peter: I exhort; and, to give force to this exhortation, he tells them he was their brother-presbyter or fellow-elder, and so puts nothing upon them but what he was ready to perform himself. He was also a wit...', 'teologico');
add('1pe', 5, 5, 'Matthew Henry', 'Having settled and explained the duty of the pastors or spiritual guides of the church, the apostle comes now to instruct the flock,\nI. How to behave themselves to their ministers and to one another. He calls them the younger, as being generally younger than their grave pastors, and to put them in mind of their inferiority, the term younger being used by our Saviour to signify an inferior, Luk 22:26. He exhorts those that are younger and inferior to submit themselves to the elder, to give due...', 'teologico');
add('1pe', 5, 10, 'Matthew Henry', 'We come now to the conclusion of this epistle, which,\nI. The apostle begins with a most weighty prayer, which he addresses to God as the God of all grace, the author and finisher of every heavenly gift and quality, acknowledging, on their behalf, that God had already called them to be partakers of that eternal glory, which, being his own, he had promised and settled upon them, through the merit and intercession of Jesus Christ. Observe,\n1. What he prays for on their account; not that they mig...', 'teologico');

// 2PE (15 comentários)
add('2pe', 1, 4, 'Pedro', 'Fiqueis participantes da natureza divina — A graça nos eleva à semelhança de Cristo.', 'teologico');
add('2pe', 3, 9, 'Spurgeon', 'Não retarda a Sua promessa — A paciência de Deus é salvação, não lentidão.', 'escatologico');
add('2pe', 1, 1, 'Matthew Henry', 'The apostle Peter, being moved by the Holy Ghost to write once more to those who from among the Jews were turned to faith in Christ, begins this second epistle with an introduction, wherein the same persons are described and the same blessings are desired that are in the preface to his former letter; but there are some additions or alterations which ought to be taken notice of, in all the three parts of the introduction.\nI. We have here a description of the person who wrote the epistle, by th...', 'teologico');
add('2pe', 1, 5, 'Matthew Henry', 'In these words the apostle comes to the chief thing intended in this epistle - to excite and engage them to advance in grace and holiness, they having already obtained precious faith, and been made partakers of the divine nature. This is a very good beginning, but it is not to be rested in, as if we were already perfect. The apostle had prayed that grace and peace might be multiplied to them, and now he exhorts them to press forward for the obtaining of more grace. We should, as we have oppor...', 'teologico');
add('2pe', 1, 12, 'Matthew Henry', 'I. The importance and advantage of progress and perseverance in grace and holiness made the apostle to be very diligent in doing the work of a minister of Christ, that he might thereby excite and assist them to be diligent in the duty of Christians. If ministers be negligent in their work, it can hardly be expected that the people will be diligent in theirs; therefore Peter will not be negligent (that is, at no time or place, in no part of his work, to no part of his charge), but will be exem...', 'teologico');
add('2pe', 1, 16, 'Matthew Henry', 'Here we have the reason of giving the foregoing exhortation, and that with so much diligence and seriousness. These things are not idle tales, or a vain thing, but of undoubted truth and vast concern. The gospel is not a cunningly devised fable. These are not the words of one who hath a devil, nor the contrivance of any number of men who by cunning craftiness endeavour to deceive. The way of salvation by Jesus Christ is eminently the counsel of God, the most excellent contrivance of the infin...', 'teologico');
add('2pe', 1, 19, 'Matthew Henry', 'In these words the apostle lays down another argument to prove the truth and reality of the gospel, and intimates that this second proof is more strong and convincing than the former, and more unanswerably makes out that the doctrine of the power and coming of our Lord Jesus Christ is not a mere fable or cunning contrivance of men, but the wise and wonderful counsel of the holy and gracious God. For this is foretold by the prophets and penmen of the Old Testament, who spoke and wrote under th...', 'teologico');
add('2pe', 2, 1, 'Matthew Henry', 'I. In the end of the former chapter there is mention made of holy men of God, who lived in the times of the Old Testament, and were used as the amanuenses of the Holy Ghost, in writing the sacred oracles; but in the beginning of this he tells us they had, even at that time, false prophets in the church as well as true. In all ages of the church, and under all dispensations, when God sends true prophets, the devil sends some to seduce and deceive, false prophets in the Old Testament, and false...', 'teologico');
add('2pe', 2, 3, 'Matthew Henry', 'Men are apt to think that a reprieve is the forerunner of a pardon, and that if judgment be not speedily executed it is, or will be, certainly reversed. But the apostle tells us that how successful and prosperous soever false teachers may be, and that for a time, yet their judgment lingereth not. God has determined long ago how he will deal with them. Such unbelievers, who endeavour to turn others from the faith, are condemned already, and the wrath of God abideth on them. The righteous Judge...', 'teologico');
add('2pe', 2, 7, 'Matthew Henry', 'When God sends destruction on the ungodly, he commands deliverance for the righteous; and, if he rain fire and brimstone on the wicked, he will cover the head of the just, and they shall be hid in the day of his anger. This we have an instance of in his preserving Lot. Here observe, 1. The character given of Lot; he is called a just man; this he was as to the generally prevailing bent of his heart and through the main of his conversation. God does not account men just or unjust from one singl...', 'teologico');
add('2pe', 2, 10, 'Matthew Henry', 'The apostle\'s design being to warn us of, and arm us against, seducers, he now returns to discourse more particularly of them, and give us an account of their character and conduct, which abundantly justifies the righteous Judge of the world in reserving them in an especial manner for the most severe and heavy doom, as Cain is taken under special protection that he might be kept for uncommon vengeance. But why will God thus deal with these false teachers? This he shows in what follows.\nI. The...', 'teologico');
add('2pe', 3, 1, 'Matthew Henry', 'That the apostle might the better reach his end in writing this epistle, which is to make them steady and constant in a fiducial and practical remembrance of the doctrine of the gospel, he, 1. Expresses his special affection and tenderness for them, by calling them beloved, hereby evidencing that he added to godliness brotherly-kindness, as he had (Pe2 1:17) exhorted them to do. Ministers must be examples of love and affection, as well as life and conversation. 2. He evinces a sincere love to...', 'teologico');
add('2pe', 3, 3, 'Matthew Henry', 'To quicken and excite us to a serious minding and firm adhering to what God has revealed to us by the prophets and apostles, we are told that there will be scoffers, men who will make a mock of sin, and of salvation from it. God\'s way of saving sinners by Jesus Christ is what men will scoff at, and that in the last days, under the gospel. This indeed may seem very strange, that the New Testament dispensation of the covenant of grace, which is spiritual and therefore more agreeable to the natu...', 'teologico');
add('2pe', 3, 8, 'Matthew Henry', 'The apostle comes in these words to instruct and establish Christians in the truth of the coming of the Lord, where we may clearly discern the tenderness and affection wherewith he speaks to them, calling them beloved; he had a compassionate concern and a love of good-will for the ungodly wretches who refused to believe divine revelation, but he has a peculiar respect for the true believers, and the remaining ignorance and weakness that the apprehends to be in them make him jealous, and put h...', 'teologico');
add('2pe', 3, 11, 'Matthew Henry', 'The apostle, having instructed them in the doctrine of Christ\'s second coming,\nI. Takes occasion thence to exhort them to purity and godliness in their whole conversation: all the truths which are revealed in scripture should be improved for our advancement in practical godliness: this is the effect that knowledge must produce, or we are never the better for it. If you know these things, happy are you if you do them. Seeing all these things must be dissolved, how holy should we be, that are a...', 'teologico');

// 1JO (30 comentários)
add('1jo', 1, 9, 'Charles Ellicott', 'Ele é fiel — A fidelidade de Deus: Ele cumpre Sua promessa de perdoar.', 'teologico');
add('1jo', 2, 1, 'Tomás de Aquino', 'Temos um advogado — Cristo é nosso intercessor junto ao Pai: advogado perfeito.', 'teologico');
add('1jo', 3, 1, 'R.C. Sproul', 'Vede que amor — A adoção divina: o amor do Pai para conosco é inimaginável.', 'teologico');
add('1jo', 4, 8, 'Adam Clarke', 'Deus é amor — O amor é a essência de Deus: toda a Sua obra é motivada pelo amor.', 'teologico');
add('1jo', 4, 19, 'Tim Keller', 'Nós o amamos — Amamos porque Ele nos amou primeiro: o amor é resposta, não origem.', 'aplicacao');
add('1jo', 5, 4, 'Lloyd-Jones', 'Tudo o que é nascido de Deus — A vitória da fé: a fé supera o mundo.', 'teologico');
add('1jo', 1, 1, 'Matthew Henry', 'The apostle omits his name and character (as also the author to the Hebrews does) either out of humility, or as being willing that the Christian reader should be swayed by the light and weight of the things written rather than by the name that might recommend them. And so he begins,\nI. With an account or character of the Mediator\'s person. He is the great subject of the gospel, the foundation and object of our faith and hope, the bond and cement that unite us unto God. He should be well known...', 'teologico');
add('1jo', 1, 5, 'Matthew Henry', 'The apostle, having declared the truth and dignity of the author of the gospel, brings a message or report from him, from which a just conclusion is to be drawn for the consideration and conviction of the professors of religion, or professed entertainers of this glorious gospel.\nI. Here is the message or report that the apostle avers to come from the Lord Jesus: This then is the message which we have heard of him (Jo1 1:5), of his Son Jesus Christ. As he was the immediate sender of the apostl...', 'teologico');
add('1jo', 1, 8, 'Matthew Henry', 'Here, I. The apostle, having supposed that even those of this heavenly communion have yet their sin, proceeds here to justify that supposition, and this he does by showing the dreadful consequences of denying it, and that in two particulars: - 1. If we say, We have no sin, we deceive ourselves, and the truth is not in us, Jo1 1:8. We must beware of deceiving ourselves in denying or excusing our sins. The more we see them the more we shall esteem and value the remedy. If we deny them, the trut...', 'teologico');
add('1jo', 2, 3, 'Matthew Henry', 'These verses may seem to relate to the seventh verse of the former chapter, between which and these verses there occurred an incidental discourse concerning the believer\'s duty and relief in case of sin, occasioned by the mention of one of the believer\'s privileges - his being cleansed from sin by the Mediator\'s blood. In that verse the apostle asserts the beneficial consequence of walking in the light: "We have then fellowship with one another, such divine fellowship and communion as are the...', 'teologico');
add('1jo', 2, 7, 'Matthew Henry', 'The seventh verse may be supposed either to look backward to what immediately preceded (and then it is walking as Christ walked that is here represented as no new, but an old commandment; it is that which the apostles would certainly inculcate wherever they brought Christ\'s gospel), or to look forward to what the apostle is now going to recommend, and that is the law of fraternal love; this is the message heard from the beginning (Jo1 3:11), and the old commandment, Jo2 1:5. Now, while the ap...', 'teologico');
add('1jo', 2, 12, 'Matthew Henry', 'This new command of holy love, with the incentives thereto, may possibly be directed to the several ranks of disciples that are here accosted. The several graduates in the Christian university, the catholic church, must be sure to preserve the bond of sacred love. Or, there being an important dehortation and dissuasion to follow, without the observance of which vital religion in the love of God and love of the brethren cannot subsist, the apostle may justly seem to preface it with a solemn ad...', 'teologico');
add('1jo', 2, 18, 'Matthew Henry', 'Here is, I. A moral prognostication of the time; the end is coming: Little children, it is the last time, Jo1 2:18. Some may suppose that the apostle here addresses the first rank of Christians again; the juniors are most apt to be seduced, and therefore, "Little children, you that are young in religion, take heed to yourselves that you be not corrupted." But it may be, as elsewhere, a universal appellation, introductive of an alarm to all Christians: "Little children, it is the last time; ou...', 'teologico');
add('1jo', 2, 20, 'Matthew Henry', 'Here, I. The apostle encourages the disciples (to whom he writes) in these dangerous times, in this hour of seducers; he encourages them in the assurance of their stability in this day of apostasy: But you have an unction from the Holy One, and you know all things. We see, 1. The blessing wherewith they were enriched - an unguent from heaven: You have an unction. True Christians are anointed ones, their name intimates as much. They are anointed with the oil of grace, with gifts and spiritual ...', 'teologico');
add('1jo', 2, 28, 'Matthew Henry', 'From the blessing of the sacred unction the apostle proceeds in his advice and exhortation to constancy in and with Christ: And now, little children, abide in him, Jo1 2:28. The apostle repeats his kind appellation, little children, which I suppose does not so much denote their diminutiveness as his affection, and therefore, I judge, may be rendered dear children. He would persuade by love, and prevail by endearment as well as by reason. "Not only the love of Christ, but the love of you, cons...', 'teologico');
add('1jo', 3, 4, 'Matthew Henry', 'The apostle, having alleged the believer\'s obligation to purity from his hope of heaven, and of communion with Christ in glory at the day of his appearance, now proceeds to fill his own mouth and the believer\'s mind with multiplied arguments against sin, and all communion with the impure unfruitful works of darkness. And so he reasons and argues,\nI. From the nature of sin and the intrinsic evil of it. It is a contrariety to the divine law: Whosoever committeth sin transgresseth also (or even)...', 'teologico');
add('1jo', 3, 11, 'Matthew Henry', 'The apostle, having intimated that one mark of the devil\'s children is hatred of the brethren, takes occasion thence,\nI. To recommend fraternal Christian love, and that from the excellence, or antiquity, or primariness of the injunction relating thereto: And this is the message (the errand or charge) which you heard from the beginning (this came among the principal parts of practical Christianity), that we should love one another, Jo1 3:11. We should love the Lord Jesus, and value his love, a...', 'teologico');
add('1jo', 3, 14, 'Matthew Henry', 'The beloved apostle can scarcely touch upon the mention of sacred love, but he must enlarge upon the enforcement of it, as here he does by divers arguments and incentives thereto; as,\nI. That it is a mark of our evangelical justification, of our transition into a state of life: We know that we have passed from death to life, because we love the brethren, Jo1 3:14. We are by nature children of wrath and heirs of death. By the gospel (the gospel-covenant or promise) our state towards another wo...', 'teologico');
add('1jo', 3, 20, 'Matthew Henry', 'The apostle, having intimated that there may be, even among us, such a privilege as an assurance or sound persuasion of heart towards God, proceeds here,\nI. To establish the court of conscience, and to assert the authority of it: For, if our heart condemn us, God is greater than our heart, and knoweth all things, Jo1 3:20. Our heart here is our self-reflecting judicial power, that noble excellent ability whereby we can take cognizance of ourselves, of our spirits, our dispositions, and action...', 'teologico');
add('1jo', 3, 23, 'Matthew Henry', 'The apostle, having mentioned keeping the commandments, and pleasing God, as the qualification of effectual petitioners in and with Heaven, here suitably proceeds,\nI. To represent to us what those commandments primarily and summarily are; they are comprehended in this double one: And this is his commandment, That we should believe on the name of his Son Jesus Christ, and love one another, as he gave us commandment, Jo1 3:23. To believe on the name of his Son Jesus Christ is, 1. To discern wha...', 'teologico');
add('1jo', 4, 1, 'Matthew Henry', 'The apostle, having said that God\'s dwelling in and with us may be known by the Spirit that he hath given us, intimates that that Spirit may be discerned and distinguished from other spirits that appear in the world; and so here,\nI. He calls the disciples, to whom he writes, to caution and scrutiny about the spirits and spiritual professors that had now risen. 1. To caution: "Beloved, believe not every spirit; regard not, trust not, follow not, every pretender to the Spirit of God, or every p...', 'teologico');
add('1jo', 4, 4, 'Matthew Henry', 'In these verses the apostle encourages the disciples against the fear and danger of this seducing antichristian spirit, and that by such methods as these: - 1. He assures them of a more divine principle in them: "You are of God, little children, Jo1 4:4. You are God\'s little children. We are of God, Jo1 4:6. We are born of God, taught of God, anointed of God, and so secured against infectious fatal delusions. God has his chosen, who shall not be mortally seduced." 2. He gives them hope of vic...', 'teologico');
add('1jo', 4, 7, 'Matthew Henry', 'As the Spirit of truth is known by doctrine (thus spirits are to be tried), it is known by love likewise; and so here follows a strong fervent exhortation to holy Christian love: Beloved, let us love one another, Jo1 4:7. The apostle would unite them in his love, that he might unite them in love to each other: "Beloved, I beseech you, by the love I bear to you, that you put on unfeigned mutual love." This exhortation is pressed and urged with variety of argument: as,\nI. From the high and heav...', 'teologico');
add('1jo', 4, 14, 'Matthew Henry', 'Since faith in Christ works love to God, and love to God must kindle love to the brethren, the apostle here confirms the prime article of the Christian faith as the foundation of such love. Here,\nI. He proclaims the fundamental article of the Christian religion, which is so representative of the love of God: And we have seen, and do testify, that the Father sent the Son to be the Saviour of the world, Jo1 4:14. We here see, 1. The Lord Jesus\'s relation to God; he is Son to the Father, such a ...', 'teologico');
add('1jo', 4, 17, 'Matthew Henry', 'The apostle, having thus excited and enforced sacred love from the great pattern and motive of it, the love that is and dwells in God himself, proceeds to recommend it further by other considerations; and he recommends it in both the branches of it, both as love to God, and love to our brother or Christian neighbour.\nI. As love to God, to the primum amabile - the first and chief of all amiable beings and objects, who has the confluence of all beauty, excellence, and loveliness, in himself, an...', 'teologico');
add('1jo', 5, 1, 'Matthew Henry', 'I. The apostle having, in the conclusion of the last chapter, as was there observed, urged Christian love upon those two accounts, as suitable to Christian profession and as suitable to the divine command, here adds a third: Such love is suitable, and indeed demanded, by their eminent relation; our Christian brethren or fellow-believers are nearly related to God; they are his children: Whosoever believeth that Jesus is the Christ is born of God, Jo1 5:1. Here the Christian brother is, 1. Desc...', 'teologico');
add('1jo', 5, 6, 'Matthew Henry', 'The faith of the Christian believer (or the believer in Christ) being thus mighty and victorious, it had need to be well founded, to be furnished with unquestionable celestial evidence concerning the divine mission, authority, and office of the Lord Jesus; and it is so; he brings his credentials along with him, and he brings them in a way by which he came and in the witness that attends him.\nI. In the way and manner by which he came; not barely by which he came into the world, but by and with...', 'teologico');
add('1jo', 5, 10, 'Matthew Henry', 'In those words we may observe,\nI. The privilege and stability of the real Christian: He that believeth on the Son of God, hath been prevailed with unfeignedly to cleave to him for salvation, hath the witness in himself, Jo1 5:10. He hath not only the outward evidence that others have, but he hath in his own heart a testimony for Jesus Christ. He can allege what Christ and the truth of Christ have done for his soul and what he has seen and found in him. As, 1. He has deeply seen his sin, and g...', 'teologico');
add('1jo', 5, 14, 'Matthew Henry', 'Here we have,\nI. A privilege belonging to faith in Christ, namely, audience in prayer: This is the confidence that we have in him, that, if we ask any thing according to his will, he heareth us, Jo1 5:14. The Lord Christ emboldens us to come to God in all circumstances, with all our supplications and requests. Through him our petitions are admitted and accepted of God. The matter of our prayer must be agreeable to the declared will of God. It is not fit that we should ask what is contrary eit...', 'teologico');
add('1jo', 5, 18, 'Matthew Henry', 'Here we have,\nI. A recapitulation of the privileges and advantages of sound Christian believers. 1. They are secured against sin, against the fulness of its dominion or the fulness of its guilt: We know that whosoever is born of God (and the believer in Christ is born of God, Jo1 5:1) sinneth not (Jo1 5:18), sinneth not with that fulness of heart and spirit that the unregenerate do (as was said Jo1 3:6, Jo1 3:9), and consequently not with that fulness of guilt that attends the sins of others;...', 'teologico');

// 2JO (6 comentários)
add('2jo', 1, 6, 'João Crisóstomo', 'Andar segundo os Seus mandamentos — O amor se manifesta na obediência, não apenas em sentimento.', 'aplicacao');
add('2jo', 1, 1, 'Matthew Henry', 'Ancient epistles began, as here, with salutation and good wishes: religion consecrates, as far as may be, old forms, and turns compliments into real expressions of life and love. Here we have, as usually,\nI. The saluter, not expressed by name, but by a chosen character: The elder. The expression, and style, and love, intimate that the penman was the same with that of the foregoing epistle; he is now the elder, emphatically and eminently so; possibly the oldest apostle now living, the chief el...', 'teologico');
add('2jo', 1, 5, 'Matthew Henry', 'We come now more into the design and substance of the epistle; and here we have,\nI. The apostle\'s request: Now, I beseech thee, lady. Considering what it is that he entreats, the way of address is very remarkable; it is not any particular boon or bounty to himself, but common duty and observance of divine command. Here he might command or charge; but harsher measures are worse than needless where milder will prevail; and the apostolical spirit is, of all other, the most tender and endearing. ...', 'teologico');
add('2jo', 1, 7, 'Matthew Henry', 'In this principal part of the epistle we find,\nI. The ill news communicated to the lady-seducers are abroad: For many deceivers have entered into the world. This report is introduced by a particle that bespeaks a reason of the report. "You have need to maintain your love, for there are destroyers of it in the world. Those who subvert the faith destroy the love; the common faith is one ground of the common love;" or, "You must secure your walk according to the commands of God; this will secure...', 'teologico');
add('2jo', 1, 10, 'Matthew Henry', 'Here, I. Upon due warning given concerning seducers, the apostle gives direction concerning the treatment of such. They are not to be entertained as the ministers of Christ. The Lord Christ will distinguish them from such, and so would he have his disciples. The direction is negative. 1. "Support them not: If there come any unto you, and bring not this doctrine (concerning Christ as the Son of God, the Messiah and anointed of God for our redemption and salvation), receive him not into your ho...', 'teologico');
add('2jo', 1, 12, 'Matthew Henry', 'The apostle concludes this letter, 1. With an adjournment of many things to personal conference: Having many things to write unto you I would not write with paper and ink; but I trust to come unto you, and speak face to face, that our joy may be full. Here it is supposed that some things are better spoken than written. The use of pen and ink may be a mercy and a pleasure; but a personal interview may be more so. The apostle was not yet too old for travel, nor consequently for travelling servi...', 'teologico');

// 3JO (5 comentários)
add('3jo', 1, 4, 'João', 'Não tenho maior gozo — O contentamento do pastor: ver os filhos na verdade.', 'aplicacao');
add('3jo', 1, 1, 'Matthew Henry', 'I. The sacred penman writes and sends the letter, referred to as "The elder," meaning by years and office, deserving honor. Some question whether this was John the apostle, but his style and spirit are evident. Gaius could not question who wrote it. John humbly refers to himself as "the elder," aligning with ordinary church pastors. II. The recipient is Gaius, a well-beloved individual, possibly the same Gaius mentioned by Paul in Romans 16:23. John expresses his love for him "in the truth," ...', 'teologico');
add('3jo', 1, 3, 'Matthew Henry', 'I. John receives a good report of Gaius\'s faith and charity from the brethren. Gaius’s love for the brethren and hospitality to strangers proves his sincerity in the faith. II. Gaius is commended for his hospitality, a virtue extended to strangers and those of different churches. III. John expresses great joy in hearing of Gaius\'s walk in truth. This reflects the joy of ministers when they see their followers living out their faith. IV. John advises Gaius to continue supporting the brethren b...', 'teologico');
add('3jo', 1, 9, 'Matthew Henry', 'I. Diotrephes, unlike Gaius, loved preeminence and refused apostolic authority, spreading malicious words. He did not accept John’s letter and discouraged others from showing hospitality, casting them out of the church. John warns that he will address this behavior when he visits. II. John cautions against following Diotrephes’ evil example and encourages believers to imitate what is good, for those who do good are of God, while those who do evil have not seen God.', 'teologico');
add('3jo', 1, 12, 'Matthew Henry', 'I. Demetrius, on the other hand, has a good report from all and of the truth itself. John and others also bear witness to his character, and Gaius can trust this testimony. Demetrius was likely well known to both John’s church and Gaius\'s. II. John closes the letter expressing a desire to see Gaius soon and wishing him peace. He also sends greetings from mutual friends and instructs Gaius to greet their friends by name, indicating a personal connection.', 'teologico');

// JD (1 comentários)
add('jd', 1, 24, 'John Stott', 'Pode vos guardar — A segurança dos santos: Deus é fiel para completar a obra.', 'teologico');

// AP (74 comentários)
add('ap', 1, 7, 'N.T. Wright', 'Virá com as nuvens — A segunda vinda: toda a terra verá o Filho do Homem.', 'escatologico');
add('ap', 1, 8, 'Tomás de Aquino', 'Eu sou o Alfa e o Ômega — A eternidade de Deus: princípio e fim de todas as coisas.', 'teologico');
add('ap', 3, 20, 'John Stott', 'Eu chamo e chamo — A paciência de Cristo: Ele persiste em convidar.', 'aplicacao');
add('ap', 5, 9, 'João Crisóstomo', 'Tribaste o teu sangue — O Cordeiro é digno: sua morte redentora é motivo de louvor cósmico.', 'teologico');
add('ap', 5, 12, 'Spurgeon', 'Digno é o Cordeiro — A adoração celestial: sete atributos de louvor ao Cordeiro.', 'teologico');
add('ap', 7, 9, 'Adam Clarke', 'Uma grande multidão — A multidão celestial: todos os povos diante do trono.', 'escatologico');
add('ap', 11, 15, 'Lloyd-Jones', 'Os reinos do mundo — O reino do mundo se tornou do Senhor: a vitória final é certa.', 'escatologico');
add('ap', 12, 11, 'John Piper', 'Venceram pelo sangue — A vitória sobre Satanás: pelo sangue do Cordeiro e palavra do testemunho.', 'teologico');
add('ap', 13, 8, 'R.C. Sproul', 'Escrito no livro — A eleição é anterior à fundação do mundo: nome escrito antes da criação.', 'teologico');
add('ap', 19, 11, 'Albert Barnes', 'Um cavalo branco — Cristo retorna como juiz e rei: a guerra final.', 'escatologico');
add('ap', 19, 13, 'Charles Ellicott', 'Em sangue vestido — O sangue é o de seus inimigos: Cristo é o juiz justo.', 'escatologico');
add('ap', 19, 16, 'Lutero', 'Rei dos reis — A soberania suprema de Cristo: todos os poderes estão sujeitos a Ele.', 'teologico');
add('ap', 20, 12, 'Calvino', 'Livros foram abertos — O juízo final: cada pessoa será julgada pelas suas obras.', 'escatologico');
add('ap', 20, 15, 'Spurgeon', 'Lançado no lago de fogo — A segunda morte é real: o destino eterno dos não salvos.', 'escatologico');
add('ap', 21, 1, 'N.T. Wright', 'Nova criação — O novo céu e nova terra são a renovação: Deus não abandona, mas restaura.', 'escatologico');
add('ap', 21, 4, 'Lloyd-Jones', 'Não haverá mais morte — A vitória final: todas as promessas de Deus cumpridas.', 'escatologico');
add('ap', 21, 5, 'John Piper', 'Eis que faço novas todas as coisas — Deus renova tudo: a criação restaurada é a morada de Deus.', 'teologico');
add('ap', 22, 1, 'Matthew Henry', 'Rio da água da vida — O jardim restaurado: o rio de vida brota do trono de Deus.', 'cultural');
add('ap', 22, 5, 'Tim Keller', 'Não haverá mais noite — A luz eterna: Deus é a luz que ilumina para sempre.', 'teologico');
add('ap', 22, 13, 'Atanásio', 'Eu sou o Alfa e o Ômega — Cristo é o princípio e o fim: eterno em Sua pessoa e obra.', 'teologico');
add('ap', 22, 17, 'Albert Barnes', 'Venha quem quer — O convite é aberto: todos são bem-vindos a beber.', 'aplicacao');
add('ap', 22, 20, 'Wesley', 'Vem, Senhor Jesus — O anseio da igreja: a segunda vinda é a esperança máxima.', 'escatologico');
add('ap', 1, 1, 'Matthew Henry', 'Here we have,\nI. What we may call the pedigree of this book. 1. It is the revelation of Jesus Christ. The whole Bible is so; for all revelation comes through Christ and all centres in him; and especially in these last days God has spoken to us by his Son, and concerning his Son. Christ, as the king of his church, has been pleased thus far to let his church know by what rules and methods he will proceed in his government; and, as the prophet of the church, he has made known to us the things th...', 'teologico');
add('ap', 1, 3, 'Matthew Henry', 'We have here an apostolic benediction on those who should give a due regard to this divine revelation; and this benediction is given more generally and more especially.\nI. More generally, to all who either read or hear the words of the prophecy. This blessing seems to be pronounced with a design to encourage us to study this book, and not be weary of looking into it upon account of the obscurity of many things in it; it will repay the labour of the careful and attentive reader. Observe, 1. It...', 'teologico');
add('ap', 1, 9, 'Matthew Henry', 'We have now come to that glorious vision which the apostle had of the Lord Jesus Christ, when he came to deliver this revelation to him, where observe,\nI. The account given of the person who was favoured with this vision. He describes himself, 1. By his present state and condition. He was the brother and companion of these churches in tribulation, and in the kingdom and patience of Christ. He was, at their time, as the rest of true Christians were, a persecuted man, banished, and perhaps impr...', 'teologico');
add('ap', 2, 1, 'Matthew Henry', 'We have here,\nI. The inscription, where observe, 1. To whom the first of these epistles is directed: To the church of Ephesus, a famous church planted by the apostle Paul (Acts 19), and afterwards watered and governed by John, who had his residence very much there. We can hardly think that Timothy was the angel, or sole pastor and bishop, of this church at this time, - that he who was of a very excellent spirit, and naturally cared for the good state of the souls of the people, should become ...', 'teologico');
add('ap', 2, 8, 'Matthew Henry', 'We now proceed to the second epistle sent to another of the Asian churches, where, as before, observe,\nI. The preface or inscription in both parts. 1. The superscription, telling us to whom it was more expressly and immediately directed: To the angel of the church in Smyrna, a place well known at this day by our merchants, a city of great trade and wealth, perhaps the only city of all the seven that is still known by the same name, now however no longer distinguished for its Christian church ...', 'teologico');
add('ap', 2, 12, 'Matthew Henry', 'Here also we are to consider,\nI. The inscription of this message. 1. To whom it was sent: To the angel of the church of Pergamos. Whether this was a city raised up out of the ruins of old Troy, a Troy nouveau (as our London was once called), or some other city of the same name, is neither certain nor material; it was a place where Christ had called and constituted a gospel church, by the preaching of the gospel and the grace of his Spirit making the word effectual. 2. Who it was that sent thi...', 'teologico');
add('ap', 2, 18, 'Matthew Henry', 'The form of each epistle is very much the same; and in this, as the rest, we have to consider the inscription, contents, and conclusion.\nI. The inscription, telling us, 1. To whom it is directed: To the angel of the church of Thyatira, a city of the proconsular Asia, bordering upon Mysia on the north and Lydia on the south, a town of trade, whence came the woman named Lydia, a seller of purple, who, being at Philippi in Macedonia, probably about the business of her calling, heard Paul preach ...', 'teologico');
add('ap', 3, 1, 'Matthew Henry', 'Here is, I. The preface, showing, 1. To whom this letter is directed: To the angel of the church of Sardis, an ancient city of Lydia, on the banks of the mountain Tmolus, said to have been the chief city of Asia the Less, and the first city in that part of the world that was converted by the preaching of John; and, some say, the first that revolted from Christianity, and one of the first that was laid in its ruins, in which it still lies, without any church or ministry. 2. By whom this messag...', 'teologico');
add('ap', 3, 7, 'Matthew Henry', 'We have now come to the sixth letter, sent to one of the Asian churches, where observe,\nI. The inscription, showing,\n1. For whom it was more immediately designed: The angel of the church of Philadelphia; this also was a city in Asia Minor, seated upon the borders of Mysia and Lydia, and had its name from that brotherly love for which it was eminent. We can hardly suppose that this name was given to it after it received the Christian religion, and that it was so called from that Christian affe...', 'teologico');
add('ap', 3, 14, 'Matthew Henry', 'We now come to the last and worst of all the seven Asian churches, the reverse of the church of Philadelphia; for, as there was nothing reproved in that, here is nothing commended in this, and yet this was one of the seven golden candlesticks, for a corrupt church may still be a church. Here we have, as before,\nI. The inscription, to whom, and from whom. 1. To whom: To the angel of the church of Laodicea. This was a once famous city near the river Lycus, had a wall of vast compass, and three ...', 'teologico');
add('ap', 4, 1, 'Matthew Henry', 'We have here an account of a second vision with which the apostle John was favoured: After this, that is, not only "after I had seen the vision of Christ walking in the midst of the golden candlesticks," but "after I had taken his messages from his mouth, and written and sent them to the several churches, according to his command, after this I had another vision." Those who well improve the discoveries they have had of God already are prepared thereby for more, and may expect them. Observe,\nI...', 'teologico');
add('ap', 4, 8, 'Matthew Henry', 'We have considered the sights that the apostle saw in heaven: now let us observe the songs that he heard, for there is in heaven not only that to be seen which will highly please a sanctified eye, but there is that to be heard which will greatly delight a sanctified ear. This is true concerning the church of Christ here, which is a heaven upon earth, and it will be eminently so in the church made perfect in the heaven of heavens.\nI. He heard the song of the four living creatures, of the minis...', 'teologico');
add('ap', 5, 1, 'Matthew Henry', 'Hitherto the apostle had seen only the great God, the governor of all things, now,\nI. He is favoured with a sight of the model and methods of his government, as they are all written down in a book which he holds in his hand; and this we are now to consider as shut up and sealed in the hand of God. Observe, 1. The designs and methods of divine Providence towards the church and the world are stated and fixed; they are resolved upon and agreed to, as that which is written in a book. The great de...', 'teologico');
add('ap', 5, 6, 'Matthew Henry', 'Here, I. The apostle beholds this book taken into the hands of the Lord Jesus Christ, in order to its being unsealed and opened by him. Here Christ is described, 1. By his place and station: In the midst of the throne, and of the four beasts, and of the elders. He was on the same throne with the Father; he was nearer to him than either the elders or ministers of the churches. Christ, as man and Mediator, is subordinate to God the Father, but is nearer to him than all the creatures; for in him...', 'teologico');
add('ap', 6, 1, 'Matthew Henry', 'Here, 1. Christ, the Lamb, opens the first seal; he now enters upon the great work of opening and accomplishing the purposes of God towards the church and the world. 2. One of the ministers of the church calls upon the apostle, with a voice like thunder, to come near, and observe what then appeared. 3. We have the vision itself, Rev 6:2. (1.) The Lord Jesus appears riding on a white horse. White horses are generally refused in war, because they make the rider a mark for the enemy; but our Lor...', 'teologico');
add('ap', 6, 3, 'Matthew Henry', 'The next three seals give us a sad prospect of great and desolating judgments with which God punishes those who either refuse or abuse the everlasting gospel. Though some understand them of the persecutions that befell the church of Christ, and others of the destruction of the Jews, they rather seem more generally to represent God\'s terrible judgments, by which he avenges the quarrel of his covenant upon those who make light of it.\nI. Upon opening the second seal, to which John was called to ...', 'teologico');
add('ap', 6, 9, 'Matthew Henry', 'In the remaining part of this chapter we have the opening of the fifth and the sixth seals.\nI. The fifth seal. Here is no mention made of any one who called the apostle to make his observation, probably because the decorum of the vision was to be observed, and each of the four living creatures had discharged its duty of a monitor before, or because the events here opened lay out of the sight, and beyond the time, of the present ministers of the church; or because it does not contain a new pro...', 'teologico');
add('ap', 7, 1, 'Matthew Henry', 'Here we have, I. An account of the restraint laid upon the winds. By these winds we suppose are meant those errors and corruptions in religion which would occasion a great deal of trouble and mischief to the church of God. Sometimes the Holy Spirit is compared to the wind: here the spirits of error are compared to the four winds, contrary one to another, but doing much hurt to the church, the garden and vineyard of God, breaking the branches and blasting the fruits of his plantation. The devi...', 'teologico');
add('ap', 7, 13, 'Matthew Henry', 'Here we have a description of the honour and happiness of those who have faithfully served the Lord Jesus Christ, and suffered for him. Observe,\nI. A question asked by one of the elders, not for his own information, but for John\'s instruction: ministers may learn from the people, especially from aged and experienced Christians; the lowest saint in heaven knows more than the greatest apostle in the world. Now the question has two parts: - 1. What are these that are arrayed in white robes? 2. W...', 'teologico');
add('ap', 8, 1, 'Matthew Henry', 'In these verses we have the prelude to the sounding of the trumpets in several parts.\nI. The opening of the last seal. This was to introduce a new set of prophetical iconisms and events; there is a continued chain of providence, one part linked to another (where one ends another begins), and, though they may differ in nature and in time, they all make up one wise, well-connected, uniform design in the hand of God.\nII. A profound silence in heaven for the space of half an hour, which may be un...', 'teologico');
add('ap', 8, 7, 'Matthew Henry', 'Observe, I. The first angel sounded the first trumpet, and the events which followed were very dismal: There followed hail and fire mingled with blood, etc., Rev 8:7. There was a terrible storm; but whether it is to be understood of a storm of heresies, a mixture of monstrous errors falling on the church (for in that age Arianism prevailed), or a storm or tempest of war falling on the civil state, expositors are not agreed. Mr. Mede takes it to be meant of the Gothic inundation that broke in ...', 'teologico');
add('ap', 9, 1, 'Matthew Henry', 'Upon the sounding of this trumpet, the things to be observed are, 1. A star falling from heaven to the earth. Some think this star represents some eminent bishop in the Christian church, some angel of the church; for, in the same way of speaking by which pastors are called stars, the church is called heaven; but who this is expositors do not agree. Some understand it of Boniface the third bishop of Rome, who assumed the title of universal bishop, by the favour of the emperor Phocas, who, bein...', 'teologico');
add('ap', 9, 13, 'Matthew Henry', 'Here let us consider the preface to this vision, and then the vision itself.\nI. The preface to this vision: A voice was heard from the horns of the golden altar, Rev 9:13, Rev 9:14. Here observe, 1. The power of the church\'s enemies is restrained till God gives the word to have them turned loose. 2. When nations are ripe for punishment, those instruments of God\'s anger that were before restrained are let loose upon them, Rev 9:14. 3. The instruments that God makes use of to punish a people ma...', 'teologico');
add('ap', 10, 1, 'Matthew Henry', 'Here we have an account of another vision the apostle was favoured with, between the sounding of the sixth trumpet and that of the seventh. And we observe,\nI. The person who was principally concerned in communicating this discovery to John - an angel from heaven, another mighty angel, who is so set forth as would induce one to think it could be no other than our Lord and Saviour Jesus Christ! 1. He was clothed with a cloud: he veils his glory, which is too great for mortality to behold; and h...', 'teologico');
add('ap', 10, 8, 'Matthew Henry', 'Here we have, I. A strict charge given to the apostle, which was, 1. That he should go and take the little book out of the hands of that mighty angel mentioned before. This charge was given, not by the angel himself who stood upon the earth, but by the same voice from heaven that in the fourth verse had lain an injunction upon him not to write what he had discerned by the seven thunders. 2. To eat the book; this part of the charge was given by the angel himself, hinting to the apostle that be...', 'teologico');
add('ap', 11, 1, 'Matthew Henry', 'This prophetical passage about measuring the temple is a plain reference to what we find in Ezekiel\'s vision, Eze 40:3, etc. But how to understand either the one or the other is not so easy. It should seem the design of measuring the temple in the former case was in order to the rebuilding of it, and that with advantage; the design of this measurement seems to be either, 1. For the preservation of it in those times of public danger and calamity that are here foretold; or, 2. For its trial; th...', 'teologico');
add('ap', 11, 3, 'Matthew Henry', 'In this time of treading down, God has reserved to himself his faithful witnesses, who will not fail to attest the truth of his word and worship, and the excellency of his ways. Here observe,\nI. The number of these witnesses: it is but a small number and yet it is sufficient. 1. It is but small. Many will own and acknowledge Christ in times of prosperity who will desert and deny him in times of persecution; one witness, when the cause is upon trial, is worth many at other times. 2. It is a su...', 'teologico');
add('ap', 11, 14, 'Matthew Henry', 'We have here the sounding of the seventh and last trumpet, which is ushered in by the usual warning and demand of attention: The second woe is past, and, behold, the third woe cometh quickly. Then the seventh angel sounded. This had been suspended for some time, till the apostle had been made acquainted with some intervening occurrences of very great moment, and worthy of his notice and observation. But what he before expected he now heard - the seventh angel sounding. Here observe the effect...', 'teologico');
add('ap', 12, 1, 'Matthew Henry', 'Here we see that early prophecy eminently fulfilled in which God said he would put enmity between the seed of the woman and the seed of the serpent, Gen 3:15. You will observe,\nI. The attempts of Satan and his agents to prevent the increase of the church, by devouring her offspring as soon as it was born; of this we have a very lively description in the most proper images.\n1. We see how the church is represented in this vision. (1.) As a woman, the weaker part of the world, but the spouse of ...', 'teologico');
add('ap', 12, 12, 'Matthew Henry', 'We have here an account of this war, so happily finished in heaven, or in the church, as it was again renewed and carried on in the wilderness, the place to which the church had fled, and where she had been for some time secured by the special care of her God and Saviour. Observe,\nI. The warning given of the distress and calamity that should fall upon the inhabitants of the world in general, through the wrath and rage of the devil. For, though his malice is chiefly bent against the servants o...', 'teologico');
add('ap', 13, 1, 'Matthew Henry', 'We have here an account of the rise, figure, and progress of the first beast; and observe, 1. From what situation the apostle saw this monster. He seemed to himself to stand upon the sea-shore, though it is probable he was still in a rapture; but he took himself to be in the island Patmos, but whether in the body or out of the body he could not tell. 2. Whence this beast came - out of the sea; and yet, by the description of it, it would seem more likely to be a land-monster; but the more mons...', 'teologico');
add('ap', 13, 11, 'Matthew Henry', 'Those who think the first beast signifies Rome pagan by this second beast would understand Rome papal, which promotes idolatry and tyranny, but in a more soft and lamb-like manner: those that understand the first beast of the secular power of the papacy take the second to intend its spiritual and ecclesiastical powers, which act under the disguise of religion and charity to the souls of men. Here observe,\nI. The form and shape of this second beast: He had two horns like a lamb, but a mouth th...', 'teologico');
add('ap', 14, 1, 'Matthew Henry', 'Here we have one of the most pleasing sights that can be viewed in this world - the Lord Jesus Christ at the head of his faithful adherents and attendants. Here observe, 1. How Christ appears: as a Lamb standing upon mount Zion. Mount Zion is the gospel church. Christ is with his church and in the midst of her in all her troubles, and therefore she is not consumed. It is his presence that secures her perseverance; he appears as a Lamb, a true Lamb, the Lamb of God. A counterfeit lamb is menti...', 'teologico');
add('ap', 14, 6, 'Matthew Henry', 'In this part of the chapter we have three angels or messengers sent from heaven to give notice of the fall of Babylon, and of those things that were antecedent and consequent to that great event.\nI. The first angel was sent on an errand antecedent to it, and that was to preach the everlasting gospel, Rev 14:6, Rev 14:7. Observe, 1. The gospel is an everlasting gospel; it is so in its nature, and it will be so in its consequences. Though all flesh be grass, the word of the Lord endureth for ev...', 'teologico');
add('ap', 14, 13, 'Matthew Henry', 'Here we have the vision of the harvest and vintage, introduced with a solemn preface. Observe,\nI. The preface, Rev 14:13. Here note, 1. Whence this prophecy about the harvest came: it came down from heaven, and not from men, and therefore it is of certain truth and great authority. 2. How it was to be preserved and published - by writing; it was to be a matter of record, that the people of God might have recourse to it for their support and comfort upon all occasions. 3. What it principally i...', 'teologico');
add('ap', 15, 1, 'Matthew Henry', 'Here we have the preparation of matters for the pouring out of the seven vials, which was committed to seven angels; and observe how these angels appeared to the apostle - in heaven; it was in a wonderful manner, and that upon account, 1. Of the work they had to do, which was to finish the destruction of antichrist. God was now about to pour out his seven last plagues upon that interest; and, as the measure of Babylon\'s sins was filled up, they should now find the full measure of his vindicti...', 'teologico');
add('ap', 15, 5, 'Matthew Henry', 'Observe, I. How these angels appeared - coming out of heaven to execute their commission: The temple of the tabernacle of the testimony in heaven was opened, Rev 15:5. Here is an allusion to the holiest of all the tabernacle and temple, where was the mercy-seat, covering the ark of the testimony, where the high priest made intercession, and God communed with his people, and heard their prayers. Now by this, as it is here mentioned, we may understand, 1. That, in the judgments God was now abou...', 'teologico');
add('ap', 16, 1, 'Matthew Henry', 'We had in the foregoing chapter the great and solemn preparation that was made for the pouring out of the vials; now we have the performance of that work. Here observe,\nI. That, though every thing was made ready before, yet nothing was to be put in execution without an immediate positive order from God; and this he gave out of the temple, answering the prayers of his people, and avenging their quarrel.\nII. No sooner was the word of command given than it was immediately obeyed; no delay, no ob...', 'teologico');
add('ap', 16, 8, 'Matthew Henry', 'In these verses we see the work going on in the appointed order. The fourth angel poured out his vial, and that fell upon the sun; that is, say some, upon some eminent prince of the popish communion, who should renounce their false religion a little while before his utter downfall; and some expect it will be the German emperor. And now what will be the consequence of this? That sun which before cherished them with warm and benign influences shall now grow hot against these idolaters, and shal...', 'teologico');
add('ap', 16, 12, 'Matthew Henry', 'The sixth angel poured out his vial; and observe,\nI. Where it fell - upon the great river Euphrates. Some take it literally, for the place where the Turkish power and empire began; and they think this is a prophecy of the destruction of the Turkish monarchy and of idolatry, which they suppose will be effected about the same time with that of the papacy, as another antichrist, and that thereby a way shall be made for the conveniency of the Jews, those princes of the east. Others take it for th...', 'teologico');
add('ap', 16, 17, 'Matthew Henry', 'Here we have an account of the seventh and last angel pouring forth his vial, contributing his part towards the accomplishment of the downfall of Babylon, which was the finishing stroke. And here, as before, observe,\nI. Where this plague fell - on the air, upon the prince of the power of the air, that is, the devil. His powers were restrained, his policies confounded; he was bound in God\'s chain: the sword of God was upon his eye and upon his arm; for he, as well as the powers of the earth, i...', 'teologico');
add('ap', 17, 1, 'Matthew Henry', 'Here we have a new vision, not as to the matter of it, for that is contemporary with what came under the three last vials; but as to the manner of description, etc. Observe, 1. The invitation given to the apostle to take a view of what was here to be represented: Come hither, and I will show thee the judgment of the great whore, etc., Rev 17:1. This is a name of great infamy. A whore [in this passage] is one that is married, and has been false to her husband\'s bed, has forsaken the guide of h...', 'teologico');
add('ap', 17, 7, 'Matthew Henry', 'Here we have the mystery of this vision explained. The apostle wonders at the sight of this woman: the angel undertakes to open this vision to him, it being the key of the former visions; and he tells the apostle what was meant by the beast on which the woman sat; but it is so explained as still to need further explanation. 1. This beast was, and is not, and yet is; that is, it was a seat of idolatry and persecution; and is not, that is, not in the ancient form, which was pagan; and yet it is...', 'teologico');
add('ap', 17, 14, 'Matthew Henry', 'Here we have some account of the downfall of Babylon, to be more fully described in the following chapter.\nI. Here is a war begun between the beast and his followers, and the Lamb and his followers. The beast and his army, to an eye of sense, appear much stronger than the Lamb and his army: one would think an army with a lamb at the head of them could not stand before the great red dragon. But,\nII. Here is a victory gained by the Lamb: The Lamb shall overcome. Christ must reign till all enemi...', 'teologico');
add('ap', 18, 1, 'Matthew Henry', 'The downfall and destruction of Babylon form an event so fully determined in the counsels of God, and of such consequence to his interests and glory, that the visions and predictions concerning it are repeated. 1. Here is another angel sent from heaven, attended with great power and lustre, Rev 18:1. He had not only light in himself, to discern the truth of his own prediction, but to inform and enlighten the world about that great event; and not only light to discern it, but power to accompli...', 'teologico');
add('ap', 18, 9, 'Matthew Henry', 'Here we have,\nI. A doleful lamentation made by Babylon\'s friends for her fall; and here observe,\n1. Who are the mourners, namely, those who had been bewitched by her fornication, those who had been sharers in her sensual pleasures, and those who had been gainers by her wealth and trade - the kings and the merchants of the earth: the kings of the earth, whom she had flattered into idolatry by allowing them to be arbitrary and tyrannical over their subjects, while they were obsequious to her; a...', 'teologico');
add('ap', 19, 1, 'Matthew Henry', 'The fall of Babylon being fixed, finished, and declared to be irrecoverable in the foregoing chapter, this begins with a holy triumph over her, in pursuance of the order given forth: Rejoice over her, thou heaven, and you holy apostles and prophets, Rev 18:20. They now gladly answer the call; and here you have, 1. The form of their thanksgiving, in that heavenly and most comprehensive word, Alleluia, praise you the Lord: with this they begin, with this they go on, and with this they end (Rev ...', 'teologico');
add('ap', 19, 5, 'Matthew Henry', 'The triumphant song being ended, and epithalamium, or marriage-song, begins, Rev 19:6. Here observe,\nI. The concert of heavenly music. The chorus was large and loud, as the voice of many waters and of mighty thunderings. God is fearful in praises. There is no discord in heaven; the morning stars sing together; no jarring string, nor key untuned, but pure and perfect melody.\nII. The occasion of this song; and that is the reign and dominion of that omnipotent God who has redeemed his church by ...', 'teologico');
add('ap', 20, 1, 'Matthew Henry', 'We have here, I. A prophecy of the binding of Satan for a certain term of time, in which he should have much less power and the church much more peace than before. The power of Satan was broken in part by the setting up of the gospel kingdom in the world; it was further reduced by the empire\'s becoming Christian; it was yet further broken by the downfall of the mystical Babylon; but still this serpent had many heads, and, when one is wounded, another has life remaining in it. Here we have a f...', 'teologico');
add('ap', 20, 11, 'Matthew Henry', 'The utter destruction of the devil\'s kingdom very properly leads to an account of the day of judgment, which will determine every man\'s everlasting state; and we may be assured there will be a judgment when we see the prince of this world is judged, Joh 16:11. This will be a great day, the great day, when all shall appear before the judgment-seat of Christ. The Lord help us firmly to believe this doctrine of the judgment to come. It is a doctrine that made Felix tremble. Here we have a descri...', 'teologico');
add('ap', 21, 9, 'Matthew Henry', 'We have already considered the introduction to the vision of the new Jerusalem in a more general idea of the heavenly state; we now come to the vision itself, where observe,\nI. The person that opened the vision to the apostle - one of the seven angels, that had the seven vials full of the seven last plagues, Rev 21:9. God has a variety of work and employment for his holy angels. Sometimes they are to sound the trumpet of divine Providence, and give fair warning to a careless world; sometimes ...', 'teologico');
add('ap', 22, 6, 'Matthew Henry', 'We have here a solemn ratification of the contents of this book, and particularly of this last vision (though some think it may not only refer to the whole book, but to the whole New Testament, yea, to the whole Bible, completing and confirming the canon of scripture); and here, 1. This is confirmed by the name and nature of that God who gave out these discoveries: he is the Lord God, faithful and true, and so are all his sayings. 2. By the messengers he chose, to reveal these things to the w...', 'teologico');

export function obterComentarios(livro: string, capitulo: number, versiculo: number): Comentario[] {
  return comentarios[chave(livro, capitulo, versiculo)] || [];
}

export function temComentario(livro: string, capitulo: number, versiculo: number): boolean {
  return chave(livro, capitulo, versiculo) in comentarios;
}

export function obterTodosComentarios(): Comentario[] {
  return Object.values(comentarios).flat();
}

export function obterAutoresComentarios(): string[] {
  const autores = new Set<string>();
  for (const lista of Object.values(comentarios)) {
    for (const c of lista) autores.add(c.autor);
  }
  return [...autores].sort();
}
